INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2766229654', 'plant-biology', 'Feed Your Friends: Do Plant Exudates Shape the Root Microbiome?', 'Feed Your Friends: Do Plant Exudates Shape the Root Microbiome?', '2017', 2017, 2165, 2165, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1016/j.tplants.2017.09.003.g001', 'https://pubmed.ncbi.nlm.nih.gov/29050989', 'repository', 'review', 'Trends in Plant Science', '["Joëlle Sasse","Enrico Martinoia","Trent R. Northen"]', 'plant biology', NULL, '2026-07-07 20:21:46');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4210644165', 'plant-biology', 'Sustainable data analysis with Snakemake', 'Data analysis often entails a multitude of heterogeneous steps, from the application of various command line tools to the usage of scripting languages like R or Python for the generation of plots and…', '2021', 2021, 855, 855, 'https://f1000research-files.f1000.com/manuscripts/32078/2dd5741c-0e33-41b8-a76b-a26a36ae899c_figure1.gif', 'https://doi.org/10.12688/f1000research.29032.1', 'repository', 'preprint', 'F1000Research', '["Felix Mölder","Kim Philipp Jablonski","Brice Letcher","Michael B. Hall","Christopher H. Tomkins-Tinch","Vanessa Sochat","Jan Förster","Soohyun Lee","Sven Twardziok","Alexander Kanitz","Andreas Wilm","Manuel Holtgrewe","Sven Rahmann","Sven Nahnsen","Johannes Köster"]', 'plant biology', 'Data analysis often entails a multitude of heterogeneous steps, from the application of various command line tools to the usage of scripting languages like R or Python for the generation of plots and tables. It is widely recognized that data analyses should ideally be conducted in a reproducible way. Reproducibility enables technical validation and regeneration of results on the original or even new data. However, reproducibility alone is by no means sufficient to deliver an analysis that is of lasting impact (i.e., sustainable) for the field, or even just one research group. We postulate that it is equally important to ensure adaptability and transparency. The former describes the ability to modify the analysis to answer extended or slightly different research questions. The latter describes the ability to understand the analysis in order to judge whether it is not only technically, but methodologically valid. Here, we analyze the properties needed for a data analysis to become reproducible, adaptable, and transparent. We show how the popular workflow management system Snakemake can be used to guarantee this, and how it enables an ergonomic, combined, unified representation of all steps involved in data analysis, ranging from raw data processing, to quality control and fine-grained, interactive exploration and plotting of final results.', '2026-07-07 20:22:44');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4280619656', 'plant-biology', 'Doublet identification in single-cell sequencing data using scDblFinder', 'Doublets are prevalent in single-cell sequencing data and can lead to artifactual findings. A number of strategies have therefore been proposed to detect them. Building on the strengths of existing…', '2022', 2022, 625, 625, 'https://f1000research-files.f1000.com/manuscripts/133464/39a8b937-1fca-4526-b07e-e4535e9f8705_figure1.gif', 'https://doi.org/10.12688/f1000research.73600.2', 'repository', 'preprint', 'F1000Research', '["Pierre‐Luc Germain","Aaron T. L. Lun","Carlos Garcia Meixide","Will Macnair","Mark D. Robinson"]', 'plant biology', 'Doublets are prevalent in single-cell sequencing data and can lead to artifactual findings. A number of strategies have therefore been proposed to detect them. Building on the strengths of existing approaches, we developed scDblFinder , a fast, flexible and accurate Bioconductor-based doublet detection method. Here we present the method, justify its design choices, demonstrate its performance on both single-cell RNA and accessibility (ATAC) sequencing data, and provide some observations on doublet formation, detection, and enrichment analysis. Even in complex datasets, scDblFinder can accurately identify most heterotypic doublets, and was already found by an independent benchmark to outcompete alternatives.', '2026-07-07 20:23:21');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4242856680', 'plant-biology', 'gprofiler2 -- an R package for gene list functional enrichment analysis and namespace conversion toolset g:Profiler', 'g:Profiler ( https://biit.cs.ut.ee/gprofiler ) is a widely used gene list functional profiling and namespace conversion toolset that has been contributing to reproducible biological data analysis…', '2020', 2020, 568, 568, 'https://f1000research-files.f1000.com/manuscripts/27533/f078f444-2600-412e-9ca0-8f5354fde249_figure1.gif', 'https://doi.org/10.12688/f1000research.24956.1', 'repository', 'preprint', 'F1000Research', '["Liis Kolberg","Uku Raudvere","Ivan Kuzmin","Jaak Vilo","Hedi Peterson"]', 'plant biology', 'g:Profiler ( https://biit.cs.ut.ee/gprofiler ) is a widely used gene list functional profiling and namespace conversion toolset that has been contributing to reproducible biological data analysis already since 2007. Here we introduce the accompanying R package, gprofiler2 , developed to facilitate programmatic access to g:Profiler computations and databases via REST API. The gprofiler2 package provides an easy-to-use functionality that enables researchers to incorporate functional enrichment analysis into automated analysis pipelines written in R. The package also implements interactive visualisation methods to help to interpret the enrichment results and to illustrate them for publications. In addition, gprofiler2 gives access to the versatile gene/protein identifier conversion functionality in g:Profiler enabling to map between hundreds of different identifier types or orthologous species. The gprofiler2 package is freely available at the CRAN repository .', '2026-07-07 20:23:48');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4245901258', 'plant-biology', 'CoNet app: inference of biological association networks using Cytoscape', 'Here we present the Cytoscape app version of our association network inference tool CoNet. Though CoNet was developed with microbial community data from sequencing experiments in mind, it is designed…', '2016', 2016, 526, 526, 'https://f1000research-files.f1000.com/manuscripts/9740/7968dcee-8c6a-4181-93fb-f5b5fbe313fc_figure1.gif', 'https://doi.org/10.12688/f1000research.9050.1', 'repository', 'preprint', 'F1000Research', '["Karoline Faust","Jeroen Raes"]', 'plant biology', 'Here we present the Cytoscape app version of our association network inference tool CoNet. Though CoNet was developed with microbial community data from sequencing experiments in mind, it is designed to be generic and can detect associations in any data set where biological entities (such as genes, metabolites or species) have been observed repeatedly. The CoNet app supports Cytoscape 2.x and 3.x and offers a variety of network inference approaches, which can also be combined. Here we briefly describe its main features and illustrate its use on microbial count data obtained by 16S rDNA sequencing of arctic soil samples. The CoNet app is available at: http://apps.cytoscape.org/apps/conet .', '2026-07-07 20:23:51');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4255658650', 'plant-biology', 'scRepertoire: An R-based toolkit for single-cell immune receptor analysis', 'Single-cell sequencing is an emerging technology in the field of immunology and oncology that allows researchers to couple RNA quantification and other modalities, like immune cell receptor profiling…', '2020', 2020, 494, 494, 'https://f1000research-files.f1000.com/manuscripts/24415/cfd77d18-d2bf-40c1-8126-efd0b8999cac_figure1.gif', 'https://doi.org/10.12688/f1000research.22139.1', 'repository', 'preprint', 'F1000Research', '["Nicholas Borcherding","Nicholas L. Bormann"]', 'plant biology', 'Single-cell sequencing is an emerging technology in the field of immunology and oncology that allows researchers to couple RNA quantification and other modalities, like immune cell receptor profiling at the level of an individual cell. A number of workflows and software packages have been created to process and analyze single-cell transcriptomic data. These packages allow users to take the vast dimensionality of the data generated in single-cell-based experiments and distill the data into novel insights. Unlike the transcriptomic field, there is a lack of options for software that allow for single-cell immune receptor profiling. Enabling users to easily combine mRNA and immune profiling, scRepertoire was built to process data derived from 10x Genomics Chromium Immune Profiling for both T-cell receptor (TCR) and immunoglobulin (Ig) enrichment workflows and subsequently interacts with the popular Seurat R package. The scRepertoire R package and processed data are open source and available on GitHub and provides in-depth tutorials on the capability of the package.', '2026-07-07 20:23:53');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2416334815', 'plant-biology', 'Plant Metabolomics: An Indispensable System Biology Tool for Plant Science', 'As genomes of many plant species have been sequenced, demand for functional genomics has dramatically accelerated the improvement of other omics including metabolomics. Despite a large amount of…', '2016', 2016, 378, 378, 'https://pub.mdpi-res.com/ijms/ijms-17-00767/article_deploy/html/images/ijms-17-00767-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4926328', 'pmc', 'review', 'International Journal of Molecular Sciences', '["Jun Hong","Litao Yang","Dabing Zhang","Jianxin Shi"]', 'plant biology', 'As genomes of many plant species have been sequenced, demand for functional genomics has dramatically accelerated the improvement of other omics including metabolomics. Despite a large amount of metabolites still remaining to be identified, metabolomics has contributed significantly not only to the understanding of plant physiology and biology from the view of small chemical molecules that reflect the end point of biological activities, but also in past decades to the attempts to improve plant behavior under both normal and stressed conditions. Hereby, we summarize the current knowledge on the genetic and biochemical mechanisms underlying plant growth, development, and stress responses, focusing further on the contributions of metabolomics to practical applications in crop quality improvement and food safety assessment, as well as plant metabolic engineering. We also highlight the current challenges and future perspectives in this inspiring area, with the aim to stimulate further studies leading to better crop improvement of yield and quality.', '2026-07-07 20:24:45');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4248656187', 'plant-biology', 'Falco: high-speed FastQC emulation for quality control of sequencing data', 'Quality control is an essential first step in sequencing data analysis, and software tools for quality control are deeply entrenched in standard pipelines at most sequencing centers. Although the…', '2019', 2019, 359, 359, 'https://f1000research-files.f1000.com/manuscripts/23273/1d67e864-49fe-4290-8919-09c70ca391fb_figure1.gif', 'https://doi.org/10.12688/f1000research.21142.1', 'repository', 'preprint', 'F1000Research', '["Guilherme De Sena Brandine","Andrew D. Smith"]', 'plant biology', 'Quality control is an essential first step in sequencing data analysis, and software tools for quality control are deeply entrenched in standard pipelines at most sequencing centers. Although the associated computations are straightforward, in many settings the total computing effort required for quality control is appreciable and warrants optimization. We present falco, an emulation of the popular FastQC tool that runs on average three times faster while generating equivalent results. Compared to FastQC, falco also provides greater scalability for datasets with longer reads and more flexible visualization of HTML reports.', '2026-07-07 20:25:01');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2985045444', 'plant-biology', 'Falco: high-speed FastQC emulation for quality control of sequencing data', 'Quality control is an essential first step in sequencing data analysis, and software tools for quality control are deeply entrenched in standard pipelines at most sequencing centers. Although the…', '2021', 2021, 336, 336, 'https://f1000research-files.f1000.com/manuscripts/46637/307e537c-d01e-4c60-ae52-92d5e9f8e8fc_figure1.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7845152', 'pmc', 'preprint', 'F1000Research', '["Guilherme De Sena Brandine","Andrew D. Smith"]', 'plant biology', 'Quality control is an essential first step in sequencing data analysis, and software tools for quality control are deeply entrenched in standard pipelines at most sequencing centers. Although the associated computations are straightforward, in many settings the total computing effort required for quality control is appreciable and warrants optimization. We present falco, an emulation of the popular FastQC tool that runs on average three times faster while generating equivalent results. Compared to FastQC, falco also provides greater scalability for datasets with longer reads and more flexible visualization of HTML reports.', '2026-07-07 20:25:32');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3209782606', 'plant-biology', 'Plastid phylogenomic insights into relationships of all flowering plant families', 'BACKGROUND: Flowering plants (angiosperms) are dominant components of global terrestrial ecosystems, but phylogenetic relationships at the familial level and above remain only partially resolved,…', '2021', 2021, 296, 296, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs12915-021-01166-2/MediaObjects/12915_2021_1166_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8555322', 'pmc', 'article', 'BMC Biology', '["Hongtao Li","Yang Luo","Lu Gan","Pengfei Ma","Lian‐Ming Gao","Junbo Yang","Jie Cai","Matthew A. Gitzendanner","Peter W. Fritsch","Ting Zhang","Jian‐Jun Jin","Chun‐Xia Zeng","Hong Wang","Wen‐Bin Yu","Rong Zhang","Michelle van der Bank","Richard G. Olmstead","Peter M. Hollingsworth","Mark W. Chase","Pamela S. Soltis","Pamela S. Soltis","Ting‐Shuang Yi","Li D"]', 'plant biology', 'BACKGROUND: Flowering plants (angiosperms) are dominant components of global terrestrial ecosystems, but phylogenetic relationships at the familial level and above remain only partially resolved, greatly impeding our full understanding of their evolution and early diversification. The plastome, typically mapped as a circular genome, has been the most important molecular data source for plant phylogeny reconstruction for decades. RESULTS: Here, we assembled by far the largest plastid dataset of angiosperms, composed of 80 genes from 4792 plastomes of 4660 species in 2024 genera representing all currently recognized families. Our phylogenetic tree (PPA II) is essentially congruent with those of previous plastid phylogenomic analyses but generally provides greater clade support. In the PPA II tree, 75% of nodes at or above the ordinal level and 78% at or above the familial level were resolved with high bootstrap support (BP ≥ 90). We obtained strong support for many interordinal and interfamilial relationships that were poorly resolved previously within the core eudicots, such as Dilleniales, Saxifragales, and Vitales being resolved as successive sisters to the remaining rosids, and Santalales, Berberidopsidales, and Caryophyllales as successive sisters to the asterids. However, the placement of magnoliids, although resolved as sister to all other Mesangiospermae, is not well supported and disagrees with topologies inferred from nuclear data. Relationships among the five major clades of Mesangiospermae remain intractable despite increased sampling, probably due to an ancient rapid radiation. CONCLUSIONS: We provide the most comprehensive dataset of plastomes to date and a well-resolved phylogenetic tree, which together provide a strong foundation for future evolutionary studies of flowering plants.', '2026-07-07 20:26:13');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2207779154', 'plant-biology', 'Regulation of IL-10 and IL-12 production and function in macrophages and dendritic cells', 'Interleukin-10 and Interleukin-12 are produced primarily by pathogen-activated antigen-presenting cells, particularly macrophages and dendritic cells. IL-10 and IL-12 play very important…', '2015', 2015, 266, 266, 'https://f1000research-files.f1000.com/manuscripts/7547/42b55751-3fac-4c32-95bc-efdecc115f29_figure1.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4754024', 'pmc', 'preprint', 'F1000Research', '["Xiaojing Ma","Wenjun Yan","Hua Zheng","Qinglin Du","Lixing Zhang","Yi Ban","Na Li","Fang Wei"]', 'plant biology', 'Interleukin-10 and Interleukin-12 are produced primarily by pathogen-activated antigen-presenting cells, particularly macrophages and dendritic cells. IL-10 and IL-12 play very important immunoregulatory roles in host defense and immune homeostasis. Being anti- and pro-inflammatory in nature, respectively, their functions are antagonistically opposing. A comprehensive and in-depth understanding of their immunological properties and signaling mechanisms will help develop better clinical intervention strategies in therapy for a wide range of human disorders. Here, we provide an update on some emerging concepts, controversies, unanswered questions, and opinions regarding the immune signaling of IL-10 and IL-12.', '2026-07-07 20:32:02');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4244292587', 'plant-biology', 'Benchmarking of long-read assemblers for prokaryote whole genome sequencing', 'Background: Data sets from long-read sequencing platforms (Oxford Nanopore Technologies and Pacific Biosciences) allow for most prokaryote genomes to be completely assembled – one contig per…', '2019', 2019, 256, 256, 'https://f1000research-files.f1000.com/manuscripts/24010/f00bbf85-b0f3-4372-80b9-1d26fb51a12c_figure1.gif', 'https://doi.org/10.12688/f1000research.21782.1', 'repository', 'preprint', 'F1000Research', '["Ryan R. Wick","Kathryn E. Holt"]', 'plant biology', 'Background: Data sets from long-read sequencing platforms (Oxford Nanopore Technologies and Pacific Biosciences) allow for most prokaryote genomes to be completely assembled – one contig per chromosome or plasmid. However, the high per-read error rate of long-read sequencing necessitates different approaches to assembly than those used for short-read sequencing. Multiple assembly tools (assemblers) exist, which use a variety of algorithms for long-read assembly. Methods: We used 500 simulated read sets and 120 real read sets to assess the performance of six long-read assemblers (Canu, Flye, Miniasm/Minipolish, Raven, Redbean and Shasta) across a wide variety of genomes and read parameters. Assemblies were assessed on their structural accuracy/completeness, sequence identity, contig circularisation and computational resources used. Results: Canu v1.9 produced moderately reliable assemblies but had the longest runtimes of all assemblers tested. Flye v2.6 was more reliable and did particularly well with plasmid assembly. Miniasm/Minipolish v0.3 was the only assembler which consistently produced clean contig circularisation. Raven v0.0.5 was the most reliable for chromosome assembly, though it did not perform well on small plasmids and had circularisation issues. Redbean v2.5 and Shasta v0.3.0 were computationally efficient but more likely to produce incomplete assemblies. Conclusions: Of the assemblers tested, Flye, Miniasm/Minipolish and Raven performed best overall. However, no single tool performed well on all metrics, highlighting the need for continued development on long-read assembly algorithms.', '2026-07-07 20:32:17');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3012443370', 'plant-biology', 'A Pan-plant Protein Complex Map Reveals Deep Conservation and Novel Assemblies', 'A Pan-plant Protein Complex Map Reveals Deep Conservation and Novel Assemblies', '2020', 2020, 245, 245, 'https://ars.els-cdn.com/content/image/1-s2.0-S0092867420302269-fx1.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7297045', 'pmc', 'article', 'Cell', '["Claire D. McWhite","Ophelia Papoulas","Kevin Drew","Rachael M. Cox","Viviana June","Oliver Xiaoou Dong","Taejoon Kwon","Cuihong Wan","Mari L. Salmi","Stanley J. Roux","Karen Browning","Z. Jeffrey Chen","Pamela C. Ronald","Edward M. Marcotte"]', 'plant biology', NULL, '2026-07-07 20:33:00');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4235332646', 'plant-biology', 'What is open peer review? A systematic review', 'Background: “Open peer review” (OPR), despite being a major pillar of Open Science, has neither a standardized definition nor an agreed schema of its features and implementations. The literature…', '2017', 2017, 234, 234, 'https://f1000research-files.f1000.com/manuscripts/12273/703ec170-1aad-40e3-b5ee-7dae130261e2_figure1.gif', 'https://doi.org/10.12688/f1000research.11369.1', 'repository', 'review', 'F1000Research', '["Tony Ross‐Hellauer"]', 'plant biology', 'Background: “Open peer review” (OPR), despite being a major pillar of Open Science, has neither a standardized definition nor an agreed schema of its features and implementations. The literature reflects this, with a myriad of overlapping and often contradictory definitions. While the term is used by some to refer to peer review where the identities of both author and reviewer are disclosed to each other, for others it signifies systems where reviewer reports are published alongside articles. For others it signifies both of these conditions, and for yet others it describes systems where not only “invited experts” are able to comment. For still others, it includes a variety of combinations of these and other novel methods. Methods: Recognising the absence of a consensus view on what open peer review is, this article undertakes a systematic review of definitions of “open peer review” or “open review”, to create a corpus of 122 definitions. These definitions are then systematically analysed to build a coherent typology of the many different innovations in peer review signified by the term, and hence provide the precise technical definition currently lacking. Results: This quantifiable data yields rich information on the range and extent of differing definitions over time and by broad subject area. Quantifying definitions in this way allows us to accurately portray exactly how ambiguously the phrase “open peer review” has been used thus far, for the literature offers a total of 22 distinct configurations of seven traits, effectively meaning that there are 22 different definitions of OPR in the literature. Conclusions: Based on this work, I propose a pragmatic definition of open peer review as an umbrella term for a number of overlapping ways that peer review models can be adapted in line with the ethos of Open Science, including making reviewer and author identities open, publishing review reports and enabling greater participation in the peer review process.', '2026-07-07 20:33:11');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4251287806', 'plant-biology', 'Comparison of clustering tools in R for medium-sized 10x Genomics single-cell RNA-sequencing data', 'Background: The commercially available 10x Genomics protocol to generate droplet-based single-cell RNA-seq (scRNA-seq) data is enjoying growing popularity among researchers. Fundamental to the…', '2018', 2018, 205, 205, 'https://f1000research-files.f1000.com/manuscripts/17256/d60760c5-81bf-4a84-b5bf-be174d9726a9_figure1.gif', 'https://doi.org/10.12688/f1000research.15809.1', 'repository', 'preprint', 'F1000Research', '["Saskia Freytag","Luyi Tian","Ingrid Lönnstedt","Milica Ng","Melanie Bahlo"]', 'plant biology', 'Background: The commercially available 10x Genomics protocol to generate droplet-based single-cell RNA-seq (scRNA-seq) data is enjoying growing popularity among researchers. Fundamental to the analysis of such scRNA-seq data is the ability to cluster similar or same cells into non-overlapping groups. Many competing methods have been proposed for this task, but there is currently little guidance with regards to which method to use. Methods: Here we use one gold standard 10x Genomics dataset, generated from the mixture of three cell lines, as well as three silver standard 10x Genomics datasets generated from peripheral blood mononuclear cells to examine not only the accuracy but also robustness of a dozen methods. Results: We found that some methods, including Seurat and Cell Ranger, outperform other methods, although performance seems to be dependent on the complexity of the studied system. Furthermore, we found that solutions produced by different methods have little in common with each other. Conclusions: In light of this, we conclude that the choice of clustering tool crucially determines interpretation of scRNA-seq data generated by 10x Genomics. Hence practitioners and consumers should remain vigilant about the outcome of 10x Genomics scRNA-seq analysis.', '2026-07-07 20:35:04');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2342913879', 'plant-biology', 'Parental epigenetic asymmetry of PRC2‐mediated histone modifications in the Arabidopsis endosperm', 'Parental epigenetic asymmetry of PRC2‐mediated histone modifications in the Arabidopsis endosperm', '2016', 2016, 167, 167, 'https://cdn.ncbi.nlm.nih.gov/pmc/blobs/78d0/4910532/fa5ab50208fe/EMBJ-35-1298-g002.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4910532', 'pmc', 'article', 'The EMBO Journal', '["Jordi Moreno‐Romero","Hua Jiang","Juan Santos‐González","Claudia Köhler"]', 'plant biology', NULL, '2026-07-07 20:38:50');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4387234697', 'plant-biology', 'An Integrated Multi-Omics and Artificial Intelligence Framework for Advance Plant Phenotyping in Horticulture', 'This review discusses the transformative potential of integrating multi-omics data and artificial intelligence (AI) in advancing horticultural research, specifically plant phenotyping. The…', '2023', 2023, 156, 156, 'https://pub.mdpi-res.com/biology/biology-12-01298/article_deploy/html/images/biology-12-01298-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/10603917', 'pmc', 'review', 'Biology', '["Danuta Cembrowska-Lech","Adrianna Krzemińska","Tymoteusz Miller","Anna Nowakowska","Cezary Adamski","Martyna Radaczyńska","Grzegorz Mikiciuk","Małgorzata Mikiciuk"]', 'plant biology', 'This review discusses the transformative potential of integrating multi-omics data and artificial intelligence (AI) in advancing horticultural research, specifically plant phenotyping. The traditional methods of plant phenotyping, while valuable, are limited in their ability to capture the complexity of plant biology. The advent of (meta-)genomics, (meta-)transcriptomics, proteomics, and metabolomics has provided an opportunity for a more comprehensive analysis. AI and machine learning (ML) techniques can effectively handle the complexity and volume of multi-omics data, providing meaningful interpretations and predictions. Reflecting the multidisciplinary nature of this area of research, in this review, readers will find a collection of state-of-the-art solutions that are key to the integration of multi-omics data and AI for phenotyping experiments in horticulture, including experimental design considerations with several technical and non-technical challenges, which are discussed along with potential solutions. The future prospects of this integration include precision horticulture, predictive breeding, improved disease and stress response management, sustainable crop management, and exploration of plant biodiversity. The integration of multi-omics and AI holds immense promise for revolutionizing horticultural research and applications, heralding a new era in plant phenotyping.', '2026-07-07 20:40:48');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2989882319', 'plant-biology', 'Distinct roles of GRIN2A and GRIN2B variants in neurological conditions', 'Rapid advances in sequencing technology have led to an explosive increase in the number of genetic variants identified in patients with neurological disease and have also enabled the assembly of a…', '2019', 2019, 153, 153, 'https://f1000research-files.f1000.com/manuscripts/20772/eb683fac-f6c7-4b8d-826a-1de320ab1441_figure1.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6871362', 'pmc', 'preprint', 'F1000Research', '["Scott J. Myers","Hongjie Yuan","Jing‐Qiong Kang","Francis Chee Kuan Tan","Stephen F. Traynelis","Chian‐Ming Low"]', 'plant biology', 'Rapid advances in sequencing technology have led to an explosive increase in the number of genetic variants identified in patients with neurological disease and have also enabled the assembly of a robust database of variants in healthy individuals. A surprising number of variants in the GRIN genes that encode N -methyl-D-aspartate (NMDA) glutamatergic receptor subunits have been found in patients with various neuropsychiatric disorders, including autism spectrum disorders, epilepsy, intellectual disability, attention-deficit/hyperactivity disorder, and schizophrenia. This review compares and contrasts the available information describing the clinical and functional consequences of genetic variations in GRIN2A and GRIN2B. Comparison of clinical phenotypes shows that GRIN2A variants are commonly associated with an epileptic phenotype but that GRIN2B variants are commonly found in patients with neurodevelopmental disorders. These observations emphasize the distinct roles that the gene products serve in circuit function and suggest that functional analysis of GRIN2A and GRIN2B variation may provide insight into the molecular mechanisms, which will allow more accurate subclassification of clinical phenotypes. Furthermore, characterization of the pharmacological properties of variant receptors could provide the first opportunity for translational therapeutic strategies for these GRIN -related neurological and psychiatric disorders.', '2026-07-07 20:41:00');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2750953134', 'plant-biology', 'Evolutionary routes to biochemical innovation revealed by integrative analysis of a plant-defense related specialized metabolic pathway', 'The diversity of life on Earth is a result of continual innovations in molecular networks influencing morphology and physiology. Plant specialized metabolism produces hundreds of thousands of…', '2017', 2017, 120, 120, 'https://cdn.elifesciences.org/articles/28468/elife-28468-fig1-v1.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5595436', 'pmc', 'article', 'eLife', '["Gaurav D. Moghe","Bryan J. Leong","Steven M. Hurney","A. Daniel Jones","Robert L. Last"]', 'plant biology', 'The diversity of life on Earth is a result of continual innovations in molecular networks influencing morphology and physiology. Plant specialized metabolism produces hundreds of thousands of compounds, offering striking examples of these innovations. To understand how this novelty is generated, we investigated the evolution of the Solanaceae family-specific, trichome-localized acylsugar biosynthetic pathway using a combination of mass spectrometry, RNA-seq, enzyme assays, RNAi and phylogenomics in different non-model species. Our results reveal hundreds of acylsugars produced across the Solanaceae family and even within a single plant, built on simple sugar cores. The relatively short biosynthetic pathway experienced repeated cycles of innovation over the last 100 million years that include gene duplication and divergence, gene loss, evolution of substrate preference and promiscuity. This study provides mechanistic insights into the emergence of plant chemical novelty, and offers a template for investigating the ~300,000 non-model plant species that remain underexplored.', '2026-07-07 20:45:02');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4388494131', 'plant-biology', 'Plant Metabolomics: Current Initiatives and Future Prospects', 'Plant metabolomics is a rapidly advancing field of plant sciences and systems biology. It involves comprehensive analyses of small molecules (metabolites) in plant tissues and cells. These…', '2023', 2023, 110, 110, 'https://pub.mdpi-res.com/cimb/cimb-45-00558/article_deploy/html/images/cimb-45-00558-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/10670879', 'pmc', 'review', 'Current Issues in Molecular Biology', '["Sudha Manickam","Veera Ranjani Rajagopalan","Rohit Kambale","Rajasekaran Raghu","Selvaraju Kanagarajan","M. Raveendran"]', 'plant biology', 'Plant metabolomics is a rapidly advancing field of plant sciences and systems biology. It involves comprehensive analyses of small molecules (metabolites) in plant tissues and cells. These metabolites include a wide range of compounds, such as sugars, amino acids, organic acids, secondary metabolites (e.g., alkaloids and flavonoids), lipids, and more. Metabolomics allows an understanding of the functional roles of specific metabolites in plants'' physiology, development, and responses to biotic and abiotic stresses. It can lead to the identification of metabolites linked with specific traits or functions. Plant metabolic networks and pathways can be better understood with the help of metabolomics. Researchers can determine how plants react to environmental cues or genetic modifications by examining how metabolite profiles change under various crop stages. Metabolomics plays a major role in crop improvement and biotechnology. Integrating metabolomics data with other omics data (genomics, transcriptomics, and proteomics) provides a more comprehensive perspective of plant biology. This systems biology approach enables researchers to understand the complex interactions within organisms.', '2026-07-07 20:47:03');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2569393637', 'plant-biology', 'Transcriptional and Post-transcriptional Mechanisms Limit Heading Date 1 (Hd1) Function to Adapt Rice to High Latitudes', 'Rice flowering is controlled by changes in the photoperiod that promote the transition to the reproductive phase as days become shorter. Natural genetic variation for flowering time has been largely…', '2017', 2017, 106, 106, 'https://journals.plos.org/plosgenetics/article/figure/image?size=large&id=10.1371/journal.pgen.1006530.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5221825', 'pmc', 'article', 'PLoS Genetics', '["Daniela Goretti","Damiano Martignago","Martina Landini","Vittoria Brambilla","Jorge Gómez‐Ariza","Nerina Gnesutta","Francesca Galbiati","Silvio Collani","Hiroki Takagi","Ryohei Terauchi","Roberto Mantovani","Fabio Fornara"]', 'plant biology', 'Rice flowering is controlled by changes in the photoperiod that promote the transition to the reproductive phase as days become shorter. Natural genetic variation for flowering time has been largely documented and has been instrumental to define the genetics of the photoperiodic pathway, as well as providing valuable material for artificial selection of varieties better adapted to local environments. We mined genetic variation in a collection of rice varieties highly adapted to European regions and isolated distinct variants of the long day repressor HEADING DATE 1 (Hd1) that perturb its expression or protein function. Specific variants allowed us to define novel features of the photoperiodic flowering pathway. We demonstrate that a histone fold domain scaffold formed by GRAIN YIELD, PLANT HEIGHT AND HEADING DATE 8 (Ghd8) and several NF-YC subunits can accommodate distinct proteins, including Hd1 and PSEUDO RESPONSE REGULATOR 37 (PRR37), and that the resulting OsNF-Y complex containing Hd1 can bind a specific sequence in the promoter of HEADING DATE 3A (Hd3a). Artificial selection has locally favored an Hd1 variant unable to assemble in such heterotrimeric complex. The causal polymorphism was defined as a single conserved lysine in the CCT domain of the Hd1 protein. Our results indicate how genetic variation can be stratified and explored at multiple levels, and how its description can contribute to the molecular understanding of basic developmental processes.', '2026-07-07 20:48:02');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4234509242', 'plant-biology', 'Revisiting inconsistency in large pharmacogenomic studies', 'In 2013, we published a comparative analysis mutation and gene expression profiles and drug sensitivity measurements for 15 drugs characterized in the 471 cancer cell lines screened in the Genomics…', '2016', 2016, 101, 101, 'https://f1000research-files.f1000.com/manuscripts/10354/828ef650-b741-4fa8-9a7e-dc73240554b2_figure1.gif', 'https://doi.org/10.12688/f1000research.9611.1', 'repository', 'preprint', 'F1000Research', '["Zhaleh Safikhani","Petr Smirnov","Mark Freeman","Nehmé El-Hachem","Adrian She","Quevedo Rene","Anna Goldenberg","Nicolai J. Birkbak","Christos Hatzis","Leming Shi","Andrew H. Beck","Hugo J.W.L. Aerts","John Quackenbush","Benjamin Haibe‐Kains"]', 'plant biology', 'In 2013, we published a comparative analysis mutation and gene expression profiles and drug sensitivity measurements for 15 drugs characterized in the 471 cancer cell lines screened in the Genomics of Drug Sensitivity in Cancer (GDSC) and Cancer Cell Line Encyclopedia (CCLE). While we found good concordance in gene expression profiles, there was substantial inconsistency in the drug responses reported by the GDSC and CCLE projects. We received extensive feedback on the comparisons that we performed. This feedback, along with the release of new data, prompted us to revisit our initial analysis. Here we present a new analysis using these expanded data in which we address the most significant suggestions for improvements on our published analysis — that targeted therapies and broad cytotoxic drugs should have been treated differently in assessing consistency, that consistency of both molecular profiles and drug sensitivity measurements should both be compared across cell lines, and that the software analysis tools we provided should have been easier to run, particularly as the GDSC and CCLE released additional data. Our re-analysis supports our previous finding that gene expression data are significantly more consistent than drug sensitivity measurements. The use of new statistics to assess data consistency allowed us to identify two broad effect drugs and three targeted drugs with moderate to good consistency in drug sensitivity data between GDSC and CCLE. For three other targeted drugs, there were not enough sensitive cell lines to assess the consistency of the pharmacological profiles. We found evidence of inconsistencies in pharmacological phenotypes for the remaining eight drugs. Overall, our findings suggest that the drug sensitivity data in GDSC and CCLE continue to present challenges for robust biomarker discovery. This re-analysis provides additional support for the argument that experimental standardization and validation of pharmacogenomic response will be necessary to advance the broad use of large pharmacogenomic screens.', '2026-07-07 20:49:01');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2256186434', 'plant-biology', 'Size Control in Plants—Lessons from Leaves and Flowers', 'To achieve optimal functionality, plant organs like leaves and petals have to grow to a certain size. Beginning with a limited number of undifferentiated cells, the final size of an organ is attained…', '2015', 2015, 96, 96, 'https://cshperspectives.cshlp.org/adsystem/graphics/8842236969244882/cshperspect/Long_Oligos_anim_480x60.gif?ad=50842&adview=true', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4526744', 'pmc', 'review', 'Cold Spring Harbor Perspectives in Biology', '["Hjördis Czesnick","Michael Lenhard"]', 'plant biology', 'To achieve optimal functionality, plant organs like leaves and petals have to grow to a certain size. Beginning with a limited number of undifferentiated cells, the final size of an organ is attained by a complex interplay of cell proliferation and subsequent cell expansion. Regulatory mechanisms that integrate intrinsic growth signals and environmental cues are required to enable optimal leaf and flower development. This review focuses on plant-specific principles of growth reaching from the cellular to the organ level. The currently known genetic pathways underlying these principles are summarized and network connections are highlighted. Putative non-cell autonomously acting mechanisms that might coordinate plant-cell growth are discussed.', '2026-07-07 20:50:21');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4252374256', 'plant-biology', 'Preprocessed Consortium for Neuropsychiatric Phenomics dataset', 'Here we present preprocessed MRI data of 265 participants from the Consortium for Neuropsychiatric Phenomics (CNP) dataset. The preprocessed dataset includes minimally preprocessed data in the…', '2017', 2017, 93, 93, 'https://f1000research-files.f1000.com/manuscripts/12934/d8548c5d-723b-4388-9be6-43df67fd1467_figure1.gif', 'https://doi.org/10.12688/f1000research.11964.1', 'repository', 'preprint', 'F1000Research', '["Krzysztof J. Gorgolewski","Joke Durnez","Russell A. Poldrack"]', 'plant biology', 'Here we present preprocessed MRI data of 265 participants from the Consortium for Neuropsychiatric Phenomics (CNP) dataset. The preprocessed dataset includes minimally preprocessed data in the native, MNI and surface spaces accompanied with potential confound regressors, tissue probability masks, brain masks and transformations. In addition the preprocessed dataset includes unthresholded group level and single subject statistical maps from all tasks included in the original dataset. We hope that availability of this dataset will greatly accelerate research.', '2026-07-07 20:51:50');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4234639590', 'plant-biology', 'Carrying out streamlined routine data analyses with reports for observational studies: introduction to a series of generic SAS® macros', 'For a typical medical research project based on observational data, sequential routine analyses are often essential to comprehend the data on hand and to draw valid conclusions. However, generating…', '2018', 2018, 89, 89, 'https://f1000research-files.f1000.com/manuscripts/18441/b8231dc0-967f-40f2-a971-4e373baf511a_figure1.gif', 'https://doi.org/10.12688/f1000research.16866.1', 'repository', 'preprint', 'F1000Research', '["Yuan Liu","Dana Nickleach","Chao Zhang","Jeffrey M. Switchenko","Jeanne Kowalski"]', 'plant biology', 'For a typical medical research project based on observational data, sequential routine analyses are often essential to comprehend the data on hand and to draw valid conclusions. However, generating reports in SAS ® for routine analyses can be a time-consuming and tedious process, especially when dealing with large databases with a massive number of variables in an iterative and collaborative research environment. In this work, we present a general workflow of research based on an observational database and a series of SAS ® macros that fits this framework, which covers a streamlined data analyses and produces journal-quality summary tables. The system is generic enough to fit a variety of research projects and enables researchers to build a highly organized and concise coding for quick updates as research evolves. The result reports promote communication in collaborations and will escort the research with ease and efficiency.', '2026-07-07 20:53:35');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4235632790', 'plant-biology', 'False positives in trans-eQTL and co-expression analyses arising from RNA-sequencing alignment errors', 'Sequence similarity among distinct genomic regions can lead to errors in alignment of short reads from next-generation sequencing. While this is well known, the downstream consequences of…', '2018', 2018, 86, 86, 'https://f1000research-files.f1000.com/manuscripts/18744/a0a9ce92-bde6-4dec-944d-275cd4ed7493_figure1.gif', 'https://doi.org/10.12688/f1000research.17145.1', 'repository', 'preprint', 'F1000Research', '["Ashis Saha","Alexis Battle"]', 'plant biology', 'Sequence similarity among distinct genomic regions can lead to errors in alignment of short reads from next-generation sequencing. While this is well known, the downstream consequences of misalignment have not been fully characterized. We assessed the potential for incorrect alignment of RNA-sequencing reads to cause false positives in both gene expression quantitative trait locus (eQTL) and co-expression analyses. Trans-eQTLs identified from human RNA-sequencing studies appeared to be particularly affected by this phenomenon, even when only uniquely aligned reads are considered. Over 75\% of trans-eQTLs using a standard pipeline occurred between regions of sequence similarity and therefore could be due to alignment errors. Further, associations due to mapping errors are likely to misleadingly replicate between studies. To help address this problem, we quantified the potential for "cross-mapping'''' to occur between every pair of annotated genes in the human genome. Such cross-mapping data can be used to filter or flag potential false positives in both trans-eQTL and co-expression analyses. Such filtering substantially alters the detection of significant associations and can have an impact on the assessment of false discovery rate, functional enrichment, and replication for RNA-sequencing association studies.', '2026-07-07 20:55:19');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1970192788', 'plant-biology', 'Phytomonas: Trypanosomatids Adapted to Plant Environments', 'Over 100 years after trypanosomatids were first discovered in plant tissues, Phytomonas parasites have now been isolated across the globe from members of 24 different plant families. Most identified…', '2015', 2015, 85, 85, 'https://journals.plos.org/plospathogens/article/figure/image?size=large&id=10.1371/journal.ppat.1004484.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4301809', 'pmc', 'review', 'PLoS Pathogens', '["Eleanor Jaskowska","Claire Butler","Gail M. Preston","Steven Kelly"]', 'plant biology', 'Over 100 years after trypanosomatids were first discovered in plant tissues, Phytomonas parasites have now been isolated across the globe from members of 24 different plant families. Most identified species have not been associated with any plant pathology and to date only two species are definitively known to cause plant disease. These diseases (wilt of palm and coffee phloem necrosis) are problematic in areas of South America where they threaten the economies of developing countries. In contrast to their mammalian infective relatives, our knowledge of the biology of Phytomonas parasites and how they interact with their plant hosts is limited. This review draws together a century of research into plant trypanosomatids, from the first isolations and experimental infections to the recent publication of the first Phytomonas genomes. The availability of genomic data for these plant parasites opens a new avenue for comparative investigations into trypanosomatid biology and provides fresh insight into how this important group of parasites have adapted to survive in a spectrum of hosts from crocodiles to coconuts.', '2026-07-07 20:56:24');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4291170379', 'plant-biology', 'Solanum lycopersicum, a Model Plant for the Studies in Developmental Biology, Stress Biology and Food Science', 'Fruits, vegetables and other plant-derived foods contribute important ingredients for human diets, and are thus favored by consumers worldwide. Among these horticultural crops, tomato belongs to the…', '2022', 2022, 84, 84, 'https://pub.mdpi-res.com/foods/foods-11-02402/article_deploy/html/images/foods-11-02402-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/9407197', 'pmc', 'review', 'Foods', '["Wei Liu","Kui Liu","Daoguo Chen","Zhanquan Zhang","Boqiang Li","Mohamed M. El-Mogy","Shiping Tian","Tong Chen"]', 'plant biology', 'Fruits, vegetables and other plant-derived foods contribute important ingredients for human diets, and are thus favored by consumers worldwide. Among these horticultural crops, tomato belongs to the Solanaceae family, ranks only secondary to potato (S. tuberosum L.) in yields and is widely cultivated for fresh fruit and processed foods owing to its abundant nutritional constituents (including vitamins, dietary fibers, antioxidants and pigments). Aside from its important economic and nutritional values, tomato is also well received as a model species for the studies on many fundamental biological events, including regulations on flowering, shoot apical meristem maintenance, fruit ripening, as well as responses to abiotic and biotic stresses (such as light, salinity, temperature and various pathogens). Moreover, tomato also provides abundant health-promoting secondary metabolites (flavonoids, phenolics, alkaloids, etc.), making it an excellent source and experimental system for investigating nutrient biosynthesis and availability in food science. Here, we summarize some latest results on these aspects, which may provide some references for further investigations on developmental biology, stress signaling and food science.', '2026-07-07 20:56:46');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2727138777', 'plant-biology', 'Post-chikungunya chronic inflammatory rheumatism: results from a retrospective follow-up study of 283 adult and child cases in La Virginia, Risaralda, Colombia', 'Objective: There are limited studies in Latin America regarding the chronic consequences of the Chikungunya virus (CHIK), such as post-CHIK chronic inflammatory rheumatism (pCHIK-CIR). We assessed…', '2016', 2016, 80, 80, 'https://f1000research-files.f1000.com/manuscripts/8857/a424f2dc-b1dc-40f2-8244-be5b061e18b9_figure1.gif', 'https://doi.org/10.12688/f1000research.8235.1', 'repository', 'preprint', 'F1000Research', '["Alfonso J. Rodríguez‐Morales","Andrés Felipe Gil-Restrepo","Valeria Ramírez-Jaramillo","Cindy P. Montoya-Arias","Wilmer F. Acevedo-Mendoza","Juan E. Bedoya-Arias","Laura A. Chica-Quintero","David R. Murillo-García","Juan Esteban García-Robledo","Juan Daniel Castrillón-Spitia","José J. Londoño","Héctor D. Bedoya-Rendón","Javier de Jesús Cárdenas-Pérez","Jaime A. Cardona‐Ospina","Guillermo J. Lagos-Grisales"]', 'plant biology', 'Objective: There are limited studies in Latin America regarding the chronic consequences of the Chikungunya virus (CHIK), such as post-CHIK chronic inflammatory rheumatism (pCHIK-CIR). We assessed the largest cohort so far of pCHIK-CIR in Latin America, at the municipality of La Virginia, Risaralda, a new endemic area of CHIK in Colombia. Methods: We conducted a cohort retrospective study in Colombia of 283 patients diagnosed with CHIK that persisted with pCHIK-CIR after a minimum of 6 weeks and up to a maximum of 26.1 weeks. pCHIK cases were identified according to validated criteria via telephone. Results: Of the total CHIK-infected subjects, 152 (53.7%) reported persistent rheumatological symptoms (pCHIK-CIR). All of these patients reported joint pains (chronic polyarthralgia, pCHIK-CPA), 49.5% morning stiffness, 40.6% joint edema, and 16.6% joint redness. Of all patients, 19.4% required and attended for care prior to the current study assessment (1.4% consulting rheumatologists). Significant differences in the frequency were observed according to age groups and gender. Patients aged &gt;40 years old required more medical attention (39.5%) than those ≤40 years-old (12.1%) (RR=4.748, 95%CI 2.550-8.840). Conclusions: According to our results, at least half of the patients with CHIK developed chronic rheumatologic sequelae, and from those with pCHIK-CPA, nearly half presented clinical symptoms consistent with inflammatory forms of the disease. These results support previous estimates obtained from pooled data of studies in La Reunion (France) and India and are consistent with the results published previously from other Colombian cohorts in Venadillo (Tolima) and Since (Sucre).', '2026-07-07 20:58:23');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2796441808', 'plant-biology', 'Biology in Bloom: A Primer on the <i>Arabidopsis thaliana</i> Model System', 'Abstract Arabidopsis thaliana could have easily escaped human scrutiny. Instead, Arabidopsis has become the most widely studied plant in modern biology despite its absence from the dinner table.…', '2018', 2018, 80, 80, 'https://cdn.ncbi.nlm.nih.gov/pmc/blobs/75f3/5887134/669e8ac3c6b6/1337fig1.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5887134', 'pmc', 'review', 'Genetics', '["Andrew W. Woodward","Bonnie Bartel"]', 'plant biology', 'Abstract Arabidopsis thaliana could have easily escaped human scrutiny. Instead, Arabidopsis has become the most widely studied plant in modern biology despite its absence from the dinner table. Pairing diminutive stature and genome with prodigious resources and tools, Arabidopsis offers a window into the molecular, cellular, and developmental mechanisms underlying life as a multicellular photoautotroph. Many basic discoveries made using this plant have spawned new research areas, even beyond the verdant fields of plant biology. With a suite of resources and tools unmatched among plants and rivaling other model systems, Arabidopsis research continues to offer novel insights and deepen our understanding of fundamental biological processes.', '2026-07-07 20:58:32');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4245957864', 'plant-biology', 'Real-time 3D Photoacoustic Visualization System with a Wide Field of View for Imaging Human Limbs', 'Background : A breast-specific photoacoustic imaging (PAI) system prototype equipped with a hemispherical detector array (HDA) has been reported as a promising system configuration for providing high…', '2018', 2018, 68, 68, 'https://f1000research-files.f1000.com/manuscripts/18301/25d29fcb-20af-4390-9151-160169206d0f_figure1.gif', 'https://doi.org/10.12688/f1000research.16743.1', 'repository', 'preprint', 'F1000Research', '["Kenichi Nagae","Yasufumi Asao","Yoshiaki Sudo","Naoyuki Murayama","Yuusuke Tanaka","Katsumi Ohira","Yoshihiro Ishida","Atsushi Otsuka","Yoshiaki Matsumoto","Susumu Saito","Moritoshi Furu","Koichi Murata","Hiroyuki Sekiguchi","Masako Kataoka","Aya Yoshikawa","Tomoko Ishii","Kaori Togashi","Tsuyoshi Shiina","Kenji Kabashima","Masakazu Toi","T. Yagi"]', 'plant biology', 'Background : A breast-specific photoacoustic imaging (PAI) system prototype equipped with a hemispherical detector array (HDA) has been reported as a promising system configuration for providing high morphological reproducibility for vascular structures in living bodies. Methods : To image the vasculature of human limbs, a newly designed PAI system prototype (PAI-05) with an HDA with a higher density sensor arrangement was developed. The basic device configuration mimicked that of a previously reported breast-specific PAI system. A new imaging table and a holding tray for imaging a subject''s limb were adopted. Results : The device’s performance was verified using a phantom. Contrast of 8.5 was obtained at a depth of 2 cm, and the viewing angle reached up to 70 degrees, showing sufficient performance for limb imaging. An arbitrary wavelength was set, and a reasonable PA signal intensity dependent on the wavelength was obtained. To prove the concept of imaging human limbs, various parts of the subject were scanned. High-quality still images of a living human with a wider size than that previously reported were obtained by scanning within the horizontal plane and averaging the images. The maximum field of view (FOV) was 270 mm × 180 mm. Even in movie mode, one-shot 3D volumetric data were obtained in an FOV range of 20 mm in diameter, which is larger than values in previous reports. By continuously acquiring these images, we were able to produce motion pictures. Conclusion : We developed a PAI prototype system equipped with an HDA suitable for imaging limbs. As a result, the subject could be scanned over a wide range while in a more comfortable position, and high-quality still images and motion pictures could be obtained.', '2026-07-07 21:03:49');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4235501706', 'plant-biology', 'rmcorrShiny: A web and standalone application for repeated measures correlation', 'We describe a web and standalone Shiny app for calculating the common, linear within-individual association for repeated assessments of paired measures with multiple individuals: repeated measures…', '2021', 2021, 67, 67, 'https://f1000research-files.f1000.com/manuscripts/58566/788883f8-5984-4d2b-8418-e9e10684eb9a_figure1.gif', 'https://doi.org/10.12688/f1000research.55027.1', 'repository', 'preprint', 'F1000Research', '["Laura R. Marusich","Jonathan Z. Bakdash"]', 'plant biology', 'We describe a web and standalone Shiny app for calculating the common, linear within-individual association for repeated assessments of paired measures with multiple individuals: repeated measures correlation (rmcorr). This tool makes rmcorr more widely accessible, providing a graphical interface for performing and visualizing the output of analysis with rmcorr. In contrast to rmcorr, most widely used correlation techniques assume paired data are independent. Incorrectly analyzing repeated measures data as independent will likely produce misleading results. Using aggregation or separate models to address the issue of independence may obscure meaningful patterns and will also tend to reduce statistical power. rmcorrShiny (repeated measures correlation Shiny) provides a simple and accessible solution for computing the repeated measures correlation. It is available at: https://lmarusich.shinyapps.io/shiny_rmcorr/.', '2026-07-07 21:04:26');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3094482919', 'plant-biology', 'Peer review and preprint policies are unclear at most major journals', 'Clear and findable publishing policies are important for authors to choose appropriate journals for publication. We investigated the clarity of policies of 171 major academic journals across…', '2020', 2020, 66, 66, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0239518.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7577440', 'pmc', 'article', 'PLoS ONE', '["Thomas Klebel","Stefan Reichmann","Jessica Polka","Gary S. McDowell","Naomi Penfold","Samantha Hindle","Tony Ross‐Hellauer"]', 'plant biology', 'Clear and findable publishing policies are important for authors to choose appropriate journals for publication. We investigated the clarity of policies of 171 major academic journals across disciplines regarding peer review and preprinting. 31.6% of journals surveyed do not provide information on the type of peer review they use. Information on whether preprints can be posted or not is unclear in 39.2% of journals. 58.5% of journals offer no clear information on whether reviewer identities are revealed to authors. Around 75% of journals have no clear policy on co-reviewing, citation of preprints, and publication of reviewer identities. Information regarding practices of open peer review is even more scarce, with <20% of journals providing clear information. Having found a lack of clear information, we conclude by examining the implications this has for researchers (especially early career) and the spread of open research practices.', '2026-07-07 21:05:06');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2466373387', 'plant-biology', '“White Paper” meeting summary and catalyst for future inquiry: Complex mechanisms linking neurocognitive dysfunction to insulin resistance and other metabolic dysfunction', 'Scientific evidence has established several links between metabolic and neurocognitive dysfunction, and epidemiologic evidence has revealed an increased risk of Alzheimer’s disease and vascular…', '2016', 2016, 65, 65, 'https://f1000research-files.f1000.com/manuscripts/8926/01f51c1f-773b-4372-9097-44f98c5462cd_figure1.gif', 'https://doi.org/10.12688/f1000research.8300.1', 'repository', 'preprint', 'F1000Research', '["Luke E. Stoeckel","Zoe Arvanitakis","Sam Gandy","Dana M. Small","C. Ronald Kahn","Álvaro Pascual‐Leone","Aaron C. Pawlyk","Robert Sherwin","Philip J Smith"]', 'plant biology', 'Scientific evidence has established several links between metabolic and neurocognitive dysfunction, and epidemiologic evidence has revealed an increased risk of Alzheimer’s disease and vascular dementia in patients with diabetes. In July 2015, the National Institute of Diabetes, Digestive, and Kidney Diseases gathered experts from multiple clinical and scientific disciplines, in a workshop entitled “The Intersection of Metabolic and Neurocognitive Dysfunction”, to clarify the state-of-the-science on the mechanisms linking metabolic dysfunction, and insulin resistance and diabetes in particular, to neurocognitive impairment and dementia. This perspective is intended to serve as a summary of the opinions expressed at this meeting, which focused on identifying gaps and opportunities to advance research in this emerging area with important public health relevance.', '2026-07-07 21:05:10');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2604017328', 'plant-biology', 'Recent advances in understanding Epstein-Barr virus', 'Epstein-Barr virus (EBV) is a common human herpes virus known to infect the majority of the world population. Infection with EBV is often asymptomatic but can manifest in a range of pathologies from…', '2017', 2017, 64, 64, 'https://f1000research-files.f1000.com/manuscripts/11413/ef53ac9b-d0db-4287-918f-1d794a266161_figure1.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5373418', 'pmc', 'preprint', 'F1000Research', '["Brent Stanfield","Micah A. Luftig"]', 'plant biology', 'Epstein-Barr virus (EBV) is a common human herpes virus known to infect the majority of the world population. Infection with EBV is often asymptomatic but can manifest in a range of pathologies from infectious mononucleosis to severe cancers of epithelial and lymphocytic origin. Indeed, in the past decade, EBV has been linked to nearly 10% of all gastric cancers. Furthermore, recent advances in high-throughput next-generation sequencing and the development of humanized mice, which effectively model EBV pathogenesis, have led to a wealth of knowledge pertaining to strain variation and host-pathogen interaction. This review highlights some recent advances in our understanding of EBV biology, focusing on new findings on the early events of infection, the role EBV plays in gastric cancer, new strain variation, and humanized mouse models of EBV infection.', '2026-07-07 21:06:18');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2156642684', 'plant-biology', 'Exogenous salicylic acid-triggered changes in the glutathione transferases and peroxidases are key factors in the successful salt stress acclimation of Arabidopsis thaliana', 'Salicylic acid (SA) applied exogenously is a potential priming agent during abiotic stress. In our experiments, the priming effect of SA was tested by exposing Arabidopsis thaliana (L.) Heynh. plants…', '2015', 2015, 60, 60, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1071/fp15119.g001', 'https://pubmed.ncbi.nlm.nih.gov/32480751', 'repository', 'article', 'Functional Plant Biology', '["Edit Horváth","Szilvia Brunner","Krisztina Bela","Csaba Papdi","László Szabados","Irma Tari","Jolán Csiszár"]', 'plant biology', 'Salicylic acid (SA) applied exogenously is a potential priming agent during abiotic stress. In our experiments, the priming effect of SA was tested by exposing Arabidopsis thaliana (L.) Heynh. plants to 2-week-long 10-9-10-5 M SA pretreatments in a hydroponic medium, followed by 1 week of 100mM NaCl stress. The levels of reactive oxygen species and H2O2, changes in antioxidant enzyme activity and the expression of selected glutathione transferase (GST) genes were investigated. Although 10-9-10-7 M SA pretreatment insufficiently induced defence mechanisms during the subsequent salt stress, 2-week pretreatments with 10-6 and 10-5 M SA alleviated the salinity-induced H2O2 and malondialdehyde accumulation, and increased superoxide dismutase, guaiacol peroxidase, GST and glutathione peroxidase (GPOX) activity. Our results indicate that long-term 10-6 and 10-5 M SA treatment mitigated the salt stress injury in this model plant. Enhanced expression of AtGSTU19 and AtGSTU24 may be responsible for the induced GST and GPOX activity, which may play an important role in acclimation. Modified GST expression suggested altered signalling in SA-hardened plants during salt stress. The hydroponic system applied in our experiments proved to be a useful tool for studying the effects of sequential treatments in A. thaliana.', '2026-07-07 21:07:29');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2265054258', 'plant-biology', 'Open drug discovery for the Zika virus', 'The Zika virus (ZIKV) outbreak in the Americas has caused global concern that we may be on the brink of a healthcare crisis. The lack of research on ZIKV in the over 60 years that we have known about…', '2016', 2016, 58, 58, 'https://f1000research-files.f1000.com/manuscripts/8622/c7d1bc42-98ad-4e1e-9838-6ef46d1b20c2_figure1.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4841202', 'pmc', 'preprint', 'F1000Research', '["Sean Ekins","Daniel Mietchen","Megan Coffee","Thomas P. Stratton","Joel S. Freundlich","Lúcio H. Freitas-Júnior","Eugene Muratov","Jair L. Siqueira-Neto","Antony Williams","Carolina Horta Andrade"]', 'plant biology', 'The Zika virus (ZIKV) outbreak in the Americas has caused global concern that we may be on the brink of a healthcare crisis. The lack of research on ZIKV in the over 60 years that we have known about it has left us with little in the way of starting points for drug discovery. Our response can build on previous efforts with virus outbreaks and lean heavily on work done on other flaviviruses such as dengue virus. We provide some suggestions of what might be possible and propose an open drug discovery effort that mobilizes global science efforts and provides leadership, which thus far has been lacking. We also provide a listing of potential resources and molecules that could be prioritized for testing as in vitro assays for ZIKV are developed. We propose also that in order to incentivize drug discovery, a neglected disease priority review voucher should be available to those who successfully develop an FDA approved treatment. Learning from the response to the ZIKV, the approaches to drug discovery used and the success and failures will be critical for future infectious disease outbreaks.', '2026-07-07 21:09:40');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3132005273', 'plant-biology', 'Registration of spatio-temporal point clouds of plants for phenotyping', 'Plant phenotyping is a central task in crop science and plant breeding. It involves measuring plant traits to describe the anatomy and physiology of plants and is used for deriving traits and…', '2021', 2021, 57, 57, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0247243.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7906482', 'pmc', 'article', 'PLoS ONE', '["Nived Chebrolu","Federico Magistri","Thomas Läbe","Cyrill Stachniss"]', 'plant biology', 'Plant phenotyping is a central task in crop science and plant breeding. It involves measuring plant traits to describe the anatomy and physiology of plants and is used for deriving traits and evaluating plant performance. Traditional methods for phenotyping are often time-consuming operations involving substantial manual labor. The availability of 3D sensor data of plants obtained from laser scanners or modern depth cameras offers the potential to automate several of these phenotyping tasks. This automation can scale up the phenotyping measurements and evaluations that have to be performed to a larger number of plant samples and at a finer spatial and temporal resolution. In this paper, we investigate the problem of registering 3D point clouds of the plants over time and space. This means that we determine correspondences between point clouds of plants taken at different points in time and register them using a new, non-rigid registration approach. This approach has the potential to form the backbone for phenotyping applications aimed at tracking the traits of plants over time. The registration task involves finding data associations between measurements taken at different times while the plants grow and change their appearance, allowing 3D models taken at different points in time to be compared with each other. Registering plants over time is challenging due to its anisotropic growth, changing topology, and non-rigid motion in between the time of the measurements. Thus, we propose a novel approach that first extracts a compact representation of the plant in the form of a skeleton that encodes both topology and semantic information, and then use this skeletal structure to determine correspondences over time and drive the registration process. Through this approach, we can tackle the data association problem for the time-series point cloud data of plants effectively. We tested our approach on different datasets acquired over time and successfully registered the 3D plant point clouds recorded with a laser scanner. We demonstrate that our method allows for developing systems for automated temporal plant-trait analysis by tracking plant traits at an organ level.', '2026-07-07 21:09:59');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4252678359', 'plant-biology', 'Investigation of chimeric reads using the MinION', 'Following a nanopore sequencing run of PCR products of three amplicons less than 1kb, an abundance of reads failed quality control due to template/complement mismatch. A BLAST search demonstrated…', '2017', 2017, 55, 55, 'https://f1000research-files.f1000.com/manuscripts/12473/5fad195b-3555-4482-9bb8-2e1be7addd18_figure1.gif', 'https://doi.org/10.12688/f1000research.11547.1', 'repository', 'preprint', 'F1000Research', '["Ruby White","Christophe Pellefigues","Franca Ronchese","Olivier Lamiable","David Eccles"]', 'plant biology', 'Following a nanopore sequencing run of PCR products of three amplicons less than 1kb, an abundance of reads failed quality control due to template/complement mismatch. A BLAST search demonstrated that some of the failed reads mapped to two different genes -- an unexpected observation, given that PCR was carried out separately for each amplicon. A further investigation was carried out specifically to search for chimeric reads, using separate barcodes for each amplicon and trying two different ligation methods prior to sample loading. Despite the separation of ligation products, chimeric reads formed from different amplicons were still observed in the base-called sequence.The long-read nature of nanopore sequencing presents an effective tool for the discovery and filtering of chimeric reads. We have found that at least 1.7% of reads prepared using the Nanopore LSK002 2D Ligation Kit include post-amplification chimeric elements. This finding has potential implications for other amplicon sequencing technologies, as the process is unlikely to be specific to the sample preparation used for nanopore sequencing.', '2026-07-07 21:13:07');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1864482449', 'plant-biology', 'A citation-based, author- and age-normalized, logarithmic index for evaluation of individual researchers independently of publication counts', 'The use of citation metrics for evaluation of individual researchers has dramatically increased over the last decade. However, currently existing indices either are based on misleading premises or…', '2015', 2015, 54, 54, 'https://f1000research-files.f1000.com/manuscripts/7610/3d28ba53-ad21-41d2-b627-bbb33b5ffcf5_figure1.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4654436', 'pmc', 'preprint', 'F1000Research', '["Aleksey V. Belikov","В. В. Беликов"]', 'plant biology', 'The use of citation metrics for evaluation of individual researchers has dramatically increased over the last decade. However, currently existing indices either are based on misleading premises or are cumbersome to implement. This leads to poor assessment of researchers and creates dangerous trends in science, such as overproduction of low quality articles. Here we propose an index (namely, the L-index) that does not depend on the number of publications, accounts for different co-author contributions and age of publications, and scales from 0.0 to 9.9. Moreover, it can be calculated with the help of freely available software.', '2026-07-07 21:13:10');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3120523561', 'plant-biology', 'Current market rates for scholarly publishing services', 'For decades, the supra-inflation increase of subscription prices for scholarly journals has concerned scholarly institutions. After years of fruitless efforts to solve this “serials crisis”, open…', '2021', 2021, 53, 53, 'https://f1000research-files.f1000.com/manuscripts/57214/249db17b-d4f8-474b-a210-c627c1d46b0d_figure1.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8276192', 'pmc', 'preprint', 'F1000Research', '["Alexander Grossmann","Björn Brembs"]', 'plant biology', 'For decades, the supra-inflation increase of subscription prices for scholarly journals has concerned scholarly institutions. After years of fruitless efforts to solve this “serials crisis”, open access has been proposed as the latest potential solution. However, also the prices for open access publishing are high and are rising well beyond inflation. What has been missing from the public discussion so far is a quantitative approach to determine the actual costs of efficiently publishing a scholarly article using state-of-the-art technologies, such that informed decisions can be made as to appropriate price levels. Here we provide a granular, step-by-step calculation of the costs associated with publishing primary research articles, from submission, through peer-review, to publication, indexing and archiving. We find that these costs range from less than US$200 per article in modern, large scale publishing platforms using post-publication peer-review, to about US$1,000 per article in prestigious journals with rejection rates exceeding 90%. The publication costs for a representative scholarly article today come to lie at around US$400. These results appear uncontroversial as they not only match previous data using different methodologies, but also conform to the costs that many publishers have openly or privately shared. We discuss the numerous additional non-publication items that make up the difference between these publication costs and final price at the more expensive, legacy publishers.', '2026-07-07 21:14:44');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2563052372', 'plant-biology', 'A Bioconductor workflow for processing and analysing spatial proteomics data', 'Spatial proteomics is the systematic study of protein sub-cellular localisation. In this workflow, we describe the analysis of a typical quantitative mass spectrometry-based spatial proteomics…', '2018', 2018, 52, 52, 'https://f1000research-files.f1000.com/manuscripts/16436/c86624d8-34cd-4584-96d8-e99a96f8be6b_figure1.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6053703', 'pmc', 'preprint', 'F1000Research', '["Lisa M. Breckels","Claire M. Mulvey","Kathryn S. Lilley","Laurent Gatto"]', 'plant biology', 'Spatial proteomics is the systematic study of protein sub-cellular localisation. In this workflow, we describe the analysis of a typical quantitative mass spectrometry-based spatial proteomics experiment using the MSnbase and pRoloc Bioconductor package suite. To walk the user through the computational pipeline, we use a recently published experiment predicting protein sub-cellular localisation in pluripotent embryonic mouse stem cells. We describe the software infrastructure at hand, importing and processing data, quality control, sub-cellular marker definition, visualisation and interactive exploration. We then demonstrate the application and interpretation of statistical learning methods, including novelty detection using semi-supervised learning, classification, clustering and transfer learning and conclude the pipeline with data export. The workflow is aimed at beginners who are familiar with proteomics in general and spatial proteomics in particular.', '2026-07-07 21:16:31');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4238227044', 'plant-biology', 'Recent advances in understanding the complexities of metastasis', 'Tumour metastasis is a dynamic and systemic process. It is no longer seen as a tumour cell-autonomous program but as a multifaceted and complex series of events, which is influenced by the intrinsic…', '2018', 2018, 52, 52, 'https://f1000research-files.f1000.com/manuscripts/16400/d2a0cb89-bb62-4327-9692-2aa461db29ca_figure1.gif', 'https://doi.org/10.12688/f1000research.15064.1', 'repository', 'preprint', 'F1000Research', '["Jessica L. Chitty","Elysse C. Filipe","Morghan C. Lucas","David Herrmann","Thomas R. Cox","Paul Timpson"]', 'plant biology', 'Tumour metastasis is a dynamic and systemic process. It is no longer seen as a tumour cell-autonomous program but as a multifaceted and complex series of events, which is influenced by the intrinsic cellular mutational burden of cancer cells and the numerous bidirectional interactions between malignant and non-malignant cells and fine-tuned by the various extrinsic cues of the extracellular matrix. In cancer biology, metastasis as a process is one of the most technically challenging aspects of cancer biology to study. As a result, new platforms and technologies are continually being developed to better understand this process. In this review, we discuss some of the recent advances in metastasis and how the information gleaned is re-shaping our understanding of metastatic dissemination.', '2026-07-07 21:17:26');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3134833671', 'plant-biology', 'Use of the journal impact factor for assessing individual articles: Statistically flawed or not? [version 2; peer review: 2 approved]', 'Most scientometricians reject the use of the journal impact factor for assessing individual articles and their authors. The well-known San Francisco Declaration on Research Assessment also strongly…', '2021', 2021, 49, 49, 'https://f1000research-files.f1000.com/manuscripts/54872/a10796b7-4e23-4e49-9676-81d57db02594_figure1.gif', 'https://doi.org/10.12688/f1000research.23418.2', 'repository', 'preprint', 'DOAJ (DOAJ: Directory of Open Access Journals)', '["Ludo Waltman","Vincent Traag"]', 'plant biology', 'Most scientometricians reject the use of the journal impact factor for assessing individual articles and their authors. The well-known San Francisco Declaration on Research Assessment also strongly objects against this way of using the impact factor. Arguments against the use of the impact factor at the level of individual articles are often based on statistical considerations. The skewness of journal citation distributions typically plays a central role in these arguments. We present a theoretical analysis of statistical arguments against the use of the impact factor at the level of individual articles. Our analysis shows that these arguments do not support the conclusion that the impact factor should not be used for assessing individual articles. Using computer simulations, we demonstrate that under certain conditions the number of citations an article has received is a more accurate indicator of the value of the article than the impact factor. However, under other conditions, the impact factor is a more accurate indicator. It is important to critically discuss the dominant role of the impact factor in research evaluations, but the discussion should not be based on misplaced statistical arguments. Instead, the primary focus should be on the socio-technical implications of the use of the impact factor.', '2026-07-07 21:19:52');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4232061444', 'plant-biology', 'Infrastructure for genomic interactions: Bioconductor classes for Hi-C, ChIA-PET and related experiments', 'The study of genomic interactions has been greatly facilitated by techniques such as chromatin conformation capture with high-throughput sequencing (Hi-C). These genome-wide experiments generate…', '2016', 2016, 48, 48, 'https://f1000research-files.f1000.com/manuscripts/9426/9a4b03d3-878c-47dc-9db7-5f1d24c8adff_figure1.gif', 'https://doi.org/10.12688/f1000research.8759.1', 'repository', 'preprint', 'F1000Research', '["Aaron T. L. Lun","Malcolm Perry","Elizabeth Ing‐Simmons"]', 'plant biology', 'The study of genomic interactions has been greatly facilitated by techniques such as chromatin conformation capture with high-throughput sequencing (Hi-C). These genome-wide experiments generate large amounts of data that require careful analysis to obtain useful biological conclusions. However, development of the appropriate software tools is hindered by the lack of basic infrastructure to represent and manipulate genomic interaction data. Here, we present the InteractionSet package that provides classes to represent genomic interactions and store their associated experimental data, along with the methods required for low-level manipulation and processing of those classes. The InteractionSet package exploits existing infrastructure in the open-source Bioconductor project, while in turn being used by Bioconductor packages designed for higher-level analyses. For new packages, use of the functionality in InteractionSet will simplify development, allow access to more features and improve interoperability between packages.', '2026-07-07 21:20:16');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2548172335', 'plant-biology', 'Chromatin Biology Impacts Adaptive Evolution of Filamentous Plant Pathogens', 'An organism’s adaptation to changing environments is fueled by its genetic variability, which is established by mechanisms ranging from single-nucleotide polymorphisms to large-scale structural…', '2016', 2016, 47, 47, 'https://journals.plos.org/plospathogens/article/figure/image?size=large&id=10.1371/journal.ppat.1005920.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5094656', 'pmc', 'review', 'PLoS Pathogens', '["Michael Seidl","David E. Cook","Bart P. H. J. Thomma"]', 'plant biology', 'An organism’s adaptation to changing environments is fueled by its genetic variability, which is established by mechanisms ranging from single-nucleotide polymorphisms to large-scale structural variations, all of which affect chromosomal shape, organization, and gene content [1]. These processes are particularly relevant for pathogens that must respond to continual selection pressure arising from host immune systems that evolved to detect the presence or activity of potentialmicrobial pathogens through a variety of invasion patterns [2]. In their adaptive response, pathogens evolve strategies, often involving secreted effectormolecules, to overcome host immunity and support host colonization [3]. Thus, it can be anticipated that this coevolutionary arms race leads to highly specific interactions between adapted pathogens and their specific hosts. Paradoxically, particular pathogens successfully colonize a broad range of hosts, yet how such pathogens cope in arms races with such a diversity of hosts remains unknown.', '2026-07-07 21:20:39');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3007964334', 'plant-biology', 'Diversity of left-right symmetry breaking strategy in animals', 'Left-right (L-R) asymmetry of visceral organs in animals is established during embryonic development via a stepwise process. While some steps are conserved, different strategies are employed among…', '2020', 2020, 47, 47, 'https://f1000research-files.f1000.com/manuscripts/23890/101444ad-add0-41cf-98ea-678657092024_figure1.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7043131', 'pmc', 'preprint', 'F1000Research', '["Hiroshi Hamada","Patrick Tam"]', 'plant biology', 'Left-right (L-R) asymmetry of visceral organs in animals is established during embryonic development via a stepwise process. While some steps are conserved, different strategies are employed among animals for initiating the breaking of body symmetry. In zebrafish (teleost), Xenopus (amphibian), and mice (mammal), symmetry breaking is elicited by directional fluid flow at the L-R organizer, which is generated by motile cilia and sensed by mechanoresponsive cells. In contrast, birds and reptiles do not rely on the cilia-driven fluid flow. Invertebrates such as Drosophila and snails employ another distinct mechanism, where the symmetry breaking process is underpinned by cellular chirality acquired downstream of the molecular interaction of myosin and actin. Here, we highlight the convergent entry point of actomyosin interaction and planar cell polarity to the diverse L-R symmetry breaking mechanisms among animals.', '2026-07-07 21:21:50');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4249732730', 'plant-biology', 'Individuality, phenotypic differentiation, dormancy and ‘persistence’ in culturable bacterial systems: commonalities shared by environmental, laboratory, and clinical microbiology', 'For bacteria, replication mainly involves growth by binary fission. However, in a very great many natural environments there are examples of phenotypically dormant, non-growing cells that do not…', '2015', 2015, 43, 43, 'https://f1000research-files.f1000.com/manuscripts/7206/809aaaba-4368-422a-84f5-b21f2a8fd7ad_figure1.gif', 'https://doi.org/10.12688/f1000research.6709.1', 'repository', 'preprint', 'F1000Research', '["Douglas B. Kell","Marnie Potgieter","Etheresia Pretorius"]', 'plant biology', 'For bacteria, replication mainly involves growth by binary fission. However, in a very great many natural environments there are examples of phenotypically dormant, non-growing cells that do not replicate immediately and that are phenotypically ‘nonculturable’ on media that normally admit their growth. They thereby evade detection by conventional culture-based methods. Such dormant cells may also be observed in laboratory cultures and in clinical microbiology. They are usually more tolerant to stresses such as antibiotics, and in clinical microbiology they are typically referred to as ‘persisters’. Bacterial cultures necessarily share a great deal of relatedness, and inclusive fitness theory implies that there are conceptual evolutionary advantages in trading a variation in growth rate against its mean, equivalent to hedging one’s bets. There is much evidence that bacteria exploit this strategy widely. We here bring together data that show the commonality of these phenomena across environmental, laboratory and clinical microbiology. Considerable evidence, using methods similar to those common in environmental microbiology, now suggests that many supposedly non-communicable, chronic and inflammatory diseases are exacerbated (if not indeed largely caused) by the presence of dormant or persistent bacteria (the ability of whose components to cause inflammation is well known). This dormancy (and resuscitation therefrom) often reflects the extent of the availability of free iron. Together, these phenomena can provide a ready explanation for the continuing inflammation common to such chronic diseases and its correlation with iron dysregulation. This implies that measures designed to assess and to inhibit or remove such organisms (or their access to iron) might be of much therapeutic benefit.', '2026-07-07 21:27:35');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3014644244', 'plant-biology', 'Lithium and coronaviral infections. A scoping review.', 'The current rapid spread of the novel coronavirus (SARS-CoV-2) causing coronavirus disease 2019 (COVID-19) calls for a rapid response from the research community. Lithium is widely used to treat…', '2020', 2020, 42, 42, 'https://f1000research-files.f1000.com/manuscripts/25289/94ca0a9a-b251-434f-81af-794260358c41_figure1.gif', 'https://doi.org/10.12688/f1000research.22299.2', 'repository', 'preprint', 'F1000Research', '["Jan Krzysztof Nowak","Jarosław Walkowiak"]', 'plant biology', 'The current rapid spread of the novel coronavirus (SARS-CoV-2) causing coronavirus disease 2019 (COVID-19) calls for a rapid response from the research community. Lithium is widely used to treat bipolar disorder, but has been shown to exhibit antiviral activity. This brief review took a systematic approach to identify six in vitro studies reporting on the influence of lithium on coronaviral infections. We propose mechanistic investigation of the influence of lithium – alone and with chloroquine – on the SARS-CoV-2 infection.', '2026-07-07 21:30:13');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3208450127', 'plant-biology', 'Global prevalence and pathogenesis of headache in COVID-19: A systematic review and meta-analysis', 'Background : This study was conducted to determine the prevalence of headache in coronavirus disease 2019 (COVID-19) and to assess its association as a predictor for COVID-19. This study also aimed…', '2020', 2020, 41, 41, 'https://f1000research-files.f1000.com/manuscripts/30205/2d90dd5d-1a50-42f4-86c6-571d235c9e37_figure1.gif', 'https://doi.org/10.12688/f1000research.27334.1', 'repository', 'review', 'F1000Research', '["Endang Mutiawati","Syahrul Syahrul","Marhami Fahriani","Jonny Karunia Fajar","Sukamto S. Mamada","Helnida Anggun Maliga","Nur Samsu","Muhammad Ilmawan","Yeni Purnamasari","Anisa Asmiragani","Ichsan Ichsan","Talha Bin Emran","Ali A. Rabaan","Sri Masyeni","Firzan Nainu","Harapan Harapan"]', 'plant biology', 'Background : This study was conducted to determine the prevalence of headache in coronavirus disease 2019 (COVID-19) and to assess its association as a predictor for COVID-19. This study also aimed to discuss the possible pathogenesis of headache in COVID-19. Methods : Available articles from PubMed, Scopus, and Web of Science were searched as of September 2 nd , 2020. Data on characteristics of the study, headache and COVID-19 were extracted following the PRISMA guidelines. Biases were assessed using the Newcastle-Ottawa scale. The cumulative prevalence of headache was calculated for the general population (i.e. adults and children). The pooled odd ratio (OR) with 95% confidence intervals (95%CI) was calculated using the Z test to assess the association between headache and the presence of COVID-19 cases. Results : We included 104,751 COVID-19 cases from 78 eligible studies to calculate the global prevalence of headache in COVID-19 and 17 studies were included to calculate the association of headache and COVID-19. The cumulative prevalence of headache in COVID-19 was 25.2% (26,464 out of 104,751 cases). Headache was found to be more prevalent, approximately by two-fold, in COVID-19 patients than in non-COVID-19 patients with symptoms of other respiratory viral infections, OR: 1.73; 95% CI: 1.94, 2.5 with p=0.04. Conclusion : Headache is common among COVID-19 patients and seems to be more common in COVID-19 patients compared to those with the non-COVID-19 viral infection. No definitive mechanisms on how headache emerges in COVID-19 patients but several possible hypotheses have been proposed. However, extensive studies are warranted to elucidate the mechanisms. PROSPERO registration : CRD42020210332 (28/09/2020)', '2026-07-07 21:30:16');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3004501337', 'plant-biology', 'Recent Advances in Plant Chemical Biology of Jasmonates', 'Lipid-derived plant hormone jasmonates are implicated in plant growth, reproductive performance, senescence, secondary metabolite productions, and defense against both necrotrophic pathogens and…', '2020', 2020, 39, 39, 'https://pub.mdpi-res.com/ijms/ijms-21-01124/article_deploy/html/images/ijms-21-01124-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7036767', 'pmc', 'review', 'International Journal of Molecular Sciences', '["Minoru Ueda","Takuya Kaji","Wataru Kozaki"]', 'plant biology', 'Lipid-derived plant hormone jasmonates are implicated in plant growth, reproductive performance, senescence, secondary metabolite productions, and defense against both necrotrophic pathogens and feeding insects. A major jasmonate is (+)-7-iso-jasmonoyl-l-isoleucine (JA-Ile), which is perceived by the unique COI1-JAZ coreceptor system. Recent advances in plant chemical biology have greatly informed the bioscience of jasmonate, including the development of chemical tools such as the antagonist COR-MO; the agonist NOPh; and newly developed jasmonates, including JA-Ile-macrolactone and 12-OH-JA-Ile. This review article summarizes the current status of plant chemical biology as it pertains to jasmonates, and offers some perspectives for the future.', '2026-07-07 21:35:16');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4230085039', 'plant-biology', 'TreeSummarizedExperiment: a S4 class for data with hierarchical structure', 'Data organized into hierarchical structures (e.g., phylogenies or cell types) arises in several biological fields. It is therefore of interest to have data containers that store the hierarchical…', '2020', 2020, 38, 38, 'https://f1000research-files.f1000.com/manuscripts/29440/07ce820b-dde9-4215-bdc0-51e051729637_figure1.gif', 'https://doi.org/10.12688/f1000research.26669.1', 'repository', 'preprint', 'F1000Research', '["Ruizhu Huang","Charlotte Soneson","Felix G.M. Ernst","Kévin Rue-Albrecht","Guangchuang Yu","Stephanie C. Hicks","Mark D. Robinson"]', 'plant biology', 'Data organized into hierarchical structures (e.g., phylogenies or cell types) arises in several biological fields. It is therefore of interest to have data containers that store the hierarchical structure together with the biological profile data, and provide functions to easily access or manipulate data at different resolutions. Here, we present TreeSummarizedExperiment, a R/S4 class that extends the commonly used SingleCellExperiment class by incorporating tree representations of rows and/or columns (represented by objects of the phylo class). It follows the convention of the SummarizedExperiment class, while providing links between the assays and the nodes of a tree to allow data manipulation at arbitrary levels of the tree. The package is designed to be extensible, allowing new functions on the tree (phylo) to be contributed. As the work is based on the SingleCellExperiment class and the phylo class, both of which are popular classes used in many R packages, it is expected to be able to interact seamlessly with many other tools.', '2026-07-07 21:37:49');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4249246656', 'plant-biology', 'Nelfinavir and other protease inhibitors in cancer: mechanisms involved in anticancer activity', 'Objective: To review the mechanisms of anti-cancer activity of nelfinavir and other protease inhibitors (PIs) based on evidences reported in the published literature. Methods: We extensively reviewed…', '2015', 2015, 37, 37, 'https://f1000research-files.f1000.com/manuscripts/6594/acba4db2-412f-4f40-9f7e-44f11ffdb423_figure1.gif', 'https://doi.org/10.12688/f1000research.5827.1', 'repository', 'preprint', 'F1000Research', '["Tomas Koltai"]', 'plant biology', 'Objective: To review the mechanisms of anti-cancer activity of nelfinavir and other protease inhibitors (PIs) based on evidences reported in the published literature. Methods: We extensively reviewed the literature concerning nelfinavir (NFV) as an off target anti-cancer drug and other PIs. A classification of PIs based on anti-cancer mode of action was proposed. Controversies regarding nelfinavir mode of action were also addressed. Conclusions: The two main mechanisms involved in anti-cancer activity are endoplasmic reticulum stress-unfolded protein response pathway and Akt inhibition. However there are many other effects, partially dependent and independent of those mentioned, that may be useful in cancer treatment, including MMP-9 and MMP-2 inhibition, down-regulation of CDK-2, VEGF, bFGF, NF-kB, STAT-3, HIF-1 alfa, IGF, EGFR, survivin, BCRP, androgen receptor, proteasome, fatty acid synthase (FAS), decrease in cellular ATP concentration and upregulation of TRAIL receptor DR5, Bax, increased radiosensitivity, and autophagy. The end result of all these effects is slower growth, decreased angiogenesis, decreased invasion and increased apoptosis, which means reduced proliferation and increased cancer cells death. PIs may be classified according to their anticancer activity at clinically achievable doses, in AKT inhibitors, ER stressors and Akt inhibitors/ER stressors. Beyond the phase I trials that have been recently completed, adequately powered and well-designed clinical trials are needed in the various cancer type settings, and specific trials where NFV is tested in association with other known anti-cancer pharmaceuticals should be sought, in order to find an appropriate place for NFV in cancer treatment. The analysis of controversies on the molecular mechanisms of NFV hints to the possibility that NFV works in a different way in tumor cells and in hepatocytes and adipocytes.', '2026-07-07 21:39:45');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3034453825', 'plant-biology', 'Prediction of repurposed drugs for treating lung injury in COVID-19', 'Coronavirus disease (COVID-19) is an infectious disease discovered in 2019 and currently in outbreak across the world. Lung injury with severe respiratory failure is the leading cause of death in…', '2020', 2020, 36, 36, 'https://f1000research-files.f1000.com/manuscripts/28930/7c86ffd9-9554-49a4-9f95-8f140a0c6a12_figure1.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7280878', 'pmc', 'preprint', 'F1000Research', '["Bing He","Lana X. Garmire"]', 'plant biology', 'Coronavirus disease (COVID-19) is an infectious disease discovered in 2019 and currently in outbreak across the world. Lung injury with severe respiratory failure is the leading cause of death in COVID-19, brought by severe acute respiratory syndrome coronavirus 2 (SARS- CoV-2). However, there still lacks efficient treatment for COVID-19 induced lung injury and acute respiratory failure. Inhibition of Angiotensin-converting enzyme 2 (ACE2) caused by spike protein of SARS-CoV-2 is the most plausible mechanism of lung injury in COVID-19. We propose two candidate drugs, COL-3 (a chemically modified tetracycline) and CGP-60474 (a cyclin-dependent kinase inhibitor), for treating lung injuries in COVID-19, based on their abilities to reverse the gene expression patterns in HCC515 cells treated with ACE2 inhibitor and in human COVID-19 patient lung tissues. Further bioinformatics analysis shows that twelve significantly enriched pathways (P-value <0.05) overlap between HCC515 cells treated with ACE2 inhibitor and human COVID-19 patient lung tissues, including signaling pathways known to be associated with lung injury such as TNF signaling, MAPK signaling and Chemokine signaling pathways. All these twelve pathways are targeted in COL-3 treated HCC515 cells, in which genes such as RHOA, RAC2, FAS, CDC42 have reduced expression. CGP-60474 shares eleven of twelve pathways with COL-3 with common target genes such as RHOA. It also uniquely targets genes related to lung injury, such as CALR and MMP14. In summary, this study shows that ACE2 inhibition is likely part of the mechanisms leading to lung injury in COVID-19, and that compounds such as COL-3 and CGP-60474 have the potential as repurposed drugs for its treatment.', '2026-07-07 21:40:55');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4231025004', 'plant-biology', 'CyTargetLinker app update: A flexible solution for network extension in Cytoscape', 'Here, we present an update of the open-source CyTargetLinker app for Cytoscape (http://apps.cytoscape.org/apps/cytargetlinker) that introduces new automation features. CyTargetLinker provides a…', '2018', 2018, 36, 36, 'https://f1000research-files.f1000.com/manuscripts/15902/6169a661-dc66-4a7c-ba93-4ed940624cd0_figure1.gif', 'https://doi.org/10.12688/f1000research.14613.1', 'repository', 'preprint', 'F1000Research', '["Martina Kutmon","Friederike Ehrhart","Egon Willighagen","Chris T. Evelo","Susan L. Coort"]', 'plant biology', 'Here, we present an update of the open-source CyTargetLinker app for Cytoscape (http://apps.cytoscape.org/apps/cytargetlinker) that introduces new automation features. CyTargetLinker provides a simple interface to extend networks with links to relevant data and/or knowledge extracted from so-called linksets. The linksets are provided on the CyTargetLinker website or can be custom-made for specific use cases. The new automation feature enables users to programmatically execute the app’s functionality in Cytoscape (command line tool) and with external tools (e.g. R, Jupyter, Python, etc). This allows users to share their analysis workflows and therefore increase repeatability and reproducibility. Three use cases demonstrate automated workflows, combinations with other Cytoscape apps and core Cytoscape functionality. We first extend a protein-protein interaction network created with the stringApp, with compound-target interactions and disease-gene annotations. In the second use case, we created a workflow to load differentially expressed genes from an experimental dataset and extend it with gene-pathway associations. Lastly, we chose an example outside the biological domain and used CyTargetLinker to create an author-article-journal network for the five authors of this manuscript using a two-step extension mechanism. With 300 downloads per month in the last year and over 12,000 downloads in total, CyTargetLinker shows the adoption and relevance of the app in the field of network biology. In April 2018, the original publication was cited in 57 articles demonstrating the applicability in biomedical research.', '2026-07-07 21:41:09');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4235394253', 'plant-biology', 'TRGAted: A web tool for survival analysis using protein data in the Cancer Genome Atlas.', 'Reverse-phase protein arrays (RPPAs) are a highthroughput approach to protein quantification utilizing an antibody-based micro-to-nano scale dot blot. Within the Cancer Genome Atlas (TCGA), RPPAs…', '2018', 2018, 36, 36, 'https://f1000research-files.f1000.com/manuscripts/17235/0854c6f4-b825-489a-a64e-8fdfb8ff5141_figure1.gif', 'https://doi.org/10.12688/f1000research.15789.1', 'repository', 'preprint', 'F1000Research', '["Nicholas Borcherding","Nicholas L. Bormann","Andrew P. Voigt","Weizhou Zhang"]', 'plant biology', 'Reverse-phase protein arrays (RPPAs) are a highthroughput approach to protein quantification utilizing an antibody-based micro-to-nano scale dot blot. Within the Cancer Genome Atlas (TCGA), RPPAs were used to quantify over 200 proteins in 8,167 tumor or metastatic samples. This protein-level data has particular advantages in assessing putative prognostic or therapeutic targets in tumors. However, many of the available pipelines do not allow for the partitioning of clinical and RPPA information to make meaningful conclusions. We developed a cloud-based application, TRGAted to enable researchers to better examine survival based on single or multiple proteins across 31 cancer types in the TCGA. TRGAted contains up-to-date overall survival, disease-specific survival, disease-free interval and progression-free interval information. Furthermore, survival information for primary tumor samples can be stratified based on gender, age, tumor stage, histological type, and subtype, allowing for highly adaptive and intuitive user experience. The code and processed data is open sourced and available on github and with a tutorial built into the application for assisting users.', '2026-07-07 21:41:12');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4237361490', 'plant-biology', 'A refinement to the formalin test in mice', 'The constant refinement of tests used in animal research is crucial for the scientific community. This is particularly true for the field of pain research, where ethical standards are notably…', '2019', 2019, 36, 36, 'https://f1000research-files.f1000.com/manuscripts/20060/821b03f9-067d-4331-b67b-fb2291107654_figure1.gif', 'https://doi.org/10.12688/f1000research.18338.1', 'repository', 'preprint', 'F1000Research', '["Douglas M. Lopes","Heather Cater","Matthew Thakur","Sara Wells","Stephen B. McMahon"]', 'plant biology', 'The constant refinement of tests used in animal research is crucial for the scientific community. This is particularly true for the field of pain research, where ethical standards are notably sensitive. The formalin test is widely used in pain research and some of its mechanisms resemble those underlying clinical pain in humans. Immediately upon injection, formalin triggers two waves (an early and a late phase) of strong, nociceptive behaviour, characterised by licking, biting, lifting and shaking the injected paw of the animal. Although well characterised at the behaviour level, since its proposal over four decades ago, there has not been any significant refinement to the formalin test, especially those combining minimisation of animal distress and preservation of behavioural outcomes of the test. Here, we propose a modified and improved method for the formalin test. We show that anaesthetising the animal with the inhalable anaesthetic sevoflurane at the time of the injection can produce reliable, robust and reproducible results whilst animal distress during the initial phase is reduced. Importantly, our results were validated by pharmacological suppression of the behaviour during the late phase of the test with gabapentin, the anaesthetic showing no interference with the drug. In addition, we demonstrate that this is also a useful method to screen for changes in pain behaviour in response to formalin in transgenic lines.', '2026-07-07 21:41:14');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2952935296', 'plant-biology', 'Real time portable genome sequencing for global food security', 'Crop losses due to viral diseases and pests are major constraints on food security and income for millions of households in sub-Saharan Africa (SSA). Such losses can be reduced if plant diseases and…', '2018', 2018, 35, 35, 'https://f1000research-files.f1000.com/manuscripts/16909/b3f24430-e3d6-49ec-8109-bd7e8d15400c_figure1.gif', 'https://doi.org/10.12688/f1000research.15507.1', 'repository', 'preprint', 'F1000Research', '["Laura M. Boykin","Ammar Ghalab","Bruno Rossitto De Marchi","Anders Savill","James M. Wainaina","Tonny Kinene","Stephen Lamb","Myriam Rodrigues","Monica Kehoe","Joseph Ndunguru","Fred Tairo","Peter Sseruwagi","Charles Kayuki","Deogratius Mark","Joel Erasto","Hilda Bachwenkizi","Titus Alicai","Geoffrey Okao-Okuja","Phillip Abridrabo","Emmanuel Ogwok","John Francis Osingada","Jimmy Akono","Elijah Ateka","Brenda Muga","Samuel Kiarie"]', 'plant biology', 'Crop losses due to viral diseases and pests are major constraints on food security and income for millions of households in sub-Saharan Africa (SSA). Such losses can be reduced if plant diseases and pests are correctly diagnosed and identified early. Currently, accurate diagnosis for definitive identification of plant viruses and their vectors in SSA mostly relies on standard PCR and next generation sequencing technologies (NGS). However, it can take up to 6 months before results generated using these approaches are available. The long time taken to detect or identify viruses impedes quick, within-season decision-making necessary for early action, crop protection advice and disease control measures by farmers. This ultimately compounds the magnitude of crop losses and food shortages suffered by farmers. The MinION portable pocket DNA sequencer was used, to our knowledge globally for the first time, to sequence whole plant virus genomes. We used this technology to identify the begomoviruses causing the devastating cassava mosaic virus, which is ravaging smallholder farmers’ crops in sub-Saharan Africa.', '2026-07-07 21:42:15');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4249663987', 'plant-biology', 'The evolution and diversity of the nonsense-mediated mRNA decay pathway', 'Nonsense-mediated mRNA decay is a eukaryotic pathway that degrades transcripts with premature termination codons (PTCs). In most eukaryotes, thousands of transcripts are degraded by NMD, including…', '2018', 2018, 35, 35, 'https://f1000research-files.f1000.com/manuscripts/17330/2dc37d75-52fe-4be4-9f2a-64c570edf28a_figure1.gif', 'https://doi.org/10.12688/f1000research.15872.1', 'repository', 'preprint', 'F1000Research', '["James P. B. Lloyd"]', 'plant biology', 'Nonsense-mediated mRNA decay is a eukaryotic pathway that degrades transcripts with premature termination codons (PTCs). In most eukaryotes, thousands of transcripts are degraded by NMD, including many important regulators of development and stress response pathways. Transcripts can be targeted to NMD by the presence of an upstream ORF or by introduction of a PTC through alternative splicing. Many factors involved in the recognition of PTCs and the destruction of NMD targets have been characterized. While some are highly conserved, others have been repeatedly lost in eukaryotic lineages. Here, I outline the factors involved in NMD, our current understanding of their interactions and how they have evolved. I outline a classification system to describe NMD pathways based on the presence/absence of key NMD factors. These types of NMD pathways exist in multiple different lineages, indicating the plasticity of the NMD pathway through recurrent losses of NMD factors during eukaryotic evolution. By classifying the NMD pathways in this way, gaps in our understanding are revealed, even within well studied organisms. Finally, I discuss the likely driving force behind the origins of the NMD pathway before the appearance of the last eukaryotic common ancestor: transposable element expansion and the consequential origin of introns.', '2026-07-07 21:42:56');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1951069276', 'synthetic-biology', 'Host Biology in Light of the Microbiome: Ten Principles of Holobionts and Hologenomes', 'Groundbreaking research on the universality and diversity of microorganisms is now challenging the life sciences to upgrade fundamental theories that once seemed untouchable. To fully appreciate the…', '2015', 2015, 1280, 1280, 'https://journals.plos.org/plosbiology/article/figure/image?size=large&id=10.1371/journal.pbio.1002226.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4540581', 'pmc', 'article', 'PLoS Biology', '["Seth R. Bordenstein","Kevin R. Theis"]', 'synthetic biology', 'Groundbreaking research on the universality and diversity of microorganisms is now challenging the life sciences to upgrade fundamental theories that once seemed untouchable. To fully appreciate the change that the field is now undergoing, one has to place the epochs and foundational principles of Darwin, Mendel, and the modern synthesis in light of the current advances that are enabling a new vision for the central importance of microbiology. Animals and plants are no longer heralded as autonomous entities but rather as biomolecular networks composed of the host plus its associated microbes, i.e., "holobionts." As such, their collective genomes forge a "hologenome," and models of animal and plant biology that do not account for these intergenomic associations are incomplete. Here, we integrate these concepts into historical and contemporary visions of biology and summarize a predictive and refutable framework for their evaluation. Specifically, we present ten principles that clarify and append what these concepts are and are not, explain how they both support and extend existing theory in the life sciences, and discuss their potential ramifications for the multifaceted approaches of zoology and botany. We anticipate that the conceptual and evidence-based foundation provided in this essay will serve as a roadmap for hypothesis-driven, experimentally validated research on holobionts and their hologenomes, thereby catalyzing the continued fusion of biology''s subdisciplines. At a time when symbiotic microbes are recognized as fundamental to all aspects of animal and plant biology, the holobiont and hologenome concepts afford a holistic view of biological complexity that is consistent with the generally reductionist approaches of biology.', '2026-07-07 21:43:48');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2792453707', 'synthetic-biology', 'The dTAG system for immediate and target-specific protein degradation', 'The dTAG system for immediate and target-specific protein degradation', '2018', 2018, 1172, 1172, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41589-018-0021-8/MediaObjects/41589_2018_21_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6295913', 'pmc', 'article', 'Nature Chemical Biology', '["Behnam Nabet","Justin M. Roberts","Dennis L. Buckley","Joshiawa Paulk","Shiva Dastjerdi","Annan Yang","Alan L. Leggett","Michael A. Erb","Matthew A. Lawlor","Amanda Souza","Thomas G. Scott","Sarah Vittori","Jennifer A. Perry","Jun Qi","Georg E. Winter","Kwok‐Kin Wong","Nathanael S. Gray","James E. Bradner"]', 'synthetic biology', NULL, '2026-07-07 21:43:55');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4230321861', 'synthetic-biology', 'Biomimetic peptide self-assembly for functional materials', 'Biomimetic peptide self-assembly for functional materials', '2020', 2020, 834, 834, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41570-020-0215-y/MediaObjects/41570_2020_215_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7617017', 'pmc', 'review', 'Nature Reviews Chemistry', '["Aviad Levin","Tuuli A. Hakala","Lee Schnaider","Gonçalo J. L. Bernardes","Ehud Gazit","Tuomas P. J. Knowles"]', 'synthetic biology', NULL, '2026-07-07 21:44:01');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2990434592', 'synthetic-biology', 'Microbial response to acid stress: mechanisms and applications', 'Microorganisms encounter acid stress during multiple bioprocesses. Microbial species have therefore developed a variety of resistance mechanisms. The damage caused by acidic environments is mitigated…', '2019', 2019, 642, 642, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1007%2Fs00253-019-10226-1/MediaObjects/253_2019_10226_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6942593', 'pmc', 'review', 'Applied Microbiology and Biotechnology', '["Ningzi Guan","Long Liu"]', 'synthetic biology', 'Microorganisms encounter acid stress during multiple bioprocesses. Microbial species have therefore developed a variety of resistance mechanisms. The damage caused by acidic environments is mitigated through the maintenance of pH homeostasis, cell membrane integrity and fluidity, metabolic regulation, and macromolecule repair. The acid tolerance mechanisms can be used to protect probiotics against gastric acids during the process of food intake, and can enhance the biosynthesis of organic acids. The combination of systems and synthetic biology technologies offers new and wide prospects for the industrial applications of microbial acid tolerance mechanisms. In this review, we summarize acid stress response mechanisms of microbial cells, illustrate the application of microbial acid tolerance in industry, and prospect the introduction of systems and synthetic biology to further explore the acid tolerance mechanisms and construct a microbial cell factory for valuable chemicals.', '2026-07-07 21:44:11');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2967876620', 'synthetic-biology', 'The emergence of adaptive laboratory evolution as an efficient tool for biological discovery and industrial biotechnology', 'The emergence of adaptive laboratory evolution as an efficient tool for biological discovery and industrial biotechnology', '2019', 2019, 561, 561, 'https://ars.els-cdn.com/content/image/1-s2.0-S1096717619301533-gr1.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6944292', 'pmc', 'review', 'Metabolic Engineering', '["Troy E. Sandberg","Michael Salazar","Liam L. Weng","Bernhard Ø. Palsson","Adam M. Feist"]', 'synthetic biology', NULL, '2026-07-07 21:44:26');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2507192932', 'synthetic-biology', 'Directed evolution of artificial metalloenzymes for in vivo metathesis', 'Directed evolution of artificial metalloenzymes for in vivo metathesis', '2016', 2016, 459, 459, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1038/nature19114.g001', 'https://pubmed.ncbi.nlm.nih.gov/27571282', 'repository', 'article', 'Nature', '["Markus Jeschek","Raphael Reuter","Tillmann Heinisch","Christian Trindler","Juliane Klehr","Sven Panke","Thomas R. Ward"]', 'synthetic biology', NULL, '2026-07-07 21:44:32');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2955231772', 'synthetic-biology', 'Human 5′ UTR design and variant effect prediction from a massively parallel translation assay', 'Human 5′ UTR design and variant effect prediction from a massively parallel translation assay', '2019', 2019, 460, 460, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41587-019-0164-5/MediaObjects/41587_2019_164_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7100133', 'pmc', 'article', 'Nature Biotechnology', '["Paul Sample","Ban Wang","David W. Reid","Vladimir Presnyak","Iain J. McFadyen","David Morris","Georg Seelig"]', 'synthetic biology', NULL, '2026-07-07 21:44:42');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4211130512', 'synthetic-biology', 'Bacterial microcompartments', 'Bacterial microcompartments', '2018', 2018, 490, 490, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnrmicro.2018.10/MediaObjects/41579_2018_Article_BFnrmicro201810_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6022854', 'pmc', 'review', 'Nature Reviews Microbiology', '["Cheryl A. Kerfeld","Clément Aussignargues","Jan Zarzycki","Fei Cai","Markus Sutter"]', 'synthetic biology', NULL, '2026-07-07 21:44:43');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2582378544', 'synthetic-biology', 'Microbial production of vitamin B12: a review and future perspectives', 'Vitamin B12 is an essential vitamin that is widely used in medical and food industries. Vitamin B12 biosynthesis is confined to few bacteria and archaea, and as such its production relies on…', '2017', 2017, 471, 471, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1007%2Fs10482-022-01795-9/MediaObjects/10482_2022_1795_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5282855', 'pmc', 'review', 'Microbial Cell Factories', '["Huan Fang","Jie Kang","Dawei Zhang"]', 'synthetic biology', 'Vitamin B12 is an essential vitamin that is widely used in medical and food industries. Vitamin B12 biosynthesis is confined to few bacteria and archaea, and as such its production relies on microbial fermentation. Rational strain engineering is dependent on efficient genetic tools and a detailed knowledge of metabolic pathways, regulation of which can be applied to improve product yield. Recent advances in synthetic biology and metabolic engineering have been used to efficiently construct many microbial chemical factories. Many published reviews have probed the vitamin B12 biosynthetic pathway. To maximize the potential of microbes for vitamin B12 production, new strategies and tools are required. In this review, we provide a comprehensive understanding of advances in the microbial production of vitamin B12, with a particular focus on establishing a heterologous host for the vitamin B12 production, as well as on strategies and tools that have been applied to increase microbial cobalamin production. Several worthy strategies employed for other products are also included.', '2026-07-07 21:44:43');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2074933455', 'synthetic-biology', 'Biocontainment of genetically modified organisms by synthetic protein design', 'Biocontainment of genetically modified organisms by synthetic protein design', '2015', 2015, 464, 464, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature14121/MediaObjects/41586_2015_BFnature14121_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4422498', 'pmc', 'article', 'Nature', '["Daniel J. Mandell","Marc J. Lajoie","Michael T. Mee","Ryo Takeuchi","Gleb Kuznetsov","Julie E. Norville","Christopher Gregg","Barry Stoddard","George M. Church"]', 'synthetic biology', NULL, '2026-07-07 21:44:45');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2063408699', 'synthetic-biology', 'Engineered pairs of distinct photoswitches for optogenetic control of cellular proteins', 'Optogenetic methods take advantage of photoswitches to control the activity of cellular proteins. Here, we completed a multi-directional engineering of the fungal photoreceptor Vivid to develop pairs…', '2015', 2015, 449, 449, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fncomms7256/MediaObjects/41467_2015_Article_BFncomms7256_Fig1_HTML.jpg', 'https://pubmed.ncbi.nlm.nih.gov/25708714', 'repository', 'article', 'Nature Communications', '["Fuun Kawano","Hideyuki Suzuki","Akihiro Furuya","Moritoshi Sato"]', 'synthetic biology', 'Optogenetic methods take advantage of photoswitches to control the activity of cellular proteins. Here, we completed a multi-directional engineering of the fungal photoreceptor Vivid to develop pairs of distinct photoswitches named Magnets. These new photoswitches were engineered to recognize each other based on the electrostatic interactions, thus preventing homodimerization and enhancing light-induced heterodimerization. Furthermore, we tuned the switch-off kinetics by four orders of magnitude and developed several variants, including those with substantially faster kinetics than any of the other conventional dimerization-based blue spectrum photoswitches. We demonstrate the utility of Magnets as powerful tools that can optogenetically manipulate molecular processes in biological systems. Photoreceptor-based photoswitches have proved to be powerful tools for the specific control of protein activity in live cells. Here the authors describe Magnets, a new set of photoswitches based on the Vivid photoreceptor with enhanced hetero-dimerization specificity and variable activation kinetics.', '2026-07-07 21:44:58');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3004119871', 'synthetic-biology', 'Production of Gamma-Aminobutyric Acid from Lactic Acid Bacteria: A Systematic Review', 'Gamma-aminobutyric acid (GABA) is widely distributed in nature and considered a potent bioactive compound with numerous and important physiological functions, such as anti-hypertensive and…', '2020', 2020, 430, 430, 'https://pub.mdpi-res.com/ijms/ijms-21-00995/article_deploy/html/images/ijms-21-00995-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7037312', 'pmc', 'review', 'International Journal of Molecular Sciences', '["Yanhua Cui","Kai Miao","Siripitakyotin Niyaphorn","Xiaojun Qu"]', 'synthetic biology', 'Gamma-aminobutyric acid (GABA) is widely distributed in nature and considered a potent bioactive compound with numerous and important physiological functions, such as anti-hypertensive and antidepressant activities. There is an ever-growing demand for GABA production in recent years. Lactic acid bacteria (LAB) are one of the most important GABA producers because of their food-grade nature and potential of producing GABA-rich functional foods directly. In this paper, the GABA-producing LAB species, the biosynthesis pathway of GABA by LAB, and the research progress of glutamate decarboxylase (GAD), the key enzyme of GABA biosynthesis, were reviewed. Furthermore, GABA production enhancement strategies are reviewed, from optimization of culture conditions and genetic engineering to physiology-oriented engineering approaches and co-culture methods. The advances in both the molecular mechanisms of GABA biosynthesis and the technologies of synthetic biology and genetic engineering will promote GABA production of LAB to meet people''s demand for GABA. The aim of the review is to provide an insight of microbial engineering for improved production of GABA by LAB in the future.', '2026-07-07 21:45:01');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2739451081', 'synthetic-biology', 'Complex cellular logic computation using ribocomputing devices', 'Complex cellular logic computation using ribocomputing devices', '2017', 2017, 413, 413, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature23271/MediaObjects/41586_2017_Article_BFnature23271_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6078203', 'pmc', 'article', 'Nature', '["Alexander A. Green","Jongmin Kim","Duo Ma","Pamela A. Silver","James J. Collins","Peng Yin"]', 'synthetic biology', NULL, '2026-07-07 21:45:12');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2617511364', 'synthetic-biology', 'Engineered bacteria can function in the mammalian gut long-term as live diagnostics of inflammation', 'Engineered bacteria can function in the mammalian gut long-term as live diagnostics of inflammation', '2017', 2017, 425, 425, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnbt.3879/MediaObjects/41587_2017_Article_BFnbt3879_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5658125', 'pmc', 'article', 'Nature Biotechnology', '["David T. Riglar","Tobias W. Giessen","Michael Baym","S. Jordan Kerns","Matthew J. Niederhuber","Roderick T. Bronson","Jonathan W. Kotula","Georg K. Gerber","Jeffrey C. Way","Pamela A. Silver"]', 'synthetic biology', NULL, '2026-07-07 21:45:14');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2561073732', 'synthetic-biology', 'Synthetic DNA Synthesis and Assembly: Putting the Synthetic in Synthetic Biology', 'The chemical synthesis of DNA oligonucleotides and their assembly into synthons, genes, circuits, and even entire genomes by gene synthesis methods has become an enabling technology for modern…', '2017', 2017, 416, 416, 'https://cshperspectives.cshlp.org/adsystem/graphics/4110912709913739/cshperspect/Long_Oligos_anim_480x60.gif?ad=50842&adview=true', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5204324', 'pmc', 'review', 'Cold Spring Harbor Perspectives in Biology', '["Randall A. Hughes","Andrew D. Ellington"]', 'synthetic biology', 'The chemical synthesis of DNA oligonucleotides and their assembly into synthons, genes, circuits, and even entire genomes by gene synthesis methods has become an enabling technology for modern molecular biology and enables the design, build, test, learn, and repeat cycle underpinning innovations in synthetic biology. In this perspective, we briefly review the techniques and technologies that enable the synthesis of DNA oligonucleotides and their assembly into larger DNA constructs with a focus on recent advancements that have sought to reduce synthesis cost and increase sequence fidelity. The development of lower-cost methods to produce high-quality synthetic DNA will allow for the exploration of larger biological hypotheses by lowering the cost of use and help to close the DNA read-write cost gap.', '2026-07-07 21:45:16');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4388694364', 'synthetic-biology', 'Illuminating protein space with a programmable generative model', ', but the full potential of proteins is likely to be much greater. Accessing this potential has been challenging for both computation and experiments because the space of possible protein molecules…', '2023', 2023, 413, 413, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-023-06728-8/MediaObjects/41586_2023_6728_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/10686827', 'pmc', 'article', 'Nature', '["John Ingraham","Max Baranov","Zak Costello","Karl W. Barber","Wujie Wang","Ahmed Ismail","Vincent Frappier","Dana M. Lord","Christopher Ng‐Thow‐Hing","Erik R. Van Vlack","Shan Tie","Vincent Xue","Sarah C. Cowles","Alan Leung","João V. Rodrigues","Claudio L. Morales-Pérez","Alex Ayoub","Robin Green","Katherine Puentes","Frank Oplinger","Nishant V. Panwar","Fritz Obermeyer","Adam Root","Andrew L. Beam","Frank J. Poelwijk","Gevorg Grigoryan"]', 'synthetic biology', ', but the full potential of proteins is likely to be much greater. Accessing this potential has been challenging for both computation and experiments because the space of possible protein molecules is much larger than the space of those likely to have functions. Here we introduce Chroma, a generative model for proteins and protein complexes that can directly sample novel protein structures and sequences, and that can be conditioned to steer the generative process towards desired properties and functions. To enable this, we introduce a diffusion process that respects the conformational statistics of polymer ensembles, an efficient neural architecture for molecular systems that enables long-range reasoning with sub-quadratic scaling, layers for efficiently synthesizing three-dimensional structures of proteins from predicted inter-residue geometries and a general low-temperature sampling algorithm for diffusion models. Chroma achieves protein design as Bayesian inference under external constraints, which can involve symmetries, substructure, shape, semantics and even natural-language prompts. The experimental characterization of 310 proteins shows that sampling from Chroma results in proteins that are highly expressed, fold and have favourable biophysical properties. The crystal structures of two designed proteins exhibit atomistic agreement with Chroma samples (a backbone root-mean-square deviation of around 1.0 Å). With this unified approach to protein design, we hope to accelerate the programming of protein matter to benefit human health, materials science and synthetic biology.', '2026-07-07 21:45:26');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1990530150', 'synthetic-biology', 'High-throughput preparation methods of crude extract for robust cell-free protein synthesis', 'Crude extract based cell-free protein synthesis (CFPS) has emerged as a powerful technology platform for high-throughput protein production and genetic part characterization. Unfortunately, robust…', '2015', 2015, 411, 411, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fsrep08663/MediaObjects/41598_2015_Article_BFsrep08663_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4345344', 'pmc', 'article', 'Scientific Reports', '["Yong‐Chan Kwon","Michael C. Jewett"]', 'synthetic biology', 'Crude extract based cell-free protein synthesis (CFPS) has emerged as a powerful technology platform for high-throughput protein production and genetic part characterization. Unfortunately, robust preparation of highly active extracts generally requires specialized and costly equipment and can be labor and time intensive. Moreover, cell lysis procedures can be hard to standardize, leading to different extract performance across laboratories. These challenges limit new entrants to the field and new applications, such as comprehensive genome engineering programs to improve extract performance. To address these challenges, we developed a generalizable and easily accessible high-throughput crude extract preparation method for CFPS based on sonication. To validate our approach, we investigated two Escherichia coli strains: BL21 Star™ (DE3) and a K12 MG1655 variant, achieving similar productivity (defined as CFPS yield in g/L) by varying only a few parameters. In addition, we observed identical productivity of cell extracts generated from culture volumes spanning three orders of magnitude (10 mL culture tubes to 10 L fermentation). We anticipate that our rapid and robust extract preparation method will speed-up screening of genomically engineered strains for CFPS applications, make possible highly active extracts from non-model organisms, and promote a more general use of CFPS in synthetic biology and biotechnology.', '2026-07-07 21:45:26');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2747801569', 'synthetic-biology', 'Burden-driven feedback control of gene expression', 'Burden-driven feedback control of gene expression', '2018', 2018, 409, 409, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnmeth.4635/MediaObjects/41592_2018_Article_BFnmeth4635_Fig1_HTML.jpg', 'https://hal.science/hal-03851810', 'repository', 'article', 'Nature Methods', '["Francesca Ceroni","Alice Boo","Simone Furini","Thomas E. Gorochowski","Olivier Borkowski","Yaseen Ladak","Ali R. Awan","Charlie Gilbert","Guy‐Bart Stan","Tom Ellis"]', 'synthetic biology', NULL, '2026-07-07 21:45:27');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2192893656', 'synthetic-biology', '''Deadman'' and ''Passcode'' microbial kill switches for bacterial containment', '''Deadman'' and ''Passcode'' microbial kill switches for bacterial containment', '2015', 2015, 403, 403, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnchembio.1979/MediaObjects/41589_2016_Article_BFnchembio1979_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4718764', 'pmc', 'article', 'Nature Chemical Biology', '["Clement T. Y. Chan","Jeong Wook Lee","D. Ewen Cameron","Caleb J. Bashor","James J. Collins"]', 'synthetic biology', NULL, '2026-07-07 21:45:28');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2528458398', 'synthetic-biology', 'Genome-Editing Technologies: Principles and Applications', 'Targeted nucleases have provided researchers with the ability to manipulate virtually any genomic sequence, enabling the facile creation of isogenic cell lines and animal models for the study of…', '2016', 2016, 408, 408, 'https://cshperspectives.cshlp.org/adsystem/graphics/48983734930471723/cshperspect/SPCT_web_468x60.gif?ad=50833&adview=true', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5131771', 'pmc', 'review', 'Cold Spring Harbor Perspectives in Biology', '["Thomas Gaj","Shannon J. Sirk","Sai-lan Shui","Jia Liu"]', 'synthetic biology', 'Targeted nucleases have provided researchers with the ability to manipulate virtually any genomic sequence, enabling the facile creation of isogenic cell lines and animal models for the study of human disease, and promoting exciting new possibilities for human gene therapy. Here we review three foundational technologies-clustered regularly interspaced short palindromic repeats (CRISPR)-CRISPR-associated protein 9 (Cas9), transcription activator-like effector nucleases (TALENs), and zinc-finger nucleases (ZFNs). We discuss the engineering advances that facilitated their development and highlight several achievements in genome engineering that were made possible by these tools. We also consider artificial transcription factors, illustrating how this technology can complement targeted nucleases for synthetic biology and gene therapy.', '2026-07-07 21:45:28');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2919102308', 'synthetic-biology', 'DNA-based communication in populations of synthetic protocells', 'DNA-based communication in populations of synthetic protocells', '2019', 2019, 353, 353, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41565-019-0399-9/MediaObjects/41565_2019_399_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6451639', 'pmc', 'article', 'Nature Nanotechnology', '["Alex Joesaar","Shuo Yang","Bas W. A. Bögels","Ardjan J. van der Linden","Pascal A. Pieters","B. V. V. S. Pavan Kumar","Neil Dalchau","Andrew Phillips","Stephen Mann","Tom F. A. de Greef"]', 'synthetic biology', NULL, '2026-07-07 21:45:31');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2760464869', 'synthetic-biology', 'Engineering nucleic acid structures for programmable molecular circuitry and intracellular biocomputation', 'Engineering nucleic acid structures for programmable molecular circuitry and intracellular biocomputation', '2017', 2017, 351, 351, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnchem.2852/MediaObjects/41557_2017_Article_BFnchem2852_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/11421837', 'pmc', 'review', 'Nature Chemistry', '["Jiang Li","Alexander A. Green","Hao Yan","Chunhai Fan"]', 'synthetic biology', NULL, '2026-07-07 21:45:32');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2260617737', 'synthetic-biology', 'Engineering an allosteric transcription factor to respond to new ligands', 'Engineering an allosteric transcription factor to respond to new ligands', '2015', 2015, 352, 352, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnmeth.3696/MediaObjects/41592_2016_Article_BFnmeth3696_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4907361', 'pmc', 'article', 'Nature Methods', '["Noah D. Taylor","Alexander S. Garruss","Rocco Moretti","Sum Chan","Mark A. Arbing","Duilio Cascio","Jameson K. Rogers","Farren J. Isaacs","Sriram Kosuri","David Baker","Stanley Fields","George M. Church","Srivatsan Raman"]', 'synthetic biology', NULL, '2026-07-07 21:45:33');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1179069838', 'synthetic-biology', 'Microfluidics: reframing biological enquiry', 'Microfluidics: reframing biological enquiry', '2015', 2015, 345, 345, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnrm4041/MediaObjects/41580_2015_Article_BFnrm4041_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6240156', 'pmc', 'review', 'Nature Reviews Molecular Cell Biology', '["Todd A. Duncombe","Augusto M. Tentori","Amy E. Herr"]', 'synthetic biology', NULL, '2026-07-07 21:45:48');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2531578105', 'synthetic-biology', 'Synchronous long-term oscillations in a synthetic gene circuit', 'Synchronous long-term oscillations in a synthetic gene circuit', '2016', 2016, 343, 343, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature19841/MediaObjects/41586_2016_Article_BFnature19841_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5637407', 'pmc', 'article', 'Nature', '["Laurent Potvin-Trottier","Nathan D. Lord","Glenn Vinnicombe","Johan Paulsson"]', 'synthetic biology', NULL, '2026-07-07 21:45:52');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2767343818', 'synthetic-biology', 'Programmable autonomous synthesis of single-stranded DNA', 'Programmable autonomous synthesis of single-stranded DNA', '2017', 2017, 311, 311, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnchem.2872/MediaObjects/41557_2018_Article_BFnchem2872_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5784857', 'pmc', 'article', 'Nature Chemistry', '["Jocelyn Y. Kishi","Thomas E. Schaus","Nikhil Gopalkrishnan","Feng Xuan","Peng Yin"]', 'synthetic biology', NULL, '2026-07-07 21:45:57');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2563521043', 'synthetic-biology', 'Cpf1 Is A Versatile Tool for CRISPR Genome Editing Across Diverse Species of Cyanobacteria', 'directly into the desired end product using solar energy. Unfortunately, the engineering of cyanobacteria to create efficient cell factories has been impaired by the cumbersome genetic tools that are…', '2016', 2016, 315, 315, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fsrep39681/MediaObjects/41598_2016_Article_BFsrep39681_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5175191', 'pmc', 'article', 'Scientific Reports', '["Justin Ungerer","Himadri B. Pakrasi"]', 'synthetic biology', 'directly into the desired end product using solar energy. Unfortunately, the engineering of cyanobacteria to create efficient cell factories has been impaired by the cumbersome genetic tools that are currently available for these organisms; especially when trying to accumulate multiple modifications. We sought to construct an efficient and precise tool for generating numerous markerless modifications in cyanobacteria using CRISPR technology and the alternative nuclease, Cpf1. In this study we demonstrate rapid engineering of markerless knock-ins, knock-outs and point mutations in each of three model cyanobacteria; Synechococcus, Synechocystis and Anabaena. The markerless nature of cpf1 genome editing will allow for complex genome modification that was not possible with previously existing technology while facilitating the development of cyanobacteria as highly modified biofactories.', '2026-07-07 21:45:57');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2769160949', 'synthetic-biology', 'Combinatorial metabolic engineering using an orthogonal tri-functional CRISPR system', 'Designing an optimal microbial cell factory often requires overexpression, knock-down, and knock-out of multiple gene targets. Unfortunately, such rewiring of cellular metabolism is often carried out…', '2017', 2017, 316, 316, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41467-017-01695-x/MediaObjects/41467_2017_1695_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5700065', 'pmc', 'article', 'Nature Communications', '["Jiazhang Lian","Mohammad HamediRad","Sumeng Hu","Huimin Zhao"]', 'synthetic biology', 'Designing an optimal microbial cell factory often requires overexpression, knock-down, and knock-out of multiple gene targets. Unfortunately, such rewiring of cellular metabolism is often carried out sequentially and with low throughput. Here, we report a combinatorial metabolic engineering strategy based on an orthogonal tri-functional CRISPR system that combines transcriptional activation, transcriptional interference, and gene deletion (CRISPR-AID) in the yeast Saccharomyces cerevisiae. This strategy enables perturbation of the metabolic and regulatory networks in a modular, parallel, and high-throughput manner. We demonstrate the application of CRISPR-AID not only to increase the production of β-carotene by 3-fold in a single step, but also to achieve 2.5-fold improvement in the display of an endoglucanase on the yeast surface by optimizing multiple metabolic engineering targets in a combinatorial manner.', '2026-07-07 21:45:58');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3158484573', 'plant-biology', 'Rapid systematic review of systematic reviews: what befriending, social support and low intensity psychosocial interventions, delivered remotely, may reduce social isolation and loneliness among older adults and how?', 'Background : During the COVID-19 pandemic ‘social distancing’ has highlighted the need to minimise loneliness and isolation among older adults (aged 50+). We wanted to know what remotely delivered…', '2021', 2021, 33, 33, 'https://f1000research-files.f1000.com/manuscripts/55641/44f718ca-b488-42dc-a85e-5a35d3b4b8c2_figure1.gif', 'https://doi.org/10.12688/f1000research.27076.2', 'repository', 'preprint', 'F1000Research', '["Elisabeth Boulton","Dylan Kneale","Claire Stansfield","Paul Heron","Katy Sutcliffe","Brenda Hayanga","Alex Hall","Peter Bower","Dympna Casey","Dawn Craig","Simon Gilbody","Barbara Hanratty","Dean McMillan","James Thomas","Chris Todd"]', 'plant biology', 'Background : During the COVID-19 pandemic ‘social distancing’ has highlighted the need to minimise loneliness and isolation among older adults (aged 50+). We wanted to know what remotely delivered befriending, social support and low intensity psychosocial interventions may help to alleviate social isolation and loneliness and how they work. Methods : We followed a systematic ‘review of reviews’ approach. Searches of 11 databases from the fields of health, social care, psychology and social science were undertaken during April 2020. Reviews meeting our PICOS criteria were included if they focussed on the evaluation of remote interventions to reduce levels of social isolation or loneliness in adults aged 50+ and were critically appraised using AMSTAR2. Narrative synthesis was used at a review and study level to develop a typology of intervention types and their effectiveness. Intervention Component Analysis (ICA) and Qualitative Comparative Analysis (QCA) were used at a study level to explore the characteristics of successful interventions. Results : We synthesised evidence from five systematic reviews and 18 primary studies. Remote befriending, social support and low intensity psychosocial interventions took the form of: (i) supported video-communication; (ii) online discussion groups and forums; (iii) telephone befriending; (iv) social networking sites; and (v) multi-tool interventions. The majority of studies utilised the first two approaches, and were generally regarded positively by older adults, although with mixed evidence around effectiveness. Focussing on processes and mechanisms, using ICA and QCA, we found that the interventions that were most successful in improving social support: (i) enabled participants to speak freely and to form close relationships; (ii) ensured participants have shared experiences/characteristics; (iii) included some form of pastoral guidance. Conclusions : The findings highlight a set of intervention processes that should be incorporated into interventions, although they do not lead us to recommend specific modes of support, due to the heterogeneity of interventions.', '2026-07-07 21:46:04');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3105098767', 'synthetic-biology', 'Machine learning for metabolic engineering: A review', 'Machine learning provides researchers a unique opportunity to make metabolic engineering more predictable. In this review, we offer an introduction to this discipline in terms that are relatable to…', '2020', 2020, 305, 305, 'https://ars.els-cdn.com/content/image/1-s2.0-S109671762030166X-gr1.jpg', 'https://pubmed.ncbi.nlm.nih.gov/33221420', 'repository', 'review', 'Metabolic Engineering', '["Christopher E. Lawson","Jose Manuel Martí","Tijana Radivojević","Sai Vamshi R. Jonnalagadda","Reinhard Gentz","Nathan J. Hillson","Sean Peisert","Joonhoon Kim","Blake A. Simmons","Christopher J. Petzold","Steven W. Singer","Aindrila Mukhopadhyay","Deepti Tanjore","Joshua G. Dunn","Héctor García Martín"]', 'synthetic biology', 'Machine learning provides researchers a unique opportunity to make metabolic engineering more predictable. In this review, we offer an introduction to this discipline in terms that are relatable to metabolic engineers, as well as providing in-depth illustrative examples leveraging omics data and improving production. We also include practical advice for the practitioner in terms of data management, algorithm libraries, computational resources, and important non-technical issues. A variety of applications ranging from pathway construction and optimization, to genetic editing optimization, cell factory testing, and production scale-up are discussed. Moreover, the promising relationship between machine learning and mechanistic models is thoroughly reviewed. Finally, the future perspectives and most promising directions for this combination of disciplines are examined.', '2026-07-07 21:46:13');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4239027235', 'plant-biology', 'Virologic failure and HIV drug resistance on simplified, dolutegravir-based maintenance therapy: Systematic review and meta-analysis', 'Background: Dolutegravir-containing maintenance therapy is a promising simplification strategy for virologically suppressed HIV-infected individuals. However, most of the available data to inform…', '2018', 2018, 33, 33, 'https://f1000research-files.f1000.com/manuscripts/17470/03491d58-8899-415b-a399-64f6214fa91c_figure1.gif', 'https://doi.org/10.12688/f1000research.15995.1', 'repository', 'preprint', 'F1000Research', '["Gilles Wandeler","Marta Buzzi","Nanina Anderegg","Delphine Sculier","Charles Béguelin","Matthias Egger","Alexandra Calmy"]', 'plant biology', 'Background: Dolutegravir-containing maintenance therapy is a promising simplification strategy for virologically suppressed HIV-infected individuals. However, most of the available data to inform this strategy come from small, uncontrolled studies. We estimated the proportion of HIV-infected patients experiencing virological failure (VF) and developing drug resistance on dolutegravir (DTG)-based maintenance therapy. Methods: We searched Medline, Embase, Cochrane Central, Web of Science, and conference abstracts for studies assessing VF on DTG-based maintenance therapy. Studies including ≥5 adults with an undetectable viral load on antiretroviral therapy (ART) who switched to a DTG-based mono- or dual therapy were included. Pooled proportions of VF were estimated using random-intercept logistic meta-regression and acquired drug resistance mutations described for each strategy. Results : Of 1719 studies considered, 21 met our selection criteria, including seven interventional and 14 observational studies. Eight studies including 251 patients assessed VF on DTG monotherapy and fourteen studies including 1670 participants VF on dual therapy. The participant’s median age ranged from 43 to 63 years, their median nadir CD4 count from 90 to 399 cells/µl, and 27.6% were female. The proportion of participants experiencing VF on DTG-monotherapy was 3.6% (95% confidence interval [CI] 1.9-6.7) at 24 weeks and 8.9% (95% CI 4.7-16.2) at 48 weeks. Resistance mutations developed in seven (3.6%) participants on DTG-monotherapy. Among patients on dual therapy, ten (0.7%, 95% CI 0.4-1.3) experienced VF by 48 weeks and none developed resistance to DTG. In adjusted analyses, VF at 24 weeks was less likely on dual therapy than on monotherapy (adjusted odds ratio: 0.10, 95% CI 0.03-0.30). Conclusions: Whereas VF is relatively common on DTG maintenance monotherapy, DTG-based dual therapy appears to be a promising simplification strategy for individuals with a suppressed HIV viral load on triple-ART.', '2026-07-07 21:46:17');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2737510383', 'synthetic-biology', 'Synthetic single domain antibodies for the conformational trapping of membrane proteins', 'Mechanistic and structural studies of membrane proteins require their stabilization in specific conformations. Single domain antibodies are potent reagents for this purpose, but their generation…', '2018', 2018, 297, 297, 'https://cdn.elifesciences.org/articles/34317/elife-34317-fig1-v1.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5967865', 'pmc', 'article', 'eLife', '["Iwan Zimmermann","Pascal Egloff","Cedric A. J. Hutter","Fabian Arnold","Peter Stohler","Nicolas Bocquet","Melanie N. Hug","Sylwia Huber","M. Sloan Siegrist","Lisa Hetemann","Jennifer Gera","Samira Gmür","Peter Spies","Daniel Gygax","Eric R. Geertsma","Roger Dawson","Markus A. Seeger"]', 'synthetic biology', 'Mechanistic and structural studies of membrane proteins require their stabilization in specific conformations. Single domain antibodies are potent reagents for this purpose, but their generation relies on immunizations, which impedes selections in the presence of ligands typically needed to populate defined conformational states. To overcome this key limitation, we developed an in vitro selection platform based on synthetic single domain antibodies named sybodies. To target the limited hydrophilic surfaces of membrane proteins, we designed three sybody libraries that exhibit different shapes and moderate hydrophobicity of the randomized surface. A robust binder selection cascade combining ribosome and phage display enabled the generation of conformation-selective, high affinity sybodies against an ABC transporter and two previously intractable human SLC transporters, GlyT1 and ENT1. The platform does not require access to animal facilities and builds exclusively on commercially available reagents, thus enabling every lab to rapidly generate binders against challenging membrane proteins.', '2026-07-07 21:46:26');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4310995529', 'plant-biology', 'Nitric Oxide in Seed Biology', 'Nitric oxide (NO) has been recognized as a gasotransmitter in the mainstream of plant research since the beginning of the 21st century. It is produced in plant tissue and the environment. It…', '2022', 2022, 33, 33, 'https://pub.mdpi-res.com/ijms/ijms-23-04951/article_deploy/html/images/ijms-23-04951-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/9736209', 'pmc', 'review', 'International Journal of Molecular Sciences', '["Katarzyna Ciacka","Paweł Staszek","Katarzyna Sobczynska","Urszula Krasuska","Agnieszka Gniazdowska"]', 'plant biology', 'Nitric oxide (NO) has been recognized as a gasotransmitter in the mainstream of plant research since the beginning of the 21st century. It is produced in plant tissue and the environment. It influences plant physiology during every ontogenetic stage from seed germination to plant senescence. In this review, we demonstrate the increased interest in NO as a regulatory molecule in combination with other signalling molecules and phytohormones in the information network of plant cells. This work is a summary of the current knowledge on NO action in seeds, starting from seed pretreatment techniques applied to increase seed quality. We describe mode of action of NO in the regulation of seed dormancy, germination, and aging. During each stage of seed physiology, NO appears to act as a key agent with a predominantly beneficial effect.', '2026-07-07 21:46:27');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2157903915', 'synthetic-biology', 'Rational design of functional and tunable oscillating enzymatic networks', 'Rational design of functional and tunable oscillating enzymatic networks', '2015', 2015, 289, 289, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnchem.2142/MediaObjects/41557_2015_Article_BFnchem2142_Fig1_HTML.jpg', 'https://pubmed.ncbi.nlm.nih.gov/25615670', 'repository', 'article', 'Nature Chemistry', '["Sergey N. Semenov","Albert S. Y. Wong","R. Martijn van der Made","Sjoerd G. J. Postma","J Groen","Hendrik W. H. van Roekel","Tom F. A. de Greef","Wilhelm T. S. Huck"]', 'synthetic biology', NULL, '2026-07-07 21:46:27');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1135359322', 'synthetic-biology', 'Better together: engineering and application of microbial symbioses', 'Better together: engineering and application of microbial symbioses', '2015', 2015, 291, 291, 'https://ars.els-cdn.com/content/image/1-s2.0-S095816691500107X-fx1.jpg', 'https://pubmed.ncbi.nlm.nih.gov/26319893', 'repository', 'review', 'Current Opinion in Biotechnology', '["Stephanie G. Hays","William G. Patrick","Marika Ziesack","Neri Oxman","Pamela A. Silver"]', 'synthetic biology', NULL, '2026-07-07 21:46:27');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2507618556', 'synthetic-biology', 'Automated optogenetic feedback control for precise and robust regulation of gene expression and cell growth', 'Dynamic control of gene expression can have far-reaching implications for biotechnological applications and biological discovery. Thanks to the advantages of light, optogenetics has emerged as an…', '2016', 2016, 278, 278, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fncomms12546/MediaObjects/41467_2016_Article_BFncomms12546_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5007438', 'pmc', 'article', 'Nature Communications', '["Andreas Milias‐Argeitis","Marc Rullan","Stephanie K. Aoki","P. Buchmann","Mustafa Khammash"]', 'synthetic biology', 'Dynamic control of gene expression can have far-reaching implications for biotechnological applications and biological discovery. Thanks to the advantages of light, optogenetics has emerged as an ideal technology for this task. Current state-of-the-art methods for optical expression control fail to combine precision with repeatability and cannot withstand changing operating culture conditions. Here, we present a novel fully automatic experimental platform for the robust and precise long-term optogenetic regulation of protein production in liquid Escherichia coli cultures. Using a computer-controlled light-responsive two-component system, we accurately track prescribed dynamic green fluorescent protein expression profiles through the application of feedback control, and show that the system adapts to global perturbations such as nutrient and temperature changes. We demonstrate the efficacy and potential utility of our approach by placing a key metabolic enzyme under optogenetic control, thus enabling dynamic regulation of the culture growth rate with potential applications in bacterial physiology studies and biotechnology.', '2026-07-07 21:46:45');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2105123684', 'plant-biology', 'Enhancement of COPD biological networks using a web-based collaboration interface', 'The construction and application of biological network models is an approach that offers a holistic way to understand biological processes involved in disease. Chronic obstructive pulmonary disease…', '2015', 2015, 32, 32, 'https://f1000research-files.f1000.com/manuscripts/6402/438a0c63-7962-4e81-b920-05a9aceb81d7_figure1.gif', 'https://doi.org/10.12688/f1000research.5984.1', 'repository', 'preprint', 'F1000Research', '["The sbv IMPROVER project team (in alphabetical order)","Stéphanie Boué","Brett Fields","Julia Hoeng","Jennifer Park","Manuel C. Peitsch","Walter K. Schlage","Marja Talikka","The Challenge Best Performers (in alphabetical order)","Ilona Binenbaum","В. В. Бондаренко","Oleg V. Bulgakov","Vera Cherkasova","Norberto Díaz–Díaz","Larisa Fedorova","Svetlana V. Guryanova","Julia A. Guzova","G. I. Koroleva","Elena Kozhemyakina","Rahul Kumar","Noa Lavid","Qingxian Lu","Swapna Menon","Yael Ouliel","Samantha C. Peterson","Alexander Prokhorov","Edward Sanders","Sarah B. Schrier","Golan Schwaitzer Neta","Irina Shvydchenko","Aravind Tallam","Gema Villa-Fombuena","John Z. Wu","Ilya Yudkevich","Mariya Zelikman"]', 'plant biology', 'The construction and application of biological network models is an approach that offers a holistic way to understand biological processes involved in disease. Chronic obstructive pulmonary disease (COPD) is a progressive inflammatory disease of the airways for which therapeutic options currently are limited after diagnosis, even in its earliest stage. COPD network models are important tools to better understand the biological components and processes underlying initial disease development. With the increasing amounts of literature that are now available, crowdsourcing approaches offer new forms of collaboration for researchers to review biological findings, which can be applied to the construction and verification of complex biological networks. We report the construction of 50 biological network models relevant to lung biology and early COPD using an integrative systems biology and collaborative crowd-verification approach. By combining traditional literature curation with a data-driven approach that predicts molecular activities from transcriptomics data, we constructed an initial COPD network model set based on a previously published non-diseased lung-relevant model set. The crowd was given the opportunity to enhance and refine the networks on a website ( https://bionet.sbvimprover.com/ ) and to add mechanistic detail, as well as critically review existing evidence and evidence added by other users, so as to enhance the accuracy of the biological representation of the processes captured in the networks. Finally, scientists and experts in the field discussed and refined the networks during an in-person jamboree meeting. Here, we describe examples of the changes made to three of these networks: Neutrophil Signaling , Macrophage Signaling , and Th1-Th2 Signaling . We describe an innovative approach to biological network construction that combines literature and data mining and a crowdsourcing approach to generate a comprehensive set of COPD-relevant models that can be used to help understand the mechanisms related to lung pathobiology. Registered users of the website can freely browse and download the networks.', '2026-07-07 21:46:56');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2344403991', 'plant-biology', 'Recent advances in large-scale protein interactome mapping', 'Protein-protein interactions (PPIs) underlie most, if not all, cellular functions. The comprehensive mapping of these complex networks of stable and transient associations thus remains a key goal,…', '2016', 2016, 32, 32, 'https://f1000research-files.f1000.com/manuscripts/8215/9a58747f-8299-44d2-806c-b520d3e80991_figure1.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4856108', 'pmc', 'preprint', 'F1000Research', '["Virja Mehta","Laura Trinkle‐Mulcahy"]', 'plant biology', 'Protein-protein interactions (PPIs) underlie most, if not all, cellular functions. The comprehensive mapping of these complex networks of stable and transient associations thus remains a key goal, both for systems biology-based initiatives (where it can be combined with other ''omics'' data to gain a better understanding of functional pathways and networks) and for focused biological studies. Despite the significant challenges of such an undertaking, major strides have been made over the past few years. They include improvements in the computation prediction of PPIs and the literature curation of low-throughput studies of specific protein complexes, but also an increase in the deposition of high-quality data from non-biased high-throughput experimental PPI mapping strategies into publicly available databases.', '2026-07-07 21:47:07');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2802610819', 'synthetic-biology', 'Self-replication of DNA by its encoded proteins in liposome-based synthetic cells', 'Replication of DNA-encoded information and its conversion into functional proteins are universal properties of life. In an effort toward the construction of a synthetic minimal cell, we implement…', '2018', 2018, 266, 266, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41467-018-03926-1/MediaObjects/41467_2018_3926_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5910420', 'pmc', 'article', 'Nature Communications', '["Pauline van Nies","Ilja Westerlaken","Duco Blanken","Margarita Salas","Mario Mencı́a","Christophe Danelon"]', 'synthetic biology', 'Replication of DNA-encoded information and its conversion into functional proteins are universal properties of life. In an effort toward the construction of a synthetic minimal cell, we implement here the DNA replication machinery of the Φ29 virus in a cell-free gene expression system. Amplification of a linear DNA template by self-encoded, de novo synthesized Φ29 proteins is demonstrated. Complete information transfer is confirmed as the copied DNA can serve as a functional template for gene expression, which can be seen as an autocatalytic DNA replication cycle. These results show how the central dogma of molecular biology can be reconstituted and form a cycle in vitro. Finally, coupled DNA replication and gene expression is compartmentalized inside phospholipid vesicles providing the chassis for evolving functions in a prospective synthetic cell relying on the extant biology.', '2026-07-07 21:47:18');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2267190811', 'synthetic-biology', 'Efficient backbone cyclization of linear peptides by a recombinant asparaginyl endopeptidase', 'Cyclotides are diverse plant backbone cyclized peptides that have attracted interest as pharmaceutical scaffolds, but fundamentals of their biosynthetic origin remain elusive. Backbone cyclization is…', '2015', 2015, 261, 261, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fncomms10199/MediaObjects/41467_2015_Article_BFncomms10199_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4703859', 'pmc', 'article', 'Nature Communications', '["Karen S. Harris","Thomas Durek","Quentin Kaas","Aaron G. Poth","Edward K. Gilding","Brendon Conlan","Ivana Saska","Norelle L. Daly","Nicole L. van der Weerden","David J. Craik","Marilyn A. Anderson"]', 'synthetic biology', 'Cyclotides are diverse plant backbone cyclized peptides that have attracted interest as pharmaceutical scaffolds, but fundamentals of their biosynthetic origin remain elusive. Backbone cyclization is a key enzyme-mediated step of cyclotide biosynthesis and confers a measure of stability on the resultant cyclotide. Furthermore, cyclization would be desirable for engineered peptides. Here we report the identification of four asparaginyl endopeptidases (AEPs), proteases implicated in cyclization, from the cyclotide-producing plant Oldenlandia affinis. We recombinantly express OaAEP1b and find it functions preferably as a cyclase by coupling C-terminal cleavage of propeptide substrates with backbone cyclization. Interestingly, OaAEP1b cannot cleave at the N-terminal site of O. affinis cyclotide precursors, implicating additional proteases in cyclotide biosynthesis. Finally, we demonstrate the broad utility of this enzyme by cyclization of peptides unrelated to cyclotides. We propose that recombinant OaAEP1b is a powerful tool for use in peptide engineering applications where increased stability of peptide products is desired.', '2026-07-07 21:47:20');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3024027148', 'synthetic-biology', 'Mammalian cell culture for production of recombinant proteins: A review of the critical steps in their biomanufacturing', 'Mammalian cell culture for production of recombinant proteins: A review of the critical steps in their biomanufacturing', '2020', 2020, 266, 266, 'https://ars.els-cdn.com/content/image/1-s2.0-S0734975020300495-gr1.jpg', 'https://pubmed.ncbi.nlm.nih.gov/32416132', 'repository', 'review', 'Biotechnology Advances', '["Róisín O’Flaherty","Adam Bergin","Evangelia Flampouri","Letícia Martins Mota","Ismael Obaidi","Andrew Quigley","Yongjing Xie","Michael Butler"]', 'synthetic biology', NULL, '2026-07-07 21:47:21');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2898866616', 'synthetic-biology', 'A biomimetic receptor for glucose', 'A biomimetic receptor for glucose', '2018', 2018, 264, 264, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41557-018-0155-z/MediaObjects/41557_2018_155_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/30420776', 'repository', 'article', 'Nature Chemistry', '["Robert A. Tromans","Tom S. Carter","Laurent Chabanne","Matthew P. Crump","Hongyu Li","Johnathan V. Matlock","Michael G. Orchard","Anthony P. Davis"]', 'synthetic biology', NULL, '2026-07-07 21:47:23');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4210628575', 'synthetic-biology', 'Genetically stable CRISPR-based kill switches for engineered microbes', 'Microbial biocontainment is an essential goal for engineering safe, next-generation living therapeutics. However, the genetic stability of biocontainment circuits, including kill switches, is a…', '2022', 2022, 259, 259, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41467-022-28163-5/MediaObjects/41467_2022_28163_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8813983', 'pmc', 'article', 'Nature Communications', '["Austin G. Rottinghaus","Aura Ferreiro","Skye R. S. Fishbein","Gautam Dantas","Tae Seok Moon"]', 'synthetic biology', 'Microbial biocontainment is an essential goal for engineering safe, next-generation living therapeutics. However, the genetic stability of biocontainment circuits, including kill switches, is a challenge that must be addressed. Kill switches are among the most difficult circuits to maintain due to the strong selection pressure they impart, leading to high potential for evolution of escape mutant populations. Here we engineer two CRISPR-based kill switches in the probiotic Escherichia coli Nissle 1917, a single-input chemical-responsive switch and a 2-input chemical- and temperature-responsive switch. We employ parallel strategies to address kill switch stability, including functional redundancy within the circuit, modulation of the SOS response, antibiotic-independent plasmid maintenance, and provision of intra-niche competition by a closely related strain. We demonstrate that strains harboring either kill switch can be selectively and efficiently killed inside the murine gut, while strains harboring the 2-input switch are additionally killed upon excretion. Leveraging redundant strategies, we demonstrate robust biocontainment of our kill switch strains and provide a template for future kill switch development.', '2026-07-07 21:47:34');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3034867886', 'synthetic-biology', 'In vitro prototyping and rapid optimization of biosynthetic enzymes for cell design', 'In vitro prototyping and rapid optimization of biosynthetic enzymes for cell design', '2020', 2020, 255, 255, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41589-020-0559-0/MediaObjects/41589_2020_559_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/32541965', 'repository', 'article', 'Nature Chemical Biology', '["Ashty S. Karim","Quentin M. Dudley","Alex Juminaga","Yongbo Yuan","Samantha A. Crowe","Jacob T. Heggestad","Shivani Garg","Tanus Abdalla","William S. Grubbe","Blake J. Rasor","David N. Coar","Maria Torculas","Michael Krein","Fungmin Liew","Amy Quattlebaum","Rasmus O. Jensen","Jeffrey A. Stuart","Séan D. Simpson","Michael Köpke","Michael C. Jewett"]', 'synthetic biology', NULL, '2026-07-07 21:47:35');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3120686965', 'synthetic-biology', 'RetroBioCat as a computer-aided synthesis planning tool for biocatalytic reactions and cascades', 'RetroBioCat as a computer-aided synthesis planning tool for biocatalytic reactions and cascades', '2021', 2021, 251, 251, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41929-020-00556-z/MediaObjects/41929_2020_556_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7116764', 'pmc', 'article', 'Nature Catalysis', '["William Finnigan","Lorna J. Hepworth","Sabine L. Flitsch","Nicholas J. Turner"]', 'synthetic biology', NULL, '2026-07-07 21:47:35');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2997333704', 'synthetic-biology', 'Expanding the enzyme universe with genetically encoded unnatural amino acids', 'Expanding the enzyme universe with genetically encoded unnatural amino acids', '2020', 2020, 250, 250, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41929-019-0410-8/MediaObjects/41929_2019_410_Fig1_HTML.png', 'https://doi.org/10.1038/s41929-019-0410-8', 'repository', 'article', 'Nature Catalysis', '["Ivana Drienovská","Gérard Roelfes"]', 'synthetic biology', NULL, '2026-07-07 21:47:36');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4243545763', 'plant-biology', 'netSmooth: Network-smoothing based imputation for single cell RNA-seq', 'Single cell RNA-seq (scRNA-seq) experiments suffer from a range of characteristic technical biases, such as dropouts (zero or near zero counts) and high variance. Current analysis methods rely on…', '2018', 2018, 32, 32, 'https://f1000research-files.f1000.com/manuscripts/14669/c84db29f-c15d-4c56-9070-e17ff28b9885_figure1.gif', 'https://doi.org/10.12688/f1000research.13511.1', 'repository', 'preprint', 'F1000Research', '["Jonathan Ronen","Altuna Akalin"]', 'plant biology', 'Single cell RNA-seq (scRNA-seq) experiments suffer from a range of characteristic technical biases, such as dropouts (zero or near zero counts) and high variance. Current analysis methods rely on imputing missing values by various means of local averaging or regression, often amplifying biases inherent in the data. We present netSmooth, a network-diffusion based method that uses priors for the covariance structure of gene expression profiles on scRNA-seq experiments in order to smooth expression values. We demonstrate that netSmooth improves clustering results of scRNA-seq experiments from distinct cell populations, time-course experiments, and cancer genomics. We provide an R package for our method, available at: https://github.com/BIMSBbioinfo/netSmooth.', '2026-07-07 21:47:46');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2397510433', 'synthetic-biology', 'From dirt to industrial applications: Pseudomonas putida as a Synthetic Biology chassis for hosting harsh biochemical reactions', 'From dirt to industrial applications: Pseudomonas putida as a Synthetic Biology chassis for hosting harsh biochemical reactions', '2016', 2016, 243, 243, 'https://ars.els-cdn.com/content/image/1-s2.0-S1367593116300515-fx1.jpg', 'https://pubmed.ncbi.nlm.nih.gov/27239751', 'repository', 'review', 'Current Opinion in Chemical Biology', '["Pablo I. Nikel","Max Chavarría","Antoine Danchin","Vı́ctor de Lorenzo"]', 'synthetic biology', NULL, '2026-07-07 21:48:03');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4391849830', 'synthetic-biology', 'Machine learning for functional protein design', 'Machine learning for functional protein design', '2024', 2024, 242, 242, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41587-024-02127-0/MediaObjects/41587_2024_2127_Fig1_HTML.png', 'https://pmc.ncbi.nlm.nih.gov/articles/PMC13159571/', 'repository', 'article', 'Nature Biotechnology', '["Pascal Notin","Nathan Rollins","Yarin Gal","Chris Sander","Debora S. Marks"]', 'synthetic biology', NULL, '2026-07-07 21:48:04');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2172791605', 'synthetic-biology', 'Imaging and manipulating proteins in live cells through covalent labeling', 'Imaging and manipulating proteins in live cells through covalent labeling', '2015', 2015, 237, 237, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnchembio.1959/MediaObjects/41589_2015_Article_BFnchembio1959_Fig1_HTML.jpg', 'https://pubmed.ncbi.nlm.nih.gov/26575238', 'repository', 'article', 'Nature Chemical Biology', '["Lin Xue","Julie Karpenko","Julien Hiblot","Kai Johnsson"]', 'synthetic biology', NULL, '2026-07-07 21:48:05');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3041039796', 'synthetic-biology', 'Optimization of AsCas12a for combinatorial genetic screens in human cells', 'Optimization of AsCas12a for combinatorial genetic screens in human cells', '2020', 2020, 243, 243, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41587-020-0600-6/MediaObjects/41587_2020_600_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7854777', 'pmc', 'article', 'Nature Biotechnology', '["Peter C. DeWeirdt","Kendall R Sanson","Annabel K. Sangree","Mudra Hegde","Ruth E. Hanna","Marissa N. Feeley","Audrey L Griffith","Teng Teng","Samantha Borys","Christine Strand","J. Keith Joung","Benjamin P. Kleinstiver","Xuewen Pan","Alan Huang","John G. Doench"]', 'synthetic biology', NULL, '2026-07-07 21:48:05');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2793430004', 'synthetic-biology', 'Metabolic Engineering of the Shikimate Pathway for Production of Aromatics and Derived Compounds—Present and Future Strain Construction Strategies', 'The aromatic nature of shikimate pathway intermediates gives rise to a wealth of potential bio-replacements for commonly fossil-fuel derived aromatics, as well as naturally produced secondary…', '2018', 2018, 228, 228, 'https://www.frontiersin.org/files/Articles/336527/fbioe-06-00032-HTML-r1/image_m/fbioe-06-00032-g001.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5879953', 'pmc', 'article', 'Frontiers in Bioengineering and Biotechnology', '["Nils J. H. Averesch","Jens O. Krömer"]', 'synthetic biology', 'The aromatic nature of shikimate pathway intermediates gives rise to a wealth of potential bio-replacements for commonly fossil-fuel derived aromatics, as well as naturally produced secondary metabolites. Through metabolic engineering, the abundance of certain intermediates may be increased, while draining flux from other branches off the pathway. Often targets for genetic engineering lie beyond the shikimate pathway, altering flux deep in central metabolism. This has been extensively used to develop microbial production systems for a variety of compounds valuable in chemical industry, including aromatic and non-aromatic acids like muconic acid, para-hydroxybenzoic acid and para-coumaric acid, as well as aminobenzoic acids and aromatic α-amino acids. Further many natural products and secondary metabolites that are valuable in food- and pharma-industry are formed outgoing from shikimate pathway intermediates. (Re)construction of such routes has been shown by de novo production of resveratrol, reticuline, opioids and vanillin. In this review, strain construction strategies are compared across organisms and put into perspective with requirements by industry for commercial viability. Focus is put on enhancing flux to and through shikimate pathway and engineering strategies are assessed, in order to provide a guideline for future optimizations.', '2026-07-07 21:48:29');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2797189957', 'synthetic-biology', 'Engineering yeast for the production of breviscapine by genomic analysis and synthetic biology approaches', 'Abstract The flavonoid extract from Erigeron breviscapus, breviscapine, has increasingly been used to treat cardio- and cerebrovascular diseases in China for more than 30 years, and plant supply of…', '2018', 2018, 225, 225, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41467-018-02883-z/MediaObjects/41467_2018_2883_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5792594', 'pmc', 'article', 'Nature Communications', '["Xiaonan Liu","Jian Cheng","Guanghui Zhang","Wentao Ding","Lijin Duan","Jing Yang","Ling Kui","Xiaozhi Cheng","Jiangxing Ruan","Wei Fan","Jun‐Wen Chen","Guangqiang Long","Yan Zhao","Jing Cai","Wen Wang","Yanhe Ma","Yang Dong","Shengchao Yang","Huifeng Jiang"]', 'synthetic biology', 'Abstract The flavonoid extract from Erigeron breviscapus, breviscapine, has increasingly been used to treat cardio- and cerebrovascular diseases in China for more than 30 years, and plant supply of E. breviscapus is becoming insufficient to satisfy the growing market demand. Here we report an alternative strategy for the supply of breviscapine by building a yeast cell factory using synthetic biology. We identify two key enzymes in the biosynthetic pathway (flavonoid-7- O -glucuronosyltransferase and flavone-6-hydroxylase) from E. breviscapus genome and engineer yeast to produce breviscapine from glucose. After metabolic engineering and optimization of fed-batch fermentation, scutellarin and apigenin-7- O -glucuronide, two major active ingredients of breviscapine, reach to 108 and 185 mg l –1, respectively. Our study not only introduces an alternative source of these valuable compounds, but also provides an example of integrating genomics and synthetic biology knowledge for metabolic engineering of natural compounds.', '2026-07-07 21:48:44');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3104099683', 'synthetic-biology', 'Enzyme-mediated nitric oxide production in vasoactive erythrocyte membrane-enclosed coacervate protocells', 'Enzyme-mediated nitric oxide production in vasoactive erythrocyte membrane-enclosed coacervate protocells', '2020', 2020, 222, 222, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41557-020-00585-y/MediaObjects/41557_2020_585_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/33219364', 'repository', 'article', 'Nature Chemistry', '["Songyang Liu","Yanwen Zhang","Mei Li","Li Xiong","Zijian Zhang","Xiaohai Yang","Xiaoxiao He","Kemin Wang","Jianbo Liu","Stephen Mann"]', 'synthetic biology', NULL, '2026-07-07 21:48:44');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2790952789', 'synthetic-biology', 'Cell-free protein synthesis from genomically recoded bacteria enables multisite incorporation of noncanonical amino acids', 'Cell-free protein synthesis has emerged as a powerful approach for expanding the range of genetically encoded chemistry into proteins. Unfortunately, efforts to site-specifically incorporate multiple…', '2018', 2018, 222, 222, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41467-018-03469-5/MediaObjects/41467_2018_3469_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5865108', 'pmc', 'article', 'Nature Communications', '["Rey W. Martin","Benjamin J. Des Soye","Yong‐Chan Kwon","Jennifer E. Kay","Roderick G. Davis","Paul M. Thomas","Natalia I. Majewska","Cindy X. Chen","Ryan Marcum","Mary Grace Weiss","Ashleigh E. Stoddart","Miriam Amiram","Arnaz K. Ranji Charna","Jaymin R. Patel","Farren J. Isaacs","Neil L. Kelleher","Seok Hoon Hong","Michael C. Jewett"]', 'synthetic biology', 'Cell-free protein synthesis has emerged as a powerful approach for expanding the range of genetically encoded chemistry into proteins. Unfortunately, efforts to site-specifically incorporate multiple non-canonical amino acids into proteins using crude extract-based cell-free systems have been limited by release factor 1 competition. Here we address this limitation by establishing a bacterial cell-free protein synthesis platform based on genomically recoded Escherichia coli lacking release factor 1. This platform was developed by exploiting multiplex genome engineering to enhance extract performance by functionally inactivating negative effectors. Our most productive cell extracts enabled synthesis of 1,780 ± 30 mg/L superfolder green fluorescent protein. Using an optimized platform, we demonstrated the ability to introduce 40 identical p-acetyl-L-phenylalanine residues site specifically into an elastin-like polypeptide with high accuracy of incorporation ( ≥ 98%) and yield (96 ± 3 mg/L). We expect this cell-free platform to facilitate fundamental understanding and enable manufacturing paradigms for proteins with new and diverse chemistries.', '2026-07-07 21:48:45');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4221125443', 'synthetic-biology', 'The living interface between synthetic biology and biomaterial design', 'Recent far-reaching advances in synthetic biology have yielded exciting tools for the creation of new materials. Conversely, advances in the fundamental understanding of soft-condensed matter,…', '2022', 2022, 219, 219, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41563-022-01231-3/MediaObjects/41563_2022_1231_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/10265650', 'pmc', 'review', 'Nature Materials', '["Allen P. Liu","Eric A. Appel","Paul D. Ashby","Brendon M. Baker","Elisa Franco","Luo Gu","Karmella A. Haynes","Neel Joshi","April M. Kloxin","Paul H. J. Kouwer","Jeetain Mittal","Leonardo Morsut","Vincent Noireaux","Sapun H. Parekh","Rebecca Schulman","Sindy K. Y. Tang","Megan T. Valentine","Sebastián L. Vega","Wilfried Weber","Nicholas Stephanopoulos","Ovijit Chaudhuri"]', 'synthetic biology', 'Recent far-reaching advances in synthetic biology have yielded exciting tools for the creation of new materials. Conversely, advances in the fundamental understanding of soft-condensed matter, polymers and biomaterials offer new avenues to extend the reach of synthetic biology. The broad and exciting range of possible applications have substantial implications to address grand challenges in health, biotechnology and sustainability. Despite the potentially transformative impact that lies at the interface of synthetic biology and biomaterials, the two fields have, so far, progressed mostly separately. This Perspective provides a review of recent key advances in these two fields, and a roadmap for collaboration at the interface between the two communities. We highlight the near-term applications of this interface to the development of hierarchically structured biomaterials, from bioinspired building blocks to ‘living’ materials that sense and respond based on the reciprocal interactions between materials and embedded cells. This Perspective reviews the complementary developments in synthetic biology and biomaterials and discusses how convergence of these two fields creates a promising design strategy for the fabrication of tailored living materials for medicine and biotechnology.', '2026-07-07 21:48:55');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2728941587', 'synthetic-biology', 'Light controlled 3D micromotors powered by bacteria', 'Self-propelled bacteria can be integrated into synthetic micromachines and act as biological propellers. So far, proposed designs suffer from low reproducibility, large noise levels or lack of…', '2017', 2017, 216, 216, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fncomms15974/MediaObjects/41467_2017_Article_BFncomms15974_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5493761', 'pmc', 'article', 'Nature Communications', '["Gaszton Vizsnyiczai","Giacomo Frangipane","Claudio Maggi","Filippo Saglimbeni","S. Bianchi","Roberto Di Leonardo"]', 'synthetic biology', 'Self-propelled bacteria can be integrated into synthetic micromachines and act as biological propellers. So far, proposed designs suffer from low reproducibility, large noise levels or lack of tunability. Here we demonstrate that fast, reliable and tunable bio-hybrid micromotors can be obtained by the self-assembly of synthetic structures with genetically engineered biological propellers. The synthetic components consist of 3D interconnected structures having a rotating unit that can capture individual bacteria into an array of microchambers so that cells contribute maximally to the applied torque. Bacterial cells are smooth swimmers expressing a light-driven proton pump that allows to optically control their swimming speed. Using a spatial light modulator, we can address individual motors with tunable light intensities allowing the dynamic control of their rotational speeds. Applying a real-time feedback control loop, we can also command a set of micromotors to rotate in unison with a prescribed angular speed.', '2026-07-07 21:48:55');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2595507107', 'synthetic-biology', 'Global metabolic rewiring for improved CO2 fixation and chemical production in cyanobacteria', 'Abstract Cyanobacteria have attracted much attention as hosts to recycle CO 2 into valuable chemicals. Although cyanobacteria have been engineered to produce various compounds, production…', '2017', 2017, 216, 216, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fncomms14724/MediaObjects/41467_2017_Article_BFncomms14724_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5355792', 'pmc', 'article', 'Nature Communications', '["Masahiro Kanno","Austin L. Carroll","Shota Atsumi"]', 'synthetic biology', 'Abstract Cyanobacteria have attracted much attention as hosts to recycle CO 2 into valuable chemicals. Although cyanobacteria have been engineered to produce various compounds, production efficiencies are too low for commercialization. Here we engineer the carbon metabolism of Synechococcus elongatus PCC 7942 to improve glucose utilization, enhance CO 2 fixation and increase chemical production. We introduce modifications in glycolytic pathways and the Calvin Benson cycle to increase carbon flux and redirect it towards carbon fixation. The engineered strain efficiently uses both CO 2 and glucose, and produces 12.6 g l −1 of 2,3-butanediol with a rate of 1.1 g l −1 d −1 under continuous light conditions. Removal of native regulation enables carbon fixation and 2,3-butanediol production in the absence of light. This represents a significant step towards industrial viability and an excellent example of carbon metabolism plasticity.', '2026-07-07 21:48:55');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2772342852', 'synthetic-biology', 'Evolution of a designed protein assembly encapsulating its own RNA genome', 'Evolution of a designed protein assembly encapsulating its own RNA genome', '2017', 2017, 219, 219, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature25157/MediaObjects/41586_2017_Article_BFnature25157_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5927965', 'pmc', 'article', 'Nature', '["Gabriel L. Butterfield","Marc J. Lajoie","Heather H. Gustafson","Drew L. Sellers","Una Nattermann","Daniel Ellis","Jacob B. Bale","Sharon Ke","Garreck Lenz","Angelica Yehdego","Rashmi Ravichandran","Suzie H. Pun","Neil P. King","David Baker"]', 'synthetic biology', NULL, '2026-07-07 21:48:56');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1255767896', 'synthetic-biology', 'Mammalian synthetic circuits with RNA binding proteins for RNA-only delivery', 'Mammalian synthetic circuits with RNA binding proteins for RNA-only delivery', '2015', 2015, 218, 218, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnbt.3301/MediaObjects/41587_2015_Article_BFnbt3301_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4532950', 'pmc', 'article', 'Nature Biotechnology', '["Liliana Wróblewska","Tasuku Kitada","Kei Endo","Velia Siciliano","Breanna Stillo","Hirohide Saito","Ron Weiss"]', 'synthetic biology', NULL, '2026-07-07 21:48:56');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2076336907', 'synthetic-biology', 'Engineering Escherichia coli for methanol conversion', 'Engineering Escherichia coli for methanol conversion', '2015', 2015, 215, 215, 'https://ars.els-cdn.com/content/image/1-s2.0-S1096717615000026-gr1.jpg', 'https://hal.science/hal-01269203', 'repository', 'article', 'Metabolic Engineering', '["Jonas E. N. Müller","Fabian Meyer","Boris Litsanov","Patrick Kiefer","Eva Potthoff","Stéphanie Heux","Wim J. Quax","Volker F. Wendisch","Trygve Brautaset","Jean‐Charles Portais","Julia A. Vorholt"]', 'synthetic biology', NULL, '2026-07-07 21:48:59');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3217398469', 'biosecurity', 'Challenges and opportunities of area-based conservation in reaching biodiversity and sustainability goals', 'Abstract Area-based conservation is essential to safeguard nature’s diversity. In view of expanding human land use, increasing climate change and unmet conservation targets, area-based conservation…', '2021', 2021, 253, 253, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1007%2Fs10531-021-02340-2/MediaObjects/10531_2021_2340_Fig1_HTML.png', 'https://doi.org/10.1007/s10531-021-02340-2', 'repository', 'article', 'Biodiversity and Conservation', '["Samuel Hoffmann"]', 'biosecurity', 'Abstract Area-based conservation is essential to safeguard nature’s diversity. In view of expanding human land use, increasing climate change and unmet conservation targets, area-based conservation requires efficiency and effectiveness more than ever. In this review, I identify and relate pressing challenges to promising opportunities for effective and efficient protected area governance and management, to enhance research, decision-making and capacity building in area-based conservation under uncertain future developments. I reveal that protected area management is particularly challenged by human land use, climate change, invasive species, and social, political and economic limitations. Protected area management often lacks the continuous availability of data on current states and trends of nature and threats. Biocultural conservation, climate-smart management and biosecurity approaches help to overcome challenges induced by human needs, climate change and invasive species, respectively. Economic valuation and shifts in funding priorities can boost protected area effectiveness and efficiency. In-situ monitoring techniques, remote sensing and open data infrastructures can fill data and information gaps for protected area planning and management. Moreover, adaptive management is an auspicious concept in the framework of systematic conservation planning to ensure the enduring effectiveness of protected areas despite unpredictable future developments. Post-2020 international biodiversity and sustainable development goals could be met earlier if protected areas were more effective. I consequently conclude with the need for a global information system that is to support area-based conservation by synthesizing challenges and opportunities for protected area management effectiveness and efficiency at the local to global level.', '2026-07-07 21:49:42');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2590156219', 'biosecurity', 'Advanced biosensors for detection of pathogens related to livestock and poultry', 'Infectious animal diseases caused by pathogenic microorganisms such as bacteria and viruses threaten the health and well-being of wildlife, livestock, and human populations, limit productivity and…', '2017', 2017, 243, 243, 'https://media.springernature.com/lw685/springer-static/image/art%3A10.1186%2Fs13567-017-0418-5/MediaObjects/13567_2017_418_Fig1_HTML.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5320782', 'pmc', 'review', 'Veterinary Research', '["Jasmina Vidić","Marisa Manzano","Chung-Ming Chang","Nicole Jaffrézic‐Renault"]', 'biosecurity', 'Infectious animal diseases caused by pathogenic microorganisms such as bacteria and viruses threaten the health and well-being of wildlife, livestock, and human populations, limit productivity and increase significantly economic losses to each sector. The pathogen detection is an important step for the diagnostics, successful treatment of animal infection diseases and control management in farms and field conditions. Current techniques employed to diagnose pathogens in livestock and poultry include classical plate-based methods and conventional biochemical methods as enzyme-linked immunosorbent assays (ELISA). These methods are time-consuming and frequently incapable to distinguish between low and highly pathogenic strains. Molecular techniques such as polymerase chain reaction (PCR) and real time PCR (RT-PCR) have also been proposed to be used to diagnose and identify relevant infectious disease in animals. However these DNA-based methodologies need isolated genetic materials and sophisticated instruments, being not suitable for in field analysis. Consequently, there is strong interest for developing new swift point-of-care biosensing systems for early detection of animal diseases with high sensitivity and specificity. In this review, we provide an overview of the innovative biosensing systems that can be applied for livestock pathogen detection. Different sensing strategies based on DNA receptors, glycan, aptamers and antibodies are presented. Besides devices still at development level some are validated according to standards of the World Organization for Animal Health and are commercially available. Especially, paper-based platforms proposed as an affordable, rapid and easy to perform sensing systems for implementation in field condition are included in this review.', '2026-07-07 21:49:43');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2545397852', 'biosecurity', 'Review on the transmission porcine reproductive and respiratory syndrome virus between pigs and farms and impact on vaccination', 'Porcine reproductive and respiratory syndrome (PRRS) is considered to be one of the most costly diseases affecting intensive pig production worldwide. Control of PRRS is a complex issue and involves…', '2016', 2016, 266, 266, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs13662-019-2351-6/MediaObjects/13662_2019_2351_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5086057', 'pmc', 'review', 'Veterinary Research', '["Emanuela Pileri","Enric Mateu"]', 'biosecurity', 'Porcine reproductive and respiratory syndrome (PRRS) is considered to be one of the most costly diseases affecting intensive pig production worldwide. Control of PRRS is a complex issue and involves a combination of measures including monitoring, diagnosis, biosecurity, herd management, and immunization. In spite of the numerous studies dealing with PRRS virus epidemiology, transmission of the infection is still not fully understood. The present article reviews the current knowledge on PRRSV transmission between and within farm, and the impact of vaccination on virus transmission.', '2026-07-07 21:49:44');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2625212982', 'biosecurity', 'Invasive alien species on islands: impacts, distribution, interactions and management', 'SUMMARY Invasive alien species (IASs) on islands have broad impacts across biodiversity, agriculture, economy, health and culture, which tend to be stronger than on continents. Across small-island…', '2017', 2017, 282, 282, 'https://static.cambridge.org/binary/version/id/urn:cambridge.org:id:binary:20171128055210265-0517:S0376892917000297:S0376892917000297_fig1g.gif?pub-status=live', 'https://doi.org/10.1017/s0376892917000297', 'repository', 'article', 'Environmental Conservation', '["James C. Russell","Jean‐Yves Meyer","Nick D. Holmes","Shyama Pagad"]', 'biosecurity', 'SUMMARY Invasive alien species (IASs) on islands have broad impacts across biodiversity, agriculture, economy, health and culture, which tend to be stronger than on continents. Across small-island developing states (SIDSs), although only a small number of IASs are widely distributed, many more, including those with greatest impact, are found on only a small number of islands. Patterns of island invasion are not consistent across SIDS geographic regions, with differences attributable to correlated patterns in island biogeography and human development. We identify 15 of the most globally prevalent IASs on islands. IAS impacts on islands are exacerbated through interactions with a number of other global change threats, including over-exploitation, agricultural intensification, urban development and climate change. Biosecurity is critical in preventing IAS invasion of islands. Eradication of IASs on islands is possible at early stages of invasion, but otherwise is largely restricted to invasive mammals, or otherwise control is the only option. Future directions in IAS management and research on islands must consider IASs within a broader portfolio of threats to species, ecosystems and people''s livelihoods on islands. We advocate for stronger collaborations among island countries and territories faced with the same IASs in similar socio-ecological environments.', '2026-07-07 21:49:44');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3118590551', 'biosecurity', 'Biosecurity in pig farms: a review', 'The perception of the importance of animal health and its relationship with biosecurity has increased in recent years with the emergence and re-emergence of several diseases difficult to control.…', '2021', 2021, 246, 246, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs13620-025-00289-0/MediaObjects/13620_2025_289_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7780598', 'pmc', 'review', 'Porcine Health Management', '["Laura Alarcón","Alberto Allepuz","Enric Mateu"]', 'biosecurity', 'The perception of the importance of animal health and its relationship with biosecurity has increased in recent years with the emergence and re-emergence of several diseases difficult to control. This is particularly evident in the case of pig farming as shown by the recent episodes of African swine fever or porcine epidemic diarrhoea. Moreover, a better biosecurity may help to improve productivity and may contribute to reducing the use of antibiotics. Biosecurity can be defined as the application of measures aimed to reduce the probability of the introduction (external biosecurity) and further spread of pathogens within the farm (internal biosecurity). Thus, the key idea is to avoid transmission, either between farms or within the farm. This implies knowledge of the epidemiology of the diseases to be avoided that is not always available, but since ways of transmission of pathogens are limited to a few, it is possible to implement effective actions even with some gaps in our knowledge on a given disease. For the effective design of a biosecurity program, veterinarians must know how diseases are transmitted, the risks and their importance, which mitigation measures are thought to be more effective and how to evaluate the biosecurity and its improvements. This review provides a source of information on external and internal biosecurity measures that reduce risks in swine production and the relationship between these measures and the epidemiology of the main diseases, as well as a description of some systems available for risk analysis and the assessment of biosecurity. Also, it reviews the factors affecting the successful application of a biosecurity plan in a pig farm.', '2026-07-07 21:49:45');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2016767615', 'biosecurity', 'The Potential Distribution of Invading Helicoverpa armigera in North America: Is It Just a Matter of Time?', 'Helicoverpa armigera has recently invaded South and Central America, and appears to be spreading rapidly. We update a previously developed potential distribution model to highlight the global…', '2015', 2015, 228, 228, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0119618.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4364701', 'pmc', 'article', 'PLoS ONE', '["Darren J. Kriticos","Noboru Ota","W. D. Hutchison","Jason M. Beddow","Tom Walsh","Wee Tek Tay","Daniel M. Borchert","Silvana V. Paula-Moreas","Cecília Czepak","Myron P. Zalucki"]', 'biosecurity', 'Helicoverpa armigera has recently invaded South and Central America, and appears to be spreading rapidly. We update a previously developed potential distribution model to highlight the global invasion threat, with emphasis on the risks to the United States. The continued range expansion of H. armigera in Central America is likely to change the invasion threat it poses to North America qualitatively, making natural dispersal from either the Caribbean islands or Mexico feasible. To characterise the threat posed by H. armigera, we collated the value of the major host crops in the United States growing within its modelled potential range, including that area where it could expand its range during favourable seasons. We found that the annual value of crops that would be exposed to H. armigera totalled approximately US$78 billion p.a., with US$843 million p.a. worth growing in climates that are optimal for the pest. Elsewhere, H. armigera has developed broad-spectrum pesticide resistance; meaning that if it invades the United States, protecting these crops from significant production impacts could be challenging. It may be cost-effective to undertake pre-emptive biosecurity activities such as slowing the spread of H. armigera throughout the Americas, improving the system for detecting H. armigera, and methods for rapid identification, especially distinguishing between H. armigera, H. zea and potential H. armigera x H. zea hybrids. Developing biological control programs, especially using inundative techniques with entomopathogens and parasitoids could slow the spread of H. armigera, and reduce selective pressure for pesticide resistance. The rapid spread of H. armigera through South America into Central America suggests that its spread into North America is a matter of time. The likely natural dispersal routes preclude aggressive incursion responses, emphasizing the value of preparatory communication with agricultural producers in areas suitable for invasion by H. armigera.', '2026-07-07 21:49:55');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2765520149', 'biosecurity', 'Wanted dead or alive? Using metabarcoding of environmental DNA and RNA to distinguish living assemblages for biosecurity applications', 'High-throughput sequencing metabarcoding studies in marine biosecurity have largely focused on targeting environmental DNA (eDNA). DNA can persist extracellularly in the environment, making…', '2017', 2017, 200, 200, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0187636.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5667844', 'pmc', 'article', 'PLoS ONE', '["Xavier Pochon","Anastasija Zaiko","Lauren Fletcher","Olivier Laroche","Susanna A. Wood"]', 'biosecurity', 'High-throughput sequencing metabarcoding studies in marine biosecurity have largely focused on targeting environmental DNA (eDNA). DNA can persist extracellularly in the environment, making discrimination of living organisms difficult. In this study, bilge water samples (i.e., water accumulating on-board a vessel during transit) were collected from 15 small recreational and commercial vessels. eDNA and eRNA molecules were co-extracted and the V4 region of the 18S ribosomal RNA gene targeted for metabarcoding. In total, 62.7% of the Operational Taxonomic Units (OTUs) were identified at least once in the corresponding eDNA and eRNA reads, with 19.5% unique to eDNA and 17.7% to eRNA. There were substantial differences in diversity between molecular compartments; 57% of sequences from eDNA-only OTUs belonged to fungi, likely originating from legacy DNA. In contrast, there was a higher percentage of metazoan (50.2%) and ciliate (31.7%) sequences in the eRNA-only OTUs. Our data suggest that the presence of eRNA-only OTUs could be due to increased cellular activities of some rare taxa that were not identified in the eDNA datasets, unusually high numbers of rRNA transcripts in ciliates, and/or artefacts produced during the reverse transcriptase, PCR and sequencing steps. The proportions of eDNA/eRNA shared and unshared OTUs were highly heterogeneous within individual bilge water samples. Multiple factors including boat type and the activities performed on-board, such as washing of scientific equipment, may play a major role in contributing to this variability. For some marine biosecurity applications analysis, eDNA-only data may be sufficient, however there are an increasing number of instances where distinguishing the living portion of a community is essential. For these circumstances, we suggest only including OTUs that are present in both eDNA and eRNA data. OTUs found only in the eRNA data need to be interpreted with caution until further research provides conclusive evidence for their origin.', '2026-07-07 21:49:55');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2595374266', 'biosecurity', 'Economics of invasive species policy and management', 'This article examines the use of economic analysis to inform bioinvasion management, with particular focus on forest resources. Economics is key for understanding invasion processes, impacts, and…', '2017', 2017, 225, 225, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1007%2Fs10530-021-02727-w/MediaObjects/10530_2021_2727_Fig1_HTML.png', 'https://doi.org/10.1007/s10530-017-1406-4', 'repository', 'article', 'Biological Invasions', '["Rebecca S. Epanchin‐Niell"]', 'biosecurity', 'This article examines the use of economic analysis to inform bioinvasion management, with particular focus on forest resources. Economics is key for understanding invasion processes, impacts, and decision-making. Biological invasions are driven by and affect economic activities at multiple scales and stages of an invasion. Bioeconomic modeling seeks to inform how resources can be optimally allocated across invasion management activities-including prevention, surveillance programs for early detection and management, and controlling invasion populations and spread-to minimize the long-term costs and damages. Economic analysis facilitates understanding of decisions by public and private decision-makers, gaps between these, and the design of policies to achieve socially desirable outcomes. Private decisionmakers may undercontrol invasions relative to socially optimal levels, because they generally account for their own costs and benefits of control but less often for broader ecosystem impacts or future spread across the landscape. Economic analysis considers approaches for increasing private invasion management and evaluates feedbacks between ecological and economic systems that can affect policy outcomes. Future research should continue evaluation and design of control strategies across the biosecurity continuum and across species to enhance cost-effectiveness, better incorporate uncertainty into policy design, increase focus on incentives and behavioral tools to influence private behaviors that affect invasion spread, and incorporate invasive species consideration within broader systems-focused science. In addition, challenges in valuing biodiversity and ecosystem service impacts and the costs and effectiveness of control measures are key data gaps. Greater collaboration between decision-makers and researchers will facilitate development and communication of usable economic research.', '2026-07-07 21:50:05');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2913725860', 'biosecurity', 'Beyond Biodiversity: Can Environmental DNA (eDNA) Cut It as a Population Genetics Tool?', 'Population genetic data underpin many studies of behavioral, ecological, and evolutionary processes in wild populations and contribute to effective conservation management. However, collecting…', '2019', 2019, 236, 236, 'https://pub.mdpi-res.com/genes/genes-10-00192/article_deploy/html/images/genes-10-00192-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6470983', 'pmc', 'review', 'Genes', '["Clare I. M. Adams","Michael Knapp","Neil J. Gemmell","Gert‐Jan Jeunen","Michael Bunce","Miles D. Lamare","Helen R. Taylor"]', 'biosecurity', 'Population genetic data underpin many studies of behavioral, ecological, and evolutionary processes in wild populations and contribute to effective conservation management. However, collecting genetic samples can be challenging when working with endangered, invasive, or cryptic species. Environmental DNA (eDNA) offers a way to sample genetic material non-invasively without requiring visual observation. While eDNA has been trialed extensively as a biodiversity and biosecurity monitoring tool with a strong taxonomic focus, it has yet to be fully explored as a means for obtaining population genetic information. Here, we review current research that employs eDNA approaches for the study of populations. We outline challenges facing eDNA-based population genetic methodologies, and suggest avenues of research for future developments. We advocate that with further optimizations, this emergent field holds great potential as part of the population genetics toolkit.', '2026-07-07 21:50:10');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2147544664', 'biosecurity', 'The Role of Tourism and Recreation in the Spread of Non-Native Species: A Systematic Review and Meta-Analysis', 'Managing the pathways by which non-native species are introduced and spread is considered the most effective way of preventing species invasions. Tourism and outdoor recreation involve the frequent…', '2015', 2015, 195, 195, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0140833.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4618285', 'pmc', 'review', 'PLoS ONE', '["Lucy G. Anderson","Steve Rocliffe","Neal Haddaway","Alison M. Dunn"]', 'biosecurity', 'Managing the pathways by which non-native species are introduced and spread is considered the most effective way of preventing species invasions. Tourism and outdoor recreation involve the frequent congregation of people, vehicles and vessels from geographically diverse areas. They are therefore perceived to be major pathways for the movement of non-native species, and ones that will become increasingly important with the continued growth of these sectors. However, a global assessment of the relationship between tourism activities and the introduction of non-native species-particularly in freshwater and marine environments-is lacking. We conducted a systematic review and meta-analysis to determine the impact of tourism and outdoor recreation on non-native species in terrestrial, marine and freshwater environments. Our results provide quantitative evidence that the abundance and richness of non-native species are significantly higher in sites where tourist activities take place than in control sites. The pattern was consistent across terrestrial, freshwater and marine environments; across a variety of vectors (e.g. horses, hikers, yachts); and across a range of taxonomic groups. These results highlight the need for widespread biosecurity interventions to prevent the inadvertent introduction of invasive non-native species (INNS) as the tourism and outdoor recreation sectors grow.', '2026-07-07 21:50:12');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2755269651', 'biosecurity', 'Alien species pathways to the Galapagos Islands, Ecuador', 'Alien species, one of the biggest threats to natural ecosystems worldwide, are of particular concern for oceanic archipelagos such as Galápagos. To enable more effective management of alien species,…', '2017', 2017, 190, 190, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0184379.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5597199', 'pmc', 'article', 'PLoS ONE', '["M. Verónica Toral-Granda","Charlotte E. Causton","Heinke Jäger","Mandy Trueman","Juan Carlos Izurieta","Eddy Araujo","Marilyn Cruz","Kerstin K. Zander","Arturo Izurieta","Stephen T. Garnett"]', 'biosecurity', 'Alien species, one of the biggest threats to natural ecosystems worldwide, are of particular concern for oceanic archipelagos such as Galápagos. To enable more effective management of alien species, we reviewed, collated and analysed all available records of alien species for Galápagos. We also assembled a comprehensive dataset on pathways to and among the Galápagos Islands, including tourist and resident numbers, tourist vessels, their itineraries and visitation sites, aircraft capacity and occupancy, air and sea cargo and biosecurity interceptions. So far, 1,579 alien terrestrial and marine species have been introduced to Galápagos by humans. Of these, 1,476 have become established. Almost half of these were intentional introductions, mostly of plants. Most unintentional introductions arrived on plants and plant associated material, followed by transport vehicles, and commodities (in particular fruit and vegetables). The number, frequency and geographic origin of pathways for the arrival and dispersal of alien species to and within Galápagos have increased over time, tracking closely the increase in human population (residents and tourists) on the islands. Intentional introductions of alien species should decline as biosecurity is strengthened but there is a danger that unintentional introductions will increase further as tourism on Galápagos expands. This unique world heritage site will only retain its biodiversity values if the pathways for invasion are managed effectively.', '2026-07-07 21:50:12');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4231887591', 'plant-biology', 'Local adaptation in populations of Mycobacterium tuberculosis endemic to the Indian Ocean Rim', 'Background: Lineage 1 (L1) and 3 (L3) are two lineages of the Mycobacterium tuberculosis complex (MTBC) causing tuberculosis (TB) in humans. L1 and L3 are prevalent around the rim of the Indian…', '2021', 2021, 31, 31, 'https://f1000research-files.f1000.com/manuscripts/31323/3c1183ec-9dcd-4378-bdeb-251d317a7647_figure1.gif', 'https://doi.org/10.12688/f1000research.28318.1', 'repository', 'preprint', 'F1000Research', '["Fabrizio Menardo","Liliana K. Rutaihwa","Michaela Zwyer","Sònia Borrell","Iñaki Comas","Emilyn Costa Conceição","Mireia Coscollá","Helen Cox","Moses Joloba","Horng-Yunn Dou","Julia Feldmann","Lukas Fenner","Janet Fyfe","Qian Gao","Darı́o Garcı́a de Viedma","Alberto L. García‐Basteiro","Sebastian M. Gygli","Jerry Hella","Hellen Hiza","Levan Jugheli","Lujeko Kamwela","Midori Kato‐Maeda","Qingyun Liu","Serej D. Ley","Chloé Loiseau","Surakameth Mahasirimongkol","Bijaya Malla","Prasit Palittapongarnpim","Niaina Rakotosamimanana","Voahangy Rasolofo","Miriam Reinhard","Klaus Reither","Mohamed Sasamalo","Rafael Silva Duarte","Christophe Sola","Philip Noël Suffys","Karla Valéria Batista Lima","Dorothy Yeboah‐Manu","Christian Beisel","Daniela Brites","Sébastien Gagneux"]', 'plant biology', 'Background: Lineage 1 (L1) and 3 (L3) are two lineages of the Mycobacterium tuberculosis complex (MTBC) causing tuberculosis (TB) in humans. L1 and L3 are prevalent around the rim of the Indian Ocean, the region that accounts for most of the world’s new TB cases. Despite their relevance for this region, L1 and L3 remain understudied. Methods: We analyzed 2,938 L1 and 2,030 L3 whole genome sequences originating from 69 countries. We reconstructed the evolutionary history of these two lineages and identified genes under positive selection. Results: We found a strongly asymmetric pattern of migration from South Asia toward neighboring regions, highlighting the historical role of South Asia in the dispersion of L1 and L3. Moreover, we found that several genes were under positive selection, including genes involved in virulence and resistance to antibiotics. For L1 we identified signatures of local adaptation at the esxH locus, a gene coding for a secreted effector that targets the human endosomal sorting complex, and is included in several vaccine candidates. Conclusions: Our study highlights the importance of genetic diversity in the MTBC, and sheds new light on two of the most important MTBC lineages affecting humans.', '2026-07-07 21:50:19');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4236693100', 'plant-biology', 'Assessing the bipotency of in vitro-derived neuromesodermal progenitors', 'Retrospective clonal analysis in the mouse has demonstrated that the posterior spinal cord neurectoderm and paraxial mesoderm share a common bipotent progenitor. These neuromesodermal progenitors…', '2015', 2015, 31, 31, 'https://f1000research-files.f1000.com/manuscripts/6803/a7c05d96-c712-4a9d-b851-647aaed46620_figure1.gif', 'https://doi.org/10.12688/f1000research.6345.1', 'repository', 'preprint', 'F1000Research', '["Anestis Tsakiridis","Valerie Wilson"]', 'plant biology', 'Retrospective clonal analysis in the mouse has demonstrated that the posterior spinal cord neurectoderm and paraxial mesoderm share a common bipotent progenitor. These neuromesodermal progenitors (NMPs) are the source of new axial structures during embryonic rostrocaudal axis elongation and are marked by the simultaneous co-expression of the transcription factors T(Brachyury) (T(Bra)) and Sox2. NMP-like cells have recently been derived from pluripotent stem cells in vitro following combined stimulation of Wnt and fibroblast growth factor (FGF) signaling. Under these conditions the majority of cultures consist of T(Bra)/Sox2 co-expressing cells after 48-72 hours of differentiation. Although the capacity of these cells to generate posterior neural and paraxial mesoderm derivatives has been demonstrated at the population level, it is unknown whether a single in vitro -derived NMP can give rise to both neural and mesodermal cells. Here we demonstrate that T(Bra) positive cells obtained from mouse epiblast stem cells (EpiSCs) after culture in NMP-inducing conditions can generate both neural and mesodermal clones. This finding suggests that, similar to their embryonic counterparts, in vitro -derived NMPs are truly bipotent and can thus be exploited as a model for studying the molecular basis of developmental cell fate decisions.', '2026-07-07 21:50:22');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2295502830', 'biosecurity', 'Resistome diversity in cattle and the environment decreases during beef production', 'Antimicrobial resistant determinants (ARDs) can be transmitted from livestock systems through meat products or environmental effluents. The public health risk posed by these two routes is not well…', '2016', 2016, 150, 150, 'https://cdn.elifesciences.org/articles/13195/elife-13195-fig1-v1.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4798965', 'pmc', 'article', 'eLife', '["Noelle Noyes","Xiang Yang","Lyndsey Linke","Roberta J. Magnuson","Adam Dettenwanger","Shaun R. Cook","Ifigenia Geornaras","Dale E Woerner","Sheryl Gow","Tim A. McAllister","Hua Yang","Jaime Ruiz","Kenneth L. Jones","Christina Boucher","Paul S. Morley","K. E. Belk"]', 'biosecurity', 'Antimicrobial resistant determinants (ARDs) can be transmitted from livestock systems through meat products or environmental effluents. The public health risk posed by these two routes is not well understood, particularly in non-pathogenic bacteria. We collected pooled samples from 8 groups of 1741 commercial cattle as they moved through the process of beef production from feedlot entry through slaughter. We recorded antimicrobial drug exposures and interrogated the resistome at points in production when management procedures could potentially influence ARD abundance and/or transmission. Over 300 unique ARDs were identified. Resistome diversity decreased while cattle were in the feedlot, indicating selective pressure. ARDs were not identified in beef products, suggesting that slaughter interventions may reduce the risk of transmission of ARDs to beef consumers. This report highlights the utility and limitations of metagenomics for assessing public health risks regarding antimicrobial resistance, and demonstrates that environmental pathways may represent a greater risk than the food supply.', '2026-07-07 21:50:49');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2346143842', 'biosecurity', 'Evaluation of the relationship between the biosecurity status, production parameters, herd characteristics and antimicrobial usage in farrow-to-finish pig production in four EU countries', 'High antimicrobial usage and the threat of antimicrobial resistance highlighted the need for reduced antimicrobial usage in pig production. Prevention of disease however, is necessary to obtain a…', '2016', 2016, 142, 142, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs40813-018-0106-5/MediaObjects/40813_2018_106_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5382489', 'pmc', 'article', 'Porcine Health Management', '["Merel Postma","Annette Backhans","Lucie Collineau","Svenja Loesken","Marie Sjölund","Catherine Belloc","Ulf Emanuelson","Elisabeth große Beilage","Elisabeth Okholm Nielsen","Katharina D.C. Stärk","Jeroen Dewulf"]', 'biosecurity', 'High antimicrobial usage and the threat of antimicrobial resistance highlighted the need for reduced antimicrobial usage in pig production. Prevention of disease however, is necessary to obtain a reduced need for antimicrobial treatment. This study aimed at assessing possible associations between the biosecurity level, antimicrobial usage and farm and production characteristics in order to advice on best practices for a low antimicrobial usage and maximum animal health and production. A cross-sectional study was conducted in 227 farrow-to-finish pig herds in Belgium, France, Germany and Sweden between December 2012 and December 2013. Associations between biosecurity status, antimicrobial usage, and production parameters were evaluated with multivariable general linear models, according to an assumed causal pathway. The results showed that higher antimicrobial usage in sows tended to be associated with higher antimicrobial usage from birth until slaughter ( p = 0.06). The antimicrobial usage from birth until slaughter was positively associated with the number of pathogens vaccinated against ( p < 0.01). A shorter farrowing rhythm ( p < 0.01) and a younger weaning age ( p = 0.06) tended to be also associated with a higher antimicrobial usage from birth until slaughter whereas a better external biosecurity ( p < 0.01) was related with a lower antimicrobial usage from birth until slaughter. Management practices such as weaning age and biosecurity measures may be important factors indirectly impacting on antimicrobial usage. We therefore promote a holistic approach when assessing the potential to reduce the need for antimicrobial treatments.', '2026-07-07 21:50:51');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2889863550', 'biosecurity', 'Advantages and Limitations of Environmental DNA/RNA Tools for Marine Biosecurity: Management and Surveillance of Non-indigenous Species', 'To enable successful management of marine bioinvasions, timely and robust scientific advice is required. This knowledge should inform managers and stakeholders on the magnitude of a pressure (rate of…', '2018', 2018, 148, 148, 'https://www.frontiersin.org/files/Articles/400559/fmars-05-00322-HTML/image_m/fmars-05-00322-g001.jpg', 'https://doi.org/10.3389/fmars.2018.00322', 'repository', 'article', 'Frontiers in Marine Science', '["Anastasija Zaiko","Xavier Pochon","Eva García‐Vázquez","Sergej Olenin","Susanna A. Wood"]', 'biosecurity', 'To enable successful management of marine bioinvasions, timely and robust scientific advice is required. This knowledge should inform managers and stakeholders on the magnitude of a pressure (rate of human-mediated introductions), the environmental state of an ecosystem (impacts of non-indigenous species), and the success of management response (prevention, eradication, mitigation). This advice often relies on baseline biodiversity information in the form of measureable parameters (metrics). This can be derived from conventional approaches such as visual surveys, but also by utilizing environmental DNA/RNA-based molecular techniques, which are increasingly being touted as promising tools for assessing biodiversity and detecting rare or invasive species. Depending on the stage of incursion, each approach has merits and limitations. In this review we assess the performance of biosecurity-relevant biodiversity parameters derived from eDNA/eRNA samples and discuss the results in relation to different stages of invasion and management applications. The overall performance of considered methods ranged between 42 and 90% based on defined criteria, with target-specific approaches scoring higher for respective biosecurity applications, followed by eDNA metabarcoding. Caveats are discussed along with avenues which may enhance these techniques and their successful uptake for marine biosecurity surveillance and management. To facilitate and encourage uptake of these techniques, there is a need for an international collaborative framework aimed at unifying molecular sampling and analysis methodologies. Improvement of quantitative capacity and cost-efficiency will also enhance their integration in biosecurity programmes.', '2026-07-07 21:50:56');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2290711777', 'biosecurity', 'Mini-review: Assessing the drivers of ship biofouling management – aligning industry and biosecurity goals', 'Biofouling exerts a frictional and cost penalty on ships and is a direct cause of invasion by marine species. These negative consequences provide a unifying purpose for the maritime industry and…', '2016', 2016, 134, 134, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1080/08927014.2016.1149572.g001', 'https://pubmed.ncbi.nlm.nih.gov/26930397', 'repository', 'review', 'Biofouling', '["Ian Davidson","Christopher Scianni","Chad L. Hewitt","Richard A. Everett","Eric Holm","Mario N. Tamburri","Gregory M. Ruiz"]', 'biosecurity', 'Biofouling exerts a frictional and cost penalty on ships and is a direct cause of invasion by marine species. These negative consequences provide a unifying purpose for the maritime industry and biosecurity managers to prevent biofouling accumulation and transfer, but important gaps exist between these sectors. This mini-review examines the approach to assessments of ship biofouling among sectors (industry, biosecurity and marine science) and the implications for existing and emerging management of biofouling. The primary distinctions between industry and biosecurity in assessment of vessels biofouling revolve around the resolution of biological information collected and the specific wetted surface areas of primary concern to each sector. The morphological characteristics of biofouling and their effects on propulsion dynamics are of primary concern to industry, with an almost exclusive focus on the vertical sides and flat bottom of hulls and an emphasis on antifouling and operational performance. In contrast, the identity, biogeography, and ecology of translocated organisms is of highest concern to invasion researchers and biosecurity managers and policymakers, especially as it relates to species with known histories of invasion elsewhere. Current management practices often provide adequate, although not complete, provision for hull surfaces, but niche areas are well known to enhance biosecurity risk. As regulations to prevent invasions emerge in this arena, there is a growing opportunity for industry, biosecurity and academic stakeholders to collaborate and harmonize efforts to assess and manage biofouling of ships that should lead to more comprehensive biofouling solutions that promote industry goals while reducing biosecurity risk and greenhouse gas emissions.', '2026-07-07 21:51:02');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2795731652', 'biosecurity', 'Geographical and Historical Patterns in the Emergences of Novel Highly Pathogenic Avian Influenza (HPAI) H5 and H7 Viruses in Poultry', 'Over the years, the emergence of novel H5 and H7 highly pathogenic avian influenza viruses (HPAI) has been taking place through two main mechanisms: first, the conversion of a low pathogenic into a…', '2018', 2018, 132, 132, 'https://www.frontiersin.org/files/Articles/323596/fvets-05-00084-HTML-r1/image_m/fvets-05-00084-g001.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5996087', 'pmc', 'article', 'Frontiers in Veterinary Science', '["Madhur Dhingra","Jean Artois","Simon Dellicour","Philippe Lemey","Gwenae͏̈lle Dauphin","Sophie von Dobschuetz","Thomas P. Van Boeckel","David M. Castellan","Subhash Morzaria","Marius Gilbert"]', 'biosecurity', 'Over the years, the emergence of novel H5 and H7 highly pathogenic avian influenza viruses (HPAI) has been taking place through two main mechanisms: first, the conversion of a low pathogenic into a highly pathogenic virus, and second, the reassortment between different genetic segments of low and highly pathogenic viruses already in circulation. We investigated and summarized the literature on emerging HPAI H5 and H7 viruses with the aim of building a spatio-temporal database of all these recorded conversions and reassortments events. We subsequently mapped the spatio-temporal distribution of known emergence events, as well as the species and production systems that they were associated with, the aim being to establish their main characteristics. From 1959 onwards, we identified a total of 39 independent H7 and H5 LPAI to HPAI conversion events. All but two of these events were reported in commercial poultry production systems, and a majority of these events took place in high-income countries. In contrast, a total of 127 reassortments have been reported from 1983 to 2015, which predominantly took place in countries with poultry production systems transitioning from backyard to intensive production systems. Those systems are characterized by several co-circulating viruses, multiple host species, regular contact points in live bird markets, limited biosecurity within value chains, and frequent vaccination campaigns that impose selection pressures for emergence of novel reassortants. We conclude that novel HPAI emergences by these two mechanisms occur in different ecological niches, with different viral, environmental and host associated factors, which has implications in early detection and management and mitigation of the risk of emergence of novel HPAI viruses.', '2026-07-07 21:51:06');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2753747891', 'biosecurity', 'DNA in a bottle—Rapid metabarcoding survey for early alerts of invasive species in ports', 'Biota monitoring in ports is increasingly needed for biosecurity reasons and safeguarding marine biodiversity from biological invasion. Present and future international biosecurity directives can be…', '2017', 2017, 126, 126, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0183347.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5584753', 'pmc', 'article', 'PLoS ONE', '["Yaisel J. Borrell","Laura Miralles","Hoang Do Huu","Khaled Mohammed-Geba","Eva García‐Vázquez"]', 'biosecurity', 'Biota monitoring in ports is increasingly needed for biosecurity reasons and safeguarding marine biodiversity from biological invasion. Present and future international biosecurity directives can be accomplished only if the biota acquired by maritime traffic in ports is controlled. Methodologies for biota inventory are diverse and now rely principally on extensive and labor-intensive sampling along with taxonomic identification by experts. In this study, we employed an extremely simplified environmental DNA (eDNA) sampling methodology from only three 1-L bottles of water per port, followed by metabarcoding (high-throughput sequencing and DNA-based species identification) using 18S rDNA and Cytochrome oxidase I as genetic barcodes. Eight Bay of Biscay ports with available inventory of fouling invertebrates were employed as a case study. Despite minimal sampling efforts, three invasive invertebrates were detected: the barnacle Austrominius modestus, the tubeworm Ficopomatus enigmaticus and the polychaete Polydora triglanda. The same species have been previously found from visual and DNA barcoding (genetic identification of individuals) surveys in the same ports. The current costs of visual surveys, conventional DNA barcoding and this simplified metabarcoding protocol were compared. The results encourage the use of metabarcoding for early biosecurity alerts.', '2026-07-07 21:51:19');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3120910052', 'biosecurity', 'Insects, Rodents, and Pets as Reservoirs, Vectors, and Sentinels of Antimicrobial Resistance', 'This paper reviews the occurrence of antimicrobial resistance (AMR) in insects, rodents, and pets. Insects (e.g., houseflies, cockroaches), rodents (rats, mice), and pets (dogs, cats) act as…', '2021', 2021, 123, 123, 'https://pub.mdpi-res.com/antibiotics/antibiotics-10-00068/article_deploy/html/images/antibiotics-10-00068-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7826649', 'pmc', 'review', 'Antibiotics', '["Willis Gwenzi","Nhamo Chaukura","Norah Muisa‐Zikali","Charles Teta","Tendai Musvuugwa","Piotr Rzymski","Akebe Luther King Abia"]', 'biosecurity', 'This paper reviews the occurrence of antimicrobial resistance (AMR) in insects, rodents, and pets. Insects (e.g., houseflies, cockroaches), rodents (rats, mice), and pets (dogs, cats) act as reservoirs of AMR for first-line and last-resort antimicrobial agents. AMR proliferates in insects, rodents, and pets, and their skin and gut systems. Subsequently, insects, rodents, and pets act as vectors that disseminate AMR to humans via direct contact, human food contamination, and horizontal gene transfer. Thus, insects, rodents, and pets might act as sentinels or bioindicators of AMR. Human health risks are discussed, including those unique to low-income countries. Current evidence on human health risks is largely inferential and based on qualitative data, but comprehensive statistics based on quantitative microbial risk assessment (QMRA) are still lacking. Hence, tracing human health risks of AMR to insects, rodents, and pets, remains a challenge. To safeguard human health, mitigation measures are proposed, based on the one-health approach. Future research should include human health risk analysis using QMRA, and the application of in-silico techniques, genomics, network analysis, and ''big data'' analytical tools to understand the role of household insects, rodents, and pets in the persistence, circulation, and health risks of AMR.', '2026-07-07 21:51:29');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2515847873', 'biosecurity', 'Assessing and Managing the Current and Future Pest Risk from Water Hyacinth, (Eichhornia crassipes), an Invasive Aquatic Plant Threatening the Environment and Water Security', 'Understanding and managing the biological invasion threats posed by aquatic plants under current and future climates is a growing challenge for biosecurity and land management agencies worldwide.…', '2016', 2016, 121, 121, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0120054.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4981303', 'pmc', 'article', 'PLoS ONE', '["Darren J. Kriticos","Sarah Brunel"]', 'biosecurity', 'Understanding and managing the biological invasion threats posed by aquatic plants under current and future climates is a growing challenge for biosecurity and land management agencies worldwide. Eichhornia crassipes is one of the world''s worst aquatic weeds. Presently, it threatens aquatic ecosystems, and hinders the management and delivery of freshwater services in both developed and developing parts of the world. A niche model was fitted using CLIMEX, to estimate the potential distribution of E. crassipes under historical and future climate scenarios. Under two future greenhouse gas emission scenarios for 2080 simulated with three Global Climate Models, the area with a favourable temperature regime appears set to shift polewards. The greatest potential for future range expansion lies in Europe. Elsewhere in the northern hemisphere temperature gradients are too steep for significant geographical range expansion under the climate scenarios explored here. In the Southern Hemisphere, the southern range boundary for E. crassipes is set to expand southwards in Argentina, Australia and New Zealand; under current climate conditions it is already able to invade the southern limits of Africa. The opportunity exists to prevent its spread into the islands of Tasmania in Australia and the South Island of New Zealand, both of which depend upon hydroelectric facilities that would be threatened by the presence of E. crassipes. In Europe, efforts to slow or stop the spread of E. crassipes will face the challenge of limited internal biosecurity capacity. The modelling technique demonstrated here is the first application of niche modelling for an aquatic weed under historical and projected future climates. It provides biosecurity agencies with a spatial tool to foresee and manage the emerging invasion threats in a manner that can be included in the international standard for pest risk assessments. It should also support more detailed local and regional management.', '2026-07-07 21:51:32');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1858641767', 'biosecurity', 'Modelling Hotspots for Invasive Alien Plants in India', 'Identification of invasion hotspots that support multiple invasive alien species (IAS) is a pre-requisite for control and management of invasion. However, till recently it remained a methodological…', '2015', 2015, 114, 114, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0134665.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4521859', 'pmc', 'article', 'PLoS ONE', '["Dibyendu Adhikari","Raghuvar Tiwary","Saroj Kanta Barik"]', 'biosecurity', 'Identification of invasion hotspots that support multiple invasive alien species (IAS) is a pre-requisite for control and management of invasion. However, till recently it remained a methodological challenge to precisely determine such invasive hotspots. We identified the hotspots of alien species invasion in India through Ecological Niche Modelling (ENM) using species occurrence data from the Global Biodiversity Information Facility (GBIF). The predicted area of invasion for selected species were classified into 4 categories based on number of model agreements for a region i.e. high, medium, low and very low. About 49% of the total geographical area of India was predicted to be prone to invasion at moderate to high levels of climatic suitability. The intersection of anthropogenic biomes and ecoregions with the regions of ''high'' climatic suitability was classified as hotspot of alien plant invasion. Nineteen of 47 ecoregions of India, harboured such hotspots. Most ecologically sensitive regions of India, including the ''biodiversity hotspots'' and coastal regions coincide with invasion hotspots, indicating their vulnerability to alien plant invasion. Besides demonstrating the usefulness of ENM and open source data for IAS management, the present study provides a knowledge base for guiding the formulation of an effective policy and management strategy for controlling the invasive alien species.', '2026-07-07 21:51:52');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2169296930', 'biosecurity', 'Alternatives to the use of antimicrobial agents in pig production: A multi-country expert-ranking of perceived effectiveness, feasibility and return on investment', 'Nineteen alternatives to antimicrobial agents were ranked on perceived effectiveness, feasibility and return on investment (ROI) from 0 (not effective, not feasible, no ROI) to 10 (fully effective,…', '2015', 2015, 109, 109, 'https://ars.els-cdn.com/content/image/1-s2.0-S0167587715000252-gr1.jpg', 'https://pubmed.ncbi.nlm.nih.gov/25650306', 'repository', 'article', 'Preventive Veterinary Medicine', '["Merel Postma","Katharina D.C. Stärk","Marie Sjölund","Annette Backhans","Elisabeth große Beilage","Svenja Lösken","Catherine Belloc","Lucie Collineau","Denise Iten","Vivianne Visschers","Elisabeth Okholm Nielsen","Jeroen Dewulf"]', 'biosecurity', 'Nineteen alternatives to antimicrobial agents were ranked on perceived effectiveness, feasibility and return on investment (ROI) from 0 (not effective, not feasible, no ROI) to 10 (fully effective, completely feasible, maximum ROI) by 111 pig health experts from Belgium, Denmark, France, Germany, Sweden and Switzerland. The top 5 measures in terms of perceived effectiveness were (1) improved internal biosecurity, (2) improved external biosecurity, (3) improved climate/environmental conditions, (4) high health/Specific Pathogen Free/disease eradication and (5) increased vaccination. The top 5 measures in terms of perceived feasibility were (1) increased vaccination, (2) increased use of anti-inflammatory products, (3) improved water quality, (4) feed quality/optimization and (5) use of zinc/metals. The top 5 measures in terms of perceived ROI were (1) improved internal biosecurity, (2) zinc/metals, (3) diagnostics/action plan, (4) feed quality/optimization and (5) climate/environmental improvements. Univariate linear regression showed that veterinary practitioners rank internal biosecurity, vaccination, use of zinc/metals, feed quality optimization and climate/environmental on average highest, while researchers and professors focused more on increased use of diagnostics and action plans. Financial incentives/penalties ranked low in all countries. Belgian respondents ranked feed quality significantly lower compared to the German respondents while reduction of stocking density was ranked higher in Belgium compared to Denmark. Categorical Principal Component Analysis applied to the average ranking supported the finding that veterinary practitioners had a preference for more practical, common and already known alternatives. The results showed that improvements in biosecurity, increased use of vaccination, use of zinc/metals, feed quality improvement and regular diagnostic testing combined with a clear action plan were perceived to be the most promising alternatives to antimicrobials in industrial pig production based on combined effectiveness, feasibility and ROI.', '2026-07-07 21:51:59');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3135465667', 'biosecurity', 'Research perspectives on animal health in the era of artificial intelligence', 'Leveraging artificial intelligence (AI) approaches in animal health (AH) makes it possible to address highly complex issues such as those encountered in quantitative and predictive epidemiology,…', '2021', 2021, 104, 104, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs13567-021-00902-4/MediaObjects/13567_2021_902_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7936489', 'pmc', 'review', 'Veterinary Research', '["Pauline Ezanno","Sébastien Picault","Gaël Beaunée","Xavier Bailly","Facundo Muñoz","Raphaël Duboz","Hervé Monod","Jean‐François Guégan"]', 'biosecurity', 'Leveraging artificial intelligence (AI) approaches in animal health (AH) makes it possible to address highly complex issues such as those encountered in quantitative and predictive epidemiology, animal/human precision-based medicine, or to study host × pathogen interactions. AI may contribute (i) to diagnosis and disease case detection, (ii) to more reliable predictions and reduced errors, (iii) to representing more realistically complex biological systems and rendering computing codes more readable to non-computer scientists, (iv) to speeding-up decisions and improving accuracy in risk analyses, and (v) to better targeted interventions and anticipated negative effects. In turn, challenges in AH may stimulate AI research due to specificity of AH systems, data, constraints, and analytical objectives. Based on a literature review of scientific papers at the interface between AI and AH covering the period 2009-2019, and interviews with French researchers positioned at this interface, the present study explains the main AH areas where various AI approaches are currently mobilised, how it may contribute to renew AH research issues and remove methodological or conceptual barriers. After presenting the possible obstacles and levers, we propose several recommendations to better grasp the challenge represented by the AH/AI interface. With the development of several recent concepts promoting a global and multisectoral perspective in the field of health, AI should contribute to defract the different disciplines in AH towards more transversal and integrative research.', '2026-07-07 21:52:14');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3110839635', 'biosecurity', 'Coffee Berry Borer (Hypothenemus hampei), a Global Pest of Coffee: Perspectives from Historical and Recent Invasions, and Future Priorities', '(Ferrari), CBB) has invaded nearly every coffee-producing country in the world, and it is commonly recognized as the most damaging insect pest of coffee. While research has been conducted on this…', '2020', 2020, 104, 104, 'https://pub.mdpi-res.com/insects/insects-11-00882/article_deploy/html/images/insects-11-00882-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7763606', 'pmc', 'review', 'Insects', '["Melissa A. Johnson","Claudia Patricia Ruiz-Díaz","Nicholas C. Manoukis","J. C. V. Rodrigues"]', 'biosecurity', '(Ferrari), CBB) has invaded nearly every coffee-producing country in the world, and it is commonly recognized as the most damaging insect pest of coffee. While research has been conducted on this pest in individual coffee-growing regions, new insights may be gained by comparing and contrasting patterns of invasion and response across its global distribution. In this review, we explore the existing literature and focus on common themes in the invasion biology of CBB by examining (1) how it was introduced into each particular region and the response to its invasion, (2) flight activity and infestation patterns, (3) economic impacts, and (4) management strategies. We highlight research conducted over the last ten years in Hawaii as a case study for the development and implementation of an effective integrated pest management (IPM) program for CBB, and also discuss biosecurity issues contributing to incursion and establishment. Potential areas for future research in each of the five major components of CBB IPM (monitoring and sampling, cultural, biological, chemical, and physical controls) are also presented. Finally, we emphasize that outreach efforts are crucial to the successful implementation of CBB IPM programs. Future research programs should strive to include coffee growers as much as possible to ensure that management options are feasible and cost-effective.', '2026-07-07 21:52:19');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2592643202', 'biosecurity', 'Salmonella serovars and their distribution in Nigerian commercial chicken layer farms', 'Commercial poultry farms (n° 523), located in all the six regions of Nigeria were sampled with a view to generate baseline information about the distribution of Salmonella serovars in this country.…', '2017', 2017, 103, 103, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0173097.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5344354', 'pmc', 'article', 'PLoS ONE', '["Idowu Oluwabunmi Fagbamila","Lisa Barco","Marzia Mancin","Jacob K. P. Kwaga","Sati Samuel Ngulukun","Paola Zavagnin","Antonia Anna Lettini","Monica Lorenzetto","Paul Ayuba Abdu","Junaidu Kabir","J. U. Umoh","Antonia Ricci","Maryam Muhammad"]', 'biosecurity', 'Commercial poultry farms (n° 523), located in all the six regions of Nigeria were sampled with a view to generate baseline information about the distribution of Salmonella serovars in this country. Five different matrices (litter, dust, faeces, feed and water) were collected from each visited farm. Salmonella was isolated from at least one of the five matrices in 228 farms, with a farm prevalence of 43.6% (CI95[39.7-48.3%]). Altogether, 370 of 2615 samples collected (14.1%, CI95[12.8; 15.5%]) contained Salmonella. Considering the number of positive farms and the number of positive samples, it was evident that for the majority of the sampled farms, few samples were positive for Salmonella. With regard to the matrices, there was no difference in Salmonella prevalence among the five matrices considered. Of the 370 isolates serotyped, eighty-two different serotypes were identified and Salmonella Kentucky was identified as having the highest isolation rate in all the matrices sampled (16.2%), followed by S. Poona and S. Elisabethville. S. Kentucky was distributed across the country, whereas the other less frequent serovars had a more circumscribed diffusion. This is one of few comprehensive studies on the occurrence and distribution of Salmonella in commercial chicken layer farms from all the six regions of Nigeria. The relatively high prevalence rate documented in this study may be attributed to the generally poor infrastructure and low biosecurity measures in controlling stray animals, rodents and humans. Data collected could be valuable for instituting effective intervention strategies for Salmonella control in Nigeria and also in other developing countries with a similar poultry industry structure, with the final aim of reducing Salmonella spread in animals and ultimately in humans.', '2026-07-07 21:52:24');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3122903569', 'plant-biology', 'Identification of publicly available data sources to inform the conduct of Health Technology Assessment in India', 'Background: Health technology assessment (HTA) provides a globally-accepted and structured approach to synthesising evidence for cost and clinical effectiveness alongside ethical and equity…', '2018', 2018, 30, 30, 'https://f1000research-files.f1000.com/manuscripts/15265/a6bd818a-57fd-4e36-9127-93eddc814e56_figure1.gif', 'https://doi.org/10.12688/f1000research.14041.1', 'repository', 'preprint', 'F1000Research', '["Laura Downey","Neethi Rao","Lorna Guinness","Miqdad Asaria","Shankar Prinja","Anju Sinha","Rajni Kant","Arvind Pandey","Françoise Cluzeau","Kalipso Chalkidou"]', 'plant biology', 'Background: Health technology assessment (HTA) provides a globally-accepted and structured approach to synthesising evidence for cost and clinical effectiveness alongside ethical and equity considerations to inform evidence-based priorities. India is one of the most recent countries to formally commit to institutionalising HTA as an integral component of the heath resource allocation decision-making process. The effective conduct of HTA depends on the availability of reliable data. Methods : We draw from our experience of collecting, synthesizing, and analysing health-related datasets in India and internationally, to highlight the complex requirements for undertaking HTA, and explore the availability of such data in India. We first outlined each of the core data components required for the conduct of HTA, and their availability in India, drawing attention to where data can be accessed, and different ways in which researchers can overcome the challenges of missing or low quality data. Results : We grouped data into the following categories: clinical efficacy; cost; epidemiology; quality of life; service use/consumption; and equity. We identified numerous large local data sources containing epidemiological information. There was a marked absence of other locally-collected data necessary for informing HTA, particularly data relating to cost, service use, and quality of life. Conclusions: The introduction of HTA into the health policy space in India provides an opportunity to comprehensively assess the availability and quality of health data capture across the country. While epidemiological information is routinely collected across India, other data inputs necessary for HTA are not readily available. This poses a significant bottleneck to the efficient generation and deployment of HTA into the health decision space. Overcoming these data gaps by strengthening the routine collection of comprehensive and verifiable health data will have important implications not only for embedding economic analyses into the priority setting process, but for strengthening the health system as a whole.', '2026-07-07 21:52:25');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4307944359', 'biosecurity', 'Fish Farming Techniques: Current Situation and Trends', 'World aquaculture is increasingly diversified and intensive, due to the use of new technologies, having grown a lot in recent decades and contributed significantly to improving food security and…', '2022', 2022, 101, 101, 'https://pub.mdpi-res.com/jmse/jmse-10-01598/article_deploy/html/images/jmse-10-01598-g001.png', 'https://www.mdpi.com/2077-1312/10/11/1598/pdf?version=1668137744', 'repository', 'article', 'Journal of Marine Science and Engineering', '["Glácio Souza Araújo","José William Alves da Silva","João Cotas","Leonel Pereira"]', 'biosecurity', 'World aquaculture is increasingly diversified and intensive, due to the use of new technologies, having grown a lot in recent decades and contributed significantly to improving food security and reducing poverty in the world, with fish farming being a promising activity for the production of protein with high nutritional value. The large aquaculture companies that recognize the potential of this important modality have invested in the study and production of various productive segments of the most diverse species of fish. This review article aims to provide information on the world panorama of marine fish farming, with the main systems and production stages of the most important organisms with commercial potential, aiming to achieve a highly sustainable production, with high nutritional content and benefits for human health. The production of live feed in the larval stage should be highlighted, in order to optimize survival and weight gain. In addition, trends in the cultivation of estuarine and saltwater fish will be detailed in this review, such as the use of biotechnology and technological innovations, cultivations integration, and biosecurity. Thus, innovative methods to optimize the farming system need to be more ecosustainable, reducing the negative impacts on the environmental level.', '2026-07-07 21:52:34');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3165779836', 'biosecurity', 'Leveraging natural history biorepositories as a global, decentralized, pathogen surveillance network', 'The Severe Acute Respiratory Syndrome Coronavirus 2 (SARS-CoV-2) pandemic reveals a major gap in global biosecurity infrastructure: a lack of publicly available biological samples representative…', '2021', 2021, 99, 99, 'https://journals.plos.org/plospathogens/article/figure/image?size=large&id=10.1371/journal.ppat.1009583.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8174688', 'pmc', 'article', 'PLoS Pathogens', '["Jocelyn P. Colella","John M. Bates","Santiago F. Burneo","M. Alejandra Camacho","Carlos Carrión Bonilla","I. D. Constable","Guillermo D’Elía","Jonathan L. Dunnum","Stephen E. Greiman","Eric P. Hoberg","Enrique P. Lessa","Schuyler Liphardt","Manuela Londoño-Gaviria","Elizabeth Losos","Holly L. Lutz","Nicté Ordóñez‐Garza","A. Townsend Peterson","M. Laura Martín","Camila C. Ribas","Bruce Struminger","Fernando Torres‐Pérez","Cody W. Thompson","Marcelo Weksler","Joseph A. Cook"]', 'biosecurity', 'The Severe Acute Respiratory Syndrome Coronavirus 2 (SARS-CoV-2) pandemic reveals a major gap in global biosecurity infrastructure: a lack of publicly available biological samples representative across space, time, and taxonomic diversity. The shortfall, in this case for vertebrates, prevents accurate and rapid identification and monitoring of emerging pathogens and their reservoir host(s) and precludes extended investigation of ecological, evolutionary, and environmental associations that lead to human infection or spillover. Natural history museum biorepositories form the backbone of a critically needed, decentralized, global network for zoonotic pathogen surveillance, yet this infrastructure remains marginally developed, underutilized, underfunded, and disconnected from public health initiatives. Proactive detection and mitigation for emerging infectious diseases (EIDs) requires expanded biodiversity infrastructure and training (particularly in biodiverse and lower income countries) and new communication pipelines that connect biorepositories and biomedical communities. To this end, we highlight a novel adaptation of Project ECHO''s virtual community of practice model: Museums and Emerging Pathogens in the Americas (MEPA). MEPA is a virtual network aimed at fostering communication, coordination, and collaborative problem-solving among pathogen researchers, public health officials, and biorepositories in the Americas. MEPA now acts as a model of effective international, interdisciplinary collaboration that can and should be replicated in other biodiversity hotspots. We encourage deposition of wildlife specimens and associated data with public biorepositories, regardless of original collection purpose, and urge biorepositories to embrace new specimen sources, types, and uses to maximize strategic growth and utility for EID research. Taxonomically, geographically, and temporally deep biorepository archives serve as the foundation of a proactive and increasingly predictive approach to zoonotic spillover, risk assessment, and threat mitigation.', '2026-07-07 21:52:41');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2805586073', 'biosecurity', 'Import volumes and biosecurity interventions shape the arrival rate of fungal pathogens', 'Global trade and the movement of people accelerate biological invasions by spreading species worldwide. Biosecurity measures seek to allow trade and passenger movements while preventing incursions…', '2018', 2018, 97, 97, 'https://journals.plos.org/plosbiology/article/figure/image?size=large&id=10.1371/journal.pbio.2006025.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5978781', 'pmc', 'article', 'PLoS Biology', '["Benjamin A. Sikes","Jennifer L. Bufford","Philip E. Hulme","Jerry Cooper","Peter R. Johnston","Richard P. Duncan"]', 'biosecurity', 'Global trade and the movement of people accelerate biological invasions by spreading species worldwide. Biosecurity measures seek to allow trade and passenger movements while preventing incursions that could lead to the establishment of unwanted pests, pathogens, and weeds. However, few data exist to evaluate whether changes in trade volumes, passenger arrivals, and biosecurity measures have altered rates of establishment of nonnative species over time. This is particularly true for pathogens, which pose significant risks to animal and plant health and are consequently a major focus of biosecurity efforts but are difficult to detect. Here, we use a database of all known plant pathogen associations recorded in New Zealand to estimate the rate at which new fungal pathogens arrived and established on 131 economically important plant species over the last 133 years. We show that the annual arrival rate of new fungal pathogens increased from 1880 to about 1980 in parallel with increasing import trade volume but subsequently stabilised despite continued rapid growth in import trade and recent rapid increases in international passenger arrivals. Nevertheless, while pathogen arrival rates for crop and pasture species have declined in recent decades, arrival rates have increased for forestry and fruit tree species. These contrasting trends between production sectors reflect differences in biosecurity effort and suggest that targeted biosecurity can slow pathogen arrival and establishment despite increasing trade and international movement of people.', '2026-07-07 21:52:41');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3123156385', 'biosecurity', 'Role of novel protein sources in sustainably meeting future global requirements', 'Global population growth, increased life expectancy and climate change are all impacting world''s food systems. In industrialised countries, many individuals are consuming significantly more protein…', '2021', 2021, 95, 95, 'https://static.cambridge.org/binary/version/id/urn:cambridge.org:id:binary:20220212082605929-0537:S0029665121000513:S0029665121000513_fig1.png', 'https://pubmed.ncbi.nlm.nih.gov/33494845', 'repository', 'review', 'Proceedings of The Nutrition Society', '["Andrew M. Salter","Carlos Lopez-Viso"]', 'biosecurity', 'Global population growth, increased life expectancy and climate change are all impacting world''s food systems. In industrialised countries, many individuals are consuming significantly more protein than needed to maintain health, with the majority being obtained from animal products, including meat, dairy, fish and other aquatic animals. Current animal production systems are responsible for a large proportion of land and fresh-water use, and directly contributing to climate change through the production of greenhouse gases. Overall, approximately 60% of the global protein produced is used for animal and fish feed. Concerns about their impact on both human, and planetary health, have led to calls to dramatically curb our consumption of animal products. Underutilised plants, insects and single-cell organisms are all actively being considered as alternative protein sources. Each present challenges that need to be met before they can become economically viable and safe alternatives for food or feed. Many plant species contain anti-nutritional factors that impair the digestion and absorption of protein and micronutrients. Insects represent a potentially rich source of high-quality protein although, questions remain relating to digestibility, allergenicity and biosecurity. Algae, fungi and bacteria are also a rich source of protein and there is growing interest in the development of ''cultured meat'' using stem cell technology. For the foreseeable future, it appears likely that the ''protein-economy'' will remain mixed. The present paper reviews progress and future opportunities in the development of novel protein sources as food and animal feed.', '2026-07-07 21:53:03');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2885936995', 'plant-biology', 'Tackling resistance: emerging antimalarials and new parasite targets in the era of elimination', 'spp. parasites. Aggressive control measures have reduced the global prevalence of malaria significantly over the past decade. However, resistance to available antimalarials continues to spread,…', '2018', 2018, 30, 30, 'https://f1000research-files.f1000.com/manuscripts/16190/d60ca416-893b-4179-90e6-c3b353fd31a0_figure1.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6073090', 'pmc', 'preprint', 'F1000Research', '["Emily S. Mathews","Audrey R. Odom John"]', 'plant biology', 'spp. parasites. Aggressive control measures have reduced the global prevalence of malaria significantly over the past decade. However, resistance to available antimalarials continues to spread, including resistance to the widely used artemisinin-based combination therapies. Novel antimalarial compounds and therapeutic targets are greatly needed. This review will briefly discuss several promising current antimalarial development projects, including artefenomel, ferroquine, cipargamin, SJ733, KAF156, MMV048, and tafenoquine. In addition, we describe recent large-scale genetic and resistance screens that have been instrumental in target discovery. Finally, we highlight new antimalarial targets, which include essential transporters and proteases. These emerging antimalarial compounds and therapeutic targets have the potential to overcome multi-drug resistance in ongoing efforts toward malaria elimination.', '2026-07-07 21:53:11');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4233586970', 'plant-biology', 'Best practice data life cycle approaches for the life sciences', 'Throughout history, the life sciences have been revolutionised by technological advances; in our era this is manifested by advances in instrumentation for data generation, and consequently…', '2017', 2017, 30, 30, 'https://f1000research-files.f1000.com/manuscripts/13366/21ab9ed9-9e58-4fe9-93f0-99b8e769f8b2_figure1.gif', 'https://doi.org/10.12688/f1000research.12344.1', 'repository', 'preprint', 'F1000Research', '["Philippa C. Griffin","Jyoti Khadake","Kate LeMay","Suzanna Lewis","Sandra Orchard","Andrew J. Pask","Bernard J. Pope","Ute Roessner","Keith Russell","Torsten Seemann","Andrew Treloar","Sonika Tyagi","Jeffrey H. Christiansen","Saravanan Dayalan","Simon Gladman","Sandra Hangartner","Helen L. Hayden","William Wing Ho Ho","Gabriel Keeble‐Gagnère","Pasi K. Korhonen","Peter Neish","Priscilla R. Prestes","Mark F. Richardson","Nathan S. Watson‐Haigh","Kelly L. Wyres","Neil D. Young","Maria Victoria Schneider"]', 'plant biology', 'Throughout history, the life sciences have been revolutionised by technological advances; in our era this is manifested by advances in instrumentation for data generation, and consequently researchers now routinely handle large amounts of heterogeneous data in digital formats. The simultaneous transitions towards biology as a data science and towards a ‘life cycle’ view of research data pose new challenges. Researchers face a bewildering landscape of data management requirements, recommendations and regulations, without necessarily being able to access data management training or possessing a clear understanding of practical approaches that can assist in data management in their particular research domain. Here we provide an overview of best practice data life cycle approaches for researchers in the life sciences/bioinformatics space with a particular focus on ‘omics’ datasets and computer-based data processing and analysis. We discuss the different stages of the data life cycle and provide practical suggestions for useful tools and resources to improve data management practices.', '2026-07-07 21:53:13');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4237028857', 'plant-biology', 'Feature selection with the R package MXM', 'Feature (or variable) selection is the process of identifying the minimal set of features with the highest predictive performance on the target variable of interest. Numerous feature selection…', '2018', 2018, 29, 29, 'https://f1000research-files.f1000.com/manuscripts/17707/b3a2d543-c1e2-4425-ba28-3866b8e10525_figure1.gif', 'https://doi.org/10.12688/f1000research.16216.1', 'repository', 'preprint', 'F1000Research', '["Michail Tsagris","Ioannis Tsamardinos"]', 'plant biology', 'Feature (or variable) selection is the process of identifying the minimal set of features with the highest predictive performance on the target variable of interest. Numerous feature selection algorithms have been developed over the years, but only few have been implemented in R as a package. The R package MXM is such an example, which not only offers a variety of feature selection algorithms, but has unique features that make it advantageous over its competitors: a) it contains feature selection algorithms that can treat numerous types of target variables, including continuous, percentages, time to event (survival), binary, nominal, ordinal, clustered, counts, left censored, etc; b) it contains a variety of regression models to plug into the feature selection algorithms; c) it includes an algorithm for detecting multiple solutions (many sets of equivalent features); and d) it includes memory efficient algorithms for high volume data, data that cannot be loaded into R. In this paper we qualitatively compare MXM with other relevant packages and discuss its advantages and disadvantages. We also provide a demonstration of its algorithms using real high-dimensional data from various applications.', '2026-07-07 21:53:16');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4401244743', 'biosecurity', 'Antimicrobial Resistance in Aquaculture: Risk Mitigation within the One Health Context', 'The application of antimicrobials in aquaculture primarily aims to prevent and treat bacterial infections in fish, but their inappropriate use may result in the emergence of zoonotic…', '2024', 2024, 89, 89, 'https://pub.mdpi-res.com/foods/foods-13-02448/article_deploy/html/images/foods-13-02448-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/11311770', 'pmc', 'review', 'Foods', '["Milan Milijašević","Slavica Vesković-Moračanin","Jelena Babić Milijašević","Jelena Petrović","Ivan Nastasijević"]', 'biosecurity', 'The application of antimicrobials in aquaculture primarily aims to prevent and treat bacterial infections in fish, but their inappropriate use may result in the emergence of zoonotic antibiotic-resistant bacteria and the subsequent transmission of resistant strains to humans via food consumption. The aquatic environment serves as a potential reservoir for resistant bacteria, providing an ideal breeding ground for development of antimicrobial resistance (AMR). The mutual inter-connection of intensive fish-farming systems with terrestrial environments, the food processing industry and human population creates pathways for the transmission of resistant bacteria, exacerbating the problem further. The aim of this study was to provide an overview of the most effective and available risk mitigation strategies to tackle AMR in aquaculture, based on the One Health (OH) concept. The stringent antimicrobial use guidelines, promoting disease control methods like enhanced farm biosecurity measures and vaccinations, alternatives to antibiotics (ABs) (prebiotics, probiotics, immunostimulants, essential oils (EOs), peptides and phage therapy), feeding practices, genetics, monitoring water quality, and improving wastewater treatment, rather than applying excessive use of antimicrobials, can effectively prevent the development of AMR and release of resistant bacteria into the environment and food. The contribution of the environment to AMR development traditionally receives less attention, and, therefore, environmental aspects should be included more prominently in OH efforts to predict, detect and prevent the risks to health. This is of particular importance for low and middle-income countries with a lack of integration of the national AMR action plans (NAPs) with the aquaculture-producing environment. Integrated control of AMR in fisheries based on the OH approach can contribute to substantial decrease in resistance, and such is the case in Asia, where in aquaculture, the percentage of antimicrobial compounds with resistance exceeding 50% (P50) decreased from 52% to 22% within the period of the previous two decades.', '2026-07-07 21:53:24');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2903335172', 'biosecurity', 'Improved Biosafety and Biosecurity Measures and/or Strategies to Tackle Laboratory-Acquired Infections and Related Risks', 'Herein, we reviewed laboratory-acquired infections (LAIs) along with their health-related biological risks to provide an evidence base to tackle biosafety/biosecurity and biocontainment issues. Over…', '2018', 2018, 90, 90, 'https://pub.mdpi-res.com/ijerph/ijerph-15-02697/article_deploy/html/images/ijerph-15-02697-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6313313', 'pmc', 'review', 'International Journal of Environmental Research and Public Health', '["Huasong Peng","Muhammad Bilal","Hafiz M.N. Iqbal"]', 'biosecurity', 'Herein, we reviewed laboratory-acquired infections (LAIs) along with their health-related biological risks to provide an evidence base to tackle biosafety/biosecurity and biocontainment issues. Over the past years, a broad spectrum of pathogenic agents, such as bacteria, fungi, viruses, parasites, or genetically modified organisms, have been described and gained a substantial concern due to their profound biological as well as ecological risks. Furthermore, the emergence and/or re-emergence of life-threatening diseases are of supreme concern and come under the biosafety and biosecurity agenda to circumvent LAIs. Though the precise infection risk after an exposure remains uncertain, LAIs inspections revealed that Brucella spp., Mycobacterium tuberculosis, Salmonella spp., Shigella spp., Rickettsia spp., and Neisseria meningitidis are the leading causes. Similarly, the human immunodeficiency virus (HIV) as well as hepatitis B (HBV) and C viruses (HCV), and the dimorphic fungi are accountable for the utmost number of viral and fungal-associated LAIs. In this context, clinical laboratories at large and microbiology, mycology, bacteriology, and virology-oriented laboratories, in particular, necessitate appropriate biosafety and/or biosecurity measures to ensure the safety of laboratory workers and working environment, which are likely to have direct or indirect contact/exposure to hazardous materials or organisms. Laboratory staff education and training are indispensable to gain an adequate awareness to handle biologically hazardous materials as per internationally recognized strategies. In addition, workshops should be organized among laboratory workers to let them know the epidemiology, pathogenicity, and human susceptibility of LAIs. In this way, several health-related threats that result from the biologically hazardous materials can be abridged or minimized and controlled by the correct implementation of nationally and internationally certified protocols that include proper microbiological practices, containment devices/apparatus, satisfactory facilities or resources, protective barriers, and specialized education and training of laboratory staffs. The present work highlights this serious issue of LAIs and associated risks with suitable examples. Potential preventive strategies to tackle an array of causative agents are also discussed. In this respect, the researchers and scientific community may benefit from the lessons learned in the past to anticipate future problems.', '2026-07-07 21:53:25');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2997672749', 'biosecurity', 'Biosecurity policy and legislation for the global seaweed aquaculture industry', 'Abstract Each year a significant proportion of global food production is lost to pests and diseases, with concerted efforts by government and industry focussed on application of effective biosecurity…', '2019', 2019, 85, 85, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1007%2Fs10811-019-02010-5/MediaObjects/10811_2019_2010_Fig1_HTML.png', 'https://doi.org/10.1007/s10811-019-02010-5', 'repository', 'article', 'Journal of Applied Phycology', '["Iona Campbell","Cicilia S. B. Kambey","Jonalyn P. Mateo","Sadock B. Rusekwa","Anicia Q. Hurtado","Flower E. Msuya","Grant D. Stentiford","Elizabeth Cook"]', 'biosecurity', 'Abstract Each year a significant proportion of global food production is lost to pests and diseases, with concerted efforts by government and industry focussed on application of effective biosecurity policies which attempt to minimise their emergence and spread. In aquaculture the volume of seaweeds produced is second only to farmed fish and red algal carrageenophytes currently represent approximately 42% of global production of all seaweeds. Despite this importance, expansion of the seaweed sector is increasingly limited by the high prevalence of recalcitrant diseases and epiphytic pests with potential to emerge and with the demonstrated propensity to spread, particularly in the absence of effective national and international biosecurity policies. Developing biosecurity policy and legislation to manage biosecurity risk in seaweed aquaculture is urgently required to limit these impacts. To understand current international biosecurity frameworks and their efficacy, existing legislative frameworks were analysed quantitatively for the content of biosecurity measures, applicability to the seaweed industry, and inclusion of risks posed by diseases, pests and non-native species. Deficiencies in existing frameworks included the following: inconsistent terminology for inclusion of cultivated seaweeds, unclear designation of implementation responsibility, insufficient evidence-based information and limited alignment of biosecurity hazards and risks. Given the global importance of the cultivation of various seaweeds in alleviating poverty in low and middle income countries, it is crucial that the relatively low-unit value of the industry (i.e. as compared with other aquatic animal sectors) should not conflate with a perceived low risk of disease or pest transfer, nor the subsequent economic and environmental impact that disease transfer may impact on receiving nations (well beyond their seaweed operations). Developing a clear basis for development of robust international biosecurity policies related to the trade in seaweeds arising from the global aquaculture industry, by first addressing the gaps highlighted in this study, will be crucial in limiting impacts of pests and diseases on this valuable industry and on natural capital in locations where seaweeds are farmed.', '2026-07-07 21:53:35');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2351321356', 'biosecurity', 'Ecosystem Interactions Underlie the Spread of Avian Influenza A Viruses with Pandemic Potential', 'Despite evidence for avian influenza A virus (AIV) transmission between wild and domestic ecosystems, the roles of bird migration and poultry trade in the spread of viruses remain enigmatic. In this…', '2016', 2016, 82, 82, 'https://journals.plos.org/plospathogens/article/figure/image?size=large&id=10.1371/journal.ppat.1005620.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4864295', 'pmc', 'article', 'PLoS Pathogens', '["Justin Bahl","Truc T. Pham","Nichola J. Hill","Islam T. M. Hussein","Eric Ma","B. C. Easterday","Rebecca Halpin","Timothy B. Stockwell","David E. Wentworth","Ghazi Kayali","Scott Krauss","Stacey Schultz‐Cherry","Robert G. Webster","Richard J. Webby","Michael D. Swartz","Gavin J. D. Smith","Jonathan A. Runstadler"]', 'biosecurity', 'Despite evidence for avian influenza A virus (AIV) transmission between wild and domestic ecosystems, the roles of bird migration and poultry trade in the spread of viruses remain enigmatic. In this study, we integrate ecosystem interactions into a phylogeographic model to assess the contribution of wild and domestic hosts to AIV distribution and persistence. Analysis of globally sampled AIV datasets shows frequent two-way transmission between wild and domestic ecosystems. In general, viral flow from domestic to wild bird populations was restricted to within a geographic region. In contrast, spillover from wild to domestic populations occurred both within and between regions. Wild birds mediated long-distance dispersal at intercontinental scales whereas viral spread among poultry populations was a major driver of regional spread. Viral spread between poultry flocks frequently originated from persistent lineages circulating in regions of intensive poultry production. Our analysis of long-term surveillance data demonstrates that meaningful insights can be inferred from integrating ecosystem into phylogeographic reconstructions that may be consequential for pandemic preparedness and livestock protection.', '2026-07-07 21:53:49');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2973445699', 'biosecurity', 'Using DNA barcoding to improve invasive pest identification at U.S. ports-of-entry', 'Interception of potential invasive species at ports-of-entry is essential for effective biosecurity and biosurveillance programs. However, taxonomic assessment of the immature stages of most…', '2019', 2019, 82, 82, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0222291.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6748562', 'pmc', 'article', 'PLoS ONE', '["Mary Madden","Robert G. Young","John W. Brown","Scott E. Miller","Andrew J. Frewin","Robert Hanner"]', 'biosecurity', 'Interception of potential invasive species at ports-of-entry is essential for effective biosecurity and biosurveillance programs. However, taxonomic assessment of the immature stages of most arthropods is challenging; characters for identification are often dependent on adult morphology and reproductive structures. This study aims to strengthen the identification of such specimens through DNA barcoding, with a focus on microlepidoptera. A sample of 241 primarily immature microlepidoptera specimens intercepted at U.S. ports-of-entry from 2007 to 2011 were selected for analysis. From this sample, 201 COI-5P sequences were generated and analyzed for concordance between morphology-based and DNA-based identifications. The retrospective analysis of the data over 10 years (2009 to 2019) using the Barcode of Life Data (BOLD) system demonstrates the importance of establishing and growing DNA barcode reference libraries for use in specimen identification. Additionally, analysis of specimen identification using public data (43.3% specimens identified) vs. non-public data (78.6% specimens identified) highlights the need to encourage researchers to make data publicly accessible. DNA barcoding surpassed morphological identification with 42.3% (public) and 66.7% (non-public) of the sampled specimens achieving a species-level identification, compared to 38.3% species-level identification by morphology. Whilst DNA barcoding was not able to identify all specimens in our dataset, its incorporation into border security programs as an adjunct to morphological identification can provide secondary lines of evidence and lower taxonomic resolution in many cases. Furthermore, with increased globalization, database records need to be clearly annotated for suspected specimen origin versus interception location.', '2026-07-07 21:53:49');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3164946853', 'biosecurity', 'Challenges and Solutions to Viral Diseases of Finfish in Marine Aquaculture', 'Aquaculture is the fastest food-producing sector in the world, accounting for one-third of global food production. As is the case with all intensive farming systems, increase in infectious diseases…', '2021', 2021, 82, 82, 'https://pub.mdpi-res.com/pathogens/pathogens-10-00673/article_deploy/html/images/pathogens-10-00673-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8227678', 'pmc', 'review', 'Pathogens', '["Kizito K. Mugimba","Denis K. Byarugaba","Stephen Mutoloki","Øystein Evensen","Hetron Mweemba Munang’andu"]', 'biosecurity', 'Aquaculture is the fastest food-producing sector in the world, accounting for one-third of global food production. As is the case with all intensive farming systems, increase in infectious diseases has adversely impacted the growth of marine fish farming worldwide. Viral diseases cause high economic losses in marine aquaculture. We provide an overview of the major challenges limiting the control and prevention of viral diseases in marine fish farming, as well as highlight potential solutions. The major challenges include increase in the number of emerging viral diseases, wild reservoirs, migratory species, anthropogenic activities, limitations in diagnostic tools and expertise, transportation of virus contaminated ballast water, and international trade. The proposed solutions to these problems include developing biosecurity policies at global and national levels, implementation of biosecurity measures, vaccine development, use of antiviral drugs and probiotics to combat viral infections, selective breeding of disease-resistant fish, use of improved diagnostic tools, disease surveillance, as well as promoting the use of good husbandry and management practices. A multifaceted approach combining several control strategies would provide more effective long-lasting solutions to reduction in viral infections in marine aquaculture than using a single disease control approach like vaccination alone.', '2026-07-07 21:53:53');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1966258067', 'biosecurity', 'A hybrid modeling approach to simulating foot-and-mouth disease outbreaks in Australian livestock', 'Foot-and-mouth disease (FMD) is a highly contagious and economically important viral disease of cloven-hoofed animals. Australia''s freedom from FMD underpins a valuable trade in live animals and…', '2015', 2015, 84, 84, 'https://www.frontiersin.org/files/Articles/128449/fenvs-03-00017-HTML/image_m/fenvs-03-00017-g001.jpg', 'https://doi.org/10.3389/fenvs.2015.00017', 'repository', 'article', 'Frontiers in Environmental Science', '["Richard Bradhurst","Sharon Roche","I.J. East","Paul Kwan","M.G. Garner"]', 'biosecurity', 'Foot-and-mouth disease (FMD) is a highly contagious and economically important viral disease of cloven-hoofed animals. Australia''s freedom from FMD underpins a valuable trade in live animals and animal products. An outbreak of FMD would result in the loss of export markets and cause severe disruption to domestic markets. The prevention of, and contingency planning for, FMD are of key importance to government, industry, producers and the community. The spread and control of FMD is complex and dynamic due to a highly contagious multi-host pathogen operating in a heterogeneous environment across multiple jurisdictions. Epidemiological modelling is increasingly being recognized as a valuable tool for investigating the spread of disease under different conditions and the effectiveness of control strategies. Models of infectious disease can be broadly classified as: population-based models that are formulated from the top-down and employ population-level relationships to describe individual-level behaviour, individual-based models that are formulated from the bottom-up and aggregate individual-level behaviour to reveal population-level relationships, or hybrid models which combine the two approaches into a single model. The Australian Animal Disease Spread (AADIS) hybrid model employs a deterministic equation-based model (EBM) to model within-herd spread of FMD, and a stochastic, spatially-explicit agent-based model (ABM) to model between-herd spread and control. The EBM provides concise and computationally efficient predictions of herd prevalence and clinical signs over time. The ABM captures the complex, stochastic and heterogeneous environment in which an FMD epidemic operates. The AADIS event-driven hybrid EBM/ABM architecture is a flexible, efficient and extensible framework for modelling the spread and control of disease in livestock on a national scale. We present an overview of the AADIS hybrid approach and a description of the model''s epidemiological capabilities', '2026-07-07 21:53:56');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2605070838', 'biosecurity', 'Evaluation of biosecurity measures to prevent indirect transmission of porcine epidemic diarrhea virus', 'BACKGROUND: The effectiveness of biosecurity methods to mitigate the transmission of porcine epidemic diarrhea virus (PEDV) via farm personnel or contaminated fomites is poorly understood. This study…', '2017', 2017, 79, 79, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1007%2Fs00705-019-04166-4/MediaObjects/705_2019_4166_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5382501', 'pmc', 'article', 'BMC Veterinary Research', '["Yonghyan Kim","My Yang","Sagar M. Goyal","Maxim C.‐J. Cheeran","Montserrat Torremorell"]', 'biosecurity', 'BACKGROUND: The effectiveness of biosecurity methods to mitigate the transmission of porcine epidemic diarrhea virus (PEDV) via farm personnel or contaminated fomites is poorly understood. This study was undertaken to evaluate the effectiveness of biosecurity procedures directed at minimizing transmission via personnel following different biosecurity protocols using a controlled experimental setting. RESULTS: PEDV RNA was detected from rectal swabs of experimentally infected (INF) and sentinel pigs by real-time reverse transcription polymerase chain reaction (rRT-PCR). Virus shedding in INF pigs peaked at 1 day post infection (dpi) and viral RNA levels remained elevated through 19 dpi. Sentinel pigs in the low biosecurity group (LB) became PEDV positive after the first movement of study personnel from the INF group. However, rectal swabs from pigs in the medium biosecurity (MB) and high biosecurity (HB) groups were negative during the 10 consecutive days of movements and remained negative through 24 days post movement (dpm) when the first trial was terminated. Viral RNA was detected at 1 dpm through 3 dpm from the personal protective equipment (PPE) of LB personnel. In addition, at 1 dpm, 2 hair/face swabs from MB personnel were positive; however, transmission of virus was not detected. All swabs of fomite from the HB study personnel were negative. CONCLUSIONS: These results indicate that indirect PEDV transmission through contaminated PPE occurs rapidly (within 24 h) under modeled conditions. Biosecurity procedures such as changing PPE, washing exposed skin areas, or taking a shower are recommended for pig production systems and appear to be an effective option for lowering the risk of PEDV transmission between groups of pigs.', '2026-07-07 21:54:09');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2901068016', 'biosecurity', 'Association between antimicrobial usage, biosecurity measures as well as farm performance in German farrow-to-finish farms', 'Antimicrobial usage in food producing animals is of major concern. A clear link between the extent of use and the development of antimicrobial resistance has already been demonstrated. To evaluate…', '2018', 2018, 79, 79, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs40813-018-0106-5/MediaObjects/40813_2018_106_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6293545', 'pmc', 'article', 'Porcine Health Management', '["Svenja Raasch","Merel Postma","Jeroen Dewulf","Katharina D.C. Stärk","Elisabeth große Beilage"]', 'biosecurity', 'Antimicrobial usage in food producing animals is of major concern. A clear link between the extent of use and the development of antimicrobial resistance has already been demonstrated. To evaluate strategies that may reduce the antimicrobial usage while assuring pig health and welfare, it requires profound knowledge of factors that are associated with antimicrobial usage. Data on biosecurity and herd management practices are important parameters to identify risk factors which are related to a higher antimicrobial usage. To investigate between-farm variations of high and low usage the treatment incidence (TI) per age group in 60 German farrow-to-finish herds was qualitatively and quantitatively analysed and linked to biosecurity measures, and herd management characteristics. Weaned pigs received most of the treatments (median TI = 487.6), followed by suckling pigs (median TI = 138.9). Suckling pigs were treated with critically important antimicrobials (3rd and 4th generation cephalosporines) to a remarkable extent. The number of sows present at site ( p < 0.01) and a low score for external biosecurity ( p = 0.06) were associated with a higher antimicrobial usage in pigs from birth till slaughter. Herds with a higher treatment incidence in growing pigs (TI 200 days): i) were located in a region with a high pig density ( p < 0.01), ii) had a less strict access check for visitors and personnel ( p < 0.01) and iii) scored lower in the subcategory ‘cleaning and disinfection’ (internal biosecurity) ( p < 0.01). Herds with a higher treatment incidence in breeding pigs weaned more piglets per sow and year and scored better in the internal biosecurity level ( p = 0.02). With the main focus on the treatment incidence in pigs from birth till slaughter and in breeding pigs risk factors for a high usage in these age groups were identified. The level of biosecurity of a herd was associated with the amount of antimicrobials used. Therefore, the findings in this study indicate possible points of action in the reduction and prudent use of antimicrobials in Germany. The active improvement of biosecurity measures could be a promising alternative to reduce antimicrobial usage on herd level.', '2026-07-07 21:54:11');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4376137760', 'biosecurity', 'Can Improved Farm Biosecurity Reduce the Need for Antimicrobials in Food Animals? A Scoping Review', 'Limited and judicious antimicrobial usage (AMU) is considered the key to saving the success of human and veterinary medicine in treating infections. With the limited alternatives for antimicrobials,…', '2023', 2023, 79, 79, 'https://pub.mdpi-res.com/antibiotics/antibiotics-12-00893/article_deploy/html/images/antibiotics-12-00893-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/10215210', 'pmc', 'review', 'Antibiotics', '["Pankaj Dhaka","Ilias Chantziaras","Deepthi Vijay","Jasbir Singh Bedi","I. F. Makovska","Evelien Biebaut","Jeroen Dewulf"]', 'biosecurity', 'Limited and judicious antimicrobial usage (AMU) is considered the key to saving the success of human and veterinary medicine in treating infections. With the limited alternatives for antimicrobials, farm biosecurity (and herd management) is considered a promising tool to mitigate the non-judicious AMU and to maintain animal health, production, and welfare. The present scoping review aims to analyse the effect of farm biosecurity on AMU in livestock systems and formulate recommendations. Peer-reviewed manuscripts published between 2001-2022 were analyzed using the PRISMA framework using PubMed, Scopus, and Science Direct databases. After applying the inclusion criteria, 27 studies were found to assess the effect of farm biosecurity (or management practices) on AMU at the herd/farm level in quantitative/semi-quantitative terms. These studies were carried out in 16 countries, of which 74.1% (20/27) were from 11 European countries. The highest number of studies were from pig farms [51.8% (14/27)], followed by poultry (chicken) farms [25.9% (7/27)], cattle farms [11.1% (3/27)], and a single study from a turkey farm. Two studies include both pig and poultry farms. Most of the studies were cross-sectional [70.4% (19/27)], seven were longitudinal, and one was a case-control study. Complex interactions were observed among factors influencing AMU, such as biosecurity measures, farm characteristics, farmers'' attitudes, availability of animal health services, stewardship, etc. A positive association between farm biosecurity and reduction in AMU was observed in 51.8% (14/27) of the studies, and 18.5% (5/27) showed that improvement in farm management practices was associated with a reduction in AMU. Two studies highlighted that coaching and awareness among farmers might lead to a decrease in AMU. A single study on economic assessment concluded biosecurity practices as a cost-effective way to reduce AMU. On the other hand, five studies showed an uncertain or spurious association between farm biosecurity and AMU. We recommend the reinforcement of the concept of farm biosecurity, especially in lower- and middle-income countries (LMICs). Further, there is a need to strengthen the evidence on the association between farm biosecurity and AMU in region- and species-specific farm settings.', '2026-07-07 21:54:16');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2761395061', 'biosecurity', 'Potential impacts of climate change on habitat suitability for the Queensland fruit fly', 'Anthropogenic climate change is a major factor driving shifts in the distributions of pests and invasive species. The Queensland fruit fly, Bactrocera tryoni Froggatt (Qfly), is the most economically…', '2017', 2017, 74, 74, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41598-017-13307-1/MediaObjects/41598_2017_13307_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5638917', 'pmc', 'article', 'Scientific Reports', '["Sabira Sultana","John B. Baumgartner","Bernard C. Dominiak","Jane E Royer","Linda J. Beaumont"]', 'biosecurity', 'Anthropogenic climate change is a major factor driving shifts in the distributions of pests and invasive species. The Queensland fruit fly, Bactrocera tryoni Froggatt (Qfly), is the most economically damaging insect pest of Australia''s horticultural industry, and its management is a key priority for plant protection and biosecurity. Identifying the extent to which climate change may alter the distribution of suitable habitat for Qfly is important for the development and continuation of effective monitoring programs, phytosanitary measures, and management strategies. We used Maxent, a species distribution model, to map suitable habitat for Qfly under current climate, and six climate scenarios for 2030, 2050 and 2070. Our results highlight that south-western Australia, northern regions of the Northern Territory, eastern Queensland, and much of south-eastern Australia are currently suitable for Qfly. This includes southern Victoria and eastern Tasmania, which are currently free of breeding populations. There is substantial agreement across future climate scenarios that most areas currently suitable will remain so until at least 2070. Our projections provide an initial estimate of the potential exposure of Australia''s horticultural industry to Qfly as climate changes, highlighting the need for long-term vigilance across southern Australia to prevent further range expansion of this species.', '2026-07-07 21:54:20');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2601127770', 'biosecurity', 'Mitochondrial DNA and trade data support multiple origins of Helicoverpa armigera (Lepidoptera, Noctuidae) in Brazil', 'The Old World bollworm Helicoverpa armigera is now established in Brazil but efforts to identify incursion origin(s) and pathway(s) have met with limited success due to the patchiness of available…', '2017', 2017, 74, 74, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fsrep45302/MediaObjects/41598_2017_Article_BFsrep45302_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5368605', 'pmc', 'article', 'Scientific Reports', '["Wee Tek Tay","Tom Walsh","Sharon Downes","Craig Anderson","Lars S. Jermiin","Thomas K. F. Wong","Melissa Claire Piper","Ester Silva Chang","Isabella Barony Macedo","Cecília Czepak","G. T. Behere","Pierre Silvie","Miguel F. Soria","Marie Frayssinet","Karl Gordon"]', 'biosecurity', 'The Old World bollworm Helicoverpa armigera is now established in Brazil but efforts to identify incursion origin(s) and pathway(s) have met with limited success due to the patchiness of available data. Using international agricultural/horticultural commodity trade data and mitochondrial DNA (mtDNA) cytochrome oxidase I (COI) and cytochrome b (Cyt b) gene markers, we inferred the origins and incursion pathways into Brazil. We detected 20 mtDNA haplotypes from six Brazilian states, eight of which were new to our 97 global COI-Cyt b haplotype database. Direct sequence matches indicated five Brazilian haplotypes had Asian, African, and European origins. We identified 45 parsimoniously informative sites and multiple substitutions per site within the concatenated (945 bp) nucleotide dataset, implying that probabilistic phylogenetic analysis methods are needed. High diversity and signatures of uniquely shared haplotypes with diverse localities combined with the trade data suggested multiple incursions and introduction origins in Brazil. Increasing agricultural/horticultural trade activities between the Old and New Worlds represents a significant biosecurity risk factor. Identifying pest origins will enable resistance profiling that reflects countries of origin to be included when developing a resistance management strategy, while identifying incursion pathways will improve biosecurity protocols and risk analysis at biosecurity hotspots including national ports.', '2026-07-07 21:54:20');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4307944290', 'biosecurity', 'Campylobacter jejuni in Poultry: Pathogenesis and Control Strategies', 'C. jejuni is the leading cause of human foodborne illness associated with poultry, beef, and pork consumption. C. jejuni is highly prevalent in commercial poultry farms, where horizontal transmission…', '2022', 2022, 76, 76, 'https://pub.mdpi-res.com/microorganisms/microorganisms-10-02134/article_deploy/html/images/microorganisms-10-02134-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/9697106', 'pmc', 'review', 'Microorganisms', '["Walid Ghazi Al Hakeem","Shahna Fathima","Revathi Shanmugasundaram","Ramesh K. Selvaraj"]', 'biosecurity', 'C. jejuni is the leading cause of human foodborne illness associated with poultry, beef, and pork consumption. C. jejuni is highly prevalent in commercial poultry farms, where horizontal transmission from the environment is considered to be the primary source of C. jejuni. As an enteric pathogen, C. jejuni expresses virulence factors regulated by a two-component system that mediates C. jejuni’s ability to survive in the host. C. jejuni survives and reproduces in the avian intestinal mucus. The avian intestinal mucus is highly sulfated and sialylated compared with the human mucus modulating C. jejuni pathogenicity into a near commensal bacteria in poultry. Birds are usually infected from two to four weeks of age and remain colonized until they reach market age. A small dose of C. jejuni (around 35 CFU/mL) is sufficient for successful bird colonization. In the U.S., where chickens are raised under antibiotic-free environments, additional strategies are required to reduce C. jejuni prevalence on broilers farms. Strict biosecurity measures can decrease C. jejuni prevalence by more than 50% in broilers at market age. Vaccination and probiotics, prebiotics, synbiotics, organic acids, bacteriophages, bacteriocins, and quorum sensing inhibitors supplementation can improve gut health and competitively exclude C. jejuni load in broilers. Most of the mentioned strategies showed promising results; however, they are not fully implemented in poultry production. Current knowledge on C. jejuni’s morphology, source of transmission, pathogenesis in poultry, and available preharvest strategies to decrease C. jejuni colonization in broilers are addressed in this review.', '2026-07-07 21:54:26');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4409412903', 'biosecurity', 'Engineering biology applications for environmental solutions: potential and challenges', 'Engineering biology applies synthetic biology to address global environmental challenges like bioremediation, biosequestration, pollutant monitoring, and resource recovery. This perspective outlines…', '2025', 2025, 73, 73, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41467-025-58492-0/MediaObjects/41467_2025_58492_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/11997111', 'pmc', 'review', 'Nature Communications', '["David J. Lea‐Smith","Francis Hassard","Frédéric Coulon","Natalie Partridge","Louise Horsfall","Kyle D. J. Parker","R. Smith","Ronan R. McCarthy","Boyd A. McKew","Tony Gutiérrez","Vinod Kumar","Gabriela Dotro","Zhugen Yang","EBIC partners","Thomas P. Curtis","Peter Golyshin","Sonia Heaven","Bruce Jefferson","Paul Jeffrey","Davey L. Jones","Kristell Le Corre Pidou","Yongqiang Liu","Tao Lyu","Cindy Smith","Alexander Yakunin","Yue Zhang","Natalio Krasnogor"]', 'biosecurity', 'Engineering biology applies synthetic biology to address global environmental challenges like bioremediation, biosequestration, pollutant monitoring, and resource recovery. This perspective outlines innovations in engineering biology, its integration with other technologies (e.g., nanotechnology, IoT, AI), and commercial ventures leveraging these advancements. We also discuss commercialisation and scaling challenges, biosafety and biosecurity considerations including biocontainment strategies, social and political dimensions, and governance issues that must be addressed for successful real-world implementation. Finally, we highlight future perspectives and propose strategies to overcome existing hurdles, aiming to accelerate the adoption of engineering biology for environmental solutions.', '2026-07-07 21:54:37');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4291209192', 'biosecurity', 'A global dataset for prevalence of Salmonella Gallinarum between 1945 and 2021', 'Pullorum disease and fowl typhoid are among the most significant poultry diseases worldwide. However, the global burden of these diseases remains unknown. Most importantly, the parameters…', '2022', 2022, 73, 73, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41597-022-01605-x/MediaObjects/41597_2022_1605_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/9376096', 'pmc', 'review', 'Scientific Data', '["Xiao Zhou","Xiamei Kang","Kun Zhou","Min Yue"]', 'biosecurity', 'Pullorum disease and fowl typhoid are among the most significant poultry diseases worldwide. However, the global burden of these diseases remains unknown. Most importantly, the parameters contributing to the prevalence of Salmonella Gallinarum variants are not well documented. Therefore, in this study, we present a systematic review and meta-analysis of the global prevalence of Salmonella Gallinarum during 1945-2021. In total, 201 studies were identified for qualitative analysis (>900 million samples). The meta-analysis was subjected to over 183 screened studies. The global prevalence of S. Gallinarum (percentage of positive samples in total samples) was 8.54% (95% CI: 8.43-8.65) and showed a V-shaped recovery over time. Pullorum disease is most common in Asia, particularly in eastern China. Further investigations on chicken origin samples revealed significant differences in S. Gallinarum prevalence by gender, breed, raising mode, economic use, and growth stage, indicating a critical role of vertical transmission. Together, this study offered an updated, evidence-based dataset and knowledge regarding S. Gallinarum epidemics, which might significantly impact decision-making policy with targeted interventions.', '2026-07-07 21:54:37');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2802000588', 'biosecurity', 'Quantitative Microbial Risk Assessment and Infectious Disease Transmission Modeling of Waterborne Enteric Pathogens', 'Quantitative Microbial Risk Assessment and Infectious Disease Transmission Modeling of Waterborne Enteric Pathogens', '2018', 2018, 73, 73, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1007%2Fs00267-022-01657-0/MediaObjects/267_2022_1657_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5984175', 'pmc', 'review', 'Current Environmental Health Reports', '["Andrew F. Brouwer","Nina B. Masters","Joseph N. S. Eisenberg"]', 'biosecurity', NULL, '2026-07-07 21:54:38');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3205748264', 'biosecurity', 'Managing Biofouling on Submerged Static Artificial Structures in the Marine Environment – Assessment of Current and Emerging Approaches', 'The number, extent, diversity, and global reach of submerged static artificial structures (SSAS) in the marine environment is increasing. These structures are prone to the accumulation of biofouling…', '2021', 2021, 72, 72, 'https://www.frontiersin.org/files/Articles/759194/fmars-08-759194-HTML-r1/image_m/fmars-08-759194-g001.jpg', 'https://doi.org/10.3389/fmars.2021.759194', 'repository', 'article', 'Frontiers in Marine Science', '["Grant A. Hopkins","Ian Davidson","Eugene Georgiades","Oliver Floerl","Donald J. Morrisey","Patrick Cahill"]', 'biosecurity', 'The number, extent, diversity, and global reach of submerged static artificial structures (SSAS) in the marine environment is increasing. These structures are prone to the accumulation of biofouling that can result in unwanted impacts, both immediate and long-term. Therefore, management of biofouling on SSAS has a range of potential benefits that can improve structure functions, cost-efficiency, sustainability, productivity, and biosecurity. This review and synthesis collates the range of methods and tools that exist or are emerging for managing SSAS biofouling for a variety of sectors, highlighting key criteria and knowledge gaps that affect development, and uptake to improve operational and environmental outcomes. The most common methods to manage biofouling on SSAS are mechanical and are applied reactively to manage biofouling assemblages after they have developed to substantial levels. Effective application of reactive methods is logistically challenging, occurs after impacts have accumulated, can pose health and safety risks, and is costly at large scales. Emerging technologies aim to shift this paradigm to a more proactive and preventive management approach, but uncertainty remains regarding their long-term efficacy, feasibility, and environmental effects at operational scales. Key priorities to promote more widespread biofouling management of SSAS include rigorous and transparent independent testing of emerging treatment systems, with more holistic cost-benefit analyses where efficacy is demonstrated.', '2026-07-07 21:54:40');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3186530033', 'biosecurity', 'Global Patterns of the Fungal Pathogen Batrachochytrium dendrobatidis Support Conservation Urgency', 'The amphibian chytrid fungus Batrachochytrium dendrobatidis ( Bd ) is a skin pathogen that can cause the emerging infectious disease chytridiomycosis in susceptible species. It has been considered…', '2021', 2021, 70, 70, 'https://www.frontiersin.org/files/Articles/685877/fvets-08-685877-HTML-r2/image_m/fvets-08-685877-g001.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8322974', 'pmc', 'article', 'Frontiers in Veterinary Science', '["Deanna H. Olson","Kathryn L. Ronnenberg","Caroline K. Glidden","Kelly Christiansen","Andrew R. Blaustein"]', 'biosecurity', 'The amphibian chytrid fungus Batrachochytrium dendrobatidis ( Bd ) is a skin pathogen that can cause the emerging infectious disease chytridiomycosis in susceptible species. It has been considered one of the most severe threats to amphibian biodiversity. We aimed to provide an updated compilation of global Bd occurrences by host taxon and geography, and with the larger global Bd dataset we reanalyzed Bd associations with environmental metrics at the world and regional scales. We also compared our Bd data compilation with a recent independent assessment to provide a more comprehensive count of species and countries with Bd occurrences. Bd has been detected in 1,375 of 2,525 (55%) species sampled, more than doubling known species infections since 2013. Bd occurrence is known from 93 of 134 (69%) countries at this writing; this compares to known occurrences in 56 of 82 (68%) countries in 2013. Climate-niche space is highly associated with Bd detection, with different climate metrics emerging as key predictors of Bd occurrence at regional scales; this warrants further assessment relative to climate-change projections. The accretion of Bd occurrence reports points to the common aims of worldwide investigators to understand the conservation concerns for amphibian biodiversity in the face of potential disease threat. Renewed calls for better mitigation of amphibian disease threats resonate across continents with amphibians, especially outside Asia. As Bd appears to be able to infect about half of amphibian taxa and sites, there is considerable room for biosecurity actions to forestall its spread using both bottom-up community-run efforts and top-down national-to-international policies. Conservation safeguards for sensitive species and biodiversity refugia are continuing priorities.', '2026-07-07 21:54:52');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3209931176', 'plant-biology', 'Prediction of repurposed drugs for treating lung injury in COVID-19', 'Background: Coronavirus disease (COVID-19) is an infectious disease discovered in 2019 and currently in outbreak across the world. Lung injury with severe respiratory failure is the leading cause of…', '2020', 2020, 29, 29, 'https://f1000research-files.f1000.com/manuscripts/26472/a0f1f233-c81a-42ee-a380-6f8e304cdeb0_figure1.gif', 'https://doi.org/10.12688/f1000research.23996.1', 'repository', 'preprint', 'F1000Research', '["Bing He","Lana X. Garmire"]', 'plant biology', 'Background: Coronavirus disease (COVID-19) is an infectious disease discovered in 2019 and currently in outbreak across the world. Lung injury with severe respiratory failure is the leading cause of death in COVID-19, caused by severe acute respiratory syndrome coronavirus 2 (SARS-CoV-2). However, there still lacks efficient treatment for COVID-19 induced lung injury and acute respiratory failure. Methods: Inhibition of angiotensin-converting enzyme 2 (ACE2) caused by the spike protein of SARS-CoV-2 is the most plausible mechanism of lung injury in COVID-19. We performed drug repositioning analysis to identify drug candidates that reverse gene expression pattern in L1000 lung cell line HCC515 treated with ACE2 inhibitor. We confirmed these drug candidates by similar bioinformatics analysis using lung tissues from patients deceased from COVID-19. We further investigated deregulated genes and pathways related to lung injury, as well as the gene-pathway-drug candidate relationships. Results: We propose two candidate drugs, COL-3 (a chemically modified tetracycline) and CGP-60474 (a cyclin-dependent kinase inhibitor), for treating lung injuries in COVID-19. Further bioinformatics analysis shows that 12 significantly enriched pathways (P-value &lt;0.05) overlap between HCC515 cells treated with ACE2 inhibitor and human COVID-19 patient lung tissues. These include signaling pathways known to be associated with lung injury such as TNF signaling, MAPK signaling and chemokine signaling pathways. All 12 pathways are targeted in COL-3 treated HCC515 cells, in which genes such as RHOA, RAC2, FAS, CDC42 have reduced expression. CGP-60474 shares 11 of 12 pathways with COL-3 and common target genes such as RHOA. It also uniquely targets other genes related to lung injury, such as CALR and MMP14. Conclusions: This study shows that ACE2 inhibition is likely part of the mechanisms leading to lung injury in COVID-19, and that compounds such as COL-3 and CGP-60474 have potential as repurposed drugs for its treatment.', '2026-07-07 21:55:00');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2464507224', 'biosecurity', 'A Mathematical Model that Simulates Control Options for African Swine Fever Virus (ASFV)', 'A stochastic model designed to simulate transmission dynamics of African swine fever virus (ASFV) in a free-ranging pig population under various intervention scenarios is presented. The model was…', '2016', 2016, 69, 69, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0158658.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4938631', 'pmc', 'article', 'PLoS ONE', '["Mike B. Barongo","Richard P. Bishop","Eric M. Fèvre","Darryn L. Knobel","Amos Ssematimba"]', 'biosecurity', 'A stochastic model designed to simulate transmission dynamics of African swine fever virus (ASFV) in a free-ranging pig population under various intervention scenarios is presented. The model was used to assess the relative impact of the timing of the implementation of different control strategies on disease-related mortality. The implementation of biosecurity measures was simulated through incorporation of a decay function on the transmission rate. The model predicts that biosecurity measures implemented within 14 days of the onset of an epidemic can avert up to 74% of pig deaths due to ASF while hypothetical vaccines that confer 70% immunity when deployed prior to day 14 of the epidemic could avert 65% of pig deaths. When the two control measures are combined, the model predicts that 91% of the pigs that would have otherwise succumbed to the disease if no intervention was implemented would be saved. However, if the combined interventions are delayed (defined as implementation from > 60 days) only 30% of ASF-related deaths would be averted. In the absence of vaccines against ASF, we recommend early implementation of enhanced biosecurity measures. Active surveillance and use of pen-side diagnostic assays, preferably linked to rapid dissemination of this data to veterinary authorities through mobile phone technology platforms are essential for rapid detection and confirmation of ASF outbreaks. This prediction, although it may seem intuitive, rationally confirms the importance of early intervention in managing ASF epidemics. The modelling approach is particularly valuable in that it determines an optimal timing for implementation of interventions in controlling ASF outbreaks.', '2026-07-07 21:55:06');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2598792310', 'biosecurity', 'Risk factors for ESBL-producing Escherichia coli on pig farms: A longitudinal study in the context of reduced use of antimicrobials', 'The presence of extended-spectrum beta-lactamase-producing Escherichia coli (ESBL-E. coli) in food animals is a public health concern. This study aimed to determine prevalence of ESBL-E. coli on pig…', '2017', 2017, 69, 69, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0174094.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5360262', 'pmc', 'article', 'PLoS ONE', '["Wietske Dohmen","Alejandro Dorado-García","Marc J. M. Bonten","Jaap A. Wagenaar","Dik Mevius","Dick Heederik"]', 'biosecurity', 'The presence of extended-spectrum beta-lactamase-producing Escherichia coli (ESBL-E. coli) in food animals is a public health concern. This study aimed to determine prevalence of ESBL-E. coli on pig farms and to assess the effect of reducing veterinary antimicrobial use (AMU) and farm management practices on ESBL-E. coli occurrence on pig farms. During 2011-2013, 36 Dutch conventional pig farms participated in a longitudinal study (4 sampling times in 18 months). Rectal swabs were taken from 60 pigs per farm and pooled per 6 pigs within the same age category. Presence of ESBL-E. coli was determined by selective plating and ESBL genes were characterized by microarray, PCR and gene sequencing. An extensive questionnaire on farm characteristics and AMU as Defined Daily Dosages per Animal Year (DDDA/Y) was available for the 6-month periods before each sampling moment. Associations between the presence of ESBL-E. coli-positive pigs and farm management practices were modelled with logistic regression. The number of farms with ESBL-E. coli carrying pigs decreased from 16 to 10 and the prevalence of ESBL-E. coli-positive pooled pig samples halved from 27% to 13%. Overall, the most detected ESBL genes were blaCTX-M-1, blaTEM-52 and blaCTX-M-14. The presence of ESBL-E. coli carrying pigs was not related to total AMU, but it was strongly determined by the presence or absence of cephalosporin use at the farm (OR = 46.4, p = 0.006). Other farm management factors, related with improved biosecurity, were also plausibly related to lower probabilities for ESBL-E. coli-positive farms (e.g. presence of a hygiene lock, pest control delivered by a professional). In conclusion, ESBL-E. coli prevalence decreased in pigs during 2011 and 2013 in the Netherlands. On pig farms, the use of cephalosporins was associated with the presence of ESBL-E. coli carrying pigs.', '2026-07-07 21:55:06');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4407302842', 'plant-biology', 'Recent Advances in Biopesticide Research and Development with a Focus on Microbials', 'Biopesticides are pest control products derived from natural sources such as microbes, macro-organisms (insects and pathogens), plant extracts, and certain minerals. Many biopesticides are considered…', '2025', 2025, 28, 28, 'https://f1000research-files.f1000.com/manuscripts/177450/1bbfe5e3-bc8d-40bb-adc8-3724b6006baa_figure1.gif', 'https://doi.org/10.12688/f1000research.154392.4', 'repository', 'preprint', 'F1000Research', '["Kahsay Tadesse Mawcha","Lawrence Malinga","Debbie Muir","Jing Ge","Dennis Ndolo"]', 'plant biology', 'Biopesticides are pest control products derived from natural sources such as microbes, macro-organisms (insects and pathogens), plant extracts, and certain minerals. Many biopesticides are considered environmentally safe and can complement or substitute conventional chemical pesticides. They can also be highly specific or broad spectrum with a unique mode of action controlling a wide range of pest species. Due to their target-specificity and low to no environmental residuality, biopesticides conform to the 3 pillars of Climate-Smart Agriculture, the Sustainable Development Goals, and, ultimately, the Paris Agreement. This review focuses largely on microbial biopesticides derived from fungi, bacteria, viruses, and nematodes. It discusses (i) the various microbial biopesticide formulations, (ii) the mode of microbial biopesticide action, (iii) the factors that affect the potential efficacy of biopesticides, (iv) challenges to the adoption of microbial biopesticides, and (v) the role of microbial biopesticides in Integrated Pest Management programs. Finally, advancements in application techniques, as well as future research directions and gaps, are highlighted.', '2026-07-07 21:55:14');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2800335896', 'biosecurity', 'Biosecurity practices on Australian commercial layer and meat chicken farms: Performance and perceptions of farmers', 'This paper describes the level of adoption of biosecurity practices performed on Australian commercial chicken meat and layer farms and farmer-perceived importance of these practices. On-farm…', '2018', 2018, 68, 68, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0195582.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5906091', 'pmc', 'article', 'PLoS ONE', '["Angela Bullanday Scott","Mini Singh","Peter J. Groves","Marta Hernández‐Jover","Belinda Barnes","Kathryn Glass","Barbara Moloney","Amanda Black","Jenny‐Ann Toribio"]', 'biosecurity', 'This paper describes the level of adoption of biosecurity practices performed on Australian commercial chicken meat and layer farms and farmer-perceived importance of these practices. On-farm interviews were conducted on 25 free range layer farms, nine cage layer farms, nine barn layer farms, six free range meat chicken farms and 15 barn meat chicken farms in the Sydney basin bioregion and South East Queensland. There was a high level of treatment of drinking water across all farm types; town water was the most common source. In general, meat chicken farms had a higher level of adoption of biosecurity practices than layer farms. Cage layer farms had the shortest median distance between sheds (7.75m) and between sheds and waterbodies (30m). Equipment sharing between sheds was performed on 43% of free range meat chicken farms compared to 92% of free range layer farms. There was little disinfection of this shared equipment across all farm types. Footbaths and visitor recording books were used by the majority of farms for all farm types except cage layer farms (25%). Wild birds in sheds were most commonly reported in free range meat chicken farms (73%). Dogs and cats were kept across all farm types, from 56% of barn layer farms to 89% of cage layer farms, and they had access to the sheds in the majority (67%) of cage layer farms and on the range in some free range layer farms (44%). Most biosecurity practices were rated on average as ''very important'' by farmers. A logistic regression analysis revealed that for most biosecurity practices, performing a practice was significantly associated with higher perceived farmer importance of that biosecurity practice. These findings help identify farm types and certain biosecurity practices with low adoption levels. This information can aid decision-making on efforts used to improve adoption levels.', '2026-07-07 21:55:22');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2189960091', 'biosecurity', 'Expert Opinion on the Perceived Effectiveness and Importance of On-Farm Biosecurity Measures for Cattle and Swine Farms in Switzerland', 'Biosecurity is crucial for safeguarding livestock from infectious diseases. Despite the plethora of biosecurity recommendations, published scientific evidence on the effectiveness of individual…', '2015', 2015, 68, 68, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0144533.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4686079', 'pmc', 'article', 'PLoS ONE', '["Karin Küster","Marie‐Eve Cousin","Thomas Jemmi","Gertraud Schüpbach‐Regula","Ioannis Magouras"]', 'biosecurity', 'Biosecurity is crucial for safeguarding livestock from infectious diseases. Despite the plethora of biosecurity recommendations, published scientific evidence on the effectiveness of individual biosecurity measures is limited. The objective of this study was to assess the perception of Swiss experts about the effectiveness and importance of individual on-farm biosecurity measures for cattle and swine farms (31 and 30 measures, respectively). Using a modified Delphi method, 16 Swiss livestock disease specialists (8 for each species) were interviewed. The experts were asked to rank biosecurity measures that were written on cards, by allocating a score from 0 (lowest) to 5 (highest). Experts ranked biosecurity measures based on their importance related to Swiss legislation, feasibility, as well as the effort required for implementation and the benefit of each biosecurity measure. The experts also ranked biosecurity measures based on their effectiveness in preventing an infectious agent from entering and spreading on a farm, solely based on transmission characteristics of specific pathogens. The pathogens considered by cattle experts were those causing Bluetongue (BT), Bovine Viral Diarrhea (BVD), Foot and Mouth Disease (FMD) and Infectious Bovine Rhinotracheitis (IBR). Swine experts expressed their opinion on the pathogens causing African Swine Fever (ASF), Enzootic Pneumonia (EP), Porcine Reproductive and Respiratory Syndrome (PRRS), as well as FMD. For cattle farms, biosecurity measures that improve disease awareness of farmers were ranked as both most important and most effective. For swine farms, the most important and effective measures identified were those related to animal movements. Among all single measures evaluated, education of farmers was perceived by the experts to be the most important and effective for protecting both Swiss cattle and swine farms from disease. The findings of this study provide an important basis for recommendation to farmers and policy makers.', '2026-07-07 21:55:22');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3121849878', 'biosecurity', 'Understanding Antimicrobial Use Contexts in the Poultry Sector: Challenges for Small-Scale Layer Farms in Kenya', 'The poultry sector contributes significantly to Kenya''s food and economic security. This contribution is expected to rise dramatically with a growing population, urbanization, and preferences for…', '2021', 2021, 67, 67, 'https://pub.mdpi-res.com/antibiotics/antibiotics-10-00106/article_deploy/html/images/antibiotics-10-00106-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7911778', 'pmc', 'article', 'Antibiotics', '["Stella Kiambi","Rosemary Mwanza","Anima Sirma","Christine Czerniak","Tabitha Kimani","Emmanuel Kabali","Alejandro Dorado-García","Suzanne Eckford","Cortney Price","Stephen Gikonyo","Denis K. Byarugaba","Mark A. Caudell"]', 'biosecurity', 'The poultry sector contributes significantly to Kenya''s food and economic security. This contribution is expected to rise dramatically with a growing population, urbanization, and preferences for animal-source foods. Antimicrobial resistance is putting the poultry sector in Kenya-and worldwide-at risk of production losses due to the failure of medicines for animal (and human) health. The emergence and spread of antimicrobial resistance has been linked to overuse and misuse of antimicrobials in poultry and other sectors. Previous studies have documented poultry farmer antimicrobial use but without systematic consideration of the contexts (i.e., drivers) as important targets for behavior change, particularly in low- and middle-income countries. To improve understanding of antimicrobial use patterns in poultry systems, we conducted a mixed-methods knowledge, attitudes, and practices study of 76 layer farms in Kiambu County; Kenya. We found that commonly used antibiotics were often labeled for prophylactic, growth promotion, and egg production improvement purposes. Antimicrobial use was also motivated by the presence of diseases/disease symptoms, most of which could instead be managed through infection prevention measures. The results suggest that improving vaccination and biosecurity practices on farms and engaging with drug-makers to ensure proper labeling and marketing of antimicrobial drugs may represent important areas of opportunity for social behavior change communication and/or behavioral science interventions (i.e., nudges) to reduce disease burdens and promote prudent antimicrobial use. We conclude our findings with suggestions for further research into the behavioral insights at play in these scenarios to fuel future intervention development.', '2026-07-07 21:55:31');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3194359460', 'biosecurity', 'Antibiotic Usage and Resistance in Food Animal Production: What Have We Learned from Bangladesh?', 'Irrational and inappropriate use of antibiotics in commercial chicken and aquaculture industries can accelerate the antibiotic resistance process in humans and animals. In Bangladesh, the growing…', '2021', 2021, 67, 67, 'https://pub.mdpi-res.com/antibiotics/antibiotics-10-01032/article_deploy/html/images/antibiotics-10-01032-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8467341', 'pmc', 'review', 'Antibiotics', '["Sukanta Chowdhury","Sumon Ghosh","Mohammad Abdul Aleem","Shahana Parveen","Md. Ariful Islam","Md. Mahbubur Rashid","Zubair Akhtar","Fahmida Chowdhury"]', 'biosecurity', 'Irrational and inappropriate use of antibiotics in commercial chicken and aquaculture industries can accelerate the antibiotic resistance process in humans and animals. In Bangladesh, the growing commercial chicken and aquaculture industries are playing significantly important roles in the food value chain. It is necessary to know the antibiotic usage practices and antibiotic resistance in food animal production to design rational policies, guidelines, and interventions. We conducted a narrative review to understand the level of antibiotic usage and resistance in food animal production in Bangladesh. Information about antibiotic usage in different food animal production systems, including commercial chickens and aquaculture in Bangladesh is inadequate. Only a few small-scale studies reported that the majority (up to 100%) of the broiler and layer chicken farms used antibiotics for treating and preventing diseases. However, numerous studies reported antibiotic-resistant bacteria of public health importance in commercial chicken, fish, livestock, and animal origin food. The isolates from different pathogenic bacteria were found resistant against multiple antibiotics, including quinolones, the third or fourth generation of cephalosporins, and polymyxins. Veterinary practitioners empirically treat animals with antibiotics based on presumptive diagnosis due to inadequate microbial diagnostic facilities in Bangladesh. Intensive training is helpful to raise awareness among farmers, feed dealers, and drug sellers on good farming practices, standard biosecurity practices, personal hygiene, and the prudent use of antibiotics. Urgently, the Government of Bangladesh should develop and implement necessary guidelines to mitigate irrational use of antibiotics in food animals using a multi-sectoral One Health approach.', '2026-07-07 21:55:32');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2804854320', 'microbiome', 'Keystone taxa as drivers of microbiome structure and functioning', 'Keystone taxa as drivers of microbiome structure and functioning', '2018', 2018, 2966, 2966, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1038/s41579-018-0024-1.g001', 'https://pubmed.ncbi.nlm.nih.gov/29789680', 'repository', 'review', 'Nature Reviews Microbiology', '["Samiran Banerjee","Klaus Schlaeppi","Marcel G. A. van der Heijden"]', 'microbiome', NULL, '2026-07-07 21:55:54');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2605052214', 'microbiome', 'Influence of diet on the gut microbiome and implications for human health', 'Recent studies have suggested that the intestinal microbiome plays an important role in modulating risk of several chronic diseases, including inflammatory bowel disease, obesity, type 2 diabetes,…', '2017', 2017, 2606, 2606, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1038%2Fs41579-019-0256-8/MediaObjects/41579_2019_256_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5385025', 'pmc', 'review', 'Journal of Translational Medicine', '["Rasnik Singh","Hsin-Wen Chang","Di Yan","Kristina M. Lee","Derya Uçmak","Kirsten Wong","Michael Abrouk","Benjamin Farahnik","Mio Nakamura","Tian Hao Zhu","Tina Bhutani","Wilson Liao"]', 'microbiome', 'Recent studies have suggested that the intestinal microbiome plays an important role in modulating risk of several chronic diseases, including inflammatory bowel disease, obesity, type 2 diabetes, cardiovascular disease, and cancer. At the same time, it is now understood that diet plays a significant role in shaping the microbiome, with experiments showing that dietary alterations can induce large, temporary microbial shifts within 24 h. Given this association, there may be significant therapeutic utility in altering microbial composition through diet. This review systematically evaluates current data regarding the effects of several common dietary components on intestinal microbiota. We show that consumption of particular types of food produces predictable shifts in existing host bacterial genera. Furthermore, the identity of these bacteria affects host immune and metabolic parameters, with broad implications for human health. Familiarity with these associations will be of tremendous use to the practitioner as well as the patient.', '2026-07-07 21:55:57');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3159504416', 'microbiome', 'Integrating taxonomic, functional, and strain-level profiling of diverse microbial communities with bioBakery 3', 'Culture-independent analyses of microbial communities have progressed dramatically in the last decade, particularly due to advances in methods for biological profiling via shotgun metagenomics.…', '2021', 2021, 2293, 2293, 'https://cdn.elifesciences.org/articles/65088/elife-65088-fig1-v1.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8096432', 'pmc', 'article', 'eLife', '["Francesco Beghini","Lauren J. McIver","Aitor Blanco‐Míguez","Léonard Dubois","Francesco Asnicar","Sagun Maharjan","Ana Mailyan","Paolo Manghi","Matthias Scholz","Andrew Maltez Thomas","Mireia Valles‐Colomer","George Weingart","Yancong Zhang","Moreno Zolfo","Curtis Huttenhower","Eric A. Franzosa","Nicola Segata"]', 'microbiome', 'Culture-independent analyses of microbial communities have progressed dramatically in the last decade, particularly due to advances in methods for biological profiling via shotgun metagenomics. Opportunities for improvement continue to accelerate, with greater access to multi-omics, microbial reference genomes, and strain-level diversity. To leverage these, we present bioBakery 3, a set of integrated, improved methods for taxonomic, strain-level, functional, and phylogenetic profiling of metagenomes newly developed to build on the largest set of reference sequences now available. Compared to current alternatives, MetaPhlAn 3 increases the accuracy of taxonomic profiling, and HUMAnN 3 improves that of functional potential and activity. These methods detected novel disease-microbiome links in applications to CRC (1262 metagenomes) and IBD (1635 metagenomes and 817 metatranscriptomes). Strain-level profiling of an additional 4077 metagenomes with StrainPhlAn 3 and PanPhlAn 3 unraveled the phylogenetic and functional structure of the common gut microbe Ruminococcus bromii, previously described by only 15 isolate genomes. With open-source implementations and cloud-deployable reproducible workflows, the bioBakery 3 platform can help researchers deepen the resolution, scale, and accuracy of multi-omic profiling for microbial community studies.', '2026-07-07 21:56:10');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2897037806', 'microbiome', 'The oral microbiota: dynamic communities and host interactions', 'The oral microbiota: dynamic communities and host interactions', '2018', 2018, 2141, 2141, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41579-018-0089-x/MediaObjects/41579_2018_89_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6278837', 'pmc', 'review', 'Nature Reviews Microbiology', '["Richard J. Lamont","Hyun Koo","George Hajishengallis"]', 'microbiome', NULL, '2026-07-07 21:56:12');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2887136521', 'microbiome', 'Structure and function of the global topsoil microbiome', 'Structure and function of the global topsoil microbiome', '2018', 2018, 2541, 2541, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-018-0386-6/MediaObjects/41586_2018_386_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/30069051', 'repository', 'article', 'Nature', '["Mohammad Bahram","Falk Hildebrand","Sofia K. Forslund","Jennifer Anderson","Nadejda A. Soudzilovskaia","Peter M. van Bodegom","Johan Bengtsson‐Palme","Sten Anslan","Luís Pedro Coelho","Helery Harend","Jaime Huerta‐Cepas","Marnix H. Medema","Mia R. Maltz","Sunil Mundra","Pål Axel Olsson","Mari Pent","Sergei Põlme","Shinichi Sunagawa","Martin Ryberg","Leho Tedersoo","Peer Bork"]', 'microbiome', NULL, '2026-07-07 21:56:13');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2465681871', 'microbiome', 'MEGAN Community Edition - Interactive Exploration and Analysis of Large-Scale Microbiome Sequencing Data', 'There is increasing interest in employing shotgun sequencing, rather than amplicon sequencing, to analyze microbiome samples. Typical projects may involve hundreds of samples and billions of…', '2016', 2016, 1856, 1856, 'https://journals.plos.org/ploscompbiol/article/figure/image?size=large&id=10.1371/journal.pcbi.1004957.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4915700', 'pmc', 'article', 'PLoS Computational Biology', '["Daniel H. Huson","Sina Beier","Isabell Flade","Anna Górska","Mohamed El-Hadidi","Suparna Mitra","Hans‐Joachim Ruscheweyh","Rewati Tappu"]', 'microbiome', 'There is increasing interest in employing shotgun sequencing, rather than amplicon sequencing, to analyze microbiome samples. Typical projects may involve hundreds of samples and billions of sequencing reads. The comparison of such samples against a protein reference database generates billions of alignments and the analysis of such data is computationally challenging. To address this, we have substantially rewritten and extended our widely-used microbiome analysis tool MEGAN so as to facilitate the interactive analysis of the taxonomic and functional content of very large microbiome datasets. Other new features include a functional classifier called InterPro2GO, gene-centric read assembly, principal coordinate analysis of taxonomy and function, and support for metadata. The new program is called MEGAN Community Edition (CE) and is open source. By integrating MEGAN CE with our high-throughput DNA-to-protein alignment tool DIAMOND and by providing a new program MeganServer that allows access to metagenome analysis files hosted on a server, we provide a straightforward, yet powerful and complete pipeline for the analysis of metagenome shotgun sequences. We illustrate how to perform a full-scale computational analysis of a metagenomic sequencing project, involving 12 samples and 800 million reads, in less than three days on a single server. All source code is available here: https://github.com/danielhuson/megan-ce.', '2026-07-07 21:56:36');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2484230073', 'microbiome', 'Diet-induced extinctions in the gut microbiota compound over generations', 'Diet-induced extinctions in the gut microbiota compound over generations', '2016', 2016, 1777, 1777, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature16504/MediaObjects/41586_2016_BFnature16504_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4850918', 'pmc', 'article', 'Nature', '["Erica D. Sonnenburg","Samuel A. Smits","Mikhail Tikhonov","Steven K. Higginbottom","Ned S. Wingreen","Justin L. Sonnenburg"]', 'microbiome', NULL, '2026-07-07 21:56:39');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2897611961', 'microbiome', 'Species-level functional profiling of metagenomes and metatranscriptomes', 'Functional profiles of microbial communities are typically generated using comprehensive metagenomic or metatranscriptomic sequence read searches, which are time-consuming, prone to spurious mapping,…', '2018', 2018, 1794, 1794, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41592-018-0176-y/MediaObjects/41592_2018_176_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6235447', 'pmc', 'article', 'Nature Methods', '["Eric A. Franzosa","Lauren J. McIver","Ali Rahnavard","Luke Thompson","Melanie Schirmer","George Weingart","Karen Schwarzberg Lipson","Rob Knight","J. Gregory Caporaso","Nicola Segata","Curtis Huttenhower"]', 'microbiome', 'Functional profiles of microbial communities are typically generated using comprehensive metagenomic or metatranscriptomic sequence read searches, which are time-consuming, prone to spurious mapping, and often limited to community-level quantification. We developed HUMAnN2, a tiered search strategy that enables fast, accurate, and species-resolved functional profiling of host-associated and environmental communities. HUMAnN2 identifies a community''s known species, aligns reads to their pangenomes, performs translated search on unclassified reads, and finally quantifies gene families and pathways. Relative to pure translated search, HUMAnN2 is faster and produces more accurate gene family profiles. We applied HUMAnN2 to study clinal variation in marine metabolism, ecological contribution patterns among human microbiome pathways, variation in species'' genomic versus transcriptional contributions, and strain profiling. Further, we introduce ''contributional diversity'' to explain patterns of ecological assembly across different microbial community types.', '2026-07-07 21:56:39');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3121407008', 'microbiome', 'Large-scale association analyses identify host factors influencing human gut microbiome composition', 'Large-scale association analyses identify host factors influencing human gut microbiome composition', '2021', 2021, 1845, 1845, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41588-020-00763-1/MediaObjects/41588_2020_763_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/33462485', 'repository', 'article', 'Nature Genetics', '["Alexander Kurilshikov","Carolina Medina‐Gómez","Rodrigo Bacigalupe","Djawad Radjabzadeh","Jun Wang","Ayşe Demirkan","Caroline Le Roy","Juan A. Raygoza Garay","Casey T. Finnicum","Xingrong Liu","Daria V. Zhernakova","Marc Jan Bonder","Tue H. Hansen","Fabian Frost","Malte Rühlemann","Williams Turpin","Jee‐Young Moon","Han‐Na Kim","Kreete Lüll","Elad Barkan","Shiraz A. Shah","Myriam Fornage","Joanna Szopinska-Tokov","Zachary D. Wallen","Dmitrii Borisevich","Lars Agréus","Anna Andréasson","Corinna Bang","Larbi Bedrani","Jordana T. Bell","Hans Bisgaard","Michael Boehnke","Dorret I. Boomsma","Robert D. Burk","Annique Claringbould","Kenneth Croitoru","Gareth E. Davies","Cornelia M. van Duijn","Liesbeth Duijts","Gwen Falony","Jingyuan Fu","Adriaan van der Graaf","Torben Hansen","Georg Homuth","David A. Hughes","Richard G. IJzerman","Matthew Jackson","Vincent W. V. Jaddoe","Marie Joossens","Torben Jørgensen","Dániel Keszthelyi","Rob Knight","Markku Laakso","Matthias Laudes","Lenore J. Launer","Wolfgang Lieb","Aldons J. Lusis","Ad Masclee","Henriëtte A. Moll","Zlatan Mujagic","Qibin Qi","Daphna Rothschild","Hocheol Shin","Søren J. Sørensen","Claire J. Steves","Jonathan Thorsen","Nicholas J. Timpson","Raúl Y. Tito","Sara Vieira‐Silva","Uwe Völker","Henry Völzke","Urmo Võsa","Kaitlin H. Wade","Susanna Walter","Kyoko Watanabe","Stefan Weiß","Frank Ulrich Weiß","Omer Weissbrod","Harm-Jan Westra","Gonneke Willemsen","Haydeh Payami","Daisy Jonkers","Alejandro Arias Vásquez","Eco J. C. de Geus","Katie A. Meyer","Jakob Stokholm","Eran Segal","Elin Org","Cisca Wijmenga","Hyung‐Lae Kim","Robert C. Kaplan","Tim D. Spector","André G. Uitterlinden","Fernando Rivadeneira","André Franke","Markus M. Lerch","Lude Franke","Serena Sanna","Mauro D’Amato","Oluf Pedersen"]', 'microbiome', NULL, '2026-07-07 21:56:42');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2981774387', 'microbiome', 'Fungal-bacterial diversity and microbiome complexity predict ecosystem functioning', 'The soil microbiome is highly diverse and comprises up to one quarter of Earth''s diversity. Yet, how such a diverse and functionally complex microbiome influences ecosystem functioning remains…', '2019', 2019, 1798, 1798, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41467-019-12798-y/MediaObjects/41467_2019_12798_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6813331', 'pmc', 'article', 'Nature Communications', '["Cameron Wagg","Klaus Schlaeppi","Samiran Banerjee","Eiko E. Kuramae","Marcel G. A. van der Heijden"]', 'microbiome', 'The soil microbiome is highly diverse and comprises up to one quarter of Earth''s diversity. Yet, how such a diverse and functionally complex microbiome influences ecosystem functioning remains unclear. Here we manipulated the soil microbiome in experimental grassland ecosystems and observed that microbiome diversity and microbial network complexity positively influenced multiple ecosystem functions related to nutrient cycling (e.g. multifunctionality). Grassland microcosms with poorly developed microbial networks and reduced microbial richness had the lowest multifunctionality due to fewer taxa present that support the same function (redundancy) and lower diversity of taxa that support different functions (reduced functional uniqueness). Moreover, different microbial taxa explained different ecosystem functions pointing to the significance of functional diversity in microbial communities. These findings indicate the importance of microbial interactions within and among fungal and bacterial communities for enhancing ecosystem performance and demonstrate that the extinction of complex ecological associations belowground can impair ecosystem functioning.', '2026-07-07 21:56:42');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2736839127', 'microbiome', 'Gut microbiota and IBD: causation or correlation?', 'Gut microbiota and IBD: causation or correlation?', '2017', 2017, 1751, 1751, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnrgastro.2017.88/MediaObjects/41575_2017_Article_BFnrgastro201788_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5880536', 'pmc', 'review', 'Nature Reviews Gastroenterology & Hepatology', '["Josephine Ni","Gary D. Wu","Lindsey Albenberg","Vesselin T. Tomov"]', 'microbiome', NULL, '2026-07-07 21:56:43');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1842963151', 'microbiome', 'Rumen microbial community composition varies with diet and host, but a core microbiome is found across a wide geographical range', 'Ruminant livestock are important sources of human food and global greenhouse gas emissions. Feed degradation and methane formation by ruminants rely on metabolic interactions between rumen microbes…', '2015', 2015, 1740, 1740, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fsrep14567/MediaObjects/41598_2015_Article_BFsrep14567_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4598811', 'pmc', 'article', 'Scientific Reports', '["Gemma Henderson","Faith Cox","Siva Ganesh","Arjan Jonker","Wayne Young","Global Rumen Census Collaborators","Leticia Abecia","Erika Angarita","Paula Aravena","Graciela Nora Arenas","Claudia Ariza","Graeme T. Attwood","Jose Mauricio Avila","Jorge Ávila–Stagno","A. Bannink","Rolando Barahona Rosales","Mariano Batistotti","Mads F. Bertelsen","Aya Brown-Kav","A. Carvajal","Laura Cersosimo","Alex V. Chaves","John S. Church","Nicholas Clipson","Mario A. Cobos-Peralta","Adrian L. Cookson","Silvio Cravero","Omar Cristobal-Carballo","Katie Crosley","G. D. Cruz","María Esperanza Cerón‐Cucchi","Rodrigo de la Barra","Alexandre B. de Menezes","Edênio Detmann","K. Dieho","J. Dijkstra","William Lima Santiago dos Reis","M. E. R. Dugan","Seyed Hadi Ebrahimi","Emma Eythórsdóttir","Fabian Nde Fon","Martín Fraga","Francisco Franco","Chris Friedeman","Naoki Fukuma","Dragana Gagić","Isabelle D.M. Gangnat","Diego Grilli","Le Luo Guan","Vahideh Heidarian Miri","Emma Hernandez‐Sanabria","Alma Ximena Ibarra Gomez","O. A. Isah","Suzanne L. Ishaq","Elie Jami","Juan Jelincic","Juha Kantanen","William J. Kelly","Seon‐Ho Kim","Athol V. Klieve","Yasuo Kobayashi","Satoshi Koike","J Kopečný","Torsten Nygaard Kristensen","S.J. Krizsan","Hannah Lachance","Medora Lachman","W. R. Lamberson","Suzanne C. Lambie","Jan Lassen","Sinead C. Leahy","Sang-Suk Lee","Florian Leiber","E. Lewis","Bo Lin","Raúl Lira","Peter Lund","Edgar Macipe","Lovelia L. Mamuad","Hilário Cuquetto Mantovani","Gisela Marcoppido","Cristian Márquez","Cécile Martin","G. Martı́nez","María Eugenia Martínez","Olga Lucía Mayorga","Tim A. McAllister","Christopher S. McSweeney","Lorena Mestre","Elena Minnée","Makoto Mitsumori","Itzhak Mizrahi","Isabel Molina","A. Muenger","Camila Muñoz","Boštjan Murovec","J.R. Newbold","Victor Nsereko","M. O’Donovan","Sunday Adewale Okunade"]', 'microbiome', 'Ruminant livestock are important sources of human food and global greenhouse gas emissions. Feed degradation and methane formation by ruminants rely on metabolic interactions between rumen microbes and affect ruminant productivity. Rumen and camelid foregut microbial community composition was determined in 742 samples from 32 animal species and 35 countries, to estimate if this was influenced by diet, host species, or geography. Similar bacteria and archaea dominated in nearly all samples, while protozoal communities were more variable. The dominant bacteria are poorly characterised, but the methanogenic archaea are better known and highly conserved across the world. This universality and limited diversity could make it possible to mitigate methane emissions by developing strategies that target the few dominant methanogens. Differences in microbial community compositions were predominantly attributable to diet, with the host being less influential. There were few strong co-occurrence patterns between microbes, suggesting that major metabolic interactions are non-selective rather than specific.', '2026-07-07 21:56:43');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2978355872', 'microbiome', 'Soil microbiomes and climate change', 'Soil microbiomes and climate change', '2019', 2019, 1620, 1620, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41579-019-0265-7/MediaObjects/41579_2019_265_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/31586158', 'repository', 'review', 'Nature Reviews Microbiology', '["Janet Jansson","Kirsten Hofmockel"]', 'microbiome', NULL, '2026-07-07 21:56:57');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4241986295', 'plant-biology', 'Supine versus prone position in percutaneous nephrolithotomy: a systematic review and meta-analysis', 'Background: The decision for using supine or prone position in percutaneous nephrolithotomy (PCNL) is still debatable. The aim of this study is to compare the efficacy and safety profile of the…', '2020', 2020, 28, 28, 'https://f1000research-files.f1000.com/manuscripts/25326/9dd4e877-f7ea-4ab7-a13d-202962ac2290_figure1.gif', 'https://doi.org/10.12688/f1000research.22940.1', 'repository', 'review', 'F1000Research', '["Ponco Birowo","William Tendi","Indah Suci Widyahening","Nur Rasyid","Widi Atmoko"]', 'plant biology', 'Background: The decision for using supine or prone position in percutaneous nephrolithotomy (PCNL) is still debatable. The aim of this study is to compare the efficacy and safety profile of the supine and prone position when performing PCNL. Methods: A systematic electronic search was performed using the database from MEDLINE, Cochrane library and Google Scholar from January 2009 to November 2019. The outcomes assessed were stone free rate, major complication rate, length of hospital stay and mean operation time. Results: A total of 11 articles were included in qualitative and quantitative analysis. The efficacy of PCNL in supine position as determined by stone free rate is significantly lower than in prone position (OR: 0.74; 95% CI: 0.66 – 0.83; p&lt;0.00001), However, major complication rate is also lower in the supine group compared with the prone group (OR: 0.70; 95% CI: 0.51 – 0.96; p=0.03). There is no statistically significant difference in the length of hospital stay and mean operation time between both groups. Conclusion: Prone position leads to a higher stone free rate, but also a higher rate of major complication. Thus, the decision of using which position during PCNL should be based on the surgeon’s experience and clinical aspects of the patients.', '2026-07-07 21:57:19');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2281227836', 'microbiome', 'Microbial Hub Taxa Link Host and Abiotic Factors to Plant Microbiome Variation', 'Plant-associated microorganisms have been shown to critically affect host physiology and performance, suggesting that evolution and ecology of plants and animals can only be understood in a holobiont…', '2016', 2016, 1442, 1442, 'https://journals.plos.org/plosbiology/article/figure/image?size=large&id=10.1371/journal.pbio.1002352.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4720289', 'pmc', 'article', 'PLoS Biology', '["Matthew T. Agler","Jonas Ruhe","Samuel Kroll","Constanze Morhenn","Sang‐Tae Kim","Detlef Weigel","Eric Kemen"]', 'microbiome', 'Plant-associated microorganisms have been shown to critically affect host physiology and performance, suggesting that evolution and ecology of plants and animals can only be understood in a holobiont (host and its associated organisms) context. Host-associated microbial community structures are affected by abiotic and host factors, and increased attention is given to the role of the microbiome in interactions such as pathogen inhibition. However, little is known about how these factors act on the microbial community, and especially what role microbe-microbe interaction dynamics play. We have begun to address this knowledge gap for phyllosphere microbiomes of plants by simultaneously studying three major groups of Arabidopsis thaliana symbionts (bacteria, fungi and oomycetes) using a systems biology approach. We evaluated multiple potential factors of microbial community control: we sampled various wild A. thaliana populations at different times, performed field plantings with different host genotypes, and implemented successive host colonization experiments under lab conditions where abiotic factors, host genotype, and pathogen colonization was manipulated. Our results indicate that both abiotic factors and host genotype interact to affect plant colonization by all three groups of microbes. Considering microbe-microbe interactions, however, uncovered a network of interkingdom interactions with significant contributions to community structure. As in other scale-free networks, a small number of taxa, which we call microbial "hubs," are strongly interconnected and have a severe effect on communities. By documenting these microbe-microbe interactions, we uncover an important mechanism explaining how abiotic factors and host genotypic signatures control microbial communities. In short, they act directly on "hub" microbes, which, via microbe-microbe interactions, transmit the effects to the microbial community. We analyzed two "hub" microbes (the obligate biotrophic oomycete pathogen Albugo and the basidiomycete yeast fungus Dioszegia) more closely. Albugo had strong effects on epiphytic and endophytic bacterial colonization. Specifically, alpha diversity decreased and beta diversity stabilized in the presence of Albugo infection, whereas they otherwise varied between plants. Dioszegia, on the other hand, provided evidence for direct hub interaction with phyllosphere bacteria. The identification of microbial "hubs" and their importance in phyllosphere microbiome structuring has crucial implications for plant-pathogen and microbe-microbe research and opens new entry points for ecosystem management and future targeted biocontrol. The revelation that effects can cascade through communities via "hub" microbes is important to understand community structure perturbations in parallel fields including human microbiomes and bioprocesses. In particular, parallels to human microbiome "keystone" pathogens and microbes open new avenues of interdisciplinary research that promise to better our understanding of functions of host-associated microbiomes.', '2026-07-07 21:57:23');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3015020049', 'microbiome', 'SCFA: mechanisms and functional importance in the gut', 'In recent years, the importance of the gut microbiota in human health has been revealed and many publications have highlighted its role as a key component of human physiology. Owing to the use of…', '2020', 2020, 1449, 1449, 'https://static.cambridge.org/binary/version/id/urn:cambridge.org:id:binary:20210310031709329-0420:S0029665120006916:S0029665120006916_fig1.png', 'https://agroparistech.hal.science/hal-02536149', 'repository', 'review', 'Proceedings of The Nutrition Society', '["Camille Martin‐Gallausiaux","Ludovica Marinelli","Hervé M. Blottière","Pierre Larraufie","Nicolas Lapaque"]', 'microbiome', 'In recent years, the importance of the gut microbiota in human health has been revealed and many publications have highlighted its role as a key component of human physiology. Owing to the use of modern sequencing approaches, the characterisation of the microbiome in healthy individuals and in disease has demonstrated a disturbance of the microbiota, or dysbiosis, associated with pathological conditions. The microbiota establishes a symbiotic crosstalk with their host: commensal microbes benefit from the nutrient-rich environment provided by the gut and the microbiota produces hundreds of proteins and metabolites that modulate key functions of the host, including nutrient processing, maintenance of energy homoeostasis and immune system development. Many bacteria-derived metabolites originate from dietary sources. Among them, an important role has been attributed to the metabolites derived from the bacterial fermentation of dietary fibres, namely SCFA linking host nutrition to intestinal homoeostasis maintenance. SCFA are important fuels for intestinal epithelial cells (IEC) and regulate IEC functions through different mechanisms to modulate their proliferation, differentiation as well as functions of subpopulations such as enteroendocrine cells, to impact gut motility and to strengthen the gut barrier functions as well as host metabolism. Recent findings show that SCFA, and in particular butyrate, also have important intestinal and immuno-modulatory functions. In this review, we discuss the mechanisms and the impact of SCFA on gut functions and host immunity and consequently on human health.', '2026-07-07 21:57:28');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2896269751', 'microbiome', 'An insight into gut microbiota and its functionalities', 'An insight into gut microbiota and its functionalities', '2018', 2018, 1449, 1449, 'https://cdn.ncbi.nlm.nih.gov/pmc/blobs/04d1/11105460/50c7e8d841a8/18_2018_2943_Fig1_HTML.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/11105460', 'pmc', 'review', 'Cellular and Molecular Life Sciences', '["Atanu Adak","Mojibur R. Khan"]', 'microbiome', NULL, '2026-07-07 21:57:31');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4237478702', 'plant-biology', 'The challenges of designing a benchmark strategy for bioinformatics pipelines in the identification of antimicrobial resistance determinants using next generation sequencing technologies', 'Next-Generation Sequencing (NGS) technologies are expected to play a crucial role in the surveillance of infectious diseases, with their unprecedented capabilities for the characterisation of genetic…', '2018', 2018, 28, 28, 'https://f1000research-files.f1000.com/manuscripts/15794/5912ef1d-798f-4e39-ac48-fcfabeab4853_figure1.gif', 'https://doi.org/10.12688/f1000research.14509.1', 'repository', 'preprint', 'F1000Research', '["Alexandre Angers‐Loustau","Mauro Petrillo","Johan Bengtsson‐Palme","Thomas U. Berendonk","Burton W. Blais","Kok‐Gan Chan","Teresa M. Coque","Paul Hammer","Stefanie Heß","Dafni Maria Kagkli","Carsten Krumbiegel","Val F. Lanza","Jean-Yves Madec","Thierry Naas","Justin O’Grady","Valentina Paracchini","John W. A. Rossen","Étienne Ruppé","Jessica Vamathevan","Vittorio Venturi","Guy Van den Eede"]', 'plant biology', 'Next-Generation Sequencing (NGS) technologies are expected to play a crucial role in the surveillance of infectious diseases, with their unprecedented capabilities for the characterisation of genetic information underlying the virulence and antimicrobial resistance (AMR) properties of microorganisms. In the implementation of any novel technology for regulatory purposes, important considerations such as harmonisation, validation and quality assurance need to be addressed. NGS technologies pose unique challenges in these regards, in part due to their reliance on bioinformatics for the processing and proper interpretation of the data produced. Well-designed benchmark resources are thus needed to evaluate, validate and ensure continued quality control over the bioinformatics component of the process. This concept was explored as part of a workshop on "Next-generation sequencing technologies and antimicrobial resistance" held October 4-5 2017. Challenges involved in the development of such a benchmark resource, with a specific focus on identifying the molecular determinants of AMR, were identified. For each of the challenges, sets of unsolved questions that will need to be tackled for them to be properly addressed were compiled. These take into consideration the requirement for monitoring of AMR bacteria in humans, animals, food and the environment, which is aligned with the principles of a “One Health” approach.', '2026-07-07 21:57:50');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2345813655', 'microbiome', 'Culturing of ‘unculturable’ human microbiota reveals novel taxa and extensive sporulation', 'Our intestinal microbiota harbours a diverse bacterial community required for our health, sustenance and wellbeing. Intestinal colonization begins at birth and climaxes with the acquisition of two…', '2016', 2016, 1333, 1333, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature17645/MediaObjects/41586_2016_BFnature17645_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4890681', 'pmc', 'article', 'Nature', '["Hilary P. Browne","Samuel C. Forster","Blessing O. Anonye","Nitin Kumar","Bridget A. Neville","Mark Stares","David Goulding","Trevor D. Lawley"]', 'microbiome', 'Our intestinal microbiota harbours a diverse bacterial community required for our health, sustenance and wellbeing. Intestinal colonization begins at birth and climaxes with the acquisition of two dominant groups of strict anaerobic bacteria belonging to the Firmicutes and Bacteroidetes phyla. Culture-independent, genomic approaches have transformed our understanding of the role of the human microbiome in health and many diseases. However, owing to the prevailing perception that our indigenous bacteria are largely recalcitrant to culture, many of their functions and phenotypes remain unknown. Here we describe a novel workflow based on targeted phenotypic culturing linked to large-scale whole-genome sequencing, phylogenetic analysis and computational modelling that demonstrates that a substantial proportion of the intestinal bacteria are culturable. Applying this approach to healthy individuals, we isolated 137 bacterial species from characterized and candidate novel families, genera and species that were archived as pure cultures. Whole-genome and metagenomic sequencing, combined with computational and phenotypic analysis, suggests that at least 50-60% of the bacterial genera from the intestinal microbiota of a healthy individual produce resilient spores, specialized for host-to-host transmission. Our approach unlocks the human intestinal microbiota for phenotypic analysis and reveals how a marked proportion of oxygen-sensitive intestinal bacteria can be transmitted between individuals, affecting microbiota heritability.', '2026-07-07 21:58:01');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2461853012', 'microbiome', 'Alterations of the human gut microbiome in multiple sclerosis', 'The gut microbiome plays an important role in immune function and has been implicated in several autoimmune disorders. Here we use 16S rRNA sequencing to investigate the gut microbiome in subjects…', '2016', 2016, 1309, 1309, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fncomms12015/MediaObjects/41467_2016_Article_BFncomms12015_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4931233', 'pmc', 'article', 'Nature Communications', '["Sushrut Jangi","Roopali Gandhi","Laura M. Cox","Ning Li","Felipe von Glehn","Raymond Yan","Bonny Patel","Maria Antonietta Mazzola","Shirong Liu","Bonnie Glanz","Sandra Cook","Stephanie Tankou","Fiona Stuart","Kirsy Melo","Parham Nejad","Kathleen M. Smith","Begüm D. Topçuolu","James F. Holden","Pia Kivisäkk","Tanuja Chitnis","Philip L. De Jager","Francisco J. Quintana","Georg K. Gerber","Lynn Bry","Howard L. Weiner"]', 'microbiome', 'The gut microbiome plays an important role in immune function and has been implicated in several autoimmune disorders. Here we use 16S rRNA sequencing to investigate the gut microbiome in subjects with multiple sclerosis (MS, n=60) and healthy controls (n=43). Microbiome alterations in MS include increases in Methanobrevibacter and Akkermansia and decreases in Butyricimonas, and correlate with variations in the expression of genes involved in dendritic cell maturation, interferon signalling and NF-kB signalling pathways in circulating T cells and monocytes. Patients on disease-modifying treatment show increased abundances of Prevotella and Sutterella, and decreased Sarcina, compared with untreated patients. MS patients of a second cohort show elevated breath methane compared with controls, consistent with our observation of increased gut Methanobrevibacter in MS in the first cohort. Further study is required to assess whether the observed alterations in the gut microbiome play a role in, or are a consequence of, MS pathogenesis.', '2026-07-07 21:58:01');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2775152143', 'microbiome', 'Enterotypes in the landscape of gut microbial community composition', 'Enterotypes in the landscape of gut microbial community composition', '2017', 2017, 1230, 1230, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41564-017-0072-8/MediaObjects/41564_2017_72_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5832044', 'pmc', 'review', 'Nature Microbiology', '["Paul Igor Costea","Falk Hildebrand","Manimozhiyan Arumugam","Fredrik Bäckhed","Martin J. Blaser","Frederic D. Bushman","Willem M. de Vos","S. Dusko Ehrlich","Claire M. Fraser","Masahira Hattori","Curtis Huttenhower","Ian B. Jeffery","Dan Knights","James D. Lewis","Ruth E. Ley","Howard Ochman","Paul W. O’Toole","Christopher Quince","David A. Relman","Fergus Shanahan","Shinichi Sunagawa","Jun Wang","George M. Weinstock","Gary D. Wu","Georg Zeller","Liping Zhao","Jeroen Raes","Rob Knight","Peer Bork"]', 'microbiome', NULL, '2026-07-07 21:58:26');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2901539283', 'plant-biology', 'Head models of healthy and depressed adults for simulating the electric fields of non-invasive electric brain stimulation', 'During the past decade, it became clear that the electric field elicited by non-invasive brain stimulation (NIBS) techniques such as transcranial direct current stimulation (tDCS) and transcranial…', '2018', 2018, 27, 27, 'https://f1000research-files.f1000.com/manuscripts/18435/e690bf13-f0b0-47a4-95bb-f43337e87c4f_figure1.gif', 'http://api.osf.io/v2/nodes/exbd5/', 'repository', 'preprint', 'F1000Research', '["Nya Mehnwolo Boayue","Gábor Csifcsák","Oula Puonti","Axel Thielscher","Matthias Mittner"]', 'plant biology', 'During the past decade, it became clear that the electric field elicited by non-invasive brain stimulation (NIBS) techniques such as transcranial direct current stimulation (tDCS) and transcranial magnetic stimulation (TMS) are substantially influenced by variations in individual head and brain anatomy. In addition to structural variations in the healthy, several psychiatric disorders are characterized by anatomical alterations that are likely to further constrain the intracerebral effects of NIBS. Here, we present high-resolution realistic head models derived from structural magnetic resonance imaging data of 19 healthy adults and 19 patients diagnosed with major depressive disorder (MDD). By using a freely available software package for modelling the electric fields induced by different NIBS protocols, we show that our head models are well-suited for assessing inter-individual and between-group variability in the magnitude and focality of tDCS-induced electric fields for two protocols targeting the left dorsolateral prefrontal cortex.', '2026-07-07 21:58:54');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2915216906', 'plant-biology', 'Contextual Hub Analysis Tool (CHAT): A Cytoscape app for identifying contextually relevant hubs in biological networks', 'Highly connected nodes (hubs) in biological networks are topologically important to the structure of the network and have also been shown to be preferentially associated with a range of phenotypes of…', '2016', 2016, 27, 27, 'https://f1000research-files.f1000.com/manuscripts/9812/38c2e095-c966-4630-a3de-7c77d792699c_figure1.gif', 'https://doi.org/10.12688/f1000research.9118.1', 'repository', 'preprint', 'F1000Research', '["Tanja Muetze","Ivan H. Goenawan","Heather L. Wiencko","Manuel Bernal Llinares","Kenneth Bryan","David J. Lynn"]', 'plant biology', 'Highly connected nodes (hubs) in biological networks are topologically important to the structure of the network and have also been shown to be preferentially associated with a range of phenotypes of interest. The relative importance of a hub node, however, can change depending on the biological context. Here, we report a Cytoscape app, the Contextual Hub Analysis Tool (CHAT), which enables users to easily construct and visualize a network of interactions from a gene list of interest, integrate contextual information, such as gene expression data, and identify hub nodes that are more highly connected to contextual nodes (e.g. genes that are differentially expressed) than expected by chance. In a case study, we use CHAT to construct a network of genes that are differentially expressed in Dengue fever, a viral infection. CHAT was used to identify and compare contextual and degree-based hubs in this network. The top 20 degree-based hubs were enriched in pathways related to the cell cycle and cancer, which is likely due to the fact that proteins involved in these processes tend to be highly connected in general. In comparison, the top 20 contextual hubs were enriched in pathways commonly observed in a viral infection including pathways related to the immune response to viral infection. This analysis shows that such contextual hubs are considerably more biologically relevant than degree-based hubs and that analyses which rely on the identification of hubs solely based on their connectivity may be biased towards nodes that are highly connected in general rather than in the specific context of interest. Availability: CHAT is available for Cytoscape 3.0+ and can be installed via the Cytoscape App Store (http://apps.cytoscape.org/apps/chat).', '2026-07-07 21:58:57');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2905301720', 'microbiome', 'Diet-Independent Correlations between Bacteria and Dysfunction of Gut, Adipose Tissue, and Liver: A Comprehensive Microbiota Analysis in Feces and Mucosa of the Ileum and Colon in Obese Mice with NAFLD', 'Development of non-alcoholic fatty liver disease (NAFLD) is linked to obesity, adipose tissue inflammation, and gut dysfunction, all of which depend on diet. So far, studies have mainly focused on…', '2018', 2018, 1100, 1100, 'https://pub.mdpi-res.com/ijms/ijms-20-00001/article_deploy/html/images/ijms-20-00001-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6337295', 'pmc', 'article', 'International Journal of Molecular Sciences', '["Eveline Gart","Everton Souto Lima","Frank Schuren","Christa G. F. De Ruiter","Joline Attema","Lars Verschuren","Jaap Keijer","Kanita Salic","Martine C. Morrison","Robert Kleemann"]', 'microbiome', 'Development of non-alcoholic fatty liver disease (NAFLD) is linked to obesity, adipose tissue inflammation, and gut dysfunction, all of which depend on diet. So far, studies have mainly focused on diet-related fecal microbiota changes, but other compartments may be more informative on host health. We present a first systematic analysis of microbiota changes in the ileum and colon using multiple diets and investigating both fecal and mucosal samples. Ldlr−/−.Leiden mice received one of three different energy-dense (ED)-diets (n = 15/group) for 15 weeks. All of the ED diets induced obesity and metabolic risk factors, altered short-chain fatty acids (SCFA), and increased gut permeability and NAFLD to various extents. ED diets reduced the diversity of high-abundant bacteria and increased the diversity of low-abundant bacteria in all of the gut compartments. The ED groups showed highly variable, partially overlapping microbiota compositions that differed significantly from chow. Correlation analyses demonstrated that (1) specific groups of bacteria correlate with metabolic risk factors, organ dysfunction, and NAFLD endpoints, (2) colon mucosa had greater predictive value than other compartments, (3) correlating bacteria differed per compartment, and (4) some bacteria correlated with plasma SCFA levels. In conclusion, this comprehensive microbiota analysis demonstrates correlations between the microbiota and dysfunctions of gut, adipose tissue, and liver, independent of a specific disease-inducing diet.', '2026-07-07 21:59:08');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2741026700', 'microbiome', 'BlobTools: Interrogation of genome assemblies', 'The goal of many genome sequencing projects is to provide a complete representation of a target genome (or genomes) as underpinning data for further analyses. However, it can be problematic to…', '2017', 2017, 1073, 1073, 'https://f1000research-files.f1000.com/manuscripts/13242/6b29a936-0de0-41ca-a338-334eb4aeb423_figure1.gif', 'https://doi.org/10.12688/f1000research.12232.1', 'repository', 'preprint', 'F1000Research', '["Dominik R. Laetsch","Mark Blaxter"]', 'microbiome', 'The goal of many genome sequencing projects is to provide a complete representation of a target genome (or genomes) as underpinning data for further analyses. However, it can be problematic to identify which sequences in an assembly truly derive from the target genome(s) and which are derived from associated microbiome or contaminant organisms. We present BlobTools, a modular command-line solution for visualisation, quality control and taxonomic partitioning of genome datasets. Using guanine+cytosine content of sequences, read coverage in sequencing libraries and taxonomy of sequence similarity matches, BlobTools can assist in primary partitioning of data, leading to improved assemblies, and screening of final assemblies for potential contaminants. Through simulated paired-end read dataset,s containing a mixture of metazoan and bacterial taxa, we illustrate the main BlobTools workflow and suggest useful parameters for taxonomic partitioning of low-complexity metagenome assemblies.', '2026-07-07 21:59:16');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2568352511', 'microbiome', 'The Microbiome-Gut-Brain Axis in Health and Disease', 'The Microbiome-Gut-Brain Axis in Health and Disease', '2017', 2017, 1085, 1085, 'https://ars.els-cdn.com/content/image/1-s2.0-S0889855316300826-gr1.jpg', 'https://pubmed.ncbi.nlm.nih.gov/28164854', 'repository', 'review', 'Gastroenterology Clinics of North America', '["Timothy G. Dinan","John F. Cryan"]', 'microbiome', NULL, '2026-07-07 21:59:20');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2771045365', 'microbiome', 'Meta-analysis of gut microbiome studies identifies disease-specific and shared responses', 'Hundreds of clinical studies have demonstrated associations between the human microbiome and disease, yet fundamental questions remain on how we can generalize this knowledge. Results from individual…', '2017', 2017, 1032, 1032, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41467-017-01973-8/MediaObjects/41467_2017_1973_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5716994', 'pmc', 'review', 'Nature Communications', '["Claire Duvallet","Sean M. Gibbons","Thomas Gurry","Rafael A. Irizarry","Eric J. Alm"]', 'microbiome', 'Hundreds of clinical studies have demonstrated associations between the human microbiome and disease, yet fundamental questions remain on how we can generalize this knowledge. Results from individual studies can be inconsistent, and comparing published data is further complicated by a lack of standard processing and analysis methods. Here we introduce the MicrobiomeHD database, which includes 28 published case-control gut microbiome studies spanning ten diseases. We perform a cross-disease meta-analysis of these studies using standardized methods. We find consistent patterns characterizing disease-associated microbiome changes. Some diseases are associated with over 50 genera, while most show only 10-15 genus-level changes. Some diseases are marked by the presence of potentially pathogenic microbes, whereas others are characterized by a depletion of health-associated bacteria. Furthermore, we show that about half of genera associated with individual studies are bacteria that respond to more than one disease. Thus, many associations found in case-control studies are likely not disease-specific but rather part of a non-specific, shared response to health and disease.', '2026-07-07 21:59:33');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3010810358', 'microbiome', 'RETRACTED ARTICLE: Microbiome analyses of blood and tissues suggest cancerdiagnostic approach', 'RETRACTED ARTICLE: Microbiome analyses of blood and tissues suggest cancerdiagnostic approach', '2020', 2020, 1044, 1044, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-020-2095-1/MediaObjects/41586_2020_2095_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7500457', 'pmc', 'article', 'Nature', '["Gregory Poore","Evguenia Kopylova","Qiyun Zhu","Carolina S. Carpenter","Serena Fraraccio","Stephen Wandro","Tomasz Kościółek","Stefan Janssen","Jessica L. Metcalf","Se Jin Song","Jad Kanbar","Sandrine Miller‐Montgomery","Robert K. Heaton","Rana R. McKay","Sandip Pravin Patel","Austin D. Swafford","Rob Knight"]', 'microbiome', NULL, '2026-07-07 21:59:33');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2947640277', 'microbiome', 'The vaginal microbiome and preterm birth', 'The incidence of preterm birth exceeds 10% worldwide. There are significant disparities in the frequency of preterm birth among populations within countries, and women of African ancestry…', '2019', 2019, 1036, 1036, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41591-019-0450-2/MediaObjects/41591_2019_450_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6750801', 'pmc', 'article', 'Nature Medicine', '["Jennifer M. Fettweis","Myrna G. Serrano","J. Paul Brooks","David Edwards","Philippe H. Girerd","Hardik I. Parikh","Bernice Huang","Tom Arodz","Laahirie Edupuganti","Abigail Glascock","Jie Xu","Nicole R. Jimenez","Stephany C. Vivadelli","Stephen S. Fong","Nihar U. Sheth","Sophonie Jean","Vladimir Lee","Yahya Bokhari","Ana M. Lara","Shreni Mistry","Robert A. Duckworth","Steven Bradley","Vishal N. Kopardé","X. Valentine Orenda","Sarah H. Milton","Sarah K. Rozycki","Andrey Matveyev","Michelle L. Wright","Snehalata Huzurbazar","Eugenie M. Jackson","Ekaterina Smirnova","Jonas Korlach","Yu‐Chih Tsai","Molly R. Dickinson","Jamie L. Brooks","Jennifer I. Drake","Donald O. Chaffin","Amber L. Sexton","Michael G. Gravett","Craig E. Rubens","N. Romesh Wijesooriya","Karen D. Hendricks‐Muñoz","Kimberly K. Jefferson","Jerome F. Strauss","Gregory A. Buck"]', 'microbiome', 'The incidence of preterm birth exceeds 10% worldwide. There are significant disparities in the frequency of preterm birth among populations within countries, and women of African ancestry disproportionately bear the burden of risk in the United States. In the present study, we report a community resource that includes ''omics'' data from approximately 12,000 samples as part of the integrative Human Microbiome Project. Longitudinal analyses of 16S ribosomal RNA, metagenomic, metatranscriptomic and cytokine profiles from 45 preterm and 90 term birth controls identified harbingers of preterm birth in this cohort of women predominantly of African ancestry. Women who delivered preterm exhibited significantly lower vaginal levels of Lactobacillus crispatus and higher levels of BVAB1, Sneathia amnii, TM7-H1, a group of Prevotella species and nine additional taxa. The first representative genomes of BVAB1 and TM7-H1 are described. Preterm-birth-associated taxa were correlated with proinflammatory cytokines in vaginal fluid. These findings highlight new opportunities for assessment of the risk of preterm birth.', '2026-07-07 21:59:33');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3009231580', 'microbiome', 'Gut microbiota and human NAFLD: disentangling microbial signatures from metabolic disorders', 'Gut microbiota and human NAFLD: disentangling microbial signatures from metabolic disorders', '2020', 2020, 1046, 1046, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41575-020-0269-9/MediaObjects/41575_2020_269_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/32152478', 'repository', 'review', 'Nature Reviews Gastroenterology & Hepatology', '["Judith Aron‐Wisnewsky","Chloé Vigliotti","Julia J. Witjes","Phuong Thi Le","Adriaan G. Holleboom","Joanne Verheij","Max Nieuwdorp","Karine Clément"]', 'microbiome', NULL, '2026-07-07 21:59:33');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2464547619', 'microbiome', 'Host genotype and age shape the leaf and root microbiomes of a wild perennial plant', 'Bacteria living on and in leaves and roots influence many aspects of plant health, so the extent of a plant''s genetic control over its microbiota is of great interest to crop breeders and…', '2016', 2016, 1046, 1046, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fncomms12151/MediaObjects/41467_2016_Article_BFncomms12151_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4945892', 'pmc', 'article', 'Nature Communications', '["Maggie R. Wagner","Derek S. Lundberg","Tijana Glavina del Rio","Susannah G. Tringe","Jeffery L. Dangl","Thomas Mitchell‐Olds"]', 'microbiome', 'Bacteria living on and in leaves and roots influence many aspects of plant health, so the extent of a plant''s genetic control over its microbiota is of great interest to crop breeders and evolutionary biologists. Laboratory-based studies, because they poorly simulate true environmental heterogeneity, may misestimate or totally miss the influence of certain host genes on the microbiome. Here we report a large-scale field experiment to disentangle the effects of genotype, environment, age and year of harvest on bacterial communities associated with leaves and roots of Boechera stricta (Brassicaceae), a perennial wild mustard. Host genetic control of the microbiome is evident in leaves but not roots, and varies substantially among sites. Microbiome composition also shifts as plants age. Furthermore, a large proportion of leaf bacterial groups are shared with roots, suggesting inoculation from soil. Our results demonstrate how genotype-by-environment interactions contribute to the complexity of microbiome assembly in natural environments.', '2026-07-07 21:59:34');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2371807656', 'microbiome', 'Gut Microbiota and Extreme Longevity', 'Gut Microbiota and Extreme Longevity', '2016', 2016, 1012, 1012, 'https://ars.els-cdn.com/content/image/1-s2.0-S0960982216303384-fx1.jpg', 'https://pubmed.ncbi.nlm.nih.gov/27185560', 'repository', 'article', 'Current Biology', '["Elena Biagi","Claudio Franceschi","Simone Rampelli","Marco Severgnini","Rita Ostan","Silvia Turroni","Clarissa Consolandi","Sara Quercia","Maria Scurti","Daniela Monti","Miriam Capri","Patrizia Brigidi","Marco Candela"]', 'microbiome', NULL, '2026-07-07 21:59:44');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4313552967', 'plant-biology', 'Artificial intelligence based glaucoma and diabetic retinopathy detection using MATLAB — retrained AlexNet convolutional neural network', 'Background: Glaucoma and diabetic retinopathy are the leading causes of blindness due to an irreversible damage to the retina which results in vision loss. Early detection of these diseases through…', '2023', 2023, 27, 27, 'https://f1000research-files.f1000.com/manuscripts/134260/c79105f2-8c9c-411b-9141-ad308c45c778_figure1.gif', 'https://doi.org/10.12688/f1000research.122288.1', 'repository', 'preprint', 'F1000Research', '["Isaac Arias-Serrano","Paolo A. Velásquez-López","Laura N. Avila-Briones","Fanny C. Laurido-Mora","Fernando Villalba-Meneses","Andrés Tirado-Espín","Jonathan Cruz-Varela","Diego Almeida-Galárraga"]', 'plant biology', 'Background: Glaucoma and diabetic retinopathy are the leading causes of blindness due to an irreversible damage to the retina which results in vision loss. Early detection of these diseases through regular screening is especially important to prevent progression. The image of retinal fundus is the main evaluating strategy for the glaucoma and diabetic retinopathy detection. Then, automated eye disease detection is an important application of retinal image analysis. Compared with classical diagnostic techniques, image classification by convolutional neural networks (CNN) have the potential for better cost-effective performance. Methods: In this paper, we propose the use of MATLAB – retrained AlexNet CNN for computerized eye diseases identification, particularly glaucoma and diabetic retinopathy, by employing retinal fundus images. The acquisition of the database was carried out through free access databases and access upon request. A transfer learning technique is used for retraining the AlexNet CNN. Specifically, the model divides the fundus image dataset into training and testing data. Results: As datasets were added by network training, different values were reported for validation accuracy, false positives and false negatives, precision, and recall. Thus, having NetTransfer I with a validation accuracy value of 94.3% for two classes. NetTransfer II with a validation accuracy value of 91.8% for two classes. NetTransfer III with a validation accuracy value of 89.7% for three classes. Net transfer IV with a validation accuracy value of 93.1% for three classes. Finally, NetTransfer V with a validation accuracy value of 92.1% for three classes. Conclusions: Re-training of the AlexNet network proved to be a powerful tool to create disease detection systems having high accuracy values and being able to discern between more than two diseases.', '2026-07-07 21:59:48');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2596895947', 'microbiome', 'Root microbiota drive direct integration of phosphate stress and immunity', 'Root microbiota drive direct integration of phosphate stress and immunity', '2017', 2017, 983, 983, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature21417/MediaObjects/41586_2017_Article_BFnature21417_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5364063', 'pmc', 'article', 'Nature', '["Gabriel Castrillo","Paulo José Pereira Lima Teixeira","Sur Herrera Paredes","Theresa F. Law","Laura de Lorenzo","Meghan E. Feltcher","Omri M. Finkel","Natalie W. Breakfield","Piotr A. Mieczkowski","Corbin D. Jones","Javier Paz‐Ares","Jeffery L. Dangl"]', 'microbiome', NULL, '2026-07-07 21:59:57');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3104596207', 'microbiome', 'A genomic catalog of Earth’s microbiomes', 'The reconstruction of bacterial and archaeal genomes from shotgun metagenomes has enabled insights into the ecology and evolution of environmental and host-associated microbiomes. Here we applied…', '2020', 2020, 977, 977, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41587-020-0718-6/MediaObjects/41587_2020_718_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/33169036', 'repository', 'article', 'Nature Biotechnology', '["Stephen Nayfach","Simon Roux","R. Seshadri","Daniel Udwary","Neha Varghese","Frederik Schulz","Dongying Wu","David Páez-Espino","I-Min A. Chen","Marcel Huntemann","Krishna Palaniappan","Joshua Ladau","Supratim Mukherjee","T. B. K. Reddy","Torben Nielsen","Edward Kirton","José P. Faria","Janaka N. Edirisinghe","Christopher S. Henry","Sean P. Jungbluth","Dylan Chivian","Paramvir Dehal","Elisha M. Wood‐Charlson","Adam P. Arkin","Susannah G. Tringe","Axel Visel","Helena Abreu","Silvia G. Acinas","Eric Allen","Michelle A. Allen","Lauren V. Alteio","Gary L. Andersen","Alexandre M. B. Anesio","Graeme T. Attwood","Viridiana Avila‐Magaña","Yacine Badis","Jake V. Bailey","Brett J. Baker","Petr Baldrián","Hazel A. Barton","David A. C. Beck","Eric D. Becraft","Harry R. Beller","J. Michael Beman","Rizlan Bernier‐Latmani","Timothy D. Berry","Anthony D. Bertagnolli","Stefan Bertilsson","Jennifer Bhatnagar","Jordan T. Bird","Jeffrey L. Blanchard","Sara E. Blumer‐Schuette","Brendan J. M. Bohannan","Mikayla A. Borton","Allyson Brady","Susan H. Brawley","Juliet Brodie","Steven D. Brown","Jennifer R. Brum","Andreas Brune","Donald A. Bryant","Alison Buchan","Daniel H. Buckley","Joy Buongiorno","Hinsby Cadillo‐Quiroz","Sean M. Caffrey","Ashley Campbell","Barbara J. Campbell","Stephanie Carr","JoLynn Carroll","S. Craig Cary","Anna M. Cates","Rose Ann Cattolico","Ricardo Cavicchioli","Ludmila Chistoserdova","Maureen L. Coleman","Philippe Constant","Jonathan M. Conway","Walter P. Mac Cormack","Sean A. Crowe","Byron C. Crump","Cameron R. Currie","Rebecca Daly","Kristen M. DeAngelis","Vincent J. Denef","Stuart E. Denman","Adey Feleke Desta","Hebe M. Dionisi","Jeremy A. Dodsworth","Nina Dombrowski","Timothy J. Donohue","Mark Dopson","Timothy Driscoll","Peter F. Dunfield","Christopher L. Dupont","Katherine A. Dynarski","Virginia P. Edgcomb","Elizabeth A. Edwards","Mostafa S. Elshahed","Israel Figueroa"]', 'microbiome', 'The reconstruction of bacterial and archaeal genomes from shotgun metagenomes has enabled insights into the ecology and evolution of environmental and host-associated microbiomes. Here we applied this approach to >10,000 metagenomes collected from diverse habitats covering all of Earth''s continents and oceans, including metagenomes from human and animal hosts, engineered environments, and natural and agricultural soils, to capture extant microbial, metabolic and functional potential. This comprehensive catalog includes 52,515 metagenome-assembled genomes representing 12,556 novel candidate species-level operational taxonomic units spanning 135 phyla. The catalog expands the known phylogenetic diversity of bacteria and archaea by 44% and is broadly available for streamlined comparative analyses, interactive exploration, metabolic modeling and bulk download. We demonstrate the utility of this collection for understanding secondary-metabolite biosynthetic potential and for resolving thousands of new host linkages to uncultivated viruses. This resource underscores the value of genome-centric approaches for revealing genomic properties of uncultivated microorganisms that affect ecosystem processes.', '2026-07-07 21:59:57');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2955323986', 'microbiome', 'Microbial genes and pathways in inflammatory bowel disease', 'Microbial genes and pathways in inflammatory bowel disease', '2019', 2019, 997, 997, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41579-019-0213-6/MediaObjects/41579_2019_213_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6759048', 'pmc', 'review', 'Nature Reviews Microbiology', '["Melanie Schirmer","Ashley Garner","Hera Vlamakis","Ramnik J. Xavier"]', 'microbiome', NULL, '2026-07-07 21:59:57');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3118724893', 'microbiome', 'Microbiome connections with host metabolism and habitual diet from 1,098 deeply phenotyped individuals', 'Microbiome connections with host metabolism and habitual diet from 1,098 deeply phenotyped individuals', '2021', 2021, 997, 997, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41591-020-01183-8/MediaObjects/41591_2020_1183_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8353542', 'pmc', 'article', 'Nature Medicine', '["Francesco Asnicar","Sarah Berry","Ana M. Valdes","Long H. Nguyen","Gianmarco Piccinno","David A. Drew","Emily R. Leeming","Rachel Gibson","Caroline Le Roy","Haya Al Khatib","Lucy Francis","Mohsen Mazidi","Olatz Mompeó","Mireia Valles‐Colomer","Adrian Tett","Francesco Beghini","Léonard Dubois","Davide Bazzani","Andrew Maltez Thomas","Chloe Mirzayi","Asya Khleborodova","Sehyun Oh","Rachel Hine","Christopher Bonnett","Joan Capdevila Pujol","Serge Danzanvilliers","Francesca Giordano","Ludwig Geistlinger","Levi Waldron","Richard Davies","George Hadjigeorgiou","Jonathan Wolf","José M. Ordovás","Christopher D. Gardner","Paul W. Franks","Andrew T. Chan","Curtis Huttenhower","Tim D. Spector","Nicola Segata"]', 'microbiome', NULL, '2026-07-07 21:59:58');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2997490540', 'microbiome', 'Microbial bile acid metabolites modulate gut RORγ+ regulatory T cell homeostasis', 'Microbial bile acid metabolites modulate gut RORγ+ regulatory T cell homeostasis', '2019', 2019, 992, 992, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-019-1865-0/MediaObjects/41586_2019_1865_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7274525', 'pmc', 'article', 'Nature', '["Xinyang Song","Ximei Sun","Sungwhan F. Oh","Meng–Huang Wu","Yanbo Zhang","Wenfeng Zheng","Naama Geva‐Zatorsky","Ray Jupp","Diane Mathis","Christophe Benoıst","Dennis L. Kasper"]', 'microbiome', NULL, '2026-07-07 21:59:58');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4392783067', 'microbiome', 'Microbiota–gut–brain axis and its therapeutic applications in neurodegenerative diseases', 'The human gastrointestinal tract is populated with a diverse microbial community. The vast genetic and metabolic potential of the gut microbiome underpins its ubiquity in nearly every aspect of human…', '2024', 2024, 981, 981, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41392-024-01743-1/MediaObjects/41392_2024_1743_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/10869798', 'pmc', 'review', 'Signal Transduction and Targeted Therapy', '["Jian Sheng Loh","Wen Qi Mak","Li Tan","Chu Xin Ng","Hong Hao Chan","Shiau Hueh Yeow","Jhi Biau Foo","Yong Sze Ong","Chee Wun How","Kooi Yeong Khaw"]', 'microbiome', 'The human gastrointestinal tract is populated with a diverse microbial community. The vast genetic and metabolic potential of the gut microbiome underpins its ubiquity in nearly every aspect of human biology, including health maintenance, development, aging, and disease. The advent of new sequencing technologies and culture-independent methods has allowed researchers to move beyond correlative studies toward mechanistic explorations to shed light on microbiome-host interactions. Evidence has unveiled the bidirectional communication between the gut microbiome and the central nervous system, referred to as the "microbiota-gut-brain axis". The microbiota-gut-brain axis represents an important regulator of glial functions, making it an actionable target to ameliorate the development and progression of neurodegenerative diseases. In this review, we discuss the mechanisms of the microbiota-gut-brain axis in neurodegenerative diseases. As the gut microbiome provides essential cues to microglia, astrocytes, and oligodendrocytes, we examine the communications between gut microbiota and these glial cells during healthy states and neurodegenerative diseases. Subsequently, we discuss the mechanisms of the microbiota-gut-brain axis in neurodegenerative diseases using a metabolite-centric approach, while also examining the role of gut microbiota-related neurotransmitters and gut hormones. Next, we examine the potential of targeting the intestinal barrier, blood-brain barrier, meninges, and peripheral immune system to counteract glial dysfunction in neurodegeneration. Finally, we conclude by assessing the pre-clinical and clinical evidence of probiotics, prebiotics, and fecal microbiota transplantation in neurodegenerative diseases. A thorough comprehension of the microbiota-gut-brain axis will foster the development of effective therapeutic interventions for the management of neurodegenerative diseases.', '2026-07-07 22:00:01');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2461582275', 'microbiome', 'Multiple sclerosis patients have a distinct gut microbiota compared to healthy controls', 'Multiple sclerosis (MS) is an immune-mediated disease, the etiology of which involves both genetic and environmental factors. The exact nature of the environmental factors responsible for…', '2016', 2016, 973, 973, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fsrep28484/MediaObjects/41598_2016_Article_BFsrep28484_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4921909', 'pmc', 'article', 'Scientific Reports', '["Jun Chen","Nicholas Chia","Krishna R. Kalari","Janet Yao","Martina Novotná","M. Mateo Paz Soldán","David Luckey","Eric Marietta","Patricio Jeraldo","Xianfeng Chen","Brian G. Weinshenker","Moses Rodriguez","Orhun H. Kantarci","Heidi Nelson","Joseph A. Murray","Ashutosh K. Mangalam"]', 'microbiome', 'Multiple sclerosis (MS) is an immune-mediated disease, the etiology of which involves both genetic and environmental factors. The exact nature of the environmental factors responsible for predisposition to MS remains elusive; however, it''s hypothesized that gastrointestinal microbiota might play an important role in pathogenesis of MS. Therefore, this study was designed to investigate whether gut microbiota are altered in MS by comparing the fecal microbiota in relapsing remitting MS (RRMS) (n = 31) patients to that of age- and gender-matched healthy controls (n = 36). Phylotype profiles of the gut microbial populations were generated using hypervariable tag sequencing of the V3-V5 region of the 16S ribosomal RNA gene. Detailed fecal microbiome analyses revealed that MS patients had distinct microbial community profile compared to healthy controls. We observed an increased abundance of Psuedomonas, Mycoplana, Haemophilus, Blautia, and Dorea genera in MS patients, whereas control group showed increased abundance of Parabacteroides, Adlercreutzia and Prevotella genera. Thus our study is consistent with the hypothesis that MS patients have gut microbial dysbiosis and further study is needed to better understand their role in the etiopathogenesis of MS.', '2026-07-07 22:00:11');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2340717842', 'microbiome', 'From gut dysbiosis to altered brain function and mental illness: mechanisms and pathways', 'The human body hosts an enormous abundance and diversity of microbes, which perform a range of essential and beneficial functions. Our appreciation of the importance of these microbial communities to…', '2016', 2016, 963, 963, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fmp.2016.50/MediaObjects/41380_2016_Article_BFmp201650_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4879184', 'pmc', 'review', 'Molecular Psychiatry', '["Geraint B. Rogers","Damien J. Keating","Richard L. Young","Ma‐Li Wong","Júlio Licinio","Steve Wesselingh"]', 'microbiome', 'The human body hosts an enormous abundance and diversity of microbes, which perform a range of essential and beneficial functions. Our appreciation of the importance of these microbial communities to many aspects of human physiology has grown dramatically in recent years. We know, for example, that animals raised in a germ-free environment exhibit substantially altered immune and metabolic function, while the disruption of commensal microbiota in humans is associated with the development of a growing number of diseases. Evidence is now emerging that, through interactions with the gut-brain axis, the bidirectional communication system between the central nervous system and the gastrointestinal tract, the gut microbiome can also influence neural development, cognition and behaviour, with recent evidence that changes in behaviour alter gut microbiota composition, while modifications of the microbiome can induce depressive-like behaviours. Although an association between enteropathy and certain psychiatric conditions has long been recognized, it now appears that gut microbes represent direct mediators of psychopathology. Here, we examine roles of gut microbiome in shaping brain development and neurological function, and the mechanisms by which it can contribute to mental illness. Further, we discuss how the insight provided by this new and exciting field of research can inform care and provide a basis for the design of novel, microbiota-targeted, therapies.', '2026-07-07 22:00:12');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2275606382', 'microbiome', 'Intestinal microbiome analyses identify melanoma patients at risk for checkpoint-blockade-induced colitis', 'The composition of the intestinal microbiota influences the development of inflammatory disorders. However, associating inflammatory diseases with specific microbial members of the microbiota is…', '2016', 2016, 964, 964, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fncomms10391/MediaObjects/41467_2016_Article_BFncomms10391_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4740747', 'pmc', 'article', 'Nature Communications', '["Krista Dubin","Margaret K. Callahan","Boyu Ren","Raya Khanin","Agnès Viale","Lilan Ling","Daniel J. No","Asia Gobourne","Eric R. Littmann","Curtis Huttenhower","Eric G. Pamer","Jedd D. Wolchok"]', 'microbiome', 'The composition of the intestinal microbiota influences the development of inflammatory disorders. However, associating inflammatory diseases with specific microbial members of the microbiota is challenging, because clinically detectable inflammation and its treatment can alter the microbiota''s composition. Immunologic checkpoint blockade with ipilimumab, a monoclonal antibody that blocks cytotoxic T-lymphocyte-associated antigen-4 (CTLA-4) signalling, is associated with new-onset, immune-mediated colitis. Here we conduct a prospective study of patients with metastatic melanoma undergoing ipilimumab treatment and correlate the pre-inflammation faecal microbiota and microbiome composition with subsequent colitis development. We demonstrate that increased representation of bacteria belonging to the Bacteroidetes phylum is correlated with resistance to the development of checkpoint-blockade-induced colitis. Furthermore, a paucity of genetic pathways involved in polyamine transport and B vitamin biosynthesis is associated with an increased risk of colitis. Identification of these biomarkers may enable interventions to reduce the risk of inflammatory complications following cancer immunotherapy.', '2026-07-07 22:00:12');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2763540102', 'microbiome', 'Towards standards for human fecal sample processing in metagenomic studies', 'Towards standards for human fecal sample processing in metagenomic studies', '2017', 2017, 907, 907, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnbt.3960/MediaObjects/41587_2017_Article_BFnbt3960_Fig1_HTML.jpg', 'https://cea.hal.science/cea-02073086', 'repository', 'article', 'Nature Biotechnology', '["Paul Igor Costea","Georg Zeller","Shinichi Sunagawa","Éric Pelletier","Adriana Alberti","Florence Levenez","Melanie Tramontano","Marja Driessen","Rajna Hercog","Ferris Jung","Jens Roat Kultima","Matthew R. Hayward","Luís Pedro Coelho","Emma Allen‐Vercoe","Laurie Bertrand","Michaël Blaut","Jillian R. Brown","Thomas Carton","Stéphanie Cools-Portier","Michelle C. Daigneault","Muriel Derrien","Anne Druesne","Willem M. de Vos","B. Brett Finlay","Harry J. Flint","Francisco Guarner","Masahira Hattori","Hans G. H. J. Heilig","Ruth Ann Luna","Johan van Hylckama Vlieg","Jana Junick","Ingeborg Klymiuk","Philippe Langella","Emmanuelle Le Chatelier","Volker Mai","Chaysavanh Manichanh","Jennifer C. Martin","Clémentine Mery","Hidetoshi Morita","Paul W. O’Toole","Céline Orvain","Kiran Raosaheb Patil","John Penders","Søren Persson","Nicolas Pons","Milena Popova","Anne Salonen","Delphine Saulnier","Karen P. Scott","Bhagirath Singh","Kathleen Slezak","Patrick Veiga","James Versalovic","Liping Zhao","Erwin G. Zoetendal","S. Dusko Ehrlich","Joël Doré","Peer Bork"]', 'microbiome', NULL, '2026-07-07 22:00:27');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2896617742', 'microbiome', 'The human gut microbiome in early-onset type 1 diabetes from the TEDDY study', 'Type 1 diabetes (T1D) is an autoimmune disease that targets pancreatic islet beta cells and incorporates genetic and environmental factors1, including complex genetic elements2, patient exposures3…', '2018', 2018, 902, 902, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-018-0620-2/MediaObjects/41586_2018_620_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6296767', 'pmc', 'article', 'Nature', '["Tommi Vatanen","Eric A. Franzosa","Randall Schwager","Surya Tripathi","Timothy D. Arthur","Kendra Vehik","Åke Lernmark","William Hagopian","Marian Rewers","Jin‐Xiong She","Jorma Toppari","Anette‐G. Ziegler","Beena Akolkar","Jeffrey P. Krischer","Christopher J. Stewart","Nadim J. Ajami","Joseph F. Petrosino","Dirk Gevers","Harri Lähdesmäki","Hera Vlamakis","Curtis Huttenhower","Ramnik J. Xavier"]', 'microbiome', 'Type 1 diabetes (T1D) is an autoimmune disease that targets pancreatic islet beta cells and incorporates genetic and environmental factors1, including complex genetic elements2, patient exposures3 and the gut microbiome4. Viral infections5 and broader gut dysbioses6 have been identified as potential causes or contributing factors; however, human studies have not yet identified microbial compositional or functional triggers that are predictive of islet autoimmunity or T1D. Here we analyse 10,913 metagenomes in stool samples from 783 mostly white, non-Hispanic children. The samples were collected monthly from three months of age until the clinical end point (islet autoimmunity or T1D) in the The Environmental Determinants of Diabetes in the Young (TEDDY) study, to characterize the natural history of the early gut microbiome in connection to islet autoimmunity, T1D diagnosis, and other common early life events such as antibiotic treatments and probiotics. The microbiomes of control children contained more genes that were related to fermentation and the biosynthesis of short-chain fatty acids, but these were not consistently associated with particular taxa across geographically diverse clinical centres, suggesting that microbial factors associated with T1D are taxonomically diffuse but functionally more coherent. When we investigated the broader establishment and development of the infant microbiome, both taxonomic and functional profiles were dynamic and highly individualized, and dominated in the first year of life by one of three largely exclusive Bifidobacterium species (B. bifidum, B. breve or B. longum) or by the phylum Proteobacteria. In particular, the strain-specific carriage of genes for the utilization of human milk oligosaccharide within a subset of B. longum was present specifically in breast-fed infants. These analyses of TEDDY gut metagenomes provide, to our knowledge, the largest and most detailed longitudinal functional profile of the developing gut microbiome in relation to islet autoimmunity, T1D and other early childhood events. Together with existing evidence from human cohorts7,8 and a T1D mouse model9, these data support the protective effects of short-chain fatty acids in early-onset human T1D. An analysis of more than 10,000 metagenomes from the TEDDY study provides a detailed functional profile of the gut microbiome in relation to islet autoimmunity, and supports the protective effects of short-chain fatty acids in early-onset type 1 diabetes.', '2026-07-07 22:00:44');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3187959711', 'microbiome', 'An omics-based framework for assessing the health risk of antimicrobial resistance genes', 'Antibiotic resistance genes (ARGs) are widespread among bacteria. However, not all ARGs pose serious threats to public health, highlighting the importance of identifying those that are high-risk.…', '2021', 2021, 870, 870, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41467-021-25096-3/MediaObjects/41467_2021_25096_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8346589', 'pmc', 'article', 'Nature Communications', '["Anni Zhang","Jeffry M. Gaston","Chengzhen L. Dai","Shijie Zhao","Mathilde Poyet","Mathieu Groussin","Xiaole Yin","Li-Guan Li","Mark C.M. van Loosdrecht","Edward Topp","Michael R. Gillings","William P. Hanage","James M. Tiedje","Katya Moniz","Eric J. Alm","Tong Zhang"]', 'microbiome', 'Antibiotic resistance genes (ARGs) are widespread among bacteria. However, not all ARGs pose serious threats to public health, highlighting the importance of identifying those that are high-risk. Here, we developed an ''omics-based'' framework to evaluate ARG risk considering human-associated-enrichment, gene mobility, and host pathogenicity. Our framework classifies human-associated, mobile ARGs (3.6% of all ARGs) as the highest risk, which we further differentiate as ''current threats'' (Rank I; 3%) - already present among pathogens - and ''future threats'' (Rank II; 0.6%) - novel resistance emerging from non-pathogens. Our framework identified 73 ''current threat'' ARG families. Of these, 35 were among the 37 high-risk ARGs proposed by the World Health Organization and other literature; the remaining 38 were significantly enriched in hospital plasmids. By evaluating all pathogen genomes released since framework construction, we confirmed that ARGs that recently transferred into pathogens were significantly enriched in Rank II (''future threats''). Lastly, we applied the framework to gut microbiome genomes from fecal microbiota transplantation donors. We found that although ARGs were widespread (73% of genomes), only 8.9% of genomes contained high-risk ARGs. Our framework provides an easy-to-implement approach to identify current and future antimicrobial resistance threats, with potential clinical applications including reducing risk of microbiome-based interventions.', '2026-07-07 22:00:58');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2559597060', 'microbiome', 'Generation of genome-scale metabolic reconstructions for 773 members of the human gut microbiota', 'Generation of genome-scale metabolic reconstructions for 773 members of the human gut microbiota', '2016', 2016, 876, 876, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnbt.3703/MediaObjects/41587_2017_Article_BFnbt3703_Fig1_HTML.jpg', 'https://pubmed.ncbi.nlm.nih.gov/27893703', 'repository', 'article', 'Nature Biotechnology', '["Stefanía Magnúsdóttir","Almut Heinken","Laura Kutt","Dmitry A. Ravcheev","Eugen Bauer","Alberto Noronha","Kacy Greenhalgh","Christian Jäger","Joanna Bagińska","Paul Wilmes","Ronan M. T. Fleming","Ines Thiele"]', 'microbiome', NULL, '2026-07-07 22:00:59');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2603930527', 'microbiome', 'Research priorities for harnessing plant microbiomes in sustainable agriculture', 'Feeding a growing world population amidst climate change requires optimizing the reliability, resource use, and environmental impacts of food production. One way to assist in achieving these goals is…', '2017', 2017, 862, 862, 'https://journals.plos.org/plosbiology/article/figure/image?size=large&id=10.1371/journal.pbio.2001793.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5370116', 'pmc', 'article', 'PLoS Biology', '["Posy E. Busby","Chinmay Soman","Maggie R. Wagner","Maren Friesen","James M. Kremer","Alison E. Bennett","Mustafa Morsy","Jonathan A. Eisen","Jan E. Leach","Jeffery L. Dangl"]', 'microbiome', 'Feeding a growing world population amidst climate change requires optimizing the reliability, resource use, and environmental impacts of food production. One way to assist in achieving these goals is to integrate beneficial plant microbiomes-i.e., those enhancing plant growth, nutrient use efficiency, abiotic stress tolerance, and disease resistance-into agricultural production. This integration will require a large-scale effort among academic researchers, industry researchers, and farmers to understand and manage plant-microbiome interactions in the context of modern agricultural systems. Here, we identify priorities for research in this area: (1) develop model host-microbiome systems for crop plants and non-crop plants with associated microbial culture collections and reference genomes, (2) define core microbiomes and metagenomes in these model systems, (3) elucidate the rules of synthetic, functionally programmable microbiome assembly, (4) determine functional mechanisms of plant-microbiome interactions, and (5) characterize and refine plant genotype-by-environment-by-microbiome-by-management interactions. Meeting these goals should accelerate our ability to design and implement effective agricultural microbiome manipulations and management strategies, which, in turn, will pay dividends for both the consumers and producers of the world food supply.', '2026-07-07 22:01:11');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2914769190', 'plant-biology', 'Recent advances in gene function prediction using context-specific coexpression networks in plants', 'Predicting gene functions from genome sequence alone has been difficult, and the functions of a large fraction of plant genes remain unknown. However, leveraging the vast amount of currently…', '2019', 2019, 26, 26, 'https://f1000research-files.f1000.com/manuscripts/18816/ecb913fc-4632-4dc2-b6d3-478b3d2691d4_figure1.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6364378', 'pmc', 'preprint', 'F1000Research', '["Chirag Gupta","Andy Pereira"]', 'plant biology', 'Predicting gene functions from genome sequence alone has been difficult, and the functions of a large fraction of plant genes remain unknown. However, leveraging the vast amount of currently available gene expression data has the potential to facilitate our understanding of plant gene functions, especially in determining complex traits. Gene coexpression networks-created by integrating multiple expression datasets-connect genes with similar patterns of expression across multiple conditions. Dense gene communities in such networks, commonly referred to as modules, often indicate that the member genes are functionally related. As such, these modules serve as tools for generating new testable hypotheses, including the prediction of gene function and importance. Recently, we have seen a paradigm shift from the traditional "global" to more defined, context-specific coexpression networks. Such coexpression networks imply genetic correlations in specific biological contexts such as during development or in response to a stress. In this short review, we highlight a few recent studies that attempt to fill the large gaps in our knowledge about cellular functions of plant genes using context-specific coexpression networks.', '2026-07-07 22:01:24');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2982359845', 'microbiome', 'The human gut bacteria Christensenellaceae are widespread, heritable, and associated with health', 'The Christensenellaceae, a recently described family in the phylum Firmicutes, is emerging as an important player in human health. The relative abundance of Christensenellaceae in the human gut is…', '2019', 2019, 838, 838, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs12915-019-0699-4/MediaObjects/12915_2019_699_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6819567', 'pmc', 'review', 'BMC Biology', '["Jillian L. Waters","Ruth E. Ley"]', 'microbiome', 'The Christensenellaceae, a recently described family in the phylum Firmicutes, is emerging as an important player in human health. The relative abundance of Christensenellaceae in the human gut is inversely related to host body mass index (BMI) in different populations and multiple studies, making its relationship with BMI the most robust and reproducible link between the microbial ecology of the human gut and metabolic disease reported to date. The family is also related to a healthy status in a number of other different disease contexts, including obesity and inflammatory bowel disease. In addition, Christensenellaceae is highly heritable across multiple populations, although specific human genes underlying its heritability have so far been elusive. Further research into the microbial ecology and metabolism of these bacteria should reveal mechanistic underpinnings of their host-health associations and enable their development as therapeutics.', '2026-07-07 22:01:30');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3087819424', 'plant-biology', 'Control of T lymphocyte fate decisions by PI3K signaling', 'Virtually all aspects of T and B lymphocyte development, homeostasis, activation, and effector function are impacted by the interaction of their clonally distributed antigen receptors with antigens…', '2020', 2020, 26, 26, 'https://f1000research-files.f1000.com/manuscripts/29743/b24a8fde-4598-45a4-9a3e-778237f1f85b_figure1.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7520711', 'pmc', 'preprint', 'F1000Research', '["Benjamin Murter","Larry Kane"]', 'plant biology', 'Virtually all aspects of T and B lymphocyte development, homeostasis, activation, and effector function are impacted by the interaction of their clonally distributed antigen receptors with antigens encountered in their respective environments. Antigen receptors mediate their effects by modulating intracellular signaling pathways that ultimately impinge on the cytoskeleton, bioenergetic pathways, transcription, and translation. Although these signaling pathways are rather well described at this point, especially those steps that are most receptor-proximal, how such pathways contribute to more quantitative aspects of lymphocyte function is still being elucidated. One of the signaling pathways that appears to be involved in this "tuning" process is controlled by the lipid kinase PI3K. Here we review recent key findings regarding both the triggering/enhancement of PI3K signals (via BCAP and ICOS) as well as their regulation (via PIK3IP1 and PHLPP) and how these signals integrate and determine cellular processes. Lymphocytes display tremendous functional plasticity, adjusting their metabolism and gene expression programs to specific conditions depending on their tissue of residence and the nature of the infectious threat to which they are responding. We give an overview of recent findings that have contributed to this model, with a focus on T cells, including what has been learned from patients with gain-of-function mutations in PI3K as well as lessons from cancer immunotherapy approaches.', '2026-07-07 22:01:38');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2921815890', 'microbiome', 'New insights from uncultivated genomes of the global human gut microbiome', 'The genome sequences of many species of the human gut microbiome remain unknown, largely owing to challenges in cultivating microorganisms under laboratory conditions. Here we address this problem by…', '2019', 2019, 829, 829, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-019-1058-x/MediaObjects/41586_2019_1058_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6784871', 'pmc', 'article', 'Nature', '["Stephen Nayfach","Zhou Jason Shi","R. Seshadri","Katherine S. Pollard","Nikos C. Kyrpides"]', 'microbiome', 'The genome sequences of many species of the human gut microbiome remain unknown, largely owing to challenges in cultivating microorganisms under laboratory conditions. Here we address this problem by reconstructing 60,664 draft prokaryotic genomes from 3,810 faecal metagenomes, from geographically and phenotypically diverse humans. These genomes provide reference points for 2,058 newly identified species-level operational taxonomic units (OTUs), which represents a 50% increase over the previously known phylogenetic diversity of sequenced gut bacteria. On average, the newly identified OTUs comprise 33% of richness and 28% of species abundance per individual, and are enriched in humans from rural populations. A meta-analysis of clinical gut-microbiome studies pinpointed numerous disease associations for the newly identified OTUs, which have the potential to improve predictive models. Finally, our analysis revealed that uncultured gut species have undergone genome reduction that has resulted in the loss of certain biosynthetic pathways, which may offer clues for improving cultivation strategies in the future. Draft prokaryotic genomes from faecal metagenomes of diverse human populations enrich our understanding of the human gut microbiome by identifying over two thousand new species-level taxa that have numerous disease associations.', '2026-07-07 22:01:41');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2944263569', 'microbiome', 'A complex human gut microbiome cultured in an anaerobic intestine-on-a-chip', 'A complex human gut microbiome cultured in an anaerobic intestine-on-a-chip', '2019', 2019, 811, 811, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41551-019-0397-0/MediaObjects/41551_2019_397_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6658209', 'pmc', 'article', 'Nature Biomedical Engineering', '["Sasan Jalili‐Firoozinezhad","Francesca S. Gazzaniga","Elizabeth Calamari","Diogo M. Camacho","Cicely W. Fadel","Amir Bein","Ben Swenor","Bret Nestor","Michael J. Cronce","Alessio Tovaglieri","Oren Levy","Katherine E. Gregory","David T. Breault","Joaquim M. S. Cabral","Dennis L. Kasper","Richard Novák","Donald E. Ingber"]', 'microbiome', NULL, '2026-07-07 22:01:41');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4240706514', 'plant-biology', 'Computational screening for potential drug candidates against the SARS-CoV-2 main protease', 'Background: SARS-CoV-2 is the causal agent of the current coronavirus disease 2019 (COVID-19) pandemic. They are enveloped, positive-sense, single-stranded RNA viruses of the Coronaviridae family.…', '2020', 2020, 26, 26, 'https://f1000research-files.f1000.com/manuscripts/26292/e0a15c80-d040-4873-9de4-85e8265b389c_figure1.gif', 'https://doi.org/10.12688/f1000research.23829.1', 'repository', 'preprint', 'F1000Research', '["Bruno Silva Andrade","Preetam Ghosh","Debmalya Barh","Sandeep Tiwari","Raner José Santana Silva","Wagner Rodrigues de Assis Soares","Tarcísio Silva Melo","Andria Santos Freitas","Patrícia González-Grande","Lucas Sousa Palmeira","Luiz Carlos Junior Alcantara","Marta Giovanetti","Aristóteles Goés‐Neto","Vasco Azevedo"]', 'plant biology', 'Background: SARS-CoV-2 is the causal agent of the current coronavirus disease 2019 (COVID-19) pandemic. They are enveloped, positive-sense, single-stranded RNA viruses of the Coronaviridae family. Proteases of SARS-CoV-2 are necessary for viral replication, structural assembly, and pathogenicity. The approximately 33.8 kDa M pro protease of SARS-CoV-2 is a non-human homologue and is highly conserved among several coronaviruses, indicating that M pro could be a potential drug target for Coronaviruses. Methods: Herein, we performed computational ligand screening of four pharmacophores (OEW, remdesivir, hydroxychloroquine and N3) that are presumed to have positive effects against SARS-CoV-2 M pro protease (6LU7), and also screened 50,000 natural compounds from the ZINC Database dataset against this protease target. Results: We found 40 pharmacophore-like structures of natural compounds from diverse chemical classes that exhibited better affinity of docking as compared to the known ligands. The 11 best selected ligands, namely ZINC1845382, ZINC1875405, ZINC2092396, ZINC2104424, ZINC44018332, ZINC2101723, ZINC2094526, ZINC2094304, ZINC2104482, ZINC3984030, and ZINC1531664, are mainly classified as beta-carboline, alkaloids, and polyflavonoids, and all displayed interactions with dyad CYS145 and HIS41 from the protease pocket in a similar way as other known ligands. Conclusions: Our results suggest that these 11 molecules could be effective against SARS-CoV-2 protease and may be subsequently tested in vitro and in vivo to develop novel drugs against this virus.', '2026-07-07 22:01:56');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2769664962', 'microbiome', 'A novel Ruminococcus gnavus clade enriched in inflammatory bowel disease patients', 'BACKGROUND: Inflammatory bowel disease (IBD) is characterized by chronic inflammation of the gastrointestinal tract that is associated with changes in the gut microbiome. Here, we sought to identify…', '2017', 2017, 787, 787, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1038%2Fs41579-019-0213-6/MediaObjects/41579_2019_213_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5704459', 'pmc', 'article', 'Genome Medicine', '["A. Brantley Hall","Moran Yassour","Jenny Sauk","Ashley Garner","Xiaofang Jiang","Timothy D. Arthur","Georgia Lagoudas","Tommi Vatanen","Nadine Fornelos","Robin Wilson","Madeline Bertha","Melissa Cohen","John J. Garber","Hamed Khalili","Dirk Gevers","Ashwin N. Ananthakrishnan","Subra Kugathasan","Eric S. Lander","Paul C. Blainey","Hera Vlamakis","Ramnik J. Xavier","Curtis Huttenhower"]', 'microbiome', 'BACKGROUND: Inflammatory bowel disease (IBD) is characterized by chronic inflammation of the gastrointestinal tract that is associated with changes in the gut microbiome. Here, we sought to identify strain-specific functional correlates with IBD outcomes. METHODS: We performed metagenomic sequencing of monthly stool samples from 20 IBD patients and 12 controls (266 total samples). These were taxonomically profiled with MetaPhlAn2 and functionally profiled using HUMAnN2. Differentially abundant species were identified using MaAsLin and strain-specific pangenome haplotypes were analyzed using PanPhlAn. RESULTS: We found a significantly higher abundance in patients of facultative anaerobes that can tolerate the increased oxidative stress of the IBD gut. We also detected dramatic, yet transient, blooms of Ruminococcus gnavus in IBD patients, often co-occurring with increased disease activity. We identified two distinct clades of R. gnavus strains, one of which is enriched in IBD patients. To study functional differences between these two clades, we augmented the R. gnavus pangenome by sequencing nine isolates from IBD patients. We identified 199 IBD-specific, strain-specific genes involved in oxidative stress responses, adhesion, iron-acquisition, and mucus utilization, potentially conferring an adaptive advantage for this R. gnavus clade in the IBD gut. CONCLUSIONS: This study adds further evidence to the hypothesis that increased oxidative stress may be a major factor shaping the dysbiosis of the microbiome observed in IBD and suggests that R. gnavus may be an important member of the altered gut community in IBD.', '2026-07-07 22:02:00');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1948774627', 'microbiome', 'Host genetic variation impacts microbiome composition across human body sites', 'BACKGROUND: The composition of bacteria in and on the human body varies widely across human individuals, and has been associated with multiple health conditions. While microbial communities are…', '2015', 2015, 795, 795, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1038%2Fnrg.2017.63/MediaObjects/41576_2017_Article_BFnrg201763_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4570153', 'pmc', 'article', 'Genome biology', '["Ran Blekhman","Julia K. Goodrich","Katherine Huang","Qi Sun","Robert Bukowski","Jordana T. Bell","Timothy D. Spector","Alon Keinan","Ruth E. Ley","Dirk Gevers","Andrew G. Clark"]', 'microbiome', 'BACKGROUND: The composition of bacteria in and on the human body varies widely across human individuals, and has been associated with multiple health conditions. While microbial communities are influenced by environmental factors, some degree of genetic influence of the host on the microbiome is also expected. This study is part of an expanding effort to comprehensively profile the interactions between human genetic variation and the composition of this microbial ecosystem on a genome- and microbiome-wide scale. RESULTS: Here, we jointly analyze the composition of the human microbiome and host genetic variation. By mining the shotgun metagenomic data from the Human Microbiome Project for host DNA reads, we gathered information on host genetic variation for 93 individuals for whom bacterial abundance data are also available. Using this dataset, we identify significant associations between host genetic variation and microbiome composition in 10 of the 15 body sites tested. These associations are driven by host genetic variation in immunity-related pathways, and are especially enriched in host genes that have been previously associated with microbiome-related complex diseases, such as inflammatory bowel disease and obesity-related disorders. Lastly, we show that host genomic regions associated with the microbiome have high levels of genetic differentiation among human populations, possibly indicating host genomic adaptation to environment-specific microbiomes. CONCLUSIONS: Our results highlight the role of host genetic variation in shaping the composition of the human microbiome, and provide a starting point toward understanding the complex interaction between human genetics and the microbiome in the context of human evolution and disease.', '2026-07-07 22:02:01');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2513320387', 'plant-biology', 'Cardio-renal syndrome', 'Cardio-renal syndrome is a commonly encountered problem in clinical practice. Its pathogenesis is not fully understood. The purpose of this article is to highlight the interaction between the…', '2016', 2016, 26, 26, 'https://f1000research-files.f1000.com/manuscripts/8613/7f5f64d0-1dfe-42e3-89d4-4b37e60f9625_figure1.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5007748', 'pmc', 'preprint', 'F1000Research', '["Joseph Gnanaraj","Jai Radhakrishnan"]', 'plant biology', 'Cardio-renal syndrome is a commonly encountered problem in clinical practice. Its pathogenesis is not fully understood. The purpose of this article is to highlight the interaction between the cardiovascular system and the renal system and how their interaction results in the complex syndrome of cardio-renal dysfunction. Additionally, we outline the available therapeutic strategies to manage this complex syndrome.', '2026-07-07 22:02:10');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2807270740', 'microbiome', 'The Vaginal Microenvironment: The Physiologic Role of Lactobacilli', 'In addition to being a passage for sperm, menstruum, and the baby, the human vagina and its microbiota can influence conception, pregnancy, the mode and timing of delivery, and the risk of acquiring…', '2018', 2018, 771, 771, 'https://www.frontiersin.org/files/Articles/389042/fmed-05-00181-HTML/image_m/fmed-05-00181-g001.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6008313', 'pmc', 'review', 'Frontiers in Medicine', '["Emmanuel Amabebe","Dilly Anumba"]', 'microbiome', 'In addition to being a passage for sperm, menstruum, and the baby, the human vagina and its microbiota can influence conception, pregnancy, the mode and timing of delivery, and the risk of acquiring sexually transmitted infections. The physiological status of the vaginal milieu is important for the wellbeing of the host as well as for successful reproduction. High oestrogen states, as seen during puberty and pregnancy, promote the preservation of a homeostatic (eubiotic) vaginal microenvironment by stimulating the maturation and proliferation of vaginal epithelial cells and the accumulation of glycogen. A glycogen-rich vaginal milieu is a haven for the proliferation of Lactobacilli facilitated by the production of lactic acid and decreased pH. Lactobacilli and their antimicrobial and anti-inflammatory products along with components of the epithelial mucosal barrier provide an effective first line defense against invading pathogens including bacterial vaginosis, aerobic vaginitis-associated bacteria, viruses, fungi and protozoa. An optimal host-microbial interaction is required for the maintenance of eubiosis and vaginal health. This review explores the composition, function and adaptive mechanisms of the vaginal microbiome in health and those disease states in which there is a breach in the host-microbial relationship. The potential impact of vaginal dysbiosis on reproduction is also outlined.', '2026-07-07 22:02:12');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2977433364', 'microbiome', 'Interplay between the human gut microbiome and host metabolism', 'The human gut is inhabited by a complex and metabolically active microbial ecosystem. While many studies focused on the effect of individual microbial taxa on human health, their overall metabolic…', '2019', 2019, 773, 773, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41467-019-12476-z/MediaObjects/41467_2019_12476_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6776654', 'pmc', 'article', 'Nature Communications', '["Alessia Visconti","Caroline I. Le Roy","Fabio Rosa","Niccolò Rossi","Tiphaine Martin","Robert P. Mohney","Weizhong Li","Emanuele de Rinaldis","Jordana T. Bell","J. Craig Venter","Karen E. Nelson","Tim D. Spector","Mario Falchi"]', 'microbiome', 'The human gut is inhabited by a complex and metabolically active microbial ecosystem. While many studies focused on the effect of individual microbial taxa on human health, their overall metabolic potential has been under-explored. Using whole-metagenome shotgun sequencing data in 1,004 twins, we first observed that unrelated subjects share, on average, almost double the number of metabolic pathways (82%) than species (43%). Then, using 673 blood and 713 faecal metabolites, we found metabolic pathways to be associated with 34% of blood and 95% of faecal metabolites, with over 18,000 significant associations, while species showed less than 3,000 associations. Finally, we estimated that the microbiome was involved in a dialogue between 71% of faecal, and 15% of blood, metabolites. This study underlines the importance of studying the microbial metabolic potential rather than focusing purely on taxonomy to find therapeutic and diagnostic targets, and provides a unique resource describing the interplay between the microbiome and the systemic and faecal metabolic environments.', '2026-07-07 22:02:13');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3202462308', 'microbiome', 'Bioconductor workflow for microbiome data analysis: from raw reads to community analyses', 'High-throughput sequencing of PCR-amplified taxonomic markers (like the 16S rRNA gene) has enabled a new level of analysis of complex bacterial communities known as microbiomes. Many tools exist to…', '2016', 2016, 739, 739, 'https://f1000research-files.f1000.com/manuscripts/9666/feef7f31-9d44-4bb9-8853-a3f371e6fcd5_figure1.gif', 'https://doi.org/10.12688/f1000research.8986.1', 'repository', 'preprint', 'F1000Research', '["Ben J. Callahan","Kris Sankaran","Julia Fukuyama","Paul J. McMurdie","Susan Holmes"]', 'microbiome', 'High-throughput sequencing of PCR-amplified taxonomic markers (like the 16S rRNA gene) has enabled a new level of analysis of complex bacterial communities known as microbiomes. Many tools exist to quantify and compare abundance levels or microbial composition of communities in different conditions. The sequencing reads have to be denoised and assigned to the closest taxa from a reference database. Common approaches use a notion of 97% similarity and normalize the data by subsampling to equalize library sizes. In this paper, we show that statistical models allow more accurate abundance estimates. By providing a complete workflow in R, we enable the user to do sophisticated downstream statistical analyses, including both parameteric and nonparametric methods. We provide examples of using the R packages dada2, phyloseq, DESeq2, ggplot2 and vegan to filter, visualize and test microbiome data. We also provide examples of supervised analyses using random forests, partial least squares and linear models as well as nonparametric testing using community networks and the ggnetwork package.', '2026-07-07 22:02:48');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W7161566309', 'crop-pathology', 'Plant Fungal Diseases and Crop Protection, Second Edition', 'Fungal pathogens constitute the largest group of plant disease agents, infecting crops through leaves, seeds, and soil, and causing substantial losses in agricultural productivity worldwide [...].', '2026', 2026, 0, 0, 'https://pub.mdpi-res.com/jof/jof-12-00372/article_deploy/html/images/jof-12-00372-g001.png', 'https://pmc.ncbi.nlm.nih.gov/articles/PMC13208714/', 'repository', 'article', 'Journal of Fungi', '["Ofir Degani"]', 'crop pathology', 'Fungal pathogens constitute the largest group of plant disease agents, infecting crops through leaves, seeds, and soil, and causing substantial losses in agricultural productivity worldwide [...].', '2026-07-07 22:03:22');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2327037637', 'biology', 'A Guideline of Selecting and Reporting Intraclass Correlation Coefficients for Reliability Research', 'OBJECTIVE: Intraclass correlation coefficient (ICC) is a widely used reliability index in test-retest, intrarater, and interrater reliability analyses. This article introduces the basic concept of…', '2016', 2016, 27828, 27828, 'https://ars.els-cdn.com/content/image/1-s2.0-S1556370716000158-gr1.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4913118', 'pmc', 'article', 'Journal of Chiropractic Medicine', '["Terry K. Koo","Mae Y. Li"]', 'biology', 'OBJECTIVE: Intraclass correlation coefficient (ICC) is a widely used reliability index in test-retest, intrarater, and interrater reliability analyses. This article introduces the basic concept of ICC in the content of reliability analysis. DISCUSSION FOR RESEARCHERS: There are 10 forms of ICCs. Because each form involves distinct assumptions in their calculation and will lead to different interpretations, researchers should explicitly specify the ICC form they used in their calculation. A thorough review of the research design is needed in selecting the appropriate form of ICC to evaluate reliability. The best practice of reporting ICC should include software information, "model," "type," and "definition" selections. DISCUSSION FOR READERS: When coming across an article that includes ICC, readers should first check whether information about the ICC form has been reported and if an appropriate ICC form was used. Based on the 95% confident interval of the ICC estimate, values less than 0.5, between 0.5 and 0.75, between 0.75 and 0.9, and greater than 0.90 are indicative of poor, moderate, good, and excellent reliability, respectively. CONCLUSION: This article provides a practical guideline for clinical researchers to choose the correct form of ICC and suggests the best practice of reporting ICC parameters in scientific publications. This article also gives readers an appreciation for what to look for when coming across ICC while reading an article.', '2026-07-07 22:03:29');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2104549677', 'biology', 'A global reference for human genetic variation', 'The 1000 Genomes Project set out to provide a comprehensive description of common human genetic variation by applying whole-genome sequencing to a diverse set of individuals from multiple…', '2015', 2015, 20023, 20023, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature15393/MediaObjects/41586_2015_Article_BFnature15393_Fig1_HTML.jpg', 'https://pubmed.ncbi.nlm.nih.gov/26432245', 'repository', 'article', 'Nature', '["Corresponding authors","Adam Auton","Gonçalo R. Abecasis","David M. Altshuler","Richard Durbin","Gonçalo R. Abecasis","David R. Bentley","Aravinda Chakravarti","Andrew G. Clark","Peter Donnelly","Evan E. Eichler","Paul Flicek","Stacey B. Gabriel","Richard A. Gibbs","Eric D. Green","Matthew E. Hurles","Bartha M. Knoppers","Jan O. Korbel","Eric S. Lander","Charles Lee","Hans Lehrach","Elaine R. Mardis","Gábor Marth","Gil A. McVean","Deborah A. Nickerson","Jeanette P. Schmidt","Stephen T. Sherry","Jun Wang","Richard K. Wilson","Production group","Richard A. Gibbs","Eric Boerwinkle","HarshaVardhan Doddapaneni","Yi Han","Viktoriya Korchina","Christie Kovar","Sandra Lee","Donna M. Muzny","Jeffrey G. Reid","Yiming Zhu","BGI-Shenzhen","Jun Wang","Yuqi Chang","Qiang Feng","Xiaodong Fang","Xiaosen Guo","Min Jian","Hui Jiang","Xin Jin","Tianming Lan","Guoqing Li","Jingxiang Li","Yingrui Li","Shengmao Liu","Xiao Liu","Yao Lu","Xuedi Ma","Meifang Tang","Bo Wang","Guangbiao Wang","Honglong Wu","Renhua Wu","Xun Xu","Ye Yin","Dandan Zhang","Wenwei Zhang","Jiao Zhao","Meiru Zhao","Xiaole Zheng","Eric S. Lander","David M. Altshuler","Stacey Gabriel","Namrata Gupta","Neda Gharani","Lorraine H. Toji","Norman P. Gerry","Alissa Resch","Paul Flicek","Jonathan Barker","Laura Clarke","Laurent Gil","Sarah Hunt","Gavin Kelman","Eugene Kulesha","Rasko Leinonen","William McLaren","Rajesh Radhakrishnan","Asier Roa","Dmitriy Smirnov","Richard E. Smith","Ian Streeter","Anja Thormann","Iliana Toneva","Brendan Vaughan","Xiangqun Zheng-Bradley","Illumina","David R. Bentley","Russell Grocock","Sean Humphray","Terena James"]', 'biology', 'The 1000 Genomes Project set out to provide a comprehensive description of common human genetic variation by applying whole-genome sequencing to a diverse set of individuals from multiple populations. Here we report completion of the project, having reconstructed the genomes of 2,504 individuals from 26 populations using a combination of low-coverage whole-genome sequencing, deep exome sequencing, and dense microarray genotyping. We characterized a broad spectrum of genetic variation, in total over 88 million variants (84.7 million single nucleotide polymorphisms (SNPs), 3.6 million short insertions/deletions (indels), and 60,000 structural variants), all phased onto high-quality haplotypes. This resource includes >99% of SNP variants with a frequency of >1% for a variety of ancestries. We describe the distribution of genetic variation across the global sample, and discuss the implications for common disease studies. Results for the final phase of the 1000 Genomes Project are presented including whole-genome sequencing, targeted exome sequencing, and genotyping on high-density SNP arrays for 2,504 individuals across 26 populations, providing a global reference data set to support biomedical genetics. The 1000 Genomes Project has sought to comprehensively catalogue human genetic variation across populations, providing a valuable public genomic resource. The data obtained so far have found applications ranging from association studies and fine mapping studies to the filtering of likely neutral variants in rare-disease cohorts. The authors now report on the final phase of the project, phase 3, which covers previously uncharacterized areas of human genetic diversity in terms of the populations sampled and categories of characterized variation. The sample now includes more than 2,500 individuals from 26 global populations, with low coverage whole-genome and deep exome sequencing, as well as dense microarray genotyping. They find that while most common variants are shared across populations, rarer variants are often restricted to closely related populations. The authors also demonstrate the use of the phase 3 dataset as a reference panel for imputation to improve the resolution in genetic association studies.', '2026-07-07 22:03:39');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2593436234', 'biology', 'SwissADME: a free web tool to evaluate pharmacokinetics, drug-likeness and medicinal chemistry friendliness of small molecules', 'To be effective as a drug, a potent molecule must reach its target in the body in sufficient concentration, and stay there in a bioactive form long enough for the expected biologic events to occur.…', '2017', 2017, 17256, 17256, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fsrep42717/MediaObjects/41598_2017_Article_BFsrep42717_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5335600', 'pmc', 'article', 'Scientific Reports', '["Antoine Daina","Olivier Michielin","Vincent Zoete"]', 'biology', 'To be effective as a drug, a potent molecule must reach its target in the body in sufficient concentration, and stay there in a bioactive form long enough for the expected biologic events to occur. Drug development involves assessment of absorption, distribution, metabolism and excretion (ADME) increasingly earlier in the discovery process, at a stage when considered compounds are numerous but access to the physical samples is limited. In that context, computer models constitute valid alternatives to experiments. Here, we present the new SwissADME web tool that gives free access to a pool of fast yet robust predictive models for physicochemical properties, pharmacokinetics, drug-likeness and medicinal chemistry friendliness, among which in-house proficient methods such as the BOILED-Egg, iLOGP and Bioavailability Radar. Easy efficient input and interpretation are ensured thanks to a user-friendly interface through the login-free website http://www.swissadme.ch. Specialists, but also nonexpert in cheminformatics or computational chemistry can predict rapidly key parameters for a collection of molecules to support their drug discovery endeavours.', '2026-07-07 22:03:39');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2082704080', 'biology', 'UK Biobank: An Open Access Resource for Identifying the Causes of a Wide Range of Complex Diseases of Middle and Old Age', 'Cathie Sudlow and colleagues describe the UK Biobank, a large population-based prospective study, established to allow investigation of the genetic and non-genetic determinants of the diseases of…', '2015', 2015, 13402, 13402, 'https://journals.plos.org/plosmedicine/article/figure/image?size=large&id=10.1371/journal.pmed.1001779.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4380465', 'pmc', 'article', 'PLoS Medicine', '["Cathie Sudlow","John Gallacher","Naomi E. Allen","Valerie Beral","Paul R. Burton","John Danesh","Paul Downey","Paul Elliott","Jane Green","Martin Landray","Bette Liu","Paul M. Matthews","Giok Ong","Jill P. Pell","Alan J. Silman","A. P. Young","Tim Sprosen","Tim Peakman","Rory Collins"]', 'biology', 'Cathie Sudlow and colleagues describe the UK Biobank, a large population-based prospective study, established to allow investigation of the genetic and non-genetic determinants of the diseases of middle and old age.', '2026-07-07 22:04:01');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4396721167', 'biology', 'Accurate structure prediction of biomolecular interactions with AlphaFold 3', 'Abstract The introduction of AlphaFold 2 1 has spurred a revolution in modelling the structure of proteins and their interactions, enabling a huge range of applications in protein modelling and…', '2024', 2024, 14096, 14096, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-024-07487-w/MediaObjects/41586_2024_7487_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/11168924', 'pmc', 'article', 'Nature', '["Josh Abramson","Jonas Adler","Jack Dunger","Richard Evans","Tim Green","Alexander Pritzel","Olaf Ronneberger","Lindsay Willmore","Andrew J. Ballard","Joshua Bambrick","Sebastian W. Bodenstein","David A. Evans","Chia-Chun Hung","Michael O’Neill","David Reiman","Kathryn Tunyasuvunakool","Zachary Wu","Akvilė Žemgulytė","Eirini Arvaniti","Charles Beattie","Ottavia Bertolli","Alex Bridgland","Alexey V. Cherepanov","Miles Congreve","Alexander I. Cowen-Rivers","Andrew Cowie","Michael Figurnov","Fabian B. Fuchs","Hannah Gladman","Rishub Jain","Yousuf A. Khan","Caroline M. R. Low","Kuba Perlin","Anna Potapenko","Pascal Savy","Sukhdeep Singh","Adrian Stecuła","Ashok Thillaisundaram","Catherine Tong","Sergei Yakneen","Ellen D. Zhong","Michał Zieliński","Augustin Žídek","Victor Bapst","Pushmeet Kohli","Max Jaderberg","Demis Hassabis","John Jumper"]', 'biology', 'Abstract The introduction of AlphaFold 2 1 has spurred a revolution in modelling the structure of proteins and their interactions, enabling a huge range of applications in protein modelling and design 2–6. Here we describe our AlphaFold 3 model with a substantially updated diffusion-based architecture that is capable of predicting the joint structure of complexes including proteins, nucleic acids, small molecules, ions and modified residues. The new AlphaFold model demonstrates substantially improved accuracy over many previous specialized tools: far greater accuracy for protein–ligand interactions compared with state-of-the-art docking tools, much higher accuracy for protein–nucleic acid interactions compared with nucleic-acid-specific predictors and substantially higher antibody–antigen prediction accuracy compared with AlphaFold-Multimer v.2.3 7,8. Together, these results show that high-accuracy modelling across biomolecular space is possible within a single unified deep-learning framework.', '2026-07-07 22:04:03');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2794480084', 'biology', 'Integrating single-cell transcriptomic data across different conditions, technologies, and species', 'Integrating single-cell transcriptomic data across different conditions, technologies, and species', '2018', 2018, 14724, 14724, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnbt.4096/MediaObjects/41587_2018_Article_BFnbt4096_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6700744', 'pmc', 'article', 'Nature Biotechnology', '["Andrew Butler","Paul Hoffman","Peter Smibert","Efthymia Papalexi","Rahul Satija"]', 'biology', NULL, '2026-07-07 22:04:05');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4237130412', 'plant-biology', 'The rise and fall of machine learning methods in biomedical research', 'In the era of explosion in biological data, machine learning techniques are becoming more popular in life sciences, including biology and medicine. This research note examines the rise and fall of…', '2017', 2017, 25, 25, 'https://f1000research-files.f1000.com/manuscripts/14114/5db46b82-0306-4f94-b997-d34a22ef33a2_figure1.gif', 'https://doi.org/10.12688/f1000research.13016.1', 'repository', 'preprint', 'F1000Research', '["Hashem Koohy"]', 'plant biology', 'In the era of explosion in biological data, machine learning techniques are becoming more popular in life sciences, including biology and medicine. This research note examines the rise and fall of the most commonly used machine learning techniques in life sciences over the past three decades.', '2026-07-07 22:04:05');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3022049692', 'plant-biology', 'Recent advances in understanding and managing hepatic encephalopathy in chronic liver disease', 'Hepatic encephalopathy (HE) is a common, severe complication of advanced chronic liver disease (CLD) and has a devastating impact on the patient''s quality of life and prognosis. The neurotoxin…', '2020', 2020, 24, 24, 'https://f1000research-files.f1000.com/manuscripts/24468/9a7e1196-237f-4637-b051-270ddb09da1a_figure1.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7194462', 'pmc', 'preprint', 'F1000Research', '["Annarein Kerbert","Rajiv Jalan"]', 'plant biology', 'Hepatic encephalopathy (HE) is a common, severe complication of advanced chronic liver disease (CLD) and has a devastating impact on the patient''s quality of life and prognosis. The neurotoxin ammonia and the presence of systemic and neurological inflammation are considered the key drivers of this neuropsychiatric syndrome. Treatment options available in routine clinical practice are limited, and the development of novel therapies is hampered owing to the complexity and heterogeneity of HE. This review article aims to outline the current understanding of the pathomechanisms of HE and the recent advances in the identification and development of novel therapeutic targets.', '2026-07-07 22:04:56');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2952167528', 'biology', 'Unicycler: Resolving bacterial genome assemblies from short and long sequencing reads', 'The Illumina DNA sequencing platform generates accurate but short reads, which can be used to produce accurate but fragmented genome assemblies. Pacific Biosciences and Oxford Nanopore Technologies…', '2017', 2017, 8815, 8815, 'https://journals.plos.org/ploscompbiol/article/figure/image?size=large&id=10.1371/journal.pcbi.1005595.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5481147', 'pmc', 'article', 'PLoS Computational Biology', '["Ryan R. Wick","Louise M. Judd","Claire L. Gorrie","Kathryn E. Holt"]', 'biology', 'The Illumina DNA sequencing platform generates accurate but short reads, which can be used to produce accurate but fragmented genome assemblies. Pacific Biosciences and Oxford Nanopore Technologies DNA sequencing platforms generate long reads that can produce complete genome assemblies, but the sequencing is more expensive and error-prone. There is significant interest in combining data from these complementary sequencing technologies to generate more accurate "hybrid" assemblies. However, few tools exist that truly leverage the benefits of both types of data, namely the accuracy of short reads and the structural resolving power of long reads. Here we present Unicycler, a new tool for assembling bacterial genomes from a combination of short and long reads, which produces assemblies that are accurate, complete and cost-effective. Unicycler builds an initial assembly graph from short reads using the de novo assembler SPAdes and then simplifies the graph using information from short and long reads. Unicycler uses a novel semi-global aligner to align long reads to the assembly graph. Tests on both synthetic and real reads show Unicycler can assemble larger contigs with fewer misassemblies than other hybrid assemblers, even when long-read depth and accuracy are low. Unicycler is open source (GPLv3) and available at github.com/rrwick/Unicycler.', '2026-07-07 22:05:10');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4283361827', 'plant-biology', 'COVID-19, Cation Dysmetabolism, Sialic Acid, CD147, ACE2, Viroporins, Hepcidin and Ferroptosis: A Possible Unifying Hypothesis', 'Background: iron and calcium dysmetabolism, with hyperferritinemia, hypoferremia, hypocalcemia and anemia have been documented in the majority of COVID-19 patients at later/worse stages. Furthermore,…', '2022', 2022, 24, 24, 'https://f1000research-files.f1000.com/manuscripts/121457/ca5e3400-ffe2-4d54-adeb-0dfc98023bc3_figure1.gif', 'https://doi.org/10.12688/f1000research.108667.2', 'repository', 'preprint', 'F1000Research', '["Attilio Cavezzi","Roberto Menicagli","Emidio Troiani","Salvatore Corrao"]', 'plant biology', 'Background: iron and calcium dysmetabolism, with hyperferritinemia, hypoferremia, hypocalcemia and anemia have been documented in the majority of COVID-19 patients at later/worse stages. Furthermore, complementary to ACE2, both sialic acid (SA) molecules and CD147 proved relevant host receptors for SARS-CoV-2 entry, which explains the viral attack to multiple types of cells, including erythrocytes, endothelium and neural tissue. Several authors advocated that cell ferroptosis may be the core and final cell degenerative mechanism. Methods : a literature research was performed in several scientific search engines, such as PubMed Central, Cochrane Library, Chemical Abstract Service. More than 500 articles were retrieved until mid-December 2021, to highlight the available evidence about the investigated issues. Results : based on COVID-19 literature data, we have highlighted a few pathophysiological mechanisms, associated with virus-based cation dysmetabolism, multi-organ attack, mitochondria degeneration and ferroptosis. Our suggested elucidated pathological sequence is: a) spike protein subunit S1 docking with sialylated membrane glycoproteins/receptors (ACE2, CD147), and S2 subunit fusion with the lipid layer; b) cell membrane morpho-functional changes due to the consequent electro-chemical variations and viroporin action, which induce an altered ion channel function and intracellular cation accumulation; c) additional intracellular iron concentration due to a deregulated hepcidin-ferroportin axis, with higher hepcidin levels. Viral invasion may also affect erythrocytes/erythroid precursors, endothelial cells and macrophages, through SA and CD147 receptors, with relative hemoglobin and iron/calcium dysmetabolism. AB0 blood group, hemochromatosis, or environmental elements may represent possible factors which affect individual susceptibility to COVID-19. Conclusions : our literature analysis confirms the combined role of SA molecules, ACE2, CD147, viroporins and hepcidin in determining the cation dysmetabolism and final ferroptosis in the cells infected by SARS-CoV-2. The altered ion channels and electrochemical gradients of the cell membrane have a pivotal role in the virus entry and cell dysmetabolism, with subsequent multi-organ immune-inflammatory degeneration and erythrocyte/hemoglobin alterations.', '2026-07-07 22:05:11');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2805983714', 'biology', 'The MR-Base platform supports systematic causal inference across the human phenome', 'Results from genome-wide association studies (GWAS) can be used to infer causal relationships between phenotypes, using a strategy known as 2-sample Mendelian randomization (2SMR) and bypassing the…', '2018', 2018, 8444, 8444, 'https://cdn.elifesciences.org/articles/34408/elife-34408-fig1-v1.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5976434', 'pmc', 'article', 'eLife', '["Gibran Hemani","Jie Zheng","Benjamin Elsworth","Kaitlin H. Wade","Valeriia Haberland","Denis Baird","Charles Laurin","Stephen Burgess","Jack Bowden","Ryan Langdon","Vanessa Y. Tan","James Yarmolinsky","Hashem A. Shihab","Nicholas J. Timpson","David M. Evans","Caroline L. Relton","Richard M. Martin","George Davey Smith","Tom R. Gaunt","Philip Haycock"]', 'biology', 'Results from genome-wide association studies (GWAS) can be used to infer causal relationships between phenotypes, using a strategy known as 2-sample Mendelian randomization (2SMR) and bypassing the need for individual-level data. However, 2SMR methods are evolving rapidly and GWAS results are often insufficiently curated, undermining efficient implementation of the approach. We therefore developed MR-Base ( http://www.mrbase.org ): a platform that integrates a curated database of complete GWAS results (no restrictions according to statistical significance) with an application programming interface, web app and R packages that automate 2SMR. The software includes several sensitivity analyses for assessing the impact of horizontal pleiotropy and other violations of assumptions. The database currently comprises 11 billion single nucleotide polymorphism-trait associations from 1673 GWAS and is updated on a regular basis. Integrating data with software ensures more rigorous application of hypothesis-driven analyses and allows millions of potential causal relationships to be efficiently evaluated in phenome-wide association studies.', '2026-07-07 22:05:11');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3004227146', 'biology', 'Re-epithelialization and immune cell behaviour in an ex vivo human skin model', 'Abstract A large body of literature is available on wound healing in humans. Nonetheless, a standardized ex vivo wound model without disruption of the dermal compartment has not been put forward with…', '2020', 2020, 8286, 8286, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41598-019-56847-4/MediaObjects/41598_2019_56847_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6959339', 'pmc', 'article', 'Scientific Reports', '["Ana Rakita","Nenad Nikolić","Michael Mildner","Johannes Matiasek","Adelheid Elbe‐Bürger"]', 'biology', 'Abstract A large body of literature is available on wound healing in humans. Nonetheless, a standardized ex vivo wound model without disruption of the dermal compartment has not been put forward with compelling justification. Here, we present a novel wound model based on application of negative pressure and its effects for epidermal regeneration and immune cell behaviour. Importantly, the basement membrane remained intact after blister roof removal and keratinocytes were absent in the wounded area. Upon six days of culture, the wound was covered with one to three-cell thick K14 + Ki67 + keratinocyte layers, indicating that proliferation and migration were involved in wound closure. After eight to twelve days, a multi-layered epidermis was formed expressing epidermal differentiation markers (K10, filaggrin, DSG-1, CDSN). Investigations about immune cell-specific manners revealed more T cells in the blister roof epidermis compared to normal epidermis. We identified several cell populations in blister roof epidermis and suction blister fluid that are absent in normal epidermis which correlated with their decrease in the dermis, indicating a dermal efflux upon negative pressure. Together, our model recapitulates the main features of epithelial wound regeneration, and can be applied for testing wound healing therapies and investigating underlying mechanisms.', '2026-07-07 22:05:27');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2572710398', 'biology', 'Neurotoxic reactive astrocytes are induced by activated microglia', 'Neurotoxic reactive astrocytes are induced by activated microglia', '2017', 2017, 8058, 8058, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature21029/MediaObjects/41586_2017_Article_BFnature21029_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5404890', 'pmc', 'article', 'Nature', '["Shane A. Liddelow","Kevin A. Guttenplan","Laura Clarke","F. Chris Bennett","Christopher J. Bohlen","Lucas Schirmer","Mariko L. Bennett","Alexandra E. Münch","Won‐Suk Chung","Todd C. Peterson","Daniel K. Wilton","Arnaud Frouin","Brooke A. Napier","Nikhil Panicker","Manoj Kumar","Marion S. Buckwalter","David H. Rowitch","Valina L. Dawson","Ted M. Dawson","Beth Stevens","Ben A. Barres"]', 'biology', NULL, '2026-07-07 22:05:27');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2735527928', 'biology', 'NF-κB signaling in inflammation', 'The transcription factor NF-κB regulates multiple aspects of innate and adaptive immune functions and serves as a pivotal mediator of inflammatory responses. NF-κB induces the expression of various…', '2017', 2017, 8197, 8197, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fsigtrans.2017.23/MediaObjects/41392_2017_Article_BFsigtrans201723_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5661633', 'pmc', 'article', 'Signal Transduction and Targeted Therapy', '["Ting Liu","Lingyun Zhang","Donghyun Joo","Shao‐Cong Sun"]', 'biology', 'The transcription factor NF-κB regulates multiple aspects of innate and adaptive immune functions and serves as a pivotal mediator of inflammatory responses. NF-κB induces the expression of various pro-inflammatory genes, including those encoding cytokines and chemokines, and also participates in inflammasome regulation. In addition, NF-κB plays a critical role in regulating the survival, activation and differentiation of innate immune cells and inflammatory T cells. Consequently, deregulated NF-κB activation contributes to the pathogenic processes of various inflammatory diseases. In this review, we will discuss the activation and function of NF-κB in association with inflammatory diseases and highlight the development of therapeutic strategies based on NF-κB inhibition.', '2026-07-07 22:05:27');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2951506174', 'biology', 'Massively parallel digital transcriptional profiling of single cells', 'Characterizing the transcriptome of individual cells is fundamental to understanding complex biological systems. We describe a droplet-based system that enables 3'' mRNA counting of tens of thousands…', '2017', 2017, 7871, 7871, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fncomms14049/MediaObjects/41467_2017_Article_BFncomms14049_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5241818', 'pmc', 'article', 'Nature Communications', '["Grace Zheng","Jessica M. Terry","Phillip Belgrader","Paul Ryvkin","Zachary Bent","Ryan J. Wilson","Solongo B. Ziraldo","Tobias D. Wheeler","Geoff P. McDermott","Junjie Zhu","Mark Gregory","Joe Shuga","Luz Montesclaros","Jason G. Underwood","Donald A Masquelier","Stefanie Y. Nishimura","Michael Schnall-Levin","Paul W. Wyatt","Christopher M. Hindson","Rajiv Bharadwaj","Alexander Wong","Kevin D. Ness","Lan Beppu","H. Joachim Deeg","Christopher McFarland","Keith R. Loeb","William J. Valente","Nolan G. Ericson","Emily A. Stevens","Jerald P. Radich","Tarjei S. Mikkelsen","Benjamin J. Hindson","Jason H. Bielas"]', 'biology', 'Characterizing the transcriptome of individual cells is fundamental to understanding complex biological systems. We describe a droplet-based system that enables 3'' mRNA counting of tens of thousands of single cells per sample. Cell encapsulation, of up to 8 samples at a time, takes place in ∼6 min, with ∼50% cell capture efficiency. To demonstrate the system''s technical performance, we collected transcriptome data from ∼250k single cells across 29 samples. We validated the sensitivity of the system and its ability to detect rare populations using cell lines and synthetic RNAs. We profiled 68k peripheral blood mononuclear cells to demonstrate the system''s ability to characterize large immune populations. Finally, we used sequence variation in the transcriptome data to determine host and donor chimerism at single-cell resolution from bone marrow mononuclear cells isolated from transplant patients.', '2026-07-07 22:05:28');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3132661792', 'biology', 'Inference and analysis of cell-cell communication using CellChat', 'Understanding global communications among cells requires accurate representation of cell-cell signaling links and effective systems-level analyses of those links. We construct a database of…', '2021', 2021, 8360, 8360, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41467-021-21246-9/MediaObjects/41467_2021_21246_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7889871', 'pmc', 'article', 'Nature Communications', '["Suoqin Jin","Christian F. Guerrero‐Juarez","Lihua Zhang","Ivan Chang","Raúl Ramos","Chen‐Hsiang Kuan","Peggy Myung","Maksim V. Plikus","Qing Nie"]', 'biology', 'Understanding global communications among cells requires accurate representation of cell-cell signaling links and effective systems-level analyses of those links. We construct a database of interactions among ligands, receptors and their cofactors that accurately represent known heteromeric molecular complexes. We then develop CellChat, a tool that is able to quantitatively infer and analyze intercellular communication networks from single-cell RNA-sequencing (scRNA-seq) data. CellChat predicts major signaling inputs and outputs for cells and how those cells and signals coordinate for functions using network analysis and pattern recognition approaches. Through manifold learning and quantitative contrasts, CellChat classifies signaling pathways and delineates conserved and context-specific pathways across different datasets. Applying CellChat to mouse and human skin datasets shows its ability to extract complex signaling patterns. Our versatile and easy-to-use toolkit CellChat and a web-based Explorer ( http://www.cellchat.org/ ) will help discover novel intercellular communications and build cell-cell communication atlases in diverse tissues.', '2026-07-07 22:05:28');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2134629862', 'biology', 'Predicting effective microRNA target sites in mammalian mRNAs', 'MicroRNA targets are often recognized through pairing between the miRNA seed region and complementary sites within target mRNAs, but not all of these canonical sites are equally effective, and both…', '2015', 2015, 7685, 7685, 'https://cdn.elifesciences.org/articles/05005/elife-05005-fig1-v1.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4532895', 'pmc', 'article', 'eLife', '["Vikram Agarwal","George W. Bell","Jin‐Wu Nam","David P. Bartel"]', 'biology', 'MicroRNA targets are often recognized through pairing between the miRNA seed region and complementary sites within target mRNAs, but not all of these canonical sites are equally effective, and both computational and in vivo UV-crosslinking approaches suggest that many mRNAs are targeted through non-canonical interactions. Here, we show that recently reported non-canonical sites do not mediate repression despite binding the miRNA, which indicates that the vast majority of functional sites are canonical. Accordingly, we developed an improved quantitative model of canonical targeting, using a compendium of experimental datasets that we pre-processed to minimize confounding biases. This model, which considers site type and another 14 features to predict the most effectively targeted mRNAs, performed significantly better than existing models and was as informative as the best high-throughput in vivo crosslinking approaches. It drives the latest version of TargetScan (v7.0; targetscan.org), thereby providing a valuable resource for placing miRNAs into gene-regulatory networks.', '2026-07-07 22:05:42');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2069089843', 'biology', 'Spatial reconstruction of single-cell gene expression data', 'Spatial reconstruction of single-cell gene expression data', '2015', 2015, 7736, 7736, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnbt.3192/MediaObjects/41587_2015_Article_BFnbt3192_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4430369', 'pmc', 'article', 'Nature Biotechnology', '["Rahul Satija","Jeffrey A. Farrell","David Gennert","Alexander F. Schier","Aviv Regev"]', 'biology', NULL, '2026-07-07 22:05:43');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3009906937', 'biology', 'The species Severe acute respiratory syndrome-related coronavirus: classifying 2019-nCoV and naming it SARS-CoV-2', 'The present outbreak of a coronavirus-associated acute respiratory disease called coronavirus disease 19 (COVID-19) is the third documented spillover of an animal coronavirus to humans in only two…', '2020', 2020, 7753, 7753, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41564-020-0695-z/MediaObjects/41564_2020_695_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7095448', 'pmc', 'article', 'Nature Microbiology', '["Alexander E. Gorbalenya","Susan C. Baker","Ralph S. Baric","Raoul J. de Groot","Christian Drosten","Anastasia Gulyaeva","Bart L. Haagmans","Chris Lauber","A. M. Leontovich","Benjamin W. Neuman","Dmitry Penzar","Stanley Perlman","Leo L. M. Poon","Dmitry V. Samborskiy","Igor A. Sidorov","Isabel Sola","John Ziebuhr"]', 'biology', 'The present outbreak of a coronavirus-associated acute respiratory disease called coronavirus disease 19 (COVID-19) is the third documented spillover of an animal coronavirus to humans in only two decades that has resulted in a major epidemic. The Coronaviridae Study Group (CSG) of the International Committee on Taxonomy of Viruses, which is responsible for developing the classification of viruses and taxon nomenclature of the family Coronaviridae, has assessed the placement of the human pathogen, tentatively named 2019-nCoV, within the Coronaviridae. Based on phylogeny, taxonomy and established practice, the CSG recognizes this virus as forming a sister clade to the prototype human and bat severe acute respiratory syndrome coronaviruses (SARS-CoVs) of the species Severe acute respiratory syndrome-related coronavirus, and designates it as SARS-CoV-2. In order to facilitate communication, the CSG proposes to use the following naming convention for individual isolates: SARS-CoV-2/host/location/isolate/date. While the full spectrum of clinical manifestations associated with SARS-CoV-2 infections in humans remains to be determined, the independent zoonotic transmission of SARS-CoV and SARS-CoV-2 highlights the need for studying viruses at the species level to complement research focused on individual pathogenic viruses of immediate significance. This will improve our understanding of virus–host interactions in an ever-changing environment and enhance our preparedness for future outbreaks.', '2026-07-07 22:05:44');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2555870966', 'biology', 'CHARMM36m: an improved force field for folded and intrinsically disordered proteins', 'CHARMM36m: an improved force field for folded and intrinsically disordered proteins', '2016', 2016, 7637, 7637, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnmeth.4067/MediaObjects/41592_2017_Article_BFnmeth4067_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5199616', 'pmc', 'article', 'Nature Methods', '["Jing Huang","Sarah Rauscher","Grzegorz Nawrocki","Ting Ran","Michael Feig","Bert L. de Groot","Helmut Grubmüller","Alexander D. MacKerell"]', 'biology', NULL, '2026-07-07 22:05:44');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2756283300', 'biology', 'Conceptualizing the circular economy: An analysis of 114 definitions', 'Abstract The circular economy concept has gained momentum both among scholars and practitioners. However, critics claim that it means many different things to different people. This paper provides…', '2017', 2017, 7803, 7803, 'https://ars.els-cdn.com/content/image/1-s2.0-S0921344917302835-gr1.jpg', 'https://doi.org/10.1016/j.resconrec.2017.09.005', 'repository', 'article', 'Resources Conservation and Recycling', '["Julian Kirchherr","Denise Reike","Marko P. Hekkert"]', 'biology', 'Abstract The circular economy concept has gained momentum both among scholars and practitioners. However, critics claim that it means many different things to different people. This paper provides further evidence for these critics. The aim of this paper is to create transparency regarding the current understandings of the circular economy concept. For this purpose, we have gathered 114 circular economy definitions which were coded on 17 dimensions. Our findings indicate that the circular economy is most frequently depicted as a combination of reduce, reuse and recycle activities, whereas it is oftentimes not highlighted that CE necessitates a systemic shift. We further find that the definitions show few explicit linkages of the circular economy concept to sustainable development. The main aim of the circular economy is considered to be economic prosperity, followed by environmental quality; its impact on social equity and future generations is barely mentioned. Furthermore, neither business models nor consumers are frequently outlined as enablers of the circular economy. We critically discuss the various circular economy conceptualizations throughout this paper. Overall, we hope to contribute via this study towards the coherence of the circular economy concept; we presume that significantly varying circular economy definitions may eventually result in the collapse of the concept.', '2026-07-07 22:05:49');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4252914493', 'plant-biology', 'Revised World Health Organization (WHO)’s causality assessment of adverse events following immunization—a critique', 'The World Health Organisation (WHO) has recently revised how adverse events after immunization (AEFI) are classified. Only reactions that have previously been acknowledged in epidemiological studies…', '2018', 2018, 24, 24, 'https://f1000research-files.f1000.com/manuscripts/14875/ece5358a-fcb7-4e1d-9340-394063cbed7b_figure1.gif', 'https://doi.org/10.12688/f1000research.13694.1', 'repository', 'preprint', 'F1000Research', '["Jacob Puliyel","Pathik Naik"]', 'plant biology', 'The World Health Organisation (WHO) has recently revised how adverse events after immunization (AEFI) are classified. Only reactions that have previously been acknowledged in epidemiological studies to be caused by the vaccine, are classified as a vaccine-product–related-reaction. Deaths observed during post-marketing surveillance are not considered as “consistent with causal association with vaccine”, if there was no statistically significant increase in deaths recorded during the small Phase 3 trials that preceded it. Of course, vaccines that caused deaths in the control-trials stage would not be licensed. After licensure, deaths and all new serious adverse reactions are labelled as ‘coincidental deaths’ or ‘unclassifiable’, and the association with vaccine is not acknowledged. The resulting paradox is evident. The definition of causal association has also been changed. It is now used only if there is “no other factor intervening in the processes.” Therefore, if a child with an underlying congenital heart disease (other factor), develops fever and cardiac decompensation after vaccination, the cardiac failure would not be considered causally related to the vaccine. The Global Advisory Committee on Vaccine Safety has documented many deaths in children with pre-existing heart disease after they were administered the Pentavalent vaccine. The WHO now advises precautions when vaccinating such children and this has reduced the risk of death. Using the new definition of causal association, this relationship would not be acknowledged and lives would be put at risk. In view of the above, it is necessary that the AEFI manual be revaluated and revised urgently. AEFI reporting is said to be for vaccine safety. Child safety (safety of children) rather than vaccine safety (safety for vaccines) needs to be the emphasis.', '2026-07-07 22:06:09');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2998840182', 'biology', 'U1 snRNP regulates cancer cell migration and invasion in vitro', 'Stimulated cells and cancer cells have widespread shortening of mRNA 3''-untranslated regions (3''UTRs) and switches to shorter mRNA isoforms due to usage of more proximal polyadenylation signals…', '2020', 2020, 7238, 7238, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41467-019-13993-7/MediaObjects/41467_2019_13993_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6946686', 'pmc', 'article', 'Nature Communications', '["Jung‐Min Oh","Christopher C. Venters","Chao Di","Anna Maria Pinto","Lili Wan","Ihab Younis","Zhiqiang Cai","Chie Arai","Byung Ran So","Jingqi Duan","Gideon Dreyfuss"]', 'biology', 'Stimulated cells and cancer cells have widespread shortening of mRNA 3''-untranslated regions (3''UTRs) and switches to shorter mRNA isoforms due to usage of more proximal polyadenylation signals (PASs) in introns and last exons. U1 snRNP (U1), vertebrates'' most abundant non-coding (spliceosomal) small nuclear RNA, silences proximal PASs and its inhibition with antisense morpholino oligonucleotides (U1 AMO) triggers widespread premature transcription termination and mRNA shortening. Here we show that low U1 AMO doses increase cancer cells'' migration and invasion in vitro by up to 500%, whereas U1 over-expression has the opposite effect. In addition to 3''UTR length, numerous transcriptome changes that could contribute to this phenotype are observed, including alternative splicing, and mRNA expression levels of proto-oncogenes and tumor suppressors. These findings reveal an unexpected role for U1 homeostasis (available U1 relative to transcription) in oncogenic and activated cell states, and suggest U1 as a potential target for their modulation.', '2026-07-07 22:06:15');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2990618091', 'biology', 'Improved metagenomic analysis with Kraken 2', 'Although Kraken''s k-mer-based approach provides a fast taxonomic classification of metagenomic sequence data, its large memory requirements can be limiting for some applications. Kraken 2 improves…', '2019', 2019, 7201, 7201, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs13059-019-1891-0/MediaObjects/13059_2019_1891_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6883579', 'pmc', 'article', 'Genome biology', '["Derrick E. Wood","Jennifer Lu","Ben Langmead"]', 'biology', 'Although Kraken''s k-mer-based approach provides a fast taxonomic classification of metagenomic sequence data, its large memory requirements can be limiting for some applications. Kraken 2 improves upon Kraken 1 by reducing memory usage by 85%, allowing greater amounts of reference genomic data to be used, while maintaining high accuracy and increasing speed fivefold. Kraken 2 also introduces a translated search mode, providing increased sensitivity in viral metagenomics analysis.', '2026-07-07 22:06:23');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2410390527', 'biology', 'The Shared Socioeconomic Pathways and their energy, land use, and greenhouse gas emissions implications: An overview', 'This paper presents the overview of the Shared Socioeconomic Pathways (SSPs) and their energy, land use, and emissions implications. The SSPs are part of a new scenario framework, established by the…', '2016', 2016, 6515, 6515, 'https://ars.els-cdn.com/content/image/1-s2.0-S0959378016300681-gr1.jpg', 'https://doi.org/10.1016/j.gloenvcha.2016.05.009', 'repository', 'article', 'Global Environmental Change', '["Keywan Riahi","Detlef P. van Vuuren","Elmar Kriegler","Jae Edmonds","Brian C. O’Neill","Shinichiro Fujimori","Nico Bauer","Katherine Calvin","Rob Dellink","Oliver Fricko","Wolfgang Lutz","Alexander Popp","Jesús Crespo Cuaresma","Samir KC","Marian Leimbach","Leiwen Jiang","Tom Kram","Shilpa Rao","Johannes Emmerling","Kristie L. Ebi","Tomoko Hasegawa","Peter Havlík","Florian Humpenöder","Lara Aleluia Da Silva","Steve Smith","Elke Stehfest","Valentina Bosetti","Jiyong Eom","David Gernaat","Toshihiko Masui","Joeri Rogelj","Jessica Strefler","Laurent Drouet","Volker Krey","Gunnar Luderer","Mathijs Harmsen","Kiyoshi Takahashi","Lavinia Baumstark","Jonathan Doelman","Mikiko Kainuma","Zbigniew Klimont","Giacomo Marangoni","Hermann Lotze‐Campen","Michael Obersteiner","Andrzej Tabeau","Massimo Tavoni"]', 'biology', 'This paper presents the overview of the Shared Socioeconomic Pathways (SSPs) and their energy, land use, and emissions implications. The SSPs are part of a new scenario framework, established by the climate change research community in order to facilitate the integrated analysis of future climate impacts, vulnerabilities, adaptation, and mitigation. The pathways were developed over the last years as a joint community effort and describe plausible major global developments that together would lead in the future to different challenges for mitigation and adaptation to climate change. The SSPs are based on five narratives describing alternative socio-economic developments, including sustainable development, regional rivalry, inequality, fossil-fueled development, and middle-of-the-road development. The long-term demographic and economic projections of the SSPs depict a wide uncertainty range consistent with the scenario literature. A multi-model approach was used for the elaboration of the energy, land-use and the emissions trajectories of SSP-based scenarios. The baseline scenarios lead to global energy consumption of 400–1200 EJ in 2100, and feature vastly different land-use dynamics, ranging from a possible reduction in cropland area up to a massive expansion by more than 700 million hectares by 2100. The associated annual CO2 emissions of the baseline scenarios range from about 25 GtCO2 to more than 120 GtCO2 per year by 2100. With respect to mitigation, we find that associated costs strongly depend on three factors: (1) the policy assumptions, (2) the socio-economic narrative, and (3) the stringency of the target. The carbon price for reaching the target of 2.6 W/m2 that is consistent with a temperature change limit of 2 °C, differs in our analysis thus by about a factor of three across the SSP marker scenarios. Moreover, many models could not reach this target from the SSPs with high mitigation challenges. While the SSPs were designed to represent different mitigation and adaptation challenges, the resulting narratives and quantifications span a wide range of different futures broadly representative of the current literature. This allows their subsequent use and development in new assessments and research projects. Critical next steps for the community scenario process will, among others, involve regional and sectoral extensions, further elaboration of the adaptation and impacts dimension, as well as employing the SSP scenarios with the new generation of earth system models as part of the 6th climate model intercomparison project (CMIP6).', '2026-07-07 22:06:50');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2886965597', 'plant-biology', 'Soil fertility assessment and mapping of chungbang farm, Pakhribas, Dhankuta, Nepal', '&#13;\n\tSoil fertility evaluation is a basic factor for sustainable planning of a particular area. Thus, a study was done to assess the soil fertility status of the Chungbang farm, Pakhribas,…', '2018', 2018, 23, 23, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.15406/apar.2018.08.00317.g001', 'https://doi.org/10.15406/apar.2018.08.00317', 'repository', 'article', 'Advances in Plants & Agriculture Research', '["Dinesh Khadka"]', 'plant biology', '&#13;\n\tSoil fertility evaluation is a basic factor for sustainable planning of a particular area. Thus, a study was done to assess the soil fertility status of the Chungbang farm, Pakhribas, Dhankuta, Nepal. The farm is situated at the latitude 27.00739&amp;deg;N and longitude 87.25894&amp;deg;E as well altitude 1176masl. The total 27 soil samples were collected randomly at a depth of 0-20 cm by using soil sampling auger. A GPS device was used for determination of geographical position of soil sampling points. The collected samples were analyzed for their texture, pH, OM, N, P2O5, K2O, Ca, Mg, S, B, Fe, Zn, Cu and Mn status following standard analytical methods in the laboratory of Soil Science Division, Khumaltar. The Arc-GIS 10.1 software was used for the preparation of soil fertility maps. The observed data revealed that structure was granular and sub-angular blocky, whereas colour were yellowish brown and brown. The sand, silt and clay content were 59.25&amp;plusmn;1.01%, 27.41&amp;plusmn;0.83% and 13.34&amp;plusmn;0.38%, respectively and categorized as sandy loam in texture. The soil was very acidic in pH (4.75&amp;plusmn;0.07) and very low in available boron (0.21&amp;plusmn;0.05mg/kg), available sulphur (1.22&amp;plusmn;0.34mg/kg) and available zinc (0.20&amp;plusmn;0.02mg/kg). The organic matter (1.32&amp;plusmn;0.13%), total nitrogen (0.08&amp;plusmn;0.004%) and available calcium (512.5&amp;plusmn;36.3mg/kg) were low in status. Similarly, available potassium (104.1&amp;plusmn;12mg/kg) and available magnesium (66.27&amp;plusmn;7.33mg/kg) were medium in status. Consequently, the available iron (20.59&amp;plusmn;2.91mg/kg) was high, while available phosphorus (54.88&amp;plusmn;7.19mg/kg), available copper (2.96&amp;plusmn;0.62mg/kg) and available manganese (31.19&amp;plusmn;2.94mg/kg) were very high in status. The determined soil test data can be used for sustainable soil management as well as developing future research strategy in the farm.&#13;\n&#13;\n\t&amp;nbsp;', '2026-07-07 22:07:02');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4236357753', 'biology', 'The ARRIVE guidelines 2.0: Updated guidelines for reporting animal research', 'Reproducible science requires transparent reporting. The ARRIVE guidelines (Animal Research: Reporting of In Vivo Experiments) were originally developed in 2010 to improve the reporting of animal…', '2020', 2020, 5638, 5638, 'https://journals.plos.org/plosbiology/article/figure/image?size=large&id=10.1371/journal.pbio.3000410.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7360023', 'pmc', 'article', 'PLoS Biology', '["Nathalie Percie du Sert","Viki Hurst","Amrita Ahluwalia","Sabina Alam","Marc T. Avey","Monya Baker","William J. Browne","Alejandra Clark","Innes C. Cuthill","Ulrich Dirnagl","Michael Emerson","Paul Garner","Stephen T. Holgate","David W. Howells","Natasha A. Karp","Stanley E. Lazic","Katie Lidster","Catriona MacCallum","Malcolm Macleod","Esther J. Pearl","Ole H. Petersen","Frances Rawle","Penny S. Reynolds","Kieron Rooney","Emily S. Sena","Shai D. Silberberg","Thomas Steckler","Hanno Würbel"]', 'biology', 'Reproducible science requires transparent reporting. The ARRIVE guidelines (Animal Research: Reporting of In Vivo Experiments) were originally developed in 2010 to improve the reporting of animal research. They consist of a checklist of information to include in publications describing in vivo experiments to enable others to scrutinise the work adequately, evaluate its methodological rigour, and reproduce the methods and results. Despite considerable levels of endorsement by funders and journals over the years, adherence to the guidelines has been inconsistent, and the anticipated improvements in the quality of reporting in animal research publications have not been achieved. Here, we introduce ARRIVE 2.0. The guidelines have been updated and information reorganised to facilitate their use in practice. We used a Delphi exercise to prioritise and divide the items of the guidelines into 2 sets, the "ARRIVE Essential 10," which constitutes the minimum requirement, and the "Recommended Set," which describes the research context. This division facilitates improved reporting of animal research by supporting a stepwise approach to implementation. This helps journal editors and reviewers verify that the most important items are being reported in manuscripts. We have also developed the accompanying Explanation and Elaboration (E&E) document, which serves (1) to explain the rationale behind each item in the guidelines, (2) to clarify key concepts, and (3) to provide illustrative examples. We aim, through these changes, to help ensure that researchers, reviewers, and journal editors are better equipped to improve the rigour and transparency of the scientific process and thus reproducibility.', '2026-07-07 22:07:26');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4231556566', 'plant-biology', 'Causes of reporting bias: a theoretical framework', 'Reporting of research findings is often selective. This threatens the validity of the published body of knowledge if the decision to report depends on the nature of the results. Studies on causes and…', '2019', 2019, 23, 23, 'https://f1000research-files.f1000.com/manuscripts/20029/bc4a1042-7e16-4b78-8e86-f772edcfbb50_figure1.gif', 'https://doi.org/10.12688/f1000research.18310.1', 'repository', 'preprint', 'F1000Research', '["Jenny T. van der Steen","Gerben ter Riet","Cornelis A. van den Bogert","L.M. Bouter"]', 'plant biology', 'Reporting of research findings is often selective. This threatens the validity of the published body of knowledge if the decision to report depends on the nature of the results. Studies on causes and mechanisms underlying selective reporting may help to avoid or reduce reporting bias. Such research should be guided by a theoretical framework of possible causal pathways that lead to reporting bias. We build upon a classification of determinants of selective reporting that we recently developed in a systematic review of the topic. The resulting theoretical framework features four clusters of causes. There are two clusters of necessary causes: (A) motivations (e.g. a preference for positive findings) and (B) means (e.g. a flexible study design). These two combined represent a sufficient cause for reporting bias to occur. The framework also features two clusters of component causes: (C) conflicts and balancing of interests referring to the individual or the team, and (D) pressures from science and society. The component causes may modify the effect of the necessary causes or may lead to reporting bias mediated through the necessary causes. Our theoretical framework is meant to inspire further research and to create awareness among researchers and end-users of research about reporting bias and its causes.', '2026-07-07 22:07:42');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2747877289', 'biology', 'Reversed graph embedding resolves complex single-cell trajectories', 'Reversed graph embedding resolves complex single-cell trajectories', '2017', 2017, 5399, 5399, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnmeth.4402/MediaObjects/41592_2017_BFnmeth4402_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5764547', 'pmc', 'article', 'Nature Methods', '["Xiaojie Qiu","Qi Mao","Ying Tang","Li Wang","Raghav Chawla","Hannah A. Pliner","Cole Trapnell"]', 'biology', NULL, '2026-07-07 22:07:54');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3092136311', 'biology', 'Characteristics of SARS-CoV-2 and COVID-19', 'Severe acute respiratory syndrome coronavirus 2 (SARS-CoV-2) is a highly transmissible and pathogenic coronavirus that emerged in late 2019 and has caused a pandemic of acute respiratory disease,…', '2020', 2020, 5461, 5461, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41579-020-00459-7/MediaObjects/41579_2020_459_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7537588', 'pmc', 'review', 'Nature Reviews Microbiology', '["Ben Hu","Hua Guo","Peng Zhou","Zheng‐Li Shi"]', 'biology', 'Severe acute respiratory syndrome coronavirus 2 (SARS-CoV-2) is a highly transmissible and pathogenic coronavirus that emerged in late 2019 and has caused a pandemic of acute respiratory disease, named ‘coronavirus disease 2019’ (COVID-19), which threatens human health and public safety. In this Review, we describe the basic virology of SARS-CoV-2, including genomic characteristics and receptor use, highlighting its key difference from previously known coronaviruses. We summarize current knowledge of clinical, epidemiological and pathological features of COVID-19, as well as recent progress in animal models and antiviral treatment approaches for SARS-CoV-2 infection. We also discuss the potential wildlife hosts and zoonotic origin of this emerging virus in detail. In this Review, Shi and colleagues summarize the exceptional amount of research that has characterized acute respiratory syndrome coronavirus 2 (SARS-CoV-2) and coronavirus disease 2019 (COVID-19) since this virus has swept around the globe. They discuss what we know so far about the emergence and virology of SARS-CoV-2 and the pathogenesis and treatment of COVID-19.', '2026-07-07 22:07:55');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2627092521', 'biology', 'Expert consensus document: The International Scientific Association for Probiotics and Prebiotics (ISAPP) consensus statement on the definition and scope of prebiotics', 'With the continued interest in the role of the gut microbiota in health, attention has now turned to how to harness the microbiota for the benefit of the host. This Consensus Statement outlines the…', '2017', 2017, 5353, 5353, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnrgastro.2017.75/MediaObjects/41575_2017_Article_BFnrgastro201775_Fig1_HTML.jpg', 'https://pubmed.ncbi.nlm.nih.gov/28611480', 'repository', 'review', 'Nature Reviews Gastroenterology & Hepatology', '["Glenn R. Gibson","Robert W. Hutkins","Mary Ellen Sanders","Susan L. Prescott","Raylene A. Reimer","Seppo Salminen","Karen P. Scott","Catherine Stanton","Kelly S. Swanson","Patrice D. Cani","Kristin Verbeke","Gregor Reid"]', 'biology', 'With the continued interest in the role of the gut microbiota in health, attention has now turned to how to harness the microbiota for the benefit of the host. This Consensus Statement outlines the definition and scope of the term ''prebiotic'' as determined by an expert panel convened by the International Scientific Association for Probiotics and Prebiotics in December 2016. In December 2016, a panel of experts in microbiology, nutrition and clinical research was convened by the International Scientific Association for Probiotics and Prebiotics to review the definition and scope of prebiotics. Consistent with the original embodiment of prebiotics, but aware of the latest scientific and clinical developments, the panel updated the definition of a prebiotic: a substrate that is selectively utilized by host microorganisms conferring a health benefit. This definition expands the concept of prebiotics to possibly include non-carbohydrate substances, applications to body sites other than the gastrointestinal tract, and diverse categories other than food. The requirement for selective microbiota-mediated mechanisms was retained. Beneficial health effects must be documented for a substance to be considered a prebiotic. The consensus definition applies also to prebiotics for use by animals, in which microbiota-focused strategies to maintain health and prevent disease is as relevant as for humans. Ultimately, the goal of this Consensus Statement is to engender appropriate use of the term ''prebiotic'' by relevant stakeholders so that consistency and clarity can be achieved in research reports, product marketing and regulatory oversight of the category. To this end, we have reviewed several aspects of prebiotic science including its development, health benefits and legislation.', '2026-07-07 22:07:56');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2122519929', 'plant-biology', 'How to avoid pitfalls in antibody use', 'Antibody use is ubiquitous in the biomedical sciences. However, determining best research practices has not been trivial. Many commercially available antibodies and antibody-conjugates are poorly…', '2015', 2015, 23, 23, 'https://f1000research-files.f1000.com/manuscripts/7423/0b79af2c-403a-44f9-a95e-08c7cec49d93_figure1.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4722690', 'pmc', 'preprint', 'F1000Research', '["Diana Pauly","Katja Hanack"]', 'plant biology', 'Antibody use is ubiquitous in the biomedical sciences. However, determining best research practices has not been trivial. Many commercially available antibodies and antibody-conjugates are poorly characterized and lack proper validation. Uncritical application of such useless tools has contributed to the reproducibility crisis in biomedical research. Despite early initiatives such as MIAPAR or PSI-PAR, a best practice guideline for antibody characterization is still not in prospect. Here, we analyze 24 antibody-related databases and compare their content with regard to validation aspects and coverage. We also provide a flowchart for end-users with all necessary steps to facilitate finding and choosing specific and sensitive antibodies for their experiments. Based on a growing demand for better and standardized validation procedures and characterization guidelines for antibody molecules we have summarized our findings in a five-point plan. We intend to keep the discussion alive and hope that properly used antibodies will remain as central to biomedicine as they are today.', '2026-07-07 22:07:56');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1934094702', 'biology', 'The consensus molecular subtypes of colorectal cancer', 'The consensus molecular subtypes of colorectal cancer', '2015', 2015, 5272, 5272, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnm.3967/MediaObjects/41591_2015_Article_BFnm3967_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4636487', 'pmc', 'article', 'Nature Medicine', '["Justin Guinney","Rodrigo Dienstmann","Xin Wang","Aurélien de Reyniès","Andreas Schlicker","Charlotte Soneson","Laëtitia Marisa","Paul Roepman","Gift Nyamundanda","Paolo Angelino","Brian M. Bot","Jeffrey S. Morris","Iris Simón","Sarah Gerster","Evelyn Fessler","Felipe de Sousa e Melo","Edoardo Missiaglia","Hena R. Ramay","David Barras","Krisztián Homicskó","Dipen Maru","Ganiraju C. Manyam","Bradley M. Broom","Valérie Boige","Beatriz Pérez‐Villamil","Ted Laderas","Ramón Salazar","Joe W. Gray","Douglas Hanahan","Josep Tabernero","René Bernards","Stephen Friend","Pierre Laurent‐Puig","Jan Paul Medema","Anguraj Sadanandam","Lodewyk F.A. Wessels","Mauro Delorenzi","Scott Kopetz","Louis Vermeulen","Sabine Tejpar"]', 'biology', NULL, '2026-07-07 22:08:10');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2952564192', 'biology', 'Revised Estimates for the Number of Human and Bacteria Cells in the Body', 'Reported values in the literature on the number of cells in the body differ by orders of magnitude and are very seldom supported by any measurements or calculations. Here, we integrate the most…', '2016', 2016, 5091, 5091, 'https://journals.plos.org/plosbiology/article/figure/image?size=large&id=10.1371/journal.pbio.1002533.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4991899', 'pmc', 'article', 'PLoS Biology', '["Ron Sender","Shai Fuchs","Ron Milo"]', 'biology', 'Reported values in the literature on the number of cells in the body differ by orders of magnitude and are very seldom supported by any measurements or calculations. Here, we integrate the most up-to-date information on the number of human and bacterial cells in the body. We estimate the total number of bacteria in the 70 kg "reference man" to be 3.8·1013. For human cells, we identify the dominant role of the hematopoietic lineage to the total count (≈90%) and revise past estimates to 3.0·1013 human cells. Our analysis also updates the widely-cited 10:1 ratio, showing that the number of bacteria in the body is actually of the same order as the number of human cells, and their total mass is about 0.2 kg.', '2026-07-07 22:08:19');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2344644350', 'biology', 'Analysis of nanoparticle delivery to tumours', 'Analysis of nanoparticle delivery to tumours', '2016', 2016, 4921, 4921, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnatrevmats.2016.14/MediaObjects/41578_2016_Article_BFnatrevmats201614_Fig1_HTML.jpg', 'https://doi.org/10.1038/natrevmats.2016.14', 'repository', 'review', 'Nature Reviews Materials', '["Stefan Wilhelm","Anthony J. Tavares","Qin Dai","Seiichi Ohta","Julie Audet","Harold F. Dvorak","Warren C. W. Chan"]', 'biology', NULL, '2026-07-07 22:08:48');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2337225114', 'biology', 'The Scenario Model Intercomparison Project (ScenarioMIP) for CMIP6', 'Abstract. Projections of future climate change play a fundamental role in improving understanding of the climate system as well as characterizing societal risks and response options. The Scenario…', '2016', 2016, 4937, 4937, 'https://www.geoscientific-model-development.net/graphic_egu_claim_logo_blue.png', 'https://doi.org/10.5194/gmd-9-3461-2016', 'repository', 'article', 'Geoscientific model development', '["Brian C. O’Neill","Claudia Tebaldi","Detlef P. van Vuuren","Veronika Eyring","Pierre Friedlingstein","G. C. Hurtt","Reto Knutti","Elmar Kriegler","Jean‐François Lamarque","Jason Lowe","Gerald A. Meehl","Richard H. Moss","Keywan Riahi","Benjamin M. Sanderson"]', 'biology', 'Abstract. Projections of future climate change play a fundamental role in improving understanding of the climate system as well as characterizing societal risks and response options. The Scenario Model Intercomparison Project (ScenarioMIP) is the primary activity within Phase 6 of the Coupled Model Intercomparison Project (CMIP6) that will provide multi-model climate projections based on alternative scenarios of future emissions and land use changes produced with integrated assessment models. In this paper, we describe ScenarioMIP''s objectives, experimental design, and its relation to other activities within CMIP6. The ScenarioMIP design is one component of a larger scenario process that aims to facilitate a wide range of integrated studies across the climate science, integrated assessment modeling, and impacts, adaptation, and vulnerability communities, and will form an important part of the evidence base in the forthcoming Intergovernmental Panel on Climate Change (IPCC) assessments. At the same time, it will provide the basis for investigating a number of targeted science and policy questions that are especially relevant to scenario-based analysis, including the role of specific forcings such as land use and aerosols, the effect of a peak and decline in forcing, the consequences of scenarios that limit warming to below 2 °C, the relative contributions to uncertainty from scenarios, climate models, and internal variability, and long-term climate system outcomes beyond the 21st century. To serve this wide range of scientific communities and address these questions, a design has been identified consisting of eight alternative 21st century scenarios plus one large initial condition ensemble and a set of long-term extensions, divided into two tiers defined by relative priority. Some of these scenarios will also provide a basis for variants planned to be run in other CMIP6-Endorsed MIPs to investigate questions related to specific forcings. Harmonized, spatially explicit emissions and land use scenarios generated with integrated assessment models will be provided to participating climate modeling groups by late 2016, with the climate model simulations run within the 2017–2018 time frame, and output from the climate model projections made available and analyses performed over the 2018–2020 period.', '2026-07-07 22:08:49');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2039153962', 'biology', 'Genetic studies of body mass index yield new insights for obesity biology', 'Genetic studies of body mass index yield new insights for obesity biology', '2015', 2015, 4909, 4909, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature14177/MediaObjects/41586_2015_BFnature14177_Fig1_HTML.jpg', 'https://pubmed.ncbi.nlm.nih.gov/25673413', 'repository', 'review', 'Nature', '["The LifeLines Cohort Study","Adam E. Locke","The AGEN-BMI Working Group","The GLGC","The ICBP","The MAGIC Investigators","Bratati Kahali","Sonja I. Berndt","Anne E. Justice","Tune H. Pers","Felix R. Day","C. E. Powell","Sailaja Vedantam","Martin L. Buchkovich","Jian Yang","Damien C. Croteau‐Chonka","Tõnu Esko","Tove Fall","Teresa Ferreira","Stefan Gustafsson","Zoltán Kutalik","Jian’an Luan","Reedik Mägi","Joshua C. Randall","Thomas W. Winkler","Andrew R. Wood","Tsegaselassie Workalemahu","Jessica D. Faul","Jennifer A. Smith","Wei Zhao","Wei Zhao","Jin Chen","Rudolf S.N. Fehrmann","Åsa K. Hedman","Juha Karjalainen","Ellen M. Schmidt","Devin Absher","Najaf Amin","Denise Anderson","Marian Beekman","Jennifer L. Bolton","Jennifer L. Bragg‐Gresham","Steven Buyske","Ayşe Demirkan","Guohong Deng","Georg Ehret","Bjarke Feenstra","Mary F. Feitosa","Krista Fischer","Anuj Goel","Jian Gong","Anne Jackson","Stavroula Kanoni","Marcus E. Kleber","Kati Kristiansson","Unhee Lim","Vaneet Lotay","Massimo Mangino","Irene Mateo Leach","Carolina Medina‐Gómez","Sarah E. Medland","Michael A. Nalls","Cameron D. Palmer","Dorota Pasko","Sonali Pechlivanis","Marjolein J. Peters","Inga Prokopenko","Dmitry Shungin","Alena Stančáková","Rona J. Strawbridge","Yun Ju Sung","Toshiko Tanaka","Alexander Teumer","Stella Trompet","Sander W. van der Laan","Jessica van Setten","Jana V. van Vliet‐Ostaptchouk","Zhaoming Wang","Loïc Yengo","Weihua Zhang","Aaron Isaacs","Eva Albrecht","Johan Ärnlöv","Gillian M. Arscott","Antony Attwood","Stefania Bandinelli","Amy Barrett","Isabelita Bas","Claire Bellis","Amanda J. Bennett","Christian Berne","Roza Blagieva","Matthias Blüher","Stefan Böhringer","Lori L. Bonnycastle","Yvonne Böttcher","Heather A. Boyd","Marcel Bruinenberg","Ida Henriette Caspersen","Yii‐Der Ida Chen"]', 'biology', NULL, '2026-07-07 22:08:51');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4401461701', 'plant-biology', 'The Nexus of Climate Change, Food Insecurity, and Conflict in Somalia: A Comprehensive Analysis of Multifaceted Challenges and Resilience Strategies', 'Climate change poses a significant threat to Somalia’s food security and stability. This review examines the complex interplay between climate change impacts, food insecurity, and conflict in…', '2024', 2024, 22, 22, 'https://f1000research-files.f1000.com/manuscripts/169421/5025af6c-b86c-44a5-b0a6-16d73d12d54a_figure1.gif', 'https://doi.org/10.12688/f1000research.154400.1', 'repository', 'preprint', 'F1000Research', '["Mohamed Mustaf Ahmed","Hodo Aideed Asowe","Najib Isse Dirie","Abdirahman Khalif Mohamud","Don Eliseo Lucero‐Prisno","Olalekan John Okesanya","Jerico Bautista Ogaya","Shuaibu Saidu Musa","Muhammad Kabir Musa","Zhinya Kawa Othman","Deborah Oluwaseun Shomuyiwa","Abdullateef Abdulsalam"]', 'plant biology', 'Climate change poses a significant threat to Somalia’s food security and stability. This review examines the complex interplay between climate change impacts, food insecurity, and conflict in Somalia. Recent climate data and forecasts paint a concerning picture: the rainfall probabilistic forecast for April- June 2024 indicates a high likelihood of above-normal rainfall across much of Somalia, thus increasing the flood risks. Concurrently, temperature forecasts project above-normal temperatures, potentially exacerbating drought conditions between the rainy seasons. Historical climatology data reveal Somalia’s vulnerability, with average temperatures ranging from 25°C to 30°C and significant seasonal variations affecting agriculture and water resources. These climate trends, combined with ongoing political instability and weak governance, have created a storm of challenges. This perspective explores how recurrent droughts and floods disrupt agricultural production, decimate livestock, and displace vulnerable populations, particularly those affecting rural and nomadic communities. It also examines how environmental stress exacerbates poverty and conflict, thereby creating a vicious cycle of vulnerability. This analysis draws on recent data on poverty rates, food expenditure patterns, and climate-related displacement, to illustrate the multifaceted nature of the crisis. Finally, this perspective proposed recommendations for building climate resilience, enhancing food security, and promoting sustainable development in Somalia, emphasizing the need for integrated approaches that combine immediate humanitarian assistance with long-term adaptation strategies.', '2026-07-07 22:08:57');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4409247985', 'plant-biology', 'Data extraction methods for systematic review (semi)automation: Update of a living systematic review', 'Background The reliable and usable (semi) automation of data extraction can support the field of systematic review by reducing the workload required to gather information about the conduct and…', '2025', 2025, 22, 22, 'https://f1000research-files.f1000.com/manuscripts/179210/f066a662-12e8-4aff-8733-c7f9bda9d794_figure1.gif', 'https://doi.org/10.12688/f1000research.51117.3', 'repository', 'preprint', 'F1000Research', '["Lena Schmidt","Ailbhe N. Finnerty Mutlu","Rebecca Elmore","Babatunde Kazeem Olorisade","James Thomas","Julian P. T. Higgins"]', 'plant biology', 'Background The reliable and usable (semi) automation of data extraction can support the field of systematic review by reducing the workload required to gather information about the conduct and results of the included studies. This living systematic review examines published approaches for data extraction from reports of clinical studies. Methods We systematically and continually search PubMed, ACL Anthology, arXiv, OpenAlex via EPPI-Reviewer, and the dblp computer science bibliography databases. Full text screening and data extraction are conducted using a mix of open-source and commercial tools. This living review update includes publications up to August 2024 and OpenAlex content up to September 2024. Results 117 publications are included in this review. Of these, 30 (26%) used full texts while the rest used titles and abstracts. A total of 112 (96%) publications developed classifiers for randomised controlled trials. Over 30 entities were extracted, with PICOs (population, intervention, comparator, outcome) being the most frequently extracted. Data are available from 53 (45%), and code from 49 (42%) publications. Nine (8%) implemented publicly available tools. Conclusions This living systematic review presents an overview of (semi)automated data-extraction literature of interest to different types of literature review. We identified a broad evidence base of publications describing data extraction for interventional reviews and a small number of publications extracting other study types. Between review updates, large language models emerged as a new tool for data extraction. While facilitating access to automated extraction, they showed a trend of decreasing quality of results reporting, especially quantitative results such as recall and lower reproducibility of results. Compared with the previous update, trends such as transition to relation extraction and sharing of code and datasets stayed similar.', '2026-07-07 22:09:00');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4255052536', 'plant-biology', 'Immunoprofiling of human uterine mast cells identifies three phenotypes and expression of ERβ and glucocorticoid receptor', 'Background: Human mast cells (MCs) are long-lived tissue-resident immune cells characterised by granules containing the proteases chymase and/or tryptase. Their phenotype is modulated by their tissue…', '2017', 2017, 22, 22, 'https://f1000research-files.f1000.com/manuscripts/12343/8a25f2ab-6f83-474a-8640-f5555a91ec0f_figure1.gif', 'https://doi.org/10.12688/f1000research.11432.1', 'repository', 'preprint', 'F1000Research', '["Bianca De Leo","Arantza Esnal‐Zufiaurre","Frances Collins","Hilary Critchley","Philippa T. K. Saunders"]', 'plant biology', 'Background: Human mast cells (MCs) are long-lived tissue-resident immune cells characterised by granules containing the proteases chymase and/or tryptase. Their phenotype is modulated by their tissue microenvironment. The human uterus has an outer muscular layer (the myometrium) surrounding the endometrium, both of which play an important role in supporting a pregnancy. The endometrium is a sex steroid target tissue consisting of epithelial cells (luminal, glandular) surrounded by a multicellular stroma, with the latter containing an extensive vascular compartment as well as fluctuating populations of immune cells that play an important role in regulating tissue function. The role of MCs in the human uterus is poorly understood with little known about their regulation or the impact of steroids on their differentiation status. The current study had two aims: 1) To investigate the spatial and temporal location of uterine MCs and determine their phenotype; 2) To determine whether MCs express receptors for steroids implicated in uterine function, including oestrogen (ERα, ERβ), progesterone (PR) and glucocorticoids (GR). Methods: Tissue samples from women (n=46) were used for RNA extraction or fixed for immunohistochemistry. Results: Messenger RNAs encoded by TPSAB1 (tryptase) and CMA1 (chymase) were detected in endometrial tissue homogenates. Immunohistochemistry revealed the relative abundance of tryptase MCs was myometrium&gt;basal endometrium&gt;functional endometrium. We show for the first time that uterine MCs are predominantly of the classical MC subtypes: (positive, +; negative, -) tryptase+/chymase- and tryptase+/chymase+, but a third subtype was also identified (tryptase-/chymase+). Tryptase+ MCs were of an ERβ+/ERα-/PR-/GR+ phenotype mirroring other uterine immune cell populations, including natural killer cells. Conclusions: Endometrial tissue resident immune MCs have three protease-specific phenotypes. Expression of both ERβ and GR in MCs mirrors that of other immune cells in the endometrium and suggests that MC function may be altered by the local steroid microenvironment.', '2026-07-07 22:09:03');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2978346165', 'biology', 'Digital transformation: A multidisciplinary reflection and research agenda', 'Digital transformation and resultant business model innovation have fundamentally altered consumers’ expectations and behaviors, putting immense pressure on traditional firms, and disrupting numerous…', '2019', 2019, 4782, 4782, 'https://ars.els-cdn.com/content/image/1-s2.0-S0148296319305478-gr1.jpg', 'https://doi.org/10.1016/j.jbusres.2019.09.022', 'repository', 'article', 'Journal of Business Research', '["Peter C. Verhoef","Thijs Broekhuizen","Yakov Bart","Abhi Bhattacharya","John Qi Dong","Nicolai Etienne Fabian","Michael Haenlein"]', 'biology', 'Digital transformation and resultant business model innovation have fundamentally altered consumers’ expectations and behaviors, putting immense pressure on traditional firms, and disrupting numerous markets. Drawing on extant literature, we identify three stages of digital transformation: digitization, digitalization, and digital transformation. We identify and delineate growth strategies for digital firms as well as the assets and capabilities required in order to successfully transform digitally. We posit that digital transformation requires specific organizational structures and bears consequences for the metrics used to calibrate performance. Finally, we provide a research agenda to stimulate and guide future research on digital transformation.', '2026-07-07 22:09:05');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2912990441', 'biology', 'SignalP 5.0 improves signal peptide predictions using deep neural networks', 'SignalP 5.0 improves signal peptide predictions using deep neural networks', '2019', 2019, 4708, 4708, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41587-019-0036-z/MediaObjects/41587_2019_36_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/30778233', 'repository', 'article', 'Nature Biotechnology', '["José Juan Almagro Armenteros","Konstantinos D. Tsirigos","Casper Kaae Sønderby","Thomas Nordahl Petersen","Ole Winther","Søren Brunak","Gunnar von Heijne","Henrik Nielsen"]', 'biology', NULL, '2026-07-07 22:09:18');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2920925854', 'biology', 'INFOGEST static in vitro simulation of gastrointestinal food digestion', 'Developing a mechanistic understanding of the impact of food structure and composition on human health has increasingly involved simulating digestion in the upper gastrointestinal tract. These…', '2019', 2019, 4698, 4698, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41596-018-0119-1/MediaObjects/41596_2018_119_Fig1_HTML.png', 'https://hal.science/hal-02073386', 'repository', 'article', 'Nature Protocols', '["André Brodkorb","Lotti Egger","Marie Alminger","Paula Alvito","Ricardo Assunção","Simon Ballance","Torsten Bohn","Claire Bourlieu‐Lacanal","Rachel Boutrou","Frédéric Carrière","Alfonso Clemente","Milena Corredig","Didier Dupont","Claire Dufour","Cathrina H. Edwards","Matt Golding","Sibel Karakaya","Bente Kirkhus","Steven Le Feunteun","Uri Lesmes","Adam Macierzanka","Alan R. Mackie","Carla Martins","Sébastien Marze","David Julian McClements","Olivia Ménard","Mans Minekus","Reto Portmann","Cláudia Nunes dos Santos","Isabelle Souchon","R. Paul Singh","Gerd E. Vegarud","Martin Wickham","Werner Weitschies","Isidra Recio"]', 'biology', 'Developing a mechanistic understanding of the impact of food structure and composition on human health has increasingly involved simulating digestion in the upper gastrointestinal tract. These simulations have used a wide range of different conditions that often have very little physiological relevance, and this impedes the meaningful comparison of results. The standardized protocol presented here is based on an international consensus developed by the COST INFOGEST network. The method is designed to be used with standard laboratory equipment and requires limited experience to encourage a wide range of researchers to adopt it. It is a static digestion method that uses constant ratios of meal to digestive fluids and a constant pH for each step of digestion. This makes the method simple to use but not suitable for simulating digestion kinetics. Using this method, food samples are subjected to sequential oral, gastric and intestinal digestion while parameters such as electrolytes, enzymes, bile, dilution, pH and time of digestion are based on available physiological data. This amended and improved digestion method (INFOGEST 2.0) avoids challenges associated with the original method, such as the inclusion of the oral phase and the use of gastric lipase. The method can be used to assess the endpoints resulting from digestion of foods by analyzing the digestion products (e.g., peptides/amino acids, fatty acids, simple sugars) and evaluating the release of micronutrients from the food matrix. The whole protocol can be completed in ~7 d, including ~5 d required for the determination of enzyme activities.', '2026-07-07 22:09:18');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2195783463', 'biology', 'An atlas of genetic correlations across human diseases and traits', 'An atlas of genetic correlations across human diseases and traits', '2015', 2015, 4706, 4706, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fng.3406/MediaObjects/41588_2015_Article_BFng3406_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4797329', 'pmc', 'article', 'Nature Genetics', '["Brendan Bulik‐Sullivan","Hilary K. Finucane","Verneri Anttila","Alexander Gusev","Felix R. Day","Po‐Ru Loh","Laramie E. Duncan","John R. B. Perry","Nick Patterson","Elise Robinson","Mark J. Daly","Alkes L. Price","Benjamin M. Neale"]', 'biology', NULL, '2026-07-07 22:09:18');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2981137429', 'biology', 'Search-and-replace genome editing without double-strand breaks or donor DNA', 'Search-and-replace genome editing without double-strand breaks or donor DNA', '2019', 2019, 4698, 4698, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-019-1711-4/MediaObjects/41586_2019_1711_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6907074', 'pmc', 'article', 'Nature', '["Andrew V. Anzalone","Peyton B. Randolph","Jessie R. Davis","Alexander A. Sousa","Luke W. Koblan","Jonathan M. Levy","Peter J. Chen","Christopher Wilson","Gregory A. Newby","Aditya Raguram","David R. Liu"]', 'biology', NULL, '2026-07-07 22:09:18');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2197124664', 'biology', 'Differential analyses for RNA-seq: transcript-level estimates improve gene-level inferences', 'High-throughput sequencing of cDNA (RNA-seq) is used extensively to characterize the transcriptome of cells. Many transcriptomic studies aim at comparing either abundance levels or the transcriptome…', '2015', 2015, 4374, 4374, 'https://f1000research-files.f1000.com/manuscripts/8143/fa54b4f8-fda8-465b-8db5-b544644b10ee_figure1.gif', 'https://doi.org/10.12688/f1000research.7563.1', 'repository', 'preprint', 'F1000Research', '["Charlotte Soneson","Michael I. Love","Mark D. Robinson"]', 'biology', 'High-throughput sequencing of cDNA (RNA-seq) is used extensively to characterize the transcriptome of cells. Many transcriptomic studies aim at comparing either abundance levels or the transcriptome composition between given conditions, and as a first step, the sequencing reads must be used as the basis for abundance quantification of transcriptomic features of interest, such as genes or transcripts. Several different quantification approaches have been proposed, ranging from simple counting of reads that overlap given genomic regions to more complex estimation of underlying transcript abundances. In this paper, we show that gene-level abundance estimates and statistical inference offer advantages over transcript-level analyses, in terms of performance and interpretability. We also illustrate that while the presence of differential isoform usage can lead to inflated false discovery rates in differential expression analyses on simple count matrices and transcript-level abundance estimates improve the performance in simulated data, the difference is relatively minor in several real data sets. Finally, we provide an R package ( tximport ) to help users integrate transcript-level abundance estimates from common quantification pipelines into count-based statistical inference engines.', '2026-07-07 22:10:21');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4253599726', 'plant-biology', 'Open laboratory notebooks: good for science, good for society, good for scientists', 'The fundamental goal of the growing open science movement is to increase the efficiency of the global scientific community and accelerate progress and discoveries for the common good. Central to this…', '2019', 2019, 21, 21, 'https://f1000research-files.f1000.com/manuscripts/19363/11eae4f9-0029-44ce-906b-947fcbdd316b_figure1.gif', 'https://doi.org/10.12688/f1000research.17710.1', 'repository', 'preprint', 'F1000Research', '["Matthieu Schapira","Rachel Harding"]', 'plant biology', 'The fundamental goal of the growing open science movement is to increase the efficiency of the global scientific community and accelerate progress and discoveries for the common good. Central to this principle is the rapid disclosure of research outputs in open-access peer-reviewed journals and on pre-print servers. The next bold step in this direction is open laboratory notebooks, where research scientists share their research — including detailed protocols, negative and positive results — online and in near-real-time to synergize with their peers. Here, we highlight the benefits of open lab notebooks to science, society and scientists, and discuss the challenges that this nascent movement is facing. We also present the implementation and progress of our own initiative at openlabnotebooks.org, with more than 20 active contributors after one year of operation.', '2026-07-07 22:10:46');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2051314902', 'biology', 'MAGMA: Generalized Gene-Set Analysis of GWAS Data', 'By aggregating data for complex traits in a biologically meaningful way, gene and gene-set analysis constitute a valuable addition to single-marker analysis. However, although various methods for…', '2015', 2015, 4035, 4035, 'https://journals.plos.org/ploscompbiol/article/figure/image?size=large&id=10.1371/journal.pcbi.1004219.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4401657', 'pmc', 'article', 'PLoS Computational Biology', '["Christiaan de Leeuw","Joris M. Mooij","Tom Heskes","Daniëlle Posthuma"]', 'biology', 'By aggregating data for complex traits in a biologically meaningful way, gene and gene-set analysis constitute a valuable addition to single-marker analysis. However, although various methods for gene and gene-set analysis currently exist, they generally suffer from a number of issues. Statistical power for most methods is strongly affected by linkage disequilibrium between markers, multi-marker associations are often hard to detect, and the reliance on permutation to compute p-values tends to make the analysis computationally very expensive. To address these issues we have developed MAGMA, a novel tool for gene and gene-set analysis. The gene analysis is based on a multiple regression model, to provide better statistical performance. The gene-set analysis is built as a separate layer around the gene analysis for additional flexibility. This gene-set analysis also uses a regression structure to allow generalization to analysis of continuous properties of genes and simultaneous analysis of multiple gene sets and other gene properties. Simulations and an analysis of Crohn''s Disease data are used to evaluate the performance of MAGMA and to compare it to a number of other gene and gene-set analysis tools. The results show that MAGMA has significantly more power than other tools for both the gene and the gene-set analysis, identifying more genes and gene sets associated with Crohn''s Disease while maintaining a correct type 1 error rate. Moreover, the MAGMA analysis of the Crohn''s Disease data was found to be considerably faster as well.', '2026-07-07 22:10:51');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2470481127', 'biology', 'Global Prevalence of Chronic Kidney Disease – A Systematic Review and Meta-Analysis', 'Chronic kidney disease (CKD) is a global health burden with a high economic cost to health systems and is an independent risk factor for cardiovascular disease (CVD). All stages of CKD are associated…', '2016', 2016, 4008, 4008, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0158765.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4934905', 'pmc', 'review', 'PLoS ONE', '["Nathan R. Hill","Samuel Fatoba","Jason Oke","Jennifer Hirst","Christopher A. O’Callaghan","Daniel Lasserson","Richard Hobbs"]', 'biology', 'Chronic kidney disease (CKD) is a global health burden with a high economic cost to health systems and is an independent risk factor for cardiovascular disease (CVD). All stages of CKD are associated with increased risks of cardiovascular morbidity, premature mortality, and/or decreased quality of life. CKD is usually asymptomatic until later stages and accurate prevalence data are lacking. Thus we sought to determine the prevalence of CKD globally, by stage, geographical location, gender and age. A systematic review and meta-analysis of observational studies estimating CKD prevalence in general populations was conducted through literature searches in 8 databases. We assessed pooled data using a random effects model. Of 5,842 potential articles, 100 studies of diverse quality were included, comprising 6,908,440 patients. Global mean(95%CI) CKD prevalence of 5 stages 13·4%(11·7-15·1%), and stages 3-5 was 10·6%(9·2-12·2%). Weighting by study quality did not affect prevalence estimates. CKD prevalence by stage was Stage-1 (eGFR>90+ACR>30): 3·5% (2·8-4·2%); Stage-2 (eGFR 60-89+ACR>30): 3·9% (2·7-5·3%); Stage-3 (eGFR 30-59): 7·6% (6·4-8·9%); Stage-4 = (eGFR 29-15): 0·4% (0·3-0·5%); and Stage-5 (eGFR<15): 0·1% (0·1-0·1%). CKD has a high global prevalence with a consistent estimated global CKD prevalence of between 11 to 13% with the majority stage 3. Future research should evaluate intervention strategies deliverable at scale to delay the progression of CKD and improve CVD outcomes.', '2026-07-07 22:11:04');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2533508881', 'biology', 'Estimating the population abundance of tissue-infiltrating immune and stromal cell populations using gene expression', 'We introduce the Microenvironment Cell Populations-counter (MCP-counter) method, which allows the robust quantification of the absolute abundance of eight immune and two stromal cell populations in…', '2016', 2016, 4011, 4011, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs13073-020-00783-w/MediaObjects/13073_2020_783_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5073889', 'pmc', 'article', 'Genome biology', '["Étienne Becht","Nicolás A. Giraldo","Laetitia Lacroix","Bénédicte Buttard","Nabila Elarouci","Florent Petitprez","Janick Sèlves","Pierre Laurent‐Puig","Catherine Sautès‐Fridman","Wolf H. Fridman","Aurélien de Reyniès"]', 'biology', 'We introduce the Microenvironment Cell Populations-counter (MCP-counter) method, which allows the robust quantification of the absolute abundance of eight immune and two stromal cell populations in heterogeneous tissues from transcriptomic data. We present in vitro mRNA mixture and ex vivo immunohistochemical data that quantitatively support the validity of our method''s estimates. Additionally, we demonstrate that MCP-counter overcomes several limitations or weaknesses of previously proposed computational approaches. MCP-counter is applied to draw a global picture of immune infiltrates across human healthy tissues and non-hematopoietic human tumors and recapitulates microenvironment-based patient stratifications associated with overall survival in lung adenocarcinoma and colorectal and breast cancer.', '2026-07-07 22:11:06');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4406847215', 'plant-biology', 'Multifunctional Role of Cytokinin in Horticultural Crops', 'Cytokinins (CKs) are a class of phytohormones identified in the early 1960s and are mainly responsible for stimulating cell division. Following the discovery, research to help understand the…', '2025', 2025, 21, 21, 'https://pub.mdpi-res.com/ijms/ijms-26-01037/article_deploy/html/images/ijms-26-01037-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/11816932', 'pmc', 'review', 'International Journal of Molecular Sciences', '["Shahid Hussain","Jingjing Chang","Jing Li","Lei Chen","Sheraz Ahmad","Zhao Song","Baige Zhang","Xiao Chen"]', 'plant biology', 'Cytokinins (CKs) are a class of phytohormones identified in the early 1960s and are mainly responsible for stimulating cell division. Following the discovery, research to help understand the pluralistic roles of CKs in plant growth and stress biology increased. With their fascinating ability, CKs serve as an important element in regulating the defense-growth trade-off. Herein, we demonstrate how the CK fine-tuning the organogenesis of different parts of horticultural plants is discussed. CK''s role in tailoring reproductive biology (flowering, sex differentiation, fruit set, and fruit attributes) has been presented. An extensive explanation of the CK-mediated response of horticultural crops to abiotic (temperature, drought, and salinity) and biotic stresses (fungal, bacterial, and nematodes) is provided. Finally, we posit the unexplored roles of CKs and highlight the research gaps worth addressing.', '2026-07-07 22:11:07');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3017049640', 'biology', 'RepeatModeler2 for automated genomic discovery of transposable element families', 'The accelerating pace of genome sequencing throughout the tree of life is driving the need for improved unsupervised annotation of genome components such as transposable elements (TEs). Because the…', '2020', 2020, 4005, 4005, 'https://cdn.ncbi.nlm.nih.gov/pmc/blobs/4437/7196820/1242febb3f4b/pnas.1921046117fig01.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7196820', 'pmc', 'article', 'Proceedings of the National Academy of Sciences', '["Jullien M. Flynn","Robert Hubley","Clément Goubert","Jeb Rosen","Andrew G. Clark","Cédric Feschotte","Arian F. A. Smit"]', 'biology', 'The accelerating pace of genome sequencing throughout the tree of life is driving the need for improved unsupervised annotation of genome components such as transposable elements (TEs). Because the types and sequences of TEs are highly variable across species, automated TE discovery and annotation are challenging and time-consuming tasks. A critical first step is the de novo identification and accurate compilation of sequence models representing all of the unique TE families dispersed in the genome. Here we introduce RepeatModeler2, a pipeline that greatly facilitates this process. This program brings substantial improvements over the original version of RepeatModeler, one of the most widely used tools for TE discovery. In particular, this version incorporates a module for structural discovery of complete long terminal repeat (LTR) retroelements, which are widespread in eukaryotic genomes but recalcitrant to automated identification because of their size and sequence complexity. We benchmarked RepeatModeler2 on three model species with diverse TE landscapes and high-quality, manually curated TE libraries: Drosophila melanogaster (fruit fly), Danio rerio (zebrafish), and Oryza sativa (rice). In these three species, RepeatModeler2 identified approximately 3 times more consensus sequences matching with &gt;95% sequence identity and sequence coverage to the manually curated sequences than the original RepeatModeler. As expected, the greatest improvement is for LTR retroelements. Thus, RepeatModeler2 represents a valuable addition to the genome annotation toolkit that will enhance the identification and study of TEs in eukaryotic genome sequences. RepeatModeler2 is available as source code or a containerized package under an open license ( https://github.com/Dfam-consortium/RepeatModeler, http://www.repeatmasker.org/RepeatModeler/ ).', '2026-07-07 22:11:11');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2950985821', 'biology', 'mixOmics: An R package for ‘omics feature selection and multiple data integration', 'The advent of high throughput technologies has led to a wealth of publicly available ''omics data coming from different sources, such as transcriptomics, proteomics, metabolomics. Combining such…', '2017', 2017, 3943, 3943, 'https://journals.plos.org/ploscompbiol/article/figure/image?size=large&id=10.1371/journal.pcbi.1005752.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5687754', 'pmc', 'article', 'PLoS Computational Biology', '["Florian Rohart","Benoît Gautier","Amrit Singh","Kim‐Anh Lê Cao"]', 'biology', 'The advent of high throughput technologies has led to a wealth of publicly available ''omics data coming from different sources, such as transcriptomics, proteomics, metabolomics. Combining such large-scale biological data sets can lead to the discovery of important biological insights, provided that relevant information can be extracted in a holistic manner. Current statistical approaches have been focusing on identifying small subsets of molecules (a ''molecular signature'') to explain or predict biological conditions, but mainly for a single type of ''omics. In addition, commonly used methods are univariate and consider each biological feature independently. We introduce mixOmics, an R package dedicated to the multivariate analysis of biological data sets with a specific focus on data exploration, dimension reduction and visualisation. By adopting a systems biology approach, the toolkit provides a wide range of methods that statistically integrate several data sets at once to probe relationships between heterogeneous ''omics data sets. Our recent methods extend Projection to Latent Structure (PLS) models for discriminant analysis, for data integration across multiple ''omics data or across independent studies, and for the identification of molecular signatures. We illustrate our latest mixOmics integrative frameworks for the multivariate analyses of ''omics data available from the package.', '2026-07-07 22:11:18');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2795989238', 'biology', 'An Integrated TCGA Pan-Cancer Clinical Data Resource to Drive High-Quality Survival Outcome Analytics', 'An Integrated TCGA Pan-Cancer Clinical Data Resource to Drive High-Quality Survival Outcome Analytics', '2018', 2018, 3953, 3953, 'https://ars.els-cdn.com/content/image/1-s2.0-S0092867418302290-fx1.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6066282', 'pmc', 'article', 'Cell', '["Jianfang Liu","Tara M. Lichtenberg","Katherine A. Hoadley","Laila Poisson","Alexander J. Lazar","Andrew D. Cherniack","Albert J. Kovatich","Christopher C. Benz","Douglas A. Levine","Adrian V. Lee","Larsson Omberg","Denise M. Wolf","Craig D. Shriver","Vésteinn Thórsson","Rory Johnson","John A. Demchok","Ina Felau","Melpomeni Kasapi","Martin L. Ferguson","Carolyn M. Hutter","Heidi J. Sofia","Roy Tarnuzzer","Zhining Wang","Liming Yang","Jean C. Zenklusen","Jiashan Zhang","Sudha Chudamani","Jia Liu","Laxmi Lolla","Rashi Naresh","Todd Pihl","Qiang Sun","Yunhu Wan","Ye Wu","Juok Cho","Timothy Defreitas","Scott Frazer","Nils Gehlenborg","Gad Getz","David I. Heiman","Jaegil Kim","Michael S. Lawrence","Pei Lin","Sam Meier","Michael S. Noble","Gordon Saksena","Doug Voet","Hailei Zhang","Brady Bernard","Nyasha Chambwe","Varsha Dhankani","Theo Knijnenburg","Roger Kramer","Kalle Leinonen","Yuexin Liu","Michael B. Miller","Sheila M. Reynolds","Ilya Shmulevich","Vesteinn Thorsson","Wei Zhang","Rehan Akbani","Bradley M. Broom","Apurva M. Hegde","Zhenlin Ju","Rupa S. Kanchi","Anil Korkut","Jun Li","Han Liang","Shiyun Ling","Wenbin Liu","Yiling Lu","Gordon B. Mills","Kwok-Shing Ng","Arvind Rao","Michael Ryan","Jing Wang","John N. Weinstein","Jiexin Zhang","Adam Abeshouse","Joshua Armenia","Debyani Chakravarty","Walid K. Chatila","Ino de Bruijn","Galen F. Gao","Benjamin E. Gross","Zachary Heins","Ritika Kundra","Konnor La","Marc Ladanyi","Augustin Luna","Moriah G. Nissan","Angelica Ochoa","Sarah Phillips","Ed Reznik","Francisco Sánchez-Vega","Chris Sander","Nikolaus Schultz","Robert E. Sheridan","S. Onur Sumer","Yichao Sun"]', 'biology', NULL, '2026-07-07 22:11:20');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3027658010', 'biology', 'Interaction between microbiota and immunity in health and disease', 'The interplay between the commensal microbiota and the mammalian immune system development and function includes multifold interactions in homeostasis and disease. The microbiome plays critical roles…', '2020', 2020, 3893, 3893, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41422-020-0332-7/MediaObjects/41422_2020_332_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7264227', 'pmc', 'review', 'Cell Research', '["Danping Zheng","Timur Liwinski","Eran Elinav"]', 'biology', 'The interplay between the commensal microbiota and the mammalian immune system development and function includes multifold interactions in homeostasis and disease. The microbiome plays critical roles in the training and development of major components of the host''s innate and adaptive immune system, while the immune system orchestrates the maintenance of key features of host-microbe symbiosis. In a genetically susceptible host, imbalances in microbiota-immunity interactions under defined environmental contexts are believed to contribute to the pathogenesis of a multitude of immune-mediated disorders. Here, we review features of microbiome-immunity crosstalk and their roles in health and disease, while providing examples of molecular mechanisms orchestrating these interactions in the intestine and extra-intestinal organs. We highlight aspects of the current knowledge, challenges and limitations in achieving causal understanding of host immune-microbiome interactions, as well as their impact on immune-mediated diseases, and discuss how these insights may translate towards future development of microbiome-targeted therapeutic interventions.', '2026-07-07 22:11:34');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2529052661', 'biology', 'TrackMate: An open and extensible platform for single-particle tracking', 'We present TrackMate, an open source Fiji plugin for the automated, semi-automated, and manual tracking of single-particles. It offers a versatile and modular solution that works out of the box for…', '2016', 2016, 3773, 3773, 'https://ars.els-cdn.com/content/image/1-s2.0-S1046202316303346-fx1.jpg', 'https://pasteur.hal.science/pasteur-01799353', 'repository', 'article', 'Methods', '["Jean-Yves Tinévez","Nick Perry","Johannes Schindelin","Genevieve M. Hoopes","Gregory D. Reynolds","Emmanuel Laplantine","Sebastian Y. Bednarek","Spencer Shorte","Kevin W. Eliceiri"]', 'biology', 'We present TrackMate, an open source Fiji plugin for the automated, semi-automated, and manual tracking of single-particles. It offers a versatile and modular solution that works out of the box for end users, through a simple and intuitive user interface. It is also easily scriptable and adaptable, operating equally well on 1D over time, 2D over time, 3D over time, or other single and multi-channel image variants. TrackMate provides several visualization and analysis tools that aid in assessing the relevance of results. The utility of TrackMate is further enhanced through its ability to be readily customized to meet specific tracking problems. TrackMate is an extensible platform where developers can easily write their own detection, particle linking, visualization or analysis algorithms within the TrackMate environment. This evolving framework provides researchers with the opportunity to quickly develop and optimize new algorithms based on existing TrackMate modules without the need of having to write de novo user interfaces, including visualization, analysis and exporting tools. The current capabilities of TrackMate are presented in the context of three different biological problems. First, we perform Caenorhabditis-elegans lineage analysis to assess how light-induced damage during imaging impairs its early development. Our TrackMate-based lineage analysis indicates the lack of a cell-specific light-sensitive mechanism. Second, we investigate the recruitment of NEMO (NF-κB essential modulator) clusters in fibroblasts after stimulation by the cytokine IL-1 and show that photodamage can generate artifacts in the shape of TrackMate characterized movements that confuse motility analysis. Finally, we validate the use of TrackMate for quantitative lifetime analysis of clathrin-mediated endocytosis in plant cells.', '2026-07-07 22:11:50');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2583342343', 'biology', 'Microplastics in freshwater and terrestrial environments: Evaluating the current understanding to identify the knowledge gaps and future research priorities', 'Microplastics in freshwater and terrestrial environments: Evaluating the current understanding to identify the knowledge gaps and future research priorities', '2017', 2017, 3628, 3628, 'https://ars.els-cdn.com/content/image/1-s2.0-S0048969717302073-fx1.jpg', 'https://pubmed.ncbi.nlm.nih.gov/28169032', 'repository', 'review', 'The Science of The Total Environment', '["Alice A. Horton","Alexander Walton","David J. Spurgeon","Elma Lahive","Claus Svendsen"]', 'biology', NULL, '2026-07-07 22:12:32');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3085758516', 'biology', 'Merqury: reference-free quality, completeness, and phasing assessment for genome assemblies', 'Recent long-read assemblies often exceed the quality and completeness of available reference genomes, making validation challenging. Here we present Merqury, a novel tool for reference-free assembly…', '2020', 2020, 3552, 3552, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs13059-020-02134-9/MediaObjects/13059_2020_2134_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7488777', 'pmc', 'article', 'Genome biology', '["Arang Rhie","Brian P. Walenz","Sergey Koren","Adam M. Phillippy"]', 'biology', 'Recent long-read assemblies often exceed the quality and completeness of available reference genomes, making validation challenging. Here we present Merqury, a novel tool for reference-free assembly evaluation based on efficient k-mer set operations. By comparing k-mers in a de novo assembly to those found in unassembled high-accuracy reads, Merqury estimates base-level accuracy and completeness. For trios, Merqury can also evaluate haplotype-specific accuracy, completeness, phase block continuity, and switch errors. Multiple visualizations, such as k-mer spectrum plots, can be generated for evaluation. We demonstrate on both human and plant genomes that Merqury is a fast and robust method for assembly validation.', '2026-07-07 22:12:49');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3206377390', 'plant-biology', 'Machine learning meets pKa', 'We present a small molecule pK a prediction tool entirely written in Python. It predicts the macroscopic pK a value and is trained on a literature compilation of monoprotic compounds. Different…', '2020', 2020, 21, 21, 'https://f1000research-files.f1000.com/manuscripts/24362/6811d445-4bd8-49a9-95ad-ec460c6326eb_figure1.gif', 'https://doi.org/10.12688/f1000research.22090.1', 'repository', 'preprint', 'F1000Research', '["Marcel Baltruschat","Paul Czodrowski"]', 'plant biology', 'We present a small molecule pK a prediction tool entirely written in Python. It predicts the macroscopic pK a value and is trained on a literature compilation of monoprotic compounds. Different machine learning models were tested and random forest performed best given a five-fold cross-validation (mean absolute error=0.682, root mean squared error=1.032, correlation coefficient r 2 =0.82). We test our model on two external validation sets, where our model performs comparable to Marvin and is better than a recently published open source model. Our Python tool and all data is freely available at https://github.com/czodrowskilab/Machine-learning-meets-pKa .', '2026-07-07 22:12:55');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4390053616', 'plant-biology', 'Comparative evaluation of clinical performance, child and parental satisfaction of Bioflx, zirconia and stainless steel crowns in pediatric patients', 'Background Pediatric dental treatment is challenging in patients with early childhood caries. For clinician its difficult to manage child and provide good work at the same time. Its necessity to have…', '2023', 2023, 21, 21, 'https://f1000research-files.f1000.com/manuscripts/158784/363f0cb6-29bf-4cb2-a4a4-7bc0826c2e61_figure1.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/11190641', 'pmc', 'preprint', 'F1000Research', '["Ishani Rahate","Punit Fulzele","Nilima Thosar"]', 'plant biology', 'Background Pediatric dental treatment is challenging in patients with early childhood caries. For clinician its difficult to manage child and provide good work at the same time. Its necessity to have the best equipments as well as materials. Nowadays, aesthetics play an important role in managing decayed teeth. Zirconia crown is better option but requires excessive preparation. As Bioflx is newly developed crown and has combined stainless steel and zirconia properties. Aim To assess the clinical performance and child and parental satisfaction of Bioflex crowns compared to zirconia and stainless steel crowns. Methods In this comparative study of Bioflx crowns with zirconia and stainless steel crowns, children aged three to seven years old will be selected, and 72 primary teeth requiring crowns will be randomly distributed into three groups, n = 24: Group I: Preformed stainless steel crown, control; Group II: Preformed Bioflex crown; Group III: Preformed zirconia crown. Crowns will be evaluated for recurrent caries, plaque accumulation, restoration failure, gingival status opposing tooth wear, and clinicians and parental satisfaction at zero, three, six, and 12 months. Results Bioflx crown will have better clinical as well as parental satisfaction among zirconia and stainless steel crowns. Conclusions The Bioflx crown can be used as an alternative economical esthetic full-coronal restoration for primary teeth. Trial registration CTRI registration number: CTRI/2023/05/052256; Date of registration: May 03, 2023. Protocol version Two; Date: April 22, 2023', '2026-07-07 22:13:31');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2954782052', 'biology', 'The NLRP3 Inflammasome: An Overview of Mechanisms of Activation and Regulation', 'The NLRP3 inflammasome is a critical component of the innate immune system that mediates caspase-1 activation and the secretion of proinflammatory cytokines IL-1β/IL-18 in response to microbial…', '2019', 2019, 3452, 3452, 'https://pub.mdpi-res.com/ijms/ijms-20-03328/article_deploy/html/images/ijms-20-03328-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6651423', 'pmc', 'review', 'International Journal of Molecular Sciences', '["Nathan Kelley","Devon Jeltema","Yanhui Duan","Yuan He"]', 'biology', 'The NLRP3 inflammasome is a critical component of the innate immune system that mediates caspase-1 activation and the secretion of proinflammatory cytokines IL-1β/IL-18 in response to microbial infection and cellular damage. However, the aberrant activation of the NLRP3 inflammasome has been linked with several inflammatory disorders, which include cryopyrin-associated periodic syndromes, Alzheimer''s disease, diabetes, and atherosclerosis. The NLRP3 inflammasome is activated by diverse stimuli, and multiple molecular and cellular events, including ionic flux, mitochondrial dysfunction, and the production of reactive oxygen species, and lysosomal damage have been shown to trigger its activation. How NLRP3 responds to those signaling events and initiates the assembly of the NLRP3 inflammasome is not fully understood. In this review, we summarize our current understanding of the mechanisms of NLRP3 inflammasome activation by multiple signaling events, and its regulation by post-translational modifications and interacting partners of NLRP3.', '2026-07-07 22:13:34');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2766208183', 'biology', 'More than 75 percent decline over 27 years in total flying insect biomass in protected areas', 'Global declines in insects have sparked wide interest among scientists, politicians, and the general public. Loss of insect diversity and abundance is expected to provoke cascading effects on food…', '2017', 2017, 3437, 3437, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0185809.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5646769', 'pmc', 'article', 'PLoS ONE', '["Caspar A. Hallmann","Martin Sorg","Eelke Jongejans","H. Siepel","Nick Hofland","Heinz Schwan","Werner Stenmans","Antoine Müller","Hubert Sumser","Thomas Hörren","Dave Goulson","Hans de Kroon"]', 'biology', 'Global declines in insects have sparked wide interest among scientists, politicians, and the general public. Loss of insect diversity and abundance is expected to provoke cascading effects on food webs and to jeopardize ecosystem services. Our understanding of the extent and underlying causes of this decline is based on the abundance of single species or taxonomic groups only, rather than changes in insect biomass which is more relevant for ecological functioning. Here, we used a standardized protocol to measure total insect biomass using Malaise traps, deployed over 27 years in 63 nature protection areas in Germany (96 unique location-year combinations) to infer on the status and trend of local entomofauna. Our analysis estimates a seasonal decline of 76%, and mid-summer decline of 82% in flying insect biomass over the 27 years of study. We show that this decline is apparent regardless of habitat type, while changes in weather, land use, and habitat characteristics cannot explain this overall decline. This yet unrecognized loss of insect biomass must be taken into account in evaluating declines in abundance of species depending on insects as a food source, and ecosystem functioning in the European landscape.', '2026-07-07 22:13:37');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2067107606', 'biology', 'Ferroptosis as a p53-mediated activity during tumour suppression', 'Ferroptosis as a p53-mediated activity during tumour suppression', '2015', 2015, 3371, 3371, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature14344/MediaObjects/41586_2015_BFnature14344_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4455927', 'pmc', 'article', 'Nature', '["Le Jiang","Ning Kon","Tongyuan Li","Shang-Jui Wang","Tao Su","Hanina Hibshoosh","Richard Baer","Wei Gu"]', 'biology', NULL, '2026-07-07 22:14:10');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2596630349', 'biology', 'Global warming and recurrent mass bleaching of corals', 'Global warming and recurrent mass bleaching of corals', '2017', 2017, 3387, 3387, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature21707/MediaObjects/41586_2017_Article_BFnature21707_Fig1_HTML.jpg', 'https://pubmed.ncbi.nlm.nih.gov/28300113', 'repository', 'article', 'Nature', '["Terry P. Hughes","James T. Kerry","Mariana Álvarez‐Noriega","Jorge G. Álvarez‐Romero","Kristen D. Anderson","Andrew H. Baird","Russell C. Babcock","Maria Beger","David R. Bellwood","Ray Berkelmans","Tom C. L. Bridge","Ian R. Butler","Maria Byrne","Neal E. Cantin","Steeve Comeau","Sean R. Connolly","Graeme S. Cumming","Steven J. Dalton","Guillermo Díaz-Pulido","C. Mark Eakin","Will F. Figueira","James Gilmour","Hugo B. Harrison","Scott F. Heron","Andrew S. Hoey","J. Hobbs","Mia O. Hoogenboom","Emma Kennedy","Chao‐Yang Kuo","Janice Lough","Ryan Lowe","Gang Liu","Malcolm T. McCulloch","Hamish A. Malcolm","Mike McWilliam","John M. Pandolfi","Rachel Pears","Morgan S. Pratchett","Verena Schoepf","Tristan Simpson","William Skirving","Brigitte Sommer","Gergely Torda","David Wachenfeld","Bette L. Willis","Shaun K. Wilson"]', 'biology', NULL, '2026-07-07 22:14:10');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2398894736', 'biology', 'Gut microbiota, metabolites and host immunity', 'Gut microbiota, metabolites and host immunity', '2016', 2016, 3368, 3368, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnri.2016.42/MediaObjects/41577_2016_Article_BFnri201642_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5541232', 'pmc', 'review', 'Nature reviews. Immunology', '["Michelle Rooks","Wendy S. Garrett"]', 'biology', NULL, '2026-07-07 22:14:11');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2161374186', 'medicine', 'Preferred reporting items for systematic review and meta-analysis protocols (PRISMA-P) 2015 statement', 'Systematic reviews should build on a protocol that describes the rationale, hypothesis, and planned methods of the review; few reviews report whether a protocol exists. Detailed, well-described…', '2015', 2015, 26593, 26593, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs13643-020-01542-z/MediaObjects/13643_2020_1542_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4320440', 'pmc', 'article', 'Systematic Reviews', '["PRISMA-P Group","David Moher","Larissa Shamseer","Mike Clarke","Davina Ghersi","Alessandro Liberati","Mark Petticrew","Paul Shekelle","Lesley Stewart"]', 'medicine', 'Systematic reviews should build on a protocol that describes the rationale, hypothesis, and planned methods of the review; few reviews report whether a protocol exists. Detailed, well-described protocols can facilitate the understanding and appraisal of the review methods, as well as the detection of modifications to methods and selective reporting in completed reviews. We describe the development of a reporting guideline, the Preferred Reporting Items for Systematic reviews and Meta-Analyses for Protocols 2015 (PRISMA-P 2015). PRISMA-P consists of a 17-item checklist intended to facilitate the preparation and reporting of a robust protocol for the systematic review. Funders and those commissioning reviews might consider mandating the use of the checklist to facilitate the submission of relevant protocol information in funding applications. Similarly, peer reviewers and editors can use the guidance to gauge the completeness and transparency of a systematic review protocol submitted for publication in a journal or other medium.', '2026-07-07 22:14:43');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2560438049', 'medicine', 'Rayyan—a web and mobile app for systematic reviews', 'BACKGROUND: Synthesis of multiple randomized controlled trials (RCTs) in a systematic review can summarize the effects of individual outcomes and provide numerical answers about the effectiveness of…', '2016', 2016, 24891, 24891, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs13643-024-02533-0/MediaObjects/13643_2024_2533_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5139140', 'pmc', 'article', 'Systematic Reviews', '["Mourad Ouzzani","Hossam M. Hammady","Zbys Fedorowicz","Ahmed K. Elmagarmid"]', 'medicine', 'BACKGROUND: Synthesis of multiple randomized controlled trials (RCTs) in a systematic review can summarize the effects of individual outcomes and provide numerical answers about the effectiveness of interventions. Filtering of searches is time consuming, and no single method fulfills the principal requirements of speed with accuracy. Automation of systematic reviews is driven by a necessity to expedite the availability of current best evidence for policy and clinical decision-making. We developed Rayyan ( http://rayyan.qcri.org ), a free web and mobile app, that helps expedite the initial screening of abstracts and titles using a process of semi-automation while incorporating a high level of usability. For the beta testing phase, we used two published Cochrane reviews in which included studies had been selected manually. Their searches, with 1030 records and 273 records, were uploaded to Rayyan. Different features of Rayyan were tested using these two reviews. We also conducted a survey of Rayyan''s users and collected feedback through a built-in feature. RESULTS: Pilot testing of Rayyan focused on usability, accuracy against manual methods, and the added value of the prediction feature. The "taster" review (273 records) allowed a quick overview of Rayyan for early comments on usability. The second review (1030 records) required several iterations to identify the previously identified 11 trials. The "suggestions" and "hints," based on the "prediction model," appeared as testing progressed beyond five included studies. Post rollout user experiences and a reflexive response by the developers enabled real-time modifications and improvements. The survey respondents reported 40% average time savings when using Rayyan compared to others tools, with 34% of the respondents reporting more than 50% time savings. In addition, around 75% of the respondents mentioned that screening and labeling studies as well as collaborating on reviews to be the two most important features of Rayyan. As of November 2016, Rayyan users exceed 2000 from over 60 countries conducting hundreds of reviews totaling more than 1.6M citations. Feedback from users, obtained mostly through the app web site and a recent survey, has highlighted the ease in exploration of searches, the time saved, and simplicity in sharing and comparing include-exclude decisions. The strongest features of the app, identified and reported in user feedback, were its ability to help in screening and collaboration as well as the time savings it affords to users. CONCLUSIONS: Rayyan is responsive and intuitive in use with significant potential to lighten the load of reviewers.', '2026-07-07 22:14:43');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2549976854', 'medicine', 'Ultrastructural Characterization of the Lower Motor System in a Mouse Model of Krabbe Disease', 'Krabbe disease (KD) is a neurodegenerative disorder caused by the lack of β- galactosylceramidase enzymatic activity and by widespread accumulation of the cytotoxic galactosyl-sphingosine in…', '2016', 2016, 13283, 13283, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41598-016-0001-8/MediaObjects/41598_2016_1_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5431369', 'pmc', 'article', 'Scientific Reports', '["Valentina Cappello","Laura Marchetti","Paola Parlanti","Silvia Landi","Ilaria Tonazzini","Marco Cecchini","Vincenzo Piazza","Mauro Gemmi"]', 'medicine', 'Krabbe disease (KD) is a neurodegenerative disorder caused by the lack of β- galactosylceramidase enzymatic activity and by widespread accumulation of the cytotoxic galactosyl-sphingosine in neuronal, myelinating and endothelial cells. Despite the wide use of Twitcher mice as experimental model for KD, the ultrastructure of this model is partial and mainly addressing peripheral nerves. More details are requested to elucidate the basis of the motor defects, which are the first to appear during KD onset. Here we use transmission electron microscopy (TEM) to focus on the alterations produced by KD in the lower motor system at postnatal day 15 (P15), a nearly asymptomatic stage, and in the juvenile P30 mouse. We find mild effects on motorneuron soma, severe ones on sciatic nerves and very severe effects on nerve terminals and neuromuscular junctions at P30, with peripheral damage being already detectable at P15. Finally, we find that the gastrocnemius muscle undergoes atrophy and structural changes that are independent of denervation at P15. Our data further characterize the ultrastructural analysis of the KD mouse model, and support recent theories of a dying-back mechanism for neuronal degeneration, which is independent of demyelination.', '2026-07-07 22:15:36');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3003217347', 'medicine', 'A new coronavirus associated with human respiratory disease in China', 'Abstract Emerging infectious diseases, such as severe acute respiratory syndrome (SARS) and Zika virus disease, present a major threat to public health 1–3. Despite intense research efforts, how,…', '2020', 2020, 12906, 12906, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-020-2008-3/MediaObjects/41586_2020_2008_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7094943', 'pmc', 'article', 'Nature', '["Fan Wu","Zhao Su","Bin Yu","Yanmei Chen","Wen Wang","Zhi-Gang Song","Yi Hu","Zhao-Wu Tao","Jun-Hua Tian","Yuan-Yuan Pei","Ming-Li Yuan","Yu-Ling Zhang","Fa-Hui Dai","Yi Liu","Qimin Wang","Jiao-Jiao Zheng","Lin Xu","Edward C. Holmes","Yǒng-Zhèn Zhāng","Yǒng-Zhèn Zhāng","Yǒng-Zhèn Zhāng"]', 'medicine', 'Abstract Emerging infectious diseases, such as severe acute respiratory syndrome (SARS) and Zika virus disease, present a major threat to public health 1–3. Despite intense research efforts, how, when and where new diseases appear are still a source of considerable uncertainty. A severe respiratory disease was recently reported in Wuhan, Hubei province, China. As of 25 January 2020, at least 1,975 cases had been reported since the first patient was hospitalized on 12 December 2019. Epidemiological investigations have suggested that the outbreak was associated with a seafood market in Wuhan. Here we study a single patient who was a worker at the market and who was admitted to the Central Hospital of Wuhan on 26 December 2019 while experiencing a severe respiratory syndrome that included fever, dizziness and a cough. Metagenomic RNA sequencing 4 of a sample of bronchoalveolar lavage fluid from the patient identified a new RNA virus strain from the family Coronaviridae, which is designated here ‘WH-Human 1’ coronavirus (and has also been referred to as ‘2019-nCoV’). Phylogenetic analysis of the complete viral genome (29,903 nucleotides) revealed that the virus was most closely related (89.1% nucleotide similarity) to a group of SARS-like coronaviruses (genus Betacoronavirus, subgenus Sarbecovirus) that had previously been found in bats in China 5. This outbreak highlights the ongoing ability of viral spill-over from animals to cause severe disease in humans.', '2026-07-07 22:15:37');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3009506062', 'medicine', 'Immediate Psychological Responses and Associated Factors during the Initial Stage of the 2019 Coronavirus Disease (COVID-19) Epidemic among the General Population in China', 'Background: The 2019 coronavirus disease (COVID-19) epidemic is a public health emergency of international concern and poses a challenge to psychological resilience. Research data are needed to…', '2020', 2020, 10265, 10265, 'https://pub.mdpi-res.com/ijerph/ijerph-17-01729/article_deploy/html/images/ijerph-17-01729-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7084952', 'pmc', 'article', 'International Journal of Environmental Research and Public Health', '["Cuiyan Wang","Riyu Pan","Xiaoyang Wan","Yilin Tan","Linkang Xu","Cyrus S. H. Ho","Roger Ho"]', 'medicine', 'Background: The 2019 coronavirus disease (COVID-19) epidemic is a public health emergency of international concern and poses a challenge to psychological resilience. Research data are needed to develop evidence-driven strategies to reduce adverse psychological impacts and psychiatric symptoms during the epidemic. The aim of this study was to survey the general public in China to better understand their levels of psychological impact, anxiety, depression, and stress during the initial stage of the COVID-19 outbreak. The data will be used for future reference. Methods: From 31 January to 2 February 2020, we conducted an online survey using snowball sampling techniques. The online survey collected information on demographic data, physical symptoms in the past 14 days, contact history with COVID-19, knowledge and concerns about COVID-19, precautionary measures against COVID-19, and additional information required with respect to COVID-19. Psychological impact was assessed by the Impact of Event Scale-Revised (IES-R), and mental health status was assessed by the Depression, Anxiety and Stress Scale (DASS-21). Results: This study included 1210 respondents from 194 cities in China. In total, 53.8% of respondents rated the psychological impact of the outbreak as moderate or severe; 16.5% reported moderate to severe depressive symptoms; 28.8% reported moderate to severe anxiety symptoms; and 8.1% reported moderate to severe stress levels. Most respondents spent 20–24 h per day at home (84.7%); were worried about their family members contracting COVID-19 (75.2%); and were satisfied with the amount of health information available (75.1%). Female gender, student status, specific physical symptoms (e.g., myalgia, dizziness, coryza), and poor self-rated health status were significantly associated with a greater psychological impact of the outbreak and higher levels of stress, anxiety, and depression (p &lt; 0.05). Specific up-to-date and accurate health information (e.g., treatment, local outbreak situation) and particular precautionary measures (e.g., hand hygiene, wearing a mask) were associated with a lower psychological impact of the outbreak and lower levels of stress, anxiety, and depression (p &lt; 0.05). Conclusions: During the initial phase of the COVID-19 outbreak in China, more than half of the respondents rated the psychological impact as moderate-to-severe, and about one-third reported moderate-to-severe anxiety. Our findings identify factors associated with a lower level of psychological impact and better mental health status that can be used to formulate psychological interventions to improve the mental health of vulnerable groups during the COVID-19 epidemic.', '2026-07-07 22:16:22');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2895486342', 'medicine', 'The UK Biobank resource with deep phenotyping and genomic data', 'The UK Biobank project is a prospective cohort study with deep genetic and phenotypic data collected on approximately 500,000 individuals from across the United Kingdom, aged between 40 and 69 at…', '2018', 2018, 9800, 9800, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-018-0579-z/MediaObjects/41586_2018_579_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6786975', 'pmc', 'article', 'Nature', '["Clare Bycroft","Colin Freeman","Desislava Petkova","Gavin Band","Lloyd T. Elliott","Kevin Sharp","Allan Motyer","Damjan Vukcevic","Olivier Delaneau","Jared O’Connell","Adrián Cortés","Samantha Welsh","A. P. Young","Mark Effingham","Gil McVean","Stephen Leslie","Naomi E. Allen","Peter Donnelly","Jonathan Marchini"]', 'medicine', 'The UK Biobank project is a prospective cohort study with deep genetic and phenotypic data collected on approximately 500,000 individuals from across the United Kingdom, aged between 40 and 69 at recruitment. The open resource is unique in its size and scope. A rich variety of phenotypic and health-related information is available on each participant, including biological measurements, lifestyle indicators, biomarkers in blood and urine, and imaging of the body and brain. Follow-up information is provided by linking health and medical records. Genome-wide genotype data have been collected on all participants, providing many opportunities for the discovery of new genetic associations and the genetic bases of complex traits. Here we describe the centralized analysis of the genetic data, including genotype quality, properties of population structure and relatedness of the genetic data, and efficient phasing and genotype imputation that increases the number of testable variants to around 96 million. Classical allelic variation at 11 human leukocyte antigen genes was imputed, resulting in the recovery of signals with known associations between human leukocyte antigen alleles and many diseases.', '2026-07-07 22:16:25');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3011610993', 'medicine', 'Risk Factors Associated With Acute Respiratory Distress Syndrome and Death in Patients With Coronavirus Disease 2019 Pneumonia in Wuhan, China', 'Importance: Coronavirus disease 2019 (COVID-19) is an emerging infectious disease that was first reported in Wuhan, China, and has subsequently spread worldwide. Risk factors for the clinical…', '2020', 2020, 8750, 8750, 'https://cdn.ncbi.nlm.nih.gov/pmc/blobs/8359/7070509/8536f715eac7/jamainternmed-180-934-g001.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7070509', 'pmc', 'article', 'JAMA Internal Medicine', '["Chaomin Wu","Xiaoyan Chen","Yanping Cai","Jiaan Xia","Xing Zhou","Sha Xu","Han-Ping Huang","Li Zhang","Xia Zhou","Chunling Du","Yuye Zhang","Juan Song","Sijiao Wang","Yencheng Chao","Zeyong Yang","Jie Xu","Xin Zhou","Dechang Chen","Weining Xiong","Lei Xu","Feng Zhou","Jinjun Jiang","Chunxue Bai","Junhua Zheng","Yuanlin Song"]', 'medicine', 'Importance: Coronavirus disease 2019 (COVID-19) is an emerging infectious disease that was first reported in Wuhan, China, and has subsequently spread worldwide. Risk factors for the clinical outcomes of COVID-19 pneumonia have not yet been well delineated. Objective: To describe the clinical characteristics and outcomes in patients with COVID-19 pneumonia who developed acute respiratory distress syndrome (ARDS) or died. Design, Setting, and Participants: Retrospective cohort study of 201 patients with confirmed COVID-19 pneumonia admitted to Wuhan Jinyintan Hospital in China between December 25, 2019, and January 26, 2020. The final date of follow-up was February 13, 2020. Exposures: Confirmed COVID-19 pneumonia. Main Outcomes and Measures: The development of ARDS and death. Epidemiological, demographic, clinical, laboratory, management, treatment, and outcome data were also collected and analyzed. Results: Of 201 patients, the median age was 51 years (interquartile range, 43-60 years), and 128 (63.7%) patients were men. Eighty-four patients (41.8%) developed ARDS, and of those 84 patients, 44 (52.4%) died. In those who developed ARDS, compared with those who did not, more patients presented with dyspnea (50 of 84 [59.5%] patients and 30 of 117 [25.6%] patients, respectively [difference, 33.9%; 95% CI, 19.7%-48.1%]) and had comorbidities such as hypertension (23 of 84 [27.4%] patients and 16 of 117 [13.7%] patients, respectively [difference, 13.7%; 95% CI, 1.3%-26.1%]) and diabetes (16 of 84 [19.0%] patients and 6 of 117 [5.1%] patients, respectively [difference, 13.9%; 95% CI, 3.6%-24.2%]). In bivariate Cox regression analysis, risk factors associated with the development of ARDS and progression from ARDS to death included older age (hazard ratio [HR], 3.26; 95% CI 2.08-5.11; and HR, 6.17; 95% CI, 3.26-11.67, respectively), neutrophilia (HR, 1.14; 95% CI, 1.09-1.19; and HR, 1.08; 95% CI, 1.01-1.17, respectively), and organ and coagulation dysfunction (eg, higher lactate dehydrogenase [HR, 1.61; 95% CI, 1.44-1.79; and HR, 1.30; 95% CI, 1.11-1.52, respectively] and D-dimer [HR, 1.03; 95% CI, 1.01-1.04; and HR, 1.02; 95% CI, 1.01-1.04, respectively]). High fever (≥39 °C) was associated with higher likelihood of ARDS development (HR, 1.77; 95% CI, 1.11-2.84) and lower likelihood of death (HR, 0.41; 95% CI, 0.21-0.82). Among patients with ARDS, treatment with methylprednisolone decreased the risk of death (HR, 0.38; 95% CI, 0.20-0.72). Conclusions and Relevance: Older age was associated with greater risk of development of ARDS and death likely owing to less rigorous immune response. Although high fever was associated with the development of ARDS, it was also associated with better outcomes among patients with ARDS. Moreover, treatment with methylprednisolone may be beneficial for patients who develop ARDS.', '2026-07-07 22:16:48');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4365452398', 'plant-biology', 'Microplastic content of over-the-counter toothpastes - a systematic review', 'Background: Microplastic particles are used as ingredients in personal care products such as face washes, shower gels and toothpastes and form one of the main sources of microplastic pollution,…', '2023', 2023, 20, 20, 'https://f1000research-files.f1000.com/manuscripts/144931/c43fdc3f-4d04-4888-8a4a-66f3ea606513_figure1.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/10372460', 'pmc', 'review', 'F1000Research', '["Kavery Chengappa S","Ashwini Rao","Aparna KS","Praveen Jodalli","Ramya Shenoy"]', 'plant biology', 'Background: Microplastic particles are used as ingredients in personal care products such as face washes, shower gels and toothpastes and form one of the main sources of microplastic pollution, especially in the marine environment. In addition to being a potential pollutant to the environment, the transfer of microplastics to humans can become a severe threat to public health. This systematic review was conceptualized to identify evidence for the presence of and characteristics of microplastics in toothpaste formulations. Methods: The PICOS Criteria was used for including studies for the review. Electronic databases of Scopus, Embase, Springer Link, PubMed, Web of Science and Google Scholar were searched, as well as hand and reference searching of the articles was carried out. The articles were screened using the software application, Covidence® and data was extracted. Results: This systematic review showed that toothpastes from China, Vietnam, Myanmar and the UAE, reported no evidence of microplastics and those from Malaysia, Turkey and India reported the presence of microplastics. The shape of the microplastics present in these toothpastes were found to be granular, irregular with opaque appearance and also in the form of fragments and fibers and the percentage weight in grams ranged from 0.2 to 7.24%. Malaysia releases 0.199 trillion microbeads annually from personal care products into the environment and toothpastes in Turkey release an average of 871 million grams of microplastics annually. Similarly, in India, it has been reported that 1.4 billion grams of microplastic particles are emitted annually from toothpaste. Conclusions: The findings of this systematic review provide evidence that toothpastes, at least in some parts of the world, do contain microplastics and that there is a great risk of increase in the addition of microplastics to the environment by the use of toothpaste.', '2026-07-07 22:17:07');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3014067025', 'medicine', 'Structure of the SARS-CoV-2 spike receptor-binding domain bound to the ACE2 receptor', 'Structure of the SARS-CoV-2 spike receptor-binding domain bound to the ACE2 receptor', '2020', 2020, 6724, 6724, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-020-2180-5/MediaObjects/41586_2020_2180_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/32225176', 'repository', 'article', 'Nature', '["Jun Lan","Jiwan Ge","Jinfang Yu","Sisi Shan","Huan Zhou","Shilong Fan","Qi Zhang","Xuanling Shi","Qisheng Wang","Linqi Zhang","Xinquan Wang"]', 'medicine', NULL, '2026-07-07 22:17:49');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3047144258', 'medicine', 'Factors associated with COVID-19-related death using OpenSAFELY', 'Factors associated with COVID-19-related death using OpenSAFELY', '2020', 2020, 6744, 6744, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-020-2521-4/MediaObjects/41586_2020_2521_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7611074', 'pmc', 'article', 'Nature', '["Elizabeth Williamson","Alex J Walker","Krishnan Bhaskaran","Seb Bacon","Chris Bates","Caroline E Morton","Helen J Curtis","Amir Mehrkar","David Evans","Peter Inglesby","Jonathan Cockburn","Helen McDonald","Brian MacKenna","Laurie A. Tomlinson","Ian Douglas","Christopher T. Rentsch","Rohini Mathur","Angel Wong","Richard Grieve","David A Harrison","Harriet Forbes","Anna Schultze","Richard Croker","John Parry","Frank Hester","Sam Harper","Rafael Perera","Stephen Evans","Liam Smeeth","Ben Goldacre"]', 'medicine', NULL, '2026-07-07 22:17:49');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2143463421', 'medicine', 'Principles of nanoparticle design for overcoming biological barriers to drug delivery', 'Principles of nanoparticle design for overcoming biological barriers to drug delivery', '2015', 2015, 6716, 6716, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnbt.3330/MediaObjects/41587_2015_BFnbt3330_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4978509', 'pmc', 'article', 'Nature Biotechnology', '["Elvin Blanco","Haifa Shen","Mauro Ferrari"]', 'medicine', NULL, '2026-07-07 22:17:50');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1943745580', 'medicine', 'Decision aids for people facing health treatment or screening decisions', 'BACKGROUND: Decision aids are interventions that support patients by making their decisions explicit, providing information about options and associated benefits/harms, and helping clarify congruence…', '2017', 2017, 6620, 6620, 'https://cdn.ncbi.nlm.nih.gov/pmc/blobs/4a72/6478132/a3024cb73900/nCD001431-AFig-FIG01.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6478132', 'pmc', 'review', 'Cochrane Database of Systematic Reviews', '["Dawn Stacey","France Légaré","Krystina B. Lewis","Michael J. Barry","Carol Bennett","Karen Eden","Margaret Holmes‐Rovner","Hilary A. Llewellyn‐Thomas","Anne Lyddiatt","Richard Thomson","Lyndal Trevena"]', 'medicine', 'BACKGROUND: Decision aids are interventions that support patients by making their decisions explicit, providing information about options and associated benefits/harms, and helping clarify congruence between decisions and personal values. OBJECTIVES: To assess the effects of decision aids in people facing treatment or screening decisions. SEARCH METHODS: Updated search (2012 to April 2015) in CENTRAL; MEDLINE; Embase; PsycINFO; and grey literature; includes CINAHL to September 2008. SELECTION CRITERIA: We included published randomized controlled trials comparing decision aids to usual care and/or alternative interventions. For this update, we excluded studies comparing detailed versus simple decision aids. DATA COLLECTION AND ANALYSIS: Two reviewers independently screened citations for inclusion, extracted data, and assessed risk of bias. Primary outcomes, based on the International Patient Decision Aid Standards (IPDAS), were attributes related to the choice made and the decision-making process.Secondary outcomes were behavioural, health, and health system effects.We pooled results using mean differences (MDs) and risk ratios (RRs), applying a random-effects model. We conducted a subgroup analysis of studies that used the patient decision aid to prepare for the consultation and of those that used it in the consultation. We used GRADE to assess the strength of the evidence. MAIN RESULTS: We included 105 studies involving 31,043 participants. This update added 18 studies and removed 28 previously included studies comparing detailed versus simple decision aids. During the ''Risk of bias'' assessment, we rated two items (selective reporting and blinding of participants/personnel) as mostly unclear due to inadequate reporting. Twelve of 105 studies were at high risk of bias.With regard to the attributes of the choice made, decision aids increased participants'' knowledge (MD 13.27/100; 95% confidence interval (CI) 11.32 to 15.23; 52 studies; N = 13,316; high-quality evidence), accuracy of risk perceptions (RR 2.10; 95% CI 1.66 to 2.66; 17 studies; N = 5096; moderate-quality evidence), and congruency between informed values and care choices (RR 2.06; 95% CI 1.46 to 2.91; 10 studies; N = 4626; low-quality evidence) compared to usual care.Regarding attributes related to the decision-making process and compared to usual care, decision aids decreased decisional conflict related to feeling uninformed (MD -9.28/100; 95% CI -12.20 to -6.36; 27 studies; N = 5707; high-quality evidence), indecision about personal values (MD -8.81/100; 95% CI -11.99 to -5.63; 23 studies; N = 5068; high-quality evidence), and the proportion of people who were passive in decision making (RR 0.68; 95% CI 0.55 to 0.83; 16 studies; N = 3180; moderate-quality evidence).Decision aids reduced the proportion of undecided participants and appeared to have a positive effect on patient-clinician communication. Moreover, those exposed to a decision aid were either equally or more satisfied with their decision, the decision-making process, and/or the preparation for decision making compared to usual care.Decision aids also reduced the number of people choosing major elective invasive surgery in favour of more conservative options (RR 0.86; 95% CI 0.75 to 1.00; 18 studies; N = 3844), but this reduction reached statistical significance only after removing the study on prophylactic mastectomy for breast cancer gene carriers (RR 0.84; 95% CI 0.73 to 0.97; 17 studies; N = 3108). Compared to usual care, decision aids reduced the number of people choosing prostate-specific antigen screening (RR 0.88; 95% CI 0.80 to 0.98; 10 studies; N = 3996) and increased those choosing to start new medications for diabetes (RR 1.65; 95% CI 1.06 to 2.56; 4 studies; N = 447). For other testing and screening choices, mostly there were no differences between decision aids and usual care.The median effect of decision aids on length of consultation was 2.6 minutes longer (24 versus 21; 7.5% increase). The costs of the decision aid group were lower in two studies and similar to usual care in four studies. People receiving decision aids do not appear to differ from those receiving usual care in terms of anxiety, general health outcomes, and condition-specific health outcomes. Studies did not report adverse events associated with the use of decision aids.In subgroup analysis, we compared results for decision aids used in preparation for the consultation versus during the consultation, finding similar improvements in pooled analysis for knowledge and accurate risk perception. For other outcomes, we could not conduct formal subgroup analyses because there were too few studies in each subgroup. AUTHORS'' CONCLUSIONS: Compared to usual care across a wide variety of decision contexts, people exposed to decision aids feel more knowledgeable, better informed, and clearer about their values, and they probably have a more active role in decision making and more accurate risk perceptions. There is growing evidence that decision aids may improve values-congruent choices. There are no adverse effects on health outcomes or satisfaction. New for this updated is evidence indicating improved knowledge and accurate risk perceptions when decision aids are used either within or in preparation for the consultation. Further research is needed on the effects on adherence with the chosen option, cost-effectiveness, and use with lower literacy populations.', '2026-07-07 22:18:03');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3015127078', 'plant-biology', 'Preconditioning strategies to prevent acute kidney injury', 'Acute kidney injury is a common clinical disorder resulting in significantly increased morbidity and mortality. However, despite extensive research, strategies for prevention or treatment are still…', '2020', 2020, 20, 20, 'https://f1000research-files.f1000.com/manuscripts/23577/e70a9d11-a6e7-4fc6-b32f-0d4668772c9a_figure1.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7135682', 'pmc', 'preprint', 'F1000Research', '["Martin R. Späth","Felix C. Koehler","Karla Johanna Ruth Hoyer-Allo","Franziska Grundmann","Volker Burst","Roman‐Ulrich Müller"]', 'plant biology', 'Acute kidney injury is a common clinical disorder resulting in significantly increased morbidity and mortality. However, despite extensive research, strategies for prevention or treatment are still lacking in routine clinical practice. Already decades ago, several preconditioning strategies (e. g. ischemic/hypoxic preconditioning and calorie restriction) have been published and their extraordinary effectiveness - especially in rodents - has raised the hope for powerful clinical tools to prevent acute kidney injury. However, the underlying mechanisms are still not completely understood and translation to the clinics has not been successful yet. In this review, the most attractive strategies and the current mechanistic concepts are introduced and discussed. Furthermore, we present clinical trials evaluating the feasibility of preconditioning in the clinical setting.', '2026-07-07 22:19:03');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4230396685', 'plant-biology', 'A genome-wide scan of cleft lip triads identifies parent-of-origin interaction effects between ANK3 and maternal smoking, and between ARHGEF10 and alcohol consumption', 'Background: Although both genetic and environmental factors have been reported to influence the risk of isolated cleft lip with or without cleft palate (CL/P), the exact mechanisms behind CL/P are…', '2019', 2019, 20, 20, 'https://f1000research-files.f1000.com/manuscripts/21459/575bffa4-e2fc-44fa-b203-22185c508023_figure1.gif', 'https://doi.org/10.12688/f1000research.19571.1', 'repository', 'preprint', 'F1000Research', '["Øystein Ariansen Haaland","Julia Romanowska","Miriam Gjerdevik","Rolv T. Lie","Håkon K. Gjessing","Astanand Jugessur"]', 'plant biology', 'Background: Although both genetic and environmental factors have been reported to influence the risk of isolated cleft lip with or without cleft palate (CL/P), the exact mechanisms behind CL/P are still largely unaccounted for. We recently developed new methods to identify parent-of-origin (PoO) interactions with environmental exposures (PoOxE) and applied them to families with children born with isolated cleft palate only. Here, we used the same genome-wide association study (GWAS) dataset and methodology to screen for PoOxE effects in the larger sample of CL/P triads. Methods: Genotypes from 1594 complete triads and 314 dyads (1908 nuclear families in total) with CL/P were available for the current analyses. Of these families, 1024 were Asian, 825 were European and 59 had other ancestries. After quality control, 341,191 SNPs remained from the original 569,244. The exposures were maternal cigarette smoking, use of alcohol, and use of vitamin supplements in the periconceptional period. The methodology applied in the analyses is implemented in the R -package Haplin. Results: Among Europeans, there was evidence of a PoOxSmoke effect for ANK3 with three SNPs (rs3793861, q=0.20, p=2.6e-6; rs7087489, q=0.20, p=3.1e-6; rs4310561, q=0.67, p=4.0e-5) and a PoOxAlcohol effect for ARHGEF10 with two SNPs (rs2294035, q=0.32, p=2.9e-6; rs4876274, q=0.76, p=1.3e-5). Conclusion: Our results indicate that the detected PoOxE effects have a plausible biological basis, and thus warrant replication in other independent cleft samples. Our demonstration of the feasibility of identifying complex interactions between relevant environmental exposures and PoO effects offers new avenues for future research aimed at unravelling the complex etiology of cleft lip defects.', '2026-07-07 22:19:05');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2163278718', 'medicine', 'The REporting of studies Conducted using Observational Routinely-collected health Data (RECORD) Statement', 'Routinely collected health data, obtained for administrative and clinical purposes without specific a priori research goals, are increasingly used for research. The rapid evolution and availability…', '2015', 2015, 5328, 5328, 'https://journals.plos.org/plosmedicine/article/figure/image?size=large&id=10.1371/journal.pmed.1001885.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4595218', 'pmc', 'article', 'PLoS Medicine', '["Eric I. Benchimol","Liam Smeeth","Astrid Guttmann","Katie Harron","David Moher","Irene Petersen","Henrik Toft Sørensen","Erik von Elm","Sinéad Langan"]', 'medicine', 'Routinely collected health data, obtained for administrative and clinical purposes without specific a priori research goals, are increasingly used for research. The rapid evolution and availability of these data have revealed issues not addressed by existing reporting guidelines, such as Strengthening the Reporting of Observational Studies in Epidemiology (STROBE). The REporting of studies Conducted using Observational Routinely collected health Data (RECORD) statement was created to fill these gaps. RECORD was created as an extension to the STROBE statement to address reporting items specific to observational studies using routinely collected health data. RECORD consists of a checklist of 13 items related to the title, abstract, introduction, methods, results, and discussion section of articles, and other information required for inclusion in such research reports. This document contains the checklist and explanatory and elaboration information to enhance the use of the checklist. Examples of good reporting for each RECORD checklist item are also included herein. This document, as well as the accompanying website and message board (http://www.record-statement.org), will enhance the implementation and understanding of RECORD. Through implementation of RECORD, authors, journals editors, and peer reviewers can encourage transparency of research reporting.', '2026-07-07 22:19:53');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2759997926', 'medicine', 'Global burden of NAFLD and NASH: trends, predictions, risk factors and prevention', 'Global burden of NAFLD and NASH: trends, predictions, risk factors and prevention', '2017', 2017, 5269, 5269, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnrgastro.2017.109/MediaObjects/41575_2018_Article_BFnrgastro2017109_Fig1_HTML.jpg', 'https://pubmed.ncbi.nlm.nih.gov/28930295', 'repository', 'review', 'Nature Reviews Gastroenterology & Hepatology', '["Zobair M. Younossi","Quentin M. Anstee","M. Marietti","Timothy Hardy","Linda Henry","Mohammed Eslam","Jacob George","Elisabetta Bugianesi"]', 'medicine', NULL, '2026-07-07 22:20:06');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2565383127', 'medicine', 'Flavonoids: an overview', 'Flavonoids, a group of natural substances with variable phenolic structures, are found in fruits, vegetables, grains, bark, roots, stems, flowers, tea and wine. These natural products are well known…', '2016', 2016, 5117, 5117, 'https://static.cambridge.org/binary/version/id/urn:cambridge.org:id:binary:20161229083620629-0238:S2048679016000410:S2048679016000410_fig1g.gif?pub-status=live', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5465813', 'pmc', 'review', 'Journal of Nutritional Science', '["Archana Panche","A D Diwan","Sheela Chandra"]', 'medicine', 'Flavonoids, a group of natural substances with variable phenolic structures, are found in fruits, vegetables, grains, bark, roots, stems, flowers, tea and wine. These natural products are well known for their beneficial effects on health and efforts are being made to isolate the ingredients so called flavonoids. Flavonoids are now considered as an indispensable component in a variety of nutraceutical, pharmaceutical, medicinal and cosmetic applications. This is attributed to their anti-oxidative, anti-inflammatory, anti-mutagenic and anti-carcinogenic properties coupled with their capacity to modulate key cellular enzyme function. Research on flavonoids received an added impulse with the discovery of the low cardiovascular mortality rate and also prevention of CHD. Information on the working mechanisms of flavonoids is still not understood properly. However, it has widely been known for centuries that derivatives of plant origin possess a broad spectrum of biological activity. Current trends of research and development activities on flavonoids relate to isolation, identification, characterisation and functions of flavonoids and finally their applications on health benefits. Molecular docking and knowledge of bioinformatics are also being used to predict potential applications and manufacturing by industry. In the present review, attempts have been made to discuss the current trends of research and development on flavonoids, working mechanisms of flavonoids, flavonoid functions and applications, prediction of flavonoids as potential drugs in preventing chronic diseases and future research directions.', '2026-07-07 22:20:19');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3007246056', 'medicine', 'Environmental and Health Impacts of Air Pollution: A Review', 'One of our era''s greatest scourges is air pollution, on account not only of its impact on climate change but also its impact on public and individual health due to increasing morbidity and mortality.…', '2020', 2020, 5074, 5074, 'https://www.frontiersin.org/files/Articles/505570/fpubh-08-00014-HTML/image_m/fpubh-08-00014-g001.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7044178', 'pmc', 'review', 'Frontiers in Public Health', '["Ioannis Manisalidis","Elisavet Stavropoulou","Agathangelos Stavropoulos","Eugenia Bezirtzoglou"]', 'medicine', 'One of our era''s greatest scourges is air pollution, on account not only of its impact on climate change but also its impact on public and individual health due to increasing morbidity and mortality. There are many pollutants that are major factors in disease in humans. Among them, Particulate Matter (PM), particles of variable but very small diameter, penetrate the respiratory system via inhalation, causing respiratory and cardiovascular diseases, reproductive and central nervous system dysfunctions, and cancer. Despite the fact that ozone in the stratosphere plays a protective role against ultraviolet irradiation, it is harmful when in high concentration at ground level, also affecting the respiratory and cardiovascular system. Furthermore, nitrogen oxide, sulfur dioxide, Volatile Organic Compounds (VOCs), dioxins, and polycyclic aromatic hydrocarbons (PAHs) are all considered air pollutants that are harmful to humans. Carbon monoxide can even provoke direct poisoning when breathed in at high levels. Heavy metals such as lead, when absorbed into the human body, can lead to direct poisoning or chronic intoxication, depending on exposure. Diseases occurring from the aforementioned substances include principally respiratory problems such as Chronic Obstructive Pulmonary Disease (COPD), asthma, bronchiolitis, and also lung cancer, cardiovascular events, central nervous system dysfunctions, and cutaneous diseases. Last but not least, climate change resulting from environmental pollution affects the geographical distribution of many infectious diseases, as do natural disasters. The only way to tackle this problem is through public awareness coupled with a multidisciplinary approach by scientific experts; national and international organizations must address the emergence of this threat and propose sustainable solutions.', '2026-07-07 22:20:19');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3118577024', 'medicine', 'Plasma Hsp90 levels in patients with systemic sclerosis and relation to lung and skin involvement: a cross-sectional and longitudinal study', 'Our previous study demonstrated increased expression of Heat shock protein (Hsp) 90 in the skin of patients with systemic sclerosis (SSc). We aimed to evaluate plasma Hsp90 in SSc and characterize…', '2021', 2021, 5052, 5052, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41598-020-79139-8/MediaObjects/41598_2020_79139_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7791137', 'pmc', 'article', 'Scientific Reports', '["Hana Štorkánová","Sabína Oreská","Maja Špiritović","Barbora Heřmánková","Kristýna Bubová","Martin Komarc","Karel Pavelká","Jiří Vencovský","Jörg H. W. Distler","Ladislav Šenolt","Radim Bečvář","Michal Tomčík"]', 'medicine', 'Our previous study demonstrated increased expression of Heat shock protein (Hsp) 90 in the skin of patients with systemic sclerosis (SSc). We aimed to evaluate plasma Hsp90 in SSc and characterize its association with SSc-related features. Ninety-two SSc patients and 92 age-/sex-matched healthy controls were recruited for the cross-sectional analysis. The longitudinal analysis comprised 30 patients with SSc associated interstitial lung disease (ILD) routinely treated with cyclophosphamide. Hsp90 was increased in SSc compared to healthy controls. Hsp90 correlated positively with C-reactive protein and negatively with pulmonary function tests: forced vital capacity and diffusing capacity for carbon monoxide (DLCO). In patients with diffuse cutaneous (dc) SSc, Hsp90 positively correlated with the modified Rodnan skin score. In SSc-ILD patients treated with cyclophosphamide, no differences in Hsp90 were found between baseline and after 1, 6, or 12 months of therapy. However, baseline Hsp90 predicts the 12-month change in DLCO. This study shows that Hsp90 plasma levels are increased in SSc patients compared to age-/sex-matched healthy controls. Elevated Hsp90 in SSc is associated with increased inflammatory activity, worse lung functions, and in dcSSc, with the extent of skin involvement. Baseline plasma Hsp90 predicts the 12-month change in DLCO in SSc-ILD patients treated with cyclophosphamide.', '2026-07-07 22:20:32');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3148962211', 'medicine', 'The PRISMA 2020 statement: An updated guideline for reporting systematic reviews', 'Matthew Page and co-authors describe PRISMA 2020, an updated reporting guideline for systematic reviews and meta-analyses.', '2021', 2021, 4954, 4954, 'https://journals.plos.org/plosmedicine/article/figure/image?size=large&id=10.1371/journal.pmed.1003583.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8007028', 'pmc', 'article', 'PLoS Medicine', '["Matthew J. Page","Joanne E. McKenzie","Patrick M. Bossuyt","Isabelle Boutron","Tammy Hoffmann","Cynthia D. Mulrow","Larissa Shamseer","Jennifer Tetzlaff","Elie A. Akl","Sue Brennan","Roger Chou","Julie Glanville","Jeremy Grimshaw","Asbjørn Hróbjartsson","Manoj M. Lalu","Tianjing Li","Elizabeth Loder","Evan Mayo‐Wilson","Steve McDonald","Luke A. McGuinness","Lesley Stewart","James Thomas","Andrea C. Tricco","Vivian Welch","Penny Whiting","David Moher"]', 'medicine', 'Matthew Page and co-authors describe PRISMA 2020, an updated reporting guideline for systematic reviews and meta-analyses.', '2026-07-07 22:20:44');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3014125413', 'medicine', 'Version 4 of the CRU TS monthly high-resolution gridded multivariate climate dataset', 'CRU TS (Climatic Research Unit gridded Time Series) is a widely used climate dataset on a 0.5° latitude by 0.5° longitude grid over all land domains of the world except Antarctica. It is derived by…', '2020', 2020, 4806, 4806, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41597-020-0453-3/MediaObjects/41597_2020_453_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7125108', 'pmc', 'article', 'Scientific Data', '["Ian Harris","Timothy J. Osborn","P. D. Jones","David Lister"]', 'medicine', 'CRU TS (Climatic Research Unit gridded Time Series) is a widely used climate dataset on a 0.5° latitude by 0.5° longitude grid over all land domains of the world except Antarctica. It is derived by the interpolation of monthly climate anomalies from extensive networks of weather station observations. Here we describe the construction of a major new version, CRU TS v4. It is updated to span 1901-2018 by the inclusion of additional station observations, and it will be updated annually. The interpolation process has been changed to use angular-distance weighting (ADW), and the production of secondary variables has been revised to better suit this approach. This implementation of ADW provides improved traceability between each gridded value and the input observations, and allows more informative diagnostics that dataset users can utilise to assess how dataset quality might vary geographically.', '2026-07-07 22:21:29');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3135257712', 'medicine', 'A global panel database of pandemic policies (Oxford COVID-19 Government Response Tracker)', 'COVID-19 has prompted unprecedented government action around the world. We introduce the Oxford COVID-19 Government Response Tracker (OxCGRT), a dataset that addresses the need for continuously…', '2021', 2021, 4778, 4778, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41562-021-01079-8/MediaObjects/41562_2021_1079_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/33686204', 'repository', 'article', 'Nature Human Behaviour', '["Thomas Hale","Noam Angrist","Rafael Goldszmidt","Beatriz Kira","Anna Petherick","Toby Phillips","Samuel Webster","Emily Cameron-Blake","Laura Hallas","Saptarshi Majumdar","Helen Tatlow"]', 'medicine', 'COVID-19 has prompted unprecedented government action around the world. We introduce the Oxford COVID-19 Government Response Tracker (OxCGRT), a dataset that addresses the need for continuously updated, readily usable and comparable information on policy measures. From 1 January 2020, the data capture government policies related to closure and containment, health and economic policy for more than 180 countries, plus several countries’ subnational jurisdictions. Policy responses are recorded on ordinal or continuous scales for 19 policy areas, capturing variation in degree of response. We present two motivating applications of the data, highlighting patterns in the timing of policy adoption and subsequent policy easing and reimposition, and illustrating how the data can be combined with behavioural and epidemiological indicators. This database enables researchers and policymakers to explore the empirical effects of policy responses on the spread of COVID-19 cases and deaths, as well as on economic and social welfare. The Oxford COVID-19 Government Response Tracker (OxCGRT) records data on 19 different government COVID-19 policy indicators for over 190 countries. Covering closure and containment, health and economics measures, it creates an evidence base for effective responses.', '2026-07-07 22:21:30');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4281286822', 'plant-biology', 'Genome of the lepidopleurid chiton Hanleya hanleyi (Mollusca, Polyplacophora)', 'Mollusca is the second most species-rich phylum and includes animals as disparate as octopuses, clams, and chitons. Dozens of molluscan genomes are available, but only one representative of the…', '2022', 2022, 19, 19, 'https://f1000research-files.f1000.com/manuscripts/133601/caf271dc-3546-4d39-aa0d-49bf09740b98_figure1.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/9366239', 'pmc', 'preprint', 'F1000Research', '["Rebecca Varney","Meghan K. Yap-Chiongco","Nina T. Mikkelsen","Kevin M. Kocot"]', 'plant biology', 'Mollusca is the second most species-rich phylum and includes animals as disparate as octopuses, clams, and chitons. Dozens of molluscan genomes are available, but only one representative of the subphylum Aculifera, the sister taxon to all other molluscs, has been sequenced to date, hindering comparative and evolutionary studies. To facilitate evolutionary studies across Mollusca, we sequenced the genome of a second aculiferan mollusc, the lepidopleurid chiton Hanleya hanleyi (Bean 1844), using a hybrid approach combining Oxford Nanopore and Illumina reads. After purging redundant haplotigs and removing contamination from this 1.3% heterozygous genome, we produced a 2.5 Gbp haploid assembly (&gt;4X the size of the other chiton genome sequenced to date) with an N50 of 65.0 Kbp. Despite a fragmented assembly, the genome is rather complete (92.0% of BUSCOs detected; 79.4% complete plus 12.6% fragmented). Remarkably, the genome has the highest repeat content of any molluscan genome reported to date (&gt;66%). Our gene annotation pipeline predicted 69,284 gene models (92.9% of BUSCOs detected; 81.8% complete plus 11.1% fragmented) of which 35,362 were supported by transcriptome and/or protein evidence. Phylogenomic analysis recovered Polyplacophora sister to all other sampled molluscs with maximal support. The Hanleya genome will be a valuable resource for studies of molluscan biology with diverse potential applications ranging from evolutionary and comparative genomics to molecular ecology.', '2026-07-07 22:21:42');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2539107597', 'medicine', 'Designing hydrogels for controlled drug delivery', 'Designing hydrogels for controlled drug delivery', '2016', 2016, 4583, 4583, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnatrevmats.2016.71/MediaObjects/41578_2016_Article_BFnatrevmats201671_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5898614', 'pmc', 'review', 'Nature Reviews Materials', '["Jianyu Li","David Mooney"]', 'medicine', NULL, '2026-07-07 22:21:53');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2504691963', 'medicine', 'Sharing and community curation of mass spectrometry data with Global Natural Products Social Molecular Networking', 'The potential of the diverse chemistries present in natural products (NP) for biotechnology and medicine remains untapped because NP databases are not searchable with raw data and the NP community…', '2016', 2016, 4613, 4613, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnbt.3597/MediaObjects/41587_2016_Article_BFnbt3597_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5321674', 'pmc', 'article', 'Nature Biotechnology', '["Mingxun Wang","Jeremy Carver","Vanessa V. Phelan","Laura M. Sanchez","Neha Garg","Yao Peng","Don D. Nguyen","Jeramie D. Watrous","Clifford A. Kapono","Tal Luzzatto‐Knaan","Carla Porto","Amina Bouslimani","Alexey V. Melnik","Michael J. Meehan","Wei-Ting Liu","Max Crüsemann","Paul D. Boudreau","Eduardo Esquenazi","Mario Sandoval‐Calderón","Roland D. Kersten","Laura Pace","Robert A. Quinn","Katherine Duncan","Cheng‐Chih Hsu","Dimitrios J. Floros","Ronnie G. Gavilán","Karin Kleigrewe","Trent R. Northen","Rachel J. Dutton","Delphine Parrot","Erin E. Carlson","Bertrand Aigle","Charlotte Frydenlund Michelsen","Lars Jelsbak","Christian Sohlenkamp","Pavel A. Pevzner","Anna Edlund","Jeffrey S. McLean","Jörn Piel","Brian T. Murphy","Lena Gerwick","Chih‐Chuang Liaw","Yuliang Yang","Hans‐Ulrich Humpf","Maria Maansson","Robert A. Keyzers","Amy Sims","Andrew R. Johnson","Ashley M. Sidebottom","Brian E. Sedio","Andreas Klitgaard","Charles B. Larson","Cristopher A. Boya P.","Daniel Torres‐Mendoza","David J. Gonzalez","Denise Brentan Silva","Lucas Maciel Mauriz Marques","Daniel P. Demarque","Eglė Pociūtė","Ellis C. O’Neill","Enora Briand","Eric J. N. Helfrich","Eve A. Granatosky","Evgenia Glukhov","Florian Ryffel","Hailey Houson","Hosein Mohimani","Jenan J. Kharbush","Yi Zeng","Julia A. Vorholt","Kenji L. Kurita","Pep Charusanti","Kerry L. McPhail","Kristian Fog Nielsen","Lisa Vuong","Maryam Elfeki","Matthew F. Traxler","Niclas Engene","Nobuhiro Koyama","Oliver B. Vining","Ralph S. Baric","Ricardo Silva","Samantha J. Mascuch","Sophie Tomasi","Stefan Jenkins","Venkat R. Macherla","Thomas Hoffman","Vinayak Agarwal","Philip G. Williams","Jingqui Dai","Ram P. Neupane","Joshua R. Gurr","Andrés Mauricio Caraballo‐Rodríguez","Anne Lamsa","Chen Zhang","Kathleen Dorrestein","Brendan M. Duggan","Jehad Almaliti","Pierre‐Marie Allard","Prasad Phapale"]', 'medicine', 'The potential of the diverse chemistries present in natural products (NP) for biotechnology and medicine remains untapped because NP databases are not searchable with raw data and the NP community has no way to share data other than in published papers. Although mass spectrometry (MS) techniques are well-suited to high-throughput characterization of NP, there is a pressing need for an infrastructure to enable sharing and curation of data. We present Global Natural Products Social Molecular Networking (GNPS; http://gnps.ucsd.edu), an open-access knowledge base for community-wide organization and sharing of raw, processed or identified tandem mass (MS/MS) spectrometry data. In GNPS, crowdsourced curation of freely available community-wide reference MS libraries will underpin improved annotations. Data-driven social-networking should facilitate identification of spectra and foster collaborations. We also introduce the concept of ''living data'' through continuous reanalysis of deposited data.', '2026-07-07 22:21:54');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3083241614', 'medicine', 'Gut microbiota in human metabolic health and disease', 'Gut microbiota in human metabolic health and disease', '2020', 2020, 4584, 4584, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41579-020-0433-9/MediaObjects/41579_2020_433_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/32887946', 'repository', 'review', 'Nature Reviews Microbiology', '["Yong Fan","Oluf Pedersen"]', 'medicine', NULL, '2026-07-07 22:21:54');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3018517500', 'medicine', 'The trinity of COVID-19: immunity, inflammation and intervention', 'The trinity of COVID-19: immunity, inflammation and intervention', '2020', 2020, 4632, 4632, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41577-020-0311-8/MediaObjects/41577_2020_311_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7187672', 'pmc', 'review', 'Nature reviews. Immunology', '["Matthew Zirui Tay","Chek Meng Poh","Laurent Rénia","Paul A. MacAry","Lisa F. P. Ng"]', 'medicine', NULL, '2026-07-07 22:21:54');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2804846127', 'medicine', 'Impact of Particle Size and Polydispersity Index on the Clinical Applications of Lipidic Nanocarrier Systems', 'Lipid-based drug delivery systems, or lipidic carriers, are being extensively employed to enhance the bioavailability of poorly-soluble drugs. They have the ability to incorporate both lipophilic and…', '2018', 2018, 4586, 4586, 'https://pub.mdpi-res.com/pharmaceutics/pharmaceutics-10-00057/article_deploy/html/images/pharmaceutics-10-00057-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6027495', 'pmc', 'review', 'Pharmaceutics', '["M. Danaei","M. Dehghankhold","Shahla Ataei","Fatemeh Hasanzadeh Davarani","R. Javanmard","A. Dokhani","Sepideh Khorasani","M. R. Mozafari"]', 'medicine', 'Lipid-based drug delivery systems, or lipidic carriers, are being extensively employed to enhance the bioavailability of poorly-soluble drugs. They have the ability to incorporate both lipophilic and hydrophilic molecules and protecting them against degradation in vitro and in vivo. There is a number of physical attributes of lipid-based nanocarriers that determine their safety, stability, efficacy, as well as their in vitro and in vivo behaviour. These include average particle size/diameter and the polydispersity index (PDI), which is an indication of their quality with respect to the size distribution. The suitability of nanocarrier formulations for a particular route of drug administration depends on their average diameter, PDI and size stability, among other parameters. Controlling and validating these parameters are of key importance for the effective clinical applications of nanocarrier formulations. This review highlights the significance of size and PDI in the successful design, formulation and development of nanosystems for pharmaceutical, nutraceutical and other applications. Liposomes, nanoliposomes, vesicular phospholipid gels, solid lipid nanoparticles, transfersomes and tocosomes are presented as frequently-used lipidic drug carriers. The advantages and limitations of a range of available analytical techniques used to characterize lipidic nanocarrier formulations are also covered.', '2026-07-07 22:22:00');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3012747666', 'medicine', 'Association of Cardiac Injury With Mortality in Hospitalized Patients With COVID-19 in Wuhan, China', 'Importance: Coronavirus disease 2019 (COVID-19) has resulted in considerable morbidity and mortality worldwide since December 2019. However, information on cardiac injury in patients affected by…', '2020', 2020, 4546, 4546, 'https://cdn.ncbi.nlm.nih.gov/pmc/blobs/da0d/7097841/4f95c12ff714/jamacardiol-5-802-g001.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7097841', 'pmc', 'article', 'JAMA Cardiology', '["Shaobo Shi","Mu Qin","Bo Shen","Yuli Cai","Tao Liu","Fan Yang","Wei Gong","Xu Liu","Jinjun Liang","Qinyan Zhao","He Huang","Bo Yang","Congxin Huang"]', 'medicine', 'Importance: Coronavirus disease 2019 (COVID-19) has resulted in considerable morbidity and mortality worldwide since December 2019. However, information on cardiac injury in patients affected by COVID-19 is limited. Objective: To explore the association between cardiac injury and mortality in patients with COVID-19. Design, Setting, and Participants: This cohort study was conducted from January 20, 2020, to February 10, 2020, in a single center at Renmin Hospital of Wuhan University, Wuhan, China; the final date of follow-up was February 15, 2020. All consecutive inpatients with laboratory-confirmed COVID-19 were included in this study. Main Outcomes and Measures: Clinical laboratory, radiological, and treatment data were collected and analyzed. Outcomes of patients with and without cardiac injury were compared. The association between cardiac injury and mortality was analyzed. Results: A total of 416 hospitalized patients with COVID-19 were included in the final analysis; the median age was 64 years (range, 21-95 years), and 211 (50.7%) were female. Common symptoms included fever (334 patients [80.3%]), cough (144 [34.6%]), and shortness of breath (117 [28.1%]). A total of 82 patients (19.7%) had cardiac injury, and compared with patients without cardiac injury, these patients were older (median [range] age, 74 [34-95] vs 60 [21-90] years; P <.001); had more comorbidities (eg, hypertension in 49 of 82 [59.8%] vs 78 of 334 [23.4%]; P <.001); had higher leukocyte counts (median [interquartile range (IQR)], 9400 [6900-13 800] vs 5500 [4200-7400] cells/μL) and levels of C-reactive protein (median [IQR], 10.2 [6.4-17.0] vs 3.7 [1.0-7.3] mg/dL), procalcitonin (median [IQR], 0.27 [0.10-1.22] vs 0.06 [0.03-0.10] ng/mL), creatinine kinase-myocardial band (median [IQR], 3.2 [1.8-6.2] vs 0.9 [0.6-1.3] ng/mL), myohemoglobin (median [IQR], 128 [68-305] vs 39 [27-65] μg/L), high-sensitivity troponin I (median [IQR], 0.19 [0.08-1.12] vs <0.006 [<0.006-0.009] μg/L), N-terminal pro-B-type natriuretic peptide (median [IQR], 1689 [698-3327] vs 139 [51-335] pg/mL), aspartate aminotransferase (median [IQR], 40 [27-60] vs 29 [21-40] U/L), and creatinine (median [IQR], 1.15 [0.72-1.92] vs 0.64 [0.54-0.78] mg/dL); and had a higher proportion of multiple mottling and ground-glass opacity in radiographic findings (53 of 82 patients [64.6%] vs 15 of 334 patients [4.5%]). Greater proportions of patients with cardiac injury required noninvasive mechanical ventilation (38 of 82 [46.3%] vs 13 of 334 [3.9%]; P <.001) or invasive mechanical ventilation (18 of 82 [22.0%] vs 14 of 334 [4.2%]; P <.001) than those without cardiac injury. Complications were more common in patients with cardiac injury than those without cardiac injury and included acute respiratory distress syndrome (48 of 82 [58.5%] vs 49 of 334 [14.7%]; P <.001), acute kidney injury (7 of 82 [8.5%] vs 1 of 334 [0.3%]; P <.001), electrolyte disturbances (13 of 82 [15.9%] vs 17 of 334 [5.1%]; P =.003), hypoproteinemia (11 of 82 [13.4%] vs 16 of 334 [4.8%]; P =.01), and coagulation disorders (6 of 82 [7.3%] vs 6 of 334 [1.8%]; P =.02). Patients with cardiac injury had higher mortality than those without cardiac injury (42 of 82 [51.2%] vs 15 of 334 [4.5%]; P <.001). In a Cox regression model, patients with vs those without cardiac injury were at a higher risk of death, both during the time from symptom onset (hazard ratio, 4.26 [95% CI, 1.92-9.49]) and from admission to end point (hazard ratio, 3.41 [95% CI, 1.62-7.16]). Conclusions and Relevance: Cardiac injury is a common condition among hospitalized patients with COVID-19 in Wuhan, China, and it is associated with higher risk of in-hospital mortality.', '2026-07-07 22:22:11');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3015579983', 'medicine', 'A new definition for metabolic dysfunction-associated fatty liver disease: An international expert consensus statement', 'A new definition for metabolic dysfunction-associated fatty liver disease: An international expert consensus statement', '2020', 2020, 4428, 4428, 'https://ars.els-cdn.com/content/image/1-s2.0-S0168827820302014-fx1.jpg', 'https://hal.science/hal-03490447', 'repository', 'review', 'Journal of Hepatology', '["Mohammed Eslam","Philip N. Newsome","Shiv Kumar Sarin","Quentin M. Anstee","Giovanni Targher","Manuel Romero‐Gómez","Shira Zelber‐Sagi","Vincent Wai‐Sun Wong","Jean‐François Dufour","Jörn M. Schattenberg","Takumi Kawaguchi","Marco Arrese","Luca Valenti","Gamal Shiha","Claudio Tiribelli","Hannele Yki‐Järvinen","Jian-Gao Fan","Henning Grønbæk","Yusuf Yılmaz","Helena Cortez‐Pinto","Cláudia P. Oliveira","Pierre Bédossa","Leon A. Adams","Ming‐Hua Zheng","Yasser Fouad","Wah‐Kheong Chan","Nahúm Méndez‐Sánchez","Sang Hoon Ahn","Laurent Castéra","Elisabetta Bugianesi","Vlad Ratziu","Jacob George"]', 'medicine', NULL, '2026-07-07 22:22:19');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2969802526', 'medicine', 'A global view of hepatocellular carcinoma: trends, risk, prevention and management', 'A global view of hepatocellular carcinoma: trends, risk, prevention and management', '2019', 2019, 4396, 4396, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41575-019-0186-y/MediaObjects/41575_2019_186_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6813818', 'pmc', 'review', 'Nature Reviews Gastroenterology & Hepatology', '["Ju Dong Yang","Pierre Hainaut","Gregory J. Gores","Amina Amadou","Amelie Plymoth","Lewis R. Roberts"]', 'medicine', NULL, '2026-07-07 22:22:32');
