INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3165479483', 'medicine', 'SARS-CoV-2 variants, spike mutations and immune escape', 'SARS-CoV-2 variants, spike mutations and immune escape', '2021', 2021, 3879, 3879, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41579-021-00573-0/MediaObjects/41579_2021_573_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8167834', 'pmc', 'review', 'Nature Reviews Microbiology', '["William T. Harvey","Alessandro M. Carabelli","Ben Jackson","Ravindra K. Gupta","Emma C. Thomson","Ewan M. Harrison","Catherine Ludden","Richard Reeve","Andrew Rambaut","Sharon J. Peacock","David L. Robertson"]', 'medicine', NULL, '2026-07-07 22:24:18');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3032971139', 'medicine', 'Estimating the effects of non-pharmaceutical interventions on COVID-19 in Europe', 'Estimating the effects of non-pharmaceutical interventions on COVID-19 in Europe', '2020', 2020, 3814, 3814, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-020-2405-7/MediaObjects/41586_2020_2405_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/32512579', 'repository', 'article', 'Nature', '["Seth Flaxman","Swapnil Mishra","Axel Gandy","H. Juliette T. Unwin","Thomas A. Mellan","Helen Coupland","Charles Whittaker","Hong Zhu","Tresnia Berah","Jeffrey W. Eaton","Mélodie Monod","Pablo N. Perez‐Guzman","Nora Schmit","Lucia Cilloni","Kylie E. C. Ainslie","Marc Baguelin","Adhiratha Boonyasiri","Olivia Boyd","Lorenzo Cattarino","Laura Cooper","Zulma M. Cucunubá","Gina Cuomo-Dannenburg","Amy Dighe","Bimandra A Djaafara","Ilaria Dorigatti","Sabine van Elsland","Richard G. FitzJohn","Katy A. M. Gaythorpe","Lily Geidelberg","Nicholas C. Grassly","William D. Green","Timothy B. Hallett","Arran Hamlet","Wes Hinsley","B Jeffrey","Edward Knock","Daniel J. Laydon","Gemma Nedjati‐Gilani","Pierre Nouvellet","Kris V. Parag","Igor Siveroni","Hayley A Thompson","Robert Verity","Erik Volz","Caroline E. Walters","Haowei Wang","Yuanrong Wang","Oliver J. Watson","Peter Winskill","Xiaoyue Xi","Patrick Walker","Azra C. Ghani","Christl A. Donnelly","Steven Riley","Michaela Vollmer","Neil M. Ferguson","Lucy Okell","Samir Bhatt"]', 'medicine', NULL, '2026-07-07 22:24:19');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2949100461', 'medicine', 'An epigenetic biomarker of aging for lifespan and healthspan', 'Identifying reliable biomarkers of aging is a major goal in geroscience. While the first generation of epigenetic biomarkers of aging were developed using chronological age as a surrogate for…', '2018', 2018, 3597, 3597, 'https://cdn.aging-us.com/article/101414/figure/f1/large.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5940111', 'pmc', 'article', 'Aging', '["Morgan E. Levine","Ake T. Lu","Austin Quach","Brian H. Chen","Themistocles L. Assimes","Stefania Bandinelli","Lifang Hou","Andrea Baccarelli","James D. Stewart","Yun Li","Eric A. Whitsel","James G. Wilson","Alex P. Reiner","Abraham Aviv","Kurt Lohman","Ching‐Ti Liu","Luigi Ferrucci","Steve Horvath"]', 'medicine', 'Identifying reliable biomarkers of aging is a major goal in geroscience. While the first generation of epigenetic biomarkers of aging were developed using chronological age as a surrogate for biological age, we hypothesized that incorporation of composite clinical measures of phenotypic age that capture differences in lifespan and healthspan may identify novel CpGs and facilitate the development of a more powerful epigenetic biomarker of aging. Using an innovative two-step process, we develop a new epigenetic biomarker of aging, DNAm PhenoAge, that strongly outperforms previous measures in regards to predictions for a variety of aging outcomes, including all-cause mortality, cancers, healthspan, physical functioning, and Alzheimer''s disease. While this biomarker was developed using data from whole blood, it correlates strongly with age in every tissue and cell tested. Based on an in-depth transcriptional analysis in sorted cells, we find that increased epigenetic, relative to chronological age, is associated with increased activation of pro-inflammatory and interferon pathways, and decreased activation of transcriptional/translational machinery, DNA damage response, and mitochondrial signatures. Overall, this single epigenetic biomarker of aging is able to capture risks for an array of diverse outcomes across multiple tissues and cells, and provide insight into important pathways in aging.', '2026-07-07 22:25:43');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4319662928', 'medicine', 'Performance of ChatGPT on USMLE: Potential for AI-assisted medical education using large language models', 'We evaluated the performance of a large language model called ChatGPT on the United States Medical Licensing Exam (USMLE), which consists of three exams: Step 1, Step 2CK, and Step 3. ChatGPT…', '2023', 2023, 3603, 3603, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pdig.0000198.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/9931230', 'pmc', 'article', 'PLOS Digital Health', '["Tiffany H. Kung","Morgan Cheatham","Arielle Medenilla","Czarina Sillos","Lorie De Leon","Camille Elepaño","Maria Madriaga","Rimel Aggabao","Giezel Diaz-Candido","James Maningo","Victor Tseng"]', 'medicine', 'We evaluated the performance of a large language model called ChatGPT on the United States Medical Licensing Exam (USMLE), which consists of three exams: Step 1, Step 2CK, and Step 3. ChatGPT performed at or near the passing threshold for all three exams without any specialized training or reinforcement. Additionally, ChatGPT demonstrated a high level of concordance and insight in its explanations. These results suggest that large language models may have the potential to assist with medical education, and potentially, clinical decision-making.', '2026-07-07 22:25:43');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3022435472', 'medicine', 'Cell entry mechanisms of SARS-CoV-2', 'A novel severe acute respiratory syndrome (SARS)-like coronavirus (SARS-CoV-2) is causing the global coronavirus disease 2019 (COVID-19) pandemic. Understanding how SARS-CoV-2 enters human cells is a…', '2020', 2020, 3459, 3459, 'https://cdn.ncbi.nlm.nih.gov/pmc/blobs/df51/7260975/d740576f2fd1/pnas.2003138117fig01.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7260975', 'pmc', 'article', 'Proceedings of the National Academy of Sciences', '["Jian Shang","Yushun Wan","Chuming Luo","Gang Ye","Qibin Geng","Ashley A. Auerbach","Fang Li"]', 'medicine', 'A novel severe acute respiratory syndrome (SARS)-like coronavirus (SARS-CoV-2) is causing the global coronavirus disease 2019 (COVID-19) pandemic. Understanding how SARS-CoV-2 enters human cells is a high priority for deciphering its mystery and curbing its spread. A virus surface spike protein mediates SARS-CoV-2 entry into cells. To fulfill its function, SARS-CoV-2 spike binds to its receptor human ACE2 (hACE2) through its receptor-binding domain (RBD) and is proteolytically activated by human proteases. Here we investigated receptor binding and protease activation of SARS-CoV-2 spike using biochemical and pseudovirus entry assays. Our findings have identified key cell entry mechanisms of SARS-CoV-2. First, SARS-CoV-2 RBD has higher hACE2 binding affinity than SARS-CoV RBD, supporting efficient cell entry. Second, paradoxically, the hACE2 binding affinity of the entire SARS-CoV-2 spike is comparable to or lower than that of SARS-CoV spike, suggesting that SARS-CoV-2 RBD, albeit more potent, is less exposed than SARS-CoV RBD. Third, unlike SARS-CoV, cell entry of SARS-CoV-2 is preactivated by proprotein convertase furin, reducing its dependence on target cell proteases for entry. The high hACE2 binding affinity of the RBD, furin preactivation of the spike, and hidden RBD in the spike potentially allow SARS-CoV-2 to maintain efficient cell entry while evading immune surveillance. These features may contribute to the wide spread of the virus. Successful intervention strategies must target both the potency of SARS-CoV-2 and its evasiveness.', '2026-07-07 22:26:21');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2763920048', 'medicine', 'What is polypharmacy? A systematic review of definitions', 'BACKGROUND: Multimorbidity and the associated use of multiple medicines (polypharmacy), is common in the older population. Despite this, there is no consensus definition for polypharmacy. A…', '2017', 2017, 3287, 3287, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1007%2Fs41999-021-00479-3/MediaObjects/41999_2021_479_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5635569', 'pmc', 'review', 'BMC Geriatrics', '["Nashwa Masnoon","Sepehr Shakib","Lisa M. Kalisch Ellett","Gillian E. Caughey"]', 'medicine', 'BACKGROUND: Multimorbidity and the associated use of multiple medicines (polypharmacy), is common in the older population. Despite this, there is no consensus definition for polypharmacy. A systematic review was conducted to identify and summarise polypharmacy definitions in existing literature. METHODS: The reporting of this systematic review conforms to the Preferred Reporting Items for Systematic reviews and Meta-Analyses (PRISMA) checklist. MEDLINE (Ovid), EMBASE and Cochrane were systematically searched, as well as grey literature, to identify articles which defined the term polypharmacy (without any limits on the types of definitions) and were in English, published between 1st January 2000 and 30th May 2016. Definitions were categorised as i. numerical only (using the number of medications to define polypharmacy), ii. numerical with an associated duration of therapy or healthcare setting (such as during hospital stay) or iii. Descriptive (using a brief description to define polypharmacy). RESULTS: A total of 1156 articles were identified and 110 articles met the inclusion criteria. Articles not only defined polypharmacy but associated terms such as minor and major polypharmacy. As a result, a total of 138 definitions of polypharmacy and associated terms were obtained. There were 111 numerical only definitions (80.4% of all definitions), 15 numerical definitions which incorporated a duration of therapy or healthcare setting (10.9%) and 12 descriptive definitions (8.7%). The most commonly reported definition of polypharmacy was the numerical definition of five or more medications daily (n = 51, 46.4% of articles), with definitions ranging from two or more to 11 or more medicines. Only 6.4% of articles classified the distinction between appropriate and inappropriate polypharmacy, using descriptive definitions to make this distinction. CONCLUSIONS: Polypharmacy definitions were variable. Numerical definitions of polypharmacy did not account for specific comorbidities present and make it difficult to assess safety and appropriateness of therapy in the clinical setting.', '2026-07-07 22:27:25');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3081655479', 'medicine', 'Pathophysiology of Type 2 Diabetes Mellitus', 'Type 2 Diabetes Mellitus (T2DM), one of the most common metabolic disorders, is caused by a combination of two primary factors: defective insulin secretion by pancreatic β-cells and the inability of…', '2020', 2020, 3192, 3192, 'https://pub.mdpi-res.com/ijms/ijms-21-06275/article_deploy/html/images/ijms-21-06275-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7503727', 'pmc', 'review', 'International Journal of Molecular Sciences', '["Unai Galicia-García","Asier Benito‐Vicente","Shifa Jebari","Asier Larrea‐Sebal","Haziq Siddiqi","Kepa B. Uribe","Helena Ostolaza","César Martı́n"]', 'medicine', 'Type 2 Diabetes Mellitus (T2DM), one of the most common metabolic disorders, is caused by a combination of two primary factors: defective insulin secretion by pancreatic β-cells and the inability of insulin-sensitive tissues to respond appropriately to insulin. Because insulin release and activity are essential processes for glucose homeostasis, the molecular mechanisms involved in the synthesis and release of insulin, as well as in its detection are tightly regulated. Defects in any of the mechanisms involved in these processes can lead to a metabolic imbalance responsible for the development of the disease. This review analyzes the key aspects of T2DM, as well as the molecular mechanisms and pathways implicated in insulin metabolism leading to T2DM and insulin resistance. For that purpose, we summarize the data gathered up until now, focusing especially on insulin synthesis, insulin release, insulin sensing and on the downstream effects on individual insulin-sensitive organs. The review also covers the pathological conditions perpetuating T2DM such as nutritional factors, physical activity, gut dysbiosis and metabolic memory. Additionally, because T2DM is associated with accelerated atherosclerosis development, we review here some of the molecular mechanisms that link T2DM and insulin resistance (IR) as well as cardiovascular risk as one of the most important complications in T2DM.', '2026-07-07 22:28:15');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2519678626', 'medicine', 'Silver Nanoparticles: Synthesis, Characterization, Properties, Applications, and Therapeutic Approaches', 'Recent advances in nanoscience and nanotechnology radically changed the way we diagnose, treat, and prevent various diseases in all aspects of human life. Silver nanoparticles (AgNPs) are one of the…', '2016', 2016, 3170, 3170, 'https://pub.mdpi-res.com/ijms/ijms-17-01534/article_deploy/html/images/ijms-17-01534-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5037809', 'pmc', 'review', 'International Journal of Molecular Sciences', '["Xifeng Zhang","Zhi-guo Liu","Wei Shen","Sangiliyandi Gurunathan"]', 'medicine', 'Recent advances in nanoscience and nanotechnology radically changed the way we diagnose, treat, and prevent various diseases in all aspects of human life. Silver nanoparticles (AgNPs) are one of the most vital and fascinating nanomaterials among several metallic nanoparticles that are involved in biomedical applications. AgNPs play an important role in nanoscience and nanotechnology, particularly in nanomedicine. Although several noble metals have been used for various purposes, AgNPs have been focused on potential applications in cancer diagnosis and therapy. In this review, we discuss the synthesis of AgNPs using physical, chemical, and biological methods. We also discuss the properties of AgNPs and methods for their characterization. More importantly, we extensively discuss the multifunctional bio-applications of AgNPs; for example, as antibacterial, antifungal, antiviral, anti-inflammatory, anti-angiogenic, and anti-cancer agents, and the mechanism of the anti-cancer activity of AgNPs. In addition, we discuss therapeutic approaches and challenges for cancer therapy using AgNPs. Finally, we conclude by discussing the future perspective of AgNPs.', '2026-07-07 22:28:30');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2408017125', 'medicine', 'Statistical tests, P values, confidence intervals, and power: a guide to misinterpretations', 'Misinterpretation and abuse of statistical tests, confidence intervals, and statistical power have been decried for decades, yet remain rampant. A key problem is that there are no interpretations of…', '2016', 2016, 3154, 3154, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs12874-020-01105-9/MediaObjects/12874_2020_1105_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4877414', 'pmc', 'article', 'European Journal of Epidemiology', '["Sander Greenland","Stephen Senn","Kenneth J. Rothman","John B. Carlin","Charles Poole","Steven N. Goodman","Douglas G. Altman"]', 'medicine', 'Misinterpretation and abuse of statistical tests, confidence intervals, and statistical power have been decried for decades, yet remain rampant. A key problem is that there are no interpretations of these concepts that are at once simple, intuitive, correct, and foolproof. Instead, correct use and interpretation of these statistics requires an attention to detail which seems to tax the patience of working scientists. This high cognitive demand has led to an epidemic of shortcut definitions and interpretations that are simply wrong, sometimes disastrously so-and yet these misinterpretations dominate much of the scientific literature. In light of this problem, we provide definitions and a discussion of basic statistics that are more general and critical than typically found in traditional introductory expositions. Our goal is to provide a resource for instructors, researchers, and consumers of statistics whose knowledge of statistical theory and technique may be limited but who wish to avoid and spot misinterpretations. We emphasize how violation of often unstated analysis protocols (such as selecting analyses for presentation based on the P values they produce) can lead to small P values even if the declared test hypothesis is correct, and can lead to large P values even if that hypothesis is incorrect. We then provide an explanatory list of 25 misinterpretations of P values, confidence intervals, and power. We conclude with guidelines for improving statistical interpretation and reporting.', '2026-07-07 22:28:38');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2402636472', 'medicine', 'Triple-negative breast cancer: challenges and opportunities of a heterogeneous disease', 'Triple-negative breast cancer: challenges and opportunities of a heterogeneous disease', '2016', 2016, 3084, 3084, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnrclinonc.2016.66/MediaObjects/41571_2016_Article_BFnrclinonc201666_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5461122', 'pmc', 'review', 'Nature Reviews Clinical Oncology', '["Giampaolo Bianchini","Justin M. Balko","Ingrid A. Mayer","Melinda E. Sanders","Luca Gianni"]', 'medicine', NULL, '2026-07-07 22:28:45');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3021590963', 'medicine', 'Antibody responses to SARS-CoV-2 in patients with COVID-19', 'Antibody responses to SARS-CoV-2 in patients with COVID-19', '2020', 2020, 3117, 3117, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41591-020-0897-1/MediaObjects/41591_2020_897_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/32350462', 'repository', 'article', 'Nature Medicine', '["Quanxin Long","Bai-Zhong Liu","Haijun Deng","Gui-Cheng Wu","Kun Deng","Yao-Kai Chen","Pu Liao","Jingfu Qiu","Yong Lin","Xue-Fei Cai","De-Qiang Wang","Yuan Hu","Ji‐Hua Ren","Ni Tang","Yinyin Xu","Li-Hua Yu","Zhan Mo","Fang Gong","Xiaoli Zhang","Wen-Guang Tian","Hu Li","Xian-Xiang Zhang","Jiang-Lin Xiang","Hong-Xin Du","Hua-Wen Liu","Chunhui Lang","Xiao-He Luo","Shao-Bo Wu","Xiao-Ping Cui","Zheng Zhou","Manman Zhu","Jing Wang","Cheng-Jun Xue","Xiao-Feng Li","Li Wang","Zhi-Jie Li","Kun Wang","Chang-Chun Niu","Qing-Jun Yang","Xiao-Jun Tang","Yong Zhang","Xia-Mao Liu","Jin-Jing Li","De-Chun Zhang","Fan Zhang","Ping Liu","Jun Yuan","Qin Li","Jieli Hu","Juan Chen","Ailong Huang"]', 'medicine', NULL, '2026-07-07 22:28:45');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4205379795', 'medicine', 'PROTAC targeted protein degraders: the past is prologue', 'PROTAC targeted protein degraders: the past is prologue', '2022', 2022, 3078, 3078, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41573-021-00371-6/MediaObjects/41573_2021_371_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8765495', 'pmc', 'review', 'Nature Reviews Drug Discovery', '["Miklós Békés","David R. Langley","Craig M. Crews"]', 'medicine', NULL, '2026-07-07 22:29:01');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3123497531', 'medicine', 'PRISMA-S: an extension to the PRISMA Statement for Reporting Literature Searches in Systematic Reviews', 'BACKGROUND: Literature searches underlie the foundations of systematic reviews and related review types. Yet, the literature searching component of systematic reviews and related review types is…', '2021', 2021, 2913, 2913, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs13643-020-01542-z/MediaObjects/13643_2020_1542_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7839230', 'pmc', 'article', 'Systematic Reviews', '["Melissa L. Rethlefsen","Shona Kirtley","Siw Waffenschmidt","Ana Patricia Ayala","David Moher","Matthew J. Page","Jonathan Koffel","PRISMA-S Group","Heather B. Blunt","Tara Brigham","Steven Chang","Justin Clark","Aislinn Conway","Rachel Couban","Shelley de Kock","Kelly Farrah","Paul Fehrmann","Margaret Foster","Susan A. Fowler","Julie Glanville","Elizabeth Harris","Lilian Hoffecker","Jaana Isojärvi","David Kaunelis","Hans Ket","Paul Levay","Jennifer A. Lyon","Jessie McGowan","Mohammed Murad","Joey Nicholson","Virginia Pannabecker","Robin Paynter","Rachel Pinotti","Amanda Ross‐White","Margaret Sampson","Tracy Shields","Adrienne Stevens","Anthea Sutton","Elizabeth Weinfurter","Kath Wright","Sarah Young"]', 'medicine', 'BACKGROUND: Literature searches underlie the foundations of systematic reviews and related review types. Yet, the literature searching component of systematic reviews and related review types is often poorly reported. Guidance for literature search reporting has been diverse, and, in many cases, does not offer enough detail to authors who need more specific information about reporting search methods and information sources in a clear, reproducible way. This document presents the PRISMA-S (Preferred Reporting Items for Systematic reviews and Meta-Analyses literature search extension) checklist, and explanation and elaboration. METHODS: The checklist was developed using a 3-stage Delphi survey process, followed by a consensus conference and public review process. RESULTS: The final checklist includes 16 reporting items, each of which is detailed with exemplar reporting and rationale. CONCLUSIONS: The intent of PRISMA-S is to complement the PRISMA Statement and its extensions by providing a checklist that could be used by interdisciplinary authors, editors, and peer reviewers to verify that each component of a search is completely reported and therefore reproducible.', '2026-07-07 22:30:45');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3010126769', 'medicine', 'Angiotensin-converting enzyme 2 (ACE2) as a SARS-CoV-2 receptor: molecular mechanisms and potential therapeutic target', 'A novel infectious disease, caused by severe acute respiratory syndrome coronavirus 2 (SARS-CoV-2), was detected in Wuhan, China, in December 2019.The disease (COVID-19) spread rapidly, reaching…', '2020', 2020, 2824, 2824, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1007%2Fs00134-020-05985-9/MediaObjects/134_2020_5985_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7079879', 'pmc', 'article', 'Intensive Care Medicine', '["Haibo Zhang","Josef Penninger","Yimin Li","Nanshan Zhong","Arthur S. Slutsky"]', 'medicine', 'A novel infectious disease, caused by severe acute respiratory syndrome coronavirus 2 (SARS-CoV-2), was detected in Wuhan, China, in December 2019.The disease (COVID-19) spread rapidly, reaching epidemic proportions in China, and has been found in 27 other countries.As of February 27, 2020, over 82,000 cases of COVID-19 were reported, with > 2800 deaths.No specific therapeutics are available, and current management includes travel restrictions, patient isolation, and supportive medical care.There are a number of pharmaceuticals already being tested [1, 2], but a better understanding of the underlying pathobiology is required.In this context, this article will briefly review the rationale for angiotensin-converting enzyme 2 (ACE2) receptor as a specific target.', '2026-07-07 22:31:49');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3011720761', 'medicine', 'Mental health problems and social media exposure during COVID-19 outbreak', 'Huge citizens expose to social media during a novel coronavirus disease (COVID-19) outbroke in Wuhan, China. We assess the prevalence of mental health problems and examine their association with…', '2020', 2020, 2809, 2809, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0231924.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7162477', 'pmc', 'article', 'PLoS ONE', '["Junling Gao","Pinpin Zheng","Yingnan Jia","Hao Chen","Yimeng Mao","Suhong Chen","Yi Wang","Hua Fu","Junming Dai"]', 'medicine', 'Huge citizens expose to social media during a novel coronavirus disease (COVID-19) outbroke in Wuhan, China. We assess the prevalence of mental health problems and examine their association with social media exposure. A cross-sectional study among Chinese citizens aged≥18 years old was conducted during Jan 31 to Feb 2, 2020. Online survey was used to do rapid assessment. Total of 4872 participants from 31 provinces and autonomous regions were involved in the current study. Besides demographics and social media exposure (SME), depression was assessed by The Chinese version of WHO-Five Well-Being Index (WHO-5) and anxiety was assessed by Chinese version of generalized anxiety disorder scale (GAD-7). multivariable logistic regressions were used to identify associations between social media exposure with mental health problems after controlling for covariates. The prevalence of depression, anxiety and combination of depression and anxiety (CDA) was 48.3% (95%CI: 46.9%-49.7%), 22.6% (95%CI: 21.4%-23.8%) and 19.4% (95%CI: 18.3%-20.6%) during COVID-19 outbroke in Wuhan, China. More than 80% (95%CI:80.9%-83.1%) of participants reported frequently exposed to social media. After controlling for covariates, frequently SME was positively associated with high odds of anxiety (OR = 1.72, 95%CI: 1.31-2.26) and CDA (OR = 1.91, 95%CI: 1.52-2.41) compared with less SME. Our findings show there are high prevalence of mental health problems, which positively associated with frequently SME during the COVID-19 outbreak. These findings implicated the government need pay more attention to mental health problems, especially depression and anxiety among general population and combating with "infodemic" while combating during public health emergency.', '2026-07-07 22:31:51');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2887249435', 'medicine', 'Exosomal PD-L1 contributes to immunosuppression and is associated with anti-PD-1 response', 'Exosomal PD-L1 contributes to immunosuppression and is associated with anti-PD-1 response', '2018', 2018, 2801, 2801, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-018-0392-8/MediaObjects/41586_2018_392_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6095740', 'pmc', 'article', 'Nature', '["Gang Chen","Alexander C. Huang","Wei Zhang","Gao Zhang","Min Wu","Wei Xu","Zi‐Li Yu","Jiegang Yang","Beike Wang","Honghong Sun","Hou-Fu Xia","Qi‐Wen Man","Wenqun Zhong","Leonardo F. Antelo","Bin Wu","Xuepeng Xiong","Xiaoming Liu","Lei Guan","Ting Li","Shujing Liu","Ruifeng Yang","Youtao Lu","Liyun Dong","Suzanne McGettigan","Rajasekharan Somasundaram","Ravi Radhakrishnan","Gordon B. Mills","Yiling Lu","Junhyong Kim","Youhai H. Chen","Haidong Dong","Yi‐Fang Zhao","Giorgos C. Karakousis","Tara C. Mitchell","Lynn M. Schuchter","Meenhard Herlyn","E. John Wherry","Xiaowei Xu","Wei Guo"]', 'medicine', NULL, '2026-07-07 22:31:59');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2911487850', 'medicine', 'Genome-wide meta-analysis of depression identifies 102 independent variants and highlights the importance of the prefrontal brain regions', 'Major depression is a debilitating psychiatric illness that is typically associated with low mood and anhedonia. Depression has a heritable component that has remained difficult to elucidate with…', '2019', 2019, 2804, 2804, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41593-018-0326-7/MediaObjects/41593_2018_326_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6522363', 'pmc', 'review', 'Nature Neuroscience', '["David M. Howard","Mark J. Adams","Toni‐Kim Clarke","Jonathan D. Hafferty","Jude Gibson","Masoud Shirali","Jonathan R. I. Coleman","Saskia P. Hagenaars","Joey Ward","Eleanor M. Wigmore","Clara Alloza","Xueyi Shen","Miruna C. Barbu","Eileen Y. Xu","Heather C. Whalley","Riccardo E. Marioni","David J. Porteous","Gail Davies","Ian J. Deary","Gibran Hemani","Klaus Berger","Henning Teismann","Rajesh Rawal","Volker Arolt","Bernhard T. Baune","Udo Dannlowski","Katharina Domschke","Chao Tian","David A. Hinds","Maciej Trzaskowski","Enda M. Byrne","Stephan Ripke","Daniel J. Smıth","Patrick F. Sullivan","Naomi R. Wray","Gerome Breen","Cathryn M. Lewis","Andrew M. McIntosh"]', 'medicine', 'Major depression is a debilitating psychiatric illness that is typically associated with low mood and anhedonia. Depression has a heritable component that has remained difficult to elucidate with current sample sizes due to the polygenic nature of the disorder. To maximize sample size, we meta-analyzed data on 807,553 individuals (246,363 cases and 561,190 controls) from the three largest genome-wide association studies of depression. We identified 102 independent variants, 269 genes, and 15 genesets associated with depression, including both genes and gene pathways associated with synaptic structure and neurotransmission. An enrichment analysis provided further evidence of the importance of prefrontal brain regions. In an independent replication sample of 1,306,354 individuals (414,055 cases and 892,299 controls), 87 of the 102 associated variants were significant after multiple testing correction. These findings advance our understanding of the complex genetic architecture of depression and provide several future avenues for understanding etiology and developing new treatment approaches.', '2026-07-07 22:31:59');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3017334101', 'medicine', 'CRISPR–Cas12-based detection of SARS-CoV-2', 'CRISPR–Cas12-based detection of SARS-CoV-2', '2020', 2020, 2807, 2807, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41587-020-0513-4/MediaObjects/41587_2020_513_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/9107629', 'pmc', 'article', 'Nature Biotechnology', '["James P. Broughton","Xianding Deng","Guixia Yu","Clare L. Fasching","Venice Servellita","Jasmeet Singh","Xin Miao","Jessica Streithorst","Andrea Granados","Alicia Sotomayor-González","Kelsey C. Zorn","Allan Gopez","Elaine Hsu","Wei Gu","Steve Miller","Chao‐Yang Pan","Hugo Guevara","Debra A. Wadford","Janice S. Chen","Charles Y. Chiu"]', 'medicine', NULL, '2026-07-07 22:31:59');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2338289743', 'medicine', 'Circulating microRNAs in Sera Correlate with Soluble Biomarkers of Immune Activation but Do Not Predict Mortality in ART Treated Individuals with HIV-1 Infection: A Case Control Study', 'INTRODUCTION: The use of anti-retroviral therapy (ART) has dramatically reduced HIV-1 associated morbidity and mortality. However, HIV-1 infected individuals have increased rates of morbidity and…', '2015', 2015, 2741, 2741, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0139981.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4605674', 'pmc', 'article', 'PLoS ONE', '["Daniel D. Murray","Kazuo Suzuki","Matthew Law","Jonel Trebicka","Jacquie Neuhaus","Deborah Wentworth","Margaret Johnson","Michael J. Vjecha","Anthony D. Kelleher","Sean Emery","INSIGHT ESPRIT and SMART Study Groups"]', 'medicine', 'INTRODUCTION: The use of anti-retroviral therapy (ART) has dramatically reduced HIV-1 associated morbidity and mortality. However, HIV-1 infected individuals have increased rates of morbidity and mortality compared to the non-HIV-1 infected population and this appears to be related to end-organ diseases collectively referred to as Serious Non-AIDS Events (SNAEs). Circulating miRNAs are reported as promising biomarkers for a number of human disease conditions including those that constitute SNAEs. Our study sought to investigate the potential of selected miRNAs in predicting mortality in HIV-1 infected ART treated individuals. MATERIALS AND METHODS: A set of miRNAs was chosen based on published associations with human disease conditions that constitute SNAEs. This case: control study compared 126 cases (individuals who died whilst on therapy), and 247 matched controls (individuals who remained alive). Cases and controls were ART treated participants of two pivotal HIV-1 trials. The relative abundance of each miRNA in serum was measured, by RTqPCR. Associations with mortality (all-cause, cardiovascular and malignancy) were assessed by logistic regression analysis. Correlations between miRNAs and CD4+ T cell count, hs-CRP, IL-6 and D-dimer were also assessed. RESULTS: None of the selected miRNAs was associated with all-cause, cardiovascular or malignancy mortality. The levels of three miRNAs (miRs -21, -122 and -200a) correlated with IL-6 while miR-21 also correlated with D-dimer. Additionally, the abundance of miRs -31, -150 and -223, correlated with baseline CD4+ T cell count while the same three miRNAs plus miR-145 correlated with nadir CD4+ T cell count. DISCUSSION: No associations with mortality were found with any circulating miRNA studied. These results cast doubt onto the effectiveness of circulating miRNA as early predictors of mortality or the major underlying diseases that contribute to mortality in participants treated for HIV-1 infection.', '2026-07-07 22:32:50');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2336040088', 'medicine', 'Computational protein–ligand docking and virtual drug screening with the AutoDock suite', 'Computational protein–ligand docking and virtual drug screening with the AutoDock suite', '2016', 2016, 2752, 2752, 'https://media.springernature.com/full/springer-static/image/art%3A10.1038%2Fnprot.2016.051/MediaObjects/41596_2016_Article_BFnprot2016051_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4868550', 'pmc', 'article', 'Nature Protocols', '["Stefano Forli","Ruth Huey","Michael E. Pique","Michel F. Sanner","David S. Goodsell","Arthur J. Olson"]', 'medicine', NULL, '2026-07-07 22:32:52');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3024643080', 'medicine', 'Single-cell landscape of bronchoalveolar immune cells in patients with COVID-19', 'Single-cell landscape of bronchoalveolar immune cells in patients with COVID-19', '2020', 2020, 2749, 2749, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41591-020-0901-9/MediaObjects/41591_2020_901_Fig1_HTML.png', 'https://zenodo.org/record/7647722', 'repository', 'article', 'Nature Medicine', '["Mingfeng Liao","Yang Liu","Jing Yuan","Yanling Wen","Gang Xu","Juanjuan Zhao","Lin Cheng","Jinxiu Li","Xin Wang","Fuxiang Wang","Lei Liu","Ido Amit","Shuye Zhang","Zheng Zhang"]', 'medicine', NULL, '2026-07-07 22:32:53');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3173948537', 'medicine', 'Targeting oxidative stress in disease: promise and limitations of antioxidant therapy', 'Targeting oxidative stress in disease: promise and limitations of antioxidant therapy', '2021', 2021, 2756, 2756, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41573-021-00233-1/MediaObjects/41573_2021_233_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8243062', 'pmc', 'review', 'Nature Reviews Drug Discovery', '["Henry Jay Forman","Hongqiao Zhang"]', 'medicine', NULL, '2026-07-07 22:32:53');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1014257459', 'medicine', 'Association analyses identify 38 susceptibility loci for inflammatory bowel disease and highlight shared genetic risk across populations', 'Association analyses identify 38 susceptibility loci for inflammatory bowel disease and highlight shared genetic risk across populations', '2015', 2015, 2755, 2755, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fng.3359/MediaObjects/41588_2015_BFng3359_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4881818', 'pmc', 'review', 'Nature Genetics', '["Jimmy Z. Liu","Suzanne van Sommeren","Hailiang Huang","Siew C. Ng","Rudi Alberts","Atsushi Takahashi","Stephan Ripke","James Lee","Luke Jostins-Dean","Tejas Shah","Shifteh Abedian","Jae Hee Cheon","Judy H. Cho","Naser Ebrahim Daryani","Lude Franke","Yuta Fuyuno","Ailsa Hart","Ramesh C. Juyal","Garima Juyal","Won Ho Kim","Andrew P. Morris","Hossein Poustchi","William G Newman","Vandana Midha","Timothy R. Orchard","Homayon Vahedi","Ajit Sood","Joseph J.�Y. Sung","Reza Malekzadeh","Harm-Jan Westra","Keiko Yamazaki","Suk-Kyun Yang","Jeffrey C. Barrett","Andre Franke","Behrooz Z Alizadeh","Miles Parkes","B.K. Thelma","Mark Daly","Michiaki Kubo","Carl A. Anderson","Rinse K. Weersma"]', 'medicine', NULL, '2026-07-07 22:32:53');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2560473567', 'precision-nutrition', 'Efficacy of interventions that use apps to improve diet, physical activity and sedentary behaviour: a systematic review', 'BACKGROUND: Health and fitness applications (apps) have gained popularity in interventions to improve diet, physical activity and sedentary behaviours but their efficacy is unclear. This systematic…', '2016', 2016, 1051, 1051, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs13643-022-02067-3/MediaObjects/13643_2022_2067_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5142356', 'pmc', 'review', 'International Journal of Behavioral Nutrition and Physical Activity', '["Stephanie Schöeppe","Stephanie Alley","Wendy Van Lippevelde","Nicola Bray","Susan L. Williams","Mitch J. Duncan","Corneel Vandelanotte"]', 'precision nutrition', 'BACKGROUND: Health and fitness applications (apps) have gained popularity in interventions to improve diet, physical activity and sedentary behaviours but their efficacy is unclear. This systematic review examined the efficacy of interventions that use apps to improve diet, physical activity and sedentary behaviour in children and adults. METHODS: Systematic literature searches were conducted in five databases to identify papers published between 2006 and 2016. Studies were included if they used a smartphone app in an intervention to improve diet, physical activity and/or sedentary behaviour for prevention. Interventions could be stand-alone interventions using an app only, or multi-component interventions including an app as one of several intervention components. Outcomes measured were changes in the health behaviours and related health outcomes (i.e., fitness, body weight, blood pressure, glucose, cholesterol, quality of life). Study inclusion and methodological quality were independently assessed by two reviewers. RESULTS: Twenty-seven studies were included, most were randomised controlled trials (n = 19; 70%). Twenty-three studies targeted adults (17 showed significant health improvements) and four studies targeted children (two demonstrated significant health improvements). Twenty-one studies targeted physical activity (14 showed significant health improvements), 13 studies targeted diet (seven showed significant health improvements) and five studies targeted sedentary behaviour (two showed significant health improvements). More studies (n = 12; 63%) of those reporting significant effects detected between-group improvements in the health behaviour or related health outcomes, whilst fewer studies (n = 8; 42%) reported significant within-group improvements. A larger proportion of multi-component interventions (8 out of 13; 62%) showed significant between-group improvements compared to stand-alone app interventions (5 out of 14; 36%). Eleven studies reported app usage statistics, and three of them demonstrated that higher app usage was associated with improved health outcomes. CONCLUSIONS: This review provided modest evidence that app-based interventions to improve diet, physical activity and sedentary behaviours can be effective. Multi-component interventions appear to be more effective than stand-alone app interventions, however, this remains to be confirmed in controlled trials. Future research is needed on the optimal number and combination of app features, behaviour change techniques, and level of participant contact needed to maximise user engagement and intervention efficacy.', '2026-07-07 22:33:10');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2143709617', 'precision-nutrition', 'Objectively measured physical activity and sedentary time in youth: the International children’s accelerometry database (ICAD)', 'BACKGROUND: Physical activity and sedentary behaviour in youth have been reported to vary by sex, age, weight status and country. However, supporting data are often self-reported and/or do not…', '2015', 2015, 858, 858, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs12966-020-00930-x/MediaObjects/12966_2020_930_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4574095', 'pmc', 'article', 'International Journal of Behavioral Nutrition and Physical Activity', '["Ashley R Cooper","Anna Goodman","Angie S Page","Lauren B. Sherar","Dale Esliger","Esther van Sluijs","Lars Bo Andersen","Sigmund A. Anderssen","Greet Cardon","Rachel Davey","Karsten Froberg","Pedro Curi Hallal","Kathleen F. Janz","Katarzyna Kordas","Susi Kreimler","R. R. Pate","Jardena J. Puder","John J. Reilly","Jo Salmon","Luís B. Sardinha","Anna Timperio","Ulf Ekelund"]', 'precision nutrition', 'BACKGROUND: Physical activity and sedentary behaviour in youth have been reported to vary by sex, age, weight status and country. However, supporting data are often self-reported and/or do not encompass a wide range of ages or geographical locations. This study aimed to describe objectively-measured physical activity and sedentary time patterns in youth. METHODS: The International Children''s Accelerometry Database (ICAD) consists of ActiGraph accelerometer data from 20 studies in ten countries, processed using common data reduction procedures. Analyses were conducted on 27,637 participants (2.8-18.4 years) who provided at least three days of valid accelerometer data. Linear regression was used to examine associations between age, sex, weight status, country and physical activity outcomes. RESULTS: Boys were less sedentary and more active than girls at all ages. After 5 years of age there was an average cross-sectional decrease of 4.2% in total physical activity with each additional year of age, due mainly to lower levels of light-intensity physical activity and greater time spent sedentary. Physical activity did not differ by weight status in the youngest children, but from age seven onwards, overweight/obese participants were less active than their normal weight counterparts. Physical activity varied between samples from different countries, with a 15-20% difference between the highest and lowest countries at age 9-10 and a 26-28% difference at age 12-13. CONCLUSIONS: Physical activity differed between samples from different countries, but the associations between demographic characteristics and physical activity were consistently observed. Further research is needed to explore environmental and sociocultural explanations for these differences.', '2026-07-07 22:33:10');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W764184423', 'precision-nutrition', 'Prevalence of hospital malnutrition in cancer patients: a sub-analysis of the PREDyCES® study', 'Prevalence of hospital malnutrition in cancer patients: a sub-analysis of the PREDyCES® study', '2015', 2015, 258, 258, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1007%2Fs00066-018-1360-9/MediaObjects/66_2018_1360_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/26099900', 'repository', 'article', 'Supportive Care in Cancer', '["on behalf of the PREDyCES® researchers","M. Planas","Julia Álvarez-Hernández","M. León‐Sanz","Sebastián Celaya-Pérez","Krysmarú Araujo","A. García de Lorenzo"]', 'precision nutrition', NULL, '2026-07-07 22:34:21');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2572657948', 'precision-nutrition', 'A review of total &amp; added sugar intakes and dietary sources in Europe', 'Public health policies, including in Europe, are considering measures and recommendations to limit the intake of added or free sugars. For such policies to be efficient and monitored, a precise…', '2017', 2017, 257, 257, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1038%2Fejcn.2016.206/MediaObjects/41430_2017_Article_BFejcn2016206_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5251321', 'pmc', 'review', 'Nutrition Journal', '["Véronique Azaïs‐Braesco","Diewertje Sluik","Matthieu Maillot","Frans J. Kok","Luís A. Moreno"]', 'precision nutrition', 'Public health policies, including in Europe, are considering measures and recommendations to limit the intake of added or free sugars. For such policies to be efficient and monitored, a precise knowledge of the current situation regarding sugar intake in Europe is needed. This review summarizes published or re-analyzed data from 11 representative surveys in Belgium, France, Denmark, Hungary, Ireland, Italy, Norway, The Netherlands, Spain and the UK. Relative intakes were higher in children than in adults: total sugars ranged between 15 and 21% of energy intake in adults and between 16 and 26% in children. Added sugars (or non-milk extrinsic sugars (NMES), in the UK) contributed 7 to 11% of total energy intake in adults and represented a higher proportion of children''s energy intake (11 to 17%). Educational level did not significantly affect intakes of total or added sugars in France and the Netherlands. Sweet products (e.g. confectionery, chocolates, cakes and biscuits, sugar, and jam) were major contributors to total sugars intake in all countries, genders and age groups, followed by fruits, beverages and dairy products. Fruits contributed more and beverages contributed less to adults'' total sugars intakes than to children''s. Added sugars were provided mostly by sweet products (36 to 61% in adults and 40 to 50% in children), followed by beverages (12 to 31% in adults and 20 to 34% in children, fruit juices excluded), then by dairy products (4 to 15% in adults and 6 to 18% in children). Caution is needed, however, as survey methodologies differ on important items such as dietary data collection, food composition tables or estimation of added sugars. Cross-country comparisons are thus not meaningful and overall information might thus not be robust enough to provide a solid basis for implementation of policy measures. Data nevertheless confirm that intakes of total and added sugars are high in the European countries considered, especially in children, and point to sweet products and beverages as the major contributors to added sugar intakes.', '2026-07-07 22:34:21');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2586572493', 'precision-nutrition', 'Low birth weight was the most dominant predictor associated with stunting among children aged 12–23 months in Indonesia', 'Stunting among toddlers is highly prevalent in Indonesia. As a chronic malnutrition problem, stunting is closely related to internal (maternal health) and external factors such as feeding practices,…', '2017', 2017, 267, 267, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1007%2Fs40609-024-00368-0/MediaObjects/40609_2024_368_Fig1_HTML.png', 'https://bmcnutr.biomedcentral.com/track/pdf/10.1186/s40795-017-0130-x', 'repository', 'article', 'BMC Nutrition', '["Ni Ketut Aryastami","Anuraj H. Shankar","Nunik Kusumawardani","Besral Besral","Abas Basuni Jahari","Endang Achadi"]', 'precision nutrition', 'Stunting among toddlers is highly prevalent in Indonesia. As a chronic malnutrition problem, stunting is closely related to internal (maternal health) and external factors such as feeding practices, illness and socio-economics of the community. The purpose of this study was to analyze the relationship between low birth weight (LBW), child feeding practices and neonatal illness with stunting among Indonesian toddlers. For this study, we took data from the 2010 Indonesian National Basic Health Survey (RISKESDAS). Totally 3024 children aged of 12–23 months included in this analysis. Stunting was measured using standardized body length and was defined based on criteria from WHO AnthroII.PC2007. Data analysis was done through bivariate and multivariate logistic regressions. The results showed that the prevalence of stunting among Indonesian toddlers (12 23 months) was 40.4%. Early initiation of breast-feeding and exclusive breast feeding was experienced by 42.7% and 19.7% of the babies. More than half of the babies were given pre-lacteal feeds, while early complementary feeding was given to 68.5% of the subjects. Multivariate analysis showed infants born with LBW were 1.74 times more likely to be stunted (95% CI 1.38–2.19) than those born with normal weight. Boys were 1.27 times (95% CI 1.10–1.48) more likely to be stunted than girls. Infants with a history of neonatal illness, they were 1.23 times (95% CI 0.99–1.50) more susceptible to stunting. Being poor was another indirect variable that significantly associated with stunting (OR = 1.3, 95% CI 1.12–1.51). LBW, gender (boys), history of neonatal illness and poverty are factors related to stunting among children aged 12–23 months in Indonesia, with LBW being the major determinant of stunting.', '2026-07-07 22:34:21');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2762357782', 'precision-nutrition', 'Efficacy and safety of turmeric and curcumin in lowering blood lipid levels in patients with cardiovascular risk factors: a meta-analysis of randomized controlled trials', 'BACKGROUND: Dyslipidemia is an important and common cardiovascular risk factor in the general population. The lipid-lowering effects of turmeric and curcumin are unconfirmed. We performed a…', '2017', 2017, 250, 250, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs12937-022-00816-7/MediaObjects/12937_2022_816_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5637251', 'pmc', 'review', 'Nutrition Journal', '["Si Qin","Lifan Huang","Jiaojiao Gong","Shasha Shen","Juan Huang","Hong Ren","Huaidong Hu"]', 'precision nutrition', 'BACKGROUND: Dyslipidemia is an important and common cardiovascular risk factor in the general population. The lipid-lowering effects of turmeric and curcumin are unconfirmed. We performed a meta-analysis to assess the efficacy and safety of turmeric and curcumin in lowering blood lipids in patients at risk of cardiovascular disease (CVD). METHODS: A comprehensive literature search was conducted on PubMed, Embase, Ovid, Medline and Cochrane Library databases to identify randomized controlled trials (published as of November 2016) that assessed the effect of turmeric and curcumin on blood lipid levels including total cholesterol (TC), low-density lipoprotein cholesterol (LDL-C), high-density lipoprotein cholesterol (HDL-C), and triglycerides (TG). Pooled standardized mean difference (SMD) with 95% confidence interval (CI) was used to assess the effect. RESULTS: The analysis included 7 eligible studies (649 patients). Turmeric and curcumin significantly reduced serum LDL-C (SMD = -0.340, 95% confidence interval [CI]: -0.530 to -0.150, P < 0.0001) and TG (SMD = -0.214, 95% CI: -0.369 to -0.059, P = 0.007) levels as compared to those in the control group. These may be effective in lowering serum TC levels in patients with metabolic syndrome (MetS, SMD = -0.934, 95% CI: -1.289 to -0.579, P < 0.0001), and turmeric extract could possibly have a greater effect on reducing serum TC levels (SMD = -0.584, 95% CI: -0.980 to -0.188, P = 0.004); however, the efficacy is yet to be confirmed. Serum HDL-C levels were not obviously improved. Turmeric and curcumin appeared safe, and no serious adverse events were reported in any of the included studies. CONCLUSIONS: Turmeric and curcumin may protect patients at risk of CVD through improving serum lipid levels. Curcumin may be used as a well-tolerated dietary adjunct to conventional drugs. Further research is required to resolve uncertainties related to dosage form, dose and medication frequency of curcumin.', '2026-07-07 22:34:22');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2901550897', 'precision-nutrition', 'Nutrition in Pediatric Inflammatory Bowel Disease', 'BACKGROUND AND AIMS: A growing body of evidence supports the need for detailed attention to nutrition and diet in children with inflammatory bowel disease (IBD). We aimed to define the steps in…', '2018', 2018, 187, 187, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1097/mpg.0000000000001896.g001', 'https://pubmed.ncbi.nlm.nih.gov/29570147', 'repository', 'article', 'Journal of Pediatric Gastroenterology and Nutrition', '["Erasmo Miele","Raanan Shamir","Marina Aloi","Amit Assa","Christian Braegger","Jiří Bronský","Lissy de Ridder","Johanna C. Escher","Iva Hojsak","Sanja Kolaček","Sibylle Koletzko","Arie Levine","Paolo Lionetti","Massimo Martinelli","Frank M. Ruemmele","Richard K. Russell","Rotem Sigall Boneh","Johan Van Limbergen","Gigi Veereman","Annamaria Staiano"]', 'precision nutrition', 'BACKGROUND AND AIMS: A growing body of evidence supports the need for detailed attention to nutrition and diet in children with inflammatory bowel disease (IBD). We aimed to define the steps in instituting dietary or nutritional management in light of the current evidence and to offer a useful and practical guide to physicians and dieticians involved in the care of pediatric IBD patients. METHODS: A group of 20 experts in pediatric IBD participated in an iterative consensus process including 2 face-to-face meetings, following an open call to Nutrition Committee of the European Society of Pediatric Gastroenterology, Hepatology and Nutrition Porto, IBD Interest, and Nutrition Committee. A list of 41 predefined questions was addressed by working subgroups based on a systematic review of the literature. RESULTS: A total of 53 formal recommendations and 47 practice points were endorsed with a consensus rate of at least 80% on the following topics: nutritional assessment; macronutrients needs; trace elements, minerals, and vitamins; nutrition as a primary therapy of pediatric IBD; probiotics and prebiotics; specific dietary restrictions; and dietary compounds and the risk of IBD. CONCLUSIONS: This position paper represents a useful guide to help the clinicians in the management of nutrition issues in children with IBD.', '2026-07-07 22:35:29');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3203246503', 'precision-nutrition', 'Time-restricted feeding improves blood glucose and insulin sensitivity in overweight patients with type 2 diabetes: a randomised controlled trial', 'BACKGROUND: Time-restricted feeding is an emerging dietary intervention that is becoming increasingly popular. There are, however, no randomised clinical trials of time-restricted feeding in…', '2021', 2021, 194, 194, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs12986-021-00613-9/MediaObjects/12986_2021_613_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8499480', 'pmc', 'article', 'Nutrition & Metabolism', '["Tingting Che","Yan Cheng","Ding‐Yuan Tian","Xin Zhang","Xuejun Liu","Zhongming Wu"]', 'precision nutrition', 'BACKGROUND: Time-restricted feeding is an emerging dietary intervention that is becoming increasingly popular. There are, however, no randomised clinical trials of time-restricted feeding in overweight patients with type 2 diabetes. Here, we explored the effects of time-restricted feeding on glycaemic regulation and weight changes in overweight patients with type 2 diabetes over 12 weeks. METHODS: Overweight adults with type 2 diabetes (n = 120) were randomised 1:1 to two diet groups: time-restricted feeding (n = 60) or control (n = 60). Sixty patients participated in a 10-h restricted feeding treatment program (ad libitum feeding from 8:00 to 18:00 h; fasting between 18:00 and 8:00 h) for 12 weeks. RESULTS: Haemoglobin A1c and body weight decreased in the time-restricted feeding group (- 1.54% ± 0.19 and - 2.98 ± 0.43 kg, respectively) relative to the control group over 12 weeks (p < 0.001). Homeostatic model assessment of β-cell function and insulin resistance changed in the time-restricted feeding group (0.73 ± 0.21, p = 0.005; - 0.51 ± 0.08, p = 0.02, respectively) compared with the control group. The medication effect score, SF-12 score, and the levels of triglycerides, total cholesterol and low-density lipoprotein cholesterol were improved in the time-restricted feeding group (- 0.66 ± 0.17, p = 0.006; 5.92 ± 1.38, p < 0.001; - 0.23 ± 0.08 mmol/L, p = 0.03; - 0.32 ± 0.07 mmol/L, p = 0.01; - 0.42 ± 0.13 mmol/L, p = 0.02, respectively) relative to the control group. High-density lipoprotein cholesterol was not significantly different between the two groups. CONCLUSION: These results suggest that 10-h restricted feeding improves blood glucose and insulin sensitivity, results in weight loss, reduces the necessary dosage of hypoglycaemic drugs and enhances quality of life. It can also offer cardiovascular benefits by reducing atherosclerotic lipid levels. TRIAL REGISTRATION: This study was registered with the Chinese Clinical Trial Registry (ChiCTR-IPR-15006371).', '2026-07-07 22:35:32');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2283413659', 'precision-nutrition', 'Associations among the plasma amino acid profile, obesity, and glucose metabolism in Japanese adults with normal glucose tolerance', 'BACKGROUND: Amino acids (AAs) are emerging as a new class of effective molecules in the etiology of obesity and diabetes mellitus. However, most investigations have focused on subjects with obesity…', '2016', 2016, 190, 190, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1007%2Fs00726-023-03258-5/MediaObjects/726_2023_3258_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4717594', 'pmc', 'article', 'Nutrition & Metabolism', '["Chisa Takashina","Ichizo Tsujino","Taku Watanabe","Shinji Sakaue","Daisuke Ikeda","Asuka Yamada","Takahiro Sato","Hiroshi Ohira","Yoshinori Otsuka","Noriko Oyama‐Manabe","Yoichi M. Ito","Masaharu Nishimura"]', 'precision nutrition', 'BACKGROUND: Amino acids (AAs) are emerging as a new class of effective molecules in the etiology of obesity and diabetes mellitus. However, most investigations have focused on subjects with obesity and/or impaired glucose regulation; the possible involvement of AAs in the initial phase of glucose dysregulation remains poorly understood. Furthermore, little attention has been given to possible associations between the pattern/degree of fat deposition and the plasma AA profile. Our objective was therefore to determine the relationships between plasma AA concentrations and the type/degree of obesity and glucose regulation in Japanese adults with normal glucose tolerance. METHODS: Eighty-three subjects with normal glucose tolerance were classified as obese or nonobese and as visceral obesity or nonvisceral obesity. Correlations between the plasma levels of 23 AAs and somatometric measurements, visceral fat area (VFA), subcutaneous fat area (SFA), and 75-g oral glucose tolerance test results were analyzed. RESULTS: Obesity or visceral obesity was associated with higher levels of branched-chain AAs (isoleucine, leucine, and valine), lysine, tryptophan, cystine, and glutamate but lower levels of asparagine, citrulline, glutamine, glycine, and serine (p < 0.04). Age- and gender-adjusted analyses indicated that VFA was positively correlated with tryptophan and glutamate levels, whereas VFA and SFA were negatively correlated with citrulline, glutamine, and glycine levels (p < 0.05). The fasting and 2-h plasma glucose levels or the homeostasis model assessment of insulin resistance were positively correlated with valine, glutamate, and tyrosine levels but negatively correlated with citrulline, glutamine, and glycine levels. The homeostasis model assessment for the β-cell function index was positively correlated with leucine, tryptophan, valine, and glutamate levels but negatively correlated with citrulline, glutamine, glycine, and serine levels (p < 0.05). CONCLUSIONS: The present study identified specific associations between 10 AAs and the type/degree of obesity, and indices of glucose/insulin regulation, in Japanese adults with preserved glucose metabolism. With the growing concern about the increasing prevalence of obesity and diabetes, the possible roles of these AAs as early markers and/or precursors warrant further investigation.', '2026-07-07 22:35:33');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2923829237', 'precision-nutrition', '“Responses to the Chilean law of food labeling and advertising: exploring knowledge, perceptions and behaviors of mothers of young children”', 'BACKGROUND: In line with calls for action from international health organizations, Chile implemented in June 2016 a set of regulations to tackle the obesity epidemic. The new regulation includes the…', '2019', 2019, 194, 194, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs12966-021-01126-7/MediaObjects/12966_2021_1126_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6375144', 'pmc', 'article', 'International Journal of Behavioral Nutrition and Physical Activity', '["Teresa Correa","Camila Fierro","Marcela Reyes","Francesca R. Dillman Carpentier","Lindsey Smith Taillie","Camila Corvalán"]', 'precision nutrition', 'BACKGROUND: In line with calls for action from international health organizations, Chile implemented in June 2016 a set of regulations to tackle the obesity epidemic. The new regulation includes the mandatory use of front-of-package warning labels on packaged foods/beverages high in energy, sugars, saturated fats and sodium. Additionally, such foods cannot be sold nor offered in daycares/schools and cannot be promoted to children under 14yo. The law is targeted to children; thus, this study examined mothers'' understanding, perceptions, and behaviors associated with the regulation one year after its implementation, using a qualitative approach. METHODS: Nine focus groups of mothers (7-10 people each) of children (2-14yo) were conducted in July 2017 in Santiago-Chile. They were stratified by socioeconomic status (SES) and children''s age. Macrocodes were developed by three researchers, combining an iterative process of deductive and inductive thematic analyses. Quotations representing each category were selected. RESULTS: Mothers understood the new regulation as a policy to fight child obesity and were aware that products with more labels were less healthy than products with fewer labels. Attention and use of labels in the buying decision-making process ranged from participants who did not pay attention to others who relied on them as a quick shortcut (mostly from middle and upper-SES); many mothers indicated changing their purchase habits only when buying new products. Mothers declared that young children accepted school environment changes while teens/preteens resisted them more. Many mothers agreed that schools have become key promoters of food behavioral change. Mothers were less aware about the food marketing regulations. Mothers declared that they perceived that the regulation was changing the perceptions, attitudes and behaviors toward healthier eating patterns. CONCLUSION: After the first year of implementation, the regulation was well known by mothers of diverse SES and different children ages. The degree of use of warning labels was heterogeneous among participants, but most of them agreed that their children, particularly the youngest have positive attitudes toward the regulation and have become promoters of change in their families. Many mothers also expressed that they perceived an important shift toward healthier eating, which may lead to a change in eating social norms. This information contributes to better understand how regulatory actions may influence people''s consumer behaviors.', '2026-07-07 22:35:36');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2589229055', 'precision-nutrition', 'Framework for the design and delivery of organized physical activity sessions for children and adolescents: rationale and description of the ‘SAAFE’ teaching principles', 'The economic burden of inactivity is substantial, with conservative estimates suggesting the global cost to health care systems is more than US$50 billion. School-based programs, including physical…', '2017', 2017, 190, 190, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1007%2Fs11482-021-10002-2/MediaObjects/11482_2021_10002_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5324233', 'pmc', 'review', 'International Journal of Behavioral Nutrition and Physical Activity', '["David R. Lubans","Chris Lonsdale","Kristen E. Cohen","Narelle Eather","Mark R. Beauchamp","Philip J. Morgan","Benjamin D. Sylvester","Jordan Smith"]', 'precision nutrition', 'The economic burden of inactivity is substantial, with conservative estimates suggesting the global cost to health care systems is more than US$50 billion. School-based programs, including physical education and school sport, have been recommended as important components of a multi-sector, multi-system approach to address physical inactivity. Additionally, community sporting clubs and after-school programs (ASPs) offer further opportunities for young people to be physically active outside of school. Despite demonstrating promise, current evidence suggests school-based physical activity programs, community sporting clubs and ASPs are not achieving their full potential. For example, physical activity levels in physical education (PE) and ASP sessions are typically much lower than recommended. For these sessions to have the strongest effects on young people''s physical activity levels and their on-going physical literacy, they need to improve in quality and should be highly active and engaging. This paper presents the Supportive, Active, Autonomous, Fair, Enjoyable (SAAFE) principles, which represent an evidence-based framework designed to guide the planning, delivery and evaluation of organized physical activity sessions in school, community sport and ASPs. In this paper we provide a narrative and integrative review of the conceptual and empirical bases that underpin this framework and highlight implications for knowledge translation and application.', '2026-07-07 22:35:41');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3135893275', 'precision-nutrition', 'Dietary patterns and associations with biomarkers of inflammation in adults: a systematic review of observational studies', 'BACKGROUND: Evidence indicates that low-grade inflammation is involved in manychronic diseases of ageing. Modifiable lifestyle factors including dietcan affect low-grade inflammation. Dietary…', '2021', 2021, 183, 183, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs12937-021-00674-9/MediaObjects/12937_2021_674_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7955619', 'pmc', 'review', 'Nutrition Journal', '["Michael J. Hart","Susan J. Torres","Sarah A. McNaughton","Catherine M. Milte"]', 'precision nutrition', 'BACKGROUND: Evidence indicates that low-grade inflammation is involved in manychronic diseases of ageing. Modifiable lifestyle factors including dietcan affect low-grade inflammation. Dietary patterns allow assessment of the complex interactions of food nutrients and health and may be associated with inflammatory status. This systematic review aimed to summarises current evidence from observational studies for associations between dietary patterns and inflammatory biomarkers in the general adult population. This review followed the PRISMA guidelines. METHODS: We conducted a systematic search in Embase, CINAHL Complete, Global Health and MEDLINE complete databases. Search terms included terms for diet ("dietary patterns", "diet scores") and inflammation ("inflammation", "c-reactive protein", "interleukin"). RESULTS: The search produced 7161 records. Duplicates were removed leaving 3164 for screening. There were 69 studies included (60 cross-sectional, 9 longitudinal). Papers included studies that were: 1) observational studies; 2) conducted in community-dwelling adults over 18 years of age; 3) assessed dietary patterns; 4) measured specified biomarkers of inflammation and 5) published in English. Dietary patterns were assessed using diet scores (n = 45), data-driven approaches (n = 22), both a data-driven approach and diet score (n = 2). The most frequently assessed biomarkers were CRP (n = 64) and/or IL-6 (n = 22). Cross-sectionally the majority of analyses reported an association between higher diet scores (mostly Mediterranean and anti-inflammatory diet scores) and lower inflammatory markers with 82 significant associations from 133 analyses. Only 22 of 145 cross-sectional analyses using data-driven approaches reported an association between a dietary patterns and lower inflammatory markers; the majority reported no association. Evidence of an association between dietary patterns and inflammatory markers longitudinally is limited, with the majority reporting no association. CONCLUSIONS: Adherence to healthy, Mediterranean and anti-inflammatory dietary scores, appear to be associated with lower inflammatory status cross-sectionally. Future research could focus on longitudinal studies using a potential outcomes approach in the data analysis. TRIAL REGISTRATION: PROSPERO Registration Number CRD42019114501.', '2026-07-07 22:35:48');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2528820978', 'precision-nutrition', 'Level of nutrition knowledge and its association with fat consumption among college students', 'BACKGROUND: Intake of saturated fat, trans fat, and cholesterol has been associated with increased risk of coronary heart disease. The aim of this study was to explore whether increased nutrition…', '2016', 2016, 178, 178, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs40795-024-00871-9/MediaObjects/40795_2024_871_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5050673', 'pmc', 'article', 'BMC Public Health', '["Najat Yahia","Carrie Brown","Melyssa Rapley","Mei Chung"]', 'precision nutrition', 'BACKGROUND: Intake of saturated fat, trans fat, and cholesterol has been associated with increased risk of coronary heart disease. The aim of this study was to explore whether increased nutrition knowledge is associated with a reduction in the consumption of unhealthy fats in a sample of university students. METHODS: A sample of 231 students, with a mean age of 20 years, was recruited from university campus during spring 2012. Students completed a validated questionnaire related to students'' demographic, nutrition knowledge, and daily fat consumption. Weight, height, and waist circumference were measured. Data were analyzed using one-way ANOVA, chi-square, and student''s t-test. RESULTS: Results indicate that female students have greater nutrition knowledge than male students (the mean nutrition score for women was 5 points higher than that of men (P = 0.01)). Nutrition knowledge was negatively correlated with fat and cholesterol intake. Students who consumed more than 35 % calories from fat or >300 mg of cholesterol daily had lower mean nutrition scores than those students with lower fat or cholesterol intake (8 points lower and 7.9 points lower, respectively). Using linear regression for nutrition scores on estimated saturated fat intake and cholesterol intake (controlling for gender, height, weight, age, and dieting), nutrition scores were negatively associated with saturated fat intake (-0.15, P <0.0001) and cholesterol intake (-1.38, P <0.0001). CONCLUSION: Students with greater nutritional knowledge consumed less unhealthy fats and cholesterol. This finding magnifies the role of nutrition education as a potential tool in health campaigns to promote healthy eating patterns among college students. Results of this pilot study can inform the design of future nutrition education intervention studies to assess the efficacy of nutrition knowledge on pattern of fat consumption among college students.', '2026-07-07 22:35:49');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2002133710', 'precision-nutrition', 'Resistant dextrin, as a prebiotic, improves insulin resistance and inflammation in women with type 2 diabetes: a randomised controlled clinical trial', 'Improvement of insulin resistance and inflammation is a basic strategy in the management of type 2 diabetes. There is limited evidence that prebiotics improve insulin resistance and inflammation.…', '2015', 2015, 148, 148, 'https://static.cambridge.org/binary/version/id/urn:cambridge.org:id:binary-alt:20160921074308-77014-mediumThumb-S0007114514003675_fig1g.jpg', 'https://pubmed.ncbi.nlm.nih.gov/27028002', 'repository', 'article', 'British Journal Of Nutrition', '["Akbar Aliasgharzadeh","Parvin Dehghan","Bahram Pourghassem Gargari","Mohammad Asghari Jafarabadi"]', 'precision nutrition', 'Improvement of insulin resistance and inflammation is a basic strategy in the management of type 2 diabetes. There is limited evidence that prebiotics improve insulin resistance and inflammation. However, the ameliorating effect of resistant dextrin, as a prebiotic, on insulin resistance and inflammation in patients with type 2 diabetes has not been investigated so far. Therefore, the present study aimed to examine the effects of resistant dextrin on insulin resistance and inflammation in type 2 diabetic patients. In a randomised controlled clinical trial, fifty-five women with type 2 diabetes were assigned to two groups: the intervention group (n 30) and the control group (n 25). The intervention group received a daily supplement of 10 g resistant dextrin and the control group received a similar amount of maltodextrin as placebo for 8 weeks. Fasting plasma glucose (FPG), HbA1c, insulin, high-sensitivity C-reactive protein (hs-CRP), IL-6, TNF-α, malondialdehyde (MDA) and serum endotoxin concentrations were measured before and after the intervention. Data were analysed using SPSS (version 13). Paired and unpaired t tests and ANCOVA were used to compare quantitative variables after the intervention. Patients supplemented with resistant dextrin exhibited a significant decrease in fasting insulin (20.1 pmol/l, 22.8%), homeostasis model assessment of insulin resistance (1.3, 24.9%), quantitative insulin sensitivity check index (0.2, 7.2%), IL-6 (1.4 pg/ml, 28.4 %), TNF-α (5.4 pg/ml, 18.8 %), MDA (1.2 nmol/ml, 25.6 %) and endotoxin (6.2 endotoxin units/ml, 17.8%) concentrations than those supplemented with maltodextrin (P< 0.05). Decreases in FPG (0.05 mmol/l, 0.6%), HbA1c (0.5%, 9.6%) and hs-CRP (2.7 ng/ml, 35.1%) concentrations in the resistant dextrin group were not significant when compared with the maltodextrin group. In conclusion, resistant dextrin supplementation can modulate inflammation and improve insulin resistance in women with type 2 diabetes.', '2026-07-07 22:37:12');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2605899784', 'precision-nutrition', 'Nutrition education improves dietary diversity of children 6-23 months at community-level: Results from a cluster randomized controlled trial in Malawi', 'BACKGROUND: Low dietary quality and quantity and inappropriate feeding practices can cause undernutrition. Poor nutritional status in early childhood is associated with growth faltering. The…', '2017', 2017, 142, 142, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0175216.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5398527', 'pmc', 'article', 'PLoS ONE', '["Judith Kuchenbecker","Anika Reinbott","Beatrice Mtimuni","Michael Krawinkel","Irmgard Jordan"]', 'precision nutrition', 'BACKGROUND: Low dietary quality and quantity and inappropriate feeding practices can cause undernutrition. Poor nutritional status in early childhood is associated with growth faltering. The objective of the study was to assess the potential of community-based nutrition education to improve height-for-age z-scores in children 6-23 months of age. METHODS AND FINDINGS: We carried out a cluster-randomized-controlled trial to assess the effectiveness of nutrition education. A total of 24 Extension Planning Area Sections served as clusters. The selection criteria were: the position of the extension officer was staffed and the sections had been selected by the project for activities in its first project year. The sections were randomized into intervention and control restricted on mean height for age Z-score using baseline information. In the intervention area, food security activities and community-based nutrition education was implemented. The control area received food security activities only. At baseline (2011) and endline (2014), caregivers with a child below two years of age were enrolled. Data assessment included anthropometric measurements, interviews on socio-economic status, dietary intake and feeding practices. A difference-in-differences estimator was used to calculate intervention effects. A positive impact on child dietary diversity was observed (B (SE) = 0.39 (0.15), p = 0.01; 95%CI 0.09-0.68). There was a non-significant positive intervention effect on mean height-for-age z-scores (B (SE) = 0.17 (0.12), p = 0.15; 95%CI -0.06-0.41). LIMITATIONS: The 24h dietary recalls used to measure dietary diversity did not consider quantities of consumed foods. Unrecorded poor quality of consumed foods might have masked a potential benefit of increased child dietary diversity on growth. CONCLUSIONS: Participatory community-based nutrition education for caregivers improved child dietary diversity even in a food insecure area. Nutrition education should be part of programs in food insecure settings aiming at ameliorating food insecurity among communities.', '2026-07-07 22:37:20');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3015769550', 'precision-nutrition', 'Mutual interaction between endoplasmic reticulum and mitochondria in nonalcoholic fatty liver disease', 'Abstract Nonalcoholic fatty liver disease (NAFLD) is a common metabolic syndrome. Imbalances between liver lipid output and input are the direct causes of NAFLD, and hepatic steatosis is the…', '2020', 2020, 143, 143, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs12944-020-01210-0/MediaObjects/12944_2020_1210_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7155254', 'pmc', 'review', 'Lipids in Health and Disease', '["Jin Wang","Wanping He","Ping-Ju Tsai","Pei-Hsuan Chen","Manxiang Ye","Jiao Guo","Zhengquan Su"]', 'precision nutrition', 'Abstract Nonalcoholic fatty liver disease (NAFLD) is a common metabolic syndrome. Imbalances between liver lipid output and input are the direct causes of NAFLD, and hepatic steatosis is the pathological premise and basis for NAFLD progression. Mutual interaction between endoplasmic reticulum stress (ERS) and oxidative stress play important roles in NAFLD pathogenesis. Notably, mitochondria-associated membranes (MAMs) act as a structural bridges for functional clustering of molecules, particularly for Ca 2+, lipids, and reactive oxygen species (ROS) exchange. Previous studies have examined the crucial roles of ERS and ROS in NAFLD and have shown that MAM structural and functional integrity determines normal ER- mitochondria communication. Upon disruption of MAM integrity, miscommunication directly or indirectly causes imbalances in Ca2+ homeostasis and increases ERS and oxidative stress. Here, we emphasize the involvement of MAMs in glucose and lipid metabolism, chronic inflammation and insulin resistance in NAFLD and summarize MAM-targeting drugs and compounds, most of which achieve their therapeutic or ameliorative effects on NAFLD by improving MAM integrity. Therefore, targeting MAMs may be a viable strategy for NAFLD treatment. This review provides new ideas and key points for basic NAFLD research and drug development centred on mitochondria and the endoplasmic reticulum.', '2026-07-07 22:37:25');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2800020550', 'precision-nutrition', 'Status of lipid and lipoprotein in female breast cancer patients at initial diagnosis and during chemotherapy', 'BACKGROUND: The lipid profile status among breast cancer patients at initial diagnosis and during chemotherapy remain controversial. The aim of this study is to study the status of lipid and…', '2018', 2018, 142, 142, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs12885-023-10683-y/MediaObjects/12885_2023_10683_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5910614', 'pmc', 'article', 'Lipids in Health and Disease', '["Xin Li","Zili Liu","Yutuan Wu","He Wu","Wei Dai","Bilal Arshad","Zhou Xu","Hao Li","Kainan Wu","Lingquan Kong"]', 'precision nutrition', 'BACKGROUND: The lipid profile status among breast cancer patients at initial diagnosis and during chemotherapy remain controversial. The aim of this study is to study the status of lipid and lipoprotein in female breast cancer patients at initial diagnosis and during chemotherapy. METHODS: We conducted a retrospective cohort study of the status of the lipid and lipoprotein in 1054 primarily diagnosed breast cancer patients and 2483 normal controls with age stratification, from July 2015 to October 2016. At the same time, the status of lipid and lipoprotein were also analyzed among 394 breast cancer patients before and after adjuvant chemotherapy. RESULTS: The incidence of dyslipidemia was significantly lower in breast cancer group(42.98%) compared to normal group(58.28%)(P < 0.001). The levels of total cholesterol (TC), triglycerides (TG), HDL cholesterol (HDL-C), LDL cholesterol (LDL-C) among breast cancer group were significantly lower compared to normal control group (P < 0.05). With age stratification, the levels of TC and LDL-C in breast cancer group were still significantly lower than those in control group (P < 0.001). And the levels of TC, TG, LDL-C, apolipoprotein B were significantly higher among post chemotherapeutic patients compared to prechemotherapeutic patients, however HDL-C and Apo-A1 levels were contrary. CONCLUSIONS: Breast cancer patients have lower incidence of dyslipidemia compared to normal populations. However, the situation of dyslipidemia may become worsened after chemotherapy. Therefore, lipid monitoring and dyslipidemia prevention and treatment should be conducted for breast cancer patients at initial diagnosis and during chemotherapy.', '2026-07-07 22:37:26');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2345857515', 'precision-nutrition', 'Association between serum selenium level and type 2 diabetes mellitus: a non-linear dose–response meta-analysis of observational studies', 'BACKGROUND: The association between serum selenium levels and type 2 diabetes mellitus (T2DM) is controversial. We performed a systematic review and non-linear dose-response meta-analysis of…', '2015', 2015, 142, 142, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1007%2Fs12011-023-03900-z/MediaObjects/12011_2023_3900_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4855440', 'pmc', 'review', 'Nutrition Journal', '["Xinliang Wang","Tubao Yang","Jie Wei","Guanghua Lei","Chao Zeng"]', 'precision nutrition', 'BACKGROUND: The association between serum selenium levels and type 2 diabetes mellitus (T2DM) is controversial. We performed a systematic review and non-linear dose-response meta-analysis of observational studies to investigate the association in the present study. METHODS: A comprehensive literature search was conducted using MEDLINE and EMBASE databases. A pooled odds ratio (OR) and related 95 % confidence interval (95 % CI) for T2DM between the highest and lowest serum selenium categories, and a non-linear dose-response relationship between selenium and T2DM were estimated. RESULTS: A total of five studies (of 13,460 participants) were identified as meeting the inclusion criteria. The pooled OR indicated that there was a significantly higher prevalence of T2DM in the highest category of blood selenium compared with the lowest (OR = 1.63, 95 % CI: 1.04-2.56, P = 0.033). Moreover, a significant non-linear dose-response relationship was observed between serum selenium levels and T2DM (P 132.5 μg/l). CONCLUSIONS: The positive association between serum selenium levels and T2DM existed in populations with relatively low levels and high levels of serum selenium, indicating a likely U-shaped non-linear dose-response relationship between serum selenium and T2DM.', '2026-07-07 22:37:27');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2180342883', 'precision-nutrition', 'Impact of diet on cardiometabolic health in children and adolescents', 'The manifestation of cardiovascular risk factors, such as hypertension, diabetes, and particularly obesity begins in children and adolescents, with deleterious effects for cardiometabolic health at…', '2015', 2015, 141, 141, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs12887-022-03341-y/MediaObjects/12887_2022_3341_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4647337', 'pmc', 'review', 'Nutrition Journal', '["Anna N. Funtikova","Estanis Navarro","Rowaedh Ahmed Bawaked","Montserrat Fitó","Helmut Schröder"]', 'precision nutrition', 'The manifestation of cardiovascular risk factors, such as hypertension, diabetes, and particularly obesity begins in children and adolescents, with deleterious effects for cardiometabolic health at adulthood. Although the impact of diet on cardiovascular risk factors has been studied extensively in adults, showing that their cardiometabolic health is strongly lifestyle-dependent, less is known about this impact in children and adolescents. In particular, little is known about the relationship between their dietary patterns, especially when derived a posteriori, and cardiovascular risk. An adverse association of cardiovascular health and increased intake of sodium, saturated fat, meat, fast food and soft drinks has been reported in this population. In contrast, vitamin D, fiber, mono-and poly-unsaturated fatty acids, dairy, fruits and vegetables were positively linked to cardiovascular health.The aim of this review was to summarize current epidemiological and experimental evidence on the impact of nutrients, foods, and dietary pattern on cardiometabolic health in children and adolescents. A comprehensive review of the literature available in English and related to diet and cardiometabolic health in this population was undertaken via the electronic databases PubMed, Cochrane Library, and Medline.', '2026-07-07 22:37:28');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2766713131', 'precision-nutrition', 'Associations of the perceived and objective neighborhood environment with physical activity and sedentary time in New Zealand adolescents', 'BACKGROUND: There is accumulating evidence supporting the association between neighborhood built environments and adults'' physical activity (PA) and sedentary time (ST); however, few studies have…', '2017', 2017, 140, 140, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs12889-023-16243-0/MediaObjects/12889_2023_16243_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5655834', 'pmc', 'article', 'International Journal of Behavioral Nutrition and Physical Activity', '["Erica Hinckson","Ester Cerin","Suzanne Mavoa","Melody Smith","Hannah Badland","Tom Stewart","Scott Duncan","Grant Schofield"]', 'precision nutrition', 'BACKGROUND: There is accumulating evidence supporting the association between neighborhood built environments and adults'' physical activity (PA) and sedentary time (ST); however, few studies have investigated these associations in adolescents. A better understanding of the features of the built environment that encourage PA or ST is therefore of critical importance to promote health and wellbeing in adolescents. The aim of this study was to estimate the associations of GIS-determined and perceived walkability components in individual residential buffer zones with accelerometer-assessed moderate-to-vigorous physical activity (MVPA) and ST in adolescents. METHODS: The Built Environment in Adolescent New Zealanders (BEANZ) study was conducted in two cities (Auckland and Wellington) during the 2013-2014 academic school years. The exposure measures were subjective and objective environmental indices of activity-friendliness using four residential buffers. Road network buffers were calculated around participant''s residential addresses using the sausage buffer approach at 250 m, 500 m, 1 km, and 2 km scales. A 25 m radius was used for the buffers. Data were analysed using Generalized Additive Mixed Models in R. RESULTS: Data were analysed from 524 participants (15.78 ± 1.62 years; 45% male). Participants accumulated ~114 min/day of moderate-to-vigorous PA (MVPA) and ~354 min/day of ST during accelerometer wear-time (~828 min/day). The estimated difference in MVPA between participants with the 1st and 3rd quartiles observed values on the composite subjective environmental index of activity-friendliness (perceived land use mix - diversity, street connectivity and aesthetics) was equivalent to ~8 min/day (~56 MVPA min/week) and for the objective environmental index of activity-friendliness (gross residential density and number of parks within 2 km distance from home) was ~6 min of MVPA/day (~45 MVPA min/week). When both indices were entered in a main-effect model, both indices remained significantly correlated with MVPA with sex as a moderator. The predicted difference in sedentary time between those with the minimum and maximum observed values on the subjective index of non-sedentariness was ~20 min/day. CONCLUSIONS: The combined assessment of the main effects of subjective and objective indices of activity-friendliness on NZ adolescents'' PA and ST showed positive relationships with MVPA for the subjective index only. The subjective index was a significant correlate of PA in both girls and boys, while the objective index was significant only in boys when sex was entered as a moderator. Further research is warranted to understand the relationships of ST with the built environment.', '2026-07-07 22:37:37');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2901314851', 'precision-nutrition', 'Relationship of insulin resistance estimated by triglyceride glucose index to arterial stiffness', 'BACKGROUND: Insulin resistance (IR) is an important risk factor for subclinical atherosclerosis. This study evaluated the relationship between the triglyceride glucose (TyG) index, which is a simple…', '2018', 2018, 136, 136, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs12944-018-0914-2/MediaObjects/12944_2018_914_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6260653', 'pmc', 'article', 'Lipids in Health and Disease', '["Ki‐Bum Won","Gyung-Min Park","Sang‐Eun Lee","In‐Jeong Cho","Hyeon Chang Kim","Byoung Kwon Lee","Hyuk‐Jae Chang"]', 'precision nutrition', 'BACKGROUND: Insulin resistance (IR) is an important risk factor for subclinical atherosclerosis. This study evaluated the relationship between the triglyceride glucose (TyG) index, which is a simple and reliable surrogate marker for IR, and arterial stiffness. METHODS: This study included 2560 Korean subjects without a previous history of coronary artery disease, stroke, and malignancies who participated in a community-based cohort study. Arterial stiffness was measured using the brachial-ankle pulse wave velocity (baPWV). RESULTS: All participants were stratified into four groups based on the quartile of the TyG index. The prevalence of metabolic syndrome and diabetes significantly increased with increasing TyG index quartile. The mean baPWV was significantly different among all groups (group I [lowest]: 1421 ± 242 vs. group II: 1480 ± 244 vs. group III: 1534 ± 260 vs. group IV [highest]: 1575 ± 279 cm/s; p < 0.001). The TyG index values were correlated with baPWV (r = 0.224, p < 0.001). Multiple regression analysis showed that age (β = 0.410), male gender (β = 0.051), increased blood pressure (β = 0.266), and TyG index (β = 0.158) were associated with baPWV (p < 0.05, respectively). TyG index was independently related to baPWV in both non-diabetics and diabetics. CONCLUSIONS: The TyG index is independently associated with arterial stiffness in a relatively healthy Korean population.', '2026-07-07 22:37:51');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2610570440', 'precision-nutrition', 'Change in diet in the period from adolescence to early adulthood: a systematic scoping review of longitudinal studies', 'BACKGROUND: Late adolescence to early adulthood is a period of lifestyle change and personal development which may influence dietary behaviour. Understanding dietary trajectories across this age…', '2017', 2017, 134, 134, 'https://media.springernature.com/lw685/springer-static/image/art%3A10.1186%2Fs12966-017-0518-7/MediaObjects/12966_2017_518_Fig1_HTML.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5418762', 'pmc', 'article', 'International Journal of Behavioral Nutrition and Physical Activity', '["Eleanor Winpenny","Tarra L. Penney","Kirsten Corder","Martin White","Esther van Sluijs"]', 'precision nutrition', 'BACKGROUND: Late adolescence to early adulthood is a period of lifestyle change and personal development which may influence dietary behaviour. Understanding dietary trajectories across this age range may help in targeting interventions appropriately. This scoping review aimed to assess how longitudinal change in diet is conceptualised and measured between the ages of 13 to 30. METHODS: We searched Medline, SCOPUS, Embase, PsycInfo (EBSCO), ASSIA, Sportdiscus, and Web of Science Core Collection (January 2016) using search terms combining diet outcomes, longitudinal methods and indicators of adolescent or young adult age. Titles and abstracts were screened and data extracted following published guidelines for scoping reviews. Data were analysed to summarize key data on each study and map availability of longitudinal data on macronutrients and food groups by age of study participants. RESULTS: We identified 98 papers reporting on 40 studies. Longitudinal dietary data were available on intake of energy, key macronutrients and several food groups, but this data had significant gaps and limitations. Most studies provided only two or three waves of data within the age range of interest and few studies reported data collected beyond the early twenties. A range of dietary assessment methods were used, with greater use of less comprehensive dietary assessment methods among studies reporting food group intakes. CONCLUSION: Despite limited availability of longitudinal data to aid understanding of dietary trajectories across this age range, this scoping review identified areas with scope for further evidence synthesis. We identified a paucity of longitudinal data continuing into the mid and late twenties, variability in (quality of) dietary assessment methods, and a large variety of macronutrients and food groups studied. Advances in dietary assessment methodologies as well as increased use of social media may facilitate new data collection to further understanding of changing diet across this life stage.', '2026-07-07 22:37:51');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2193640425', 'precision-nutrition', 'The descriptive epidemiology of accelerometer-measured physical activity in older adults', 'BACKGROUND: Objectively measured physical activity between older individuals and between populations has been poorly described. We aimed to describe and compare the variation in accelerometry data in…', '2016', 2016, 135, 135, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs12889-022-14333-z/MediaObjects/12889_2022_14333_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4704380', 'pmc', 'article', 'International Journal of Behavioral Nutrition and Physical Activity', '["K. Berkemeyer","Katrien Wijndaele","Tom White","Andrew Cooper","Robert Luben","Kate Westgate","Simon J. Griffin","K.‐T. Khaw","Nicholas J. Wareham","Søren Brage"]', 'precision nutrition', 'BACKGROUND: Objectively measured physical activity between older individuals and between populations has been poorly described. We aimed to describe and compare the variation in accelerometry data in older UK (EPIC-Norfolk) and American (NHANES) adults. METHODS: Physical activity was measured by uniaxial accelerometry in 4,052 UK (49-91 years) and 3459 US older adults (49-85 years). We summarized physical activity as volume (average counts/minute), its underlying intensity distribution, and as time spent 809 counts/minute is used 18.7% of people reached the 30 min/day threshold. By comparison, 2.5% and 9.5% of American older adults accumulated activity at these levels, respectively. CONCLUSION: As assessed by objectively measured physical activity, the majority of older adults in this UK study did not meet current activity guidelines. Older adults in the UK were more active overall, but also spent more time being sedentary than US adults.', '2026-07-07 22:37:52');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2272672613', 'precision-nutrition', 'Whole grain consumption trends and associations with body weight measures in the United States: results from the cross sectional National Health and Nutrition Examination Survey 2001–2012', 'BACKGROUND: The purpose of this study was (1) to describe intakes of total grain and whole grain in the United States over the past 12 years and major dietary sources, and (2) to determine the…', '2015', 2015, 133, 133, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1007%2Fs00394-018-1615-3/MediaObjects/394_2018_1615_Fig1_HTML.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4722728', 'pmc', 'article', 'Nutrition Journal', '["Ann M. Albertson","Marla Reicks","Nandan Joshi","Carolyn Gugger"]', 'precision nutrition', 'BACKGROUND: The purpose of this study was (1) to describe intakes of total grain and whole grain in the United States over the past 12 years and major dietary sources, and (2) to determine the relationship between whole grain intake and adiposity measures for children and adults. METHODS: Cross-sectional dietary data from the continuous National Health and Nutrition Examination Survey 2001-12 (6 2-year cycles) for children 6-18 years (n = 15,280) and adults 19+ years (n = 29,683) were linked to the My Pyramid and Food Patterns Equivalents Databases to assess daily intake of total grain and whole grain. These populations were classified into groups based on average whole grain intake: 0 ounce equivalents (oz eq)/day, > 0 and <1 oz eq/day, and ≥1 oz eq/day. Within these classifications, body mass index, waist circumference, and percent overweight/obese were identified. Regression and logistic regression analyses were used to assess associations between these dependent variables and whole grain intake. RESULTS: Adults consumed a mean 0.72 whole grain oz eq/day in 2001-02 and 0.97 oz eq/day in 2011-12 and children consumed a mean 0.56 whole grain oz eq/day in 2001-02 and 0.74 oz eq/day in 2011-12. While over 70 % of children and 60 % of adults met daily intake recommendations for total grain, less than 1.0 and 8.0 % percent of children and adults, respectively, met whole grain recommendations in 2011-12. Adults and children who consumed whole grain had significantly better intakes of nutrients and dietary fiber compared to non-consumers. From 2001 to 2012, grain mixed dishes and yeast breads were the leading sources of total grain, while yeast breads and ready to eat cereals were the leading sources of whole grain for both children and adults. Multiple regression analysis showed a significant, inverse relationship between body mass index and waist circumference with respect to whole grain intake after adjustment for covariates in both children and adults (p < 0.05). Similarly, logistic regression analysis showed a significant inverse relationship between percent overweight/obese and whole grain intake (p < 0.05). CONCLUSIONS: Although most children and adults meet daily intake goals for grain foods overall, whole grain as a portion of total grain intake continues to be consumed at levels well below recommendations. The data from the current study suggest that greater whole grain consumption is associated with better intakes of nutrients and healthier body weight in children and adults. Continued efforts to promote increased intake of whole grain foods are warranted.', '2026-07-07 22:37:52');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2322786801', 'precision-nutrition', 'Achieving dietary recommendations and reducing greenhouse gas emissions: modelling diets to minimise the change from current intakes', 'BACKGROUND: Average population dietary intakes do not reflect the wide diversity of dietary patterns across the population. It is recognised that most people in the UK do not meet dietary…', '2016', 2016, 126, 126, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1038%2Fs41430-017-0080-z/MediaObjects/41430_2017_80_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4823893', 'pmc', 'article', 'International Journal of Behavioral Nutrition and Physical Activity', '["Graham Horgan","Amandine Perrin","Stephen Whybrow","Jennie I. Macdiarmid"]', 'precision nutrition', 'BACKGROUND: Average population dietary intakes do not reflect the wide diversity of dietary patterns across the population. It is recognised that most people in the UK do not meet dietary recommendations and have diets with a high environmental impact, but changing dietary habits has proved very difficult. The purpose of this study was to investigate the diversity in dietary changes needed to achieve a healthy diet and a healthy diet with lower greenhouse gas emissions (GHGE) (referred to as a sustainable diet) by taking into account each individual''s current diet and then minimising the changes they need to make. METHODS: Linear programming was used to construct two new diets for each adult in the UK National Diet and Nutrition Survey (n = 1491) by minimising the changes to their current intake. Stepwise changes were applied until (i) dietary recommendations were achieved and (ii) dietary recommendations and a GHGE target were met. First, gradual changes (≤50%) were made to the amount of any foods currently eaten. Second, new foods were added to the diet. Third, greater reductions (≤75%) were made to the amount of any food currently eaten and finally, foods were removed from the diet. RESULTS: One person out of 1491 in the sample met all the dietary requirements based on their reported dietary intake. Only 7.5 and 4.6 % of people achieved a healthy diet and a sustainable diet, respectively, by changing the amount of any food they currently ate by up to 50 %. The majority required changes to the amount of each food eaten plus the addition of new foods. Fewer than 5 % had to remove foods they ate to meet recommendations. Sodium proved the most difficult nutrient recommendation to meet. The healthy diets and sustainable diets produced a 15 and 27 % reduction in greenhouse gas emissions respectively. CONCLUSIONS: Since healthy diets alone do not produce substantial reductions in greenhouse gas emissions, dietary guidelines need to include recommendations for environmental sustainability. Minimising the shift from current dietary intakes is likely to make dietary change more realistic and achievable.', '2026-07-07 22:38:53');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2620105395', 'precision-nutrition', 'Association between home food preparation skills and behaviour, and consumption of ultra-processed foods: Cross-sectional analysis of the UK National Diet and nutrition survey (2008–2009)', 'BACKGROUND: ''Ultra-processed foods'' (UPF) have been industrially processed and tend to be higher in saturated fat, sodium and sugar than other foods. There is some evidence that consumption of UPF is…', '2017', 2017, 125, 125, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1007%2Fs00394-018-1870-3/MediaObjects/394_2018_1870_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5442685', 'pmc', 'article', 'International Journal of Behavioral Nutrition and Physical Activity', '["Matthew Chak Leung Lam","Jean Adams"]', 'precision nutrition', 'BACKGROUND: ''Ultra-processed foods'' (UPF) have been industrially processed and tend to be higher in saturated fat, sodium and sugar than other foods. There is some evidence that consumption of UPF is associated with overweight, obesity and related diseases. In developed countries more than half of dietary energy is attributed to UPF. One reason for reliance on UPF may be poor home food preparation skills or infrequent use of these. This relationship has been previously proposed but not tested. We examined the relationship between home food preparation skills and behaviour and consumption of UPF. METHODS: We used data from adults in the UK National Diet & Nutrition Survey 2008-09. Home food preparation skills and behaviours of adults (n = 509) were assessed using questions on confidence using eight cooking techniques, confidence cooking 10 foods, ability to prepare a cake or biscuits without help, and whether or not participants prepared a main meal five or more days per week. Individuals'' UPF consumption was determined from four-day estimated diet diaries. Associations were adjusted for age, gender, occupational social class and household composition. RESULTS: In fully adjusted models, individuals who were confident with all 10 foods (adjusted beta (95% CI) = -3.76 (-6.02 to -1.50)), able to bake cakes or biscuits without help (-3.87 (-6.62 to -1.12)), and cooked a main meal at least five days a week (-2.84 (-5.43 to -0.24)) consumed a lower percentage of dietary energy from UPF. CONCLUSIONS: In UK adults better home food preparation skills and more frequent use of these skills tended to be cross-sectionally associated with lower UPF consumption. Greater encouragement of these skills may help reduce reliance on UPF.', '2026-07-07 22:38:54');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2478807248', 'precision-nutrition', 'Development of sedentary behavior across childhood and adolescence: longitudinal analysis of the Gateshead Millennium Study', 'BACKGROUND: In many parts of the world policy and research interventions to modify sedentary behavior of children and adolescents are now being developed. However, the evidence to inform these…', '2016', 2016, 116, 116, 'https://media.springernature.com/lw685/springer-static/image/art%3A10.1186%2Fs12966-016-0413-7/MediaObjects/12966_2016_413_Fig1_HTML.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4971697', 'pmc', 'article', 'International Journal of Behavioral Nutrition and Physical Activity', '["Xanne Janssen","Kay Mann","Laura Basterfield","Kathryn Parkinson","Mark S. Pearce","Jessica Reilly","Ashley Adamson","John J. Reilly"]', 'precision nutrition', 'BACKGROUND: In many parts of the world policy and research interventions to modify sedentary behavior of children and adolescents are now being developed. However, the evidence to inform these interventions (e.g. how sedentary behavior changes across childhood and adolescence) is limited. This study aimed to assess longitudinal changes in sedentary behavior, and examine the degree of tracking of sedentary behavior from age 7y to 15y. METHODS: Participants were part of the Gateshead Millennium Study cohort. Measures were made at age 7y (n = 507), 9y (n = 510), 12y (n = 425) and 15y (n = 310). Participants were asked to wear an ActiGraph GT1M and accelerometer epochs were defined as sedentary when recorded counts were ≤25 counts/15 s. Differences in sedentary time and sedentary fragmentation were examined using the Friedman test. Tracking was examined using Spearman''s correlation coefficients and trajectories over time were assessed using multilevel linear spline modelling. RESULTS: Median daily sedentary time increased from 51.3% of waking hours at 7y to 74.2% at 15y. Sedentary fragmentation decreased from 7y to 15y. The median number of breaks/hour decreased from 8.6 to 4.1 breaks/hour and the median bout duration at 50% of the cumulative sedentary time increased from 2.4 min to 6.4 min from 7y to 15y. Tracking of sedentary time and sedentary fragmentation was moderate from 7y to 15y however, the rate of change differed with the steepest increases/decreases seen between 9y and 12y. CONCLUSION: In this study, sedentary time was high and increased to almost 75% of waking hours at 15y. Sedentary behavior became substantially less fragmented as children grew older. The largest changes in sedentary time and sedentary fragmentation occurred between 9y to 12y, a period which spans the transition to secondary school. These results can be used to inform future interventions aiming to change sedentary behavior.', '2026-07-07 22:39:23');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2194477794', 'precision-nutrition', 'Reds are more important than greens: how UK supermarket shoppers use the different information on a traffic light nutrition label in a choice experiment', 'BACKGROUND: Colour coded front-of-pack nutrition labelling (''traffic light labelling'') has been recommended for use in the UK since 2006. The voluntary scheme is used by all the major retailers and…', '2015', 2015, 106, 106, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1007%2Fs12144-025-08847-z/MediaObjects/12144_2025_8847_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4676872', 'pmc', 'article', 'International Journal of Behavioral Nutrition and Physical Activity', '["Peter Scarborough","Anne Matthews","Helen Eyles","Asha Kaur","Charo Hodgkins","Monique Raats","Mike Rayner"]', 'precision nutrition', 'BACKGROUND: Colour coded front-of-pack nutrition labelling (''traffic light labelling'') has been recommended for use in the UK since 2006. The voluntary scheme is used by all the major retailers and some manufacturers. It is not clear how consumers use these labels to make a single decision about the relative healthiness of foods. Our research questions were: Which of the four nutrients on UK traffic light labels (total fat, saturated fat, sugar and salt) has the most influence on decisions? Do green lights or red lights have a greater influence? Are there age and gender differences in how people use the colour and nutrient information? METHODS: We recruited participants from a UK supermarket chain membership list to conduct an online choice experiment in May 2014. We analysed data using multilevel logisitic models with food choices (n = 3321) nested in individuals (n = 187) as the unit of analysis. RESULTS: A food with more reds was 11.4 (95% confidence intervals: 10.3, 12.5) times less likely to be chosen as healthy, whereas a food with more greens was 6.1 (5.6, 6.6) times more likely to be chosen as healthy. Foods with better colours on saturated fat and salt were 7.3 (6.7, 8.0) and 7.1 (6.5, 7.8) times more likely to be chosen as healthy - significantly greater than for total fat (odds ratio 4.8 (4.4, 5.3)) and sugar (5.2 (4.7, 5.6)). Results were broadly similar for different genders and age groups. CONCLUSIONS: We found that participants were more concerned with avoiding reds than choosing greens, and that saturated fat and salt had a greater influence on decisions regarding healthiness than total fat and sugar. This could influence decisions about food reformulation and guidance on using nutrition labelling.', '2026-07-07 22:40:36');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3111004176', 'precision-nutrition', 'A cross-sectional survey of the readiness of consumers to adopt an environmentally sustainable diet', 'BACKGROUND: The current food system is responsible for significant environmental damage therefore, encouraging consumers to adopt an environmentally sustainable diet is a key public health challenge.…', '2020', 2020, 95, 95, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs12937-020-00644-7/MediaObjects/12937_2020_644_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7727219', 'pmc', 'article', 'Nutrition Journal', '["Amy Culliford","Jane Bradbury"]', 'precision nutrition', 'BACKGROUND: The current food system is responsible for significant environmental damage therefore, encouraging consumers to adopt an environmentally sustainable diet is a key public health challenge. Dietary guidelines have been developed that outline recommendations for purchasing and consuming food in an environmentally sustainable manner, but they have not yet been incorporated in UK national dietary guidelines. METHODS: Via an online survey of UK adults, we evaluated consumers'' perceptions of the environmental benefit of various sustainable diet recommendations, their readiness to adopt these behaviours using the stage of change construct of the Transtheoretical Model, the factors that influenced their food choices, and their current consumption of plant- and animal-based sources of protein. Additionally, we investigated how demographic characteristics and food choice motives were associated with perceived environmental benefit of and readiness to adopt these sustainable diet recommendations. RESULTS: The survey was completed by 442 participants (66% female, 80% aged 25-54 years, 85% with higher education). The majority of participants considered the recommendations to ''reduce consumption of air-freighted foods'' (79%), ''reduce food waste'' (75%), and ''buy locally grown produce'' (78%) to have a high environmental benefit, whereas a smaller proportion of participants perceived ''prioritise plant-based proteins'' (42%) and ''choose organic produce'' (27%) to have a high environmental benefit. Differences in perceptions and readiness to adopt sustainable dietary behaviours were observed between demographic groups, with women significantly more likely than men to be in action/maintenance (A/M) stages of change for prioritising plant proteins (OR 0.54), and younger participants more likely to be in pre-contemplation/contemplation (PC/C) stages of change for ''choose organic produce'' (OR 2.03) and ''choose sustainable fish'' (OR 2.45). Health, cost, environmental sustainability and taste were the most commonly reported food choice motives. Reporting environmental sustainability as a food choice motive was associated with readiness to adopt sustainable diet recommendations. CONCLUSIONS: We found that consumers in the UK are engaged with some aspects of sustainable diets but remain resistant to others. The results of this study indicate that acceptable dietary guidelines could be developed to address environmental sustainability. Several behaviours were identified that consumers were willing to adopt, but there were barriers preventing them, highlighting that policy action is required to enable behaviour change to occur. Differences between demographic groups highlight potential targets for future campaigns promoting sustainable diets.', '2026-07-07 22:41:48');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3011820459', 'precision-nutrition', 'Effectiveness of prescribing physical activity in parks to improve health and wellbeing - the park prescription randomized controlled trial', 'BACKGROUND: Programs promoting population health through physical activity (PA) and exposure to nature are popular, but few have been evaluated in randomized-controlled trials (RCTs). OBJECTIVE: To…', '2020', 2020, 96, 96, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs12966-020-00941-8/MediaObjects/12966_2020_941_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7079356', 'pmc', 'article', 'International Journal of Behavioral Nutrition and Physical Activity', '["Falk Müller‐Riemenschneider","Nick Petrunoff","Jiali Yao","Alwyn Ng","Angelia Sia","Anbumalar Ramiah","Michael Wong","Jane Han","Bee Choo Tai","Léonie Uijtdewilligen"]', 'precision nutrition', 'BACKGROUND: Programs promoting population health through physical activity (PA) and exposure to nature are popular, but few have been evaluated in randomized-controlled trials (RCTs). OBJECTIVE: To investigate the effectiveness of a park prescription intervention (PPI) for improving total moderate-to-vigorous PA (MVPA), other PA related behaviors, quality of life (QoL) and cardio-metabolic health among adults. METHODS: Healthy individuals aged 40 to 65 years were recruited through community health screenings and randomly assigned to 1) PPI: face-to-face Park Prescription + invitation to weekly exercise sessions in parks, or 2) control: standard PA materials. After the six-month intervention, participants completed accelerometer assessments, questionnaires on health behaviors and QoL, and health screenings. Independent sample t-tests were used to compare outcomes between groups, with secondary analysis adjusted for co-variates via multiple linear regression. A p-value <0.05 was considered statistically significant. RESULTS: Eighty participants were allocated to each group. Participants with mean age of 51.1 (Standard Deviation: 6.3) years were predominantly female (79%) and of Chinese ethnicity (81%). Participation in the group exercise started at 48% and declined to 24% by week 26. At six-months, 145 (91%) participants attended health screenings for outcome measure collection, and 126 (79%) provided valid accelerometer data. Time spent in MVPA favored the PPI group but this difference was not statistically significant (4.4 (- 43.8, 52.7) minutes/week; when removing 2 extreme outliers 26.8 (- 9.7, 63.4) minutes/week). Time spent in parks (147.5 (2.1, 292.9) minutes/month), PA in parks (192.5 (59.5, 325.5) minutes/month), and recreational PA (48.7 (1.4, 96.0) minutes/week) were significantly greater in the PPI group. PPI also significantly improved psychological QoL (4.0 (0.0, 8.0). DISCUSSION: PPI improved park use, PA in parks, recreational PA, and psychological QoL but not total MVPA. Future RCTs'' are warranted to investigate PPI in different target populations and to provide further evidence for improvements in health outcomes. TRIAL REGISTRATION: ClinicalTrials.gov NCT02615392, 26 November 2015.', '2026-07-07 22:41:48');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2946925417', 'precision-nutrition', 'Validity and reliability of a food frequency questionnaire for assessing dietary intake among Shanghai residents', 'BACKGROUND: Few localized food frequency questionnaires (FFQ) have been developed and used in Chinese nutrition surveys despite China''s large population and diverse dietary habits. METHOD: We…', '2019', 2019, 95, 95, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs12937-019-0454-2/MediaObjects/12937_2019_454_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6533674', 'pmc', 'article', 'Nutrition Journal', '["Jiajie Zang","Baozhang Luo","Su-ying Chang","Shan Jin","Chengdi Shan","Lifang Ma","Zhenni Zhu","Changyi Guo","Shurong Zou","Xiaodong Jia","Fan Wu"]', 'precision nutrition', 'BACKGROUND: Few localized food frequency questionnaires (FFQ) have been developed and used in Chinese nutrition surveys despite China''s large population and diverse dietary habits. METHOD: We analyzed data collected in two waves (six months apart) of the Shanghai Diet and Health Study in 2012-2013, from 1623 Shanghai residents (798 men and 825 women) older than 18 years. The results of 3-day 24-h dietary recalls (HDR) plus condiment weighing were used to evaluate the validity and reliability of the SDHS FFQ. RESULTS: The median and first and third quartiles for energy intake (in kcal) derived from the FFQ1 and FFQ2 were 1566.5 (1310.1-1869.6) and 1561.9 (1280.2-1838.4), respectively, of which protein (in g) was 54.3 (42.5-65.8) and 52.9 (42.4-64.5), fat (in g) was 49.8 (37.2-64.7) and 47.9 (34.9-61.9), and carbohydrates (in g) was 227.3 (180.8-277.9) and 228.1 (182.2-275.2) in the reliability analysis. The median and first and third quartiles for energy-intake differences between the FFQ1 and the 3-day 24-HDR with condiment weighing was 59.3 (- 255.5-341.6), of which protein was - 5.2 (- 18.7-7.8) and fat was - 11.2 (- 30.8-5.3). The adjusted Spearman''s correlations were 0.33-0.77 for validity and 0.46-0.79 for reliability. The intra-class correlation coefficients exceeded 0.46 (validity) and 0.47 (reliability) for macronutrient intake. The consistency between the same and adjacent quartiles was approximately 80% for various nutrients. CONCLUSION: The reliability and comparative validity of the SDHS FFQ is similar to FFQs that are used worldwide.', '2026-07-07 22:41:48');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2105686058', 'precision-nutrition', 'Classification of occupational activity categories using accelerometry: NHANES 2003–2004', 'BACKGROUND: An individual''s occupational activity (OA) may contribute significantly to daily physical activity (PA) and sedentary behavior (SB). However, there is little consensus about which…', '2015', 2015, 96, 96, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs12966-024-01627-1/MediaObjects/12966_2024_1627_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4499449', 'pmc', 'article', 'International Journal of Behavioral Nutrition and Physical Activity', '["Jeremy A. Steeves","Catrine Tudor‐Locke","Rachel A. Murphy","George A. King","Eugene C. Fitzhugh","Tamara B. Harris"]', 'precision nutrition', 'BACKGROUND: An individual''s occupational activity (OA) may contribute significantly to daily physical activity (PA) and sedentary behavior (SB). However, there is little consensus about which occupational categories involve high OA or low OA, and the majority of categories are unclassifiable with current methods. The purpose of this study was to present population estimates of accelerometer-derived PA and SB variables for adults (n = 1112, 20-60 years) working the 40 occupational categories collected during the 2003-2004 National Health and Nutrition Examination Survey (NHANES). METHODS: ActiGraph accelerometer-derived total activity counts/day (TAC), activity counts/minute, and proportion of wear time spent in moderate-to-vigorous PA [MVPA], lifestyle, and light PA organized by occupational category were ranked in ascending order and SB was ranked in descending order. Summing the ranks of the six accelerometer-derived variables generated a summary score for each occupational category, which was re-ranked in ascending order. Higher rankings indicated higher levels of OA, lower rankings indicated lower levels of OA. Tertiles of the summary score were used to establish three mutually exclusive accelerometer-determined OA groupings: high OA, intermediate OA, and low OA. RESULTS: According to their summary score, ''farm and nursery workers'' were classified as high OA and ''secretaries, stenographers, and typists'' were classified as low OA. Consistent with previous research, some low OA occupational categories (e.g., ''engineers, architects, and scientists'', ''technicians and related support occupations'', ''management related occupations'', ''executives, administrators, and managers'', ''protective services'', and ''writers, artists, entertainers, and athletes'') associated with higher education and income had relatively greater amounts of MVPA compared to other low OA occupational categories, likely due to the greater percentage of men in those occupations and/or the influence of higher levels of leisure time PA. Men had more TAC, activity counts/minute and time in MVPA, but similar proportions of SB compared to women in all three OA groupings. CONCLUSIONS: Objectively measured PA allowed for a more precise estimate of the amount of PA and SB associated with different occupations and facilitated systematic classification of the 40 different occupational categories into three distinct OA groupings. This information provides new opportunities to explore the relationship between OA and health outcomes.', '2026-07-07 22:41:48');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2766721026', 'precision-nutrition', 'Serum uric acid and non-alcoholic fatty liver disease in non-obesity Chinese adults', 'BACKGROUND: Previous studies found elevated serum uric acid (SUA) was associated with the development or progression of non-alcoholic fatty liver disease (NAFLD) in general population; in this study…', '2017', 2017, 95, 95, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1038%2Fsrep38605/MediaObjects/41598_2016_Article_BFsrep38605_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5644248', 'pmc', 'article', 'Lipids in Health and Disease', '["Xiaoya Zheng","Lilin Gong","Rong Luo","Hua Chen","Bin Peng","Wei Ren","Yonghong Wang"]', 'precision nutrition', 'BACKGROUND: Previous studies found elevated serum uric acid (SUA) was associated with the development or progression of non-alcoholic fatty liver disease (NAFLD) in general population; in this study we aim to investigate the association of SUA and the severity of NAFLD based on grade of fatty liver on ultrasonography in non-obese subjects. METHODS: Data were obtained from subjects via routine physical examinations in the Public Health Center of our hospital between 2011 and 2014. The data included completed anthropometry and blood biochemical indicators and the results of abdominal ultrasound. The diagnosis of NAFLD was according to the clinical diagnosis of the Guidelines for the diagnosis and treatment of nonalcoholic fatty liver disease in 2008. RESULTS: In total, 95,924 subjects were analyzed in this study. The prevalence rate of lean-NAFLD was 8.16%, among which 7.58% had mild steatosis, and 0.58% had moderate and severe steatosis. The prevalence of fatty liver was increased progressively with SUA. Among which the prevalence of mild fatty liver from Q1 to Q4 were 10.33%, 18.39%, 23.11% and 25.93%; the prevalence of moderate and severe fatty liver from Q1 to Q4 were 1.06%, 2.82%, 5.05% and 7.27%. Lean-subjects with hyperuricemia had an OR of 1.718 (95% CI 1.622-1.820) to have NAFLD, after adjusted for other metabolic disorders. The area under curve (AUC) for detecting mild fatty liver based on SUA was 0.70; and the AUC for detecting moderate and severe fatty liver based on SUA was 0.78. CONCLUSIONS: Our data showed positive associations between elevated SUA levels and lean-NAFLD risk in the inland Chinese adults, independent of other metabolic factors. Our study also suggests that SUA could be considered as a simple and non-invasive method to follow up patients with lean-NAFLD.', '2026-07-07 22:41:48');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2465978957', 'precision-nutrition', 'Patterns and Determinants of Double-Burden of Malnutrition among Rural Children: Evidence from China', 'Chinese children are facing dual burden of malnutrition-coexistence of under-and over-nutrition. Little systematic evidence exists for explaining the simultaneous presence of under-and…', '2016', 2016, 93, 93, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0158119.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4938417', 'pmc', 'article', 'PLoS ONE', '["Nan Zhang","Laia Bécares","Tarani Chandola"]', 'precision nutrition', 'Chinese children are facing dual burden of malnutrition-coexistence of under-and over-nutrition. Little systematic evidence exists for explaining the simultaneous presence of under-and over-nutrition. This study aims to explore underlying mechanisms of under-and over-nutrition among children in rural China. This study used a nationwide longitudinal dataset of children (N = 5,017) from 9 provinces across China, with four exclusively categories of nutritional outcomes including under-nutrition (stunting and underweight), over-nutrition (overweight only including obesity), paradox (stunted overweight), with normal nutrition as reference. Multinomial logit models (Level-1: occasions; Level-2: children; Level-3: villages) were fitted which corrected for non-independence of observations due to geographic clustering and repeated observations of individuals. A mixture of risk factors at the individual, household and neighbourhood levels predicted under-and over-nutrition among children in rural China. Improved socioeconomic status and living in more urbanised villages reduced the risk of stunted overweight among rural children in China. Young girls appeared to have higher risk of under-nutrition, and the risk decreased with age more markedly than for boys up to age 5. From age 5 onwards, boys tended to have higher risk of under-nutrition than girls. Girls aged around 12 and older were less likely to suffer from under-nutrition, while boys'' higher risk of under-nutrition persisted throughout adolescence. Children were less likely to suffer from over-nutrition compared to normal nutrition. Boys tended to have an even lower risk of over-nutrition than girls and the gender difference widened with age until adolescence. Our results have important policy implications that improving household economic status, in particular, maternal education and health insurance for children, and living environment are important to enhance rural children''s nutritional status in China. Investments in early years of childhood can be effective to reduce gender inequality in nutritional health in rural China.', '2026-07-07 22:42:16');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2762656590', 'precision-nutrition', 'Does replacing sedentary behaviour with light or moderate to vigorous physical activity modulate inflammatory status in adults?', 'BACKGROUND: Sedentary behaviour, obesity and insulin resistance are associated with pro-inflammatory status. Limited data on whether physical activity modulates inflammatory status and counteracts…', '2017', 2017, 89, 89, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs13098-023-01040-x/MediaObjects/13098_2023_1040_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5637054', 'pmc', 'article', 'International Journal of Behavioral Nutrition and Physical Activity', '["Catherine M. Phillips","Christina Dillon","Ivan J. Perry"]', 'precision nutrition', 'BACKGROUND: Sedentary behaviour, obesity and insulin resistance are associated with pro-inflammatory status. Limited data on whether physical activity modulates inflammatory status and counteracts obesity and insulin resistance associated low-grade inflammation exist. Our objective was to investigate associations between objectively measured physical activity and inflammatory status, and specifically whether substituting daily sedentary behaviour with light activity or moderate to vigorous physical activity (MVPA), is associated with beneficial alterations to the inflammatory profile among middle-aged adults and those at increased cardiometabolic risk (obese and insulin resistant subjects). METHODS: Data are from a sub-sample of the Mitchelstown cohort; a population-based cross-sectional sample of 2047 Irish adults. Physical activity intensity and duration were measured in 396 participants for 7-consecutive days using the GENEActiv accelerometer. Isotemporal regression analysis examined the associations between replacing 30 min per day of sedentary behaviour with equal amounts of light activity and MVPA on inflammatory factors (serum acute-phase reactants, adipocytokines, pro-inflammatory cytokines and white blood cells (WBC)). RESULTS: Reallocating 30 min of sedentary time with MVPA was associated with a more favourable inflammatory profile characterized by higher adiponectin and lower complement component C3 (C3), leptin, interleukin 6 (IL-6) and WBC concentrations (P 75th percentile) subjects. Among the non-obese and non-insulin resistant subjects substituting 30 min of sedentary behaviour with MVPA was associated with decreased C3, IL-6 and WBC concentrations. CONCLUSIONS: Replacing sedentary behaviour with MVPA modulates pro-inflammatory status. These findings, which highlight the need for the developing randomized trials aimed at lowering cardiometabolic risk, warrant further investigation.', '2026-07-07 22:42:52');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2515491022', 'precision-nutrition', 'Cost effectiveness of a multi-component school-based physical activity intervention targeting adolescents: the ‘Physical Activity 4 Everyone’ cluster randomized trial', 'BACKGROUND: Few school-based interventions have been successful in reducing physical activity decline and preventing overweight and obesity in adolescent populations. As a result, few cost…', '2016', 2016, 90, 90, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs12889-019-6965-0/MediaObjects/12889_2019_6965_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4994166', 'pmc', 'article', 'International Journal of Behavioral Nutrition and Physical Activity', '["Rachel Sutherland","Penny Reeves","Elizabeth Campbell","David R. Lubans","Philip J. Morgan","Nicole Nathan","Luke Wolfenden","Anthony D. Okely","Karen Gillham","Lynda Davies","John Wiggers"]', 'precision nutrition', 'BACKGROUND: Few school-based interventions have been successful in reducing physical activity decline and preventing overweight and obesity in adolescent populations. As a result, few cost effectiveness analyses have been reported. The aim of this paper is to report the cost and cost effectiveness of the Physical Activity 4 Everyone (PA4E1) intervention which was a multi-component intervention implemented in secondary schools located in low-income communities. Cost effectiveness was assessed using both the physical activity and weight status trial outcomes. METHODS: Intervention and Study Design: The PA4E1 cluster randomised controlled trial was implemented in 10 Australian secondary schools (5 intervention: 5 control) and consisted of intervention schools receiving seven physical activity promotion strategies and six additional strategies that supported school implementation of the intervention components. Costs associated with physical activity strategies, and intervention implementation strategies within the five intervention schools were estimated and compared to the costs of usual physical activity practices of schools in the control group. The total cost of implementing the intervention was estimated from a societal perspective, based on the number of enrolled students in the target grade at the start of the intervention (Grade 7, n = 837). Economic Outcomes: The economic analysis outcomes were cost and incremental cost effectiveness ratios for the following: minutes of moderate-to-vigorous physical activity (MVPA) per day gained, MET hours gained per person/day; Body Mass Index (BMI) unit avoided; and 10% reduction in BMI z-score. RESULTS: The intervention cost AUD $329,952 over 24 months, or AUD$394 per student in the intervention group. This resulted in a cost effectiveness ratio of AUD$56 ($35-$147) per additional minute of MVPA, AUD$1 ($0.6-$2.7) per MET hour gained per person per day, AUD$1408 ($788-$6,570) per BMI unit avoided, and AUD$563 ($282-$3,942) per 10% reduction in BMI z-score. CONCLUSION: PA4E1 is a cost effective intervention for increasing the physical activity levels and reducing unhealthy weight gain in adolescence, a period in which physical activity typically declines. Additional modelling could explore the potential economic impact of the intervention on morbidity and mortality. TRIAL REGISTRATION: Australian New Zealand Clinical Trials Registry ACTRN12612000382875.', '2026-07-07 22:42:52');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2893215083', 'precision-nutrition', 'Rapid Eating Assessment for Participants [shortened version] scores are associated with Healthy Eating Index-2010 scores and other indices of diet quality in healthy adult omnivores and vegetarians', 'The Healthy Eating Index-2010 is a measure of diet quality as portrayed by the Dietary Guidelines for Americans; however, computing the Healthy Eating Index score is time consuming and requires…', '2018', 2018, 82, 82, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs12937-020-00646-5/MediaObjects/12937_2020_646_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6162919', 'pmc', 'article', 'Nutrition Journal', '["Carol S. Johnston","Courtney Bliss","Jessica Knurick","Cameron Scholtz"]', 'precision nutrition', 'The Healthy Eating Index-2010 is a measure of diet quality as portrayed by the Dietary Guidelines for Americans; however, computing the Healthy Eating Index score is time consuming and requires trained personnel. The Rapid Eating Assessment for Participants [shortened version] is a simple measure that quickly, in less than 10 min, assesses diet quality in a clinical or research setting. This research evaluated the degree of correlation between these two methods of scoring diet quality, as well as between these methods and other indicators of diet quality, including the nutrient density of the diet, the dietary potential renal acid load, urine pH, and plasma vitamin C concentrations. The research design was a secondary data analysis, and participants were healthy adults (n = 81) self-classified as omnivorous, vegetarian, or vegan. Confounding variables were identified and controlled using partial correlations. The two methods of scoring diet quality were significantly correlated (r = 0.227, p = 0.047). Both the Healthy Eating Index and the Rapid Eating Assessment for Participants scoring methods were correlated to nutrient density of the diets (r = 0.474 and r = 0.472 respectively, p < 0.001) as well as to the dietary potential renal acid load and urinary pH (r ranging from 0.304-0.341, p ≤ 0.002). The Rapid Eating Assessment for Participants, but not the Healthy Eating Index, was significantly correlated to plasma vitamin C concentrations (r = 0.500, p < 0.001 and 0.192, p = 0.095 respectively). These results in combination with ease of use and low cost suggest that the Rapid Eating Assessment for Participants measure is a useful tool for assessing diet quality.', '2026-07-07 22:44:21');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2951287001', 'precision-nutrition', 'Preserving the quality of life: nutrition in the ICU', 'Critically ill patients require adequate nutritional support to meet energy requirements both during and after intensive care unit (ICU) stay to protect against severe catabolism and prevent…', '2019', 2019, 82, 82, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs13054-019-2415-8/MediaObjects/13054_2019_2415_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6570623', 'pmc', 'review', 'Critical Care', '["Pierre Singer"]', 'precision nutrition', 'Critically ill patients require adequate nutritional support to meet energy requirements both during and after intensive care unit (ICU) stay to protect against severe catabolism and prevent significant deconditioning. ICU patients often suffer from chronic critical illness causing an increase in energy expenditure, leading to proteolysis and related muscle loss. Careful supplementation and modulation of caloric and protein intake can avoid under- or overfeeding, both associated with poorer outcomes. Indirect calorimetry is the preferred method for assessing resting energy expenditure and the appropriate caloric and protein intake to counter energy and muscle loss. Physical exercise may have favorable effects on muscle preservation and should be considered even early in the hospital course of a critically ill patient. After liberation from the ventilator or during non-invasive ventilation, oral intake should be carefully evaluated and, in case of severe dysphagia, should be avoided and replaced by enteral of parenteral nutrition. Upon transfer from the ICU to the ward, adequate nutrition remains essential for long-term rehabilitation success and continued emphasis on sufficient nutritional supplementation in the ward is necessary to avoid a suboptimal nutritional state.', '2026-07-07 22:44:21');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3034605371', 'precision-nutrition', 'Nutritional Support in Coronavirus 2019 Disease', 'The epidemic that broke out in Chinese Wuhan at the beginning of 2020 presented how important the rapid diagnosis of malnutrition (elevating during intensive care unit stay) and the immediate…', '2020', 2020, 70, 70, 'https://pub.mdpi-res.com/medicina/medicina-56-00289/article_deploy/html/images/medicina-56-00289-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7353890', 'pmc', 'review', 'Medicina', '["Ewa Stachowska","Marcin Folwarski","Dominika Jamioł-Milc","Dominika Maciejewska","Karolina Skonieczna‐Żydecka"]', 'precision nutrition', 'The epidemic that broke out in Chinese Wuhan at the beginning of 2020 presented how important the rapid diagnosis of malnutrition (elevating during intensive care unit stay) and the immediate implementation of caloric and protein-balanced nutrition care are. According to specialists from the Chinese Medical Association for Parenteral and Enteral Nutrition (CSPEN), these activities are crucial for both the therapy success and reduction of mortality rates. The Chinese have published their recommendations including principles for the diagnosis of nutritional status along with the optimal method for nutrition supply including guidelines when to introduce education approach, oral nutritional supplement, tube feeding, and parenteral nutrition. They also calculated energy demand and gave their opinion on proper monitoring and supplementation of immuno-nutrients, fluids and macronutrients intake. The present review summarizes Chinese observations and compares these with the latest European Society for Clinical Nutrition and Metabolism guidelines. Nutritional approach should be an inseparable element of therapy in patients with COVID-19.', '2026-07-07 22:47:42');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2978801380', 'precision-nutrition', 'Correlates of stunting among under-five children in Bangladesh: a multilevel approach', 'BACKGROUND: Child malnutrition still remains a major cause of childhood morbidity and mortality in Bangladesh. This study aims to determine the prevalence and identify the associated risk factors of…', '2019', 2019, 67, 67, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs40795-019-0304-9/MediaObjects/40795_2019_304_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7050784', 'pmc', 'article', 'BMC Nutrition', '["Papia Sultana","Md. Mahfuzur Rahman","Jahanara Akter"]', 'precision nutrition', 'BACKGROUND: Child malnutrition still remains a major cause of childhood morbidity and mortality in Bangladesh. This study aims to determine the prevalence and identify the associated risk factors of child malnutrition in Bangladesh using multilevel logistic regression model on data from the Bangladesh Demographic and Health Survey (BDHS), 2014. METHODS: A total sample of 6965 children aged 0-59 months was extracted from BDHS 2014. We performed descriptive analysis and multilevel generalized linear regression analysis with clustered data structure. RESULTS: Our findings show that among children the prevalence of moderate and severe values was respectively: 25 and 12% for stunting; 11 and 3.1% for wasting; 25 and 7.9% for underweight. The probability of stunting increased with age, with highest rate among children aged 36-47 months, which was significantly higher than children aged less than 6 months (OR = 6.71, 95% CI = 4.46, 10.10). Female children are found to be 11% less likely to be stunted than male children (OR = 0.89, 95% CI = 0.78, 1.02). Children with birth interval less than 24 months were significantly more likely to be stunted than children of first birth by 36% (OR = 1.36, 95% CI = 1.11, 1.67). Mothers with a normal BMI were 16% less likely to have children with stunting compared to mothers who are underweight (OR = 0.84, 95% CI = 0.76, 0.93). Other factors which were associated with a higher risk of stunting included parents with lower educational levels, children from the poorest wealth index, and mothers aged less than 20 years as first birth. CONCLUSION: Government and non-government organization should generate effective program to aware women of reproductive age about adverse effect of short birth interval, and to aware parents about standard height and weight according to age and gender of children. Overall, necessary steps may be taken to make people educated and to reduce household wealth inequality to improve nutritional status of children.', '2026-07-07 22:48:34');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2412280990', 'precision-nutrition', 'A cross-sectional study on nutrient intake and -status in inflammatory bowel disease patients', 'BACKGROUND AND AIMS: Inflammatory bowel disease (IBD) can be associated with nutritional problems. The aim of this study was to investigate diet and nutritional status of IBD patients. METHODS: A…', '2015', 2015, 67, 67, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1038%2Fs41575-022-00619-5/MediaObjects/41575_2022_619_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4897945', 'pmc', 'article', 'Nutrition Journal', '["Jona B. Vidarsdottir","Sigridur E. Johannsdottir","Inga Þórsdóttir","Einar S. Björnsson","Alfons Ramel"]', 'precision nutrition', 'BACKGROUND AND AIMS: Inflammatory bowel disease (IBD) can be associated with nutritional problems. The aim of this study was to investigate diet and nutritional status of IBD patients. METHODS: A total of 78 participants (35 men and 43 women aged 18-74 years) were included in this cross-sectional study. The majority (80 %) of the participant received infliximab treatment. Participants filled out disease related questionnaires and 31 participants also a 3-day food record. Body composition was measured and blood samples analysed in order to estimate nutritional status. RESULTS: The majority (87 %) claimed that diet affects digestive tract symptoms and 72 % had changed diet accordingly. The most common foods restricted were dairy products (60 %), processed meat (55 %), soft drinks (46 %), alcohol (45 %) and fast food (44 %). Body mass index was mostly in the overweight range but 46 % of the participants had been diagnosed with some nutritional deficiency since IBD diagnosis (most common was iron deficiency: 39 %). Patients who restricted meat products had lower ferritin values (48 ± 39 vs. 95 ± 74 μg/L, P = 0.011). Intake of vitamin D and calcium were not adequate (65 % below recommeded intake for both) and 60 % had poor vitamin D status. CONCLUSION: IBD patients often change their dietary intake in order to affect digestive tract symptoms. Many patients have a history of nutrient deficiency. Restriction of dairy and meat consumption is common and is negatively associated with intake or status of micronutrients like calcium and iron. Dietary advice by a dietitian and use of potentially helpful dietary supplements is indicated.', '2026-07-07 22:48:38');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2604131046', 'precision-nutrition', 'Household food insecurity and its association with nutritional status of under five children in Sekela District, Western Ethiopia: a comparative cross-sectional study', 'BACKGROUND: Food insecurity influences children nutritional status by limiting the quantity and quality of dietary intake. Studies conducted across different parts of the world revealed controversial…', '2017', 2017, 67, 67, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs40066-021-00296-8/MediaObjects/40066_2021_296_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7050715', 'pmc', 'article', 'BMC Nutrition', '["Ermiyas Mulu","Bezatu Mengistie"]', 'precision nutrition', 'BACKGROUND: Food insecurity influences children nutritional status by limiting the quantity and quality of dietary intake. Studies conducted across different parts of the world revealed controversial evidences about the relationship between household food insecurity and child nutritional status. Although child malnutrition and food insecurity are the main problems in Ethiopia, to what extent food insecurity contributes to children nutritional status is not yet well studied. Therefore, this study was conducted to compare children nutritional status in food secure and insecure housholds. METHOD: A community based comparative cross sectional study was conducted in Sekela District,Western Ethiopia from February 5-27, 2014. The total sample size was 576 households having at least one children less than 5 year''s old. Two stage cluster stratified sampling technique was used to select study participants. Data were collected using a pre tested structured questionnaire and anthropometric measurements. Household food insecurity was measured using household food insecurity access scale. Anthropometry indices were calculated using WHO Anthro 3.1.0 and interpreted according to WHO 2006 cutoff points. Data were entered using Epi.Data 3.2. and exported to SPSS 21.0 for analysis. Logistic regression analysis was employed to identify independent predictors of children under nutrition. RESULT: The mean of household food insecurity score was 8.16 ± 6.01 and the prevalence of food insecurity was 74.1%. Of children in food insecure households 38.9% were stunted, 22.6% were underweighted and 12.9% were wasted while the respective prevalence of stunting, underweight and wasting were 31.3%, 11.8% and 7.6% among children in food secure households. Food insecurity had association with children underweight (AOR = 2.25; 95% CI = 1.29, 3.94), but not with stunting and wasting. Children under nutrition had independent association with sex and age of the child, colostrum feeding, upper respiratory infection, fever, and maternal literacy. CONCLUSION: Household food insecurity and child under nutrition were critical problems in the study setting. Socio demographic factors, poor child caring practices, infection and food insecurity had positive association with children under nutrition. Thus, due emphasis should be given for the designing and implementation of multi sectorial community based nutrition interventions and initiation of income generating livelihood to the community to curtail under nutrition and household food insecurity in the locality.', '2026-07-07 22:48:42');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4225554953', 'precision-nutrition', 'A pilot exploration of multi-omics research of gut microbiome in major depressive disorders', 'The pathophysiology of major depressive disorder (MDD) remains obscure. Recently, the microbiota-gut-brain (MGB) axis''s role in MDD has an increasing attention. However, the specific mechanism of the…', '2022', 2022, 67, 67, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41398-021-01769-x/MediaObjects/41398_2021_1769_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8748871', 'pmc', 'article', 'Translational Psychiatry', '["Haoyang Zhao","Kangyu Jin","Chaonan Jiang","Fen Pan","Jing Wu","Honglin Luan","Zhiyong Zhao","Jingkai Chen","Tingting Mou","Zheng Wang","Jing Lü","Shaojia Lu","Shaohua Hu","Yi Xu","Manli Huang"]', 'precision nutrition', 'The pathophysiology of major depressive disorder (MDD) remains obscure. Recently, the microbiota-gut-brain (MGB) axis''s role in MDD has an increasing attention. However, the specific mechanism of the multi-level effects of gut microbiota on host metabolism, immunity, and brain structure is unclear. Multi-omics approaches based on the analysis of different body fluids and tissues using a variety of analytical platforms have the potential to provide a deeper understanding of MGB axis disorders. Therefore, the data of metagenomics, metabolomic, inflammatory factors, and MRI scanning are collected from the two groups including 24 drug-naïve MDD patients and 26 healthy controls (HCs). Then, the correlation analysis is performed in all omics. The results confirmed that there are many markedly altered differences, such as elevated Actinobacteria abundance, plasma IL-1β concentration, lipid, vitamin, and carbohydrate metabolism disorder, and diminished grey matter volume (GMV) of inferior frontal gyrus (IFG) in the MDD patients. Notably, three kinds of discriminative bacteria, Ruminococcus bromii, Lactococcus chungangensis, and Streptococcus gallolyticus have an extensive correlation with metabolome, immunology, GMV, and clinical symptoms. All three microbiota are closely related to IL-1β and lipids (as an example, phosphoethanolamine (PEA)). Besides, Lactococcus chungangensis is negatively related to the GMV of left IFG. Overall, this study demonstrate that the effects of gut microbiome exert in MDD is multifactorial.', '2026-07-07 22:48:45');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2790707851', 'precision-nutrition', 'Infant formulae supplemented with prebiotics: Are they better than unsupplemented formulae? An updated systematic review', 'In 2011, the Committee on Nutrition of the European Society for Paediatric Gastroenterology, Hepatology and Nutrition systematically reviewed published evidence related to the safety and health…', '2018', 2018, 65, 65, 'https://static.cambridge.org/binary/version/id/urn:cambridge.org:id:binary:20180323122112903-0064:S0007114518000120:S0007114518000120_fig1g.jpeg', 'https://pubmed.ncbi.nlm.nih.gov/29457570', 'repository', 'review', 'British Journal Of Nutrition', '["Agata Skórka","Małgorzata Pieścik‐Lech","Maciej Kołodziej","Hania Szajewska"]', 'precision nutrition', 'In 2011, the Committee on Nutrition of the European Society for Paediatric Gastroenterology, Hepatology and Nutrition systematically reviewed published evidence related to the safety and health effects of the administration of formulae supplemented with pro- and/or prebiotics compared with unsupplemented formulae. We updated evidence on the effects of the administration of prebiotic-supplemented infant formulae (IF) compared with unsupplemented IF. Five databases were searched up to March 2017 for randomised controlled trials. In all, forty-one publications were identified, including twenty-five new publications. The administration of currently evaluated prebiotic-supplemented formulae to healthy infants does not raise safety concerns with regard to growth and adverse effects. Some favourable clinical effects are possible, primarily stool softening, which may be beneficial in some infants. Currently, there is no existing robust evidence to recommend the routine use of prebiotic-supplemented formulae. The latter conclusion may reflect the small amount of data on specific prebiotics and outcomes, rather than a genuine lack of an effect. The efficacy and safety should be considered for each prebiotic(s)-supplemented formula.', '2026-07-07 22:49:25');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3041457765', 'precision-nutrition', 'Effectiveness of school-based nutrition interventions in sub-Saharan Africa: a systematic review', 'OBJECTIVE: To evaluate the effect of school-based nutrition interventions (SBNI) involving schoolchildren and adolescents in sub-Saharan Africa (SSA) on child nutrition status and nutrition-related…', '2020', 2020, 62, 62, 'https://static.cambridge.org/binary/version/id/urn:cambridge.org:id:binary:20200917072210388-0637:S1368980020000506:S1368980020000506_fig1.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/10200642', 'pmc', 'review', 'Public Health Nutrition', '["Paul Kyere","Lennert Veerman","Patricia Lee","Donald Stewart"]', 'precision nutrition', 'OBJECTIVE: To evaluate the effect of school-based nutrition interventions (SBNI) involving schoolchildren and adolescents in sub-Saharan Africa (SSA) on child nutrition status and nutrition-related knowledge, attitudes and behaviour. DESIGN: A systematic review on published school nutrition intervention studies of randomised controlled trials, controlled clinical trials, controlled before-and-after studies or quasi-experimental designs with control. Nine electronic bibliographic databases were searched. To be included, interventions had to involve changes to the school''s physical and social environments, to the school''s nutrition policies, to teaching curriculum to incorporate nutrition education and/or to partnership with parents/community. SETTING: Schools in SSA. PARTICIPANTS: School-aged children and adolescents, aged 5-19 years. RESULTS: Fourteen studies met our inclusion criteria. While there are few existing studies of SBNI in SSA, the evidence shows that food supplementation/fortification is very effective in reducing micronutrient deficiencies and can improve nutrition status. Secondly, school nutrition education can improve nutrition knowledge, but this may not necessarily translate into healthy nutrition behaviour, indicating that nutrition knowledge may have little impact without a facilitating environment. Results regarding anthropometry were inconclusive; however, there is evidence for the effectiveness of SBNI in improving cognitive abilities. CONCLUSIONS: There is enough evidence to warrant further trials of SBNI in SSA. Future research should consider investigating the impact of SBNI on anthropometry and nutrition behaviour, focusing on the role of programme intensity and/or duration. To address the high incidence of micronutrient deficiencies in low- and middle-income countries, food supplementation strategies currently available to schoolchildren should be expanded.', '2026-07-07 22:50:10');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2999983901', 'precision-nutrition', 'Plasma retinol-binding protein 4 in the first and second trimester and risk of gestational diabetes mellitus in Chinese women: a nested case-control study', 'Abstract Background To assess the association between plasma retinol-binding protein 4 (RBP4) levels both in the first trimester and second trimester and risk of gestational diabetes mellitus (GDM).…', '2020', 2020, 61, 61, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs12884-021-04006-x/MediaObjects/12884_2021_4006_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6945716', 'pmc', 'article', 'Nutrition & Metabolism', '["Chuyao Jin","Li‐Zi Lin","Na Han","Zhiling Zhao","Zheng Liu","Shusheng Luo","Xiangrong Xu","Jue Liu","Haijun Wang"]', 'precision nutrition', 'Abstract Background To assess the association between plasma retinol-binding protein 4 (RBP4) levels both in the first trimester and second trimester and risk of gestational diabetes mellitus (GDM). Methods Plasma RBP4 levels and insulin were measured among 135 GDM cases and 135 controls nested within the Peking University Birth Cohort in Tongzhou. Multivariable linear regression analysis was conducted to assess the influence of RBP4 levels on insulin resistance. Conditional logistic regression models were used to compute the odds ratio (OR) and 95% confidence interval (CI) between RBP4 levels and risk of GDM. Results The GDM cases had significantly higher levels of RBP4 in the first trimester than controls (medians: 18.0 μg/L vs 14.4 μg/L; P &lt; 0.05). Plasma RBP4 concentrations in the first and second trimester were associated with fasting insulin, homeostasis model assessment for insulin resistance (HOMA-IR), and the quantitative insulin sensitivity check index (QUICKI) in the second trimester (all P &lt; 0.001). With adjustment for diet, physical activity, and other risk factors for GDM, the risk of GDM increased with every 1-log μg/L increment of RBP4 levels, and the OR (95% CI) was 3.12 (1.08–9.04) for RBP4 in the first trimester and 3.38 (1.03–11.08) for RBP4 in the second trimester. Conclusions Plasma RBP4 levels both in the first trimester and second trimester were dose-dependently associated with increased risk of GDM.', '2026-07-07 22:50:21');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2607478100', 'precision-nutrition', 'Effects of omega-3 fatty acids on patients undergoing surgery for gastrointestinal malignancy: a systematic review and meta-analysis', 'Surgical resection remains the primary treatment for gastrointestinal (GI) malignancy including early-stage cancer. Omega-3 polyunsaturated fatty acids (n-3 PUFAs) have been reported to have…', '2017', 2017, 62, 62, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1038%2Fs41430-019-0527-5/MediaObjects/41430_2019_527_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5391568', 'pmc', 'review', 'BMC Cancer', '["Jing Yu","Lian Liu","Yue Zhang","Jia Wei","Fan Yang"]', 'precision nutrition', 'Surgical resection remains the primary treatment for gastrointestinal (GI) malignancy including early-stage cancer. Omega-3 polyunsaturated fatty acids (n-3 PUFAs) have been reported to have beneficial clinical and immune-modulating effects in the prognosis of GI cancer patients undergoing surgery. We searched PubMed, Embase, EBSCO-Medline, Cochrane Central Register of Controlled Trials (CENTRAL), CNKI and Wanfang to identify primary research reporting the effects of n-3 PUFAs compared with isocaloric nutrition on GI cancer patients who underwent surgery up to the end of June 30, 2016. Two authors independently reviewed and selected eligible randomized controlled trials (RCTs). A total of 9 RCTs (623 participants) were included. The n-3 PUFAs regime resulted in lower levels of C-reactive protein (CRP) (P < 0.05), interleukin-6 (IL-6) (P < 0.01), and higher levels of albumin (ALB), CD3+ T cells, CD4+ T cells and CD4+/CD8+ ratio (P < 0.05) compared with the isocaloric nutrition regime. However, there was no significant difference in the level of tumor necrosis factor-α (TNF-α) between the n-3 PUFAs regime and the isocaloric nutrition regime (P = 0.17). And the level of CD8 + T cells decreased compared with the isocaloric nutrition regime (P < 0.0001). Our meta-analysis revealed that n-3 PUFAs are effective in improving the nutritional status and immune function of GI cancer patients undergoing surgery as they effectively enhance immunity and attenuate the inflammatory response.', '2026-07-07 22:50:21');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4385277895', 'precision-nutrition', 'Circulating metabolites modulated by diet are associated with depression', 'Metabolome reflects the interplay of genome and exposome at molecular level and thus can provide deep insights into the pathogenesis of a complex disease like major depression. To identify…', '2023', 2023, 58, 58, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41380-023-02180-2/MediaObjects/41380_2023_2180_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/10730409', 'pmc', 'article', 'Molecular Psychiatry', '["Ashley van der Spek","Isobel D. Stewart","Brigitte Kühnel","Maik Pietzner","Tahani Alshehri","Karen Friederike Gauß","Pirro G. Hysi","Siamak MahmoudianDehkordi","Almut Heinken","Annemarie I. Luik","Karl-Heinz Ladwig","Gabi Kastenmüller","Cristina Menni","Johannes Hertel","M. Arfan Ikram","Renée de Mutsert","Karsten Suhre","Christian Gieger","Konstantin Strauch","Henry Völzke","Thomas Meitinger","Massimo Mangino","Antònia Flaquer","Mélanie Waldenberger","Annette Peters","Ines Thiele","Rima Kaddurah‐Daouk","Boadie W. Dunlop","Frits R. Rosendaal","Nicholas J. Wareham","Tim D. Spector","Sonja Kunze","Hans J. Grabe","Dennis O. Mook‐Kanamori","Claudia Langenberg","Cornelia M. van Duijn","Najaf Amin"]', 'precision nutrition', 'Metabolome reflects the interplay of genome and exposome at molecular level and thus can provide deep insights into the pathogenesis of a complex disease like major depression. To identify metabolites associated with depression we performed a metabolome-wide association analysis in 13,596 participants from five European population-based cohorts characterized for depression, and circulating metabolites using ultra high-performance liquid chromatography/tandem accurate mass spectrometry (UHPLC/MS/MS) based Metabolon platform. We tested 806 metabolites covering a wide range of biochemical processes including those involved in lipid, amino-acid, energy, carbohydrate, xenobiotic and vitamin metabolism for their association with depression. In a conservative model adjusting for life style factors and cardiovascular and antidepressant medication use we identified 8 metabolites, including 6 novel, significantly associated with depression. In individuals with depression, increased levels of retinol (vitamin A), 1-palmitoyl-2-palmitoleoyl-GPC (16:0/16:1) (lecithin) and mannitol/sorbitol and lower levels of hippurate, 4-hydroxycoumarin, 2-aminooctanoate (alpha-aminocaprylic acid), 10-undecenoate (11:1n1) (undecylenic acid), 1-linoleoyl-GPA (18:2) (lysophosphatidic acid; LPA 18:2) are observed. These metabolites are either directly food derived or are products of host and gut microbial metabolism of food-derived products. Our Mendelian randomization analysis suggests that low hippurate levels may be in the causal pathway leading towards depression. Our findings highlight putative actionable targets for depression prevention that are easily modifiable through diet interventions.', '2026-07-07 22:51:42');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2604660883', 'precision-nutrition', 'Fatty acid composition in serum cholesterol esters and phospholipids is linked to visceral and subcutaneous adipose tissue content in elderly individuals: a cross-sectional study', 'BACKGROUND: Visceral adipose tissue (VAT) and truncal fat predict cardiometabolic disease. Intervention trials suggest that saturated fatty acids (SFA), e.g. palmitic acid, promote abdominal and…', '2017', 2017, 54, 54, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1007%2Fs00394-020-02422-x/MediaObjects/394_2020_2422_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5379570', 'pmc', 'article', 'Lipids in Health and Disease', '["Fredrik Rosqvist","Helena Bjermo","Joel Kullberg","Lars Johansson","Karl Michaëlsson","Håkan Åhlström","Lars Lind","Ulf Risérus"]', 'precision nutrition', 'BACKGROUND: Visceral adipose tissue (VAT) and truncal fat predict cardiometabolic disease. Intervention trials suggest that saturated fatty acids (SFA), e.g. palmitic acid, promote abdominal and liver fat storage whereas polyunsaturated fatty acids (PUFA), e.g. linoleic acid, prevent fat accumulation. Such findings require investigation in population-based studies of older individuals. We aimed to investigate the relationships of serum biomarkers of PUFA intake as well as serum levels of palmitic acid, with abdominal and total adipose tissue content. METHODS: In a population-based sample of 287 elderly subjects in the PIVUS cohort, we assessed fatty acid composition in serum cholesterol esters (CE) and phospholipids (PL) by gas chromatography and the amount of VAT and abdominal subcutaneous (SAT) adipose tissue by magnetic resonance imaging (MRI), liver fat by MR spectroscopy (MRS), and total body fat, trunk fat and leg fat by dual-energy X-ray absorptiometry (DXA). Insulin resistance was estimated by HOMA-IR. RESULTS: VAT and trunk fat showed the strongest correlation with insulin resistance (r = 0.49, P < 0.001). Linoleic acid in both CE and PL was inversely related to all body fat depots (r = -0.24 to -0.33, P < 0.001) including liver fat measured in a sub-group (r = -0.26, P < 0.05, n = 73), whereas n-3 PUFA showed weak inverse (18:3n-3) or positive (20:5n-3) associations. Palmitic acid in CE, but not in PL, was directly correlated with VAT (r = 0.19, P < 0.001) and trunk fat (r = 0.18, P = 0.003). Overall, the significant associations remained after adjusting for energy intake, height, alcohol, sex, smoking, education and physical activity. The inverse correlation between linoleic acid and VAT remained significant after further adjustment for total body fat. CONCLUSIONS: Serum linoleic acid is inversely related to body fat storage including VAT and trunk fat whereas palmitic acid was less consistently but directly associated, in line with recent feeding studies. Considering the close link between VAT and insulin resistance, a potential preventive role of plant-based PUFA in VAT accumulation warrants further study.', '2026-07-07 22:53:39');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2541671680', 'precision-nutrition', 'The use of probiotic L. fermentum ME-3 containing Reg’Activ Cholesterol supplement for 4 weeks has a positive influence on blood lipoprotein profiles and inflammatory cytokines: an open-label preliminary study', 'BACKGROUND: Cardiovascular diseases continue to be a challenge and burden to heath. The incidence of type 2 diabetes is increasing. Modifying the (common) risk factors of them is the key of longterm…', '2016', 2016, 54, 54, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs40795-022-00586-9/MediaObjects/40795_2022_586_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5084312', 'pmc', 'article', 'Nutrition Journal', '["Tiiu Kullisaar","Kersti Zilmer","Tiit Salum","Aune Rehema","Mihkel Zilmer"]', 'precision nutrition', 'BACKGROUND: Cardiovascular diseases continue to be a challenge and burden to heath. The incidence of type 2 diabetes is increasing. Modifying the (common) risk factors of them is the key of longterm success. The aim of the study was to establish if the special composition of innovative food supplement Reg''Activ Cholesterol (RAC) has a positive influence to the human body cardiovascular-inflammatory and diabetic parameters. METHODS: Forty-five clinically asymptomatic participants consumed an RAC containing an antioxidative and antiatherogenic probiotic Lactobacillus fermentum ME-3 (LFME-3) for 4 weeks. The parameters measured were total cholesterol, HDL cholesterol, LDL cholesterol, triglyceride, oxLDL, hsCRP, IL-6 and glycosylated haemoglobin (HbA1c%). RESULTS: The cardiovascular and diabetes risk profile of the participants improved significantly after 4 weeks of the intervention. The reduction of total cholesterol (from 6.5 ± 1.0 to 5.7 ± 0.9 mmol/l, p = 9.90806E-11) was on the account of LDL cholesterol as the HDL cholesterol level rose from 1.60 ± 0.31to 1.67 ± 0.34mml/l, p = 0.01. HbA1c% was reduced from 5.85 ± 0.28 to 5.66 ± 0.25 p = 4.64E-05 and oxLDL decreased from 84 ± 20 to 71 ± 15 U/l, p = 4.66292E-08. CONCLUSIONS: The consumption of RAC in clinically asymptomatic volunteers with borderline-high values of risk factors for cardiovascular disease (BMI, HbA1c%, LDL cholesterol) for 4 weeks had a positive effect on blood lipoprotein, oxidative stress and inflammatory profile. There are no human trials published before with RAC. TRIAL REGISTRATION: The trial described here isa n open label pilot study within the framework of a larger special clinical trial ( ISRCTN55339917 ) [Accessed 20 Feb 2016].', '2026-07-07 22:53:40');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2965517013', 'precision-nutrition', 'Determinants of stunting among children aged 0–59 months in Nepal: findings from Nepal Demographic and health Survey, 2006, 2011, and 2016', 'BACKGROUND: Stunting is one of the most commonly used indicators of child nutrition and health status. Despite significant efforts by the government and external development partners to improve…', '2019', 2019, 54, 54, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1007%2Fs10995-019-02817-1/MediaObjects/10995_2019_2817_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7050935', 'pmc', 'article', 'BMC Nutrition', '["Ramesh P. Adhikari","Manisha Shrestha","Ajay Acharya","Nawaraj Upadhaya"]', 'precision nutrition', 'BACKGROUND: Stunting is one of the most commonly used indicators of child nutrition and health status. Despite significant efforts by the government and external development partners to improve maternal and child health and nutrition, stunting is consistently high in Nepal. This paper assesses the potential determinants of stunting among children aged 0-59 months using the last three successive Nepal Demographic and Health Surveys (NDHS). METHODS: = 2421 in 2016. RESULTS: Rates of stunting decreased from nearly 50% in 2006 to about 36% in 2016. The prevalence of stunting was higher among children from larger families (51.0% in 2006, 41.1% in 2011, 38.7% in 2016), poor wealth quintile households (61.2% in 2006, 56.0% in 2011, 49.2% in 2016), and severely food insecure households (49.0% in 2011, 46.5% in 2016). For child stunting, the common determinants in all three surveys included: being from the highest equity quintile (OR: 0.58 in 2006, 0.26 in 2011, 0.28 in 2016), being older (OR: 2.24 in 2006, 2.58 in 2011, 1.58 in 2016), being below average size at time of birth (OR: 1.64 in 2006, 1.55 in 2011, 1.60 in 2016), and being affected by anemia (OR: 1.32 in 2006, 1.59 in 2011, 1.40 in 2016). CONCLUSIONS: This study found that household wealth status, age of child, size of child at time of birth, and child anemia comprised the common determinants of stunting in all three surveys in Nepal. Study findings underscore the need for effective implementation of evidence-based nutrition interventions in health and non-health sectors to reduce the high rates of child stunting in Nepal.', '2026-07-07 22:53:42');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3123922203', 'neuroscience', 'Ferroptosis: mechanisms, biology and role in disease', 'Ferroptosis: mechanisms, biology and role in disease', '2021', 2021, 7286, 7286, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41580-020-00324-8/MediaObjects/41580_2020_324_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8142022', 'pmc', 'review', 'Nature Reviews Molecular Cell Biology', '["Xuejun Jiang","Brent R. Stockwell","Marcus Conrad"]', 'neuroscience', NULL, '2026-07-07 22:54:04');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2499800833', 'neuroscience', 'A multi-modal parcellation of human cerebral cortex', 'A multi-modal parcellation of human cerebral cortex', '2016', 2016, 5647, 5647, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature18933/MediaObjects/41586_2016_Article_BFnature18933_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4990127', 'pmc', 'article', 'Nature', '["Matthew F. Glasser","Timothy S. Coalson","Emma C. Robinson","Carl D. Hacker","John Harwell","Essa Yacoub","Kâmil Uǧurbil","Jesper Andersson","Christian F. Beckmann","Mark Jenkinson","Stephen M. Smith","David C. Van Essen"]', 'neuroscience', NULL, '2026-07-07 22:54:07');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2965717703', 'neuroscience', 'The neuropathological diagnosis of Alzheimer’s disease', 'Alzheimer''s disease is a progressive neurodegenerative disease most often associated with memory deficits and cognitive decline, although less common clinical presentations are increasingly…', '2019', 2019, 3342, 3342, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs13024-019-0333-5/MediaObjects/13024_2019_333_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6679484', 'pmc', 'review', 'Molecular Neurodegeneration', '["Michael DeTure","Dennis W. Dickson"]', 'neuroscience', 'Alzheimer''s disease is a progressive neurodegenerative disease most often associated with memory deficits and cognitive decline, although less common clinical presentations are increasingly recognized. The cardinal pathological features of the disease have been known for more than one hundred years, and today the presence of these amyloid plaques and neurofibrillary tangles are still required for a pathological diagnosis. Alzheimer''s disease is the most common cause of dementia globally. There remain no effective treatment options for the great majority of patients, and the primary causes of the disease are unknown except in a small number of familial cases driven by genetic mutations. Confounding efforts to develop effective diagnostic tools and disease-modifying therapies is the realization that Alzheimer''s disease is a mixed proteinopathy (amyloid and tau) frequently associated with other age-related processes such as cerebrovascular disease and Lewy body disease. Defining the relationships between and interdependence of various co-pathologies remains an active area of investigation. This review outlines etiologically-linked pathologic features of Alzheimer''s disease, as well as those that are inevitable findings of uncertain significance, such as granulovacuolar degeneration and Hirano bodies. Other disease processes that are frequent, but not inevitable, are also discussed, including pathologic processes that can clinically mimic Alzheimer''s disease. These include cerebrovascular disease, Lewy body disease, TDP-43 proteinopathies and argyrophilic grain disease. The purpose of this review is to provide an overview of Alzheimer''s disease pathology, its defining pathologic substrates and the related pathologies that can affect diagnosis and treatment.', '2026-07-07 22:54:28');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3124420883', 'neuroscience', 'Past, present, and future of simultaneous localization and mapping: Toward the robust-perception age', 'Simultaneous localization and mapping (SLAM) consists in the concurrent construction of a model of the environment (the map), and the estimation of the state of the robot moving within it. The SLAM…', '2016', 2016, 3158, 3158, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.5167/uzh-138892.g001', 'https://doi.org/10.5167/uzh-138892', 'repository', 'article', 'Zurich Open Repository and Archive (University of Zurich)', '["César Cadena","Luca Carlone","Henry Carrillo","Yasir Latif","Davide Scaramuzza","José Neira","Ian Reid","John J. Leonard"]', 'neuroscience', 'Simultaneous localization and mapping (SLAM) consists in the concurrent construction of a model of the environment (the map), and the estimation of the state of the robot moving within it. The SLAM community has made astonishing progress over the last 30 years, enabling large-scale real-world applications and witnessing a steady transition of this technology to industry. We survey the current state of SLAM and consider future directions. We start by presenting what is now the de-facto standard formulation for SLAM. We then review related work, covering a broad set of topics including robustness and scalability in long-term mapping, metric and semantic representations for mapping, theoretical performance guarantees, active SLAM and exploration, and other new frontiers. This paper simultaneously serves as a position paper and tutorial to those who are users of SLAM. By looking at the published research with a critical eye, we delineate open challenges and new research issues, that still deserve careful scientific investigation. The paper also contains the authors'' take on two questions that often animate discussions during robotics conferences: Do robots need SLAM? and Is SLAM solved?', '2026-07-07 22:54:28');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2125411036', 'neuroscience', 'The Blood–Brain Barrier', 'Blood vessels are critical to deliver oxygen and nutrients to all of the tissues and organs throughout the body. The blood vessels that vascularize the central nervous system (CNS) possess unique…', '2015', 2015, 3290, 3290, 'https://cshperspectives.cshlp.org/adsystem/graphics/3453626053548411/cshperspect/SPCT_web_468x60.gif?ad=50819&adview=true', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4292164', 'pmc', 'review', 'Cold Spring Harbor Perspectives in Biology', '["Richard Daneman","Alexandre Prat"]', 'neuroscience', 'Blood vessels are critical to deliver oxygen and nutrients to all of the tissues and organs throughout the body. The blood vessels that vascularize the central nervous system (CNS) possess unique properties, termed the blood-brain barrier, which allow these vessels to tightly regulate the movement of ions, molecules, and cells between the blood and the brain. This precise control of CNS homeostasis allows for proper neuronal function and also protects the neural tissue from toxins and pathogens, and alterations of these barrier properties are an important component of pathology and progression of different neurological diseases. The physiological barrier is coordinated by a series of physical, transport, and metabolic properties possessed by the endothelial cells (ECs) that form the walls of the blood vessels, and these properties are regulated by interactions with different vascular, immune, and neural cells. Understanding how these different cell populations interact to regulate the barrier properties is essential for understanding how the brain functions during health and disease.', '2026-07-07 22:54:33');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1992193293', 'neuroscience', 'The roads ahead: Narratives for shared socioeconomic pathways describing world futures in the 21st century', 'The roads ahead: Narratives for shared socioeconomic pathways describing world futures in the 21st century', '2015', 2015, 3343, 3343, 'https://ars.els-cdn.com/content/image/1-s2.0-S0959378015000060-gr1.jpg', 'https://doi.org/10.1016/j.gloenvcha.2015.01.004', 'repository', 'article', 'Global Environmental Change', '["Brian C. O’Neill","Elmar Kriegler","Kristie L. Ebi","Eric Kemp‐Benedict","Keywan Riahi","Dale S. Rothman","Bas van Ruijven","Detlef P. van Vuuren","Joern Birkmann","Kasper Kok","Marc A. Levy","William Solecki"]', 'neuroscience', NULL, '2026-07-07 22:54:35');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3003912482', 'neuroscience', 'The Role of Short-Chain Fatty Acids From Gut Microbiota in Gut-Brain Communication', 'A substantial body of evidence supports that the gut microbiota plays a pivotal role in the regulation of metabolic, endocrine and immune functions. In recent years, there has been growing…', '2020', 2020, 2889, 2889, 'https://www.frontiersin.org/files/Articles/508738/fendo-11-00025-HTML/image_m/fendo-11-00025-g001.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7005631', 'pmc', 'review', 'Frontiers in Endocrinology', '["Ygor Parladore Silva","Andressa Bernardi","Rudimar Luiz Frozza"]', 'neuroscience', 'A substantial body of evidence supports that the gut microbiota plays a pivotal role in the regulation of metabolic, endocrine and immune functions. In recent years, there has been growing recognition of the involvement of the gut microbiota in the modulation of multiple neurochemical pathways through the highly interconnected gut-brain axis. Although amazing scientific breakthroughs over the last few years have expanded our knowledge on the communication between microbes and their hosts, the underpinnings of microbiota-gut-brain crosstalk remain to be determined. Short-chain fatty acids (SCFAs), the main metabolites produced in the colon by bacterial fermentation of dietary fibers and resistant starch, are speculated to play a key role in neuro-immunoendocrine regulation. However, the underlying mechanisms through which SCFAs might influence brain physiology and behavior have not been fully elucidated. In this review, we outline the current knowledge about the involvement of SCFAs in microbiota-gut-brain interactions. We also highlight how the development of future treatments for central nervous system (CNS) disorders can take advantage of the intimate and mutual interactions of the gut microbiota with the brain by exploring the role of SCFAs in the regulation of neuro-immunoendocrine function.', '2026-07-07 22:54:44');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2140358254', 'neuroscience', 'Non-invasive electrical and magnetic stimulation of the brain, spinal cord, roots and peripheral nerves: Basic principles and procedures for routine clinical and research application. An updated report from an I.F.C.N. Committee', 'These guidelines provide an up-date of previous IFCN report on "Non-invasive electrical and magnetic stimulation of the brain, spinal cord and roots: basic principles and procedures for routine…', '2015', 2015, 2774, 2774, 'https://ars.els-cdn.com/content/image/1-s2.0-S1388245715000711-gr1.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6350257', 'pmc', 'review', 'Clinical Neurophysiology', '["Paolo Maria Rossini","David Burke","Robert Chen","Leonardo G. Cohen","Zafiris J. Daskalakis","Riccardo Di Iorio","Vincenzo Di Lazzaro","Florinda Ferreri","Paul B. Fitzgerald","Mark S. George","Mark Hallett","Jean‐Pascal Lefaucheur","Berthold Langguth","Hideyuki Matsumoto","Carlo Miniussi","Michael A. Nitsche","Álvaro Pascual‐Leone","Walter Paulus","Símone Rossi","John C. Rothwell","Hartwig R. Siebner","Yoshikazu Ugawa","Vincent Walsh","Ulf Ziemann"]', 'neuroscience', 'These guidelines provide an up-date of previous IFCN report on "Non-invasive electrical and magnetic stimulation of the brain, spinal cord and roots: basic principles and procedures for routine clinical application" (Rossini et al., 1994). A new Committee, composed of international experts, some of whom were in the panel of the 1994 "Report", was selected to produce a current state-of-the-art review of non-invasive stimulation both for clinical application and research in neuroscience. Since 1994, the international scientific community has seen a rapid increase in non-invasive brain stimulation in studying cognition, brain-behavior relationship and pathophysiology of various neurologic and psychiatric disorders. New paradigms of stimulation and new techniques have been developed. Furthermore, a large number of studies and clinical trials have demonstrated potential therapeutic applications of non-invasive brain stimulation, especially for TMS. Recent guidelines can be found in the literature covering specific aspects of non-invasive brain stimulation, such as safety (Rossi et al., 2009), methodology (Groppa et al., 2012) and therapeutic applications (Lefaucheur et al., 2014). This up-dated review covers theoretical, physiological and practical aspects of non-invasive stimulation of brain, spinal cord, nerve roots and peripheral nerves in the light of more updated knowledge, and include some recent extensions and developments.', '2026-07-07 22:54:56');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3112948680', 'neuroscience', 'Comprehensive Review on Alzheimer’s Disease: Causes and Treatment', 'Alzheimer’s disease (AD) is a disorder that causes degeneration of the cells in the brain and it is the main cause of dementia, which is characterized by a decline in thinking and independence in…', '2020', 2020, 2678, 2678, 'https://pub.mdpi-res.com/molecules/molecules-25-05789/article_deploy/html/images/molecules-25-05789-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7764106', 'pmc', 'review', 'Molecules', '["Zeinab Breijyeh","Rafik Karaman"]', 'neuroscience', 'Alzheimer’s disease (AD) is a disorder that causes degeneration of the cells in the brain and it is the main cause of dementia, which is characterized by a decline in thinking and independence in personal daily activities. AD is considered a multifactorial disease: two main hypotheses were proposed as a cause for AD, cholinergic and amyloid hypotheses. Additionally, several risk factors such as increasing age, genetic factors, head injuries, vascular diseases, infections, and environmental factors play a role in the disease. Currently, there are only two classes of approved drugs to treat AD, including inhibitors to cholinesterase enzyme and antagonists to N-methyl d-aspartate (NMDA), which are effective only in treating the symptoms of AD, but do not cure or prevent the disease. Nowadays, the research is focusing on understanding AD pathology by targeting several mechanisms, such as abnormal tau protein metabolism, β-amyloid, inflammatory response, and cholinergic and free radical damage, aiming to develop successful treatments that are capable of stopping or modifying the course of AD. This review discusses currently available drugs and future theories for the development of new therapies for AD, such as disease-modifying therapeutics (DMT), chaperones, and natural compounds.', '2026-07-07 22:55:07');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2767493192', 'neuroscience', 'Fully integrated silicon probes for high-density recording of neural activity', 'Fully integrated silicon probes for high-density recording of neural activity', '2017', 2017, 2399, 2399, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature24636/MediaObjects/41586_2017_Article_BFnature24636_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5955206', 'pmc', 'article', 'Nature', '["James J. Jun","Nicholas A. Steinmetz","Joshua H. Siegle","Daniel J. Denman","Marius Bauža","Brian Barbarits","Albert K. Lee","Costas A. Anastassiou","Alexandru Andrei","Çağatay Aydın","Mladen Barbic","Timothy J. Blanche","Vincent Bonin","João Couto","B. Dutta","Sergey L. Gratiy","Diego A. Gutnisky","Michael Häusser","Bill Karsh","Peter Ledochowitsch","Carolina Mora López","Catalin Mitelut","Silke Musa","Michael Okun","Marius Pachitariu","Jan Putzeys","Phil Rich","Cyrille Rossant","Wei-lung Sun","Karel Svoboda","Matteo Carandini","Kenneth D. Harris","Christof Koch","John O’Keefe","T.D. Harris"]', 'neuroscience', NULL, '2026-07-07 22:55:14');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4211036635', 'neuroscience', 'Alzheimer disease', 'Alzheimer disease', '2021', 2021, 2405, 2405, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41572-021-00269-y/MediaObjects/41572_2021_269_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8574196', 'pmc', 'review', 'Nature Reviews Disease Primers', '["David S. Knopman","Hélène Amieva","Ronald C. Petersen","Gaël Chételat","David M. Holtzman","Bradley T. Hyman","Ralph A. Nixon","David T. Jones"]', 'neuroscience', NULL, '2026-07-07 22:55:14');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2270498673', 'neuroscience', 'Hydrogels with tunable stress relaxation regulate stem cell fate and activity', 'Hydrogels with tunable stress relaxation regulate stem cell fate and activity', '2015', 2015, 2389, 2389, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnmat4489/MediaObjects/41563_2016_Article_BFnmat4489_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4767627', 'pmc', 'article', 'Nature Materials', '["Ovijit Chaudhuri","Luo Gu","Darinka D. Klumpers","Max Darnell","Sidi A. Bencherif","James C. Weaver","Nathaniel Huebsch","Hong-Pyo Lee","Evi Lippens","Georg N. Duda","David Mooney"]', 'neuroscience', NULL, '2026-07-07 22:55:16');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2937074474', 'neuroscience', 'Oxidative Stress: A Key Modulator in Neurodegenerative Diseases', 'Oxidative stress is proposed as a regulatory element in ageing and various neurological disorders. The excess of oxidants causes a reduction of antioxidants, which in turn produce an…', '2019', 2019, 2230, 2230, 'https://pub.mdpi-res.com/molecules/molecules-24-01583/article_deploy/html/images/molecules-24-01583-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6514564', 'pmc', 'review', 'Molecules', '["Anju Singh","Ritushree Kukreti","Luciano Saso","Shrikant Kukreti"]', 'neuroscience', 'Oxidative stress is proposed as a regulatory element in ageing and various neurological disorders. The excess of oxidants causes a reduction of antioxidants, which in turn produce an oxidation-reduction imbalance in organisms. Paucity of the antioxidant system generates oxidative-stress, characterized by elevated levels of reactive species (oxygen, hydroxyl free radical, and so on). Mitochondria play a key role in ATP supply to cells via oxidative phosphorylation, as well as synthesis of essential biological molecules. Various redox reactions catalyzed by enzymes take place in the oxidative phosphorylation process. An inefficient oxidative phosphorylation may generate reactive oxygen species (ROS), leading to mitochondrial dysfunction. Mitochondrial redox metabolism, phospholipid metabolism, and proteolytic pathways are found to be the major and potential source of free radicals. A lower concentration of ROS is essential for normal cellular signaling, whereas the higher concentration and long-time exposure of ROS cause damage to cellular macromolecules such as DNA, lipids and proteins, ultimately resulting in necrosis and apoptotic cell death. Normal and proper functioning of the central nervous system (CNS) is entirely dependent on the chemical integrity of brain. It is well established that the brain consumes a large amount of oxygen and is highly rich in lipid content, becoming prone to oxidative stress. A high consumption of oxygen leads to excessive production of ROS. Apart from this, the neuronal membranes are found to be rich in polyunsaturated fatty acids, which are highly susceptible to ROS. Various neurodegenerative diseases such as Parkinson''s disease (PD), Alzheimer''s disease (AD), Huntington''s disease (HD), and amyotrophic lateral sclerosis (ALS), among others, can be the result of biochemical alteration (due to oxidative stress) in bimolecular components. There is a need to understand the processes and role of oxidative stress in neurodegenerative diseases. This review is an effort towards improving our understanding of the pivotal role played by OS in neurodegenerative disorders.', '2026-07-07 22:55:54');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2556818673', 'neuroscience', 'Decoding ALS: from genes to mechanism', 'Decoding ALS: from genes to mechanism', '2016', 2016, 2095, 2095, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature20413/MediaObjects/41586_2016_Article_BFnature20413_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5585017', 'pmc', 'review', 'Nature', '["J. Paul Taylor","Robert H. Brown","Don W. Cleveland"]', 'neuroscience', NULL, '2026-07-07 22:56:16');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4308150510', 'neuroscience', 'Microglia states and nomenclature: A field at its crossroads', 'Microglia states and nomenclature: A field at its crossroads', '2022', 2022, 1894, 1894, 'https://ars.els-cdn.com/content/image/1-s2.0-S0896627322009539-gr1.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/9999291', 'pmc', 'review', 'Neuron', '["Rosa Chiara Paolicelli","Amanda Sierra","Beth Stevens","Marie‐Ève Tremblay","Adriano Aguzzi","Bahareh Ajami","Ido Amit","Étienne Audinat","Ingo Bechmann","Mariko L. Bennett","F. Chris Bennett","Alain Bessis","Knut Biber","Staci D. Bilbo","Mathew Blurton‐Jones","Erik Boddeke","Dora Brites","Bert Brône","Guy C. Brown","Oleg Butovsky","Monica J. Carson","Bernardo Castellano","Marco Colonna","Sally A. Cowley","Colm Cunningham","Dimitrios Davalos","Philip L. De Jager","Bart De Strooper","Ádám Dénes","Bart J. L. Eggen","Ukpong B. Eyo","Elena Galea","Sonia Garel","Florent Ginhoux","Christopher K. Glass","Özgün Gökçe","Diego Gómez‐Nicola","Berta González","Siamon Gordon","Manuel B. Graeber","Andrew D. Greenhalgh","Pierre Gressèns","Melanie Greter","David H. Gutmann","Christian Haass","Michael T. Heneka","Frank L. Heppner","Soyon Hong","David Hume","Steffen Jung","Helmut Kettenmann","Jonathan Kipnis","Ryuta Koyama","Greg Lemke","Marina A. Lynch","Ania K. Majewska","Marzia Malcangio","Tarja Malm","Renzo Mancuso","Takahiro Masuda","Michela Matteoli","Barry W. McColl","Véronique E. Miron","Anna V. Molofsky","Michelle Monje","Éva Mracskó","Agnès Nadjar","Jonas J. Neher","Urtė Neniškytė","Harald Neumann","Mami Noda","Bo Peng","Francesca Peri","V. Hugh Perry","Phillip G. Popovich","Clare Pridans","Josef Priller","Marco Prinz","Davide Ragozzino","Richard M. Ransohoff","Michael W. Salter","Anne Schaefer","Dorothy P. Schafer","Michal Schwartz","Mikael Simons","Cody J. Smith","Wolfgang J. Streit","Tuan Leng Tay","Li‐Huei Tsai","Alexei Verkhratsky","Rommy von Bernhardi","Hiroaki Wake","Valérie Wittamer","Susanne A. Wolf","Long‐Jun Wu","Tony Wyss‐Coray"]', 'neuroscience', NULL, '2026-07-07 22:56:44');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3125847321', 'neuroscience', 'Drought Stress Impacts on Plants and Different Approaches to Alleviate Its Adverse Effects', 'Drought stress, being the inevitable factor that exists in various environments without recognizing borders and no clear warning thereby hampering plant biomass production, quality, and energy. It is…', '2021', 2021, 1908, 1908, 'https://pub.mdpi-res.com/plants/plants-10-00259/article_deploy/html/images/plants-10-00259-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7911879', 'pmc', 'review', 'Plants', '["Mahmoud F. Seleiman","Nasser Al-Suhaibani","Nawab Ali","Mohammad Akmal","Majed A. Alotaibi","Yahya Refay","Turgay Dindaroğlu","Hafiz Haleem Abdul-Wajid","Martín Leonardo Battaglia"]', 'neuroscience', 'Drought stress, being the inevitable factor that exists in various environments without recognizing borders and no clear warning thereby hampering plant biomass production, quality, and energy. It is the key important environmental stress that occurs due to temperature dynamics, light intensity, and low rainfall. Despite this, its cumulative, not obvious impact and multidimensional nature severely affects the plant morphological, physiological, biochemical and molecular attributes with adverse impact on photosynthetic capacity. Coping with water scarcity, plants evolve various complex resistance and adaptation mechanisms including physiological and biochemical responses, which differ with species level. The sophisticated adaptation mechanisms and regularity network that improves the water stress tolerance and adaptation in plants are briefly discussed. Growth pattern and structural dynamics, reduction in transpiration loss through altering stomatal conductance and distribution, leaf rolling, root to shoot ratio dynamics, root length increment, accumulation of compatible solutes, enhancement in transpiration efficiency, osmotic and hormonal regulation, and delayed senescence are the strategies that are adopted by plants under water deficit. Approaches for drought stress alleviations are breeding strategies, molecular and genomics perspectives with special emphasis on the omics technology alteration i.e., metabolomics, proteomics, genomics, transcriptomics, glyomics and phenomics that improve the stress tolerance in plants. For drought stress induction, seed priming, growth hormones, osmoprotectants, silicon (Si), selenium (Se) and potassium application are worth using under drought stress conditions in plants. In addition, drought adaptation through microbes, hydrogel, nanoparticles applications and metabolic engineering techniques that regulate the antioxidant enzymes activity for adaptation to drought stress in plants, enhancing plant tolerance through maintenance in cell homeostasis and ameliorates the adverse effects of water stress are of great potential in agriculture.', '2026-07-07 22:56:49');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3006275595', 'neuroscience', 'A Detailed Review Study on Potential Effects of Microplastics and Additives of Concern on Human Health', 'The distribution and abundance of microplastics into the world are so extensive that many scientists use them as key indicators of the recent and contemporary period defining a new historical epoch:…', '2020', 2020, 1876, 1876, 'https://pub.mdpi-res.com/ijerph/ijerph-17-01212/article_deploy/html/images/ijerph-17-01212-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7068600', 'pmc', 'review', 'International Journal of Environmental Research and Public Health', '["Claudia Campanale","Carmine Massarelli","Ilaria Savino","Vito Locaputo","Vito Felice Uricchio"]', 'neuroscience', 'The distribution and abundance of microplastics into the world are so extensive that many scientists use them as key indicators of the recent and contemporary period defining a new historical epoch: The Plasticene. However, the implications of microplastics are not yet thoroughly understood. There is considerable complexity involved to understand their impact due to different physical-chemical properties that make microplastics multifaceted stressors. If, on the one hand, microplastics carry toxic chemicals in the ecosystems, thus serving as vectors of transport, they are themselves, on the other hand, a cocktail of hazardous chemicals that are added voluntarily during their production as additives to increase polymer properties and prolong their life. To date, there is a considerable lack of knowledge on the major additives of concern that are used in the plastic industry, on their fate once microplastics dispose into the environment, and on their consequent effects on human health when associated with micro and nanoplastics. The present study emphasizes the most toxic and dangerous chemical substances that are contained in all plastic products to describe the effects and implications of these hazardous chemicals on human health, providing a detailed overview of studies that have investigated their abundance on microplastics. In the present work, we conducted a capillary review of the literature on micro and nanoplastic exposure pathways and their potential risk to human health to summarize current knowledge with the intention of better focus future research in this area and fill knowledge gaps.', '2026-07-07 22:57:01');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4384464487', 'neuroscience', 'Students’ voices on generative AI: perceptions, benefits, and challenges in higher education', 'Abstract This study explores university students’ perceptions of generative AI (GenAI) technologies, such as ChatGPT, in higher education, focusing on familiarity, their willingness to engage,…', '2023', 2023, 1831, 1831, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1057%2Fs41599-025-05982-7/MediaObjects/41599_2025_5982_Fig1_HTML.png', 'https://doi.org/10.1186/s41239-023-00411-8', 'repository', 'article', 'International Journal of Educational Technology in Higher Education', '["Cecilia Ka Yuk Chan","Wenjie Hu"]', 'neuroscience', 'Abstract This study explores university students’ perceptions of generative AI (GenAI) technologies, such as ChatGPT, in higher education, focusing on familiarity, their willingness to engage, potential benefits and challenges, and effective integration. A survey of 399 undergraduate and postgraduate students from various disciplines in Hong Kong revealed a generally positive attitude towards GenAI in teaching and learning. Students recognized the potential for personalized learning support, writing and brainstorming assistance, and research and analysis capabilities. However, concerns about accuracy, privacy, ethical issues, and the impact on personal development, career prospects, and societal values were also expressed. According to John Biggs’ 3P model, student perceptions significantly influence learning approaches and outcomes. By understanding students’ perceptions, educators and policymakers can tailor GenAI technologies to address needs and concerns while promoting effective learning outcomes. Insights from this study can inform policy development around the integration of GenAI technologies into higher education. By understanding students’ perceptions and addressing their concerns, policymakers can create well-informed guidelines and strategies for the responsible and effective implementation of GenAI tools, ultimately enhancing teaching and learning experiences in higher education.', '2026-07-07 22:57:09');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3109793392', 'neuroscience', 'Fibrosis: from mechanisms to medicines', 'Fibrosis: from mechanisms to medicines', '2020', 2020, 1804, 1804, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-020-2938-9/MediaObjects/41586_2020_2938_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8034822', 'pmc', 'review', 'Nature', '["Neil C. Henderson","Florian Rieder","Thomas A. Wynn"]', 'neuroscience', NULL, '2026-07-07 22:57:09');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2923614429', 'neuroscience', 'Stem cells: past, present, and future', 'In recent years, stem cell therapy has become a very promising and advanced scientific research topic. The development of treatment methods has evoked great expectations. This paper is a review…', '2019', 2019, 1818, 1818, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs13287-019-1165-5/MediaObjects/13287_2019_1165_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6390367', 'pmc', 'review', 'Stem Cell Research & Therapy', '["Wojciech Zakrzewski","Maciej Dobrzyński","Maria Szymonowicz","Zbigniew Rybak"]', 'neuroscience', 'In recent years, stem cell therapy has become a very promising and advanced scientific research topic. The development of treatment methods has evoked great expectations. This paper is a review focused on the discovery of different stem cells and the potential therapies based on these cells. The genesis of stem cells is followed by laboratory steps of controlled stem cell culturing and derivation. Quality control and teratoma formation assays are important procedures in assessing the properties of the stem cells tested. Derivation methods and the utilization of culturing media are crucial to set proper environmental conditions for controlled differentiation. Among many types of stem tissue applications, the use of graphene scaffolds and the potential of extracellular vesicle-based therapies require attention due to their versatility. The review is summarized by challenges that stem cell therapy must overcome to be accepted worldwide. A wide variety of possibilities makes this cutting edge therapy a turning point in modern medicine, providing hope for untreatable diseases.', '2026-07-07 22:57:10');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3198052269', 'neuroscience', 'The Amyloid-β Pathway in Alzheimer’s Disease', 'Breakthroughs in molecular medicine have positioned the amyloid-β (Aβ) pathway at the center of Alzheimer''s disease (AD) pathophysiology. While the detailed molecular mechanisms of the pathway and…', '2021', 2021, 1817, 1817, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41380-021-01249-0/MediaObjects/41380_2021_1249_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8758495', 'pmc', 'review', 'Molecular Psychiatry', '["Harald Hampel","John Hardy","Kaj Blennow","Christopher Chen","George Perry","Seung Hyun Kim","Victor L. Villemagne","Paul Aisen","Michele Vendruscolo","Takeshi Iwatsubo","Colin L. Masters","Min Cho","Lars Lannfelt","Jeffrey L. Cummings","Andrea Vergallo"]', 'neuroscience', 'Breakthroughs in molecular medicine have positioned the amyloid-β (Aβ) pathway at the center of Alzheimer''s disease (AD) pathophysiology. While the detailed molecular mechanisms of the pathway and the spatial-temporal dynamics leading to synaptic failure, neurodegeneration, and clinical onset are still under intense investigation, the established biochemical alterations of the Aβ cycle remain the core biological hallmark of AD and are promising targets for the development of disease-modifying therapies. Here, we systematically review and update the vast state-of-the-art literature of Aβ science with evidence from basic research studies to human genetic and multi-modal biomarker investigations, which supports a crucial role of Aβ pathway dyshomeostasis in AD pathophysiological dynamics. We discuss the evidence highlighting a differentiated interaction of distinct Aβ species with other AD-related biological mechanisms, such as tau-mediated, neuroimmune and inflammatory changes, as well as a neurochemical imbalance. Through the lens of the latest development of multimodal in vivo biomarkers of AD, this cross-disciplinary review examines the compelling hypothesis- and data-driven rationale for Aβ-targeting therapeutic strategies in development for the early treatment of AD.', '2026-07-07 22:57:15');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1620203002', 'neuroscience', 'Interoceptive predictions in the brain', 'Interoceptive predictions in the brain', '2015', 2015, 1772, 1772, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnrn3950/MediaObjects/41583_2015_Article_BFnrn3950_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4731102', 'pmc', 'review', 'Nature reviews. Neuroscience', '["Lisa Feldman Barrett","W. Kyle Simmons"]', 'neuroscience', NULL, '2026-07-07 22:57:37');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2979984433', 'neuroscience', 'The blood–brain barrier and blood–tumour barrier in brain tumours and metastases', 'The blood–brain barrier and blood–tumour barrier in brain tumours and metastases', '2019', 2019, 1752, 1752, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41568-019-0205-x/MediaObjects/41568_2019_205_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8246629', 'pmc', 'review', 'Nature reviews. Cancer', '["Costas Arvanitis","Gino B. Ferraro","Rakesh K. Jain"]', 'neuroscience', NULL, '2026-07-07 22:57:37');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2799444748', 'neuroscience', 'Organoids in cancer research', 'Organoids in cancer research', '2018', 2018, 1751, 1751, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41568-018-0007-6/MediaObjects/41568_2018_7_Fig1_HTML.jpg', 'https://pubmed.ncbi.nlm.nih.gov/29692415', 'repository', 'review', 'Nature reviews. Cancer', '["Jarno Drost","Hans Clevers"]', 'neuroscience', NULL, '2026-07-07 22:57:38');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1921182138', 'neuroscience', 'Reconstruction and Simulation of Neocortical Microcircuitry', 'Reconstruction and Simulation of Neocortical Microcircuitry', '2015', 2015, 1674, 1674, 'https://ars.els-cdn.com/content/image/1-s2.0-S0092867415011915-fx1.jpg', 'https://pubmed.ncbi.nlm.nih.gov/26451489', 'repository', 'article', 'Cell', '["Henry Markram","Eilif Müller","Srikanth Ramaswamy","Michael Reimann","Marwan Abdellah","Carlos Sanchez","Anastasia Ailamaki","Lidia Alonso‐Nanclares","Nicolas Antille","Selim Arsever","Guy Antoine Atenekeng Kahou","Thomas K. Berger","Ahmet Bilgili","Nenad Buncic","Athanassia Chalimourda","Giuseppe Chindemi","Jean-Denis Courcol","Fabien Delalondre","Erika Ross","Shaul Druckmann","Raphael Dumusc","J.A. Dynes","Stefan Eilemann","Eyal Gal","Michael Gevaert","Jean-Pierre Ghobril","Albert Gidon","Joe W. Graham","Anirudh Gupta","Valentin Haenel","Etay Hay","Thomas Heinis","Juan Hernando","Michael L. Hines","Lida Kanari","Daniel Keller","John Kenyon","Georges Khazen","Yihwa Kim","James King","Zoltán F. Kisvárday","Pramod Kumbhar","Sébastien Lasserre","Jean-Vincent Le Bé","Bruno R. C. Magalhães","Ángel Merchán-Pérez","Julie Meystre","Benjamin Roy Morrice","Jeffrey Muller","Alberto Muñoz","Shruti Muralidhar","Keerthan Muthurasa","Daniel Nachbaur","Taylor Newton","Max Nolte","Aleksandr Ovcharenko","Juan C. Palacios","Luis Pastor","Rodrigo Perin","Rajnish Ranjan","Imad Riachi","José‐Rodrigo Rodríguez","Juan Luis Riquelme","Christian Rössert","Konstantinos Sfyrakis","Ying Shi","Julian C. Shillcock","Gilad Silberberg","Ricardo Silva","Farhan Tauheed","Martin Telefont","Maria Toledo‐Rodriguez","Thomas Tränkler","Werner Van Geit","Jafet Villafranca Díaz","Richard Walker","Yun Wang","Stefano M. Zaninetta","Javier DeFelipe","Sean Hill","Idan Segev","Felix Schürmann"]', 'neuroscience', NULL, '2026-07-07 22:57:48');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2520345180', 'neuroscience', 'Opposite Effects of mGluR1a and mGluR5 Activation on Nucleus Accumbens Medium Spiny Neuron Dendritic Spine Density', 'The group I metabotropic glutamate receptors (mGluR1a and mGluR5) are important modulators of neuronal structure and function. Although these receptors share common signaling pathways, they are…', '2016', 2016, 1630, 1630, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0162755.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5019418', 'pmc', 'article', 'PLoS ONE', '["Kellie S. Gross","Dieter D. Brandner","Luis A. Martinez","M. Foster Olive","Robert L. Meisel","P. Mermelstein"]', 'neuroscience', 'The group I metabotropic glutamate receptors (mGluR1a and mGluR5) are important modulators of neuronal structure and function. Although these receptors share common signaling pathways, they are capable of having distinct effects on cellular plasticity. We investigated the individual effects of mGluR1a or mGluR5 activation on dendritic spine density in medium spiny neurons in the nucleus accumbens (NAc), which has become relevant with the potential use of group I mGluR based therapeutics in the treatment of drug addiction. We found that systemic administration of mGluR subtype-specific positive allosteric modulators had opposite effects on dendritic spine densities. Specifically, mGluR5 positive modulation decreased dendritic spine densities in the NAc shell and core, but was without effect in the dorsal striatum, whereas increased spine densities in the NAc were observed with mGluR1a positive modulation. Additionally, direct activation of mGluR5 via CHPG administration into the NAc also decreased the density of dendritic spines. These data provide insight on the ability of group I mGluRs to induce structural plasticity in the NAc and demonstrate that the group I mGluRs are capable of producing not just distinct, but opposing, effects on dendritic spine density.', '2026-07-07 22:58:15');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4213108508', 'neuroscience', 'The Human Cell Atlas', 'The recent advent of methods for high-throughput single-cell molecular profiling has catalyzed a growing sense in the scientific community that the time is ripe to complete the 150-year-old effort to…', '2017', 2017, 1598, 1598, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.5167/uzh-162597.g001', 'https://doi.org/10.5167/uzh-162597', 'repository', 'article', 'Zurich Open Repository and Archive (University of Zurich)', '["Aviv Regev","Sarah A. Teichmann","Eric S. Lander","Ido Amit","Christophe Benoıst","Ewan Birney","Bernd Bodenmiller","Peter J. Campbell"]', 'neuroscience', 'The recent advent of methods for high-throughput single-cell molecular profiling has catalyzed a growing sense in the scientific community that the time is ripe to complete the 150-year-old effort to identify all cell types in the human body. The Human Cell Atlas Project is an international collaborative effort that aims to define all human cell types in terms of distinctive molecular profiles (such as gene expression profiles) and to connect this information with classical cellular descriptions (such as location and morphology). An open comprehensive reference map of the molecular state of cells in healthy human tissues would propel the systematic study of physiological states, developmental trajectories, regulatory circuitry and interactions of cells, and also provide a framework for understanding cellular dysregulation in human disease. Here we describe the idea, its potential utility, early proofs-of-concept, and some design considerations for the Human Cell Atlas, including a commitment to open data, code, and community.', '2026-07-07 22:58:29');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2953462495', 'neuroscience', 'Mechanisms of ROS Regulation of Plant Development and Stress Responses', 'Plants are subjected to various environmental stresses throughout their life cycle. Reactive oxygen species (ROS) play important roles in maintaining normal plant growth, and improving their…', '2019', 2019, 1454, 1454, 'https://www.frontiersin.org/files/Articles/440478/fpls-10-00800-HTML/image_m/fpls-10-00800-g001.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6603150', 'pmc', 'review', 'Frontiers in Plant Science', '["Honglin Huang","Farhan Ullah","Dao‐Xiu Zhou","Ming Yi","Yu Zhao"]', 'neuroscience', 'Plants are subjected to various environmental stresses throughout their life cycle. Reactive oxygen species (ROS) play important roles in maintaining normal plant growth, and improving their tolerance to stress. This review describes the production and removal of ROS in plants, summarizes recent progress in understanding the role of ROS during plant vegetative apical meristem development, organogenesis, and abiotic stress responses, and some novel findings in recent years are discussed. More importantly, interplay between ROS and epigenetic modifications in regulating gene expression is specifically discussed. To summarize, plants integrate ROS with genetic, epigenetic, hormones and external signals to promote development and environmental adaptation.', '2026-07-07 22:59:38');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2098605272', 'neuroscience', 'Family income, parental education and brain structure in children and adolescents', 'Family income, parental education and brain structure in children and adolescents', '2015', 2015, 1438, 1438, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnn.3983/MediaObjects/41593_2015_Article_BFnn3983_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4414816', 'pmc', 'article', 'Nature Neuroscience', '["Kimberly G. Noble","Suzanne M. Houston","Natalie H. Brito","Hauke Bartsch","Eric Kan","Joshua Kuperman","Natacha Akshoomoff","David G. Amaral","Cinnamon S. Bloss","Ondrej Libiger","Nicholas J. Schork","Sarah Murray","B.J. Casey","Linda Chang","Thomas Ernst","Jean A. Frazier","Jeffrey R. Gruen","David N. Kennedy","Peter C.M. van Zijl","Stewart H. Mostofsky","Walter E. Kaufmann","Tal Kenet","Anders M. Dale","Terry L. Jernigan","Elizabeth R. Sowell"]', 'neuroscience', NULL, '2026-07-07 22:59:39');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3035432101', 'neuroscience', 'A typology of compound weather and climate events', 'A typology of compound weather and climate events', '2020', 2020, 1454, 1454, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs43017-020-0060-z/MediaObjects/43017_2020_60_Fig1_HTML.png', 'https://insu.hal.science/insu-03726983', 'repository', 'review', 'Nature Reviews Earth & Environment', '["Jakob Zscheischler","Olivia Martius","Seth Westra","Emanuele Bevacqua","Colin Raymond","Radley Horton","Bart van den Hurk","Amir AghaKouchak","Aglaé Jézéquel","Miguel D. Mahecha","Douglas Maraun","Alexandre M. Ramos","Nina Ridder","Wim Thiery","Edoardo Vignotto"]', 'neuroscience', NULL, '2026-07-07 22:59:39');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2766639217', 'neuroscience', 'The challenge of mapping the human connectome based on diffusion tractography', 'Tractography based on non-invasive diffusion imaging is central to the study of human brain connectivity. To date, the approach has not been systematically validated in ground truth studies. Based on…', '2017', 2017, 1435, 1435, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1038%2Fs41597-022-01624-8/MediaObjects/41597_2022_1624_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5677006', 'pmc', 'article', 'Nature Communications', '["Klaus Maier‐Hein","Peter Neher","Jean-Christophe Houde","Marc-Alexandre Côté","Eleftherios Garyfallidis","jinyu zhong","Maxime Chamberland","Fang‐Cheng Yeh","Ying‐Chia Lin","Qing Ji","Wilburn E. Reddick","John O. Glass","David Qixiang Chen","Yuanjing Feng","Chengfeng Gao","Ye Wu","Jieyan Ma","Renjie He","Qiang Li","Carl‐Fredrik Westin","Samuel Deslauriers‐Gauthier","J. Omar Ocegueda González","Michael Paquette","Samuel St‐Jean","Gabriel Girard","François Rheault","Jasmeen Sidhu","Chantal M. W. Tax","Fenghua Guo","Hamed Y. Mesri","Szabolcs Dávid","Martijn Froeling","Anneriet M. Heemskerk","Alexander Leemans","Arnaud Boré","Basile Pinsard","Christophe Bedetti","Matthieu Desrosiers","Simona M. Brambati","Julien Doyon","Alessia Sarica","Roberta Vasta","Antonio Cerasa","Aldo Quattrone","Jason D. Yeatman","Ali R. Khan","Wes Hodges","Simon Alexander","David Romascano","Muhamed Baraković","Anna Auría","Oscar Estéban","Alia Lemkaddem","Jean‐Philippe Thiran","H. Ertan Çetingül","Benjamin L. Odry","Boris Mailhé","Mariappan S. Nadar","Fabrizio Pizzagalli","Gautam Prasad","Julio E. Villalón‐Reina","Justin Galvis","Paul M. Thompson","Francisco De Santiago Requejo","Pedro Luque Laguna","Luís Miguel Lacerda","Rachel Barrett","Flavio Dell’Acqua","Marco Catani","Laurent Petit","Emmanuel Caruyer","Alessandro Daducci","Tim B. Dyrby","Tim Holland‐Letz","Claus C. Hilgetag","Bram Stieltjes","Maxime Descoteaux"]', 'neuroscience', 'Tractography based on non-invasive diffusion imaging is central to the study of human brain connectivity. To date, the approach has not been systematically validated in ground truth studies. Based on a simulated human brain data set with ground truth tracts, we organized an open international tractography challenge, which resulted in 96 distinct submissions from 20 research groups. Here, we report the encouraging finding that most state-of-the-art algorithms produce tractograms containing 90% of the ground truth bundles (to at least some extent). However, the same tractograms contain many more invalid than valid bundles, and half of these invalid bundles occur systematically across research groups. Taken together, our results demonstrate and confirm fundamental ambiguities inherent in tract reconstruction based on orientation information alone, which need to be considered when interpreting tractography and connectivity results. Our approach provides a novel framework for estimating reliability of tractography and encourages innovation to address its current limitations.', '2026-07-07 22:59:41');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2609844460', 'neuroscience', 'Cell diversity and network dynamics in photosensitive human brain organoids', 'Cell diversity and network dynamics in photosensitive human brain organoids', '2017', 2017, 1342, 1342, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature22047/MediaObjects/41586_2017_Article_BFnature22047_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5659341', 'pmc', 'article', 'Nature', '["Giorgia Quadrato","Tuan Nguyen","Evan Z. Macosko","J. L. Sherwood","Sung Min Yang","Daniel R. Berger","Natalie Maria","Jörg Scholvin","Melissa Goldman","Justin P. Kinney","Edward S. Boyden","Jeff W. Lichtman","Ziv M. Williams","Steven A. McCarroll","Paola Arlotta"]', 'neuroscience', NULL, '2026-07-07 23:00:33');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2346576232', 'neuroscience', 'Cortical abnormalities in adults and adolescents with major depression based on brain scans from 20 cohorts worldwide in the ENIGMA Major Depressive Disorder Working Group', 'The neuro-anatomical substrates of major depressive disorder (MDD) are still not well understood, despite many neuroimaging studies over the past few decades. Here we present the largest ever…', '2016', 2016, 1342, 1342, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fmp.2016.60/MediaObjects/41380_2017_Article_BFmp201660_Fig1_HTML.jpg', 'https://pubmed.ncbi.nlm.nih.gov/27137745', 'repository', 'review', 'Molecular Psychiatry', '["for the ENIGMA-Major Depressive Disorder Working Group","Lianne Schmaal","Derrek P. Hibar","Philipp G. Sämann","Geoffrey B. Hall","Bernhard T. Baune","Neda Jahanshad","J. Cheung","Theo G.M. van Erp","Daniël Bos","M. Arfan Ikram","Meike W. Vernooij","Wiro J. Niessen","Henning Tiemeier","Albert Hofman","Katharina Wittfeld","Hans J. Grabe","Deborah Janowitz","Robin Bülow","M Selonke","Henry Völzke","Dominik Grotegerd","Udo Dannlowski","Volker Arolt","Nils Opel","Walter Heindel","Harald Kugel","David Hoehn","Michael Czisch","Baptiste Couvy‐Duchesne","Miguel E. Rentería","Lachlan T. Strike","Margaret J. Wright","Natalie Mills","Greig I. de Zubicaray","Katie L. McMahon","Sarah E. Medland","Nicholas G. Martin","Nathan A. Gillespie","Roberto Goya‐Maldonado","Oliver Gruber","Bernd Krämer","Sean N. Hatton","Jim Lagopoulos","Ian B. Hickie","Thomas Frodl","Angela Carballedo","Eva-Maria Frey","Laura S. van Velzen","Brenda W.J.H. Penninx","M-J van Tol","Nic J. van der Wee","Christopher G. Davey","Ben J. Harrison","Benson Mwangi","Bo Cao","Jair C. Soares","Ilya M. Veer","Henrik Walter","Dieter Schoepf","Bartosz Zurowski","Carsten Konrad","Elisabeth Schramm","Claus Normann","Knut Schnell","Matthew D. Sacchet","Ian H. Gotlib","Glenda MacQueen","Beata R. Godlewska","Thomas E. Nickson","Andrew M. McIntosh","Martina Papmeyer","Heather C. Whalley","Jérémy Hall","J. E. Sussmann","Mingzhe Li","Martin Walter","Lyubomir I. Aftanas","Ivan Brack","Н. А. Бохан","Paul M. Thompson","Dick J. Veltman"]', 'neuroscience', 'The neuro-anatomical substrates of major depressive disorder (MDD) are still not well understood, despite many neuroimaging studies over the past few decades. Here we present the largest ever worldwide study by the ENIGMA (Enhancing Neuro Imaging Genetics through Meta-Analysis) Major Depressive Disorder Working Group on cortical structural alterations in MDD. Structural T1-weighted brain magnetic resonance imaging (MRI) scans from 2148 MDD patients and 7957 healthy controls were analysed with harmonized protocols at 20 sites around the world. To detect consistent effects of MDD and its modulators on cortical thickness and surface area estimates derived from MRI, statistical effects from sites were meta-analysed separately for adults and adolescents. Adults with MDD had thinner cortical gray matter than controls in the orbitofrontal cortex (OFC), anterior and posterior cingulate, insula and temporal lobes (Cohen''s d effect sizes: -0.10 to -0.14). These effects were most pronounced in first episode and adult-onset patients (>21 years). Compared to matched controls, adolescents with MDD had lower total surface area (but no differences in cortical thickness) and regional reductions in frontal regions (medial OFC and superior frontal gyrus) and primary and higher-order visual, somatosensory and motor areas (d: -0.26 to -0.57). The strongest effects were found in recurrent adolescent patients. This highly powered global effort to identify consistent brain abnormalities showed widespread cortical alterations in MDD patients as compared to controls and suggests that MDD may impact brain structure in a highly dynamic way, with different patterns of alterations at different stages of life.', '2026-07-07 23:00:34');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4214833982', 'neuroscience', 'Inflammation and immune dysfunction in Parkinson disease', 'Inflammation and immune dysfunction in Parkinson disease', '2022', 2022, 1354, 1354, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41577-022-00684-6/MediaObjects/41577_2022_684_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8895080', 'pmc', 'review', 'Nature reviews. Immunology', '["Malú G. Tansey","Rebecca L. Wallings","Madelyn C. Houser","Mary K. Herrick","Cody E. Keating","Valerie Joers"]', 'neuroscience', NULL, '2026-07-07 23:00:35');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3174664487', 'neuroscience', 'Parkinson disease-associated cognitive impairment', 'Parkinson disease-associated cognitive impairment', '2021', 2021, 1354, 1354, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41572-021-00280-3/MediaObjects/41572_2021_280_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/34210995', 'repository', 'review', 'Nature Reviews Disease Primers', '["Dag Aarsland","Lucia Batzu","Glenda M. Halliday","Gert J. Geurtsen","Clive Ballard","К. Ray Chaudhuri","Daniel Weintraub"]', 'neuroscience', NULL, '2026-07-07 23:00:35');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2609473806', 'neuroscience', 'Assembly of functionally integrated human forebrain spheroids', 'Assembly of functionally integrated human forebrain spheroids', '2017', 2017, 1348, 1348, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature22330/MediaObjects/41586_2017_Article_BFnature22330_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5805137', 'pmc', 'article', 'Nature', '["Fikri Birey","Jimena Andersen","Christopher D. Makinson","Saiful Islam","Wei Wu","Nina Huber","H. Christina Fan","Kimberly R. Cordes Metzler","Georgia Panagiotakos","Nicholas Thom","Nancy O’Rourke","Lars M. Steinmetz","Jonathan A. Bernstein","Joachim Hallmayer","John R. Huguenard","Sergiu P. Pașca"]', 'neuroscience', NULL, '2026-07-07 23:00:35');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2566775857', 'neuroscience', 'Closed-loop brain training: the science of neurofeedback', 'Closed-loop brain training: the science of neurofeedback', '2016', 2016, 1340, 1340, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnrn.2016.164/MediaObjects/41583_2017_Article_BFnrn2016164_Fig1_HTML.jpg', 'https://pubmed.ncbi.nlm.nih.gov/28003656', 'repository', 'review', 'Nature reviews. Neuroscience', '["Ranganatha Sitaram","Tomas Ros","Luke E. Stoeckel","Sven Haller","Frank Scharnowski","Jarrod A. Lewis‐Peacock","Nikolaus Weiskopf","Maria Laura Blefari","Mohit Rana","Ethan Oblak","Niels Birbaumer","James Sulzer"]', 'neuroscience', NULL, '2026-07-07 23:00:35');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2888970663', 'neuroscience', 'Emergency department crowding: A systematic review of causes, consequences and solutions', 'BACKGROUND: Emergency department crowding is a major global healthcare issue. There is much debate as to the causes of the phenomenon, leading to difficulties in developing successful, targeted…', '2018', 2018, 1330, 1330, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0203316.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6117060', 'pmc', 'review', 'PLoS ONE', '["Claire Morley","Maria Unwin","Gregory M. Peterson","Jim Stankovich","Leigh Kinsman"]', 'neuroscience', 'BACKGROUND: Emergency department crowding is a major global healthcare issue. There is much debate as to the causes of the phenomenon, leading to difficulties in developing successful, targeted solutions. AIM: The aim of this systematic review was to critically analyse and summarise the findings of peer-reviewed research studies investigating the causes and consequences of, and solutions to, emergency department crowding. METHOD: The Preferred Reporting Items for Systematic Reviews and Meta-Analyses (PRISMA) guidelines were followed. A structured search of four databases (Medline, CINAHL, EMBASE and Web of Science) was undertaken to identify peer-reviewed research publications aimed at investigating the causes or consequences of, or solutions to, emergency department crowding, published between January 2000 and June 2018. Two reviewers used validated critical appraisal tools to independently assess the quality of the studies. The study protocol was registered with the International prospective register of systematic reviews (PROSPERO 2017: CRD42017073439). RESULTS: From 4,131 identified studies and 162 full text reviews, 102 studies met the inclusion criteria. The majority were retrospective cohort studies, with the greatest proportion (51%) trialling or modelling potential solutions to emergency department crowding. Fourteen studies examined causes and 40 investigated consequences. Two studies looked at both causes and consequences, and two investigated causes and solutions. CONCLUSIONS: The negative consequences of ED crowding are well established, including poorer patient outcomes and the inability of staff to adhere to guideline-recommended treatment. This review identified a mismatch between causes and solutions. The majority of identified causes related to the number and type of people attending ED and timely discharge from ED, while reported solutions focused on efficient patient flow within the ED. Solutions aimed at the introduction of whole-of-system initiatives to meet timed patient disposition targets, as well as extended hours of primary care, demonstrated promising outcomes. While the review identified increased presentations by the elderly with complex and chronic conditions as an emerging and widespread driver of crowding, more research is required to isolate the precise local factors leading to ED crowding, with system-wide solutions tailored to address identified causes.', '2026-07-07 23:00:48');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2790631595', 'neuroscience', 'Cannabinoid Receptors and the Endocannabinoid System: Signaling and Function in the Central Nervous System', '(marijuana) are mediated by two members of the G-protein coupled receptor family, cannabinoid receptors 1 (CB1R) and 2. The CB1R is the prominent subtype in the central nervous system (CNS) and has…', '2018', 2018, 1333, 1333, 'https://pub.mdpi-res.com/ijms/ijms-19-00833/article_deploy/html/images/ijms-19-00833-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5877694', 'pmc', 'review', 'International Journal of Molecular Sciences', '["Shenglong Zou","Ujendra Kumar"]', 'neuroscience', '(marijuana) are mediated by two members of the G-protein coupled receptor family, cannabinoid receptors 1 (CB1R) and 2. The CB1R is the prominent subtype in the central nervous system (CNS) and has drawn great attention as a potential therapeutic avenue in several pathological conditions, including neuropsychological disorders and neurodegenerative diseases. Furthermore, cannabinoids also modulate signal transduction pathways and exert profound effects at peripheral sites. Although cannabinoids have therapeutic potential, their psychoactive effects have largely limited their use in clinical practice. In this review, we briefly summarized our knowledge of cannabinoids and the endocannabinoid system, focusing on the CB1R and the CNS, with emphasis on recent breakthroughs in the field. We aim to define several potential roles of cannabinoid receptors in the modulation of signaling pathways and in association with several pathophysiological conditions. We believe that the therapeutic significance of cannabinoids is masked by the adverse effects and here alternative strategies are discussed to take therapeutic advantage of cannabinoids.', '2026-07-07 23:00:59');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2968628489', 'neuroscience', 'The Gamification of Learning: a Meta-analysis', 'This meta-analysis was conducted to systematically synthesize research findings on effects of gamification on cognitive, motivational, and behavioral learning outcomes. Results from random effects…', '2019', 2019, 1289, 1289, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1007%2Fs10648-019-09498-w/MediaObjects/10648_2019_9498_Fig1_HTML.png', 'https://doi.org/10.1007/s10648-019-09498-w', 'repository', 'article', 'Educational Psychology Review', '["Michael Sailer","Lisa Homner"]', 'neuroscience', 'This meta-analysis was conducted to systematically synthesize research findings on effects of gamification on cognitive, motivational, and behavioral learning outcomes. Results from random effects models showed significant small effects of gamification on cognitive ( g =.49, 95% CI [0.30, 0.69], k = 19, N = 1686), motivational ( g =.36, 95% CI [0.18, 0.54], k = 16, N = 2246), and behavioral learning outcomes ( g =.25, 95% CI [0.04, 0.46], k = 9, N = 951). Whereas the effect of gamification on cognitive learning outcomes was stable in a subsplit analysis of studies employing high methodological rigor, effects on motivational and behavioral outcomes were less stable. Given the heterogeneity of effect sizes, moderator analyses were conducted to examine inclusion of game fiction, social interaction, learning arrangement of the comparison group, as well as situational, contextual, and methodological moderators, namely, period of time, research context, randomization, design, and instruments. Inclusion of game fiction and social interaction were significant moderators of the effect of gamification on behavioral learning outcomes. Inclusion of game fiction and combining competition with collaboration were particularly effective within gamification for fostering behavioral learning outcomes. Results of the subsplit analysis indicated that effects of competition augmented with collaboration might also be valid for motivational learning outcomes. The results suggest that gamification as it is currently operationalized in empirical studies is an effective method for instruction, even though factors contributing to successful gamification are still somewhat unresolved, especially for cognitive learning outcomes.', '2026-07-07 23:01:18');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2288271511', 'neuroscience', 'RETRACTED: A mathematical model explains saturating axon guidance responses to molecular gradients', 'Correct wiring is crucial for the proper functioning of the nervous system. Molecular gradients provide critical signals to guide growth cones, which are the motile tips of developing axons, to their…', '2016', 2016, 1259, 1259, 'https://cdn.elifesciences.org/articles/12248/elife-12248-fig1-v1.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4755759', 'pmc', 'article', 'eLife', '["Huyen Nguyen","Peter Dayan","Zac Pujic","Justin J. Cooper‐White","Geoffrey J. Goodhill"]', 'neuroscience', 'Correct wiring is crucial for the proper functioning of the nervous system. Molecular gradients provide critical signals to guide growth cones, which are the motile tips of developing axons, to their targets. However, in vitro, growth cones trace highly stochastic trajectories, and exactly how molecular gradients bias their movement is unclear. Here, we introduce a mathematical model based on persistence, bias, and noise to describe this behaviour, constrained directly by measurements of the detailed statistics of growth cone movements in both attractive and repulsive gradients in a microfluidic device. This model provides a mathematical explanation for why average axon turning angles in gradients in vitro saturate very rapidly with time at relatively small values. This work introduces the most accurate predictive model of growth cone trajectories to date, and deepens our understanding of axon guidance events both in vitro and in vivo.', '2026-07-07 23:01:40');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3093434759', 'neuroscience', 'Spinal Cord Injury: Pathophysiology, Multimolecular Interactions, and Underlying Recovery Mechanisms', 'Spinal cord injury (SCI) is a destructive neurological and pathological state that causes major motor, sensory and autonomic dysfunctions. Its pathophysiology comprises acute and chronic phases and…', '2020', 2020, 1254, 1254, 'https://pub.mdpi-res.com/ijms/ijms-21-07533/article_deploy/html/images/ijms-21-07533-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7589539', 'pmc', 'review', 'International Journal of Molecular Sciences', '["Anam Anjum","Muhammad Dain Yazid","Muhammad Daud","Jalilah Idris","Min Hwei Ng","Amaramalar Selvi Naicker","Ohnmar Htwe Rashidah Ismail","Ramesh Kumar","Yogeswaran Lokanathan"]', 'neuroscience', 'Spinal cord injury (SCI) is a destructive neurological and pathological state that causes major motor, sensory and autonomic dysfunctions. Its pathophysiology comprises acute and chronic phases and incorporates a cascade of destructive events such as ischemia, oxidative stress, inflammatory events, apoptotic pathways and locomotor dysfunctions. Many therapeutic strategies have been proposed to overcome neurodegenerative events and reduce secondary neuronal damage. Efforts have also been devoted in developing neuroprotective and neuro-regenerative therapies that promote neuronal recovery and outcome. Although varying degrees of success have been achieved, curative accomplishment is still elusive probably due to the complex healing and protective mechanisms involved. Thus, current understanding in this area must be assessed to formulate appropriate treatment modalities to improve SCI recovery. This review aims to promote the understanding of SCI pathophysiology, interrelated or interlinked multimolecular interactions and various methods of neuronal recovery i.e., neuroprotective, immunomodulatory and neuro-regenerative pathways and relevant approaches.', '2026-07-07 23:01:48');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2474981734', 'neuroscience', 'Early role of vascular dysregulation on late-onset Alzheimer’s disease based on multifactorial data-driven analysis', 'Multifactorial mechanisms underlying late-onset Alzheimer''s disease (LOAD) are poorly characterized from an integrative perspective. Here spatiotemporal alterations in brain amyloid-β deposition,…', '2016', 2016, 1207, 1207, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fncomms11934/MediaObjects/41467_2016_Article_BFncomms11934_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4919512', 'pmc', 'article', 'Nature Communications', '["Yasser Iturria‐Medina","Roberto C. Sotero","P.-J. Toussaint","J.M. Mateos-Pérez","Alan C. Evans","The Alzheimer’s Disease Neuroimaging Initiative","Michael W. Weiner","Paul Aisen","Ronald C. Petersen","Clifford R. Jack","William J. Jagust","John Q. Trojanowki","Arthur W. Toga","Laurel Beckett","Robert C. Green","Andrew J. Saykin","John C. Morris","Leslie M. Shaw","Zaven S. Khachaturian","Greg Sorensen","Lew Kuller","Marc Raichle","Steven M. Paul","Peter Davies","Howard Fillit","Franz Hefti","Davie Holtzman","M. Marcel Mesulam","William Z. Potter","Peter J. Snyder","Adam J. Schwartz","Tom Montine","Ronald G. Thomas","Michael Donohue","Sarah Walter","Devon Gessert","Tamie Sather","Gus Jiminez","Danielle Harvey","Matt A. Bernstein","Nick C. Fox","Paul M. Thompson","Norbert Schuff","Bret Borowski","Jeff Gunter","Matthew L. Senjem","Prashanthi Vemuri","David T. Jones","Kejal Kantarci","Chad Ward","Robert A. Koeppe","Norm Foster","Eric M. Reiman","Kewei Chen","Chet Mathis","Susan Landau","Nigel J. Cairns","Erin Householder","Lisa Taylor‐Reinwald","Virginia Lee","Magdalena Korecka","Michal Figurski","Karen Crawford","Scott Neu","Tatiana Foroud","Steven Potkin","Li Shen","Kelley Faber","Sungeun Kim","Kwangsik Nho","Leon J. Thal","Neil Buckholtz","Marylyn Albert","Richard Frank","John Hsiao","Jeffrey Kaye","Joseph F. Quinn","Betty Lind","Raina Carter","Sara Dolen","Lon S. Schneider","Sonia Pawluczyk","Mauricio Beccera","Liberty Teodoro","Bryan M. Spann","James B. Brewer","Helen Vanderswag","Adam Fleisher","Judith L. Heidebrink","Joanne Lord","Sara S. Mason","Colleen S. Albers","David S. Knopman","Kris Johnson","Rachelle S. Doody","Javier Villanueva‐Meyer","Munir Chowdhury","Susan Rountree","Mimi Dang","Yaakov Stern"]', 'neuroscience', 'Multifactorial mechanisms underlying late-onset Alzheimer''s disease (LOAD) are poorly characterized from an integrative perspective. Here spatiotemporal alterations in brain amyloid-β deposition, metabolism, vascular, functional activity at rest, structural properties, cognitive integrity and peripheral proteins levels are characterized in relation to LOAD progression. We analyse over 7,700 brain images and tens of plasma and cerebrospinal fluid biomarkers from the Alzheimer''s Disease Neuroimaging Initiative (ADNI). Through a multifactorial data-driven analysis, we obtain dynamic LOAD-abnormality indices for all biomarkers, and a tentative temporal ordering of disease progression. Imaging results suggest that intra-brain vascular dysregulation is an early pathological event during disease development. Cognitive decline is noticeable from initial LOAD stages, suggesting early memory deficit associated with the primary disease factors. High abnormality levels are also observed for specific proteins associated with the vascular system''s integrity. Although still subjected to the sensitivity of the algorithms and biomarkers employed, our results might contribute to the development of preventive therapeutic interventions.', '2026-07-07 23:02:25');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2998795963', 'neuroscience', 'Human and mouse single-nucleus transcriptomics reveal TREM2-dependent and TREM2-independent cellular responses in Alzheimer’s disease', 'Human and mouse single-nucleus transcriptomics reveal TREM2-dependent and TREM2-independent cellular responses in Alzheimer’s disease', '2020', 2020, 1209, 1209, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41591-019-0695-9/MediaObjects/41591_2019_695_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6980793', 'pmc', 'article', 'Nature Medicine', '["Yingyue Zhou","Wilbur M. Song","Prabhakar S. Andhey","Amanda Swain","Tyler Levy","Kelly R. Miller","Pietro Luigi Poliani","Manuela Cominelli","Shikha Grover","Susan Gilfillan","Marina Cella","Tyler K. Ulland","Konstantin Zaitsev","Akinori Miyashita","Takeshi Ikeuchi","Makoto Sainouchi","Akiyoshi Kakita","David A. Bennett","Julie A. Schneider","Michael R. Nichols","Sean A. Beausoleil","Jason D. Ulrich","David M. Holtzman","Maxim N. Artyomov","Marco Colonna"]', 'neuroscience', NULL, '2026-07-07 23:02:25');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2018681635', 'neuroscience', 'Astrocyte barriers to neurotoxic inflammation', 'Astrocyte barriers to neurotoxic inflammation', '2015', 2015, 1204, 1204, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnrn3898/MediaObjects/41583_2015_Article_BFnrn3898_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5253239', 'pmc', 'review', 'Nature reviews. Neuroscience', '["Michael V. Sofroniew"]', 'neuroscience', NULL, '2026-07-07 23:02:25');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2507387536', 'neuroscience', 'The Human Connectome Project''s neuroimaging approach', 'The Human Connectome Project''s neuroimaging approach', '2016', 2016, 1200, 1200, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnn.4361/MediaObjects/41593_2016_Article_BFnn4361_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6172654', 'pmc', 'review', 'Nature Neuroscience', '["Matthew F. Glasser","Stephen M. Smith","Daniel S. Marcus","Jesper Andersson","Edward J. Auerbach","Timothy E.J. Behrens","Timothy S. Coalson","Michael P. Harms","Mark Jenkinson","Steen Moeller","Emma C. Robinson","Stamatios N. Sotiropoulos","Junqian Xu","Essa Yacoub","Kâmil Uǧurbil","David C. Van Essen"]', 'neuroscience', NULL, '2026-07-07 23:02:26');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2805798400', 'neuroscience', 'APOE4 Causes Widespread Molecular and Cellular Alterations Associated with Alzheimer’s Disease Phenotypes in Human iPSC-Derived Brain Cell Types', 'APOE4 Causes Widespread Molecular and Cellular Alterations Associated with Alzheimer’s Disease Phenotypes in Human iPSC-Derived Brain Cell Types', '2018', 2018, 1152, 1152, 'https://ars.els-cdn.com/content/image/1-s2.0-S0896627318303805-fx1.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6023751', 'pmc', 'article', 'Neuron', '["Yuan-Ta Lin","Jinsoo Seo","Fan Gao","Heather Feldman","Hsin-Lan Wen","Jay Penney","Hugh P. Cam","Elizabeta Gjoneska","Waseem Raja","Jemmie Cheng","Richard Rueda","Oleg Kritskiy","Fatema Abdurrob","Zhuyu Peng","Blerta Milo","Chung Jong Yu","Sara Elmsaouri","Dilip Dey","Tak Ko","Bruce A. Yankner","Li‐Huei Tsai"]', 'neuroscience', NULL, '2026-07-07 23:03:17');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4386448978', 'neuroscience', 'Mitochondrial dynamics in health and disease: mechanisms and potential targets', 'Mitochondria are organelles that are able to adjust and respond to different stressors and metabolic needs within a cell, showcasing their plasticity and dynamic nature. These abilities allow them to…', '2023', 2023, 1151, 1151, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41392-023-01547-9/MediaObjects/41392_2023_1547_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/10480456', 'pmc', 'review', 'Signal Transduction and Targeted Therapy', '["Wen Chen","Huakan Zhao","Yongsheng Li"]', 'neuroscience', 'Mitochondria are organelles that are able to adjust and respond to different stressors and metabolic needs within a cell, showcasing their plasticity and dynamic nature. These abilities allow them to effectively coordinate various cellular functions. Mitochondrial dynamics refers to the changing process of fission, fusion, mitophagy and transport, which is crucial for optimal function in signal transduction and metabolism. An imbalance in mitochondrial dynamics can disrupt mitochondrial function, leading to abnormal cellular fate, and a range of diseases, including neurodegenerative disorders, metabolic diseases, cardiovascular diseases and cancers. Herein, we review the mechanism of mitochondrial dynamics, and its impacts on cellular function. We also delve into the changes that occur in mitochondrial dynamics during health and disease, and offer novel perspectives on how to target the modulation of mitochondrial dynamics.', '2026-07-07 23:03:29');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2890187093', 'neuroscience', 'Microglial signatures and their role in health and disease', 'Microglial signatures and their role in health and disease', '2018', 2018, 1149, 1149, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41583-018-0057-5/MediaObjects/41583_2018_57_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7255106', 'pmc', 'review', 'Nature reviews. Neuroscience', '["Oleg Butovsky","Howard L. Weiner"]', 'neuroscience', NULL, '2026-07-07 23:03:30');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2971683016', 'neuroscience', 'The brain’s default network: updated anatomy, physiology and evolving insights', 'The brain’s default network: updated anatomy, physiology and evolving insights', '2019', 2019, 1148, 1148, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41583-019-0212-7/MediaObjects/41583_2019_212_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/31492945', 'repository', 'review', 'Nature reviews. Neuroscience', '["Randy L. Buckner","Lauren M. DiNicola"]', 'neuroscience', NULL, '2026-07-07 23:03:33');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2800819102', 'climate-hydrology', 'Rainfall–runoff modelling using Long Short-Term Memory (LSTM) networks', 'Abstract. Rainfall–runoff modelling is one of the key challenges in the field of hydrology. Various approaches exist, ranging from physically based over conceptual to fully data-driven models. In…', '2018', 2018, 1847, 1847, 'https://www.hydrology-and-earth-system-sciences.net/graphic_egu_claim_logo_blue.png', 'http://api.osf.io/v2/nodes/dxzet/', 'repository', 'article', 'Hydrology and earth system sciences', '["Frederik Kratzert","Daniel Klotz","Claire Brenner","Karsten Schulz","Mathew Herrnegger"]', 'climate & hydrology', 'Abstract. Rainfall–runoff modelling is one of the key challenges in the field of hydrology. Various approaches exist, ranging from physically based over conceptual to fully data-driven models. In this paper, we propose a novel data-driven approach, using the Long Short-Term Memory (LSTM) network, a special type of recurrent neural network. The advantage of the LSTM is its ability to learn long-term dependencies between the provided input and output of the network, which are essential for modelling storage effects in e.g. catchments with snow influence. We use 241 catchments of the freely available CAMELS data set to test our approach and also compare the results to the well-known Sacramento Soil Moisture Accounting Model (SAC-SMA) coupled with the Snow-17 snow routine. We also show the potential of the LSTM as a regional hydrological model in which one model predicts the discharge for a variety of catchments. In our last experiment, we show the possibility to transfer process understanding, learned at regional scale, to individual catchments and thereby increasing model performance when compared to a LSTM trained only on the data of single catchments. Using this approach, we were able to achieve better model performance as the SAC-SMA + Snow-17, which underlines the potential of the LSTM for hydrological modelling applications.', '2026-07-07 23:03:46');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3166420679', 'climate-hydrology', 'SoilGrids 2.0: producing soil information for the globe with quantified spatial uncertainty', 'Abstract. SoilGrids produces maps of soil properties for the entire globe at medium spatial resolution (250 m cell size) using state-of-the-art machine learning methods to generate the necessary…', '2021', 2021, 2086, 2086, 'https://www.soil-journal.net/graphic_egu_claim_logo_blue.png', 'https://doi.org/10.5194/soil-7-217-2021', 'repository', 'article', 'SOIL', '["Laura Poggio","Luís Moreira de Sousa","N.H. Batjes","G.B.M. Heuvelink","Bas Kempen","Eloi Ribeiro","David G. Rossiter"]', 'climate & hydrology', 'Abstract. SoilGrids produces maps of soil properties for the entire globe at medium spatial resolution (250 m cell size) using state-of-the-art machine learning methods to generate the necessary models. It takes as inputs soil observations from about 240 000 locations worldwide and over 400 global environmental covariates describing vegetation, terrain morphology, climate, geology and hydrology. The aim of this work was the production of global maps of soil properties, with cross-validation, hyper-parameter selection and quantification of spatially explicit uncertainty, as implemented in the SoilGrids version 2.0 product incorporating state-of-the-art practices and adapting them for global digital soil mapping with legacy data. The paper presents the evaluation of the global predictions produced for soil organic carbon content, total nitrogen, coarse fragments, pH (water), cation exchange capacity, bulk density and texture fractions at six standard depths (up to 200 cm). The quantitative evaluation showed metrics in line with previous global, continental and large-region studies. The qualitative evaluation showed that coarse-scale patterns are well reproduced. The spatial uncertainty at global scale highlighted the need for more soil observations, especially in high-latitude regions.', '2026-07-07 23:03:47');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2745770579', 'climate-hydrology', 'Soil carbon debt of 12,000 years of human land use', 'Human appropriation of land for agriculture has greatly altered the terrestrial carbon balance, creating a large but uncertain carbon debt in soils. Estimating the size and spatial distribution of…', '2017', 2017, 1459, 1459, 'https://cdn.ncbi.nlm.nih.gov/pmc/blobs/920a/5594668/afa706dac62c/pnas.1706103114fig01.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5594668', 'pmc', 'article', 'Proceedings of the National Academy of Sciences', '["Jonathan Sanderman","Tomislav Hengl","Greg Fiske"]', 'climate & hydrology', 'Human appropriation of land for agriculture has greatly altered the terrestrial carbon balance, creating a large but uncertain carbon debt in soils. Estimating the size and spatial distribution of soil organic carbon (SOC) loss due to land use and land cover change has been difficult but is a critical step in understanding whether SOC sequestration can be an effective climate mitigation strategy. In this study, a machine learning-based model was fitted using a global compilation of SOC data and the History Database of the Global Environment (HYDE) land use data in combination with climatic, landform and lithology covariates. Model results compared favorably with a global compilation of paired plot studies. Projection of this model onto a world without agriculture indicated a global carbon debt due to agriculture of 133 Pg C for the top 2 m of soil, with the rate of loss increasing dramatically in the past 200 years. The HYDE classes "grazing" and "cropland" contributed nearly equally to the loss of SOC. There were higher percent SOC losses on cropland but since more than twice as much land is grazed, slightly higher total losses were found from grazing land. Important spatial patterns of SOC loss were found: Hotspots of SOC loss coincided with some major cropping regions as well as semiarid grazing regions, while other major agricultural zones showed small losses and even net gains in SOC. This analysis has demonstrated that there are identifiable regions which can be targeted for SOC restoration efforts.', '2026-07-07 23:03:49');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1483105054', 'climate-hydrology', 'The new assessment of soil loss by water erosion in Europe', 'Soil erosion by water is one of the major threats to soils in the European Union, with a negative impact on ecosystem services, crop production, drinking water and carbon stocks. The European…', '2015', 2015, 1300, 1300, 'https://ars.els-cdn.com/content/image/1-s2.0-S1462901115300654-gr1.jpg', 'https://doi.org/10.1016/j.envsci.2015.08.012', 'repository', 'article', 'Environmental Science & Policy', '["Panos Panagos","Pasquale Borrelli","Jean Poesen","Cristiano Ballabio","Emanuele Lugato","Katrin Meusburger","Luca Montanarella","Christine Alewell"]', 'climate & hydrology', 'Soil erosion by water is one of the major threats to soils in the European Union, with a negative impact on ecosystem services, crop production, drinking water and carbon stocks. The European Commission''s Soil Thematic Strategy has identified soil erosion as a relevant issue for the European Union, and has proposed an approach to monitor soil erosion. This paper presents the application of a modified version of the Revised Universal Soil Loss Equation (RUSLE) model (RUSLE2015) to estimate soil loss in Europe for the reference year 2010, within which the input factors (Rainfall erosivity, Soil erodibility, Cover-Management, Topography, Support practices) are modelled with the most recently available pan-European datasets. While RUSLE has been used before in Europe, RUSLE2015 improves the quality of estimation by introducing updated (2010), high-resolution (100 m), peer-reviewed input layers. The mean soil loss rate in the European Union''s erosion-prone lands (agricultural, forests and semi-natural areas) was found to be 2.46 t ha −1 yr −1, resulting in a total soil loss of 970 Mt annually. A major benefit of RUSLE2015 is that it can incorporate the effects of policy scenarios based on land-use changes and support practices. The impact of the Good Agricultural and Environmental Condition (GAEC) requirements of the Common Agricultural Policy (CAP) and the EU''s guidelines for soil protection can be grouped under land management (reduced/no till, plant residues, cover crops) and support practices (contour farming, maintenance of stone walls and grass margins). The policy interventions (GAEC, Soil Thematic Strategy) over the past decade have reduced the soil loss rate by 9.5% on average in Europe, and by 20% for arable lands. Special attention is given to the 4 million ha of croplands which currently have unsustainable soil loss rates of more than 5 t ha −1 yr −1, and to which policy measures should be targeted.', '2026-07-07 23:04:00');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2525409352', 'climate-hydrology', 'Large microplastic particles in sediments of tributaries of the River Thames, UK – Abundance, sources and methods for effective quantification', 'Large microplastic particles in sediments of tributaries of the River Thames, UK – Abundance, sources and methods for effective quantification', '2016', 2016, 951, 951, 'https://ars.els-cdn.com/content/image/1-s2.0-S0025326X16307251-fx1.jpg', 'https://pubmed.ncbi.nlm.nih.gov/27692488', 'repository', 'article', 'Marine Pollution Bulletin', '["Alice A. Horton","Claus Svendsen","Richard J. Williams","David J. Spurgeon","Elma Lahive"]', 'climate & hydrology', NULL, '2026-07-07 23:04:15');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2603766970', 'climate-hydrology', 'The CAMELS data set: catchment attributes and meteorology for large-sample studies', 'Abstract. We present a new data set of attributes for 671 catchments in the contiguous United States (CONUS) minimally impacted by human activities. This complements the daily time series of…', '2017', 2017, 888, 888, 'https://www.hydrology-and-earth-system-sciences.net/graphic_egu_claim_logo_blue.png', 'https://doi.org/10.5194/hess-21-5293-2017', 'repository', 'article', 'Hydrology and earth system sciences', '["Nans Addor","Andrew J. Newman","Naoki Mizukami","Martyn Clark"]', 'climate & hydrology', 'Abstract. We present a new data set of attributes for 671 catchments in the contiguous United States (CONUS) minimally impacted by human activities. This complements the daily time series of meteorological forcing and streamflow provided by Newman et al. (2015b). To produce this extension, we synthesized diverse and complementary data sets to describe six main classes of attributes at the catchment scale: topography, climate, streamflow, land cover, soil, and geology. The spatial variations among basins over the CONUS are discussed and compared using a series of maps. The large number of catchments, combined with the diversity of the attributes we extracted, makes this new data set well suited for large-sample studies and comparative hydrology. In comparison to the similar Model Parameter Estimation Experiment (MOPEX) data set, this data set relies on more recent data, it covers a wider range of attributes, and its catchments are more evenly distributed across the CONUS. This study also involves assessments of the limitations of the source data sets used to compute catchment attributes, as well as detailed descriptions of how the attributes were computed. The hydrometeorological time series provided by Newman et al. (2015b, https://doi.org/10.5065/D6MW2F4D) together with the catchment attributes introduced in this paper (https://doi.org/10.5065/D6G73C3Q) constitute the freely available CAMELS data set, which stands for Catchment Attributes and MEteorology for Large-sample Studies.', '2026-07-07 23:04:16');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W355622041', 'climate-hydrology', 'Estimating the soil erosion cover-management factor at the European scale', 'Land use and management influence the magnitude of soil loss. Among the different soil erosion risk factors, the cover-management factor (C-factor) is the one that policy makers and farmers can most…', '2015', 2015, 878, 878, 'https://ars.els-cdn.com/content/image/1-s2.0-S0264837715001611-gr1.jpg', 'https://doi.org/10.1016/j.landusepol.2015.05.021', 'repository', 'article', 'Land Use Policy', '["Panos Panagos","Pasquale Borrelli","Katrin Meusburger","Christine Alewell","Emanuele Lugato","Luca Montanarella"]', 'climate & hydrology', 'Land use and management influence the magnitude of soil loss. Among the different soil erosion risk factors, the cover-management factor (C-factor) is the one that policy makers and farmers can most readily influence in order to help reduce soil loss rates. The present study proposes a methodology for estimating the C-factor in the European Union (EU), using pan-European datasets (such as CORINE Land Cover), biophysical attributes derived from remote sensing, and statistical data on agricultural crops and practices. In arable lands, the C-factor was estimated using crop statistics (% of land per crop) and data on management practices such as conservation tillage, plant residues and winter crop cover. The C-factor in non-arable lands was estimated by weighting the range of literature values found according to fractional vegetation cover, which was estimated based on the remote sensing dataset Fcover. The mean C-factor in the EU is estimated to be 0.1043, with an extremely high variability; forests have the lowest mean C-factor (0.00116), and arable lands and sparsely vegetated areas the highest (0.233 and 0.2651, respectively). Conservation management practices (reduced/no tillage, use of cover crops and plant residues) reduce the C-factor by on average 19.1% in arable lands. The methodology is designed to be a tool for policy makers to assess the effect of future land use and crop rotation scenarios on soil erosion by water. The impact of land use changes (deforestation, arable land expansion) and the effect of policies (such as the Common Agricultural Policy and the push to grow more renewable energy crops) can potentially be quantified with the proposed model. The C-factor data and the statistical input data used are available from the European Soil Data Centre.', '2026-07-07 23:04:18');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2534439660', 'climate-hydrology', 'A new map of permafrost distribution on the Tibetan Plateau', 'Abstract. The Tibetan Plateau (TP) has the largest areas of permafrost terrain in the mid- and low-latitude regions of the world. Some permafrost distribution maps have been compiled but, due to…', '2017', 2017, 873, 873, 'https://www.the-cryosphere.net/graphic_egu_claim_logo_blue.png', 'https://doi.org/10.5194/tc-11-2527-2017', 'repository', 'article', 'The cryosphere', '["Defu Zou","Lin Zhao","Yu Sheng","Ji Chen","Guojie Hu","Tonghua Wu","Jichun Wu","Changwei Xie","Xiaodong Wu","Qiangqiang Pang","Wu Wang","Erji Du","Wangping Li","Guangyue Liu","Jing Li","Yanhui Qin","Yongping Qiao","Zhiwei Wang","Jianzong Shi","Guodong Cheng"]', 'climate & hydrology', 'Abstract. The Tibetan Plateau (TP) has the largest areas of permafrost terrain in the mid- and low-latitude regions of the world. Some permafrost distribution maps have been compiled but, due to limited data sources, ambiguous criteria, inadequate validation, and deficiency of high-quality spatial data sets, there is high uncertainty in the mapping of the permafrost distribution on the TP. We generated a new permafrost map based on freezing and thawing indices from modified Moderate Resolution Imaging Spectroradiometer (MODIS) land surface temperatures (LSTs) and validated this map using various ground-based data sets. The soil thermal properties of five soil types across the TP were estimated according to an empirical equation and soil properties (moisture content and bulk density). The temperature at the top of permafrost (TTOP) model was applied to simulate the permafrost distribution. Permafrost, seasonally frozen ground, and unfrozen ground covered areas of 1.06 × 106 km2 (0.97–1.15 × 106 km2, 90 % confidence interval) (40 %), 1.46 × 106 (56 %), and 0.03 × 106 km2 (1 %), respectively, excluding glaciers and lakes. Ground-based observations of the permafrost distribution across the five investigated regions (IRs, located in the transition zones of the permafrost and seasonally frozen ground) and three highway transects (across the entire permafrost regions from north to south) were used to validate the model. Validation results showed that the kappa coefficient varied from 0.38 to 0.78 with a mean of 0.57 for the five IRs and 0.62 to 0.74 with a mean of 0.68 within the three transects. Compared with earlier studies, the TTOP modelling results show greater accuracy. The results provide more detailed information on the permafrost distribution and basic data for use in future research on the Tibetan Plateau permafrost.', '2026-07-07 23:04:23');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2609686988', 'climate-hydrology', 'The 2010–2015 megadrought in central Chile: impacts on regional hydroclimate and vegetation', 'Abstract. Since 2010 an uninterrupted sequence of dry years, with annual rainfall deficits ranging from 25 to 45 %, has prevailed in central Chile (western South America, 30–38° S). Although intense…', '2017', 2017, 672, 672, 'https://www.hydrology-and-earth-system-sciences.net/graphic_egu_claim_logo_blue.png', 'https://doi.org/10.5194/hess-21-6307-2017', 'repository', 'article', 'Hydrology and earth system sciences', '["René Garreaud","Camila Álvarez-Garretón","Jonathan Barichivich","Juan Pablo Boisier","Duncan A. Christie","Mauricio Galleguillos","Carlos LeQuesne","James McPhee","Mauricio Zambrano‐Bigiarini"]', 'climate & hydrology', 'Abstract. Since 2010 an uninterrupted sequence of dry years, with annual rainfall deficits ranging from 25 to 45 %, has prevailed in central Chile (western South America, 30–38° S). Although intense 1- or 2-year droughts are recurrent in this Mediterranean-like region, the ongoing event stands out because of its longevity and large extent. The extraordinary character of the so-called central Chile megadrought (MD) was established against century long historical records and a millennial tree-ring reconstruction of regional precipitation. The largest MD-averaged rainfall relative anomalies occurred in the northern, semi-arid sector of central Chile, but the event was unprecedented to the south of 35° S. ENSO-neutral conditions have prevailed since 2011 (except for the strong El Niño in 2015), contrasting with La Niña conditions that often accompanied past droughts. The precipitation deficit diminished the Andean snowpack and resulted in amplified declines (up to 90 %) of river flow, reservoir volumes and groundwater levels along central Chile and westernmost Argentina. In some semi-arid basins we found a decrease in the runoff-to-rainfall coefficient. A substantial decrease in vegetation productivity occurred in the shrubland-dominated, northern sector, but a mix of greening and browning patches occurred farther south, where irrigated croplands and exotic forest plantations dominate. The ongoing warming in central Chile, making the MD one of the warmest 6-year periods on record, may have also contributed to such complex vegetation changes by increasing potential evapotranspiration. We also report some of the measures taken by the central government to relieve the MD effects and the public perception of this event. The understanding of the nature and biophysical impacts of the MD helps as a foundation for preparedness efforts to confront a dry, warm future regional climate scenario.', '2026-07-07 23:04:54');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2001317094', 'climate-hydrology', 'Development of a large-sample watershed-scale hydrometeorological data set for the contiguous USA: data set characteristics and assessment of regional variability in hydrologic model performance', 'Abstract. We present a community data set of daily forcing and hydrologic response data for 671 small- to medium-sized basins across the contiguous United States (median basin size of 336 km2) that…', '2015', 2015, 678, 678, 'https://www.hydrology-and-earth-system-sciences.net/graphic_egu_claim_logo_blue.png', 'https://doi.org/10.5194/hess-19-209-2015', 'repository', 'article', 'Hydrology and earth system sciences', '["Andrew J. Newman","Martyn Clark","K. M. Sampson","Andrew W. Wood","Lauren E. Hay","Andrew R. Bock","Roland J. Viger","D. L. Blodgett","L. D. Brekke","J. R. Arnold","T. M. Hopson","Qingyun Duan"]', 'climate & hydrology', 'Abstract. We present a community data set of daily forcing and hydrologic response data for 671 small- to medium-sized basins across the contiguous United States (median basin size of 336 km2) that spans a very wide range of hydroclimatic conditions. Area-averaged forcing data for the period 1980–2010 was generated for three basin spatial configurations – basin mean, hydrologic response units (HRUs) and elevation bands – by mapping daily, gridded meteorological data sets to the subbasin (Daymet) and basin polygons (Daymet, Maurer and NLDAS). Daily streamflow data was compiled from the United States Geological Survey National Water Information System. The focus of this paper is to (1) present the data set for community use and (2) provide a model performance benchmark using the coupled Snow-17 snow model and the Sacramento Soil Moisture Accounting Model, calibrated using the shuffled complex evolution global optimization routine. After optimization minimizing daily root mean squared error, 90% of the basins have Nash–Sutcliffe efficiency scores ≥0.55 for the calibration period and 34% ≥ 0.8. This benchmark provides a reference level of hydrologic model performance for a commonly used model and calibration system, and highlights some regional variations in model performance. For example, basins with a more pronounced seasonal cycle generally have a negative low flow bias, while basins with a smaller seasonal cycle have a positive low flow bias. Finally, we find that data points with extreme error (defined as individual days with a high fraction of total error) are more common in arid basins with limited snow and, for a given aridity, fewer extreme error days are present as the basin snow water equivalent increases.', '2026-07-07 23:04:55');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2303468042', 'climate-hydrology', 'An overview of current applications, challenges, and future trends in distributed process-based models in hydrology', 'An overview of current applications, challenges, and future trends in distributed process-based models in hydrology', '2016', 2016, 677, 677, 'https://ars.els-cdn.com/content/image/1-s2.0-S0022169416301317-gr1.jpg', 'https://doi.org/10.1016/j.jhydrol.2016.03.026', 'repository', 'article', 'Journal of Hydrology', '["Simone Fatichi","Enrique R. Vivoni","Fred L. Ogden","V. Y. Ivanov","Benjamin B. Mirus","David Gochis","Charles W. Downer","Matteo Camporese","Jason Davison","Brian A. Ebel","Norm Jones","Jongho Kim","Giuseppe Mascaro","Richard G. Niswonger","P. J. Restrepo","Riccardo Rigon","Chaopeng Shen","Mauro Sulis","David G. Tarboton"]', 'climate & hydrology', NULL, '2026-07-07 23:04:57');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1186112364', 'climate-hydrology', 'Assessment of flood hazard areas at a regional scale using an index-based approach and Analytical Hierarchy Process: Application in Rhodope–Evros region, Greece', 'The present study introduces a multi-criteria index to assess flood hazard areas in a regional scale. Accordingly, a Flood Hazard Index (FHI) has been defined and a spatial analysis in a GIS…', '2015', 2015, 637, 637, 'https://ars.els-cdn.com/content/image/1-s2.0-S0048969715305581-fx1.jpg', 'https://pubmed.ncbi.nlm.nih.gov/26318691', 'repository', 'article', 'The Science of The Total Environment', '["Nerantzis Kazakis","Ioannis Kougias","Thomas Patsialis"]', 'climate & hydrology', 'The present study introduces a multi-criteria index to assess flood hazard areas in a regional scale. Accordingly, a Flood Hazard Index (FHI) has been defined and a spatial analysis in a GIS environment has been applied for the estimation of its value. The developed methodology processes information of seven parameters namely flow accumulation, distance from the drainage network, elevation, land use, rainfall intensity and geology. The initials of these criteria gave the name to the developed method: "FIGUSED". The relative importance of each parameter for the occurrence and severity of flood has been connected to weight values. These values are calculated following an "Analytical Hierarchy Process", a method originally developed for the solution of Operational Research problems. According to their weight values, information of the different parameters is superimposed, resulting to flood hazard mapping. The accuracy of the method has been supported by a sensitivity analysis that examines a range for the weights'' values and corresponding to alternative scenarios. The presented methodology has been applied to an area in north-eastern Greece, where recurring flood events have appeared. Initially FIGUSED method resulted to a Flood Hazard Index (FHI) and a corresponding flood map. A sensitivity analysis on the parameters'' values revealed some interesting information on the relative importance of each criterion, presented and commented in the Discussion section. Moreover, the sensitivity analysis concluded to a revised index FHIS (methodology named FIGUSED-S) and flood mapping, supporting the robustness of FIGUSED methodology. A comparison of the outcome with records of historical flood events confirmed that the proposed methodology provides valid results.', '2026-07-07 23:05:06');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2772564114', 'climate-hydrology', 'PCR-GLOBWB 2: a 5 arcmin global hydrological and water resources model', 'Abstract. We present PCR-GLOBWB 2, a global hydrology and water resources model. Compared to previous versions of PCR-GLOBWB, this version fully integrates water use. Sector-specific water demand,…', '2018', 2018, 658, 658, 'https://www.geoscientific-model-development.net/graphic_egu_claim_logo_blue.png', 'https://doi.org/10.5194/gmd-11-2429-2018', 'repository', 'article', 'Geoscientific model development', '["Edwin H. Sutanudjaja","Rens van Beek","Niko Wanders","Yoshihide Wada","Joyce Bosmans","Niels Drost","Ruud van der Ent","Inge de Graaf","Jannis Hoch","Kor de Jong","Derek Karssenberg","Patricia López López","Stefanie Peßenteiner","Oliver Schmitz","Menno Straatsma","Ekkamol Vannametee","Dominik Wisser","Marc F. P. Bierkens"]', 'climate & hydrology', 'Abstract. We present PCR-GLOBWB 2, a global hydrology and water resources model. Compared to previous versions of PCR-GLOBWB, this version fully integrates water use. Sector-specific water demand, groundwater and surface water withdrawal, water consumption, and return flows are dynamically calculated at every time step and interact directly with the simulated hydrology. PCR-GLOBWB 2 has been fully rewritten in Python and PCRaster Python and has a modular structure, allowing easier replacement, maintenance, and development of model components. PCR-GLOBWB 2 has been implemented at 5 arcmin resolution, but a version parameterized at 30 arcmin resolution is also available. Both versions are available as open-source codes on https://github.com/UU-Hydro/PCR-GLOBWB_model (Sutanudjaja et al., 2017a). PCR-GLOBWB 2 has its own routines for groundwater dynamics and surface water routing. These relatively simple routines can alternatively be replaced by dynamically coupling PCR-GLOBWB 2 to a global two-layer groundwater model and 1-D–2-D hydrodynamic models. Here, we describe the main components of the model, compare results of the 30 and 5 arcmin versions, and evaluate their model performance using Global Runoff Data Centre discharge data. Results show that model performance of the 5 arcmin version is notably better than that of the 30 arcmin version. Furthermore, we compare simulated time series of total water storage (TWS) of the 5 arcmin model with those observed with GRACE, showing similar negative trends in areas of prevalent groundwater depletion. Also, we find that simulated total water withdrawal matches reasonably well with reported water withdrawal from AQUASTAT, while water withdrawal by source and sector provide mixed results.', '2026-07-07 23:05:08');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2149888331', 'climate-hydrology', 'Reviews and syntheses: Effects of permafrost thaw on Arctic aquatic ecosystems', 'Abstract. The Arctic is a water-rich region, with freshwater systems covering about 16 % of the northern permafrost landscape. Permafrost thaw creates new freshwater ecosystems, while at the same…', '2015', 2015, 601, 601, 'https://www.biogeosciences.net/graphic_egu_claim_logo_blue.png', 'https://doi.org/10.5194/bg-12-7129-2015', 'repository', 'article', 'Biogeosciences', '["Jorien E. Vonk","Suzanne E. Tank","William B. Bowden","Isabelle Laurion","Warwick F. Vincent","Pavel Alekseychik","Marc Amyot","M. F. Billet","João Canário","Rose M. Cory","Bethany Deshpande","Manuel Helbig","Mathilde Jammet","J. Karlsson","J. R. Larouche","Gwyneth A. MacMillan","Milla Rautio","Katey Walter Anthony","Kimberly P. Wickland"]', 'climate & hydrology', 'Abstract. The Arctic is a water-rich region, with freshwater systems covering about 16 % of the northern permafrost landscape. Permafrost thaw creates new freshwater ecosystems, while at the same time modifying the existing lakes, streams, and rivers that are impacted by thaw. Here, we describe the current state of knowledge regarding how permafrost thaw affects lentic (still) and lotic (moving) systems, exploring the effects of both thermokarst (thawing and collapse of ice-rich permafrost) and deepening of the active layer (the surface soil layer that thaws and refreezes each year). Within thermokarst, we further differentiate between the effects of thermokarst in lowland areas vs. that on hillslopes. For almost all of the processes that we explore, the effects of thaw vary regionally, and between lake and stream systems. Much of this regional variation is caused by differences in ground ice content, topography, soil type, and permafrost coverage. Together, these modifying factors determine (i) the degree to which permafrost thaw manifests as thermokarst, (ii) whether thermokarst leads to slumping or the formation of thermokarst lakes, and (iii) the manner in which constituent delivery to freshwater systems is altered by thaw. Differences in thaw-enabled constituent delivery can be considerable, with these modifying factors determining, for example, the balance between delivery of particulate vs. dissolved constituents, and inorganic vs. organic materials. Changes in the composition of thaw-impacted waters, coupled with changes in lake morphology, can strongly affect the physical and optical properties of thermokarst lakes. The ecology of thaw-impacted lakes and streams is also likely to change; these systems have unique microbiological communities, and show differences in respiration, primary production, and food web structure that are largely driven by differences in sediment, dissolved organic matter, and nutrient delivery. The degree to which thaw enables the delivery of dissolved vs. particulate organic matter, coupled with the composition of that organic matter and the morphology and stratification characteristics of recipient systems will play an important role in determining the balance between the release of organic matter as greenhouse gases (CO2 and CH4), its burial in sediments, and its loss downstream. The magnitude of thaw impacts on northern aquatic ecosystems is increasing, as is the prevalence of thaw-impacted lakes and streams. There is therefore an urgent need to quantify how permafrost thaw is affecting aquatic ecosystems across diverse Arctic landscapes, and the implications of this change for further climate warming.', '2026-07-07 23:05:26');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2190221061', 'climate-hydrology', 'From meteorological to hydrological drought using standardised indicators', 'Abstract. Drought monitoring and early warning (M &amp;amp; EW) systems are a crucial component of drought preparedness. M &amp;amp; EW systems typically make use of drought indicators such as the…', '2016', 2016, 581, 581, 'https://www.hydrology-and-earth-system-sciences.net/graphic_egu_claim_logo_blue.png', 'https://doi.org/10.5194/hess-20-2483-2016', 'repository', 'article', 'Hydrology and earth system sciences', '["Lucy Barker","Jamie Hannaford","Andrew Chiverton","Cecilia Svensson"]', 'climate & hydrology', 'Abstract. Drought monitoring and early warning (M &amp;amp; EW) systems are a crucial component of drought preparedness. M &amp;amp; EW systems typically make use of drought indicators such as the Standardised Precipitation Index (SPI), but such indicators are not widely used in the UK. More generally, such tools have not been well developed for hydrological (i.e. streamflow) drought. To fill these research gaps, this paper characterises meteorological and hydrological droughts, and the propagation from one to the other, using the SPI and the related Standardised Streamflow Index (SSI), with the objective of improving understanding of the drought hazard in the UK. SPI and SSI time series were calculated for 121 near-natural catchments in the UK for accumulation periods of 1–24 months. From these time series, drought events were identified and for each event, the duration and severity were calculated. The relationship between meteorological and hydrological drought was examined by cross-correlating the 1-month SSI with various SPI accumulation periods. Finally, the influence of climate and catchment properties on the hydrological drought characteristics and propagation was investigated. Results showed that at short accumulation periods meteorological drought characteristics showed little spatial variability, whilst hydrological drought characteristics showed fewer but longer and more severe droughts in the south and east than in the north and west of the UK. Propagation characteristics showed a similar spatial pattern with catchments underlain by productive aquifers, mostly in the south and east, having longer SPI accumulation periods strongly correlated with the 1-month SSI. For catchments in the north and west of the UK, which typically have little catchment storage, standard-period average annual rainfall was strongly correlated with hydrological drought and propagation characteristics. However, in the south and east, catchment properties describing storage (such as base flow index, the percentage of highly productive fractured rock and typical soil wetness) were more influential on hydrological drought characteristics. This knowledge forms a basis for more informed application of standardised indicators in the UK in the future, which could aid in the development of improved M &amp;amp; EW systems. Given the lack of studies applying standardised indicators to hydrological droughts, and the diversity of catchment types encompassed here, the findings could prove valuable for enhancing the hydrological aspects of drought M &amp;amp; EW systems in both the UK and elsewhere.', '2026-07-07 23:05:37');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2788043166', 'climate-hydrology', 'A review of the (Revised) Universal Soil Loss Equation ((R)USLE): with a view to increasing its global applicability and improving soil loss estimates', 'Abstract. Soil erosion is a major problem around the world because of its effects on soil productivity, nutrient loss, siltation in water bodies, and degradation of water quality. By understanding…', '2018', 2018, 540, 540, 'https://www.hydrology-and-earth-system-sciences.net/graphic_egu_claim_logo_blue.png', 'https://doi.org/10.5194/hess-22-6059-2018', 'repository', 'review', 'Hydrology and earth system sciences', '["Rubianca Benavidez","Bethanna Jackson","Deborah Maxwell","Kevin Norton"]', 'climate & hydrology', 'Abstract. Soil erosion is a major problem around the world because of its effects on soil productivity, nutrient loss, siltation in water bodies, and degradation of water quality. By understanding the driving forces behind soil erosion, we can more easily identify erosion-prone areas within a landscape to address the problem strategically. Soil erosion models have been used to assist in this task. One of the most commonly used soil erosion models is the Universal Soil Loss Equation (USLE) and its family of models: the Revised Universal Soil Loss Equation (RUSLE), the Revised Universal Soil Loss Equation version 2 (RUSLE2), and the Modified Universal Soil Loss Equation (MUSLE). This paper reviews the different sub-factors of USLE and RUSLE, and analyses how different studies around the world have adapted the equations to local conditions. We compiled these studies and equations to serve as a reference for other researchers working with (R)USLE and related approaches. Within each sub-factor section, the strengths and limitations of the different equations are discussed, and guidance is given as to which equations may be most appropriate for particular climate types, spatial resolution, and temporal scale. We investigate some of the limitations of existing (R)USLE formulations, such as uncertainty issues given the simple empirical nature of the model and many of its sub-components; uncertainty issues around data availability; and its inability to account for soil loss from gully erosion, mass wasting events, or predicting potential sediment yields to streams. Recommendations on how to overcome some of the uncertainties associated with the model are given. Several key future directions to refine it are outlined: e.g. incorporating soil loss from other types of soil erosion, estimating soil loss at sub-annual temporal scales, and compiling consistent units for the future literature to reduce confusion and errors caused by mismatching units. The potential of combining (R)USLE with the Compound Topographic Index (CTI) and sediment delivery ratio (SDR) to account for gully erosion and sediment yield to streams respectively is discussed. Overall, the aim of this paper is to review the (R)USLE and its sub-factors, and to elucidate the caveats, limitations, and recommendations for future applications of these soil erosion models. We hope these recommendations will help researchers more robustly apply (R)USLE in a range of geoclimatic regions with varying data availability, and modelling different land cover scenarios at finer spatial and temporal scales (e.g. at the field scale with different cropping options).', '2026-07-07 23:05:51');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2276915090', 'climate-hydrology', 'Global riverine N and P transport to ocean increased during the 20th century despite increased retention along the aquatic continuum', 'Abstract. Various human activities – including agriculture, water consumption, river damming, and aquaculture – have intensified over the last century. This has had a major impact on nitrogen (N) and…', '2016', 2016, 549, 549, 'https://www.biogeosciences.net/graphic_egu_claim_logo_blue.png', 'https://doi.org/10.5194/bg-13-2441-2016', 'repository', 'article', 'Biogeosciences', '["Arthur Beusen","Lex Bouwman","Rens van Beek","José M. Mogollón","Jack J. Middelburg"]', 'climate & hydrology', 'Abstract. Various human activities – including agriculture, water consumption, river damming, and aquaculture – have intensified over the last century. This has had a major impact on nitrogen (N) and phosphorus (P) cycling in global continental waters. In this study, we use a coupled nutrient-input–hydrology–in-stream nutrient retention model to quantitatively track the changes in the global freshwater N and P cycles over the 20th century. Our results suggest that, during this period, the global nutrient delivery to streams increased from 34 to 64 Tg N yr−1 and from 5 to 9 Tg P yr−1. Furthermore, in-stream retention and removal grew from 14 to 27 Tg N yr−1 and 3 to 5 Tg P yr−1. One of the major causes of increased retention is the growing number of reservoirs, which now account for 24 and 22 % of global N and P retention/removal in freshwater systems, respectively. This increase in nutrient retention could not balance the increase in nutrient delivery to rivers with the consequence that river nutrient transport to the ocean increased from 19 to 37 Tg N yr−1 and from 2 to 4 Tg P yr−1. Human activities have also led to a global increase in the molar N: P ratio in freshwater bodies.', '2026-07-07 23:05:51');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2237118555', 'climate-hydrology', 'Mapping topsoil physical properties at European scale using the LUCAS database', 'The Land Use and Cover Area frame Statistical survey (LUCAS) aimed at the collecting harmonized data about the state of land use/cover over the extent of European Union (EU). Among these 2•105 land…', '2015', 2015, 542, 542, 'https://ars.els-cdn.com/content/image/1-s2.0-S0016706115300173-gr1.jpg', 'https://doi.org/10.1016/j.geoderma.2015.07.006', 'repository', 'article', 'Geoderma', '["Cristiano Ballabio","Panos Panagos","Luca Monatanarella"]', 'climate & hydrology', 'The Land Use and Cover Area frame Statistical survey (LUCAS) aimed at the collecting harmonized data about the state of land use/cover over the extent of European Union (EU). Among these 2•105 land use/cover observations selected for validation, a topsoil survey was conducted at about 10% of these sites. Topsoil sampling locations were selected as to be representative of European landscape using a latin hypercube stratified random sampling, taking into account CORINE land cover 2000, the Shuttle Radar Topography Mission (SRTM) DEM and its derived slope, aspect and curvature.\nIn this study we will discuss how the LUCAS topsoil database can be used to map soil properties at continental scale over the geographical extent of Europe. Several soil properties were predicted using hybrid approaches like regression kriging. In this paper we describe the prediction of topsoil texture and related derived physical properties. Regression models were fitted using, along other variables, remotely sensed data coming from the MODIS sensor. The high temporal resolution of MODIS allowed detecting changes in the vegetative response due to soil properties, which can then be used to map soil features distribution. We will also discuss the prediction of intrinsically collinear variables like soil texture which required the use of models capable of dealing with multivariate constrained dependent variables like Multivariate Adaptive Regression Splines (MARS).\nCross validation of the fitted models proved that the LUCAS dataset constitutes a good sample for mapping puropses leading to cross-validation R2 between 0.47 and 0.50 for soil texture and normalised errors between 4 and 10%.', '2026-07-07 23:05:54');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2788379540', 'climate-hydrology', 'The CAMELS-CL dataset: catchment attributes and meteorology for large sample studies – Chile dataset', 'Abstract. We introduce the first catchment dataset for large sample studies in Chile. This dataset includes 516 catchments; it covers particularly wide latitude (17.8 to 55.0∘ S) and elevation (0 to…', '2018', 2018, 505, 505, 'https://www.hydrology-and-earth-system-sciences.net/graphic_egu_claim_logo_blue.png', 'https://doi.org/10.5194/hess-22-5817-2018', 'repository', 'article', 'Hydrology and earth system sciences', '["Camila Álvarez-Garretón","Pablo A. Mendoza","Juan Pablo Boisier","Nans Addor","Mauricio Galleguillos","Mauricio Zambrano‐Bigiarini","Antonio Lara","Cristóbal Puelma","G. Cortés","René Garreaud","James McPhee","Ãlvaro Ayala"]', 'climate & hydrology', 'Abstract. We introduce the first catchment dataset for large sample studies in Chile. This dataset includes 516 catchments; it covers particularly wide latitude (17.8 to 55.0∘ S) and elevation (0 to 6993 m a.s.l.) ranges, and it relies on multiple data sources (including ground data, remote-sensed products and reanalyses) to characterise the hydroclimatic conditions and landscape of a region where in situ measurements are scarce. For each catchment, the dataset provides boundaries, daily streamflow records and basin-averaged daily time series of precipitation (from one national and three global datasets), maximum, minimum and mean temperatures, potential evapotranspiration (PET; from two datasets), and snow water equivalent. We calculated hydro-climatological indices using these time series, and leveraged diverse data sources to extract topographic, geological and land cover features. Relying on publicly available reservoirs and water rights data for the country, we estimated the degree of anthropic intervention within the catchments. To facilitate the use of this dataset and promote common standards in large sample studies, we computed most catchment attributes introduced by Addor et al. (2017) in their Catchment Attributes and MEteorology for Large-sample Studies (CAMELS) dataset, and added several others. We used the dataset presented here (named CAMELS-CL) to characterise regional variations in hydroclimatic conditions over Chile and to explore how basin behaviour is influenced by catchment attributes and water extractions. Further, CAMELS-CL enabled us to analyse biases and uncertainties in basin-wide precipitation and PET. The characterisation of catchment water balances revealed large discrepancies between precipitation products in arid regions and a systematic precipitation underestimation in headwater mountain catchments (high elevations and steep slopes) over humid regions. We evaluated PET products based on ground data and found a fairly good performance of both products in humid regions (r&gt;0.91) and lower correlation (r&lt;0.76) in hyper-arid regions. Further, the satellite-based PET showed a consistent overestimation of observation-based PET. Finally, we explored local anomalies in catchment response by analysing the relationship between hydrological signatures and an attribute characterising the level of anthropic interventions. We showed that larger anthropic interventions are correlated with lower than normal annual flows, runoff ratios, elasticity of runoff with respect to precipitation, and flashiness of runoff, especially in arid catchments. CAMELS-CL provides unprecedented information on catchments in a region largely underrepresented in large sample studies. This effort is part of an international initiative to create multi-national large sample datasets freely available for the community. CAMELS-CL can be visualised from http://camels.cr2.cl and downloaded from https://doi.pangaea.de/10.1594/PANGAEA.894885.', '2026-07-07 23:06:08');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2144990831', 'climate-hydrology', 'A global data set of the extent of irrigated land from 1900 to 2005', 'Abstract. Irrigation intensifies land use by increasing crop yield but also impacts water resources. It affects water and energy balances and consequently the microclimate in irrigated regions.…', '2015', 2015, 498, 498, 'https://www.hydrology-and-earth-system-sciences.net/graphic_egu_claim_logo_blue.png', 'https://doi.org/10.5194/hess-19-1521-2015', 'repository', 'article', 'Hydrology and earth system sciences', '["Stefan Siebert","Matti Kummu","Miina Porkka","Petra Döll","Navin Ramankutty","Bridget R. Scanlon"]', 'climate & hydrology', 'Abstract. Irrigation intensifies land use by increasing crop yield but also impacts water resources. It affects water and energy balances and consequently the microclimate in irrigated regions. Therefore, knowledge of the extent of irrigated land is important for hydrological and crop modelling, global change research, and assessments of resource use and management. Information on the historical evolution of irrigated lands is limited. The new global historical irrigation data set (HID) provides estimates of the temporal development of the area equipped for irrigation (AEI) between 1900 and 2005 at 5 arcmin resolution. We collected sub-national irrigation statistics from various sources and found that the global extent of AEI increased from 63 million ha (Mha) in 1900 to 111 Mha in 1950 and 306 Mha in 2005. We developed eight gridded versions of time series of AEI by combining sub-national irrigation statistics with different data sets on the historical extent of cropland and pasture. Different rules were applied to maximize consistency of the gridded products to sub-national irrigation statistics or to historical cropland and pasture data sets. The HID reflects very well the spatial patterns of irrigated land as shown on historical maps for the western United States (around year 1900) and on a global map (around year 1960). Mean aridity on irrigated land increased and mean natural river discharge on irrigated land decreased from 1900 to 1950 whereas aridity decreased and river discharge remained approximately constant from 1950 to 2005. The data set and its documentation are made available in an open-data repository at https://mygeohub.org/publications/8 (doi:10.13019/M20599).', '2026-07-07 23:06:19');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3049214693', 'climate-hydrology', 'The global water resources and use model WaterGAP v2.2d: model description and evaluation', 'Abstract. WaterGAP is a global hydrological model that quantifies human use of groundwater and surface water as well as water flows and water storage and thus water resources on all land areas of the…', '2021', 2021, 480, 480, 'https://www.geoscientific-model-development.net/graphic_egu_claim_logo_blue.png', 'https://doi.org/10.5194/gmd-14-1037-2021', 'repository', 'article', 'Geoscientific model development', '["Hannes Müller Schmied","Denise Cáceres","Stephanie Eisner","Martina Flörke","Claudia Herbert","Christoph Niemann","Thedini Asali Peiris","Eklavyya Popat","F. T. Portmann","Robert Reinecke","Maike Schumacher","Somayeh Shadkam","Camelia-Eliza Telteu","Tim Trautmann","Petra Döll"]', 'climate & hydrology', 'Abstract. WaterGAP is a global hydrological model that quantifies human use of groundwater and surface water as well as water flows and water storage and thus water resources on all land areas of the Earth. Since 1996, it has served to assess water resources and water stress both historically and in the future, in particular under climate change. It has improved our understanding of continental water storage variations, with a focus on overexploitation and depletion of water resources. In this paper, we describe the most recent model version WaterGAP 2.2d, including the water use models, the linking model that computes net abstractions from groundwater and surface water and the WaterGAP Global Hydrology Model (WGHM). Standard model output variables that are freely available at a data repository are explained. In addition, the most requested model outputs, total water storage anomalies, streamflow and water use, are evaluated against observation data. Finally, we show examples of assessments of the global freshwater system that can be achieved with WaterGAP 2.2d model output.', '2026-07-07 23:06:26');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2346877152', 'climate-hydrology', 'Development and evaluation of a framework for global flood hazard mapping', 'Nowadays, the development of high-resolution flood hazard models have become feasible at continental and global scale, and their application in developing countries and data-scarce regions can be…', '2016', 2016, 484, 484, 'https://ars.els-cdn.com/content/image/1-s2.0-S0309170816301257-gr1.jpg', 'https://doi.org/10.1016/j.advwatres.2016.05.002', 'repository', 'article', 'Advances in Water Resources', '["Francesco Dottori","Peter Salamon","Alessandra Bianchi","Lorenzo Alfieri","Feyera A. Hirpa","Luc Feyen"]', 'climate & hydrology', 'Nowadays, the development of high-resolution flood hazard models have become feasible at continental and global scale, and their application in developing countries and data-scarce regions can be extremely helpful to increase preparedness of population and reduce catastrophic impacts.\nThe present work describes the development of a novel procedure for global flood hazard mapping, based on the most recent advances in large scale flood modelling. We derive a long-term dataset of daily river discharges from the global hydrological simulations of the Global Flood Awareness System (GloFAS). Streamflow data is downscaled on a high resolution river network and processed to provide the input for local flood inundation simulations, performed with a two-dimensional hydrodynamic model. All flood-prone areas identified along the river network are then merged to create continental flood hazard maps for different return periods at 30’’ resolution. We evaluate the performance of our methodology in several large river basins by comparing simulated flood maps with a mosaic of flooded areas detected from satellite images for the same reference period. We further investigate the sensitivity of the flood modelling framework to different parameters and modelling approaches and identify strengths, limitations and possible improvements of the methodology.', '2026-07-07 23:06:28');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1996838292', 'climate-hydrology', 'Global distribution of soil organic carbon – Part 1: Masses and frequency distributions of SOC stocks for the tropics, permafrost regions, wetlands, and the world', 'Abstract. The global soil organic carbon (SOC) mass is relevant for the carbon cycle budget and thus atmospheric carbon concentrations. We review current estimates of SOC stocks and mass (stock ×…', '2015', 2015, 472, 472, 'https://www.soil-journal.net/graphic_egu_claim_logo_blue.png', 'https://doi.org/10.5194/soil-1-351-2015', 'repository', 'article', 'SOIL', '["Martin Köchy","Roland Hiederer","Annette Freibauer"]', 'climate & hydrology', 'Abstract. The global soil organic carbon (SOC) mass is relevant for the carbon cycle budget and thus atmospheric carbon concentrations. We review current estimates of SOC stocks and mass (stock × area) in wetlands, permafrost and tropical regions and the world in the upper 1 m of soil. The Harmonized World Soil Database (HWSD) v.1.2 provides one of the most recent and coherent global data sets of SOC, giving a total mass of 2476 Pg when using the original values for bulk density. Adjusting the HWSD''s bulk density (BD) of soil high in organic carbon results in a mass of 1230 Pg, and additionally setting the BD of Histosols to 0.1 g cm−3 (typical of peat soils), results in a mass of 1062 Pg. The uncertainty in BD of Histosols alone introduces a range of −56 to +180 Pg C into the estimate of global SOC mass in the top 1 m, larger than estimates of global soil respiration. We report the spatial distribution of SOC stocks per 0.5 arcminutes; the areal masses of SOC; and the quantiles of SOC stocks by continents, wetland types, and permafrost types. Depending on the definition of "wetland", wetland soils contain between 82 and 158 Pg SOC. With more detailed estimates for permafrost from the Northern Circumpolar Soil Carbon Database (496 Pg SOC) and tropical peatland carbon incorporated, global soils contain 1325 Pg SOC in the upper 1 m, including 421 Pg in tropical soils, whereof 40 Pg occurs in tropical wetlands. Global SOC amounts to just under 3000 Pg when estimates for deeper soil layers are included. Variability in estimates is due to variation in definitions of soil units, differences in soil property databases, scarcity of information about soil carbon at depths &gt; 1 m in peatlands, and variation in definitions of "peatland".', '2026-07-07 23:06:37');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2587446396', 'climate-hydrology', 'The future of Earth observation in hydrology', 'In just the past five years, the field of Earth observation has progressed beyond the offerings of conventional space agency based platforms to include a plethora of sensing opportunities afforded by…', '2017', 2017, 471, 471, 'https://www.hydrology-and-earth-system-sciences.net/graphic_egu_claim_logo_blue.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6140349', 'pmc', 'article', 'Hydrology and earth system sciences', '["Matthew F. McCabe","Matthew Rodell","Douglas Alsdorf","Diego G. Miralles","R. Uijlenhoet","Wolfgang Wagner","Arko Lucieer","Rasmus Houborg","Niko E. C. Verhoest","Trenton E. Franz","Jiancheng Shi","Huilin Gao","Eric F. Wood"]', 'climate & hydrology', 'In just the past five years, the field of Earth observation has progressed beyond the offerings of conventional space agency based platforms to include a plethora of sensing opportunities afforded by CubeSats, Unmanned Aerial Vehicles (UAVs), and smartphone technologies that are being embraced by both for-profit companies and individual researchers. Over the previous decades, space agency efforts have brought forth well-known and immensely useful satellites such as the Landsat series and the Gravity Research and Climate Experiment (GRACE) system, with costs typically on the order of one billion dollars per satellite and with concept-to-launch timelines on the order of two decades (for new missions). More recently, the proliferation of smartphones has helped to miniaturise sensors and energy requirements, facilitating advances in the use of CubeSats that can be launched by the dozens, while providing ultra-high (3-5 m) resolution sensing of the Earth on a daily basis. Start-up companies that did not exist five years ago now operate more satellites in orbit than any space agency, and at costs that are a mere fraction of the cost of traditional satellite missions. With these advances come new space-borne measurements, such as real-time high-definition video for tracking air pollution, storm-cell development, flood propagation, precipitation monitoring, or even for constructing digital surfaces using structure-from-motion techniques. Closer to the surface, measurements from small unmanned drones and tethered balloons have mapped snow depths, floods, and estimated evaporation at sub-meter resolutions, pushing back on spatio-temporal constraints and delivering new process insights. At ground level, precipitation has been measured using signal attenuation between antennae mounted on cell phone towers, while the proliferation of mobile devices has enabled citizen-scientists to catalogue photos of environmental conditions, estimate daily average temperatures from battery state, and sense other hydrologically important variables such as channel depths using commercially available wireless devices. Global internet access is being pursued via high altitude balloons, solar planes, and hundreds of planned satellite launches, providing a means to exploit the Internet of Things as an entirely new measurement domain. Such global access will enable real-time collection of data from billions of smartphones or from remote research platforms. This future will produce petabytes of data that can only be accessed via cloud storage and will require new analytical approaches to interpret. The extent to which today''s hydrologic models can usefully ingest such massive data volumes is unclear. Nor is it clear whether this deluge of data will be usefully exploited, either because the measurements are superfluous, inconsistent, not accurate enough, or simply because we lack the capacity to process and analyse them. What is apparent is that the tools and techniques afforded by this array of novel and game-changing sensing platforms present our community with a unique opportunity to develop new insights that advance fundamental aspects of the hydrological sciences. To accomplish this will require more than just an application of the technology: in some cases, it will demand a radical rethink on how we utilise and exploit these new observing systems to enhance our understanding of the Earth and its linked processes.', '2026-07-07 23:06:37');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2100236613', 'climate-hydrology', 'Quantifying atmospheric nitrogen deposition through a nationwide monitoring network across China', 'Abstract. A Nationwide Nitrogen Deposition Monitoring Network (NNDMN) containing 43 monitoring sites was established in China to measure gaseous NH3, NO2, and HNO3 and particulate NH4+ and NO3− in…', '2015', 2015, 458, 458, 'https://www.atmospheric-chemistry-and-physics.net/graphic_egu_claim_logo_blue.png', 'https://doi.org/10.5194/acp-15-12345-2015', 'repository', 'article', 'Atmospheric chemistry and physics', '["Wen Xu","Xiaojin Luo","Yuepeng Pan","Lin Zhang","Aohan Tang","Jianlin Shen","Y. Zhang","K. H. Li","Qinghua Wu","Daxin Yang","Yangyang Zhang","Jian Xue","Wanjin Li","Qiao‐Qiao Li","Linling Tang","Shihua Lu","Tian Liang","Yanan Tong","Ping Liu","Q. Zhang","Zhengqin Xiong","X. J. Shi","Liang‐Cai Wu","Wenhong Shi","Kun Tian","Xiaojian Zhong","Kun� Shi","Qi Tang","L. J. Zhang","Jianliang Huang","C. E. He","Fuhong Kuang","Bingqi Zhu","H. Liu","X. Jin","Yue Xin","Xuefeng Shi","Enzai Du","Anthony J. Dore","Sim Tang","Jeffrey L. Collett","K. W. T. Goulding","Yixiang Sun","Jianhong Ren","Fusuo Zhang","X. J. Liu"]', 'climate & hydrology', 'Abstract. A Nationwide Nitrogen Deposition Monitoring Network (NNDMN) containing 43 monitoring sites was established in China to measure gaseous NH3, NO2, and HNO3 and particulate NH4+ and NO3− in air and/or precipitation from 2010 to 2014. Wet/bulk deposition fluxes of Nr species were collected by precipitation gauge method and measured by continuous-flow analyzer; dry deposition fluxes were estimated using airborne concentration measurements and inferential models. Our observations reveal large spatial variations of atmospheric Nr concentrations and dry and wet/bulk Nr deposition. On a national basis, the annual average concentrations (1.3–47.0 μg N m−3) and dry plus wet/bulk deposition fluxes (2.9–83.3 kg N ha−1 yr−1) of inorganic Nr species are ranked by land use as urban &gt; rural &gt; background sites and by regions as north China &gt; southeast China &gt; southwest China &gt; northeast China &gt; northwest China &gt; Tibetan Plateau, reflecting the impact of anthropogenic Nr emission. Average dry and wet/bulk N deposition fluxes were 20.6 ± 11.2 (mean ± standard deviation) and 19.3 ± 9.2 kg N ha−1 yr−1 across China, with reduced N deposition dominating both dry and wet/bulk deposition. Our results suggest atmospheric dry N deposition is equally important to wet/bulk N deposition at the national scale. Therefore, both deposition forms should be included when considering the impacts of N deposition on environment and ecosystem health.', '2026-07-07 23:06:50');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2565128291', 'climate-hydrology', 'A global review on hydrological responses to forest change across multiple spatial scales: Importance of scale, climate, forest type and hydrological regime', 'A global review on hydrological responses to forest change across multiple spatial scales: Importance of scale, climate, forest type and hydrological regime', '2016', 2016, 458, 458, 'https://ars.els-cdn.com/content/image/1-s2.0-S0022169416308307-gr1.jpg', 'https://doi.org/10.1016/j.jhydrol.2016.12.040', 'repository', 'review', 'Journal of Hydrology', '["Mingfang Zhang","Ning Liu","R.J. Harper","Qiang Li","Kuan Liu","Xiaohua Wei","Dingyuan Ning","Yiping Hou","Shirong Liu"]', 'climate & hydrology', NULL, '2026-07-07 23:06:52');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3134876352', 'climate-hydrology', 'The International Soil Moisture Network: serving Earth system science for over a decade', 'Abstract. In 2009, the International Soil Moisture Network (ISMN) was initiated as a community effort, funded by the European Space Agency, to serve as a centralised data hosting facility for…', '2021', 2021, 447, 447, 'https://www.hydrology-and-earth-system-sciences.net/graphic_egu_claim_logo_blue.png', 'https://meteofrance.hal.science/meteo-03478163', 'repository', 'article', 'Hydrology and earth system sciences', '["Wouter Dorigo","Irene Himmelbauer","Daniel Aberer","Lukas Schremmer","Ivana Petrakovic","Luca Zappa","Wolfgang Preimesberger","Angelika Xaver","Frank Annor","Jonas Ardö","Dennis Baldocchi","Marco Bitelli","Günter Blöschl","Heye Bogena","Luca Brocca","Jean‐Christophe Calvet","J. Julio Camarero","Giorgio Capello","Minha Choi","Michael C. Cosh","Nick van de Giesen","Istvan Hajdu","Jaakko Ikonen","Karsten H. Jensen","Kasturi Devi Kanniah","Ileen de Kat","Gottfried Kirchengast","Pankaj Kumar","Jenni Kyrouac","Kristine M. Larson","Suxia Liu","Alexander Loew","Mahta Moghaddam","José Martínez‐Fernández","Cristian Mattar Bader","Renato Morbidelli","Jan Musiał","Elise Osenga","Michael A. Palecki","Thierry Pellarin","George P. Petropoulos","Isabella Pfeil","Jarrett Powers","Alan Robock","Christoph Rüdiger","U. Rummel","Michael Ströbel","Zhongbo Su","Ryan C. Sullivan","Torbern Tagesson","Andrej Varlagin","Mariëtte Vreugdenhil","Jeffrey P. Walker","Jun Wen","Fred Wenger","Jean‐Pierre Wigneron","Mel Woods","Kun Yang","Yijian Zeng","Xiang Zhang","Marek Zreda","Stephan Dietrich","Alexander Gruber","P.J. van Oevelen","Wolfgang Wagner","Klaus Scipal","Matthias Drusch","Roberto Sabia"]', 'climate & hydrology', 'Abstract. In 2009, the International Soil Moisture Network (ISMN) was initiated as a community effort, funded by the European Space Agency, to serve as a centralised data hosting facility for globally available in situ soil moisture measurements (Dorigo et al., 2011b, a). The ISMN brings together in situ soil moisture measurements collected and freely shared by a multitude of organisations, harmonises them in terms of units and sampling rates, applies advanced quality control, and stores them in a database. Users can freely retrieve the data from this database through an online web portal (https://ismn.earth/en/, last access: 28 October 2021). Meanwhile, the ISMN has evolved into the primary in situ soil moisture reference database worldwide, as evidenced by more than 3000 active users and over 1000 scientific publications referencing the data sets provided by the network. As of July 2021, the ISMN now contains the data of 71 networks and 2842 stations located all over the globe, with a time period spanning from 1952 to the present. The number of networks and stations covered by the ISMN is still growing, and approximately 70 % of the data sets contained in the database continue to be updated on a regular or irregular basis. The main scope of this paper is to inform readers about the evolution of the ISMN over the past decade, including a description of network and data set updates and quality control procedures. A comprehensive review of the existing literature making use of ISMN data is also provided in order to identify current limitations in functionality and data usage and to shape priorities for the next decade of operations of this unique community-based data repository.', '2026-07-07 23:07:04');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2748742102', 'climate-hydrology', 'The Value of Coastal Wetlands for Flood Damage Reduction in the Northeastern USA', 'As exposure to coastal hazards increases there is growing interest in nature-based solutions for risk reduction. This study uses high-resolution flood and loss models to quantify the impacts of…', '2017', 2017, 434, 434, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41598-017-09269-z/MediaObjects/41598_2017_9269_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5579246', 'pmc', 'article', 'Scientific Reports', '["Siddharth Narayan","Michael W. Beck","Paul Wilson","Christopher Thomas","Alexandra Guerrero","Christine C. Shepard","Borja G. Reguero","Guillermo Franco","Jane Carter Ingram","Dania Trespalacios"]', 'climate & hydrology', 'As exposure to coastal hazards increases there is growing interest in nature-based solutions for risk reduction. This study uses high-resolution flood and loss models to quantify the impacts of coastal wetlands in the northeastern USA on (i) regional flood damages by Hurricane Sandy and (ii) local annual flood losses in Barnegat Bay in Ocean County, New Jersey. Using an extensive database of property exposure, the regional study shows that wetlands avoided $625 Million in direct flood damages during Hurricane Sandy. The local study combines these models with a database of synthetic storms in Ocean County and estimates a 16% average reduction in annual flood losses by salt marshes with higher reductions at lower elevations. Together, the studies quantify the risk reduction ecosystem services of marsh wetlands. Measuring these benefits in collaboration with the risk modelling industry is crucial for assessing risk accurately and, where appropriate, aligning conservation and risk reduction goals.', '2026-07-07 23:07:16');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2143629408', 'climate-hydrology', 'Global pattern for the effect of climate and land cover on water yield', 'Research results on the effects of land cover change on water resources vary greatly and the topic remains controversial. Here we use published data worldwide to examine the validity of Fuh''s…', '2015', 2015, 437, 437, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fncomms6918/MediaObjects/41467_2015_Article_BFncomms6918_Fig1_HTML.jpg', 'https://pubmed.ncbi.nlm.nih.gov/25574930', 'repository', 'article', 'Nature Communications', '["Guoyi Zhou","Xiaohua Wei","Xiuzhi Chen","Ping Zhou","Xiaodong Liu","Xiao Yin","Ge Sun","David F. Scott","Shu‐Yi‐Dan Zhou","Liusheng Han","Yongxian Su"]', 'climate & hydrology', 'Research results on the effects of land cover change on water resources vary greatly and the topic remains controversial. Here we use published data worldwide to examine the validity of Fuh''s equation, which relates annual water yield (R) to a wetness index (precipitation/potential evapotranspiration; P/PET) and watershed characteristics (m). We identify two critical values at P/PET=1 and m=2. m plays a more important role than P/PET when m 2. When P/PET 1, suggesting that any land cover changes in non-humid regions (P/PET<1) or in watersheds of low water retention capacity (m<2) can lead to greater hydrological responses. m significantly correlates with forest coverage, watershed slope and watershed area. This global pattern has far-reaching significance in studying and managing hydrological responses to land cover and climate changes.', '2026-07-07 23:07:16');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2403208941', 'climate-hydrology', 'Organic carbon decomposition rates controlled by water retention time across inland waters', 'Organic carbon decomposition rates controlled by water retention time across inland waters', '2016', 2016, 439, 439, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fngeo2720/MediaObjects/41561_2016_Article_BFngeo2720_Fig1_HTML.jpg', 'https://doi.org/10.1038/ngeo2720', 'repository', 'article', 'Nature Geoscience', '["Núria Catalán","Rafael Marcé","Dolly N. Kothawala","Lars J. Tranvik"]', 'climate & hydrology', NULL, '2026-07-07 23:07:17');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2555442175', 'climate-hydrology', 'Climate Change Impacts on the Upper Indus Hydrology: Sources, Shifts and Extremes', 'The Indus basin heavily depends on its upstream mountainous part for the downstream supply of water while downstream demands are high. Since downstream demands will likely continue to increase,…', '2016', 2016, 428, 428, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0165630.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5102348', 'pmc', 'article', 'PLoS ONE', '["Arthur Lutz","Walter W. Immerzeel","Philip Kraaijenbrink","A. B. Shrestha","Marc F. P. Bierkens"]', 'climate & hydrology', 'The Indus basin heavily depends on its upstream mountainous part for the downstream supply of water while downstream demands are high. Since downstream demands will likely continue to increase, accurate hydrological projections for the future supply are important. We use an ensemble of statistically downscaled CMIP5 General Circulation Model outputs for RCP4.5 and RCP8.5 to force a cryospheric-hydrological model and generate transient hydrological projections for the entire 21st century for the upper Indus basin. Three methodological advances are introduced: (i) A new precipitation dataset that corrects for the underestimation of high-altitude precipitation is used. (ii) The model is calibrated using data on river runoff, snow cover and geodetic glacier mass balance. (iii) An advanced statistical downscaling technique is used that accounts for changes in precipitation extremes. The analysis of the results focuses on changes in sources of runoff, seasonality and hydrological extremes. We conclude that the future of the upper Indus basin''s water availability is highly uncertain in the long run, mainly due to the large spread in the future precipitation projections. Despite large uncertainties in the future climate and long-term water availability, basin-wide patterns and trends of seasonal shifts in water availability are consistent across climate change scenarios. Most prominent is the attenuation of the annual hydrograph and shift from summer peak flow towards the other seasons for most ensemble members. In addition there are distinct spatial patterns in the response that relate to monsoon influence and the importance of meltwater. Analysis of future hydrological extremes reveals that increases in intensity and frequency of extreme discharges are very likely for most of the upper Indus basin and most ensemble members.', '2026-07-07 23:07:30');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2898656436', 'climate-hydrology', 'Remarkable agrivoltaic influence on soil moisture, micrometeorology and water-use efficiency', 'Power demands are set to increase by two-fold within the current century and a high fraction of that demand should be met by carbon free sources. Among the renewable energies, solar energy is among…', '2018', 2018, 425, 425, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0203256.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6211631', 'pmc', 'article', 'PLoS ONE', '["Elnaz Hassanpour Adeh","J. S. Selker","Chad W. Higgins"]', 'climate & hydrology', 'Power demands are set to increase by two-fold within the current century and a high fraction of that demand should be met by carbon free sources. Among the renewable energies, solar energy is among the fastest growing; therefore, a comprehensive and accurate design methodology for solar systems and how they interact with the local environment is vital. This paper addresses the environmental effects of solar panels on an unirrigated pasture that often experiences water stress. Changes to the microclimatology, soil moisture, water usage, and biomass productivity due to the presence of solar panels were quantified. The goal of this study was to show that the impacts of these factors should be considered in designing the solar farms to take advantage of potential net gains in agricultural and power production. Microclimatological stations were placed in the Rabbit Hills agrivoltaic solar arrays, located in Oregon State campus, two years after the solar array was installed. Soil moisture was quantified using neutron probe readings. Significant differences in mean air temperature, relative humidity, wind speed, wind direction, and soil moisture were observed. Areas under PV solar panels maintained higher soil moisture throughout the period of observation. A significant increase in late season biomass was also observed for areas under the PV panels (90% more biomass), and areas under PV panels were significantly more water efficient (328% more efficient).', '2026-07-07 23:07:30');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2414369363', 'climate-hydrology', 'Maps of heavy metals in the soils of the European Union and proposed priority areas for detailed assessment', 'Soil contamination is one of the greatest concerns among the threats to soil resources in Europe and globally. Despite of its importance there was only very course scale (1/5000km(2)) data available…', '2016', 2016, 427, 427, 'https://ars.els-cdn.com/content/image/1-s2.0-S0048969716310452-fx1.jpg', 'https://pubmed.ncbi.nlm.nih.gov/27261421', 'repository', 'article', 'The Science of The Total Environment', '["Gergely Tóth","Tamás Hermann","Gábor Szatmári","László Pásztor"]', 'climate & hydrology', 'Soil contamination is one of the greatest concerns among the threats to soil resources in Europe and globally. Despite of its importance there was only very course scale (1/5000km(2)) data available on soil heavy metal concentrations prior to the LUCAS topsoil survey, which had a sampling density of 200km(2). Based on the results of the LUCAS sampling and auxiliary information detailed and up-to-date maps of heavy metals (As, Cd, Cr, Cu, Hg, Pb, Zn, Sb, Co and Ni) in the topsoil of the European Union were produced. Using the maps of heavy metal concentration in topsoil we made a spatial prediction of areas where local assessment is suggested to monitor and eventually control the potential threat from heavy metals. Most of the examined elements remain under the corresponding threshold values in the majority of the land of the EU. However, one or more of the elements exceed the applied threshold concentration on 1.2Mkm(2), which is 28.3% of the total surface area of the EU. While natural backgrounds might be the reason for high concentrations on large proportion of the affected soils, historical and recent industrial and mining areas show elevated concentrations (predominantly of As, Cd, Pb and Hg) too, indicating the magnitude of anthropogenic effect on soil quality in Europe.', '2026-07-07 23:07:33');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2115026348', 'climate-hydrology', 'Water savings potentials of irrigation systems: global simulation of processes and linkages', 'Abstract. Global agricultural production is heavily sustained by irrigation, but irrigation system efficiencies are often surprisingly low. However, our knowledge of irrigation efficiencies is mostly…', '2015', 2015, 421, 421, 'https://www.hydrology-and-earth-system-sciences.net/graphic_egu_claim_logo_blue.png', 'https://doi.org/10.5194/hess-19-3073-2015', 'repository', 'article', 'Hydrology and earth system sciences', '["Jonas Jägermeyr","Dieter Gerten","Jens Heinke","S. Schaphoff","Matti Kummu","Wolfgang Lucht"]', 'climate & hydrology', 'Abstract. Global agricultural production is heavily sustained by irrigation, but irrigation system efficiencies are often surprisingly low. However, our knowledge of irrigation efficiencies is mostly confined to rough indicative estimates for countries or regions that do not account for spatiotemporal heterogeneity due to climate and other biophysical dependencies. To allow for refined estimates of global agricultural water use, and of water saving and water productivity potentials constrained by biophysical processes and also non-trivial downstream effects, we incorporated a process-based representation of the three major irrigation systems (surface, sprinkler, and drip) into a bio- and agrosphere model, LPJmL. Based on this enhanced model we provide a gridded world map of irrigation efficiencies that are calculated in direct linkage to differences in system types, crop types, climatic and hydrologic conditions, and overall crop management. We find pronounced regional patterns in beneficial irrigation efficiency (a refined irrigation efficiency indicator accounting for crop-productive water consumption only), due to differences in these features, with the lowest values (&lt; 30 %) in south Asia and sub-Saharan Africa and the highest values (&gt; 60 %) in Europe and North America. We arrive at an estimate of global irrigation water withdrawal of 2469 km3 (2004–2009 average); irrigation water consumption is calculated to be 1257 km3, of which 608 km3 are non-beneficially consumed, i.e., lost through evaporation, interception, and conveyance. Replacing surface systems by sprinkler or drip systems could, on average across the world''s river basins, reduce the non-beneficial consumption at river basin level by 54 and 76 %, respectively, while maintaining the current level of crop yields. Accordingly, crop water productivity would increase by 9 and 15 %, respectively, and by much more in specific regions such as in the Indus basin. This study significantly advances the global quantification of irrigation systems while providing a framework for assessing potential future transitions in these systems. In this paper, presented opportunities associated with irrigation improvements are significant and suggest that they should be considered an important means on the way to sustainable food security.', '2026-07-07 23:07:45');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2982434552', 'climate-hydrology', 'Coping with salinity in irrigated agriculture: Crop evapotranspiration and water management issues', 'Coping with salinity in irrigated agriculture: Crop evapotranspiration and water management issues', '2019', 2019, 412, 412, 'https://ars.els-cdn.com/content/image/1-s2.0-S0378377419309151-fx1.jpg', 'https://doi.org/10.1016/j.agwat.2019.105832', 'repository', 'article', 'Agricultural Water Management', '["P.S. Minhas","Tiago B. Ramos","Alon Ben‐Gal","L. S. Pereira"]', 'climate & hydrology', NULL, '2026-07-07 23:07:45');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2233740707', 'climate-hydrology', 'The immediate effectiveness of barley straw mulch in reducing soil erodibility and surface runoff generation in Mediterranean vineyards', 'The immediate effectiveness of barley straw mulch in reducing soil erodibility and surface runoff generation in Mediterranean vineyards', '2016', 2016, 423, 423, 'https://ars.els-cdn.com/content/image/1-s2.0-S0048969715312328-fx1.jpg', 'https://pubmed.ncbi.nlm.nih.gov/26789370', 'repository', 'article', 'The Science of The Total Environment', '["Massimo Prosdocimi","António Jordán","Paolo Tarolli","Saskia Keesstra","Agata Novara","Artemi Cerdà"]', 'climate & hydrology', NULL, '2026-07-07 23:07:45');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1860446517', 'climate-hydrology', 'Reconciling high-altitude precipitation in the upper Indus basin with glacier mass balances and runoff', 'Abstract. Mountain ranges in Asia are important water suppliers, especially if downstream climates are arid, water demands are high and glaciers are abundant. In such basins, the hydrological cycle…', '2015', 2015, 409, 409, 'https://www.hydrology-and-earth-system-sciences.net/graphic_egu_claim_logo_blue.png', 'https://doi.org/10.5194/hess-19-4673-2015', 'repository', 'article', 'Hydrology and earth system sciences', '["Walter W. Immerzeel","Niko Wanders","Arthur Lutz","J. M. Shea","Marc F. P. Bierkens"]', 'climate & hydrology', 'Abstract. Mountain ranges in Asia are important water suppliers, especially if downstream climates are arid, water demands are high and glaciers are abundant. In such basins, the hydrological cycle depends heavily on high-altitude precipitation. Yet direct observations of high-altitude precipitation are lacking and satellite derived products are of insufficient resolution and quality to capture spatial variation and magnitude of mountain precipitation. Here we use glacier mass balances to inversely infer the high-altitude precipitation in the upper Indus basin and show that the amount of precipitation required to sustain the observed mass balances of large glacier systems is far beyond what is observed at valley stations or estimated by gridded precipitation products. An independent validation with observed river flow confirms that the water balance can indeed only be closed when the high-altitude precipitation on average is more than twice as high and in extreme cases up to a factor of 10 higher than previously thought. We conclude that these findings alter the present understanding of high-altitude hydrology and will have an important bearing on climate change impact studies, planning and design of hydropower plants and irrigation reservoirs as well as the regional geopolitical situation in general.', '2026-07-07 23:07:58');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2020869916', 'climate-hydrology', 'A high-resolution simulation of groundwater and surface water over most of the continental US with the integrated hydrologic model ParFlow v3', 'Abstract. Interactions between surface and groundwater systems are well-established theoretically and observationally. While numerical models that solve both surface and subsurface flow equations in…', '2015', 2015, 399, 399, 'https://www.geoscientific-model-development.net/graphic_egu_claim_logo_blue.png', 'https://doi.org/10.5194/gmd-8-923-2015', 'repository', 'article', 'Geoscientific model development', '["R. M. Maxwell","Laura E. Condon","Stefan Kollet"]', 'climate & hydrology', 'Abstract. Interactions between surface and groundwater systems are well-established theoretically and observationally. While numerical models that solve both surface and subsurface flow equations in a single framework (matrix) are increasingly being applied, computational limitations have restricted their use to local and regional studies. Regional or watershed-scale simulations have been effective tools for understanding hydrologic processes; however, there are still many questions, such as the adaptation of water resources to anthropogenic stressors and climate variability, that can only be answered across large spatial extents at high resolution. In response to this grand challenge in hydrology, we present the results of a parallel, integrated hydrologic model simulating surface and subsurface flow at high spatial resolution (1 km) over much of continental North America (~ 6.3 M km2). These simulations provide integrated predictions of hydrologic states and fluxes, namely, water table depth and streamflow, at very large scale and high resolution. The physics-based modeling approach used here requires limited parameterizations and relies only on more fundamental inputs such as topography, hydrogeologic properties and climate forcing. Results are compared to observations and provide mechanistic insight into hydrologic process interaction. This study demonstrates both the feasibility of continental-scale integrated models and their utility for improving our understanding of large-scale hydrologic systems; the combination of high resolution and large spatial extent facilitates analysis of scaling relationships using model outputs.', '2026-07-07 23:07:59');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W251816126', 'climate-hydrology', 'A review of water scarcity and drought indexes in water resources planning and management', 'A review of water scarcity and drought indexes in water resources planning and management', '2015', 2015, 395, 395, 'https://ars.els-cdn.com/content/image/1-s2.0-S0022169415003388-fx1.jpg', 'https://doi.org/10.1016/j.jhydrol.2015.05.003', 'repository', 'review', 'Journal of Hydrology', '["María Pedro-Monzonís","Abel Solera","Javier Ferrer","Teodoro Estrela","Javier Paredes-Arquiola"]', 'climate & hydrology', NULL, '2026-07-07 23:08:13');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1996985044', 'climate-hydrology', 'Aggregation in environmental systems – Part 1: Seasonal tracer cycles quantify young water fractions, but not mean transit times, in spatially heterogeneous catchments', 'Abstract. Environmental heterogeneity is ubiquitous, but environmental systems are often analyzed as if they were homogeneous instead, resulting in aggregation errors that are rarely explored and…', '2016', 2016, 389, 389, 'https://www.hydrology-and-earth-system-sciences.net/graphic_egu_claim_logo_blue.png', 'https://doi.org/10.5194/hess-20-279-2016', 'repository', 'article', 'Hydrology and earth system sciences', '["James W. Kirchner"]', 'climate & hydrology', 'Abstract. Environmental heterogeneity is ubiquitous, but environmental systems are often analyzed as if they were homogeneous instead, resulting in aggregation errors that are rarely explored and almost never quantified. Here I use simple benchmark tests to explore this general problem in one specific context: the use of seasonal cycles in chemical or isotopic tracers (such as Cl−, δ18O, or δ2H) to estimate timescales of storage in catchments. Timescales of catchment storage are typically quantified by the mean transit time, meaning the average time that elapses between parcels of water entering as precipitation and leaving again as streamflow. Longer mean transit times imply greater damping of seasonal tracer cycles. Thus, the amplitudes of tracer cycles in precipitation and streamflow are commonly used to calculate catchment mean transit times. Here I show that these calculations will typically be wrong by several hundred percent, when applied to catchments with realistic degrees of spatial heterogeneity. This aggregation bias arises from the strong nonlinearity in the relationship between tracer cycle amplitude and mean travel time. I propose an alternative storage metric, the young water fraction in streamflow, defined as the fraction of runoff with transit times of less than roughly 0.2 years. I show that this young water fraction (not to be confused with event-based "new water" in hydrograph separations) is accurately predicted by seasonal tracer cycles within a precision of a few percent, across the entire range of mean transit times from almost zero to almost infinity. Importantly, this relationship is also virtually free from aggregation error. That is, seasonal tracer cycles also accurately predict the young water fraction in runoff from highly heterogeneous mixtures of subcatchments with strongly contrasting transit-time distributions. Thus, although tracer cycle amplitudes yield biased and unreliable estimates of catchment mean travel times in heterogeneous catchments, they can be used to reliably estimate the fraction of young water in runoff.', '2026-07-07 23:08:26');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2125443063', 'climate-hydrology', 'Modelling the effect of support practices (P-factor) on the reduction of soil erosion by water at European scale', 'The USLE/RUSLE support practice factor (P-factor) is rarely taken into account in soil erosion risk modelling at sub-continental scale, as it is difficult to estimate for large areas. This study…', '2015', 2015, 388, 388, 'https://ars.els-cdn.com/content/image/1-s2.0-S1462901115000611-gr1.jpg', 'https://doi.org/10.1016/j.envsci.2015.03.012', 'repository', 'article', 'Environmental Science & Policy', '["Panos Panagos","Pasquale Borrelli","Katrin Meusburger","Emma H. van der Zanden","Jean Poesen","Christine Alewell"]', 'climate & hydrology', 'The USLE/RUSLE support practice factor (P-factor) is rarely taken into account in soil erosion risk modelling at sub-continental scale, as it is difficult to estimate for large areas. This study attempts to model the P-factor in the European Union. For this, it considers the latest policy developments in the Common Agricultural Policy, and applies the rules set by Member States for contour farming over a certain slope. The impact of stone walls and grass margins is also modelled using the more than 226,000 observations from the Land use/cover area frame statistical survey (LUCAS) carried out in 2012 in the European Union. The mean P-factor considering contour farming, stone walls and grass margins in the European Union is estimated at 0.9702. The support practices accounted for in the P-factor reduce the risk of soil erosion by 3%, with grass margins having the largest impact (57% of the total erosion risk reduction) followed by stone walls (38%). Contour farming contributes very little to the P-factor given its limited application; it is only used as a support practice in eight countries and only on very steep slopes. Support practices have the highest impact in Malta, Portugal, Spain, Italy, Greece, Belgium, The Netherlands and United Kingdom where they reduce soil erosion risk by at least 5%. The P-factor modelling tool can potentially be used by policy makers to run soil-erosion risk scenarios for a wider application of contour farming in areas with slope gradients less than 10%, maintaining stone walls and increasing the number of grass margins under the forthcoming reform of the Common Agricultural Policy.', '2026-07-07 23:08:30');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2512312809', 'climate-hydrology', 'Mulching practices for reducing soil water erosion: A review', 'Mulching practices for reducing soil water erosion: A review', '2016', 2016, 376, 376, 'https://ars.els-cdn.com/content/image/1-s2.0-S0012825216302264-gr1.jpg', 'https://doi.org/10.1016/j.earscirev.2016.08.006', 'repository', 'review', 'Earth-Science Reviews', '["Massimo Prosdocimi","Paolo Tarolli","Artemi Cerdà"]', 'climate & hydrology', NULL, '2026-07-07 23:09:03');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2080468149', 'climate-hydrology', 'Soil erosion in the humid tropics: A systematic quantitative review', 'Healthy soils provide a wide range of ecosystem services. But soil erosion (one component of land degradation) jeopardizes the sustainable delivery of these services worldwide, and particularly in…', '2015', 2015, 375, 375, 'https://ars.els-cdn.com/content/image/1-s2.0-S0167880915000468-gr1.jpg', 'https://hal.science/cirad-01117271', 'repository', 'article', 'Agriculture Ecosystems & Environment', '["Nicolas Labrière","Bruno Locatelli","Yves Laumonier","Vincent Freycon","Martial Bernoux"]', 'climate & hydrology', 'Healthy soils provide a wide range of ecosystem services. But soil erosion (one component of land degradation) jeopardizes the sustainable delivery of these services worldwide, and particularly in the humid tropics where erosion potential is high due to heavy rainfall. The Millennium Ecosystem Assessment pointed out the role of poor land-use and management choices in increasing land degradation. We hypothesized that land use has a limited influence on soil erosion provided vegetation cover is developed enough or good management practices are implemented. We systematically reviewed the literature to study how soil and vegetation management influence soil erosion control in the humid tropics. More than 3600 measurements of soil loss from 55 references covering 21 countries were compiled. Quantitative analysis of the collected data revealed that soil erosion in the humid tropics is dramatically concentrated in space (over landscape elements of bare soil) and time (e.g. during crop rotation). No land use is erosion-prone per se, but creation of bare soil elements in the landscape through particular land uses and other human activities (e.g. skid trails and logging roads) should be avoided as much as possible. Implementation of sound practices of soil and vegetation management (e.g. contour planting, no-till farming and use of vegetative buffer strips) can reduce erosion by up to 99%. With limited financial and technical means, natural resource managers and policy makers can therefore help decrease soil loss at a large scale by promoting wise management of highly erosion-prone landscape elements and enhancing the use of low-erosion-inducing practices.', '2026-07-07 23:09:03');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2788952672', 'climate-hydrology', 'Climate warming over the past half century has led to thermal degradation of permafrost on the Qinghai–Tibet Plateau', 'Abstract. Air temperature increases thermally degrade permafrost, which has widespread impacts on engineering design, resource development, and environmental protection in cold regions. This study…', '2018', 2018, 375, 375, 'https://www.the-cryosphere.net/graphic_egu_claim_logo_blue.png', 'https://doi.org/10.5194/tc-12-595-2018', 'repository', 'article', 'The cryosphere', '["Youhua Ran","Xin Li","Guodong Cheng"]', 'climate & hydrology', 'Abstract. Air temperature increases thermally degrade permafrost, which has widespread impacts on engineering design, resource development, and environmental protection in cold regions. This study evaluates the potential thermal degradation of permafrost over the Qinghai–Tibet Plateau (QTP) from the 1960s to the 2000s using estimated decadal mean annual air temperatures (MAATs) by integrating remote-sensing-based estimates of mean annual land surface temperatures (MASTs), leaf area index (LAI) and fractional snow cover values, and decadal mean MAAT date from 152 weather stations with a geographically weighted regression (GWR). The results reflect a continuous rise of approximately 0.04 ∘C a−1 in the decadal mean MAAT values over the past half century. A thermal-condition classification matrix is used to convert modelled MAATs to permafrost thermal type. Results show that the climate warming has led to a thermal degradation of permafrost in the past half century. The total area of thermally degraded permafrost is approximately 153.76×104 km2, which corresponds to 88 % of the permafrost area in the 1960s. The thermal condition of 75.2 % of the very cold permafrost, 89.6 % of the cold permafrost, 90.3 % of the cool permafrost, 92.3 % of the warm permafrost, and 32.8 % of the very warm permafrost has been degraded to lower levels of thermal condition. Approximately 49.4 % of the very warm permafrost and 96 % of the likely thawing permafrost has degraded to seasonally frozen ground. The mean elevations of the very cold, cold, cool, warm, very warm, and likely thawing permafrost areas increased by 88, 97, 155, 185, 161, and 250 m, respectively. The degradation mainly occurred from the 1960s to the 1970s and from the 1990s to the 2000s. This degradation may lead to increased risks to infrastructure, reductions in ecosystem resilience, increased flood risks, and positive climate feedback effects. It therefore affects the well-being of millions of people and sustainable development at the Third Pole.', '2026-07-07 23:09:14');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2624779099', 'climate-hydrology', 'A global hydrological simulation to specify the sources of water used by humans', 'Abstract. Humans abstract water from various sources to sustain their livelihood and society. Some global hydrological models (GHMs) include explicit schemes of human water abstraction, but the…', '2018', 2018, 361, 361, 'https://www.hydrology-and-earth-system-sciences.net/graphic_egu_claim_logo_blue.png', 'https://doi.org/10.5194/hess-22-789-2018', 'repository', 'article', 'Hydrology and earth system sciences', '["Naota Hanasaki","Sayaka Yoshikawa","Yadu Pokhrel","Shinjiro Kanae"]', 'climate & hydrology', 'Abstract. Humans abstract water from various sources to sustain their livelihood and society. Some global hydrological models (GHMs) include explicit schemes of human water abstraction, but the representation and performance of these schemes remain limited. We substantially enhanced the water abstraction schemes of the H08 GHM. This enabled us to estimate water abstraction from six major water sources, namely, river flow regulated by global reservoirs (i.e., reservoirs regulating the flow of the world''s major rivers), aqueduct water transfer, local reservoirs, seawater desalination, renewable groundwater, and nonrenewable groundwater. In its standard setup, the model covers the whole globe at a spatial resolution of 0.5° × 0.5°, and the calculation interval is 1 day. All the interactions were simulated in a single computer program, and all water fluxes and storage were strictly traceable at any place and time during the simulation period. A global hydrological simulation was conducted to validate the performance of the model for the period of 1979–2013 (land use was fixed for the year 2000). The simulated water fluxes for water abstraction were validated against those reported in earlier publications and showed a reasonable agreement at the global and country level. The simulated monthly river discharge and terrestrial water storage (TWS) for six of the world''s most significantly human-affected river basins were compared with gauge observations and the data derived from the Gravity Recovery and Climate Experiment (GRACE) satellite mission. It is found that the simulation including the newly added schemes outperformed the simulation without human activities. The simulated results indicated that, in 2000, of the 3628±75 km3 yr−1 global freshwater requirement, 2839±50 km3 yr−1 was taken from surface water and 789±30 km3 yr−1 from groundwater. Streamflow, aqueduct water transfer, local reservoirs, and seawater desalination accounted for 1786±23, 199±10, 106±5, and 1.8±0 km3 yr−1 of the surface water, respectively. The remaining 747±45 km3 yr−1 freshwater requirement was unmet, or surface water was not available when and where it was needed in our simulation. Renewable and nonrenewable groundwater accounted for 607±11 and 182±26 km3 yr−1 of the groundwater total, respectively. Each source differed in its renewability, economic costs for development, and environmental consequences of usage. The model is useful for performing global water resource assessments by considering the aspects of sustainability, economy, and environment.', '2026-07-07 23:09:33');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2532304287', 'climate-hydrology', 'Spatial and temporal variability of rainfall and their effects on hydrological response in urban areas – a review', 'Abstract. In urban areas, hydrological processes are characterized by high variability in space and time, making them sensitive to small-scale temporal and spatial rainfall variability. In the last…', '2017', 2017, 363, 363, 'https://www.hydrology-and-earth-system-sciences.net/graphic_egu_claim_logo_blue.png', 'https://doi.org/10.5194/hess-21-3859-2017', 'repository', 'review', 'Hydrology and earth system sciences', '["Elena Cristiano","Marie‐Claire ten Veldhuis","Nick van de Giesen"]', 'climate & hydrology', 'Abstract. In urban areas, hydrological processes are characterized by high variability in space and time, making them sensitive to small-scale temporal and spatial rainfall variability. In the last decades new instruments, techniques, and methods have been developed to capture rainfall and hydrological processes at high resolution. Weather radars have been introduced to estimate high spatial and temporal rainfall variability. At the same time, new models have been proposed to reproduce hydrological response, based on small-scale representation of urban catchment spatial variability. Despite these efforts, interactions between rainfall variability, catchment heterogeneity, and hydrological response remain poorly understood. This paper presents a review of our current understanding of hydrological processes in urban environments as reported in the literature, focusing on their spatial and temporal variability aspects. We review recent findings on the effects of rainfall variability on hydrological response and identify gaps where knowledge needs to be further developed to improve our understanding of and capability to predict urban hydrological response.', '2026-07-07 23:09:33');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2800027363', 'climate-hydrology', 'Estimating the impacts of land use/land cover changes on Ecosystem Service Values: The case of the Andassa watershed in the Upper Blue Nile basin of Ethiopia', 'Estimating the impacts of land use/land cover changes on Ecosystem Service Values: The case of the Andassa watershed in the Upper Blue Nile basin of Ethiopia', '2018', 2018, 362, 362, 'https://ars.els-cdn.com/content/image/1-s2.0-S2212041617306769-gr1.jpg', 'https://doi.org/10.1016/j.ecoser.2018.05.001', 'repository', 'article', 'Ecosystem Services', '["Temesgen Gashaw","Taffa Tulu","Mekuria Argaw","Abeyou W. Worqlul","Terefe Tolessa","Mengistie Kindu"]', 'climate & hydrology', NULL, '2026-07-07 23:09:35');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2610828627', 'climate-hydrology', 'Reviews and syntheses: Isotopic approaches to quantify root water uptake: a review and comparison of methods', 'Abstract. Plant root water uptake (RWU) has been documented for the past five decades from water stable isotopic analysis. By comparing the (hydrogen or oxygen) stable isotopic compositions of plant…', '2017', 2017, 357, 357, 'https://www.biogeosciences.net/graphic_egu_claim_logo_blue.png', 'https://doi.org/10.5194/bg-14-2199-2017', 'repository', 'review', 'Biogeosciences', '["Youri Rothfuss","Mathieu Javaux"]', 'climate & hydrology', 'Abstract. Plant root water uptake (RWU) has been documented for the past five decades from water stable isotopic analysis. By comparing the (hydrogen or oxygen) stable isotopic compositions of plant xylem water to those of potential contributive water sources (e.g., water from different soil layers, groundwater, water from recent precipitation or from a nearby stream), studies were able to determine the relative contributions of these water sources to RWU. In this paper, the different methods used for locating/quantifying relative contributions of water sources to RWU (i.e., graphical inference, statistical (e.g., Bayesian) multi-source linear mixing models) are reviewed with emphasis on their respective advantages and drawbacks. The graphical and statistical methods are tested against a physically based analytical RWU model during a series of virtual experiments differing in the depth of the groundwater table, the soil surface water status, and the plant transpiration rate value. The benchmarking of these methods illustrates the limitations of the graphical and statistical methods while it underlines the performance of one Bayesian mixing model. The simplest two-end-member mixing model is also successfully tested when all possible sources in the soil can be identified to define the two end-members and compute their isotopic compositions. Finally, the authors call for a development of approaches coupling physically based RWU models with controlled condition experimental setups.', '2026-07-07 23:09:50');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2282783886', 'climate-hydrology', 'Are oxygen limitations under recognized regulators of organic carbon turnover in upland soils?', 'Are oxygen limitations under recognized regulators of organic carbon turnover in upland soils?', '2016', 2016, 358, 358, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1007%2Fs00374-018-1317-2/MediaObjects/374_2018_1317_Fig1_HTML.png', 'https://doi.org/10.1007/s10533-015-0180-6', 'repository', 'article', 'Biogeochemistry', '["Marco Keiluweit","Peter Nico","Markus Kleber","Scott Fendorf"]', 'climate & hydrology', NULL, '2026-07-07 23:09:51');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2969713210', 'climate-hydrology', 'Evaluation of global terrestrial evapotranspiration using state-of-the-art approaches in remote sensing, machine learning and land surface modeling', 'Abstract. Evapotranspiration (ET) is critical in linking global water, carbon and energy cycles. However, direct measurement of global terrestrial ET is not feasible. Here, we first reviewed the…', '2020', 2020, 351, 351, 'https://www.hydrology-and-earth-system-sciences.net/graphic_egu_claim_logo_blue.png', 'https://hal.science/hal-02532761', 'repository', 'article', 'Hydrology and earth system sciences', '["Shufen Pan","Naiqing Pan","Hanqin Tian","Pierre Friedlingstein","Stephen Sitch","Hao Shi","Vivek K. Arora","Vanessa Haverd","Atul K. Jain","Etsushi Kato","Sebastian Lienert","Danica Lombardozzi","Julia E. M. S. Nabel","Catherine Ottlé","Benjamin Poulter","Sönke Zaehle","Steven W. Running"]', 'climate & hydrology', 'Abstract. Evapotranspiration (ET) is critical in linking global water, carbon and energy cycles. However, direct measurement of global terrestrial ET is not feasible. Here, we first reviewed the basic theory and state-of-the-art approaches for estimating global terrestrial ET, including remote-sensing-based physical models, machine-learning algorithms and land surface models (LSMs). We then utilized 4 remote-sensing-based physical models, 2 machine-learning algorithms and 14 LSMs to analyze the spatial and temporal variations in global terrestrial ET. The results showed that the ensemble means of annual global terrestrial ET estimated by these three categories of approaches agreed well, with values ranging from 589.6 mm yr−1 (6.56×104 km3 yr−1) to 617.1 mm yr−1 (6.87×104 km3 yr−1). For the period from 1982 to 2011, both the ensembles of remote-sensing-based physical models and machine-learning algorithms suggested increasing trends in global terrestrial ET (0.62 mm yr−2 with a significance level of p&lt;0.05 and 0.38 mm yr−2 with a significance level of p&lt;0.05, respectively). In contrast, the ensemble mean of the LSMs showed no statistically significant change (0.23 mm yr−2, p&gt;0.05), although many of the individual LSMs reproduced an increasing trend. Nevertheless, all 20 models used in this study showed that anthropogenic Earth greening had a positive role in increasing terrestrial ET. The concurrent small interannual variability, i.e., relative stability, found in all estimates of global terrestrial ET, suggests that a potential planetary boundary exists in regulating global terrestrial ET, with the value of this boundary being around 600 mm yr−1. Uncertainties among approaches were identified in specific regions, particularly in the Amazon Basin and arid/semiarid regions. Improvements in parameterizing water stress and canopy dynamics, the utilization of new available satellite retrievals and deep-learning methods, and model–data fusion will advance our predictive understanding of global terrestrial ET.', '2026-07-07 23:10:07');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2611498547', 'climate-hydrology', 'Human–water interface in hydrological modelling: current status and future directions', 'Abstract. Over recent decades, the global population has been rapidly increasing and human activities have altered terrestrial water fluxes to an unprecedented extent. The phenomenal growth of the…', '2017', 2017, 351, 351, 'https://www.hydrology-and-earth-system-sciences.net/graphic_egu_claim_logo_blue.png', 'https://doi.org/10.5194/hess-21-4169-2017', 'repository', 'article', 'Hydrology and earth system sciences', '["Yoshihide Wada","Marc F. P. Bierkens","Ad de Roo","Paul A. Dirmeyer","J. S. Famiglietti","Naota Hanasaki","Megan Konar","Junguo Liu","Hannes Müller Schmied","Taikan Oki","Yadu Pokhrel","Murugesu Sivapalan","Tara J. Troy","Albert I. J. M. van Dijk","Tim van Emmerik","M.H.J. van Huijgevoort","H.A.J. van Lanen","Charles J Vörösmarty","Niko Wanders","H. S. Wheater"]', 'climate & hydrology', 'Abstract. Over recent decades, the global population has been rapidly increasing and human activities have altered terrestrial water fluxes to an unprecedented extent. The phenomenal growth of the human footprint has significantly modified hydrological processes in various ways (e.g. irrigation, artificial dams, and water diversion) and at various scales (from a watershed to the globe). During the early 1990s, awareness of the potential for increased water scarcity led to the first detailed global water resource assessments. Shortly thereafter, in order to analyse the human perturbation on terrestrial water resources, the first generation of large-scale hydrological models (LHMs) was produced. However, at this early stage few models considered the interaction between terrestrial water fluxes and human activities, including water use and reservoir regulation, and even fewer models distinguished water use from surface water and groundwater resources. Since the early 2000s, a growing number of LHMs have incorporated human impacts on the hydrological cycle, yet the representation of human activities in hydrological models remains challenging. In this paper we provide a synthesis of progress in the development and application of human impact modelling in LHMs. We highlight a number of key challenges and discuss possible improvements in order to better represent the human–water interface in hydrological models.', '2026-07-07 23:10:07');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2784776647', 'climate-hydrology', 'A global lake and reservoir volume analysis using a surface water dataset and satellite altimetry', 'Abstract. Lakes and reservoirs are crucial elements of the hydrological and biochemical cycle and are a valuable resource for hydropower, domestic and industrial water use, and irrigation. Although…', '2019', 2019, 354, 354, 'https://www.hydrology-and-earth-system-sciences.net/graphic_egu_claim_logo_blue.png', 'https://doi.org/10.5194/hess-23-669-2019', 'repository', 'article', 'Hydrology and earth system sciences', '["Tim Busker","Ad de Roo","Emiliano Gelati","Christian Schwatke","Marko Adamovic","Berny Bisselink","Jean‐François Pekel","Andrew Cottam"]', 'climate & hydrology', 'Abstract. Lakes and reservoirs are crucial elements of the hydrological and biochemical cycle and are a valuable resource for hydropower, domestic and industrial water use, and irrigation. Although their monitoring is crucial in times of increased pressure on water resources by both climate change and human interventions, publically available datasets of lake and reservoir levels and volumes are scarce. Within this study, a time series of variation in lake and reservoir volume between 1984 and 2015 were analysed for 137 lakes over all continents by combining the JRC Global Surface Water (GSW) dataset and the satellite altimetry database DAHITI. The GSW dataset is a highly accurate surface water dataset at 30 m resolution compromising the whole L1T Landsat 5, 7 and 8 archive, which allowed for detailed lake area calculations globally over a very long time period using Google Earth Engine. Therefore, the estimates in water volume fluctuations using the GSW dataset are expected to improve compared to current techniques as they are not constrained by complex and computationally intensive classification procedures. Lake areas and water levels were combined in a regression to derive the hypsometry relationship (dh ∕ dA) for all lakes. Nearly all lakes showed a linear regression, and 42 % of the lakes showed a strong linear relationship with a R2 &gt; 0.8, an average R2 of 0.91 and a standard deviation of 0.05. For these lakes and for lakes with a nearly constant lake area (coefficient of variation &lt; 0.008), volume variations were calculated. Lakes with a poor linear relationship were not considered. Reasons for low R2 values were found to be (1) a nearly constant lake area, (2) winter ice coverage and (3) a predominant lack of data within the GSW dataset for those lakes. Lake volume estimates were validated for 18 lakes in the US, Spain, Australia and Africa using in situ volume time series, and gave an excellent Pearson correlation coefficient of on average 0.97 with a standard deviation of 0.041, and a normalized RMSE of 7.42 %. These results show a high potential for measuring lake volume dynamics using a pre-classified GSW dataset, which easily allows the method to be scaled up to an extensive global volumetric dataset. This dataset will not only provide a historical lake and reservoir volume variation record, but will also help to improve our understanding of the behaviour of lakes and reservoirs and their representation in (large-scale) hydrological models.', '2026-07-07 23:10:07');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3149443718', 'physics', 'Fundamentals of heat and mass transfer', 'Familiarization of students with the physical fundamentals of heat and mass transfer processes and modern practical problems solved within the framework of this theory, the formation of students''…', '2018', 2018, 8063, 8063, 'http://adlik.akavita.com/bin/lik?id=32646&it=1', 'http://elib.bsu.by/handle/123456789/194378', 'repository', 'article', 'BSU Digital Library (Belarusian State University)', '["A. V. Larkin"]', 'physics', 'Familiarization of students with the physical fundamentals of heat and mass transfer processes and modern practical problems solved within the framework of this theory, the formation of students'' ideas about the interconnection of the phenomena of momentum, energy and mass transfer.', '2026-07-07 23:11:31');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2133151341', 'physics', 'The HITRAN2016 molecular spectroscopic database', 'The HITRAN database is a compilation of molecular spectroscopic parameters. It was established in the early 1970s and is used by various computer codes to predict and simulate the transmission and…', '2017', 2017, 7947, 7947, 'https://ars.els-cdn.com/content/image/1-s2.0-S0022407317301073-gr1.jpg', 'https://hal.science/hal-01765945', 'repository', 'article', 'Journal of Quantitative Spectroscopy and Radiative Transfer', '["Iouli E. Gordon","Laurence S. Rothman","C. Hill","Roman V. Kochanov","Yan Tan","P. F. Bernath","Manfred Birk","Vincent Boudon","A. Campargue","K. Chance","Brian J. Drouin","J.‐M. Flaud","Robert R. Gamache","Joseph T. Hodges","D. Jacquemart","V. I. Perevalov","A. Perrin","Keith P. Shine","Mary Ann H. Smith","Jonathan Tennyson","Geoffrey C. Toon","H. Tran","Vladimir G. Tyuterev","A. Barbé","Attila G. Császár","V. Malathy Devi","Tibor Furtenbacher","Jeremy J. Harrison","J.‐M. Hartmann","A. Jolly","Timothy J. Johnson","Tijs Karman","Isabelle Kleiner","Aleksandra A. Kyuberis","Joep Loos","O.M. Lyulin","S. T. Massie","С.Н. Михайленко","N. Moazzen-Ahmadi","H. S. P. Müller","O. V. Naumenko","A.V. Nikitin","O. L. Polyansky","M. Rey","M. Rotger","Steven W. Sharpe","Keeyoon Sung","E. Starikova","S.A. Tashkun","J. Vander Auwera","Georg Wagner","Jonas Wilzewski","Piotr Wcisło","Shanshan Yu","E. J. Zak"]', 'physics', 'The HITRAN database is a compilation of molecular spectroscopic parameters. It was established in the early 1970s and is used by various computer codes to predict and simulate the transmission and emission of light in gaseous media (with an emphasis on terrestrial and planetary atmospheres). The HITRAN compilation is composed of five major components: the line-by-line spectroscopic parameters required for high-resolution radiative-transfer codes, experimental infrared absorption cross-sections (for molecules where it is not yet feasible for representation in a line-by-line form), collision-induced absorption data, aerosol indices of refraction, and general tables (including partition sums) that apply globally to the data. This paper describes the contents of the 2020 quadrennial edition of HITRAN. The HITRAN2020 edition takes advantage of recent experimental and theoretical data that were meticulously validated, in particular, against laboratory and atmospheric spectra. The new edition replaces the previous HITRAN edition of 2016 (including its updates during the intervening years). All five components of HITRAN have undergone major updates. In particular, the extent of the updates in the HITRAN2020 edition range from updating a few lines of specific molecules to complete replacements of the lists, and also the introduction of additional isotopologues and new (to HITRAN) molecules: SO, CH3F, GeH4, CS2, CH3I and NF3. Many new vibrational bands were added, extending the spectral coverage and completeness of the line lists. Also, the accuracy of the parameters for major atmospheric absorbers has been increased substantially, often featuring sub-percent uncertainties. Broadening parameters associated with the ambient pressure of water vapor were introduced to HITRAN for the first time and are now available for several molecules. The HITRAN2020 edition continues to take advantage of the relational structure and efficient interface available at www.hitran.org and the HITRAN Application Programming Interface (HAPI). The functionality of both tools has been extended for the new edition.', '2026-07-07 23:11:32');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3015391807', 'physics', 'The IntCal20 Northern Hemisphere Radiocarbon Age Calibration Curve (0–55 cal kBP)', 'ABSTRACT Radiocarbon ( 14 C) ages cannot provide absolutely dated chronologies for archaeological or paleoenvironmental studies directly but must be converted to calendar age equivalents using a…', '2020', 2020, 7627, 7627, 'https://static.cambridge.org/binary/version/id/urn:cambridge.org:id:binary:20200922090001038-0892:S0033822220000417:S0033822220000417_fig1.png', 'https://doi.org/10.1017/rdc.2020.41', 'repository', 'article', 'Radiocarbon', '["Paula Reimer","William E. N. Austin","Édouard Bard","Alex Bayliss","Paul G. Blackwell","Christopher Bronk Ramsey","Martin Butzin","Hai Cheng","R. Lawrence Edwards","Michael Friedrich","Pieter Meiert Grootes","T. P. Guilderson","Irka Hajdas","Timothy Heaton","Alan Hogg","Konrad A Hughen","Bernd Kromer","Sturt W. Manning","Raimund Muscheler","Jonathan Palmer","Charlotte Pearson","J. van der Plicht","Ron Reimer","David A. Richards","E. M. Scott","John Southon","Chris Turney","Lukas Wacker","Florian Adolphi","Ulf Büntgen","Manuela Capano","Simon Fahrni","Alexandra Fogtmann-Schulz","Ronny Friedrich","Peter Köhler","Sabrina G K Kudsk","Fusa Miyake","Jesper Olsen","Frederick Reinig","Minoru Sakamoto","Adam Sookdeo","Sahra Talamo"]', 'physics', 'ABSTRACT Radiocarbon ( 14 C) ages cannot provide absolutely dated chronologies for archaeological or paleoenvironmental studies directly but must be converted to calendar age equivalents using a calibration curve compensating for fluctuations in atmospheric 14 C concentration. Although calibration curves are constructed from independently dated archives, they invariably require revision as new data become available and our understanding of the Earth system improves. In this volume the international 14 C calibration curves for both the Northern and Southern Hemispheres, as well as for the ocean surface layer, have been updated to include a wealth of new data and extended to 55,000 cal BP. Based on tree rings, IntCal20 now extends as a fully atmospheric record to ca. 13,900 cal BP. For the older part of the timescale, IntCal20 comprises statistically integrated evidence from floating tree-ring chronologies, lacustrine and marine sediments, speleothems, and corals. We utilized improved evaluation of the timescales and location variable 14 C offsets from the atmosphere (reservoir age, dead carbon fraction) for each dataset. New statistical methods have refined the structure of the calibration curves while maintaining a robust treatment of uncertainties in the 14 C ages, the calendar ages and other corrections. The inclusion of modeled marine reservoir ages derived from a three-dimensional ocean circulation model has allowed us to apply more appropriate reservoir corrections to the marine 14 C data rather than the previous use of constant regional offsets from the atmosphere. Here we provide an overview of the new and revised datasets and the associated methods used for the construction of the IntCal20 curve and explore potential regional offsets for tree-ring data. We discuss the main differences with respect to the previous calibration curve, IntCal13, and some of the implications for archaeology and geosciences ranging from the recent past to the time of the extinction of the Neanderthals.', '2026-07-07 23:11:46');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3208645186', 'physics', 'Sample sizes for saturation in qualitative research: A systematic review of empirical tests', 'OBJECTIVE: To review empirical studies that assess saturation in qualitative research in order to identify sample sizes for saturation, strategies used to assess saturation, and guidance we can draw…', '2021', 2021, 5620, 5620, 'https://ars.els-cdn.com/content/image/1-s2.0-S0277953621008558-gr1.jpg', 'https://pubmed.ncbi.nlm.nih.gov/34785096', 'repository', 'review', 'Social Science & Medicine', '["Monique Hennink","Bonnie N. Kaiser"]', 'physics', 'OBJECTIVE: To review empirical studies that assess saturation in qualitative research in order to identify sample sizes for saturation, strategies used to assess saturation, and guidance we can draw from these studies. METHODS: We conducted a systematic review of four databases to identify studies empirically assessing sample sizes for saturation in qualitative research, supplemented by searching citing articles and reference lists. RESULTS: We identified 23 articles that used empirical data (n = 17) or statistical modeling (n = 6) to assess saturation. Studies using empirical data reached saturation within a narrow range of interviews (9-17) or focus group discussions (4-8), particularly those with relatively homogenous study populations and narrowly defined objectives. Most studies had a relatively homogenous study population and assessed code saturation; the few outliers (e.g., multi-country research, meta-themes, "code meaning" saturation) needed larger samples for saturation. CONCLUSIONS: Despite varied research topics and approaches to assessing saturation, studies converged on a relatively consistent sample size for saturation for commonly used qualitative research methods. However, these findings apply to certain types of studies (e.g., those with homogenous study populations). These results provide strong empirical guidance on effective sample sizes for qualitative research, which can be used in conjunction with the characteristics of individual studies to estimate an appropriate sample size prior to data collection. This synthesis also provides an important resource for researchers, academic journals, journal reviewers, ethical review boards, and funding agencies to facilitate greater transparency in justifying and reporting sample sizes in qualitative research. Future empirical research is needed to explore how various parameters affect sample sizes for saturation.', '2026-07-07 23:12:24');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2801702920', 'physics', 'Best Practices for Developing and Validating Scales for Health, Social, and Behavioral Research: A Primer', 'Scale development and validation are critical to much of the work in the health, social, and behavioral sciences. However, the constellation of techniques required for scale development and…', '2018', 2018, 5265, 5265, 'https://www.frontiersin.org/files/Articles/366616/fpubh-06-00149-HTML/image_m/fpubh-06-00149-g001.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6004510', 'pmc', 'review', 'Frontiers in Public Health', '["Godfred O. Boateng","Torsten B. Neilands","Edward A. Frongillo","Hugo Melgar‐Quiñonez","Sera L. Young"]', 'physics', 'Scale development and validation are critical to much of the work in the health, social, and behavioral sciences. However, the constellation of techniques required for scale development and evaluation can be onerous, jargon-filled, unfamiliar, and resource-intensive. Further, it is often not a part of graduate training. Therefore, our goal was to concisely review the process of scale development in as straightforward a manner as possible, both to facilitate the development of new, valid, and reliable scales, and to help improve existing ones. To do this, we have created a primer for best practices for scale development in measuring complex phenomena. This is not a systematic review, but rather the amalgamation of technical literature and lessons learned from our experiences spent creating or adapting a number of scales over the past several decades. We identified three phases that span nine steps. In the first phase, items are generated and the validity of their content is assessed. In the second phase, the scale is constructed. Steps in scale construction include pre-testing the questions, administering the survey, reducing the number of items, and understanding how many factors the scale captures. In the third phase, scale evaluation, the number of dimensions is tested, reliability is tested, and validity is assessed. We have also added examples of best practices to each step. In sum, this primer will equip both scientists and practitioners to understand the ontology and methodology of scale development and validation, thereby facilitating the advancement of our understanding of a range of health, social, and behavioral outcomes.', '2026-07-07 23:12:31');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2127309075', 'physics', 'An integrated approach to correction for off-resonance effects and subject movement in diffusion MR imaging', 'In this paper we describe a method for retrospective estimation and correction of eddy current (EC)-induced distortions and subject movement in diffusion imaging. In addition a susceptibility-induced…', '2015', 2015, 3821, 3821, 'https://ars.els-cdn.com/content/image/1-s2.0-S1053811915009209-fx1.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4692656', 'pmc', 'article', 'NeuroImage', '["Jesper Andersson","Stamatios N. Sotiropoulos"]', 'physics', 'In this paper we describe a method for retrospective estimation and correction of eddy current (EC)-induced distortions and subject movement in diffusion imaging. In addition a susceptibility-induced field can be supplied and will be incorporated into the calculations in a way that accurately reflects that the two fields (susceptibility- and EC-induced) behave differently in the presence of subject movement. The method is based on registering the individual volumes to a model free prediction of what each volume should look like, thereby enabling its use on high b-value data where the contrast is vastly different in different volumes. In addition we show that the linear EC-model commonly used is insufficient for the data used in the present paper (high spatial and angular resolution data acquired with Stejskal-Tanner gradients on a 3T Siemens Verio, a 3T Siemens Connectome Skyra or a 7T Siemens Magnetome scanner) and that a higher order model performs significantly better. The method is already in extensive practical use and is used by four major projects (the WU-UMinn HCP, the MGH HCP, the UK Biobank and the Whitehall studies) to correct for distortions and subject movement.', '2026-07-07 23:13:46');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1729017034', 'physics', 'The effect of malaria control on Plasmodium falciparum in Africa between 2000 and 2015', 'Since the year 2000, a concerted campaign against malaria has led to unprecedented levels of intervention coverage across sub-Saharan Africa. Understanding the effect of this control effort is vital…', '2015', 2015, 3586, 3586, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature15535/MediaObjects/41586_2015_Article_BFnature15535_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4820050', 'pmc', 'article', 'Nature', '["Samir Bhatt","D. J. Weiss","Ewan Cameron","Donal Bisanzio","Bonnie Mappin","Ursula Dalrymple","Katherine E. Battle","Catherine L. Moyes","Alasdair L. Henry","Philip A. Eckhoff","Edward A. Wenger","Olivier Briët","Melissa A. Penny","Thomas A. Smith","Adam Bennett","Joshua Yukich","Thomas P. Eisele","Jamie T. Griffin","Cristin Fergus","Michael Lynch","Finn Lindgren","Justin M Cohen","Christopher Murray","David L. Smith","Simon I Hay","Richard Cibulskis","Peter W. Gething"]', 'physics', 'Since the year 2000, a concerted campaign against malaria has led to unprecedented levels of intervention coverage across sub-Saharan Africa. Understanding the effect of this control effort is vital to inform future control planning. However, the effect of malaria interventions across the varied epidemiological settings of Africa remains poorly understood owing to the absence of reliable surveillance data and the simplistic approaches underlying current disease estimates. Here we link a large database of malaria field surveys with detailed reconstructions of changing intervention coverage to directly evaluate trends from 2000 to 2015, and quantify the attributable effect of malaria disease control efforts. We found that Plasmodium falciparum infection prevalence in endemic Africa halved and the incidence of clinical disease fell by 40% between 2000 and 2015. We estimate that interventions have averted 663 (542–753 credible interval) million clinical cases since 2000. Insecticide-treated nets, the most widespread intervention, were by far the largest contributor (68% of cases averted). Although still below target levels, current malaria interventions have substantially reduced malaria disease incidence across the continent. Increasing access to these interventions, and maintaining their effectiveness in the face of insecticide and drug resistance, should form a cornerstone of post-2015 control strategies. In this study, the authors present an analysis of the malaria burden in sub-Saharan Africa between 2000 and 2015, and quantify the effects of the interventions that have been implemented to combat the disease; they find that the prevalence of Plasmodium falciparum infection has been reduced by 50% since 2000 and the incidence of clinical disease by 40%, and that interventions have averted approximately 663 million clinical cases since 2000, with insecticide-treated bed nets being the largest contributor. In one of the largest public health campaigns in history, a concerted malaria control campaign has been under way in sub-Saharan Africa for the past 15 years. Billions of dollars have been invested to provide interventions such as bed nets and antimalarial drugs but the overall effect on malaria burden remains unclear. This study uses field data from 30,000 population clusters in a sophisticated space–time modelling framework to quantify the changing Plasmodium falciparum risk (a 40% decline in case incidence since 2000) and the role of malaria interventions (around 700 million cases averted). Although below target levels, the current campaign has substantially reduced the incidence of malaria across the continent. Continued success will depend upon increasing access to these interventions, and maintaining their effectiveness in the face of insecticide and drug resistance.', '2026-07-07 23:14:13');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2570760970', 'physics', 'A manifesto for reproducible science', 'Improving the reliability and efficiency of scientific research will increase the credibility of the published scientific literature and accelerate discovery. Here we argue for the adoption of…', '2017', 2017, 3508, 3508, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41562-016-0021/MediaObjects/41562_2016_Article_BFs415620160021_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7610724', 'pmc', 'article', 'Nature Human Behaviour', '["Marcus R. Munafò","Brian A. Nosek","Dorothy Bishop","Katherine S. Button","Chris Chambers","Nathalie Percie du Sert","Uri Simonsohn","Eric‐Jan Wagenmakers","Jennifer J. Ware","John P. A. Ioannidis"]', 'physics', 'Improving the reliability and efficiency of scientific research will increase the credibility of the published scientific literature and accelerate discovery. Here we argue for the adoption of measures to optimize key elements of the scientific process: methods, reporting and dissemination, reproducibility, evaluation and incentives. There is some evidence from both simulations and empirical studies supporting the likely effectiveness of these measures, but their broad adoption by researchers, institutions, funders and journals will require iterative evaluation and improvement. We discuss the goals of these measures, and how they can be implemented, in the hope that this will facilitate action toward improving the transparency, reproducibility and efficiency of scientific research.', '2026-07-07 23:14:14');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2161112598', 'physics', 'The Molecular Taxonomy of Primary Prostate Cancer', 'The Molecular Taxonomy of Primary Prostate Cancer', '2015', 2015, 3234, 3234, 'https://ars.els-cdn.com/content/image/1-s2.0-S0092867415013392-fx1.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4695400', 'pmc', 'article', 'Cell', '["Adam Abeshouse","Jaeil Ahn","Rehan Akbani","Adrian Ally","Samirkumar B. Amin","Chris Andry","Matti Annala","Armen Aprikian","Joshua Armenia","Arshi Arora","J. Todd Auman","Miruna Balasundaram","Saianand Balu","Christopher E. Barbieri","Thomas Bauer","Christopher C. Benz","Alain Bergeron","Rameen Beroukhim","Mario Berríos","Adrian Bivol","Tom Bodenheimer","Lori Boice","Moiz S. Bootwalla","Rodolfo Borges dos Reis","Paul C. Boutros","Jay Bowen","Reanne Bowlby","Jeffrey M. Boyd","Robert K. Bradley","Anne Breggia","Fadi Brimo","Christopher A. Bristow","Denise Brooks","Bradley M. Broom","Alan H. Bryce","Glenn J. Bubley","Eric Burks","Yaron S.N. Butterfield","M. Button","David Canes","Carlos Gilberto Carlotti","Rebecca Carlsen","Michel Carmel","Peter R. Carroll","Scott L. Carter","Richard W. Cartun","Brett S. Carver","June M. Chan","Matthew T. Chang","Yu Chen","Andrew D. Cherniack","Simone Chevalier","Lynda Chin","Juok Cho","Andy Chu","Eric Chuah","Sudha Chudamani","Kristian Cibulskis","Giovanni Ciriello","Amanda Clarke","Matthew R. Cooperberg","Niall M. Corcoran","Anthony J. Costello","Janet E. Cowan","Daniel Crain","Erin Curley","Kerstin A. David","John A. Demchok","Francesca Demichelis","Noreen Dhalla","Rajiv Dhir","Alexandre A. Doueik","Bettina F. Drake","Heidi Dvinge","Natalya Dyakova","Ina Felau","Martin L. Ferguson","Scott Frazer","Stephen J. Freedland","Yao Fu","Stacey Gabriel","Jianjiong Gao","Johanna Gardner","Julie M. Gastier-Foster","Nils Gehlenborg","Mark Gerken","Mark Gerstein","Gad Getz","Andrew K. Godwin","Anuradha Gopalan","Markus Graefen","Kiley Graim","Thomas Gribbin","Ranabir Guin","Manaswi Gupta","Angela Hadjipanayis","Syed Haider","Lucie Hamel","D. Neil Hayes","David I. Heiman"]', 'physics', NULL, '2026-07-07 23:14:50');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3183475563', 'physics', 'Highly accurate protein structure prediction for the human proteome', 'Abstract Protein structures can provide invaluable information, both for reasoning about biological processes and for enabling interventions such as structure-based drug development or targeted…', '2021', 2021, 3231, 3231, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-021-03828-1/MediaObjects/41586_2021_3828_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8387240', 'pmc', 'article', 'Nature', '["Kathryn Tunyasuvunakool","Jonas Adler","Zachary Wu","Tim Green","Michał Zieliński","Augustin Žídek","Alex Bridgland","Andrew Cowie","Clemens Meyer","Agata Laydon","Sameer Velankar","Gerard J. Kleywegt","Alex Bateman","Richard Evans","Alexander Pritzel","Michael Figurnov","Olaf Ronneberger","Russ Bates","Simon Köhl","Anna Potapenko","Andrew J. Ballard","Bernardino Romera‐Paredes","Stanislav Nikolov","Rishub Jain","Ellen Clancy","David Reiman","Stig Petersen","Andrew Senior","Koray Kavukcuoglu","Ewan Birney","Pushmeet Kohli","John Jumper","Demis Hassabis"]', 'physics', 'Abstract Protein structures can provide invaluable information, both for reasoning about biological processes and for enabling interventions such as structure-based drug development or targeted mutagenesis. After decades of effort, 17% of the total residues in human protein sequences are covered by an experimentally determined structure 1. Here we markedly expand the structural coverage of the proteome by applying the state-of-the-art machine learning method, AlphaFold 2, at a scale that covers almost the entire human proteome (98.5% of human proteins). The resulting dataset covers 58% of residues with a confident prediction, of which a subset (36% of all residues) have very high confidence. We introduce several metrics developed by building on the AlphaFold model and use them to interpret the dataset, identifying strong multi-domain predictions as well as regions that are likely to be disordered. Finally, we provide some case studies to illustrate how high-quality predictions could be used to generate biological hypotheses. We are making our predictions freely available to the community and anticipate that routine large-scale and high-accuracy structure prediction will become an important tool that will allow new questions to be addressed from a structural perspective.', '2026-07-07 23:14:51');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2261135145', 'physics', 'Entropy-stabilized oxides', 'Configurational disorder can be compositionally engineered into mixed oxide by populating a single sublattice with many distinct cations. The formulations promote novel and entropy-stabilized forms…', '2015', 2015, 3278, 3278, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fncomms9485/MediaObjects/41467_2015_Article_BFncomms9485_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4598836', 'pmc', 'article', 'Nature Communications', '["Christina M. Rost","Edward Sachet","Trent Borman","Ali Moballegh","Elizabeth C. Dickey","Dong Hou","Jacob L. Jones","Stefano Curtarolo","Jon‐Paul Maria"]', 'physics', 'Configurational disorder can be compositionally engineered into mixed oxide by populating a single sublattice with many distinct cations. The formulations promote novel and entropy-stabilized forms of crystalline matter where metal cations are incorporated in new ways. Here, through rigorous experiments, a simple thermodynamic model, and a five-component oxide formulation, we demonstrate beyond reasonable doubt that entropy predominates the thermodynamic landscape, and drives a reversible solid-state transformation between a multiphase and single-phase state. In the latter, cation distributions are proven to be random and homogeneous. The findings validate the hypothesis that deliberate configurational disorder provides an orthogonal strategy to imagine and discover new phases of crystalline matter and untapped opportunities for property engineering.', '2026-07-07 23:14:52');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2946372752', 'physics', 'The role of short-chain fatty acids in microbiota–gut–brain communication', 'The role of short-chain fatty acids in microbiota–gut–brain communication', '2019', 2019, 3208, 3208, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41575-019-0157-3/MediaObjects/41575_2019_157_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/31123355', 'repository', 'review', 'Nature Reviews Gastroenterology & Hepatology', '["Boushra Dalile","Lukas Van Oudenhove","Bram Vervliet","Kristin Verbeke"]', 'physics', NULL, '2026-07-07 23:14:55');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2752849906', 'physics', 'Deep learning with coherent nanophotonic circuits', 'Deep learning with coherent nanophotonic circuits', '2017', 2017, 3105, 3105, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnphoton.2017.93/MediaObjects/41566_2017_Article_BFnphoton201793_Fig1_HTML.jpg', 'http://arxiv.org/abs/1610.02365', 'arxiv', 'article', 'Nature Photonics', '["Yichen Shen","Nicholas C. Harris","Scott A. Skirlo","Mihika Prabhu","Tom Baehr‐Jones","Michael Hochberg","Xin Sun","Shijie Zhao","Hugo Larochelle","Dirk Englund","Marin Soljačić"]', 'physics', NULL, '2026-07-07 23:14:56');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2937483840', 'physics', 'Epidemiology of Prostate Cancer', 'Prostate cancer is the second most frequent cancer diagnosis made in men and the fifth leading cause of death worldwide. Prostate cancer may be asymptomatic at the early stage and often has an…', '2019', 2019, 2764, 2764, 'https://cdn.ncbi.nlm.nih.gov/pmc/blobs/a11f/6497009/cd5e0a7ede68/wjon-10-063-g001.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6497009', 'pmc', 'review', 'World Journal of Oncology', '["Prashanth Rawla"]', 'physics', 'Prostate cancer is the second most frequent cancer diagnosis made in men and the fifth leading cause of death worldwide. Prostate cancer may be asymptomatic at the early stage and often has an indolent course that may require only active surveillance. Based on GLOBOCAN 2018 estimates, 1,276,106 new cases of prostate cancer were reported worldwide in 2018, with higher prevalence in the developed countries. Differences in the incidence rates worldwide reflect differences in the use of diagnostic testing. Prostate cancer incidence and mortality rates are strongly related to the age with the highest incidence being seen in elderly men (> 65 years of age). African-American men have the highest incidence rates and more aggressive type of prostate cancer compared to White men. There is no evidence yet on how to prevent prostate cancer; however, it is possible to lower the risk by limiting high-fat foods, increasing the intake of vegetables and fruits and performing more exercise. Screening is highly recommended at age 45 for men with familial history and African-American men. Up-to-date statistics on prostate cancer occurrence and outcomes along with a better understanding of the etiology and causative risk factors are essential for the primary prevention of this disease.', '2026-07-07 23:15:38');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3043135743', 'physics', 'Reporting animal research: Explanation and elaboration for the ARRIVE guidelines 2.0', 'Improving the reproducibility of biomedical research is a major challenge. Transparent and accurate reporting is vital to this process; it allows readers to assess the reliability of the findings and…', '2020', 2020, 2798, 2798, 'https://journals.plos.org/plosbiology/article/figure/image?size=large&id=10.1371/journal.pbio.3000411.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7360025', 'pmc', 'article', 'PLoS Biology', '["Nathalie Percie du Sert","Amrita Ahluwalia","Sabina Alam","Marc T. Avey","Monya Baker","William J. Browne","Alejandra Clark","Innes C. Cuthill","Ulrich Dirnagl","Michael Emerson","Paul Garner","Stephen T. Holgate","David W. Howells","Viki Hurst","Natasha A. Karp","Stanley E. Lazic","Katie Lidster","Catriona MacCallum","Malcolm Macleod","Esther J. Pearl","Ole H. Petersen","Frances Rawle","Penny S. Reynolds","Kieron Rooney","Emily S. Sena","Shai D. Silberberg","Thomas Steckler","Hanno Würbel"]', 'physics', 'Improving the reproducibility of biomedical research is a major challenge. Transparent and accurate reporting is vital to this process; it allows readers to assess the reliability of the findings and repeat or build upon the work of other researchers. The ARRIVE guidelines (Animal Research: Reporting In Vivo Experiments) were developed in 2010 to help authors and journals identify the minimum information necessary to report in publications describing in vivo experiments. Despite widespread endorsement by the scientific community, the impact of ARRIVE on the transparency of reporting in animal research publications has been limited. We have revised the ARRIVE guidelines to update them and facilitate their use in practice. The revised guidelines are published alongside this paper. This explanation and elaboration document was developed as part of the revision. It provides further information about each of the 21 items in ARRIVE 2.0, including the rationale and supporting evidence for their inclusion in the guidelines, elaboration of details to report, and examples of good reporting from the published literature. This document also covers advice and best practice in the design and conduct of animal studies to support researchers in improving standards from the start of the experimental design process through to publication.', '2026-07-07 23:15:39');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2949223833', 'physics', 'OpenMM 7: Rapid development of high performance algorithms for molecular dynamics', 'OpenMM is a molecular dynamics simulation toolkit with a unique focus on extensibility. It allows users to easily add new features, including forces with novel functional forms, new integration…', '2017', 2017, 2776, 2776, 'https://journals.plos.org/ploscompbiol/article/figure/image?size=large&id=10.1371/journal.pcbi.1005659.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5549999', 'pmc', 'article', 'PLoS Computational Biology', '["Peter Eastman","Jason Swails","John D. Chodera","Robert T. McGibbon","Yutong Zhao","Kyle A. Beauchamp","Lee‐Ping Wang","Andrew C. Simmonett","Matthew P. Harrigan","Chaya Stern","Rafal Wiewiora","Bernard R. Brooks","Vijay S. Pande"]', 'physics', 'OpenMM is a molecular dynamics simulation toolkit with a unique focus on extensibility. It allows users to easily add new features, including forces with novel functional forms, new integration algorithms, and new simulation protocols. Those features automatically work on all supported hardware types (including both CPUs and GPUs) and perform well on all of them. In many cases they require minimal coding, just a mathematical description of the desired function. They also require no modification to OpenMM itself and can be distributed independently of OpenMM. This makes it an ideal tool for researchers developing new simulation methods, and also allows those new methods to be immediately available to the larger community.', '2026-07-07 23:15:39');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2770598799', 'physics', 'Orienting the causal relationship between imprecisely measured traits using GWAS summary data', 'Inference about the causal structure that induces correlations between two traits can be achieved by combining genetic associations with a mediation-based approach, as is done in the causal inference…', '2017', 2017, 2769, 2769, 'https://journals.plos.org/plosgenetics/article/figure/image?size=large&id=10.1371/journal.pgen.1007081.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5711033', 'pmc', 'article', 'PLoS Genetics', '["Gibran Hemani","Kate Tilling","George Davey Smith"]', 'physics', 'Inference about the causal structure that induces correlations between two traits can be achieved by combining genetic associations with a mediation-based approach, as is done in the causal inference test (CIT). However, we show that measurement error in the phenotypes can lead to the CIT inferring the wrong causal direction, and that increasing sample sizes has the adverse effect of increasing confidence in the wrong answer. This problem is likely to be general to other mediation-based approaches. Here we introduce an extension to Mendelian randomisation, a method that uses genetic associations in an instrumentation framework, that enables inference of the causal direction between traits, with some advantages. First, it can be performed using only summary level data from genome-wide association studies; second, it is less susceptible to bias in the presence of measurement error or unmeasured confounding. We apply the method to infer the causal direction between DNA methylation and gene expression levels. Our results demonstrate that, in general, DNA methylation is more likely to be the causal factor, but this result is highly susceptible to bias induced by systematic differences in measurement error between the platforms, and by horizontal pleiotropy. We emphasise that, where possible, implementing MR and appropriate sensitivity analyses alongside other approaches such as CIT is important to triangulate reliable conclusions about causality.', '2026-07-07 23:15:39');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1026348989', 'physics', 'Ionic transport in hybrid lead iodide perovskite solar cells', 'Solar cells based on organic-inorganic halide perovskites have recently shown rapidly rising power conversion efficiencies, but exhibit unusual behaviour such as current-voltage hysteresis and a…', '2015', 2015, 2802, 2802, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fncomms8497/MediaObjects/41467_2015_Article_BFncomms8497_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4491179', 'pmc', 'article', 'Nature Communications', '["Christopher Eames","Jarvist M. Frost","Piers R. F. Barnes","Brian C. O’Regan","Aron Walsh","M. Saiful Islam"]', 'physics', 'Solar cells based on organic-inorganic halide perovskites have recently shown rapidly rising power conversion efficiencies, but exhibit unusual behaviour such as current-voltage hysteresis and a low-frequency giant dielectric response. Ionic transport has been suggested to be an important factor contributing to these effects; however, the chemical origin of this transport and the mobile species are unclear. Here, the activation energies for ionic migration in methylammonium lead iodide (CH3NH3PbI3) are derived from first principles, and are compared with kinetic data extracted from the current-voltage response of a perovskite-based solar cell. We identify the microscopic transport mechanisms, and find facile vacancy-assisted migration of iodide ions with an activation energy of 0.6 eV, in good agreement with the kinetic measurements. The results of this combined computational and experimental study suggest that hybrid halide perovskites are mixed ionic-electronic conductors, a finding that has major implications for solar cell device architectures.', '2026-07-07 23:15:41');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1709784975', 'physics', 'Loophole-free Bell inequality violation using electron spins separated by 1.3 kilometres', 'Loophole-free Bell inequality violation using electron spins separated by 1.3 kilometres', '2015', 2015, 2821, 2821, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature15759/MediaObjects/41586_2015_Article_BFnature15759_Fig1_HTML.jpg', 'http://arxiv.org/abs/1508.05949', 'arxiv', 'article', 'Nature', '["Bas Hensen","Hannes Bernien","A. Dréau","Andreas Reiserer","Norbert Kalb","Machiel Blok","Just Ruitenberg","R. F. L. Vermeulen","R. N. Schouten","Carlos Abellán","Waldimar Amaya","Valerio Pruneri","Morgan W. Mitchell","Matthew Markham","Daniel J. Twitchen","David Elkouss","Stephanie Wehner","T. H. Taminiau","Ronald Hanson"]', 'physics', NULL, '2026-07-07 23:15:41');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3179964610', 'physics', 'Designing the next generation of proton-exchange membrane fuel cells', 'Designing the next generation of proton-exchange membrane fuel cells', '2021', 2021, 2787, 2787, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-021-03482-7/MediaObjects/41586_2021_3482_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/34262215', 'repository', 'review', 'Nature', '["Kui Jiao","Jin Xuan","Qing Du","Zhiming Bao","Biao Xie","Bowen Wang","Yan Zhao","Linhao Fan","Huizhi Wang","Zhongjun Hou","Sen Huo","Nigel P. Brandon","Yan Yin","Michael D. Guiver"]', 'physics', NULL, '2026-07-07 23:15:42');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2035616341', 'physics', 'Compilation of Henry''s law constants (version 4.0) for water as solvent', 'Abstract. Many atmospheric chemicals occur in the gas phase as well as in liquid cloud droplets and aerosol particles. Therefore, it is necessary to understand the distribution between the phases.…', '2015', 2015, 2776, 2776, 'https://www.atmospheric-chemistry-and-physics.net/graphic_egu_claim_logo_blue.png', 'https://doi.org/10.5194/acp-15-4399-2015', 'repository', 'article', 'Atmospheric chemistry and physics', '["Rolf Sander"]', 'physics', 'Abstract. Many atmospheric chemicals occur in the gas phase as well as in liquid cloud droplets and aerosol particles. Therefore, it is necessary to understand the distribution between the phases. According to Henry''s law, the equilibrium ratio between the abundances in the gas phase and in the aqueous phase is constant for a dilute solution. Henry''s law constants of trace gases of potential importance in environmental chemistry have been collected and converted into a uniform format. The compilation contains 17 350 values of Henry''s law constants for 4632 species, collected from 689 references. It is also available at http://www.henrys-law.org.', '2026-07-07 23:15:43');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1886626438', 'physics', 'A precipitation-hardened high-entropy alloy with outstanding tensile properties', 'A precipitation-hardened high-entropy alloy with outstanding tensile properties', '2015', 2015, 2760, 2760, 'https://ars.els-cdn.com/content/image/1-s2.0-S1359645415006631-fx1.jpg', 'https://doi.org/10.1016/j.actamat.2015.08.076', 'repository', 'article', 'Acta Materialia', '["Junyang He","Hui Wang","Hailong Huang","Xiandong Xu","Mingwei Chen","Yuxian Wu","Xiongjun Liu","T.G. Nieh","Ke An","Zhaoping Lü"]', 'physics', NULL, '2026-07-07 23:15:47');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2570166109', 'physics', 'Recent development of two-dimensional transition metal dichalcogenides and their applications', 'Recent advances in atomically thin two-dimensional transition metal dichalcogenides (2D TMDs) have led to a variety of promising technologies for nanoelectronics, photonics, sensing, energy storage,…', '2017', 2017, 2732, 2732, 'https://ars.els-cdn.com/content/image/1-s2.0-S1369702116302917-gr1.jpg', 'https://doi.org/10.1016/j.mattod.2016.10.002', 'repository', 'article', 'Materials Today', '["Wonbong Choi","Nitin Choudhary","Gang Han","Juhong Park","Deji Akinwande","Young Hee Lee"]', 'physics', 'Recent advances in atomically thin two-dimensional transition metal dichalcogenides (2D TMDs) have led to a variety of promising technologies for nanoelectronics, photonics, sensing, energy storage, and opto-electronics, to name a few. This article reviews the recent progress in 2D materials beyond graphene and includes mainly transition metal dichalcogenides (TMDs) (e.g. MoS 2, WS 2, MoSe 2, and WSe 2 ). These materials are finding niche applications for next-generation electronics and optoelectronics devices relying on ultimate atomic thicknesses. Albeit several challenges in developing scalable and defect-free TMDs on desired substrates, new growth techniques compatible with traditional and unconventional substrates have been developed to meet the ever-increasing demand of high quality and controllability for practical applications. The fabrication of novel 2D TMDs that exhibit exotic functionalities and fundamentally new chemistry is highlighted. And finally, in parallel with the electronics, the considerable effort devoted to using these materials for energy and sensing applications is discussed in detail.', '2026-07-07 23:15:50');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2340338776', 'physics', 'Role of Nrf2/HO-1 system in development, oxidative stress response and diseases: an evolutionarily conserved mechanism', 'The multifunctional regulator nuclear factor erythroid 2-related factor (Nrf2) is considered not only as a cytoprotective factor regulating the expression of genes coding for anti-oxidant,…', '2016', 2016, 2642, 2642, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1134%2FS0006297922010060/MediaObjects/10541_2022_2272_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4967105', 'pmc', 'review', 'Cellular and Molecular Life Sciences', '["Agnieszka Łoboda","Milena Damulewicz","Elżbieta Pyza","Alicja Józkowicz","Józef Dulak"]', 'physics', 'The multifunctional regulator nuclear factor erythroid 2-related factor (Nrf2) is considered not only as a cytoprotective factor regulating the expression of genes coding for anti-oxidant, anti-inflammatory and detoxifying proteins, but it is also a powerful modulator of species longevity. The vertebrate Nrf2 belongs to Cap ''n'' Collar (Cnc) bZIP family of transcription factors and shares a high homology with SKN-1 from Caenorhabditis elegans or CncC found in Drosophila melanogaster. The major characteristics of Nrf2 are to some extent mimicked by Nrf2-dependent genes and their proteins including heme oxygenase-1 (HO-1), which besides removing toxic heme, produces biliverdin, iron ions and carbon monoxide. HO-1 and their products exert beneficial effects through the protection against oxidative injury, regulation of apoptosis, modulation of inflammation as well as contribution to angiogenesis. On the other hand, the disturbances in the proper HO-1 level are associated with the pathogenesis of some age-dependent disorders, including neurodegeneration, cancer or macular degeneration. This review summarizes our knowledge about Nrf2 and HO-1 across different phyla suggesting their conservative role as stress-protective and anti-aging factors.', '2026-07-07 23:16:13');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2610602137', 'physics', 'Global Public Health Burden of Heart Failure', 'Heart failure (HF) is a global pandemic affecting at least 26 million people worldwide and is increasing in prevalence. HF health expenditures are considerable and will increase dramatically with an…', '2017', 2017, 2658, 2658, 'https://assets.radcliffecardiology.com/s3fs-public/article/2020-12/figure1-burden-of-heart-failure_0.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5494150', 'pmc', 'article', 'Cardiac failure review', '["Gianluigi Savarese","Lars H. Lund"]', 'physics', 'Heart failure (HF) is a global pandemic affecting at least 26 million people worldwide and is increasing in prevalence. HF health expenditures are considerable and will increase dramatically with an ageing population. Despite the significant advances in therapies and prevention, mortality and morbidity are still high and quality of life poor. The prevalence, incidence, mortality and morbidity rates reported show geographic variations, depending on the different aetiologies and clinical characteristics observed among patients with HF. In this review we focus on the global epidemiology of HF, providing data about prevalence, incidence, mortality and morbidity worldwide.', '2026-07-07 23:16:13');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3007172120', 'physics', 'Opportunities and challenges in long-read sequencing data analysis', 'Long-read technologies are overcoming early limitations in accuracy and throughput, broadening their application domains in genomics. Dedicated analysis tools that take into account the…', '2020', 2020, 2648, 2648, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs13059-020-1935-5/MediaObjects/13059_2020_1935_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7006217', 'pmc', 'review', 'Genome biology', '["Shanika L. Amarasinghe","Shian Su","Xueyi Dong","Luke Zappia","Matthew E. Ritchie","Quentin Gouil"]', 'physics', 'Long-read technologies are overcoming early limitations in accuracy and throughput, broadening their application domains in genomics. Dedicated analysis tools that take into account the characteristics of long-read data are thus required, but the fast pace of development of such tools can be overwhelming. To assist in the design and analysis of long-read sequencing projects, we review the current landscape of available tools and present an online interactive database, long-read-tools.org, to facilitate their browsing. We further focus on the principles of error correction, base modification detection, and long-read transcriptomics analysis and highlight the challenges that remain.', '2026-07-07 23:16:14');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2175118067', 'physics', 'Type-II Weyl semimetals', 'Type-II Weyl semimetals', '2015', 2015, 2539, 2539, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature15768/MediaObjects/41586_2015_Article_BFnature15768_Fig1_HTML.jpg', 'http://arxiv.org/abs/1507.01603', 'arxiv', 'article', 'Nature', '["Alexey A. Soluyanov","Dominik Gresch","Zhijun Wang","Quansheng Wu","Matthias Troyer","Xi Dai","B. Andrei Bernevig"]', 'physics', NULL, '2026-07-07 23:16:39');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2735457220', 'physics', 'Probing many-body dynamics on a 51-atom quantum simulator', 'Probing many-body dynamics on a 51-atom quantum simulator', '2017', 2017, 2511, 2511, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature24622/MediaObjects/41586_2017_Article_BFnature24622_Fig1_HTML.jpg', 'http://arxiv.org/abs/1707.04344', 'arxiv', 'article', 'Nature', '["Hannes Bernien","Sylvain Schwartz","Alexander Keesling","Harry Levine","Ahmed Omran","Hannes Pichler","Soonwon Choi","A. S. Zibrov","Manuel Endres","Markus Greiner","Vladan Vuletić","Mikhail D. Lukin"]', 'physics', NULL, '2026-07-07 23:16:40');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2255138985', 'physics', 'Schizophrenia risk from complex variation of complement component 4', 'Schizophrenia risk from complex variation of complement component 4', '2016', 2016, 2518, 2518, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature16549/MediaObjects/41586_2016_Article_BFnature16549_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4752392', 'pmc', 'article', 'Nature', '["Aswin Sekar","Allison R. Bialas","Heather de Rivera","Avery Davis","Timothy R. Hammond","Nolan Kamitaki","Katherine Tooley","Jessy Présumey","Matthew L. Baum","Vanessa Van Doren","Giulio Genovese","Samuel A. Rose","Robert E. Handsaker","Mark J. Daly","Michael C. Carroll","Beth Stevens","Steven A. McCarroll"]', 'physics', NULL, '2026-07-07 23:16:40');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2485420366', 'physics', 'GLEAM v3: satellite-based land evaporation and root-zone soil moisture', 'Abstract. The Global Land Evaporation Amsterdam Model (GLEAM) is a set of algorithms dedicated to the estimation of terrestrial evaporation and root-zone soil moisture from satellite data. Ever since…', '2017', 2017, 2524, 2524, 'https://www.geoscientific-model-development.net/graphic_egu_claim_logo_blue.png', 'https://doi.org/10.5194/gmd-10-1903-2017', 'repository', 'article', 'Geoscientific model development', '["Brecht Martens","Diego G. Miralles","Hans Lievens","Robin van der Schalie","Richard de Jeu","Diego Fernández‐Prieto","Hylke E. Beck","Wouter Dorigo","Niko E. C. Verhoest"]', 'physics', 'Abstract. The Global Land Evaporation Amsterdam Model (GLEAM) is a set of algorithms dedicated to the estimation of terrestrial evaporation and root-zone soil moisture from satellite data. Ever since its development in 2011, the model has been regularly revised, aiming at the optimal incorporation of new satellite-observed geophysical variables, and improving the representation of physical processes. In this study, the next version of this model (v3) is presented. Key changes relative to the previous version include (1) a revised formulation of the evaporative stress, (2) an optimized drainage algorithm, and (3) a new soil moisture data assimilation system. GLEAM v3 is used to produce three new data sets of terrestrial evaporation and root-zone soil moisture, including a 36-year data set spanning 1980–2015, referred to as v3a (based on satellite-observed soil moisture, vegetation optical depth and snow-water equivalent, reanalysis air temperature and radiation, and a multi-source precipitation product), and two satellite-based data sets. The latter share most of their forcing, except for the vegetation optical depth and soil moisture, which are based on observations from different passive and active C- and L-band microwave sensors (European Space Agency Climate Change Initiative, ESA CCI) for the v3b data set (spanning 2003–2015) and observations from the Soil Moisture and Ocean Salinity (SMOS) satellite in the v3c data set (spanning 2011–2015). Here, these three data sets are described in detail, compared against analogous data sets generated using the previous version of GLEAM (v2), and validated against measurements from 91 eddy-covariance towers and 2325 soil moisture sensors across a broad range of ecosystems. Results indicate that the quality of the v3 soil moisture is consistently better than the one from v2: average correlations against in situ surface soil moisture measurements increase from 0.61 to 0.64 in the case of the v3a data set and the representation of soil moisture in the second layer improves as well, with correlations increasing from 0.47 to 0.53. Similar improvements are observed for the v3b and c data sets. Despite regional differences, the quality of the evaporation fluxes remains overall similar to the one obtained using the previous version of GLEAM, with average correlations against eddy-covariance measurements ranging between 0.78 and 0.81 for the different data sets. These global data sets of terrestrial evaporation and root-zone soil moisture are now openly available at www.GLEAM.eu and may be used for large-scale hydrological applications, climate studies, or research on land–atmosphere feedbacks.', '2026-07-07 23:16:41');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2087606978', 'physics', 'To Be or Not To Be Pseudocapacitive?', 'International audience', '2015', 2015, 2455, 2455, 'https://content.cld.iop.org/journals/1945-7111/162/5/A5185/revision1/A5185fig1.jpeg', 'https://hal.science/hal-01725986', 'repository', 'article', 'Journal of The Electrochemical Society', '["Thierry Brousse","Daniel Bélanger","Jeffrey W. Long"]', 'physics', 'International audience', '2026-07-07 23:17:09');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4200599926', 'physics', 'The HITRAN2020 molecular spectroscopic database', 'The HITRAN database is a compilation of molecular spectroscopic parameters. It was established in the early 1970s and is used by various computer codes to predict and simulate the transmission and…', '2021', 2021, 2371, 2371, 'https://ars.els-cdn.com/content/image/1-s2.0-S0022407321004416-gr1.jpg', 'https://hal.science/hal-03388954', 'repository', 'article', 'Journal of Quantitative Spectroscopy and Radiative Transfer', '["Iouli E. Gordon","Laurence S. Rothman","Robert J. Hargreaves","Robab Hashemi","E.V. Karlovets","Frances Skinner","E. K. Conway","C. Hill","Roman V. Kochanov","Yan Tan","Piotr Wcisło","Artem A. Finenko","Kenneth E. Nelson","P. F. Bernath","Manfred Birk","Vincent Boudon","A. Campargue","K. Chance","A. Coustenis","Brian J. Drouin","J.‐M. Flaud","Robert R. Gamache","Joseph T. Hodges","D. Jacquemart","E. J. Mlawer","A.V. Nikitin","V. I. Perevalov","M. Rotger","Jonathan Tennyson","Geoffrey C. Toon","H. Tran","Vladimir G. Tyuterev","Erin M. Adkins","Ashley Baker","A. Barbé","Elisabetta Canè","Attila G. Császár","A.S. Dudaryonok","O. V. Egorov","Adam J. Fleisher","Hélène Fleurbaey","Aleksandra Foltynowicz","Tibor Furtenbacher","Jeremy J. Harrison","Jean‐Michel Hartmann","V.–M. Horneman","Xinchuan Huang","Tijs Karman","Joshua Karns","S. Kassi","Isabelle Kleiner","Vincent Kofman","F. Kwabia–Tchana","N.N. Lavrentieva","T.J. Lee","David A. Long","A.A. Lukashevskaya","O.M. Lyulin","Vladimir Yu. Makhnev","Wyatt Matt","S. T. Massie","Mattia Melosso","С.Н. Михайленко","D. Mondelain","H. S. P. Müller","O. V. Naumenko","A. Perrin","O. L. Polyansky","E. Raddaoui","Paul L. Raston","Zachary Reed","M. Rey","C. Richard","Roland Tóbiás","Ibrahim Sadiek","David W. Schwenke","E. Starikova","Keeyoon Sung","Filippo Tamassia","S.A. Tashkun","J. Vander Auwera","I. A. Vasilenko","A. A. Vigasin","G. L. Villanueva","Bastien Vispoel","Georg Wagner","Andrey Yachmenev","S. N. Yurchenko"]', 'physics', 'The HITRAN database is a compilation of molecular spectroscopic parameters. It was established in the early 1970s and is used by various computer codes to predict and simulate the transmission and emission of light in gaseous media (with an emphasis on terrestrial and planetary atmospheres). The HITRAN compilation is composed of five major components: the line-by-line spectroscopic parameters required for high-resolution radiative-transfer codes, experimental infrared absorption cross-sections (for molecules where it is not yet feasible for representation in a line-by-line form), collision-induced absorption data, aerosol indices of refraction, and general tables (including partition sums) that apply globally to the data. This paper describes the contents of the 2020 quadrennial edition of HITRAN. The HITRAN2020 edition takes advantage of recent experimental and theoretical data that were meticulously validated, in particular, against laboratory and atmospheric spectra. The new edition replaces the previous HITRAN edition of 2016 (including its updates during the intervening years). All five components of HITRAN have undergone major updates. In particular, the extent of the updates in the HITRAN2020 edition range from updating a few lines of specific molecules to complete replacements of the lists, and also the introduction of additional isotopologues and new (to HITRAN) molecules: SO, CH3F, GeH4, CS2, CH3I and NF3. Many new vibrational bands were added, extending the spectral coverage and completeness of the line lists. Also, the accuracy of the parameters for major atmospheric absorbers has been increased substantially, often featuring sub-percent uncertainties. Broadening parameters associated with the ambient pressure of water vapor were introduced to HITRAN for the first time and are now available for several molecules. The HITRAN2020 edition continues to take advantage of the relational structure and efficient interface available at www.hitran.org and the HITRAN Application Programming Interface (HAPI). The functionality of both tools has been extended for the new edition.', '2026-07-07 23:17:36');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2734584755', 'physics', 'Ultra-high-rate pseudocapacitive energy storage in two-dimensional transition metal carbides', 'Ultra-high-rate pseudocapacitive energy storage in two-dimensional transition metal carbides', '2017', 2017, 2288, 2288, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1038/nenergy.2017.105.g001', 'https://hal.science/hal-02007475', 'repository', 'article', 'Nature Energy', '["Maria R. Lukatskaya","Sankalp Kota","Zifeng Lin","Meng‐Qiang Zhao","Netanel Shpigel","Mikhael D. Levi","Joseph Halim","Pierre‐Louis Taberna","Michel W. Barsoum","Patrice Simon","Yury Gogotsi"]', 'physics', NULL, '2026-07-07 23:17:56');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2333787883', 'physics', 'The ReaxFF reactive force-field: development, applications and future directions', 'Abstract The reactive force-field (ReaxFF) interatomic potential is a powerful computational tool for exploring, developing and optimizing material properties. Methods based on the principles of…', '2016', 2016, 2284, 2284, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnpjcompumats.2015.11/MediaObjects/41524_2016_Article_BFnpjcompumats201511_Fig1_HTML.jpg', 'https://doi.org/10.1038/npjcompumats.2015.11', 'repository', 'article', 'npj Computational Materials', '["Thomas P. Senftle","Sungwook Hong","Md Mahbubul Islam","Sudhir B. Kylasa","Yuanxia Zheng","Yun Kyung Shin","Chad E. Junkermeier","Roman Engel‐Herbert","Michael J. Janik","Hasan Metin Aktulga","Toon Verstraelen","Ananth Grama","Adri C. T. van Duin"]', 'physics', 'Abstract The reactive force-field (ReaxFF) interatomic potential is a powerful computational tool for exploring, developing and optimizing material properties. Methods based on the principles of quantum mechanics (QM), while offering valuable theoretical guidance at the electronic level, are often too computationally intense for simulations that consider the full dynamic evolution of a system. Alternatively, empirical interatomic potentials that are based on classical principles require significantly fewer computational resources, which enables simulations to better describe dynamic processes over longer timeframes and on larger scales. Such methods, however, typically require a predefined connectivity between atoms, precluding simulations that involve reactive events. The ReaxFF method was developed to help bridge this gap. Approaching the gap from the classical side, ReaxFF casts the empirical interatomic potential within a bond-order formalism, thus implicitly describing chemical bonding without expensive QM calculations. This article provides an overview of the development, application, and future directions of the ReaxFF method.', '2026-07-07 23:18:00');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2526646482', 'physics', 'Memristors with diffusive dynamics as synaptic emulators for neuromorphic computing', 'Memristors with diffusive dynamics as synaptic emulators for neuromorphic computing', '2016', 2016, 2301, 2301, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnmat4756/MediaObjects/41563_2017_Article_BFnmat4756_Fig1_HTML.jpg', 'https://pubmed.ncbi.nlm.nih.gov/27669052', 'repository', 'article', 'Nature Materials', '["Zhongrui Wang","Saumil Joshi","Sergey Savel’ev","Hao Jiang","Rivu Midya","Peng Lin","Miao Hu","Ning Ge","John Paul Strachan","Zhiyong Li","Qing Wu","Mark Barnell","Geng‐Lin Li","Huolin L. Xin","R. Stanley Williams","Qiangfei Xia","J. Joshua Yang"]', 'physics', NULL, '2026-07-07 23:18:01');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3192855505', 'physics', 'CB-SEM vs PLS-SEM methods for research in social sciences and technology forecasting', 'This study compares the two widely used methods of Structural Equation Modeling (SEM): Covariance based Structural Equation Modeling (CB-SEM) and Partial Least Squares based Structural Equation…', '2021', 2021, 2267, 2267, 'https://ars.els-cdn.com/content/image/1-s2.0-S0040162521005254-gr1.jpg', 'https://doi.org/10.1016/j.techfore.2021.121092', 'repository', 'article', 'Technological Forecasting and Social Change', '["Ganesh Dash","Justin Paul"]', 'physics', 'This study compares the two widely used methods of Structural Equation Modeling (SEM): Covariance based Structural Equation Modeling (CB-SEM) and Partial Least Squares based Structural Equation Modeling (PLS-SEM). The first approach is based on covariance, and the second one is based on variance (partial least squares). It further assesses the difference between PLS and Consistent PLS algorithms. To assess the same, empirical data is used. Four hundred sixty-six respondents from India, Saudi Arabia, South Africa, the USA, and few other countries are considered. The structural model is tested with the help of both approaches. Findings indicate that the item loadings are usually higher in PLS-SEM than CB-SEM. The structural relationship is closer to CB-SEM if a consistent PLS algorithm is undertaken in PLS-SEM. It is also found that average variance extracted (AVE) and composite reliability (CR) values are higher in the PLS-SEM method, indicating better construct reliability and validity. CB-SEM is better in providing model fit indices, whereas PLS-SEM fit indices are still evolving. CB-SEM models are better for factor-based models like ours, whereas composite-based models provide excellent outcomes in PLS-SEM. This study contributes to the existing literature significantly by providing an empirical comparison of all the three methods for predictive research domains. The multi-national context makes the study relevant and replicable universally. We call for researchers to revisit the widely used SEM approaches, especially using appropriate SEM methods for factor-based and composite-based models.', '2026-07-07 23:18:16');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3159296886', 'physics', 'Hydrogen energy systems: A critical review of technologies, applications, trends and challenges', 'The global energy transition towards a carbon neutral society requires a profound transformation of electricity generation and consumption, as well as of electric power systems. Hydrogen has an…', '2021', 2021, 2209, 2209, 'https://ars.els-cdn.com/content/image/1-s2.0-S1364032121004688-gr1.jpg', 'https://hal.science/hal-03221850', 'repository', 'review', 'Renewable and Sustainable Energy Reviews', '["Meiling Yue","Hugo Lambert","Elodie Pahon","Robin Roche","Samir Jemeï","Daniel Hissel"]', 'physics', 'The global energy transition towards a carbon neutral society requires a profound transformation of electricity generation and consumption, as well as of electric power systems. Hydrogen has an important potential to accelerate the process of scaling up clean and renewable energy, however its integration in power systems remains little studied. This paper reviews the current progress and outlook of hydrogen technologies and their application in power systems for hydrogen production, re-electrification and storage. The characteristics of electrolysers and fuel cells are demonstrated with experimental data and the deployments of hydrogen for energy storage, power-to-gas, co- and tri-generation and transportation are investigated using examples from worldwide projects. The current techno-economic status of these technologies and applications is presented, in which cost, efficiency and durability are identified as the main critical aspects. This is also confirmed by the results of a statistical analysis of the literature. Finally, conclusions show that continuous efforts on performance improvements, scale ramp-up, technical prospects and political support are required to enable a cost-competitive hydrogen economy.', '2026-07-07 23:18:46');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3046546345', 'physics', 'Perspectives for electrochemical capacitors and related devices', 'Perspectives for electrochemical capacitors and related devices', '2020', 2020, 2123, 2123, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1038/s41563-020-0747-z.g001', 'https://hal.science/hal-03054220', 'repository', 'review', 'Nature Materials', '["Patrice Simon","Yury Gogotsi"]', 'physics', NULL, '2026-07-07 23:19:04');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2533230523', 'physics', 'The Global Burden of Latent Tuberculosis Infection: A Re-estimation Using Mathematical Modelling', 'BACKGROUND: The existing estimate of the global burden of latent TB infection (LTBI) as "one-third" of the world population is nearly 20 y old. Given the importance of controlling LTBI as part of the…', '2016', 2016, 2086, 2086, 'https://journals.plos.org/plosmedicine/article/figure/image?size=large&id=10.1371/journal.pmed.1002152.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5079585', 'pmc', 'review', 'PLoS Medicine', '["Rein M G J Houben","Peter J. Dodd"]', 'physics', 'BACKGROUND: The existing estimate of the global burden of latent TB infection (LTBI) as "one-third" of the world population is nearly 20 y old. Given the importance of controlling LTBI as part of the End TB Strategy for eliminating TB by 2050, changes in demography and scientific understanding, and progress in TB control, it is important to re-assess the global burden of LTBI. METHODS AND FINDINGS: We constructed trends in annual risk in infection (ARI) for countries between 1934 and 2014 using a combination of direct estimates of ARI from LTBI surveys (131 surveys from 1950 to 2011) and indirect estimates of ARI calculated from World Health Organisation (WHO) estimates of smear positive TB prevalence from 1990 to 2014. Gaussian process regression was used to generate ARIs for country-years without data and to represent uncertainty. Estimated ARI time-series were applied to the demography in each country to calculate the number and proportions of individuals infected, recently infected (infected within 2 y), and recently infected with isoniazid (INH)-resistant strains. Resulting estimates were aggregated by WHO region. We estimated the contribution of existing infections to TB incidence in 2035 and 2050. In 2014, the global burden of LTBI was 23.0% (95% uncertainty interval [UI]: 20.4%-26.4%), amounting to approximately 1.7 billion people. WHO South-East Asia, Western-Pacific, and Africa regions had the highest prevalence and accounted for around 80% of those with LTBI. Prevalence of recent infection was 0.8% (95% UI: 0.7%-0.9%) of the global population, amounting to 55.5 (95% UI: 48.2-63.8) million individuals currently at high risk of TB disease, of which 10.9% (95% UI:10.2%-11.8%) was isoniazid-resistant. Current LTBI alone, assuming no additional infections from 2015 onwards, would be expected to generate TB incidences in the region of 16.5 per 100,000 per year in 2035 and 8.3 per 100,000 per year in 2050. Limitations included the quantity and methodological heterogeneity of direct ARI data, and limited evidence to inform on potential clearance of LTBI. CONCLUSIONS: We estimate that approximately 1.7 billion individuals were latently infected with Mycobacterium tuberculosis (M.tb) globally in 2014, just under a quarter of the global population. Investment in new tools to improve diagnosis and treatment of those with LTBI at risk of progressing to disease is urgently needed to address this latent reservoir if the 2050 target of eliminating TB is to be reached.', '2026-07-07 23:19:30');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2098774185', 'physics', 'Maximum Entropy Inverse Reinforcement Learning', 'Recent research has shown the beneﬁt of framing problems of imitation learning as solutions to Markov Decision Problems. This approach reduces learning to the problem of re- covering a utility…', '2018', 2018, 2062, 2062, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1184/r1/6555512.g001', 'https://doi.org/10.1184/r1/6555512', 'repository', 'article', 'Research Showcase @ Carnegie Mellon University (Carnegie Mellon University)', '["Brian D. Ziebart","Andrew L. Maas","J. Andrew Bagnell","Anind K. Dey"]', 'physics', 'Recent research has shown the beneﬁt of framing problems of imitation learning as solutions to Markov Decision Problems. This approach reduces learning to the problem of re- covering a utility function that makes the behavior induced by a near-optimal policy closely mimic demonstrated behavior. In this work, we develop a probabilistic approach based on the principle of maximum entropy. Our approach provides a well-deﬁned, globally normalized distribution over decision sequences, while providing the same performance guarantees as existing methods. We develop our technique in the context of modeling real world navigation and driving behaviors where collected data is inherently noisy and imperfect. Our probabilistic approach enables modeling of route preferences as well as a powerful new approach to inferring destinations and routes based on partial trajectories.', '2026-07-07 23:19:30');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2775708988', 'physics', 'DeePMD-kit: A deep learning package for many-body potential energy representation and molecular dynamics', 'DeePMD-kit: A deep learning package for many-body potential energy representation and molecular dynamics', '2018', 2018, 2048, 2048, 'https://ars.els-cdn.com/content/image/1-s2.0-S0010465518300882-fx1.jpg', 'http://arxiv.org/abs/1712.03641', 'arxiv', 'article', 'Computer Physics Communications', '["Han Wang","Linfeng Zhang","Jiequn Han","E Weinan"]', 'physics', NULL, '2026-07-07 23:19:46');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2622680715', 'physics', 'Review—SEI: Past, Present and Future', 'The Solid-Electrolyte-Interphase (SEI) model for non-aqueous alkali-metal batteries constitutes a paradigm change in the understanding of lithium batteries and has thus enabled the development of…', '2017', 2017, 2046, 2046, 'https://content.cld.iop.org/journals/1945-7111/164/7/A1703/revision1/A1703fig1.jpeg', 'https://doi.org/10.1149/2.1441707jes', 'repository', 'article', 'Journal of The Electrochemical Society', '["E. Peled","Svetlana Menkin"]', 'physics', 'The Solid-Electrolyte-Interphase (SEI) model for non-aqueous alkali-metal batteries constitutes a paradigm change in the understanding of lithium batteries and has thus enabled the development of safer, durable, higher-power and lower-cost lithium batteries for portable and EV applications. Prior to the publication of the SEI model (1979), researchers used the Butler-Volmer equation, in which a direct electron transfer from the electrode to lithium cations in the solution is assumed. The SEI model proved that this is a mistaken concept and that, in practice, the transfer of electrons from the electrode to the solution in a lithium battery, must be prevented, since it will result in fast self-discharge of the active materials and poor battery performance. This model provides [E. Peled, in "Lithium Batteries," J.P. Gabano (ed), Academic Press, (1983), E. Peled, J. Electrochem. Soc., 126, 2047 (1979).] new equations for: electrode kinetics (io and b), anode corrosion, SEI resistivity and growth rate and irreversible capacity loss of lithium-ion batteries. This model became a cornerstone in the science and technology of lithium batteries. This paper reviews the past, present and the future of SEI batteries.', '2026-07-07 23:19:47');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1948094720', 'physics', 'Global Morbidity and Mortality of Leptospirosis: A Systematic Review', 'BACKGROUND: Leptospirosis, a spirochaetal zoonosis, occurs in diverse epidemiological settings and affects vulnerable populations, such as rural subsistence farmers and urban slum dwellers. Although…', '2015', 2015, 1971, 1971, 'https://journals.plos.org/plosntds/article/figure/image?size=large&id=10.1371/journal.pntd.0003898.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4574773', 'pmc', 'review', 'PLoS neglected tropical diseases', '["Federico Costa","José E. Hagan","Juan Ignácio Calcagno","Michael J. Kane","Paul R. Torgerson","Martha Sílvia Martinez-Silveira","Cláudia Stein","Bernadette Abela-Ridder","Albert I. Ko"]', 'physics', 'BACKGROUND: Leptospirosis, a spirochaetal zoonosis, occurs in diverse epidemiological settings and affects vulnerable populations, such as rural subsistence farmers and urban slum dwellers. Although leptospirosis is a life-threatening disease and recognized as an important cause of pulmonary haemorrhage syndrome, the lack of global estimates for morbidity and mortality has contributed to its neglected disease status. METHODOLOGY/PRINCIPAL FINDINGS: We conducted a systematic review of published morbidity and mortality studies and databases to extract information on disease incidence and case fatality ratios. Linear regression and Monte Carlo modelling were used to obtain age and gender-adjusted estimates of disease morbidity for countries and Global Burden of Disease (GBD) and WHO regions. We estimated mortality using models that incorporated age and gender-adjusted disease morbidity and case fatality ratios. The review identified 80 studies on disease incidence from 34 countries that met quality criteria. In certain regions, such as Africa, few quality assured studies were identified. The regression model, which incorporated country-specific variables of population structure, life expectancy at birth, distance from the equator, tropical island, and urbanization, accounted for a significant proportion (R(2) = 0.60) of the variation in observed disease incidence. We estimate that there were annually 1.03 million cases (95% CI 434,000-1,750,000) and 58,900 deaths (95% CI 23,800-95,900) due to leptospirosis worldwide. A large proportion of cases (48%, 95% CI 40-61%) and deaths (42%, 95% CI 34-53%) were estimated to occur in adult males with age of 20-49 years. Highest estimates of disease morbidity and mortality were observed in GBD regions of South and Southeast Asia, Oceania, Caribbean, Andean, Central, and Tropical Latin America, and East Sub-Saharan Africa. CONCLUSIONS/SIGNIFICANCE: Leptospirosis is among the leading zoonotic causes of morbidity worldwide and accounts for numbers of deaths, which approach or exceed those for other causes of haemorrhagic fever. Highest morbidity and mortality were estimated to occur in resource-poor countries, which include regions where the burden of leptospirosis has been underappreciated.', '2026-07-07 23:20:34');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W773815729', 'physics', 'High-quality bulk hybrid perovskite single crystals within minutes by inverse temperature crystallization', 'Single crystals of methylammonium lead trihalide perovskites (MAPbX3; MA = CH3NH3(+), X = Br(-) or I(-)) have shown remarkably low trap density and charge transport properties; however, growth of…', '2015', 2015, 1887, 1887, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fncomms8586/MediaObjects/41467_2015_Article_BFncomms8586_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4544059', 'pmc', 'article', 'Nature Communications', '["Makhsud I. Saidaminov","Ahmed L. Abdelhady","Banavoth Murali","Erkki Alarousu","V. M. Burlakov","Wei Peng","İbrahim Dursun","Lingfei Wang","Yao He","Giacomo Maculan","Alain Goriely","Tom Wu","Omar F. Mohammed","Osman M. Bakr"]', 'physics', 'Single crystals of methylammonium lead trihalide perovskites (MAPbX3; MA = CH3NH3(+), X = Br(-) or I(-)) have shown remarkably low trap density and charge transport properties; however, growth of such high-quality semiconductors is a time-consuming process. Here we present a rapid crystal growth process to obtain MAPbX3 single crystals, an order of magnitude faster than previous reports. The process is based on our observation of the substantial decrease of MAPbX3 solubility, in certain solvents, at elevated temperatures. The crystals can be both size- and shape-controlled by manipulating the different crystallization parameters. Despite the rapidity of the method, the grown crystals exhibit transport properties and trap densities comparable to the highest quality MAPbX3 reported to date. The phenomenon of inverse or retrograde solubility and its correlated inverse temperature crystallization strategy present a major step forward for advancing the field on perovskite crystallization.', '2026-07-07 23:21:29');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2749576414', 'physics', 'Molecular magnetic hysteresis at 60 kelvin in dysprosocenium', 'Molecular magnetic hysteresis at 60 kelvin in dysprosocenium', '2017', 2017, 1902, 1902, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature23447/MediaObjects/41586_2017_Article_BFnature23447_Fig1_HTML.jpg', 'https://pubmed.ncbi.nlm.nih.gov/28836589', 'repository', 'article', 'Nature', '["Conrad A. P. Goodwin","Fabrizio Ortu","Daniel Reta","Nicholas F. Chilton","David P. Mills"]', 'physics', NULL, '2026-07-07 23:21:30');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2755626276', 'physics', 'Incidence and Trends of Sepsis in US Hospitals Using Clinical vs Claims Data, 2009-2014', 'Importance: Estimates from claims-based analyses suggest that the incidence of sepsis is increasing and mortality rates from sepsis are decreasing. However, estimates from claims data may lack…', '2017', 2017, 1887, 1887, 'https://cdn.ncbi.nlm.nih.gov/pmc/blobs/548c/5710396/e18b6246d899/jama-318-1241-g001.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5710396', 'pmc', 'article', 'JAMA', '["Chanu Rhee","Raymund Dantes","Lauren Epstein","David J. Murphy","Christopher Seymour","Theodore J. Iwashyna","Sameer S. Kadri","Derek C. Angus","Robert L. Danner","Anthony E. Fiore","John A. Jernigan","Greg S. Martin","Edward Septimus","David K. Warren","Anita Karcz","Christina K. Chan","John T. Menchaca","Rui Wang","Susan Gruber","Michael Klompas"]', 'physics', 'Importance: Estimates from claims-based analyses suggest that the incidence of sepsis is increasing and mortality rates from sepsis are decreasing. However, estimates from claims data may lack clinical fidelity and can be affected by changing diagnosis and coding practices over time. Objective: To estimate the US national incidence of sepsis and trends using detailed clinical data from the electronic health record (EHR) systems of diverse hospitals. Design, Setting, and Population: Retrospective cohort study of adult patients admitted to 409 academic, community, and federal hospitals from 2009-2014. Exposures: Sepsis was identified using clinical indicators of presumed infection and concurrent acute organ dysfunction, adapting Third International Consensus Definitions for Sepsis and Septic Shock (Sepsis-3) criteria for objective and consistent EHR-based surveillance. Main Outcomes and Measures: Sepsis incidence, outcomes, and trends from 2009-2014 were calculated using regression models and compared with claims-based estimates using International Classification of Diseases, Ninth Revision, Clinical Modification codes for severe sepsis or septic shock. Case-finding criteria were validated against Sepsis-3 criteria using medical record reviews. Results: A total of 173 690 sepsis cases (mean age, 66.5 [SD, 15.5] y; 77 660 [42.4%] women) were identified using clinical criteria among 2 901 019 adults admitted to study hospitals in 2014 (6.0% incidence). Of these, 26 061 (15.0%) died in the hospital and 10 731 (6.2%) were discharged to hospice. From 2009-2014, sepsis incidence using clinical criteria was stable (+0.6% relative change/y [95% CI, -2.3% to 3.5%], P =.67) whereas incidence per claims increased (+10.3%/y [95% CI, 7.2% to 13.3%], P <.001). In-hospital mortality using clinical criteria declined (-3.3%/y [95% CI, -5.6% to -1.0%], P =.004), but there was no significant change in the combined outcome of death or discharge to hospice (-1.3%/y [95% CI, -3.2% to 0.6%], P =.19). In contrast, mortality using claims declined significantly (-7.0%/y [95% CI, -8.8% to -5.2%], P <.001), as did death or discharge to hospice (-4.5%/y [95% CI, -6.1% to -2.8%], P <.001). Clinical criteria were more sensitive in identifying sepsis than claims (69.7% [95% CI, 52.9% to 92.0%] vs 32.3% [95% CI, 24.4% to 43.0%], P <.001), with comparable positive predictive value (70.4% [95% CI, 64.0% to 76.8%] vs 75.2% [95% CI, 69.8% to 80.6%], P =.23). Conclusions and Relevance: In clinical data from 409 hospitals, sepsis was present in 6% of adult hospitalizations, and in contrast to claims-based analyses, neither the incidence of sepsis nor the combined outcome of death or discharge to hospice changed significantly between 2009-2014. The findings also suggest that EHR-based clinical data provide more objective estimates than claims-based data for sepsis surveillance.', '2026-07-07 23:21:33');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4285794683', 'physics', 'Root-mean-square error (RMSE) or mean absolute error (MAE): when to use them or not', 'Abstract. The root-mean-squared error (RMSE) and mean absolute error (MAE) are widely used metrics for evaluating models. Yet, there remains enduring confusion over their use, such that a standard…', '2022', 2022, 1764, 1764, 'https://www.geoscientific-model-development.net/graphic_egu_claim_logo_blue.png', 'https://doi.org/10.5194/gmd-15-5481-2022', 'repository', 'article', 'Geoscientific model development', '["Timothy Hodson"]', 'physics', 'Abstract. The root-mean-squared error (RMSE) and mean absolute error (MAE) are widely used metrics for evaluating models. Yet, there remains enduring confusion over their use, such that a standard practice is to present both, leaving it to the reader to decide which is more relevant. In a recent reprise to the 200-year debate over their use, Willmott and Matsuura (2005) and Chai and Draxler (2014) give arguments for favoring one metric or the other. However, this comparison can present a false dichotomy. Neither metric is inherently better: RMSE is optimal for normal (Gaussian) errors, and MAE is optimal for Laplacian errors. When errors deviate from these distributions, other metrics are superior.', '2026-07-07 23:23:08');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3209678193', 'physics', 'Cantera: An Object-oriented Software Toolkit for Chemical Kinetics, Thermodynamics, and Transport Processes', 'Cantera is a suite of object-oriented software tools for problems involving chemical kinetics, thermodynamics, and/or transport processes. Cantera provides types (or classes) of objects representing…', '2018', 2018, 1738, 1738, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.5281/zenodo.1174508.g001', 'https://zenodo.org/record/1174508', 'repository', 'article', 'Figshare', '["David G. Goodwin","Raymond L. Speth","Harry K. Moffat","Bryan W. Weber"]', 'physics', 'Cantera is a suite of object-oriented software tools for problems involving chemical kinetics, thermodynamics, and/or transport processes. Cantera provides types (or classes) of objects representing phases of matter, interfaces between these phases, reaction managers, time-dependent reactor networks, and steady one-dimensional reacting flows. Cantera is currently used for applications including combustion, detonations, electrochemical energy conversion and storage, fuel cells, batteries, aqueous electrolyte solutions, plasmas, and thin film deposition.', '2026-07-07 23:23:35');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2210337079', 'physics', 'Prevalence of Total Hip and Knee Replacement in the United States', 'BACKGROUND: Descriptive epidemiology of total joint replacement procedures is limited to annual procedure volumes (incidence). The prevalence of the growing number of individuals living with a total…', '2015', 2015, 1733, 1733, 'https://cdn.ncbi.nlm.nih.gov/pmc/blobs/f0a1/4551172/c1e2a076d7e1/jbjsam.n01141fig1a.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4551172', 'pmc', 'article', 'Journal of Bone and Joint Surgery', '["Hilal Maradit Kremers","Dirk R. Larson","Cynthia S. Crowson","Walter K. Kremers","Raynard Washington","Claudia Steiner","William A. Jiranek","Daniel J. Berry"]', 'physics', 'BACKGROUND: Descriptive epidemiology of total joint replacement procedures is limited to annual procedure volumes (incidence). The prevalence of the growing number of individuals living with a total hip or total knee replacement is currently unknown. Our objective was to estimate the prevalence of total hip and total knee replacement in the United States. METHODS: Prevalence was estimated using the counting method by combining historical incidence data from the National Hospital Discharge Survey and the Healthcare Cost and Utilization Project (HCUP) State Inpatient Databases from 1969 to 2010 with general population census and mortality counts. We accounted for relative differences in mortality rates between those who have had total hip or knee replacement and the general population. RESULTS: The 2010 prevalence of total hip and total knee replacement in the total U.S. population was 0.83% and 1.52%, respectively. Prevalence was higher among women than among men and increased with age, reaching 5.26% for total hip replacement and 10.38% for total knee replacement at eighty years. These estimates corresponded to 2.5 million individuals (1.4 million women and 1.1 million men) with total hip replacement and 4.7 million individuals (3.0 million women and 1.7 million men) with total knee replacement in 2010. Secular trends indicated a substantial rise in prevalence over time and a shift to younger ages. CONCLUSIONS: Around 7 million Americans are living with a hip or knee replacement, and consequently, in most cases, are mobile, despite advanced arthritis. These numbers underscore the substantial public health impact of total hip and knee arthroplasties.', '2026-07-07 23:23:39');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3048501727', 'physics', 'The shared socio-economic pathway (SSP) greenhouse gas concentrations and their extensions to 2500', 'Abstract. Anthropogenic increases in atmospheric greenhouse gas concentrations are the main driver of current and future climate change. The integrated assessment community has quantified…', '2020', 2020, 1728, 1728, 'https://www.geoscientific-model-development.net/graphic_egu_claim_logo_blue.png', 'https://doi.org/10.5194/gmd-13-3571-2020', 'repository', 'article', 'Geoscientific model development', '["Malte Meinshausen","Zebedee Nicholls","Jared Lewis","Matthew Gidden","Elisabeth Vogel","Mandy Freund","Urs Beyerle","Claudia Gessner","Alexander Nauels","Nico Bauer","Josep G. Canadell","J. S. Daniel","Andrew John","Paul B. Krummel","Gunnar Luderer","Nicolai Meinshausen","S. A. Montzka","P. J. Rayner","Stefan Reimann","Steven J. Smith","Marten van den Berg","Guus J. M. Velders","Martin K. Vollmer","Ray H. J. Wang"]', 'physics', 'Abstract. Anthropogenic increases in atmospheric greenhouse gas concentrations are the main driver of current and future climate change. The integrated assessment community has quantified anthropogenic emissions for the shared socio-economic pathway (SSP) scenarios, each of which represents a different future socio-economic projection and political environment. Here, we provide the greenhouse gas concentrations for these SSP scenarios – using the reduced-complexity climate–carbon-cycle model MAGICC7.0. We extend historical, observationally based concentration data with SSP concentration projections from 2015 to 2500 for 43 greenhouse gases with monthly and latitudinal resolution. CO2 concentrations by 2100 range from 393 to 1135 ppm for the lowest (SSP1-1.9) and highest (SSP5-8.5) emission scenarios, respectively. We also provide the concentration extensions beyond 2100 based on assumptions regarding the trajectories of fossil fuels and land use change emissions, net negative emissions, and the fraction of non-CO2 emissions. By 2150, CO2 concentrations in the lowest emission scenario are approximately 350 ppm and approximately plateau at that level until 2500, whereas the highest fossil-fuel-driven scenario projects CO2 concentrations of 1737 ppm and reaches concentrations beyond 2000 ppm by 2250. We estimate that the share of CO2 in the total radiative forcing contribution of all considered 43 long-lived greenhouse gases increases from 66 % for the present day to roughly 68 % to 85 % by the time of maximum forcing in the 21st century. For this estimation, we updated simple radiative forcing parameterizations that reflect the Oslo Line-By-Line model results. In comparison to the representative concentration pathways (RCPs), the five main SSPs (SSP1-1.9, SSP1-2.6, SSP2-4.5, SSP3-7.0, and SSP5-8.5) are more evenly spaced and extend to lower 2100 radiative forcing and temperatures. Performing two pairs of six-member historical ensembles with CESM1.2.2, we estimate the effect on surface air temperatures of applying latitudinally and seasonally resolved GHG concentrations. We find that the ensemble differences in the March–April–May (MAM) season provide a regional warming in higher northern latitudes of up to 0.4 K over the historical period, latitudinally averaged of about 0.1 K, which we estimate to be comparable to the upper bound (∼5 % level) of natural variability. In comparison to the comparatively straight line of the last 2000 years, the greenhouse gas concentrations since the onset of the industrial period and this studies'' projections over the next 100 to 500 years unequivocally depict a “hockey-stick” upwards shape. The SSP concentration time series derived in this study provide a harmonized set of input assumptions for long-term climate science analysis; they also provide an indication of the wide set of futures that societal developments and policy implementations can lead to – ranging from multiple degrees of future warming on the one side to approximately 1.5 ∘C warming on the other.', '2026-07-07 23:23:42');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4281790889', 'chemistry', 'ColabFold: making protein folding accessible to all', 'ColabFold offers accelerated prediction of protein structures and complexes by combining the fast homology search of MMseqs2 with AlphaFold2 or RoseTTAFold. ColabFold''s 40-60-fold faster search and…', '2022', 2022, 9738, 9738, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41592-022-01488-1/MediaObjects/41592_2022_1488_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/9184281', 'pmc', 'article', 'Nature Methods', '["Milot Mirdita","Konstantin Schütze","Yoshitaka Moriwaki","Lim Heo","Sergey Ovchinnikov","Martin Steinegger"]', 'chemistry', 'ColabFold offers accelerated prediction of protein structures and complexes by combining the fast homology search of MMseqs2 with AlphaFold2 or RoseTTAFold. ColabFold''s 40-60-fold faster search and optimized model utilization enables prediction of close to 1,000 structures per day on a server with one graphics processing unit. Coupled with Google Colaboratory, ColabFold becomes a free and accessible platform for protein folding. ColabFold is open-source software available at https://github.com/sokrypton/ColabFold and its novel environmental databases are available at https://colabfold.mmseqs.com.', '2026-07-07 23:23:58');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2919115771', 'chemistry', 'Deep learning', 'Deep learning', '2015', 2015, 81967, 81967, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature14539/MediaObjects/41586_2015_BFnature14539_Fig1_HTML.jpg', 'https://hal.science/hal-04206682', 'repository', 'review', 'Nature', '["Yann LeCun","Yoshua Bengio","Geoffrey E. Hinton"]', 'chemistry', NULL, '2026-07-07 23:23:59');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2921966151', 'chemistry', 'Short Chain Fatty Acids (SCFAs)-Mediated Gut Epithelial and Immune Regulation and Its Relevance for Inflammatory Bowel Diseases', 'Ulcerative colitis (UC) and Crohn''s disease (CD), collectively known as Inflammatory Bowel Diseases (IBD), are caused by a complex interplay between genetic, immunologic, microbial and environmental…', '2019', 2019, 3729, 3729, 'https://www.frontiersin.org/files/Articles/424615/fimmu-10-00277-HTML-r1/image_m/fimmu-10-00277-g001.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6421268', 'pmc', 'review', 'Frontiers in Immunology', '["Daniela Parada Venegas","Marjorie K. De la Fuente","Glauben Landskron","Marı́a Julieta González","Rodrigo Quera","Gerard Dijkstra","Hermie J. M. Harmsen","Klaas Nico Faber","Marcela A. Hermoso"]', 'chemistry', 'Ulcerative colitis (UC) and Crohn''s disease (CD), collectively known as Inflammatory Bowel Diseases (IBD), are caused by a complex interplay between genetic, immunologic, microbial and environmental factors. Dysbiosis of the gut microbiome is increasingly considered to be causatively related to IBD and is strongly affected by components of a Western life style. Bacteria that ferment fibers and produce short chain fatty acids (SCFAs) are typically reduced in mucosa and feces of patients with IBD, as compared to healthy individuals. SCFAs, such as acetate, propionate and butyrate, are important metabolites in maintaining intestinal homeostasis. Several studies have indeed shown that fecal SCFAs levels are reduced in active IBD. SCFAs are an important fuel for intestinal epithelial cells and are known to strengthen the gut barrier function. Recent findings, however, show that SCFAs, and in particular butyrate, also have important immunomodulatory functions. Absorption of SCFAs is facilitated by substrate transporters like MCT1 and SMCT1 to promote cellular metabolism. Moreover, SCFAs may signal through cell surface G-protein coupled receptors (GPCRs), like GPR41, GPR43, and GPR109A, to activate signaling cascades that control immune functions. Transgenic mouse models support the key role of these GPCRs in controlling intestinal inflammation. Here, we present an overview of microbial SCFAs production and their effects on the intestinal mucosa with specific emphasis on their relevance for IBD. Moreover, we discuss the therapeutic potential of SCFAs for IBD, either applied directly or by stimulating SCFAs-producing bacteria through pre- or probiotic approaches.', '2026-07-07 23:26:08');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2991106430', 'chemistry', 'DIA-NN: neural networks and interference correction enable deep proteome coverage in high throughput', 'DIA-NN: neural networks and interference correction enable deep proteome coverage in high throughput', '2019', 2019, 3416, 3416, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41592-019-0638-x/MediaObjects/41592_2019_638_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6949130', 'pmc', 'article', 'Nature Methods', '["Vadim Demichev","Christoph B. Messner","Spyros I. Vernardis","Kathryn S. Lilley","Markus Ralser"]', 'chemistry', NULL, '2026-07-07 23:26:33');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3109968655', 'chemistry', 'Plasticenta: First evidence of microplastics in human placenta', 'Microplastics are particles smaller than five millimeters deriving from the degradation of plastic objects present in the environment. Microplastics can move from the environment to living organisms,…', '2020', 2020, 3228, 3228, 'https://ars.els-cdn.com/content/image/1-s2.0-S0160412020322297-gr1.jpg', 'https://pubmed.ncbi.nlm.nih.gov/33395930', 'repository', 'review', 'Environment International', '["Antonio Ragusa","Alessandro Svelato","Criselda Santacroce","Piera Catalano","Valentina Notarstefano","Oliana Carnevali","Fabrizio Papa","Mauro Rongioletti","F. Baiocco","Simonetta Draghi","Elisabetta D’Amore","Denise Rinaldo","Maria Matta","Elisabetta Giorgini"]', 'chemistry', 'Microplastics are particles smaller than five millimeters deriving from the degradation of plastic objects present in the environment. Microplastics can move from the environment to living organisms, including mammals. In this study, six human placentas, collected from consenting women with physiological pregnancies, were analyzed by Raman Microspectroscopy to evaluate the presence of microplastics. In total, 12 microplastic fragments (ranging from 5 to 10 μm in size), with spheric or irregular shape were found in 4 placentas (5 in the fetal side, 4 in the maternal side and 3 in the chorioamniotic membranes); all microplastics particles were characterized in terms of morphology and chemical composition. All of them were pigmented; three were identified as stained polypropylene a thermoplastic polymer, while for the other nine it was possible to identify only the pigments, which were all used for man-made coatings, paints, adhesives, plasters, finger paints, polymers and cosmetics and personal care products.', '2026-07-07 23:26:51');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3023639742', 'chemistry', 'A simple method to assess and report thematic saturation in qualitative research', 'Data saturation is the most commonly employed concept for estimating sample sizes in qualitative research. Over the past 20 years, scholars using both empirical research and mathematical/statistical…', '2020', 2020, 2695, 2695, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0232076.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7200005', 'pmc', 'article', 'PLoS ONE', '["Greg Guest","Emily Namey","Mario Chen"]', 'chemistry', 'Data saturation is the most commonly employed concept for estimating sample sizes in qualitative research. Over the past 20 years, scholars using both empirical research and mathematical/statistical models have made significant contributions to the question: How many qualitative interviews are enough? This body of work has advanced the evidence base for sample size estimation in qualitative inquiry during the design phase of a study, prior to data collection, but it does not provide qualitative researchers with a simple and reliable way to determine the adequacy of sample sizes during and/or after data collection. Using the principle of saturation as a foundation, we describe and validate a simple-to-apply method for assessing and reporting on saturation in the context of inductive thematic analyses. Following a review of the empirical research on data saturation and sample size estimation in qualitative research, we propose an alternative way to evaluate saturation that overcomes the shortcomings and challenges associated with existing methods identified in our review. Our approach includes three primary elements in its calculation and assessment: Base Size, Run Length, and New Information Threshold. We additionally propose a more flexible approach to reporting saturation. To validate our method, we use a bootstrapping technique on three existing thematically coded qualitative datasets generated from in-depth interviews. Results from this analysis indicate the method we propose to assess and report on saturation is feasible and congruent with findings from earlier studies.', '2026-07-07 23:28:15');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3157638995', 'chemistry', 'The Chemistry of Reactive Oxygen Species (ROS) Revisited: Outlining Their Role in Biological Macromolecules (DNA, Lipids and Proteins) and Induced Pathologies', 'Living species are continuously subjected to all extrinsic forms of reactive oxidants and others that are produced endogenously. There is extensive literature on the generation and effects of…', '2021', 2021, 2633, 2633, 'https://pub.mdpi-res.com/ijms/ijms-22-04642/article_deploy/html/images/ijms-22-04642-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8125527', 'pmc', 'review', 'International Journal of Molecular Sciences', '["Celia Andrés","José Manuel Pérez de la Lastra","Francisco J. Plou","Eduardo Pérez‐Lebeña"]', 'chemistry', 'Living species are continuously subjected to all extrinsic forms of reactive oxidants and others that are produced endogenously. There is extensive literature on the generation and effects of reactive oxygen species (ROS) in biological processes, both in terms of alteration and their role in cellular signaling and regulatory pathways. Cells produce ROS as a controlled physiological process, but increasing ROS becomes pathological and leads to oxidative stress and disease. The induction of oxidative stress is an imbalance between the production of radical species and the antioxidant defense systems, which can cause damage to cellular biomolecules, including lipids, proteins and DNA. Cellular and biochemical experiments have been complemented in various ways to explain the biological chemistry of ROS oxidants. However, it is often unclear how this translates into chemical reactions involving redox changes. This review addresses this question and includes a robust mechanistic explanation of the chemical reactions of ROS and oxidative stress.', '2026-07-07 23:28:39');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2899246795', 'chemistry', '‘Green’ synthesis of metals and their oxide nanoparticles: applications for environmental remediation', 'In materials science, "green" synthesis has gained extensive attention as a reliable, sustainable, and eco-friendly protocol for synthesizing a wide range of materials/nanomaterials including…', '2018', 2018, 2599, 2599, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs12951-018-0408-4/MediaObjects/12951_2018_408_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6206834', 'pmc', 'review', 'Journal of Nanobiotechnology', '["Jagpreet Singh","Tanushree Dutta","Ki‐Hyun Kim","Mohit Rawat","Pallabi Samddar","Pawan Kumar"]', 'chemistry', 'In materials science, "green" synthesis has gained extensive attention as a reliable, sustainable, and eco-friendly protocol for synthesizing a wide range of materials/nanomaterials including metal/metal oxides nanomaterials, hybrid materials, and bioinspired materials. As such, green synthesis is regarded as an important tool to reduce the destructive effects associated with the traditional methods of synthesis for nanoparticles commonly utilized in laboratory and industry. In this review, we summarized the fundamental processes and mechanisms of "green" synthesis approaches, especially for metal and metal oxide [e.g., gold (Au), silver (Ag), copper oxide (CuO), and zinc oxide (ZnO)] nanoparticles using natural extracts. Importantly, we explored the role of biological components, essential phytochemicals (e.g., flavonoids, alkaloids, terpenoids, amides, and aldehydes) as reducing agents and solvent systems. The stability/toxicity of nanoparticles and the associated surface engineering techniques for achieving biocompatibility are also discussed. Finally, we covered applications of such synthesized products to environmental remediation in terms of antimicrobial activity, catalytic activity, removal of pollutants dyes, and heavy metal ion sensing.', '2026-07-07 23:28:50');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3032103849', 'chemistry', 'The Effects of Cadmium Toxicity', 'Cadmium (Cd) is a toxic non-essential transition metal that poses a health risk for both humans and animals. It is naturally occurring in the environment as a pollutant that is derived from…', '2020', 2020, 2595, 2595, 'https://pub.mdpi-res.com/ijerph/ijerph-17-03782/article_deploy/html/images/ijerph-17-03782-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7312803', 'pmc', 'review', 'International Journal of Environmental Research and Public Health', '["Giuseppe Genchi","Maria Stefania Sinicropi","Graziantonio Lauria","Alessia Carocci","Alessia Catalano"]', 'chemistry', 'Cadmium (Cd) is a toxic non-essential transition metal that poses a health risk for both humans and animals. It is naturally occurring in the environment as a pollutant that is derived from agricultural and industrial sources. Exposure to cadmium primarily occurs through the ingestion of contaminated food and water and, to a significant extent, through inhalation and cigarette smoking. Cadmium accumulates in plants and animals with a long half-life of about 25–30 years. Epidemiological data suggest that occupational and environmental cadmium exposure may be related to various types of cancer, including breast, lung, prostate, nasopharynx, pancreas, and kidney cancers. It has been also demonstrated that environmental cadmium may be a risk factor for osteoporosis. The liver and kidneys are extremely sensitive to cadmium’s toxic effects. This may be due to the ability of these tissues to synthesize metallothioneins (MT), which are Cd-inducible proteins that protect the cell by tightly binding the toxic cadmium ions. The oxidative stress induced by this xenobiotic may be one of the mechanisms responsible for several liver and kidney diseases. Mitochondria damage is highly plausible given that these organelles play a crucial role in the formation of ROS (reactive oxygen species) and are known to be among the key intracellular targets for cadmium. When mitochondria become dysfunctional after exposure to Cd, they produce less energy (ATP) and more ROS. Recent studies show that cadmium induces various epigenetic changes in mammalian cells, both in vivo and in vitro, causing pathogenic risks and the development of various types of cancers. The epigenetics present themselves as chemical modifications of DNA and histones that alter the chromatin without changing the sequence of the DNA nucleotide. DNA methyltransferase, histone acetyltransferase, histone deacetylase and histone methyltransferase, and micro RNA are involved in the epigenetic changes. Recently, investigations of the capability of sunflower (Helianthus annuus L.), Indian mustard (Brassica juncea), and river red gum (Eucalyptus camaldulensis) to remove cadmium from polluted soil and water have been carried out. Moreover, nanoparticles of TiO2 and Al2O3 have been used to efficiently remove cadmium from wastewater and soil. Finally, microbial fermentation has been studied as a promising method for removing cadmium from food. This review provides an update on the effects of Cd exposure on human health, focusing on the cellular and molecular alterations involved.', '2026-07-07 23:28:53');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2264767503', 'chemistry', 'Introduction to the Analysis of Survival Data in the Presence of Competing Risks', 'Competing risks occur frequently in the analysis of survival data. A competing risk is an event whose occurrence precludes the occurrence of the primary event of interest. In a study examining time…', '2016', 2016, 2547, 2547, 'https://cdn.ncbi.nlm.nih.gov/pmc/blobs/80c8/4741409/809fccabce3f/cir-133-601-g005.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4741409', 'pmc', 'article', 'Circulation', '["Peter C. Austin","Douglas S. Lee","Jason P. Fine"]', 'chemistry', 'Competing risks occur frequently in the analysis of survival data. A competing risk is an event whose occurrence precludes the occurrence of the primary event of interest. In a study examining time to death attributable to cardiovascular causes, death attributable to noncardiovascular causes is a competing risk. When estimating the crude incidence of outcomes, analysts should use the cumulative incidence function, rather than the complement of the Kaplan-Meier survival function. The use of the Kaplan-Meier survival function results in estimates of incidence that are biased upward, regardless of whether the competing events are independent of one another. When fitting regression models in the presence of competing risks, researchers can choose from 2 different families of models: modeling the effect of covariates on the cause-specific hazard of the outcome or modeling the effect of covariates on the cumulative incidence function. The former allows one to estimate the effect of the covariates on the rate of occurrence of the outcome in those subjects who are currently event free. The latter allows one to estimate the effect of covariates on the absolute risk of the outcome over time. The former family of models may be better suited for addressing etiologic questions, whereas the latter model may be better suited for estimating a patient''s clinical prognosis. We illustrate the application of these methods by examining cause-specific mortality in patients hospitalized with heart failure. Statistical software code in both R and SAS is provided.', '2026-07-07 23:28:59');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1940496428', 'chemistry', 'Renewable Power-to-Gas: A technological and economic review', 'The Power-to-Gas (PtG) process chain could play a significant role in the future energy system. Renewable electric energy can be transformed into storable methane via electrolysis and subsequent…', '2015', 2015, 2521, 2521, 'https://ars.els-cdn.com/content/image/1-s2.0-S0960148115301610-fx1.jpg', 'https://doi.org/10.1016/j.renene.2015.07.066', 'repository', 'article', 'Renewable Energy', '["Manuel Götz","Jonathan Lefebvre","Friedemann Mörs","Amy McDaniel Koch","Frank Graf","Siegfried Bajohr","R. Reimert","Thomas Kolb"]', 'chemistry', 'The Power-to-Gas (PtG) process chain could play a significant role in the future energy system. Renewable electric energy can be transformed into storable methane via electrolysis and subsequent methanation. This article compares the available electrolysis and methanation technologies with respect to the stringent requirements of the PtG chain such as low CAPEX, high efficiency, and high flexibility. Three water electrolysis technologies are considered: alkaline electrolysis, PEM electrolysis, and solid oxide electrolysis. Alkaline electrolysis is currently the cheapest technology; however, in the future PEM electrolysis could be better suited for the PtG process chain. Solid oxide electrolysis could also be an option in future, especially if heat sources are available. Several different reactor concepts can be used for the methanation reaction. For catalytic methanation, typically fixed-bed reactors are used; however, novel reactor concepts such as three-phase methanation and micro reactors are currently under development. Another approach is the biochemical conversion. The bioprocess takes place in aqueous solutions and close to ambient temperatures. Finally, the whole process chain is discussed. Critical aspects of the PtG process are the availability of CO 2 sources, the dynamic behaviour of the individual process steps, and especially the economics as well as the efficiency.', '2026-07-07 23:29:02');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1653739410', 'chemistry', 'Molecular Docking and Structure-Based Drug Design Strategies', 'Pharmaceutical research has successfully incorporated a wealth of molecular modeling methods, within a variety of drug discovery programs, to study complex biological and chemical systems. The…', '2015', 2015, 2469, 2469, 'https://pub.mdpi-res.com/molecules/molecules-20-13384/article_deploy/html/images/molecules-20-13384-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6332083', 'pmc', 'review', 'Molecules', '["Leonardo L. G. Ferreira","Ricardo Nascimento dos Santos","Glaucius Oliva","Adriano D. Andricopulo"]', 'chemistry', 'Pharmaceutical research has successfully incorporated a wealth of molecular modeling methods, within a variety of drug discovery programs, to study complex biological and chemical systems. The integration of computational and experimental strategies has been of great value in the identification and development of novel promising compounds. Broadly used in modern drug design, molecular docking methods explore the ligand conformations adopted within the binding sites of macromolecular targets. This approach also estimates the ligand-receptor binding free energy by evaluating critical phenomena involved in the intermolecular recognition process. Today, as a variety of docking algorithms are available, an understanding of the advantages and limitations of each method is of fundamental importance in the development of effective strategies and the generation of relevant results. The purpose of this review is to examine current molecular docking strategies used in drug discovery and medicinal chemistry, exploring the advances in the field and the role played by the integration of structure- and ligand-based methods.', '2026-07-07 23:29:26');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2600399632', 'chemistry', 'Historical (1750–2014) anthropogenic emissions of reactive gases and aerosols from the Community Emissions Data System (CEDS)', 'Abstract. We present a new data set of annual historical (1750–2014) anthropogenic chemically reactive gases (CO, CH4, NH3, NOx, SO2, NMVOCs), carbonaceous aerosols (black carbon – BC, and organic…', '2018', 2018, 2367, 2367, 'https://www.geoscientific-model-development.net/graphic_egu_claim_logo_blue.png', 'https://doi.org/10.5194/gmd-11-369-2018', 'repository', 'article', 'Geoscientific model development', '["Rachel Hoesly","Steven J. Smith","Leyang Feng","Zbigniew Klimont","Greet Janssens‐Maenhout","Tyler Pitkanen","Jonathan J. Seibert","Linh Vu","R. J. Andres","Ryan M. Bolt","Tami C. Bond","Laura Dawidowski","Nazar Kholod","June-ichi Kurokawa","Meng Li","Liang Liu","Zifeng Lü","Maria Cecilia P. Moura","Patrick O’Rourke","Qiang Zhang"]', 'chemistry', 'Abstract. We present a new data set of annual historical (1750–2014) anthropogenic chemically reactive gases (CO, CH4, NH3, NOx, SO2, NMVOCs), carbonaceous aerosols (black carbon – BC, and organic carbon – OC), and CO2 developed with the Community Emissions Data System (CEDS). We improve upon existing inventories with a more consistent and reproducible methodology applied to all emission species, updated emission factors, and recent estimates through 2014. The data system relies on existing energy consumption data sets and regional and country-specific inventories to produce trends over recent decades. All emission species are consistently estimated using the same activity data over all time periods. Emissions are provided on an annual basis at the level of country and sector and gridded with monthly seasonality. These estimates are comparable to, but generally slightly higher than, existing global inventories. Emissions over the most recent years are more uncertain, particularly in low- and middle-income regions where country-specific emission inventories are less available. Future work will involve refining and updating these emission estimates, estimating emissions'' uncertainty, and publication of the system as open-source software.', '2026-07-07 23:29:52');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2988278250', 'chemistry', 'The technological and economic prospects for CO2 utilization and removal', 'The technological and economic prospects for CO2 utilization and removal', '2019', 2019, 2321, 2321, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-019-1681-6/MediaObjects/41586_2019_1681_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/31695213', 'repository', 'review', 'Nature', '["Cameron Hepburn","Ella Adlen","J. R. Beddington","Emily A. Carter","Sabine Fuss","Niall Mac Dowell","Jan C. Minx","Pete Smith","Charlotte K. Williams"]', 'chemistry', NULL, '2026-07-07 23:30:06');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2793476021', 'chemistry', 'Dynamic root exudate chemistry and microbial substrate preferences drive patterns in rhizosphere microbial community assembly', 'Dynamic root exudate chemistry and microbial substrate preferences drive patterns in rhizosphere microbial community assembly', '2018', 2018, 2348, 2348, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41564-018-0129-3/MediaObjects/41564_2018_129_Fig1_HTML.jpg', 'https://hal.science/hal-02000374', 'repository', 'article', 'Nature Microbiology', '["Kateryna Zhalnina","Katherine Louie","Zhao Hao","Nasim Mansoori","Ulisses Nunes da Rocha","Shengjing Shi","Heejung Cho","Ulaş Karaöz","Dominique Loqué","Benjamin P. Bowen","Mary K. Firestone","Trent R. Northen","Eoin Brodie"]', 'chemistry', NULL, '2026-07-07 23:30:08');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2971801381', 'chemistry', 'Molecular Docking: Shifting Paradigms in Drug Discovery', 'Molecular docking is an established in silico structure-based method widely used in drug discovery. Docking enables the identification of novel compounds of therapeutic interest, predicting…', '2019', 2019, 2264, 2264, 'https://pub.mdpi-res.com/ijms/ijms-20-04331/article_deploy/html/images/ijms-20-04331-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6769923', 'pmc', 'review', 'International Journal of Molecular Sciences', '["Luca Pinzi","Giulio Rastelli"]', 'chemistry', 'Molecular docking is an established in silico structure-based method widely used in drug discovery. Docking enables the identification of novel compounds of therapeutic interest, predicting ligand-target interactions at a molecular level, or delineating structure-activity relationships (SAR), without knowing a priori the chemical structure of other target modulators. Although it was originally developed to help understanding the mechanisms of molecular recognition between small and large molecules, uses and applications of docking in drug discovery have heavily changed over the last years. In this review, we describe how molecular docking was firstly applied to assist in drug discovery tasks. Then, we illustrate newer and emergent uses and applications of docking, including prediction of adverse effects, polypharmacology, drug repurposing, and target fishing and profiling, discussing also future applications and further potential of this technique when combined with emergent techniques, such as artificial intelligence.', '2026-07-07 23:30:40');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2945777288', 'chemistry', 'Macrophage Polarization: Different Gene Signatures in M1(LPS+) vs. Classically and M2(LPS–) vs. Alternatively Activated Macrophages', 'Macrophages are found in tissues, body cavities, and mucosal surfaces. Most tissue macrophages are seeded in the early embryo before definitive hematopoiesis is established. Others are derived from…', '2019', 2019, 2090, 2090, 'https://www.frontiersin.org/files/Articles/451543/fimmu-10-01084-HTML-r2/image_m/fimmu-10-01084-g001.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6543837', 'pmc', 'review', 'Frontiers in Immunology', '["Marco Orecchioni","Yanal Ghosheh","Akula Bala Pramod","Klaus Ley"]', 'chemistry', 'Macrophages are found in tissues, body cavities, and mucosal surfaces. Most tissue macrophages are seeded in the early embryo before definitive hematopoiesis is established. Others are derived from blood monocytes. The macrophage lineage diversification and plasticity are key aspects of their functionality. Macrophages can also be generated from monocytes in vitro and undergo classical (LPS+IFN-γ) or alternative (IL-4) activation. In vivo, macrophages with different polarization and different activation markers coexist in tissues. Certain mouse strains preferentially promote T-helper-1 (Th1) responses and other Th2 responses. Their macrophages preferentially induce iNOS or arginase and have been called M1 and M2, respectively. In many publications, M1 and classically activated and M2 and alternatively activated are used interchangeably. We tested whether this is justified by comparing the gene lists positively [M1(=LPS+)] or negatively [M2(=LPS-)] correlated with the ratio of IL-12 and arginase 1 in transcriptomes of LPS-treated peritoneal macrophages with in vitro classically (LPS, IFN-γ) versus alternatively activated (IL-4) bone marrow-derived macrophages, both from published datasets. Although there is some overlap between in vivo M1(=LPS+) and in vitro classically activated (LPS+IFNγ) and in vivo M2(=LPS-) and in vitro alternatively activated macrophages, many more genes are regulated in opposite or unrelated ways. Thus, M1(=LPS+) macrophages are not equivalent to classically activated, and M2(=LPS-) macrophages are not equivalent to alternatively activated macrophages. This fundamental discrepancy explains why most surface markers identified on in vitro generated macrophages do not translate to the in vivo situation. Valid in vivo M1/M2 surface markers remain to be discovered.', '2026-07-07 23:31:44');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2922522932', 'chemistry', 'SIRIUS 4: a rapid tool for turning tandem mass spectra into metabolite structure information', 'Mass spectrometry is a predominant experimental technique in metabolomics and related fields, but metabolite structural elucidation remains highly challenging. We report SIRIUS 4 (…', '2019', 2019, 2046, 2046, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41592-019-0344-8/MediaObjects/41592_2019_344_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/30886413', 'repository', 'article', 'Nature Methods', '["Kai Dührkop","Markus Fleischauer","Marcus Ludwig","Alexander A. Aksenov","Alexey V. Melnik","Marvin Meusel","Pieter C. Dorrestein","Juho Rousu","Sebastian Böcker"]', 'chemistry', 'Mass spectrometry is a predominant experimental technique in metabolomics and related fields, but metabolite structural elucidation remains highly challenging. We report SIRIUS 4 ( https://bio.informatik.uni-jena.de/sirius/ ), which provides a fast computational approach for molecular structure identification. SIRIUS 4 integrates CSI:FingerID for searching in molecular structure databases. Using SIRIUS 4, we achieved identification rates of more than 70% on challenging metabolomics datasets. SIRIUS 4 is a fast and highly accurate tool for molecular structure interpretation from mass-spectrometry-based metabolomics data.', '2026-07-07 23:32:27');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1696825759', 'chemistry', 'Direct measurement of the exciton binding energy and effective masses for charge carriers in organic–inorganic tri-halide perovskites', 'Direct measurement of the exciton binding energy and effective masses for charge carriers in organic–inorganic tri-halide perovskites', '2015', 2015, 2037, 2037, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnphys3357/MediaObjects/41567_2015_Article_BFnphys3357_Fig1_HTML.jpg', 'http://arxiv.org/abs/1504.07025', 'arxiv', 'article', 'Nature Physics', '["Atsuhiko Miyata","Anatolie Mitioglu","Paulina Płochocka","O. Portugall","Jacob Tse‐Wei Wang","Samuel D. Stranks","Henry J. Snaith","R. J. Nicholas"]', 'chemistry', NULL, '2026-07-07 23:32:27');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2522833408', 'chemistry', 'Polymer-templated nucleation and crystal growth of perovskite films for solar cells with efficiency greater than 21%', 'Polymer-templated nucleation and crystal growth of perovskite films for solar cells with efficiency greater than 21%', '2016', 2016, 2035, 2035, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnenergy.2016.142/MediaObjects/41560_2016_Article_BFnenergy2016142_Fig1_HTML.jpg', 'https://doi.org/10.1038/nenergy.2016.142', 'repository', 'article', 'Nature Energy', '["Dongqin Bi","Chenyi Yi","Jingshan Luo","Jean‐David Decoppet","Fei Zhang","Shaik M. Zakeeruddin","Xiong Li","Anders Hagfeldt","Michaël Grätzel"]', 'chemistry', NULL, '2026-07-07 23:32:27');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1989121075', 'chemistry', 'A highly efficient polysulfide mediator for lithium–sulfur batteries', 'The lithium–sulfur battery is receiving intense interest because its theoretical energy density exceeds that of lithium-ion batteries at much lower cost, but practical applications are still hindered…', '2015', 2015, 2040, 2040, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fncomms6682/MediaObjects/41467_2015_Article_BFncomms6682_Fig1_HTML.jpg', 'https://pubmed.ncbi.nlm.nih.gov/25562485', 'repository', 'article', 'Nature Communications', '["Xiao Liang","Connor J. Hart","Quanquan Pang","Arnd Garsuch","Thomas Weiß","Linda F. Nazar"]', 'chemistry', 'The lithium–sulfur battery is receiving intense interest because its theoretical energy density exceeds that of lithium-ion batteries at much lower cost, but practical applications are still hindered by capacity decay caused by the polysulfide shuttle. Here we report a strategy to entrap polysulfides in the cathode that relies on a chemical process, whereby a host—manganese dioxide nanosheets serve as the prototype—reacts with initially formed lithium polysulfides to form surface-bound intermediates. These function as a redox shuttle to catenate and bind ‘higher’ polysulfides, and convert them on reduction to insoluble lithium sulfide via disproportionation. The sulfur/manganese dioxide nanosheet composite with 75 wt% sulfur exhibits a reversible capacity of 1,300 mA h g−1 at moderate rates and a fade rate over 2,000 cycles of 0.036%/cycle, among the best reported to date. We furthermore show that this mechanism extends to graphene oxide and suggest it can be employed more widely. The polysulfide shuttle is a major problem leading to capacity decay in lithium–sulfur batteries. Here, the authors show that in-situ-generated thiosulfate species on a manganese oxide nanosheet act as a polysulfide mediator, which effectively prevents polysulfide dissolution, leading to enhanced cyclability.', '2026-07-07 23:32:28');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2621222172', 'chemistry', 'One-Year stable perovskite solar cells by 2D/3D interface engineering', 'Abstract Despite the impressive photovoltaic performances with power conversion efficiency beyond 22%, perovskite solar cells are poorly stable under operation, failing by far the market…', '2017', 2017, 2035, 2035, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fncomms15684/MediaObjects/41467_2017_Article_BFncomms15684_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5461484', 'pmc', 'article', 'Nature Communications', '["Giulia Grancini","Cristina Roldán‐Carmona","Iwan Zimmermann","Edoardo Mosconi","Xin Yi Lee","David Martineau","Stèphanie Narbey","Frédéric Oswald","Filippo De Angelis","Michaël Grätzel","Mohammad Khaja Nazeeruddin"]', 'chemistry', 'Abstract Despite the impressive photovoltaic performances with power conversion efficiency beyond 22%, perovskite solar cells are poorly stable under operation, failing by far the market requirements. Various technological approaches have been proposed to overcome the instability problem, which, while delivering appreciable incremental improvements, are still far from a market-proof solution. Here we show one-year stable perovskite devices by engineering an ultra-stable 2D/3D (HOOC(CH 2 ) 4 NH 3 ) 2 PbI 4 /CH 3 NH 3 PbI 3 perovskite junction. The 2D/3D forms an exceptional gradually-organized multi-dimensional interface that yields up to 12.9% efficiency in a carbon-based architecture, and 14.6% in standard mesoporous solar cells. To demonstrate the up-scale potential of our technology, we fabricate 10 × 10 cm 2 solar modules by a fully printable industrial-scale process, delivering 11.2% efficiency stable for &gt;10,000 h with zero loss in performances measured under controlled standard conditions. This innovative stable and low-cost architecture will enable the timely commercialization of perovskite solar cells.', '2026-07-07 23:32:28');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2615990324', 'chemistry', 'Fundamentals and advances in magnesium alloy corrosion', 'There remains growing interest in magnesium (Mg) and its alloys, as they are the lightest structural metallic materials. Mg alloys have the potential to enable design of lighter engineered systems,…', '2017', 2017, 2032, 2032, 'https://ars.els-cdn.com/content/image/1-s2.0-S0079642517300506-gr1.jpg', 'https://doi.org/10.1016/j.pmatsci.2017.04.011', 'repository', 'article', 'Progress in Materials Science', '["M. Esmaily","Jan‐Erik Svensson","S. Fajardo","N. Birbilis","G. S. Frankel","Sannakaisa Virtanen","R. Arrabal","S. Thomas","L.‐G. Johansson"]', 'chemistry', 'There remains growing interest in magnesium (Mg) and its alloys, as they are the lightest structural metallic materials. Mg alloys have the potential to enable design of lighter engineered systems, including positive implications for reduced energy consumption. Furthermore, Mg alloys are also emerging as viable biodegradable materials and battery electrodes. In spite of the greatest historical Mg usage at present, the wider use of Mg alloys remains restricted by a number of inherent limitations, including vulnerability to corrosion, poor formability and low creep resistance. This review covers recent research that has led to advances in Mg-alloy corrosion; including the application of contemporary methods for understanding Mg corrosion, the establishment of an electrochemical framework for Mg corrosion, illumination of alloying effects, and attempts at corrosion resistant Mg alloys. A discussion drawing from many sources provides an unbiased focus on new achievements, as well as some contentious issues in the field. The electrochemistry of Mg is reviewed in detail, including so-called anodic hydrogen evolution and cathodic activation. This review also covers atmospheric corrosion, and biodegradable Mg alloys. Finally, past and present trends in the field of Mg corrosion are reviewed, identifying knowledge gaps, whilst attempting to also identify future developments and directions.', '2026-07-07 23:32:42');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2418622137', 'chemistry', 'Single-molecule strong coupling at room temperature in plasmonic nanocavities', 'Single-molecule strong coupling at room temperature in plasmonic nanocavities', '2016', 2016, 1981, 1981, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature17974/MediaObjects/41586_2016_BFnature17974_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4947385', 'pmc', 'article', 'Nature', '["Rohit Chikkaraddy","Bart de Nijs","Felix Benz","Steven J. Barrow","Oren A. Scherman","Edina Rosta","Angela Demetriadou","Peter T. Fox","Ortwin Hess","Jeremy J. Baumberg"]', 'chemistry', NULL, '2026-07-07 23:33:04');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2331484215', 'chemistry', 'Sulfur Containing Scaffolds in Drugs: Synthesis and Application in Medicinal Chemistry', 'The impact of the development of sulfur therapeutics is instrumental to the evolution of the pharmaceutical industry. Sulfur-derived functional groups can be found in a broad range of pharmaceuticals…', '2016', 2016, 1966, 1966, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.2174/1568026615666150915111741.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4877035', 'pmc', 'review', 'Current Topics in Medicinal Chemistry', '["Minghao Feng","Bingqing Tang","Steven H. Liang","Xuefeng Jiang"]', 'chemistry', 'The impact of the development of sulfur therapeutics is instrumental to the evolution of the pharmaceutical industry. Sulfur-derived functional groups can be found in a broad range of pharmaceuticals and natural products. For centuries, sulfur continues to maintain its status as the dominating heteroatom integrated into a set of 362 sulfur-containing FDA approved drugs (besides oxygen or nitrogen) through the present. Sulfonamides, thioethers, sulfones and Penicillin are the most common scaffolds in sulfur containing drugs, which are well studied both on synthesis and application during the past decades. In this review, these four moieties in pharmaceuticals and recent advances in the synthesis of the corresponding core scaffolds are presented.', '2026-07-07 23:33:21');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3146013771', 'chemistry', 'Analytical Methods Used in Determining Antioxidant Activity: A Review', 'The study of antioxidants and their implications in various fields, from food engineering to medicine and pharmacy, is of major interest to the scientific community. The present paper is a critical…', '2021', 2021, 1971, 1971, 'https://pub.mdpi-res.com/ijms/ijms-22-03380/article_deploy/html/images/ijms-22-03380-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8037236', 'pmc', 'review', 'International Journal of Molecular Sciences', '["Irina Georgiana Munteanu","Constantin Apetrei"]', 'chemistry', 'The study of antioxidants and their implications in various fields, from food engineering to medicine and pharmacy, is of major interest to the scientific community. The present paper is a critical presentation of the most important tests used to determine the antioxidant activity, detection mechanism, applicability, advantages and disadvantages of these methods. Out of the tests based on the transfer of a hydrogen atom, the following were presented: the Oxygen Radical Absorption Capacity (ORAC) test, the Hydroxyl Radical Antioxidant Capacity (HORAC) test, the Total Peroxyl Radical Trapping Antioxidant Parameter (TRAP) test, and the Total Oxyradical Scavenging Capacity (TOSC) test. The tests based on the transfer of one electron include the Cupric Reducing Antioxidant Power (CUPRAC) test, the Ferric Reducing Antioxidant Power (FRAP) test, the Folin-Ciocalteu test. Mixed tests, including the transfer of both a hydrogen atom and an electron, include the 2,2''-Azinobis-(3-ethylbenzothiazoline-6-sulfonic acid (ABTS) test, and the [2,2-di(4-tert-octylphenyl)-1-picrylhydrazyl] (DPPH) test. All these assays are based on chemical reactions and assessing the kinetics or reaching the equilibrium state relies on spectrophotometry, presupposing the occurrence of characteristic colours or the discolouration of the solutions to be analysed, which are processes monitored by specific wavelength adsorption. These assays were successfully applied in antioxidant analysis or the determination of the antioxidant capacity of complex samples. As a complementary method in such studies, one may use methods based on electrochemical (bio)sensors, requiring stages of calibration and validation. The use of chemical methods together with electrochemical methods may result in clarification of the operating mechanisms and kinetics of the processes involving several antioxidants.', '2026-07-07 23:33:34');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2953705934', 'chemistry', 'Response of Phenylpropanoid Pathway and the Role of Polyphenols in Plants under Abiotic Stress', 'Phenolic compounds are an important class of plant secondary metabolites which play crucial physiological roles throughout the plant life cycle. Phenolics are produced under optimal and suboptimal…', '2019', 2019, 1940, 1940, 'https://pub.mdpi-res.com/molecules/molecules-24-02452/article_deploy/html/images/molecules-24-02452-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6651195', 'pmc', 'review', 'Molecules', '["Anket Sharma","Babar Shahzad","Abdul Rehman","Renu Bhardwaj","Marco Landi","Bingsong Zheng"]', 'chemistry', 'Phenolic compounds are an important class of plant secondary metabolites which play crucial physiological roles throughout the plant life cycle. Phenolics are produced under optimal and suboptimal conditions in plants and play key roles in developmental processes like cell division, hormonal regulation, photosynthetic activity, nutrient mineralization, and reproduction. Plants exhibit increased synthesis of polyphenols such as phenolic acids and flavonoids under abiotic stress conditions, which help the plant to cope with environmental constraints. Phenylpropanoid biosynthetic pathway is activated under abiotic stress conditions (drought, heavy metal, salinity, high/low temperature, and ultraviolet radiations) resulting in accumulation of various phenolic compounds which, among other roles, have the potential to scavenge harmful reactive oxygen species. Deepening the research focuses on the phenolic responses to abiotic stress is of great interest for the scientific community. In the present article, we discuss the biochemical and molecular mechanisms related to the activation of phenylpropanoid metabolism and we describe phenolic-mediated stress tolerance in plants. An attempt has been made to provide updated and brand-new information about the response of phenolics under a challenging environment.', '2026-07-07 23:33:44');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3048882402', 'chemistry', 'Marine20—The Marine Radiocarbon Age Calibration Curve (0–55,000 cal BP)', 'ABSTRACT The concentration of radiocarbon ( 14 C) differs between ocean and atmosphere. Radiocarbon determinations from samples which obtained their 14 C in the marine environment therefore need a…', '2020', 2020, 1928, 1928, 'https://static.cambridge.org/binary/version/id/urn:cambridge.org:id:binary:20200922090001038-0892:S0033822220000685:S0033822220000685_fig1.png', 'https://doi.org/10.1017/rdc.2020.68', 'repository', 'article', 'Radiocarbon', '["Timothy Heaton","Peter Köhler","Martin Butzin","Édouard Bard","Ron Reimer","William E. N. Austin","Christopher Bronk Ramsey","Pieter Meiert Grootes","Konrad A Hughen","Bernd Kromer","Paula Reimer","Jess F. Adkins","Andrea Burke","M. S. Cook","Jesper Olsen","Luke C Skinner"]', 'chemistry', 'ABSTRACT The concentration of radiocarbon ( 14 C) differs between ocean and atmosphere. Radiocarbon determinations from samples which obtained their 14 C in the marine environment therefore need a marine-specific calibration curve and cannot be calibrated directly against the atmospheric-based IntCal20 curve. This paper presents Marine20, an update to the internationally agreed marine radiocarbon age calibration curve that provides a non-polar global-average marine record of radiocarbon from 0–55 cal kBP and serves as a baseline for regional oceanic variation. Marine20 is intended for calibration of marine radiocarbon samples from non-polar regions; it is not suitable for calibration in polar regions where variability in sea ice extent, ocean upwelling and air-sea gas exchange may have caused larger changes to concentrations of marine radiocarbon. The Marine20 curve is based upon 500 simulations with an ocean/atmosphere/biosphere box-model of the global carbon cycle that has been forced by posterior realizations of our Northern Hemispheric atmospheric IntCal20 14 C curve and reconstructed changes in CO 2 obtained from ice core data. These forcings enable us to incorporate carbon cycle dynamics and temporal changes in the atmospheric 14 C level. The box-model simulations of the global-average marine radiocarbon reservoir age are similar to those of a more complex three-dimensional ocean general circulation model. However, simplicity and speed of the box model allow us to use a Monte Carlo approach to rigorously propagate the uncertainty in both the historic concentration of atmospheric 14 C and other key parameters of the carbon cycle through to our final Marine20 calibration curve. This robust propagation of uncertainty is fundamental to providing reliable precision for the radiocarbon age calibration of marine based samples. We make a first step towards deconvolving the contributions of different processes to the total uncertainty; discuss the main differences of Marine20 from the previous age calibration curve Marine13; and identify the limitations of our approach together with key areas for further work. The updated values for ΔR, the regional marine radiocarbon reservoir age corrections required to calibrate against Marine20, can be found at the data base http://calib.org/marine/.', '2026-07-07 23:33:53');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3127297964', 'chemistry', 'Trends in peptide drug discovery', 'Trends in peptide drug discovery', '2021', 2021, 1914, 1914, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41573-020-00135-8/MediaObjects/41573_2020_135_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/33536635', 'repository', 'review', 'Nature Reviews Drug Discovery', '["Markus Muttenthaler","Glenn F. King","David J. Adams","Paul F. Alewood"]', 'chemistry', NULL, '2026-07-07 23:33:53');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2794844698', 'chemistry', 'Itaconate is an anti-inflammatory metabolite that activates Nrf2 via alkylation of KEAP1', 'Itaconate is an anti-inflammatory metabolite that activates Nrf2 via alkylation of KEAP1', '2018', 2018, 1854, 1854, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1038/nature25986.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6047741', 'pmc', 'article', 'Nature', '["Evanna L. Mills","Dylan G. Ryan","Hiran A. Prag","Dina Dikovskaya","Deepthi Menon","Zbigniew Zasłona","Mark P. Jedrychowski","Ana S.H. Costa","Maureen Higgins","Emily Hams","John Szpyt","Marah C. Runtsch","Martin King","Joanna F. McGouran","Román Fischer","Benedikt M. Kessler","Anne F. McGettrick","Mark Hughes","Richard G. Carroll","Lee M. Booty","Elena V. Knatko","Paul J. Meakin","Michael L.J. Ashford","Louise K. Modis","Gino Brunori","Daniel C. Sévin","Padraic G. Fallon","Stuart T. Caldwell","Edmund R.S. Kunji","Edward T. Chouchani","Christian Frezza","Albena T. Dinkova‐Kostova","Richard C. Hartley","Michael P. Murphy","Luke O''neill"]', 'chemistry', NULL, '2026-07-07 23:34:41');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3162306949', 'chemistry', 'DHODH-mediated ferroptosis defence is a targetable vulnerability in cancer', 'DHODH-mediated ferroptosis defence is a targetable vulnerability in cancer', '2021', 2021, 1798, 1798, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-021-03539-7/MediaObjects/41586_2021_3539_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8895686', 'pmc', 'article', 'Nature', '["Chao Mao","Xiaoguang Liu","Yilei Zhang","Guang Lei","Yuelong Yan","Hyemin Lee","Pranavi Koppula","Shiqi Wu","Li Zhuang","Bingliang Fang","Masha V. Poyurovsky","Kellen Olszewski","Boyi Gan"]', 'chemistry', NULL, '2026-07-07 23:35:13');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1559832400', 'chemistry', 'Growth of Rhodococcus sp. strain BCP1 on gaseous n-alkanes: new metabolic insights and transcriptional analysis of two soluble di-iron monooxygenase genes', 'Rhodococcus sp. strain BCP1 was initially isolated for its ability to grow on gaseous n-alkanes, which act as inducers for the co-metabolic degradation of low-chlorinated compounds. Here, both…', '2015', 2015, 1780, 1780, 'https://www.frontiersin.org/files/Articles/125317/fmicb-06-00393-HTML/image_m/fmicb-06-00393-g001.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4428276', 'pmc', 'article', 'Frontiers in Microbiology', '["Martina Cappelletti","Alessandro Presentato","Giorgio Milazzo","Raymond J. Turner","Stefano Fedi","Dario Frascari","Davide Zannoni"]', 'chemistry', 'Rhodococcus sp. strain BCP1 was initially isolated for its ability to grow on gaseous n-alkanes, which act as inducers for the co-metabolic degradation of low-chlorinated compounds. Here, both molecular and metabolic features of BCP1 cells grown on gaseous and short-chain n-alkanes (up to n-heptane) were examined in detail. We show that propane metabolism generated terminal and sub-terminal oxidation products such as 1- and 2-propanol, whereas 1-butanol was the only terminal oxidation product detected from n-butane metabolism. Two gene clusters, prmABCD and smoABCD-coding for Soluble Di-Iron Monooxgenases (SDIMOs) involved in gaseous n-alkanes oxidation-were detected in the BCP1 genome. By means of Reverse Transcriptase-quantitative PCR (RT-qPCR) analysis, a set of substrates inducing the expression of the sdimo genes in BCP1 were assessed as well as their transcriptional repression in the presence of sugars, organic acids, or during the cell growth on rich medium (Luria-Bertani broth). The transcriptional start sites of both the sdimo gene clusters were identified by means of primer extension experiments. Finally, proteomic studies revealed changes in the protein pattern induced by growth on gaseous- (n-butane) and/or liquid (n-hexane) short-chain n-alkanes as compared to growth on succinate. Among the differently expressed protein spots, two chaperonins and an isocytrate lyase were identified along with oxidoreductases involved in oxidation reactions downstream of the initial monooxygenase reaction step.', '2026-07-07 23:35:32');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1516762549', 'chemistry', 'Synthesis of silver nanoparticles: chemical, physical and biological methods.', 'Silver nanoparticles (NPs) have been the subjects of researchers because of their unique properties (e.g., size and shape depending optical, antimicrobial, and electrical properties). A variety of…', '2015', 2015, 1763, 1763, 'https://cdn.ncbi.nlm.nih.gov/pmc/blobs/b88a/4326978/4f2ee0881b28/RPS-9-385-g003.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4326978', 'pmc', 'article', 'PubMed', '["Siavash Iravani","Hassan Korbekandi","Seyed Vahid Mirmohammadi","Behzad Zolfaghari"]', 'chemistry', 'Silver nanoparticles (NPs) have been the subjects of researchers because of their unique properties (e.g., size and shape depending optical, antimicrobial, and electrical properties). A variety of preparation techniques have been reported for the synthesis of silver NPs; notable examples include, laser ablation, gamma irradiation, electron irradiation, chemical reduction, photochemical methods, microwave processing, and biological synthetic methods. This review presents an overview of silver nanoparticle preparation by physical, chemical, and biological synthesis. The aim of this review article is, therefore, to reflect on the current state and future prospects, especially the potentials and limitations of the above mentioned techniques for industries.', '2026-07-07 23:35:45');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2765303057', 'chemistry', 'Glucose feeds the TCA cycle via circulating lactate', 'Glucose feeds the TCA cycle via circulating lactate', '2017', 2017, 1720, 1720, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1038/nature24057.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5898814', 'pmc', 'article', 'Nature', '["Sheng Hui","Jonathan M. Ghergurovich","Raphael J. Morscher","Cholsoon Jang","Xin Teng","Wenyun Lu","Lourdes Adriana Esparza","Tannishtha Reya","Le Zhan","Jessie Yanxiang Guo","Eileen White","Joshua D. Rabinowitz"]', 'chemistry', NULL, '2026-07-07 23:36:28');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2952213661', 'chemistry', 'Methylammonium Chloride Induces Intermediate Phase Stabilization for Efficient Perovskite Solar Cells', 'Methylammonium Chloride Induces Intermediate Phase Stabilization for Efficient Perovskite Solar Cells', '2019', 2019, 1722, 1722, 'https://ars.els-cdn.com/content/image/1-s2.0-S2542435119303058-fx1.jpg', 'https://doi.org/10.1016/j.joule.2019.06.014', 'repository', 'article', 'Joule', '["Minjin Kim","Gi‐Hwan Kim","Tae Kyung Lee","In Woo Choi","Hyewon Choi","Yimhyun Jo","Yung Jin Yoon","Jae Won Kim","Jae Won Kim","Jiyun Lee","Daihong Huh","Heon Lee","Sang Kyu Kwak","Jin Young Kim","Jin Young Kim","Dong Suk Kim"]', 'chemistry', NULL, '2026-07-07 23:36:30');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2738136165', 'chemistry', 'cGAS surveillance of micronuclei links genome instability to innate immunity', 'cGAS surveillance of micronuclei links genome instability to innate immunity', '2017', 2017, 1721, 1721, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature23449/MediaObjects/41586_2017_Article_BFnature23449_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5870830', 'pmc', 'article', 'Nature', '["Karen J. Mackenzie","Paula Carroll","Carol-Anne Martin","Olga Murina","Adeline Fluteau","Daniel J. Simpson","Nelly Olova","Hannah Sutcliffe","Jacqueline K. Rainger","Andrea Leitch","Ruby Tamara Osborn","Ann P. Wheeler","Marcin Nowotny","Nick Gilbert","Tamir Chandra","Martin A.M. Reijns","Andrew P. Jackson"]', 'chemistry', NULL, '2026-07-07 23:36:31');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2801873687', 'chemistry', 'Aqueous rechargeable zinc/sodium vanadate batteries with enhanced performance from simultaneous insertion of dual carriers', 'Abstract Rechargeable aqueous zinc-ion batteries are promising energy storage devices due to their high safety and low cost. However, they remain in their infancy because of the limited choice of…', '2018', 2018, 1722, 1722, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41467-018-04060-8/MediaObjects/41467_2018_4060_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5916908', 'pmc', 'article', 'Nature Communications', '["Fang Wan","Linlin Zhang","Xi Dai","Xinyu Wang","Zhiqiang Niu","Jun Chen"]', 'chemistry', 'Abstract Rechargeable aqueous zinc-ion batteries are promising energy storage devices due to their high safety and low cost. However, they remain in their infancy because of the limited choice of positive electrodes with high capacity and satisfactory cycling performance. Furthermore, their energy storage mechanisms are not well established yet. Here we report a highly reversible zinc/sodium vanadate system, where sodium vanadate hydrate nanobelts serve as positive electrode and zinc sulfate aqueous solution with sodium sulfate additive is used as electrolyte. Different from conventional energy release/storage in zinc-ion batteries with only zinc-ion insertion/extraction, zinc/sodium vanadate hydrate batteries possess a simultaneous proton, and zinc-ion insertion/extraction process that is mainly responsible for their excellent performance, such as a high reversible capacity of 380 mAh g –1 and capacity retention of 82% over 1000 cycles. Moreover, the quasi-solid-state zinc/sodium vanadate hydrate battery is also a good candidate for flexible energy storage device.', '2026-07-07 23:36:31');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2981679558', 'chemistry', 'Machine learning algorithm validation with a limited sample size', 'Advances in neuroimaging, genomic, motion tracking, eye-tracking and many other technology-based data collection methods have led to a torrent of high dimensional datasets, which commonly have a…', '2019', 2019, 1708, 1708, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0224365.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6837442', 'pmc', 'article', 'PLoS ONE', '["Andrius Vabalas","Emma Gowen","Ellen Poliakoff","Alexander J. Casson"]', 'chemistry', 'Advances in neuroimaging, genomic, motion tracking, eye-tracking and many other technology-based data collection methods have led to a torrent of high dimensional datasets, which commonly have a small number of samples because of the intrinsic high cost of data collection involving human participants. High dimensional data with a small number of samples is of critical importance for identifying biomarkers and conducting feasibility and pilot work, however it can lead to biased machine learning (ML) performance estimates. Our review of studies which have applied ML to predict autistic from non-autistic individuals showed that small sample size is associated with higher reported classification accuracy. Thus, we have investigated whether this bias could be caused by the use of validation methods which do not sufficiently control overfitting. Our simulations show that K-fold Cross-Validation (CV) produces strongly biased performance estimates with small sample sizes, and the bias is still evident with sample size of 1000. Nested CV and train/test split approaches produce robust and unbiased performance estimates regardless of sample size. We also show that feature selection if performed on pooled training and testing data is contributing to bias considerably more than parameter tuning. In addition, the contribution to bias by data dimensionality, hyper-parameter space and number of CV folds was explored, and validation methods were compared with discriminable data. The results suggest how to design robust testing methodologies when working with small datasets and how to interpret the results of other studies based on what validation method was used.', '2026-07-07 23:36:43');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2907588123', 'chemistry', 'High electronic conductivity as the origin of lithium dendrite formation within solid electrolytes', 'High electronic conductivity as the origin of lithium dendrite formation within solid electrolytes', '2019', 2019, 1680, 1680, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41560-018-0312-z/MediaObjects/41560_2018_312_Fig1_HTML.png', 'https://doi.org/10.1038/s41560-018-0312-z', 'repository', 'article', 'Nature Energy', '["Fudong Han","Andrew S. Westover","Jie Yue","Xiulin Fan","Fei Wang","Miaofang Chi","Donovan N. Leonard","Nancy J. Dudney","Howard Wang","Chunsheng Wang"]', 'chemistry', NULL, '2026-07-07 23:39:08');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2167267527', 'chemistry', 'Light-emitting diodes by band-structure engineering in van der Waals heterostructures', 'Light-emitting diodes by band-structure engineering in van der Waals heterostructures', '2015', 2015, 1680, 1680, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnmat4205/MediaObjects/41563_2015_Article_BFnmat4205_Fig1_HTML.jpg', 'http://arxiv.org/abs/1412.7621', 'arxiv', 'article', 'Nature Materials', '["Freddie Withers","Osvaldo Del Pozo-Zamudio","Artem Mishchenko","Aidan P. Rooney","A. Gholinia","Kenji Watanabe","Takashi Taniguchi","Sarah J. Haigh","A. K. Geǐm","A. I. Tartakovskii","Kostya S. Novoselov"]', 'chemistry', NULL, '2026-07-07 23:39:08');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2575591472', 'chemistry', 'MIX: a mosaic Asian anthropogenic emission inventory under the international collaboration framework of the MICS-Asia and HTAP', 'Abstract. The MIX inventory is developed for the years 2008 and 2010 to support the Model Inter-Comparison Study for Asia (MICS-Asia) and the Task Force on Hemispheric Transport of Air Pollution (TF…', '2017', 2017, 1663, 1663, 'https://www.atmospheric-chemistry-and-physics.net/graphic_egu_claim_logo_blue.png', 'https://doi.org/10.5194/acp-17-935-2017', 'repository', 'article', 'Atmospheric chemistry and physics', '["Meng Li","Qiang Zhang","Junichi Kurokawa","Jung‐Hun Woo","Kebin He","Zifeng Lü","Toshimasa Ohara","Yu Song","David G. Streets","Gregory R. Carmichael","Yafang Cheng","Chaopeng Hong","Hong Huo","Xujia Jiang","Sicong Kang","Fei Liu","Hang Su","Bo Zheng"]', 'chemistry', 'Abstract. The MIX inventory is developed for the years 2008 and 2010 to support the Model Inter-Comparison Study for Asia (MICS-Asia) and the Task Force on Hemispheric Transport of Air Pollution (TF HTAP) by a mosaic of up-to-date regional emission inventories. Emissions are estimated for all major anthropogenic sources in 29 countries and regions in Asia. We conducted detailed comparisons of different regional emission inventories and incorporated the best available ones for each region into the mosaic inventory at a uniform spatial and temporal resolution. Emissions are aggregated to five anthropogenic sectors: power, industry, residential, transportation, and agriculture. We estimate the total Asian emissions of 10 species in 2010 as follows: 51.3 Tg SO2, 52.1 Tg NOx, 336.6 Tg CO, 67.0 Tg NMVOC (non-methane volatile organic compounds), 28.8 Tg NH3, 31.7 Tg PM10, 22.7 Tg PM2.5, 3.5 Tg BC, 8.3 Tg OC, and 17.3 Pg CO2. Emissions from China and India dominate the emissions of Asia for most of the species. We also estimated Asian emissions in 2006 using the same methodology of MIX. The relative change rates of Asian emissions for the period of 2006–2010 are estimated as follows: −8.1 % for SO2, +19.2 % for NOx, +3.9 % for CO, +15.5 % for NMVOC, +1.7 % for NH3, −3.4 % for PM10, −1.6 % for PM2.5, +5.5 % for BC, +1.8 % for OC, and +19.9 % for CO2. Model-ready speciated NMVOC emissions for SAPRC-99 and CB05 mechanisms were developed following a profile-assignment approach. Monthly gridded emissions at a spatial resolution of 0.25° × 0.25° are developed and can be accessed from http://www.meicmodel.org/dataset-mix.', '2026-07-07 23:39:18');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1559815414', 'chemistry', 'Silver Nanoparticles as Potential Antibacterial Agents', 'Multi-drug resistance is a growing problem in the treatment of infectious diseases and the widespread use of broad-spectrum antibiotics has produced antibiotic resistance for many human bacterial…', '2015', 2015, 1663, 1663, 'https://pub.mdpi-res.com/molecules/molecules-20-08856/article_deploy/html/images/molecules-20-08856-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6272636', 'pmc', 'review', 'Molecules', '["Gianluigi Franci","Annarita Falanga","Stefania Galdiero","Luciana Palomba","Mahendra Rai","Giancarlo Morelli","Massimiliano Galdiero"]', 'chemistry', 'Multi-drug resistance is a growing problem in the treatment of infectious diseases and the widespread use of broad-spectrum antibiotics has produced antibiotic resistance for many human bacterial pathogens. Advances in nanotechnology have opened new horizons in nanomedicine, allowing the synthesis of nanoparticles that can be assembled into complex architectures. Novel studies and technologies are devoted to understanding the mechanisms of disease for the design of new drugs, but unfortunately infectious diseases continue to be a major health burden worldwide. Since ancient times, silver was known for its anti-bacterial effects and for centuries it has been used for prevention and control of disparate infections. Currently nanotechnology and nanomaterials are fully integrated in common applications and objects that we use every day. In addition, the silver nanoparticles are attracting much interest because of their potent antibacterial activity. Many studies have also shown an important activity of silver nanoparticles against bacterial biofilms. This review aims to summarize the emerging efforts to address current challenges and solutions in the treatment of infectious diseases, particularly the use of nanosilver antimicrobials.', '2026-07-07 23:39:24');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2119642490', 'chemistry', 'Reduced carbon emission estimates from fossil fuel combustion and cement production in China', 'Reduced carbon emission estimates from fossil fuel combustion and cement production in China', '2015', 2015, 1656, 1656, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature14677/MediaObjects/41586_2015_Article_BFnature14677_Fig1_HTML.jpg', 'https://hal.science/hal-02892347', 'repository', 'article', 'Nature', '["Zhu Liu","Dabo Guan","Wei Wei","Steven J. Davis","Philippe Ciais","Jin Bai","Shushi Peng","Qiang Zhang","Klaus Hubacek","Gregg Marland","R. J. Andres","Douglas Crawford‐Brown","Jintai Lin","Hongyan Zhao","Chaopeng Hong","Thomas A. Boden","Kuishuang Feng","Glen P. Peters","Fengming Xi","Junguo Liu","Yuan Li","Yu Zhao","Ning Zeng","Kebin He"]', 'chemistry', NULL, '2026-07-07 23:39:29');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2920912088', 'chemistry', 'Challenges and prospects in the catalysis of electroreduction of nitrogen to ammonia', 'Challenges and prospects in the catalysis of electroreduction of nitrogen to ammonia', '2019', 2019, 1644, 1644, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41929-019-0252-4/MediaObjects/41929_2019_252_Fig1_HTML.png', 'https://doi.org/10.1038/s41929-019-0252-4', 'repository', 'article', 'Nature Catalysis', '["Bryan H. R. Suryanto","Hoang‐Long Du","Da-Bin Wang","Jun Chen","Alexandr N. Simonov","Douglas R. MacFarlane"]', 'chemistry', NULL, '2026-07-07 23:39:30');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3016762617', 'chemistry', 'A Review on Recent Advances in Nitrogen-Containing Molecules and Their Biological Applications', 'The analogs of nitrogen-based heterocycles occupy an exclusive position as a valuable source of therapeutic agents in medicinal chemistry. More than 75% of drugs approved by the FDA and currently…', '2020', 2020, 1644, 1644, 'https://pub.mdpi-res.com/molecules/molecules-25-01909/article_deploy/html/images/molecules-25-01909-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7221918', 'pmc', 'review', 'Molecules', '["Nagaraju Kerru","Lalitha Gummidi","Suresh Maddila","Kranthi Kumar Gangu","Sreekantha B. Jonnalagadda"]', 'chemistry', 'The analogs of nitrogen-based heterocycles occupy an exclusive position as a valuable source of therapeutic agents in medicinal chemistry. More than 75% of drugs approved by the FDA and currently available in the market are nitrogen-containing heterocyclic moieties. In the forthcoming decade, a much greater share of new nitrogen-based pharmaceuticals is anticipated. Many new nitrogen-based heterocycles have been designed. The number of novel N-heterocyclic moieties with significant physiological properties and promising applications in medicinal chemistry is ever-growing. In this review, we consolidate the recent advances on novel nitrogen-containing heterocycles and their distinct biological activities, reported over the past one year (2019 to early 2020). This review highlights the trends in the use of nitrogen-based moieties in drug design and the development of different potent and competent candidates against various diseases.', '2026-07-07 23:39:35');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2038621246', 'chemistry', 'Review of energy system flexibility measures to enable high levels of variable renewable electricity', 'Review of energy system flexibility measures to enable high levels of variable renewable electricity', '2015', 2015, 1626, 1626, 'https://ars.els-cdn.com/content/image/1-s2.0-S1364032115000672-gr1.jpg', 'https://doi.org/10.1016/j.rser.2015.01.057', 'repository', 'article', 'Renewable and Sustainable Energy Reviews', '["Peter D. Lund","Juuso Lindgren","Jani Mikkola","Jyri Salpakari"]', 'chemistry', NULL, '2026-07-07 23:39:49');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2266013672', 'chemistry', 'Insights into Protein–Ligand Interactions: Mechanisms, Models, and Methods', 'Molecular recognition, which is the process of biological macromolecules interacting with each other or various small molecules with a high specificity and affinity to form a specific complex,…', '2016', 2016, 1619, 1619, 'https://pub.mdpi-res.com/ijms/ijms-17-00144/article_deploy/html/images/ijms-17-00144-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4783878', 'pmc', 'review', 'International Journal of Molecular Sciences', '["Xing Du","Yi Li","Yuan-Ling Xia","Shi-Meng Ai","Jing Liang","Peng Sang","Xinglai Ji","Shu-Qun Liu"]', 'chemistry', 'Molecular recognition, which is the process of biological macromolecules interacting with each other or various small molecules with a high specificity and affinity to form a specific complex, constitutes the basis of all processes in living organisms. Proteins, an important class of biological macromolecules, realize their functions through binding to themselves or other molecules. A detailed understanding of the protein-ligand interactions is therefore central to understanding biology at the molecular level. Moreover, knowledge of the mechanisms responsible for the protein-ligand recognition and binding will also facilitate the discovery, design, and development of drugs. In the present review, first, the physicochemical mechanisms underlying protein-ligand binding, including the binding kinetics, thermodynamic concepts and relationships, and binding driving forces, are introduced and rationalized. Next, three currently existing protein-ligand binding models--the "lock-and-key", "induced fit", and "conformational selection"--are described and their underlying thermodynamic mechanisms are discussed. Finally, the methods available for investigating protein-ligand binding affinity, including experimental and theoretical/computational approaches, are introduced, and their advantages, disadvantages, and challenges are discussed.', '2026-07-07 23:40:09');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3182217762', 'chemistry', 'Silver Nanoparticles and Their Antibacterial Applications', 'Silver nanoparticles (AgNPs) have been imposed as an excellent antimicrobial agent being able to combat bacteria in vitro and in vivo causing infections. The antibacterial capacity of AgNPs covers…', '2021', 2021, 1625, 1625, 'https://pub.mdpi-res.com/ijms/ijms-22-07202/article_deploy/html/images/ijms-22-07202-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8268496', 'pmc', 'review', 'International Journal of Molecular Sciences', '["Tamara Bruna","Francisca Maldonado-Bravo","Paul Jara","Nelson Caro"]', 'chemistry', 'Silver nanoparticles (AgNPs) have been imposed as an excellent antimicrobial agent being able to combat bacteria in vitro and in vivo causing infections. The antibacterial capacity of AgNPs covers Gram-negative and Gram-positive bacteria, including multidrug resistant strains. AgNPs exhibit multiple and simultaneous mechanisms of action and in combination with antibacterial agents as organic compounds or antibiotics it has shown synergistic effect against pathogens bacteria such as Escherichia coli and Staphylococcus aureus. The characteristics of silver nanoparticles make them suitable for their application in medical and healthcare products where they may treat infections or prevent them efficiently. With the urgent need for new efficient antibacterial agents, this review aims to establish factors affecting antibacterial and cytotoxic effects of silver nanoparticles, as well as to expose the advantages of using AgNPs as new antibacterial agents in combination with antibiotic, which will reduce the dosage needed and prevent secondary effects associated to both.', '2026-07-07 23:40:10');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3100994999', 'chemistry', 'Important Flavonoids and Their Role as a Therapeutic Agent', 'Flavonoids are phytochemical compounds present in many plants, fruits, vegetables, and leaves, with potential applications in medicinal chemistry. Flavonoids possess a number of medicinal benefits,…', '2020', 2020, 1621, 1621, 'https://pub.mdpi-res.com/molecules/molecules-25-05243/article_deploy/html/images/molecules-25-05243-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7697716', 'pmc', 'review', 'Molecules', '["Asad Ullah","Sidra Munir","Syed Lal Badshah","Noreen Khan","Lubna Ghani","Benjamin Gabriel Poulson","Abdul‐Hamid Emwas","Mariusz Jaremko"]', 'chemistry', 'Flavonoids are phytochemical compounds present in many plants, fruits, vegetables, and leaves, with potential applications in medicinal chemistry. Flavonoids possess a number of medicinal benefits, including anticancer, antioxidant, anti-inflammatory, and antiviral properties. They also have neuroprotective and cardio-protective effects. These biological activities depend upon the type of flavonoid, its (possible) mode of action, and its bioavailability. These cost-effective medicinal components have significant biological activities, and their effectiveness has been proved for a variety of diseases. The most recent work is focused on their isolation, synthesis of their analogs, and their effects on human health using a variety of techniques and animal models. Thousands of flavonoids have been successfully isolated, and this number increases steadily. We have therefore made an effort to summarize the isolated flavonoids with useful activities in order to gain a better understanding of their effects on human health.', '2026-07-07 23:40:10');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2269917342', 'chemistry', 'Low-threshold amplified spontaneous emission and lasing from colloidal nanocrystals of caesium lead halide perovskites', 'Metal halide semiconductors with perovskite crystal structures have recently emerged as highly promising optoelectronic materials. Despite the recent surge of reports on microcrystalline, thin-film…', '2015', 2015, 1604, 1604, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fncomms9056/MediaObjects/41467_2015_Article_BFncomms9056_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4560790', 'pmc', 'article', 'Nature Communications', '["Sergii Yakunin","Loredana Proteşescu","Franziska Krieg","Maryna I. Bodnarchuk","Georgian Nedelcu","Markus Humer","Gabriele De Luca","M. Fiebig","Wolfgang Heiß","Maksym V. Kovalenko"]', 'chemistry', 'Metal halide semiconductors with perovskite crystal structures have recently emerged as highly promising optoelectronic materials. Despite the recent surge of reports on microcrystalline, thin-film and bulk single-crystalline metal halides, very little is known about the photophysics of metal halides in the form of uniform, size-tunable nanocrystals. Here we report low-threshold amplified spontaneous emission and lasing from ∼10 nm monodisperse colloidal nanocrystals of caesium lead halide perovskites CsPbX3 (X=Cl, Br or I, or mixed Cl/Br and Br/I systems). We find that room-temperature optical amplification can be obtained in the entire visible spectral range (440-700 nm) with low pump thresholds down to 5±1 μJ cm(-2) and high values of modal net gain of at least 450±30 cm(-1). Two kinds of lasing modes are successfully observed: whispering-gallery-mode lasing using silica microspheres as high-finesse resonators, conformally coated with CsPbX3 nanocrystals and random lasing in films of CsPbX3 nanocrystals.', '2026-07-07 23:40:33');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2509883496', 'chemistry', 'Multidimensional materials and device architectures for future hybrid energy storage', 'Electrical energy storage plays a vital role in daily life due to our dependence on numerous portable electronic devices. Moreover, with the continued miniaturization of electronics, integration of…', '2016', 2016, 1604, 1604, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fncomms12647/MediaObjects/41467_2016_Article_BFncomms12647_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5023960', 'pmc', 'review', 'Nature Communications', '["Maria R. Lukatskaya","Bruce Dunn","Yury Gogotsi"]', 'chemistry', 'Electrical energy storage plays a vital role in daily life due to our dependence on numerous portable electronic devices. Moreover, with the continued miniaturization of electronics, integration of wireless devices into our homes and clothes and the widely anticipated ''Internet of Things'', there are intensive efforts to develop miniature yet powerful electrical energy storage devices. This review addresses the cutting edge of electrical energy storage technology, outlining approaches to overcome current limitations and providing future research directions towards the next generation of electrical energy storage devices whose characteristics represent a true hybridization of batteries and electrochemical capacitors.', '2026-07-07 23:40:34');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2790701366', 'chemistry', 'Identification of distinct nanoparticles and subsets of extracellular vesicles by asymmetric flow field-flow fractionation', 'Identification of distinct nanoparticles and subsets of extracellular vesicles by asymmetric flow field-flow fractionation', '2018', 2018, 1607, 1607, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41556-018-0040-4/MediaObjects/41556_2018_40_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5931706', 'pmc', 'article', 'Nature Cell Biology', '["Haiying Zhang","Daniela Freitas","Han Sang Kim","Kristina Ivana Fabijanic","Zhong Li","Haiyan Chen","Milica Tešić Mark","Henrik Molina","Alberto Benito‐Martín","Linda Bojmar","Justin Fang","Sham Rampersaud","Ayuko Hoshino","Irina Matei","Candia M. Kenific","Miho Nakajima","Anders P. Mutvei","Pasquale Sansone","Weston Buehring","Huajuan Wang","Juan Pablo Jiménez Navarro","Leona Cohen‐Gould","Navid Paknejad","Matthew Brendel","Katia Manova‐Todorova","Ana Magalhães","José Alexandre Ferreira","Hugo Osório","André M. N. Silva","Ashish C. Massey","Juan R. Cubillos‐Ruiz","Giuseppe Galletti","Paraskevi Giannakakou","Ana María Cuervo","John Blenis","Robert E. Schwartz","Mary Sue Brady","Héctor Peinado","Jacqueline Bromberg","Hiroshi Matsui","Celso A. Reis","David Lyden"]', 'chemistry', NULL, '2026-07-07 23:40:34');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2193503481', 'engineering', 'Overview of the Coupled Model Intercomparison Project Phase 6 (CMIP6) experimental design and organization', 'Abstract. By coordinating the design and distribution of global climate model simulations of the past, current, and future climate, the Coupled Model Intercomparison Project (CMIP) has become one of…', '2016', 2016, 12035, 12035, 'https://www.geoscientific-model-development.net/graphic_egu_claim_logo_blue.png', 'https://doi.org/10.5194/gmd-9-1937-2016', 'repository', 'article', 'Geoscientific model development', '["Veronika Eyring","Sandrine Bony","Gerald A. Meehl","C. A. Senior","Björn Stevens","Ronald J. Stouffer","Karl E. Taylor"]', 'engineering', 'Abstract. By coordinating the design and distribution of global climate model simulations of the past, current, and future climate, the Coupled Model Intercomparison Project (CMIP) has become one of the foundational elements of climate science. However, the need to address an ever-expanding range of scientific questions arising from more and more research communities has made it necessary to revise the organization of CMIP. After a long and wide community consultation, a new and more federated structure has been put in place. It consists of three major elements: (1) a handful of common experiments, the DECK (Diagnostic, Evaluation and Characterization of Klima) and CMIP historical simulations (1850–near present) that will maintain continuity and help document basic characteristics of models across different phases of CMIP; (2) common standards, coordination, infrastructure, and documentation that will facilitate the distribution of model outputs and the characterization of the model ensemble; and (3) an ensemble of CMIP-Endorsed Model Intercomparison Projects (MIPs) that will be specific to a particular phase of CMIP (now CMIP6) and that will build on the DECK and CMIP historical simulations to address a large range of specific questions and fill the scientific gaps of the previous CMIP phases. The DECK and CMIP historical simulations, together with the use of CMIP data standards, will be the entry cards for models participating in CMIP. Participation in CMIP6-Endorsed MIPs by individual modelling groups will be at their own discretion and will depend on their scientific interests and priorities. With the Grand Science Challenges of the World Climate Research Programme (WCRP) as its scientific backdrop, CMIP6 will address three broad questions: – How does the Earth system respond to forcing? – What are the origins and consequences of systematic model biases? – How can we assess future climate changes given internal climate variability, predictability, and uncertainties in scenarios? This CMIP6 overview paper presents the background and rationale for the new structure of CMIP, provides a detailed description of the DECK and CMIP6 historical simulations, and includes a brief introduction to the 21 CMIP6-Endorsed MIPs.', '2026-07-07 23:41:00');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2901669506', 'engineering', 'Systematic review or scoping review? Guidance for authors when choosing between a systematic or scoping review approach', 'BACKGROUND: Scoping reviews are a relatively new approach to evidence synthesis and currently there exists little guidance regarding the decision to choose between a systematic review or scoping…', '2018', 2018, 11059, 11059, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs13643-018-0856-9/MediaObjects/13643_2018_856_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6245623', 'pmc', 'article', 'BMC Medical Research Methodology', '["Zachary Munn","Micah D.J. Peters","Cindy Stern","Cătălin Tufănaru","Alexa McArthur","Edoardo Aromataris"]', 'engineering', 'BACKGROUND: Scoping reviews are a relatively new approach to evidence synthesis and currently there exists little guidance regarding the decision to choose between a systematic review or scoping review approach when synthesising evidence. The purpose of this article is to clearly describe the differences in indications between scoping reviews and systematic reviews and to provide guidance for when a scoping review is (and is not) appropriate. RESULTS: Researchers may conduct scoping reviews instead of systematic reviews where the purpose of the review is to identify knowledge gaps, scope a body of literature, clarify concepts or to investigate research conduct. While useful in their own right, scoping reviews may also be helpful precursors to systematic reviews and can be used to confirm the relevance of inclusion criteria and potential questions. CONCLUSIONS: Scoping reviews are a useful tool in the ever increasing arsenal of evidence synthesis approaches. Although conducted for different purposes compared to systematic reviews, scoping reviews still require rigorous and transparent methods in their conduct to ensure that the results are trustworthy. Our hope is that with clear guidance available regarding whether to conduct a scoping review or a systematic review, there will be less scoping reviews being performed for inappropriate indications better served by a systematic review, and vice-versa.', '2026-07-07 23:41:01');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3144543375', 'engineering', 'The PRISMA 2020 statement: an updated guideline for reporting systematic reviews', 'The Preferred Reporting Items for Systematic reviews and Meta-Analyses (PRISMA) statement, published in 2009, was designed to help systematic reviewers transparently report why the review was done,…', '2021', 2021, 13565, 13565, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs13643-021-01626-4/MediaObjects/13643_2021_1626_Fig1_HTML.png', 'https://systematicreviewsjournal.biomedcentral.com/track/pdf/10.1186/s13643-021-01626-4', 'repository', 'article', 'Systematic Reviews', '["Matthew J. Page","Joanne E. McKenzie","Patrick M. Bossuyt","Isabelle Boutron","Tammy Hoffmann","Cynthia D. Mulrow","Larissa Shamseer","Jennifer Tetzlaff","Elie A. Akl","Sue Brennan","Roger Chou","Julie Glanville","Jeremy Grimshaw","Asbjørn Hróbjartsson","Manoj M. Lalu","Tianjing Li","Elizabeth Loder","Evan Mayo‐Wilson","Steve McDonald","Luke A. McGuinness","Lesley Stewart","James Thomas","Andrea C. Tricco","Vivian Welch","Penny Whiting","David Moher"]', 'engineering', 'The Preferred Reporting Items for Systematic reviews and Meta-Analyses (PRISMA) statement, published in 2009, was designed to help systematic reviewers transparently report why the review was done, what the authors did, and what they found. Over the past decade, advances in systematic review methodology and terminology have necessitated an update to the guideline. The PRISMA 2020 statement replaces the 2009 statement and includes new reporting guidance that reflects advances in methods to identify, select, appraise, and synthesise studies. The structure and presentation of the items have been modified to facilitate implementation. In this article, we present the PRISMA 2020 27-item checklist, an expanded checklist that details reporting recommendations for each item, the PRISMA 2020 abstract checklist, and the revised flow diagrams for original and updated reviews.', '2026-07-07 23:41:02');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2588003345', 'engineering', 'SoilGrids250m: Global gridded soil information based on machine learning', 'This paper describes the technical development and accuracy assessment of the most recent and improved version of the SoilGrids system at 250m resolution (June 2016 update). SoilGrids provides global…', '2017', 2017, 4698, 4698, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0169748.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5313206', 'pmc', 'article', 'PLoS ONE', '["Tomislav Hengl","Jorge Mendes de Jesus","G.B.M. Heuvelink","M. Ruiperez González","Milan Kilibarda","Aleksandar Blagotić","Wei Shangguan","Marvin N. Wright","Xiaoyuan Geng","Bernhard Bauer-Marschallinger","Mário Guevara","Rodrigo Vargas","R.A. MacMillan","N.H. Batjes","J.G.B. Leenaars","Eloi Ribeiro","Ichsani Wheeler","S. Mantel","Bas Kempen"]', 'engineering', 'This paper describes the technical development and accuracy assessment of the most recent and improved version of the SoilGrids system at 250m resolution (June 2016 update). SoilGrids provides global predictions for standard numeric soil properties (organic carbon, bulk density, Cation Exchange Capacity (CEC), pH, soil texture fractions and coarse fragments) at seven standard depths (0, 5, 15, 30, 60, 100 and 200 cm), in addition to predictions of depth to bedrock and distribution of soil classes based on the World Reference Base (WRB) and USDA classification systems (ca. 280 raster layers in total). Predictions were based on ca. 150,000 soil profiles used for training and a stack of 158 remote sensing-based soil covariates (primarily derived from MODIS land products, SRTM DEM derivatives, climatic images and global landform and lithology maps), which were used to fit an ensemble of machine learning methods-random forest and gradient boosting and/or multinomial logistic regression-as implemented in the R packages ranger, xgboost, nnet and caret. The results of 10-fold cross-validation show that the ensemble models explain between 56% (coarse fragments) and 83% (pH) of variation with an overall average of 61%. Improvements in the relative accuracy considering the amount of variation explained, in comparison to the previous version of SoilGrids at 1 km spatial resolution, range from 60 to 230%. Improvements can be attributed to: (1) the use of machine learning instead of linear regression, (2) to considerable investments in preparing finer resolution covariate layers and (3) to insertion of additional soil profiles. Further development of SoilGrids could include refinement of methods to incorporate input uncertainties and derivation of posterior probability distributions (per pixel), and further automation of spatial modeling so that soil maps can be generated for potentially hundreds of soil variables. Another area of future research is the development of methods for multiscale merging of SoilGrids predictions with local and/or national gridded soil products (e.g. up to 50 m spatial resolution) so that increasingly more accurate, complete and consistent global soil information can be produced. SoilGrids are available under the Open Data Base License.', '2026-07-07 23:42:58');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2564178799', 'engineering', 'The path towards sustainable energy', 'The path towards sustainable energy', '2016', 2016, 4740, 4740, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnmat4834/MediaObjects/41563_2017_Article_BFnmat4834_Fig1_HTML.jpg', 'https://pubmed.ncbi.nlm.nih.gov/27994253', 'repository', 'article', 'Nature Materials', '["Steven Chu","Yi Cui","Nian Liu"]', 'engineering', NULL, '2026-07-07 23:43:03');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2969625533', 'engineering', 'Artificial Intelligence (AI): Multidisciplinary perspectives on emerging challenges, opportunities, and agenda for research, practice and policy', 'As far back as the industrial revolution, significant development in technical innovation has succeeded in transforming numerous manual tasks and processes that had been in existence for decades…', '2019', 2019, 4077, 4077, 'https://ars.els-cdn.com/content/image/1-s2.0-S026840121930917X-gr1.jpg', 'https://doi.org/10.1016/j.ijinfomgt.2019.08.002', 'repository', 'article', 'International Journal of Information Management', '["Yogesh K. Dwivedi","Laurie Hughes","Elvira Ismagilova","Gert Aarts","Crispin Coombs","Tom Crick","Yanqing Duan","Rohita Dwivedi","John S. Edwards","Aled Eirug","Vassilis Galanos","P. Vigneswara Ilavarasan","Marijn Janssen","Paul Jones","Arpan Kumar Kar","Hatice Kizgin","Bianca Kronemann","Banita Lal","Biagio Lucini","Rony Medaglia","Kenneth Le Meunier‐FitzHugh","Leslie Caroline Le Meunier-FitzHugh","Santosh K. Misra","Emmanuel Mogaji","Sujeet Kumar Sharma","Jang Bahadur Singh","Vishnupriya Raghavan","Ramakrishnan Raman","Nripendra P. Rana","Spyridon Samothrakis","Jak Spencer","Kuttimani Tamilmani","Annie Tubadji","Paul Walton","Michael D. Williams"]', 'engineering', 'As far back as the industrial revolution, significant development in technical innovation has succeeded in transforming numerous manual tasks and processes that had been in existence for decades where humans had reached the limits of physical capacity. Artificial Intelligence (AI) offers this same transformative potential for the augmentation and potential replacement of human tasks and activities within a wide range of industrial, intellectual and social applications. The pace of change for this new AI technological age is staggering, with new breakthroughs in algorithmic machine learning and autonomous decision-making, engendering new opportunities for continued innovation. The impact of AI could be significant, with industries ranging from: finance, healthcare, manufacturing, retail, supply chain, logistics and utilities, all potentially disrupted by the onset of AI technologies. The study brings together the collective insight from a number of leading expert contributors to highlight the significant opportunities, realistic assessment of impact, challenges and potential research agenda posed by the rapid emergence of AI within a number of domains: business and management, government, public sector, and science and technology. This research offers significant and timely insight to AI technology and its impact on the future of industry and society in general, whilst recognising the societal and industrial influence on pace and direction of AI development.', '2026-07-07 23:43:18');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4360620450', 'engineering', 'Opinion Paper: “So what if ChatGPT wrote it?” Multidisciplinary perspectives on opportunities, challenges and implications of generative conversational AI for research, practice and policy', 'Transformative artificially intelligent tools, such as ChatGPT, designed to generate sophisticated text indistinguishable from that produced by a human, are applicable across a wide range of…', '2023', 2023, 3766, 3766, 'https://ars.els-cdn.com/content/image/1-s2.0-S0268401223000233-gr1.jpg', 'https://doi.org/10.1016/j.ijinfomgt.2023.102642', 'repository', 'article', 'International Journal of Information Management', '["Yogesh K. Dwivedi","Nir Kshetri","Laurie Hughes","Emma Slade","Anand Jeyaraj","Arpan Kumar Kar","Abdullah M. Baabdullah","Alex Koohang","Vishnupriya Raghavan","Manju Ahuja","Hanaa Albanna","Mousa Ahmad Albashrawi","Adil S. Al-Busaidi","Janarthanan Balakrishnan","Yves Barlette","Sriparna Basu","Indranil Bose","Laurence Brooks","Dimitrios Buhalis","Lemuria Carter","Soumyadeb Chowdhury","Tom Crick","Scott W. Cunningham","Gareth H. Davies","Robert M. Davison","Rahul Dé","Denis Dennehy","Yanqing Duan","Rameshwar Dubey","Rohita Dwivedi","John S. Edwards","Carlos Flavián","Robin Gauld","Varun Grover","Mei‐Chih Hu","Marijn Janssen","Paul Jones","Iris Junglas","Sangeeta Khorana","Sascha Kraus","Kai R. Larsen","Paul Latreille","Sven Laumer","Tegwen Malik","Abbas Mardani","Marcello Mariani","Sunil Mithas","Emmanuel Mogaji","Jeretta Horn Nord","Siobhán O’Connor","Fevzi Okumus","Margherita Pagani","Neeraj Pandey","Savvas Papagiannidis","Ilias O. Pappas","Nishith Pathak","Jan Pries‐Heje","Ramakrishnan Raman","Nripendra P. Rana","Sven‐Volker Rehm","Samuel Ribeiro‐Navarrete","Alexander Richter","Frantz Rowe","Suprateek Sarker","Bernd Carsten Stahl","Manoj Tiwari","Wil van der Aalst","Viswanath Venkatesh","Giampaolo Viglia","Michael Wade","Paul Walton","Jochen Wirtz","Ryan Wright"]', 'engineering', 'Transformative artificially intelligent tools, such as ChatGPT, designed to generate sophisticated text indistinguishable from that produced by a human, are applicable across a wide range of contexts. The technology presents opportunities as well as, often ethical and legal, challenges, and has the potential for both positive and negative impacts for organisations, society, and individuals. Offering multi-disciplinary insight into some of these, this article brings together 43 contributions from experts in fields such as computer science, marketing, information systems, education, policy, hospitality and tourism, management, publishing, and nursing. The contributors acknowledge ChatGPT’s capabilities to enhance productivity and suggest that it is likely to offer significant gains in the banking, hospitality and tourism, and information technology industries, and enhance business activities, such as management and marketing. Nevertheless, they also consider its limitations, disruptions to practices, threats to privacy and security, and consequences of biases, misuse, and misinformation. However, opinion is split on whether ChatGPT’s use should be restricted or legislated. Drawing on these contributions, the article identifies questions requiring further research across three thematic areas: knowledge, transparency, and ethics; digital transformation of organisations and societies; and teaching, learning, and scholarly research. The avenues for further research include: identifying skills, resources, and capabilities needed to handle generative AI; examining biases of generative AI attributable to training datasets and processes; exploring business and societal contexts best suited for generative AI implementation; determining optimal combinations of human and generative AI for various tasks; identifying ways to assess accuracy of text produced by generative AI; and uncovering the ethical and legal issues in using generative AI across different contexts.', '2026-07-07 23:43:47');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3008985036', 'engineering', 'Sensitivity of Chest CT for COVID-19: Comparison to RT-PCR', 'Sensitivity of Chest CT for COVID-19: Comparison to RT-PCR', '2020', 2020, 3584, 3584, 'https://cdn.ncbi.nlm.nih.gov/pmc/blobs/f971/7233365/dca4aa346cf7/radiol.2020200432.fig1.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7233365', 'pmc', 'article', 'Radiology', '["Yicheng Fang","Huangqi Zhang","Jicheng Xie","Minjie Lin","Lingjun Ying","Peipei Pang","Wenbin Ji"]', 'engineering', NULL, '2026-07-07 23:43:54');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2921112006', 'engineering', 'Global, regional, and national burden of stroke, 1990–2016: a systematic analysis for the Global Burden of Disease Study 2016', 'BACKGROUND: Stroke is a leading cause of mortality and disability worldwide and the economic costs of treatment and post-stroke care are substantial. The Global Burden of Diseases, Injuries, and Risk…', '2019', 2019, 3369, 3369, 'https://ars.els-cdn.com/content/image/1-s2.0-S1474442219300341-gr1.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6494974', 'pmc', 'article', 'The Lancet Neurology', '["Catherine O. Johnson","Minh Nguyen","Gregory A. Roth","Emma Nichols","Shazia Alam","Degu Abate","Foad Abd-Allah","Ahmed Abdelalim","Haftom Niguse Abraha","Niveen ME Abu-Rmeileh","Oladimeji Adebayo","Abiodun M. Adeoye","Gina Agarwal","Sutapa Agrawal","Amani Nidhal Aichour","Ibtihel Aichour","Miloud Taki Eddine Aichour","Fares Alahdab","Raghib Ali","Nelson Alvis‐Guzmán","Nahla Anber","Mina Anjomshoa","Jalal Arabloo","Antonio Araúz","Johan Ärnlöv","Amit Arora","Ashish Awasthi","Maciej Banach","Miguel A. Barboza","Suzanne Barker‐Collo","Till Bärnighausen","Sanjay Basu","Abate Bekele Belachew","Yaschilal Muche Belayneh","Derrick Bennett","Isabela M. Benseñor","Krittika Bhattacharyya","Belete Biadgo","Ali Bijani","Boris Bikbov","Muhammad Shahdaat Bin Sayeed","Zahid A Butt","Lucero Cahuana-Hurtado","Juan Jesús Carrero","Félix Carvalho","Carlos A Castañeda-Orjuela","Franz Castro","Ferrán Catalá-López","Yazan Chaiah","Peggy Pei-Chia Chiang","Jee-Young J Choi","Hanne Christensen","Dinh‐Toi Chu","Monica Cortinovis","Albertino Damasceno","Lalit Dandona","Rakhi Dandona","Ahmad Daryani","Kairat Davletov","Barbora de Courten","Vanessa De la Cruz‐Góngora","Meaza Girma Degefa","Samath Dhamminda Dharmaratne","Daniel Díaz","Manisha Dubey","Eyasu Ejeta Duken","Dumessa Edessa","Matthias Endres","Emerito Jose A Faraon","Farshad Farzadfar","Eduarda Fernandes","Florian Fischer","Luísa Sório Flor","Morsaleh Ganji","Abadi Kahsu Gebre","Teklu Gebrehiwo Gebremichael","Birhanu Geta","Kebede Embaye Gezae","Paramjit Gill","E. V. Gnedovskaya","Hector Gómez‐Dantés","Alessandra C. Goulart","Giuseppe Grosso","Yuming Guo","Rajeev Gupta","Arvin Haj‐Mirzaian","Arya Haj‐Mirzaian","Samer Hamidi","Graeme J. Hankey","Hamid Yimam Hassen","Simon I Hay","Mohamed Hegazy","Behnam Heidari","Nabeel Herial","Mohammad Ali Hosseini","Sorin Hostiuc","Seyed Sina Naghibi Irvani","Sheikh Mohammed Shariful Islam","Nader Jahanmehr","Mehdi Javanbakht"]', 'engineering', 'BACKGROUND: Stroke is a leading cause of mortality and disability worldwide and the economic costs of treatment and post-stroke care are substantial. The Global Burden of Diseases, Injuries, and Risk Factors Study (GBD) provides a systematic, comparable method of quantifying health loss by disease, age, sex, year, and location to provide information to health systems and policy makers on more than 300 causes of disease and injury, including stroke. The results presented here are the estimates of burden due to overall stroke and ischaemic and haemorrhagic stroke from GBD 2016. METHODS: We report estimates and corresponding uncertainty intervals (UIs), from 1990 to 2016, for incidence, prevalence, deaths, years of life lost (YLLs), years lived with disability (YLDs), and disability-adjusted life-years (DALYs). DALYs were generated by summing YLLs and YLDs. Cause-specific mortality was estimated using an ensemble modelling process with vital registration and verbal autopsy data as inputs. Non-fatal estimates were generated using Bayesian meta-regression incorporating data from registries, scientific literature, administrative records, and surveys. The Socio-demographic Index (SDI), a summary indicator generated using educational attainment, lagged distributed income, and total fertility rate, was used to group countries into quintiles. FINDINGS: In 2016, there were 5·5 million (95% UI 5·3 to 5·7) deaths and 116·4 million (111·4 to 121·4) DALYs due to stroke. The global age-standardised mortality rate decreased by 36·2% (-39·3 to -33·6) from 1990 to 2016, with decreases in all SDI quintiles. Over the same period, the global age-standardised DALY rate declined by 34·2% (-37·2 to -31·5), also with decreases in all SDI quintiles. There were 13·7 million (12·7 to 14·7) new stroke cases in 2016. Global age-standardised incidence declined by 8·1% (-10·7 to -5·5) from 1990 to 2016 and decreased in all SDI quintiles except the middle SDI group. There were 80·1 million (74·1 to 86·3) prevalent cases of stroke globally in 2016; 41·1 million (38·0 to 44·3) in women and 39·0 million (36·1 to 42·1) in men. INTERPRETATION: Although age-standardised mortality rates have decreased sharply from 1990 to 2016, the decrease in age-standardised incidence has been less steep, indicating that the burden of stroke is likely to remain high. Planned updates to future GBD iterations include generating separate estimates for subarachnoid haemorrhage and intracerebral haemorrhage, generating estimates of transient ischaemic attack, and including atrial fibrillation as a risk factor. FUNDING: Bill & Melinda Gates Foundation.', '2026-07-07 23:44:09');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2047775546', 'engineering', 'High rate and stable cycling of lithium metal anode', 'Lithium metal is an ideal battery anode. However, dendrite growth and limited Coulombic efficiency during cycling have prevented its practical application in rechargeable batteries. Herein, we report…', '2015', 2015, 2511, 2511, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fncomms7362/MediaObjects/41467_2015_Article_BFncomms7362_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4346622', 'pmc', 'article', 'Nature Communications', '["Jiangfeng Qian","Wesley A. Henderson","Wu Xu","Priyanka Bhattacharya","Mark Engelhard","Oleg Borodin","Ji‐Guang Zhang"]', 'engineering', 'Lithium metal is an ideal battery anode. However, dendrite growth and limited Coulombic efficiency during cycling have prevented its practical application in rechargeable batteries. Herein, we report that the use of highly concentrated electrolytes composed of ether solvents and the lithium bis(fluorosulfonyl)imide salt enables the high-rate cycling of a lithium metal anode at high Coulombic efficiency (up to 99.1%) without dendrite growth. With 4 M lithium bis(fluorosulfonyl)imide in 1,2-dimethoxyethane as the electrolyte, a lithium|lithium cell can be cycled at 10 mA cm(-2) for more than 6,000 cycles, and a copper|lithium cell can be cycled at 4 mA cm(-2) for more than 1,000 cycles with an average Coulombic efficiency of 98.4%. These excellent performances can be attributed to the increased solvent coordination and increased availability of lithium ion concentration in the electrolyte. Further development of this electrolyte may enable practical applications for lithium metal anode in rechargeable batteries.', '2026-07-07 23:46:27');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2220596051', 'engineering', 'Activating and optimizing MoS2 basal planes for hydrogen evolution through the formation of strained sulphur vacancies', 'Activating and optimizing MoS2 basal planes for hydrogen evolution through the formation of strained sulphur vacancies', '2015', 2015, 2503, 2503, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnmat4465/MediaObjects/41563_2016_Article_BFnmat4465_Fig1_HTML.jpg', 'https://pubmed.ncbi.nlm.nih.gov/26552057', 'repository', 'article', 'Nature Materials', '["Hong Li","Charlie Tsai","Ai Leen Koh","Lili Cai","Alex W. Contryman","Alex H. Fragapane","Jiheng Zhao","Hyun Soo Han","Hari C. Manoharan","Frank Abild‐Pedersen","Jens K. Nørskov","Xiaolin Zheng"]', 'engineering', NULL, '2026-07-07 23:46:30');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3211779138', 'engineering', 'Multivariable association discovery in population-scale meta-omics studies', 'It is challenging to associate features such as human health outcomes, diet, environmental conditions, or other metadata to microbial community measurements, due in part to their quantitative…', '2021', 2021, 2458, 2458, 'https://journals.plos.org/ploscompbiol/article/figure/image?size=large&id=10.1371/journal.pcbi.1009442.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8714082', 'pmc', 'article', 'PLoS Computational Biology', '["Himel Mallick","Ali Rahnavard","Lauren J. McIver","Siyuan Ma","Yancong Zhang","Long H. Nguyen","Timothy L. Tickle","George Weingart","Boyu Ren","Emma Schwager","Suvo Chatterjee","Kelsey N. Thompson","Jeremy E. Wilkinson","Ayshwarya Subramanian","Yiren Lu","Levi Waldron","Joseph N. Paulson","Eric A. Franzosa","Héctor Corrada Bravo","Curtis Huttenhower"]', 'engineering', 'It is challenging to associate features such as human health outcomes, diet, environmental conditions, or other metadata to microbial community measurements, due in part to their quantitative properties. Microbiome multi-omics are typically noisy, sparse (zero-inflated), high-dimensional, extremely non-normal, and often in the form of count or compositional measurements. Here we introduce an optimized combination of novel and established methodology to assess multivariable association of microbial community features with complex metadata in population-scale observational studies. Our approach, MaAsLin 2 (Microbiome Multivariable Associations with Linear Models), uses generalized linear and mixed models to accommodate a wide variety of modern epidemiological studies, including cross-sectional and longitudinal designs, as well as a variety of data types (e.g., counts and relative abundances) with or without covariates and repeated measurements. To construct this method, we conducted a large-scale evaluation of a broad range of scenarios under which straightforward identification of meta-omics associations can be challenging. These simulation studies reveal that MaAsLin 2''s linear model preserves statistical power in the presence of repeated measures and multiple covariates, while accounting for the nuances of meta-omics features and controlling false discovery. We also applied MaAsLin 2 to a microbial multi-omics dataset from the Integrative Human Microbiome (HMP2) project which, in addition to reproducing established results, revealed a unique, integrated landscape of inflammatory bowel diseases (IBD) across multiple time points and omics profiles.', '2026-07-07 23:46:42');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2934302500', 'engineering', 'Artificial intelligence for decision making in the era of Big Data – evolution, challenges and research agenda', 'Artificial intelligence for decision making in the era of Big Data – evolution, challenges and research agenda', '2019', 2019, 2466, 2466, 'https://ars.els-cdn.com/content/image/1-s2.0-S0268401219300581-gr1.jpg', 'https://doi.org/10.1016/j.ijinfomgt.2019.01.021', 'repository', 'article', 'International Journal of Information Management', '["Yanqing Duan","John S. Edwards","Yogesh K. Dwivedi"]', 'engineering', NULL, '2026-07-07 23:46:48');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4211056572', 'engineering', 'System for Automated Geoscientific Analyses (SAGA) v. 2.1.4', 'Abstract. The System for Automated Geoscientific Analyses (SAGA) is an open source geographic information system (GIS), mainly licensed under the GNU General Public License. Since its first release…', '2015', 2015, 2404, 2404, 'https://www.geoscientific-model-development.net/graphic_egu_claim_logo_blue.png', 'https://doi.org/10.5194/gmd-8-1991-2015', 'repository', 'article', 'Geoscientific model development', '["Olaf Conrad","Benjamin Bechtel","M. Bock","Helge Dietrich","Elke Kerstin Fischer","Lars Gerlitz","Jan Wehberg","Volker Wichmann","Jürgen Böhner"]', 'engineering', 'Abstract. The System for Automated Geoscientific Analyses (SAGA) is an open source geographic information system (GIS), mainly licensed under the GNU General Public License. Since its first release in 2004, SAGA has rapidly developed from a specialized tool for digital terrain analysis to a comprehensive and globally established GIS platform for scientific analysis and modeling. SAGA is coded in C++ in an object oriented design and runs under several operating systems including Windows and Linux. Key functional features of the modular software architecture comprise an application programming interface for the development and implementation of new geoscientific methods, a user friendly graphical user interface with many visualization options, a command line interpreter, and interfaces to interpreted languages like R and Python. The current version 2.1.4 offers more than 600 tools, which are implemented in dynamically loadable libraries or shared objects and represent the broad scopes of SAGA in numerous fields of geoscientific endeavor and beyond. In this paper, we inform about the system''s architecture, functionality, and its current state of development and implementation. Furthermore, we highlight the wide spectrum of scientific applications of SAGA in a review of published studies, with special emphasis on the core application areas digital terrain analysis, geomorphology, soil science, climatology and meteorology, as well as remote sensing.', '2026-07-07 23:46:54');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2899357412', 'engineering', 'Blockchain technology in the energy sector: A systematic review of challenges and opportunities', 'Blockchains or distributed ledgers are an emerging technology that has drawn considerable interest from energy supply firms, startups, technology developers, financial institutions, national…', '2018', 2018, 2360, 2360, 'https://ars.els-cdn.com/content/image/1-s2.0-S1364032118307184-gr1.jpg', 'https://doi.org/10.1016/j.rser.2018.10.014', 'repository', 'review', 'Renewable and Sustainable Energy Reviews', '["Merlinda Andoni","Valentin Robu","David Flynn","Simone Abram","Dale Geach","David Jenkins","Peter McCallum","Andrew Peacock"]', 'engineering', 'Blockchains or distributed ledgers are an emerging technology that has drawn considerable interest from energy supply firms, startups, technology developers, financial institutions, national governments and the academic community. Numerous sources coming from these backgrounds identify blockchains as having the potential to bring significant benefits and innovation. Blockchains promise transparent, tamper-proof and secure systems that can enable novel business solutions, especially when combined with smart contracts. This work provides a comprehensive overview of fundamental principles that underpin blockchain technologies, such as system architectures and distributed consensus algorithms. Next, we focus on blockchain solutions for the energy industry and inform the state-of-the-art by thoroughly reviewing the literature and current business cases. To our knowledge, this is one of the first academic, peer-reviewed works to provide a systematic review of blockchain activities and initiatives in the energy sector. Our study reviews 140 blockchain research projects and startups from which we construct a map of the potential and relevance of blockchains for energy applications. These initiatives were systematically classified into different groups according to the field of activity, implementation platform and consensus strategy used.1 Opportunities, potential challenges and limitations for a number of use cases are discussed, ranging from emerging peer-to-peer (P2P) energy trading and Internet of Things (IoT) applications, to decentralised marketplaces, electric vehicle charging and e-mobility. For each of these use cases, our contribution is twofold: first, in identifying the technical challenges that blockchain technology can solve for that application as well as its potential drawbacks, and second in briefly presenting the research and industrial projects and startups that are currently applying blockchain technology to that area. The paper ends with a discussion of challenges and market barriers the technology needs to overcome to get past the hype phase, prove its commercial viability and finally be adopted in the mainstream.', '2026-07-07 23:47:13');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2463406035', 'engineering', 'Global and regional effects of potentially modifiable risk factors associated with acute stroke in 32 countries (INTERSTROKE): a case-control study', 'Global and regional effects of potentially modifiable risk factors associated with acute stroke in 32 countries (INTERSTROKE): a case-control study', '2016', 2016, 2216, 2216, 'https://ars.els-cdn.com/content/image/1-s2.0-S0140673616305062-gr1.sml', 'https://pubmed.ncbi.nlm.nih.gov/27431356', 'repository', 'article', 'The Lancet', '["Martin O’Donnell","Siu Lim Chin","Sumathy Rangarajan","Denis Xavier","Lisheng Liu","Hongye Zhang","Rao Ps","Xiaohe Zhang","Prem Pais","Steven Agapay","Patricio López‐Jaramillo","Albertino Damasceno","Peter Langhorne","Matthew McQueen","Annika Rosengren","Mahshid Dehghan","Graeme J. Hankey","Antonio L Dans","Ahmed ElSayed","Álvaro Avezum","Charles Mondo","Hans‐Christoph Diener","Danuta Ryglewicz","Anna Członkowska","Nana Pogosova","Christian Weimar","Romaina Iqbal","Rafael Díaz","Khalid Yusoff","Afzalhussein Yusufali","Aytekin Oğuz","Xingyu Wang","Ernesto Peñaherrera","Fernando Laņas","Okechukwu S. Ogah","Adesola Ogunniyi","Helle K. Iversen","Germán Málaga","Zvonko Rumboldt","Shahram Oveisgharan","F Hussain","Daliwonga Magazi","Yongchai Nilanont","John Ferguson","Guillaume Paré","Salim Yusuf"]', 'engineering', NULL, '2026-07-07 23:47:53');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2923879367', 'engineering', 'Waste Mismanagement in Developing Countries: A Review of Global Issues', 'Environmental contamination due to solid waste mismanagement is a global issue. Open dumping and open burning are the main implemented waste treatment and final disposal systems, mainly visible in…', '2019', 2019, 2212, 2212, 'https://pub.mdpi-res.com/ijerph/ijerph-16-01060/article_deploy/html/images/ijerph-16-01060-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6466021', 'pmc', 'review', 'International Journal of Environmental Research and Public Health', '["Navarro Ferronato","Vincenzo Torretta"]', 'engineering', 'Environmental contamination due to solid waste mismanagement is a global issue. Open dumping and open burning are the main implemented waste treatment and final disposal systems, mainly visible in low-income countries. This paper reviews the main impacts due to waste mismanagement in developing countries, focusing on environmental contamination and social issues. The activity of the informal sector in developing cities was also reviewed, focusing on the main health risks due to waste scavenging. Results reported that the environmental impacts are pervasive worldwide: marine litter, air, soil and water contamination, and the direct interaction of waste pickers with hazardous waste are the most important issues. Many reviews were published in the scientific literature about specific waste streams, in order to quantify its effect on the environment. This narrative literature review assessed global issues due to different waste fractions showing how several sources of pollution are affecting the environment, population health, and sustainable development. The results and case studies presented can be of reference for scholars and stakeholders for quantifying the comprehensive impacts and for planning integrated solid waste collection and treatment systems, for improving sustainability at a global level.', '2026-07-07 23:47:56');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3161611462', 'engineering', 'Non-fullerene acceptors with branched side chains and improved molecular packing to exceed 18% efficiency in organic solar cells', 'Non-fullerene acceptors with branched side chains and improved molecular packing to exceed 18% efficiency in organic solar cells', '2021', 2021, 2146, 2146, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41560-021-00820-x/MediaObjects/41560_2021_820_Fig1_HTML.png', 'https://doi.org/10.1038/s41560-021-00820-x', 'repository', 'article', 'Nature Energy', '["Chao Li","Jiadong Zhou","Jiali Song","Jinqiu Xu","Huotian Zhang","Xuning Zhang","Jing Guo","Lei Zhu","Donghui Wei","Guangchao Han","Jie Min","Yuan Zhang","Zengqi Xie","Yuanping Yi","He Yan","Feng Gao","Feng Liu","Yanming Sun"]', 'engineering', NULL, '2026-07-07 23:48:17');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2805362231', 'engineering', 'In-memory computing with resistive switching devices', 'In-memory computing with resistive switching devices', '2018', 2018, 2162, 2162, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41928-018-0092-2/MediaObjects/41928_2018_92_Fig1_HTML.jpg', 'https://doi.org/10.1038/s41928-018-0092-2', 'repository', 'article', 'Nature Electronics', '["Daniele Ielmini","H.‐S. Philip Wong"]', 'engineering', NULL, '2026-07-07 23:48:17');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2990024397', 'engineering', 'Climate tipping points — too risky to bet against', 'Climate tipping points — too risky to bet against', '2019', 2019, 2144, 2144, 'https://media.nature.com/w140h79/springer-static/image/art%3A10.1038%2Fs41586-026-10731-0/MediaObjects/41586_2026_10731_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/31776487', 'repository', 'article', 'Nature', '["Timothy M. Lenton","Johan Rockström","Owen Gaffney","Stefan Rahmstorf","Katherine Richardson","Will Steffen","Hans Joachim Schellnhuber"]', 'engineering', NULL, '2026-07-07 23:48:18');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2487200295', 'engineering', 'Critical analysis of Big Data challenges and analytical methods', 'Big Data (BD), with their potential to ascertain valued insights for enhanced decision-making process, have recently attracted substantial interest from both academics and practitioners. Big Data…', '2016', 2016, 2016, 2016, 'https://ars.els-cdn.com/content/image/1-s2.0-S014829631630488X-gr1.jpg', 'https://doi.org/10.1016/j.jbusres.2016.08.001', 'repository', 'article', 'Journal of Business Research', '["Uthayasankar Sivarajah","Muhammad Mustafa Kamal","Zahir Irani","Vishanth Weerakkody"]', 'engineering', 'Big Data (BD), with their potential to ascertain valued insights for enhanced decision-making process, have recently attracted substantial interest from both academics and practitioners. Big Data Analytics (BDA) is increasingly becoming a trending practice that many organizations are adopting with the purpose of constructing valuable information from BD. The analytics process, including the deployment and use of BDA tools, is seen by organizations as a tool to improve operational efficiency though it has strategic potential, drive new revenue streams and gain competitive advantages over business rivals. However, there are different types of analytic applications to consider. Therefore, prior to hasty use and buying costly BD tools, there is a need for organizations to first understand the BDA landscape. Given the significant nature of the BD and BDA, this paper presents a state-of-the-art review that presents a holistic view of the BD challenges and BDA methods theorized/proposed/employed by organizations to help others understand this landscape with the objective of making robust investment decisions. In doing so, systematically analysing and synthesizing the extant research published on BD and BDA area. More specifically, the authors seek to answer the following two principal questions: Q1 – What are the different types of BD challenges theorized/proposed/confronted by organizations? and Q2 – What are the different types of BDA methods theorized/proposed/employed to overcome BD challenges?. This systematic literature review (SLR) is carried out through observing and understanding the past trends and extant patterns/themes in the BDA research area, evaluating contributions, summarizing knowledge, thereby identifying limitations, implications and potential further research avenues to support the academic community in exploring research themes/patterns. Thus, to trace the implementation of BD strategies, a profiling method is employed to analyze articles (published in English-speaking peer-reviewed journals between 1996 and 2015) extracted from the Scopus database. The analysis presented in this paper has identified relevant BD research studies that have contributed both conceptually and empirically to the expansion and accrual of intellectual wealth to the BDA in technology and organizational resource management discipline.', '2026-07-07 23:49:25');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3128415798', 'engineering', 'Fuzzy-set Qualitative Comparative Analysis (fsQCA): Guidelines for research practice in Information Systems and marketing', 'The increasing interest in fuzzy-set Qualitative Comparative Analysis (fsQCA) in Information Systems and marketing raises the need for a tutorial paper that discusses the basic concepts and…', '2021', 2021, 2008, 2008, 'https://ars.els-cdn.com/content/image/1-s2.0-S0268401221000037-fx1.jpg', 'https://doi.org/10.1016/j.ijinfomgt.2021.102310', 'repository', 'article', 'International Journal of Information Management', '["Ilias O. Pappas","Arch G. Woodside"]', 'engineering', 'The increasing interest in fuzzy-set Qualitative Comparative Analysis (fsQCA) in Information Systems and marketing raises the need for a tutorial paper that discusses the basic concepts and principles of the method, provide answers to typical questions that editors, reviewers, and authors would have when dealing with a new tool of analysis, and practically guide researchers on how to employ fsQCA. This article helps the reader to gain richer information from their data and understand the importance of avoiding shallow information‐from‐data reporting. To this end, it proposes a different research paradigm that includes asymmetric, configurational‐focused case‐outcome theory construction and somewhat precise outcome testing. This article offers a detailed step-by-step guide on how to employ fsQCA by using as an example an already published study. We analyze the same dataset and present all the details in each step of the analysis to guide the reader onto how to employ fsQCA. The article discusses differences between fsQCA and variance-based approaches and compares fsQCA with those from structured equation modelling. Finally, the article offers a summary of thresholds and guidelines for practice, along with a discussion on how existing papers that employ variance-based methods are extendable and complemented through fsQCA.', '2026-07-07 23:49:35');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2475009926', 'engineering', 'Design for Additive Manufacturing: Trends, opportunities, considerations, and constraints', 'Design for Additive Manufacturing: Trends, opportunities, considerations, and constraints', '2016', 2016, 1936, 1936, 'https://ars.els-cdn.com/content/image/1-s2.0-S0007850616301913-gr1.jpg', 'https://hal.science/hal-02380637', 'repository', 'article', 'CIRP Annals', '["Mary Kathryn Thompson","Giovanni Moroni","Tom Vaneker","Georges Fadel","R.I. Campbell","Ian Gibson","Alain Bernard","Joachim Schulz","Patricia Graf","Bhrigu Ahuja","Filomeno Martina"]', 'engineering', NULL, '2026-07-07 23:50:13');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2997242469', 'engineering', 'The History of Nanoscience and Nanotechnology: From Chemical–Physical Applications to Nanomedicine', 'Nanoscience breakthroughs in almost every field of science and nanotechnologies make life easier in this era. Nanoscience and nanotechnology represent an expanding research area, which involves…', '2019', 2019, 1939, 1939, 'https://pub.mdpi-res.com/molecules/molecules-25-00112/article_deploy/html/images/molecules-25-00112-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6982820', 'pmc', 'review', 'Molecules', '["Samer Bayda","Muhammad Adeel","Tiziano Tuccinardi","Marco Cordani","Flavio Rizzolio"]', 'engineering', 'Nanoscience breakthroughs in almost every field of science and nanotechnologies make life easier in this era. Nanoscience and nanotechnology represent an expanding research area, which involves structures, devices, and systems with novel properties and functions due to the arrangement of their atoms on the 1-100 nm scale. The field was subject to a growing public awareness and controversy in the early 2000s, and in turn, the beginnings of commercial applications of nanotechnology. Nanotechnologies contribute to almost every field of science, including physics, materials science, chemistry, biology, computer science, and engineering. Notably, in recent years nanotechnologies have been applied to human health with promising results, especially in the field of cancer treatment. To understand the nature of nanotechnology, it is helpful to review the timeline of discoveries that brought us to the current understanding of this science. This review illustrates the progress and main principles of nanoscience and nanotechnology and represents the pre-modern as well as modern timeline era of discoveries and milestones in these fields.', '2026-07-07 23:50:16');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2744045251', 'engineering', 'Enhanced sensitivity at higher-order exceptional points', 'Enhanced sensitivity at higher-order exceptional points', '2017', 2017, 1871, 1871, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature23280/MediaObjects/41586_2017_Article_BFnature23280_Fig1_HTML.jpg', 'https://pubmed.ncbi.nlm.nih.gov/28796201', 'repository', 'article', 'Nature', '["Hossein Hodaei","Absar U. Hassan","Steffen Wittek","Hipolito Garcia-Gracia","Ramy El‐Ganainy","Demetrios N. Christodoulides","Mercedeh Khajavikhan"]', 'engineering', NULL, '2026-07-07 23:50:50');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2580411523', 'engineering', 'Tunable sieving of ions using graphene oxide membranes', 'Tunable sieving of ions using graphene oxide membranes', '2017', 2017, 1841, 1841, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnnano.2017.21/MediaObjects/41565_2017_Article_BFnnano201721_Fig1_HTML.jpg', 'http://arxiv.org/abs/1701.05519', 'arxiv', 'article', 'Nature Nanotechnology', '["Jijo Abraham","K. S. Vasu","Christopher D. Williams","K. Gopinadhan","Yang Su","Christie Thomas Cherian","James A. Dix","Éric Prestat","Sarah J. Haigh","I. V. Grigorieva","Paola Carbone","A. K. Geǐm","Rahul R. Nair"]', 'engineering', NULL, '2026-07-07 23:51:17');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2799571143', 'engineering', 'Barriers to the Circular Economy: Evidence From the European Union (EU)', 'Barriers to the Circular Economy: Evidence From the European Union (EU)', '2018', 2018, 1790, 1790, 'https://ars.els-cdn.com/content/image/1-s2.0-S0921800917317573-gr1.jpg', 'https://doi.org/10.1016/j.ecolecon.2018.04.028', 'repository', 'article', 'Ecological Economics', '["Julian Kirchherr","Laura Piscicelli","Ruben Bour","Erica Kostense-Smit","Jennifer Muller","Anne Huibrechtse-Truijens","Marko P. Hekkert"]', 'engineering', NULL, '2026-07-07 23:51:47');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2794597140', 'engineering', 'Response of Plant Secondary Metabolites to Environmental Factors', 'Plant secondary metabolites (SMs) are not only a useful array of natural products but also an important part of plant defense system against pathogenic attacks and environmental stresses. With…', '2018', 2018, 1701, 1701, 'https://pub.mdpi-res.com/molecules/molecules-23-00762/article_deploy/html/images/molecules-23-00762-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6017249', 'pmc', 'review', 'Molecules', '["Yang Li","Kuishan Wen","Xiao Ruan","Yingxian Zhao","Feng Wei","Qiang Wang"]', 'engineering', 'Plant secondary metabolites (SMs) are not only a useful array of natural products but also an important part of plant defense system against pathogenic attacks and environmental stresses. With remarkable biological activities, plant SMs are increasingly used as medicine ingredients and food additives for therapeutic, aromatic and culinary purposes. Various genetic, ontogenic, morphogenetic and environmental factors can influence the biosynthesis and accumulation of SMs. According to the literature reports, for example, SMs accumulation is strongly dependent on a variety of environmental factors such as light, temperature, soil water, soil fertility and salinity, and for most plants, a change in an individual factor may alter the content of SMs even if other factors remain constant. Here, we review with emphasis how each of single factors to affect the accumulation of plant secondary metabolites, and conduct a comparative analysis of relevant natural products in the stressed and unstressed plants. Expectantly, this documentary review will outline a general picture of environmental factors responsible for fluctuation in plant SMs, provide a practical way to obtain consistent quality and high quantity of bioactive compounds in vegetation, and present some suggestions for future research and development.', '2026-07-07 23:53:23');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2509613771', 'engineering', 'Long-term patterns of European PV output using 30 years of validated hourly reanalysis and satellite data', 'Solar PV is rapidly growing globally, creating difficult questions around how to efficiently integrate it into national electricity grids. Its time-varying power output is difficult to model credibly…', '2016', 2016, 1645, 1645, 'https://ars.els-cdn.com/content/image/1-s2.0-S0360544216311744-gr1.jpg', 'https://doi.org/10.1016/j.energy.2016.08.060', 'repository', 'article', 'Energy', '["Stefan Pfenninger","Iain Staffell"]', 'engineering', 'Solar PV is rapidly growing globally, creating difficult questions around how to efficiently integrate it into national electricity grids. Its time-varying power output is difficult to model credibly because it depends on complex and variable weather systems, leading to difficulty in understanding its potential and limitations. We demonstrate how the MERRA and MERRA-2 global meteorological reanalyses as well as the Meteosat-based CM-SAF SARAH satellite dataset can be used to produce hourly PV simulations across Europe. To validate these simulations, we gather metered time series from more than 1000 PV systems as well as national aggregate output reported by transmission network operators. We find slightly better accuracy from satellite data, but greater stability from reanalysis data. We correct for systematic bias by matching our simulations to the mean bias in modeling individual sites, then examine the long-term patterns, variability and correlation with power demand across Europe, using thirty years of simulated outputs. The results quantify how the increasing deployment of PV substantially changes net power demand and affects system adequacy and ramping requirements, with heterogeneous impacts across different European countries. The simulation code and the hourly simulations for all European countries are available freely via an interactive web platform, www.renewables.ninja.', '2026-07-07 23:53:54');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2921524827', 'engineering', 'Stroke in China: advances and challenges in epidemiology, prevention, and management', 'Stroke in China: advances and challenges in epidemiology, prevention, and management', '2019', 2019, 1617, 1617, 'https://ars.els-cdn.com/content/image/1-s2.0-S1474442218305003-gr1.jpg', 'https://pubmed.ncbi.nlm.nih.gov/30878104', 'repository', 'review', 'The Lancet Neurology', '["Simiao Wu","Bo Wu","Ming Liu","Zhengming Chen","Wenzhi Wang","Craig S Anderson","Peter Sandercock","Yongjun Wang","Yining Huang","Liying Cui","Chuanqiang Pu","Jianping Jia","Tong Zhang","Xinfeng Liu","Suming Zhang","Peng Xie","Dongsheng Fan","Xunming Ji","Ka Sing Wong","Longde Wang","Simiao Wu","Bo Wu","Ming Liu","Zhengming Chen","Wenzhi Wang","Craig S Anderson","Peter Sandercock","Yongjun Wang","Yining Huang","Liying Cui","Chuanqiang Pu","Jianping Jia","Tong Zhang","Xinfeng Liu","Suming Zhang","Peng Xie","Dongsheng Fan","Xunming Ji","Ka Sing Wong","Longde Wang","Chenchen Wei","Yanan Wang","Yajun Cheng","Yunhai Liu","Xin Li","Qiang Dong","Jinsheng Zeng","Bin Peng","Yun Xu","Yi Yang","Yilong Wang","Gang Zhao","Wei Wang","Yuming Xu","Qingwu Yang","Zhiyi He","Shaoshi Wang","Chao You","Ying Gao","Dong Zhou","Li He","Zixiao Li","Jie Yang","Chunyan Lei","Yuhua Zhao","Junfeng Liu","Shuting Zhang","Wendan Tao","Zilong Hao","Deren Wang","Shihong Zhang"]', 'engineering', NULL, '2026-07-07 23:54:40');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2297046696', 'engineering', 'Defining Feasibility and Pilot Studies in Preparation for Randomised Controlled Trials: Development of a Conceptual Framework', 'We describe a framework for defining pilot and feasibility studies focusing on studies conducted in preparation for a randomised controlled trial. To develop the framework, we undertook a Delphi…', '2016', 2016, 1596, 1596, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0150205.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4792418', 'pmc', 'article', 'PLoS ONE', '["Sandra Eldridge","Gillian Lancaster","Michael J. Campbell","Lehana Thabane","Sally Hopewell","Claire Coleman","Christine Bond"]', 'engineering', 'We describe a framework for defining pilot and feasibility studies focusing on studies conducted in preparation for a randomised controlled trial. To develop the framework, we undertook a Delphi survey; ran an open meeting at a trial methodology conference; conducted a review of definitions outside the health research context; consulted experts at an international consensus meeting; and reviewed 27 empirical pilot or feasibility studies. We initially adopted mutually exclusive definitions of pilot and feasibility studies. However, some Delphi survey respondents and the majority of open meeting attendees disagreed with the idea of mutually exclusive definitions. Their viewpoint was supported by definitions outside the health research context, the use of the terms ''pilot'' and ''feasibility'' in the literature, and participants at the international consensus meeting. In our framework, pilot studies are a subset of feasibility studies, rather than the two being mutually exclusive. A feasibility study asks whether something can be done, should we proceed with it, and if so, how. A pilot study asks the same questions but also has a specific design feature: in a pilot study a future study, or part of a future study, is conducted on a smaller scale. We suggest that to facilitate their identification, these studies should be clearly identified using the terms ''feasibility'' or ''pilot'' as appropriate. This should include feasibility studies that are largely qualitative; we found these difficult to identify in electronic searches because researchers rarely used the term ''feasibility'' in the title or abstract of such studies. Investigators should also report appropriate objectives and methods related to feasibility; and give clear confirmation that their study is in preparation for a future randomised controlled trial designed to assess the effect of an intervention.', '2026-07-07 23:55:01');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2796282060', 'engineering', 'Review on modeling of the anode solid electrolyte interphase (SEI) for lithium-ion batteries', 'Abstract A passivation layer called the solid electrolyte interphase (SEI) is formed on electrode surfaces from decomposition products of electrolytes. The SEI allows Li + transport and blocks…', '2018', 2018, 1594, 1594, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41524-018-0064-0/MediaObjects/41524_2018_64_Fig1_HTML.jpg', 'https://doi.org/10.1038/s41524-018-0064-0', 'repository', 'article', 'npj Computational Materials', '["Aiping Wang","Sanket Kadam","Hong Li","Siqi Shi","Yue Qi"]', 'engineering', 'Abstract A passivation layer called the solid electrolyte interphase (SEI) is formed on electrode surfaces from decomposition products of electrolytes. The SEI allows Li + transport and blocks electrons in order to prevent further electrolyte decomposition and ensure continued electrochemical reactions. The formation and growth mechanism of the nanometer thick SEI films are yet to be completely understood owing to their complex structure and lack of reliable in situ experimental techniques. Significant advances in computational methods have made it possible to predictively model the fundamentals of SEI. This review aims to give an overview of state-of-the-art modeling progress in the investigation of SEI films on the anodes, ranging from electronic structure calculations to mesoscale modeling, covering the thermodynamics and kinetics of electrolyte reduction reactions, SEI formation, modification through electrolyte design, correlation of SEI properties with battery performance, and the artificial SEI design. Multi-scale simulations have been summarized and compared with each other as well as with experiments. Computational details of the fundamental properties of SEI, such as electron tunneling, Li-ion transport, chemical/mechanical stability of the bulk SEI and electrode/(SEI/) electrolyte interfaces have been discussed. This review shows the potential of computational approaches in the deconvolution of SEI properties and design of artificial SEI. We believe that computational modeling can be integrated with experiments to complement each other and lead to a better understanding of the complex SEI for the development of a highly efficient battery in the future.', '2026-07-07 23:55:04');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2784648660', 'engineering', 'Inverse design in nanophotonics', 'Inverse design in nanophotonics', '2018', 2018, 1602, 1602, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41566-018-0246-9/MediaObjects/41566_2018_246_Fig1_HTML.png', 'http://arxiv.org/abs/1801.06715', 'arxiv', 'article', 'Nature Photonics', '["Sean Molesky","Zin Lin","Alexander Y. Piggott","Weiliang Jin","Jelena Vucković","Alejandro W. Rodriguez"]', 'engineering', NULL, '2026-07-07 23:55:04');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3126489566', 'engineering', 'Developing fibrillated cellulose as a sustainable technological material', 'Developing fibrillated cellulose as a sustainable technological material', '2021', 2021, 1601, 1601, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-020-03167-7/MediaObjects/41586_2020_3167_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/33536649', 'repository', 'review', 'Nature', '["Tian Li","Chaoji Chen","Alexandra H. Brozena","J. Y. Zhu","Lixian Xu","Carlos Driemeier","Jiaqi Dai","Orlando J. Rojas","Akira Isogai","Lars Wågberg","Liangbing Hu"]', 'engineering', NULL, '2026-07-07 23:55:04');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3016170263', 'engineering', 'A general Lewis acidic etching route for preparing MXenes with enhanced electrochemical performance in non-aqueous electrolyte', 'A general Lewis acidic etching route for preparing MXenes with enhanced electrochemical performance in non-aqueous electrolyte', '2020', 2020, 1598, 1598, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41563-020-0657-0/MediaObjects/41563_2020_657_Fig1_HTML.png', 'https://hal.science/hal-03065962', 'repository', 'article', 'Nature Materials', '["Youbing Li","Hui Shao","Zifeng Lin","Jun Lu","Liyuan Liu","Benjamin Duployer","Per O. Å. Persson","Per Eklund","Lars Hultman","Mian Li","Ke Chen","Xian‐Hu Zha","Shiyu Du","Patrick Rozier","Zhifang Chai","Encarnación Raymundo‐Piñero","Pierre‐Louis Taberna","Patrice Simon","Qing Huang"]', 'engineering', NULL, '2026-07-07 23:55:05');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2205836349', 'engineering', 'Risk assessment and risk management: Review of recent advances on their foundation', 'Risk assessment and management was established as a scientific field some 30–40 years ago. Principles and methods were developed for how to conceptualise, assess and manage risk. These principles and…', '2015', 2015, 1592, 1592, 'https://ars.els-cdn.com/content/image/1-s2.0-S0377221715011479-gr1.jpg', 'https://doi.org/10.1016/j.ejor.2015.12.023', 'repository', 'article', 'European Journal of Operational Research', '["Terje Aven"]', 'engineering', 'Risk assessment and management was established as a scientific field some 30–40 years ago. Principles and methods were developed for how to conceptualise, assess and manage risk. These principles and methods still represent to a large extent the foundation of this field today, but many advances have been made, linked to both the theoretical platform and practical models and procedures. The purpose of the present invited paper is to perform a review of these advances, with a special focus on the fundamental ideas and thinking on which these are based. We have looked for trends in perspectives and approaches, and we also reflect on where further development of the risk field is needed and should be encouraged. The paper is written for readers with different types of background, not only for experts on risk.', '2026-07-07 23:55:18');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2576077683', 'engineering', 'A New Strategy for Heavy Metal Polluted Environments: A Review of Microbial Biosorbents', 'Persistent heavy metal pollution poses a major threat to all life forms in the environment due to its toxic effects. These metals are very reactive at low concentrations and can accumulate in the…', '2017', 2017, 1592, 1592, 'https://pub.mdpi-res.com/ijerph/ijerph-14-00094/article_deploy/html/images/ijerph-14-00094-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5295344', 'pmc', 'review', 'International Journal of Environmental Research and Public Health', '["Ayansina Segun Ayangbenro","Olubukola Oluranti Babalola"]', 'engineering', 'Persistent heavy metal pollution poses a major threat to all life forms in the environment due to its toxic effects. These metals are very reactive at low concentrations and can accumulate in the food web, causing severe public health concerns. Remediation using conventional physical and chemical methods is uneconomical and generates large volumes of chemical waste. Bioremediation of hazardous metals has received considerable and growing interest over the years. The use of microbial biosorbents is eco-friendly and cost effective; hence, it is an efficient alternative for the remediation of heavy metal contaminated environments. Microbes have various mechanisms of metal sequestration that hold greater metal biosorption capacities. The goal of microbial biosorption is to remove and/or recover metals and metalloids from solutions, using living or dead biomass and their components. This review discusses the sources of toxic heavy metals and describes the groups of microorganisms with biosorbent potential for heavy metal removal.', '2026-07-07 23:55:22');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W265312277', 'engineering', 'A strategy for structuring and reporting a read-across prediction of toxicity', 'Category formation, grouping and read across methods are broadly applicable in toxicological assessments and may be used to fill data gaps for chemical safety assessment and regulatory decisions. In…', '2015', 2015, 1565, 1565, 'https://ars.els-cdn.com/content/image/1-s2.0-S0273230015001154-fx1.jpg', 'https://pubmed.ncbi.nlm.nih.gov/26003513', 'repository', 'article', 'Regulatory Toxicology and Pharmacology', '["T.W. Schultz","Patric Amcoff","Elisabet Berggren","F. Gautier","Martina Klarić","Derek J. Knight","Catherine Mahony","Michael Schwarz","Andrew White","M Cronin"]', 'engineering', 'Category formation, grouping and read across methods are broadly applicable in toxicological assessments and may be used to fill data gaps for chemical safety assessment and regulatory decisions. In order to facilitate a transparent and systematic approach to aid regulatory acceptance, a strategy to evaluate chemical category membership, to support the use of read-across predictions that may be used to fill data gaps for regulatory decisions is proposed. There are two major aspects of any read-across exercise, namely assessing similarity and uncertainty. While there can be an over-arching rationale for grouping organic substances based on molecular structure and chemical properties, these similarities alone are generally not sufficient to justify a read-across prediction. Further scientific justification is normally required to justify the chemical grouping, typically including considerations of bioavailability, metabolism and biological/mechanistic plausibility. Sources of uncertainty include a variety of elements which are typically divided into two main issues: the uncertainty associated firstly with the similarity justification and secondly the completeness of the read-across argument. This article focuses on chronic toxicity, whilst acknowledging the approaches are applicable to all endpoints. Templates, developed from work to prepare for the application of new toxicological data to read-across assessment, are presented. These templates act as proposals to assist in assessing similarity in the context of chemistry, toxicokinetics and toxicodynamics as well as to guide the systematic characterisation of uncertainty both in the context of the similarity rationale, the read across data and overall approach and conclusion. Lastly, a workflow for reporting a read-across prediction is suggested.', '2026-07-07 23:55:34');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2923759160', 'engineering', 'A review on the plant microbiome: Ecology, functions, and emerging trends in microbial application', 'Plants have evolved with a plethora of microorganisms having important roles for plant growth and health. A considerable amount of information is now available on the structure and dynamics of plant…', '2019', 2019, 1534, 1534, 'https://ars.els-cdn.com/content/image/1-s2.0-S2090123219300700-fx1.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6630030', 'pmc', 'review', 'Journal of Advanced Research', '["Stéphane Compant","Abdul Samad","Hanna Faist","Angela Sessitsch"]', 'engineering', 'Plants have evolved with a plethora of microorganisms having important roles for plant growth and health. A considerable amount of information is now available on the structure and dynamics of plant microbiota as well as on the functional capacities of isolated community members. Due to the interesting functional potential of plant microbiota as well as due to current challenges in crop production there is an urgent need to bring microbial innovations into practice. Different approaches for microbiome improvement exist. On the one hand microbial strains or strain combinations can be applied, however, field success is often variable and improvement is urgently required. Smart, knowledge-driven selection of microorganisms is needed as well as the use of suitable delivery approaches and formulations. On the other hand, farming practices or the plant genotype can influence plant microbiota and thus functioning. Therefore, selection of appropriate farming practices and plant breeding leading to improved plant-microbiome interactions are avenues to increase the benefit of plant microbiota. In conclusion, different avenues making use of a new generation of inoculants as well as the application of microbiome-based agro-management practices and improved plant lines could lead to a better use of the plant microbiome. This paper reviews the importance and functionalities of the bacterial plant microbiome and discusses challenges and concepts in regard to the application of plant-associated bacteria.', '2026-07-07 23:56:15');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2271673449', 'engineering', 'Optical modulators with 2D layered materials', 'Optical modulators with 2D layered materials', '2016', 2016, 1520, 1520, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnphoton.2016.15/MediaObjects/41566_2016_Article_BFnphoton201615_Fig1_HTML.jpg', 'http://arxiv.org/abs/1601.07577', 'arxiv', 'article', 'Nature Photonics', '["Zhipei Sun","A. Martinez","Feng Wang"]', 'engineering', NULL, '2026-07-07 23:56:32');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1949455802', 'engineering', 'Behind the Scenes: The Corporate Governance Preferences of Institutional Investors', 'ABSTRACT We survey institutional investors to better understand their role in the corporate governance of firms. Consistent with a number of theories, we document widespread behind‐the‐scenes…', '2016', 2016, 1516, 1516, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1111/jofi.12393.g001', 'https://doi.org/10.1111/jofi.12393', 'repository', 'article', 'The Journal of Finance', '["Joseph A. McCahery","Zacharias Sautner","Laura T. Starks"]', 'engineering', 'ABSTRACT We survey institutional investors to better understand their role in the corporate governance of firms. Consistent with a number of theories, we document widespread behind‐the‐scenes intervention as well as governance‐motivated exit. These governance mechanisms are viewed as complementary devices, with intervention typically occurring prior to a potential exit. We further find that long‐term investors and investors that are less concerned about stock liquidity intervene more intensively. Finally, we find that most investors use proxy advisors and believe that the information provided by such advisors improves their own voting decisions.', '2026-07-07 23:56:46');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2195301797', 'engineering', 'The effect of renewable energy consumption on economic growth: Evidence from top 38 countries', 'The effect of renewable energy consumption on economic growth: Evidence from top 38 countries', '2015', 2015, 1497, 1497, 'https://ars.els-cdn.com/content/image/1-s2.0-S0306261915013318-gr1.jpg', 'https://doi.org/10.1016/j.apenergy.2015.10.104', 'repository', 'article', 'Applied Energy', '["Mita Bhattacharya","Sudharshan Reddy Paramati","İlhan Öztürk","Sankar Bhattacharya"]', 'engineering', NULL, '2026-07-07 23:57:07');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2766937672', 'engineering', 'How economic growth, renewable electricity and natural resources contribute to CO2 emissions?', 'How economic growth, renewable electricity and natural resources contribute to CO2 emissions?', '2017', 2017, 1463, 1463, 'https://ars.els-cdn.com/content/image/1-s2.0-S0301421517307255-gr1.jpg', 'https://doi.org/10.1016/j.enpol.2017.10.050', 'repository', 'article', 'Energy Policy', '["Daniel Balsalobre‐Lorente","Muhammad Shahbaz","David Roubaud","Sahbi Farhani"]', 'engineering', NULL, '2026-07-07 23:57:48');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2515518038', 'engineering', 'Using bias-corrected reanalysis to simulate current and future wind power output', 'Reanalysis models are rapidly gaining popularity for simulating wind power output due to their convenience and global coverage. However, they should only be relied upon once thoroughly proven. This…', '2016', 2016, 1457, 1457, 'https://ars.els-cdn.com/content/image/1-s2.0-S0360544216311811-fx1.jpg', 'https://doi.org/10.1016/j.energy.2016.08.068', 'repository', 'article', 'Energy', '["Iain Staffell","Stefan Pfenninger"]', 'engineering', 'Reanalysis models are rapidly gaining popularity for simulating wind power output due to their convenience and global coverage. However, they should only be relied upon once thoroughly proven. This paper reports the first international validation of reanalysis for wind energy, testing NASA''s MERRA and MERRA-2 in 23 European countries. Both reanalyses suffer significant spatial bias, overestimating wind output by 50% in northwest Europe and underestimating by 30% in the Mediterranean. We derive national correction factors, and show that after calibration national hourly output can be modelled with R2 above 0.95. Our underlying data are made freely available to aid future research. We then assess Europe''s wind resources with twenty-year simulations of the current and potential future fleets. Europe''s current average capacity factor is 24.2%, with countries ranging from 19.5% (Germany) to 32.4% (Britain). Capacity factors are rising due to improving technology and locations; for example, Britain''s wind fleet is now 23% more productive than in 2005. Based on the current planning pipeline, we estimate Europe''s average capacity factor could increase by nearly a third to 31.3%. Countries with large stakes in the North Sea will see significant gains, with Britain''s average capacity factor rising to 39.4% and Germany''s to 29.1%.', '2026-07-07 23:57:56');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3023559614', 'engineering', 'Inequality in the impact of the coronavirus shock: Evidence from real time surveys', 'Inequality in the impact of the coronavirus shock: Evidence from real time surveys', '2020', 2020, 1446, 1446, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1016/j.jpubeco.2020.104245.g001', 'https://doi.org/10.1016/j.jpubeco.2020.104245', 'repository', 'article', 'Journal of Public Economics', '["Abi Adams‐Prassl","Teodora Boneva","Marta Golin","Christopher Rauh"]', 'engineering', NULL, '2026-07-07 23:58:12');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3042021489', 'engineering', 'A mobile robotic chemist', 'A mobile robotic chemist', '2020', 2020, 1446, 1446, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-020-2442-2/MediaObjects/41586_2020_2442_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/32641813', 'repository', 'article', 'Nature', '["Benjamin Burger","Phillip M. Maffettone","Vladimir V. Gusev","Catherine M. Aitchison","Yang Bai","Xiaoyan Wang","Xiaobo Li","Ben M. Alston","Buyi Li","Rob Clowes","Nicola Rankin","Brandon Harris","Reiner Sebastian Sprick","Andrew I. Cooper"]', 'engineering', NULL, '2026-07-07 23:58:14');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3198669059', 'engineering', 'Plant Flavonoids: Chemical Characteristics and Biological Activity', 'In recent years, more attention has been paid to natural sources of antioxidants. Flavonoids are natural substances synthesized in several parts of plants that exhibit a high antioxidant capacity.…', '2021', 2021, 1439, 1439, 'https://pub.mdpi-res.com/molecules/molecules-26-05377/article_deploy/html/images/molecules-26-05377-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8434187', 'pmc', 'review', 'Molecules', '["Maria Celeste Dias","Diana C. G. A. Pinto","Artur M. S. Silva"]', 'engineering', 'In recent years, more attention has been paid to natural sources of antioxidants. Flavonoids are natural substances synthesized in several parts of plants that exhibit a high antioxidant capacity. They are a large family, presenting several classes based on their basic structure. Flavonoids have the ability to control the accumulation of reactive oxygen species (ROS) via scavenger ROS when they are formed. Therefore, these antioxidant compounds have an important role in plant stress tolerance and a high relevance in human health, mainly due to their anti-inflammatory and antimicrobial properties. In addition, flavonoids have several applications in the food industry as preservatives, pigments, and antioxidants, as well as in other industries such as cosmetics and pharmaceuticals. However, flavonoids application for industrial purposes implies extraction processes with high purity and quality. Several methodologies have been developed aimed at increasing flavonoid extraction yield and being environmentally friendly. This review presents the most abundant natural flavonoids, their structure and chemical characteristics, extraction methods, and biological activity.', '2026-07-07 23:58:24');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2482726005', 'engineering', 'On-Manifold Preintegration for Real-Time Visual--Inertial Odometry', 'Current approaches for visual-inertial odometry (VIO) are able to attain highly accurate state estimation via nonlinear optimization. However, real-time optimization quickly becomes infeasible as the…', '2016', 2016, 1427, 1427, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1109/tro.2016.2597321.g001', 'http://arxiv.org/abs/1512.02363', 'arxiv', 'article', 'IEEE Transactions on Robotics', '["Christian Förster","Luca Carlone","Frank Dellaert","Davide Scaramuzza"]', 'engineering', 'Current approaches for visual-inertial odometry (VIO) are able to attain highly accurate state estimation via nonlinear optimization. However, real-time optimization quickly becomes infeasible as the trajectory grows over time; this problem is further emphasized by the fact that inertial measurements come at high rate, hence, leading to the fast growth of the number of variables in the optimization. In this paper, we address this issue by preintegrating inertial measurements between selected keyframes into single relative motion constraints. Our first contribution is a preintegration theory that properly addresses the manifold structure of the rotation group. We formally discuss the generative measurement model as well as the nature of the rotation noise and derive the expression for the maximum a posteriori state estimator. Our theoretical development enables the computation of all necessary Jacobians for the optimization and a posteriori bias correction in analytic form. The second contribution is to show that the preintegrated inertial measurement unit model can be seamlessly integrated into a visual-inertial pipeline under the unifying framework of factor graphs. This enables the application of incremental-smoothing algorithms and the use of a structureless model for visual measurements, which avoids optimizing over the 3-D points, further accelerating the computation. We perform an extensive evaluation of our monocular VIO pipeline on real and simulated datasets. The results confirm that our modeling effort leads to an accurate state estimation in real time, outperforming state-of-the-art approaches.', '2026-07-07 23:58:39');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2755291024', 'engineering', 'The Role of Soil Microorganisms in Plant Mineral Nutrition—Current Knowledge and Future Directions', 'In their natural environment, plants are part of a rich ecosystem including numerous and diverse microorganisms in the soil. It has been long recognized that some of these microbes, such as…', '2017', 2017, 1396, 1396, 'https://www.frontiersin.org/files/Articles/292271/fpls-08-01617-HTML/image_m/fpls-08-01617-g001.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5610682', 'pmc', 'review', 'Frontiers in Plant Science', '["Richard P. Jacoby","Manuela Peukert","A. Succurro","Anna Kopřivová","Stanislav Kopřiva"]', 'engineering', 'In their natural environment, plants are part of a rich ecosystem including numerous and diverse microorganisms in the soil. It has been long recognized that some of these microbes, such as mycorrhizal fungi or nitrogen fixing symbiotic bacteria, play important roles in plant performance by improving mineral nutrition. However, the full range of microbes associated with plants and their potential to replace synthetic agricultural inputs has only recently started to be uncovered. In the last few years, a great progress has been made in the knowledge on composition of rhizospheric microbiomes and their dynamics. There is clear evidence that plants shape microbiome structures, most probably by root exudates, and also that bacteria have developed various adaptations to thrive in the rhizospheric niche. The mechanisms of these interactions and the processes driving the alterations in microbiomes are, however, largely unknown. In this review, we focus on the interaction of plants and root associated bacteria enhancing plant mineral nutrition, summarizing the current knowledge in several research fields that can converge to improve our understanding of the molecular mechanisms underpinning this phenomenon.', '2026-07-07 23:59:32');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3022667165', 'engineering', 'Membrane Technologies in Wastewater Treatment: A Review', 'In the face of water shortages, the world seeks to explore all available options in reducing the over exploitation of limited freshwater resources. One of the surest available water resources is…', '2020', 2020, 1392, 1392, 'https://pub.mdpi-res.com/membranes/membranes-10-00089/article_deploy/html/images/membranes-10-00089-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7281250', 'pmc', 'review', 'Membranes', '["Elorm Obotey Ezugbe","Sudesh Rathilal"]', 'engineering', 'In the face of water shortages, the world seeks to explore all available options in reducing the over exploitation of limited freshwater resources. One of the surest available water resources is wastewater. As the population grows, industrial, agricultural, and domestic activities increase accordingly in order to cater for the voluminous needs of man. These activities produce large volumes of wastewater from which water can be reclaimed to serve many purposes. Over the years, conventional wastewater treatment processes have succeeded to some extent in treating effluents for discharge purposes. However, improvements in wastewater treatment processes are necessary in order to make treated wastewater re-usable for industrial, agricultural, and domestic purposes. Membrane technology has emerged as a favorite choice for reclaiming water from different wastewater streams for re-use. This review looks at the trending membrane technologies in wastewater treatment, their advantages and disadvantages. It also discusses membrane fouling, membrane cleaning, and membrane modules. Finally, recommendations for future research pertaining to the application of membrane technology in wastewater treatment are made.', '2026-07-07 23:59:58');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3177828909', 'computer-science', 'Highly accurate protein structure prediction with AlphaFold', 'Abstract Proteins are essential to life, and understanding their structure can facilitate a mechanistic understanding of their function. Through an enormous experimental effort 1–4, the structures of…', '2021', 2021, 45442, 45442, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-021-03819-2/MediaObjects/41586_2021_3819_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8371605', 'pmc', 'article', 'Nature', '["John Jumper","Richard Evans","Alexander Pritzel","Tim Green","Michael Figurnov","Olaf Ronneberger","Kathryn Tunyasuvunakool","Russ Bates","Augustin Žídek","Anna Potapenko","Alex Bridgland","Clemens Meyer","Simon Köhl","Andrew J. Ballard","Andrew Cowie","Bernardino Romera‐Paredes","Stanislav Nikolov","Rishub Jain","Jonas Adler","Trevor Back","Stig Petersen","David Reiman","Ellen Clancy","Michał Zieliński","Martin Steinegger","Michalina Pacholska","Tamas Berghammer","Sebastian W. Bodenstein","David Silver","Oriol Vinyals","Andrew Senior","Koray Kavukcuoglu","Pushmeet Kohli","Demis Hassabis"]', 'computer science', 'Abstract Proteins are essential to life, and understanding their structure can facilitate a mechanistic understanding of their function. Through an enormous experimental effort 1–4, the structures of around 100,000 unique proteins have been determined 5, but this represents a small fraction of the billions of known protein sequences 6,7. Structural coverage is bottlenecked by the months to years of painstaking effort required to determine a single protein structure. Accurate computational approaches are needed to address this gap and to enable large-scale structural bioinformatics. Predicting the three-dimensional structure that a protein will adopt based solely on its amino acid sequence—the structure prediction component of the ‘protein folding problem’ 8 —has been an important open research problem for more than 50 years 9. Despite recent progress 10–14, existing methods fall far short of atomic accuracy, especially when no homologous structure is available. Here we provide the first computational method that can regularly predict protein structures with atomic accuracy even in cases in which no similar structure is known. We validated an entirely redesigned version of our neural network-based model, AlphaFold, in the challenging 14th Critical Assessment of protein Structure Prediction (CASP14) 15, demonstrating accuracy competitive with experimental structures in a majority of cases and greatly outperforming other methods. Underpinning the latest version of AlphaFold is a novel machine learning approach that incorporates physical and biological knowledge about protein structure, leveraging multi-sequence alignments, into the design of the deep learning algorithm.', '2026-07-08 06:41:57');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3003257820', 'computer-science', 'SciPy 1.0: fundamental algorithms for scientific computing in Python', 'SciPy is an open-source scientific computing library for the Python programming language. Since its initial release in 2001, SciPy has become a de facto standard for leveraging scientific algorithms…', '2020', 2020, 38193, 38193, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41592-019-0686-2/MediaObjects/41592_2019_686_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7056644', 'pmc', 'article', 'Nature Methods', '["Pauli Virtanen","Ralf Gommers","Travis E. Oliphant","Matt Haberland","Tyler Reddy","David Cournapeau","Evgeni Burovski","Pearu Peterson","Warren Weckesser","Jonathan Bright","Stéfan J. van der Walt","Matthew Brett","Joshua Wilson","K. Jarrod Millman","Nikolay Mayorov","Andrew R. J. Nelson","Eric Jones","Robert Kern","Eric Larson","C J Carey","İlhan Polat","Yu Feng","Eric W. Moore","Jake VanderPlas","Denis Laxalde","Josef Perktold","Robert Cimrman","Ian Henriksen","E. A. Quintero","Charles R. Harris","Anne M. Archibald","Antônio H. Ribeiro","Fabian Pedregosa","Paul van Mulbregt","SciPy 1.0 Contributors","Aditya Vijaykumar","Alessandro Pietro Bardelli","Alex Rothberg","Andreas Hilboll","Andreas Kloeckner","Anthony Scopatz","Antony Lee","Ariel Rokem","C. Nathan Woods","Chad Fulton","Charles Masson","Christian Häggström","Clark Fitzgerald","David A. Nicholson","David R. Hagen","Dmitrii V. Pasechnik","Emanuele Olivetti","Eric Martin","Eric Wieser","Fabrice Silva","Felix Lenders","Florian Wilhelm","G. Young","Gavin A. Price","Gert-Ludwig Ingold","Gregory E. Allen","Gregory R. Lee","Hervé Audren","Irvin Probst","Jörg P. Dietrich","Jacob Silterra","James T Webber","Janko Slavič","Joel Nothman","Johannes Buchner","Johannes Kulick","Johannes L. Schönberger","José Vinícius de Miranda Cardoso","Joscha Reimer","Joseph Harrington","Juan Luis Cano Rodríguez","Juan Nunez-Iglesias","Justin Kuczynski","Kevin Tritz","Martin Thoma","Matthew Newville","Matthias Kümmerer","Maximilian Bolingbroke","Michael Tartre","Mikhail Pak","Nathaniel J. Smith","Nikolai Nowaczyk","Nikolay Shebanov","Oleksandr Pavlyk","Per A. Brodtkorb","Perry Lee","Robert T. McGibbon","Roman Feldbauer","Sam Lewis","Sam Tygier","Scott Sievert","Sebastiano Vigna","Stefan Peterson","Surhud More","Tadeusz Pudlik"]', 'computer science', 'SciPy is an open-source scientific computing library for the Python programming language. Since its initial release in 2001, SciPy has become a de facto standard for leveraging scientific algorithms in Python, with over 600 unique code contributors, thousands of dependent packages, over 100,000 dependent repositories and millions of downloads per year. In this work, we provide an overview of the capabilities and development practices of SciPy 1.0 and highlight some recent technical developments.', '2026-07-08 06:42:09');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2102278945', 'computer-science', 'HISAT: a fast spliced aligner with low memory requirements', 'HISAT: a fast spliced aligner with low memory requirements', '2015', 2015, 26180, 26180, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnmeth.3317/MediaObjects/41592_2015_Article_BFnmeth3317_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4655817', 'pmc', 'article', 'Nature Methods', '["Daehwan Kim","Ben Langmead","Steven L. Salzberg"]', 'computer science', NULL, '2026-07-08 06:42:12');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3035965352', 'computer-science', 'Array programming with NumPy', 'Abstract Array programming provides a powerful, compact and expressive syntax for accessing, manipulating and operating on data in vectors, matrices and higher-dimensional arrays. NumPy is the…', '2020', 2020, 22486, 22486, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-020-2649-2/MediaObjects/41586_2020_2649_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7759461', 'pmc', 'article', 'Nature', '["Charles R. Harris","K. Jarrod Millman","Stéfan J. van der Walt","Ralf Gommers","Pauli Virtanen","David Cournapeau","Eric Wieser","Julian Taylor","Sebastian Berg","Nathaniel J. Smith","Robert Kern","Matti Picus","Stephan Hoyer","Marten H. van Kerkwijk","Matthew Brett","Allan Haldane","Jaime Fernández del Río","Mark Wiebe","Pearu Peterson","Pierre Gérard-Marchant","Kevin Sheppard","Tyler Reddy","Warren Weckesser","Hameer Abbasi","Christoph Gohlke","Travis E. Oliphant"]', 'computer science', 'Abstract Array programming provides a powerful, compact and expressive syntax for accessing, manipulating and operating on data in vectors, matrices and higher-dimensional arrays. NumPy is the primary array programming library for the Python language. It has an essential role in research analysis pipelines in fields as diverse as physics, chemistry, astronomy, geoscience, biology, psychology, materials science, engineering, finance and economics. For example, in astronomy, NumPy was an important part of the software stack used in the discovery of gravitational waves 1 and in the first imaging of a black hole 2. Here we review how a few fundamental array concepts lead to a simple and powerful programming paradigm for organizing, exploring and analysing scientific data. NumPy is the foundation upon which the scientific Python ecosystem is constructed. It is so pervasive that several projects, targeting audiences with specialized needs, have developed their own NumPy-like interfaces and array objects. Owing to its central position in the ecosystem, NumPy increasingly acts as an interoperability layer between such array computation libraries and, together with its application programming interface (API), provides a flexible framework to support the next decade of scientific and industrial analysis.', '2026-07-08 06:42:22');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2104005232', 'computer-science', 'StringTie enables improved reconstruction of a transcriptome from RNA-seq reads', 'StringTie enables improved reconstruction of a transcriptome from RNA-seq reads', '2015', 2015, 15524, 15524, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnbt.3122/MediaObjects/41587_2015_Article_BFnbt3122_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4643835', 'pmc', 'article', 'Nature Biotechnology', '["Mihaela Pertea","Geo Pertea","Corina Antonescu","Tsung-Cheng Chang","Joshua T. Mendell","Steven L. Salzberg"]', 'computer science', NULL, '2026-07-08 06:42:44');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2964849163', 'computer-science', 'Graph-based genome alignment and genotyping with HISAT2 and HISAT-genotype', 'Graph-based genome alignment and genotyping with HISAT2 and HISAT-genotype', '2019', 2019, 15795, 15795, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41587-019-0201-4/MediaObjects/41587_2019_201_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7605509', 'pmc', 'article', 'Nature Biotechnology', '["Daehwan Kim","Joseph M. Paggi","Chanhee Park","Christopher Bennett","Steven L. Salzberg"]', 'computer science', NULL, '2026-07-08 06:42:44');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2928665623', 'computer-science', 'Metascape provides a biologist-oriented resource for the analysis of systems-level datasets', 'A critical component in the interpretation of systems-level studies is the inference of enriched biological pathways and protein complexes contained within OMICs datasets. Successful analysis…', '2019', 2019, 15665, 15665, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41467-019-09234-6/MediaObjects/41467_2019_9234_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6447622', 'pmc', 'article', 'Nature Communications', '["Yingyao Zhou","Bin Zhou","Lars Pache","Max W. Chang","Alireza Hadj Khodabakhshi","Olga Tanaseichuk","Christopher Benner","Sumit K. Chanda"]', 'computer science', 'A critical component in the interpretation of systems-level studies is the inference of enriched biological pathways and protein complexes contained within OMICs datasets. Successful analysis requires the integration of a broad set of current biological databases and the application of a robust analytical pipeline to produce readily interpretable results. Metascape is a web-based portal designed to provide a comprehensive gene list annotation and analysis resource for experimental biologists. In terms of design features, Metascape combines functional enrichment, interactome analysis, gene annotation, and membership search to leverage over 40 independent knowledgebases within one integrated portal. Additionally, it facilitates comparative analyses of datasets across multiple independent and orthogonal experiments. Metascape provides a significantly simplified user experience through a one-click Express Analysis interface to generate interpretable outputs. Taken together, Metascape is an effective and efficient tool for experimental biologists to comprehensively analyze and interpret OMICs-based studies in the big data era.', '2026-07-08 06:42:44');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2592811885', 'computer-science', 'Salmon provides fast and bias-aware quantification of transcript expression', 'Salmon provides fast and bias-aware quantification of transcript expression', '2017', 2017, 13718, 13718, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnmeth.4197/MediaObjects/41592_2017_Article_BFnmeth4197_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5600148', 'pmc', 'article', 'Nature Methods', '["Rob Patro","Geet Duggal","Michael I. Love","Rafael A. Irizarry","Carl Kingsford"]', 'computer science', NULL, '2026-07-08 06:43:11');
