INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1803102843', 'computer-science', 'The Phyre2 web portal for protein modeling, prediction and analysis', 'The Phyre2 web portal for protein modeling, prediction and analysis', '2015', 2015, 10251, 10251, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnprot.2015.053/MediaObjects/41596_2015_Article_BFnprot2015053_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5298202', 'pmc', 'article', 'Nature Protocols', '["Lawrence A. Kelley","Stefans Mezulis","Christopher M. Yates","Mark N. Wass","Michael J.E. Sternberg"]', 'computer science', NULL, '2026-07-08 06:43:50');
