INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2396881363', 'computer-science', 'MIMIC-III, a freely accessible critical care database', 'MIMIC-III (''Medical Information Mart for Intensive Care'') is a large, single-center database comprising information relating to patients admitted to critical care units at a large tertiary care…', '2016', 2016, 8168, 8168, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fsdata.2016.35/MediaObjects/41597_2016_Article_BFsdata201635_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4878278', 'pmc', 'article', 'Scientific Data', '["Alistair E. W. Johnson","Tom Pollard","Lu Shen","Li-wei H. Lehman","Mengling Feng","Mohammad M. Ghassemi","Benjamin Moody","Peter Szolovits","Leo Anthony Celi","Roger G. Mark"]', 'computer science', 'MIMIC-III (''Medical Information Mart for Intensive Care'') is a large, single-center database comprising information relating to patients admitted to critical care units at a large tertiary care hospital. Data includes vital signs, medications, laboratory measurements, observations and notes charted by care providers, fluid balance, procedure codes, diagnostic codes, imaging reports, hospital length of stay, survival data, and more. The database supports applications including academic and industrial research, quality improvement initiatives, and higher education coursework.', '2026-07-08 06:45:01');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2526781987', 'computer-science', 'The future of employment: How susceptible are jobs to computerisation?', 'The future of employment: How susceptible are jobs to computerisation?', '2016', 2016, 8304, 8304, 'https://ars.els-cdn.com/content/image/1-s2.0-S0040162516302244-gr1.jpg', 'https://doi.org/10.1016/j.techfore.2016.08.019', 'repository', 'article', 'Technological Forecasting and Social Change', '["Carl Benedikt Frey","Michael A. Osborne"]', 'computer science', NULL, '2026-07-08 06:45:03');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3109746568', 'computer-science', 'Engineering precision nanoparticles for drug delivery', 'Engineering precision nanoparticles for drug delivery', '2020', 2020, 7442, 7442, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41573-020-0090-8/MediaObjects/41573_2020_90_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7717100', 'pmc', 'review', 'Nature Reviews Drug Discovery', '["Michael J. Mitchell","Margaret M. Billingsley","Rebecca M. Haley","Marissa E. Wechsler","Nicholas A. Peppas","Róbert Langer"]', 'computer science', NULL, '2026-07-08 06:45:45');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2616922646', 'computer-science', 'SCENIC: single-cell regulatory network inference and clustering', 'SCENIC: single-cell regulatory network inference and clustering', '2017', 2017, 6993, 6993, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnmeth.4463/MediaObjects/41592_2017_Article_BFnmeth4463_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5937676', 'pmc', 'article', 'Nature Methods', '["Sara Aibar","Carmen Bravo González‐Blas","Thomas Moerman","Vân Anh Huynh‐Thu","Hana Imrichová","Gert Hulselmans","Florian Rambow","Jean‐Christophe Marine","Pierre Geurts","Jan Aerts","Joost van den Oord","Zeynep Kalender Atak","Jasper Wouters","Stein Aerts"]', 'computer science', NULL, '2026-07-08 06:45:57');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2982169647', 'computer-science', 'Quantum supremacy using a programmable superconducting processor', 'The promise of quantum computers is that certain computational tasks might be executed exponentially faster on a quantum processor than on a classical processor1. A fundamental challenge is to build…', '2019', 2019, 7011, 7011, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-019-1666-5/MediaObjects/41586_2019_1666_Fig1_HTML.png', 'http://arxiv.org/abs/1910.11333', 'arxiv', 'article', 'Nature', '["Frank Arute","Kunal Arya","Ryan Babbush","Dave Bacon","Joseph C. Bardin","Rami Barends","Rupak Biswas","Sergio Boixo","Fernando G. S. L. Brandao","David A. Buell","Brian Burkett","Yu Chen","Zijun Chen","Ben Chiaro","Roberto Collins","William Courtney","Andrew Dunsworth","Edward Farhi","Brooks Foxen","Austin Fowler","Craig Gidney","Marissa Giustina","Rob Graff","Keith Guerin","Steve Habegger","Matthew P. Harrigan","Michael J. Hartmann","Alan Ho","Markus Hoffmann","Trent Huang","Travis S. Humble","Sergei V. Isakov","Evan Jeffrey","Zhang Jiang","Dvir Kafri","Kostyantyn Kechedzhi","Julian Kelly","Paul V. Klimov","Sergey Knysh","Alexander Korotkov","Fedor Kostritsa","David Landhuis","Mike Lindmark","Erik Lucero","Dmitry Lyakh","Salvatore Mandrà","Jarrod R. McClean","Matthew McEwen","Anthony Megrant","Xiao Mi","Kristel Michielsen","Masoud Mohseni","Josh Mutus","Ofer Naaman","Matthew Neeley","Charles Neill","Murphy Yuezhen Niu","Eric Ostby","Andre Petukhov","John C. Platt","Chris Quintana","Eleanor G. Rieffel","Pedram Roushan","Nicholas C. Rubin","Daniel Sank","Kevin J. Satzinger","Vadim Smelyanskiy","Kevin J. Sung","Matthew D. Trevithick","Amit Vainsencher","Benjamin Villalonga","Theodore White","Z. Jamie Yao","Ping Yeh","Adam Zalcman","Hartmut Neven","John M. Martinis"]', 'computer science', 'The promise of quantum computers is that certain computational tasks might be executed exponentially faster on a quantum processor than on a classical processor1. A fundamental challenge is to build a high-fidelity processor capable of running quantum algorithms in an exponentially large computational space. Here we report the use of a processor with programmable superconducting qubits2–7 to create quantum states on 53 qubits, corresponding to a computational state-space of dimension 253 (about 1016). Measurements from repeated experiments sample the resulting probability distribution, which we verify using classical simulations. Our Sycamore processor takes about 200 seconds to sample one instance of a quantum circuit a million times—our benchmarks currently indicate that the equivalent task for a state-of-the-art classical supercomputer would take approximately 10,000 years. This dramatic increase in speed compared to all known classical algorithms is an experimental realization of quantum supremacy8–14 for this specific computational task, heralding a much-anticipated computing paradigm. Quantum supremacy is demonstrated using a programmable superconducting processor known as Sycamore, taking approximately 200 seconds to sample one instance of a quantum circuit a million times, which would take a state-of-the-art supercomputer around ten thousand years to compute.', '2026-07-08 06:45:58');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3163993681', 'computer-science', 'Physics-informed machine learning', 'Physics-informed machine learning', '2021', 2021, 6764, 6764, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs42254-021-00314-5/MediaObjects/42254_2021_314_Fig1_HTML.png', 'https://doi.org/10.1038/s42254-021-00314-5', 'repository', 'review', 'Nature Reviews Physics', '["George Em Karniadakis","Ioannis G. Kevrekidis","Lu Lu","Paris Perdikaris","Sifan Wang","Liu Yang"]', 'computer science', NULL, '2026-07-08 06:46:09');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2580035316', 'computer-science', 'ImageJ2: ImageJ for the next generation of scientific image data', 'BACKGROUND: ImageJ is an image analysis program extensively used in the biological sciences and beyond. Due to its ease of use, recordable macro language, and extensible plug-in architecture, ImageJ…', '2017', 2017, 6267, 6267, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1038%2Fs41592-021-01262-9/MediaObjects/41592_2021_1262_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5708080', 'pmc', 'article', 'BMC Bioinformatics', '["Curtis Rueden","Johannes Schindelin","Mark Hiner","Barry E. DeZonia","Alison E. Walter","Ellen T. Arena","Kevin W. Eliceiri"]', 'computer science', 'BACKGROUND: ImageJ is an image analysis program extensively used in the biological sciences and beyond. Due to its ease of use, recordable macro language, and extensible plug-in architecture, ImageJ enjoys contributions from non-programmers, amateur programmers, and professional developers alike. Enabling such a diversity of contributors has resulted in a large community that spans the biological and physical sciences. However, a rapidly growing user base, diverging plugin suites, and technical limitations have revealed a clear need for a concerted software engineering effort to support emerging imaging paradigms, to ensure the software''s ability to handle the requirements of modern science. RESULTS: We rewrote the entire ImageJ codebase, engineering a redesigned plugin mechanism intended to facilitate extensibility at every level, with the goal of creating a more powerful tool that continues to serve the existing community while addressing a wider range of scientific requirements. This next-generation ImageJ, called "ImageJ2" in places where the distinction matters, provides a host of new functionality. It separates concerns, fully decoupling the data model from the user interface. It emphasizes integration with external applications to maximize interoperability. Its robust new plugin framework allows everything from image formats, to scripting languages, to visualization to be extended by the community. The redesigned data model supports arbitrarily large, N-dimensional datasets, which are increasingly common in modern image acquisition. Despite the scope of these changes, backwards compatibility is maintained such that this new functionality can be seamlessly integrated with the classic ImageJ interface, allowing users and developers to migrate to these new methods at their own pace. CONCLUSIONS: Scientific imaging benefits from open-source programs that advance new method development and deployment to a diverse audience. ImageJ has continuously evolved with this idea in mind; however, new and emerging scientific requirements have posed corresponding challenges for ImageJ''s development. The described improvements provide a framework engineered for flexibility, intended to support these requirements as well as accommodate future needs. Future efforts will focus on implementing new algorithms in this framework and expanding collaborations with other popular scientific software suites.', '2026-07-08 06:46:38');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2395579298', 'computer-science', 'A survey of transfer learning', 'Machine learning and data mining techniques have been used in numerous real-world applications. An assumption of traditional machine learning methodologies is the training data and testing data are…', '2016', 2016, 6183, 6183, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1007%2Fs13198-024-02684-2/MediaObjects/13198_2024_2684_Fig1_HTML.jpg', 'https://doi.org/10.1186/s40537-016-0043-6', 'repository', 'article', 'Journal Of Big Data', '["Karl R. Weiss","Taghi M. Khoshgoftaar","Dingding Wang"]', 'computer science', 'Machine learning and data mining techniques have been used in numerous real-world applications. An assumption of traditional machine learning methodologies is the training data and testing data are taken from the same domain, such that the input feature space and data distribution characteristics are the same. However, in some real-world machine learning scenarios, this assumption does not hold. There are cases where training data is expensive or difficult to collect. Therefore, there is a need to create high-performance learners trained with more easily obtained data from different domains. This methodology is referred to as transfer learning. This survey paper formally defines transfer learning, presents information on current solutions, and reviews applications applied to transfer learning. Lastly, there is information listed on software downloads for various transfer learning solutions and a discussion of possible future research work. The transfer learning solutions surveyed are independent of data size and can be applied to big data environments.', '2026-07-08 06:46:39');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2887114371', 'computer-science', 'DeepLabCut: markerless pose estimation of user-defined body parts with deep learning', 'DeepLabCut: markerless pose estimation of user-defined body parts with deep learning', '2018', 2018, 5598, 5598, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41593-018-0209-y/MediaObjects/41593_2018_209_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/30127430', 'repository', 'article', 'Nature Neuroscience', '["Alexander Mathis","Pranav Mamidanna","Kevin M. Cury","Taiga Abe","Venkatesh N. Murthy","Mackenzie Weygandt Mathis","Matthias Bethge"]', 'computer science', NULL, '2026-07-08 06:52:09');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2203714058', 'computer-science', 'Practical Bayesian model evaluation using leave-one-out cross-validation and WAIC', 'Practical Bayesian model evaluation using leave-one-out cross-validation and WAIC', '2016', 2016, 5423, 5423, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1007%2Fs41237-025-00287-0/MediaObjects/41237_2025_287_Fig1_HTML.png', 'http://arxiv.org/abs/1507.04544', 'arxiv', 'article', 'Statistics and Computing', '["Aki Vehtari","Andrew Gelman","Jonah Gabry"]', 'computer science', NULL, '2026-07-08 06:52:35');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2981863007', 'computer-science', 'Systematic review of research on artificial intelligence applications in higher education – where are the educators?', 'Abstract According to various international reports, Artificial Intelligence in Education (AIEd) is one of the currently emerging fields in educational technology. Whilst it has been around for about…', '2019', 2019, 5416, 5416, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs41239-019-0171-0/MediaObjects/41239_2019_171_Fig1_HTML.png', 'https://doi.org/10.1186/s41239-019-0171-0', 'repository', 'article', 'International Journal of Educational Technology in Higher Education', '["Olaf Zawacki‐Richter","Victoria I. Marín","Melissa Bond","Franziska Gouverneur"]', 'computer science', 'Abstract According to various international reports, Artificial Intelligence in Education (AIEd) is one of the currently emerging fields in educational technology. Whilst it has been around for about 30 years, it is still unclear for educators how to make pedagogical advantage of it on a broader scale, and how it can actually impact meaningfully on teaching and learning in higher education. This paper seeks to provide an overview of research on AI applications in higher education through a systematic review. Out of 2656 initially identified publications for the period between 2007 and 2018, 146 articles were included for final synthesis, according to explicit inclusion and exclusion criteria. The descriptive results show that most of the disciplines involved in AIEd papers come from Computer Science and STEM, and that quantitative methods were the most frequently used in empirical studies. The synthesis of results presents four areas of AIEd applications in academic support services, and institutional and administrative services: 1. profiling and prediction, 2. assessment and evaluation, 3. adaptive systems and personalisation, and 4. intelligent tutoring systems. The conclusions reflect on the almost lack of critical reflection of challenges and risks of AIEd, the weak connection to theoretical pedagogical perspectives, and the need for further exploration of ethical and educational approaches in the application of AIEd in higher education.', '2026-07-08 06:52:37');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2897249806', 'computer-science', 'From Louvain to Leiden: guaranteeing well-connected communities', 'Community detection is often used to understand the structure of large and complex networks. One of the most popular algorithms for uncovering community structure is the so-called Louvain algorithm.…', '2019', 2019, 5267, 5267, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41598-019-41695-z/MediaObjects/41598_2019_41695_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6435756', 'pmc', 'article', 'Scientific Reports', '["V. A. Traag","L. Waltman","Nees Jan van Eck"]', 'computer science', 'Community detection is often used to understand the structure of large and complex networks. One of the most popular algorithms for uncovering community structure is the so-called Louvain algorithm. We show that this algorithm has a major defect that largely went unnoticed until now: the Louvain algorithm may yield arbitrarily badly connected communities. In the worst case, communities may even be disconnected, especially when running the algorithm iteratively. In our experimental analysis, we observe that up to 25% of the communities are badly connected and up to 16% are disconnected. To address this problem, we introduce the Leiden algorithm. We prove that the Leiden algorithm yields communities that are guaranteed to be connected. In addition, we prove that, when the Leiden algorithm is applied iteratively, it converges to a partition in which all subsets of all communities are locally optimally assigned. Furthermore, by relying on a fast local move approach, the Leiden algorithm runs faster than the Louvain algorithm. We demonstrate the performance of the Leiden algorithm for several benchmark and real-world networks. We find that the Leiden algorithm is faster than the Louvain algorithm and uncovers better partitions, in addition to providing explicit guarantees.', '2026-07-08 06:52:47');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2010049072', 'computer-science', 'A refined compilation of implementation strategies: results from the Expert Recommendations for Implementing Change (ERIC) project', 'BACKGROUND: Identifying, developing, and testing implementation strategies are important goals of implementation science. However, these efforts have been complicated by the use of inconsistent…', '2015', 2015, 5146, 5146, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs13012-023-01310-2/MediaObjects/13012_2023_1310_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4328074', 'pmc', 'article', 'Implementation Science', '["Byron J. Powell","Thomas J. Waltz","Matthew Chinman","Laura J. Damschroder","Jeffrey L. Smith","Monica M. Matthieu","Enola K. Proctor","JoAnn E. Kirchner"]', 'computer science', 'BACKGROUND: Identifying, developing, and testing implementation strategies are important goals of implementation science. However, these efforts have been complicated by the use of inconsistent language and inadequate descriptions of implementation strategies in the literature. The Expert Recommendations for Implementing Change (ERIC) study aimed to refine a published compilation of implementation strategy terms and definitions by systematically gathering input from a wide range of stakeholders with expertise in implementation science and clinical practice. METHODS: Purposive sampling was used to recruit a panel of experts in implementation and clinical practice who engaged in three rounds of a modified Delphi process to generate consensus on implementation strategies and definitions. The first and second rounds involved Web-based surveys soliciting comments on implementation strategy terms and definitions. After each round, iterative refinements were made based upon participant feedback. The third round involved a live polling and consensus process via a Web-based platform and conference call. RESULTS: Participants identified substantial concerns with 31% of the terms and/or definitions and suggested five additional strategies. Seventy-five percent of definitions from the originally published compilation of strategies were retained after voting. Ultimately, the expert panel reached consensus on a final compilation of 73 implementation strategies. CONCLUSIONS: This research advances the field by improving the conceptual clarity, relevance, and comprehensiveness of implementation strategies that can be used in isolation or combination in implementation research and practice. Future phases of ERIC will focus on developing conceptually distinct categories of strategies as well as ratings for each strategy''s importance and feasibility. Next, the expert panel will recommend multifaceted strategies for hypothetical yet real-world scenarios that vary by sites'' endorsement of evidence-based programs and practices and the strength of contextual supports that surround the effort.', '2026-07-08 06:53:00');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3135028703', 'computer-science', 'Machine Learning: Algorithms, Real-World Applications and Research Directions', 'Machine Learning: Algorithms, Real-World Applications and Research Directions', '2021', 2021, 5170, 5170, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1007%2Fs42979-021-00592-x/MediaObjects/42979_2021_592_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7983091', 'pmc', 'review', 'SN Computer Science', '["Iqbal H. Sarker"]', 'computer science', NULL, '2026-07-08 06:53:01');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2277195237', 'computer-science', 'Visual Genome: Connecting Language and Vision Using Crowdsourced Dense Image Annotations', 'Despite progress in perceptual tasks such as image classification, computers still perform poorly on cognitive tasks such as image description and question answering. Cognition is core to tasks that…', '2017', 2017, 5199, 5199, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1007%2Fs11263-016-0981-7/MediaObjects/11263_2016_981_Fig10_HTML.jpg', 'https://doi.org/10.1007/s11263-016-0981-7', 'repository', 'article', 'International Journal of Computer Vision', '["Ranjay Krishna","Yuke Zhu","Oliver Groth","Justin Johnson","Kenji Hata","Joshua Kravitz","Stephanie Chen","Yannis Kalantidis","Li-Jia Li","David A. Shamma","Michael S. Bernstein","Li Fei-Fei"]', 'computer science', 'Despite progress in perceptual tasks such as image classification, computers still perform poorly on cognitive tasks such as image description and question answering. Cognition is core to tasks that involve not just recognizing, but reasoning about our visual world. However, models used to tackle the rich content in images for cognitive tasks are still being trained using the same datasets designed for perceptual tasks. To achieve success at cognitive tasks, models need to understand the interactions and relationships between objects in an image. When asked “What vehicle is the person riding?”, computers will need to identify the objects in an image as well as the relationships riding(man, carriage) and pulling(horse, carriage) to answer correctly that “the person is riding a horse-drawn carriage.” In this paper, we present the Visual Genome dataset to enable the modeling of such relationships. We collect dense annotations of objects, attributes, and relationships within each image to learn these models. Specifically, our dataset contains over 108K images where each image has an average of $$35$$ objects, $$26$$ attributes, and $$21$$ pairwise relationships between objects. We canonicalize the objects, attributes, relationships, and noun phrases in region descriptions and questions answer pairs to WordNet synsets. Together, these annotations represent the densest and largest dataset of image descriptions, objects, attributes, relationships, and question answer pairs.', '2026-07-08 06:53:02');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2964321699', 'computer-science', 'Convolutional Neural Networks On Graphs With Fast Localized Spectral Filtering (Gdl Seminar)', 'Lecture at the EPFL master course A Network Tour of Data Science.', '2016', 2016, 5099, 5099, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.5281/zenodo.1318405.g001', 'https://zenodo.org/record/1286818', 'repository', 'preprint', 'Figshare', '["Michaël Defferrard"]', 'computer science', 'Lecture at the EPFL master course A Network Tour of Data Science.', '2026-07-08 06:53:09');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3143063265', 'computer-science', 'Sensitive protein alignments at tree-of-life scale using DIAMOND', 'We are at the beginning of a genomic revolution in which all known species are planned to be sequenced. Accessing such data for comparative analyses is crucial in this new age of data-driven biology.…', '2021', 2021, 5024, 5024, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41592-021-01101-x/MediaObjects/41592_2021_1101_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8026399', 'pmc', 'article', 'Nature Methods', '["Benjamin Buchfink","Klaus Reuter","Hajk‐Georg Drost"]', 'computer science', 'We are at the beginning of a genomic revolution in which all known species are planned to be sequenced. Accessing such data for comparative analyses is crucial in this new age of data-driven biology. Here, we introduce an improved version of DIAMOND that greatly exceeds previous search performances and harnesses supercomputing to perform tree-of-life scale protein alignments in hours, while matching the sensitivity of the gold standard BLASTP.', '2026-07-08 06:53:12');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3119952098', 'computer-science', 'Natural products in drug discovery: advances and opportunities', 'Natural products in drug discovery: advances and opportunities', '2021', 2021, 5044, 5044, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41573-020-00114-z/MediaObjects/41573_2020_114_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7841765', 'pmc', 'review', 'Nature Reviews Drug Discovery', '["Atanas G. Atanasov","Sergey B. Zotchev","Verena M. Dirsch","the International Natural Product Sciences Taskforce","İlkay Erdoğan Orhan","Maciej Banach","Judith M. Rollinger","Davide Barreca","Wolfram Weckwerth","Rudolf Bauer","Edward A. Bayer","Muhammed Majeed","Anupam Bishayee","Valery N. Bochkov","Günther K. Bonn","Nady Braidy","Franz Bučar","Alejandro Cifuentes","Grazia D’Onofrio","Michael J. Bodkin","Marc Diederich","Albena T. Dinkova‐Kostova","Thomas Efferth","Khalid El Bairi","Nicolas Arkells","Tai-Ping Fan","Bernd L. Fiebich","Michael Freissmuth","Milen I. Georgiev","Simon Gibbons","Keith M. Godfrey","Christian W. Gruber","Jag Heer","Lukas A. Huber","Elena Ibáñez","Anake Kijjoa","Anna K. Kiss","Aiping Lü","Francisco A. Macı́as","Mark J.S. Miller","Andrei Mocan","Rolf Müller","Ferdinando Nicoletti","George Perry","Valeria Pittalà","Luca Rastrelli","Michael Ristow","Gian Luigi Russo","A. Sanches‐Silva","Daniela Schuster","Helen Sheridan","Krystyna Skalicka‐Woźniak","Léandros Skaltsounis","Eduardo Sobarzo‐Sánchez","David S. Bredt","Hermann Stuppner","Antoni Sureda","Nikolay Tzvetkov","Rosa Anna Vacca","Bharat B. Aggarwal","Maurizio Battino","Francesca Giampieri","Michaël Wink","Jean‐Luc Wolfender","Jianbo Xiao","Andy Wai Kan Yeung","Gérard Lizard","Michael Popp","Michael Heinrich","Ioana Berindan-Neagoe","Marc Stadler","Maria Daglia","Robert Verpoorte","Claudiu T. Supuran"]', 'computer science', NULL, '2026-07-08 06:53:12');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2913323966', 'computer-science', 'Deep learning and process understanding for data-driven Earth system science', 'Deep learning and process understanding for data-driven Earth system science', '2019', 2019, 5107, 5107, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-019-0912-1/MediaObjects/41586_2019_912_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/30760912', 'repository', 'review', 'Nature', '["Markus Reichstein","Gustau Camps‐Valls","Björn Stevens","Martin Jung","Joachim Denzler","Nuno Carvalhais","Prabhat"]', 'computer science', NULL, '2026-07-08 06:53:13');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4378212544', 'computer-science', 'Dictionary learning for integrative, multimodal and scalable single-cell analysis', 'Dictionary learning for integrative, multimodal and scalable single-cell analysis', '2023', 2023, 4915, 4915, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41587-023-01767-y/MediaObjects/41587_2023_1767_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/10928517', 'pmc', 'article', 'Nature Biotechnology', '["Yuhan Hao","Tim Stuart","Madeline H. Kowalski","Saket Choudhary","Paul Hoffman","Austin Hartman","Avi Srivastava","Gesmira Molla","Shaista Madad","Carlos Fernandez‐Granda","Rahul Satija"]', 'computer science', NULL, '2026-07-08 06:53:20');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2266175888', 'computer-science', 'Fully integrated wearable sensor arrays for multiplexed in situ perspiration analysis', 'Fully integrated wearable sensor arrays for multiplexed in situ perspiration analysis', '2016', 2016, 4926, 4926, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature16521/MediaObjects/41586_2016_BFnature16521_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4996079', 'pmc', 'article', 'Nature', '["Wei Gao","Sam Emaminejad","Hnin Yin Yin Nyein","Samyuktha Challa","Kevin Chen","Austin J. Peck","Hossain M. Fahad","Hiroki Ota","Hiroshi Shiraki","Daisuke Kiriya","Der‐Hsien Lien","George A. Brooks","Ronald W. Davis","Ali Javey"]', 'computer science', NULL, '2026-07-08 06:53:21');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2901954177', 'computer-science', 'BEAST 2.5: An advanced software platform for Bayesian evolutionary analysis', 'Elaboration of Bayesian phylogenetic inference methods has continued at pace in recent years with major new advances in nearly all aspects of the joint modelling of evolutionary data. It is…', '2019', 2019, 4748, 4748, 'https://journals.plos.org/ploscompbiol/article/figure/image?size=large&id=10.1371/journal.pcbi.1006650.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6472827', 'pmc', 'article', 'PLoS Computational Biology', '["Remco Bouckaert","Timothy G. Vaughan","Joëlle Barido‐Sottani","Sebastián Duchêne","Mathieu Fourment","Alexandra Gavryushkina","Joseph Heled","Graham Jones","Denise Kühnert","Nicola De Maio","Michael Matschiner","Fábio K. Mendes","Nicola F. Müller","Huw A. Ogilvie","Louis du Plessis","Alex Popinga","Andrew Rambaut","David A. Rasmussen","Igor Siveroni","Marc A. Suchard","Chieh‐Hsi Wu","Dong Xie","Chi Zhang","Tanja Stadler","Alexei J. Drummond"]', 'computer science', 'Elaboration of Bayesian phylogenetic inference methods has continued at pace in recent years with major new advances in nearly all aspects of the joint modelling of evolutionary data. It is increasingly appreciated that some evolutionary questions can only be adequately answered by combining evidence from multiple independent sources of data, including genome sequences, sampling dates, phenotypic data, radiocarbon dates, fossil occurrences, and biogeographic range information among others. Including all relevant data into a single joint model is very challenging both conceptually and computationally. Advanced computational software packages that allow robust development of compatible (sub-)models which can be composed into a full model hierarchy have played a key role in these developments. Developing such software frameworks is increasingly a major scientific activity in its own right, and comes with specific challenges, from practical software design, development and engineering challenges to statistical and conceptual modelling challenges. BEAST 2 is one such computational software platform, and was first announced over 4 years ago. Here we describe a series of major new developments in the BEAST 2 core platform and model hierarchy that have occurred since the first release of the software, culminating in the recent 2.5 release.', '2026-07-08 06:53:44');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2951539866', 'computer-science', 'High-entropy alloys', 'High-entropy alloys', '2019', 2019, 4731, 4731, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41578-019-0121-4/MediaObjects/41578_2019_121_Fig1_HTML.png', 'https://doi.org/10.1038/s41578-019-0121-4', 'repository', 'review', 'Nature Reviews Materials', '["E.P. George","Dierk Raabe","Robert O. Ritchie"]', 'computer science', NULL, '2026-07-08 06:53:50');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1966716734', 'computer-science', 'The Precision-Recall Plot Is More Informative than the ROC Plot When Evaluating Binary Classifiers on Imbalanced Datasets', 'Binary classifiers are routinely evaluated with performance measures such as sensitivity and specificity, and performance is frequently illustrated with Receiver Operating Characteristics (ROC)…', '2015', 2015, 4702, 4702, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0118432.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4349800', 'pmc', 'article', 'PLoS ONE', '["Takaya Saito","Marc Rehmsmeier"]', 'computer science', 'Binary classifiers are routinely evaluated with performance measures such as sensitivity and specificity, and performance is frequently illustrated with Receiver Operating Characteristics (ROC) plots. Alternative measures such as positive predictive value (PPV) and the associated Precision/Recall (PRC) plots are used less frequently. Many bioinformatics studies develop and evaluate classifiers that are to be applied to strongly imbalanced datasets in which the number of negatives outweighs the number of positives significantly. While ROC plots are visually appealing and provide an overview of a classifier''s performance across a wide range of specificities, one can ask whether ROC plots could be misleading when applied in imbalanced classification scenarios. We show here that the visual interpretability of ROC plots in the context of imbalanced datasets can be deceptive with respect to conclusions about the reliability of classification performance, owing to an intuitive but wrong interpretation of specificity. PRC plots, on the other hand, can provide the viewer with an accurate prediction of future classification performance due to the fact that they evaluate the fraction of true positives among positive predictions. Our findings have potential implications for the interpretation of a large number of studies that use ROC plots on imbalanced datasets.', '2026-07-08 06:53:56');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1787224781', 'computer-science', 'On Pixel-Wise Explanations for Non-Linear Classifier Decisions by Layer-Wise Relevance Propagation', 'Understanding and interpreting classification decisions of automated image classification systems is of high value in many applications, as it allows to verify the reasoning of the system and…', '2015', 2015, 4592, 4592, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0130140.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4498753', 'pmc', 'article', 'PLoS ONE', '["Sebastian Bach","Alexander Binder","Grégoire Montavon","Frederick Klauschen","Klaus‐Robert Müller","Wojciech Samek"]', 'computer science', 'Understanding and interpreting classification decisions of automated image classification systems is of high value in many applications, as it allows to verify the reasoning of the system and provides additional information to the human expert. Although machine learning methods are solving very successfully a plethora of tasks, they have in most cases the disadvantage of acting as a black box, not providing any information about what made them arrive at a particular decision. This work proposes a general solution to the problem of understanding classification decisions by pixel-wise decomposition of nonlinear classifiers. We introduce a methodology that allows to visualize the contributions of single pixels to predictions for kernel-based classifiers over Bag of Words features and for multilayered neural networks. These pixel contributions can be visualized as heatmaps and are provided to a human expert who can intuitively not only verify the validity of the classification decision, but also focus further analysis on regions of potential interest. We evaluate our method for classifiers trained on PASCAL VOC 2009 images, synthetic image data containing geometric shapes, the MNIST handwritten digits data set and for the pre-trained ImageNet model available as part of the Caffe open source package.', '2026-07-08 06:54:26');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2884430236', 'computer-science', 'Machine learning for molecular and materials science', 'Machine learning for molecular and materials science', '2018', 2018, 4589, 4589, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-018-0337-2/MediaObjects/41586_2018_337_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/30046072', 'repository', 'review', 'Nature', '["Keith T. Butler","Daniel W. Davies","Hugh Cartwright","Olexandr Isayev","Aron Walsh"]', 'computer science', NULL, '2026-07-08 06:54:29');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2770092353', 'computer-science', 'Functional mapping and annotation of genetic associations with FUMA', 'A main challenge in genome-wide association studies (GWAS) is to pinpoint possible causal variants. Results from GWAS typically do not directly translate into causal variants because the majority of…', '2017', 2017, 4505, 4505, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41467-017-01261-5/MediaObjects/41467_2017_1261_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5705698', 'pmc', 'article', 'Nature Communications', '["Kyoko Watanabe","Erdogan Taskesen","Arjen van Bochoven","Daniëlle Posthuma"]', 'computer science', 'A main challenge in genome-wide association studies (GWAS) is to pinpoint possible causal variants. Results from GWAS typically do not directly translate into causal variants because the majority of hits are in non-coding or intergenic regions, and the presence of linkage disequilibrium leads to effects being statistically spread out across multiple variants. Post-GWAS annotation facilitates the selection of most likely causal variant(s). Multiple resources are available for post-GWAS annotation, yet these can be time consuming and do not provide integrated visual aids for data interpretation. We, therefore, develop FUMA: an integrative web-based platform using information from multiple biological resources to facilitate functional annotation of GWAS results, gene prioritization and interactive visualization. FUMA accommodates positional, expression quantitative trait loci (eQTL) and chromatin interaction mappings, and provides gene-based, pathway and tissue enrichment results. FUMA results directly aid in generating hypotheses that are testable in functional experiments aimed at proving causal relations.', '2026-07-08 06:54:58');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2510973425', 'computer-science', 'Next-generation genotype imputation service and methods', 'Next-generation genotype imputation service and methods', '2016', 2016, 4428, 4428, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fng.3656/MediaObjects/41588_2016_Article_BFng3656_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5157836', 'pmc', 'article', 'Nature Genetics', '["Sayantan Das","Lukas Forer","Sebastian Schönherr","Carlo Sidore","Adam E. Locke","Alan Kwong","Scott Vrieze","Emily Y. Chew","Shawn Levy","Matt McGue","David Schlessinger","Dwight Stambolian","Po‐Ru Loh","William G. Iacono","Anand Swaroop","Laura J. Scott","Francesco Cucca","Florian Kronenberg","Michael Boehnke","Gonçalo R. Abecasis","Christian Fuchsberger"]', 'computer science', NULL, '2026-07-08 06:54:59');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2559394418', 'computer-science', 'Quantum machine learning', 'Quantum machine learning', '2017', 2017, 4471, 4471, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature23474/MediaObjects/41586_2017_Article_BFnature23474_Fig1_HTML.jpg', 'http://arxiv.org/abs/1611.09347', 'arxiv', 'article', 'Nature', '["Jacob Biamonte","Péter Wittek","Nicola Pancotti","Patrick Rebentrost","Nathan Wiebe","Seth Lloyd"]', 'computer science', NULL, '2026-07-08 06:54:59');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4307846395', 'computer-science', 'The updated Consolidated Framework for Implementation Research based on user feedback', 'BACKGROUND: Many implementation efforts fail, even with highly developed plans for execution, because contextual factors can be powerful forces working against implementation in the real world. The…', '2022', 2022, 3909, 3909, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs13012-020-0977-0/MediaObjects/13012_2020_977_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/9617234', 'pmc', 'review', 'Implementation Science', '["Laura J. Damschroder","Caitlin M. Reardon","Marilla A. Opra Widerquist","Julie C. Lowery"]', 'computer science', 'BACKGROUND: Many implementation efforts fail, even with highly developed plans for execution, because contextual factors can be powerful forces working against implementation in the real world. The Consolidated Framework for Implementation Research (CFIR) is one of the most commonly used determinant frameworks to assess these contextual factors; however, it has been over 10 years since publication and there is a need for updates. The purpose of this project was to elicit feedback from experienced CFIR users to inform updates to the framework. METHODS: User feedback was obtained from two sources: (1) a literature review with a systematic search; and (2) a survey of authors who used the CFIR in a published study. Data were combined across both sources and reviewed to identify themes; a consensus approach was used to finalize all CFIR updates. The VA Ann Arbor Healthcare System IRB declared this study exempt from the requirements of 38 CFR 16 based on category 2. RESULTS: The systematic search yielded 376 articles that contained the CFIR in the title and/or abstract and 334 unique authors with contact information; 59 articles included feedback on the CFIR. Forty percent (n = 134/334) of authors completed the survey. The CFIR received positive ratings on most framework sensibility items (e.g., applicability, usability), but respondents also provided recommendations for changes. Overall, updates to the CFIR include revisions to existing domains and constructs as well as the addition, removal, or relocation of constructs. These changes address important critiques of the CFIR, including better centering innovation recipients and adding determinants to equity in implementation. CONCLUSION: The updates in the CFIR reflect feedback from a growing community of CFIR users. Although there are many updates, constructs can be mapped back to the original CFIR to ensure longitudinal consistency. We encourage users to continue critiquing the CFIR, facilitating the evolution of the framework as implementation science advances.', '2026-07-08 06:56:38');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2216946510', 'computer-science', 'A random forest guided tour', 'A random forest guided tour', '2016', 2016, 3888, 3888, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1007%2Fs00180-021-01182-4/MediaObjects/180_2021_1182_Fig1_HTML.png', 'http://arxiv.org/abs/1511.05741', 'arxiv', 'article', 'Test', '["Gérard Biau","Erwan Scornet"]', 'computer science', NULL, '2026-07-08 06:56:41');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2212640525', 'computer-science', 'Dose-Response Analysis Using R', 'Dose-response analysis can be carried out using multi-purpose commercial statistical software, but except for a few special cases the analysis easily becomes cumbersome as relevant, non-standard…', '2015', 2015, 3748, 3748, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0146021.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4696819', 'pmc', 'article', 'PLoS ONE', '["Christian Ritz","Florent Baty","J. C. Streibig","Daniel Gerhard"]', 'computer science', 'Dose-response analysis can be carried out using multi-purpose commercial statistical software, but except for a few special cases the analysis easily becomes cumbersome as relevant, non-standard output requires manual programming. The extension package drc for the statistical environment R provides a flexible and versatile infrastructure for dose-response analyses in general. The present version of the package, reflecting extensions and modifications over the last decade, provides a user-friendly interface to specify the model assumptions about the dose-response relationship and comes with a number of extractors for summarizing fitted models and carrying out inference on derived parameters. The aim of the present paper is to provide an overview of state-of-the-art dose-response analysis, both in terms of general concepts that have evolved and matured over the years and by means of concrete examples.', '2026-07-08 06:56:56');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2975634117', 'computer-science', 'ilastik: interactive machine learning for (bio)image analysis', 'ilastik: interactive machine learning for (bio)image analysis', '2019', 2019, 3639, 3639, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1038/s41592-019-0582-9.g001', 'https://pubmed.ncbi.nlm.nih.gov/31570887', 'repository', 'review', 'Nature Methods', '["Stuart Berg","Dominik Kutra","Thorben Kroeger","Christoph Straehle","Bernhard X. Kausler","Carsten Haubold","Martin Schiegg","Janez Aleš","Thorsten Beier","Markus Rudy","Kemal Eren","Jaime I Cervantes","Buote Xu","Fynn Beuttenmueller","Adrian Wolny","Chong Zhang","Ullrich Koethe","Fred A. Hamprecht","Anna Kreshuk"]', 'computer science', NULL, '2026-07-08 06:57:24');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2529838505', 'computer-science', 'SeqKit: A Cross-Platform and Ultrafast Toolkit for FASTA/Q File Manipulation', 'FASTA and FASTQ are basic and ubiquitous formats for storing nucleotide and protein sequences. Common manipulations of FASTA/Q file include converting, searching, filtering, deduplication, splitting,…', '2016', 2016, 3633, 3633, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0163962.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5051824', 'pmc', 'article', 'PLoS ONE', '["Wei Shen","Shuai Le","Yan Li","Fuquan Hu"]', 'computer science', 'FASTA and FASTQ are basic and ubiquitous formats for storing nucleotide and protein sequences. Common manipulations of FASTA/Q file include converting, searching, filtering, deduplication, splitting, shuffling, and sampling. Existing tools only implement some of these manipulations, and not particularly efficiently, and some are only available for certain operating systems. Furthermore, the complicated installation process of required packages and running environments can render these programs less user friendly. This paper describes a cross-platform ultrafast comprehensive toolkit for FASTA/Q processing. SeqKit provides executable binary files for all major operating systems, including Windows, Linux, and Mac OSX, and can be directly used without any dependencies or pre-configurations. SeqKit demonstrates competitive performance in execution time and memory usage compared to similar tools. The efficiency and usability of SeqKit enable researchers to rapidly accomplish common FASTA/Q file manipulations. SeqKit is open source and available on Github at https://github.com/shenwei356/seqkit.', '2026-07-08 06:57:24');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2803760365', 'computer-science', 'Artificial intelligence in radiology', 'Artificial intelligence in radiology', '2018', 2018, 3648, 3648, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41568-018-0016-5/MediaObjects/41568_2018_16_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6268174', 'pmc', 'review', 'Nature reviews. Cancer', '["Ahmed Hosny","Chintan Parmar","John Quackenbush","Lawrence H. Schwartz","Hugo J.W.L. Aerts"]', 'computer science', NULL, '2026-07-08 06:57:28');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2950150251', 'computer-science', 'Mash: fast genome and metagenome distance estimation using MinHash', 'Mash extends the MinHash dimensionality-reduction technique to include a pairwise mutation distance and P value significance test, enabling the efficient clustering and search of massive sequence…', '2016', 2016, 3574, 3574, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs13059-019-1841-x/MediaObjects/13059_2019_1841_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4915045', 'pmc', 'article', 'Genome biology', '["Brian Ondov","Todd J. Treangen","Páll Melsted","Adam B. Mallonee","Nicholas H. Bergman","Sergey Koren","Adam M. Phillippy"]', 'computer science', 'Mash extends the MinHash dimensionality-reduction technique to include a pairwise mutation distance and P value significance test, enabling the efficient clustering and search of massive sequence collections. Mash reduces large sequences and sequence sets to small, representative sketches, from which global mutation distances can be rapidly estimated. We demonstrate several use cases, including the clustering of all 54,118 NCBI RefSeq genomes in 33 CPU h; real-time database search using assembled or unassembled Illumina, Pacific Biosciences, and Oxford Nanopore data; and the scalable clustering of hundreds of metagenomic samples by composition. Mash is freely released under a BSD license ( https://github.com/marbl/mash ).', '2026-07-08 06:57:46');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2999044305', 'computer-science', 'Improved protein structure prediction using potentials from deep learning', 'Improved protein structure prediction using potentials from deep learning', '2020', 2020, 3531, 3531, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-019-1923-7/MediaObjects/41586_2019_1923_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/31942072', 'repository', 'article', 'Nature', '["Andrew Senior","Richard Evans","John Jumper","James Kirkpatrick","Laurent Sifre","Tim Green","Chongli Qin","Augustin Žídek","Alexander Nelson","Alex Bridgland","Hugo Penedones","Stig Petersen","Karen Simonyan","Steve Crossan","Pushmeet Kohli","David T. Jones","David Silver","Koray Kavukcuoglu","Demis Hassabis"]', 'computer science', NULL, '2026-07-08 06:57:58');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2779206865', 'computer-science', 'Prolific.ac—A subject pool for online experiments', 'The number of online experiments conducted with subjects recruited via online platforms has grown considerably in the recent past. While one commercial crowdworking platform – Amazon’s Mechanical…', '2017', 2017, 3403, 3403, 'https://ars.els-cdn.com/content/image/1-s2.0-S2214635017300989-gr1.jpg', 'https://doi.org/10.1016/j.jbef.2017.12.004', 'repository', 'article', 'Journal of Behavioral and Experimental Finance', '["Stefan Palan","Christian Schitter"]', 'computer science', 'The number of online experiments conducted with subjects recruited via online platforms has grown considerably in the recent past. While one commercial crowdworking platform – Amazon’s Mechanical Turk – basically has established and since dominated this field, new alternatives offer services explicitly targeted at researchers. In this article, we present www.prolific.ac and lay out its suitability for recruiting subjects for social and economic science experiments. After briefly discussing key advantages and challenges of online experiments relative to lab experiments, we trace the platform’s historical development, present its features, and contrast them with requirements for different types of social and economic experiments.', '2026-07-08 06:58:39');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2006940889', 'computer-science', 'Transparent reporting of a multivariable prediction model for individual prognosis or diagnosis (TRIPOD): The TRIPOD statement', 'Prediction models are developed to aid health-care providers in estimating the probability or risk that a specific disease or condition is present (diagnostic models) or that a specific event will…', '2015', 2015, 3350, 3350, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fbjc.2014.639/MediaObjects/41416_2015_Article_BFbjc2014639_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4454817', 'pmc', 'review', 'British Journal of Cancer', '["Gary S. Collins","Johannes B. Reitsma","Douglas G. Altman","Karel G.M. Moons"]', 'computer science', 'Prediction models are developed to aid health-care providers in estimating the probability or risk that a specific disease or condition is present (diagnostic models) or that a specific event will occur in the future (prognostic models), to inform their decision making. However, the overwhelming evidence shows that the quality of reporting of prediction model studies is poor. Only with full and clear reporting of information on all aspects of a prediction model can risk of bias and potential usefulness of prediction models be adequately assessed. The Transparent Reporting of a multivariable prediction model for Individual Prognosis Or Diagnosis (TRIPOD) Initiative developed a set of recommendations for the reporting of studies developing, validating, or updating a prediction model, whether for diagnostic or prognostic purposes. This article describes how the TRIPOD Statement was developed. An extensive list of items based on a review of the literature was created, which was reduced after a Web-based survey and revised during a 3-day meeting in June 2011 with methodologists, health-care professionals, and journal editors. The list was refined during several meetings of the steering group and in e-mail discussions with the wider group of TRIPOD contributors. The resulting TRIPOD Statement is a checklist of 22 items, deemed essential for transparent reporting of a prediction model study. The TRIPOD Statement aims to improve the transparency of the reporting of a prediction model study regardless of the study methods used. The TRIPOD Statement is best used in conjunction with the TRIPOD explanation and elaboration document. To aid the editorial process and readers of prediction model studies, it is recommended that authors include a completed checklist in their submission (also available at www.tripod-statement.org).', '2026-07-08 06:58:53');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2572080171', 'computer-science', 'The ClusPro web server for protein–protein docking', 'The ClusPro web server for protein–protein docking', '2017', 2017, 3360, 3360, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnprot.2016.169/MediaObjects/41596_2017_BFnprot2016169_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5540229', 'pmc', 'article', 'Nature Protocols', '["Dima Kozakov","David R. Hall","Bing Xia","Kathryn A. Porter","Dzmitry Padhorny","Christine Yueh","Dmitri Beglov","Sándor Vajda"]', 'computer science', NULL, '2026-07-08 06:58:55');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2991012415', 'computer-science', 'CDD/SPARCLE: the conserved domain database in 2020', 'As NLM''s Conserved Domain Database (CDD) enters its 20th year of operations as a publicly available resource, CDD curation staff continues to develop hierarchical classifications of widely…', '2019', 2019, 3343, 3343, 'https://cdn.ncbi.nlm.nih.gov/pmc/blobs/57cd/6943070/e1175e7398ad/gkz991fig1.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6943070', 'pmc', 'article', 'Nucleic Acids Research', '["Shennan Lu","Jiyao Wang","Farideh Chitsaz","Myra K. Derbyshire","Renata C. Geer","Noreen R. Gonzales","Marc Gwadz","David I. Hurwitz","Gabriele H. Marchler","James S. Song","Narmada Thanki","Roxanne A. Yamashita","Mingzhang Yang","Dachuan Zhang","Chanjuan Zheng","Christopher J. Lanczycki","Aron Marchler‐Bauer"]', 'computer science', 'As NLM''s Conserved Domain Database (CDD) enters its 20th year of operations as a publicly available resource, CDD curation staff continues to develop hierarchical classifications of widely distributed protein domain families, and to record conserved sites associated with molecular function, so that they can be mapped onto user queries in support of hypothesis-driven biomolecular research. CDD offers both an archive of pre-computed domain annotations as well as live search services for both single protein or nucleotide queries and larger sets of protein query sequences. CDD staff has continued to characterize protein families via conserved domain architectures and has built up a significant corpus of curated domain architectures in support of naming bacterial proteins in RefSeq. These architecture definitions are available via SPARCLE, the Subfamily Protein Architecture Labeling Engine. CDD can be accessed at https://www.ncbi.nlm.nih.gov/Structure/cdd/cdd.shtml.', '2026-07-08 06:58:56');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2954996726', 'artificial-intelligence', 'A survey on Image Data Augmentation for Deep Learning', 'Deep convolutional neural networks have performed remarkably well on many Computer Vision tasks. However, these networks are heavily reliant on big data to avoid overfitting. Overfitting refers to…', '2019', 2019, 12476, 12476, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs40537-019-0197-0/MediaObjects/40537_2019_197_Fig1_HTML.png', 'https://doi.org/10.1186/s40537-019-0197-0', 'repository', 'article', 'Journal Of Big Data', '["Connor Shorten","Taghi M. Khoshgoftaar"]', 'artificial intelligence', 'Deep convolutional neural networks have performed remarkably well on many Computer Vision tasks. However, these networks are heavily reliant on big data to avoid overfitting. Overfitting refers to the phenomenon when a network learns a function with very high variance such as to perfectly model the training data. Unfortunately, many application domains do not have access to big data, such as medical image analysis. This survey focuses on Data Augmentation, a data-space solution to the problem of limited data. Data Augmentation encompasses a suite of techniques that enhance the size and quality of training datasets such that better Deep Learning models can be built using them. The image augmentation algorithms discussed in this survey include geometric transformations, color space augmentations, kernel filters, mixing images, random erasing, feature space augmentation, adversarial training, generative adversarial networks, neural style transfer, and meta-learning. The application of augmentation methods based on GANs are heavily covered in this survey. In addition to augmentation techniques, this paper will briefly discuss other characteristics of Data Augmentation such as test-time augmentation, resolution impact, final dataset size, and curriculum learning. This survey will present existing methods for Data Augmentation, promising developments, and meta-level decisions for implementing Data Augmentation. Readers will understand how Data Augmentation can improve the performance of their models and expand limited datasets to take advantage of the capabilities of big data.', '2026-07-08 06:59:34');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2754799758', 'artificial-intelligence', 'Saturation in qualitative research: exploring its conceptualization and operationalization', 'Saturation has attained widespread acceptance as a methodological principle in qualitative research. It is commonly taken to indicate that, on the basis of the data that have been collected or…', '2017', 2017, 11709, 11709, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs43058-025-00833-7/MediaObjects/43058_2025_833_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5993836', 'pmc', 'article', 'Quality & Quantity', '["Benjamin Saunders","Julius Sim","Tom Kingstone","Shula Baker","Jackie Waterfield","Bernadette Bartlam","Heather Burroughs","Clare Jinks"]', 'artificial intelligence', 'Saturation has attained widespread acceptance as a methodological principle in qualitative research. It is commonly taken to indicate that, on the basis of the data that have been collected or analysed hitherto, further data collection and/or analysis are unnecessary. However, there appears to be uncertainty as to how saturation should be conceptualized, and inconsistencies in its use. In this paper, we look to clarify the nature, purposes and uses of saturation, and in doing so add to theoretical debate on the role of saturation across different methodologies. We identify four distinct approaches to saturation, which differ in terms of the extent to which an inductive or a deductive logic is adopted, and the relative emphasis on data collection, data analysis, and theorizing. We explore the purposes saturation might serve in relation to these different approaches, and the implications for how and when saturation will be sought. In examining these issues, we highlight the uncertain logic underlying saturation-as essentially a predictive statement about the unobserved based on the observed, a judgement that, we argue, results in equivocation, and may in part explain the confusion surrounding its use. We conclude that saturation should be operationalized in a way that is consistent with the research question(s), and the theoretical position and analytic framework adopted, but also that there should be some limit to its scope, so as not to risk saturation losing its coherence and potency if its conceptualization and uses are stretched too widely.', '2026-07-08 06:59:35');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2952481429', 'artificial-intelligence', 'QuPath: Open source software for digital pathology image analysis', 'QuPath is new bioimage analysis software designed to meet the growing need for a user-friendly, extensible, open-source solution for digital pathology and whole slide image analysis. In addition to…', '2017', 2017, 8710, 8710, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41598-017-17204-5/MediaObjects/41598_2017_17204_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5715110', 'pmc', 'article', 'Scientific Reports', '["Peter Bankhead","Maurice B. Loughrey","José A. Fernández","Yvonne Dombrowski","Darragh G. McArt","Philip D. Dunne","Stephen McQuaid","Ronan T. Gray","Liam Murray","Helen G. Coleman","Jacqueline A. James","Manuel Salto‐Tellez","Peter W. Hamilton"]', 'artificial intelligence', 'QuPath is new bioimage analysis software designed to meet the growing need for a user-friendly, extensible, open-source solution for digital pathology and whole slide image analysis. In addition to offering a comprehensive panel of tumor identification and high-throughput biomarker evaluation tools, QuPath provides researchers with powerful batch-processing and scripting functionality, and an extensible platform with which to develop and share new algorithms to analyze complex tissue images. Furthermore, QuPath''s flexible design makes it suitable for a wide range of additional image analysis applications across biomedical research.', '2026-07-08 07:00:02');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3014974815', 'artificial-intelligence', 'nnU-Net: a self-configuring method for deep learning-based biomedical image segmentation', 'nnU-Net: a self-configuring method for deep learning-based biomedical image segmentation', '2020', 2020, 8630, 8630, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41592-020-01008-z/MediaObjects/41592_2020_1008_Fig1_HTML.png', 'http://arxiv.org/abs/1904.08128', 'arxiv', 'article', 'Nature Methods', '["Fabian Isensee","Paul F. Jaeger","Simon A. A. Kohl","Jens Petersen","Klaus H. Maier-Hein"]', 'artificial intelligence', NULL, '2026-07-08 07:00:05');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2945976633', 'artificial-intelligence', 'Stop explaining black box machine learning models for high stakes decisions and use interpretable models instead', 'Stop explaining black box machine learning models for high stakes decisions and use interpretable models instead', '2019', 2019, 9130, 9130, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs42256-019-0048-x/MediaObjects/42256_2019_48_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/9122117', 'pmc', 'article', 'Nature Machine Intelligence', '["Cynthia Rudin"]', 'artificial intelligence', NULL, '2026-07-08 07:00:07');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3211795435', 'artificial-intelligence', 'AlphaFold Protein Structure Database: massively expanding the structural coverage of protein-sequence space with high-accuracy models', 'The AlphaFold Protein Structure Database (AlphaFold DB, https://alphafold.ebi.ac.uk) is an openly accessible, extensive database of high-accuracy protein-structure predictions. Powered by AlphaFold…', '2021', 2021, 8302, 8302, 'https://cdn.ncbi.nlm.nih.gov/pmc/blobs/957c/8728224/9871edb59920/gkab1061fig1.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8728224', 'pmc', 'article', 'Nucleic Acids Research', '["Mihály Váradi","Stephen Anyango","Mandar Deshpande","Sreenath Nair","Cindy Natassia","Galabina Yordanova","David Yu Yuan","Oana Stroe","Gemma Wood","Agata Laydon","Augustin Žídek","Tim Green","Kathryn Tunyasuvunakool","Stig Petersen","John Jumper","Ellen Clancy","Richard Green","Ankur Vora","Mira Lutfi","Michael Figurnov","Andrew Cowie","Nicole Hobbs","Pushmeet Kohli","Gerard J. Kleywegt","Ewan Birney","Demis Hassabis","Sameer Velankar"]', 'artificial intelligence', 'The AlphaFold Protein Structure Database (AlphaFold DB, https://alphafold.ebi.ac.uk) is an openly accessible, extensive database of high-accuracy protein-structure predictions. Powered by AlphaFold v2.0 of DeepMind, it has enabled an unprecedented expansion of the structural coverage of the known protein-sequence space. AlphaFold DB provides programmatic access to and interactive visualization of predicted atomic coordinates, per-residue and pairwise model-confidence estimates and predicted aligned errors. The initial release of AlphaFold DB contains over 360,000 predicted structures across 21 model-organism proteomes, which will soon be expanded to cover most of the (over 100 million) representative sequences from the UniRef90 data set.', '2026-07-08 07:00:07');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2807194798', 'artificial-intelligence', 'Optimizing taxonomic classification of marker-gene amplicon sequences with QIIME 2’s q2-feature-classifier plugin', 'BACKGROUND: Taxonomic classification of marker-gene sequences is an important step in microbiome analysis. RESULTS: We present q2-feature-classifier ( https://github.com/qiime2/q2-feature-classifier…', '2018', 2018, 6076, 6076, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs40168-018-0470-z/MediaObjects/40168_2018_470_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5956843', 'pmc', 'article', 'Microbiome', '["Nicholas A. Bokulich","Benjamin D. Kaehler","Jai Ram Rideout","Matthew R. Dillon","Evan Bolyen","Rob Knight","Gavin Huttley","J. Gregory Caporaso"]', 'artificial intelligence', 'BACKGROUND: Taxonomic classification of marker-gene sequences is an important step in microbiome analysis. RESULTS: We present q2-feature-classifier ( https://github.com/qiime2/q2-feature-classifier ), a QIIME 2 plugin containing several novel machine-learning and alignment-based methods for taxonomy classification. We evaluated and optimized several commonly used classification methods implemented in QIIME 1 (RDP, BLAST, UCLUST, and SortMeRNA) and several new methods implemented in QIIME 2 (a scikit-learn naive Bayes machine-learning classifier, and alignment-based taxonomy consensus methods based on VSEARCH, and BLAST+) for classification of bacterial 16S rRNA and fungal ITS marker-gene amplicon sequence data. The naive-Bayes, BLAST+-based, and VSEARCH-based classifiers implemented in QIIME 2 meet or exceed the species-level accuracy of other commonly used methods designed for classification of marker gene sequences that were evaluated in this work. These evaluations, based on 19 mock communities and error-free sequence simulations, including classification of simulated "novel" marker-gene sequences, are available in our extensible benchmarking framework, tax-credit ( https://github.com/caporaso-lab/tax-credit-data ). CONCLUSIONS: Our results illustrate the importance of parameter tuning for optimizing classifier performance, and we make recommendations regarding parameter choices for these classifiers under a range of standard operating conditions. q2-feature-classifier and tax-credit are both free, open-source, BSD-licensed packages available on GitHub.', '2026-07-08 07:00:45');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2253429366', 'artificial-intelligence', 'Deep Convolutional Neural Networks for Computer-Aided Detection: CNN Architectures, Dataset Characteristics and Transfer Learning', 'Remarkable progress has been made in image recognition, primarily due to the availability of large-scale annotated datasets and deep convolutional neural networks (CNNs). CNNs enable learning…', '2016', 2016, 5804, 5804, 'https://cdn.ncbi.nlm.nih.gov/pmc/blobs/2f9b/7176472/263bff9a1529/7404017-fig-1-source.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4890616', 'pmc', 'article', 'IEEE Transactions on Medical Imaging', '["Hoo-Chang Shin","Holger R. Roth","Mingchen Gao","Le Lü","Ziyue Xu","Isabella Nogues","Jianhua Yao","Daniel J. Mollura","Ronald M. Summers"]', 'artificial intelligence', 'Remarkable progress has been made in image recognition, primarily due to the availability of large-scale annotated datasets and deep convolutional neural networks (CNNs). CNNs enable learning data-driven, highly representative, hierarchical image features from sufficient training data. However, obtaining datasets as comprehensively annotated as ImageNet in the medical imaging domain remains a challenge. There are currently three major techniques that successfully employ CNNs to medical image classification: training the CNN from scratch, using off-the-shelf pre-trained CNN features, and conducting unsupervised CNN pre-training with supervised fine-tuning. Another effective method is transfer learning, i.e., fine-tuning CNN models pre-trained from natural image dataset to medical image tasks. In this paper, we exploit three important, but previously understudied factors of employing deep convolutional neural networks to computer-aided detection problems. We first explore and evaluate different CNN architectures. The studied models contain 5 thousand to 160 million parameters, and vary in numbers of layers. We then evaluate the influence of dataset scale and spatial image context on performance. Finally, we examine when and why transfer learning from pre-trained ImageNet (via fine-tuning) can be useful. We study two specific computer-aided detection (CADe) problems, namely thoraco-abdominal lymph node (LN) detection and interstitial lung disease (ILD) classification. We achieve the state-of-the-art performance on the mediastinal LN detection, and report the first five-fold cross-validation classification results on predicting axial CT slices with ILD categories. Our extensive empirical evaluation, CNN model analysis and valuable insights can be extended to the design of high performance CAD systems for other medical imaging tasks.', '2026-07-08 07:00:49');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2951254987', 'artificial-intelligence', 'High throughput ANI analysis of 90K prokaryotic genomes reveals clear species boundaries', 'A fundamental question in microbiology is whether there is continuum of genetic diversity among genomes, or clear species boundaries prevail instead. Whole-genome similarity metrics such as Average…', '2018', 2018, 5723, 5723, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41467-018-07641-9/MediaObjects/41467_2018_7641_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6269478', 'pmc', 'article', 'Nature Communications', '["Chirag Jain","Luis M. Rodriguez‐R","Adam M. Phillippy","Konstantinos T. Konstantinidis","Srinivas Aluru"]', 'artificial intelligence', 'A fundamental question in microbiology is whether there is continuum of genetic diversity among genomes, or clear species boundaries prevail instead. Whole-genome similarity metrics such as Average Nucleotide Identity (ANI) help address this question by facilitating high resolution taxonomic analysis of thousands of genomes from diverse phylogenetic lineages. To scale to available genomes and beyond, we present FastANI, a new method to estimate ANI using alignment-free approximate sequence mapping. FastANI is accurate for both finished and draft genomes, and is up to three orders of magnitude faster compared to alignment-based approaches. We leverage FastANI to compute pairwise ANI values among all prokaryotic genomes available in the NCBI database. Our results reveal clear genetic discontinuity, with 99.8% of the total 8 billion genome pairs analyzed conforming to >95% intra-species and <83% inter-species ANI values. This discontinuity is manifested with or without the most frequently sequenced species, and is robust to historic additions in the genome databases.', '2026-07-08 07:00:49');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2899714098', 'artificial-intelligence', 'New tools for automated high-resolution cryo-EM structure determination in RELION-3', 'Here, we describe the third major release of RELION. CPU-based vector acceleration has been added in addition to GPU support, which provides flexibility in use of resources and avoids memory…', '2018', 2018, 5457, 5457, 'https://iiif.elifesciences.org/lax/42166%2Felife-42166-fig1-v2.tif/full/617,/0/default.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6250425', 'pmc', 'article', 'eLife', '["Jasenko Zivanov","Takanori Nakane","Björn Forsberg","Dari Kimanius","Wim J. H. Hagen","Erik Lindahl","Sjors H. W. Scheres"]', 'artificial intelligence', 'Here, we describe the third major release of RELION. CPU-based vector acceleration has been added in addition to GPU support, which provides flexibility in use of resources and avoids memory limitations. Reference-free autopicking with Laplacian-of-Gaussian filtering and execution of jobs from python allows non-interactive processing during acquisition, including 2D-classification, de novo model generation and 3D-classification. Per-particle refinement of CTF parameters and correction of estimated beam tilt provides higher resolution reconstructions when particles are at different heights in the ice, and/or coma-free alignment has not been optimal. Ewald sphere curvature correction improves resolution for large particles. We illustrate these developments with publicly available data sets: together with a Bayesian approach to beam-induced motion correction it leads to resolution improvements of 0.2–0.7 Å compared to previous RELION versions.', '2026-07-08 07:01:04');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2473156356', 'artificial-intelligence', 'Using Deep Learning for Image-Based Plant Disease Detection', 'Crop diseases are a major threat to food security, but their rapid identification remains difficult in many parts of the world due to the lack of the necessary infrastructure. The combination of…', '2016', 2016, 4615, 4615, 'https://www.frontiersin.org/files/Articles/215232/fpls-07-01419-HTML-r2/image_m/fpls-07-01419-g001.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5032846', 'pmc', 'article', 'Frontiers in Plant Science', '["Sharada P. Mohanty","David Hughes","Marcel Salathé"]', 'artificial intelligence', 'Crop diseases are a major threat to food security, but their rapid identification remains difficult in many parts of the world due to the lack of the necessary infrastructure. The combination of increasing global smartphone penetration and recent advances in computer vision made possible by deep learning has paved the way for smartphone-assisted disease diagnosis. Using a public dataset of 54,306 images of diseased and healthy plant leaves collected under controlled conditions, we train a deep convolutional neural network to identify 14 crop species and 26 diseases (or absence thereof). The trained model achieves an accuracy of 99.35% on a held-out test set, demonstrating the feasibility of this approach. Overall, the approach of training deep learning models on increasingly large and publicly available image datasets presents a clear path toward smartphone-assisted crop disease diagnosis on a massive global scale.', '2026-07-08 07:01:51');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2809254203', 'artificial-intelligence', 'Convolutional neural networks: an overview and application in radiology', 'Convolutional neural network (CNN), a class of artificial neural networks that has become dominant in various computer vision tasks, is attracting interest across a variety of domains, including…', '2018', 2018, 4606, 4606, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1007%2Fs13244-018-0639-9/MediaObjects/13244_2018_639_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6108980', 'pmc', 'review', 'Insights into Imaging', '["Rikiya Yamashita","Mizuho Nishio","Richard Kinh Gian","Kaori Togashi"]', 'artificial intelligence', 'Convolutional neural network (CNN), a class of artificial neural networks that has become dominant in various computer vision tasks, is attracting interest across a variety of domains, including radiology. CNN is designed to automatically and adaptively learn spatial hierarchies of features through backpropagation by using multiple building blocks, such as convolution layers, pooling layers, and fully connected layers. This review article offers a perspective on the basic concepts of CNN and its application to various radiological tasks, and discusses its challenges and future directions in the field of radiology. Two challenges in applying CNN to radiological tasks, small dataset and overfitting, will also be covered in this article, as well as techniques to minimize them. Being familiar with the concepts and advantages, as well as limitations, of CNN is essential to leverage its potential in diagnostic radiology, with the goal of augmenting the performance of radiologists and improving patient care. KEY POINTS: • Convolutional neural network is a class of deep learning methods which has become dominant in various computer vision tasks and is attracting interest across a variety of domains, including radiology. • Convolutional neural network is composed of multiple building blocks, such as convolution layers, pooling layers, and fully connected layers, and is designed to automatically and adaptively learn spatial hierarchies of features through a backpropagation algorithm. • Familiarity with the concepts and advantages, as well as limitations, of convolutional neural network is essential to leverage its potential to improve radiologist performance and, eventually, patient care.', '2026-07-08 07:02:03');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2101270539', 'artificial-intelligence', 'Making sense of implementation theories, models and frameworks', 'BACKGROUND: Implementation science has progressed towards increased use of theoretical approaches to provide better understanding and explanation of how and why implementation succeeds or fails. The…', '2015', 2015, 4565, 4565, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs43058-020-00023-7/MediaObjects/43058_2020_23_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4406164', 'pmc', 'article', 'Implementation Science', '["Per Nilsén"]', 'artificial intelligence', 'BACKGROUND: Implementation science has progressed towards increased use of theoretical approaches to provide better understanding and explanation of how and why implementation succeeds or fails. The aim of this article is to propose a taxonomy that distinguishes between different categories of theories, models and frameworks in implementation science, to facilitate appropriate selection and application of relevant approaches in implementation research and practice and to foster cross-disciplinary dialogue among implementation researchers. DISCUSSION: Theoretical approaches used in implementation science have three overarching aims: describing and/or guiding the process of translating research into practice (process models); understanding and/or explaining what influences implementation outcomes (determinant frameworks, classic theories, implementation theories); and evaluating implementation (evaluation frameworks). This article proposes five categories of theoretical approaches to achieve three overarching aims. These categories are not always recognized as separate types of approaches in the literature. While there is overlap between some of the theories, models and frameworks, awareness of the differences is important to facilitate the selection of relevant approaches. Most determinant frameworks provide limited "how-to" support for carrying out implementation endeavours since the determinants usually are too generic to provide sufficient detail for guiding an implementation process. And while the relevance of addressing barriers and enablers to translating research into practice is mentioned in many process models, these models do not identify or systematically structure specific determinants associated with implementation success. Furthermore, process models recognize a temporal sequence of implementation endeavours, whereas determinant frameworks do not explicitly take a process perspective of implementation.', '2026-07-08 07:02:07');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3094704314', 'artificial-intelligence', 'A review on genetic algorithm: past, present, and future', 'A review on genetic algorithm: past, present, and future', '2020', 2020, 4462, 4462, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1007%2Fs11042-020-10139-6/MediaObjects/11042_2020_10139_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7599983', 'pmc', 'review', 'Multimedia Tools and Applications', '["Sourabh Katoch","Sumit Singh Chauhan","Vijay Kumar"]', 'artificial intelligence', NULL, '2026-07-08 07:02:09');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4384071683', 'artificial-intelligence', 'Large language models encode clinical knowledge', 'Abstract Large language models (LLMs) have demonstrated impressive capabilities, but the bar for clinical applications is high. Attempts to assess the clinical knowledge of models typically rely on…', '2023', 2023, 3250, 3250, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-023-06291-2/MediaObjects/41586_2023_6291_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/10396962', 'pmc', 'article', 'Nature', '["Karan Singhal","Shekoofeh Azizi","Tao Tu","S. Sara Mahdavi","Jason Lee","Hyung Won Chung","Nathan Scales","Ajay Kumar Tanwani","Heather Cole-Lewis","Stephen Pfohl","Perry W. Payne","Martin Seneviratne","Paul Gamble","Christopher Kelly","Abubakr Babiker","Nathanael Schärli","Aakanksha Chowdhery","P. Mansfield","Dina Demner‐Fushman","Blaise Agüera y Arcas","Dale R. Webster","Greg S. Corrado","Yossi Matias","Katherine Chou","Juraj Gottweis","Nenad Tomašev","Yun Liu","Alvin Rajkomar","Joëlle Barral","Christopher Semturs","Alan Karthikesalingam","Vivek Natarajan"]', 'artificial intelligence', 'Abstract Large language models (LLMs) have demonstrated impressive capabilities, but the bar for clinical applications is high. Attempts to assess the clinical knowledge of models typically rely on automated evaluations based on limited benchmarks. Here, to address these limitations, we present MultiMedQA, a benchmark combining six existing medical question answering datasets spanning professional medicine, research and consumer queries and a new dataset of medical questions searched online, HealthSearchQA. We propose a human evaluation framework for model answers along multiple axes including factuality, comprehension, reasoning, possible harm and bias. In addition, we evaluate Pathways Language Model 1 (PaLM, a 540-billion parameter LLM) and its instruction-tuned variant, Flan-PaLM 2 on MultiMedQA. Using a combination of prompting strategies, Flan-PaLM achieves state-of-the-art accuracy on every MultiMedQA multiple-choice dataset (MedQA 3, MedMCQA 4, PubMedQA 5 and Measuring Massive Multitask Language Understanding (MMLU) clinical topics 6 ), including 67.6% accuracy on MedQA (US Medical Licensing Exam-style questions), surpassing the prior state of the art by more than 17%. However, human evaluation reveals key gaps. To resolve this, we introduce instruction prompt tuning, a parameter-efficient approach for aligning LLMs to new domains using a few exemplars. The resulting model, Med-PaLM, performs encouragingly, but remains inferior to clinicians. We show that comprehension, knowledge recall and reasoning improve with model scale and instruction prompt tuning, suggesting the potential utility of LLMs in medicine. Our human evaluations reveal limitations of today’s models, reinforcing the importance of both evaluation frameworks and method development in creating safe, helpful LLMs for clinical applications.', '2026-07-08 07:04:05');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2794825826', 'artificial-intelligence', 'The HAM10000 dataset, a large collection of multi-source dermatoscopic images of common pigmented skin lesions', 'Training of neural networks for automated diagnosis of pigmented skin lesions is hampered by the small size and lack of diversity of available datasets of dermatoscopic images. We tackle this problem…', '2018', 2018, 3196, 3196, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fsdata.2018.161/MediaObjects/41597_2018_Article_BFsdata2018161_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6091241', 'pmc', 'article', 'Scientific Data', '["Philipp Tschandl","Cliff Rosendahl","Harald Kittler"]', 'artificial intelligence', 'Training of neural networks for automated diagnosis of pigmented skin lesions is hampered by the small size and lack of diversity of available datasets of dermatoscopic images. We tackle this problem by releasing the HAM10000 ("Human Against Machine with 10000 training images") dataset. We collected dermatoscopic images from different populations acquired and stored by different modalities. Given this diversity we had to apply different acquisition and cleaning methods and developed semi-automatic workflows utilizing specifically trained neural networks. The final dataset consists of 10015 dermatoscopic images which are released as a training set for academic machine learning purposes and are publicly available through the ISIC archive. This benchmark dataset can be used for machine learning and for comparisons with human experts. Cases include a representative collection of all important diagnostic categories in the realm of pigmented lesions. More than 50% of lesions have been confirmed by pathology, while the ground truth for the rest of the cases was either follow-up, expert consensus, or confirmation by in-vivo confocal microscopy.', '2026-07-08 07:04:06');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3105081694', 'artificial-intelligence', 'COVID-Net: a tailored deep convolutional neural network design for detection of COVID-19 cases from chest X-ray images', 'The Coronavirus Disease 2019 (COVID-19) pandemic continues to have a devastating effect on the health and well-being of the global population. A critical step in the fight against COVID-19 is…', '2020', 2020, 3159, 3159, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41598-020-76550-z/MediaObjects/41598_2020_76550_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7658227', 'pmc', 'article', 'Scientific Reports', '["Linda Wang","Zhong Qiu Lin","Alexander Wong"]', 'artificial intelligence', 'The Coronavirus Disease 2019 (COVID-19) pandemic continues to have a devastating effect on the health and well-being of the global population. A critical step in the fight against COVID-19 is effective screening of infected patients, with one of the key screening approaches being radiology examination using chest radiography. It was found in early studies that patients present abnormalities in chest radiography images that are characteristic of those infected with COVID-19. Motivated by this and inspired by the open source efforts of the research community, in this study we introduce COVID-Net, a deep convolutional neural network design tailored for the detection of COVID-19 cases from chest X-ray (CXR) images that is open source and available to the general public. To the best of the authors'' knowledge, COVID-Net is one of the first open source network designs for COVID-19 detection from CXR images at the time of initial release. We also introduce COVIDx, an open access benchmark dataset that we generated comprising of 13,975 CXR images across 13,870 patient patient cases, with the largest number of publicly available COVID-19 positive cases to the best of the authors'' knowledge. Furthermore, we investigate how COVID-Net makes predictions using an explainability method in an attempt to not only gain deeper insights into critical factors associated with COVID cases, which can aid clinicians in improved screening, but also audit COVID-Net in a responsible and transparent manner to validate that it is making decisions based on relevant information from the CXR images. By no means a production-ready solution, the hope is that the open access COVID-Net, along with the description on constructing the open source COVIDx dataset, will be leveraged and build upon by both researchers and citizen data scientists alike to accelerate the development of highly accurate yet practical deep learning solutions for detecting COVID-19 cases and accelerate treatment of those who need it the most.', '2026-07-08 07:04:21');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2998175747', 'artificial-intelligence', 'International evaluation of an AI system for breast cancer screening', 'International evaluation of an AI system for breast cancer screening', '2020', 2020, 3165, 3165, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-019-1799-6/MediaObjects/41586_2019_1799_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/31894144', 'repository', 'article', 'Nature', '["Scott Mayer McKinney","Marcin Sieniek","Varun Godbole","Jonathan Godwin","Н. В. Антропова","Hutan Ashrafian","Trevor Back","Mary Chesus","Greg S. Corrado","Ara Darzi","Mozziyar Etemadi","Florencia Garcia-Vicente","Fiona J. Gilbert","Mark Halling‐Brown","Demis Hassabis","Sunny Jansen","Alan Karthikesalingam","Christopher Kelly","Dominic King","Joseph R. Ledsam","David Melnick","Hormuz Mostofi","Lily Peng","Joshua Reicher","Bernardino Romera‐Paredes","Richard Sidebottom","Mustafa Suleyman","Daniel Tse","Kenneth C. Young","Jeffrey De Fauw","Shravya Shetty"]', 'artificial intelligence', NULL, '2026-07-08 07:04:23');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2587466508', 'artificial-intelligence', 'Big Data in Smart Farming – A review', 'Big Data in Smart Farming – A review', '2017', 2017, 3043, 3043, 'https://ars.els-cdn.com/content/image/1-s2.0-S0308521X16303754-gr1.jpg', 'https://doi.org/10.1016/j.agsy.2017.01.023', 'repository', 'review', 'Agricultural Systems', '["J. Wolfert","Lan Ge","C.N. Verdouw","M.J. Bogaardt"]', 'artificial intelligence', NULL, '2026-07-08 07:04:55');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2751069891', 'artificial-intelligence', 'Advancing The Cancer Genome Atlas glioma MRI collections with expert segmentation labels and radiomic features', 'Gliomas belong to a group of central nervous system tumors, and consist of various sub-regions. Gold standard labeling of these sub-regions in radiographic imaging is essential for both clinical and…', '2017', 2017, 2968, 2968, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fsdata.2017.117/MediaObjects/41597_2017_Article_BFsdata2017117_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5685212', 'pmc', 'article', 'Scientific Data', '["Spyridon Bakas","Hamed Akbari","Aristeidis Sotiras","Michel Bilello","Martin Rozycki","Justin Kirby","John Freymann","Keyvan Farahani","Christos Davatzikos"]', 'artificial intelligence', 'Gliomas belong to a group of central nervous system tumors, and consist of various sub-regions. Gold standard labeling of these sub-regions in radiographic imaging is essential for both clinical and computational studies, including radiomic and radiogenomic analyses. Towards this end, we release segmentation labels and radiomic features for all pre-operative multimodal magnetic resonance imaging (MRI) (n=243) of the multi-institutional glioma collections of The Cancer Genome Atlas (TCGA), publicly available in The Cancer Imaging Archive (TCIA). Pre-operative scans were identified in both glioblastoma (TCGA-GBM, n=135) and low-grade-glioma (TCGA-LGG, n=108) collections via radiological assessment. The glioma sub-region labels were produced by an automated state-of-the-art method and manually revised by an expert board-certified neuroradiologist. An extensive panel of radiomic features was extracted based on the manually-revised labels. This set of labels and features should enable i) direct utilization of the TCGA/TCIA glioma collections towards repeatable, reproducible and comparative quantitative studies leading to new predictive, prognostic, and diagnostic assessments, as well as ii) performance evaluation of computer-aided segmentation methods, and comparison to our state-of-the-art method.', '2026-07-08 07:05:08');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2937307539', 'artificial-intelligence', 'Applications of machine learning in drug discovery and development', 'Applications of machine learning in drug discovery and development', '2019', 2019, 2977, 2977, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41573-019-0024-5/MediaObjects/41573_2019_24_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6552674', 'pmc', 'review', 'Nature Reviews Drug Discovery', '["Jessica Vamathevan","Dominic A. Clark","Paul Czodrowski","Ian Dunham","Edgardo A. Ferrán","George Lee","Bin Li","Anant Madabhushi","Parantu K. Shah","Michaela Spitzer","Shanrong Zhao"]', 'artificial intelligence', NULL, '2026-07-08 07:05:09');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1542981317', 'artificial-intelligence', 'Training and operation of an integrated neuromorphic network based on metal-oxide memristors', 'Training and operation of an integrated neuromorphic network based on metal-oxide memristors', '2015', 2015, 2943, 2943, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature14441/MediaObjects/41586_2015_Article_BFnature14441_Fig1_HTML.jpg', 'http://arxiv.org/abs/1412.0611', 'arxiv', 'article', 'Nature', '["M. Prezioso","Farshad Merrikh‐Bayat","Brian D. Hoskins","Gina C. Adam","Konstantin K. Likharev","Dmitri B. Strukov"]', 'artificial intelligence', NULL, '2026-07-08 07:05:20');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2063756105', 'artificial-intelligence', 'RASTtk: A modular and extensible implementation of the RAST algorithm for building custom annotation pipelines and annotating batches of genomes', 'The RAST (Rapid Annotation using Subsystem Technology) annotation engine was built in 2008 to annotate bacterial and archaeal genomes. It works by offering a standard software pipeline for…', '2015', 2015, 2908, 2908, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fsrep08365/MediaObjects/41598_2015_Article_BFsrep08365_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4322359', 'pmc', 'article', 'Scientific Reports', '["Thomas Brettin","James J. Davis","Terry Disz","Robert A. Edwards","Svetlana Gerdes","Gary J. Olsen","Robert Olson","Ross Overbeek","Bruce Parrello","Gordon D. Pusch","Maulik Shukla","James Thomason","Rick Stevens","Veronika Vonstein","Alice R. Wattam","Fangfang Xia"]', 'artificial intelligence', 'The RAST (Rapid Annotation using Subsystem Technology) annotation engine was built in 2008 to annotate bacterial and archaeal genomes. It works by offering a standard software pipeline for identifying genomic features (i.e., protein-encoding genes and RNA) and annotating their functions. Recently, in order to make RAST a more useful research tool and to keep pace with advancements in bioinformatics, it has become desirable to build a version of RAST that is both customizable and extensible. In this paper, we describe the RAST tool kit (RASTtk), a modular version of RAST that enables researchers to build custom annotation pipelines. RASTtk offers a choice of software for identifying and annotating genomic features as well as the ability to add custom features to an annotation job. RASTtk also accommodates the batch submission of genomes and the ability to customize annotation protocols for batch submissions. This is the first major software restructuring of RAST since its inception.', '2026-07-08 07:05:20');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2760946358', 'artificial-intelligence', 'Classification and mutation prediction from non–small cell lung cancer histopathology images using deep learning', 'Classification and mutation prediction from non–small cell lung cancer histopathology images using deep learning', '2018', 2018, 2897, 2897, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41591-018-0177-5/MediaObjects/41591_2018_177_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/9847512', 'pmc', 'article', 'Nature Medicine', '["Nicolas Coudray","Paolo Ocampo","Theodore Sakellaropoulos","Navneet Narula","Matija Snuderl","David Fenyö","André L. Moreira","Narges Razavian","Aristotelis Tsirigos"]', 'artificial intelligence', NULL, '2026-07-08 07:05:21');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2924382816', 'artificial-intelligence', 'Data-driven prediction of battery cycle life before capacity degradation', 'Data-driven prediction of battery cycle life before capacity degradation', '2019', 2019, 2877, 2877, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41560-019-0356-8/MediaObjects/41560_2019_356_Fig1_HTML.png', 'https://doi.org/10.1038/s41560-019-0356-8', 'repository', 'article', 'Nature Energy', '["Kristen Severson","Peter M. Attia","Norman Jin","Nicholas Perkins","Benben Jiang","Zi Yang","Michael H. Chen","Muratahan Aykol","Patrick K. Herring","Dimitrios Fraggedakis","Martin Z. Bazant","Stephen J. Harris","William C. Chueh","Richard D. Braatz"]', 'artificial intelligence', NULL, '2026-07-08 07:05:21');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2979786244', 'artificial-intelligence', 'Learning nonlinear operators via DeepONet based on the universal approximation theorem of operators', 'Learning nonlinear operators via DeepONet based on the universal approximation theorem of operators', '2021', 2021, 2864, 2864, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs42256-021-00302-5/MediaObjects/42256_2021_302_Fig1_HTML.png', 'http://arxiv.org/abs/1910.03193', 'arxiv', 'article', 'Nature Machine Intelligence', '["Lu Lu","Pengzhan Jin","Guofei Pang","Zhongqiang Zhang","George Em Karniadakis"]', 'artificial intelligence', NULL, '2026-07-08 07:05:22');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1909740415', 'artificial-intelligence', 'Metrics for evaluating 3D medical image segmentation: analysis, selection, and tool', 'BACKGROUND: Medical Image segmentation is an important image processing step. Comparing images to evaluate the quality of segmentation is an essential part of measuring progress in this research…', '2015', 2015, 2791, 2791, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1007%2Fs42979-024-03102-x/MediaObjects/42979_2024_3102_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4533825', 'pmc', 'article', 'BMC Medical Imaging', '["Abdel Aziz Taha","Allan Hanbury"]', 'artificial intelligence', 'BACKGROUND: Medical Image segmentation is an important image processing step. Comparing images to evaluate the quality of segmentation is an essential part of measuring progress in this research area. Some of the challenges in evaluating medical segmentation are: metric selection, the use in the literature of multiple definitions for certain metrics, inefficiency of the metric calculation implementations leading to difficulties with large volumes, and lack of support for fuzzy segmentation by existing metrics. RESULT: First we present an overview of 20 evaluation metrics selected based on a comprehensive literature review. For fuzzy segmentation, which shows the level of membership of each voxel to multiple classes, fuzzy definitions of all metrics are provided. We present a discussion about metric properties to provide a guide for selecting evaluation metrics. Finally, we propose an efficient evaluation tool implementing the 20 selected metrics. The tool is optimized to perform efficiently in terms of speed and required memory, also if the image size is extremely large as in the case of whole body MRI or CT volume segmentation. An implementation of this tool is available as an open source project. CONCLUSION: We propose an efficient evaluation tool for 3D medical image segmentation using 20 evaluation metrics and provide guidelines for selecting a subset of these metrics that is suitable for the data and the segmentation task.', '2026-07-08 07:05:32');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4386958277', 'artificial-intelligence', 'Revolutionizing healthcare: the role of artificial intelligence in clinical practice', 'INTRODUCTION: Healthcare systems are complex and challenging for all stakeholders, but artificial intelligence (AI) has transformed various fields, including healthcare, with the potential to improve…', '2023', 2023, 2840, 2840, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs12909-023-04698-z/MediaObjects/12909_2023_4698_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/10517477', 'pmc', 'review', 'BMC Medical Education', '["Shuroug A. Alowais","Sahar S. Alghamdi","Nada Alsuhebany","Tariq Alqahtani","Abdulrahman Alshaya","Sumaya N. Almohareb","Atheer Aldairem","Mohammed Alrashed","Khalid Bin Saleh","Hisham A. Badreldin","Majed S. Al Yami","Shmeylan Al Harbi","Abdulkareem Albekairy"]', 'artificial intelligence', 'INTRODUCTION: Healthcare systems are complex and challenging for all stakeholders, but artificial intelligence (AI) has transformed various fields, including healthcare, with the potential to improve patient care and quality of life. Rapid AI advancements can revolutionize healthcare by integrating it into clinical practice. Reporting AI''s role in clinical practice is crucial for successful implementation by equipping healthcare providers with essential knowledge and tools. RESEARCH SIGNIFICANCE: This review article provides a comprehensive and up-to-date overview of the current state of AI in clinical practice, including its potential applications in disease diagnosis, treatment recommendations, and patient engagement. It also discusses the associated challenges, covering ethical and legal considerations and the need for human expertise. By doing so, it enhances understanding of AI''s significance in healthcare and supports healthcare organizations in effectively adopting AI technologies. MATERIALS AND METHODS: The current investigation analyzed the use of AI in the healthcare system with a comprehensive review of relevant indexed literature, such as PubMed/Medline, Scopus, and EMBASE, with no time constraints but limited to articles published in English. The focused question explores the impact of applying AI in healthcare settings and the potential outcomes of this application. RESULTS: Integrating AI into healthcare holds excellent potential for improving disease diagnosis, treatment selection, and clinical laboratory testing. AI tools can leverage large datasets and identify patterns to surpass human performance in several healthcare aspects. AI offers increased accuracy, reduced costs, and time savings while minimizing human errors. It can revolutionize personalized medicine, optimize medication dosages, enhance population health management, establish guidelines, provide virtual health assistants, support mental health care, improve patient education, and influence patient-physician trust. CONCLUSION: AI can be used to diagnose diseases, develop personalized treatment plans, and assist clinicians with decision-making. Rather than simply automating tasks, AI is about developing technologies that can enhance patient care across healthcare settings. However, challenges related to data privacy, bias, and the need for human expertise must be addressed for the responsible and effective implementation of AI in healthcare.', '2026-07-08 07:05:33');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2936503027', 'artificial-intelligence', 'Survey on deep learning with class imbalance', 'The purpose of this study is to examine existing deep learning techniques for addressing class imbalanced data. Effective classification with imbalanced data is an important area of research, as high…', '2019', 2019, 2846, 2846, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs40537-019-0192-5/MediaObjects/40537_2019_192_Fig1_HTML.png', 'https://doi.org/10.1186/s40537-019-0192-5', 'repository', 'article', 'Journal Of Big Data', '["Justin Johnson","Taghi M. Khoshgoftaar"]', 'artificial intelligence', 'The purpose of this study is to examine existing deep learning techniques for addressing class imbalanced data. Effective classification with imbalanced data is an important area of research, as high class imbalance is naturally inherent in many real-world applications, e.g., fraud detection and cancer detection. Moreover, highly imbalanced data poses added difficulty, as most learners will exhibit bias towards the majority class, and in extreme cases, may ignore the minority class altogether. Class imbalance has been studied thoroughly over the last two decades using traditional machine learning models, i.e. non-deep learning. Despite recent advances in deep learning, along with its increasing popularity, very little empirical work in the area of deep learning with class imbalance exists. Having achieved record-breaking performance results in several complex domains, investigating the use of deep neural networks for problems containing high levels of class imbalance is of great interest. Available studies regarding class imbalance and deep learning are surveyed in order to better understand the efficacy of deep learning when applied to class imbalanced data. This survey discusses the implementation details and experimental results for each study, and offers additional insight into their strengths and weaknesses. Several areas of focus include: data complexity, architectures tested, performance interpretation, ease of use, big data application, and generalization to other domains. We have found that research in this area is very limited, that most existing work focuses on computer vision tasks with convolutional neural networks, and that the effects of big data are rarely considered. Several traditional methods for class imbalance, e.g. data sampling and cost-sensitive learning, prove to be applicable in deep learning, while more advanced methods that exploit neural network feature learning abilities show promising results. The survey concludes with a discussion that highlights various gaps in deep learning from class imbalanced data for the purpose of guiding future research.', '2026-07-08 07:05:34');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2198606573', 'artificial-intelligence', 'Predicting effects of noncoding variants with deep learning–based sequence model', 'Predicting effects of noncoding variants with deep learning–based sequence model', '2015', 2015, 2611, 2611, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnmeth.3547/MediaObjects/41592_2015_Article_BFnmeth3547_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4768299', 'pmc', 'article', 'Nature Methods', '["Jian Zhou","Olga G. Troyanskaya"]', 'artificial intelligence', NULL, '2026-07-08 07:06:27');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2956228567', 'artificial-intelligence', 'Clinical-grade computational pathology using weakly supervised deep learning on whole slide images', 'Clinical-grade computational pathology using weakly supervised deep learning on whole slide images', '2019', 2019, 2635, 2635, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41591-019-0508-1/MediaObjects/41591_2019_508_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7418463', 'pmc', 'article', 'Nature Medicine', '["Gabriele Campanella","Matthew G. Hanna","Luke Geneslaw","Allen P. Miraflor","Vitor Werneck Krauss Silva","Klaus J. Busam","Edi Brogi","Victor E. Reuter","David S. Klimstra","Thomas J. Fuchs"]', 'artificial intelligence', NULL, '2026-07-08 07:06:28');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2995081665', 'artificial-intelligence', 'Evolutionary classification of CRISPR–Cas systems: a burst of class 2 and derived variants', 'Evolutionary classification of CRISPR–Cas systems: a burst of class 2 and derived variants', '2019', 2019, 2474, 2474, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41579-019-0299-x/MediaObjects/41579_2019_299_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8905525', 'pmc', 'review', 'Nature Reviews Microbiology', '["Kira S. Makarova","Yuri I. Wolf","Jaime Iranzo","Sergey Shmakov","Omer S. Alkhnbashi","Stan J. J. Brouns","Emmanuelle Charpentier","David R. Cheng","Daniel H. Haft","Philippe Horvath","Sylvain Moineau","Francisco J. M. Mojica","David Scott","Shiraz A. Shah","Virginijus Šikšnys","Michael P. Terns","Česlovas Venclovas","Malcolm F. White","Alexander F. Yakunin","Winston X. Yan","Feng Zhang","Roger A. Garrett","Rolf Backofen","John van der Oost","Rodolphe Barrangou","Eugene V. Koonin"]', 'artificial intelligence', NULL, '2026-07-08 07:07:08');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3023211159', 'artificial-intelligence', 'A comprehensive survey on support vector machine classification: Applications, challenges and trends', 'A comprehensive survey on support vector machine classification: Applications, challenges and trends', '2020', 2020, 2285, 2285, 'https://ars.els-cdn.com/content/image/1-s2.0-S0925231220307153-fx1.jpg', 'https://doi.org/10.1016/j.neucom.2019.10.118', 'repository', 'article', 'Neurocomputing', '["Jair Cervantes","Farid García‐Lamont","Lisbeth Rodríguez-Mazahua","Asdrúbal López‐Chau"]', 'artificial intelligence', NULL, '2026-07-08 07:08:10');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2515300481', 'artificial-intelligence', 'Big data analytics and firm performance: Effects of dynamic capabilities', 'Big data analytics and firm performance: Effects of dynamic capabilities', '2016', 2016, 2200, 2200, 'https://ars.els-cdn.com/content/image/1-s2.0-S0148296316304969-gr1.jpg', 'https://doi.org/10.1016/j.jbusres.2016.08.009', 'repository', 'article', 'Journal of Business Research', '["Samuel Fosso Wamba","Angappa Gunasekaran","Shahriar Akter","Steven Ji-Fan Ren","Rameshwar Dubey","Stephen J. Childe"]', 'artificial intelligence', NULL, '2026-07-08 07:08:53');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2811106513', 'artificial-intelligence', 'CellProfiler 3.0: Next-generation image processing for biology', 'CellProfiler has enabled the scientific research community to create flexible, modular image analysis pipelines since its release in 2005. Here, we describe CellProfiler 3.0, a new version of the…', '2018', 2018, 2130, 2130, 'https://journals.plos.org/plosbiology/article/figure/image?size=large&id=10.1371/journal.pbio.2005970.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6029841', 'pmc', 'article', 'PLoS Biology', '["Claire McQuin","Allen Goodman","Vasiliy S. Chernyshev","Lee Kamentsky","Beth A. Cimini","Kyle W. Karhohs","Minh Doan","Liya Ding","Susanne M. Rafelski","Derek Thirstrup","Winfried Wiegraebe","Shantanu Singh","Tim Becker","Juan Carlos Caicedo","Anne E. Carpenter"]', 'artificial intelligence', 'CellProfiler has enabled the scientific research community to create flexible, modular image analysis pipelines since its release in 2005. Here, we describe CellProfiler 3.0, a new version of the software supporting both whole-volume and plane-wise analysis of three-dimensional (3D) image stacks, increasingly common in biomedical research. CellProfiler''s infrastructure is greatly improved, and we provide a protocol for cloud-based, large-scale image processing. New plugins enable running pretrained deep learning models on images. Designed by and for biologists, CellProfiler equips researchers with powerful computational tools via a well-documented user interface, empowering biologists in all fields to create quantitative, reproducible image analysis workflows.', '2026-07-08 07:09:11');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3149839747', 'artificial-intelligence', 'Ensemble deep learning: A review', 'Ensemble deep learning: A review', '2022', 2022, 2056, 2056, 'https://ars.els-cdn.com/content/image/1-s2.0-S095219762200269X-gr1.jpg', 'http://arxiv.org/abs/2104.02395', 'arxiv', 'review', 'Engineering Applications of Artificial Intelligence', '["M. A. Ganaie","Minghui Hu","A. K. Malik","M. Tanveer","Ponnuthurai Nagaratnam Suganthan"]', 'artificial intelligence', NULL, '2026-07-08 07:10:00');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4383957026', 'artificial-intelligence', 'De novo design of protein structure and function with RFdiffusion', 'Abstract There has been considerable recent progress in designing new proteins using deep-learning methods 1–9. Despite this progress, a general deep-learning framework for protein design that…', '2023', 2023, 2001, 2001, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-023-06415-8/MediaObjects/41586_2023_6415_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/10468394', 'pmc', 'article', 'Nature', '["Joseph L. Watson","David Juergens","Nathaniel R. Bennett","Brian L. Trippe","Jason Yim","Helen E. Eisenach","Woody Ahern","Andrew J. Borst","Robert J. Ragotte","Lukas F. Milles","Basile I. M. Wicky","Nikita Hanikel","Samuel J. Pellock","Alexis Courbet","William Sheffler","Jue Wang","Preetham Venkatesh","Isaac Sappington","Susana Vázquez Torres","Anna Lauko","Valentin De Bortoli","Émile Mathieu","Sergey Ovchinnikov","Regina Barzilay","Tommi Jaakkola","Frank DiMaio","Minkyung Baek","David Baker"]', 'artificial intelligence', 'Abstract There has been considerable recent progress in designing new proteins using deep-learning methods 1–9. Despite this progress, a general deep-learning framework for protein design that enables solution of a wide range of design challenges, including de novo binder design and design of higher-order symmetric architectures, has yet to be described. Diffusion models 10,11 have had considerable success in image and language generative modelling but limited success when applied to protein modelling, probably due to the complexity of protein backbone geometry and sequence–structure relationships. Here we show that by fine-tuning the RoseTTAFold structure prediction network on protein structure denoising tasks, we obtain a generative model of protein backbones that achieves outstanding performance on unconditional and topology-constrained protein monomer design, protein binder design, symmetric oligomer design, enzyme active site scaffolding and symmetric motif scaffolding for therapeutic and metal-binding protein design. We demonstrate the power and generality of the method, called RoseTTAFold diffusion (RFdiffusion), by experimentally characterizing the structures and functions of hundreds of designed symmetric assemblies, metal-binding proteins and protein binders. The accuracy of RFdiffusion is confirmed by the cryogenic electron microscopy structure of a designed binder in complex with influenza haemagglutinin that is nearly identical to the design model. In a manner analogous to networks that produce images from user-specified inputs, RFdiffusion enables the design of diverse functional proteins from simple molecular specifications.', '2026-07-08 07:10:21');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2951553270', 'artificial-intelligence', 'Polygenic prediction via Bayesian regression and continuous shrinkage priors', 'Polygenic risk scores (PRS) have shown promise in predicting human complex traits and diseases. Here, we present PRS-CS, a polygenic prediction method that infers posterior effect sizes of single…', '2019', 2019, 1999, 1999, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41467-019-09718-5/MediaObjects/41467_2019_9718_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6467998', 'pmc', 'article', 'Nature Communications', '["Tian Ge","Chia‐Yen Chen","Yang Ni","Yen‐Chen Anne Feng","Jordan W. Smoller"]', 'artificial intelligence', 'Polygenic risk scores (PRS) have shown promise in predicting human complex traits and diseases. Here, we present PRS-CS, a polygenic prediction method that infers posterior effect sizes of single nucleotide polymorphisms (SNPs) using genome-wide association summary statistics and an external linkage disequilibrium (LD) reference panel. PRS-CS utilizes a high-dimensional Bayesian regression framework, and is distinct from previous work by placing a continuous shrinkage (CS) prior on SNP effect sizes, which is robust to varying genetic architectures, provides substantial computational advantages, and enables multivariate modeling of local LD patterns. Simulation studies using data from the UK Biobank show that PRS-CS outperforms existing methods across a wide range of genetic architectures, especially when the training sample size is large. We apply PRS-CS to predict six common complex diseases and six quantitative traits in the Partners HealthCare Biobank, and further demonstrate the improvement of PRS-CS in prediction accuracy over alternative methods.', '2026-07-08 07:10:21');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2753919178', 'artificial-intelligence', 'DeepSurv: personalized treatment recommender system using a Cox proportional hazards deep neural network', 'BACKGROUND: Medical practitioners use survival models to explore and understand the relationships between patients'' covariates (e.g. clinical and genetic features) and the effectiveness of various…', '2018', 2018, 1914, 1914, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1038%2Fs41598-019-43372-7/MediaObjects/41598_2019_43372_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5828433', 'pmc', 'article', 'BMC Medical Research Methodology', '["Jared Katzman","Uri Shaham","Alexander Cloninger","Jonathan Bates","Tingting Jiang","Yuval Kluger"]', 'artificial intelligence', 'BACKGROUND: Medical practitioners use survival models to explore and understand the relationships between patients'' covariates (e.g. clinical and genetic features) and the effectiveness of various treatment options. Standard survival models like the linear Cox proportional hazards model require extensive feature engineering or prior medical knowledge to model treatment interaction at an individual level. While nonlinear survival methods, such as neural networks and survival forests, can inherently model these high-level interaction terms, they have yet to be shown as effective treatment recommender systems. METHODS: We introduce DeepSurv, a Cox proportional hazards deep neural network and state-of-the-art survival method for modeling interactions between a patient''s covariates and treatment effectiveness in order to provide personalized treatment recommendations. RESULTS: We perform a number of experiments training DeepSurv on simulated and real survival data. We demonstrate that DeepSurv performs as well as or better than other state-of-the-art survival models and validate that DeepSurv successfully models increasingly complex relationships between a patient''s covariates and their risk of failure. We then show how DeepSurv models the relationship between a patient''s features and effectiveness of different treatment options to show how DeepSurv can be used to provide individual treatment recommendations. Finally, we train DeepSurv on real clinical studies to demonstrate how it''s personalized treatment recommendations would increase the survival time of a set of patients. CONCLUSIONS: The predictive and modeling capabilities of DeepSurv will enable medical researchers to use deep neural networks as a tool in their exploration, understanding, and prediction of the effects of a patient''s characteristics on their risk of failure.', '2026-07-08 07:11:01');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1864161604', 'artificial-intelligence', 'Sparse and Compositionally Robust Inference of Microbial Ecological Networks', '16S ribosomal RNA (rRNA) gene and other environmental sequencing techniques provide snapshots of microbial communities, revealing phylogeny and the abundances of microbial populations across diverse…', '2015', 2015, 1887, 1887, 'https://journals.plos.org/ploscompbiol/article/figure/image?size=large&id=10.1371/journal.pcbi.1004226.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4423992', 'pmc', 'article', 'PLoS Computational Biology', '["Zachary Kurtz","Christian L. Müller","Emily R. Miraldi","Dan R. Littman","Martin J. Blaser","Richard Bonneau"]', 'artificial intelligence', '16S ribosomal RNA (rRNA) gene and other environmental sequencing techniques provide snapshots of microbial communities, revealing phylogeny and the abundances of microbial populations across diverse ecosystems. While changes in microbial community structure are demonstrably associated with certain environmental conditions (from metabolic and immunological health in mammals to ecological stability in soils and oceans), identification of underlying mechanisms requires new statistical tools, as these datasets present several technical challenges. First, the abundances of microbial operational taxonomic units (OTUs) from amplicon-based datasets are compositional. Counts are normalized to the total number of counts in the sample. Thus, microbial abundances are not independent, and traditional statistical metrics (e.g., correlation) for the detection of OTU-OTU relationships can lead to spurious results. Secondly, microbial sequencing-based studies typically measure hundreds of OTUs on only tens to hundreds of samples; thus, inference of OTU-OTU association networks is severely under-powered, and additional information (or assumptions) are required for accurate inference. Here, we present SPIEC-EASI (SParse InversE Covariance Estimation for Ecological Association Inference), a statistical method for the inference of microbial ecological networks from amplicon sequencing datasets that addresses both of these issues. SPIEC-EASI combines data transformations developed for compositional data analysis with a graphical model inference framework that assumes the underlying ecological association network is sparse. To reconstruct the network, SPIEC-EASI relies on algorithms for sparse neighborhood and inverse covariance selection. To provide a synthetic benchmark in the absence of an experimentally validated gold-standard network, SPIEC-EASI is accompanied by a set of computational tools to generate OTU count data from a set of diverse underlying network topologies. SPIEC-EASI outperforms state-of-the-art methods to recover edges and network properties on synthetic data under a variety of scenarios. SPIEC-EASI also reproducibly predicts previously unknown microbial associations using data from the American Gut project.', '2026-07-08 07:11:26');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3031052835', 'artificial-intelligence', 'Latent profile analysis: A review and “how to” guide of its application within vocational behavior research', 'Latent profile analysis (LPA) is a categorical latent variable approach that focuses on identifying latent subpopulations within a population based on a certain set of variables. LPA thus assumes…', '2020', 2020, 1824, 1824, 'https://ars.els-cdn.com/content/image/1-s2.0-S0001879120300701-gr1.jpg', 'https://doi.org/10.1016/j.jvb.2020.103445', 'repository', 'review', 'Journal of Vocational Behavior', '["Daniel Spurk","Andreas Hirschi","Mo Wang","Domingo Campillo Valero","Simone Kauffeld"]', 'artificial intelligence', 'Latent profile analysis (LPA) is a categorical latent variable approach that focuses on identifying latent subpopulations within a population based on a certain set of variables. LPA thus assumes that people can be typed with varying degrees of probabilities into categories that have different configural profiles of personal and/or environmental attributes. Within this article, we (a) review the existing applications of LPA within past vocational behavior research; (b) illustrate best practice procedures in a non-technical way of how to use LPA methodology, with an illustrative example of identifying different latent profiles of heavy work investment (i.e., working compulsively, working excessively, and work engagement); and (c) outline future research possibilities in vocational behavior research. By reviewing 46 studies stemming from central journals of the field, we identified seven distinct topics that have already been investigated by LPA (e.g., job and organizational attitudes and behaviors, work motivation, career-related attitudes and orientations, vocational interests). Together with showing descriptive statistics about how LPA has been conducted in past vocational behavior research, we illustrate and derive best-practice recommendations for future LPA research. The review and “how to” guide can be helpful for all researchers interested in conducting LPA studies.', '2026-07-08 07:12:13');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2963784900', 'artificial-intelligence', 'Machine learning in materials informatics: recent applications and prospects', 'Abstract Propelled partly by the Materials Genome Initiative, and partly by the algorithmic developments and the resounding successes of data-driven efforts in other domains, informatics strategies…', '2017', 2017, 1774, 1774, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41524-017-0056-5/MediaObjects/41524_2017_56_Fig1_HTML.jpg', 'https://doi.org/10.1038/s41524-017-0056-5', 'repository', 'article', 'npj Computational Materials', '["Rampi Ramprasad","Rohit Batra","Ghanshyam Pilania","Arun Mannodi‐Kanakkithodi","Chiho Kim"]', 'artificial intelligence', 'Abstract Propelled partly by the Materials Genome Initiative, and partly by the algorithmic developments and the resounding successes of data-driven efforts in other domains, informatics strategies are beginning to take shape within materials science. These approaches lead to surrogate machine learning models that enable rapid predictions based purely on past data rather than by direct experimentation or by computations/simulations in which fundamental equations are explicitly solved. Data-centric informatics methods are becoming useful to determine material properties that are hard to measure or compute using traditional methods—due to the cost, time or effort involved—but for which reliable data either already exists or can be generated for at least a subset of the critical cases. Predictions are typically interpolative, involving fingerprinting a material numerically first, and then following a mapping (established via a learning algorithm) between the fingerprint and the property of interest. Fingerprints, also referred to as “descriptors”, may be of many types and scales, as dictated by the application domain and needs. Predictions may also be extrapolative—extending into new materials spaces—provided prediction uncertainties are properly taken into account. This article attempts to provide an overview of some of the recent successful data-driven “materials informatics” strategies undertaken in the last decade, with particular emphasis on the fingerprint or descriptor choices. The review also identifies some challenges the community is facing and those that should be overcome in the near future.', '2026-07-08 07:12:52');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2464725281', 'artificial-intelligence', 'A general-purpose machine learning framework for predicting properties of inorganic materials', 'Abstract A very active area of materials research is to devise methods that use machine learning to automatically extract predictive models from existing materials data. While prior examples have…', '2016', 2016, 1708, 1708, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnpjcompumats.2016.28/MediaObjects/41524_2016_Article_BFnpjcompumats201628_Fig1_HTML.jpg', 'http://arxiv.org/abs/1606.09551', 'arxiv', 'article', 'npj Computational Materials', '["Logan Ward","Ankit Agrawal","Alok Choudhary","Christopher Wolverton"]', 'artificial intelligence', 'Abstract A very active area of materials research is to devise methods that use machine learning to automatically extract predictive models from existing materials data. While prior examples have demonstrated successful models for some applications, many more applications exist where machine learning can make a strong impact. To enable faster development of machine-learning-based models for such applications, we have created a framework capable of being applied to a broad range of materials data. Our method works by using a chemically diverse list of attributes, which we demonstrate are suitable for describing a wide variety of properties, and a novel method for partitioning the data set into groups of similar materials to boost the predictive accuracy. In this manuscript, we demonstrate how this new method can be used to predict diverse properties of crystalline and amorphous materials, such as band gap energy and glass-forming ability.', '2026-07-08 07:14:02');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3190202966', 'artificial-intelligence', 'Exploring tissue architecture using spatial transcriptomics', 'Exploring tissue architecture using spatial transcriptomics', '2021', 2021, 1709, 1709, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-021-03634-9/MediaObjects/41586_2021_3634_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8475179', 'pmc', 'review', 'Nature', '["Anjali Rao","Dalia Barkley","Gustavo S. França","Itai Yanai"]', 'artificial intelligence', NULL, '2026-07-08 07:14:03');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2765281411', 'artificial-intelligence', 'BBMerge – Accurate paired shotgun read merging via overlap', 'Merging paired-end shotgun reads generated on high-throughput sequencing platforms can substantially improve various subsequent bioinformatics processes, including genome assembly, binning, mapping,…', '2017', 2017, 1700, 1700, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0185056.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5657622', 'pmc', 'article', 'PLoS ONE', '["Brian Bushnell","Jonathan Rood","Esther Singer"]', 'artificial intelligence', 'Merging paired-end shotgun reads generated on high-throughput sequencing platforms can substantially improve various subsequent bioinformatics processes, including genome assembly, binning, mapping, annotation, and clustering for taxonomic analysis. With the inexorable growth of sequence data volume and CPU core counts, the speed and scalability of read-processing tools becomes ever-more important. The accuracy of shotgun read merging is crucial as well, as errors introduced by incorrect merging percolate through to reduce the quality of downstream analysis. Thus, we designed a new tool to maximize accuracy and minimize processing time, allowing the use of read merging on larger datasets, and in analyses highly sensitive to errors. We present BBMerge, a new merging tool for paired-end shotgun sequence data. We benchmark BBMerge by comparison with eight other widely used merging tools, assessing speed, accuracy and scalability. Evaluations of both synthetic and real-world datasets demonstrate that BBMerge produces merged shotgun reads with greater accuracy and at higher speed than any existing merging tool examined. BBMerge also provides the ability to merge non-overlapping shotgun read pairs by using k-mer frequency information to assemble the unsequenced gap between reads, achieving a significantly higher merge rate while maintaining or increasing accuracy.', '2026-07-08 07:14:18');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4225405705', 'artificial-intelligence', 'E(3)-equivariant graph neural networks for data-efficient and accurate interatomic potentials', 'This work presents Neural Equivariant Interatomic Potentials (NequIP), an E(3)-equivariant neural network approach for learning interatomic potentials from ab-initio calculations for molecular…', '2022', 2022, 1698, 1698, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41467-022-29939-5/MediaObjects/41467_2022_29939_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/9068614', 'pmc', 'article', 'Nature Communications', '["Simon Batzner","Albert Musaelian","Lixin Sun","Mario Geiger","Jonathan P. Mailoa","Mordechai Kornbluth","Nicola Molinari","Tess Smidt","Boris Kozinsky"]', 'artificial intelligence', 'This work presents Neural Equivariant Interatomic Potentials (NequIP), an E(3)-equivariant neural network approach for learning interatomic potentials from ab-initio calculations for molecular dynamics simulations. While most contemporary symmetry-aware models use invariant convolutions and only act on scalars, NequIP employs E(3)-equivariant convolutions for interactions of geometric tensors, resulting in a more information-rich and faithful representation of atomic environments. The method achieves state-of-the-art accuracy on a challenging and diverse set of molecules and materials while exhibiting remarkable data efficiency. NequIP outperforms existing models with up to three orders of magnitude fewer training data, challenging the widely held belief that deep neural networks require massive training sets. The high data efficiency of the method allows for the construction of accurate potentials using high-order quantum chemical level of theory as reference and enables high-fidelity molecular dynamics simulations over long time scales.', '2026-07-08 07:14:22');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2151697120', 'artificial-intelligence', 'Why is Tanimoto index an appropriate choice for fingerprint-based similarity calculations?', 'BACKGROUND: Cheminformaticians are equipped with a very rich toolbox when carrying out molecular similarity calculations. A large number of molecular representations exist, and there are several…', '2015', 2015, 1658, 1658, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs13321-021-00504-4/MediaObjects/13321_2021_504_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4456712', 'pmc', 'article', 'Journal of Cheminformatics', '["Dávid Bajusz","Anita Rácz","Károly Héberger"]', 'artificial intelligence', 'BACKGROUND: Cheminformaticians are equipped with a very rich toolbox when carrying out molecular similarity calculations. A large number of molecular representations exist, and there are several methods (similarity and distance metrics) to quantify the similarity of molecular representations. In this work, eight well-known similarity/distance metrics are compared on a large dataset of molecular fingerprints with sum of ranking differences (SRD) and ANOVA analysis. The effects of molecular size, selection methods and data pretreatment methods on the outcome of the comparison are also assessed. RESULTS: A supplier database (https://mcule.com/) was used as the source of compounds for the similarity calculations in this study. A large number of datasets, each consisting of one hundred compounds, were compiled, molecular fingerprints were generated and similarity values between a randomly chosen reference compound and the rest were calculated for each dataset. Similarity metrics were compared based on their ranking of the compounds within one experiment (one dataset) using sum of ranking differences (SRD), while the results of the entire set of experiments were summarized on box and whisker plots. Finally, the effects of various factors (data pretreatment, molecule size, selection method) were evaluated with analysis of variance (ANOVA). CONCLUSIONS: This study complements previous efforts to examine and rank various metrics for molecular similarity calculations. Here, however, an entirely general approach was taken to neglect any a priori knowledge on the compounds involved, as well as any bias introduced by examining only one or a few specific scenarios. The Tanimoto index, Dice index, Cosine coefficient and Soergel distance were identified to be the best (and in some sense equivalent) metrics for similarity calculations, i.e. these metrics could produce the rankings closest to the composite (average) ranking of the eight metrics. The similarity metrics derived from Euclidean and Manhattan distances are not recommended on their own, although their variability and diversity from other similarity metrics might be advantageous in certain cases (e.g. for data fusion). Conclusions are also drawn regarding the effects of molecule size, selection method and data pretreatment on the ranking behavior of the studied metrics. Graphical AbstractA visual summary of the comparison of similarity metrics with sum of ranking differences (SRD).', '2026-07-08 07:15:04');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2903986723', 'artificial-intelligence', 'The rise of motivational information systems: A review of gamification research', '&lt;p&gt;Today, our reality and lives are increasingly game-like, not only because games have become a pervasive part of our lives, but also because activities, systems and services are increasingly…', '2018', 2018, 1659, 1659, 'https://ars.els-cdn.com/content/image/1-s2.0-S0268401217305169-gr1.jpg', 'https://doi.org/10.1016/j.ijinfomgt.2018.10.013', 'repository', 'review', 'International Journal of Information Management', '["Jonna Koivisto","Juho Hamari"]', 'artificial intelligence', '&lt;p&gt;Today, our reality and lives are increasingly game-like, not only because games have become a pervasive part of our lives, but also because activities, systems and services are increasingly gamified. Gamification refers to designing information systems to afford similar experiences and motivations as games do, and consequently, attempting to affect user behavior. In recent years, popularity of gamification has skyrocketed and manifested in growing numbers of gamified applications, as well as a rapidly increasing amount of research. However, this vein of research has mainly advanced without an agenda, theoretical guidance or a clear picture of the field.&lt;br /&gt;&lt;br /&gt;To make the picture more coherent, we provide a comprehensive review of the gamification research (N = 819 studies) and analyze the research models and results in empirical studies on gamification. While the results in general lean towards positive findings about the effectiveness of gamification, the amount of mixed results is remarkable. Furthermore, education, health and crowdsourcing as well as points, badges and leaderboards persist as the most common contexts and ways of implementing gamification. Concurrently, gamification research still lacks coherence in research models, and a consistency in the variables and theoretical foundations. As a final contribution of the review, we provide a comprehensive discussion, consisting of 15 future research trajectories, on future agenda for the growing vein of literature on gamification and gameful systems within the information system science field.&lt;br /&gt;&lt;/p&gt;', '2026-07-08 07:15:06');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2344975321', 'artificial-intelligence', 'Natural speech reveals the semantic maps that tile human cerebral cortex', 'Natural speech reveals the semantic maps that tile human cerebral cortex', '2016', 2016, 1634, 1634, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature17637/MediaObjects/41586_2016_Article_BFnature17637_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4852309', 'pmc', 'article', 'Nature', '["Alexander G. Huth","Wendy A. de Heer","Thomas L. Griffiths","Frédéric E. Theunissen","Jack L. Gallant"]', 'artificial intelligence', NULL, '2026-07-08 07:15:33');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2995225687', 'artificial-intelligence', 'MIMIC-CXR, a de-identified publicly available database of chest radiographs with free-text reports', 'Chest radiography is an extremely powerful imaging modality, allowing for a detailed inspection of a patient''s chest, but requires specialized training for proper interpretation. With the advent of…', '2019', 2019, 1631, 1631, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41597-019-0322-0/MediaObjects/41597_2019_322_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6908718', 'pmc', 'article', 'Scientific Data', '["Alistair E. W. Johnson","Tom Pollard","Seth J. Berkowitz","Nathaniel R. Greenbaum","Matthew P. Lungren","Chih-Ying Deng","Roger G. Mark","Steven Horng"]', 'artificial intelligence', 'Chest radiography is an extremely powerful imaging modality, allowing for a detailed inspection of a patient''s chest, but requires specialized training for proper interpretation. With the advent of high performance general purpose computer vision algorithms, the accurate automated analysis of chest radiographs is becoming increasingly of interest to researchers. Here we describe MIMIC-CXR, a large dataset of 227,835 imaging studies for 65,379 patients presenting to the Beth Israel Deaconess Medical Center Emergency Department between 2011-2016. Each imaging study can contain one or more images, usually a frontal view and a lateral view. A total of 377,110 images are available in the dataset. Studies are made available with a semi-structured free-text radiology report that describes the radiological findings of the images, written by a practicing radiologist contemporaneously during routine clinical care. All images and reports have been de-identified to protect patient privacy. The dataset is made freely available to facilitate and encourage a wide range of research in computer vision, natural language processing, and clinical data mining.', '2026-07-08 07:15:33');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2177180777', 'artificial-intelligence', 'Genome-wide patterns of selection in 230 ancient Eurasians', 'Genome-wide patterns of selection in 230 ancient Eurasians', '2015', 2015, 1630, 1630, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature16152/MediaObjects/41586_2015_Article_BFnature16152_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4918750', 'pmc', 'article', 'Nature', '["Iain Mathieson","Iosif Lazaridis","Nadin Rohland","Swapan Mallick","Nick Patterson","Songül Alpaslan Roodenberg","Éadaoin Harney","Kristin Stewardson","Daniel Fernandes","Mario Novak","Kendra Sirak","Cristina Gamba","Eppie R. Jones","Bastien Llamas","Stanislav Dryomov","Joseph K. Pickrell","Juan Luís Arsuaga","José Marı́a Bermúdez de Castro","Eudald Carbonell","Fokke Gerritsen","Aleksandr Khokhlov","Pavel Kuznetsov","Marina Lozano","Harald Meller","Oleg Dmitrievich Mochalov","Vyacheslav Moiseyev","Manuel Ángel Rojo Guerra","Jacob Roodenberg","Josep María Vergès","Johannes Krause","Alan Cooper","Kurt W. Alt","Dorcas Brown","David W. Anthony","Carles Lalueza‐Fox","Wolfgang Haak","Ron Pinhasi","David Reich"]', 'artificial intelligence', NULL, '2026-07-08 07:15:35');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2238851414', 'ml-for-science', 'A comprehensive 1000 Genomes–based genome-wide association meta-analysis of coronary artery disease', 'A comprehensive 1000 Genomes–based genome-wide association meta-analysis of coronary artery disease', '2015', 2015, 2699, 2699, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fng.3396/MediaObjects/41588_2015_Article_BFng3396_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4589895', 'pmc', 'review', 'Nature Genetics', '["Alexandre F Stewart","Majid Nikpay","Ruth McPherson","Christopher Grace","Shapour Jalilzadeh","Hugh Watkins","Anuj Goel","Martin Farrall","Theodosios Kyriakou","Christopher Grace","Natalie R van Zuydam","Shapour Jalilzadeh","Hugh Watkins","Cecilia M Lindgren","Erik Ingelsson","Anuj Goel","Martin Farrall","Andrew P Morris","Theodosios Kyriakou","Richa Saxena","Andrew Bjonnes","Tõnu Esko","Hong-Hee Won","Cecilia M Lindgren","Sekar Kathiresan","Hong-Hee Won","Sekar Kathiresan","Hong-Hee Won","Sekar Kathiresan","Andrew Bjonnes","Richa Saxena","Hong-Hee Won","Sekar Kathiresan","Thomas R Webb","Leanne M Hall","Christopher P Nelson","Nilesh J Samani","Christina Willenborg","Jeanette Erdmann","Christina Willenborg","Jeanette Erdmann","Inke R König","Kathleen E Stirrups","Panos Deloukas","Stavroula Kanoni","Wei Zhao","Danish Saleheen","Maria Samuel","Philippe Frossard","Danish Saleheen","Asif Rasheed","Nilesh J Samani","Thomas R Webb","Alison H Goodall","Christopher P Nelson","King Wai Lau","Rory Collins","Robert Clarke","Jemma C Hopewell","Lingyao Zeng","Thorsten Kessler","Heribert Schunkert","Christian Hengstenberg","Christian Hengstenberg","Annette Peters","Thomas Meitinger","Lingyao Zeng","Christian Gieger","Heribert Schunkert","Abbas Dehghan","Albert Hofman","Andre Uitterlinden","Oscar H Franco","Paul S de Vries","Evelin Mihailov","Andres Metspalu","Markus Perola","Natalia Pervjakova","Tõnu Esko","Maris Alver","Andres Metspalu","Maris Alver","Sebastian M Armasu","Mariza de Andrade","Kirsi Auro","Natalia Pervjakova","Markus Perola","Markus Perola","Emmi Tikkanen","Natalia Pervjakova","Kirsi Auro","Samuli Ripatti","Kirsi Auro","Natalia Pervjakova","Markus Perola","Julie E Buring","Daniel I Chasman","Paul M Ridker","Lynda M Rose","Daniel I Chasman"]', 'ml for science', NULL, '2026-07-08 07:18:41');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2772803673', 'ml-for-science', 'When and how should multiple imputation be used for handling missing data in randomised clinical trials – a practical guide with flowcharts', 'BACKGROUND: Missing data may seriously compromise inferences from randomised clinical trials, especially if missing data are not handled appropriately. The potential bias due to missing data depends…', '2017', 2017, 2788, 2788, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs12874-024-02310-6/MediaObjects/12874_2024_2310_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5717805', 'pmc', 'article', 'BMC Medical Research Methodology', '["Janus Christian Jakobsen","Christian Gluud","Jørn Wetterslev","Per Winkel"]', 'ml for science', 'BACKGROUND: Missing data may seriously compromise inferences from randomised clinical trials, especially if missing data are not handled appropriately. The potential bias due to missing data depends on the mechanism causing the data to be missing, and the analytical methods applied to amend the missingness. Therefore, the analysis of trial data with missing values requires careful planning and attention. METHODS: The authors had several meetings and discussions considering optimal ways of handling missing data to minimise the bias potential. We also searched PubMed (key words: missing data; randomi*; statistical analysis) and reference lists of known studies for papers (theoretical papers; empirical studies; simulation studies; etc.) on how to deal with missing data when analysing randomised clinical trials. RESULTS: Handling missing data is an important, yet difficult and complex task when analysing results of randomised clinical trials. We consider how to optimise the handling of missing data during the planning stage of a randomised clinical trial and recommend analytical approaches which may prevent bias caused by unavoidable missing data. We consider the strengths and limitations of using of best-worst and worst-best sensitivity analyses, multiple imputation, and full information maximum likelihood. We also present practical flowcharts on how to deal with missing data and an overview of the steps that always need to be considered during the analysis stage of a trial. CONCLUSIONS: We present a practical guide and flowcharts describing when and how multiple imputation should be used to handle missing data in randomised clinical.', '2026-07-08 07:18:41');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3198377975', 'ml-for-science', 'Learning to Prompt for Vision-Language Models', 'Learning to Prompt for Vision-Language Models', '2022', 2022, 2719, 2719, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1007%2Fs11263-022-01653-1/MediaObjects/11263_2022_1653_Fig1_HTML.png', 'http://arxiv.org/abs/2109.01134', 'arxiv', 'article', 'International Journal of Computer Vision', '["Kaiyang Zhou","Jingkang Yang","Chen Change Loy","Ziwei Liu"]', 'ml for science', NULL, '2026-07-08 07:18:42');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2264585211', 'ml-for-science', 'Integrative approaches for large-scale transcriptome-wide association studies', 'Integrative approaches for large-scale transcriptome-wide association studies', '2016', 2016, 2744, 2744, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fng.3506/MediaObjects/41588_2016_Article_BFng3506_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4767558', 'pmc', 'article', 'Nature Genetics', '["Alexander Gusev","Arthur Ko","Huwenbo Shi","Gaurav Bhatia","Wonil Chung","Brenda W.J.H. Penninx","Rick Jansen","Eco J. C. de Geus","Dorret I. Boomsma","Fred A. Wright","Patrick F. Sullivan","Elina Nikkola","Marcus Alvarez","Mete Civelek","Aldons J. Lusis","Terho Lehtimäki","Emma Raitoharju","Mika Kähönen","Ilkka Seppälä","Olli T. Raitakari","Johanna Kuusisto","Markku Laakso","Alkes L. Price","Päivi Pajukanta","Bogdan Paşaniuc"]', 'ml for science', NULL, '2026-07-08 07:18:42');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2988916019', 'ml-for-science', 'Deep Learning for Generic Object Detection: A Survey', 'Abstract Object detection, one of the most fundamental and challenging problems in computer vision, seeks to locate object instances from a large number of predefined categories in natural images.…', '2019', 2019, 2779, 2779, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1007%2Fs11263-019-01247-4/MediaObjects/11263_2019_1247_Fig1_HTML.png', 'https://doi.org/10.1007/s11263-019-01247-4', 'repository', 'article', 'International Journal of Computer Vision', '["Li Liu","Wanli Ouyang","Xiaogang Wang","Paul Fieguth","Jie Chen","Xinwang Liu","Matti Pietikäinen"]', 'ml for science', 'Abstract Object detection, one of the most fundamental and challenging problems in computer vision, seeks to locate object instances from a large number of predefined categories in natural images. Deep learning techniques have emerged as a powerful strategy for learning feature representations directly from data and have led to remarkable breakthroughs in the field of generic object detection. Given this period of rapid evolution, the goal of this paper is to provide a comprehensive survey of the recent achievements in this field brought about by deep learning techniques. More than 300 research contributions are included in this survey, covering many aspects of generic object detection: detection frameworks, object feature representation, object proposal generation, context modeling, training strategies, and evaluation metrics. We finish the survey by identifying promising directions for future research.', '2026-07-08 07:18:43');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2984353870', 'ml-for-science', 'A survey on semi-supervised learning', 'Abstract Semi-supervised learning is the branch of machine learning concerned with using labelled as well as unlabelled data to perform certain learning tasks. Conceptually situated between…', '2019', 2019, 2569, 2569, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1007%2Fs10994-019-05855-6/MediaObjects/10994_2019_5855_Fig1_HTML.png', 'https://doi.org/10.1007/s10994-019-05855-6', 'repository', 'article', 'Machine Learning', '["Jesper E. van Engelen","Holger H. Hoos"]', 'ml for science', 'Abstract Semi-supervised learning is the branch of machine learning concerned with using labelled as well as unlabelled data to perform certain learning tasks. Conceptually situated between supervised and unsupervised learning, it permits harnessing the large amounts of unlabelled data available in many use cases in combination with typically smaller sets of labelled data. In recent years, research in this area has followed the general trends observed in machine learning, with much attention directed at neural network-based models and generative learning. The literature on the topic has also expanded in volume and scope, now encompassing a broad spectrum of theory, algorithms and applications. However, no recent surveys exist to collect and organize this knowledge, impeding the ability of researchers and engineers alike to utilize it. Filling this void, we present an up-to-date overview of semi-supervised learning methods, covering earlier work as well as more recent advances. We focus primarily on semi-supervised classification, where the large majority of semi-supervised learning research takes place. Our survey aims to provide researchers and practitioners new to the field as well as more advanced readers with a solid understanding of the main approaches and algorithms developed over the past two decades, with an emphasis on the most prominent and currently relevant work. Furthermore, we propose a new taxonomy of semi-supervised classification algorithms, which sheds light on the different conceptual and methodological approaches for incorporating unlabelled data into the training process. Lastly, we show how the fundamental assumptions underlying most semi-supervised learning algorithms are closely connected to each other, and how they relate to the well-known semi-supervised clustering assumption.', '2026-07-08 07:18:57');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2987201163', 'ml-for-science', 'A comparative analysis of gradient boosting algorithms', 'A comparative analysis of gradient boosting algorithms', '2020', 2020, 2512, 2512, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1007%2Fs10462-020-09896-5/MediaObjects/10462_2020_9896_Fig1_HTML.png', 'http://arxiv.org/abs/1911.01914', 'arxiv', 'article', 'Artificial Intelligence Review', '["Candice Bentéjac","Anna Csörgő","Gonzalo Martínez-Muñoz"]', 'ml for science', NULL, '2026-07-08 07:19:13');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3153990350', 'ml-for-science', 'Machine learning and deep learning', 'Abstract Today, intelligent systems that offer artificial intelligence capabilities often rely on machine learning. Machine learning describes the capacity of systems to learn from problem-specific…', '2021', 2021, 2502, 2502, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1007%2Fs12525-021-00475-2/MediaObjects/12525_2021_475_Fig1_HTML.png', 'http://arxiv.org/abs/2104.05314', 'arxiv', 'article', 'Electronic Markets', '["Christian Janiesch","Patrick Zschech","Kai Heinrich"]', 'ml for science', 'Abstract Today, intelligent systems that offer artificial intelligence capabilities often rely on machine learning. Machine learning describes the capacity of systems to learn from problem-specific training data to automate the process of analytical model building and solve associated tasks. Deep learning is a machine learning concept based on artificial neural networks. For many applications, deep learning models outperform shallow machine learning models and traditional data analysis approaches. In this article, we summarize the fundamentals of machine learning and deep learning to generate a broader understanding of the methodical underpinning of current intelligent systems. In particular, we provide a conceptual distinction between relevant terms and concepts, explain the process of automated analytical model building through machine learning and deep learning, and discuss the challenges that arise when implementing such intelligent systems in the field of electronic markets and networked business. These naturally go beyond technological aspects and highlight issues in human-machine interaction and artificial intelligence servitization.', '2026-07-08 07:19:14');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2784499877', 'ml-for-science', 'Scalable and accurate deep learning with electronic health records', 'Predictive modeling with electronic health record (EHR) data is anticipated to drive personalized medicine and improve healthcare quality. Constructing predictive statistical models typically…', '2018', 2018, 2429, 2429, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41746-018-0029-1/MediaObjects/41746_2018_29_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6550175', 'pmc', 'article', 'npj Digital Medicine', '["Alvin Rajkomar","Eyal Oren","Kai Chen","Andrew M. Dai","Nissan Hajaj","Michaela Hardt","Peter J. Liu","Xiaobing Liu","Jake Marcus","Mimi Sun","Patrik Sundberg","Hector Yee","Kun Zhang","Yi Zhang","Gerardo Flores","Gavin E. Duggan","Jamie Irvine","Quoc Le","Kurt Litsch","Alexander Mossin","Justin Tansuwan","De Wang","James Wexler","Jimbo Wilson","Dana Ludwig","Samuel L. Volchenboum","Katherine Chou","Michael Pearson","Srinivasan Madabushi","Nigam H. Shah","Atul J. Butte","Michael D. Howell","Claire Cui","Greg S. Corrado","Jeffrey Dean"]', 'ml for science', 'Predictive modeling with electronic health record (EHR) data is anticipated to drive personalized medicine and improve healthcare quality. Constructing predictive statistical models typically requires extraction of curated predictor variables from normalized EHR data, a labor-intensive process that discards the vast majority of information in each patient''s record. We propose a representation of patients'' entire raw EHR records based on the Fast Healthcare Interoperability Resources (FHIR) format. We demonstrate that deep learning methods using this representation are capable of accurately predicting multiple medical events from multiple centers without site-specific data harmonization. We validated our approach using de-identified EHR data from two US academic medical centers with 216,221 adult patients hospitalized for at least 24 h. In the sequential format we propose, this volume of EHR data unrolled into a total of 46,864,534,945 data points, including clinical notes. Deep learning models achieved high accuracy for tasks such as predicting: in-hospital mortality (area under the receiver operator curve [AUROC] across sites 0.93-0.94), 30-day unplanned readmission (AUROC 0.75-0.76), prolonged length of stay (AUROC 0.85-0.86), and all of a patient''s final discharge diagnoses (frequency-weighted AUROC 0.90). These models outperformed traditional, clinically-used predictive models in all cases. We believe that this approach can be used to create accurate and scalable predictions for a variety of clinical scenarios. In a case study of a particular prediction, we demonstrate that neural networks can be used to identify relevant information from the patient''s chart.', '2026-07-08 07:19:34');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2968923792', 'ml-for-science', 'Recent advances and applications of machine learning in solid-state materials science', 'Abstract One of the most exciting tools that have entered the material science toolbox in recent years is machine learning. This collection of statistical methods has already proved to be capable of…', '2019', 2019, 2415, 2415, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41524-019-0221-0/MediaObjects/41524_2019_221_Fig1_HTML.png', 'https://doi.org/10.1038/s41524-019-0221-0', 'repository', 'article', 'npj Computational Materials', '["Jonathan Schmidt","Mário R. G. Marques","Silvana Botti","Miguel A. L. Marques"]', 'ml for science', 'Abstract One of the most exciting tools that have entered the material science toolbox in recent years is machine learning. This collection of statistical methods has already proved to be capable of considerably speeding up both fundamental and applied research. At present, we are witnessing an explosion of works that develop and apply machine learning to solid-state systems. We provide a comprehensive overview and analysis of the most recent research in this topic. As a starting point, we introduce machine learning principles, algorithms, descriptors, and databases in materials science. We continue with the description of different machine learning approaches for the discovery of stable materials and the prediction of their crystal structure. Then we discuss research in numerous quantitative structure–property relationships and various approaches for the replacement of first-principle methods by machine learning. We review how active learning and surrogate-based optimization can be applied to improve the rational design process and related examples of applications. Two major questions are always the interpretability of and the physical understanding gained from machine learning models. We consider therefore the different facets of interpretability and their importance in materials science. Finally, we propose solutions and future research paths for various challenges in computational materials science.', '2026-07-08 07:19:37');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1505191356', 'ml-for-science', 'Machine learning applications in genetics and genomics', 'Machine learning applications in genetics and genomics', '2015', 2015, 2061, 2061, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnrg3920/MediaObjects/41576_2015_Article_BFnrg3920_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5204302', 'pmc', 'review', 'Nature Reviews Genetics', '["Maxwell W. Libbrecht","William Stafford Noble"]', 'ml for science', NULL, '2026-07-08 07:20:32');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3200707343', 'ml-for-science', 'A guide to machine learning for biologists', 'A guide to machine learning for biologists', '2021', 2021, 2086, 2086, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41580-021-00407-0/MediaObjects/41580_2021_407_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/34518686', 'repository', 'review', 'Nature Reviews Molecular Cell Biology', '["Joe G. Greener","Shaun M. Kandathil","Lewis Moffat","David T. Jones"]', 'ml for science', NULL, '2026-07-08 07:20:33');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2622458265', 'ml-for-science', 'Re-examining the Unified Theory of Acceptance and Use of Technology (UTAUT): Towards a Revised Theoretical Model', 'Based on a critical review of the Unified Theory of Acceptance and Use of Technology (UTAUT), this study first formalized an alternative theoretical model for explaining the acceptance and use of…', '2017', 2017, 2016, 2016, 'https://media.springernature.com/lw685/springer-static/image/art%3A10.1007%2Fs10796-017-9774-y/MediaObjects/10796_2017_9774_Fig1_HTML.gif', 'https://doi.org/10.1007/s10796-017-9774-y', 'repository', 'article', 'Information Systems Frontiers', '["Yogesh K. Dwivedi","Nripendra P. Rana","Anand Jeyaraj","Marc Clement","Michael D. Williams"]', 'ml for science', 'Based on a critical review of the Unified Theory of Acceptance and Use of Technology (UTAUT), this study first formalized an alternative theoretical model for explaining the acceptance and use of information system (IS) and information technology (IT) innovations. The revised theoretical model was then empirically examined using a combination of meta-analysis and structural equation modelling (MASEM) techniques. The meta-analysis was based on 1600 observations on 21 relationships coded from 162 prior studies on IS/IT acceptance and use. The SEM analysis showed that attitude: was central to behavioural intentions and usage behaviours, partially mediated the effects of exogenous constructs on behavioural intentions, and had a direct influence on usage behaviours. A number of implications for theory and practice are derived based on the findings.', '2026-07-08 07:20:48');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4220838968', 'ml-for-science', 'Reproducible brain-wide association studies require thousands of individuals', 'Abstract Magnetic resonance imaging (MRI) has transformed our understanding of the human brain through well-replicated mapping of abilities to specific structures (for example, lesion studies) and…', '2022', 2022, 2033, 2033, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-022-04492-9/MediaObjects/41586_2022_4492_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8991999', 'pmc', 'article', 'Nature', '["Scott Marek","Brenden Tervo‐Clemmens","Finnegan J. Calabro","David F. Montez","Benjamin P. Kay","Alexander S. Hatoum","Meghan Rose Donohue","William Foran","Ryland L. Miller","Timothy Hendrickson","Stephen M. Malone","Sridhar Kandala","Eric Feczko","Óscar Miranda-Domínguez","Alice M. Graham","Eric Earl","Anders Perrone","Michaela Cordova","Olivia Doyle","Lucille A. Moore","Greg Conan","Johnny Uriarte","Kathy Snider","Benjamin J. Lynch","James C. Wilgenbusch","Thomas Pengo","Angela Tam","Jianzhong Chen","Dillan J. Newbold","Annie Zheng","Nicole A. Seider","Andrew N. Van","Athanasia Metoki","Roselyne J. Chauvin","Timothy O. Laumann","Deanna J. Greene","Steven E. Petersen","Hugh Garavan","Wesley K. Thompson","Thomas E. Nichols","B.T. Thomas Yeo","Deanna M. Barch","Beatríz Luna","Damien A. Fair","Nico U.F. Dosenbach"]', 'ml for science', 'Abstract Magnetic resonance imaging (MRI) has transformed our understanding of the human brain through well-replicated mapping of abilities to specific structures (for example, lesion studies) and functions 1–3 (for example, task functional MRI (fMRI)). Mental health research and care have yet to realize similar advances from MRI. A primary challenge has been replicating associations between inter-individual differences in brain structure or function and complex cognitive or mental health phenotypes (brain-wide association studies (BWAS)). Such BWAS have typically relied on sample sizes appropriate for classical brain mapping 4 (the median neuroimaging study sample size is about 25), but potentially too small for capturing reproducible brain–behavioural phenotype associations 5,6. Here we used three of the largest neuroimaging datasets currently available—with a total sample size of around 50,000 individuals—to quantify BWAS effect sizes and reproducibility as a function of sample size. BWAS associations were smaller than previously thought, resulting in statistically underpowered studies, inflated effect sizes and replication failures at typical sample sizes. As sample sizes grew into the thousands, replication rates began to improve and effect size inflation decreased. More robust BWAS effects were detected for functional MRI (versus structural), cognitive tests (versus mental health questionnaires) and multivariate methods (versus univariate). Smaller than expected brain–phenotype associations and variability across population subsamples can explain widespread BWAS replication failures. In contrast to non-BWAS approaches with larger effects (for example, lesions, interventions and within-person), BWAS reproducibility requires samples with thousands of individuals.', '2026-07-08 07:20:48');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2529241974', 'ml-for-science', 'Reference-based phasing using the Haplotype Reference Consortium panel', 'Reference-based phasing using the Haplotype Reference Consortium panel', '2016', 2016, 2018, 2018, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fng.3679/MediaObjects/41588_2016_Article_BFng3679_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5096458', 'pmc', 'article', 'Nature Genetics', '["Po‐Ru Loh","Petr Danecek","Pier Francesco Palamara","Christian Fuchsberger","Yakir Reshef","Hilary K. Finucane","Sebastian Schoenherr","Lukas Forer","Shane McCarthy","Gonçalo R. Abecasis","Richard Durbin","Alkes L. Price"]', 'ml for science', NULL, '2026-07-08 07:20:49');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2752747624', 'ml-for-science', 'Prediction of cardiovascular risk factors from retinal fundus photographs via deep learning', 'Prediction of cardiovascular risk factors from retinal fundus photographs via deep learning', '2018', 2018, 1842, 1842, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41551-018-0195-0/MediaObjects/41551_2018_195_Fig1_HTML.jpg', 'http://arxiv.org/abs/1708.09843', 'arxiv', 'article', 'Nature Biomedical Engineering', '["Ryan Poplin","Avinash V. Varadarajan","Katy Blumer","Yun Liu","Michael V. McConnell","Greg S. Corrado","Lily Peng","Dale R. Webster"]', 'ml for science', NULL, '2026-07-08 07:21:39');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3016970897', 'ml-for-science', 'Shortcut learning in deep neural networks', 'Shortcut learning in deep neural networks', '2020', 2020, 1835, 1835, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs42256-020-00257-z/MediaObjects/42256_2020_257_Fig1_HTML.png', 'http://arxiv.org/abs/2004.07780', 'arxiv', 'article', 'Nature Machine Intelligence', '["Robert Geirhos","Jörn-Henrik Jacobsen","Claudio Michaelis","Richard S. Zemel","Wieland Brendel","Matthias Bethge","Felix A. Wichmann"]', 'ml for science', NULL, '2026-07-08 07:21:41');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2800663167', 'ml-for-science', 'Profiting from innovation in the digital economy: Enabling technologies, standards, and licensing models in the wireless world', 'Profiting from innovation in the digital economy: Enabling technologies, standards, and licensing models in the wireless world', '2018', 2018, 1694, 1694, 'https://ars.els-cdn.com/content/image/1-s2.0-S0048733318300763-gr1.jpg', 'https://doi.org/10.1016/j.respol.2017.01.015', 'repository', 'article', 'Research Policy', '["David J. Teece"]', 'ml for science', NULL, '2026-07-08 07:23:04');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2945049087', 'ml-for-science', 'How to perform and report an impactful analysis using partial least squares: Guidelines for confirmatory and explanatory IS research', 'et la diffusion de documents scientifiques de niveau recherche, publis ou non, manant des tablissements d''enseignement et de recherche franais ou trangers, des laboratoires publics ou privs.', '2019', 2019, 1697, 1697, 'https://ars.els-cdn.com/content/image/1-s2.0-S0378720617309394-gr1.jpg', 'https://rennes-sb.hal.science/hal-02567449', 'repository', 'article', 'Information & Management', '["Jose Benitez","Jörg Henseler","Ana Castillo","Florian Schuberth"]', 'ml for science', 'et la diffusion de documents scientifiques de niveau recherche, publis ou non, manant des tablissements d''enseignement et de recherche franais ou trangers, des laboratoires publics ou privs.', '2026-07-08 07:23:05');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1924661502', 'ml-for-science', 'The Mistreatment of Women during Childbirth in Health Facilities Globally: A Mixed-Methods Systematic Review', 'BACKGROUND: Despite growing recognition of neglectful, abusive, and disrespectful treatment of women during childbirth in health facilities, there is no consensus at a global level on how these…', '2015', 2015, 1659, 1659, 'https://journals.plos.org/plosmedicine/article/figure/image?size=large&id=10.1371/journal.pmed.1001847.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4488322', 'pmc', 'review', 'PLoS Medicine', '["Meghan A. Bohren","Joshua P. Vogel","Erin Hunter","Olha Lutsiv","Suprita K. Makh","João Paulo Souza","Carolina Aguiar","Fernando Saraiva Coneglian","Alex Luíz Araújo Diniz","Özge Tunçalp","Dena Javadi","Olufemi T. Oladapo","Rajat Khosla","Michelle J. Hindin","A. Metin Gülmezog̈lu"]', 'ml for science', 'BACKGROUND: Despite growing recognition of neglectful, abusive, and disrespectful treatment of women during childbirth in health facilities, there is no consensus at a global level on how these occurrences are defined and measured. This mixed-methods systematic review aims to synthesize qualitative and quantitative evidence on the mistreatment of women during childbirth in health facilities to inform the development of an evidence-based typology of the phenomenon. METHODS AND FINDINGS: We searched PubMed, CINAHL, and Embase databases and grey literature using a predetermined search strategy to identify qualitative, quantitative, and mixed-methods studies on the mistreatment of women during childbirth across all geographical and income-level settings. We used a thematic synthesis approach to synthesize the qualitative evidence and assessed the confidence in the qualitative review findings using the CERQual approach. In total, 65 studies were included from 34 countries. Qualitative findings were organized under seven domains: (1) physical abuse, (2) sexual abuse, (3) verbal abuse, (4) stigma and discrimination, (5) failure to meet professional standards of care, (6) poor rapport between women and providers, and (7) health system conditions and constraints. Due to high heterogeneity of the quantitative data, we were unable to conduct a meta-analysis; instead, we present descriptions of study characteristics, outcome measures, and results. Additional themes identified in the quantitative studies are integrated into the typology. CONCLUSIONS: This systematic review presents a comprehensive, evidence-based typology of the mistreatment of women during childbirth in health facilities, and demonstrates that mistreatment can occur at the level of interaction between the woman and provider, as well as through systemic failures at the health facility and health system levels. We propose this typology be adopted to describe the phenomenon and be used to develop measurement tools and inform future research, programs, and interventions.', '2026-07-08 07:23:13');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2947263797', 'ml-for-science', 'Deep Learning Techniques for Medical Image Segmentation: Achievements and Challenges', 'Deep learning-based image segmentation is by now firmly established as a robust tool in image segmentation. It has been widely used to separate homogeneous areas as the first and critical component…', '2019', 2019, 1613, 1613, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1007%2Fs10278-019-00227-x/MediaObjects/10278_2019_227_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6646484', 'pmc', 'review', 'Journal of Digital Imaging', '["Mohammad Hesam Hesamian","Wenjing Jia","Xiangjian He","Paul Kennedy"]', 'ml for science', 'Deep learning-based image segmentation is by now firmly established as a robust tool in image segmentation. It has been widely used to separate homogeneous areas as the first and critical component of diagnosis and treatment pipeline. In this article, we present a critical appraisal of popular methods that have employed deep-learning techniques for medical image segmentation. Moreover, we summarize the most common challenges incurred and suggest possible solutions.', '2026-07-08 07:23:36');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2995098893', 'ml-for-science', 'Comparing different supervised machine learning algorithms for disease prediction', 'BACKGROUND: Supervised machine learning algorithms have been a dominant method in the data mining field. Disease prediction using health data has recently shown a potential application area for these…', '2019', 2019, 1633, 1633, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs12911-019-1004-8/MediaObjects/12911_2019_1004_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6925840', 'pmc', 'article', 'BMC Medical Informatics and Decision Making', '["Shahadat Uddin","Arif Khan","Md Ekramul Hossain","Mohammad Ali Moni"]', 'ml for science', 'BACKGROUND: Supervised machine learning algorithms have been a dominant method in the data mining field. Disease prediction using health data has recently shown a potential application area for these methods. This study ai7ms to identify the key trends among different types of supervised machine learning algorithms, and their performance and usage for disease risk prediction. METHODS: In this study, extensive research efforts were made to identify those studies that applied more than one supervised machine learning algorithm on single disease prediction. Two databases (i.e., Scopus and PubMed) were searched for different types of search items. Thus, we selected 48 articles in total for the comparison among variants supervised machine learning algorithms for disease prediction. RESULTS: We found that the Support Vector Machine (SVM) algorithm is applied most frequently (in 29 studies) followed by the Naïve Bayes algorithm (in 23 studies). However, the Random Forest (RF) algorithm showed superior accuracy comparatively. Of the 17 studies where it was applied, RF showed the highest accuracy in 9 of them, i.e., 53%. This was followed by SVM which topped in 41% of the studies it was considered. CONCLUSION: This study provides a wide overview of the relative performance of different variants of supervised machine learning algorithms for disease prediction. This important information of relative performance can be used to aid researchers in the selection of an appropriate supervised machine learning algorithm for their studies.', '2026-07-08 07:23:37');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4365143687', 'ml-for-science', 'Foundation models for generalist medical artificial intelligence', 'The exceptionally rapid development of highly flexible, reusable artificial intelligence (AI) models is likely to usher in newfound capabilities in medicine. We propose a new paradigm for medical AI,…', '2023', 2023, 1598, 1598, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-023-05881-4/MediaObjects/41586_2023_5881_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/37045921', 'repository', 'review', 'Nature', '["Michael Moor","Oishi Banerjee","Zahra Shakeri Hossein Abad","Harlan M. Krumholz","Jure Leskovec","Eric J. Topol","Pranav Rajpurkar"]', 'ml for science', 'The exceptionally rapid development of highly flexible, reusable artificial intelligence (AI) models is likely to usher in newfound capabilities in medicine. We propose a new paradigm for medical AI, which we refer to as generalist medical AI (GMAI). GMAI models will be capable of carrying out a diverse set of tasks using very little or no task-specific labelled data. Built through self-supervision on large, diverse datasets, GMAI will flexibly interpret different combinations of medical modalities, including data from imaging, electronic health records, laboratory results, genomics, graphs or medical text. Models will in turn produce expressive outputs such as free-text explanations, spoken recommendations or image annotations that demonstrate advanced medical reasoning abilities. Here we identify a set of high-impact potential applications for GMAI and lay out specific technical capabilities and training datasets necessary to enable them. We expect that GMAI-enabled applications will challenge current strategies for regulating and validating AI devices for medicine and will shift practices associated with the collection of large medical datasets. This review discusses generalist medical artificial intelligence, identifying potential applications and setting out specific technical capabilities and training datasets necessary to enable them, as well as highlighting challenges to its implementation.', '2026-07-08 07:23:52');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2950100524', 'ml-for-science', 'Using DeepLabCut for 3D markerless pose estimation across species and behaviors', 'Using DeepLabCut for 3D markerless pose estimation across species and behaviors', '2019', 2019, 1590, 1590, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41596-019-0176-0/MediaObjects/41596_2019_176_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/31227823', 'repository', 'article', 'Nature Protocols', '["Tanmay Nath","Alexander Mathis","An Chi Chen","Amir Patel","Matthias Bethge","Mackenzie Weygandt Mathis"]', 'ml for science', NULL, '2026-07-08 07:23:54');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2792919287', 'ml-for-science', 'Statistics versus machine learning', 'Statistics versus machine learning', '2018', 2018, 1498, 1498, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnmeth.4642/MediaObjects/41592_2018_Article_BFnmeth4642_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6082636', 'pmc', 'article', 'Nature Methods', '["Danilo Bzdok","Naomi Altman","Martin Krzywinski"]', 'ml for science', NULL, '2026-07-08 07:24:40');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2988596226', 'ml-for-science', 'Genetic strategies for improving crop yields', 'Genetic strategies for improving crop yields', '2019', 2019, 1516, 1516, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-019-1679-0/MediaObjects/41586_2019_1679_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7024682', 'pmc', 'review', 'Nature', '["Julia Bailey‐Serres","Jane E. Parker","Elizabeth A. Ainsworth","Giles Oldroyd","Julian I. Schroeder"]', 'ml for science', NULL, '2026-07-08 07:24:42');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2794778778', 'ml-for-science', 'Statistical and Machine Learning forecasting methods: Concerns and ways forward', 'Machine Learning (ML) methods have been proposed in the academic literature as alternatives to statistical ones for time series forecasting. Yet, scant evidence is available about their relative…', '2018', 2018, 1401, 1401, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0194889.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5870978', 'pmc', 'article', 'PLoS ONE', '["Spyros Makridakis","Evangelos Spiliotis","Vassilios Assimakopoulos"]', 'ml for science', 'Machine Learning (ML) methods have been proposed in the academic literature as alternatives to statistical ones for time series forecasting. Yet, scant evidence is available about their relative performance in terms of accuracy and computational requirements. The purpose of this paper is to evaluate such performance across multiple forecasting horizons using a large subset of 1045 monthly time series used in the M3 Competition. After comparing the post-sample accuracy of popular ML methods with that of eight traditional statistical ones, we found that the former are dominated across both accuracy measures used and for all forecasting horizons examined. Moreover, we observed that their computational requirements are considerably greater than those of statistical methods. The paper discusses the results, explains why the accuracy of ML models is below that of statistical ones and proposes some possible ways forward. The empirical results found in our research stress the need for objective and unbiased ways to test the performance of forecasting methods that can be achieved through sizable and open competitions allowing meaningful comparisons and definite conclusions.', '2026-07-08 07:25:39');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2967663220', 'ml-for-science', 'Hyperparameter Optimization for Machine Learning Models Based on Bayesian Optimization', 'Hyperparameter Optimization for Machine Learning Models Based on Bayesian Optimization', '2019', 2019, 1417, 1417, 'https://ars.els-cdn.com/content/image/1-s2.0-S1674862X19300047-fx1.jpg', 'https://hal.science/hal-05507953', 'repository', 'article', 'HAL (Le Centre pour la Communication Scientifique Directe)', '["Jia Wu","Xiu Yun Chen","Hao Zhang","Li Dong Xiong","Hang Lei","Sihao Deng"]', 'ml for science', NULL, '2026-07-08 07:25:40');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2901954625', 'ml-for-science', 'Deep learning for chest radiograph diagnosis: A retrospective comparison of the CheXNeXt algorithm to practicing radiologists', 'BACKGROUND: Chest radiograph interpretation is critical for the detection of thoracic diseases, including tuberculosis and lung cancer, which affect millions of people worldwide each year. This…', '2018', 2018, 1398, 1398, 'https://journals.plos.org/plosmedicine/article/figure/image?size=large&id=10.1371/journal.pmed.1002686.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6245676', 'pmc', 'article', 'PLoS Medicine', '["Pranav Rajpurkar","Jeremy Irvin","Robyn L. Ball","Kaylie Zhu","Brandon Yang","Hershel Mehta","Tony Duan","Daisy Yi Ding","Aarti Bagul","Curtis P. Langlotz","Bhavik N. Patel","Kristen W. Yeom","Katie Shpanskaya","Francis G. Blankenberg","Jayne Seekins","Timothy J. Amrhein","David A. Mong","Safwan S. Halabi","Evan J. Zucker","Andrew Y. Ng","Matthew P. Lungren"]', 'ml for science', 'BACKGROUND: Chest radiograph interpretation is critical for the detection of thoracic diseases, including tuberculosis and lung cancer, which affect millions of people worldwide each year. This time-consuming task typically requires expert radiologists to read the images, leading to fatigue-based diagnostic error and lack of diagnostic expertise in areas of the world where radiologists are not available. Recently, deep learning approaches have been able to achieve expert-level performance in medical image interpretation tasks, powered by large network architectures and fueled by the emergence of large labeled datasets. The purpose of this study is to investigate the performance of a deep learning algorithm on the detection of pathologies in chest radiographs compared with practicing radiologists. METHODS AND FINDINGS: We developed CheXNeXt, a convolutional neural network to concurrently detect the presence of 14 different pathologies, including pneumonia, pleural effusion, pulmonary masses, and nodules in frontal-view chest radiographs. CheXNeXt was trained and internally validated on the ChestX-ray8 dataset, with a held-out validation set consisting of 420 images, sampled to contain at least 50 cases of each of the original pathology labels. On this validation set, the majority vote of a panel of 3 board-certified cardiothoracic specialist radiologists served as reference standard. We compared CheXNeXt''s discriminative performance on the validation set to the performance of 9 radiologists using the area under the receiver operating characteristic curve (AUC). The radiologists included 6 board-certified radiologists (average experience 12 years, range 4-28 years) and 3 senior radiology residents, from 3 academic institutions. We found that CheXNeXt achieved radiologist-level performance on 11 pathologies and did not achieve radiologist-level performance on 3 pathologies. The radiologists achieved statistically significantly higher AUC performance on cardiomegaly, emphysema, and hiatal hernia, with AUCs of 0.888 (95% confidence interval [CI] 0.863-0.910), 0.911 (95% CI 0.866-0.947), and 0.985 (95% CI 0.974-0.991), respectively, whereas CheXNeXt''s AUCs were 0.831 (95% CI 0.790-0.870), 0.704 (95% CI 0.567-0.833), and 0.851 (95% CI 0.785-0.909), respectively. CheXNeXt performed better than radiologists in detecting atelectasis, with an AUC of 0.862 (95% CI 0.825-0.895), statistically significantly higher than radiologists'' AUC of 0.808 (95% CI 0.777-0.838); there were no statistically significant differences in AUCs for the other 10 pathologies. The average time to interpret the 420 images in the validation set was substantially longer for the radiologists (240 minutes) than for CheXNeXt (1.5 minutes). The main limitations of our study are that neither CheXNeXt nor the radiologists were permitted to use patient history or review prior examinations and that evaluation was limited to a dataset from a single institution. CONCLUSIONS: In this study, we developed and validated a deep learning algorithm that classified clinically important abnormalities in chest radiographs at a performance level comparable to practicing radiologists. Once tested prospectively in clinical settings, the algorithm could have the potential to expand patient access to chest radiograph diagnostics.', '2026-07-08 07:25:52');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2042442456', 'ml-for-science', 'Speculative bubbles in Bitcoin markets? An empirical investigation into the fundamental value of Bitcoin', 'Speculative bubbles in Bitcoin markets? An empirical investigation into the fundamental value of Bitcoin', '2015', 2015, 1396, 1396, 'https://ars.els-cdn.com/content/image/1-s2.0-S0165176515000890-gr1.jpg', 'https://doi.org/10.1016/j.econlet.2015.02.029', 'repository', 'article', 'Economics Letters', '["Jeremy Eng‐Tuck Cheah","John Fry"]', 'ml for science', NULL, '2026-07-08 07:26:04');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2785114503', 'ml-for-science', 'Bitcoin: Medium of exchange or speculative assets?', 'Bitcoin: Medium of exchange or speculative assets?', '2017', 2017, 1354, 1354, 'https://ars.els-cdn.com/content/image/1-s2.0-S1042443117300720-gr1.jpg', 'https://doi.org/10.1016/j.intfin.2017.12.004', 'repository', 'article', 'Journal of International Financial Markets Institutions and Money', '["Dirk G. Baur","KiHoon Hong","Adrian D. Lee"]', 'ml for science', NULL, '2026-07-08 07:26:15');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2605253636', 'ml-for-science', 'Can machine-learning improve cardiovascular risk prediction using routine clinical data?', 'BACKGROUND: Current approaches to predict cardiovascular risk fail to identify many people who would benefit from preventive treatment, while others receive unnecessary intervention. Machine-learning…', '2017', 2017, 1348, 1348, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0174944.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5380334', 'pmc', 'article', 'PLoS ONE', '["Stephen Weng","Jenna Reps","Joe Kai","Jonathan M. Garibaldi","Nadeem Qureshi"]', 'ml for science', 'BACKGROUND: Current approaches to predict cardiovascular risk fail to identify many people who would benefit from preventive treatment, while others receive unnecessary intervention. Machine-learning offers opportunity to improve accuracy by exploiting complex interactions between risk factors. We assessed whether machine-learning can improve cardiovascular risk prediction. METHODS: Prospective cohort study using routine clinical data of 378,256 patients from UK family practices, free from cardiovascular disease at outset. Four machine-learning algorithms (random forest, logistic regression, gradient boosting machines, neural networks) were compared to an established algorithm (American College of Cardiology guidelines) to predict first cardiovascular event over 10-years. Predictive accuracy was assessed by area under the ''receiver operating curve'' (AUC); and sensitivity, specificity, positive predictive value (PPV), negative predictive value (NPV) to predict 7.5% cardiovascular risk (threshold for initiating statins). FINDINGS: 24,970 incident cardiovascular events (6.6%) occurred. Compared to the established risk prediction algorithm (AUC 0.728, 95% CI 0.723-0.735), machine-learning algorithms improved prediction: random forest +1.7% (AUC 0.745, 95% CI 0.739-0.750), logistic regression +3.2% (AUC 0.760, 95% CI 0.755-0.766), gradient boosting +3.3% (AUC 0.761, 95% CI 0.755-0.766), neural networks +3.6% (AUC 0.764, 95% CI 0.759-0.769). The highest achieving (neural networks) algorithm predicted 4,998/7,404 cases (sensitivity 67.5%, PPV 18.4%) and 53,458/75,585 non-cases (specificity 70.7%, NPV 95.7%), correctly predicting 355 (+7.6%) more patients who developed cardiovascular disease compared to the established algorithm. CONCLUSIONS: Machine-learning significantly improves accuracy of cardiovascular risk prediction, increasing the number of patients identified who could benefit from preventive treatment, while avoiding unnecessary treatment of others.', '2026-07-08 07:26:23');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3087185550', 'ml-for-science', 'A quantitative framework reveals ecological drivers of grassland microbial community assembly in response to warming', 'Unraveling the drivers controlling community assembly is a central issue in ecology. Although it is generally accepted that selection, dispersal, diversification and drift are major community…', '2020', 2020, 1330, 1330, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41467-020-18560-z/MediaObjects/41467_2020_18560_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/32948774', 'repository', 'article', 'Nature Communications', '["Daliang Ning","Mengting Yuan","Linwei Wu","Ya Zhang","Xue Guo","Xishu Zhou","Yunfeng Yang","Adam P. Arkin","Mary K. Firestone","Jizhong Zhou"]', 'ml for science', 'Unraveling the drivers controlling community assembly is a central issue in ecology. Although it is generally accepted that selection, dispersal, diversification and drift are major community assembly processes, defining their relative importance is very challenging. Here, we present a framework to quantitatively infer community assembly mechanisms by phylogenetic bin-based null model analysis (iCAMP). iCAMP shows high accuracy (0.93-0.99), precision (0.80-0.94), sensitivity (0.82-0.94), and specificity (0.95-0.98) on simulated communities, which are 10-160% higher than those from the entire community-based approach. Application of iCAMP to grassland microbial communities in response to experimental warming reveals dominant roles of homogeneous selection (38%) and ''drift'' (59%). Interestingly, warming decreases ''drift'' over time, and enhances homogeneous selection which is primarily imposed on Bacillales. In addition, homogeneous selection has higher correlations with drought and plant productivity under warming than control. iCAMP provides an effective and robust tool to quantify microbial assembly processes, and should also be useful for plant and animal ecology.', '2026-07-08 07:26:39');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2909818755', 'ml-for-science', 'Integrated microwave photonics', 'Integrated microwave photonics', '2019', 2019, 1337, 1337, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41566-018-0310-5/MediaObjects/41566_2018_310_Fig1_HTML.png', 'https://doi.org/10.1038/s41566-018-0310-5', 'repository', 'article', 'Nature Photonics', '["David Marpaung","Jianping Yao","J. Capmany"]', 'ml for science', NULL, '2026-07-08 07:26:40');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2962764966', 'ml-for-science', 'The Canadian Earth System Model version 5 (CanESM5.0.3)', 'Abstract. The Canadian Earth System Model version 5 (CanESM5) is a global model developed to simulate historical climate change and variability, to make centennial-scale projections of future…', '2019', 2019, 1310, 1310, 'https://www.geoscientific-model-development.net/graphic_egu_claim_logo_blue.png', 'https://doi.org/10.5194/gmd-12-4823-2019', 'repository', 'article', 'Geoscientific model development', '["Neil C. Swart","Jason N. S. Cole","Viatcheslav Kharin","Mike Lazare","John Scinocca","Nathan P. Gillett","James Anstey","Vivek K. Arora","James R. Christian","Sarah Hanna","Yanjun Jiao","Warren G. Lee","Fouad Majaess","Oleg A. Saenko","Christian Seiler","Clint Seinen","Andrew Shao","Michael Sigmond","Larry Solheim","Knut von Salzen","Duo Yang","Barbara Winter"]', 'ml for science', 'Abstract. The Canadian Earth System Model version 5 (CanESM5) is a global model developed to simulate historical climate change and variability, to make centennial-scale projections of future climate, and to produce initialized seasonal and decadal predictions. This paper describes the model components and their coupling, as well as various aspects of model development, including tuning, optimization, and a reproducibility strategy. We also document the stability of the model using a long control simulation, quantify the model''s ability to reproduce large-scale features of the historical climate, and evaluate the response of the model to external forcing. CanESM5 is comprised of three-dimensional atmosphere (T63 spectral resolution equivalent roughly to 2.8∘) and ocean (nominally 1∘) general circulation models, a sea-ice model, a land surface scheme, and explicit land and ocean carbon cycle models. The model features relatively coarse resolution and high throughput, which facilitates the production of large ensembles. CanESM5 has a notably higher equilibrium climate sensitivity (5.6 K) than its predecessor, CanESM2 (3.7 K), which we briefly discuss, along with simulated changes over the historical period. CanESM5 simulations contribute to the Coupled Model Intercomparison Project phase 6 (CMIP6) and will be employed for climate science and service applications in Canada.', '2026-07-08 07:26:45');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2936573766', 'ml-for-science', 'Machine learning in medicine: a practical introduction', 'BACKGROUND: Following visible successes on a wide range of predictive tasks, machine learning techniques are attracting substantial interest from medical researchers and clinicians. We address the…', '2019', 2019, 1279, 1279, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs12874-019-0681-4/MediaObjects/12874_2019_681_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6425557', 'pmc', 'article', 'BMC Medical Research Methodology', '["Jenni A. M. Sidey-Gibbons","Chris Sidey‐Gibbons"]', 'ml for science', 'BACKGROUND: Following visible successes on a wide range of predictive tasks, machine learning techniques are attracting substantial interest from medical researchers and clinicians. We address the need for capacity development in this area by providing a conceptual introduction to machine learning alongside a practical guide to developing and evaluating predictive algorithms using freely-available open source software and public domain data. METHODS: We demonstrate the use of machine learning techniques by developing three predictive models for cancer diagnosis using descriptions of nuclei sampled from breast masses. These algorithms include regularized General Linear Model regression (GLMs), Support Vector Machines (SVMs) with a radial basis function kernel, and single-layer Artificial Neural Networks. The publicly-available dataset describing the breast mass samples (N=683) was randomly split into evaluation (n=456) and validation (n=227) samples. We trained algorithms on data from the evaluation sample before they were used to predict the diagnostic outcome in the validation dataset. We compared the predictions made on the validation datasets with the real-world diagnostic decisions to calculate the accuracy, sensitivity, and specificity of the three models. We explored the use of averaging and voting ensembles to improve predictive performance. We provide a step-by-step guide to developing algorithms using the open-source R statistical programming environment. RESULTS: The trained algorithms were able to classify cell nuclei with high accuracy (.94 -.96), sensitivity (.97 -.99), and specificity (.85 -.94). Maximum accuracy (.96) and area under the curve (.97) was achieved using the SVM algorithm. Prediction performance increased marginally (accuracy =.97, sensitivity =.99, specificity =.95) when algorithms were arranged into a voting ensemble. CONCLUSIONS: We use a straightforward example to demonstrate the theory and practice of machine learning for clinicians and medical researchers. The principals which we demonstrate here can be readily applied to other complex tasks including natural language processing and image recognition.', '2026-07-08 07:26:56');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2748021867', 'ml-for-science', 'Semantic Foggy Scene Understanding with Synthetic Data', 'Semantic Foggy Scene Understanding with Synthetic Data', '2018', 2018, 1283, 1283, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1007%2Fs11263-018-1072-8/MediaObjects/11263_2018_1072_Fig12_HTML.jpg', 'http://arxiv.org/abs/1708.07819', 'arxiv', 'article', 'International Journal of Computer Vision', '["Christos Sakaridis","Dengxin Dai","Luc Van Gool"]', 'ml for science', NULL, '2026-07-08 07:26:57');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2971724044', 'ml-for-science', 'Recurrent Neural Networks for Time Series Forecasting: Current status and future directions', 'Recurrent Neural Networks for Time Series Forecasting: Current status and future directions', '2020', 2020, 1274, 1274, 'https://ars.els-cdn.com/content/image/1-s2.0-S0169207020300996-gr1.jpg', 'http://arxiv.org/abs/1909.00590', 'arxiv', 'article', 'International Journal of Forecasting', '["Hansika Hewamalage","Christoph Bergmeir","Kasun Bandara"]', 'ml for science', NULL, '2026-07-08 07:26:58');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2620760558', 'ml-for-science', 'Optimal classifier for imbalanced data using Matthews Correlation Coefficient metric', 'Data imbalance is frequently encountered in biomedical applications. Resampling techniques can be used in binary classification to tackle this issue. However such solutions are not desired when the…', '2017', 2017, 1240, 1240, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0177678.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5456046', 'pmc', 'article', 'PLoS ONE', '["Sabri Boughorbel","Fethi Jarray","Mohammed Elanbari"]', 'ml for science', 'Data imbalance is frequently encountered in biomedical applications. Resampling techniques can be used in binary classification to tackle this issue. However such solutions are not desired when the number of samples in the small class is limited. Moreover the use of inadequate performance metrics, such as accuracy, lead to poor generalization results because the classifiers tend to predict the largest size class. One of the good approaches to deal with this issue is to optimize performance metrics that are designed to handle data imbalance. Matthews Correlation Coefficient (MCC) is widely used in Bioinformatics as a performance metric. We are interested in developing a new classifier based on the MCC metric to handle imbalanced data. We derive an optimal Bayes classifier for the MCC metric using an approach based on Frechet derivative. We show that the proposed algorithm has the nice theoretical property of consistency. Using simulated data, we verify the correctness of our optimality result by searching in the space of all possible binary classifiers. The proposed classifier is evaluated on 64 datasets from a wide range data imbalance. We compare both classification performance and CPU efficiency for three classifiers: 1) the proposed algorithm (MCC-classifier), the Bayes classifier with a default threshold (MCC-base) and imbalanced SVM (SVM-imba). The experimental evaluation shows that MCC-classifier has a close performance to SVM-imba while being simpler and more efficient.', '2026-07-08 07:27:29');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2576683119', 'ml-for-science', 'Machine learning on big data: Opportunities and challenges', 'Machine learning on big data: Opportunities and challenges', '2017', 2017, 1200, 1200, 'https://ars.els-cdn.com/content/image/1-s2.0-S0925231217300577-fx1.jpg', 'https://doi.org/10.1016/j.neucom.2017.01.026', 'repository', 'article', 'Neurocomputing', '["Lina Zhou","Shimei Pan","Jianwu Wang","Athanasios V. Vasilakos"]', 'ml for science', NULL, '2026-07-08 07:28:06');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3027572331', 'ml-for-science', 'PTB-XL, a large publicly available electrocardiography dataset', 'Electrocardiography (ECG) is a key non-invasive diagnostic tool for cardiovascular diseases which is increasingly supported by algorithms based on machine learning. Major obstacles for the…', '2020', 2020, 1159, 1159, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41597-020-0495-6/MediaObjects/41597_2020_495_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7248071', 'pmc', 'article', 'Scientific Data', '["Patrick Wagner","Nils Strodthoff","Ralf-Dieter Bousseljot","D. Kreiseler","Fatima I. Lunze","Wojciech Samek","Tobias Schaeffter"]', 'ml for science', 'Electrocardiography (ECG) is a key non-invasive diagnostic tool for cardiovascular diseases which is increasingly supported by algorithms based on machine learning. Major obstacles for the development of automatic ECG interpretation algorithms are both the lack of public datasets and well-defined benchmarking procedures to allow comparison s of different algorithms. To address these issues, we put forward PTB-XL, the to-date largest freely accessible clinical 12-lead ECG-waveform dataset comprising 21837 records from 18885 patients of 10 seconds length. The ECG-waveform data was annotated by up to two cardiologists as a multi-label dataset, where diagnostic labels were further aggregated into super and subclasses. The dataset covers a broad range of diagnostic classes including, in particular, a large fraction of healthy records. The combination with additional metadata on demographics, additional diagnostic statements, diagnosis likelihoods, manually annotated signal properties as well as suggested folds for splitting training and test sets turns the dataset into a rich resource for the development and the evaluation of automatic ECG interpretation algorithms.', '2026-07-08 07:28:51');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2993456323', 'ml-for-science', 'Understanding interface stability in solid-state batteries', 'Understanding interface stability in solid-state batteries', '2019', 2019, 1159, 1159, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41578-019-0157-5/MediaObjects/41578_2019_157_Fig1_HTML.png', 'https://doi.org/10.1038/s41578-019-0157-5', 'repository', 'review', 'Nature Reviews Materials', '["Yihan Xiao","Yan Wang","Shou‐Hang Bo","Jae Chul Kim","Lincoln J. Miara","Gerbrand Ceder"]', 'ml for science', NULL, '2026-07-08 07:28:52');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3086667591', 'ml-for-science', 'The state of artificial intelligence-based FDA-approved medical devices and algorithms: an online database', 'At the beginning of the artificial intelligence (AI)/machine learning (ML) era, the expectations are high, and experts foresee that AI/ML shows potential for diagnosing, managing and treating a wide…', '2020', 2020, 1153, 1153, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41746-020-00324-0/MediaObjects/41746_2020_324_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7486909', 'pmc', 'article', 'npj Digital Medicine', '["Stan Benjamens","Pranavsingh Dhunnoo","Bertalan Meskó"]', 'ml for science', 'At the beginning of the artificial intelligence (AI)/machine learning (ML) era, the expectations are high, and experts foresee that AI/ML shows potential for diagnosing, managing and treating a wide variety of medical conditions. However, the obstacles for implementation of AI/ML in daily clinical practice are numerous, especially regarding the regulation of these technologies. Therefore, we provide an insight into the currently available AI/ML-based medical devices and algorithms that have been approved by the US Food & Drugs Administration (FDA). We aimed to raise awareness of the importance of regulatory bodies, clearly stating whether a medical device is AI/ML based or not. Cross-checking and validating all approvals, we identified 64 AI/ML based, FDA approved medical devices and algorithms. Out of those, only 29 (45%) mentioned any AI/ML-related expressions in the official FDA announcement. The majority (85.9%) was approved by the FDA with a 510(k) clearance, while 8 (12.5%) received de novo pathway clearance and one (1.6%) premarket approval (PMA) clearance. Most of these technologies, notably 30 (46.9%), 16 (25.0%), and 10 (15.6%) were developed for the fields of Radiology, Cardiology and Internal Medicine/General Practice respectively. We have launched the first comprehensive and open access database of strictly AI/ML-based medical technologies that have been approved by the FDA. The database will be constantly updated.', '2026-07-08 07:29:03');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2621826044', 'ml-for-science', 'Spatio-Temporal Backpropagation for Training High-Performance Spiking Neural Networks', 'Spiking neural networks (SNNs) are promising in ascertaining brain-like behaviors since spikes are capable of encoding spatio-temporal information. Recent schemes, e.g., pre-training from artificial…', '2018', 2018, 1148, 1148, 'https://www.frontiersin.org/files/Articles/323875/fnins-12-00331-HTML/image_m/fnins-12-00331-g001.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5974215', 'pmc', 'article', 'Frontiers in Neuroscience', '["Yujie Wu","Lei Deng","Guoqi Li","Jun Zhu","Luping Shi"]', 'ml for science', 'Spiking neural networks (SNNs) are promising in ascertaining brain-like behaviors since spikes are capable of encoding spatio-temporal information. Recent schemes, e.g., pre-training from artificial neural networks (ANNs) or direct training based on backpropagation (BP), make the high-performance supervised training of SNNs possible. However, these methods primarily fasten more attention on its spatial domain information, and the dynamics in temporal domain are attached less significance. Consequently, this might lead to the performance bottleneck, and scores of training techniques shall be additionally required. Another underlying problem is that the spike activity is naturally non-differentiable, raising more difficulties in supervised training of SNNs. In this paper, we propose a spatio-temporal backpropagation (STBP) algorithm for training high-performance SNNs. In order to solve the non-differentiable problem of SNNs, an approximated derivative for spike activity is proposed, being appropriate for gradient descent training. The STBP algorithm combines the layer-by-layer spatial domain (SD) and the timing-dependent temporal domain (TD), and does not require any additional complicated skill. We evaluate this method through adopting both the fully connected and convolutional architecture on the static MNIST dataset, a custom object detection dataset, and the dynamic N-MNIST dataset. Results bespeak that our approach achieves the best accuracy compared with existing state-of-the-art algorithms on spiking networks. This work provides a new perspective to investigate the high-performance SNNs for future brain-like computing paradigm with rich spatio-temporal dynamics.', '2026-07-08 07:29:03');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2995656838', 'ml-for-science', 'CO2 hydrogenation to high-value products via heterogeneous catalysis', 'Recently, carbon dioxide capture and conversion, along with hydrogen from renewable resources, provide an alternative approach to synthesis of useful fuels and chemicals. People are increasingly…', '2019', 2019, 1130, 1130, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41467-019-13638-9/MediaObjects/41467_2019_13638_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6910949', 'pmc', 'review', 'Nature Communications', '["Runping Ye","Jie Ding","Weibo Gong","Morris D. Argyle","Qin Zhong","Yujun Wang","Christopher K. Russell","Zhenghe Xu","Armistead G. Russell","Qiaohong Li","Maohong Fan","Yuan‐Gen Yao"]', 'ml for science', 'Recently, carbon dioxide capture and conversion, along with hydrogen from renewable resources, provide an alternative approach to synthesis of useful fuels and chemicals. People are increasingly interested in developing innovative carbon dioxide hydrogenation catalysts, and the pace of progress in this area is accelerating. Accordingly, this perspective presents current state of the art and outlook in synthesis of light olefins, dimethyl ether, liquid fuels, and alcohols through two leading hydrogenation mechanisms: methanol reaction and Fischer-Tropsch based carbon dioxide hydrogenation. The future research directions for developing new heterogeneous catalysts with transformational technologies, including 3D printing and artificial intelligence, are provided.', '2026-07-08 07:29:08');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2989847975', 'ml-for-science', 'Mastering Atari, Go, chess and shogi by planning with a learned model', 'Mastering Atari, Go, chess and shogi by planning with a learned model', '2020', 2020, 1107, 1107, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-020-03051-4/MediaObjects/41586_2020_3051_Fig1_HTML.png', 'http://arxiv.org/abs/1911.08265', 'arxiv', 'article', 'Nature', '["Julian Schrittwieser","Ioannis Antonoglou","Thomas Hubert","Karen Simonyan","Laurent Sifre","Simon Schmitt","Arthur Guez","Edward Lockhart","Demis Hassabis","Thore Graepel","Timothy Lillicrap","David Silver"]', 'ml for science', NULL, '2026-07-08 07:29:22');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2461793432', 'ml-for-science', 'The genetic architecture of type 2 diabetes', 'The genetic architecture of type 2 diabetes', '2016', 2016, 1113, 1113, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature18642/MediaObjects/41586_2016_BFnature18642_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5034897', 'pmc', 'article', 'Nature', '["Christian Fuchsberger","Jason Flannick","Tanya M. Teslovich","Anubha Mahajan","Vineeta Agarwala","Kyle J. Gaulton","Clement Ma","Pierre Fontanillas","Loukas Moutsianas","Davis J. McCarthy","Manuel A. Rivas","John R. B. Perry","Xueling Sim","Thomas W. Blackwell","Neil R. Robertson","Nigel W. Rayner","Pablo Cingolani","Adam E. Locke","Juan Fernández Tajes","Heather M. Highland","Josée Dupuis","Peter S. Chines","Cecilia M. Lindgren","Christopher Hartl","Anne Jackson","Han Chen","Jeroen R. Huyghe","Martijn van de Bunt","Richard D. Pearson","Ashish Kumar","Martina Müller‐Nurasyid","Niels Grarup","Heather M. Stringham","Eric R. Gamazon","Jaehoon Lee","Yuhui Chen","Robert A. Scott","Jennifer E. Below","Peng Chen","Jinyan Huang","Min Jin Go","Michael L. Stitzel","Dorota Pasko","Stephen C.J. Parker","Tibor V. Varga","Todd Green","Nicola L. Beer","Aaron Day-Williams","Teresa Ferreira","Tasha E. Fingerlin","Momoko Horikoshi","Cheng Hu","Iksoo Huh","M. Kamran Ikram","Bong-Jo Kim","Yongkang Kim","Young Jin Kim","Min‐Seok Kwon","Juyoung Lee","Selyeong Lee","Keng‐Han Lin","Taylor J. Maxwell","Yoshihiko Nagai","Xu Wang","Ryan Welch","Joon Yoon","Weihua Zhang","Nir Barzilai","Benjamin F. Voight","Bok‐Ghee Han","Christopher P. Jenkinson","Teemu Kuulasmaa","Johanna Kuusisto","Alisa K. Manning","Maggie C. Y. Ng","Nicholette D. Palmer","Beverley Balkau","Alena Stančáková","Hanna E. Abboud","Heiner Boeing","Vilmantas Giedraitis","Dorairaj Prabhakaran","Omri Gottesman","James Scott","Jason Carey","Phoenix Kwan","George Grant","Joshua D. Smith","Benjamin M. Neale","Shaun Purcell","Adam S. Butterworth","Joanna M. M. Howson","Heung Man Lee","Yingchang Lu","Soo‐Heon Kwak","Wei Zhao","John Danesh","Vincent K. Lam","Kyong Soo Park","Danish Saleheen"]', 'ml for science', NULL, '2026-07-08 07:29:23');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2803163155', 'ml-for-science', 'Equivalent-accuracy accelerated neural-network training using analogue memory', 'Equivalent-accuracy accelerated neural-network training using analogue memory', '2018', 2018, 1109, 1109, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-018-0180-5/MediaObjects/41586_2018_180_Fig1_HTML.jpg', 'https://pubmed.ncbi.nlm.nih.gov/29875487', 'repository', 'article', 'Nature', '["Stefano Ambrogio","Pritish Narayanan","Hsinyu Tsai","R. M. Shelby","Irem Boybat","Carmelo di Nolfo","Severin Sidler","Massimo Giordano","Martina Bodini","Nathan C. P. Farinha","Benjamin D. Killeen","Christina Cheng","Yassine Jaoudi","Geoffrey W. Burr"]', 'ml for science', NULL, '2026-07-08 07:29:23');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2734777338', 'ml-for-science', 'A deep learning framework for financial time series using stacked autoencoders and long-short term memory', 'The application of deep learning approaches to finance has received a great deal of attention from both investors and researchers. This study presents a novel deep learning framework where wavelet…', '2017', 2017, 1087, 1087, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0180944.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5510866', 'pmc', 'article', 'PLoS ONE', '["Wei Bao","Jun Yue","Yulei Rao"]', 'ml for science', 'The application of deep learning approaches to finance has received a great deal of attention from both investors and researchers. This study presents a novel deep learning framework where wavelet transforms (WT), stacked autoencoders (SAEs) and long-short term memory (LSTM) are combined for stock price forecasting. The SAEs for hierarchically extracted deep features is introduced into stock price forecasting for the first time. The deep learning framework comprises three stages. First, the stock price time series is decomposed by WT to eliminate noise. Second, SAEs is applied to generate deep high-level features for predicting the stock price. Third, high-level denoising features are fed into LSTM to forecast the next day''s closing price. Six market indices and their corresponding index futures are chosen to examine the performance of the proposed model. Results show that the proposed model outperforms other similar models in both predictive accuracy and profitability performance.', '2026-07-08 07:29:47');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3111278950', 'ml-for-science', 'An open source machine learning framework for efficient and transparent systematic reviews', 'Abstract To help researchers conduct a systematic review or meta-analysis as efficiently and transparently as possible, we designed a tool to accelerate the step of screening titles and abstracts.…', '2021', 2021, 1065, 1065, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs42256-020-00287-7/MediaObjects/42256_2020_287_Fig1_HTML.png', 'http://arxiv.org/abs/2006.12166', 'arxiv', 'article', 'Nature Machine Intelligence', '["Rens van de Schoot","Jonathan de Bruin","Raoul Schram","Parisa Zahedi","Jan de Boer","Felix Weijdema","Bianca Kramer","Martijn Huijts","Maarten Hoogerwerf","Gerbrich Ferdinands","Albert Harkema","Joukje Willemsen","Yongchao Ma","Qixiang Fang","Sybren Hindriks","Lars Tummers","Daniel L. Oberski"]', 'ml for science', 'Abstract To help researchers conduct a systematic review or meta-analysis as efficiently and transparently as possible, we designed a tool to accelerate the step of screening titles and abstracts. For many tasks—including but not limited to systematic reviews and meta-analyses—the scientific literature needs to be checked systematically. Scholars and practitioners currently screen thousands of studies by hand to determine which studies to include in their review or meta-analysis. This is error prone and inefficient because of extremely imbalanced data: only a fraction of the screened studies is relevant. The future of systematic reviewing will be an interaction with machine learning algorithms to deal with the enormous increase of available text. We therefore developed an open source machine learning-aided pipeline applying active learning: ASReview. We demonstrate by means of simulation studies that active learning can yield far more efficient reviewing than manual reviewing while providing high quality. Furthermore, we describe the options of the free and open source research software and present the results from user experience tests. We invite the community to contribute to open source projects such as our own that provide measurable and reproducible improvements over current practice.', '2026-07-08 07:30:19');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3208687975', 'ml-for-science', 'Recent advances and applications of deep learning methods in materials science', 'Abstract Deep learning (DL) is one of the fastest-growing topics in materials data science, with rapidly emerging applications spanning atomistic, image-based, spectral, and textual data modalities.…', '2022', 2022, 1064, 1064, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41524-022-00734-6/MediaObjects/41524_2022_734_Fig1_HTML.png', 'http://arxiv.org/abs/2110.14820', 'arxiv', 'article', 'npj Computational Materials', '["Kamal Choudhary","Brian DeCost","Chi Chen","Anubhav Jain","Francesca Tavazza","Ryan Cohn","Cheol Woo Park","Alok Choudhary","Ankit Agrawal","Simon J. L. Billinge","Elizabeth A. Holm","Shyue Ping Ong","Chris Wolverton"]', 'ml for science', 'Abstract Deep learning (DL) is one of the fastest-growing topics in materials data science, with rapidly emerging applications spanning atomistic, image-based, spectral, and textual data modalities. DL allows analysis of unstructured data and automated identification of features. The recent development of large materials databases has fueled the application of DL methods in atomistic prediction in particular. In contrast, advances in image and spectral data have largely leveraged synthetic data enabled by high-quality forward models as well as by generative unsupervised DL methods. In this article, we present a high-level overview of deep learning methods followed by a detailed discussion of recent developments of deep learning in atomistic simulation, materials imaging, spectral analysis, and natural language processing. For each modality we discuss applications involving both theoretical and experimental data, typical modeling approaches with their strengths and limitations, and relevant publicly available software and datasets. We conclude the review with a discussion of recent cross-cutting work related to uncertainty quantification in this field and a brief perspective on limitations, challenges, and potential growth areas for DL methods in materials science.', '2026-07-08 07:30:21');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2564630286', 'economics', 'ReCiPe2016: a harmonised life cycle impact assessment method at midpoint and endpoint level', 'Life cycle impact assessment (LCIA) translates emissions and resource extractions into a limited number of environmental impact scores by means of so-called characterisation factors. There are two…', '2016', 2016, 4128, 4128, 'https://media.springernature.com/lw685/springer-static/image/art%3A10.1007%2Fs11367-016-1246-y/MediaObjects/11367_2016_1246_Fig1_HTML.gif', 'https://doi.org/10.1007/s11367-016-1246-y', 'repository', 'article', 'The International Journal of Life Cycle Assessment', '["Mark A. J. Huijbregts","Zoran J. N. Steinmann","Pieter M. F. Elshout","Gea Stam","Francesca Verones","Marisa Vieira","Michiel C. Zijp","Anne Hollander","Rosalie van Zelm"]', 'economics', 'Life cycle impact assessment (LCIA) translates emissions and resource extractions into a limited number of environmental impact scores by means of so-called characterisation factors. There are two mainstream ways to derive characterisation factors, i.e. at midpoint level and at endpoint level. To further progress LCIA method development, we updated the ReCiPe2008 method to its version of 2016. This paper provides an overview of the key elements of the ReCiPe2016 method. We implemented human health, ecosystem quality and resource scarcity as three areas of protection. Endpoint characterisation factors, directly related to the areas of protection, were derived from midpoint characterisation factors with a constant mid-to-endpoint factor per impact category. We included 17 midpoint impact categories. The update of ReCiPe provides characterisation factors that are representative for the global scale instead of the European scale, while maintaining the possibility for a number of impact categories to implement characterisation factors at a country and continental scale. We also expanded the number of environmental interventions and added impacts of water use on human health, impacts of water use and climate change on freshwater ecosystems and impacts of water use and tropospheric ozone formation on terrestrial ecosystems as novel damage pathways. Although significant effort has been put into the update of ReCiPe, there is still major improvement potential in the way impact pathways are modelled. Further improvements relate to a regionalisation of more impact categories, moving from local to global species extinction and adding more impact pathways. Life cycle impact assessment is a fast evolving field of research. ReCiPe2016 provides a state-of-the-art method to convert life cycle inventories to a limited number of life cycle impact scores on midpoint and endpoint level.', '2026-07-08 07:31:57');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2201607793', 'economics', 'The role of inflammation in depression: from evolutionary imperative to modern treatment target', 'The role of inflammation in depression: from evolutionary imperative to modern treatment target', '2015', 2015, 3773, 3773, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnri.2015.5/MediaObjects/41577_2016_Article_BFnri20155_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5542678', 'pmc', 'review', 'Nature reviews. Immunology', '["Andrew H. Miller","Charles L. Raison"]', 'economics', NULL, '2026-07-08 07:32:10');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4283381496', 'economics', 'The 5th edition of the World Health Organization Classification of Haematolymphoid Tumours: Lymphoid Neoplasms', 'Abstract We herein present an overview of the upcoming 5 th edition of the World Health Organization Classification of Haematolymphoid Tumours focussing on lymphoid neoplasms. Myeloid and histiocytic…', '2022', 2022, 3768, 3768, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41375-022-01620-2/MediaObjects/41375_2022_1620_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/35732829', 'repository', 'review', 'Leukemia', '["Rita Alaggio","Catalina Amador","Ioannis Anagnostopoulos","Ayoma D. Attygalle","Iguaracyra Araújo","Emilio Berti","Govind Bhagat","Anita Borges","Daniel F. Boyer","Maria Calaminici","Amy Chadburn","John K. C. Chan","Wah Cheuk","Wee Joo Chng","John Choi","Shih‐Sung Chuang","Sarah E. Coupland","Magdalena Czader","Sandeep S. Davé","Daphne de Jong","Ming‐Qing Du","Kojo S.J. Elenitoba‐Johnson","Judith A. Ferry","Julia T. Geyer","Dita Gratzinger","Joan Guitart","Sumeet Gujral","Marian H. Harris","Christine J. Harrison","Sylvia Hartmann","Andreas Hochhaus","Patty M. Jansen","Kennosuke Karube","Werner Kempf","Joseph D. Khoury","Hiroshi Kimura","Wolfgang Hiddemann","Alexandra E. Kovach","Shaji Kumar","Alexander J. Lazar","Stefano Lazzi","Lorenzo Leoncini","Nelson Leung","Vasiliki Leventaki","Xiao‐Qiu Li","Megan S. Lim","Weiping Liu","Abner Louissaint","Andrea N. Marcogliese","L. Jeffrey Medeiros","Michael Michal","Roberto N. Miranda","Christina Mitteldorf","Santiago Montes‐Moreno","William G. Morice","Valentina Nardi","Kikkeri N. Naresh","Yasodha Natkunam","Siok‐Bian Ng","Ilske Oschlies","German Ott","Marie Parrens","Melissa Pulitzer","S. Vincent Rajkumar","Andy C. Rawstron","Karen L. Rech","Andreas Rosenwald","Jonathan Said","Clémentine Sarkozy","Shahin Sayed","Caner Saygin","Anna Schuh","William A. Sewell","Reiner Siebert","Aliyah R. Sohani","Reuben Tooze","Alexandra Traverse‐Glehen","Francisco Vega","B. Vergier","Ashutosh Wechalekar","Brent L. Wood","Luc Xerri","Wenbin Xiao"]', 'economics', 'Abstract We herein present an overview of the upcoming 5 th edition of the World Health Organization Classification of Haematolymphoid Tumours focussing on lymphoid neoplasms. Myeloid and histiocytic neoplasms will be presented in a separate accompanying article. Besides listing the entities of the classification, we highlight and explain changes from the revised 4 th edition. These include reorganization of entities by a hierarchical system as is adopted throughout the 5 th edition of the WHO classification of tumours of all organ systems, modification of nomenclature for some entities, revision of diagnostic criteria or subtypes, deletion of certain entities, and introduction of new entities, as well as inclusion of tumour-like lesions, mesenchymal lesions specific to lymph node and spleen, and germline predisposition syndromes associated with the lymphoid neoplasms.', '2026-07-08 07:32:11');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2227280755', 'economics', 'Influence of extreme weather disasters on global crop production', 'Influence of extreme weather disasters on global crop production', '2016', 2016, 3746, 3746, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature16467/MediaObjects/41586_2016_Article_BFnature16467_Fig1_HTML.jpg', 'https://pubmed.ncbi.nlm.nih.gov/26738594', 'repository', 'article', 'Nature', '["Corey Lesk","Pedram Rowhani","Navin Ramankutty"]', 'economics', NULL, '2026-07-08 07:32:11');
