INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2190546151', 'economics', 'Managing nitrogen for sustainable development', 'Managing nitrogen for sustainable development', '2015', 2015, 2924, 2924, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature15743/MediaObjects/41586_2015_Article_BFnature15743_Fig1_HTML.jpg', 'https://enpc.hal.science/hal-01262089', 'repository', 'article', 'Nature', '["Xin Zhang","Eric A. Davidson","Denise L. Mauzerall","Timothy D. Searchinger","Patrice Dumas","Yuchao Shen"]', 'economics', NULL, '2026-07-08 07:33:21');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2800203331', 'economics', 'Trends in China''s anthropogenic emissions since 2010 as the consequence of clean air actions', 'Abstract. To tackle the problem of severe air pollution, China has implemented active clean air policies in recent years. As a consequence, the emissions of major air pollutants have decreased and…', '2018', 2018, 2940, 2940, 'https://www.atmospheric-chemistry-and-physics.net/graphic_egu_claim_logo_blue.png', 'https://insu.hal.science/insu-03721860', 'repository', 'article', 'Atmospheric chemistry and physics', '["Bo Zheng","Dan Tong","Meng Li","Fei Liu","Chaopeng Hong","Guannan Geng","Haiyan Li","Xin Li","Liqun Peng","Ji Qi","Liu Yan","Yuxuan Zhang","Hongyan Zhao","Yixuan Zheng","Kebin He","Qiang Zhang"]', 'economics', 'Abstract. To tackle the problem of severe air pollution, China has implemented active clean air policies in recent years. As a consequence, the emissions of major air pollutants have decreased and the air quality has substantially improved. Here, we quantified China''s anthropogenic emission trends from 2010 to 2017 and identified the major driving forces of these trends by using a combination of bottom-up emission inventory and index decomposition analysis (IDA) approaches. The relative change rates of China''s anthropogenic emissions during 2010–2017 are estimated as follows: −62 % for SO2, −17 % for NOx, +11 % for nonmethane volatile organic compounds (NMVOCs), +1 % for NH3, −27 % for CO, −38 % for PM10, −35 % for PM2.5, −27 % for BC, −35 % for OC, and +16 % for CO2. The IDA results suggest that emission control measures are the main drivers of this reduction, in which the pollution controls on power plants and industries are the most effective mitigation measures. The emission reduction rates markedly accelerated after the year 2013, confirming the effectiveness of China''s Clean Air Action that was implemented since 2013. We estimated that during 2013–2017, China''s anthropogenic emissions decreased by 59 % for SO2, 21 % for NOx, 23 % for CO, 36 % for PM10, 33 % for PM2.5, 28 % for BC, and 32 % for OC. NMVOC emissions increased and NH3 emissions remained stable during 2010–2017, representing the absence of effective mitigation measures for NMVOCs and NH3 in current policies. The relative contributions of different sectors to emissions have significantly changed after several years'' implementation of clean air policies, indicating that it is paramount to introduce new policies to enable further emission reductions in the future.', '2026-07-08 07:33:22');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2883573930', 'economics', 'Gene discovery and polygenic prediction from a genome-wide association study of educational attainment in 1.1 million individuals', 'Here we conducted a large-scale genetic association analysis of educational attainment in a sample of approximately 1.1 million individuals and identify 1,271 independent genome-wide-significant…', '2018', 2018, 2855, 2855, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41588-018-0147-3/MediaObjects/41588_2018_147_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/30038396', 'repository', 'review', 'Nature Genetics', '["James J. Lee","Robbee Wedow","Aysu Okbay","Edward Kong","Omeed Maghzian","Meghan Zacher","Tuan Anh Nguyen-Viet","Peter N. Bowers","Julia Sidorenko","Richard Karlsson Linnér","Mark Alan Fontana","Tushar Kundu","Chan Wook Lee","Hui Li","Ruoxi Li","Rebecca Royer","Pascal Timshel","Raymond K. Walters","Emily A. Willoughby","Loïc Yengo","Maris Alver","Yanchun Bao","David W. Clark","Felix R. Day","Nicholas A. Furlotte","Peter K. Joshi","Kathryn E. Kemper","Aaron Kleinman","Claudia Langenberg","Reedik Mägi","Joey W. Trampush","Shefali S. Verma","Yang Wu","Max Lam","Jing Hua Zhao","Zhili Zheng","Jason D. Boardman","Harry Campbell","Jeremy Freese","Kathleen Mullan Harris","Caroline Hayward","Pamela Herd","Meena Kumari","Todd Lencz","Jian’an Luan","Anil K. Malhotra","Andres Metspalu","Lili Milani","Ken K. Ong","John R. B. Perry","David J. Porteous","Marylyn D. Ritchie","Melissa Smart","Blair H. Smith","Joyce Y. Tung","Nicholas J. Wareham","James F. Wilson","Jonathan Beauchamp","Dalton Conley","Tõnu Esko","Steven F. Lehrer","Patrik K. E. Magnusson","Sven Oskarsson","Tune H. Pers","Matthew R. Robinson","Kevin Thom","Chelsea Watson","Christopher F. Chabris","Michelle N. Meyer","David Laibson","Jian Yang","Magnus Johannesson","Philipp Koellinger","Patrick Turley","Peter M. Visscher","Daniel J. Benjamin","David Cesarini"]', 'economics', 'Here we conducted a large-scale genetic association analysis of educational attainment in a sample of approximately 1.1 million individuals and identify 1,271 independent genome-wide-significant SNPs. For the SNPs taken together, we found evidence of heterogeneous effects across environments. The SNPs implicate genes involved in brain-development processes and neuron-to-neuron communication. In a separate analysis of the X chromosome, we identify 10 independent genome-wide-significant SNPs and estimate a SNP heritability of around 0.3% in both men and women, consistent with partial dosage compensation. A joint (multi-phenotype) analysis of educational attainment and three related cognitive phenotypes generates polygenic scores that explain 11-13% of the variance in educational attainment and 7-10% of the variance in cognitive performance. This prediction accuracy substantially increases the utility of polygenic scores as tools in research.', '2026-07-08 07:33:22');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2336426693', 'economics', 'Greening of the Earth and its drivers', 'Greening of the Earth and its drivers', '2016', 2016, 2684, 2684, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnclimate3004/MediaObjects/41558_2016_Article_BFnclimate3004_Fig1_HTML.jpg', 'https://hal.science/hal-02894738', 'repository', 'article', 'Nature Climate Change', '["Zaichun Zhu","Shilong Piao","Ranga B. Myneni","Mengtian Huang","Zhenzhong Zeng","Josep G. Canadell","Philippe Ciais","Stephen Sitch","Pierre Friedlingstein","Almut Arneth","Chunxiang Cao","Lei Cheng","Etsushi Kato","Charles D. Koven","Yue Li","Xu Lian","Yongwen Liu","Ronggao Liu","Jiafu Mao","Yaozhong Pan","Shushi Peng","Josep Peñuelas","Benjamin Poulter","Thomas A. M. Pugh","Benjamin D. Stocker","Nicolas Viovy","Xuhui Wang","Ying‐Ping Wang","Zhiqiang Xiao","Hui Yang","Sönke Zaehle","Ning Zeng"]', 'economics', NULL, '2026-07-08 07:33:33');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2163235518', 'economics', 'Global non-linear effect of temperature on economic production', 'Global non-linear effect of temperature on economic production', '2015', 2015, 2818, 2818, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature15725/MediaObjects/41586_2015_Article_BFnature15725_Fig1_HTML.jpg', 'https://pubmed.ncbi.nlm.nih.gov/26503051', 'repository', 'article', 'Nature', '["Marshall Burke","Solomon Hsiang","Edward Miguel"]', 'economics', NULL, '2026-07-08 07:33:33');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3026582775', 'economics', 'Temporary reduction in daily global CO2 emissions during the COVID-19 forced confinement', 'Temporary reduction in daily global CO2 emissions during the COVID-19 forced confinement', '2020', 2020, 2295, 2295, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41558-020-0797-x/MediaObjects/41558_2020_797_Fig1_HTML.png', 'https://zenodo.org/record/4118105', 'repository', 'article', 'Nature Climate Change', '["Corinne Le Quéré","Robert B. Jackson","Matthew W. Jones","Adam J. P. Smith","Sam Abernethy","Robbie M. Andrew","Anthony J. De-Gol","David Willis","Yuli Shan","Josep G. Canadell","Pierre Friedlingstein","Felix Creutzig","Glen P. Peters"]', 'economics', NULL, '2026-07-08 07:34:37');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2914665624', 'economics', 'Future scenarios of global plastic waste generation and disposal', 'Abstract The accumulation of mismanaged plastic waste (MPW) in the environment is a global growing concern. Knowing with precision where litter is generated is important to target priority areas for…', '2019', 2019, 2269, 2269, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1057%2Fs41599-018-0212-7/MediaObjects/41599_2018_212_Fig1_HTML.png', 'https://doi.org/10.1057/s41599-018-0212-7', 'repository', 'article', 'Palgrave Communications', '["Laurent Lebreton","Anthony L. Andrady"]', 'economics', 'Abstract The accumulation of mismanaged plastic waste (MPW) in the environment is a global growing concern. Knowing with precision where litter is generated is important to target priority areas for the implementation of mitigation policies. In this study, using country-level data on waste management combined with high-resolution distributions and long-term projections of population and the gross domestic product (GDP), we present projections of global MPW generation at ~1 km resolution from now to 2060. We estimated between 60 and 99 million metric tonnes (Mt) of MPW were produced globally in 2015. In a business-as-usual scenario, this figure could triple to 155–265 Mt y −1 by 2060. The future MPW load will continue to be disproportionately high in African and Asian continents even in the future years. However, we show that this growth in plastic waste can be reduced if developing economies significantly invest in waste management infrastructures as their GDP grows in the future and if efforts are made internationally to reduce the fraction of plastic in municipal solid waste. Using our projections, we also demonstrate that the majority of MPW (91%) are transported via watersheds larger than 100 km 2 suggesting that rivers are major pathways for plastic litter to the ocean.', '2026-07-08 07:34:37');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4210511145', 'economics', 'Long-term cardiovascular outcomes of COVID-19', 'The cardiovascular complications of acute coronavirus disease 2019 (COVID-19) are well described, but the post-acute cardiovascular manifestations of COVID-19 have not yet been comprehensively…', '2022', 2022, 2106, 2106, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41591-022-01689-3/MediaObjects/41591_2022_1689_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8938267', 'pmc', 'article', 'Nature Medicine', '["Yan Xie","Evan Xu","Benjamin Bowe","Ziyad Al‐Aly"]', 'economics', 'The cardiovascular complications of acute coronavirus disease 2019 (COVID-19) are well described, but the post-acute cardiovascular manifestations of COVID-19 have not yet been comprehensively characterized. Here we used national healthcare databases from the US Department of Veterans Affairs to build a cohort of 153,760 individuals with COVID-19, as well as two sets of control cohorts with 5,637,647 (contemporary controls) and 5,859,411 (historical controls) individuals, to estimate risks and 1-year burdens of a set of pre-specified incident cardiovascular outcomes. We show that, beyond the first 30 d after infection, individuals with COVID-19 are at increased risk of incident cardiovascular disease spanning several categories, including cerebrovascular disorders, dysrhythmias, ischemic and non-ischemic heart disease, pericarditis, myocarditis, heart failure and thromboembolic disease. These risks and burdens were evident even among individuals who were not hospitalized during the acute phase of the infection and increased in a graded fashion according to the care setting during the acute phase (non-hospitalized, hospitalized and admitted to intensive care). Our results provide evidence that the risk and 1-year burden of cardiovascular disease in survivors of acute COVID-19 are substantial. Care pathways of those surviving the acute episode of COVID-19 should include attention to cardiovascular health and disease.', '2026-07-08 07:35:26');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2558467948', 'economics', 'Safeguarding pollinators and their values to human well-being', 'Safeguarding pollinators and their values to human well-being', '2016', 2016, 2089, 2089, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature20588/MediaObjects/41586_2016_Article_BFnature20588_Fig1_HTML.jpg', 'https://pubmed.ncbi.nlm.nih.gov/27894123', 'repository', 'review', 'Nature', '["Simon G. Potts","Vera Lúcia Imperatriz-Fonseca","Hien T. Ngo","Marcelo A. Aizen","Jacobus C. Biesmeijer","Thomas D. Breeze","Lynn V. Dicks","Lucas A. Garibaldi","Rosemary Hill","Josef Settele","Adam J. Vanbergen"]', 'economics', NULL, '2026-07-08 07:35:27');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2328487243', 'economics', 'Climate-smart soils', 'Climate-smart soils', '2016', 2016, 2090, 2090, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature17174/MediaObjects/41586_2016_Article_BFnature17174_Fig1_HTML.jpg', 'https://pubmed.ncbi.nlm.nih.gov/27078564', 'repository', 'article', 'Nature', '["Keith Paustian","Johannes Lehmann","Stephen M. Ogle","David Reay","G. Philip Robertson","Pete Smith"]', 'economics', NULL, '2026-07-08 07:35:27');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2773929027', 'economics', '1 Blockchain’s roles in meeting key supply chain management objectives', '1 Blockchain’s roles in meeting key supply chain management objectives', '2017', 2017, 2068, 2068, 'https://ars.els-cdn.com/content/image/1-s2.0-S0268401217305248-fx1.jpg', 'https://doi.org/10.1016/j.ijinfomgt.2017.12.005', 'repository', 'article', 'International Journal of Information Management', '["Nir Kshetri"]', 'economics', NULL, '2026-07-08 07:35:37');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2802803660', 'economics', 'The promising future of microalgae: current status, challenges, and optimization of a sustainable and renewable industry for biofuels, feed, and other products', 'Microalgae have recently attracted considerable interest worldwide, due to their extensive application potential in the renewable energy, biopharmaceutical, and nutraceutical industries. Microalgae…', '2018', 2018, 2040, 2040, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1007%2Fs11101-022-09819-y/MediaObjects/11101_2022_9819_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5836383', 'pmc', 'review', 'Microbial Cell Factories', '["Muhammad Imran Khan","Jin Hyuk Shin","Jong Deog Kim"]', 'economics', 'Microalgae have recently attracted considerable interest worldwide, due to their extensive application potential in the renewable energy, biopharmaceutical, and nutraceutical industries. Microalgae are renewable, sustainable, and economical sources of biofuels, bioactive medicinal products, and food ingredients. Several microalgae species have been investigated for their potential as value-added products with remarkable pharmacological and biological qualities. As biofuels, they are a perfect substitute to liquid fossil fuels with respect to cost, renewability, and environmental concerns. Microalgae have a significant ability to convert atmospheric CO2 to useful products such as carbohydrates, lipids, and other bioactive metabolites. Although microalgae are feasible sources for bioenergy and biopharmaceuticals in general, some limitations and challenges remain, which must be overcome to upgrade the technology from pilot-phase to industrial level. The most challenging and crucial issues are enhancing microalgae growth rate and product synthesis, dewatering algae culture for biomass production, pretreating biomass, and optimizing the fermentation process in case of algal bioethanol production. The present review describes the advantages of microalgae for the production of biofuels and various bioactive compounds and discusses culturing parameters.', '2026-07-08 07:35:53');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2683672249', 'economics', 'The COMET Handbook: version 1.0', 'The selection of appropriate outcomes is crucial when designing clinical trials in order to compare the effects of different interventions directly. For the findings to influence policy and practice,…', '2017', 2017, 2014, 2014, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs13063-017-2054-9/MediaObjects/13063_2017_2054_Fig1_HTML.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5499094', 'pmc', 'review', 'Trials', '["Paula Williamson","Douglas G. Altman","Heather Bagley","Karen L. Barnes","Jane Blazeby","Sara Brookes","Mike Clarke","Elizabeth Gargon","Sarah L. Gorst","Nicola Harman","Jamie J Kirkham","Angus McNair","C.A.C. Prinsen","Jochen Schmitt","Caroline B. Terwee","Bridget Young"]', 'economics', 'The selection of appropriate outcomes is crucial when designing clinical trials in order to compare the effects of different interventions directly. For the findings to influence policy and practice, the outcomes need to be relevant and important to key stakeholders including patients and the public, health care professionals and others making decisions about health care. It is now widely acknowledged that insufficient attention has been paid to the choice of outcomes measured in clinical trials. Researchers are increasingly addressing this issue through the development and use of a core outcome set, an agreed standardised collection of outcomes which should be measured and reported, as a minimum, in all trials for a specific clinical area.Accumulating work in this area has identified the need for guidance on the development, implementation, evaluation and updating of core outcome sets. This Handbook, developed by the COMET Initiative, brings together current thinking and methodological research regarding those issues. We recommend a four-step process to develop a core outcome set. The aim is to update the contents of the Handbook as further research is identified.', '2026-07-08 07:35:54');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2785400778', 'economics', 'The KOF Globalisation Index – revisited', 'We introduce the revised version of the KOF Globalisation Index, a composite index measuring globalization for every country in the world along the economic, social and political dimension. The…', '2019', 2019, 1978, 1978, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1007%2Fs11558-019-09344-2/MediaObjects/11558_2019_9344_Fig1_HTML.png', 'https://doi.org/10.1007/s11558-019-09344-2', 'repository', 'article', 'The Review of International Organizations', '["Savina Gygli","Florian Haelg","Niklas Potrafke","Jan‐Egbert Sturm"]', 'economics', 'We introduce the revised version of the KOF Globalisation Index, a composite index measuring globalization for every country in the world along the economic, social and political dimension. The original index was introduced by Dreher (Applied Economics, 38(10):1091–1110, 2006) and updated in Dreher et al. (2008). This second revision of the index distinguishes between de facto and de jure measures along the different dimensions of globalization. We also disentangle trade and financial globalization within the economic dimension of globalization and use time-varying weighting of the variables. The new index is based on 43 instead of 23 variables in the previous version. Following Dreher (Applied Economics, 38(10):1091–1110, 2006), we use the new index to examine the effect of globalization on economic growth. The results suggest that de facto and de jure globalization influence economic growth differently. Future research should use the new KOF Globalisation Index to re-examine other important consequences of globalization and why globalization was proceeding rapidly in some countries, such as South Korea, but less so in others. The KOF Globalisation Index can be downloaded from http://www.kof.ethz.ch/globalisation/.', '2026-07-08 07:36:07');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2980464326', 'economics', 'Worldwide pesticide usage and its impacts on ecosystem', 'Worldwide pesticide usage and its impacts on ecosystem', '2019', 2019, 1982, 1982, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1007%2Fs42452-019-1485-1/MediaObjects/42452_2019_1485_Fig1_HTML.png', 'https://doi.org/10.1007/s42452-019-1485-1', 'repository', 'article', 'SN Applied Sciences', '["Anket Sharma","Vinod Kumar","Babar Shahzad","Mohsin Tanveer","Gagan Preet Singh Sidhu","Neha Handa","Sukhmeen Kaur Kohli","Poonam Yadav","Aditi Shreeya Bali","Ripu Daman Parihar","Owias Iqbal Dar","Kirpal Singh","Shivam Jasrotia","Palak Bakshi","M. Ramakrishnan","Sandeep Kumar","Renu Bhardwaj","Ashwani Kumar Thukral"]', 'economics', NULL, '2026-07-08 07:36:08');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2262752710', 'economics', 'The Number, Size, and Distribution of Farms, Smallholder Farms, and Family Farms Worldwide', 'Numerous sources provide evidence of trends and patterns in average farm size and farmland distribution worldwide, but they often lack documentation, are in some cases out of date, and do not provide…', '2016', 2016, 1975, 1975, 'https://ars.els-cdn.com/content/image/1-s2.0-S0305750X15002703-gr1.jpg', 'https://doi.org/10.1016/j.worlddev.2015.10.041', 'repository', 'article', 'World Development', '["Sarah K. Lowder","Jakob Skoet","Terri Raney"]', 'economics', 'Numerous sources provide evidence of trends and patterns in average farm size and farmland distribution worldwide, but they often lack documentation, are in some cases out of date, and do not provide comprehensive global and comparative regional estimates. This article uses agricultural census data (provided at the country level in Web Appendix) to show that there are more than 570 million farms worldwide, most of which are small and family-operated. It shows that small farms (less than 2 ha) operate about 12% and family farms about 75% of the world’s agricultural land. It shows that average farm size decreased in most low- and lower-middle-income countries for which data are available from 1960 to 2000, whereas average farm sizes increased from 1960 to 2000 in some upper-middle-income countries and in nearly all high-income countries for which we have information. Such estimates help inform agricultural development strategies, although the estimates are limited by the data available. Continued efforts to enhance the collection and dissemination of up-to date, comprehensive, and more standardized agricultural census data, including at the farm and national level, are essential to having a more representative picture of the number of farms, small farms, and family farms as well as changes in farm size and farmland distribution worldwide.', '2026-07-08 07:36:26');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2073034493', 'economics', 'Estimating the Global Burden of Endemic Canine Rabies', 'BACKGROUND: Rabies is a notoriously underreported and neglected disease of low-income countries. This study aims to estimate the public health and economic burden of rabies circulating in domestic…', '2015', 2015, 1822, 1822, 'https://journals.plos.org/plosntds/article/figure/image?size=large&id=10.1371/journal.pntd.0003709.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4400070', 'pmc', 'article', 'PLoS neglected tropical diseases', '["Katie Hampson","Laurent Coudeville","Tiziana Lembo","Maganga Sambo","Alexia Kieffer","Michaël Attlan","J Barrat","Jesse D. Blanton","Deborah J. Briggs","Sarah Cleaveland","Peter Costa","Conrad M. Freuling","Elly Hiby","Lea Knopf","Fernando Leanes","François-Xavier Meslin","Artem Metlin","Mary Elizabeth Miranda","Thomas Müller","Louis H. Nel","Sergio Recuenco","Charles E. Rupprecht","Carolin L. Schumacher","Louise Taylor","Marco Antonio Natal Vigilato","Jakob Zinsstag","Jonathan Dushoff","on behalf of the Global Alliance for Rabies Control Partners for Rabies Prevention"]', 'economics', 'BACKGROUND: Rabies is a notoriously underreported and neglected disease of low-income countries. This study aims to estimate the public health and economic burden of rabies circulating in domestic dog populations, globally and on a country-by-country basis, allowing an objective assessment of how much this preventable disease costs endemic countries. METHODOLOGY/PRINCIPAL FINDINGS: We established relationships between rabies mortality and rabies prevention and control measures, which we incorporated into a model framework. We used data derived from extensive literature searches and questionnaires on disease incidence, control interventions and preventative measures within this framework to estimate the disease burden. The burden of rabies impacts on public health sector budgets, local communities and livestock economies, with the highest risk of rabies in the poorest regions of the world. This study estimates that globally canine rabies causes approximately 59,000 (95% Confidence Intervals: 25-159,000) human deaths, over 3.7 million (95% CIs: 1.6-10.4 million) disability-adjusted life years (DALYs) and 8.6 billion USD (95% CIs: 2.9-21.5 billion) economic losses annually. The largest component of the economic burden is due to premature death (55%), followed by direct costs of post-exposure prophylaxis (PEP, 20%) and lost income whilst seeking PEP (15.5%), with only limited costs to the veterinary sector due to dog vaccination (1.5%), and additional costs to communities from livestock losses (6%). CONCLUSIONS/SIGNIFICANCE: This study demonstrates that investment in dog vaccination, the single most effective way of reducing the disease burden, has been inadequate and that the availability and affordability of PEP needs improving. Collaborative investments by medical and veterinary sectors could dramatically reduce the current large, and unnecessary, burden of rabies on affected communities. Improved surveillance is needed to reduce uncertainty in burden estimates and to monitor the impacts of control efforts.', '2026-07-08 07:37:03');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2983201012', 'economics', 'Contrasting Computational Models of Mate Preference Integration Across 45 Countries', 'Humans express a wide array of ideal mate preferences. Around the world, people desire romantic partners who are intelligent, healthy, kind, physically attractive, wealthy, and more. In order for…', '2019', 2019, 1775, 1775, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41598-019-52748-8/MediaObjects/41598_2019_52748_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6858324', 'pmc', 'article', 'Scientific Reports', '["Daniel Conroy‐Beam","David M. Buss","Kelly Asao","Agnieszka Sorokowska","Piotr Sorokowski","Toivo Aavik","Grace Akello","Mohammad Madallh Alhabahba","Charlotte Alm","Naumana Amjad","Afifa Anjum","Chiemezie S. Atama","Derya Atamtürk Duyar","Richard Ayebare","Carlota Batres","Mons Bendixen","Aicha Bensafia","Boris Bizumić","Mahmoud Boussena","Marina Butovskaya","Seda Can","Katarzyna Cantarero","Antonin Carrier","Hakan Çetınkaya","Ilona Croy","Rosa María Cueto","Marcin Czub","Daria Dronova","Seda Dural","İzzet Duyar","Berna Ertuğrul","Agustín Espinosa","Ignacio Estevan","Carla Sofia Esteves","Luxi Fang","Tomasz Frąckowiak","Jorge Contreras Garduño","Karina Ugalde González","Farida Guemaz","Petra Gyuris","Mária Haľamová","Iskra Herak","Marina Horvat","Ivana Hromatko","Chin Ming Hui","Jas Laile Jaafar","Feng Jiang","Konstantinos Kafetsios","Tina Kavčič","Leif Edward Ottesen Kennair","Nicolas Kervyn","Trương Thi Khanh Ha","Imran Ahmed Khilji","Nils Köbis","Hoang Moc Lan","András Láng","Georgina R. Lennard","Ernesto de León","Torun Lindholm","Trinh Thi Linh","Giulia Lopez","Nguyen Van Luot","Álvaro Mailhos","Zoi Manesi","Rocío Martínez","Sarah L. McKerchar","Norbert Meskó","Girishwar Misra","Conal Monaghan","Emanuel C. Mora","Alba Moya-Garófano","Bojan Musil","Jean Carlos Natividade","Agnieszka Niemczyk","George Nizharadze","Elisabeth Oberzaucher","Anna Oleszkiewicz","Mohd Sofian Omar Fauzee","Ike E. Onyishi","Barış Özener","Ariela Francesca Pagani","Vilmantė Pakalniškienė","Miriam Parise","Farid Pazhoohi","Annette Pisanski","Katarzyna Pisanski","Edna Lúcia Tinoco Ponciano","Camelia Popa","Pavol Prokop","Muhammad Rizwan","Mario Sainz","Svjetlana Salkičević","Rūta Sargautytė","Ivan Sarmány-Schuller","Susanne Schmehl","Shivantika Sharad","Razi Sultan Siddiqui","Franco Simonetti","Stanislava Stoyanova","Meri Tadinac"]', 'economics', 'Humans express a wide array of ideal mate preferences. Around the world, people desire romantic partners who are intelligent, healthy, kind, physically attractive, wealthy, and more. In order for these ideal preferences to guide the choice of actual romantic partners, human mating psychology must possess a means to integrate information across these many preference dimensions into summaries of the overall mate value of their potential mates. Here we explore the computational design of this mate preference integration process using a large sample of n = 14,487 people from 45 countries around the world. We combine this large cross-cultural sample with agent-based models to compare eight hypothesized models of human mating markets. Across cultures, people higher in mate value appear to experience greater power of choice on the mating market in that they set higher ideal standards, better fulfill their preferences in choice, and pair with higher mate value partners. Furthermore, we find that this cross-culturally universal pattern of mate choice is most consistent with a Euclidean model of mate preference integration.', '2026-07-08 07:37:32');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2114983539', 'economics', 'Biodiversity increases the resistance of ecosystem productivity to climate extremes', 'Biodiversity increases the resistance of ecosystem productivity to climate extremes', '2015', 2015, 1779, 1779, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature15374/MediaObjects/41586_2015_Article_BFnature15374_Fig1_HTML.jpg', 'https://ut3-toulouseinp.hal.science/hal-02959854', 'repository', 'article', 'Nature', '["Forest Isbell","Dylan Craven","John Connolly","Michel Loreau","Bernhard Schmid","Carl Beierkuhnlein","Т. Martijn Bezemer","Catherine L. Bonin","Helge Bruelheide","Enrica De Luca","Anne Ebeling","John N. Griffin","Qinfeng Guo","Yann Hautier","Andy Hector","Anke Jentsch","Jüergen Kreyling","Vojtěch Lanta","Peter Manning","Sebastian T. Meyer","Akira Mori","Shahid Naeem","Pascal A. Niklaus","H. Wayne Polley","Peter B. Reich","Christiane Roscher","Eric W. Seabloom","Melinda D. Smith","Madhav P. Thakur","David Tilman","Benjamin F. Tracy","Wim H. van der Putten","Jasper van Ruijven","Alexandra Weigelt","Wolfgang W. Weisser","Brian J. Wilsey","Nico Eisenhauer"]', 'economics', NULL, '2026-07-08 07:37:33');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2603785580', 'economics', 'Fintech, regulatory arbitrage, and the rise of shadow banks', 'Founded in 1920, the NBER is a private, non-profit, non-partisan organization dedicated to conducting economic research and to disseminating research findings among academics, public policy makers,…', '2018', 2018, 1714, 1714, 'https://ars.els-cdn.com/content/image/1-s2.0-S0304405X1830237X-gr1.jpg', 'https://doi.org/10.1016/j.jfineco.2018.03.011', 'repository', 'article', 'Journal of Financial Economics', '["Greg Buchak","Gregor Matvos","Tomasz Piskorski","Amit Seru"]', 'economics', 'Founded in 1920, the NBER is a private, non-profit, non-partisan organization dedicated to conducting economic research and to disseminating research findings among academics, public policy makers, and business professionals.', '2026-07-08 07:38:08');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2141119792', 'economics', 'The irace package: Iterated racing for automatic algorithm configuration', 'Modern optimization algorithms typically require the setting of a large number of parameters to optimize their performance. The immediate goal of automatic algorithm configuration is to find,…', '2016', 2016, 1690, 1690, 'https://ars.els-cdn.com/content/image/1-s2.0-S2214716015300270-fx1.jpg', 'https://doi.org/10.1016/j.orp.2016.09.002', 'repository', 'article', 'Operations Research Perspectives', '["Manuel López‐Ibáñez","Jérémie Dubois-Lacoste","Leslie Pérez Cáceres","Mauro Birattari","Thomas Stützle"]', 'economics', 'Modern optimization algorithms typically require the setting of a large number of parameters to optimize their performance. The immediate goal of automatic algorithm configuration is to find, automatically, the best parameter settings of an optimizer. Ultimately, automatic algorithm configuration has the potential to lead to new design paradigms for optimization software. The irace package is a software package that implements a number of automatic configuration procedures. In particular, it offers iterated racing procedures, which have been used successfully to automatically configure various state-of-the-art algorithms. The iterated racing procedures implemented in irace include the iterated F-race algorithm and several extensions and improvements over it. In this paper, we describe the rationale underlying the iterated racing procedures and introduce a number of recent extensions. Among these, we introduce a restart mechanism to avoid premature convergence, the use of truncated sampling distributions to handle correctly parameter bounds, and an elitist racing procedure for ensuring that the best configurations returned are also those evaluated in the highest number of training instances. We experimentally evaluate the most recent version of irace and demonstrate with a number of example applications the use and potential of irace, in particular, and automatic algorithm configuration, in general.', '2026-07-08 07:38:35');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2292048640', 'economics', 'Transferring the blues: Depression-associated gut microbiota induces neurobehavioural changes in the rat', 'Transferring the blues: Depression-associated gut microbiota induces neurobehavioural changes in the rat', '2016', 2016, 1685, 1685, 'https://ars.els-cdn.com/content/image/1-s2.0-S0022395616301571-gr1.jpg', 'https://pubmed.ncbi.nlm.nih.gov/27491067', 'repository', 'article', 'Journal of Psychiatric Research', '["John R. Kelly","Yuliya Borre","Ciaran O'' Brien","Elaine Patterson","Sahar El Aidy","Jennifer Deane","Paul J. Kennedy","S. Beers","Karen A. Scott","Gerard M. Moloney","Alan E. Hoban","Lucinda V. Scott","Patrick Fitzgerald","R. Paul Ross","Catherine Stanton","Gerard Clarke","John F. Cryan","Timothy G. Dinan"]', 'economics', NULL, '2026-07-08 07:38:37');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2473181783', 'economics', 'Healthcare Staff Wellbeing, Burnout, and Patient Safety: A Systematic Review', 'OBJECTIVE: To determine whether there is an association between healthcare professionals'' wellbeing and burnout, with patient safety. DESIGN: Systematic research review. DATA SOURCES: PsychInfo (1806…', '2016', 2016, 1636, 1636, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0159015.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4938539', 'pmc', 'review', 'PLoS ONE', '["Louise Hall","Judith Johnson","Ian Watt","Anastasia Tsipa","Daryl B. O’Connor"]', 'economics', 'OBJECTIVE: To determine whether there is an association between healthcare professionals'' wellbeing and burnout, with patient safety. DESIGN: Systematic research review. DATA SOURCES: PsychInfo (1806 to July 2015), Medline (1946 to July 2015), Embase (1947 to July 2015) and Scopus (1823 to July 2015) were searched, along with reference lists of eligible articles. ELIGIBILITY CRITERIA FOR SELECTING STUDIES: Quantitative, empirical studies that included i) either a measure of wellbeing or burnout, and ii) patient safety, in healthcare staff populations. RESULTS: Forty-six studies were identified. Sixteen out of the 27 studies that measured wellbeing found a significant correlation between poor wellbeing and worse patient safety, with six additional studies finding an association with some but not all scales used, and one study finding a significant association but in the opposite direction to the majority of studies. Twenty-one out of the 30 studies that measured burnout found a significant association between burnout and patient safety, whilst a further four studies found an association between one or more (but not all) subscales of the burnout measures employed, and patient safety. CONCLUSIONS: Poor wellbeing and moderate to high levels of burnout are associated, in the majority of studies reviewed, with poor patient safety outcomes such as medical errors, however the lack of prospective studies reduces the ability to determine causality. Further prospective studies, research in primary care, conducted within the UK, and a clearer definition of healthcare staff wellbeing are needed. IMPLICATIONS: This review illustrates the need for healthcare organisations to consider improving employees'' mental health as well as creating safer work environments when planning interventions to improve patient safety. SYSTEMATIC REVIEW REGISTRATION: PROSPERO registration number: CRD42015023340.', '2026-07-08 07:38:57');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4288083516', 'economics', 'The Open Images Dataset V4: Unified image classification, object detection, and visual relationship detection at scale', 'We present Open Images V4, a dataset of 9.2M images with unified annotations for image classification, object detection and visual relationship detection. The images have a Creative Commons…', '2018', 2018, 1622, 1622, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1007%2Fs11263-020-01316-z/MediaObjects/11263_2020_1316_Fig1_HTML.png', 'http://arxiv.org/abs/1811.00982', 'arxiv', 'article', 'arXiv (Cornell University)', '["Alina Kuznetsova","Hassan Rom","Neil Alldrin","Jasper Uijlings","Ivan Krasin","Jordi Pont-Tuset","Shahab Kamali","Stefan Popov","Matteo Malloci","Alexander Kolesnikov","Tom Duerig","Vittorio Ferrari"]', 'economics', 'We present Open Images V4, a dataset of 9.2M images with unified annotations for image classification, object detection and visual relationship detection. The images have a Creative Commons Attribution license that allows to share and adapt the material, and they have been collected from Flickr without a predefined list of class names or tags, leading to natural class statistics and avoiding an initial design bias. Open Images V4 offers large scale across several dimensions: 30.1M image-level labels for 19.8k concepts, 15.4M bounding boxes for 600 object classes, and 375k visual relationship annotations involving 57 classes. For object detection in particular, we provide 15x more bounding boxes than the next largest datasets (15.4M boxes on 1.9M images). The images often show complex scenes with several objects (8 annotated objects per image on average). We annotated visual relationships between them, which support visual relationship detection, an emerging task that requires structured reasoning. We provide in-depth comprehensive statistics about the dataset, we validate the quality of the annotations, we study how the performance of several modern models evolves with increasing amounts of training data, and we demonstrate two applications made possible by having unified annotations of multiple types coexisting in the same images. We hope that the scale, quality, and variety of Open Images V4 will foster further research and innovation even beyond the areas of image classification, object detection, and visual relationship detection.', '2026-07-08 07:39:18');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2558941103', 'economics', 'Will 10 Million People Die a Year due to Antimicrobial Resistance by 2050?', 'A recent high profile report estimates that, by 2050, 10 million people will die every year due to antimicrobial resistance (AMR) unless a global response to the problem of AMR is mounted.', '2016', 2016, 1581, 1581, 'https://journals.plos.org/plosmedicine/article/figure/image?size=large&id=10.1371/journal.pmed.1002184.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5127510', 'pmc', 'article', 'PLoS Medicine', '["Marlieke E.A. de Kraker","Andrew J. Stewardson","Stéphan Harbarth"]', 'economics', 'A recent high profile report estimates that, by 2050, 10 million people will die every year due to antimicrobial resistance (AMR) unless a global response to the problem of AMR is mounted.', '2026-07-08 07:39:43');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2985543011', 'economics', 'Principles alone cannot guarantee ethical AI', 'Principles alone cannot guarantee ethical AI', '2019', 2019, 1560, 1560, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1057%2Fs41599-026-07957-8/MediaObjects/41599_2026_7957_Fig1_HTML.png', 'http://arxiv.org/abs/1906.06668', 'arxiv', 'article', 'Nature Machine Intelligence', '["Brent Mittelstadt"]', 'economics', NULL, '2026-07-08 07:40:00');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2770934685', 'economics', 'A review of the use of virtual reality head-mounted displays in education and training', 'A review of the use of virtual reality head-mounted displays in education and training', '2017', 2017, 1463, 1463, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1007%2Fs10758-020-09489-9/MediaObjects/10758_2020_9489_Fig1_HTML.png', 'https://doi.org/10.1007/s10639-017-9676-0', 'repository', 'review', 'Education and Information Technologies', '["Lasse X Jensen","Flemming Konradsen"]', 'economics', NULL, '2026-07-08 07:41:34');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3128490572', 'economics', 'Hydrogen production from water electrolysis: role of catalysts', 'As a promising substitute for fossil fuels, hydrogen has emerged as a clean and renewable energy. A key challenge is the efficient production of hydrogen to meet the commercial-scale demand of…', '2021', 2021, 1456, 1456, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs40580-021-00254-x/MediaObjects/40580_2021_254_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7878665', 'pmc', 'review', 'Nano Convergence', '["Shan Wang","Aolin Lu","Chuan‐Jian Zhong"]', 'economics', 'As a promising substitute for fossil fuels, hydrogen has emerged as a clean and renewable energy. A key challenge is the efficient production of hydrogen to meet the commercial-scale demand of hydrogen. Water splitting electrolysis is a promising pathway to achieve the efficient hydrogen production in terms of energy conversion and storage in which catalysis or electrocatalysis plays a critical role. The development of active, stable, and low-cost catalysts or electrocatalysts is an essential prerequisite for achieving the desired electrocatalytic hydrogen production from water splitting for practical use, which constitutes the central focus of this review. It will start with an introduction of the water splitting performance evaluation of various electrocatalysts in terms of activity, stability, and efficiency. This will be followed by outlining current knowledge on the two half-cell reactions, hydrogen evolution reaction (HER) and oxygen evolution reaction (OER), in terms of reaction mechanisms in alkaline and acidic media. Recent advances in the design and preparation of nanostructured noble-metal and non-noble metal-based electrocatalysts will be discussed. New strategies and insights in exploring the synergistic structure, morphology, composition, and active sites of the nanostructured electrocatalysts for increasing the electrocatalytic activity and stability in HER and OER will be highlighted. Finally, future challenges and perspectives in the design of active and robust electrocatalysts for HER and OER towards efficient production of hydrogen from water splitting electrolysis will also be outlined.', '2026-07-08 07:41:35');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3022416583', 'economics', 'COVID-19 pandemic, oil prices, stock market, geopolitical risk and policy uncertainty nexus in the US economy: Fresh evidence from the wavelet-based approach', 'COVID-19 pandemic, oil prices, stock market, geopolitical risk and policy uncertainty nexus in the US economy: Fresh evidence from the wavelet-based approach', '2020', 2020, 1449, 1449, 'https://ars.els-cdn.com/content/image/1-s2.0-S105752192030140X-gr1.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7227524', 'pmc', 'article', 'International Review of Financial Analysis', '["Arshian Sharif","Chaker Aloui","Larisa Yarovaya"]', 'economics', NULL, '2026-07-08 07:41:48');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3017452399', 'economics', 'Refined Measures of Dynamic Connectedness based on Time-Varying Parameter Vector Autoregressions', 'In this study, we enhance the dynamic connectedness measures originally introduced by Diebold and Yılmaz (2012, 2014) with a time-varying parameter vector autoregressive model (TVP-VAR) which…', '2020', 2020, 1441, 1441, 'https://pub.mdpi-res.com/jrfm/jrfm-13-00084/article_deploy/html/images/jrfm-13-00084-g001.png', 'https://www.mdpi.com/1911-8074/13/4/84/pdf?version=1587725484', 'repository', 'article', 'Journal of risk and financial management', '["Nikolaos Antonakakis","Ioannis Chatziantoniou","David Gabauer"]', 'economics', 'In this study, we enhance the dynamic connectedness measures originally introduced by Diebold and Yılmaz (2012, 2014) with a time-varying parameter vector autoregressive model (TVP-VAR) which predicates upon a time-varying variance-covariance structure. This framework allows to capture possible changes in the underlying structure of the data in a more flexible and robust manner. Specifically, there is neither a need to arbitrarily set the rolling-window size nor a loss of observations in the calculation of the dynamic measures of connectedness, as no rolling-window analysis is involved. Given that the proposed framework rests on multivariate Kalman filters, it is less sensitive to outliers. Furthermore, we emphasise the merits of this approach by conducting Monte Carlo simulations. We put our framework into practice by investigating dynamic connectedness measures of the four most traded foreign exchange rates, comparing the TVP-VAR results to those obtained from three different rolling-window settings. Finally, we propose uncertainty measures for both TVP-VAR-based and rolling-window VAR-based dynamic connectedness measures.', '2026-07-08 07:41:59');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2363378650', 'economics', 'Policy mixes for sustainability transitions: An extended concept and framework for analysis', 'Reaching a better understanding of the policies and politics of transitions presents a main agenda item in the emerging field of sustainability transitions. One important requirement for these…', '2016', 2016, 1381, 1381, 'https://ars.els-cdn.com/content/image/1-s2.0-S0048733316300506-fx1.jpg', 'https://doi.org/10.1016/j.respol.2016.04.004', 'repository', 'article', 'Research Policy', '["Karoline S. Rogge","Kristin Reichardt"]', 'economics', 'Reaching a better understanding of the policies and politics of transitions presents a main agenda item in the emerging field of sustainability transitions. One important requirement for these transitions, such as the move towards a decarbonized energy system, is the redirection and acceleration of technological change, for which policies play a key role. In this regard, several studies have argued for the need to combine different policy instruments in so-called policy mixes. However, existing policy mix studies often fall short of reflecting the complexity and dynamics of actual policy mixes, the underlying politics and the evaluation of their impacts. In this paper we take a first step towards an extended, interdisciplinary policy mix concept based on a review of the bodies of literature on innovation studies, environmental economics and policy analysis. The concept introduces a clear terminology and consists of the three building blocks elements, policy processes and characteristics, which can be delineated by several dimensions. Based on this, we discuss its application as analytical framework for empirical studies analyzing the impact of the policy mix on technological change. Throughout the paper we illustrate the proposed concept by using the example of the policy mix for fostering the transition of the German energy system to renewable power generation technologies. Finally, we derive policy implications and suggest avenues for future research.', '2026-07-08 07:43:01');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2517745273', 'economics', 'How to improve firm performance using big data analytics capability and business strategy alignment?', 'How to improve firm performance using big data analytics capability and business strategy alignment?', '2016', 2016, 1373, 1373, 'https://ars.els-cdn.com/content/image/1-s2.0-S0925527316302110-fx1.jpg', 'https://doi.org/10.1016/j.ijpe.2016.08.018', 'repository', 'article', 'International Journal of Production Economics', '["Shahriar Akter","Samuel Fosso Wamba","Angappa Gunasekaran","Rameshwar Dubey","Stephen J. Childe"]', 'economics', NULL, '2026-07-08 07:43:01');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3020855431', 'economics', 'Industry 4.0 technologies assessment: A sustainability perspective', 'The fourth industrial revolution, also labelled Industry 4.0, was beget with emergent and disruptive intelligence and information technologies. These new technologies are enabling ever-higher levels…', '2020', 2020, 1365, 1365, 'https://ars.els-cdn.com/content/image/1-s2.0-S0925527320301559-gr1.jpg', 'https://doi.org/10.1016/j.ijpe.2020.107776', 'repository', 'article', 'International Journal of Production Economics', '["Chunguang Bai","Patrick Dallasega","Guido Orzes","Joseph Sarkis"]', 'economics', 'The fourth industrial revolution, also labelled Industry 4.0, was beget with emergent and disruptive intelligence and information technologies. These new technologies are enabling ever-higher levels of production efficiencies. They also have the potential to dramatically influence social and environmental sustainable development. Organizations need to consider Industry 4.0 technologies contribution to sustainability. Sufficient guidance, in this respect, is lacking in the scholarly or practitioner literature. In this study, we further examine Industry 4.0 technologies in terms of application and sustainability implications. We introduce a measures framework for sustainability based on the United Nations Sustainable Development Goals; incorporating various economic, environmental and social attributes. We also develop a hybrid multi-situation decision method integrating hesitant fuzzy set, cumulative prospect theory and VIKOR. This method can effectively evaluate Industry 4.0 technologies based on their sustainable performance and application. We apply the method using secondary case information from a report of the World Economic Forum. The results show that mobile technology has the greatest impact on sustainability in all industries, and nanotechnology, mobile technology, simulation and drones have the highest impact on sustainability in the automotive, electronics, food and beverage, and textile, apparel and footwear industries, respectively. Our recommendation is to take advantage of Industry 4.0 technology adoption to improve sustainability impact but each technology needs to be carefully evaluated as specific technology will variably influence industry and sustainability dimensions. Investment in such technologies should consider appropriate priority investment and championing.', '2026-07-08 07:43:13');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3162877622', 'economics', 'The Impact of Climate Change on Agricultural Insect Pests', 'levels, and changing precipitation patterns have significant impacts on agricultural production and on agricultural insect pests. Changes in climate can affect insect pests in several ways. They can…', '2021', 2021, 1359, 1359, 'https://pub.mdpi-res.com/insects/insects-12-00440/article_deploy/html/images/insects-12-00440-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8150874', 'pmc', 'review', 'Insects', '["Sandra Skendžić","Monika Zovko","Ivana Pajač Živković","Vinko Lešić","Darija Lemić"]', 'economics', 'levels, and changing precipitation patterns have significant impacts on agricultural production and on agricultural insect pests. Changes in climate can affect insect pests in several ways. They can result in an expansion of their geographic distribution, increased survival during overwintering, increased number of generations, altered synchrony between plants and pests, altered interspecific interaction, increased risk of invasion by migratory pests, increased incidence of insect-transmitted plant diseases, and reduced effectiveness of biological control, especially natural enemies. As a result, there is a serious risk of crop economic losses, as well as a challenge to human food security. As a major driver of pest population dynamics, climate change will require adaptive management strategies to deal with the changing status of pests. Several priorities can be identified for future research on the effects of climatic changes on agricultural insect pests. These include modified integrated pest management tactics, monitoring climate and pest populations, and the use of modelling prediction tools.', '2026-07-08 07:43:17');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2615010047', 'economics', 'The threat of antimicrobial resistance in developing countries: causes and control strategies', 'The causes of antimicrobial resistance (AMR) in developing countries are complex and may be rooted in practices of health care professionals and patients'' behavior towards the use of antimicrobials…', '2017', 2017, 1332, 1332, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs13756-018-0351-z/MediaObjects/13756_2018_351_Fig1_HTML.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5433038', 'pmc', 'review', 'Antimicrobial Resistance and Infection Control', '["James A. Ayukekbong","Michel Ntemgwa","Andrew N. Atabe"]', 'economics', 'The causes of antimicrobial resistance (AMR) in developing countries are complex and may be rooted in practices of health care professionals and patients'' behavior towards the use of antimicrobials as well as supply chains of antimicrobials in the population. Some of these factors may include inappropriate prescription practices, inadequate patient education, limited diagnostic facilities, unauthorized sale of antimicrobials, lack of appropriate functioning drug regulatory mechanisms, and non-human use of antimicrobials such as in animal production. Considering that these factors in developing countries may vary from those in developed countries, intervention efforts in developing countries need to address the context and focus on the root causes specific to this part of the world. Here, we describe these health-seeking behaviors that lead to the threat of AMR and healthcare practices that drive the development of AMR in developing countries and we discuss alternatives for disease prevention as well as other treatment options worth exploring.', '2026-07-08 07:43:43');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2530254150', 'economics', 'The wood from the trees: The use of timber in construction', 'Trees, and their derivative products, have been used by societies around the world for thousands of years. Contemporary construction of tall buildings from timber, in whole or in part, suggests a…', '2016', 2016, 1328, 1328, 'https://ars.els-cdn.com/content/image/1-s2.0-S1364032116306050-gr1.jpg', 'https://doi.org/10.1016/j.rser.2016.09.107', 'repository', 'article', 'Renewable and Sustainable Energy Reviews', '["Michael H. Ramage","Henry C. Burridge","Marta Busse‐Wicher","George Fereday","Thomas Reynolds","Darshil U. Shah","Guanglu Wu","Li Yu","Patrick H. Fleming","Danielle Densley Tingley","Julian M. Allwood","Paul Dupree","P. F. Linden","Oren A. Scherman"]', 'economics', 'Trees, and their derivative products, have been used by societies around the world for thousands of years. Contemporary construction of tall buildings from timber, in whole or in part, suggests a growing interest in the potential for building with wood at a scale not previously attainable. As wood is the only significant building material that is grown, we have a natural inclination that building in wood is good for the environment. But under what conditions is this really the case? The environmental benefits of using timber are not straightforward; although it is a natural product, a large amount of energy is used to dry and process it. Much of this can come from the biomass of the tree itself, but that requires investment in plant, which is not always possible in an industry that is widely distributed among many small producers. And what should we build with wood? Are skyscrapers in timber a good use of this natural resource, or are there other aspects of civil and structural engineering, or large-scale infrastructure, that would be a better use of wood? Here, we consider a holistic picture ranging in scale from the science of the cell wall to the engineering and global policies that could maximise forestry and timber construction as a boon to both people and the planet.', '2026-07-08 07:44:01');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W578603601', 'economics', 'Updated Global Burden of Cholera in Endemic Countries', 'BACKGROUND: The global burden of cholera is largely unknown because the majority of cases are not reported. The low reporting can be attributed to limited capacity of epidemiological surveillance and…', '2015', 2015, 1314, 1314, 'https://journals.plos.org/plosntds/article/figure/image?size=large&id=10.1371/journal.pntd.0003832.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4455997', 'pmc', 'article', 'PLoS neglected tropical diseases', '["Mohammad Ali","Allyson R. Nelson","Anna Lena Lopez","David A. Sack"]', 'economics', 'BACKGROUND: The global burden of cholera is largely unknown because the majority of cases are not reported. The low reporting can be attributed to limited capacity of epidemiological surveillance and laboratories, as well as social, political, and economic disincentives for reporting. We previously estimated 2.8 million cases and 91,000 deaths annually due to cholera in 51 endemic countries. A major limitation in our previous estimate was that the endemic and non-endemic countries were defined based on the countries'' reported cholera cases. We overcame the limitation with the use of a spatial modelling technique in defining endemic countries, and accordingly updated the estimates of the global burden of cholera. METHODS/PRINCIPAL FINDINGS: Countries were classified as cholera endemic, cholera non-endemic, or cholera-free based on whether a spatial regression model predicted an incidence rate over a certain threshold in at least three of five years (2008-2012). The at-risk populations were calculated for each country based on the percent of the country without sustainable access to improved sanitation facilities. Incidence rates from population-based published studies were used to calculate the estimated annual number of cases in endemic countries. The number of annual cholera deaths was calculated using inverse variance-weighted average case-fatality rate (CFRs) from literature-based CFR estimates. We found that approximately 1.3 billion people are at risk for cholera in endemic countries. An estimated 2.86 million cholera cases (uncertainty range: 1.3m-4.0m) occur annually in endemic countries. Among these cases, there are an estimated 95,000 deaths (uncertainty range: 21,000-143,000). CONCLUSION/SIGNIFICANCE: The global burden of cholera remains high. Sub-Saharan Africa accounts for the majority of this burden. Our findings can inform programmatic decision-making for cholera control.', '2026-07-08 07:44:09');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2193984671', 'economics', 'The sharing economy: A pathway to sustainability or a nightmarish form of neoliberal capitalism?', 'The sharing economy: A pathway to sustainability or a nightmarish form of neoliberal capitalism?', '2015', 2015, 1308, 1308, 'https://ars.els-cdn.com/content/image/1-s2.0-S0921800915004711-gr1.jpg', 'https://doi.org/10.1016/j.ecolecon.2015.11.027', 'repository', 'article', 'Ecological Economics', '["C. Martin"]', 'economics', NULL, '2026-07-08 07:44:28');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2771030840', 'economics', 'Exploring the dynamic relationships between cryptocurrencies and other financial assets', 'Exploring the dynamic relationships between cryptocurrencies and other financial assets', '2018', 2018, 1309, 1309, 'https://ars.els-cdn.com/content/image/1-s2.0-S0165176518300041-gr1.jpg', 'https://doi.org/10.1016/j.econlet.2018.01.004', 'repository', 'article', 'Economics Letters', '["Shaen Corbet","Andrew Meegan","Charles Larkin","Brian M. Lucey","Larisa Yarovaya"]', 'economics', NULL, '2026-07-08 07:44:28');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3120894151', 'economics', 'Deep learning-enabled medical computer vision', 'A decade of unprecedented progress in artificial intelligence (AI) has demonstrated the potential for many fields-including medicine-to benefit from the insights that AI techniques can extract from…', '2021', 2021, 1293, 1293, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41746-020-00376-2/MediaObjects/41746_2020_376_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7794558', 'pmc', 'review', 'npj Digital Medicine', '["Andre Esteva","Katherine Chou","Serena Yeung","Nikhil Naik","Ali Madani","Ali Mottaghi","Yun Liu","Eric J. Topol","Jeff Dean","Richard Socher"]', 'economics', 'A decade of unprecedented progress in artificial intelligence (AI) has demonstrated the potential for many fields-including medicine-to benefit from the insights that AI techniques can extract from data. Here we survey recent progress in the development of modern computer vision techniques-powered by deep learning-for medical applications, focusing on medical imaging, medical video, and clinical deployment. We start by briefly summarizing a decade of progress in convolutional neural networks, including the vision tasks they enable, in the context of healthcare. Next, we discuss several example medical imaging applications that stand to benefit-including cardiology, pathology, dermatology, ophthalmology-and propose new avenues for continued work. We then expand into general medical video, highlighting ways in which clinical workflows can integrate computer vision to enhance care. Finally, we discuss the challenges and hurdles required for real-world clinical deployment of these technologies.', '2026-07-08 07:44:38');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3171801815', 'economics', 'The burden of heat-related mortality attributable to recent human-induced climate change', 'Climate change affects human health; however, there have been no large-scale, systematic efforts to quantify the heat-related human health impacts that have already occurred due to climate change.…', '2021', 2021, 1292, 1292, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41558-021-01058-x/MediaObjects/41558_2021_1058_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7611104', 'pmc', 'article', 'Nature Climate Change', '["Ana M. Vicedo‐Cabrera","Noah Scovronick","Francesco Sera","Dominic Royé","Rochelle Schneider","Aurelio Tobı́as","Christofer Åström","Yuming Guo","Yasushi Honda","David M. Hondula","Rosana Abrutzky","Shilu Tong","Micheline de Sousa Zanotti Stagliorio Coêlho","Paulo Hilário Nascimento Saldiva","Éric Lavigne","Patricia Matus Correa","Nicolás Valdés Ortega","Haidong Kan","Samuel Osorio","Jan Kyselý","Aleš Urban","Hans Orru","Ene Indermitte","Jouni J. K. Jaakkola","Niilo Ryti","Mathilde Pascal","Alexandra Schneider","Klea Katsouyanni","Evangelia Samoli","Fatemeh Mayvaneh","Alireza Entezari","Patrick Goodman","Ariana Zeka","Paola Michelozzi","Francesca de’Donato","Masahiro Hashizume","Barrak Alahmad","Magali Hurtado‐Díaz","César De la Cruz Valencia","Ala Overcenco","Danny Houthuijs","Caroline Ameling","Shilpa Rao","Francesco Di Ruscio","Gabriel Carrasco‐Escobar","Xerxes Seposo","Susana Pereira Silva","Joana Madureira","Iulian‐Horia Holobâcă","Simona Fratianni","Fiorella Acquaotta","Ho Kim","Whanhee Lee","Carmen Íñiguez","Bertil Forsberg","Martina S. Ragettli","Yue Leon Guo","Bing-yu Chen","Shanshan Li","Ben Armstrong","Alicia V Aleman","Antonella Zanobetti","Joel Schwartz","Trần Ngọc Đăng","Do Van Dung","Nathan P. Gillett","Andy Haines","Matthias Mengel","Veronika Huber","Antonio Gasparrini"]', 'economics', 'Climate change affects human health; however, there have been no large-scale, systematic efforts to quantify the heat-related human health impacts that have already occurred due to climate change. Here, we use empirical data from 732 locations in 43 countries to estimate the mortality burdens associated with the additional heat exposure that has resulted from recent human-induced warming, during the period 1991–2018. Across all study countries, we find that 37.0% (range 20.5–76.3%) of warm-season heat-related deaths can be attributed to anthropogenic climate change and that increased mortality is evident on every continent. Burdens varied geographically but were of the order of dozens to hundreds of deaths per year in many locations. Our findings support the urgent need for more ambitious mitigation and adaptation strategies to minimize the public health impacts of climate change. Current and future climate change is expected to impact human health, both indirectly and directly, through increasing temperatures. Climate change has already had an impact and is responsible for 37% of warm-season heat-related deaths between 1991 and 2018, with increases in mortality observed globally.', '2026-07-08 07:44:39');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2739100911', 'economics', 'A framework for assessing and implementing the co-benefits of nature-based solutions in urban areas', 'To address challenges associated with climate resilience, health and well-being in urban areas, current policy platforms are shifting their focus from ecosystem-based to nature-based solutions (NBS),…', '2017', 2017, 1262, 1262, 'https://ars.els-cdn.com/content/image/1-s2.0-S1462901117306317-fx1.jpg', 'https://doi.org/10.1016/j.envsci.2017.07.008', 'repository', 'article', 'Environmental Science & Policy', '["Christopher M. Raymond","Niki Frantzeskaki","Nadja Kabisch","Pam Berry","Margaretha Breil","Mihai Răzvan Niţă","Davide Geneletti","Carlo Calfapietra"]', 'economics', 'To address challenges associated with climate resilience, health and well-being in urban areas, current policy platforms are shifting their focus from ecosystem-based to nature-based solutions (NBS), broadly defined as solutions to societal challenges that are inspired and supported by nature. NBS result in the provision of co-benefits, such as the improvement of place attractiveness, of health and quality of life, and creation of green jobs. Few frameworks exist for acknowledging and assessing the value of such co-benefits of NBS and to guide cross-sectoral project and policy design and implementation. In this paper, we firstly developed a holistic framework for assessing co-benefits (and costs) of NBS across elements of socio-cultural and socio-economic systems, biodiversity, ecosystems and climate. The framework was guided by a review of over 1700 documents from science and practice within and across 10 societal challenges relevant to cities globally. We found that NBS can have environmental, social and economic co-benefits and/or costs both within and across these 10 societal challenges. On that base, we develop and propose a seven-stage process for situating co-benefit assessment within policy and project implementation. The seven stages include: 1) identify problem or opportunity; 2) select and assess NBS and related actions; 3) design NBS implementation processes; 4) implement NBS; 5) frequently engage stakeholders and communicate co-benefits; 6) transfer and upscale NBS; and 7) monitor and evaluate co-benefits across all stages. We conclude that the developed framework together with the seven-stage co-benefit assessment process represent a valuable tool for guiding thinking and identifying the multiple values of NBS implementation.', '2026-07-08 07:45:06');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3026117698', 'economics', 'Stock markets’ reaction to COVID-19: Cases or fatalities?', 'Stock markets’ reaction to COVID-19: Cases or fatalities?', '2020', 2020, 1264, 1264, 'https://ars.els-cdn.com/content/image/1-s2.0-S0275531920304141-ga1.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7244441', 'pmc', 'article', 'Research in International Business and Finance', '["Badar Nadeem Ashraf"]', 'economics', NULL, '2026-07-08 07:45:07');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2618653913', 'economics', 'Pathways to zoonotic spillover', 'Pathways to zoonotic spillover', '2017', 2017, 1250, 1250, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnrmicro.2017.45/MediaObjects/41579_2017_Article_BFnrmicro201745_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5791534', 'pmc', 'review', 'Nature Reviews Microbiology', '["Raina K. Plowright","Colin R. Parrish","Hamish McCallum","Peter J. Hudson","Albert I. Ko","Andrea L. Graham","James O. Lloyd‐Smith"]', 'economics', NULL, '2026-07-08 07:45:35');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3161021559', 'economics', 'Health systems resilience in managing the COVID-19 pandemic: lessons from 28 countries', 'Health systems resilience in managing the COVID-19 pandemic: lessons from 28 countries', '2021', 2021, 1256, 1256, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41591-021-01381-y/MediaObjects/41591_2021_1381_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/34002090', 'repository', 'review', 'Nature Medicine', '["Victoria Haldane","Chuan De Foo","Salma M. Abdalla","Anne-Sophie Jung","Melisa Mei Jin Tan","Shishi Wu","Alvin Qijia Chua","Monica Verma","Pami Shrestha","Sudhvir Singh","Tristana Perez","See Mieng Tan","Michael Bartoš","Shunsuke Mabuchi","Mathias Bonk","Christine McNab","George K. Werner","Raj Panjabi","Anders Nordström","Helena Legido‐Quigley"]', 'economics', NULL, '2026-07-08 07:45:36');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2623703952', 'psychology', 'The Use of Cronbach’s Alpha When Developing and Reporting Research Instruments in Science Education', 'Cronbach’s alpha is a statistic commonly quoted by authors to demonstrate that tests and scales that have been constructed or adopted for research projects are fit for purpose. Cronbach’s alpha is…', '2017', 2017, 10201, 10201, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1007%2Fs10648-024-09982-y/MediaObjects/10648_2024_9982_Fig1_HTML.png', 'https://doi.org/10.1007/s11165-016-9602-2', 'repository', 'article', 'Research in Science Education', '["Keith S. Taber"]', 'psychology', 'Cronbach’s alpha is a statistic commonly quoted by authors to demonstrate that tests and scales that have been constructed or adopted for research projects are fit for purpose. Cronbach’s alpha is regularly adopted in studies in science education: it was referred to in 69 different papers published in 4 leading science education journals in a single year (2015)—usually as a measure of reliability. This article explores how this statistic is used in reporting science education research and what it represents. Authors often cite alpha values with little commentary to explain why they feel this statistic is relevant and seldom interpret the result for readers beyond citing an arbitrary threshold for an acceptable value. Those authors who do offer readers qualitative descriptors interpreting alpha values adopt a diverse and seemingly arbitrary terminology. More seriously, illustrative examples from the science education literature demonstrate that alpha may be acceptable even when there are recognised problems with the scales concerned. Alpha is also sometimes inappropriately used to claim an instrument is unidimensional. It is argued that a high value of alpha offers limited evidence of the reliability of a research instrument, and that indeed a very high value may actually be undesirable when developing a test of scientific knowledge or understanding. Guidance is offered to authors reporting, and readers evaluating, studies that present Cronbach’s alpha statistic as evidence of instrument quality.', '2026-07-08 07:46:06');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2337323496', 'psychology', 'DPABI: Data Processing &amp; Analysis for (Resting-State) Brain Imaging', 'DPABI: Data Processing &amp; Analysis for (Resting-State) Brain Imaging', '2016', 2016, 3833, 3833, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1007%2Fs10916-019-1212-x/MediaObjects/10916_2019_1212_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/27075850', 'repository', 'article', 'Neuroinformatics', '["Chao‐Gan Yan","Xindi Wang","Xi‐Nian Zuo","Yu‐Feng Zang"]', 'psychology', NULL, '2026-07-08 07:47:24');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2585292421', 'psychology', 'Beyond the Turk: Alternative platforms for crowdsourcing behavioral research', 'Beyond the Turk: Alternative platforms for crowdsourcing behavioral research', '2017', 2017, 2972, 2972, 'https://ars.els-cdn.com/content/image/1-s2.0-S0022103116303201-fx1.jpg', 'http://api.osf.io/v2/nodes/murdt/', 'repository', 'article', 'Journal of Experimental Social Psychology', '["Eyal Peer","Laura Brandimarte","Sonam Samat","Alessandro Acquisti"]', 'psychology', NULL, '2026-07-08 07:48:39');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1974527622', 'psychology', 'Future Coastal Population Growth and Exposure to Sea-Level Rise and Coastal Flooding - A Global Assessment', 'Coastal zones are exposed to a range of coastal hazards including sea-level rise with its related effects. At the same time, they are more densely populated than the hinterland and exhibit higher…', '2015', 2015, 2817, 2817, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0118571.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4367969', 'pmc', 'article', 'PLoS ONE', '["Barbara Neumann","Athanasios T. Vafeidis","Juliane Zimmermann","Robert J. Nicholls"]', 'psychology', 'Coastal zones are exposed to a range of coastal hazards including sea-level rise with its related effects. At the same time, they are more densely populated than the hinterland and exhibit higher rates of population growth and urbanisation. As this trend is expected to continue into the future, we investigate how coastal populations will be affected by such impacts at global and regional scales by the years 2030 and 2060. Starting from baseline population estimates for the year 2000, we assess future population change in the low-elevation coastal zone and trends in exposure to 100-year coastal floods based on four different sea-level and socio-economic scenarios. Our method accounts for differential growth of coastal areas against the land-locked hinterland and for trends of urbanisation and expansive urban growth, as currently observed, but does not explicitly consider possible displacement or out-migration due to factors such as sea-level rise. We combine spatially explicit estimates of the baseline population with demographic data in order to derive scenario-driven projections of coastal population development. Our scenarios show that the number of people living in the low-elevation coastal zone, as well as the number of people exposed to flooding from 1-in-100 year storm surge events, is highest in Asia. China, India, Bangladesh, Indonesia and Viet Nam are estimated to have the highest total coastal population exposure in the baseline year and this ranking is expected to remain largely unchanged in the future. However, Africa is expected to experience the highest rates of population growth and urbanisation in the coastal zone, particularly in Egypt and sub-Saharan countries in Western and Eastern Africa. The results highlight countries and regions with a high degree of exposure to coastal flooding and help identifying regions where policies and adaptive planning for building resilient coastal communities are not only desirable but essential. Furthermore, we identify needs for further research and scope for improvement in this kind of scenario-based exposure analysis.', '2026-07-08 07:48:49');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4327946446', 'psychology', 'ChatGPT Utility in Healthcare Education, Research, and Practice: Systematic Review on the Promising Perspectives and Valid Concerns', 'ChatGPT is an artificial intelligence (AI)-based conversational large language model (LLM). The potential applications of LLMs in health care education, research, and practice could be promising if…', '2023', 2023, 2740, 2740, 'https://pub.mdpi-res.com/healthcare/healthcare-11-00887/article_deploy/html/images/healthcare-11-00887-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/10048148', 'pmc', 'review', 'Healthcare', '["Malik Sallam"]', 'psychology', 'ChatGPT is an artificial intelligence (AI)-based conversational large language model (LLM). The potential applications of LLMs in health care education, research, and practice could be promising if the associated valid concerns are proactively examined and addressed. The current systematic review aimed to investigate the utility of ChatGPT in health care education, research, and practice and to highlight its potential limitations. Using the PRIMSA guidelines, a systematic search was conducted to retrieve English records in PubMed/MEDLINE and Google Scholar (published research or preprints) that examined ChatGPT in the context of health care education, research, or practice. A total of 60 records were eligible for inclusion. Benefits of ChatGPT were cited in 51/60 (85.0%) records and included: (1) improved scientific writing and enhancing research equity and versatility; (2) utility in health care research (efficient analysis of datasets, code generation, literature reviews, saving time to focus on experimental design, and drug discovery and development); (3) benefits in health care practice (streamlining the workflow, cost saving, documentation, personalized medicine, and improved health literacy); and (4) benefits in health care education including improved personalized learning and the focus on critical thinking and problem-based learning. Concerns regarding ChatGPT use were stated in 58/60 (96.7%) records including ethical, copyright, transparency, and legal issues, the risk of bias, plagiarism, lack of originality, inaccurate content with risk of hallucination, limited knowledge, incorrect citations, cybersecurity issues, and risk of infodemics. The promising applications of ChatGPT can induce paradigm shifts in health care education, research, and practice. However, the embrace of this AI chatbot should be conducted with extreme caution considering its potential limitations. As it currently stands, ChatGPT does not qualify to be listed as an author in scientific articles unless the ICMJE/COPE guidelines are revised or amended. An initiative involving all stakeholders in health care education, research, and practice is urgently needed. This will help to set a code of ethics to guide the responsible use of ChatGPT among other LLMs in health care and academia.', '2026-07-08 07:49:27');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2195703978', 'psychology', 'Racism as a Determinant of Health: A Systematic Review and Meta-Analysis', 'Despite a growing body of epidemiological evidence in recent years documenting the health impacts of racism, the cumulative evidence base has yet to be synthesized in a comprehensive meta-analysis…', '2015', 2015, 2603, 2603, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0138511.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4580597', 'pmc', 'review', 'PLoS ONE', '["Yin Paradies","Jehonathan Ben","Nida Denson","Amanuel Elias","Naomi Priest","Alex L. Pieterse","Arpana Gupta","Margaret Kelaher","Gilbert C. Gee"]', 'psychology', 'Despite a growing body of epidemiological evidence in recent years documenting the health impacts of racism, the cumulative evidence base has yet to be synthesized in a comprehensive meta-analysis focused specifically on racism as a determinant of health. This meta-analysis reviewed the literature focusing on the relationship between reported racism and mental and physical health outcomes. Data from 293 studies reported in 333 articles published between 1983 and 2013, and conducted predominately in the U.S., were analysed using random effects models and mean weighted effect sizes. Racism was associated with poorer mental health (negative mental health: r = -.23, 95% CI [-.24,-.21], k = 227; positive mental health: r = -.13, 95% CI [-.16,-.10], k = 113), including depression, anxiety, psychological stress and various other outcomes. Racism was also associated with poorer general health (r = -.13 (95% CI [-.18,-.09], k = 30), and poorer physical health (r = -.09, 95% CI [-.12,-.06], k = 50). Moderation effects were found for some outcomes with regard to study and exposure characteristics. Effect sizes of racism on mental health were stronger in cross-sectional compared with longitudinal data and in non-representative samples compared with representative samples. Age, sex, birthplace and education level did not moderate the effects of racism on health. Ethnicity significantly moderated the effect of racism on negative mental health and physical health: the association between racism and negative mental health was significantly stronger for Asian American and Latino(a) American participants compared with African American participants, and the association between racism and physical health was significantly stronger for Latino(a) American participants compared with African American participants. Protocol PROSPERO registration number: CRD42013005464.', '2026-07-08 07:49:32');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3132240972', 'psychology', 'Reactive astrocyte nomenclature, definitions, and future directions', 'Reactive astrocyte nomenclature, definitions, and future directions', '2021', 2021, 2382, 2382, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41593-020-00783-4/MediaObjects/41593_2020_783_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/PMC8007081/pdf', 'pmc', 'review', 'Nature Neuroscience', '["Carole Escartin","Elena Galea","András Lakatos","James P. O’Callaghan","Gabor C. Petzold","Alberto Serrano‐Pozo","Christian Steinhäuser","Andrea Volterra","Giorgio Carmignoto","Amit Agarwal","Nicola J. Allen","Alfonso Araque","Luis Barbeito","Ari Barzilai","Dwight E. Bergles","Gilles Bonvento","Arthur M. Butt","Wei-Ting Chen","Martine Cohen‐Salmon","Colm Cunningham","Benjamin Deneen","Bart De Strooper","Blanca Díaz‐Castro","Cinthia Farina","Marc Freeman","Vittorio Gallo","J. E. Goldman","Steven A. Goldman","Magdalena Götz","Antonia Gutiérrez","Philip G. Haydon","Dieter Henrik Heiland","Elly M. Hol","Matthew G. Holt","Masamitsu Iino","Ksenia V. Kastanenka","Helmut Kettenmann","Baljit S. Khakh","Schuichi Koizumi","C. Justin Lee","Shane A. Liddelow","Brian A. MacVicar","Pierre J. Magistretti","Albee Messing","Anusha Mishra","Anna V. Molofsky","Keith K. Murai","Christopher M. Norris","Seiji Okada","Stéphane H. R. Oliet","João Filipe Oliveira","Aude Panatier","Vladimir Parpura","Marcela Pekna","Milos Pekny","Luc Pellerin","Gertrudis Perea","Beatriz Gomez Perez‐Nievas","Frank W. Pfrieger","Kira E. Poskanzer","Francisco J. Quintana","Richard M. Ransohoff","Miriam Riquelme‐Perez","Stefanie Robel","Christine R. Rose","Jeffrey D. Rothstein","Nathalie Rouach","David H. Rowitch","Alexey Semyanov","Swetlana Sirko","Harald Sontheimer","Raymond A. Swanson","Javier Vitórica","I. Wanner","Levi B. Wood","Jiaqian Wu","Binhai Zheng","Eduardo R. Zimmer","Robert Zorec","Michael V. Sofroniew","Alexei Verkhratsky"]', 'psychology', NULL, '2026-07-08 07:50:21');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2253685848', 'psychology', '22q11.2 deletion syndrome', '22q11.2 deletion syndrome', '2015', 2015, 2246, 2246, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnrdp.2015.71/MediaObjects/41572_2015_Article_BFnrdp201571_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4900471', 'pmc', 'review', 'Nature Reviews Disease Primers', '["Donna M. McDonald‐McGinn","Kathleen E. Sullivan","Bruno Marino","Nicole Philip","Ann Swillen","Jacob Vorstman","Elaine H. Zackai","Beverly S. Emanuel","Joris Vermeesch","Bernice E. Morrow","Peter Scambler","Anne S. Bassett"]', 'psychology', NULL, '2026-07-08 07:51:03');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2560565629', 'psychology', 'Resting-state connectivity biomarkers define neurophysiological subtypes of depression', 'Resting-state connectivity biomarkers define neurophysiological subtypes of depression', '2016', 2016, 2245, 2245, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnm.4246/MediaObjects/41591_2017_Article_BFnm4246_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5624035', 'pmc', 'article', 'Nature Medicine', '["Andrew T. Drysdale","Logan Grosenick","Jonathan Downar","Katharine Dunlop","Farrokh Mansouri","Yue Meng","Robert N. Fetcho","Benjamin Zebley","Desmond J. Oathes","Amit Etkin","Alan F. Schatzberg","Keith Sudheimer","Jennifer Keller","Helen S. Mayberg","Faith M. Gunning","George S. Alexopoulos","Michael Fox","Álvaro Pascual‐Leone","Henning U. Voss","B.J. Casey","Marc J. Dubin","Conor Liston"]', 'psychology', NULL, '2026-07-08 07:51:06');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2589100236', 'psychology', 'Heart Rate Variability and Cardiac Vagal Tone in Psychophysiological Research – Recommendations for Experiment Planning, Data Analysis, and Data Reporting', 'Psychophysiological research integrating heart rate variability (HRV) has increased during the last two decades, particularly given the fact that HRV is able to index cardiac vagal tone. Cardiac…', '2017', 2017, 2213, 2213, 'https://www.frontiersin.org/files/Articles/238557/fpsyg-08-00213-HTML/image_m/fpsyg-08-00213-g001.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5316555', 'pmc', 'review', 'Frontiers in Psychology', '["Sylvain Laborde","Emma Mosley","Julian F. Thayer"]', 'psychology', 'Psychophysiological research integrating heart rate variability (HRV) has increased during the last two decades, particularly given the fact that HRV is able to index cardiac vagal tone. Cardiac vagal tone, which represents the contribution of the parasympathetic nervous system to cardiac regulation, is acknowledged to be linked with many phenomena relevant for psychophysiological research, including self-regulation at the cognitive, emotional, social, and health levels. The ease of HRV collection and measurement coupled with the fact it is relatively affordable, non-invasive and pain free makes it widely accessible to many researchers. This ease of access should not obscure the difficulty of interpretation of HRV findings that can be easily misconstrued, however, this can be controlled to some extent through correct methodological processes. Standards of measurement were developed two decades ago by a Task Force within HRV research, and recent reviews updated several aspects of the Task Force paper. However, many methodological aspects related to HRV in psychophysiological research have to be considered if one aims to be able to draw sound conclusions, which makes it difficult to interpret findings and to compare results across laboratories. Those methodological issues have mainly been discussed in separate outlets, making difficult to get a grasp on them, and thus this paper aims to address this issue. It will help to provide psychophysiological researchers with recommendations and practical advice concerning experimental designs, data analysis, and data reporting. This will ensure that researchers starting a project with HRV and cardiac vagal tone are well informed regarding methodological considerations in order for their findings to contribute to knowledge advancement in their field.', '2026-07-08 07:51:14');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2511883439', 'psychology', 'Repeated Measures Correlation', 'Repeated measures correlation (rmcorr) is a statistical technique for determining the common within-individual association for paired measures assessed on two or more occasions for multiple…', '2017', 2017, 2032, 2032, 'https://www.frontiersin.org/files/Articles/252904/fpsyg-08-00456-HTML-r1/image_m/fpsyg-08-00456-g001.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5383908', 'pmc', 'article', 'Frontiers in Psychology', '["Jonathan Z. Bakdash","Laura R. Marusich"]', 'psychology', 'Repeated measures correlation (rmcorr) is a statistical technique for determining the common within-individual association for paired measures assessed on two or more occasions for multiple individuals. Simple regression/correlation is often applied to non-independent observations or aggregated data; this may produce biased, specious results due to violation of independence and/or differing patterns between-participants versus within-participants. Unlike simple regression/correlation, rmcorr does not violate the assumption of independence of observations. Also, rmcorr tends to have much greater statistical power because neither averaging nor aggregation is necessary for an intra-individual research question. Rmcorr estimates the common regression slope, the association shared among individuals. To make rmcorr accessible, we provide background information for its assumptions and equations, visualization, power, and tradeoffs with rmcorr compared to multilevel modeling. We introduce the R package (rmcorr) and demonstrate its use for inferential statistics and visualization with two example datasets. The examples are used to illustrate research questions at different levels of analysis, intra-individual, and inter-individual. Rmcorr is well-suited for research questions regarding the common linear association in paired repeated measures data. All results are fully reproducible.', '2026-07-08 07:52:13');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3011642264', 'psychology', 'The Impact of COVID-19 Epidemic Declaration on Psychological Consequences: A Study on Active Weibo Users', 'COVID-19 (Corona Virus Disease 2019) has significantly resulted in a large number of psychological consequences. The aim of this study is to explore the impacts of COVID-19 on people''s mental health,…', '2020', 2020, 1899, 1899, 'https://pub.mdpi-res.com/ijerph/ijerph-17-02032/article_deploy/html/images/ijerph-17-02032-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7143846', 'pmc', 'article', 'International Journal of Environmental Research and Public Health', '["Sijia Li","Yilin Wang","Jia Xue","Nan Zhao","Tingshao Zhu"]', 'psychology', 'COVID-19 (Corona Virus Disease 2019) has significantly resulted in a large number of psychological consequences. The aim of this study is to explore the impacts of COVID-19 on people''s mental health, to assist policy makers to develop actionable policies, and help clinical practitioners (e.g., social workers, psychiatrists, and psychologists) provide timely services to affected populations. We sample and analyze the Weibo posts from 17,865 active Weibo users using the approach of Online Ecological Recognition (OER) based on several machine-learning predictive models. We calculated word frequency, scores of emotional indicators (e.g., anxiety, depression, indignation, and Oxford happiness) and cognitive indicators (e.g., social risk judgment and life satisfaction) from the collected data. The sentiment analysis and the paired sample t-test were performed to examine the differences in the same group before and after the declaration of COVID-19 on 20 January, 2020. The results showed that negative emotions (e.g., anxiety, depression and indignation) and sensitivity to social risks increased, while the scores of positive emotions (e.g., Oxford happiness) and life satisfaction decreased. People were concerned more about their health and family, while less about leisure and friends. The results contribute to the knowledge gaps of short-term individual changes in psychological conditions after the outbreak. It may provide references for policy makers to plan and fight against COVID-19 effectively by improving stability of popular feelings and urgently prepare clinical practitioners to deliver corresponding therapy foundations for the risk groups and affected people.', '2026-07-08 07:53:06');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2515189678', 'psychology', 'Understanding and misunderstanding randomized controlled trials', 'Randomized Controlled Trials (RCTs) are increasingly popular in the social sciences, not only in medicine. We argue that the lay public, and sometimes researchers, put too much trust in RCTs over…', '2017', 2017, 1839, 1839, 'https://ars.els-cdn.com/content/image/1-s2.0-S0277953617307359-fx1.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6019115', 'pmc', 'article', 'Social Science & Medicine', '["Angus Deaton","Nancy Cartwright"]', 'psychology', 'Randomized Controlled Trials (RCTs) are increasingly popular in the social sciences, not only in medicine. We argue that the lay public, and sometimes researchers, put too much trust in RCTs over other methods of investigation. Contrary to frequent claims in the applied literature, randomization does not equalize everything other than the treatment in the treatment and control groups, it does not automatically deliver a precise estimate of the average treatment effect (ATE), and it does not relieve us of the need to think about (observed or unobserved) covariates. Finding out whether an estimate was generated by chance is more difficult than commonly believed. At best, an RCT yields an unbiased estimate, but this property is of limited practical value. Even then, estimates apply only to the sample selected for the trial, often no more than a convenience sample, and justification is required to extend the results to other groups, including any population to which the trial sample belongs, or to any individual, including an individual in the trial. Demanding ''external validity'' is unhelpful because it expects too much of an RCT while undervaluing its potential contribution. RCTs do indeed require minimal assumptions and can operate with little prior knowledge. This is an advantage when persuading distrustful audiences, but it is a disadvantage for cumulative scientific progress, where prior knowledge should be built upon, not discarded. RCTs can play a role in building scientific knowledge and useful predictions but they can only do so as part of a cumulative program, combining with other methods, including conceptual and theoretical development, to discover not ''what works'', but ''why things work''.', '2026-07-08 07:53:24');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3024082351', 'psychology', 'Challenges and burden of the Coronavirus 2019 (COVID-19) pandemic for child and adolescent mental health: a narrative review to highlight clinical and research needs in the acute phase and the long return to normality', 'BACKGROUND: The coronavirus disease 2019 (COVID-19) is profoundly affecting life around the globe. Isolation, contact restrictions and economic shutdown impose a complete change to the psychosocial…', '2020', 2020, 1870, 1870, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs13034-020-00329-3/MediaObjects/13034_2020_329_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7216870', 'pmc', 'review', 'Child and Adolescent Psychiatry and Mental Health', '["Jörg M. Fegert","Benedetto Vitiello","Paul L. Plener","Vera Clemens"]', 'psychology', 'BACKGROUND: The coronavirus disease 2019 (COVID-19) is profoundly affecting life around the globe. Isolation, contact restrictions and economic shutdown impose a complete change to the psychosocial environment in affected countries. These measures have the potential to threaten the mental health of children and adolescents significantly. Even though the current crisis can bring with it opportunities for personal growth and family cohesion, disadvantages may outweigh these benefits. Anxiety, lack of peer contact and reduced opportunities for stress regulation are main concerns. Another main threat is an increased risk for parental mental illness, domestic violence and child maltreatment. Especially for children and adolescents with special needs or disadvantages, such as disabilities, trauma experiences, already existing mental health problems, migrant background and low socioeconomic status, this may be a particularly challenging time. To maintain regular and emergency child and adolescent psychiatric treatment during the pandemic is a major challenge but is necessary for limiting long-term consequences for the mental health of children and adolescents. Urgent research questions comprise understanding the mental health effects of social distancing and economic pressure, identifying risk and resilience factors, and preventing long-term consequences, including-but not restricted to-child maltreatment. The efficacy of telepsychiatry is another highly relevant issue is to evaluate the efficacy of telehealth and perfect its applications to child and adolescent psychiatry. CONCLUSION: There are numerous mental health threats associated with the current pandemic and subsequent restrictions. Child and adolescent psychiatrists must ensure continuity of care during all phases of the pandemic. COVID-19-associated mental health risks will disproportionately hit children and adolescents who are already disadvantaged and marginalized. Research is needed to assess the implications of policies enacted to contain the pandemic on mental health of children and adolescents, and to estimate the risk/benefit ratio of measures such as home schooling, in order to be better prepared for future developments.', '2026-07-08 07:53:26');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2461013690', 'psychology', 'Evaluation of off-target and on-target scoring algorithms and integration into the guide RNA selection tool CRISPOR', 'BACKGROUND: The success of the CRISPR/Cas9 genome editing technique depends on the choice of the guide RNA sequence, which is facilitated by various websites. Despite the importance and popularity of…', '2016', 2016, 1871, 1871, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1038%2Fs41551-017-0178-6/MediaObjects/41551_2017_178_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4934014', 'pmc', 'article', 'Genome biology', '["Maximilian Haeussler","Kai Schönig","Hélène Eckert","Alexis Eschstruth","Joffrey Mianné","Jean-Baptiste Renaud","Sylvie Schneider‐Maunoury","Alena Shkumatava","Lydia Teboul","Jim Kent","Jean‐Stéphane Joly","Jean‐Paul Concordet"]', 'psychology', 'BACKGROUND: The success of the CRISPR/Cas9 genome editing technique depends on the choice of the guide RNA sequence, which is facilitated by various websites. Despite the importance and popularity of these algorithms, it is unclear to which extent their predictions are in agreement with actual measurements. RESULTS: We conduct the first independent evaluation of CRISPR/Cas9 predictions. To this end, we collect data from eight SpCas9 off-target studies and compare them with the sites predicted by popular algorithms. We identify problems in one implementation but found that sequence-based off-target predictions are very reliable, identifying most off-targets with mutation rates superior to 0.1 %, while the number of false positives can be largely reduced with a cutoff on the off-target score. We also evaluate on-target efficiency prediction algorithms against available datasets. The correlation between the predictions and the guide activity varied considerably, especially for zebrafish. Together with novel data from our labs, we find that the optimal on-target efficiency prediction model strongly depends on whether the guide RNA is expressed from a U6 promoter or transcribed in vitro. We further demonstrate that the best predictions can significantly reduce the time spent on guide screening. CONCLUSIONS: To make these guidelines easily accessible to anyone planning a CRISPR genome editing experiment, we built a new website ( http://crispor.org ) that predicts off-targets and helps select and clone efficient guide sequences for more than 120 genomes using different Cas9 proteins and the eight efficiency scoring systems evaluated here.', '2026-07-08 07:53:27');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2803193013', 'psychology', 'The Ryerson Audio-Visual Database of Emotional Speech and Song (RAVDESS): A dynamic, multimodal set of facial and vocal expressions in North American English', 'The RAVDESS is a validated multimodal database of emotional speech and song. The database is gender balanced consisting of 24 professional actors, vocalizing lexically-matched statements in a neutral…', '2018', 2018, 1809, 1809, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0196391.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5955500', 'pmc', 'article', 'PLoS ONE', '["Steven R. Livingstone","Frank Russo"]', 'psychology', 'The RAVDESS is a validated multimodal database of emotional speech and song. The database is gender balanced consisting of 24 professional actors, vocalizing lexically-matched statements in a neutral North American accent. Speech includes calm, happy, sad, angry, fearful, surprise, and disgust expressions, and song contains calm, happy, sad, angry, and fearful emotions. Each expression is produced at two levels of emotional intensity, with an additional neutral expression. All conditions are available in face-and-voice, face-only, and voice-only formats. The set of 7356 recordings were each rated 10 times on emotional validity, intensity, and genuineness. Ratings were provided by 247 individuals who were characteristic of untrained research participants from North America. A further set of 72 participants provided test-retest data. High levels of emotional validity and test-retest intrarater reliability were reported. Corrected accuracy and composite "goodness" measures are presented to assist researchers in the selection of stimuli. All recordings are made freely available under a Creative Commons license and can be downloaded at https://doi.org/10.5281/zenodo.1188976.', '2026-07-08 07:53:48');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3015163167', 'psychology', 'CINeMA: An approach for assessing confidence in the results of a network meta-analysis', 'BACKGROUND: The evaluation of the credibility of results from a meta-analysis has become an important part of the evidence synthesis process. We present a methodological framework to evaluate…', '2020', 2020, 1735, 1735, 'https://journals.plos.org/plosmedicine/article/figure/image?size=large&id=10.1371/journal.pmed.1003082.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7122720', 'pmc', 'article', 'PLoS Medicine', '["Adriani Nikolakopoulou","Julian P. T. Higgins","Theodoros Papakonstantinou","Anna Chaimani","Cinzia Del Giovane","Matthias Egger","Georgia Salanti"]', 'psychology', 'BACKGROUND: The evaluation of the credibility of results from a meta-analysis has become an important part of the evidence synthesis process. We present a methodological framework to evaluate confidence in the results from network meta-analyses, Confidence in Network Meta-Analysis (CINeMA), when multiple interventions are compared. METHODOLOGY: CINeMA considers 6 domains: (i) within-study bias, (ii) reporting bias, (iii) indirectness, (iv) imprecision, (v) heterogeneity, and (vi) incoherence. Key to judgments about within-study bias and indirectness is the percentage contribution matrix, which shows how much information each study contributes to the results from network meta-analysis. The contribution matrix can easily be computed using a freely available web application. In evaluating imprecision, heterogeneity, and incoherence, we consider the impact of these components of variability in forming clinical decisions. CONCLUSIONS: Via 3 examples, we show that CINeMA improves transparency and avoids the selective use of evidence when forming judgments, thus limiting subjectivity in the process. CINeMA is easy to apply even in large and complicated networks.', '2026-07-08 07:54:29');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2475426101', 'psychology', 'A conceptual framework for integrated STEM education', 'The global urgency to improve STEM education may be driven by environmental and social impacts of the twenty-first century which in turn jeopardizes global security and economic stability. The…', '2016', 2016, 1733, 1733, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1007%2Fs11191-020-00135-5/MediaObjects/11191_2020_135_Fig1_HTML.png', 'https://doi.org/10.1186/s40594-016-0046-z', 'repository', 'article', 'International Journal of STEM Education', '["Todd R. Kelley","J. Geoff Knowles"]', 'psychology', 'The global urgency to improve STEM education may be driven by environmental and social impacts of the twenty-first century which in turn jeopardizes global security and economic stability. The complexity of these global factors reach beyond just helping students achieve high scores in math and science assessments. Friedman (The world is flat: A brief history of the twenty-first century, 2005) helped illustrate the complexity of a global society, and educators must help students prepare for this global shift. In response to these challenges, the USA experienced massive STEM educational reforms in the last two decades. In practice, STEM educators lack cohesive understanding of STEM education. Therefore, they could benefit from a STEM education conceptual framework. The process of integrating science, technology, engineering, and mathematics in authentic contexts can be as complex as the global challenges that demand a new generation of STEM experts. Educational researchers indicate that teachers struggle to make connections across the STEM disciplines. Consequently, students are often disinterested in science and math when they learn in an isolated and disjoined manner missing connections to crosscutting concepts and real-world applications. The following paper will operationalize STEM education key concepts and blend learning theories to build an integrated STEM education framework to assist in further researching integrated STEM education.', '2026-07-08 07:54:50');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2739751169', 'psychology', 'GRIPP2 reporting checklists: tools to improve reporting of patient and public involvement in research', 'While the patient and public involvement (PPI) evidence base has expanded over the past decade, the quality of reporting within papers is often inconsistent, limiting our understanding of how it…', '2017', 2017, 1727, 1727, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs12913-024-11021-z/MediaObjects/12913_2024_11021_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5611595', 'pmc', 'article', 'Research Involvement and Engagement', '["Sophie Staniszewska","Jo Brett","Iveta Simera","Kate Seers","Carole Mockford","Susan Goodlad","Doug Altman","David Moher","Rosemary Barber","Simon Denegri","Andrew Entwistle","Peter Littlejohns","Christopher Morris","R. Suleman","Victoria Thomas","Colin Tysall"]', 'psychology', 'While the patient and public involvement (PPI) evidence base has expanded over the past decade, the quality of reporting within papers is often inconsistent, limiting our understanding of how it works, in what context, for whom, and why. To develop international consensus on the key items to report to enhance the quality, transparency, and consistency of the PPI evidence base. To collaboratively involve patients as research partners at all stages in the development of GRIPP2. The EQUATOR method for developing reporting guidelines was used. The original GRIPP (Guidance for Reporting Involvement of Patients and the Public) checklist was revised, based on updated systematic review evidence. A three round Delphi survey was used to develop consensus on items to be included in the guideline. A subsequent face-to-face meeting produced agreement on items not reaching consensus during the Delphi process. One hundred forty-three participants agreed to participate in round one, with an 86% (123/143) response for round two and a 78% (112/143) response for round three. The Delphi survey identified the need for long form (LF) and short form (SF) versions. GRIPP2-LF includes 34 items on aims, definitions, concepts and theory, methods, stages and nature of involvement, context, capture or measurement of impact, outcomes, economic assessment, and reflections and is suitable for studies where the main focus is PPI. GRIPP2-SF includes five items on aims, methods, results, outcomes, and critical perspective and is suitable for studies where PPI is a secondary focus. GRIPP2-LF and GRIPP2-SF represent the first international evidence based, consensus informed guidance for reporting patient and public involvement in research. Both versions of GRIPP2 aim to improve the quality, transparency, and consistency of the international PPI evidence base, to ensure PPI practice is based on the best evidence. In order to encourage its wide dissemination this article is freely accessible on The BMJ and Research Involvement and Engagement journal websites.', '2026-07-08 07:54:51');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2911248861', 'psychology', 'Mitophagy inhibits amyloid-β and tau pathology and reverses cognitive deficits in models of Alzheimer’s disease', 'Mitophagy inhibits amyloid-β and tau pathology and reverses cognitive deficits in models of Alzheimer’s disease', '2019', 2019, 1702, 1702, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41593-018-0332-9/MediaObjects/41593_2018_332_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6693625', 'pmc', 'article', 'Nature Neuroscience', '["Evandro Fei Fang","Yujun Hou","Konstantinos Palikaras","Bryan A. Adriaanse","Jesse S. Kerr","Beimeng Yang","Sofie Lautrup","Md Mahdi Hasan‐Olive","Domenica Caponio","Xiuli Dan","Paula Rocktäschel","Deborah L. Croteau","Mansour Akbari","Nigel H. Greig","Tormod Fladby","Hilde Nilsen","M. Zameel Cader","Mark P. Mattson","Nektarios Tavernarakis","Vilhelm A. Bohr"]', 'psychology', NULL, '2026-07-08 07:55:08');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2769544142', 'psychology', 'Autism spectrum disorder', 'Autism spectrum disorder', '2020', 2020, 1700, 1700, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41572-019-0138-4/MediaObjects/41572_2019_138_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8900942', 'pmc', 'review', 'Nature Reviews Disease Primers', '["Catherine Lord","Traolach Brugha","Tony Charman","James Cusack","Guillaume Dumas","Thomas Frazier","Emily J. H. Jones","Rebecca M. Jones","Andrew Pickles","Matthew W. State","Julie Lounds Taylor","Jeremy Veenstra‐VanderWeele"]', 'psychology', NULL, '2026-07-08 07:55:09');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2220215167', 'psychology', 'The role of microglia and macrophages in glioma maintenance and progression', 'The role of microglia and macrophages in glioma maintenance and progression', '2015', 2015, 1681, 1681, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnn.4185/MediaObjects/41593_2016_Article_BFnn4185_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4876023', 'pmc', 'review', 'Nature Neuroscience', '["Dolores Hambardzumyan","David H. Gutmann","Helmut Kettenmann"]', 'psychology', NULL, '2026-07-08 07:55:21');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2399060753', 'psychology', 'A meta-analysis of blood cytokine network alterations in psychiatric patients: comparisons between schizophrenia, bipolar disorder and depression', 'A meta-analysis of blood cytokine network alterations in psychiatric patients: comparisons between schizophrenia, bipolar disorder and depression', '2016', 2016, 1679, 1679, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fmp.2016.3/MediaObjects/41380_2016_Article_BFmp20163_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6056174', 'pmc', 'review', 'Molecular Psychiatry', '["David R. Goldsmith","Mark Hyman Rapaport","Brian J. Miller"]', 'psychology', NULL, '2026-07-08 07:55:24');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3011962481', 'psychology', 'Methodological quality (risk of bias) assessment tools for primary and secondary medical studies: what are they and which is better?', 'Methodological quality (risk of bias) assessment is an important step before study initiation usage. Therefore, accurately judging study type is the first priority, and the choosing proper tool is…', '2020', 2020, 1647, 1647, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs44158-023-00129-z/MediaObjects/44158_2023_129_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7049186', 'pmc', 'review', 'Military Medical Research', '["Linlu Ma","Xinghuan Wang","Zhihua Yang","Di Huang","Hong Weng","Xian‐Tao Zeng"]', 'psychology', 'Methodological quality (risk of bias) assessment is an important step before study initiation usage. Therefore, accurately judging study type is the first priority, and the choosing proper tool is also important. In this review, we introduced methodological quality assessment tools for randomized controlled trial (including individual and cluster), animal study, non-randomized interventional studies (including follow-up study, controlled before-and-after study, before-after/ pre-post study, uncontrolled longitudinal study, interrupted time series study), cohort study, case-control study, cross-sectional study (including analytical and descriptive), observational case series and case reports, comparative effectiveness research, diagnostic study, health economic evaluation, prediction study (including predictor finding study, prediction model impact study, prognostic prediction model study), qualitative study, outcome measurement instruments (including patient - reported outcome measure development, content validity, structural validity, internal consistency, cross-cultural validity/ measurement invariance, reliability, measurement error, criterion validity, hypotheses testing for construct validity, and responsiveness), systematic review and meta-analysis, and clinical practice guideline. The readers of our review can distinguish the types of medical studies and choose appropriate tools. In one word, comprehensively mastering relevant knowledge and implementing more practices are basic requirements for correctly assessing the methodological quality.', '2026-07-08 07:55:57');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3003385079', 'psychology', 'The Ethics of AI Ethics: An Evaluation of Guidelines', 'Abstract Current advances in research, development and application of artificial intelligence (AI) systems have yielded a far-reaching discourse on AI ethics. In consequence, a number of ethics…', '2020', 2020, 1648, 1648, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1007%2Fs43681-024-00585-5/MediaObjects/43681_2024_585_Fig1_HTML.png', 'http://arxiv.org/abs/1903.03425', 'arxiv', 'article', 'Minds and Machines', '["Thilo Hagendorff"]', 'psychology', 'Abstract Current advances in research, development and application of artificial intelligence (AI) systems have yielded a far-reaching discourse on AI ethics. In consequence, a number of ethics guidelines have been released in recent years. These guidelines comprise normative principles and recommendations aimed to harness the “disruptive” potentials of new AI technologies. Designed as a semi-systematic evaluation, this paper analyzes and compares 22 guidelines, highlighting overlaps but also omissions. As a result, I give a detailed overview of the field of AI ethics. Finally, I also examine to what extent the respective ethical principles and values are implemented in the practice of research, development and application of AI systems—and how the effectiveness in the demands of AI ethics can be improved.', '2026-07-08 07:55:59');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2577043885', 'psychology', 'Factors influencing adoption of mobile banking by Jordanian bank customers: Extending UTAUT2 with trust', 'Factors influencing adoption of mobile banking by Jordanian bank customers: Extending UTAUT2 with trust', '2017', 2017, 1564, 1564, 'https://ars.els-cdn.com/content/image/1-s2.0-S026840121630696X-gr1.jpg', 'https://doi.org/10.1016/j.ijinfomgt.2017.01.002', 'repository', 'article', 'International Journal of Information Management', '["Ali Abdallah Alalwan","Yogesh K. Dwivedi","Nripendra P. Rana"]', 'psychology', NULL, '2026-07-08 07:57:13');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W756325778', 'psychology', 'Stress Effects on Neuronal Structure: Hippocampus, Amygdala, and Prefrontal Cortex', 'Stress Effects on Neuronal Structure: Hippocampus, Amygdala, and Prefrontal Cortex', '2015', 2015, 1538, 1538, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnpp.2015.171/MediaObjects/41386_2016_Article_BFnpp2015171_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4677120', 'pmc', 'review', 'Neuropsychopharmacology', '["Bruce S. McEwen","Carla Nasca","Jason D. Gray"]', 'psychology', NULL, '2026-07-08 07:57:40');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2571093196', 'psychology', 'Scanning the horizon: towards transparent and reproducible neuroimaging research', 'Scanning the horizon: towards transparent and reproducible neuroimaging research', '2017', 2017, 1530, 1530, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnrn.2016.167/MediaObjects/41583_2017_Article_BFnrn2016167_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6910649', 'pmc', 'review', 'Nature reviews. Neuroscience', '["Russell A. Poldrack","Chris I. Baker","Joke Durnez","Krzysztof J. Gorgolewski","Paul M. Matthews","Marcus R. Munafò","Thomas E. Nichols","Jean‐Baptiste Poline","Edward Vul","Tal Yarkoni"]', 'psychology', NULL, '2026-07-08 07:57:41');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3013207139', 'psychology', 'Impact of the COVID-19 Pandemic on Mental Health and Quality of Life among Local Residents in Liaoning Province, China: A Cross-Sectional Study', 'Our study aimed to investigate the immediate impact of the COVID-19 pandemic on mental health and quality of life among local Chinese residents aged ≥18 years in Liaoning Province, mainland China. An…', '2020', 2020, 1528, 1528, 'https://pub.mdpi-res.com/ijerph/ijerph-17-02381/article_deploy/html/images/ijerph-17-02381-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7177660', 'pmc', 'article', 'International Journal of Environmental Research and Public Health', '["Yingfei Zhang","Zheng Feei"]', 'psychology', 'Our study aimed to investigate the immediate impact of the COVID-19 pandemic on mental health and quality of life among local Chinese residents aged ≥18 years in Liaoning Province, mainland China. An online survey was distributed through a social media platform between January and February 2020. Participants completed a modified validated questionnaire that assessed the Impact of Event Scale (IES), indicators of negative mental health impacts, social and family support, and mental health-related lifestyle changes. A total of 263 participants (106 males and 157 females) completed the study. The mean age of the participants was 37.7 ± 14.0 years, and 74.9% had a high level of education. The mean IES score in the participants was 13.6 ± 7.7, reflecting a mild stressful impact. Only 7.6% of participants had an IES score ≥26. The majority of participants (53.3%) did not feel helpless due to the pandemic. On the other hand, 52.1% of participants felt horrified and apprehensive due to the pandemic. Additionally, the majority of participants (57.8-77.9%) received increased support from friends and family members, increased shared feeling and caring with family members and others. In conclusion, the COVID-19 pandemic was associated with mild stressful impact in our sample, even though the COVID-19 pandemic is still ongoing. These findings would need to be verified in larger population studies.', '2026-07-08 07:57:47');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3023519397', 'psychology', 'Real-time tracking of self-reported symptoms to predict potential COVID-19', 'Real-time tracking of self-reported symptoms to predict potential COVID-19', '2020', 2020, 1515, 1515, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41591-020-0916-2/MediaObjects/41591_2020_916_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7751267', 'pmc', 'article', 'Nature Medicine', '["Cristina Menni","Ana M. Valdes","Maxim B. Freidin","Carole H. Sudre","Long H. Nguyen","David A. Drew","Sajaysurya Ganesh","Thomas Varsavsky","M. Jorge Cardoso","Julia S. El-Sayed Moustafa","Alessia Visconti","Pirro G. Hysi","Ruth C. E. Bowyer","Massimo Mangino","Mario Falchi","Jonathan Wolf","Sébastien Ourselin","Andrew T. Chan","Claire J. Steves","Tim D. Spector"]', 'psychology', NULL, '2026-07-08 07:57:58');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2804703589', 'psychology', 'The integrated motivational–volitional model of suicidal behaviour', 'Suicide is a major public health concern accounting for 800 000 deaths globally each year. Although there have been many advances in understanding suicide risk in recent decades, our ability to…', '2018', 2018, 1476, 1476, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1098/rstb.2017.0268.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6053985', 'pmc', 'review', 'Philosophical Transactions of the Royal Society B Biological Sciences', '["Rory C. O’Connor","Olivia J Kirtley"]', 'psychology', 'Suicide is a major public health concern accounting for 800 000 deaths globally each year. Although there have been many advances in understanding suicide risk in recent decades, our ability to predict suicide is no better now than it was 50 years ago. There are many potential explanations for this lack of progress, but the absence, until recently, of comprehensive theoretical models that predict the emergence of suicidal ideation distinct from the transition between suicidal ideation and suicide attempts/suicide is key to this lack of progress. The current article presents the integrated motivational-volitional (IMV) model of suicidal behaviour, one such theoretical model. We propose that defeat and entrapment drive the emergence of suicidal ideation and that a group of factors, entitled volitional moderators (VMs), govern the transition from suicidal ideation to suicidal behaviour. According to the IMV model, VMs include access to the means of suicide, exposure to suicidal behaviour, capability for suicide (fearlessness about death and increased physical pain tolerance), planning, impulsivity, mental imagery and past suicidal behaviour. In this article, we describe the theoretical origins of the IMV model, the key premises underpinning the model, empirical tests of the model and future research directions.This article is part of the theme issue ''Evolutionary thanatology: impacts of the dead on the living in humans and other animals''.', '2026-07-08 07:58:43');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2763205864', 'psychology', 'Physical, psychological and occupational consequences of job burnout: A systematic review of prospective studies', 'Burnout is a syndrome that results from chronic stress at work, with several consequences to workers'' well-being and health. This systematic review aimed to summarize the evidence of the physical,…', '2017', 2017, 1471, 1471, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0185781.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5627926', 'pmc', 'review', 'PLoS ONE', '["Denise Albieri Jodas Salvagioni","Francine Nesello Melanda","Arthur Eumann Mesas","Alberto Durán Gonzáléz","Flávia Lopes Gabani","Selma Maffei de Andrade"]', 'psychology', 'Burnout is a syndrome that results from chronic stress at work, with several consequences to workers'' well-being and health. This systematic review aimed to summarize the evidence of the physical, psychological and occupational consequences of job burnout in prospective studies. The PubMed, Science Direct, PsycInfo, SciELO, LILACS and Web of Science databases were searched without language or date restrictions. The Transparent Reporting of Systematic Reviews and Meta-Analyses guidelines were followed. Prospective studies that analyzed burnout as the exposure condition were included. Among the 993 articles initially identified, 61 fulfilled the inclusion criteria, and 36 were analyzed because they met three criteria that must be followed in prospective studies. Burnout was a significant predictor of the following physical consequences: hypercholesterolemia, type 2 diabetes, coronary heart disease, hospitalization due to cardiovascular disorder, musculoskeletal pain, changes in pain experiences, prolonged fatigue, headaches, gastrointestinal issues, respiratory problems, severe injuries and mortality below the age of 45 years. The psychological effects were insomnia, depressive symptoms, use of psychotropic and antidepressant medications, hospitalization for mental disorders and psychological ill-health symptoms. Job dissatisfaction, absenteeism, new disability pension, job demands, job resources and presenteeism were identified as professional outcomes. Conflicting findings were observed. In conclusion, several prospective and high-quality studies showed physical, psychological and occupational consequences of job burnout. The individual and social impacts of burnout highlight the need for preventive interventions and early identification of this health condition in the work environment.', '2026-07-08 07:58:43');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W256767295', 'psychology', '15. The Death of the Author', 'In his story Sarrasine Balzac, describing a castrato disguised as a woman, writes the following sentence: ‘This was woman herself, with her sudden fears, her irrational whims, her instinctive…', '2019', 2019, 1411, 1411, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1515/9781474465519-017.g001', 'https://doi.org/10.1515/9781474465519-017', 'repository', 'article', 'Authorship', '["Roland Barthes"]', 'psychology', 'In his story Sarrasine Balzac, describing a castrato disguised as a woman, writes the following sentence: ‘This was woman herself, with her sudden fears, her irrational whims, her instinctive worries, her impetuous boldness, her fussings, and her delicious sensibility.’ Who is speaking thus? Is it the hero of the story bent on remaining ignorant of the castrato hidden beneath the woman? Is it Balzac the individual, furnished by his personal experience with a philosophy of Woman? Is it Balzac the author professing ‘literary’ ideas on femininity? Is it universal wisdom? Romantic psychology? We shall never know, for the good reason that writing is the destruction of every voice, of every point of origin. Writing is that neutral, composite, oblique space where our subject slips away, the negative where all identity is lost, starting with the very identity of the body writing. No doubt it has always been that way. As soon as a fact is narrated no longer with a view to acting directly on reality but intransitively, that is to say, Vnally outside of any function other than that of the very practice of the symbol itself, this disconnection occurs, the voice loses its origin, the author enters into his own death, writing begins. The sense of this phenomenon, however, has varied; in ethnographic societies the responsibility for a narrative is never assumed by a person but by a mediator, shaman or relator whose ‘performance’—the mastery of the narrative code—may possibly be admired but never his ‘genius’. The author is a modern Vgure, a product of our society insofar as, emerging from the Middle Ages with English empiricism, French rationalism and the personal faith of the Reformation, it discovered the prestige of the individual, of, as it is more nobly put, the ‘human person’. It is thus logical that in literature it should be this positivism, the epitome and culmination of capitalist ideology, which has attached the greatest importance to the ‘person’ of the author. The author still reigns in histories of literature, biographies of writers, interviews, magazines, as in the very consciousness of men of letters anxious to unite their person and their work through diaries and memoirs. The image of literature to be found in ordinary culture is tyrannically centred on the author, his person, his life, his tastes, his passions, while criticism still consists for the most part in saying that Baudelaire’s work is the failure of Baudelaire the man, Van Gogh’s', '2026-07-08 07:59:41');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3045484639', 'psychology', 'Students under lockdown: Comparisons of students’ social networks and mental health before and during the COVID-19 crisis in Switzerland', 'This study investigates students'' social networks and mental health before and at the time of the COVID-19 pandemic in April 2020, using longitudinal data collected since 2018. We analyze change on…', '2020', 2020, 1406, 1406, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0236337.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7377438', 'pmc', 'article', 'PLoS ONE', '["Timon Elmer","Kieran Mepham","Christoph Stadtfeld"]', 'psychology', 'This study investigates students'' social networks and mental health before and at the time of the COVID-19 pandemic in April 2020, using longitudinal data collected since 2018. We analyze change on multiple dimensions of social networks (interaction, friendship, social support, co-studying) and mental health indicators (depression, anxiety, stress, loneliness) within two cohorts of Swiss undergraduate students experiencing the crisis (N = 212), and make additional comparisons to an earlier cohort which did not experience the crisis (N = 54). In within-person comparisons we find that interaction and co-studying networks had become sparser, and more students were studying alone. Furthermore, students'' levels of stress, anxiety, loneliness, and depressive symptoms got worse, compared to measures before the crisis. Stressors shifted from fears of missing out on social life to worries about health, family, friends, and their future. Exploratory analyses suggest that COVID-19 specific worries, isolation in social networks, lack of interaction and emotional support, and physical isolation were associated with negative mental health trajectories. Female students appeared to have worse mental health trajectories when controlling for different levels of social integration and COVID-19 related stressors. As universities and researchers discuss future strategies on how to combine on-site teaching with online courses, our results indicate the importance of considering social contacts in students'' mental health and offer starting points to identify and support students at higher risk of social isolation and negative psychological effects during the COVID-19 pandemic.', '2026-07-08 07:59:56');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1848819387', 'psychology', 'The epidemiology of traumatic event exposure worldwide: results from the World Mental Health Survey Consortium', 'BACKGROUND: Considerable research has documented that exposure to traumatic events has negative effects on physical and mental health. Much less research has examined the predictors of traumatic…', '2015', 2015, 1404, 1404, 'https://static.cambridge.org/binary/version/id/urn:cambridge.org:id:binary-alt:20170127014613-28403-mediumThumb-S0033291715001981_fig1g.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4869975', 'pmc', 'article', 'Psychological Medicine', '["Corina Benjet","Evelyn J. Bromet","Elie G. Karam","Ronald C. Kessler","Katie A. McLaughlin","Ayelet Meron Ruscio","Victoria Shahly","Dan J. Stein","Maria Petukhova","Eric Hill","José M. Alonso","Lukoye Atwoli","Brendan Bunting","Ronny Bruffaerts","José Miguel Caldas‐de‐Almeida","Giovanni de Girolamo","Silvia Florescu","Oye Gureje","Yueqin Huang","J.P. Lépine","Norito Kawakami","Viviane Kovess–Masféty","María Elena Medina‐Mora","Fernando Navarro‐Mateu","Marina Piazza","J. Posada‐Villa","Kate M. Scott","Arieh Y. Shalev","Tim Slade","M. ten Have","Yolanda Torres","María Carmen Viana","Zahari Zarkov","Karestan C. Koenen"]', 'psychology', 'BACKGROUND: Considerable research has documented that exposure to traumatic events has negative effects on physical and mental health. Much less research has examined the predictors of traumatic event exposure. Increased understanding of risk factors for exposure to traumatic events could be of considerable value in targeting preventive interventions and anticipating service needs. METHOD: General population surveys in 24 countries with a combined sample of 68 894 adult respondents across six continents assessed exposure to 29 traumatic event types. Differences in prevalence were examined with cross-tabulations. Exploratory factor analysis was conducted to determine whether traumatic event types clustered into interpretable factors. Survival analysis was carried out to examine associations of sociodemographic characteristics and prior traumatic events with subsequent exposure. RESULTS: Over 70% of respondents reported a traumatic event; 30.5% were exposed to four or more. Five types - witnessing death or serious injury, the unexpected death of a loved one, being mugged, being in a life-threatening automobile accident, and experiencing a life-threatening illness or injury - accounted for over half of all exposures. Exposure varied by country, sociodemographics and history of prior traumatic events. Being married was the most consistent protective factor. Exposure to interpersonal violence had the strongest associations with subsequent traumatic events. CONCLUSIONS: Given the near ubiquity of exposure, limited resources may best be dedicated to those that are more likely to be further exposed such as victims of interpersonal violence. Identifying mechanisms that account for the associations of prior interpersonal violence with subsequent trauma is critical to develop interventions to prevent revictimization.', '2026-07-08 08:00:02');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4211041983', 'psychology', 'Amyotrophic lateral sclerosis', 'Amyotrophic lateral sclerosis (ALS), also known as motor neuron disease, is characterized by the degeneration of both upper and lower motor neurons, which leads to muscle weakness and eventual…', '2017', 2017, 1388, 1388, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnrdp.2017.71/MediaObjects/41572_2017_Article_BFnrdp201771_Fig1_HTML.jpg', 'https://pubmed.ncbi.nlm.nih.gov/28980624', 'repository', 'review', 'Nature Reviews Disease Primers', '["Orla Hardiman","Ammar Al‐Chalabi","Adriano Chiò","Emma M. Corr","Giancarlo Logroscino","Wim Robberecht","Pamela J. Shaw","Zachary Simmons","Leonard H. van den Berg"]', 'psychology', 'Amyotrophic lateral sclerosis (ALS), also known as motor neuron disease, is characterized by the degeneration of both upper and lower motor neurons, which leads to muscle weakness and eventual paralysis. Until recently, ALS was classified primarily within the neuromuscular domain, although new imaging and neuropathological data have indicated the involvement of the non-motor neuraxis in disease pathology. In most patients, the mechanisms underlying the development of ALS are poorly understood, although a subset of patients have familial disease and harbour mutations in genes that have various roles in neuronal function. Two possible disease-modifying therapies that can slow disease progression are available for ALS, but patient management is largely mediated by symptomatic therapies, such as the use of muscle relaxants for spasticity and speech therapy for dysarthria. Amyotrophic lateral sclerosis (ALS) is characterized by the degeneration of both upper and lower motor neurons, which leads to progressive muscle weakness and paralysis. This Primer by Hardiman and colleagues provides a detailed overview of the epidemiology, pathophysiology and diagnosis of ALS, and discusses the management of both the motor and non-motor symptoms of this condition.', '2026-07-08 08:00:20');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3000061011', 'psychology', 'Lipid-droplet-accumulating microglia represent a dysfunctional and proinflammatory state in the aging brain', 'Lipid-droplet-accumulating microglia represent a dysfunctional and proinflammatory state in the aging brain', '2020', 2020, 1387, 1387, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41593-019-0566-1/MediaObjects/41593_2019_566_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7595134', 'pmc', 'article', 'Nature Neuroscience', '["Julia Marschallinger","Tal Iram","Macy E. Zardeneta","Song Eun Lee","Benoit Lehallier","Michael S. Haney","John V. Pluvinage","Vidhu Mathur","Oliver Hãhn","David W. Morgens","Justin Kim","Julia Tevini","Thomas K. Felder","Heimo Wolinski","Carolyn R. Bertozzi","Michael C. Bassik","Ludwig Aigner","Tony Wyss‐Coray"]', 'psychology', NULL, '2026-07-08 08:00:20');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2791548393', 'psychology', 'Moving magnetoencephalography towards real-world applications with a wearable system', 'Moving magnetoencephalography towards real-world applications with a wearable system', '2018', 2018, 1383, 1383, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature26147/MediaObjects/41586_2018_Article_BFnature26147_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6063354', 'pmc', 'article', 'Nature', '["Elena Boto","Niall Holmes","James Leggett","Gillian Roberts","Vishal Shah","Sofie S. Meyer","Leonardo Duque‐Muñoz","Karen J. Mullinger","Tim M. Tierney","Sven Bestmann","Gareth R. Barnes","Richard Bowtell","Matthew J. Brookes"]', 'psychology', NULL, '2026-07-08 08:00:21');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2590009086', 'psychology', 'Gamifying education: what is known, what is believed and what remains uncertain: a critical review', 'Gamification of education is a developing approach for increasing learners'' motivation and engagement by incorporating game design elements in educational environments. With the growing popularity of…', '2017', 2017, 1359, 1359, 'https://media.springernature.com/lw685/springer-static/image/art%3A10.1186%2Fs41239-017-0042-5/MediaObjects/41239_2017_42_Fig1_HTML.gif', 'https://doi.org/10.1186/s41239-017-0042-5', 'repository', 'review', 'International Journal of Educational Technology in Higher Education', '["Christo Dichev","Darina Dicheva"]', 'psychology', 'Gamification of education is a developing approach for increasing learners'' motivation and engagement by incorporating game design elements in educational environments. With the growing popularity of gamification and yet mixed success of its application in educational contexts, the current review is aiming to shed a more realistic light on the research in this field by focusing on empirical evidence rather than on potentialities, beliefs or preferences. Accordingly, it critically examines the advancement in gamifying education. The discussion is structured around the used gamification mechanisms, the gamified subjects, the type of gamified learning activities, and the study goals, with an emphasis on the reliability and validity of the reported outcomes. To improve our understanding and offer a more realistic picture of the progress of gamification in education, consistent with the presented evidence, we examine both the outcomes reported in the papers and how they have been obtained. While the gamification in education is still a growing phenomenon, the review reveals that (i) insufficient evidence exists to support the long-term benefits of gamification in educational contexts; (ii) the practice of gamifying learning has outpaced researchers'' understanding of its mechanisms and methods; (iii) the knowledge of how to gamify an activity in accordance with the specifics of the educational context is still limited. The review highlights the need for systematically designed studies and rigorously tested approaches confirming the educational benefits of gamification, if gamified learning is to become a recognized instructional approach.', '2026-07-08 08:00:33');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3030253100', 'psychology', 'How to use and assess qualitative research methods', 'Abstract This paper aims to provide an overview of the use and assessment of qualitative research methods in the health sciences. Qualitative research can be defined as the study of the nature of…', '2020', 2020, 1370, 1370, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs42466-020-00059-z/MediaObjects/42466_2020_59_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7650082', 'pmc', 'review', 'Neurological Research and Practice', '["Loraine Busetto","Wolfgang Wick","Christoph Gumbinger"]', 'psychology', 'Abstract This paper aims to provide an overview of the use and assessment of qualitative research methods in the health sciences. Qualitative research can be defined as the study of the nature of phenomena and is especially appropriate for answering questions of why something is (not) observed, assessing complex multi-component interventions, and focussing on intervention improvement. The most common methods of data collection are document study, (non-) participant observations, semi-structured interviews and focus groups. For data analysis, field-notes and audio-recordings are transcribed into protocols and transcripts, and coded using qualitative data management software. Criteria such as checklists, reflexivity, sampling strategies, piloting, co-coding, member-checking and stakeholder involvement can be used to enhance and assess the quality of the research conducted. Using qualitative in addition to quantitative designs will equip us with better tools to address a greater range of research problems, and to fill in blind spots in current neurological research and practice.', '2026-07-08 08:00:33');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2288461920', 'psychology', 'Physical activity in older age: perspectives for healthy ageing and frailty', 'Regular physical activity helps to improve physical and mental functions as well as reverse some effects of chronic disease to keep older people mobile and independent. Despite the highly publicised…', '2016', 2016, 1366, 1366, 'https://media.springernature.com/lw685/springer-static/image/art%3A10.1007%2Fs10522-016-9641-0/MediaObjects/10522_2016_9641_Fig1_HTML.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4889622', 'pmc', 'review', 'Biogerontology', '["Jamie S. McPhee","David French","Dean Jackson","James Nazroo","Neil Pendleton","Hans Degens"]', 'psychology', 'Regular physical activity helps to improve physical and mental functions as well as reverse some effects of chronic disease to keep older people mobile and independent. Despite the highly publicised benefits of physical activity, the overwhelming majority of older people in the United Kingdom do not meet the minimum physical activity levels needed to maintain health. The sedentary lifestyles that predominate in older age results in premature onset of ill health, disease and frailty. Local authorities have a responsibility to promote physical activity amongst older people, but knowing how to stimulate regular activity at the population-level is challenging. The physiological rationale for physical activity, risks of adverse events, societal and psychological factors are discussed with a view to inform public health initiatives for the relatively healthy older person as well as those with physical frailty. The evidence shows that regular physical activity is safe for healthy and for frail older people and the risks of developing major cardiovascular and metabolic diseases, obesity, falls, cognitive impairments, osteoporosis and muscular weakness are decreased by regularly completing activities ranging from low intensity walking through to more vigorous sports and resistance exercises. Yet, participation in physical activities remains low amongst older adults, particularly those living in less affluent areas. Older people may be encouraged to increase their activities if influenced by clinicians, family or friends, keeping costs low and enjoyment high, facilitating group-based activities and raising self-efficacy for exercise.', '2026-07-08 08:00:33');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2604674575', 'psychology', 'Posttraumatic stress disorder in the World Mental Health Surveys', 'BACKGROUND: Traumatic events are common globally; however, comprehensive population-based cross-national data on the epidemiology of posttraumatic stress disorder (PTSD), the paradigmatic…', '2017', 2017, 1373, 1373, 'https://static.cambridge.org/binary/version/id/urn:cambridge.org:id:binary-alt:20170913043510-51099-mediumThumb-S0033291717000708_fig1g.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6034513', 'pmc', 'article', 'Psychological Medicine', '["Karestan C. Koenen","Andrew Ratanatharathorn","Lauren C. Ng","Katie A. McLaughlin","Evelyn J. Bromet","Dan J. Stein","Elie G. Karam","Ayelet Meron Ruscio","Corina Benjet","Kate M. Scott","Lukoye Atwoli","Maria Petukhova","Carmen Lim","Sergio Aguilar‐Gaxiola","A. Al-Hamzawi","Jordi Alonso","Brendan Bunting","Marius Ciutan","Giovanni de Girolamo","Louisa Degenhardt","Oye Gureje","Josep María Haro","Yueqin Huang","Norito Kawakami","S. Lee","Fernando Navarro‐Mateu","B.‐E. Pennell","Marina Piazza","Nancy A. Sampson","M. ten Have","Yolanda Torres","María Carmen Viana","Daniel R. Williams","Miguel Xavier","Ronald C. Kessler"]', 'psychology', 'BACKGROUND: Traumatic events are common globally; however, comprehensive population-based cross-national data on the epidemiology of posttraumatic stress disorder (PTSD), the paradigmatic trauma-related mental disorder, are lacking. METHODS: Data were analyzed from 26 population surveys in the World Health Organization World Mental Health Surveys. A total of 71 083 respondents ages 18+ participated. The Composite International Diagnostic Interview assessed exposure to traumatic events as well as 30-day, 12-month, and lifetime PTSD. Respondents were also assessed for treatment in the 12 months preceding the survey. Age of onset distributions were examined by country income level. Associations of PTSD were examined with country income, world region, and respondent demographics. RESULTS: The cross-national lifetime prevalence of PTSD was 3.9% in the total sample and 5.6% among the trauma exposed. Half of respondents with PTSD reported persistent symptoms. Treatment seeking in high-income countries (53.5%) was roughly double that in low-lower middle income (22.8%) and upper-middle income (28.7%) countries. Social disadvantage, including younger age, female sex, being unmarried, being less educated, having lower household income, and being unemployed, was associated with increased risk of lifetime PTSD among the trauma exposed. CONCLUSIONS: PTSD is prevalent cross-nationally, with half of all global cases being persistent. Only half of those with severe PTSD report receiving any treatment and only a minority receive specialty mental health care. Striking disparities in PTSD treatment exist by country income level. Increasing access to effective treatment, especially in low- and middle-income countries, remains critical for reducing the population burden of PTSD.', '2026-07-08 08:00:33');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2883929777', 'psychology', 'Engaging patients to improve quality of care: a systematic review', 'BACKGROUND: To identify the strategies and contextual factors that enable optimal engagement of patients in the design, delivery, and evaluation of health services. METHODS: We searched MEDLINE,…', '2018', 2018, 1348, 1348, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs13012-018-0784-z/MediaObjects/13012_2018_784_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6060529', 'pmc', 'review', 'Implementation Science', '["Yvonne Bombard","G. Ross Baker","Elaina Orlando","Carol Fancott","Pooja Bhatia","Selina Casalino","Känecy Oñate","Jean‐Louis Denis","Marie‐Pascale Pomey"]', 'psychology', 'BACKGROUND: To identify the strategies and contextual factors that enable optimal engagement of patients in the design, delivery, and evaluation of health services. METHODS: We searched MEDLINE, EMBASE, CINAHL, Cochrane, Scopus, PsychINFO, Social Science Abstracts, EBSCO, and ISI Web of Science from 1990 to 2016 for empirical studies addressing the active participation of patients, caregivers, or families in the design, delivery and evaluation of health services to improve quality of care. Thematic analysis was used to identify (1) strategies and contextual factors that enable optimal engagement of patients, (2) outcomes of patient engagement, and (3) patients'' experiences of being engaged. RESULTS: Forty-eight studies were included. Strategies and contextual factors that enable patient engagement were thematically grouped and related to techniques to enhance design, recruitment, involvement and leadership action, and those aimed to creating a receptive context. Reported outcomes ranged from educational or tool development and informed policy or planning documents (discrete products) to enhanced care processes or service delivery and governance (care process or structural outcomes). The level of engagement appears to influence the outcomes of service redesign-discrete products largely derived from low-level engagement (consultative unidirectional feedback)-whereas care process or structural outcomes mainly derived from high-level engagement (co-design or partnership strategies). A minority of studies formally evaluated patients'' experiences of the engagement process (n = 12; 25%). While most experiences were positive-increased self-esteem, feeling empowered, or independent-some patients sought greater involvement and felt that their involvement was important but tokenistic, especially when their requests were denied or decisions had already been made. CONCLUSIONS: Patient engagement can inform patient and provider education and policies, as well as enhance service delivery and governance. Additional evidence is needed to understand patients'' experiences of the engagement process and whether these outcomes translate into improved quality of care. REGISTRATION: N/A (data extraction completed prior to registration on PROSPERO).', '2026-07-08 08:00:42');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4324129606', 'psychology', 'Data quality in online human-subjects research: Comparisons between MTurk, Prolific, CloudResearch, Qualtrics, and SONA', 'With the proliferation of online data collection in human-subjects research, concerns have been raised over the presence of inattentive survey participants and non-human respondents (bots). We…', '2023', 2023, 1351, 1351, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0279720.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/10013894', 'pmc', 'article', 'PLoS ONE', '["Benjamin D Douglas","Patrick J. Ewell","Markus Bräuer"]', 'psychology', 'With the proliferation of online data collection in human-subjects research, concerns have been raised over the presence of inattentive survey participants and non-human respondents (bots). We compared the quality of the data collected through five commonly used platforms. Data quality was indicated by the percentage of participants who meaningfully respond to the researcher''s question (high quality) versus those who only contribute noise (low quality). We found that compared to MTurk, Qualtrics, or an undergraduate student sample (i.e., SONA), participants on Prolific and CloudResearch were more likely to pass various attention checks, provide meaningful answers, follow instructions, remember previously presented information, have a unique IP address and geolocation, and work slowly enough to be able to read all the items. We divided the samples into high- and low-quality respondents and computed the cost we paid per high-quality respondent. Prolific ($1.90) and CloudResearch ($2.00) were cheaper than MTurk ($4.36) and Qualtrics ($8.17). SONA cost $0.00, yet took the longest to collect the data.', '2026-07-08 08:00:42');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2884696611', 'psychology', 'OpenSim: Simulating musculoskeletal dynamics and neuromuscular control to study human and animal movement', 'Movement is fundamental to human and animal life, emerging through interaction of complex neural, muscular, and skeletal systems. Study of movement draws from and contributes to diverse fields,…', '2018', 2018, 1338, 1338, 'https://journals.plos.org/ploscompbiol/article/figure/image?size=large&id=10.1371/journal.pcbi.1006223.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6061994', 'pmc', 'article', 'PLoS Computational Biology', '["Ajay Seth","Jennifer L. Hicks","Thomas K. Uchida","Ayman Habib","Christopher L. Dembia","James J. Dunne","Carmichael Ong","Matthew S. DeMers","Apoorva Rajagopal","Matthew Millard","Samuel R. Hamner","Edith M. Arnold","Jennifer R. Yong","Shrinidhi Kowshika Lakshmikanth","Michael Sherman","Joy P. Ku","Scott L. Delp"]', 'psychology', 'Movement is fundamental to human and animal life, emerging through interaction of complex neural, muscular, and skeletal systems. Study of movement draws from and contributes to diverse fields, including biology, neuroscience, mechanics, and robotics. OpenSim unites methods from these fields to create fast and accurate simulations of movement, enabling two fundamental tasks. First, the software can calculate variables that are difficult to measure experimentally, such as the forces generated by muscles and the stretch and recoil of tendons during movement. Second, OpenSim can predict novel movements from models of motor control, such as kinematic adaptations of human gait during loaded or inclined walking. Changes in musculoskeletal dynamics following surgery or due to human-device interaction can also be simulated; these simulations have played a vital role in several applications, including the design of implantable mechanical devices to improve human grasping in individuals with paralysis. OpenSim is an extensible and user-friendly software package built on decades of knowledge about computational modeling and simulation of biomechanical systems. OpenSim''s design enables computational scientists to create new state-of-the-art software tools and empowers others to use these tools in research and clinical applications. OpenSim supports a large and growing community of biomechanics and rehabilitation researchers, facilitating exchange of models and simulations for reproducing and extending discoveries. Examples, tutorials, documentation, and an active user forum support this community. The OpenSim software is covered by the Apache License 2.0, which permits its use for any purpose including both nonprofit and commercial applications. The source code is freely and anonymously accessible on GitHub, where the community is welcomed to make contributions. Platform-specific installers of OpenSim include a GUI and are available on simtk.org.', '2026-07-08 08:01:10');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3121623025', 'psychology', 'Public opinion on automated driving: Results of an international questionnaire among 5000 respondents', 'Public opinion on automated driving: Results of an international questionnaire among 5000 respondents', '2015', 2015, 1325, 1325, 'https://ars.els-cdn.com/content/image/1-s2.0-S1369847815000777-fx1.jpg', 'https://doi.org/10.1016/j.trf.2015.04.014', 'repository', 'article', 'Transportation Research Part F Traffic Psychology and Behaviour', '["Miltos Kyriakidis","Riender Happee","Joost de Winter"]', 'psychology', NULL, '2026-07-08 08:01:32');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1139015881', 'psychology', 'Optogenetics: 10 years of microbial opsins in neuroscience', 'Optogenetics: 10 years of microbial opsins in neuroscience', '2015', 2015, 1315, 1315, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnn.4091/MediaObjects/41593_2015_Article_BFnn4091_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4790845', 'pmc', 'review', 'Nature Neuroscience', '["Karl Deisseroth"]', 'psychology', NULL, '2026-07-08 08:01:34');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1893670457', 'psychology', 'Self-injurious thoughts and behaviors as risk factors for future suicide ideation, attempts, and death: a meta-analysis of longitudinal studies', 'BACKGROUND: A history of self-injurious thoughts and behaviors (SITBs) is consistently cited as one of the strongest predictors of future suicidal behavior. However, stark discrepancies in the…', '2015', 2015, 1320, 1320, 'https://static.cambridge.org/binary/version/id/urn:cambridge.org:id:binary-alt:20170128074339-97812-mediumThumb-S0033291715001804_fig1g.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4774896', 'pmc', 'review', 'Psychological Medicine', '["Jessica D. Ribeiro","Joseph C. Franklin","Kathryn R. Fox","Kate H. Bentley","Evan M. Kleiman","Bernard Chang","Matthew K. Nock"]', 'psychology', 'BACKGROUND: A history of self-injurious thoughts and behaviors (SITBs) is consistently cited as one of the strongest predictors of future suicidal behavior. However, stark discrepancies in the literature raise questions about the true magnitude of these associations. The objective of this study is to examine the magnitude and clinical utility of the associations between SITBs and subsequent suicide ideation, attempts, and death. METHOD: We searched PubMed, PsycInfo, and Google Scholar for papers published through December 2014. Inclusion required that studies include at least one longitudinal analysis predicting suicide ideation, attempts, or death using any SITB variable. We identified 2179 longitudinal studies; 172 met inclusion criteria. RESULTS: The most common outcome was suicide attempt (47.80%), followed by death (40.50%) and ideation (11.60%). Median follow-up was 52 months (mean = 82.52, s.d. = 102.29). Overall prediction was weak, with weighted mean odds ratios (ORs) of 2.07 [95% confidence interval (CI) 1.76-2.43] for ideation, 2.14 (95% CI 2.00-2.30) for attempts, and 1.54 (95% CI 1.39-1.71) for death. Adjusting for publication bias further reduced estimates. Diagnostic accuracy analyses indicated acceptable specificity (86-87%) and poor sensitivity (10-26%), with areas under the curve marginally above chance (0.60-0.62). Most risk factors generated OR estimates of <2.0 and no risk factor exceeded 4.5. Effects were consistent regardless of sample severity, sample age groups, or follow-up length. CONCLUSIONS: Prior SITBs confer risk for later suicidal thoughts and behaviors. However, they only provide a marginal improvement in diagnostic accuracy above chance. Addressing gaps in study design, assessment, and underlying mechanisms may prove useful in improving prediction and prevention of suicidal thoughts and behaviors.', '2026-07-08 08:01:34');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2904860816', 'psychology', 'Beyond confidence: Development of a measure assessing the 5C psychological antecedents of vaccination', 'BACKGROUND: Monitoring the reasons why a considerable number of people do not receive recommended vaccinations allows identification of important trends over time, and designing and evaluating…', '2018', 2018, 1310, 1310, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0208601.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6285469', 'pmc', 'article', 'PLoS ONE', '["Cornelia Betsch","Philipp Schmid","Dorothee Heinemeier","Lars Korn","Cindy Holtmann","Robert Böhm"]', 'psychology', 'BACKGROUND: Monitoring the reasons why a considerable number of people do not receive recommended vaccinations allows identification of important trends over time, and designing and evaluating strategies to address vaccine hesitancy and increase vaccine uptake. Existing validated measures assessing vaccine hesitancy focus primarily on confidence in vaccines and the system that delivers them. However, empirical and theoretical work has stated that complacency (not perceiving diseases as high risk), constraints (structural and psychological barriers), calculation (engagement in extensive information searching), and aspects pertaining to collective responsibility (willingness to protect others) also play a role in explaining vaccination behavior. The objective was therefore to develop a validated measure of these 5C psychological antecedents of vaccination. METHODS AND FINDINGS: Three cross-sectional studies were conducted. Study 1 uses factor analysis to develop an initial scale and assesses the sub-scales'' convergent, discriminant, and concurrent validity (N = 1,445, two German convenience-samples). In Study 2, a sample representative regarding age and gender for the German population (N = 1,003) completed the measure for vaccination in general and for specific vaccinations to assess the potential need for a vaccine-specific wording of items. Study 3 compared the novel scale''s performance with six existing measures of vaccine hesitancy (N = 350, US convenience-sample). As an outcome, a long (15-item) and short (5-item) 5C scale were developed as reliable and valid indicators of confidence, complacency, constraints, calculation, and collective responsibility. The 5C sub-scales correlated with relevant psychological concepts, such as attitude (confidence), perceived personal health status and invulnerability (complacency), self-control (constraints), preference for deliberation (calculation), and communal orientation (collective responsibility), among others. The new scale provided similar results when formulated in a general vs. vaccine-specific way (Study 2). In a comparison of seven measures the 5C scale was constantly among the scales that explained the highest amounts of variance in analyses predicting single vaccinations (between 20% and 40%; Study 3). The present studies are limited to the concurrent validity of the scales. CONCLUSIONS: The 5C scale provides a novel tool to monitor psychological antecedents of vaccination and facilitates diagnosis, intervention design and evaluation. Its short version is suitable for field settings and regular global monitoring of relevant antecedents of vaccination.', '2026-07-08 08:01:39');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2581492029', 'psychology', 'Barriers of Influenza Vaccination Intention and Behavior – A Systematic Review of Influenza Vaccine Hesitancy, 2005 – 2016', 'BACKGROUND: Influenza vaccine hesitancy is a significant threat to global efforts to reduce the burden of seasonal and pandemic influenza. Potential barriers of influenza vaccination need to be…', '2017', 2017, 1267, 1267, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0170550.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5268454', 'pmc', 'review', 'PLoS ONE', '["Philipp Schmid","Dorothee Rauber","Cornelia Betsch","Gianni Lidolt","Marie-Luisa Denker"]', 'psychology', 'BACKGROUND: Influenza vaccine hesitancy is a significant threat to global efforts to reduce the burden of seasonal and pandemic influenza. Potential barriers of influenza vaccination need to be identified to inform interventions to raise awareness, influenza vaccine acceptance and uptake. OBJECTIVE: This review aims to (1) identify relevant studies and extract individual barriers of seasonal and pandemic influenza vaccination for risk groups and the general public; and (2) map knowledge gaps in understanding influenza vaccine hesitancy to derive directions for further research and inform interventions in this area. METHODS: Thirteen databases covering the areas of Medicine, Bioscience, Psychology, Sociology and Public Health were searched for peer-reviewed articles published between the years 2005 and 2016. Following the PRISMA approach, 470 articles were selected and analyzed for significant barriers to influenza vaccine uptake or intention. The barriers for different risk groups and flu types were clustered according to a conceptual framework based on the Theory of Planned Behavior and discussed using the 4C model of reasons for non-vaccination. RESULTS: Most studies were conducted in the American and European region. Health care personnel (HCP) and the general public were the most studied populations, while parental decisions for children at high risk were under-represented. This study also identifies understudied concepts. A lack of confidence, inconvenience, calculation and complacency were identified to different extents as barriers to influenza vaccine uptake in risk groups. CONCLUSION: Many different psychological, contextual, sociodemographic and physical barriers that are specific to certain risk groups were identified. While most sociodemographic and physical variables may be significantly related to influenza vaccine hesitancy, they cannot be used to explain its emergence or intensity. Psychological determinants were meaningfully related to uptake and should therefore be measured in a valid and comparable way. A compendium of measurements for future use is suggested as supporting information.', '2026-07-08 08:02:32');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2262104057', 'sociology', 'Gender Gap in Science, Technology, Engineering, and Mathematics (STEM): Current Knowledge, Implications for Practice, Policy, and Future Directions', 'Gender Gap in Science, Technology, Engineering, and Mathematics (STEM): Current Knowledge, Implications for Practice, Policy, and Future Directions', '2016', 2016, 1144, 1144, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1007%2Fs11135-025-02110-0/MediaObjects/11135_2025_2110_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5404748', 'pmc', 'article', 'Educational Psychology Review', '["Ming‐Te Wang","Jessica L. Degol"]', 'sociology', NULL, '2026-07-08 08:04:31');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3038513886', 'sociology', 'Impact of the COVID-19 virus outbreak on movement and play behaviours of Canadian children and youth: a national survey', 'BACKGROUND: Healthy childhood development is fostered through sufficient physical activity (PA; including time outdoors), limiting sedentary behaviours (SB), and adequate sleep; collectively known as…', '2020', 2020, 1128, 1128, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs12966-020-00987-8/MediaObjects/12966_2020_987_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7336091', 'pmc', 'article', 'International Journal of Behavioral Nutrition and Physical Activity', '["Sarah A. Moore","Guy Faulkner","Ryan E. Rhodes","Mariana Brussoni","Tala Chulak-Bozzer","Leah J. Ferguson","Raktim Mitra","Norm O’Reilly","John C. Spence","Leigh M. Vanderloo","Mark S. Tremblay"]', 'sociology', 'BACKGROUND: Healthy childhood development is fostered through sufficient physical activity (PA; including time outdoors), limiting sedentary behaviours (SB), and adequate sleep; collectively known as movement behaviours. Though the COVID-19 virus outbreak has changed the daily lives of children and youth, it is unknown to what extent related restrictions may compromise the ability to play and meet movement behaviour recommendations. This secondary data analysis examined the immediate impacts of COVID-19 restrictions on movement and play behaviours in children and youth. METHODS: A national sample of Canadian parents (n = 1472) of children (5-11 years) or youth (12-17 years) (54% girls) completed an online survey that assessed immediate changes in child movement and play behaviours during the COVID-19 outbreak. Behaviours included PA and play, SB, and sleep. Family demographics and parental factors that may influence movement behaviours were assessed. Correlations between behaviours and demographic and parental factors were determined. For open-ended questions, word frequency distributions were reported. RESULTS: Only 4.8% (2.8% girls, 6.5% boys) of children and 0.6% (0.8% girls, 0.5% boys) of youth were meeting combined movement behaviour guidelines during COVID-19 restrictions. Children and youth had lower PA levels, less outside time, higher SB (including leisure screen time), and more sleep during the outbreak. Parental encouragement and support, parental engagement in PA, and family dog ownership were positively associated with healthy movement behaviours. Although families spent less time in PA and more time in SB, several parents reported adopting new hobbies or accessing new resources. CONCLUSIONS: This study provides evidence of immediate collateral consequences of the COVID-19 outbreak, demonstrating an adverse impact on the movement and play behaviours of Canadian children and youth. These findings can guide efforts to preserve and promote child health during the COVID-19 outbreak and crisis recovery period, and to inform strategies to mitigate potential harm during future pandemics.', '2026-07-08 08:04:33');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2075528760', 'sociology', 'Using the theory of planned behavior to identify key beliefs underlying pro-environmental behavior in high-school students: Implications for educational interventions', 'Using the theory of planned behavior to identify key beliefs underlying pro-environmental behavior in high-school students: Implications for educational interventions', '2015', 2015, 1105, 1105, 'https://ars.els-cdn.com/content/image/1-s2.0-S0272494415000298-gr1.jpg', 'https://doi.org/10.1016/j.jenvp.2015.03.005', 'repository', 'article', 'Journal of Environmental Psychology', '["Astrid de Leeuw","Pierre Valois","Icek Ajzen","Peter Schmidt"]', 'sociology', NULL, '2026-07-08 08:04:45');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2398010472', 'sociology', 'Screening for Depression in the General Population with the Center for Epidemiologic Studies Depression (CES-D): A Systematic Review with Meta-Analysis', 'OBJECTIVE: We aimed to collect and meta-analyse the existing evidence regarding the performance of the Center for Epidemiologic Studies Depression (CES-D) for detecting depression in general…', '2016', 2016, 978, 978, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0155431.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4868329', 'pmc', 'review', 'PLoS ONE', '["Gemma Vilagut","Carlos G. Forero","Gabriela Barbaglia","Jordi Alonso"]', 'sociology', 'OBJECTIVE: We aimed to collect and meta-analyse the existing evidence regarding the performance of the Center for Epidemiologic Studies Depression (CES-D) for detecting depression in general population and primary care settings. METHOD: Systematic literature search in PubMed and PsychINFO. Eligible studies were: a) validation studies of screening questionnaires with information on the accuracy of the CES-D; b) samples from general populations or primary care settings; c) standardized diagnostic interviews following standard classification systems used as gold standard; and d) English or Spanish language of publication. Pooled sensitivity, specificity, likelihood ratios and diagnostic odds ratio were estimated for several cut-off points using bivariate mixed effects models for each threshold. The summary receiver operating characteristic curve was estimated with Rutter and Gatsonis mixed effects models; area under the curve was calculated. Quality of the studies was assessed with the QUADAS tool. Causes of heterogeneity were evaluated with the Rutter and Gatsonis mixed effects model including each covariate at a time. RESULTS: 28 studies (10,617 participants) met eligibility criteria. The median prevalence of Major Depression was 8.8% (IQ range from 3.8% to 12.6%). The overall area under the curve was 0.87. At the cut-off 16, sensitivity was 0.87 (95% CI: 0.82-0.92), specificity 0.70 (95% CI: 0.65-0.75), and DOR 16.2 (95% CI: 10.49-25.10). Better trade-offs between sensitivity and specificity were observed (Sensitivity = 0.83, Specificity = 0.78, diagnostic odds ratio = 16.64) for cut-off 20. None of the variables assessed as possible sources of heterogeneity was found to be statistically significant. CONCLUSION: The CES-D has acceptable screening accuracy in the general population or primary care settings, but it should not be used as an isolated diagnostic measure of depression. Depending on the test objectives, the cut-off 20 may be more adequate than the value of 16, which is typically recommended.', '2026-07-08 08:05:07');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2468796193', 'sociology', '“I don’t want to miss a thing”: Adolescents’ fear of missing out and its relationship to adolescents’ social needs, Facebook use, and Facebook related stress', '“I don’t want to miss a thing”: Adolescents’ fear of missing out and its relationship to adolescents’ social needs, Facebook use, and Facebook related stress', '2016', 2016, 828, 828, 'https://ars.els-cdn.com/content/image/1-s2.0-S0747563216304198-gr1.jpg', 'https://doi.org/10.1016/j.chb.2016.05.083', 'repository', 'article', 'Computers in Human Behavior', '["Ine Beyens","Eline Frison","Steven Eggermont"]', 'sociology', NULL, '2026-07-08 08:06:07');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2468117220', 'sociology', 'Development and Validation of a Self-Report Measure of Mentalizing: The Reflective Functioning Questionnaire', 'Reflective functioning or mentalizing is the capacity to interpret both the self and others in terms of internal mental states such as feelings, wishes, goals, desires, and attitudes. This paper is…', '2016', 2016, 731, 731, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0158678.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4938585', 'pmc', 'article', 'PLoS ONE', '["Peter Fonagy","Patrick Luyten","Alesia Moulton‐Perkins","Ya-Wen Lee","Fiona C Warren","Susan Howard","Rosanna Ghinai","Pasco Fearon","Benedicte Lowyck"]', 'sociology', 'Reflective functioning or mentalizing is the capacity to interpret both the self and others in terms of internal mental states such as feelings, wishes, goals, desires, and attitudes. This paper is part of a series of papers outlining the development and psychometric features of a new self-report measure, the Reflective Functioning Questionnaire (RFQ), designed to provide an easy to administer self-report measure of mentalizing. We describe the development and initial validation of the RFQ in three studies. Study 1 focuses on the development of the RFQ, its factor structure and construct validity in a sample of patients with Borderline Personality Disorder (BPD) and Eating Disorder (ED) (n = 108) and normal controls (n = 295). Study 2 aims to replicate these findings in a fresh sample of 129 patients with personality disorder and 281 normal controls. Study 3 addresses the relationship between the RFQ, parental reflective functioning and infant attachment status as assessed with the Strange Situation Procedure (SSP) in a sample of 136 community mothers and their infants. In both Study 1 and 2, confirmatory factor analyses yielded two factors assessing Certainty (RFQ_C) and Uncertainty (RFQ_U) about the mental states of self and others. These two factors were relatively distinct, invariant across clinical and non-clinical samples, had satisfactory internal consistency and test-retest stability, and were largely unrelated to demographic features. The scales discriminated between patients and controls, and were significantly and in theoretically predicted ways correlated with measures of empathy, mindfulness and perspective-taking, and with both self-reported and clinician-reported measures of borderline personality features and other indices of maladaptive personality functioning. Furthermore, the RFQ scales were associated with levels of parental reflective functioning, which in turn predicted infant attachment status in the SSP. Overall, this study lends preliminary support for the RFQ as a screening measure of reflective functioning. Further research is needed, however, to investigate in more detail the psychometric qualities of the RFQ.', '2026-07-08 08:06:39');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3113208589', 'sociology', 'Burnout Assessment Tool (BAT)—Development, Validity, and Reliability', 'This paper introduces a new definition for burnout and investigates the psychometric properties of the Burnout Assessment Tool (BAT). In a prior qualitative study, 49 practitioners were interviewed…', '2020', 2020, 700, 700, 'https://pub.mdpi-res.com/ijerph/ijerph-17-09495/article_deploy/html/images/ijerph-17-09495-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7766078', 'pmc', 'article', 'International Journal of Environmental Research and Public Health', '["Wilmar B. Schaufeli","Steffie Desart","Hans De Witte"]', 'sociology', 'This paper introduces a new definition for burnout and investigates the psychometric properties of the Burnout Assessment Tool (BAT). In a prior qualitative study, 49 practitioners were interviewed about their conceptualization of burnout (part 1). Using a dialectical approach, four core dimensions-exhaustion, mental distance, and impaired emotional and cognitive impairment-and three secondary dimensions-depressed mood, psychological distress, and psychosomatic complaints-emerged, which constitute the basis of the BAT. In the second study, the psychometric characteristics of the BAT were investigated in a representative sample of 1500 Flemish employees, focusing on factorial validity, reliability, and construct validity, respectively. Results demonstrate the assumed four-factor structure for the core dimensions, which is best represented by one general burnout factor. Contrary to expectations, instead of a three-factor structure, a two-factor structure was found for the secondary dimensions. Furthermore, the BAT and its subscales show adequate reliability. Convergent validity and discriminant validity with other burnout measures-including the MBI and OLBI-was demonstrated, as well as discriminant validity with other well-being constructs, such as work engagement and workaholism.', '2026-07-08 08:07:18');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2942996956', 'sociology', 'The Relationship Between Nature Connectedness and Eudaimonic Well-Being: A Meta-analysis', 'Nature connectedness relates to an individual’s subjective sense of their relationship with the natural world. A recent meta-analysis has found that people who are more connected to nature also tend…', '2019', 2019, 675, 675, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1007%2Fs10902-019-00118-6/MediaObjects/10902_2019_118_Fig1_HTML.png', 'https://doi.org/10.1007/s10902-019-00118-6', 'repository', 'article', 'Journal of Happiness Studies', '["Alison Pritchard","Miles Richardson","David Sheffield","Kirsten McEwan"]', 'sociology', 'Nature connectedness relates to an individual’s subjective sense of their relationship with the natural world. A recent meta-analysis has found that people who are more connected to nature also tend to have higher levels of self-reported hedonic well-being; however, no reviews have focussed on nature connection and eudaimonic well-being. This meta-analysis was undertaken to explore the relationship of nature connection with eudaimonic well-being and to test the hypothesis that this relationship is stronger than that of nature connection and hedonic well-being. From 20 samples (n = 4758), a small significant effect size was found for the relationship of nature connection and eudaimonic well-being (r = 0.24); there was no significant difference between this and the effect size (from 30 samples n = 11,638) for hedonic well-being (r = 0.20). Of the eudaimonic well-being subscales, personal growth had a moderate effect size which was significantly larger than the effect sizes for autonomy, purpose in life/meaning, self-acceptance, positive relations with others and environmental mastery, but not vitality. Thus, individuals who are more connected to nature tend to have greater eudaimonic well-being, and in particular have higher levels of self-reported personal growth.', '2026-07-08 08:07:24');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2332602756', 'sociology', 'Age and gender differences in self-esteem—A cross-cultural window.', 'Research and theorizing on gender and age differences in self-esteem have played a prominent role in psychology over the past 20 years. However, virtually all empirical research has been undertaken…', '2015', 2015, 672, 672, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1037/pspp0000078.g001', 'https://pubmed.ncbi.nlm.nih.gov/26692356', 'repository', 'article', 'Journal of Personality and Social Psychology', '["Wiebke Bleidorn","Ruben C. Arslan","Jaap J. A. Denissen","Peter J. Rentfrow","Jochen E. Gebauer","Jeff Potter","Samuel D. Gosling"]', 'sociology', 'Research and theorizing on gender and age differences in self-esteem have played a prominent role in psychology over the past 20 years. However, virtually all empirical research has been undertaken in the United States or other Western industrialized countries, providing a narrow empirical base from which to draw conclusions and develop theory. To broaden the empirical base, the present research uses a large Internet sample (N = 985,937) to provide the first large-scale systematic cross-cultural examination of gender and age differences in self-esteem. Across 48 nations, and consistent with previous research, we found age-related increases in self-esteem from late adolescence to middle adulthood and significant gender gaps, with males consistently reporting higher self-esteem than females. Despite these broad cross-cultural similarities, the cultures differed significantly in the magnitude of gender, age, and Gender × Age effects on self-esteem. These differences were associated with cultural differences in socioeconomic, sociodemographic, gender-equality, and cultural value indicators. Discussion focuses on the theoretical implications of cross-cultural research on self-esteem. (PsycINFO Database Record', '2026-07-08 08:07:52');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2802042678', 'sociology', 'A critical period for second language acquisition: Evidence from 2/3 million English speakers', 'A critical period for second language acquisition: Evidence from 2/3 million English speakers', '2018', 2018, 632, 632, 'https://ars.els-cdn.com/content/image/1-s2.0-S0010027718300994-gr1.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6559801', 'pmc', 'article', 'Cognition', '["Joshua K. Hartshorne","Joshua B. Tenenbaum","Steven Pinker"]', 'sociology', NULL, '2026-07-08 08:08:32');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2014548509', 'sociology', 'Stress and the social brain: behavioural effects and neurobiological mechanisms', 'Stress and the social brain: behavioural effects and neurobiological mechanisms', '2015', 2015, 616, 616, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnrn3918/MediaObjects/41583_2015_Article_BFnrn3918_Fig1_HTML.jpg', 'https://pubmed.ncbi.nlm.nih.gov/25891510', 'repository', 'review', 'Nature reviews. Neuroscience', '["Carmen Sandi","József Haller"]', 'sociology', NULL, '2026-07-08 08:08:41');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4293068820', 'sociology', 'Rare coding variation provides insight into the genetic architecture and phenotypic context of autism', 'Rare coding variation provides insight into the genetic architecture and phenotypic context of autism', '2022', 2022, 621, 621, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41588-022-01104-0/MediaObjects/41588_2022_1104_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/9653013', 'pmc', 'review', 'Nature Genetics', '["Jack Fu","F. Kyle Satterstrom","Minshi Peng","Harrison Brand","Ryan L. Collins","Shan Dong","Brie Wamsley","Lambertus Klei","Lily Wang","Stephanie P. Hao","Christine Stevens","Caroline Cusick","Mehrtash Babadi","Eric Banks","Brett Collins","Sheila Dodge","Stacey B. Gabriel","Laura D. Gauthier","Samuel K. Lee","Lindsay Liang","Alicia Ljungdahl","Behrang Mahjani","Laura Sloofman","Andrey N. Smirnov","Mafalda Barbosa","Catalina Betancur","Alfredo Brusco","Brian Hon‐Yin Chung","Edwin H. Cook","Michael L. Cuccaro","Enrico Domenici","Giovanni Battista Ferrero","J. Jay Gargus","Gail E. Herman","Irva Hertz‐Picciotto","Patrı́cia Maciel","Dara S. Manoach","Maria Rita Passos‐Bueno","Antonio M. Persico","Alessandra Renieri","James S. Sutcliffe","Flora Tassone","Elisabetta Trabetti","Gabriele da Silva Campos","Simona Cardaropoli","Diana Carli","Marcus C.Y. Chan","Chiara Fallerini","Elisa Giorgio","Ana Cristina De Sanctis Girardi","Emily Hansen‐Kiss","So Lun Lee","Carla Lintas","Yunin Ludeña","Rachel Nguyen","Lisa Pavinato","Margaret A. Pericak‐Vance","Isaac N. Pessah","Rebecca J. Schmidt","Moyra Smith","Claudia Ismania Samogy Costa","Slavica Trajkova","Jaqueline Y. T. Wang","Mullin H.C. Yu","Branko Aleksić","Mykyta Artomov","Elisa Benetti","Monica Biscaldi-Schafer","Anders D. Børglum","Ãngel Carracedo","Andreas G. Chiocchetti","Hilary Coon","Ryan N. Doan","Montse Fernández‐Prieto","Christine M. Freitag","Sherif Gerges","Stephen J. Guter","David M. Hougaard","Christina M. Hultman","Suma Jacob","Miia Kaartinen","A﻿lexander Kolevzon","Itaru Kushima","Terho Lehtimäki","Caterina Lo Rizzo","Nell Maltman","Marianna Manara","Gal Meiri","Idan Menashe","Judith Miller","Nancy J. Minshew","Matthew W. Mosconi","Norio Ozaki","Aarno Palotie","Mara Parellada","Kaija Puura","Abraham Reichenberg","Sven Sandin","Stephen W. Scherer","Sabine Schlitt"]', 'sociology', NULL, '2026-07-08 08:08:42');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2585989266', 'sociology', 'Neurotypical Peers are Less Willing to Interact with Those with Autism based on Thin Slice Judgments', 'Individuals with autism spectrum disorder (ASD), including those who otherwise require less support, face severe difficulties in everyday social interactions. Research in this area has primarily…', '2017', 2017, 572, 572, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fsrep40700/MediaObjects/41598_2017_Article_BFsrep40700_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5286449', 'pmc', 'article', 'Scientific Reports', '["Noah J. Sasson","Daniel J. Faso","Jack Nugent","Sarah Lovell","Daniel P. Kennedy","Ruth B. Grossman"]', 'sociology', 'Individuals with autism spectrum disorder (ASD), including those who otherwise require less support, face severe difficulties in everyday social interactions. Research in this area has primarily focused on identifying the cognitive and neurological differences that contribute to these social impairments, but social interaction by definition involves more than one person and social difficulties may arise not just from people with ASD themselves, but also from the perceptions, judgments, and social decisions made by those around them. Here, across three studies, we find that first impressions of individuals with ASD made from thin slices of real-world social behavior by typically-developing observers are not only far less favorable across a range of trait judgments compared to controls, but also are associated with reduced intentions to pursue social interaction. These patterns are remarkably robust, occur within seconds, do not change with increased exposure, and persist across both child and adult age groups. However, these biases disappear when impressions are based on conversational content lacking audio-visual cues, suggesting that style, not substance, drives negative impressions of ASD. Collectively, these findings advocate for a broader perspective of social difficulties in ASD that considers both the individual''s impairments and the biases of potential social partners.', '2026-07-08 08:09:25');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2474447283', 'sociology', 'Understanding Factors that Shape Gender Attitudes in Early Adolescence Globally: A Mixed-Methods Systematic Review', 'BACKGROUND: Early adolescence (ages 10-14) is a period of increased expectations for boys and girls to adhere to socially constructed and often stereotypical norms that perpetuate gender…', '2016', 2016, 551, 551, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0157805.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4920358', 'pmc', 'review', 'PLoS ONE', '["Anna Kågesten","Susannah Gibbs","Robert W. Blum","Caroline Moreau","Venkatraman Chandra‐Mouli","Ann Herbert","Avni Amin"]', 'sociology', 'BACKGROUND: Early adolescence (ages 10-14) is a period of increased expectations for boys and girls to adhere to socially constructed and often stereotypical norms that perpetuate gender inequalities. The endorsement of such gender norms is closely linked to poor adolescent sexual and reproductive and other health-related outcomes yet little is known about the factors that influence young adolescents'' personal gender attitudes. OBJECTIVES: To explore factors that shape gender attitudes in early adolescence across different cultural settings globally. METHODS: A mixed-methods systematic review was conducted of the peer-reviewed literature in 12 databases from 1984-2014. Four reviewers screened the titles and abstracts of articles and reviewed full text articles in duplicate. Data extraction and quality assessments were conducted using standardized templates by study design. Thematic analysis was used to synthesize quantitative and qualitative data organized by the social-ecological framework (individual, interpersonal and community/societal-level factors influencing gender attitudes). RESULTS: Eighty-two studies (46 quantitative, 31 qualitative, 5 mixed-methods) spanning 29 countries were included. Ninety percent of studies were from North America or Western Europe. The review findings indicate that young adolescents, across cultural settings, commonly express stereotypical or inequitable gender attitudes, and such attitudes appear to vary by individual sociodemographic characteristics (sex, race/ethnicity and immigration, social class, and age). Findings highlight that interpersonal influences (family and peers) are central influences on young adolescents'' construction of gender attitudes, and these gender socialization processes differ for boys and girls. The role of community factors (e.g. media) is less clear though there is some evidence that schools may reinforce stereotypical gender attitudes among young adolescents. CONCLUSIONS: The findings from this review suggest that young adolescents in different cultural settings commonly endorse norms that perpetuate gender inequalities, and that parents and peers are especially central in shaping such attitudes. Programs to promote equitable gender attitudes thus need to move beyond a focus on individuals to target their interpersonal relationships and wider social environments. Such programs need to start early and be tailored to the unique needs of sub-populations of boys and girls. Longitudinal studies, particularly from low-and middle-income countries, are needed to better understand how gender attitudes unfold in adolescence and to identify the key points for intervention.', '2026-07-08 08:10:06');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1909169078', 'sociology', 'The Ordinal Effects of Ostracism: A Meta-Analysis of 120 Cyberball Studies', 'We examined 120 Cyberball studies (N = 11,869) to determine the effect size of ostracism and conditions under which the effect may be reversed, eliminated, or small. Our analyses showed that (1) the…', '2015', 2015, 544, 544, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0127002.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4449005', 'pmc', 'review', 'PLoS ONE', '["Chris Hartgerink","Ilja van Beest","Jelte M. Wicherts","Kipling D. Williams"]', 'sociology', 'We examined 120 Cyberball studies (N = 11,869) to determine the effect size of ostracism and conditions under which the effect may be reversed, eliminated, or small. Our analyses showed that (1) the average ostracism effect is large (d > |1.4|) and (2) generalizes across structural aspects (number of players, ostracism duration, number of tosses, type of needs scale), sampling aspects (gender, age, country), and types of dependent measure (interpersonal, intrapersonal, fundamental needs). Further, we test Williams''s (2009) proposition that the immediate impact of ostracism is resistant to moderation, but that moderation is more likely to be observed in delayed measures. Our findings suggest that (3) both first and last measures are susceptible to moderation and (4) time passed since being ostracized does not predict effect sizes of the last measure. Thus, support for this proposition is tenuous and we suggest modifications to the temporal need-threat model of ostracism.', '2026-07-08 08:10:06');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2797465087', 'sociology', 'Functional circuit architecture underlying parental behaviour', 'Functional circuit architecture underlying parental behaviour', '2018', 2018, 504, 504, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-018-0027-0/MediaObjects/41586_2018_27_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5908752', 'pmc', 'article', 'Nature', '["Johannes Kohl","Bénédicte M. Babayan","Nimrod D. Rubinstein","Anita E. Autry","Brenda Marin-Rodriguez","Vikrant Kapoor","Kazunari Miyamishi","Larry S. Zweifel","Liqun Luo","Naoshige Uchida","Catherine Dulac"]', 'sociology', NULL, '2026-07-08 08:11:45');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3123520137', 'sociology', 'Gender differences in couples’ division of childcare, work and mental health during COVID-19', 'Gender differences in couples’ division of childcare, work and mental health during COVID-19', '2021', 2021, 506, 506, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1007%2Fs11150-020-09534-7/MediaObjects/11150_2020_9534_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7811157', 'pmc', 'article', 'Review of Economics of the Household', '["Gema Zamarro","María Prados"]', 'sociology', NULL, '2026-07-08 08:11:47');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3119633778', 'sociology', 'Why the COVID-19 pandemic is a traumatic stressor', 'The COVID-19 pandemic does not fit into prevailing Post-traumatic Stress Disorder (PTSD) models, or diagnostic criteria, yet emerging research shows traumatic stress symptoms as a result of this…', '2021', 2021, 491, 491, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0240146.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7799777', 'pmc', 'article', 'PLoS ONE', '["Victoria M. E. Bridgland","Ella K. Moeck","Deanne M. Green","Taylor L. Swain","Diane M. Nayda","Lucy A. Matson","Nadine P. Hutchison","Melanie K. T. Takarangi"]', 'sociology', 'The COVID-19 pandemic does not fit into prevailing Post-traumatic Stress Disorder (PTSD) models, or diagnostic criteria, yet emerging research shows traumatic stress symptoms as a result of this ongoing global stressor. Current pathogenic event models focus on past, and largely direct, trauma exposure to certain kinds of life-threatening events. Yet, traumatic stress reactions to future, indirect trauma exposure, and non-Criterion A events exist, suggesting COVID-19 is also a traumatic stressor which could lead to PTSD symptomology. To examine this idea, we asked a sample of online participants (N = 1,040), in five western countries, to indicate the COVID-19 events they had been directly exposed to, events they anticipated would happen in the future, and other forms of indirect exposure such as through media coverage. We then asked participants to complete the Posttraumatic Stress Disorder Checklist-5, adapted to measure pre/peri/post-traumatic reactions in relation to COVID-19. We also measured general emotional reactions (e.g., angry, anxious, helpless), well-being, psychosocial functioning, and depression, anxiety, and stress symptoms. We found participants had PTSD-like symptoms for events that had not happened and when participants had been directly (e.g., contact with virus) or indirectly exposed to COVID-19 (e.g., via media). Moreover, 13.2% of our sample were likely PTSD-positive, despite types of COVID-19 "exposure" (e.g., lockdown) not fitting DSM-5 criteria. The emotional impact of "worst" experienced/anticipated events best predicted PTSD-like symptoms. Taken together, our findings support emerging research that COVID-19 can be understood as a traumatic stressor event capable of eliciting PTSD-like responses and exacerbating other related mental health problems (e.g., anxiety, depression, psychosocial functioning, etc.). Our findings add to existing literature supporting a pathogenic event memory model of traumatic stress.', '2026-07-08 08:12:23');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4318486553', 'sociology', 'A systematic review and meta-analysis of the evidence on learning during the COVID-19 pandemic', 'A systematic review and meta-analysis of the evidence on learning during the COVID-19 pandemic', '2023', 2023, 488, 488, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41562-022-01506-4/MediaObjects/41562_2022_1506_Fig1_HTML.png', 'https://sciencespo.hal.science/hal-03954706', 'repository', 'review', 'Nature Human Behaviour', '["Bastian Andreas Betthäuser","Anders Bach‐Mortensen","Per Engzell"]', 'sociology', NULL, '2026-07-08 08:12:39');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3013064929', 'sociology', 'The transition to compulsion in addiction', 'The transition to compulsion in addiction', '2020', 2020, 488, 488, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41583-020-0289-z/MediaObjects/41583_2020_289_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7610550', 'pmc', 'review', 'Nature reviews. Neuroscience', '["Christian Lüscher","Trevor W. Robbins","Barry J. Everitt"]', 'sociology', NULL, '2026-07-08 08:12:39');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2119279206', 'sociology', 'Toward Understanding How Early-Life Stress Reprograms Cognitive and Emotional Brain Networks', 'Toward Understanding How Early-Life Stress Reprograms Cognitive and Emotional Brain Networks', '2015', 2015, 489, 489, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnpp.2015.181/MediaObjects/41386_2016_Article_BFnpp2015181_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4677123', 'pmc', 'review', 'Neuropsychopharmacology', '["Yuncai Chen","Tallie Z. Baram"]', 'sociology', NULL, '2026-07-08 08:12:39');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2610648287', 'sociology', 'The parental reflective functioning questionnaire: Development and preliminary validation', 'This paper reports on three studies on the development and validation of the Parental Reflective Functioning Questionnaire (PRFQ), a brief, multidimensional self-report measure that assesses parental…', '2017', 2017, 484, 484, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0176218.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5417431', 'pmc', 'article', 'PLoS ONE', '["Patrick Luyten","Linda C. Mayes","Liesbet Nijssens","Peter Fonagy"]', 'sociology', 'This paper reports on three studies on the development and validation of the Parental Reflective Functioning Questionnaire (PRFQ), a brief, multidimensional self-report measure that assesses parental reflective functioning or mentalizing, that is, the capacity to treat the infant as a psychological agent. Study 1 investigated the factor structure, reliability, and relationships of the PRFQ with demographic features, symptomatic distress, attachment dimensions, and emotional availability in a socially diverse sample of 299 mothers of a child aged 0-3. In Study 2, the factorial invariance of the PRFQ in mothers and fathers was investigated in a sample of 153 first-time parents, and relationships with demographic features, symptomatic distress, attachment dimensions, and parenting stress were investigated. Study 3 investigated the relationship between the PRFQ and infant attachment classification as assessed with the Strange Situation Procedure (SSP) in a sample of 136 community mothers and their infants. Exploratory and confirmatory factor analyses suggested three theoretically consistent factors assessing pre-mentalizing modes, certainty about the mental states of the infant, and interest and curiosity in the mental states of the infant. These factors were generally related in theoretically expected ways to parental attachment dimensions, emotional availability, parenting stress, and infant attachment status in the SSP. Yet, at the same time, more research on the PRFQ is needed to further establish its reliability and validity.', '2026-07-08 08:12:52');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2801468331', 'sociology', 'Physical Activity and Cognitive Functioning of Children: A Systematic Review', 'Childhood is an important and sensitive period for cognitive development. There is limited published research regarding the relationship between sports and cognitive functions in children. We present…', '2018', 2018, 484, 484, 'https://pub.mdpi-res.com/ijerph/ijerph-15-00800/article_deploy/html/images/ijerph-15-00800-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5923842', 'pmc', 'review', 'International Journal of Environmental Research and Public Health', '["Ilona Bidzan-Bluma","Małgorzata Lipowska"]', 'sociology', 'Childhood is an important and sensitive period for cognitive development. There is limited published research regarding the relationship between sports and cognitive functions in children. We present studies that demonstrate the influence of physical activity on health, especially a positive correlation between sports and cognitive functions. The keywords &ldquo;children, cognition, cognitive function, physical activity, and brain&rdquo; were searched for using PsycInfo, Medline, and Google Scholar, with publication dates ranging from January 2000 to November 2017. Of the 617 results, 58 articles strictly connected to the main topics of physical activity and cognitive functioning were then reviewed. The areas of attention, thinking, language, learning, and memory were analyzed relative to sports and childhood. Results suggest that engaging in sports in late childhood positively influences cognitive and emotional functions. There is a paucity of publications that investigate the impact of sports on pre-adolescents&rsquo; cognitive functions, or explore which cognitive functions are developed by which sporting disciplines. Such knowledge would be useful in developing training programs for pre-adolescents, aimed at improving cognitive functions that may guide both researchers and practitioners relative to the wide range of benefits that result from physical activity.', '2026-07-08 08:13:03');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3111898468', 'sociology', 'Early life stress and development: potential mechanisms for adverse outcomes', 'BACKGROUND: Chronic and/or extreme stress in early life, often referred to as early adversity, childhood trauma, or early life stress, has been associated with a wide range of adverse effects on…', '2020', 2020, 475, 475, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1007%2Fs00429-025-02890-z/MediaObjects/429_2025_2890_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7745388', 'pmc', 'review', 'Journal of Neurodevelopmental Disorders', '["Karen E. Smith","Seth D. Pollak"]', 'sociology', 'BACKGROUND: Chronic and/or extreme stress in early life, often referred to as early adversity, childhood trauma, or early life stress, has been associated with a wide range of adverse effects on development. However, while early life stress has been linked to negative effects on a number of neural systems, the specific mechanisms through which early life stress influences development and individual differences in children''s outcomes are still not well understood. MAIN TEXT: The current paper reviews the existing literature on the neurobiological effects of early life stress and their ties to children''s psychological and behavioral development. CONCLUSIONS: Early life stress has persistent and pervasive effects on prefrontal-hypothalamic-amygdala and dopaminergic circuits that are at least partially mediated by alterations in hypothalamic-pituitary-adrenal axis function. However, to date, this research has primarily utilized methods of assessment that focus solely on children''s event exposures. Incorporating assessment of factors that influence children''s interpretation of stressors, along with stressful events, has the potential to provide further insight into the mechanisms contributing to individual differences in neurodevelopmental effects of early life stress. This can aid in further elucidating specific mechanisms through which these neurobiological changes influence development and contribute to risk for psychopathology and health disorders.', '2026-07-08 08:13:19');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2751944115', 'sociology', 'Screening for anxiety and depression: reassessing the utility of the Zung scales', 'BACKGROUND: While the gold standard for the diagnosis of mental disorders remains the structured clinical interview, self-report measures continue to play an important role in screening and measuring…', '2017', 2017, 477, 477, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs12888-019-2427-6/MediaObjects/12888_2019_2427_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5591521', 'pmc', 'article', 'BMC Psychiatry', '["Debra A. Dunstan","Ned Scott","Anna K. Todd"]', 'sociology', 'BACKGROUND: While the gold standard for the diagnosis of mental disorders remains the structured clinical interview, self-report measures continue to play an important role in screening and measuring progress, as well as being frequently employed in research studies. Two widely-used self-report measures in the area of depression and anxiety are Zung''s Self-Rating Depression Scale (SDS) and Self Rating Anxiety Scale (SAS). However, considerable confusion exists in their application, with clinical cut-offs often applied incorrectly. This study re-examines the credentials of the Zung scales by comparing them with the Depression Anxiety Stress Scale (DASS) in terms of their ability to predict clinical diagnoses of anxiety and depression made using the Patient Health Questionnaire (PHQ). METHOD: A total sample of 376 adults, of whom 87 reported being in receipt of psychological treatment, completed the two-page version of the PHQ relating to depression and anxiety, together with the SDS, the SAS and the DASS. RESULTS: Overall, although the respective DASS scales emerged as marginally stronger predictors of PHQ diagnoses of anxiety and depression, the Zung indices performed more than acceptably in comparison. The DASS also had an advantage in discriminative ability. Using the current recommended cut-offs for all scales, the DASS has the edge on specificity, while the Zung scales are superior in terms of sensitivity. There are grounds to consider making the Zung cut-offs more conservative, and doing this would produce comparable numbers of ''Misses'' and ''False Positives'' to those obtained with the DASS. CONCLUSIONS: Given these promising results, further research is justified to assess the Zung scales ability against full clinical diagnoses and to further explore optimum cut-off levels.', '2026-07-08 08:13:20');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2466486589', 'sociology', 'Prevalence of Adolescent Problem Gambling: A Systematic Review of Recent Research', 'Previous research has shown that gambling is a popular activity among adolescents. Following a rapid expansion of legalized gambling opportunities and the emergence of new forms of gambling, many…', '2016', 2016, 476, 476, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1007%2Fs10899-016-9652-4/MediaObjects/10899_2016_9652_Fig1_HTML.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5445143', 'pmc', 'review', 'Journal of Gambling Studies', '["Filipa Calado","Joana Alexandre","Mark D. Griffiths"]', 'sociology', 'Previous research has shown that gambling is a popular activity among adolescents. Following a rapid expansion of legalized gambling opportunities and the emergence of new forms of gambling, many researchers have carried out studies on adolescent gambling and problem gambling. The present paper reviews studies that have been conducted worldwide since 2000, and then presents a more detailed picture of adolescent gambling research in Europe, by providing a country-by country analysis. After an extensive search on academic databases and following an exclusion process, 44 studies were identified. The findings showed that 0.2-12.3 % of youth meet criteria for problem gambling, notwithstanding differences among assessment instruments, cut-offs, and timeframes. However, despite this variability, several demographic characteristics were associated with adolescent gambling involvement and problem gambling. It is concluded that a small but significant minority of adolescents have gambling-related problems. Such findings will hopefully encourage more research into youth gambling to further understand the determinants of this phenomenon.', '2026-07-08 08:13:21');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2620252718', 'sociology', 'The varieties of contemplative experience: A mixed-methods study of meditation-related challenges in Western Buddhists', 'Buddhist-derived meditation practices are currently being employed as a popular form of health promotion. While meditation programs draw inspiration from Buddhist textual sources for the benefits of…', '2017', 2017, 466, 466, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0176239.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5443484', 'pmc', 'article', 'PLoS ONE', '["Jared R. Lindahl","Nathan E. Fisher","David J. Cooper","Rochelle K. Rosen","Willoughby B. Britton"]', 'sociology', 'Buddhist-derived meditation practices are currently being employed as a popular form of health promotion. While meditation programs draw inspiration from Buddhist textual sources for the benefits of meditation, these sources also acknowledge a wide range of other effects beyond health-related outcomes. The Varieties of Contemplative Experience study investigates meditation-related experiences that are typically underreported, particularly experiences that are described as challenging, difficult, distressing, functionally impairing, and/or requiring additional support. A mixed-methods approach featured qualitative interviews with Western Buddhist meditation practitioners and experts in Theravāda, Zen, and Tibetan traditions. Interview questions probed meditation experiences and influencing factors, including interpretations and management strategies. A follow-up survey provided quantitative assessments of causality, impairment and other demographic and practice-related variables. The content-driven thematic analysis of interviews yielded a taxonomy of 59 meditation-related experiences across 7 domains: cognitive, perceptual, affective, somatic, conative, sense of self, and social. Even in cases where the phenomenology was similar across participants, interpretations of and responses to the experiences differed considerably. The associated valence ranged from very positive to very negative, and the associated level of distress and functional impairment ranged from minimal and transient to severe and enduring. In order to determine what factors may influence the valence, impact, and response to any given experience, the study also identified 26 categories of influencing factors across 4 domains: practitioner-level factors, practice-level factors, relationships, and health behaviors. By identifying a broader range of experiences associated with meditation, along with the factors that contribute to the presence and management of experiences reported as challenging, difficult, distressing or functionally impairing, this study aims to increase our understanding of the effects of contemplative practices and to provide resources for mediators, clinicians, meditation researchers, and meditation teachers.', '2026-07-08 08:13:44');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3037693266', 'sociology', 'Prevalence of Autism Spectrum Disorder in China: A Nationwide Multi-center Population-based Study Among Children Aged 6 to 12 Years', 'Prevalence of Autism Spectrum Disorder in China: A Nationwide Multi-center Population-based Study Among Children Aged 6 to 12 Years', '2020', 2020, 456, 456, 'https://cdn.ncbi.nlm.nih.gov/pmc/blobs/dff3/7475160/3bbda318129c/12264_2020_530_Fig1_HTML.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7475160', 'pmc', 'article', 'Neuroscience Bulletin', '["Hao Zhou","Xiu Xu","Weili Yan","Xiaobing Zou","Lijie Wu","Xuerong Luo","Tingyu Li","Yi Huang","Hongyan Guan","Xiang Chen","Meng Mao","Kun Xia","Lan Zhang","Erzhen Li","Xiaoling Ge","Lili Zhang","Chunpei Li","Xudong Zhang","Yuanfeng Zhou","Ding Ding","Andy Shih","Éric Fombonne","Yi Zheng","Ji‐Sheng Han","Zhong Sheng Sun","Yong‐hui Jiang","Yi Wang","LATENT-NHC Study Team"]', 'sociology', NULL, '2026-07-08 08:14:35');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2301714492', 'sociology', 'Why Are Girls Less Physically Active than Boys? Findings from the LOOK Longitudinal Study', 'BACKGROUND: A gender-based disparity in physical activity (PA) among youth, whereby girls are less active than boys is a persistent finding in the literature. A greater understanding of the…', '2016', 2016, 446, 446, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0150041.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4784873', 'pmc', 'article', 'PLoS ONE', '["Rohan M. Telford","Rohan M. Telford","Richard D. Telford","Richard D. Telford","Lisa Olive","Thomas A. Cochrane","Rachel Davey"]', 'sociology', 'BACKGROUND: A gender-based disparity in physical activity (PA) among youth, whereby girls are less active than boys is a persistent finding in the literature. A greater understanding of the mechanisms underlying this difference has potential to guide PA intervention strategies. METHODS: Data were collected at age 8 and 12 years (276 boys, 279 girls) from 29 schools as part of the LOOK study. Multilevel linear models were fitted separately for boys and girls to examine effects of individual, family and environmental level correlates on pedometer measured PA. Cardio-respiratory fitness (multi-stage run), percent fat (DEXA), eye-hand coordination (throw and catch test) and perceived competence in physical education (questionnaire) were used as individual level correlates. At the family level, parent''s support and education (questionnaire) were used. School attended and extracurricular sport participation were included as environmental level correlates. RESULTS: Girls were 19% less active than boys (9420 vs 11360 steps/day, p<0.001, 95%CI [1844, 2626]). Lower PA among girls was associated with weaker influences at the school and family levels and through lower participation in extracurricular sport. School attended explained some of the variation in boys PA (8.4%) but not girls. Girls compared to boys had less favourable individual attributes associated with PA at age 8 years, including 18% lower cardio-respiratory fitness (3.5 vs 4.2, p<0.001, CI [0.5,0.9]), 44% lower eye-hand coordination (11.0 vs 17.3, p<0.001, CI [5.1,9.0]), higher percent body fat (28% vs 23%, p<0.001, CI [3.5,5.7]) and 9% lower perceived competence in physical education (7.7 vs 8.4, p<0.001, CI [0.2,0.9]). Participation in extracurricular sport at either age 8 or 12 years was protective against declines in PA over time among boys but not girls. CONCLUSION: Girls PA was less favourably influenced by socio-ecological factors at the individual, family, school and environmental levels. These factors are potentially modifiable suggesting the gap in PA between boys and girls can be reduced. Strategies aiming to increase PA should be multicomponent and take into consideration that pathways to increasing PA are likely to differ among boys and girls.', '2026-07-08 08:14:57');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1981149119', 'sociology', 'Public policy influence on renewable energy investments—A panel data study across OECD countries', 'Public policy influence on renewable energy investments—A panel data study across OECD countries', '2015', 2015, 445, 445, 'https://ars.els-cdn.com/content/image/1-s2.0-S030142151500035X-gr1.jpg', 'https://doi.org/10.1016/j.enpol.2015.01.026', 'repository', 'article', 'Energy Policy', '["Friedemann Polzin","Michael Migendt","Florian Taübe","Paschen von Flotow"]', 'sociology', NULL, '2026-07-08 08:15:03');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3160304067', 'sociology', 'Sex differences in biological aging with a focus on human studies', 'Aging is a complex biological process characterized by hallmark features accumulating over the life course, shaping the individual''s aging trajectory and subsequent disease risks. There is…', '2021', 2021, 438, 438, 'https://cdn.elifesciences.org/articles/63425/elife-63425-fig1-v1.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8118651', 'pmc', 'review', 'eLife', '["Sara Hägg","Juulia Jylhävä"]', 'sociology', 'Aging is a complex biological process characterized by hallmark features accumulating over the life course, shaping the individual''s aging trajectory and subsequent disease risks. There is substantial individual variability in the aging process between men and women. In general, women live longer than men, consistent with lower biological ages as assessed by molecular biomarkers, but there is a paradox. Women are frailer and have worse health at the end of life, while men still perform better in physical function examinations. Moreover, many age-related diseases show sex-specific patterns. In this review, we aim to summarize the current knowledge on sexual dimorphism in human studies, with support from animal research, on biological aging and illnesses. We also attempt to place it in the context of the theories of aging, as well as discuss the explanations for the sex differences, for example, the sex-chromosome linked mechanisms and hormonally driven differences.', '2026-07-08 08:15:13');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2809244390', 'sociology', 'Association of Stress-Related Disorders With Subsequent Autoimmune Disease', 'Importance: Psychiatric reactions to life stressors are common in the general population and may result in immune dysfunction. Whether such reactions contribute to the risk of autoimmune disease…', '2018', 2018, 434, 434, 'https://cdn.ncbi.nlm.nih.gov/pmc/blobs/6621/6583688/a91353c9592c/jama-319-2388-g001.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6583688', 'pmc', 'article', 'JAMA', '["Huan Song","Fang Fang","Gunnar Tómasson","Filip K. Arnberg","David Mataix‐Cols","Lorena Fernández de la Cruz","Catarina Almqvist","Katja Fall","Unnur Valdimarsdóttir"]', 'sociology', 'Importance: Psychiatric reactions to life stressors are common in the general population and may result in immune dysfunction. Whether such reactions contribute to the risk of autoimmune disease remains unclear. Objective: To determine whether there is an association between stress-related disorders and subsequent autoimmune disease. Design, Setting, and Participants: Population- and sibling-matched retrospective cohort study conducted in Sweden from January 1, 1981, to December 31, 2013. The cohort included 106 464 exposed patients with stress-related disorders, with 1 064 640 matched unexposed persons and 126 652 full siblings of these patients. Exposures: Diagnosis of stress-related disorders, ie, posttraumatic stress disorder, acute stress reaction, adjustment disorder, and other stress reactions. Main Outcomes and Measures: Stress-related disorder and autoimmune diseases were identified through the National Patient Register. The Cox model was used to estimate hazard ratios (HRs) with 95% CIs of 41 autoimmune diseases beyond 1 year after the diagnosis of stress-related disorders, controlling for multiple risk factors. Results: The median age at diagnosis of stress-related disorders was 41 years (interquartile range, 33-50 years) and 40% of the exposed patients were male. During a mean follow-up of 10 years, the incidence rate of autoimmune diseases was 9.1, 6.0, and 6.5 per 1000 person-years among the exposed, matched unexposed, and sibling cohorts, respectively (absolute rate difference, 3.12 [95% CI, 2.99-3.25] and 2.49 [95% CI, 2.23-2.76] per 1000 person-years compared with the population- and sibling-based reference groups, respectively). Compared with the unexposed population, patients with stress-related disorders were at increased risk of autoimmune disease (HR, 1.36 [95% CI, 1.33-1.40]). The HRs for patients with posttraumatic stress disorder were 1.46 (95% CI, 1.32-1.61) for any and 2.29 (95% CI, 1.72-3.04) for multiple (≥3) autoimmune diseases. These associations were consistent in the sibling-based comparison. Relative risk elevations were more pronounced among younger patients (HR, 1.48 [95% CI, 1.42-1.55]; 1.41 [95% CI, 1.33-1.48]; 1.31 [95% CI, 1.24-1.37]; and 1.23 [95% CI, 1.17-1.30] for age at ≤33, 34-41, 42-50, and ≥51 years, respectively; P for interaction <.001). Persistent use of selective serotonin reuptake inhibitors during the first year of posttraumatic stress disorder diagnosis was associated with attenuated relative risk of autoimmune disease (HR, 3.64 [95% CI, 2.00-6.62]; 2.65 [95% CI, 1.57-4.45]; and 1.82 [95% CI, 1.09-3.02] for duration ≤179, 180-319, and ≥320 days, respectively; P for trend =.03). Conclusions and Relevance: In this Swedish cohort, exposure to a stress-related disorder was significantly associated with increased risk of subsequent autoimmune disease, compared with matched unexposed individuals and with full siblings. Further studies are needed to better understand the underlying mechanisms.', '2026-07-08 08:15:36');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2748744508', 'sociology', 'Social isolation, loneliness and their relationships with depressive symptoms: A population-based study', 'OBJECTIVES: To assess the relationship between various social isolation indicators and loneliness, and to examine the differential associations that social isolation indicators, loneliness have with…', '2017', 2017, 432, 432, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0182145.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5568112', 'pmc', 'article', 'PLoS ONE', '["Lixia Ge","Chun Wei Yap","Reuben Ong","Bee Hoon Heng"]', 'sociology', 'OBJECTIVES: To assess the relationship between various social isolation indicators and loneliness, and to examine the differential associations that social isolation indicators, loneliness have with depressive symptoms. METHODS: Baseline data for 1,919 adults (aged 21 years and above) from a representative health survey in the Central region of Singapore was used for this study. The association between social isolation indicators (marital status, living arrangement, social connectedness with relatives and friends) and loneliness (the three-item UCLA Loneliness) were assessed, and their differential associations with depressive symptoms (the Patient Health Questionnaire-9) were examined using multiple linear regression, controling for relevant covariates. RESULTS: There was significant overlap between loneliness and social isolation. Social connectedness with relatives and friends were mildly correlated with loneliness score (|r| = 0.14~0.16). Social isolation in terms of weak connectedness with relatives and with friends and loneliness were associated with depressive symptoms even after controling for age, gender, employment status and other covariates. The association of loneliness with depressive symptoms (β = 0.33) was independent of and stronger than that of any social isolation indicators (|β| = 0.00~0.07). CONCLUSIONS: The results of the study establishes a significant and unique association of different social isolation indicators and loneliness with depressive symptoms in community-dwelling adults aged 21 and above.', '2026-07-08 08:15:42');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2788647475', 'sociology', 'Media use and brain development during adolescence', 'The current generation of adolescents grows up in a media-saturated world. However, it is unclear how media influences the maturational trajectories of brain regions involved in social interactions.…', '2018', 2018, 426, 426, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41467-018-03126-x/MediaObjects/41467_2018_3126_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5821838', 'pmc', 'review', 'Nature Communications', '["Eveline A. Crone","Elly A. Konijn"]', 'sociology', 'The current generation of adolescents grows up in a media-saturated world. However, it is unclear how media influences the maturational trajectories of brain regions involved in social interactions. Here we review the neural development in adolescence and show how neuroscience can provide a deeper understanding of developmental sensitivities related to adolescents'' media use. We argue that adolescents are highly sensitive to acceptance and rejection through social media, and that their heightened emotional sensitivity and protracted development of reflective processing and cognitive control may make them specifically reactive to emotion-arousing media. This review illustrates how neuroscience may help understand the mutual influence of media and peers on adolescents'' well-being and opinion formation.', '2026-07-08 08:15:59');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2912375542', 'sociology', 'Sex Differences in Human Olfaction: A Meta-Analysis', 'Although the view that women''s olfactory abilities outperform men''s is taken for granted, some studies involving large samples suggested that male and female olfactory abilities are actually similar.…', '2019', 2019, 427, 427, 'https://www.frontiersin.org/files/Articles/426219/fpsyg-10-00242-HTML/image_m/fpsyg-10-00242-g001.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6381007', 'pmc', 'article', 'Frontiers in Psychology', '["Piotr Sorokowski","Maciej Karwowski","Michał Misiak","Michalina Marczak","Martyna Dziekan","Thomas Hummel","Agnieszka Sorokowska"]', 'sociology', 'Although the view that women''s olfactory abilities outperform men''s is taken for granted, some studies involving large samples suggested that male and female olfactory abilities are actually similar. To address this discrepancy, we conducted a meta-analysis of existing studies on olfaction, targeting possible sex differences. The analyzed sample comprised n = 8 848 (5 065 women and 3 783 men) for olfactory threshold (as measured with the Sniffin Sticks Test; SST), n = 8 067 (4 496 women and 3 571 men) for discrimination (SST), n = 13 670 (7 501 women and 6 169 men) for identification (SST), and a total sample of n = 7 154 (3 866 women and 3 288 men) for works using University of Pennsylvania Smell Identification Test (UPSIT). We conducted separate meta-analyses for each aspect of olfaction: identification, discrimination and threshold. The results of our meta-analysis indicate that women generally outperform men in olfactory abilities. What is more, they do so in every aspect of olfaction analyzed in the current study. However, the effect sizes were weak and ranged between g = 0.08 and g = 0.30. We discuss our findings in the context of factors that potentially shape sex differences in olfaction. Nevertheless, although our findings seem to confirm the “common knowledge” on female olfactory superiority, it needs to be emphasized that the effect sizes we observed were notably small.', '2026-07-08 08:15:59');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2520580545', 'sociology', 'Revisiting the understanding of “transactional sex” in sub-Saharan Africa: A review and synthesis of the literature', 'In sub-Saharan Africa, young women ages 15-24 have more than twice the risk of acquiring HIV as their male counterparts. A growing body of epidemiological evidence suggests that the practice of…', '2016', 2016, 416, 416, 'https://ars.els-cdn.com/content/image/1-s2.0-S0277953616305305-gr1.jpg', 'https://pubmed.ncbi.nlm.nih.gov/27665064', 'repository', 'review', 'Social Science & Medicine', '["Kirsten Stoebenau","Lori Heise","Joyce Wamoyi","Natalia Bobrova"]', 'sociology', 'In sub-Saharan Africa, young women ages 15-24 have more than twice the risk of acquiring HIV as their male counterparts. A growing body of epidemiological evidence suggests that the practice of "transactional sex" may contribute to this disparity. Over the last 15 years, the social sciences have contributed significantly to understanding the meaning of and motivations for this practice. The findings from these studies are rich, but varied, rendering lessons difficult to navigate for intervention and further research. We therefore contribute a historically-grounded, comprehensive literature review on the nature and motivations for women''s participation in transactional sex in sub-Saharan Africa. Drawing from over 300 studies (through 2014), we distill three prominent paradigms observed in the literature that we review toward presenting a unified conceptualization of the practice. "Sex for basic needs," the first paradigm, positions women as victims in transactional sexual relationships, with implications for interventions that protect girls from exploitation. In contrast, the "sex for improved social status" paradigm positions women as sexual agents who engage in transactional sex toward attaining a middle-class status and lifestyle. Finally, a third paradigm, "sex and material expressions of love," draws attention to the connections between love and money, and the central role of men as providers in relationships. We find important commonalities in the structural factors that shape the three paradigms of transactional sex including gender inequality and processes of economic change. We suggest that there are three continua stretching across these paradigms: deprivation, agency, and instrumentality. This review proposes a definition of transactional sex and discusses implications for research and interventions aiming to reduce young women''s risk of HIV through such relationships. We consider the consequences of drawing from too narrow an understanding of the practice, and highlight the benefits of a broader conceptualization.', '2026-07-08 08:16:27');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3110226430', 'sociology', 'Recycling of Organic Wastes through Composting: Process Performance and Compost Application in Agriculture', 'Composting has become a preferable option to treat organic wastes to obtain a final stable sanitized product that can be used as an organic amendment. From home composting to big municipal waste…', '2020', 2020, 406, 406, 'https://pub.mdpi-res.com/agronomy/agronomy-10-01838/article_deploy/html/images/agronomy-10-01838-g001.png', 'https://www.mdpi.com/2073-4395/10/11/1838/pdf?version=1606113932', 'repository', 'article', 'Agronomy', '["Tahseen Sayara","Rezq Basheer-Salimia","Fatina Hawamde","Antoni Sánchez"]', 'sociology', 'Composting has become a preferable option to treat organic wastes to obtain a final stable sanitized product that can be used as an organic amendment. From home composting to big municipal waste treatment plants, composting is one of the few technologies that can be practically implemented at any scale. This review explores some of the essential issues in the field of composting/compost research: on one hand, the main parameters related to composting performance are compiled, with especial emphasis on the maturity and stability of compost; on the other hand, the main rules of applying compost on crops and other applications are explored in detail, including all the effects that compost can have on agricultural land. Especial attention is paid to aspects such as the improvement of the fertility of soils once compost is applied, the suppressor effect of compost and some negative experiences of massive compost application.', '2026-07-08 08:17:19');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2903682365', 'sociology', 'An integrative framework of stakeholder engagement for innovation management and entrepreneurship development', 'An integrative framework of stakeholder engagement for innovation management and entrepreneurship development', '2018', 2018, 404, 404, 'https://ars.els-cdn.com/content/image/1-s2.0-S0148296318306088-gr1.jpg', 'https://doi.org/10.1016/j.jbusres.2018.11.054', 'repository', 'article', 'Journal of Business Research', '["Erasmia Leonidou","Michael Christofi","Demetris Vrontis","Alkis Thrassou"]', 'sociology', NULL, '2026-07-08 08:17:30');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2982370090', 'sociology', 'Social Media, Thin-Ideal, Body Dissatisfaction and Disordered Eating Attitudes: An Exploratory Analysis', 'Disordered eating attitudes are rapidly increasing, especially among young women in their twenties. These disordered behaviours result from the interaction of several factors, including beauty…', '2019', 2019, 399, 399, 'https://pub.mdpi-res.com/ijerph/ijerph-16-04177/article_deploy/html/images/ijerph-16-04177-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/PMC6861923/pdf', 'pmc', 'article', 'International Journal of Environmental Research and Public Health', '["Pilar Aparicio‐Martinez","Alberto-Jesús Perea-Moreno","Pilar Martínez-Jiménez","María Dolores Redel-Macías","Claudia Pagliari","Manuel Vaquero Abellán"]', 'sociology', 'Disordered eating attitudes are rapidly increasing, especially among young women in their twenties. These disordered behaviours result from the interaction of several factors, including beauty ideals. A significant factor is social media, by which the unrealistic beauty ideals are popularized and may lead to these behaviours. The objectives of this study were, first, to determine the relationship between disordered eating behaviours among female university students and sociocultural factors, such as the use of social network sites, beauty ideals, body satisfaction, body image and the body image desired to achieve and, second, to determine whether there is a sensitive relationship between disordered eating attitudes, addiction to social networks, and testosterone levels as a biological factor. The data (N = 168) was obtained using validated surveys (EAT-26, BSQ, CIPE-a, SNSA) and indirect measures of prenatal testosterone. The data was analysed using chi-square, Student’s t-test, correlation tests and logistic regression tests. The results showed that disordered eating attitudes were linked to self-esteem (p &lt; 0.001), body image (p &lt; 0.001), body desired to achieve (p &lt; 0.001), the use of social media (p &lt; 0.001) and prenatal testosterone (p &lt; 0.01). The findings presented in this study suggest a relationship between body image, body concerns, body dissatisfaction, and disordered eating attitudes among college women.', '2026-07-08 08:17:48');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3013926312', 'sociology', 'What is replication?', 'Credibility of scientific claims is established with evidence for their replicability using new data. According to common understanding, replication is repeating a study''s procedure and observing…', '2020', 2020, 393, 393, 'https://journals.plos.org/plosbiology/article/figure/image?size=large&id=10.1371/journal.pbio.3000691.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7100931', 'pmc', 'article', 'PLoS Biology', '["Brian A. Nosek","Timothy M. Errington"]', 'sociology', 'Credibility of scientific claims is established with evidence for their replicability using new data. According to common understanding, replication is repeating a study''s procedure and observing whether the prior finding recurs. This definition is intuitive, easy to apply, and incorrect. We propose that replication is a study for which any outcome would be considered diagnostic evidence about a claim from prior research. This definition reduces emphasis on operational characteristics of the study and increases emphasis on the interpretation of possible outcomes. The purpose of replication is to advance theory by confronting existing understanding with new evidence. Ironically, the value of replication may be strongest when existing understanding is weakest. Successful replication provides evidence of generalizability across the conditions that inevitably differ from the original study; Unsuccessful replication indicates that the reliability of the finding may be more constrained than recognized previously. Defining replication as a confrontation of current theoretical expectations clarifies its important, exciting, and generative role in scientific progress.', '2026-07-08 08:18:03');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2980615522', 'sociology', 'Development and validation of the player experience inventory: A scale to measure player experiences at the level of functional and psychosocial consequences', 'Games User Research (GUR) focuses on measuring, analysing and understanding player experiences to optimise game designs. Hence, GUR experts aim to understand how specific game design choices are…', '2019', 2019, 395, 395, 'https://ars.els-cdn.com/content/image/1-s2.0-S1875952124000557-gr1.jpg', 'https://doi.org/10.1016/j.ijhcs.2019.102370', 'repository', 'article', 'International Journal of Human-Computer Studies', '["Vero Vanden Abeele","Katta Spiel","Lennart E. Nacke","Daniel Johnson","Kathrin Gerling"]', 'sociology', 'Games User Research (GUR) focuses on measuring, analysing and understanding player experiences to optimise game designs. Hence, GUR experts aim to understand how specific game design choices are experienced by players, and how these lead to specific emotional responses. An instrument, providing such actionable insight into player experience, specifically designed by and for GUR was thus far lacking. To address this gap, the Player Experience Inventory (PXI) was developed, drawing on Means-End theory and measuring player experience both at the level of Functional Consequences, (i.e., the immediate experiences as a direct result of game design choices, such as audiovisual appeal or ease-of-control) and at the level of Psychosocial Consequences, (i.e., the second-order emotional experiences, such as immersion or mastery). Initial construct and item development was conducted in two iterations with 64 GUR experts. Next, the scale was validated and evaluated over five studies and populations, totalling 529 participants. Results support the theorized structure of the scale and provide evidence for both discriminant and convergent validity. Results also show that the scale performs well over different sample sizes and studies, supporting configural invariance. Hence, the PXI provides a reliable and theoretically sound tool for researchers to measure player experience and investigate how game design choices are linked to emotional responses.', '2026-07-08 08:18:08');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2797004786', 'sociology', 'Lonely young adults in modern Britain: findings from an epidemiological cohort study', 'BACKGROUND: The aim of this study was to build a detailed, integrative profile of the correlates of young adults'' feelings of loneliness, in terms of their current health and functioning and their…', '2018', 2018, 395, 395, 'https://static.cambridge.org/binary/version/id/urn:cambridge.org:id:binary:20181219132526163-0428:S0033291718000788:S0033291718000788_fig1g.jpeg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6076992', 'pmc', 'article', 'Psychological Medicine', '["Timothy Matthews","Andrea Danese","Avshalom Caspi","Helen L. Fisher","Sidra Goldman‐Mellor","Agnieszka Kepa","Terrie E. Moffitt","Candice L. Odgers","Louise Arseneault"]', 'sociology', 'BACKGROUND: The aim of this study was to build a detailed, integrative profile of the correlates of young adults'' feelings of loneliness, in terms of their current health and functioning and their childhood experiences and circumstances. METHODS: Data were drawn from the Environmental Risk Longitudinal Twin Study, a birth cohort of 2232 individuals born in England and Wales in 1994 and 1995. Loneliness was measured when participants were aged 18. Regression analyses were used to test concurrent associations between loneliness and health and functioning in young adulthood. Longitudinal analyses were conducted to examine childhood factors associated with young adult loneliness. RESULTS: Lonelier young adults were more likely to experience mental health problems, to engage in physical health risk behaviours, and to use more negative strategies to cope with stress. They were less confident in their employment prospects and were more likely to be out of work. Lonelier young adults were, as children, more likely to have had mental health difficulties and to have experienced bullying and social isolation. Loneliness was evenly distributed across genders and socioeconomic backgrounds. CONCLUSIONS: Young adults'' experience of loneliness co-occurs with a diverse range of problems, with potential implications for health in later life. The findings underscore the importance of early intervention to prevent lonely young adults from being trapped in loneliness as they age.', '2026-07-08 08:18:09');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2610209740', 'sociology', 'Is functional brain connectivity atypical in autism? A systematic review of EEG and MEG studies', 'BACKGROUND: Although it is well recognized that autism is associated with altered patterns of over- and under-connectivity, specifics are still a matter of debate. Little has been done so far to…', '2017', 2017, 391, 391, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0175870.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5414938', 'pmc', 'review', 'PLoS ONE', '["Christian O’Reilly","John D. Lewis","Mayada Elsabbagh"]', 'sociology', 'BACKGROUND: Although it is well recognized that autism is associated with altered patterns of over- and under-connectivity, specifics are still a matter of debate. Little has been done so far to synthesize available literature using whole-brain electroencephalography (EEG) and magnetoencephalography (MEG) recordings. OBJECTIVES: 1) To systematically review the literature on EEG/MEG functional and effective connectivity in autism spectrum disorder (ASD), 2) to synthesize and critically appraise findings related with the hypothesis that ASD is characterized by long-range underconnectivity and local overconnectivity, and 3) to provide, based on the literature, an analysis of tentative factors that are likely to mediate association between ASD and atypical connectivity (e.g., development, topography, lateralization). METHODS: Literature reviews were done using PubMed and PsychInfo databases. Abstracts were screened, and only relevant articles were analyzed based on the objectives of this paper. Special attention was paid to the methodological characteristics that could have created variability in outcomes reported between studies. RESULTS: Our synthesis provides relatively strong support for long-range underconnectivity in ASD, whereas the status of local connectivity remains unclear. This observation was also mirrored by a similar relationship with lower frequencies being often associated with underconnectivity and higher frequencies being associated with both under- and over-connectivity. Putting together these observations, we propose that ASD is characterized by a general trend toward an under-expression of lower-band wide-spread integrative processes compensated by more focal, higher-frequency, locally specialized, and segregated processes. Further investigation is, however, needed to corroborate the conclusion and its generalizability across different tasks. Of note, abnormal lateralization in ASD, specifically an elevated left-over-right EEG and MEG functional connectivity ratio, has been also reported consistently across studies. CONCLUSIONS: The large variability in study samples and methodology makes a systematic quantitative analysis (i.e. meta-analysis) of this body of research impossible. Nevertheless, a general trend supporting the hypothesis of long-range functional underconnectivity can be observed. Further research is necessary to more confidently determine the status of the hypothesis of short-range overconnectivity. Frequency-band specific patterns and their relationships with known symptoms of autism also need to be further clarified.', '2026-07-08 08:18:17');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2989204084', 'sociology', 'Analyzing input quality along three dimensions: interactive, linguistic, and conceptual', 'This paper provides an overview of the features of caregiver input that facilitate language learning across early childhood. We discuss three dimensions of input quality: interactive, linguistic, and…', '2019', 2019, 392, 392, 'https://static.cambridge.org/binary/version/id/urn:cambridge.org:id:binary:20191220142829660-0810:S0305000919000655:S0305000919000655_fig1.png', 'https://pubmed.ncbi.nlm.nih.gov/31668157', 'repository', 'review', 'Journal of Child Language', '["Meredith L. Rowe","Catherine E. Snow"]', 'sociology', 'This paper provides an overview of the features of caregiver input that facilitate language learning across early childhood. We discuss three dimensions of input quality: interactive, linguistic, and conceptual. All three types of input features have been shown to predict children''s language learning, though perhaps through somewhat different mechanisms. We argue that input best designed to promote language learning is interactionally supportive, linguistically adapted, and conceptually challenging for the child''s age/level. Furthermore, input features interact across dimensions to promote learning. Some but not all qualities of input vary based on parent socioeconomic status, language, or culture, and contexts such as book-reading or pretend play generate uniquely facilitative input features. The review confirms that we know a great deal about the role of input quality in promoting children''s development, but that there is much more to learn. Future research should examine input features across the boundaries of the dimensions distinguished here.', '2026-07-08 08:18:21');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2344848300', 'sociology', 'Personality traits below facets: The consensual validity, longitudinal stability, heritability, and utility of personality nuances.', 'It has been argued that facets do not represent the bottom of the personality hierarchy-even more specific personality characteristics, nuances, could be useful for describing and understanding…', '2016', 2016, 388, 388, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1037/pspp0000100.g001', 'https://pubmed.ncbi.nlm.nih.gov/27124378', 'repository', 'article', 'Journal of Personality and Social Psychology', '["René Mõttus","Christian Kandler","Wiebke Bleidorn","Rainer Riemann","Robert R. McCrae"]', 'sociology', 'It has been argued that facets do not represent the bottom of the personality hierarchy-even more specific personality characteristics, nuances, could be useful for describing and understanding individuals and their differences. Combining 2 samples of German twins, we assessed the consensual validity (correlations across different observers), rank-order stability, and heritability of nuances. Personality nuances were operationalized as the 240 items of the Revised NEO Personality Inventory (NEO-PI-R). Their attributes were examined by analyzing item residuals, controlling for the variance of the facet the item had been assigned to and all other facets. Most nuances demonstrated significant (p <.0002) cross-method agreement and rank-order stability. A substantial proportion of them (48% in self-reports, 20% in informant ratings, and 50% in combined ratings) demonstrated a significant (p <.0002) component of additive genetic variance, whereas evidence for environmental influences shared by twins was modest. Applying a procedure to estimate stability and heritability of true scores of item residuals yielded estimates comparable with those of higher-order personality traits, with median estimates of rank-order stability and heritability being.77 and.52, respectively. Few nuances demonstrated robust associations with age and gender, but many showed incremental, conceptually meaningful, and replicable (across methods and/or samples) predictive validity for a range of interest domains and body mass index. We argue that these narrow personality characteristics constitute a valid level of the personality hierarchy. They may be especially useful for providing a deep and contextualized description of the individual, but also for the prediction of specific outcomes. (PsycINFO Database Record', '2026-07-08 08:18:29');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2143213483', 'sociology', 'Resting heart rate variability predicts self-reported difficulties in emotion regulation: a focus on different facets of emotion regulation', 'The Model of Neurovisceral Integration suggests that vagally mediated heart rate variability (vmHRV) represents a psychophysiological index of inhibitory control and thus, is associated with emotion…', '2015', 2015, 388, 388, 'https://www.frontiersin.org/files/Articles/132860/fpsyg-06-00261-HTML/image_m/fpsyg-06-00261-g001.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4354240', 'pmc', 'article', 'Frontiers in Psychology', '["DeWayne P. Williams","Claudia S. E. Cash","Cameron Rankin","A. Bernardi","Julian Koenig","Julian F. Thayer"]', 'sociology', 'The Model of Neurovisceral Integration suggests that vagally mediated heart rate variability (vmHRV) represents a psychophysiological index of inhibitory control and thus, is associated with emotion regulation capacity. Over the past decade, growing empirical evidence supports this notion, showing that those with higher resting vmHRV can regulate negative emotions more adequately. However, to our knowledge, no study has previously examined how resting vmHRV may relate to everyday perceived difficulties in emotion regulation. The present study attempts to examine such relationship in 183 undergraduate students (98 female, 60 minority, mean Age = 19.34). Resting vmHRV was collected during a 5-min resting baseline period, and everyday difficulties in emotion regulation were assessed using the Difficulties in Emotion Regulation Scale (DERS). Controlling for potential covariates (including both trait anxiety and rumination), results revealed a negative relationship between resting vmHRV and DERS such that lower resting vmHRV was associated with greater difficulties in emotional regulation, especially a lack of emotional clarity and impulse control, as indicated by the respective subscales of the DERS. These findings provide further evidence for the Neurovisceral Integration Model, suggesting that emotion regulation and autonomic regulation share neural networks within the brain. Moreover, the present study extends prior research by highlighting two distinct facets of emotion regulation (impulse control and emotional clarity) that should be of particular interest when investigating the link between emotion regulation, resting vmHRV, and related health outcomes including morbidity and mortality.', '2026-07-08 08:18:40');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2964208165', 'sociology', 'A Primer to (Cross-Cultural) Multi-Group Invariance Testing Possibilities in R', 'Psychology has become less WEIRD in recent years, marking progress toward becoming a truly global psychology. However, this increase in cultural diversity is not matched by greater attention to…', '2019', 2019, 386, 386, 'https://www.frontiersin.org/files/Articles/440108/fpsyg-10-01507-HTML/image_m/fpsyg-10-01507-g001.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6657455', 'pmc', 'article', 'Frontiers in Psychology', '["Ronald Fischer","Johannes Alfons Karl"]', 'sociology', 'Psychology has become less WEIRD in recent years, marking progress toward becoming a truly global psychology. However, this increase in cultural diversity is not matched by greater attention to cultural biases in research. A significant challenge in culture-comparative research in psychology is that any comparisons are open to possible item bias and non-invariance. Unfortunately, many psychologists are not aware of problems and their implications, and do not know how to best test for invariance in their data. We provide a general introduction to invariance testing and a tutorial of three major classes of techniques that can be easily implemented in the free software and statistical language R. Specifically, we describe (1) confirmatory and multi-group confirmatory factor analysis, with extension to exploratory structural equation modeling, and multi-group alignment; (2) iterative hybrid logistic regression as well as (3) exploratory factor analysis and principal component analysis with Procrustes rotation. We pay specific attention to effect size measures of item biases and differential item function. Code in R is provided in the main text and online (see https://osf.io/agr5e/), and more extended code and a general introduction to R are available in the Supplementary Materials.', '2026-07-08 08:18:46');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4392001854', 'sociology', 'Social support and mental health: the mediating role of perceived stress', 'Social support has been associated with improved mental health; however, the mechanisms underlying this relationship remain unclear. This study aimed to explore whether perceived stress mediate the…', '2024', 2024, 381, 381, 'https://www.frontiersin.org/files/Articles/1330720/fpsyg-15-1330720-HTML/image_m/fpsyg-15-1330720-g001.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/10915202', 'pmc', 'article', 'Frontiers in Psychology', '["Evelyn F. Acoba"]', 'sociology', 'Social support has been associated with improved mental health; however, the mechanisms underlying this relationship remain unclear. This study aimed to explore whether perceived stress mediate the relationship between social support and positive affect, anxiety, and depression. Drawing from Lazarus and Folkman''s stress and coping theory, the study emphasized the influential role of social support in appraising stressful events. A cross-sectional survey was conducted online among 426 Filipino adults during the peak of the COVID-19 pandemic. Participants completed measures including the Multidimensional Scale of Perceived Social Support (MSPSS), the Perceived Stress Scale-10 (PSS-10), the Positive Affect subscale of PANAS, and the Depression and Anxiety subscales of DASS-21. The hypotheses of the study were tested using mediation analysis. Consistent with the hypotheses, perceived stress significantly mediated the relationship between family and significant other support with positive affect, anxiety, and depression. Family and significant other support decreased perceived stress, increasing positive affect, and decreasing anxiety and depression. On the other hand, perceived stress did not mediate the relationship between friend support and positive affect, anxiety, and depression. Implications and future research directions are discussed.', '2026-07-08 08:19:11');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3038480796', 'sociology', 'The Relationships between Physical Activity and Life Satisfaction and Happiness among Young, Middle-Aged, and Older Adults', 'Physical activity has benefits on physical and psychological health. The aims of this study were to investigate (1) the relationships between physical activity and life satisfaction and happiness in…', '2020', 2020, 378, 378, 'https://pub.mdpi-res.com/ijerph/ijerph-17-04817/article_deploy/html/images/ijerph-17-04817-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7369812', 'pmc', 'article', 'International Journal of Environmental Research and Public Health', '["Hsin-Yu An","Wei Chen","Cheng-Wei Wang","Hui-Fei Yang","Wan‐Ting Huang","Sheng‐Yu Fan"]', 'sociology', 'Physical activity has benefits on physical and psychological health. The aims of this study were to investigate (1) the relationships between physical activity and life satisfaction and happiness in young, middle-aged, and older adults while controlling for demographic characteristics, and (2) the relationships between age and life satisfaction and happiness for different physical activity levels. A total of 2345 healthy adults were recruited. Demographic characteristic, physical activity, life satisfaction, and happiness were collected. Participants were divided into young, middle-aged, and older adult groups based on age, and physical activity was categorized as high, moderate, and low. After controlling for demographic characteristics, participants with high and moderate activity levels had significantly higher life satisfaction and happiness than those with a low activity level across the total population and the three age groups. Age squared was a significant predictor of a positive curvilinear between age and life satisfaction and happiness. Physical activity was significantly related to life satisfaction and happiness in young, middle-aged, and older adults. In addition, life satisfaction and happiness increased with increasing age. The results support the promotion of physical activity.', '2026-07-08 08:19:33');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2466307579', 'sociology', 'Gender Differences in Emotional Response: Inconsistency between Experience and Expressivity', 'The present study investigated gender differences in both emotional experience and expressivity. Heart rate (HR) was recorded as an indicator of emotional experience while the participants watched 16…', '2016', 2016, 375, 375, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0158666.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4928818', 'pmc', 'article', 'PLoS ONE', '["Yaling Deng","Lei Chang","Meng Yang","Meng Huo","Renlai Zhou"]', 'sociology', 'The present study investigated gender differences in both emotional experience and expressivity. Heart rate (HR) was recorded as an indicator of emotional experience while the participants watched 16 video clips that induced eight types of emotion (sadness, anger, horror, disgust, neutrality, amusement, surprise, and pleasure). We also asked the participants to report valence, arousal, and motivation as indicators of emotional expressivity. Overall, the results revealed gender differences in emotional experience and emotional expressivity. When watching videos that induced anger, amusement, and pleasure, men showed larger decreases in HR, whereas women reported higher levels of arousal. There was no gender difference in HR when the participants watched videos that induced horror and disgust, but women reported lower valence, higher arousal, and stronger avoidance motivation than did men. Finally, no gender difference was observed in sadness or surprise, although there was one exception-women reported higher arousal when watching videos that induced sadness. The findings suggest that, when watching videos that induce an emotional response, men often have more intense emotional experiences, whereas women have higher emotional expressivity, particularly for negative emotions. In addition, gender differences depend on the specific emotion type but not the valence.', '2026-07-08 08:19:33');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2953522645', 'political-science', 'The global landscape of AI ethics guidelines', 'The global landscape of AI ethics guidelines', '2019', 2019, 5111, 5111, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs42256-019-0088-2/MediaObjects/42256_2019_88_Fig1_HTML.png', 'http://arxiv.org/abs/1906.11668', 'arxiv', 'article', 'Nature Machine Intelligence', '["Anna Jobin","Marcello Ienca","Effy Vayena"]', 'political science', NULL, '2026-07-08 08:21:07');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3093974194', 'political-science', 'A global survey of potential acceptance of a COVID-19 vaccine', 'A global survey of potential acceptance of a COVID-19 vaccine', '2020', 2020, 3059, 3059, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1038%2Fs41598-023-34340-3/MediaObjects/41598_2023_34340_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7573523', 'pmc', 'article', 'Nature Medicine', '["Jeffrey V. Lazarus","Scott C. Ratzan","Adam Palayew","Lawrence O. Gostin","Heidi J. Larson","Kenneth Rabin","Spencer Kimball","Ayman El-Mohandes"]', 'political science', NULL, '2026-07-08 08:23:22');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3000603264', 'political-science', 'The role of artificial intelligence in achieving the Sustainable Development Goals', 'The emergence of artificial intelligence (AI) and its progressively wider impact on many sectors requires an assessment of its effect on the achievement of the Sustainable Development Goals. Using a…', '2020', 2020, 2951, 2951, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41467-019-14108-y/MediaObjects/41467_2019_14108_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6957485', 'pmc', 'review', 'Nature Communications', '["Ricardo Vinuesa","Hossein Azizpour","Iolanda Leite","Madeline Balaam","Virginia Dignum","Sami Domisch","Anna Felländer","Simone D. Langhans","Max Tegmark","Francesco Fuso Nerini"]', 'political science', 'The emergence of artificial intelligence (AI) and its progressively wider impact on many sectors requires an assessment of its effect on the achievement of the Sustainable Development Goals. Using a consensus-based expert elicitation process, we find that AI can enable the accomplishment of 134 targets across all the goals, but it may also inhibit 59 targets. However, current research foci overlook important aspects. The fast development of AI needs to be supported by the necessary regulatory insight and oversight for AI-based technologies to enable sustainable development. Failure to do so could result in gaps in transparency, safety, and ethical standards.', '2026-07-08 08:23:24');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3035686316', 'political-science', 'Setting the future of digital and social media marketing research: Perspectives and research propositions', 'The use of the internet and social media have changed consumer behavior and the ways in which companies conduct their business. Social and digital marketing offers significant opportunities to…', '2020', 2020, 2469, 2469, 'https://ars.els-cdn.com/content/image/1-s2.0-S0268401220308082-gr1.jpg', 'https://hal.science/hal-04713688', 'repository', 'article', 'International Journal of Information Management', '["Yogesh K. Dwivedi","Elvira Ismagilova","David L. Hughes","Jamie Carlson","Raffaele Filieri","Jenna Jacobson","Varsha Jain","Heikki Karjaluoto","Hajer Kéfi","Anjala S. Krishen","Vikram Kumar","Mohammad M. Rahman","Ramakrishnan Raman","Philipp A. Rauschnabel","Jennifer Rowley","Jari Salo","Gina A. Tran","Yichuan Wang"]', 'political science', 'The use of the internet and social media have changed consumer behavior and the ways in which companies conduct their business. Social and digital marketing offers significant opportunities to organizations through lower costs, improved brand awareness and increased sales. However, significant challenges exist from negative electronic word-of-mouth as well as intrusive and irritating online brand presence. This article brings together the collective insight from several leading experts on issues relating to digital and social media marketing. The experts’ perspectives offer a detailed narrative on key aspects of this important topic as well as perspectives on more specific issues including artificial intelligence, augmented reality marketing, digital content management, mobile marketing and advertising, B2B marketing, electronic word of mouth and ethical issues therein. This research offers a significant and timely contribution to both researchers and practitioners in the form of challenges and opportunities where we highlight the limitations within the current research, outline the research gaps and develop the questions and propositions that can help advance knowledge within the domain of digital and social marketing.', '2026-07-08 08:24:33');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2806521060', 'political-science', 'Prevalence of cardiovascular disease in type 2 diabetes: a systematic literature review of scientific evidence from across the world in 2007–2017', 'BACKGROUND: Cardiovascular disease (CVD) is a common comorbidity in type 2 diabetes (T2DM). CVD''s prevalence has been growing over time. PURPOSE: To estimate the current prevalence of CVD among…', '2018', 2018, 2352, 2352, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs12933-018-0728-6/MediaObjects/12933_2018_728_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5994068', 'pmc', 'review', 'Cardiovascular Diabetology', '["Thomas R. Einarson","Annabel Acs","Craig Ludwig","Ulrik Haagen Panton"]', 'political science', 'BACKGROUND: Cardiovascular disease (CVD) is a common comorbidity in type 2 diabetes (T2DM). CVD''s prevalence has been growing over time. PURPOSE: To estimate the current prevalence of CVD among adults with T2DM by reviewing literature published within the last 10 years (2007-March 2017). METHODS: We searched Medline, Embase, and proceedings of major scientific meetings for original research documenting the prevalence of CVD in T2DM. CVD included stroke, myocardial infarction, angina pectoris, heart failure, ischemic heart disease, cardiovascular disease, coronary heart disease, atherosclerosis, and cardiovascular death. No restrictions were placed on country of origin or publication language. Two reviewers independently searched for articles and extracted data, adjudicating results through consensus. Data were summarized descriptively. Risk of bias was examined by applying the STROBE checklist. RESULTS: We analyzed data from 57 articles with 4,549,481 persons having T2DM. Europe produced the most articles (46%), followed by the Western Pacific/China (21%), and North America (13%). Overall in 4,549,481 persons with T2DM, 52.0% were male, 47.0% were obese, aged 63.6 ± 6.9 years old, with T2DM duration of 10.4 ± 3.7 years. CVD affected 32.2% overall (53 studies, N = 4,289,140); 29.1% had atherosclerosis (4 studies, N = 1153), 21.2% had coronary heart disease (42 articles, N = 3,833,200), 14.9% heart failure (14 studies, N = 601,154), 14.6% angina (4 studies, N = 354,743), 10.0% myocardial infarction (13 studies, N = 3,518,833) and 7.6% stroke (39 studies, N = 3,901,505). CVD was the cause of death in 9.9% of T2DM patients (representing 50.3% of all deaths). Risk of bias was low; 80 ± 12% of STROBE checklist items were adequately addressed. CONCLUSIONS: Globally, overall CVD affects approximately 32.2% of all persons with T2DM. CVD is a major cause of mortality among people with T2DM, accounting for approximately half of all deaths over the study period. Coronary artery disease and stroke were the major contributors.', '2026-07-08 08:25:15');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2594519269', 'political-science', 'Implicit bias in healthcare professionals: a systematic review', 'BACKGROUND: Implicit biases involve associations outside conscious awareness that lead to a negative evaluation of a person on the basis of irrelevant characteristics such as race or gender. This…', '2017', 2017, 2341, 2341, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs12909-025-08317-x/MediaObjects/12909_2025_8317_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5333436', 'pmc', 'review', 'BMC Medical Ethics', '["Chloë FitzGerald","Samia Hurst"]', 'political science', 'BACKGROUND: Implicit biases involve associations outside conscious awareness that lead to a negative evaluation of a person on the basis of irrelevant characteristics such as race or gender. This review examines the evidence that healthcare professionals display implicit biases towards patients. METHODS: PubMed, PsychINFO, PsychARTICLE and CINAHL were searched for peer-reviewed articles published between 1st March 2003 and 31st March 2013. Two reviewers assessed the eligibility of the identified papers based on precise content and quality criteria. The references of eligible papers were examined to identify further eligible studies. RESULTS: Forty two articles were identified as eligible. Seventeen used an implicit measure (Implicit Association Test in fifteen and subliminal priming in two), to test the biases of healthcare professionals. Twenty five articles employed a between-subjects design, using vignettes to examine the influence of patient characteristics on healthcare professionals'' attitudes, diagnoses, and treatment decisions. The second method was included although it does not isolate implicit attitudes because it is recognised by psychologists who specialise in implicit cognition as a way of detecting the possible presence of implicit bias. Twenty seven studies examined racial/ethnic biases; ten other biases were investigated, including gender, age and weight. Thirty five articles found evidence of implicit bias in healthcare professionals; all the studies that investigated correlations found a significant positive relationship between level of implicit bias and lower quality of care. DISCUSSION: The evidence indicates that healthcare professionals exhibit the same levels of implicit bias as the wider population. The interactions between multiple patient characteristics and between healthcare professional and patient characteristics reveal the complexity of the phenomenon of implicit bias and its influence on clinician-patient interaction. The most convincing studies from our review are those that combine the IAT and a method measuring the quality of treatment in the actual world. Correlational evidence indicates that biases are likely to influence diagnosis and treatment decisions and levels of care in some circumstances and need to be further investigated. Our review also indicates that there may sometimes be a gap between the norm of impartiality and the extent to which it is embraced by healthcare professionals for some of the tested characteristics. CONCLUSIONS: Our findings highlight the need for the healthcare profession to address the role of implicit biases in disparities in healthcare. More research in actual care settings and a greater homogeneity in methods employed to test implicit biases in healthcare is needed.', '2026-07-08 08:25:15');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2271393109', 'political-science', 'The Increasing Trend in Caesarean Section Rates: Global, Regional and National Estimates: 1990-2014', 'BACKGROUND: Caesarean section (CS) rates continue to evoke worldwide concern because of their steady increase, lack of consensus on the appropriate CS rate and the associated additional short- and…', '2016', 2016, 2221, 2221, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0148343.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4743929', 'pmc', 'article', 'PLoS ONE', '["Ana Pilar Betrán","Jianfeng Ye","Anne-Beth Moller","Jun Zhang","A Metin Gülmezoglu","Maria Regina Torloni"]', 'political science', 'BACKGROUND: Caesarean section (CS) rates continue to evoke worldwide concern because of their steady increase, lack of consensus on the appropriate CS rate and the associated additional short- and long-term risks and costs. We present the latest CS rates and trends over the last 24 years. METHODS: We collected nationally-representative data on CS rates between 1990 to 2014 and calculated regional and subregional weighted averages. We conducted a longitudinal analysis calculating differences in CS rates as absolute change and as the average annual rate of increase (AARI). RESULTS: According to the latest data from 150 countries, currently 18.6% of all births occur by CS, ranging from 6% to 27.2% in the least and most developed regions, respectively. Latin America and the Caribbean region has the highest CS rates (40.5%), followed by Northern America (32.3%), Oceania (31.1%), Europe (25%), Asia (19.2%) and Africa (7.3%). Based on the data from 121 countries, the trend analysis showed that between 1990 and 2014, the global average CS rate increased 12.4% (from 6.7% to 19.1%) with an average annual rate of increase of 4.4%. The largest absolute increases occurred in Latin America and the Caribbean (19.4%, from 22.8% to 42.2%), followed by Asia (15.1%, from 4.4% to 19.5%), Oceania (14.1%, from 18.5% to 32.6%), Europe (13.8%, from 11.2% to 25%), Northern America (10%, from 22.3% to 32.3%) and Africa (4.5%, from 2.9% to 7.4%). Asia and Northern America were the regions with the highest and lowest average annual rate of increase (6.4% and 1.6%, respectively). CONCLUSION: The use of CS worldwide has increased to unprecedented levels although the gap between higher- and lower-resource settings remains. The information presented is essential to inform policy and global and regional strategies aimed at optimizing the use of CS.', '2026-07-08 08:25:37');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4205948442', 'political-science', 'The International Scientific Association of Probiotics and Prebiotics (ISAPP) consensus statement on the definition and scope of postbiotics', 'Abstract In 2019, the International Scientific Association for Probiotics and Prebiotics (ISAPP) convened a panel of experts specializing in nutrition, microbial physiology, gastroenterology,…', '2021', 2021, 2156, 2156, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41575-021-00440-6/MediaObjects/41575_2021_440_Fig1_HTML.png', 'https://doi.org/10.1038/s41575-021-00440-6', 'repository', 'review', 'Nature Reviews Gastroenterology & Hepatology', '["Seppo Salminen","María Carmen Collado","Akihito Endo","Colin Hill","Sarah Lebeer","Eamonn M.M. Quigley","Mary Ellen Sanders","Raanan Shamir","Jonathan R. Swann","Hania Szajewska","Gabriel Vinderola"]', 'political science', 'Abstract In 2019, the International Scientific Association for Probiotics and Prebiotics (ISAPP) convened a panel of experts specializing in nutrition, microbial physiology, gastroenterology, paediatrics, food science and microbiology to review the definition and scope of postbiotics. The term ‘postbiotics’ is increasingly found in the scientific literature and on commercial products, yet is inconsistently used and lacks a clear definition. The purpose of this panel was to consider the scientific, commercial and regulatory parameters encompassing this emerging term, propose a useful definition and thereby establish a foundation for future developments. The panel defined a postbiotic as a “preparation of inanimate microorganisms and/or their components that confers a health benefit on the host”. Effective postbiotics must contain inactivated microbial cells or cell components, with or without metabolites, that contribute to observed health benefits. The panel also discussed existing evidence of health-promoting effects of postbiotics, potential mechanisms of action, levels of evidence required to meet the stated definition, safety and implications for stakeholders. The panel determined that a definition of postbiotics is useful so that scientists, clinical triallists, industry, regulators and consumers have common ground for future activity in this area. A generally accepted definition will hopefully lead to regulatory clarity and promote innovation and the development of new postbiotic products.', '2026-07-08 08:26:12');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3109650690', 'political-science', 'Explainability for artificial intelligence in healthcare: a multidisciplinary perspective', 'BACKGROUND: Explainability is one of the most heavily debated topics when it comes to the application of artificial intelligence (AI) in healthcare. Even though AI-driven systems have been shown to…', '2020', 2020, 1879, 1879, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs12911-023-02103-9/MediaObjects/12911_2023_2103_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7706019', 'pmc', 'article', 'BMC Medical Informatics and Decision Making', '["Julia Amann","Alessandro Blasimme","Effy Vayena","Dietmar Frey","Vince I. Madai"]', 'political science', 'BACKGROUND: Explainability is one of the most heavily debated topics when it comes to the application of artificial intelligence (AI) in healthcare. Even though AI-driven systems have been shown to outperform humans in certain analytical tasks, the lack of explainability continues to spark criticism. Yet, explainability is not a purely technological issue, instead it invokes a host of medical, legal, ethical, and societal questions that require thorough exploration. This paper provides a comprehensive assessment of the role of explainability in medical AI and makes an ethical evaluation of what explainability means for the adoption of AI-driven tools into clinical practice. METHODS: Taking AI-based clinical decision support systems as a case in point, we adopted a multidisciplinary approach to analyze the relevance of explainability for medical AI from the technological, legal, medical, and patient perspectives. Drawing on the findings of this conceptual analysis, we then conducted an ethical assessment using the "Principles of Biomedical Ethics" by Beauchamp and Childress (autonomy, beneficence, nonmaleficence, and justice) as an analytical framework to determine the need for explainability in medical AI. RESULTS: Each of the domains highlights a different set of core considerations and values that are relevant for understanding the role of explainability in clinical practice. From the technological point of view, explainability has to be considered both in terms how it can be achieved and what is beneficial from a development perspective. When looking at the legal perspective we identified informed consent, certification and approval as medical devices, and liability as core touchpoints for explainability. Both the medical and patient perspectives emphasize the importance of considering the interplay between human actors and medical AI. We conclude that omitting explainability in clinical decision support systems poses a threat to core ethical values in medicine and may have detrimental consequences for individual and public health. CONCLUSIONS: To ensure that medical AI lives up to its promises, there is a need to sensitize developers, healthcare professionals, and legislators to the challenges and limitations of opaque algorithms in medical AI and to foster multidisciplinary collaboration moving forward.', '2026-07-08 08:27:36');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2974087526', 'political-science', 'Systematic Literature Review on the Spread of Health-related Misinformation on Social Media', 'Contemporary commentators describe the current period as "an era of fake news" in which misinformation, generated intentionally or unintentionally, spreads rapidly. Although affecting all areas of…', '2019', 2019, 1824, 1824, 'https://ars.els-cdn.com/content/image/1-s2.0-S0277953619305465-gr1.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7117034', 'pmc', 'review', 'Social Science & Medicine', '["Yuxi Wang","Martin McKee","Aleksandra Torbica","David Stückler"]', 'political science', 'Contemporary commentators describe the current period as "an era of fake news" in which misinformation, generated intentionally or unintentionally, spreads rapidly. Although affecting all areas of life, it poses particular problems in the health arena, where it can delay or prevent effective care, in some cases threatening the lives of individuals. While examples of the rapid spread of misinformation date back to the earliest days of scientific medicine, the internet, by allowing instantaneous communication and powerful amplification has brought about a quantum change. In democracies where ideas compete in the marketplace for attention, accurate scientific information, which may be difficult to comprehend and even dull, is easily crowded out by sensationalized news. In order to uncover the current evidence and better understand the mechanism of misinformation spread, we report a systematic review of the nature and potential drivers of health-related misinformation. We searched PubMed, Cochrane, Web of Science, Scopus and Google databases to identify relevant methodological and empirical articles published between 2012 and 2018. A total of 57 articles were included for full-text analysis. Overall, we observe an increasing trend in published articles on health-related misinformation and the role of social media in its propagation. The most extensively studied topics involving misinformation relate to vaccination, Ebola and Zika Virus, although others, such as nutrition, cancer, fluoridation of water and smoking also featured. Studies adopted theoretical frameworks from psychology and network science, while co-citation analysis revealed potential for greater collaboration across fields. Most studies employed content analysis, social network analysis or experiments, drawing on disparate disciplinary paradigms. Future research should examine susceptibility of different sociodemographic groups to misinformation and understand the role of belief systems on the intention to spread misinformation. Further interdisciplinary research is also warranted to identify effective and tailored interventions to counter the spread of health-related misinformation online.', '2026-07-08 08:27:42');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2886599162', 'political-science', 'Google Scholar, Web of Science, and Scopus: A systematic comparison of citations in 252 subject categories', 'Google Scholar, Web of Science, and Scopus: A systematic comparison of citations in 252 subject categories', '2018', 2018, 1854, 1854, 'https://ars.els-cdn.com/content/image/1-s2.0-S1751157718303249-fx1.jpg', 'http://arxiv.org/abs/1808.05053', 'arxiv', 'article', 'Journal of Informetrics', '["Alberto Martín‐Martín","Enrique Orduña‐Malea","Mike Thelwall","Emilio Delgado López‐Cózar"]', 'political science', NULL, '2026-07-08 08:27:45');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3185797914', 'political-science', 'Delphi methodology in healthcare research: How to decide its appropriateness', 'The Delphi technique is a systematic process of forecasting using the collective opinion of panel members. The structured method of developing consensus among panel members using Delphi methodology…', '2021', 2021, 1691, 1691, 'https://cdn.ncbi.nlm.nih.gov/pmc/blobs/ed04/8299905/86fa85b50f7a/WJM-11-116-g001.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8299905', 'pmc', 'review', 'World Journal of Methodology', '["Prashant Nasa","Ravi Jain","Deven Juneja"]', 'political science', 'The Delphi technique is a systematic process of forecasting using the collective opinion of panel members. The structured method of developing consensus among panel members using Delphi methodology has gained acceptance in diverse fields of medicine. The Delphi methods assumed a pivotal role in the last few decades to develop best practice guidance using collective intelligence where research is limited, ethically/logistically difficult or evidence is conflicting. However, the attempts to assess the quality standard of Delphi studies have reported significant variance, and details of the process followed are usually unclear. We recommend systematic quality tools for evaluation of Delphi methodology; identification of problem area of research, selection of panel, anonymity of panelists, controlled feedback, iterative Delphi rounds, consensus criteria, analysis of consensus, closing criteria, and stability of the results. Based on these nine qualitative evaluation points, we assessed the quality of Delphi studies in the medical field related to coronavirus disease 2019. There was inconsistency in reporting vital elements of Delphi methods such as identification of panel members, defining consensus, closing criteria for rounds, and presenting the results. We propose our evaluation points for researchers, medical journal editorial boards, and reviewers to evaluate the quality of the Delphi methods in healthcare research.', '2026-07-08 08:29:08');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2252512272', 'political-science', 'Iterative Usage of Fixed and Random Effect Models for Powerful and Efficient Genome-Wide Association Studies', 'False positives in a Genome-Wide Association Study (GWAS) can be effectively controlled by a fixed effect and random effect Mixed Linear Model (MLM) that incorporates population structure and kinship…', '2016', 2016, 1652, 1652, 'https://journals.plos.org/plosgenetics/article/figure/image?size=large&id=10.1371/journal.pgen.1005767.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4734661', 'pmc', 'article', 'PLoS Genetics', '["Xiaolei Liu","Meng Huang","Bin Fan","Edward S. Buckler","Zhiwu Zhang"]', 'political science', 'False positives in a Genome-Wide Association Study (GWAS) can be effectively controlled by a fixed effect and random effect Mixed Linear Model (MLM) that incorporates population structure and kinship among individuals to adjust association tests on markers; however, the adjustment also compromises true positives. The modified MLM method, Multiple Loci Linear Mixed Model (MLMM), incorporates multiple markers simultaneously as covariates in a stepwise MLM to partially remove the confounding between testing markers and kinship. To completely eliminate the confounding, we divided MLMM into two parts: Fixed Effect Model (FEM) and a Random Effect Model (REM) and use them iteratively. FEM contains testing markers, one at a time, and multiple associated markers as covariates to control false positives. To avoid model over-fitting problem in FEM, the associated markers are estimated in REM by using them to define kinship. The P values of testing markers and the associated markers are unified at each iteration. We named the new method as Fixed and random model Circulating Probability Unification (FarmCPU). Both real and simulated data analyses demonstrated that FarmCPU improves statistical power compared to current methods. Additional benefits include an efficient computing time that is linear to both number of individuals and number of markers. Now, a dataset with half million individuals and half million markers can be analyzed within three days.', '2026-07-08 08:29:55');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2736255997', 'political-science', 'Early, Accurate Diagnosis and Early Intervention in Cerebral Palsy', 'Importance: Cerebral palsy describes the most common physical disability in childhood and occurs in 1 in 500 live births. Historically, the diagnosis has been made between age 12 and 24 months but…', '2017', 2017, 1606, 1606, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1001/jamapediatrics.2017.1689.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/9641643', 'pmc', 'review', 'JAMA Pediatrics', '["Iona Novak","Cathy Morgan","Lars Adde","James A. Blackman","Roslyn N. Boyd","Janice Brunstrom-Hernandez","Giovanni Cioni","Diane L. Damiano","Johanna Darrah","Ann‐Christin Eliasson","Linda S. de Vries","Christa Einspieler","Michael Fahey","Darcy Fehlings","Donna M. Ferriero","Linda Fetters","Simona Fiori","Hans Forssberg","Andrew M. Gordon","Susan Greaves","Andrea Guzzetta","Mijna Hadders‐Algra","Regina T. Harbourne","Angelina Kakooza‐Mwesige","Petra Karlsson","Lena Krumlinde‐Sundholm","Beatrice Latal","Alison Loughran‐Fowlds","Nathalie L. Maitre","Sarah McIntyre","Garey Noritz","Lindsay Pennington","Domenico M. Romeo","Roberta B. Shepherd","Alicia J. Spittle","Marelle Thornton","Jane Valentine","Karen Walker","Robert M. White","Nadia Badawi"]', 'political science', 'Importance: Cerebral palsy describes the most common physical disability in childhood and occurs in 1 in 500 live births. Historically, the diagnosis has been made between age 12 and 24 months but now can be made before 6 months'' corrected age. Objectives: To systematically review best available evidence for early, accurate diagnosis of cerebral palsy and to summarize best available evidence about cerebral palsy-specific early intervention that should follow early diagnosis to optimize neuroplasticity and function. Evidence Review: This study systematically searched the literature about early diagnosis of cerebral palsy in MEDLINE (1956-2016), EMBASE (1980-2016), CINAHL (1983-2016), and the Cochrane Library (1988-2016) and by hand searching. Search terms included cerebral palsy, diagnosis, detection, prediction, identification, predictive validity, accuracy, sensitivity, and specificity. The study included systematic reviews with or without meta-analyses, criteria of diagnostic accuracy, and evidence-based clinical guidelines. Findings are reported according to the PRISMA statement, and recommendations are reported according to the Appraisal of Guidelines, Research and Evaluation (AGREE) II instrument. Findings: Six systematic reviews and 2 evidence-based clinical guidelines met inclusion criteria. All included articles had high methodological Quality Assessment of Diagnostic Accuracy Studies (QUADAS) ratings. In infants, clinical signs and symptoms of cerebral palsy emerge and evolve before age 2 years; therefore, a combination of standardized tools should be used to predict risk in conjunction with clinical history. Before 5 months'' corrected age, the most predictive tools for detecting risk are term-age magnetic resonance imaging (86%-89% sensitivity), the Prechtl Qualitative Assessment of General Movements (98% sensitivity), and the Hammersmith Infant Neurological Examination (90% sensitivity). After 5 months'' corrected age, the most predictive tools for detecting risk are magnetic resonance imaging (86%-89% sensitivity) (where safe and feasible), the Hammersmith Infant Neurological Examination (90% sensitivity), and the Developmental Assessment of Young Children (83% C index). Topography and severity of cerebral palsy are more difficult to ascertain in infancy, and magnetic resonance imaging and the Hammersmith Infant Neurological Examination may be helpful in assisting clinical decisions. In high-income countries, 2 in 3 individuals with cerebral palsy will walk, 3 in 4 will talk, and 1 in 2 will have normal intelligence. Conclusions and Relevance: Early diagnosis begins with a medical history and involves using neuroimaging, standardized neurological, and standardized motor assessments that indicate congruent abnormal findings indicative of cerebral palsy. Clinicians should understand the importance of prompt referral to diagnostic-specific early intervention to optimize infant motor and cognitive plasticity, prevent secondary complications, and enhance caregiver well-being.', '2026-07-08 08:30:25');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3006116566', 'political-science', 'Low-density lipoproteins cause atherosclerotic cardiovascular disease: pathophysiological, genetic, and therapeutic insights: a consensus statement from the European Atherosclerosis Society Consensus Panel', 'Abstract', '2020', 2020, 1534, 1534, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1093/eurheartj/ehz962.g001', 'https://pubmed.ncbi.nlm.nih.gov/32052833', 'repository', 'article', 'European Heart Journal', '["Jan Borén","M. John Chapman","Ronald M. Krauss","Chris J. Packard","Jacob Fog Bentzon","Christoph J. Binder","Mat J.A.P. Daemen","Linda L. Demer","Robert A. Hegele","Stephen J. Nicholls","Børge G. Nordestgaard","Gerald F. Watts","Éric Bruckert","Sergio Fazio","Brian A. Ference","Ian Graham","Jay D. Horton","Ulf Landmesser","Ulrich Laufs","L. Masana","Gerard Pasterkamp","Frederick J. Raal","Kausik K. Ray","Heribert Schunkert","Marja‐Riitta Taskinen","Bart van de Sluis","Olov Wiklund","Lâle Tokgözoğlu","Alberico L. Catapano","Henry N. Ginsberg"]', 'political science', 'Abstract', '2026-07-08 08:30:55');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3195404919', 'political-science', 'Cardiovascular, mortality, and kidney outcomes with GLP-1 receptor agonists in patients with type 2 diabetes: a systematic review and meta-analysis of randomised trials', 'Cardiovascular, mortality, and kidney outcomes with GLP-1 receptor agonists in patients with type 2 diabetes: a systematic review and meta-analysis of randomised trials', '2021', 2021, 1510, 1510, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1016/s2213-8587(21)00203-5.g001', 'https://pubmed.ncbi.nlm.nih.gov/34425083', 'repository', 'review', 'The Lancet Diabetes & Endocrinology', '["Naveed Sattar","Matthew M.Y. Lee","Søren Lund Kristensen","Kelley R. Branch","Stefano Del Prato","Nardev S. Khurmi","Carolyn S.P. Lam","Renato D. Lópes","John J.V. McMurray","Richard E. Pratley","Julio Rosenstock","Hertzel C. Gerstein"]', 'political science', NULL, '2026-07-08 08:31:34');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3044042843', 'political-science', 'The role of ESG performance during times of financial crisis: Evidence from COVID-19 in China', 'The role of ESG performance during times of financial crisis: Evidence from COVID-19 in China', '2020', 2020, 1498, 1498, 'https://ars.els-cdn.com/content/image/1-s2.0-S1544612320309983-gr1.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7425769', 'pmc', 'article', 'Finance research letters', '["David C. Broadstock","Kalok Chan","Louis T. W. Cheng","Xiaowei Wang"]', 'political science', NULL, '2026-07-08 08:31:46');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2596338372', 'political-science', 'Prevalence of antenatal and postnatal anxiety: Systematic review and meta-analysis', 'Background Maternal anxiety negatively influences child outcomes. Reliable estimates have not been established because of varying published prevalence rates. Aims To establish summary estimates for…', '2017', 2017, 1505, 1505, 'https://static.cambridge.org/binary/version/id/urn:cambridge.org:id:binary:20180726045138494-0103:S0007125000281361:S0007125000281361_fig1g.jpeg', 'https://pubmed.ncbi.nlm.nih.gov/28302701', 'repository', 'review', 'The British Journal of Psychiatry', '["Cindy‐Lee Dennis","Kobra Falah‐Hassani","Rahman Shiri"]', 'political science', 'Background Maternal anxiety negatively influences child outcomes. Reliable estimates have not been established because of varying published prevalence rates. Aims To establish summary estimates for the prevalence of maternal anxiety in the antenatal and postnatal periods. Method We searched multiple databases including MEDLINE, Embase, and PsycINFO to identify studies published up to January 2016 with data on the prevalence of antenatal or postnatal anxiety. Data were extracted from published reports and any missing information was requested from investigators. Estimates were pooled using random-effects meta-analyses. Results We reviewed 23 468 abstracts, retrieved 783 articles and included 102 studies incorporating 221 974 women from 34 countries. The prevalence for self-reported anxiety symptoms was 18.2% (95% CI 13.6–22.8) in the first trimester, 19.1% (95% CI 15.9–22.4) in the second trimester and 24.6% (95% CI 21.2–28.0) in the third trimester. The overall prevalence for a clinical diagnosis of any anxiety disorder was 15.2% (95% CI 9.0–21.4) and 4.1% (95% CI 1.9–6.2) for a generalised anxiety disorder. Postnatally, the prevalence for anxiety symptoms overall at 1–24 weeks was 15.0% (95% CI 13.7–16.4). The prevalence for any anxiety disorder over the same period was 9.9% (95% CI 6.1–13.8), and 5.7% (95% CI 2.3–9.2) for a generalised anxiety disorder. Rates were higher in low- to middle-income countries. Conclusions Results suggest perinatal anxiety is highly prevalent and merits clinical attention. Research is warranted to develop evidence-based interventions.', '2026-07-08 08:31:54');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3017894014', 'political-science', 'Functional Fear Predicts Public Health Compliance in the COVID-19 Pandemic', 'Abstract In the current context of the global pandemic of coronavirus disease-2019 (COVID-19), health professionals are working with social scientists to inform government policy on how to slow the…', '2020', 2020, 1488, 1488, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1007%2Fs10865-021-00226-w/MediaObjects/10865_2021_226_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7185265', 'pmc', 'article', 'International Journal of Mental Health and Addiction', '["Craig A. Harper","Liam Satchell","Dean Fido","Robert D. Latzman"]', 'political science', 'Abstract In the current context of the global pandemic of coronavirus disease-2019 (COVID-19), health professionals are working with social scientists to inform government policy on how to slow the spread of the virus. An increasing amount of social scientific research has looked at the role of public message framing, for instance, but few studies have thus far examined the role of individual differences in emotional and personality-based variables in predicting virus-mitigating behaviors. In this study, we recruited a large international community sample ( N = 324) to complete measures of self-perceived risk of contracting COVID-19, fear of the virus, moral foundations, political orientation, and behavior change in response to the pandemic. Consistently, the only predictor of positive behavior change (e.g., social distancing, improved hand hygiene) was fear of COVID-19, with no effect of politically relevant variables. We discuss these data in relation to the potentially functional nature of fear in global health crises.', '2026-07-08 08:32:05');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2318568688', 'political-science', 'The significance of soils and soil science towards realization of the United Nations Sustainable Development Goals', 'Abstract. In this forum paper we discuss how soil scientists can help to reach the recently adopted UN Sustainable Development Goals (SDGs) in the most effective manner. Soil science, as a…', '2016', 2016, 1491, 1491, 'https://www.soil-journal.net/graphic_egu_claim_logo_blue.png', 'https://doi.org/10.5194/soil-2-111-2016', 'repository', 'article', 'SOIL', '["Saskia Keesstra","J. Bouma","Jakob Wallinga","Pablo Tittonell","Pete Smith","Artemi Cerdà","Luca Montanarella","John Quinton","Yakov Pachepsky","Wim H. van der Putten","Richard D. Bardgett","S.W. Moolenaar","G. Mol","Boris Jansen","L.O. Fresco"]', 'political science', 'Abstract. In this forum paper we discuss how soil scientists can help to reach the recently adopted UN Sustainable Development Goals (SDGs) in the most effective manner. Soil science, as a land-related discipline, has important links to several of the SDGs, which are demonstrated through the functions of soils and the ecosystem services that are linked to those functions (see graphical abstract in the Supplement). We explore and discuss how soil scientists can rise to the challenge both internally, in terms of our procedures and practices, and externally, in terms of our relations with colleague scientists in other disciplines, diverse groups of stakeholders and the policy arena. To meet these goals we recommend the following steps to be taken by the soil science community as a whole: (i) embrace the UN SDGs, as they provide a platform that allows soil science to demonstrate its relevance for realizing a sustainable society by 2030; (ii) show the specific value of soil science: research should explicitly show how using modern soil information can improve the results of inter- and transdisciplinary studies on SDGs related to food security, water scarcity, climate change, biodiversity loss and health threats; (iii) take leadership in overarching system analysis of ecosystems, as soils and soil scientists have an integrated nature and this places soil scientists in a unique position; (iii) raise awareness of soil organic matter as a key attribute of soils to illustrate its importance for soil functions and ecosystem services; (iv) improve the transfer of knowledge through knowledge brokers with a soil background; (v) start at the basis: educational programmes are needed at all levels, starting in primary schools, and emphasizing practical, down-to-earth examples; (vi) facilitate communication with the policy arena by framing research in terms that resonate with politicians in terms of the policy cycle or by considering drivers, pressures and responses affecting impacts of land use change; and finally (vii) all this is only possible if researchers, with soil scientists in the front lines, look over the hedge towards other disciplines, to the world at large and to the policy arena, reaching over to listen first, as a basis for genuine collaboration.', '2026-07-08 08:32:06');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2805201924', 'political-science', 'Associations between loneliness and perceived social support and outcomes of mental health problems: a systematic review', 'BACKGROUND: The adverse effects of loneliness and of poor perceived social support on physical health and mortality are established, but no systematic synthesis is available of their relationship…', '2018', 2018, 1494, 1494, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs12888-018-1736-5/MediaObjects/12888_2018_1736_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5975705', 'pmc', 'review', 'BMC Psychiatry', '["Jingyi Wang","Farhana Mann","Brynmor Lloyd‐Evans","Ruimin Ma","Sonia Johnson"]', 'political science', 'BACKGROUND: The adverse effects of loneliness and of poor perceived social support on physical health and mortality are established, but no systematic synthesis is available of their relationship with the outcomes of mental health problems over time. In this systematic review, we aim to examine the evidence on whether loneliness and closely related concepts predict poor outcomes among adults with mental health problems. METHODS: We searched six databases and reference lists for longitudinal quantitative studies that examined the relationship between baseline measures of loneliness and poor perceived social support and outcomes at follow up. Thirty-four eligible papers were retrieved. Due to heterogeneity among included studies in clinical populations, predictor measures and outcomes, a narrative synthesis was conducted. RESULTS: We found substantial evidence from prospective studies that people with depression who perceive their social support as poorer have worse outcomes in terms of symptoms, recovery and social functioning. Loneliness has been investigated much less than perceived social support, but there is some evidence that greater loneliness predicts poorer depression outcome. There is also some preliminary evidence of associations between perceived social support and outcomes in schizophrenia, bipolar disorder and anxiety disorders. CONCLUSIONS: Loneliness and quality of social support in depression are potential targets for development and testing of interventions, while for other conditions further evidence is needed regarding relationships with outcomes.', '2026-07-08 08:32:06');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3017264036', 'political-science', 'Diagnosis and treatment of acute appendicitis: 2020 update of the WSES Jerusalem guidelines', 'BACKGROUND AND AIMS: Acute appendicitis (AA) is among the most common causes of acute abdominal pain. Diagnosis of AA is still challenging and some controversies on its management are still present…', '2020', 2020, 1370, 1370, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs13017-020-00306-3/MediaObjects/13017_2020_306_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7386163', 'pmc', 'review', 'World Journal of Emergency Surgery', '["Salomone Di Saverio","Mauro Podda","Belinda De Simone","Marco Ceresoli","Goran Augustin","Alice Gori","Marja A. Boermeester","Massimo Sartelli","Federico Coccolini","Antonio Tarasconi","Nicola De Angelis","Dieter Weber","Matti Tolonen","Arianna Birindelli","Walter Biffl","Ernest E. Moore","Michael E. Kelly","Kjetil Søreide","Jeffry L. Kashuk","Richard P. G. ten Broek","Carlos Augusto Gomes","Michael Sugrue","Richard Justin Davies","Dimitrios Damaskos","Ari Leppäniemi","Andrew W. Kirkpatrick","Andrew B. Peitzman","Gustavo Pereira Fraga","Ronald V. Maier","Raúl Coimbra","Massimo Chiarugi","Gabriele Sganga","Adolfo Pisanu","Gian Luigi De’ Angelis","Edward Tan","Harry van Goor","Francesco Pata","Isidoro Di Carlo","Osvaldo Chiara","Andrey Litvin","Fabio Cesare Campanile","Boris Sakakushev","Gia Tomadze","Zaza Demetrashvili","Rifat Latifi","Fakri Abu-Zidan","Oreste Romeo","Helmut Alfredo Segovia Lohse","Gian Luca Baiocchi","David W. da Costa","Sandro Rizoli","Zsolt J. Balogh","Cino Bendinelli","Thomas M. Scalea","Rao R. Ivatury","George C. Velmahos","Roland E. Andersson","Yoram Kluger","Luca Ansaloni","Fausto Catena"]', 'political science', 'BACKGROUND AND AIMS: Acute appendicitis (AA) is among the most common causes of acute abdominal pain. Diagnosis of AA is still challenging and some controversies on its management are still present among different settings and practice patterns worldwide. In July 2015, the World Society of Emergency Surgery (WSES) organized in Jerusalem the first consensus conference on the diagnosis and treatment of AA in adult patients with the intention of producing evidence-based guidelines. An updated consensus conference took place in Nijemegen in June 2019 and the guidelines have now been updated in order to provide evidence-based statements and recommendations in keeping with varying clinical practice: use of clinical scores and imaging in diagnosing AA, indications and timing for surgery, use of non-operative management and antibiotics, laparoscopy and surgical techniques, intra-operative scoring, and peri-operative antibiotic therapy. METHODS: This executive manuscript summarizes the WSES guidelines for the diagnosis and treatment of AA. Literature search has been updated up to 2019 and statements and recommendations have been developed according to the GRADE methodology. The statements were voted, eventually modified, and finally approved by the participants to the consensus conference and by the board of co-authors, using a Delphi methodology for voting whenever there was controversy on a statement or a recommendation. Several tables highlighting the research topics and questions, search syntaxes, and the statements and the WSES evidence-based recommendations are provided. Finally, two different practical clinical algorithms are provided in the form of a flow chart for both adults and pediatric (< 16 years old) patients. CONCLUSIONS: The 2020 WSES guidelines on AA aim to provide updated evidence-based statements and recommendations on each of the following topics: (1) diagnosis, (2) non-operative management for uncomplicated AA, (3) timing of appendectomy and in-hospital delay, (4) surgical treatment, (5) intra-operative grading of AA, (6),management of perforated AA with phlegmon or abscess, and (7) peri-operative antibiotic therapy.', '2026-07-08 08:34:05');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2408382927', 'political-science', 'Tools and techniques for solvent selection: green solvent selection guides', 'Driven by legislation and evolving attitudes towards environmental issues, establishing green solvents for extractions, separations, formulations and reaction chemistry has become an increasingly…', '2016', 2016, 1376, 1376, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1007%2Fs10098-021-02188-8/MediaObjects/10098_2021_2188_Fig1_HTML.jpg', 'https://doi.org/10.1186/s40508-016-0051-z', 'repository', 'article', 'Sustainable Chemical Processes', '["Fergal P. Byrne","Saimeng Jin","Giulia Paggiola","Tabitha H. M. Petchey","James H. Clark","Thomas J. Farmer","Andrew J. Hunt","Con Robert McElroy","James Sherwood"]', 'political science', 'Driven by legislation and evolving attitudes towards environmental issues, establishing green solvents for extractions, separations, formulations and reaction chemistry has become an increasingly important area of research. Several general purpose solvent selection guides have now been published with the aim to reduce use of the most hazardous solvents. This review serves the purpose of explaining the role of these guides, highlighting their similarities and differences. How they can be used most effectively to enhance the greenness of chemical processes, particularly in laboratory organic synthesis and the pharmaceutical industry, is addressed in detail.', '2026-07-08 08:34:06');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2970830005', 'political-science', 'Changing climate both increases and decreases European river floods', 'Changing climate both increases and decreases European river floods', '2019', 2019, 1302, 1302, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-019-1495-6/MediaObjects/41586_2019_1495_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/31462777', 'repository', 'article', 'Nature', '["Günter Blöschl","Julia Hall","Alberto Viglione","Rui A. P. Perdigão","Juraj Párajka","Bruno Merz","David Lun","Berit Arheimer","Giuseppe Tito Aronica","Ardian Bilibashi","Miloň Boháč","Ognjen Bonacci","Marco Borga","Ivan Čanjevac","Attilio Castellarin","Giovanni Battista Chirico","Pierluigi Claps","Н. Л. Фролова","Daniele Ganora","Liudmyla Gorbachova","Ali Gül","Jamie Hannaford","Shaun Harrigan","Maria Kireeva","Andrea Kiss","Thomas Kjeldsen","Silvia Kohnová","Jarkko Koskela","Ondřej Ledvinka","Neil Macdonald","Maria Mavrova-Guirguinova","Luis Mediero","Ralf Merz","Péter Molnár","Alberto Montanari","Conor Murphy","Marzena Osuch","Valeriya Ovcharuk","Иван Радевски","José Luis Salinas","Éric Sauquet","Mojca Šraj","Ján Szolgay","Elena Volpi","Donna Wilson","Klodian Zaımı","Nenad Živković"]', 'political science', NULL, '2026-07-08 08:35:19');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2989530049', 'political-science', 'Visualizing a field of research: A methodology of systematic scientometric reviews', 'Systematic scientometric reviews, empowered by computational and visual analytic approaches, offer opportunities to improve the timeliness, accessibility, and reproducibility of studies of the…', '2019', 2019, 1306, 1306, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0223994.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6822756', 'pmc', 'article', 'PLoS ONE', '["Chaomei Chen","Min Song"]', 'political science', 'Systematic scientometric reviews, empowered by computational and visual analytic approaches, offer opportunities to improve the timeliness, accessibility, and reproducibility of studies of the literature of a field of research. On the other hand, effectively and adequately identifying the most representative body of scholarly publications as the basis of subsequent analyses remains a common bottleneck in the current practice. What can we do to reduce the risk of missing something potentially significant? How can we compare different search strategies in terms of the relevance and specificity of topical areas covered? In this study, we introduce a flexible and generic methodology based on a significant extension of the general conceptual framework of citation indexing for delineating the literature of a research field. The method, through cascading citation expansion, provides a practical connection between studies of science from local and global perspectives. We demonstrate an application of the methodology to the research of literature-based discovery (LBD) and compare five datasets constructed based on three use scenarios and corresponding retrieval strategies, namely a query-based lexical search (one dataset), forward expansions starting from a groundbreaking article of LBD (two datasets), and backward expansions starting from a recently published review article by a prominent expert in LBD (two datasets). We particularly discuss the relevance of areas captured by expansion processes with reference to the query-based scientometric visualization. The method used in this study for comparing bibliometric datasets is applicable to comparative studies of search strategies.', '2026-07-08 08:35:19');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2986413343', 'political-science', 'The Powder Diffraction File: a quality materials characterization database', 'The ICDD''s Powder Diffraction File ™ (PDF ® ) is a database of inorganic and organic diffraction data used for phase identification and materials characterization by powder diffraction. The PDF has…', '2019', 2019, 1301, 1301, 'https://static.cambridge.org/binary/version/id/urn:cambridge.org:id:binary:20200117144105858-0745:S0885715619000812:S0885715619000812_fig1g.jpeg', 'https://doi.org/10.1017/s0885715619000812', 'repository', 'article', 'Powder Diffraction', '["Stacy Gates-Rector","Thomas N. Blanton"]', 'political science', 'The ICDD''s Powder Diffraction File ™ (PDF ® ) is a database of inorganic and organic diffraction data used for phase identification and materials characterization by powder diffraction. The PDF has been available for over 75 years and finds application in X-ray, synchrotron, electron, and neutron diffraction analyses. With entries based on powder and single crystal data, the PDF is the only crystallographic database where every entry is editorially reviewed and marked with a quality mark that alerts the user to the reliability/quality of the submitted data. The editorial processes of ICDD''s quality management system are unique in that they are ISO 9001:2015 certified. Initially offered as text on paper cards and books, the PDF evolved to a computer-readable database in the 1960s and today is both computer and web accessible. With data mining and phase identification software available in PDF products, and the databases’ compatibility with vendor (third party) software, the 1 000 000+ published PDF entries serve a wide range of disciplines covering academic, industrial, and government laboratories. Details describing the content of database entries are presented to enhance the use of the PDF.', '2026-07-08 08:35:24');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3047747926', 'political-science', 'Digital technologies in the public-health response to COVID-19', 'Digital technologies in the public-health response to COVID-19', '2020', 2020, 1252, 1252, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41591-020-1011-4/MediaObjects/41591_2020_1011_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/32770165', 'repository', 'review', 'Nature Medicine', '["Jobie Budd","Benjamin S. Miller","Erin Manning","Vasileios Lampos","Mengdie Zhuang","Michael Edelstein","Geraint Rees","Vincent C. Emery","Molly M. Stevens","Neil Keegan","Michael Short","Deenan Pillay","Ed Manley","Ingemar J. Cox","David Heymann","Anne M. Johnson","Rachel A. McKendry"]', 'political science', NULL, '2026-07-08 08:36:29');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2747361386', 'political-science', 'Revitalize the world’s countryside', 'Revitalize the world’s countryside', '2017', 2017, 1252, 1252, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2F548275a/MediaObjects/41586_2017_Article_BF548275a_Figa_HTML.jpg', 'https://pubmed.ncbi.nlm.nih.gov/28816262', 'repository', 'article', 'Nature', '["Yansui Liu","Yuheng Li"]', 'political science', NULL, '2026-07-08 08:36:29');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2887886950', 'political-science', 'A revised airway epithelial hierarchy includes CFTR-expressing ionocytes', 'A revised airway epithelial hierarchy includes CFTR-expressing ionocytes', '2018', 2018, 1254, 1254, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-018-0393-7/MediaObjects/41586_2018_393_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6295155', 'pmc', 'article', 'Nature', '["Daniel T. Montoro","Adam L. Haber","Moshe Biton","Vladimír Vinarský","Brian Lin","Susan E. Birket","Feng Yuan","Sijia Chen","Hui Min Leung","Jorge Villoria","Noga Rogel","Grace Burgin","Alexander M. Tsankov","Avinash Waghray","Michal Slyper","Julia Waldman","Lan Nguyễn","Danielle Dionne","Orit Rozenblatt–Rosen","Purushothama Rao Tata","Hongmei Mou","Manjunatha Shivaraju","Hermann Bihler","Martin Mense","Guillermo J. Tearney","Steven M. Rowe","John F. Engelhardt","Aviv Regev","Jayaraj Rajagopal"]', 'political science', NULL, '2026-07-08 08:36:30');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2883098649', 'political-science', 'Influencers on Instagram: Antecedents and consequences of opinion leadership', 'Opinion leaders are important sources of advice for other consumers. Instagram is the most used platform by opinion leaders in the fashion industry, and this trend is expected to continue in the near…', '2018', 2018, 1247, 1247, 'https://ars.els-cdn.com/content/image/1-s2.0-S0148296318303187-gr1.jpg', 'https://doi.org/10.1016/j.jbusres.2018.07.005', 'repository', 'article', 'Journal of Business Research', '["Luis V. Casaló","Carlos Flavián","Sergio Ibáñez‐Sánchez"]', 'political science', 'Opinion leaders are important sources of advice for other consumers. Instagram is the most used platform by opinion leaders in the fashion industry, and this trend is expected to continue in the near future. This study aims to identify some key antecedents and consequences of opinion leadership in this context. Our results, based on data collected from 808 followers of a fashion focused Instagram account, suggest that originality and uniqueness are crucial factors if a user is to be perceived as an opinion leader on Instagram. In addition, opinion leadership influences consumer behavioral intentions toward both the influencer (intention to interact in the account and recommend it) and the fashion industry (intention to follow fashion advice posted). Finally, the perceived fit of the account with the consumer''s personality strengthens the influence of opinion leadership on the intention to follow published advice. These results have interesting implications for the fashion industry.', '2026-07-08 08:36:42');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2314815360', 'political-science', 'Management Guidelines for Children with Thyroid Nodules and Differentiated Thyroid Cancer', 'BACKGROUND: Previous guidelines for the management of thyroid nodules and cancers were geared toward adults. Compared with thyroid neoplasms in adults, however, those in the pediatric population…', '2015', 2015, 1234, 1234, 'https://cdn.ncbi.nlm.nih.gov/pmc/blobs/8914/4854274/2fa263758bd2/fig-1.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4854274', 'pmc', 'review', 'Thyroid', '["Gary L. Francis","Steven G. Waguespack","Andrew J. Bauer","Peter Angelos","Salvatore Benvenga","Janete M. Cerutti","Catherine Dinauer","Jill Hamilton","Ian Hay","Markus Luster","Marguerite T. Parisi","Marianna Rachmiel","Geoffrey B. Thompson","Shunichi Yamashita"]', 'political science', 'BACKGROUND: Previous guidelines for the management of thyroid nodules and cancers were geared toward adults. Compared with thyroid neoplasms in adults, however, those in the pediatric population exhibit differences in pathophysiology, clinical presentation, and long-term outcomes. Furthermore, therapy that may be recommended for an adult may not be appropriate for a child who is at low risk for death but at higher risk for long-term harm from overly aggressive treatment. For these reasons, unique guidelines for children and adolescents with thyroid tumors are needed. METHODS: A task force commissioned by the American Thyroid Association (ATA) developed a series of clinically relevant questions pertaining to the management of children with thyroid nodules and differentiated thyroid cancer (DTC). Using an extensive literature search, primarily focused on studies that included subjects ≤18 years of age, the task force identified and reviewed relevant articles through April 2014. Recommendations were made based upon scientific evidence and expert opinion and were graded using a modified schema from the United States Preventive Services Task Force. RESULTS: These inaugural guidelines provide recommendations for the evaluation and management of thyroid nodules in children and adolescents, including the role and interpretation of ultrasound, fine-needle aspiration cytology, and the management of benign nodules. Recommendations for the evaluation, treatment, and follow-up of children and adolescents with DTC are outlined and include preoperative staging, surgical management, postoperative staging, the role of radioactive iodine therapy, and goals for thyrotropin suppression. Management algorithms are proposed and separate recommendations for papillary and follicular thyroid cancers are provided. CONCLUSIONS: In response to our charge as an independent task force appointed by the ATA, we developed recommendations based on scientific evidence and expert opinion for the management of thyroid nodules and DTC in children and adolescents. In our opinion, these represent the current optimal care for children and adolescents with these conditions.', '2026-07-08 08:36:56');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1977992740', 'political-science', 'The "dual-spot" Aethalometer: an improved measurement of aerosol black carbon with real-time loading compensation', 'Abstract. Aerosol black carbon is a unique primary tracer for combustion emissions. It affects the optical properties of the atmosphere and is recognized as the second most important anthropogenic…', '2015', 2015, 1202, 1202, 'https://www.atmospheric-measurement-techniques.net/graphic_egu_claim_logo_blue.png', 'https://hal.science/hal-01806211', 'repository', 'article', 'Atmospheric measurement techniques', '["Luka Drinovec","Griša Močnik","Peter Zotter","Andrê S. H. Prévôt","Christian Ruckstuhl","Esther Coz","Maheswar Rupakheti","Jean Sciare","Thomas Müller","Alfred Wiedensohler","A. D. A. Hansen"]', 'political science', 'Abstract. Aerosol black carbon is a unique primary tracer for combustion emissions. It affects the optical properties of the atmosphere and is recognized as the second most important anthropogenic forcing agent for climate change. It is the primary tracer for adverse health effects caused by air pollution. For the accurate determination of mass equivalent black carbon concentrations in the air and for source apportionment of the concentrations, optical measurements by filter-based absorption photometers must take into account the "filter loading effect". We present a new real-time loading effect compensation algorithm based on a two parallel spot measurement of optical absorption. This algorithm has been incorporated into the new Aethalometer model AE33. Intercomparison studies show excellent reproducibility of the AE33 measurements and very good agreement with post-processed data obtained using earlier Aethalometer models and other filter-based absorption photometers. The real-time loading effect compensation algorithm provides the high-quality data necessary for real-time source apportionment and for determination of the temporal variation of the compensation parameter k.', '2026-07-08 08:37:41');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2484473026', 'political-science', 'Social support and protection from depression: systematic review of current findings in Western countries', 'BACKGROUND: Numerous studies report an association between social support and protection from depression, but no systematic review or meta-analysis exists on this topic. AIMS: To review…', '2016', 2016, 1202, 1202, 'https://static.cambridge.org/binary/version/id/urn:cambridge.org:id:binary:20180530082546439-0195:S0007125000245121:S0007125000245121_fig1g.jpeg', 'https://pubmed.ncbi.nlm.nih.gov/27445355', 'repository', 'review', 'The British Journal of Psychiatry', '["Geneviève Gariépy","Helena Honkaniemi","Amélie Quesnel‐Vallée"]', 'political science', 'BACKGROUND: Numerous studies report an association between social support and protection from depression, but no systematic review or meta-analysis exists on this topic. AIMS: To review systematically the characteristics of social support (types and source) associated with protection from depression across life periods (childhood and adolescence; adulthood; older age) and by study design (cross-sectional v cohort studies). METHOD: A systematic literature search conducted in February 2015 yielded 100 eligible studies. Study quality was assessed using a critical appraisal checklist, followed by meta-analyses. RESULTS: Sources of support varied across life periods, with parental support being most important among children and adolescents, whereas adults and older adults relied more on spouses, followed by family and then friends. Significant heterogeneity in social support measurement was noted. Effects were weaker in both magnitude and significance in cohort studies. CONCLUSIONS: Knowledge gaps remain due to social support measurement heterogeneity and to evidence of reverse causality bias.', '2026-07-08 08:37:42');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2810968011', 'political-science', 'Cultural tourism: A review of recent research and trends', 'Cultural tourism: A review of recent research and trends', '2018', 2018, 1203, 1203, 'https://ars.els-cdn.com/content/image/1-s2.0-S1447677018300755-gr1.jpg', 'https://doi.org/10.1016/j.jhtm.2018.03.005', 'repository', 'review', 'Journal of Hospitality and Tourism Management', '["Greg Richards"]', 'political science', NULL, '2026-07-08 08:37:42');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2698106459', 'political-science', 'Association Between Initial Use of e-Cigarettes and Subsequent Cigarette Smoking Among Adolescents and Young Adults', 'Importance: The public health implications of e-cigarettes depend, in part, on whether e-cigarette use affects the risk of cigarette smoking. Objective: To perform a systematic review and…', '2017', 2017, 1189, 1189, 'https://cdn.ncbi.nlm.nih.gov/pmc/blobs/a37f/5710635/81537cf1a998/jamapediatr-e171488-g001.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5656237', 'pmc', 'review', 'JAMA Pediatrics', '["Samir Soneji","Jessica L. Barrington‐Trimis","Thomas A. Wills","Adam M. Leventhal","Jennifer B. Unger","Laura Gibson","Jae-Won Yang","Brian A. Primack","Judy A. Andrews","Richard A. Miech","Tory R. Spindle","Danielle M. Dick","Thomas Eissenberg","Robert Hornik","Rui Dang","James D. Sargent"]', 'political science', 'Importance: The public health implications of e-cigarettes depend, in part, on whether e-cigarette use affects the risk of cigarette smoking. Objective: To perform a systematic review and meta-analysis of longitudinal studies that assessed initial use of e-cigarettes and subsequent cigarette smoking. Data Sources: PubMed, EMBASE, Cochrane Library, Web of Science, the 2016 Society for Research on Nicotine and Tobacco 22nd Annual Meeting abstracts, the 2016 Society of Behavioral Medicine 37th Annual Meeting & Scientific Sessions abstracts, and the 2016 National Institutes of Health Tobacco Regulatory Science Program Conference were searched between February 7 and February 17, 2017. The search included indexed terms and text words to capture concepts associated with e-cigarettes and traditional cigarettes in articles published from database inception to the date of the search. Study Selection: Longitudinal studies reporting odds ratios for cigarette smoking initiation associated with ever use of e-cigarettes or past 30-day cigarette smoking associated with past 30-day e-cigarette use. Searches yielded 6959 unique studies, of which 9 met inclusion criteria (comprising 17 389 adolescents and young adults). Data Extraction and Synthesis: Study quality and risk of bias were assessed using the Newcastle-Ottawa Scale and the Risk of Bias in Non-randomized Studies of Interventions tool, respectively. Data and estimates were pooled using random-effects meta-analysis. Main Outcomes and Measures: Among baseline never cigarette smokers, cigarette smoking initiation between baseline and follow-up. Among baseline non-past 30-day cigarette smokers who were past 30-day e-cigarette users, past 30-day cigarette smoking at follow-up. Results: Among 17 389 adolescents and young adults, the ages ranged between 14 and 30 years at baseline, and 56.0% were female. The pooled probabilities of cigarette smoking initiation were 30.4% for baseline ever e-cigarette users and 7.9% for baseline never e-cigarette users. The pooled probabilities of past 30-day cigarette smoking at follow-up were 21.5% for baseline past 30-day e-cigarette users and 4.6% for baseline non-past 30-day e-cigarette users. Adjusting for known demographic, psychosocial, and behavioral risk factors for cigarette smoking, the pooled odds ratio for subsequent cigarette smoking initiation was 3.62 (95% CI, 2.42-5.41) for ever vs never e-cigarette users, and the pooled odds ratio for past 30-day cigarette smoking at follow-up was 4.28 (95% CI, 2.52-7.27) for past 30-day e-cigarette vs non-past 30-day e-cigarette users at baseline. A moderate level of heterogeneity was observed among studies (I2 = 60.1%). Conclusions and Relevance: e-Cigarette use was associated with greater risk for subsequent cigarette smoking initiation and past 30-day cigarette smoking. Strong e-cigarette regulation could potentially curb use among youth and possibly limit the future population-level burden of cigarette smoking.', '2026-07-08 08:38:08');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2980789587', 'political-science', 'Unified rational protein engineering with sequence-based deep representation learning', 'Unified rational protein engineering with sequence-based deep representation learning', '2019', 2019, 1180, 1180, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41592-019-0598-1/MediaObjects/41592_2019_598_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7067682', 'pmc', 'article', 'Nature Methods', '["Ethan C. Alley","Grigory Khimulya","Surojit Biswas","Mohammed AlQuraishi","George M. Church"]', 'political science', NULL, '2026-07-08 08:38:32');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4211017739', 'political-science', 'Machine behaviour', 'Machine behaviour', '2019', 2019, 1177, 1177, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-019-1138-y/MediaObjects/41586_2019_1138_Fig1_HTML.png', 'https://hal.science/hal-04121682', 'repository', 'review', 'Nature', '["Iyad Rahwan","Manuel Cebrián","Nick Obradovich","Josh Bongard","Jean‐François Bonnefon","Cynthia Breazeal","Jacob W. Crandall","Nicholas A. Christakis","Iain D. Couzin","Matthew O. Jackson","Nicholas R. Jennings","Ece Kamar","Isabel M. Kloumann","Hugo Larochelle","David Lazer","Richard McElreath","Alan Mislove","David C. Parkes","Alex Pentland","Margaret E. Roberts","Azim Shariff","Joshua B. Tenenbaum","Michael P. Wellman"]', 'political science', NULL, '2026-07-08 08:38:32');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2315849398', 'political-science', 'The future of mental health care: peer-to-peer support and social media', 'AIMS: People with serious mental illness are increasingly turning to popular social media, including Facebook, Twitter or YouTube, to share their illness experiences or seek advice from others with…', '2016', 2016, 1171, 1171, 'https://static.cambridge.org/binary/version/id/urn:cambridge.org:id:binary-alt:20160909115740-87388-mediumThumb-S2045796015001067_fig1g.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4830464', 'pmc', 'article', 'Epidemiology and Psychiatric Sciences', '["John A. Naslund","Kelly A. Aschbrenner","Lisa A. Marsch","Stephen J. Bartels"]', 'political science', 'AIMS: People with serious mental illness are increasingly turning to popular social media, including Facebook, Twitter or YouTube, to share their illness experiences or seek advice from others with similar health conditions. This emerging form of unsolicited communication among self-forming online communities of patients and individuals with diverse health concerns is referred to as peer-to-peer support. We offer a perspective on how online peer-to-peer connections among people with serious mental illness could advance efforts to promote mental and physical wellbeing in this group. METHODS: In this commentary, we take the perspective that when an individual with serious mental illness decides to connect with similar others online it represents a critical point in their illness experience. We propose a conceptual model to illustrate how online peer-to-peer connections may afford opportunities for individuals with serious mental illness to challenge stigma, increase consumer activation and access online interventions for mental and physical wellbeing. RESULTS: People with serious mental illness report benefits from interacting with peers online from greater social connectedness, feelings of group belonging and by sharing personal stories and strategies for coping with day-to-day challenges of living with a mental illness. Within online communities, individuals with serious mental illness could challenge stigma through personal empowerment and providing hope. By learning from peers online, these individuals may gain insight about important health care decisions, which could promote mental health care seeking behaviours. These individuals could also access interventions for mental and physical wellbeing delivered through social media that could incorporate mutual support between peers, help promote treatment engagement and reach a wider demographic. Unforeseen risks may include exposure to misleading information, facing hostile or derogatory comments from others, or feeling more uncertain about one''s health condition. However, given the evidence to date, the benefits of online peer-to-peer support appear to outweigh the potential risks. CONCLUSION: Future research must explore these opportunities to support and empower people with serious mental illness through online peer networks while carefully considering potential risks that may arise from online peer-to-peer interactions. Efforts will also need to address methodological challenges in the form of evaluating interventions delivered through social media and collecting objective mental and physical health outcome measures online. A key challenge will be to determine whether skills learned from peers in online networks translate into tangible and meaningful improvements in recovery, employment, or mental and physical wellbeing in the offline world.', '2026-07-08 08:38:45');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2605606367', 'political-science', 'Economic Burden of Obesity: A Systematic Literature Review', 'Background: The rising prevalence of obesity represents an important public health issue. An assessment of its costs may be useful in providing recommendations for policy and decision makers. This…', '2017', 2017, 1166, 1166, 'https://pub.mdpi-res.com/ijerph/ijerph-14-00435/article_deploy/html/images/ijerph-14-00435-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5409636', 'pmc', 'review', 'International Journal of Environmental Research and Public Health', '["Maximilian Tremmel","Ulf‐G. Gerdtham","Peter Nilsson","Sanjib Saha"]', 'political science', 'Background: The rising prevalence of obesity represents an important public health issue. An assessment of its costs may be useful in providing recommendations for policy and decision makers. This systematic review aimed to assess the economic burden of obesity and to identify, measure and describe the different obesity-related diseases included in the selected studies. Methods: A systematic literature search of studies in the English language was carried out in Medline (PubMed) and Web of Science databases to select cost-of-illness studies calculating the cost of obesity in a study population aged ≥18 years with obesity, as defined by a body mass index of ≥30 kg/m², for the whole selected country. The time frame for the analysis was January 2011 to September 2016. Results: The included twenty three studies reported a substantial economic burden of obesity in both developed and developing countries. There was considerable heterogeneity in methodological approaches, target populations, study time frames, and perspectives. This prevents an informative comparison between most of the studies. Specifically, there was great variety in the included obesity-related diseases and complications among the studies. Conclusions: There is an urgent need for public health measures to prevent obesity in order to save societal resources. Moreover, international consensus is required on standardized methods to calculate the cost of obesity to improve homogeneity and comparability. This aspect should also be considered when including obesity-related diseases.', '2026-07-08 08:38:50');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2128386614', 'political-science', 'Mental Health Benefits of Long-Term Exposure to Residential Green and Blue Spaces: A Systematic Review', 'Many studies conducted during the last decade suggest the mental health benefits of green and blue spaces. We aimed to systematically review the available literature on the long-term mental health…', '2015', 2015, 1155, 1155, 'https://pub.mdpi-res.com/ijerph/ijerph-12-04354/article_deploy/html/images/ijerph-12-04354-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4410252', 'pmc', 'review', 'International Journal of Environmental Research and Public Health', '["Mireia Gascón","Margarita Triguero‐Mas","David Martínez","Payam Dadvand","Joan Forns","Antoni Plasència","Mark J Nieuwenhuijsen"]', 'political science', 'Many studies conducted during the last decade suggest the mental health benefits of green and blue spaces. We aimed to systematically review the available literature on the long-term mental health benefits of residential green and blue spaces by including studies that used standardized tools or objective measures of both the exposures and the outcomes of interest. We followed the PRISMA statement guidelines for reporting systematic reviews and meta-analysis. In total 28 studies were included in the systematic review. We found limited evidence for a causal relationship between surrounding greenness and mental health in adults, whereas the evidence was inadequate in children. The evidence was also inadequate for the other exposures evaluated (access to green spaces, quality of green spaces, and blue spaces) in both adults and children. The main limitation was the limited number of studies, together with the heterogeneity regarding exposure assessment. Given the increase in mental health problems and the current rapid urbanization worldwide, results of the present systematic review should be taken into account in future urban planning. However, further research is needed to provide more consistent evidence and more detailed information on the mechanisms and the characteristics of the green and blue spaces that promote better mental health. We provide recommendations for future studies in order to provide consistent and evidence-based recommendations for policy makers.', '2026-07-08 08:39:12');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3083347663', 'political-science', 'Avoiding Ableist Language: Suggestions for Autism Researchers', 'In this commentary, we describe how language used to communicate about autism within much of autism research can reflect and perpetuate ableist ideologies (i.e., beliefs and practices that…', '2020', 2020, 1146, 1146, 'https://cdn.ncbi.nlm.nih.gov/pmc/blobs/88fd/8992888/c8c94c0f4313/aut.2020.0014_figure1.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8992888', 'pmc', 'article', 'Autism in Adulthood', '["Kristen Bottema‐Beutel","Steven K. Kapp","Jessica Nina Lester","Noah J. Sasson","Brittany N. Hand"]', 'political science', 'In this commentary, we describe how language used to communicate about autism within much of autism research can reflect and perpetuate ableist ideologies (i.e., beliefs and practices that discriminate against people with disabilities), whether or not researchers intend to have such effects. Drawing largely from autistic scholarship on this subject, along with research and theory from disability studies and discourse analysis, we define ableism and its realization in linguistic practices, provide a historical overview of ableist language used to describe autism, and review calls from autistic researchers and laypeople to adopt alternative ways of speaking and writing. Finally, we provide several specific avenues to aid autism researchers in reflecting on and adjusting their language choices. Lay summary: Language is a powerful means for shaping how people view autism. If researchers take steps to avoid ableist language, researchers, service providers, and society at large may become more accepting and accommodating of autistic people.', '2026-07-08 08:39:24');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2990520469', 'political-science', 'Innovation ecosystems: A conceptual review and a new definition', 'The concept of innovation ecosystems has become popular during the last 15 years, leading to a debate regarding its relevance and conceptual rigor, not the least in this journal. The purpose of this…', '2019', 2019, 1152, 1152, 'https://ars.els-cdn.com/content/image/1-s2.0-S0166497218303870-fx1.jpg', 'https://doi.org/10.1016/j.technovation.2019.102098', 'repository', 'review', 'Technovation', '["Ove Granstrand","Marcus Holgersson"]', 'political science', 'The concept of innovation ecosystems has become popular during the last 15 years, leading to a debate regarding its relevance and conceptual rigor, not the least in this journal. The purpose of this article is to review received definitions of innovation ecosystems and related concepts and to propose a synthesized definition of an innovation ecosystem. The conceptual analysis identifies an unbalanced focus on complementarities, collaboration, and actors in received definitions, and among other things proposes the additional inclusion of competition, substitutes, and artifacts in conceptualizations of innovation ecosystems, leading to the following definition: An innovation ecosystem is the evolving set of actors, activities, and artifacts, and the institutions and relations, including complementary and substitute relations, that are important for the innovative performance of an actor or a population of actors. This definition is compatible with related conceptualizations of innovation systems and natural ecosystems, and the validity of it is illustrated with three empirical examples of innovation ecosystems.', '2026-07-08 08:39:26');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2800190939', 'political-science', 'A low energy demand scenario for meeting the 1.5 °C target and sustainable development goals without negative emission technologies', 'A low energy demand scenario for meeting the 1.5 °C target and sustainable development goals without negative emission technologies', '2018', 2018, 1137, 1137, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41560-018-0172-6/MediaObjects/41560_2018_172_Fig1_HTML.jpg', 'https://doi.org/10.1038/s41560-018-0172-6', 'repository', 'article', 'Nature Energy', '["Arnulf Grübler","Charlie Wilson","Nuno Bento","Benigna Boza‐Kiss","Volker Krey","David McCollum","Narasimha D. Rao","Keywan Riahi","Joeri Rogelj","Simon De Stercke","Jonathan M. Cullen","Stefan Frank","Oliver Fricko","Fei Guo","Matt Gidden","Peter Havlík","Daniel Huppmann","Gregor Kiesewetter","Peter Rafaj","W. Schoepp","Hugo Valin"]', 'political science', NULL, '2026-07-08 08:39:52');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3095402549', 'political-science', 'The misuse of colour in science communication', 'The accurate representation of data is essential in science communication. However, colour maps that visually distort data through uneven colour gradients or are unreadable to those with…', '2020', 2020, 1133, 1133, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41467-020-19160-7/MediaObjects/41467_2020_19160_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7595127', 'pmc', 'review', 'Nature Communications', '["Fabio Crameri","Grace E. Shephard","Philip J. Heron"]', 'political science', 'The accurate representation of data is essential in science communication. However, colour maps that visually distort data through uneven colour gradients or are unreadable to those with colour-vision deficiency remain prevalent in science. These include, but are not limited to, rainbow-like and red-green colour maps. Here, we present a simple guide for the scientific use of colour. We show how scientifically derived colour maps report true data variations, reduce complexity, and are accessible for people with colour-vision deficiencies. We highlight ways for the scientific community to identify and prevent the misuse of colour in science, and call for a proactive step away from colour misuse among the community, publishers, and the press.', '2026-07-08 08:39:53');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1995814878', 'political-science', 'Identity and a Model of Investment in Applied Linguistics', 'ABSTRACT This article locates Norton''s foundational work on identity and investment within the social turn of applied linguistics. It discusses its historical impetus and theoretical anchors, and it…', '2015', 2015, 1108, 1108, 'https://static.cambridge.org/binary/version/id/urn:cambridge.org:id:binary:20260218092114845-0483:S0267190514000191:S0267190514000191_fig1g.jpeg', 'https://doi.org/10.1017/s0267190514000191', 'repository', 'article', 'Annual Review of Applied Linguistics', '["Ron Darvin","Bonny Norton"]', 'political science', 'ABSTRACT This article locates Norton''s foundational work on identity and investment within the social turn of applied linguistics. It discusses its historical impetus and theoretical anchors, and it illustrates how these ideas have been taken up in recent scholarship. In response to the demands of the new world order, spurred by technology and characterized by mobility, it proposes a comprehensive model of investment, which occurs at the intersection of identity, ideology, and capital. The model recognizes that the spaces in which language acquisition and socialization take place have become increasingly deterritorialized and unbounded, and the systemic patterns of control more invisible. This calls for new questions, analyses, and theories of identity. The model addresses the needs of learners who navigate their way through online and offline contexts and perform identities that have become more fluid and complex. As such, it proposes a more comprehensive and critical examination of the relationship between identity, investment, and language learning. Drawing on two case studies of a female language learner in rural Uganda and a male language learner in urban Canada, the model illustrates how structure and agency, operating across time and space, can accord or refuse learners the power to speak.', '2026-07-08 08:40:33');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2162670720', 'political-science', 'Import Competition and the Great US Employment Sag of the 2000s', 'Even before the Great Recession, US employment growth was unimpressive. Between 2000 and 2007, the economy gave back the considerable employment gains achieved during the 1990s, with a historic…', '2015', 2015, 1099, 1099, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1086/682384.g001', 'https://doi.org/10.1086/682384', 'repository', 'article', 'Journal of Labor Economics', '["Daron Acemoğlu","David Autor","David Dorn","Gordon Hanson","Brendan M. Price"]', 'political science', 'Even before the Great Recession, US employment growth was unimpressive. Between 2000 and 2007, the economy gave back the considerable employment gains achieved during the 1990s, with a historic contraction in manufacturing employment being a prime contributor to the slump. We estimate that import competition from China, which surged after 2000, was a major force behind both recent reductions in US manufacturing employment and—through input-output linkages and other general equilibrium channels—weak overall US job growth. Our central estimates suggest job losses from rising Chinese import competition over 1999–2011 in the range of 2.0–2.4 million.', '2026-07-08 08:40:55');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2923666109', 'political-science', 'Global expansion and redistribution of Aedes-borne virus transmission risk with climate change', 'Forecasting the impacts of climate change on Aedes-borne viruses-especially dengue, chikungunya, and Zika-is a key component of public health preparedness. We apply an empirically parameterized model…', '2019', 2019, 1084, 1084, 'https://journals.plos.org/plosntds/article/figure/image?size=large&id=10.1371/journal.pntd.0007213.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6438455', 'pmc', 'article', 'PLoS neglected tropical diseases', '["Sadie J. Ryan","Colin J. Carlson","Erin A. Mordecai","Leah R. Johnson"]', 'political science', 'Forecasting the impacts of climate change on Aedes-borne viruses-especially dengue, chikungunya, and Zika-is a key component of public health preparedness. We apply an empirically parameterized model of viral transmission by the vectors Aedes aegypti and Ae. albopictus, as a function of temperature, to predict cumulative monthly global transmission risk in current climates, and compare them with projected risk in 2050 and 2080 based on general circulation models (GCMs). Our results show that if mosquito range shifts track optimal temperature ranges for transmission (21.3-34.0°C for Ae. aegypti; 19.9-29.4°C for Ae. albopictus), we can expect poleward shifts in Aedes-borne virus distributions. However, the differing thermal niches of the two vectors produce different patterns of shifts under climate change. More severe climate change scenarios produce larger population exposures to transmission by Ae. aegypti, but not by Ae. albopictus in the most extreme cases. Climate-driven risk of transmission from both mosquitoes will increase substantially, even in the short term, for most of Europe. In contrast, significant reductions in climate suitability are expected for Ae. albopictus, most noticeably in southeast Asia and west Africa. Within the next century, nearly a billion people are threatened with new exposure to virus transmission by both Aedes spp. in the worst-case scenario. As major net losses in year-round transmission risk are predicted for Ae. albopictus, we project a global shift towards more seasonal risk across regions. Many other complicating factors (like mosquito range limits and viral evolution) exist, but overall our results indicate that while climate change will lead to increased net and new exposures to Aedes-borne viruses, the most extreme increases in Ae. albopictus transmission are predicted to occur at intermediate climate change scenarios.', '2026-07-08 08:41:39');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2022350358', 'political-science', 'Exceptional twentieth-century slowdown in Atlantic Ocean overturning circulation', 'Exceptional twentieth-century slowdown in Atlantic Ocean overturning circulation', '2015', 2015, 1083, 1083, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnclimate2554/MediaObjects/41558_2015_Article_BFnclimate2554_Fig1_HTML.jpg', 'https://doi.org/10.1038/nclimate2554', 'repository', 'article', 'Nature Climate Change', '["Stefan Rahmstorf","Jason E. Box","Georg Feulner","Michael Mann","A. L. Robinson","Scott Rutherford","Erik Jan Schaffernicht"]', 'political science', NULL, '2026-07-08 08:41:43');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2775419312', 'political-science', 'Mapping synergies and trade-offs between energy and the Sustainable Development Goals', 'Mapping synergies and trade-offs between energy and the Sustainable Development Goals', '2017', 2017, 1088, 1088, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41560-017-0036-5/MediaObjects/41560_2017_36_Fig1_HTML.jpg', 'https://doi.org/10.1038/s41560-017-0036-5', 'repository', 'article', 'Nature Energy', '["Francesco Fuso Nerini","Julia Tomei","Long Seng To","Iwona Bisaga","Priti Parikh","Mairi J. Black","Aiduan Borrion","Catalina Spataru","Vanesa Castán Broto","Gabrial Anandarajah","Ben Milligan","Yacob Mulugetta"]', 'political science', NULL, '2026-07-08 08:41:44');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3019313322', 'political-science', 'Startups in times of crisis – A rapid response to the COVID-19 pandemic', 'The discovery of the coronavirus (SARS-CoV-2) and the spread of COVID-19 have led many governments to take drastic measures. The lockdown of large parts of society and economic life has come as an…', '2020', 2020, 1086, 1086, 'https://ars.els-cdn.com/content/image/1-s2.0-S2352673420300251-gr1.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7183981', 'pmc', 'article', 'Journal of Business Venturing Insights', '["Andreas Kuckertz","Leif Brändle","Anja Gaudig","Sebastian Hinderer","Carlos Arturo Morales Reyes","Alicia Prochotta","Kathrin M. Steinbrink","Elisabeth S.C. Berger"]', 'political science', 'The discovery of the coronavirus (SARS-CoV-2) and the spread of COVID-19 have led many governments to take drastic measures. The lockdown of large parts of society and economic life has come as an exogenous shock to many economic actors, not least innovative startups. This rapid response research combines a qualitative research design informed by entrepreneurial ecosystem actors with an analysis of policy measures called for, announced, and reportedly implemented in the international press. Interviews from an entrepreneurial ecosystem offer a first-hand account of the adversity startups face during a crisis and how by utilizing bricolage responses they cope, and the analysis of policy measures can serve as an inspiration to design support initiatives to protect startups from the consequences of the current lockdown and to alleviate the effects of future crises. The lockdown measures as a response to the spread of the new coronavirus threaten the existence of many innovative startups. Our rapid response research first illustrates the challenges entrepreneurs face as a consequence of the crisis. Second, we illustrate how entrepreneurs are dealing with the effects of the crisis and what they are doing to protect their ventures. Finally, we present measures that could be utilized by policymakers to assist entrepreneurs facing challenges. The research conducted suggests that while startups are successfully leveraging their available resources as a first response to the crisis, their growth and innovation potential are at risk. Therefore, policy measures should not only provide first aid to startups by alleviating the pressure caused by constrained cashflow, but also involve long-term measures embedded in and supported by the wider entrepreneurial ecosystem to ensure rapid recovery and growth.', '2026-07-08 08:41:45');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1709815505', 'history', 'The MEME Suite', 'The MEME Suite is a powerful, integrated set of web-based tools for studying sequence motifs in proteins, DNA and RNA. Such motifs encode many biological functions, and their detection and…', '2015', 2015, 5513, 5513, 'https://cdn.ncbi.nlm.nih.gov/pmc/blobs/7768/4489269/b81bc1bd0348/gkv416fig1.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4489269', 'pmc', 'article', 'Nucleic Acids Research', '["Timothy L. Bailey","James Johnson","Charles E. Grant","William Stafford Noble"]', 'history', 'The MEME Suite is a powerful, integrated set of web-based tools for studying sequence motifs in proteins, DNA and RNA. Such motifs encode many biological functions, and their detection and characterization is important in the study of molecular interactions in the cell, including the regulation of gene expression. Since the previous description of the MEME Suite in the 2009 Nucleic Acids Research Web Server Issue, we have added six new tools. Here we describe the capabilities of all the tools within the suite, give advice on their best use and provide several case studies to illustrate how to combine the results of various MEME Suite tools for successful motif-based analyses. The MEME Suite is freely available for academic use at http://meme-suite.org, and source code is also available for download and local installation.', '2026-07-08 08:41:49');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2916252188', 'history', 'Pathways for practical high-energy long-cycling lithium metal batteries', 'Pathways for practical high-energy long-cycling lithium metal batteries', '2019', 2019, 3365, 3365, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41560-019-0338-x/MediaObjects/41560_2019_338_Fig1_HTML.png', 'https://doi.org/10.1038/s41560-019-0338-x', 'repository', 'article', 'Nature Energy', '["Jun Liu","Zhenan Bao","Yi Cui","Eric J. Dufek","John B. Goodenough","Peter G. Khalifah","Qiuyan Li","Bor Yann Liaw","Ping Liu","Arumugam Manthiram","Ying Shirley Meng","Venkat R. Subramanian","Michael F. Toney","Vilayanur Viswanathan","M. Stanley Whittingham","Jie Xiao","Wu Xu","Jihui Yang","Xiao‐Qing Yang","Ji‐Guang Zhang"]', 'history', NULL, '2026-07-08 08:42:04');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2036479846', 'history', 'Defining the Anthropocene', 'Defining the Anthropocene', '2015', 2015, 3313, 3313, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature14258/MediaObjects/41586_2015_Article_BFnature14258_Fig1_HTML.jpg', 'https://pubmed.ncbi.nlm.nih.gov/25762280', 'repository', 'article', 'Nature', '["Simon L. Lewis","Mark Maslin"]', 'history', NULL, '2026-07-08 08:42:04');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2611622996', 'history', 'Oxygen Release and Its Effect on the Cycling Stability of LiNi<sub>x</sub>Mn<sub>y</sub>Co<sub>z</sub>O<sub>2</sub>(NMC) Cathode Materials for Li-Ion Batteries', 'Layered LiNixMnyCozO2 (NMC) is a widely used class of cathode materials with LiNi1/3Mn1/3Co1/3O2 (NMC111) being the most common representative. However, Ni-rich NMCs are more and more in the focus of…', '2017', 2017, 1293, 1293, 'https://content.cld.iop.org/journals/1945-7111/164/7/A1361/revision1/A1361fig1.jpeg', 'https://doi.org/10.1149/2.0021707jes', 'repository', 'article', 'Journal of The Electrochemical Society', '["Roland Jung","Michael Metzger","Filippo Maglia","Christoph Stinner","Hubert A. Gasteiger"]', 'history', 'Layered LiNixMnyCozO2 (NMC) is a widely used class of cathode materials with LiNi1/3Mn1/3Co1/3O2 (NMC111) being the most common representative. However, Ni-rich NMCs are more and more in the focus of current research due to their higher specific capacity and energy. In this work we will compare LiNi1/3Mn1/3Co1/3O2 (NMC111), LiNi0.6Mn0.2Co0.2O2 (NMC622), and LiNi0.8Mn0.1Co0.1O2 (NMC811) with respect to their cycling stability in NMC-graphite full-cells at different end-of-charge potentials. It will be shown that stable cycling is possible up to 4.4 V for NMC111 and NMC622 and only up to 4.0 V for NMC811. At higher potentials, significant capacity fading was observed, which was traced back to an increase in the polarization of the NMC electrode, contrary to the nearly constant polarization of the graphite electrode. Furthermore, we show that the increase in the polarization occurs when the NMC materials are cycled up to a high-voltage feature in the dq/dV plot, which occurs at ∼4.7 V vs. Li/Li+ for NMC111 and NMC622 and at ∼4.3 V vs. Li/Li+ for NMC811. For the latter material, this feature corresponds to the H2 → H3 phase transition. Contrary to the common understanding that the electrochemical oxidation of carbonate electrolytes causes the CO2 and CO evolution at potentials above 4.7 V vs. Li/Li+, we believe that the observed CO2 and CO are mainly due to the chemical reaction of reactive lattice oxygen with the electrolyte. This hypothesis is based on gas analysis using On-line Electrochemical Mass Spectrometry (OEMS), by which we prove that all three materials release oxygen from the particle surface and that the oxygen evolution coincides with the onset of CO2 and CO evolution. Interestingly, the onsets of oxygen evolution for the different NMCs correlate well with the high-voltage redox feature at ∼4.7 V vs. Li/Li+ for NMC111 and NMC622 as well as at ∼4.3 V vs. Li/Li+ for NMC811. To support this hypothesis, we show that no CO2 or CO is evolved for the LiNi0.43Mn1.57O4 (LNMO) spinel up to 5 V vs. Li/Li+, consistent with the absence of oxygen release. Lastly, we demonstrate by the use of 13C labeled conductive carbon that it is the electrolyte rather than the conductive carbon which is oxidized by the released lattice oxygen. Taking these findings into consideration, a mechanism is proposed for the reaction of released lattice oxygen with ethylene carbonate yielding CO2, CO, and H2O.', '2026-07-08 08:43:23');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2895330846', 'history', 'Promoting novelty, rigor, and style in energy social science: Towards codes of practice for appropriate methods and research design', 'A series of weaknesses in creativity, research design, and quality of writing continue to handicap energy social science. Many studies ask uninteresting research questions, make only marginal…', '2018', 2018, 1152, 1152, 'https://ars.els-cdn.com/content/image/1-s2.0-S2214629618307230-gr1.jpg', 'https://doi.org/10.1016/j.erss.2018.07.007', 'repository', 'article', 'Energy Research & Social Science', '["Benjamin K. Sovacool","Jonn Axsen","Steve Sorrell"]', 'history', 'A series of weaknesses in creativity, research design, and quality of writing continue to handicap energy social science. Many studies ask uninteresting research questions, make only marginal contributions, and lack innovative methods or application to theory. Many studies also have no explicit research design, lack rigor, or suffer from mangled structure and poor quality of writing. To help remedy these shortcomings, this Review offers suggestions for how to construct research questions; thoughtfully engage with concepts; state objectives; and appropriately select research methods. Then, the Review offers suggestions for enhancing theoretical, methodological, and empirical novelty. In terms of rigor, codes of practice are presented across seven method categories: experiments, literature reviews, data collection, data analysis, quantitative energy modeling, qualitative analysis, and case studies. We also recommend that researchers beware of hierarchies of evidence utilized in some disciplines, and that researchers place more emphasis on balance and appropriateness in research design. In terms of style, we offer tips regarding macro and microstructure and analysis, as well as coherent writing. Our hope is that this Review will inspire more interesting, robust, multi-method, comparative, interdisciplinary and impactful research that will accelerate the contribution that energy social science can make to both theory and practice.', '2026-07-08 08:43:37');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2971826371', 'history', 'Natural Fibers as Sustainable and Renewable Resource for Development of Eco-Friendly Composites: A Comprehensive Review', 'The increase in awareness of the damage caused by synthetic materials on the environment has led to the development of eco-friendly materials. The researchers have shown a lot of interest in…', '2019', 2019, 998, 998, 'https://www.frontiersin.org/files/Articles/481024/fmats-06-00226-HTML/image_m/fmats-06-00226-g001.jpg', 'https://doi.org/10.3389/fmats.2019.00226', 'repository', 'review', 'Frontiers in Materials', '["Yashas Gowda Thyavihalli Girijappa","Sanjay Mavinkere Rangappa","Jyotishkumar Parameswaranpillai","Suchart Siengchin"]', 'history', 'The increase in awareness of the damage caused by synthetic materials on the environment has led to the development of eco-friendly materials. The researchers have shown a lot of interest in developing such materials which can replace the synthetic materials. As a result, there is an increase in demand for commercial use of the natural fiber-based composites in recent years for various industrial sectors. Natural fibers are sustainable materials which are easily available in nature and have advantages like low-cost, lightweight, renewability, biodegradability and high specific properties. The sustainability of the natural fiber-based composite materials has led to upsurge its applications in various manufacturing sectors. In this paper, we have reviewed the different sources of natural fibers, their properties, modification of natural fibers, the effect of treatments on natural fibers, etc. We also summarize the major applications of natural fibers and their effective use as reinforcement for polymer composite materials.', '2026-07-08 08:44:19');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2754797405', 'history', 'Quantum computational supremacy', 'Quantum computational supremacy', '2017', 2017, 839, 839, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature23458/MediaObjects/41586_2017_Article_BFnature23458_Fig1_HTML.jpg', 'http://arxiv.org/abs/1809.07442', 'arxiv', 'article', 'Nature', '["Aram W. Harrow","Ashley Montanaro"]', 'history', NULL, '2026-07-08 08:45:17');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2943642024', 'history', 'The contribution of washing processes of synthetic clothes to microplastic pollution', 'Microplastic pollution caused by washing processes of synthetic textiles has recently been assessed as the main source of primary microplastics in the oceans. Therefore, understanding the effective…', '2019', 2019, 807, 807, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41598-019-43023-x/MediaObjects/41598_2019_43023_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6488573', 'pmc', 'article', 'Scientific Reports', '["Francesca De Falco","Emilia Di Pace","Mariacristina Cocca","Maurizio Avella"]', 'history', 'Microplastic pollution caused by washing processes of synthetic textiles has recently been assessed as the main source of primary microplastics in the oceans. Therefore, understanding the effective contribution of the washing process of synthetic clothes to this environmental problem, is of great importance. In this study, wash trials at real scale were performed on commercial clothes by using a household washing machine in order to gain reliable data about the release of microplastics, and to identify possible influences of textile characteristics on the release. The wastewater was collected and filtered through subsequent filters with decreasing porosity, and the amount and dimensions of microfibres were determined. Microfibre release was analysed in relation to the nature and characteristics of the washed clothes. Results showed that microfibres released during washing range from 124 to 308 mg for kg of washed fabric depending from the type of washed garment that corresponds to a number of microfibres ranging from 640,000 to 1,500,000. Some textile characteristics, such as the type of fibres constituting the yarns and their twist, influenced the release of microfibres during washing. A great amount of microfibres of cellulosic nature was also released during washing of clothes made with a blend of polyester/cellulose. Finally the most abundant fraction of microfibres shed was retained by filters with pore size of 60 µm, presenting an average length of 360-660 μm and an average diameter of 12-16 μm, indicating dimensions that could pass through wastewater treatment plants and pose a threat for marine organisms.', '2026-07-08 08:45:17');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4389132715', 'history', 'An autonomous laboratory for the accelerated synthesis of inorganic materials', ', we introduce the A-Lab, an autonomous laboratory for the solid-state synthesis of inorganic powders. This platform uses computations, historical data from the literature, machine learning (ML) and…', '2023', 2023, 821, 821, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-023-06734-w/MediaObjects/41586_2023_6734_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/10700133', 'pmc', 'article', 'Nature', '["Nathan J. Szymanski","Bernardus Rendy","Yuxing Fei","Rishi E. Kumar","Tanjin He","David Milsted","Matthew J. McDermott","Max C. Gallant","Ekin D. Cubuk","Amil Merchant","Haegyeom Kim","Anubhav Jain","Christopher J. Bartel","Kristin A. Persson","Yan Zeng","Gerbrand Ceder"]', 'history', ', we introduce the A-Lab, an autonomous laboratory for the solid-state synthesis of inorganic powders. This platform uses computations, historical data from the literature, machine learning (ML) and active learning to plan and interpret the outcomes of experiments performed using robotics. Over 17 days of continuous operation, the A-Lab realized 41 novel compounds from a set of 58 targets including a variety of oxides and phosphates that were identified using large-scale ab initio phase-stability data from the Materials Project and Google DeepMind. Synthesis recipes were proposed by natural-language models trained on the literature and optimized using an active-learning approach grounded in thermodynamics. Analysis of the failed syntheses provides direct and actionable suggestions to improve current techniques for materials screening and synthesis design. The high success rate demonstrates the effectiveness of artificial-intelligence-driven platforms for autonomous materials discovery and motivates further integration of computations, historical knowledge and robotics.', '2026-07-08 08:45:18');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2740049013', 'history', 'Towards a renaissance in international business research? Big questions, grand challenges, and the future of IB scholarship', 'Towards a renaissance in international business research? Big questions, grand challenges, and the future of IB scholarship', '2017', 2017, 784, 784, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1057%2Fs41267-020-00374-2/MediaObjects/41267_2020_374_Fig1_HTML.png', 'https://doi.org/10.1057/s41267-017-0102-z', 'repository', 'article', 'Journal of International Business Studies', '["Peter J. Buckley","Jonathan P. Doh","Mirko H. Benischke"]', 'history', NULL, '2026-07-08 08:45:30');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W69413871', 'history', 'Cilia and Mucociliary Clearance', 'Mucociliary clearance (MCC) is the primary innate defense mechanism of the lung. The functional components are the protective mucous layer, the airway surface liquid layer, and the cilia on the…', '2016', 2016, 806, 806, 'https://cshperspectives.cshlp.org/adsystem/graphics/7727897393556222/cshperspect/SPCT_web_468x60.gif?ad=50833&adview=true', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5378048', 'pmc', 'review', 'Cold Spring Harbor Perspectives in Biology', '["Ximena M. Bustamante-Marin","Lawrence E. Ostrowski"]', 'history', 'Mucociliary clearance (MCC) is the primary innate defense mechanism of the lung. The functional components are the protective mucous layer, the airway surface liquid layer, and the cilia on the surface of ciliated cells. The cilia are specialized organelles that beat in metachronal waves to propel pathogens and inhaled particles trapped in the mucous layer out of the airways. In health this clearance mechanism is effective, but in patients with primary cilia dyskinesia (PCD) the cilia are abnormal, resulting in deficient MCC and chronic lung disease. This demonstrates the critical importance of the cilia for human health. In this review, we summarize the current knowledge of the components of the MCC apparatus, focusing on the role of cilia in MCC.', '2026-07-08 08:45:33');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3213104004', 'history', 'Chapel Hill Expert Survey trend file, 1999–2019', 'Chapel Hill Expert Survey trend file, 1999–2019', '2021', 2021, 709, 709, 'https://ars.els-cdn.com/content/image/1-s2.0-S0261379421001323-gr1.jpg', 'https://hal.science/hal-03822280', 'repository', 'article', 'Electoral Studies', '["Seth Jolly","Ryan Bakker","Liesbet Hooghe","Gary Marks","Jonathan Polk","Jan Rovný","Marco R. Steenbergen","Milada Anna Vachudová"]', 'history', NULL, '2026-07-08 08:46:12');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2295378318', 'history', 'Differential Susceptibilities of Aedes aegypti and Aedes albopictus from the Americas to Zika Virus', 'BACKGROUND: Since the major outbreak in 2007 in the Yap Island, Zika virus (ZIKV) causing dengue-like syndromes has affected multiple islands of the South Pacific region. In May 2015, the virus was…', '2016', 2016, 643, 643, 'https://journals.plos.org/plosntds/article/figure/image?size=large&id=10.1371/journal.pntd.0004543.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4777396', 'pmc', 'article', 'PLoS neglected tropical diseases', '["Thaís Chouin-Carneiro","Anubis Vega-Rúa","Marie Vazeille","André Yébakima","Romain Girod","Daniella Goindin","Myrielle Dupont‐Rouzeyrol","Ricardo Lourenço‐de‐Oliveira","Anna‐Bella Failloux"]', 'history', 'BACKGROUND: Since the major outbreak in 2007 in the Yap Island, Zika virus (ZIKV) causing dengue-like syndromes has affected multiple islands of the South Pacific region. In May 2015, the virus was detected in Brazil and then spread through South and Central America. In December 2015, ZIKV was detected in French Guiana and Martinique. The aim of the study was to evaluate the vector competence of the mosquito spp. Aedes aegypti and Aedes albopictus from the Caribbean (Martinique, Guadeloupe), North America (southern United States), South America (Brazil, French Guiana) for the currently circulating Asian genotype of ZIKV isolated from a patient in April 2014 in New Caledonia. METHODOLOGY/PRINCIPAL FINDINGS: Mosquitoes were orally exposed to an Asian genotype of ZIKV (NC-2014-5132). Upon exposure, engorged mosquitoes were maintained at 28° ± 1 °C, a 16h:8h light:dark cycle and 80% humidity. 25-30 mosquitoes were processed at 4, 7 and 14 days post-infection (dpi). Mosquito bodies (thorax and abdomen), heads and saliva were analyzed to measure infection, dissemination and transmission, respectively. High infection but lower disseminated infection and transmission rates were observed for both Ae. aegypti and Ae. albopictus. Ae. aegypti populations from Guadeloupe and French Guiana exhibited a higher dissemination of ZIKV than the other Ae. aegypti populations examined. Transmission of ZIKV was observed in both mosquito species at 14 dpi but at a low level. CONCLUSIONS/SIGNIFICANCE: This study suggests that although susceptible to infection, Ae. aegypti and Ae. albopictus were unexpectedly low competent vectors for ZIKV. This may suggest that other factors such as the large naïve population for ZIKV and the high densities of human-biting mosquitoes contribute to the rapid spread of ZIKV during the current outbreak.', '2026-07-08 08:46:55');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2469474955', 'history', 'Why Most Clinical Research Is Not Useful', 'John Ioannidis argues that problem base, context placement, information gain, pragmatism, patient centeredness, value for money, feasibility, and transparency define useful clinical research. He…', '2016', 2016, 641, 641, 'https://journals.plos.org/plosmedicine/article/figure/image?size=large&id=10.1371/journal.pmed.1002049.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4915619', 'pmc', 'article', 'PLoS Medicine', '["John P. A. Ioannidis"]', 'history', 'John Ioannidis argues that problem base, context placement, information gain, pragmatism, patient centeredness, value for money, feasibility, and transparency define useful clinical research. He suggests most clinical research is not useful and reform is overdue.', '2026-07-08 08:46:55');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3023562218', 'history', 'Coronavirus Disease-2019: Knowledge, Attitude, and Practices of Health Care Workers at Makerere University Teaching Hospitals, Uganda', 'Background: Coronavirus diseases- 2019 (COVID-19) is an emerging public health problem threatening the life of over 2.4 million people globally. The present study sought to determine knowledge,…', '2020', 2020, 640, 640, 'https://www.frontiersin.org/files/Articles/550865/fpubh-08-00181-HTML/image_m/fpubh-08-00181-g001.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7204940', 'pmc', 'article', 'Frontiers in Public Health', '["Ronald Olum","Gaudencia Chekwech","Godfrey Wekha","Dianah Rhoda Nassozi","Felix Bongomin"]', 'history', 'Background: Coronavirus diseases- 2019 (COVID-19) is an emerging public health problem threatening the life of over 2.4 million people globally. The present study sought to determine knowledge, attitude and practices (KAP) of health care workers (HCWs) towards COVID-19 in Makerere University Teaching Hospitals (MUTHs) in Uganda. Methods: An online cross sectional, descriptive study was undertaken through WhatsApp Messenger among HCWs in four MUTHs. HCWs aged 18 years and above constituted the study population. KAP towards COVID-19 was assessed by using a pre-validated questionnaire. Bloom’s cut-off of 80% was used to determine sufficient knowledge (≥80%), positive attitude (≥4) and good practice (≥2.4). All analyses were performed using STATA 15.1 and GraphPad Prism 8.3. Results: Of the 581 HCWs approached, 136 (23%) responded. A vast majority of the participants were male (n=87, n=64%), with a median age of 32 (range: 20-66) years. Eighty-four (62%) were medical doctors and 125 (92%) had at least a bachelor''s degree. Overall, 69% (n=94) had sufficient knowledge, 21% (n=29) had positive attitude and 74% (n=101) had good practices towards COVID-19. Factors associated with knowledge were age >40 years (aOR: 0.3; 95%CI: 0.1-1.0; p=0.047) and news media (aOR: 4.8; 95%CI: 1.4-17.0; p=0.015). Factors associated with good practices were age 40 years or more (aOR: 48.4; 95%CI: 3.1-742. 9; p=0.005) and holding a diploma (aOR: 18.4; 95%CI: 1-322.9; p=0.046). Conclusions. Continued professional education is advised among HCWs in Uganda to improve knowledge of HCWs hence averting negative attitudes and promoting positive preventive and therapeutic practices. We recommend follow up studies involving teaching and non-teaching hospitals across the country.', '2026-07-08 08:47:09');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2921224315', 'history', 'A Quarter Century of APOE and Alzheimer’s Disease: Progress to Date and the Path Forward', 'A Quarter Century of APOE and Alzheimer’s Disease: Progress to Date and the Path Forward', '2019', 2019, 579, 579, 'https://ars.els-cdn.com/content/image/1-s2.0-S0896627319300832-gr1.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6407643', 'pmc', 'review', 'Neuron', '["Michaël E. Belloy","Valerio Napolioni","Michael D. Greicius"]', 'history', NULL, '2026-07-08 08:48:13');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4288060992', 'history', 'Climate policy uncertainty and firm-level total factor productivity: Evidence from China', 'Using 2605 Chinese A-share listed companies in the mining, manufacturing, and energy production and supply sectors from 2009 to 2020, we examine the relationship between climate policy uncertainty…', '2022', 2022, 557, 557, 'https://ars.els-cdn.com/content/image/1-s2.0-S0140988322003577-gr1.jpg', 'https://doi.org/10.1016/j.eneco.2022.106209', 'repository', 'article', 'Energy Economics', '["Xiaohang Ren","Xiao Zhang","Cheng Yan","Giray Gözgör"]', 'history', 'Using 2605 Chinese A-share listed companies in the mining, manufacturing, and energy production and supply sectors from 2009 to 2020, we examine the relationship between climate policy uncertainty (CPU) and firm-level total factor productivity (TFP). The main findings are as follows: First, CPU significantly reduces firm-level TFP, with a greater impact on low-productivity firms than on high-productivity firms; second, the negative effect of CPU on firm-level TFP is most pronounced for non-state-owned, labor-intensive, and capital-intensive companies; third, CPU hinders research and development investment and reduces the amount of free cash flow. These results indicate that CPU exerts negative impacts on firm-level TFP mainly via its effects on the capital status of the companies. Our findings remain valid after a series of robustness tests and controlling for endogeneity. The government should introduce forward-looking climate policies to reduce the negative impact of policy uncertainty.', '2026-07-08 08:48:39');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2891605669', 'history', 'A room-temperature sodium–sulfur battery with high capacity and stable cycling performance', 'High-temperature sodium-sulfur batteries operating at 300-350 °C have been commercially applied for large-scale energy storage and conversion. However, the safety concerns greatly inhibit their…', '2018', 2018, 550, 550, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41467-018-06443-3/MediaObjects/41467_2018_6443_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6155237', 'pmc', 'article', 'Nature Communications', '["Xiaofu Xu","Dong Zhou","Xianying Qin","Kui Lin","Feiyu Kang","Baohua Li","Devaraj Shanmukaraj","Teófilo Rojo","Michel Armand","Guoxiu Wang"]', 'history', 'High-temperature sodium-sulfur batteries operating at 300-350 °C have been commercially applied for large-scale energy storage and conversion. However, the safety concerns greatly inhibit their widespread adoption. Herein, we report a room-temperature sodium-sulfur battery with high electrochemical performances and enhanced safety by employing a "cocktail optimized" electrolyte system, containing propylene carbonate and fluoroethylene carbonate as co-solvents, highly concentrated sodium salt, and indium triiodide as an additive. As verified by first-principle calculation and experimental characterization, the fluoroethylene carbonate solvent and high salt concentration not only dramatically reduce the solubility of sodium polysulfides, but also construct a robust solid-electrolyte interface on the sodium anode upon cycling. Indium triiodide as redox mediator simultaneously increases the kinetic transformation of sodium sulfide on the cathode and forms a passivating indium layer on the anode to prevent it from polysulfide corrosion. The as-developed sodium-sulfur batteries deliver high capacity and long cycling stability.', '2026-07-08 08:48:53');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2093626188', 'history', 'A brief history of T cell help to B cells', 'A brief history of T cell help to B cells', '2015', 2015, 548, 548, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnri3803/MediaObjects/41577_2015_Article_BFnri3803_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4414089', 'pmc', 'review', 'Nature reviews. Immunology', '["Shane Crotty"]', 'history', NULL, '2026-07-08 08:48:55');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3160227221', 'history', 'COVID-19 vaccine rumors and conspiracy theories: The need for cognitive inoculation against misinformation to improve vaccine adherence', 'INTRODUCTION: Rumors and conspiracy theories, can contribute to vaccine hesitancy. Monitoring online data related to COVID-19 vaccine candidates can track vaccine misinformation in real-time and…', '2021', 2021, 538, 538, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0251605.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8115834', 'pmc', 'article', 'PLoS ONE', '["Md Saiful Islam","Abu-Hena Mostofa Kamal","Alamgir Kabir","Dorothy L. Southern","Sazzad Hossain Khan","S. M. Murshid Hasan","Tonmoy Sarkar","Shayla Sharmin","Shiuli Das","Tuhin Roy","Md. Golam Dostogir Harun","Abrar Ahmad Chughtai","Nusrat Homaira","Holly Seale"]', 'history', 'INTRODUCTION: Rumors and conspiracy theories, can contribute to vaccine hesitancy. Monitoring online data related to COVID-19 vaccine candidates can track vaccine misinformation in real-time and assist in negating its impact. This study aimed to examine COVID-19 vaccine rumors and conspiracy theories circulating on online platforms, understand their context, and then review interventions to manage this misinformation and increase vaccine acceptance. METHOD: In June 2020, a multi-disciplinary team was formed to review and collect online rumors and conspiracy theories between 31 December 2019-30 November 2020. Sources included Google, Google Fact Check, Facebook, YouTube, Twitter, fact-checking agency websites, and television and newspaper websites. Quantitative data were extracted, entered in an Excel spreadsheet, and analyzed descriptively using the statistical package R version 4.0.3. We conducted a content analysis of the qualitative information from news articles, online reports and blogs and compared with findings from quantitative data. Based on the fact-checking agency ratings, information was categorized as true, false, misleading, or exaggerated. RESULTS: We identified 637 COVID-19 vaccine-related items: 91% were rumors and 9% were conspiracy theories from 52 countries. Of the 578 rumors, 36% were related to vaccine development, availability, and access, 20% related to morbidity and mortality, 8% to safety, efficacy, and acceptance, and the rest were other categories. Of the 637 items, 5% (30/) were true, 83% (528/637) were false, 10% (66/637) were misleading, and 2% (13/637) were exaggerated. CONCLUSIONS: Rumors and conspiracy theories may lead to mistrust contributing to vaccine hesitancy. Tracking COVID-19 vaccine misinformation in real-time and engaging with social media to disseminate correct information could help safeguard the public against misinformation.', '2026-07-08 08:49:02');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3145932765', 'history', 'Microplastic effects on carbon cycling processes in soils', 'Microplastics (MPs), plastic particles <5 mm, are found in environments, including terrestrial ecosystems, planetwide. Most research so far has focused on ecotoxicology, examining effects on…', '2021', 2021, 535, 535, 'https://journals.plos.org/plosbiology/article/figure/image?size=large&id=10.1371/journal.pbio.3001130.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8009438', 'pmc', 'article', 'PLoS Biology', '["Matthias C. Rillig","Eva F. Leifheit","Johannes Lehmann"]', 'history', 'Microplastics (MPs), plastic particles <5 mm, are found in environments, including terrestrial ecosystems, planetwide. Most research so far has focused on ecotoxicology, examining effects on performance of soil biota in controlled settings. As research pivots to a more ecosystem and global change perspective, questions about soil-borne biogeochemical cycles become important. MPs can affect the carbon cycle in numerous ways, for example, by being carbon themselves and by influencing soil microbial processes, plant growth, or litter decomposition. Great uncertainty surrounds nano-sized plastic particles, an expected by-product of further fragmentation of MPs. A major concerted effort is required to understand the pervasive effects of MPs on the functioning of soils and terrestrial ecosystems; importantly, such research needs to capture the immense diversity of these particles in terms of chemistry, aging, size, and shape.', '2026-07-08 08:49:13');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2884339618', 'history', 'Fostering meaningful work in organizations: A multi-level review and integration', 'Fostering meaningful work in organizations: A multi-level review and integration', '2018', 2018, 525, 525, 'https://ars.els-cdn.com/content/image/1-s2.0-S0001879118300800-gr1.jpg', 'https://doi.org/10.1016/j.jvb.2018.07.004', 'repository', 'review', 'Journal of Vocational Behavior', '["Evgenia I. Lysova","Blake A. Allan","Bryan J. Dik","Ryan D. Duffy","Michael F. Steger"]', 'history', NULL, '2026-07-08 08:49:17');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4317629012', 'history', 'Osprey optimization algorithm: A new bio-inspired metaheuristic algorithm for solving engineering optimization problems', 'This paper introduces a new metaheuristic algorithm named the Osprey Optimization Algorithm (OOA), which imitates the behavior of osprey in nature. The fundamental inspiration of OOA is the strategy…', '2023', 2023, 524, 524, 'https://www.frontiersin.org/files/Articles/1126450/fmech-08-1126450-HTML/image_m/fmech-08-1126450-g001.jpg', 'https://doi.org/10.3389/fmech.2022.1126450', 'repository', 'article', 'Frontiers in Mechanical Engineering', '["Mohammad Dehghani","Pavel Trojovský"]', 'history', 'This paper introduces a new metaheuristic algorithm named the Osprey Optimization Algorithm (OOA), which imitates the behavior of osprey in nature. The fundamental inspiration of OOA is the strategy of ospreys when hunting fish from the seas. In this hunting strategy, the osprey hunts the prey after detecting its position, then carries it to a suitable position to eat it. The proposed approach of OOA in two phases of exploration and exploitation is mathematically modeled based on the simulation of the natural behavior of ospreys during the hunting process. The performance of OOA has been evaluated in the optimization of twenty-nine standard benchmark functions from the CEC 2017 test suite. Furthermore, the performance of OOA is compared with the performance of twelve well-known metaheuristic algorithms. The simulation results show that the proposed OOA has provided superior performance compared to competitor algorithms by maintaining the balance between exploration and exploitation. In addition, the implementation of OOA on twenty-two real-world constrained optimization problems from the CEC 2011 test suite shows the high capability of the proposed approach in optimizing real-world applications.', '2026-07-08 08:49:29');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2552895678', 'history', 'Reconstructions of the 1900–2015 Greenland ice sheet surface mass balance using the regional climate MAR model', 'Abstract. With the aim of studying the recent Greenland ice sheet (GrIS) surface mass balance (SMB) decrease relative to the last century, we have forced the regional climate MAR (Modèle…', '2017', 2017, 522, 522, 'https://www.the-cryosphere.net/graphic_egu_claim_logo_blue.png', 'https://doi.org/10.5194/tc-11-1015-2017', 'repository', 'article', 'The cryosphere', '["Xavier Fettweis","Jason E. Box","Cécile Agosta","Charles Amory","Christoph Kittel","Charlotte Lang","D. van As","Horst Machguth","Hubert Gallée"]', 'history', 'Abstract. With the aim of studying the recent Greenland ice sheet (GrIS) surface mass balance (SMB) decrease relative to the last century, we have forced the regional climate MAR (Modèle Atmosphérique Régional; version 3.5.2) model with the ERA-Interim (ECMWF Interim Re-Analysis; 1979–2015), ERA-40 (1958–2001), NCEP–NCARv1 (National Centers for Environmental Prediction–National Center for Atmospheric Research Reanalysis version 1; 1948–2015), NCEP–NCARv2 (1979–2015), JRA-55 (Japanese 55-year Reanalysis; 1958–2014), 20CRv2(c) (Twentieth Century Reanalysis version 2; 1900–2014) and ERA-20C (1900–2010) reanalyses. While all these forcing products are reanalyses that are assumed to represent the same climate, they produce significant differences in the MAR-simulated SMB over their common period. A temperature adjustment of +1 °C (respectively −1 °C) was, for example, needed at the MAR boundaries with ERA-20C (20CRv2) reanalysis, given that ERA-20C (20CRv2) is ∼ 1 °C colder (warmer) than ERA-Interim over Greenland during the period 1980–2010. Comparisons with daily PROMICE (Programme for Monitoring of the Greenland Ice Sheet) near-surface observations support these adjustments. Comparisons with SMB measurements, ice cores and satellite-derived melt extent reveal the most accurate forcing datasets for the simulation of the GrIS SMB to be ERA-Interim and NCEP–NCARv1. However, some biases remain in MAR, suggesting that some improvements are still needed in its cloudiness and radiative schemes as well as in the representation of the bare ice albedo. Results from all MAR simulations indicate that (i) the period 1961–1990, commonly chosen as a stable reference period for Greenland SMB and ice dynamics, is actually a period of anomalously positive SMB (∼ +40 Gt yr−1) compared to 1900–2010; (ii) SMB has decreased significantly after this reference period due to increasing and unprecedented melt reaching the highest rates in the 120-year common period; (iii) before 1960, both ERA-20C and 20CRv2-forced MAR simulations suggest a significant precipitation increase over 1900–1950, but this increase could be the result of an artefact in the reanalyses that are not well-enough constrained by observations during this period and (iv) since the 1980s, snowfall is quite stable after having reached a maximum in the 1970s. These MAR-based SMB and accumulation reconstructions are, however, quite similar to those from Box (2013) after 1930 and confirm that SMB was quite stable from the 1940s to the 1990s. Finally, only the ERA-20C-forced simulation suggests that SMB during the 1920–1930 warm period over Greenland was comparable to the SMB of the 2000s, due to both higher melt and lower precipitation than normal.', '2026-07-08 08:49:29');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2979917723', 'history', 'Responsible Investing: The ESG-Efficient Frontier', 'Responsible Investing: The ESG-Efficient Frontier', '2019', 2019, 478, 478, 'https://ars.els-cdn.com/content/image/1-s2.0-S0304405X20302853-gr1.jpg', 'https://doi.org/10.2139/ssrn.3466417', 'repository', 'article', 'SSRN Electronic Journal', '["Lasse Heje Pedersen","Shaun Fitzgibbons","Łukasz Pomorski"]', 'history', NULL, '2026-07-08 08:50:36');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4232981981', 'history', 'Liquid-based gating mechanism with tunable multiphase selectivity and antifouling behaviour', 'Liquid-based gating mechanism with tunable multiphase selectivity and antifouling behaviour', '2015', 2015, 459, 459, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature14253/MediaObjects/41586_2015_BFnature14253_Fig1_HTML.jpg', 'https://pubmed.ncbi.nlm.nih.gov/25739629', 'repository', 'article', 'Nature', '["Xu Hou","Yuhang Hu","Alison Grinthal","Mughees Khan","Joanna Aizenberg"]', 'history', NULL, '2026-07-08 08:51:00');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3135942249', 'history', 'The first 12 months of COVID-19: a timeline of immunological insights', 'The first 12 months of COVID-19: a timeline of immunological insights', '2021', 2021, 464, 464, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41577-021-00522-1/MediaObjects/41577_2021_522_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7958099', 'pmc', 'review', 'Nature reviews. Immunology', '["Thiago de Amorim Carvalho","Florian Krammer","Akiko Iwasaki"]', 'history', NULL, '2026-07-08 08:51:00');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2782439335', 'history', 'Terminal Pleistocene Alaskan genome reveals first founding population of Native Americans', 'Terminal Pleistocene Alaskan genome reveals first founding population of Native Americans', '2018', 2018, 429, 429, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature25173/MediaObjects/41586_2018_Article_BFnature25173_Fig1_HTML.jpg', 'https://pubmed.ncbi.nlm.nih.gov/29323294', 'repository', 'article', 'Nature', '["J. Víctor Moreno-Mayar","Ben A. Potter","Lasse Vinner","Matthias Steinrücken","Simon Rasmussen","Jonathan Terhorst","Jack Kamm","Anders Albrechtsen","Anna‐Sapfo Malaspinas","Martin Sikora","Joshua D. Reuther","Joel D. Irish","Ripan S. Malhi","Ludovic Orlando","Yun S. Song","Rasmus Nielsen","David J. Meltzer","Eske Willerslev"]', 'history', NULL, '2026-07-08 08:52:16');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4223610593', 'history', 'Natural language processing applied to mental illness detection: a narrative review', 'Mental illness is highly prevalent nowadays, constituting a major cause of distress in people''s life with impact on society''s health and well-being. Mental illness is a complex multi-factorial…', '2022', 2022, 435, 435, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41746-022-00589-7/MediaObjects/41746_2022_589_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8993841', 'pmc', 'review', 'npj Digital Medicine', '["Tianlin Zhang","Annika Marie Schoene","Shaoxiong Ji","Sophia Ananiadou"]', 'history', 'Mental illness is highly prevalent nowadays, constituting a major cause of distress in people''s life with impact on society''s health and well-being. Mental illness is a complex multi-factorial disease associated with individual risk factors and a variety of socioeconomic, clinical associations. In order to capture these complex associations expressed in a wide variety of textual data, including social media posts, interviews, and clinical notes, natural language processing (NLP) methods demonstrate promising improvements to empower proactive mental healthcare and assist early diagnosis. We provide a narrative review of mental illness detection using NLP in the past decade, to understand methods, trends, challenges and future directions. A total of 399 studies from 10,467 records were included. The review reveals that there is an upward trend in mental illness detection NLP research. Deep learning methods receive more attention and perform better than traditional machine learning methods. We also provide some recommendations for future studies, including the development of novel detection methods, deep learning paradigms and interpretable models.', '2026-07-08 08:52:16');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2999375273', 'history', 'A review of experiments in tourism and hospitality', 'A review of experiments in tourism and hospitality', '2020', 2020, 429, 429, 'https://ars.els-cdn.com/content/image/1-s2.0-S0160738320300025-gr1.jpg', 'https://doi.org/10.1016/j.annals.2020.102858', 'repository', 'review', 'Annals of Tourism Research', '["Giampaolo Viglia","Sara Dolničar"]', 'history', NULL, '2026-07-08 08:52:35');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2965291833', 'history', 'Does corporate social responsibility impact firms'' innovation capacity? The indirect link between environmental &amp; social governance implementation and innovation performance', 'Does corporate social responsibility impact firms'' innovation capacity? The indirect link between environmental &amp; social governance implementation and innovation performance', '2019', 2019, 428, 428, 'https://ars.els-cdn.com/content/image/1-s2.0-S014829631930431X-gr1.jpg', 'https://doi.org/10.1016/j.jbusres.2019.07.014', 'repository', 'article', 'Journal of Business Research', '["David C. Broadstock","Roman Matoušek","Martin Meyer","Nickolaos Tzeremes"]', 'history', NULL, '2026-07-08 08:52:35');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2893989659', 'history', 'The pains and gains of microservices: A Systematic grey literature review', 'The pains and gains of microservices: A Systematic grey literature review', '2018', 2018, 419, 419, 'https://ars.els-cdn.com/content/image/1-s2.0-S0164121218302139-gr1.jpg', 'https://doi.org/10.1016/j.jss.2018.09.082', 'repository', 'article', 'Journal of Systems and Software', '["Jacopo Soldani","Damian A. Tamburri","Willem‐Jan van den Heuvel"]', 'history', NULL, '2026-07-08 08:53:02');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2089114538', 'history', 'A technical review of emerging technologies for energy and water efficiency and pollution reduction in the textile industry', 'A technical review of emerging technologies for energy and water efficiency and pollution reduction in the textile industry', '2015', 2015, 412, 412, 'https://ars.els-cdn.com/content/image/1-s2.0-S095965261500205X-gr1.jpg', 'https://doi.org/10.1016/j.jclepro.2015.02.079', 'repository', 'review', 'Journal of Cleaner Production', '["Ali Hasanbeigi","Lynn Price"]', 'history', NULL, '2026-07-08 08:53:17');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3121644920', 'history', 'Hidden power of the Big Three? Passive index funds, re-concentration of corporate ownership, and new financial risk', 'Abstract Since 2008, a massive shift has occurred from active toward passive investment strategies. The passive index fund industry is dominated by BlackRock, Vanguard, and State Street, which we…', '2017', 2017, 410, 410, 'https://static.cambridge.org/binary/version/id/urn:cambridge.org:id:binary:20171222130212149-0549:S1469356917000064:S1469356917000064_fig1g.gif?pub-status=live', 'https://doi.org/10.1017/bap.2017.6', 'repository', 'article', 'Business and Politics', '["Jan Fichtner","Eelke M. Heemskerk","Javier Garcia‐Bernardo"]', 'history', 'Abstract Since 2008, a massive shift has occurred from active toward passive investment strategies. The passive index fund industry is dominated by BlackRock, Vanguard, and State Street, which we call the “Big Three.” We comprehensively map the ownership of the Big Three in the United States and find that together they constitute the largest shareholder in 88 percent of the S&amp;P 500 firms. In contrast to active funds, the Big Three hold relatively illiquid and permanent ownership positions. This has led to opposing views on incentives and possibilities to actively exert shareholder power. Some argue passive investors have little shareholder power because they cannot “exit,” while others point out this gives them stronger incentives to actively influence corporations. Through an analysis of proxy vote records we find that the Big Three do utilize coordinated voting strategies and hence follow a centralized corporate governance strategy. However, they generally vote with management, except at director (re-)elections. Moreover, the Big Three may exert “hidden power” through two channels: First, via private engagements with management of invested companies; and second, because company executives could be prone to internalizing the objectives of the Big Three. We discuss how this development entails new forms of financial risk.', '2026-07-08 08:53:30');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2184907315', 'history', 'Corporate social responsibility and social capital', 'Corporate social responsibility and social capital', '2015', 2015, 400, 400, 'https://ars.els-cdn.com/content/image/1-s2.0-S0378426615002149-gr1.jpg', 'https://doi.org/10.1016/j.jbankfin.2015.08.003', 'repository', 'article', 'Journal of Banking & Finance', '["Anand Jha","James C. Cox"]', 'history', NULL, '2026-07-08 08:54:03');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1947985544', 'history', 'The Effects of Twitter Sentiment on Stock Price Returns', 'Social media are increasingly reflecting and influencing behavior of other complex systems. In this paper we investigate the relations between a well-known micro-blogging platform Twitter and…', '2015', 2015, 392, 392, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0138441.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4577113', 'pmc', 'article', 'PLoS ONE', '["Gabriele Ranco","Darko Aleksovski","Guido Caldarelli","Miha Grćar","Igor Mozetič"]', 'history', 'Social media are increasingly reflecting and influencing behavior of other complex systems. In this paper we investigate the relations between a well-known micro-blogging platform Twitter and financial markets. In particular, we consider, in a period of 15 months, the Twitter volume and sentiment about the 30 stock companies that form the Dow Jones Industrial Average (DJIA) index. We find a relatively low Pearson correlation and Granger causality between the corresponding time series over the entire time period. However, we find a significant dependence between the Twitter sentiment and abnormal returns during the peaks of Twitter volume. This is valid not only for the expected Twitter volume peaks (e.g., quarterly announcements), but also for peaks corresponding to less obvious events. We formalize the procedure by adapting the well-known "event study" from economics and finance to the analysis of Twitter data. The procedure allows to automatically identify events as Twitter volume peaks, to compute the prevailing sentiment (positive or negative) expressed in tweets at these peaks, and finally to apply the "event study" methodology to relate them to stock returns. We show that sentiment polarity of Twitter peaks implies the direction of cumulative abnormal returns. The amount of cumulative abnormal returns is relatively low (about 1-2%), but the dependence is statistically significant for several days after the events.', '2026-07-08 08:54:25');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2552189168', 'history', 'The continuous expansion of citizen participation: a new taxonomy', 'The repertoire of political participation in democratic societies is expanding rapidly and covers such different activities as voting, demonstrating, volunteering, boycotting, blogging, and flash…', '2016', 2016, 387, 387, 'https://static.cambridge.org/binary/version/id/urn:cambridge.org:id:binary:20180116061723704-0027:S1755773916000230:S1755773916000230_fig1g.jpeg', 'https://doi.org/10.1017/s1755773916000230', 'repository', 'article', 'European Political Science Review', '["Yannis Theocharis","Jan W. van Deth"]', 'history', 'The repertoire of political participation in democratic societies is expanding rapidly and covers such different activities as voting, demonstrating, volunteering, boycotting, blogging, and flash mobs. Relying on a new method for conceptualizing forms and modes of participation we show that a large variety of creative, expressive, individualized, and digitally enabled forms of participation can be classified as parts of the repertoire of political participation. Results from an innovative survey with a representative sample of the German population demonstrate that old and new forms are systematically integrated into a multi-dimensional taxonomy covering (1) voting, (2) digitally networked participation, (3) institutionalized participation, (4) protest, (5) civic participation, and (6) consumerist participation. Furthermore, the antecedents of consumerist, civic, and digitally networked participation, are very similar to those of older modes of participation such as protest and institutionalized participation. Whereas creative, expressive, and individualized modes appear to be expansions of protest activities, digitally networked forms clearly establish a new and distinct mode of political participation that fits in the general repertoire of political participation.', '2026-07-08 08:54:46');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4283796538', 'history', 'A detailed map of Higgs boson interactions by the ATLAS experiment ten years after the discovery', 'Abstract The standard model of particle physics 1–4 describes the known fundamental particles and forces that make up our Universe, with the exception of gravity. One of the central features of the…', '2022', 2022, 384, 384, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-022-04893-w/MediaObjects/41586_2022_4893_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/35788192', 'repository', 'article', 'Nature', '["G. Aad","B. Abbott","D. C. Abbott","K. Abeling","S. H. Abidi","A. Aboulhorma","H. Abramowicz","H. Abreu","Y. Abulaiti","A. C. Abusleme Hoffman","B. S. Acharya","B. Achkar","L. Adam","C. Adam Bourdarios","L. Adamczyk","Lukas Adamek","S. V. Addepalli","J. Adelman","A. Adıgüzel","S. Adorni","T. Adye","A. A. Affolder","Y. Afik","M. N. Agaras","J. Agarwala","A. Aggarwal","C. Agheorghiesei","J. A. Aguilar–Saavedra","A. Ahmad","F. Ahmadov","W. S. Ahmed","S. Ahuja","X. Ai","G. Aielli","I. Aizenberg","M. Akbiyik","T. P. A. Åkesson","A. V. Akimov","K. Al Khoury","G. L. Alberghi","J. Albert","P. Albicocco","M. J. Alconada Verzini","S. Alderweireldt","M. Aleksa","I. N. Aleksandrov","C. Alexa","T. Alexopoulos","A. Alfonsi","F. Alfonsi","M. Alhroob","B. Ali","S. Ali","M. Aliev","G. Alimonti","C. Allaire","Benedict Allbrooke","P. P. Allport","A. Aloisio","F. Alonso","C. Alpigiani","Elio Alunno Camelia","M. Alvarez Estevez","M. G. Alviggi","Y. Amaral Coutinho","A. Ambler","C. Amelung","C. G. Ames","D. Amidei","S. P. Amor Dos Santos","S. Amoroso","K. R. Amos","Cherifa Sabrina Amrouche","V. Ananiev","C. Anastopoulos","N. Andari","T. Andeen","J. K. Anders","S. Y. Andrean","Attilio Andreazza","S. Angelidakis","A. Angerami","A. V. Anisenkov","A. Annovi","C. Antel","M. T. Anthony","E. Antipov","M. Antonelli","D. J. A. Antrim","F. Anulli","M. Aoki","J. A. Aparisi Pozo","M. A. Aparo","L. Aperio Bella","C. Appelt","Nordin Aranzabal Barrio","V. Araujo Ferraz","C. Arcangeletti","A. T. H. Arce","E. Arena"]', 'history', 'Abstract The standard model of particle physics 1–4 describes the known fundamental particles and forces that make up our Universe, with the exception of gravity. One of the central features of the standard model is a field that permeates all of space and interacts with fundamental particles 5–9. The quantum excitation of this field, known as the Higgs field, manifests itself as the Higgs boson, the only fundamental particle with no spin. In 2012, a particle with properties consistent with the Higgs boson of the standard model was observed by the ATLAS and CMS experiments at the Large Hadron Collider at CERN 10,11. Since then, more than 30 times as many Higgs bosons have been recorded by the ATLAS experiment, enabling much more precise measurements and new tests of the theory. Here, on the basis of this larger dataset, we combine an unprecedented number of production and decay processes of the Higgs boson to scrutinize its interactions with elementary particles. Interactions with gluons, photons, and W and Z bosons—the carriers of the strong, electromagnetic and weak forces—are studied in detail. Interactions with three third-generation matter particles (bottom ( b ) and top ( t ) quarks, and tau leptons ( τ )) are well measured and indications of interactions with a second-generation particle (muons, μ ) are emerging. These tests reveal that the Higgs boson discovered ten years ago is remarkably consistent with the predictions of the theory and provide stringent constraints on many models of new phenomena beyond the standard model.', '2026-07-08 08:54:56');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3129075539', 'history', 'Ancient DNA analysis', 'Ancient DNA analysis', '2021', 2021, 384, 384, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs43586-020-00011-0/MediaObjects/43586_2020_11_Fig1_HTML.png', 'https://hal.science/hal-03143766', 'repository', 'article', 'Nature Reviews Methods Primers', '["Ludovic Orlando","Robin G. Allaby","Pontus Skoglund","Clio Der Sarkissian","Philipp W. Stockhammer","María C. Ávila‐Arcos","Qiaomei Fu","Johannes Krause","Eske Willerslev","Anne C. Stone","Christina Warinner"]', 'history', NULL, '2026-07-08 08:54:57');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2492165059', 'history', 'Physiological Effects of Nature Therapy: A Review of the Research in Japan', 'Humans have evolved into what they are today after the passage of 6-7 million years. If we define the beginning of urbanization as the rise of the industrial revolution, less than 0.01% of our…', '2016', 2016, 373, 373, 'https://pub.mdpi-res.com/ijerph/ijerph-13-00781/article_deploy/html/images/ijerph-13-00781-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4997467', 'pmc', 'review', 'International Journal of Environmental Research and Public Health', '["Chorong Song","Harumi Ikei","Yoshifumi Miyazaki"]', 'history', 'Humans have evolved into what they are today after the passage of 6-7 million years. If we define the beginning of urbanization as the rise of the industrial revolution, less than 0.01% of our species'' history has been spent in modern surroundings. Humans have spent over 99.99% of their time living in the natural environment. The gap between the natural setting, for which our physiological functions are adapted, and the highly urbanized and artificial setting that we inhabit is a contributing cause of the "stress state" in modern people. In recent years, scientific evidence supporting the physiological effects of relaxation caused by natural stimuli has accumulated. This review aimed to objectively demonstrate the physiological effects of nature therapy. We have reviewed research in Japan related to the following: (1) the physiological effects of nature therapy, including those of forests, urban green space, plants, and wooden material and (2) the analyses of individual differences that arise therein. The search was conducted in the PubMed database using various keywords. We applied our inclusion/exclusion criteria and reviewed 52 articles. Scientific data assessing physiological indicators, such as brain activity, autonomic nervous activity, endocrine activity, and immune activity, are accumulating from field and laboratory experiments. We believe that nature therapy will play an increasingly important role in preventive medicine in the future.', '2026-07-08 08:55:27');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2963846949', 'history', 'Digital Leadership Skills and Associations with Psychological Well-Being', 'Due to increasing digitalisation, today''s working world is changing rapidly and provides managers with new challenges. Digital leadership is an important factor in managing these challenges and has…', '2019', 2019, 364, 364, 'https://pub.mdpi-res.com/ijerph/ijerph-16-02628/article_deploy/html/images/ijerph-16-02628-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6678159', 'pmc', 'article', 'International Journal of Environmental Research and Public Health', '["Sabrina Zeike","Katherine Bradbury","Lara Lindert","Holger Pfaff"]', 'history', 'Due to increasing digitalisation, today''s working world is changing rapidly and provides managers with new challenges. Digital leadership is an important factor in managing these challenges and has become a key concept in the discussion about what kinds of skills managers need for digital transformation. The main research question our study explored was if digital leadership is associated with psychological well-being in upper-level managers. Based on a qualitative pilot study and relevant literature, we developed a new scale for digital leadership in managers. We conducted an online survey with a sample of 368 upper-level managers from a large German ICT-company. Using a stepwise logistic regression analysis, potential effects of digital leadership on psychological well-being (WHO-5) were analysed. Logistic regression analyses showed that better skills in digital leadership were significantly associated with higher well-being. Results also showed that gender, age and managerial experience had no effect in our model. Our study provides a valuable insight into the association between digital leadership and well-being in managers. However, further research is necessary to validate the newly developed scale for digital leadership and to confirm a causal effect in the relationship between digital leadership and well-being.', '2026-07-08 08:56:12');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3123289970', 'history', 'Market mechanisms and funding dynamics in equity crowdfunding', 'Equity crowdfunding is a new form of entrepreneurial finance, in which investors do not receive perks or engage in pre-purchase of the product, but rather participate in the future cash flows of a…', '2017', 2017, 359, 359, 'https://ars.els-cdn.com/content/image/1-s2.0-S0929119916302450-gr1.jpg', 'https://doi.org/10.1016/j.jcorpfin.2017.08.009', 'repository', 'article', 'Journal of Corporate Finance', '["Lars Hornuf","Armin Schwienbacher"]', 'history', 'Equity crowdfunding is a new form of entrepreneurial finance, in which investors do not receive perks or engage in pre-purchase of the product, but rather participate in the future cash flows of a firm. In this paper, we analyze what determines individual investment decisions in this new financial market. One important factor that may influence the behavior of investors is the way the portal allocates securities. We use unique data from four German equity crowdfunding portals to examine how the allocation mechanism affects funding dynamics. In contrast with the crowdfunding campaigns on Kickstarter, on which the typical pattern of project support is U shaped, we find that equity crowdfunding dynamics are L shaped under a first-come, first-served mechanism and U shaped under a second-price auction. The evidence also shows that investors base their decisions on information provided by the entrepreneur in the form of updates as well as by the investment behavior and comments of other crowd investors.', '2026-07-08 08:56:38');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2964102860', 'history', 'Neutrino Oscillations and Non-standard Interactions', 'Current neutrino experiments are measuring the neutrino mixing parameters with an unprecedented accuracy. The upcoming generation of neutrino experiments will be sensitive to subdominant neutrino…', '2018', 2018, 359, 359, 'https://www.frontiersin.org/files/Articles/324394/fphy-06-00010-HTML/image_m/fphy-06-00010-g001.jpg', 'https://doi.org/10.3389/fphy.2018.00010', 'repository', 'article', 'Frontiers in Physics', '["Yasaman Farzan","M. Tórtola"]', 'history', 'Current neutrino experiments are measuring the neutrino mixing parameters with an unprecedented accuracy. The upcoming generation of neutrino experiments will be sensitive to subdominant neutrino oscillation effects that can in principle give information on the yet-unknown neutrino parameters: the Dirac CP-violating phase in the PMNS mixing matrix, the neutrino mass ordering and the octant of 23. Determining the exact values of neutrino mass and mixing parameters is crucial to test various neutrino models and flavor symmetries that are designed to predict these neutrino parameters. In the first part of this review, we summarize the current status of the neutrino oscillation parameter determination. We consider the most recent data from all solar neutrino experiments and the atmospheric neutrino data from Super-Kamiokande, IceCube, and ANTARES. We also implement the data from the reactor neutrino experiments KamLAND, Daya Bay, RENO, and Double Chooz as well as the long baseline neutrino data from MINOS, T2K, and NOA. If in addition to the standard interactions, neutrinos have subdominant yet-unknown Non-Standard Interactions (NSI) with matter fields, extracting the values of these parameters will suffer from new degeneracies and ambiguities. We review such effects and formulate the conditions on the NSI parameters under which the precision measurement of neutrino oscillation parameters can be distorted. Like standard weak interactions, the non-standard interaction can be categorized into two groups: Charged Current (CC) NSI and Neutral Current (NC) NSI. Our focus will be mainly on neutral current NSI because it is possible to build a class of models that give rise to sizeable NC NSI with discernible effects on neutrino oscillation. These models are based on new U(1) gauge symmetry with a gauge boson of mass 10 MeV. The UV complete model should be of course electroweak invariant which in general implies that along with neutrinos, charged fermions also acquire new interactions on which there are strong bounds. We enumerate the bounds that already exist on the electroweak symmetric models and demonstrate that it is possible to build viable models avoiding all these bounds. In the end, we review methods to test these models and suggest approaches to break the degeneracies in deriving neutrino mass parameters caused by NSI.', '2026-07-08 08:56:41');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2950454348', 'history', 'Estimating genetic kin relationships in prehistoric populations', 'Archaeogenomic research has proven to be a valuable tool to trace migrations of historic and prehistoric individuals and groups, whereas relationships within a group or burial site have not been…', '2018', 2018, 357, 357, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0195491.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5912749', 'pmc', 'article', 'PLoS ONE', '["José Manuel Monroy Kuhn","Mattias Jakobsson","Torsten Günther"]', 'history', 'Archaeogenomic research has proven to be a valuable tool to trace migrations of historic and prehistoric individuals and groups, whereas relationships within a group or burial site have not been investigated to a large extent. Knowing the genetic kinship of historic and prehistoric individuals would give important insights into social structures of ancient and historic cultures. Most archaeogenetic research concerning kinship has been restricted to uniparental markers, while studies using genome-wide information were mainly focused on comparisons between populations. Applications which infer the degree of relationship based on modern-day DNA information typically require diploid genotype data. Low concentration of endogenous DNA, fragmentation and other post-mortem damage to ancient DNA (aDNA) makes the application of such tools unfeasible for most archaeological samples. To infer family relationships for degraded samples, we developed the software READ (Relationship Estimation from Ancient DNA). We show that our heuristic approach can successfully infer up to second degree relationships with as little as 0.1x shotgun coverage per genome for pairs of individuals. We uncover previously unknown relationships among prehistoric individuals by applying READ to published aDNA data from several human remains excavated from different cultural contexts. In particular, we find a group of five closely related males from the same Corded Ware culture site in modern-day Germany, suggesting patrilocality, which highlights the possibility to uncover social structures of ancient populations by applying READ to genome-wide aDNA data. READ is publicly available from https://bitbucket.org/tguenther/read.', '2026-07-08 08:56:50');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3198731561', 'history', 'The impact of coronavirus disease 2019 (COVID-19) on healthcare-associated infections in 2020: A summary of data reported to the National Healthcare Safety Network', 'OBJECTIVES: To determine the impact of the coronavirus disease 2019 (COVID-19) pandemic on healthcare-associated infection (HAI) incidence in US hospitals, national- and state-level standardized…', '2021', 2021, 357, 357, 'https://static.cambridge.org/binary/version/id/urn:cambridge.org:id:binary:20220117131914046-0988:S0899823X21003627:S0899823X21003627_fig1.png', 'https://pubmed.ncbi.nlm.nih.gov/34473013', 'repository', 'article', 'Infection Control and Hospital Epidemiology', '["Lindsey M. Weiner","Vaishnavi Pattabiraman","Rebecca Konnor","Prachi Patel","Emily Wong","Sunny Y. Xu","Brittany Smith","Jonathan R. Edwards","Margaret A. Dudeck"]', 'history', 'OBJECTIVES: To determine the impact of the coronavirus disease 2019 (COVID-19) pandemic on healthcare-associated infection (HAI) incidence in US hospitals, national- and state-level standardized infection ratios (SIRs) were calculated for each quarter in 2020 and compared to those from 2019. METHODS: Central-line-associated bloodstream infections (CLABSIs), catheter-associated urinary tract infections (CAUTIs), ventilator-associated events (VAEs), select surgical site infections, and Clostridioides difficile and methicillin-resistant Staphylococcus aureus (MRSA) bacteremia laboratory-identified events reported to the National Healthcare Safety Network for 2019 and 2020 by acute-care hospitals were analyzed. SIRs were calculated for each HAI and quarter by dividing the number of reported infections by the number of predicted infections, calculated using 2015 national baseline data. Percentage changes between 2019 and 2020 SIRs were calculated. Supporting analyses, such as an assessment of device utilization in 2020 compared to 2019, were also performed. RESULTS: Significant increases in the national SIRs for CLABSI, CAUTI, VAE, and MRSA bacteremia were observed in 2020. Changes in the SIR varied by quarter and state. The largest increase was observed for CLABSI, and significant increases in VAE incidence and ventilator utilization were seen across all 4 quarters of 2020. CONCLUSIONS: This report provides a national view of the increases in HAI incidence in 2020. These data highlight the need to return to conventional infection prevention and control practices and build resiliency in these programs to withstand future pandemics.', '2026-07-08 08:56:55');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2558063281', 'history', 'The impact of standards and regulation on innovation in uncertain markets', 'This study analyses the impact of formal standards and regulation on firms’ innovation efficiency, considering different levels of market uncertainty. We argue that formal standards and regulation…', '2016', 2016, 357, 357, 'https://ars.els-cdn.com/content/image/1-s2.0-S0048733316301743-gr1.jpg', 'https://doi.org/10.1016/j.respol.2016.11.003', 'repository', 'article', 'Research Policy', '["Knut Blind","Sören S. Petersen","Cesare Antonio Fabio Riillo"]', 'history', 'This study analyses the impact of formal standards and regulation on firms’ innovation efficiency, considering different levels of market uncertainty. We argue that formal standards and regulation have different effects, depending on the extent of market uncertainty derived from theoretical considerations about information asymmetry and regulatory capture. Our empirical analysis is based on the German Community Innovation Survey (CIS). The results show that formal standards lead to lower innovation efficiency in markets with low uncertainty, while regulations have the opposite effect. In cases of high market uncertainty, we observe that regulation leads to lower innovation efficiency, while formal standards have the reverse effect. Our results have important implications for the future application of both instruments, showing that their benefits heavily depend on the market environment.', '2026-07-08 08:56:56');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2484079420', 'history', 'Measuring emotions during epistemic activities: the Epistemically-Related Emotion Scales', 'Measurement instruments assessing multiple emotions during epistemic activities are largely lacking. We describe the construction and validation of the Epistemically-Related Emotion Scales, which…', '2016', 2016, 356, 356, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1080/02699931.2016.1204989.g001', 'https://pubmed.ncbi.nlm.nih.gov/27448030', 'repository', 'article', 'Cognition & Emotion', '["Reinhard Pekrun","Elisabeth Vogl","Krista R. Muis","Gale M. Sinatra"]', 'history', 'Measurement instruments assessing multiple emotions during epistemic activities are largely lacking. We describe the construction and validation of the Epistemically-Related Emotion Scales, which measure surprise, curiosity, enjoyment, confusion, anxiety, frustration, and boredom occurring during epistemic cognitive activities. The instrument was tested in a multinational study of emotions during learning from conflicting texts (N = 438 university students from the United States, Canada, and Germany). The findings document the reliability, internal validity, and external validity of the instrument. A seven-factor model best fit the data, suggesting that epistemically-related emotions should be conceptualised in terms of discrete emotion categories, and the scales showed metric invariance across the North American and German samples. Furthermore, emotion scores changed over time as a function of conflicting task information and related significantly to perceived task value and use of cognitive and metacognitive learning strategies.', '2026-07-08 08:57:06');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3041699688', 'history', 'Public discourse and sentiment during the COVID 19 pandemic: Using Latent Dirichlet Allocation for topic modeling on Twitter', 'The study aims to understand Twitter users'' discourse and psychological reactions to COVID-19. We use machine learning techniques to analyze about 1.9 million Tweets (written in English) related to…', '2020', 2020, 356, 356, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0239441.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7518625', 'pmc', 'article', 'PLoS ONE', '["Jia Xue","Junxiang Chen","Chen Chen","Chengda Zheng","Sijia Li","Tingshao Zhu"]', 'history', 'The study aims to understand Twitter users'' discourse and psychological reactions to COVID-19. We use machine learning techniques to analyze about 1.9 million Tweets (written in English) related to coronavirus collected from January 23 to March 7, 2020. A total of salient 11 topics are identified and then categorized into ten themes, including "updates about confirmed cases," "COVID-19 related death," "cases outside China (worldwide)," "COVID-19 outbreak in South Korea," "early signs of the outbreak in New York," "Diamond Princess cruise," "economic impact," "Preventive measures," "authorities," and "supply chain." Results do not reveal treatments and symptoms related messages as prevalent topics on Twitter. Sentiment analysis shows that fear for the unknown nature of the coronavirus is dominant in all topics. Implications and limitations of the study are also discussed.', '2026-07-08 08:57:06');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2113220543', 'history', 'Open Labware: 3-D Printing Your Own Lab Equipment', 'The introduction of affordable, consumer-oriented 3-D printers is a milestone in the current "maker movement," which has been heralded as the next industrial revolution. Combined with free and open…', '2015', 2015, 355, 355, 'https://journals.plos.org/plosbiology/article/figure/image?size=large&id=10.1371/journal.pbio.1002086.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4368627', 'pmc', 'article', 'PLoS Biology', '["Tom Baden","André Maia Chagas","Gregory J. Gage","Timothy Marzullo","Lucia L. Prieto-Godino","Thomas Euler"]', 'history', 'The introduction of affordable, consumer-oriented 3-D printers is a milestone in the current "maker movement," which has been heralded as the next industrial revolution. Combined with free and open sharing of detailed design blueprints and accessible development tools, rapid prototypes of complex products can now be assembled in one''s own garage--a game-changer reminiscent of the early days of personal computing. At the same time, 3-D printing has also allowed the scientific and engineering community to build the "little things" that help a lab get up and running much faster and easier than ever before.', '2026-07-08 08:57:06');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2770038424', 'history', 'Navigating through economic policy uncertainty: The role of corporate cash holdings', 'Navigating through economic policy uncertainty: The role of corporate cash holdings', '2020', 2020, 356, 356, 'https://ars.els-cdn.com/content/image/1-s2.0-S0929119920300511-gr1.jpg', 'https://doi.org/10.1016/j.jcorpfin.2020.101607', 'repository', 'article', 'Journal of Corporate Finance', '["Huu Nhan Duong","Justin Hung Nguyen","My Nguyеn","S. Ghon Rhee"]', 'history', NULL, '2026-07-08 08:57:11');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2618096841', 'philosophy', 'Sedentary Behavior Research Network (SBRN) – Terminology Consensus Project process and outcome', 'BACKGROUND: The prominence of sedentary behavior research in health science has grown rapidly. With this growth there is increasing urgency for clear, common and accepted terminology and definitions.…', '2017', 2017, 3783, 3783, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs12966-022-01259-3/MediaObjects/12966_2022_1259_Fig1_HTML.png', 'https://ijbnpa.biomedcentral.com/counter/pdf/10.1186/s12966-017-0525-8', 'repository', 'article', 'International Journal of Behavioral Nutrition and Physical Activity', '["on behalf of SBRN Terminology Consensus Project Participants","Mark S. Tremblay","Salomé Aubert","Joel D. Barnes","Travis J. Saunders","Valerie Carson","Amy E. Latimer‐Cheung","Sébastien Chastin","Teatske M. Altenburg","Mai J. M. Chinapaw"]', 'philosophy', 'BACKGROUND: The prominence of sedentary behavior research in health science has grown rapidly. With this growth there is increasing urgency for clear, common and accepted terminology and definitions. Such standardization is difficult to achieve, especially across multi-disciplinary researchers, practitioners, and industries. The Sedentary Behavior Research Network (SBRN) undertook a Terminology Consensus Project to address this need. METHOD: First, a literature review was completed to identify key terms in sedentary behavior research. These key terms were then reviewed and modified by a Steering Committee formed by SBRN. Next, SBRN members were invited to contribute to this project and interested participants reviewed and provided feedback on the proposed list of terms and draft definitions through an online survey. Finally, a conceptual model and consensus definitions (including caveats and examples for all age groups and functional abilities) were finalized based on the feedback received from the 87 SBRN member participants who responded to the original invitation and survey. RESULTS: Consensus definitions for the terms physical inactivity, stationary behavior, sedentary behavior, standing, screen time, non-screen-based sedentary time, sitting, reclining, lying, sedentary behavior pattern, as well as how the terms bouts, breaks, and interruptions should be used in this context are provided. CONCLUSION: It is hoped that the definitions resulting from this comprehensive, transparent, and broad-based participatory process will result in standardized terminology that is widely supported and adopted, thereby advancing future research, interventions, policies, and practices related to sedentary behaviors.', '2026-07-08 08:58:59');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2784788330', 'philosophy', 'MUMmer4: A fast and versatile genome alignment system', 'The MUMmer system and the genome sequence aligner nucmer included within it are among the most widely used alignment packages in genomics. Since the last major release of MUMmer version 3 in 2004, it…', '2018', 2018, 2809, 2809, 'https://journals.plos.org/ploscompbiol/article/figure/image?size=large&id=10.1371/journal.pcbi.1005944.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5802927', 'pmc', 'article', 'PLoS Computational Biology', '["Guillaume Marçais","Arthur L. Delcher","Adam M. Phillippy","Rachel Coston","Steven L. Salzberg","Aleksey V. Zimin"]', 'philosophy', 'The MUMmer system and the genome sequence aligner nucmer included within it are among the most widely used alignment packages in genomics. Since the last major release of MUMmer version 3 in 2004, it has been applied to many types of problems including aligning whole genome sequences, aligning reads to a reference genome, and comparing different assemblies of the same genome. Despite its broad utility, MUMmer3 has limitations that can make it difficult to use for large genomes and for the very large sequence data sets that are common today. In this paper we describe MUMmer4, a substantially improved version of MUMmer that addresses genome size constraints by changing the 32-bit suffix tree data structure at the core of MUMmer to a 48-bit suffix array, and that offers improved speed through parallel processing of input query sequences. With a theoretical limit on the input size of 141Tbp, MUMmer4 can now work with input sequences of any biologically realistic length. We show that as a result of these enhancements, the nucmer program in MUMmer4 is easily able to handle alignments of large genomes; we illustrate this with an alignment of the human and chimpanzee genomes, which allows us to compute that the two species are 98% identical across 96% of their length. With the enhancements described here, MUMmer4 can also be used to efficiently align reads to reference genomes, although it is less sensitive and accurate than the dedicated read aligners. The nucmer aligner in MUMmer4 can now be called from scripting languages such as Perl, Python and Ruby. These improvements make MUMer4 one the most versatile genome alignment packages available.', '2026-07-08 09:00:07');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3045910546', 'philosophy', 'Expanded encyclopaedias of DNA elements in the human and mouse genomes', 'Abstract The human and mouse genomes contain instructions that specify RNAs and proteins and govern the timing, magnitude, and cellular context of their production. To better delineate these…', '2020', 2020, 2597, 2597, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-020-2493-4/MediaObjects/41586_2020_2493_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7410828', 'pmc', 'article', 'Nature', '["Federico Abascal","Reyes Acosta","Nicholas J. Addleman","Jessika Adrian","Veena Afzal","Rizi Ai","Bronwen Aken","Jennifer A. Akiyama","Omar Al Jammal","Henry Amrhein","Stacie M. Anderson","Gregory R. Andrews","Igor Antoshechkin","Kristin Ardlie","Joel Armstrong","Matthew Astley","Budhaditya Banerjee","Amira Barkal","If H. A. Barnes","Iros Barozzi","Daniel Barrell","Gemma Barson","Daniel J. Bates","Ulugbek K. Baymuradov","Cassandra Bazile","M Beer","Samantha Beik","M. A. Bender","Ruth Bennett","Louis Philip Benoit Bouvrette","B Bernstein","Andrew Berry","Anand Bhaskar","Alexandra Bignell","Steven M. Blue","David M. Bodine","Carles A. Boix","Nathan Boley","Tyler Borrman","Beatrice Borsari","Alan P. Boyle","Laurel A. Brandsmeier","Alessandra Breschi","Emery H. Bresnick","Jason A. Brooks","Michael Buckley","Christopher B. Burge","Rachel Byron","Eileen Cahill","Lingling Cai","Lulu Cao","Mark Carty","Rosa G. Castanon","Andres Castillo","Hassan Chaı̈b","Esther T. Chan","Daniel R. Chee","Sora Chee","Hao Chen","Huaming Chen","Jiayu Chen","Songjie Chen","J. Michael Cherry","Surya B. Chhetri","Jyoti S. Choudhary","Jacqueline Chrast","Dongjun Chung","Declan Clarke","Neal Cody","Candice J. Coppola","Julie Coursen","Anthony D’Ippolito","Stephen Dalton","Cassidy Danyko","Claire Davidson","José Dávila-Velderrain","Carrie Davis","Job Dekker","Alden Deran","Gilberto DeSalvo","Gloria Despacio-Reyes","Colin N. Dewey","Diane E. Dickel","Morgan Diegel","Mark Diekhans","Vishnu Dileep","Bo Ding","Sarah Djebali","Alexander Dobin","Daniel Domı́nguez","Sarah Donaldson","Jörg Drenkow","Timothy R. Dreszer","Yotam Drier","Michael O. Duff","Douglass Dunn","Catharine Eastman","Joseph R. Ecker","Matthew D. Edwards","Nicole El-Ali"]', 'philosophy', 'Abstract The human and mouse genomes contain instructions that specify RNAs and proteins and govern the timing, magnitude, and cellular context of their production. To better delineate these elements, phase III of the Encyclopedia of DNA Elements (ENCODE) Project has expanded analysis of the cell and tissue repertoires of RNA transcription, chromatin structure and modification, DNA methylation, chromatin looping, and occupancy by transcription factors and RNA-binding proteins. Here we summarize these efforts, which have produced 5,992 new experimental datasets, including systematic determinations across mouse fetal development. All data are available through the ENCODE data portal ( https://www.encodeproject.org ), including phase II ENCODE 1 and Roadmap Epigenomics 2 data. We have developed a registry of 926,535 human and 339,815 mouse candidate cis -regulatory elements, covering 7.9 and 3.4% of their respective genomes, by integrating selected datatypes associated with gene regulation, and constructed a web-based server (SCREEN; http://screen.encodeproject.org ) to provide flexible, user-defined access to this resource. Collectively, the ENCODE data and registry provide an expansive resource for the scientific community to build a better understanding of the organization and function of the human and mouse genomes.', '2026-07-08 09:00:32');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2740618823', 'philosophy', 'Targeting autophagy in cancer', 'Targeting autophagy in cancer', '2017', 2017, 2597, 2597, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnrc.2017.53/MediaObjects/41568_2017_Article_BFnrc201753_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5975367', 'pmc', 'review', 'Nature reviews. Cancer', '["Jean M. Mulcahy Levy","Christina G. Towers","Andrew Thorburn"]', 'philosophy', NULL, '2026-07-08 09:00:33');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1160326939', 'philosophy', 'Nanotechnology in the real world: Redeveloping the nanomaterial consumer products inventory', 'To document the marketing and distribution of nano-enabled products into the commercial marketplace, the Woodrow Wilson International Center for Scholars and the Project on Emerging Nanotechnologies…', '2015', 2015, 1755, 1755, 'https://www.beilstein-journals.org/bjnano/content/image/51302491', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4578396', 'pmc', 'article', 'Beilstein Journal of Nanotechnology', '["Marina E. Vance","Todd Kuiken","Eric P. Vejerano","Sean McGinnis","Michael F. Hochella","David Rejeski","Matthew S. Hull"]', 'philosophy', 'To document the marketing and distribution of nano-enabled products into the commercial marketplace, the Woodrow Wilson International Center for Scholars and the Project on Emerging Nanotechnologies created the Nanotechnology Consumer Products Inventory (CPI) in 2005. The objective of this present work is to redevelop the CPI by leading a research effort to increase the usefulness and reliability of this inventory. We created eight new descriptors for consumer products, including information pertaining to the nanomaterials contained in each product. The project was motivated by the recognition that a diverse group of stakeholders from academia, industry, and state/federal government had become highly dependent on the inventory as an important resource and bellweather of the pervasiveness of nanotechnology in society. We interviewed 68 nanotechnology experts to assess key information needs. Their answers guided inventory modifications by providing a clear conceptual framework best suited for user expectations. The revised inventory was released in October 2013. It currently lists 1814 consumer products from 622 companies in 32 countries. The Health and Fitness category contains the most products (762, or 42% of the total). Silver is the most frequently used nanomaterial (435 products, or 24%); however, 49% of the products (889) included in the CPI do not provide the composition of the nanomaterial used in them. About 29% of the CPI (528 products) contain nanomaterials suspended in a variety of liquid media and dermal contact is the most likely exposure scenario from their use. The majority (1288 products, or 71%) of the products do not present enough supporting information to corroborate the claim that nanomaterials are used. The modified CPI has enabled crowdsourcing capabilities, which allow users to suggest edits to any entry and permits researchers to upload new findings ranging from human and environmental exposure data to complete life cycle assessments. There are inherent limitations to this type of database, but these modifications to the inventory addressed the majority of criticisms raised in published literature and in surveys of nanotechnology stakeholders and experts. The development of standardized methods and metrics for nanomaterial characterization and labelling in consumer products can lead to greater understanding between the key stakeholders in nanotechnology, especially consumers, researchers, regulators, and industry.', '2026-07-08 09:03:46');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3021909056', 'philosophy', 'Mechanisms of Multidrug Resistance in Cancer Chemotherapy', 'Cancer is one of the main causes of death worldwide. Despite the significant development of methods of cancer healing during the past decades, chemotherapy still remains the main method for cancer…', '2020', 2020, 1764, 1764, 'https://pub.mdpi-res.com/ijms/ijms-21-03233/article_deploy/html/images/ijms-21-03233-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7247559', 'pmc', 'review', 'International Journal of Molecular Sciences', '["Karol Bukowski","Mateusz Kciuk","Renata Kontek"]', 'philosophy', 'Cancer is one of the main causes of death worldwide. Despite the significant development of methods of cancer healing during the past decades, chemotherapy still remains the main method for cancer treatment. Depending on the mechanism of action, commonly used chemotherapeutic agents can be divided into several classes (antimetabolites, alkylating agents, mitotic spindle inhibitors, topoisomerase inhibitors, and others). Multidrug resistance (MDR) is responsible for over 90% of deaths in cancer patients receiving traditional chemotherapeutics or novel targeted drugs. The mechanisms of MDR include elevated metabolism of xenobiotics, enhanced efflux of drugs, growth factors, increased DNA repair capacity, and genetic factors (gene mutations, amplifications, and epigenetic alterations). Rapidly increasing numbers of biomedical studies are focused on designing chemotherapeutics that are able to evade or reverse MDR. The aim of this review is not only to demonstrate the latest data on the mechanisms of cellular resistance to anticancer agents currently used in clinical treatment but also to present the mechanisms of action of novel potential antitumor drugs which have been designed to overcome these resistance mechanisms. Better understanding of the mechanisms of MDR and targets of novel chemotherapy agents should provide guidance for future research concerning new effective strategies in cancer treatment.', '2026-07-08 09:03:50');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2570634615', 'philosophy', 'Pathology of Neurodegenerative Diseases', 'Neurodegenerative disorders are characterized by progressive loss of selectively vulnerable populations of neurons, which contrasts with select static neuronal loss because of metabolic or toxic…', '2017', 2017, 1631, 1631, 'https://cshperspectives.cshlp.org/adsystem/graphics/8397774367653607/cshperspect/Long_Oligos_anim_480x60.gif?ad=50842&adview=true', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5495060', 'pmc', 'review', 'Cold Spring Harbor Perspectives in Biology', '["Brittany N. Dugger","Dennis W. Dickson"]', 'philosophy', 'Neurodegenerative disorders are characterized by progressive loss of selectively vulnerable populations of neurons, which contrasts with select static neuronal loss because of metabolic or toxic disorders. Neurodegenerative diseases can be classified according to primary clinical features (e.g., dementia, parkinsonism, or motor neuron disease), anatomic distribution of neurodegeneration (e.g., frontotemporal degenerations, extrapyramidal disorders, or spinocerebellar degenerations), or principal molecular abnormality. The most common neurodegenerative disorders are amyloidoses, tauopathies, α-synucleinopathies, and TDP-43 proteinopathies. The protein abnormalities in these disorders have abnormal conformational properties. Growing experimental evidence suggests that abnormal protein conformers may spread from cell to cell along anatomically connected pathways, which may in part explain the specific anatomical patterns observed at autopsy. In this review, we detail the human pathology of select neurodegenerative disorders, focusing on their main protein aggregates.', '2026-07-08 09:04:52');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2605376995', 'philosophy', 'The Stroop Color and Word Test', 'The Stroop Color and Word Test (SCWT) is a neuropsychological test extensively used to assess the ability to inhibit cognitive interference that occurs when the processing of a specific stimulus…', '2017', 2017, 1598, 1598, 'https://www.frontiersin.org/files/Articles/241674/fpsyg-08-00557-HTML/image_m/fpsyg-08-00557-g001.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5388755', 'pmc', 'review', 'Frontiers in Psychology', '["Federica Scarpina","Sofia Tagini"]', 'philosophy', 'The Stroop Color and Word Test (SCWT) is a neuropsychological test extensively used to assess the ability to inhibit cognitive interference that occurs when the processing of a specific stimulus feature impedes the simultaneous processing of a second stimulus attribute, well-known as the Stroop Effect. The aim of the present work is to verify the theoretical adequacy of the various scoring methods used to measure the Stroop effect. We present a systematic review of studies that have provided normative data for the SCWT. We referred to both electronic databases (i.e., PubMed, Scopus, Google Scholar) and citations. Our findings show that while several scoring methods have been reported in literature, none of the reviewed methods enables us to fully assess the Stroop effect. Furthermore, we discuss several normative scoring methods from the Italian panorama as reported in literature. We claim for an alternative scoring method which takes into consideration both speed and accuracy of the response. Finally, we underline the importance of assessing the performance in all Stroop Test conditions (word reading, color naming, named color-word).', '2026-07-08 09:05:14');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2999414134', 'philosophy', 'Principles for knowledge co-production in sustainability research', 'Principles for knowledge co-production in sustainability research', '2020', 2020, 1568, 1568, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41893-019-0448-2/MediaObjects/41893_2019_448_Fig1_HTML.png', 'https://doi.org/10.1038/s41893-019-0448-2', 'repository', 'article', 'Nature Sustainability', '["Albert V. Norström","Christopher Cvitanovic","Marie Löf","Simon West","Carina Wyborn","Patricia Balvanera","Angela Bednarek","Elena M. Bennett","Reinette Biggs","Ariane de Bremond","Bruce Campbell","Josep G. Canadell","Stephen R. Carpenter","Carl Folke","Elizabeth A. Fulton","Owen Gaffney","Stefan Gelcich","Jean‐Baptiste Jouffray","Melissa Leach","Martin Le Tissier","Berta Martín‐López","Elena Louder","Marie‐France Loutre","Alison M. Meadow","Harini Nagendra","Davnah Payne","Garry Peterson","Belinda Reyers","Robert J. Scholes","Chinwe Ifejika Speranza","Marja Spierenburg","Mark Stafford‐Smith","Maria Tengö","Sandra van der Hel","Ingrid van Putten","Henrik Österblom"]', 'philosophy', NULL, '2026-07-08 09:05:17');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3162259891', 'philosophy', 'Genome-wide association study of more than 40,000 bipolar disorder cases provides new insights into the underlying biology', 'Bipolar disorder is a heritable mental illness with complex etiology. We performed a genome-wide association study of 41,917 bipolar disorder cases and 371,549 controls of European ancestry, which…', '2021', 2021, 1599, 1599, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41588-021-00857-4/MediaObjects/41588_2021_857_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8192451', 'pmc', 'review', 'Nature Genetics', '["Niamh Mullins","Andreas J. Forstner","Kevin S. O’Connell","Brandon J. Coombes","Jonathan R. I. Coleman","Zhen Qiao","Thomas D. Als","Tim B. Bigdeli","Sigrid Børte","Julien Bryois","Alexander W. Charney","Ole Kristian Drange","Michael J. Gandal","Saskia P. Hagenaars","Masashi Ikeda","Nolan Kamitaki","Minsoo Kim","Kristi Krebs","Georgia Panagiotaropoulou","Brian M. Schilder","Laura Sloofman","Stacy Steinberg","Vassily Trubetskoy","Bendik S. Winsvold","Hong‐Hee Won","Liliya Abramova","Kristina Adorjan","Esben Agerbo","Mariam Al Eissa","Diego Albani","Ney Alliey‐Rodriguez","Adebayo Anjorin","Verneri Antilla","Anastasia Antoniou","Swapnil Awasthi","Ji Hyun Baek","Marie Bækvad‐Hansen","Nicholas Bass","Michael Bauer","Eva C. Beins","Sarah E. Bergen","Armin Birner","Carsten Bøcker Pedersen","Erlend Bøen","Marco P. Boks","Rosa Bosch","Murielle Brum","Ben Brumpton","Nathalie Brunkhorst-Kanaan","Monika Budde","Jonas Bybjerg‐Grauholm","William Byerley","Murray J. Cairns","Miguel Casas","Pablo Cervantes","Toni‐Kim Clarke","Cristiana Cruceanu","Alfredo B. Cuéllar‐Barboza","Julie M. Cunningham","David Curtis","Piotr M. Czerski","Anders M. Dale","Nina Dalkner","Friederike S. David","Franziska Degenhardt","Srdjan Djurovic","Amanda Dobbyn","Athanassios Douzenis","Torbjørn Elvsåshagen","Valentina Escott‐Price","I. Nicol Ferrier","Alessia Fiorentino","Tatiana Foroud","Liz Forty","Josef Frank","Oleksandr Frei","Nelson B. Freimer","Louise Frisén","Katrin Gade","Julie Garnham","Joel Gelernter","Marianne Giørtz Pedersen","Ian R. Gizer","Scott D. Gordon","Katherine Gordon‐Smith","Tiffany A. Greenwood","Jakob Grove","José Guzmán‐Parra","Kyooseob Ha","Magnús Haraldsson","Martin Hautzinger","Urs Heilbronner","Dennis Hellgren","Stefan Herms","Per Hoffmann","Peter Holmans","Laura M. Huckins","Stéphane Jamain","Jessica Johnson","János Kálmán"]', 'philosophy', 'Bipolar disorder is a heritable mental illness with complex etiology. We performed a genome-wide association study of 41,917 bipolar disorder cases and 371,549 controls of European ancestry, which identified 64 associated genomic loci. Bipolar disorder risk alleles were enriched in genes in synaptic signaling pathways and brain-expressed genes, particularly those with high specificity of expression in neurons of the prefrontal cortex and hippocampus. Significant signal enrichment was found in genes encoding targets of antipsychotics, calcium channel blockers, antiepileptics and anesthetics. Integrating expression quantitative trait locus data implicated 15 genes robustly linked to bipolar disorder via gene expression, encoding druggable targets such as HTR6, MCHR1, DCLK3 and FURIN. Analyses of bipolar disorder subtypes indicated high but imperfect genetic correlation between bipolar disorder type I and II and identified additional associated loci. Together, these results advance our understanding of the biological etiology of bipolar disorder, identify novel therapeutic leads and prioritize genes for functional follow-up studies.', '2026-07-08 09:05:18');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2793972506', 'philosophy', 'Apoptosis: A Target for Anticancer Therapy', 'Apoptosis, the cell''s natural mechanism for death, is a promising target for anticancer therapy. Both the intrinsic and extrinsic pathways use caspases to carry out apoptosis through the cleavage of…', '2018', 2018, 1546, 1546, 'https://pub.mdpi-res.com/ijms/ijms-19-00448/article_deploy/html/images/ijms-19-00448-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5855670', 'pmc', 'review', 'International Journal of Molecular Sciences', '["Claire M. Pfeffer","Amareshwar T.K. Singh"]', 'philosophy', 'Apoptosis, the cell''s natural mechanism for death, is a promising target for anticancer therapy. Both the intrinsic and extrinsic pathways use caspases to carry out apoptosis through the cleavage of hundreds of proteins. In cancer, the apoptotic pathway is typically inhibited through a wide variety of means including overexpression of antiapoptotic proteins and under-expression of proapoptotic proteins. Many of these changes cause intrinsic resistance to the most common anticancer therapy, chemotherapy. Promising new anticancer therapies are plant-derived compounds that exhibit anticancer activity through activating the apoptotic pathway.', '2026-07-08 09:05:36');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4281625438', 'philosophy', 'The International Consensus Classification of Mature Lymphoid Neoplasms: a report from the Clinical Advisory Committee', 'Since the publication of the Revised European-American Classification of Lymphoid Neoplasms in 1994, subsequent updates of the classification of lymphoid neoplasms have been generated through…', '2022', 2022, 1514, 1514, 'https://ars.els-cdn.com/content/image/1-s2.0-S0006497122007339-gr1.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/9479027', 'pmc', 'article', 'Blood', '["Elı́as Campo","Elaine S. Jaffe","James R. Cook","Leticia Quintanilla‐Martínez","Steven H. Swerdlow","Kenneth C. Anderson","Pierre Brousset","Lorenzo Cerroni","Laurence de Leval","Stefan Dirnhofer","Ahmet Doǧan","Andrew L. Feldman","Falko Fend","Jonathan W. Friedberg","Philippe Gaulard","Paolo Ghia","Steven M. Horwitz","Rebecca L. King","Gilles Salles","Jesús F. San Miguel","John F. Seymour","Steven P. Treon","Julie M. Vose","Emanuele Zucca","Ranjana H. Advani","Stephen M. Ansell","Wing-Yan Au","Carlos Barrionuevo","Leif Bergsagel","Wing C. Chan","Jeffrey I. Cohen","Francesco d’Amore","Andrew Davies","Brunangelo Falini","Irene M. Ghobrial","John R. Goodlad","John G. Gribben","Eric D. Hsi","Brad S. Kahl","Won-Seog Kim","Shaji Kumar","Ann S. LaCasce","Camille Laurent","Georg Lenz","John P. Leonard","Michael P. Link","Armando López‐Guillermo","María‐Victoria Mateos","Elizabeth Macintyre","Ari Melnick","Franck Morschhauser","Shigeo Nakamura","Marina Narbaitz","Astrid Pavlovsky","Stefano Pileri","Miguel Á. Piris","Barbara Pro","S. Vincent Rajkumar","Steven T. Rosen","Birgitta Sander","Laurie H. Sehn","Margaret A. Shipp","Sonali M. Smith","Louis M. Staudt","Catherine Thieblemont","Thomas Tousseyn","Wyndham H. Wilson","Tadashi Yoshino","Pier Luigi Zinzani","Martin Dreyling","David W. Scott","Jane N. Winter","Andrew D. Zelenetz"]', 'philosophy', 'Since the publication of the Revised European-American Classification of Lymphoid Neoplasms in 1994, subsequent updates of the classification of lymphoid neoplasms have been generated through iterative international efforts to achieve broad consensus among hematopathologists, geneticists, molecular scientists, and clinicians. Significant progress has recently been made in the characterization of malignancies of the immune system, with many new insights provided by genomic studies. They have led to this proposal. We have followed the same process that was successfully used for the third and fourth editions of the World Health Organization Classification of Hematologic Neoplasms. The definition, recommended studies, and criteria for the diagnosis of many entities have been extensively refined. Some categories considered provisional have now been upgraded to definite entities. Terminology for some diseases has been revised to adapt nomenclature to the current knowledge of their biology, but these modifications have been restricted to well-justified situations. Major findings from recent genomic studies have impacted the conceptual framework and diagnostic criteria for many disease entities. These changes will have an impact on optimal clinical management. The conclusions of this work are summarized in this report as the proposed International Consensus Classification of mature lymphoid, histiocytic, and dendritic cell tumors.', '2026-07-08 09:06:01');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2845591014', 'philosophy', 'GOATOOLS: A Python library for Gene Ontology analyses', 'The biological interpretation of gene lists with interesting shared properties, such as up- or down-regulation in a particular experiment, is typically accomplished using gene ontology enrichment…', '2018', 2018, 1491, 1491, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41598-018-28948-z/MediaObjects/41598_2018_28948_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6052049', 'pmc', 'article', 'Scientific Reports', '["D. V. Klopfenstein","Liangsheng Zhang","Brent S. Pedersen","Fidel Ramírez","Alex Warwick Vesztrocy","Aurélien Naldi","Chris Mungall","Jeffrey M. Yunes","Olga Botvinnik","Mark Weigel","Will Dampier","Christophe Dessimoz","Patrick Flick","Haibao Tang"]', 'philosophy', 'The biological interpretation of gene lists with interesting shared properties, such as up- or down-regulation in a particular experiment, is typically accomplished using gene ontology enrichment analysis tools. Given a list of genes, a gene ontology (GO) enrichment analysis may return hundreds of statistically significant GO results in a "flat" list, which can be challenging to summarize. It can also be difficult to keep pace with rapidly expanding biological knowledge, which often results in daily changes to any of the over 47,000 gene ontologies that describe biological knowledge. GOATOOLS, a Python-based library, makes it more efficient to stay current with the latest ontologies and annotations, perform gene ontology enrichment analyses to determine over- and under-represented terms, and organize results for greater clarity and easier interpretation using a novel GOATOOLS GO grouping method. We performed functional analyses on both stochastic simulation data and real data from a published RNA-seq study to compare the enrichment results from GOATOOLS to two other popular tools: DAVID and GOstats. GOATOOLS is freely available through GitHub: https://github.com/tanghaibao/goatools.', '2026-07-08 09:06:08');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2337082154', 'philosophy', 'Machine learning phases of matter', 'Machine learning phases of matter', '2017', 2017, 1477, 1477, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnphys4035/MediaObjects/41567_2017_Article_BFnphys4035_Fig1_HTML.jpg', 'http://arxiv.org/abs/1605.01735', 'arxiv', 'article', 'Nature Physics', '["Juan Carrasquilla","Roger G. Melko"]', 'philosophy', NULL, '2026-07-08 09:06:09');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2735791018', 'philosophy', 'Determinants of Internet skills, uses and outcomes. A systematic review of the second- and third-level digital divide', 'Determinants of Internet skills, uses and outcomes. A systematic review of the second- and third-level digital divide', '2017', 2017, 1358, 1358, 'https://ars.els-cdn.com/content/image/1-s2.0-S0736585317303192-gr1.jpg', 'https://doi.org/10.1016/j.tele.2017.07.007', 'repository', 'review', 'Telematics and Informatics', '["Anique Scheerder","Alexander Johannes Aloysius Maria van Deursen","Jan van Dijk"]', 'philosophy', NULL, '2026-07-08 09:07:13');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2784805535', 'philosophy', 'Moving in the Anthropocene: Global reductions in terrestrial mammalian movements', 'Animal movement is fundamental for ecosystem functioning and species survival, yet the effects of the anthropogenic footprint on animal movements have not been estimated across species. Using a…', '2018', 2018, 1291, 1291, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1126/science.aam9712.g001', 'https://pubmed.ncbi.nlm.nih.gov/29371471', 'repository', 'article', 'Science', '["Marlee A. Tucker","Katrin Böhning‐Gaese","William F. Fagan","John M. Fryxell","Bram Van Moorter","Susan C. Alberts","Abdullahi H. Ali","Andrew M. Allen","Nina Attias","Tal Avgar","Hattie L. A. Bartlam‐Brooks","Buuveibaatar Bayarbaatar","Jerrold L. Belant","Alessandra Bertassoni","Dean E. Beyer","Laura R. Bidner","Floris M. van Beest","Stephen Blake","Niels Blaum","Chloe Bracis","Danielle Brown","P J Nico de Bruyn","Francesca Cagnacci","Justin M. Calabrese","Constança Camilo-Alves","Simon Chamaillé‐Jammes","André Chiaradia","Sarah C. Davidson","Todd E. Dennis","Stephen DeStefano","Duane R. Diefenbach","Iain Douglas‐Hamilton","Julian Fennessy","Claudia Fichtel","Wolfgang Fiedler","Christina Fischer","Ilya R. Fischhoff","Christen H. Fleming","Adam T. Ford","Susanne A. Fritz","Benedikt Gehr","Jacob R. Goheen","Eliezer Gurarie","Mark Hebblewhite","Marco Heurich","A. J. Mark Hewison","Christian Hof","Edward Hurme","Lynne A. Isbell","René Janssen","Florian Jeltsch","Petra Kaczensky","Adam Kane","Peter M. Kappeler","Matthew J. Kauffman","Roland Kays","Duncan M. Kimuyu","Flávia Koch","Bart Kranstauber","Scott LaPoint","Peter Leimgruber","John D. C. Linnell","Pascual López‐López","A. Catherine Markham","Jenny Mattisson","Emília Patrícia Medici","Ugo Mellone","Evelyn H. Merrill","Guilherme Mourão","Ronaldo Gonçalves Morato","Nicolas Morellet","Thomas A. Morrison","Samuel L. Díaz‐Muñoz","Atle Mysterud","Nandintsetseg Dejid","Ran Nathan","Aidin Niamir","John Oddén","Robert B. O’Hara","Luiz Gustavo Rodrigues Oliveira‐Santos","Kirk A. Olson","Bruce D. Patterson","Rogério Cunha de Paula","Luca Pedrotti","Björn Reineking","Martin Rimmler","Tracey L. Rogers","Christer M. Rolandsen","Christopher S. Rosenberry","Daniel I. Rubenstein","Kamran Safi","Sonia Saı̈d","Nir Sapir","Hall Sawyer","Niels Martin Schmidt","Nuria Selva","Agnieszka Sergiel","Enkhtuvshin Shiilegdamba","João Paulo Silva","Navinder J. Singh"]', 'philosophy', 'Animal movement is fundamental for ecosystem functioning and species survival, yet the effects of the anthropogenic footprint on animal movements have not been estimated across species. Using a unique GPS-tracking database of 803 individuals across 57 species, we found that movements of mammals in areas with a comparatively high human footprint were on average one-half to one-third the extent of their movements in areas with a low human footprint. We attribute this reduction to behavioral changes of individual animals and to the exclusion of species with long-range movements from areas with higher human impact. Global loss of vagility alters a key ecological trait of animals that affects not only population persistence but also ecosystem processes such as predator-prey interactions, nutrient cycling, and disease transmission.', '2026-07-08 09:07:50');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2523675164', 'philosophy', 'The inefficiency of Bitcoin', 'The inefficiency of Bitcoin', '2016', 2016, 1223, 1223, 'https://ars.els-cdn.com/content/image/1-s2.0-S0165176516303640-gr1.jpg', 'https://doi.org/10.1016/j.econlet.2016.09.019', 'repository', 'article', 'Economics Letters', '["Andrew Urquhart"]', 'philosophy', NULL, '2026-07-08 09:09:08');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2790123573', 'philosophy', 'Urban Green Space and Its Impact on Human Health', 'Background: Over half of the world’s population now lives in urban areas, and this proportion is expected to increase. While there have been numerous reviews of empirical studies on the link between…', '2018', 2018, 1145, 1145, 'https://pub.mdpi-res.com/ijerph/ijerph-15-00445/article_deploy/html/images/ijerph-15-00445-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5876990', 'pmc', 'review', 'International Journal of Environmental Research and Public Health', '["Michelle C. Kondo","Jaime Fluehr","Thomas P. McKeon","Charles C. Branas"]', 'philosophy', 'Background: Over half of the world’s population now lives in urban areas, and this proportion is expected to increase. While there have been numerous reviews of empirical studies on the link between nature and human health, very few have focused on the urban context, and most have examined almost exclusively cross-sectional research. This review is a first step toward assessing the possibility of causal relationships between nature and health in urban settings. Methods: Through systematic review of published literature, we explored the association between urban green space and human health. Results: We found consistent negative association between urban green space exposure and mortality, heart rate, and violence, and positive association with attention, mood, and physical activity. Results were mixed, or no association was found, in studies of urban green space exposure and general health, weight status, depression, and stress (via cortisol concentration). The number of studies was too low to generalize about birth outcomes, blood pressure, heart rate variability, cancer, diabetes, or respiratory symptoms. Conclusions: More studies using rigorous study design are needed to make generalizations, and meta-analyses, of these and other health outcomes possible. These findings may assist urban managers, organizations, and communities in their efforts to increase new or preserve existing green space.', '2026-07-08 09:10:33');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2297152540', 'philosophy', 'A new metric of absolute percentage error for intermittent demand forecasts', 'The mean absolute percentage error (MAPE) is one of the most widely used measures of forecast accuracy, due to its advantages of scale-independency and interpretability. However, MAPE has the…', '2016', 2016, 1114, 1114, 'https://ars.els-cdn.com/content/image/1-s2.0-S0169207016000121-gr1.jpg', 'https://doi.org/10.1016/j.ijforecast.2015.12.003', 'repository', 'article', 'International Journal of Forecasting', '["Sung‐Il Kim","Heeyoung Kim"]', 'philosophy', 'The mean absolute percentage error (MAPE) is one of the most widely used measures of forecast accuracy, due to its advantages of scale-independency and interpretability. However, MAPE has the significant disadvantage that it produces infinite or undefined values for zero or close-to-zero actual values. In order to address this issue in MAPE, we propose a new measure of forecast accuracy called the mean arctangent absolute percentage error (MAAPE). MAAPE has been developed through looking at MAPE from a different angle. In essence, MAAPE is a slope as an angle, while MAPE is a slope as a ratio, considering a triangle with adjacent and opposite sides that are equal to an actual value and the difference between the actual and forecast values, respectively. MAAPE inherently preserves the philosophy of MAPE, overcoming the problem of division by zero by using bounded influences for outliers in a fundamental manner through considering the ratio as an angle instead of a slope. The theoretical properties of MAAPE are investigated, and the practical advantages are demonstrated using both simulated and real-life data.', '2026-07-08 09:11:20');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3135555326', 'philosophy', 'Plant- or microbial-derived? A review on the molecular composition of stabilized soil organic matter', 'Plant- or microbial-derived? A review on the molecular composition of stabilized soil organic matter', '2021', 2021, 1104, 1104, 'https://ars.els-cdn.com/content/image/1-s2.0-S0038071721000614-fx1.jpg', 'https://doi.org/10.1016/j.soilbio.2021.108189', 'repository', 'review', 'Soil Biology and Biochemistry', '["Gerrit Angst","Kevin E. Mueller","Klaas G.J. Nierop","Myrna J. Simpson"]', 'philosophy', NULL, '2026-07-08 09:11:32');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2953641512', 'philosophy', 'Unsupervised word embeddings capture latent knowledge from materials science literature', 'Unsupervised word embeddings capture latent knowledge from materials science literature', '2019', 2019, 1100, 1100, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-019-1335-8/MediaObjects/41586_2019_1335_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/31270483', 'repository', 'article', 'Nature', '["Vahe Tshitoyan","John Dagdelen","Leigh Weston","Alexander Dunn","Ziqin Rong","Olga Kononova","Kristin A. Persson","Gerbrand Ceder","Anubhav Jain"]', 'philosophy', NULL, '2026-07-08 09:11:32');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3197290161', 'philosophy', 'A genome-wide association study with 1,126,563 individuals identifies new risk loci for Alzheimer’s disease', 'Late-onset Alzheimer''s disease is a prevalent age-related polygenic disease that accounts for 50-70% of dementia cases. Currently, only a fraction of the genetic variants underlying Alzheimer''s…', '2021', 2021, 1097, 1097, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41588-021-00921-z/MediaObjects/41588_2021_921_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/10243600', 'pmc', 'article', 'Nature Genetics', '["Douglas P. Wightman","Iris E. Jansen","Jeanne E. Savage","Alexey Shadrin","Shahram Bahrami","Dominic Holland","Arvid Rongve","Sigrid Børte","Bendik S. Winsvold","Ole Kristian Drange","Amy E. Martinsen","Anne Heidi Skogholt","Cristen J. Willer","Geir Bråthen","Ingunn Bosnes","Jonas B. Nielsen","Lars G. Fritsche","Laurent F. Thomas","Linda M. Pedersen","Maiken E. Gabrielsen","Marianne Bakke Johnsen","Tore Wergeland Meisingset","Wei Zhou","Petroula Proitsi","Angela Hodges","Richard Dobson","Latha Velayudhan","Karl Heilbron","Adam Auton","Michelle Agee","Stella Aslibekyan","Elizabeth Babalola","Robert K. Bell","Jessica Bielenberg","Katarzyna Bryc","Emily Bullis","Briana Cameron","Daniella Coker","Gabriel Cuéllar-Partida","Devika Dhamija","Sayantan Das","Sarah L. Elson","Teresa Filshtein","Kipper Fletez‐Brant","Pierre Fontanillas","Will Freyman","Pooja Gandhi","Barry Hicks","David A. Hinds","Karen E. Huber","Ethan M. Jewett","Yunxuan Jiang","Aaron Kleinman","Katelyn Kukar","Vanessa Lane","Keng‐Han Lin","Maya Lowe","Marie K. Luff","Jey C. McCreight","Matthew H. McIntyre","Kimberly F. McManus","Steven J. Micheletti","Meghan E. Moreno","Joanna L. Mountain","Sahar V. Mozaffari","Priyanka Nandakumar","Elizabeth S. Noblin","Jared O’Connell","Aaron A. Petrakovitz","G. David Poznik","Morgan Schumacher","Anjali J. Shastri","Janie F. Shelton","Jingchunzi Shi","Suyash Shringarpure","Chao Tian","Vinh Tran","Joyce Y. Tung","Xin Wang","Wei Wang","Catherine H. Weldon","Peter Wilton","Julia Sealock","Lea K. Davis","Nancy L. Pedersen","Chandra A. Reynolds","Ida Karlsson","Sigurður H. Magnússon","Hreinn Stefánsson","Steinunn Þórðardóttir","Pálmi V. Jónsson","Jón Snædal","Anna Zettergren","Ingmar Skoog","Silke Kern","Margda Wærn","Henrik Zetterberg","Kaj Blennow","Eystein Stordal","Kristian Hveem"]', 'philosophy', 'Late-onset Alzheimer''s disease is a prevalent age-related polygenic disease that accounts for 50-70% of dementia cases. Currently, only a fraction of the genetic variants underlying Alzheimer''s disease have been identified. Here we show that increased sample sizes allowed identification of seven previously unidentified genetic loci contributing to Alzheimer''s disease. This study highlights microglia, immune cells and protein catabolism as relevant to late-onset Alzheimer''s disease, while identifying and prioritizing previously unidentified genes of potential interest. We anticipate that these results can be included in larger meta-analyses of Alzheimer''s disease to identify further genetic variants that contribute to Alzheimer''s pathology.', '2026-07-08 09:11:34');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2766800499', 'philosophy', 'Blockchain in government: Benefits and implications of distributed ledger technology for information sharing', 'Blockchain refers to a range of general purpose technologies to exchange information and transact digital assets in distributed networks. The core question addressed in this paper is whether…', '2017', 2017, 1078, 1078, 'https://ars.els-cdn.com/content/image/1-s2.0-S0740624X17303155-gr1.jpg', 'https://doi.org/10.1016/j.giq.2017.09.007', 'repository', 'article', 'Government Information Quarterly', '["Svein Ølnes","Jolien Ubacht","Marijn Janssen"]', 'philosophy', 'Blockchain refers to a range of general purpose technologies to exchange information and transact digital assets in distributed networks. The core question addressed in this paper is whether blockchain technology will lead to innovation and transformation of governmental processes. To address this questions we present a critical assessment of the often exaggerated benefits of blockchain technology found in the literature and discuss their implications for governmental organizations and processes. We plea for a shift from a technology-driven to need-driven approach in which blockchain applications are customized to ensure a fit with requirements of administrative processes and in which the administrative processes are changed to benefit from the technology. Having sound governance models are found to be a conditions for realizing benefits. Based on a critical assessment we offer directions for further research into the potential benefits of BC applications in e-government and the role of governance of BC architectures and applications to comply with societal needs and public values.', '2026-07-08 09:12:07');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3026091149', 'philosophy', 'Public knowledge, attitudes and practices towards COVID-19: A cross-sectional study in Malaysia', 'In an effort to mitigate the outbreak of COVID-19, many countries have imposed drastic lockdown, movement control or shelter in place orders on their residents. The effectiveness of these mitigation…', '2020', 2020, 1049, 1049, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0233668.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7241824', 'pmc', 'article', 'PLoS ONE', '["Arina Anis Azlan","Mohammad Rezal Hamzah","Jen Sern Tham","Suffian Hadi Ayub","Emma Mohamad"]', 'philosophy', 'In an effort to mitigate the outbreak of COVID-19, many countries have imposed drastic lockdown, movement control or shelter in place orders on their residents. The effectiveness of these mitigation measures is highly dependent on cooperation and compliance of all members of society. The knowledge, attitudes and practices people hold toward the disease play an integral role in determining a society''s readiness to accept behavioural change measures from health authorities. The aim of this study was to determine the knowledge levels, attitudes and practices toward COVID-19 among the Malaysian public. A cross-sectional online survey of 4,850 Malaysian residents was conducted between 27th March and 3rd April 2020. The survey instrument consisted of demographic characteristics, 13 items on knowledge, 3 items on attitudes and 3 items on practices, modified from a previously published questionnaire on COVID-19. Descriptive statistics, chi-square tests, t-tests and one-way analysis of variance (ANOVA) were conducted. The overall correct rate of the knowledge questionnaire was 80.5%. Most participants held positive attitudes toward the successful control of COVID-19 (83.1%), the ability of Malaysia to conquer the disease (95.9%) and the way the Malaysian government was handling the crisis (89.9%). Most participants were also taking precautions such as avoiding crowds (83.4%) and practising proper hand hygiene (87.8%) in the week before the movement control order started. However, the wearing of face masks was less common (51.2%). This survey is among the first to assess knowledge, attitudes and practice in response to the COVID-19 pandemic in Malaysia. The results highlight the importance of consistent messaging from health authorities and the government as well as the need for tailored health education programs to improve levels of knowledge, attitudes and practices.', '2026-07-08 09:12:43');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2403237691', 'philosophy', 'The role of big data in smart city', 'The role of big data in smart city', '2016', 2016, 1051, 1051, 'https://ars.els-cdn.com/content/image/1-s2.0-S0268401216302778-gr1.jpg', 'https://doi.org/10.1016/j.ijinfomgt.2016.05.002', 'repository', 'article', 'International Journal of Information Management', '["Mohamed Hashem","Victor Chang","Nor Badrul Anuar","Kayode S. Adewole","Ibrar Yaqoob","Abdullah Gani","Ejaz Ahmed","Haruna Chiroma"]', 'philosophy', NULL, '2026-07-08 09:12:52');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2585528949', 'philosophy', 'Ensemble learning for data stream analysis: A survey', 'Ensemble learning for data stream analysis: A survey', '2017', 2017, 1045, 1045, 'https://ars.els-cdn.com/content/image/1-s2.0-S1566253516302329-gr1.jpg', 'https://doi.org/10.1016/j.inffus.2017.02.004', 'repository', 'article', 'Information Fusion', '["Bartosz Krawczyk","Leandro L. Minku","João Gama","Jerzy Stefanowski","Michał Woźniak"]', 'philosophy', NULL, '2026-07-08 09:13:02');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3157510358', 'philosophy', 'Regulation of Plant Responses to Salt Stress', 'Salt stress is a major environmental stress that affects plant growth and development. Plants are sessile and thus have to develop suitable mechanisms to adapt to high-salt environments. Salt stress…', '2021', 2021, 1026, 1026, 'https://pub.mdpi-res.com/ijms/ijms-22-04609/article_deploy/html/images/ijms-22-04609-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8125386', 'pmc', 'review', 'International Journal of Molecular Sciences', '["Shuangshuang Zhao","Qikun Zhang","Ming-Yue Liu","Huapeng Zhou","Changle Ma","Pingping Wang"]', 'philosophy', 'Salt stress is a major environmental stress that affects plant growth and development. Plants are sessile and thus have to develop suitable mechanisms to adapt to high-salt environments. Salt stress increases the intracellular osmotic pressure and can cause the accumulation of sodium to toxic levels. Thus, in response to salt stress signals, plants adapt via various mechanisms, including regulating ion homeostasis, activating the osmotic stress pathway, mediating plant hormone signaling, and regulating cytoskeleton dynamics and the cell wall composition. Unraveling the mechanisms underlying these physiological and biochemical responses to salt stress could provide valuable strategies to improve agricultural crop yields. In this review, we summarize recent developments in our understanding of the regulation of plant salt stress.', '2026-07-08 09:13:43');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3010560689', 'philosophy', 'Regulatory Mechanism of MicroRNA Expression in Cancer', 'Altered gene expression is the primary molecular mechanism responsible for the pathological processes of human diseases, including cancer. MicroRNAs (miRNAs) are virtually involved at the…', '2020', 2020, 1024, 1024, 'https://pub.mdpi-res.com/ijms/ijms-21-01723/article_deploy/html/images/ijms-21-01723-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7084905', 'pmc', 'review', 'International Journal of Molecular Sciences', '["Zainab Ali Syeda","Siu Semar Saratu’ Langden","Choijamts Munkhzul","Mihye Lee","Su Jung Song"]', 'philosophy', 'Altered gene expression is the primary molecular mechanism responsible for the pathological processes of human diseases, including cancer. MicroRNAs (miRNAs) are virtually involved at the post-transcriptional level and bind to 3'' UTR of their target messenger RNA (mRNA) to suppress expression. Dysfunction of miRNAs disturbs expression of oncogenic or tumor-suppressive target genes, which is implicated in cancer pathogenesis. As such, a large number of miRNAs have been found to be downregulated or upregulated in human cancers and to function as oncomiRs or oncosuppressor miRs. Notably, the molecular mechanism underlying the dysregulation of miRNA expression in cancer has been recently uncovered. The genetic deletion or amplification and epigenetic methylation of miRNA genomic loci and the transcription factor-mediated regulation of primary miRNA often alter the landscape of miRNA expression in cancer. Dysregulation of the multiple processing steps in mature miRNA biogenesis can also cause alterations in miRNA expression in cancer. Detailed knowledge of the regulatory mechanism of miRNAs in cancer is essential for understanding its physiological role and the implications of cancer-associated dysfunction and dysregulation. In this review, we elucidate how miRNA expression is deregulated in cancer, paying particular attention to the cancer-associated transcriptional and post-transcriptional factors that execute miRNA programs.', '2026-07-08 09:13:57');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2612872172', 'philosophy', 'Parenting Stress, Mental Health, Dyadic Adjustment: A Structural Equation Model', 'Objective: In the first year of the postpartum period, parenting stress, mental health, and dyadic adjustment are important for the wellbeing of both parents and the child. However, there are few…', '2017', 2017, 1011, 1011, 'https://www.frontiersin.org/files/Articles/256995/fpsyg-08-00839-HTML-r1/image_m/fpsyg-08-00839-g001.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5441134', 'pmc', 'article', 'Frontiers in Psychology', '["Luca Rollè","Laura Elvira Prino","Cristina Sechi","Laura Vismara","Erica Neri","Concetta Polizzi","Annamaria Trovato","Barbara Volpi","Sara Molgora","Valentina Fenaroli","E Ierardi","Valentino Ferro","Loredana Lucarelli","Francesca Agostini","Renata Tambelli","Emanuela Saita","C Riva Crugnola","Piera Brustia"]', 'philosophy', 'Objective: In the first year of the postpartum period, parenting stress, mental health, and dyadic adjustment are important for the wellbeing of both parents and the child. However, there are few studies that analyze the relationship among these three dimensions. The aim of this study is to investigate the relationships between parenting stress, mental health (depressive and anxiety symptoms), and dyadic adjustment among first-time parents. Method: We studied 268 parents (134 couples) of healthy babies. At 12 months postpartum, both parents filled out, in a counterbalanced order, the Parenting Stress Index-Short Form, the Edinburgh Postnatal Depression Scale, the State-Trait Anxiety Inventory, and the Dyadic Adjustment Scale. Structural equation modeling was used to analyze the potential mediating effects of mental health on the relationship between parenting stress and dyadic adjustment. Results: Results showed the full mediation effect of mental health between parenting stress and dyadic adjustment. A multi-group analysis further found that the paths did not differ across mothers and fathers. Discussion: The results suggest that mental health is an important dimension that mediates the relationship between parenting stress and dyadic adjustment in the transition to parenthood.', '2026-07-08 09:14:02');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2901655212', 'philosophy', 'REASSURED diagnostics to inform disease control strategies, strengthen health systems and improve patient outcomes', 'REASSURED diagnostics to inform disease control strategies, strengthen health systems and improve patient outcomes', '2018', 2018, 1013, 1013, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41564-018-0295-3/MediaObjects/41564_2018_295_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7097043', 'pmc', 'review', 'Nature Microbiology', '["Kevin Land","Debrah I. Boeras","Xiang‐Sheng Chen","Andrew Ramsay","Rosanna Ŵ. Peeling"]', 'philosophy', NULL, '2026-07-08 09:14:07');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2996705655', 'philosophy', 'Toward safer highways, application of XGBoost and SHAP for real-time accident detection and feature analysis', 'Toward safer highways, application of XGBoost and SHAP for real-time accident detection and feature analysis', '2019', 2019, 1018, 1018, 'https://ars.els-cdn.com/content/image/1-s2.0-S0001457519311790-gr1.jpg', 'https://pubmed.ncbi.nlm.nih.gov/31864931', 'repository', 'article', 'Accident Analysis & Prevention', '["Amir Bahador Parsa","Ali Movahedi","Homa Taghipour","Sybil Derrible","Abolfazl Mohammadian"]', 'philosophy', NULL, '2026-07-08 09:14:08');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3209722108', 'philosophy', 'Management of Rheumatoid Arthritis: An Overview', 'Rheumatoid arthritis (RA) is a multifactorial autoimmune disease of unknown etiology, primarily affecting the joints, then extra-articular manifestations can occur. Due to its complexity, which is…', '2021', 2021, 1019, 1019, 'https://pub.mdpi-res.com/cells/cells-10-02857/article_deploy/html/images/cells-10-02857-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8616326', 'pmc', 'review', 'Cells', '["Andrei-Flavius Radu","Simona Bungău"]', 'philosophy', 'Rheumatoid arthritis (RA) is a multifactorial autoimmune disease of unknown etiology, primarily affecting the joints, then extra-articular manifestations can occur. Due to its complexity, which is based on an incompletely elucidated pathophysiological mechanism, good RA management requires a multidisciplinary approach. The clinical status of RA patients has improved in recent years due to medical advances in diagnosis and treatment, that have made it possible to reduce disease activity and prevent systemic complications. The most promising results were obtained by developing disease-modifying anti-rheumatic drugs (DMARDs), the class to which conventional synthetic, biologic, and targeted synthetic drugs belong. Furthermore, ongoing drug development has led to obtaining molecules with improved efficacy and safety profiles, but further research is needed until RA turns into a curable pathology. In the present work, we offer a comprehensive perspective on the management of RA, by centralizing the existing data provided by significant literature, emphasizing the importance of an early and accurate diagnosis associated with optimal personalized treatment in order to achieve better outcomes for RA patients. In addition, this study suggests future research perspectives in the treatment of RA that could lead to higher efficacy and safety profiles and lower financial costs.', '2026-07-08 09:14:11');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2105798205', 'philosophy', 'Fatty Acids Composition of Vegetable Oils and Its Contribution to Dietary Energy Intake and Dependence of Cardiovascular Mortality on Dietary Intake of Fatty Acids', 'Characterizations of fatty acids composition in % of total methylester of fatty acids (FAMEs) of fourteen vegetable oils--safflower, grape, silybum marianum, hemp, sunflower, wheat germ, pumpkin…', '2015', 2015, 1017, 1017, 'https://pub.mdpi-res.com/ijms/ijms-16-12871/article_deploy/html/images/ijms-16-12871-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4490476', 'pmc', 'article', 'International Journal of Molecular Sciences', '["Jana Orsavová","Ladislava Mišurcová","Jarmila Vávra Ambrožová","Robert Vícha","Jiří­ Mlček"]', 'philosophy', 'Characterizations of fatty acids composition in % of total methylester of fatty acids (FAMEs) of fourteen vegetable oils--safflower, grape, silybum marianum, hemp, sunflower, wheat germ, pumpkin seed, sesame, rice bran, almond, rapeseed, peanut, olive, and coconut oil--were obtained by using gas chromatography (GC). Saturated (SFA), monounsaturated (MUFA) and polyunsaturated fatty acids (PUFA), palmitic acid (C16:0; 4.6%-20.0%), oleic acid (C18:1; 6.2%-71.1%) and linoleic acid (C18:2; 1.6%-79%), respectively, were found predominant. The nutritional aspect of analyzed oils was evaluated by determination of the energy contribution of SFAs (19.4%-695.7% E(RDI)), PUFAs (10.6%-786.8% E(RDI)), n-3 FAs (4.4%-117.1% E(RDI)) and n-6 FAs (1.8%-959.2% E(RDI)), expressed in % E(RDI) of 1 g oil to energy recommended dietary intakes (E(RDI)) for total fat (E(RDI)--37.7 kJ/g). The significant relationship between the reported data of total fat, SFAs, MUFAs and PUFAs intakes (% E(RDI)) for adults and mortality caused by coronary heart diseases (CHD) and cardiovascular diseases (CVD) in twelve countries has not been confirmed by Spearman''s correlations.', '2026-07-08 09:14:14');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3121471843', 'philosophy', 'Carbon Tail Risk', 'Abstract Strong regulatory actions are needed to combat climate change, but climate policy uncertainty makes it difficult for investors to quantify the impact of future climate regulation. We show…', '2020', 2020, 985, 985, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1093/rfs/hhaa071.g001', 'https://doi.org/10.1093/rfs/hhaa071', 'repository', 'article', 'Review of Financial Studies', '["Emirhan Ilhan","Zacharias Sautner","Grigory Vilkov"]', 'philosophy', 'Abstract Strong regulatory actions are needed to combat climate change, but climate policy uncertainty makes it difficult for investors to quantify the impact of future climate regulation. We show that such uncertainty is priced in the option market. The cost of option protection against downside tail risks is larger for firms with more carbon-intense business models. For carbon-intense firms, the cost of protection against downside tail risk is magnified at times when the public’s attention to climate change spikes, and it decreased after the election of climate change skeptic President Trump.', '2026-07-08 09:14:44');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2610353045', 'philosophy', 'Neutralizing misinformation through inoculation: Exposing misleading argumentation techniques reduces their influence', 'Misinformation can undermine a well-functioning democracy. For example, public misconceptions about climate change can lead to lowered acceptance of the reality of climate change and lowered support…', '2017', 2017, 965, 965, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0175799.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5419564', 'pmc', 'article', 'PLoS ONE', '["John Cook","Stephan Lewandowsky","Ullrich K. H. Ecker"]', 'philosophy', 'Misinformation can undermine a well-functioning democracy. For example, public misconceptions about climate change can lead to lowered acceptance of the reality of climate change and lowered support for mitigation policies. This study experimentally explored the impact of misinformation about climate change and tested several pre-emptive interventions designed to reduce the influence of misinformation. We found that false-balance media coverage (giving contrarian views equal voice with climate scientists) lowered perceived consensus overall, although the effect was greater among free-market supporters. Likewise, misinformation that confuses people about the level of scientific agreement regarding anthropogenic global warming (AGW) had a polarizing effect, with free-market supporters reducing their acceptance of AGW and those with low free-market support increasing their acceptance of AGW. However, we found that inoculating messages that (1) explain the flawed argumentation technique used in the misinformation or that (2) highlight the scientific consensus on climate change were effective in neutralizing those adverse effects of misinformation. We recommend that climate communication messages should take into account ways in which scientific content can be distorted, and include pre-emptive inoculation messages.', '2026-07-08 09:15:12');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2800238134', 'philosophy', 'Ionic liquids: a brief history', 'There is no doubt that ionic liquids have become a major subject of study for modern chemistry. We have become used to ever more publications in the field each year, although there is some evidence…', '2018', 2018, 955, 955, 'https://media.springernature.com/lw685/springer-static/image/art%3A10.1007%2Fs12551-018-0419-2/MediaObjects/12551_2018_419_Fig2_HTML.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5988633', 'pmc', 'review', 'Biophysical Reviews', '["Tom Welton"]', 'philosophy', 'There is no doubt that ionic liquids have become a major subject of study for modern chemistry. We have become used to ever more publications in the field each year, although there is some evidence that this is beginning to plateau at approximately 3500 papers each year. They have been the subject of several major reviews and books, dealing with different applications and aspects of their behaviours. In this article, I will show a little of how interest in ionic liquids grew and developed.', '2026-07-08 09:15:46');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2899871244', 'philosophy', 'The Roles of Autophagy in Cancer', 'Autophagy is an intracellular degradative process that occurs under several stressful conditions, including organelle damage, the presence of abnormal proteins, and nutrient deprivation. The…', '2018', 2018, 953, 953, 'https://pub.mdpi-res.com/ijms/ijms-19-03466/article_deploy/html/images/ijms-19-03466-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6274804', 'pmc', 'review', 'International Journal of Molecular Sciences', '["Chul Won Yun","Sang Hun Lee"]', 'philosophy', 'Autophagy is an intracellular degradative process that occurs under several stressful conditions, including organelle damage, the presence of abnormal proteins, and nutrient deprivation. The mechanism of autophagy initiates the formation of autophagosomes that capture degraded components and then fuse with lysosomes to recycle these components. The modulation of autophagy plays dual roles in tumor suppression and promotion in many cancers. In addition, autophagy regulates the properties of cancer stem-cells by contributing to the maintenance of stemness, the induction of recurrence, and the development of resistance to anticancer reagents. Although some autophagy modulators, such as rapamycin and chloroquine, are used to regulate autophagy in anticancer therapy, since this process also plays roles in both tumor suppression and promotion, the precise mechanism of autophagy in cancer requires further study. In this review, we will summarize the mechanism of autophagy under stressful conditions and its roles in tumor suppression and promotion in cancer and in cancer stem-cells. Furthermore, we discuss how autophagy is a promising potential therapeutic target in cancer treatment.', '2026-07-08 09:15:51');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3045058852', 'philosophy', 'How Much Should We Trust Estimates from Multiplicative Interaction Models? Simple Tools to Improve Empirical Practice', 'Multiplicative interaction models are widely used in social science to examine whether the relationship between an outcome and an independent variable changes with a moderating variable. Current…', '2018', 2018, 948, 948, 'https://static.cambridge.org/binary/version/id/urn:cambridge.org:id:binary:20190923152831675-0289:S1047198718000463:S1047198718000463_fig1g.gif?pub-status=live', 'https://doi.org/10.1017/pan.2018.46', 'repository', 'article', 'Political Analysis', '["Jens Hainmueller","Jonathan Mummolo","Yiqing Xu"]', 'philosophy', 'Multiplicative interaction models are widely used in social science to examine whether the relationship between an outcome and an independent variable changes with a moderating variable. Current empirical practice tends to overlook two important problems. First, these models assume a linear interaction effect that changes at a constant rate with the moderator. Second, estimates of the conditional effects of the independent variable can be misleading if there is a lack of common support of the moderator. Replicating 46 interaction effects from 22 recent publications in five top political science journals, we find that these core assumptions often fail in practice, suggesting that a large portion of findings across all political science subfields based on interaction models are fragile and model dependent. We propose a checklist of simple diagnostics to assess the validity of these assumptions and offer flexible estimation strategies that allow for nonlinear interaction effects and safeguard against excessive extrapolation. These statistical routines are available in both R and STATA.', '2026-07-08 09:16:21');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3016681375', 'philosophy', 'The COVID-19 Outbreak and Affected Countries Stock Markets Response', 'This paper evaluates the short-term impact of the coronavirus outbreak on 21 leading stock market indices in major affected countries including Japan, Korea, Singapore, the USA, Germany, Italy, and…', '2020', 2020, 926, 926, 'https://pub.mdpi-res.com/ijerph/ijerph-17-02800/article_deploy/html/images/ijerph-17-02800-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7215540', 'pmc', 'article', 'International Journal of Environmental Research and Public Health', '["Haiyue Liu","Aqsa Manzoor","Cangyu Wang","Lei Zhang","Zaira Manzoor"]', 'philosophy', 'This paper evaluates the short-term impact of the coronavirus outbreak on 21 leading stock market indices in major affected countries including Japan, Korea, Singapore, the USA, Germany, Italy, and the UK etc. The consequences of infectious disease are considerable and have been directly affecting stock markets worldwide. Using an event study method, our results indicate that the stock markets in major affected countries and areas fell quickly after the virus outbreak. Countries in Asia experienced more negative abnormal returns as compared to other countries. Further panel fixed effect regressions also support the adverse effect of COVID-19 confirmed cases on stock indices abnormal returns through an effective channel by adding up investors'' pessimistic sentiment on future returns and fears of uncertainties.', '2026-07-08 09:17:06');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2564632156', 'philosophy', 'SVO: Semidirect Visual Odometry for Monocular and Multicamera Systems', 'Direct methods for visual odometry (VO) have gained popularity for their capability to exploit information from all intensity gradients in the image. However, low computational speed as well as…', '2016', 2016, 923, 923, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1109/tro.2016.2623335.g001', 'https://doi.org/10.1109/tro.2016.2623335', 'repository', 'article', 'IEEE Transactions on Robotics', '["Christian Förster","Zichao Zhang","Michael Gassner","Manuel Werlberger","Davide Scaramuzza"]', 'philosophy', 'Direct methods for visual odometry (VO) have gained popularity for their capability to exploit information from all intensity gradients in the image. However, low computational speed as well as missing guarantees for optimality and consistency are limiting factors of direct methods, in which established feature-based methods succeed instead. Based on these considerations, we propose a semidirect VO (SVO) that uses direct methods to track and triangulate pixels that are characterized by high image gradients, but relies on proven feature-based methods for joint optimization of structure and motion. Together with a robust probabilistic depth estimation algorithm, this enables us to efficiently track pixels lying on weak corners and edges in environments with little or high-frequency texture. We further demonstrate that the algorithm can easily be extended to multiple cameras, to track edges, to include motion priors, and to enable the use of very large field of view cameras, such as fisheye and catadioptric ones. Experimental evaluation on benchmark datasets shows that the algorithm is significantly faster than the state of the art while achieving highly competitive accuracy.', '2026-07-08 09:17:11');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4392731282', 'philosophy', 'Major depressive disorder: hypothesis, mechanism, prevention and treatment', 'Worldwide, the incidence of major depressive disorder (MDD) is increasing annually, resulting in greater economic and social burdens. Moreover, the pathological mechanisms of MDD and the mechanisms…', '2024', 2024, 924, 924, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41392-024-01738-y/MediaObjects/41392_2024_1738_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/10853571', 'pmc', 'article', 'Signal Transduction and Targeted Therapy', '["Lulu Cui","Shu Li","Siman Wang","Xiafang Wu","Yingyu Liu","Weiyang Yu","Yijun Wang","Yong Tang","Maosheng Xia","Baoman Li"]', 'philosophy', 'Worldwide, the incidence of major depressive disorder (MDD) is increasing annually, resulting in greater economic and social burdens. Moreover, the pathological mechanisms of MDD and the mechanisms underlying the effects of pharmacological treatments for MDD are complex and unclear, and additional diagnostic and therapeutic strategies for MDD still are needed. The currently widely accepted theories of MDD pathogenesis include the neurotransmitter and receptor hypothesis, hypothalamic-pituitary-adrenal (HPA) axis hypothesis, cytokine hypothesis, neuroplasticity hypothesis and systemic influence hypothesis, but these hypothesis cannot completely explain the pathological mechanism of MDD. Even it is still hard to adopt only one hypothesis to completely reveal the pathogenesis of MDD, thus in recent years, great progress has been made in elucidating the roles of multiple organ interactions in the pathogenesis MDD and identifying novel therapeutic approaches and multitarget modulatory strategies, further revealing the disease features of MDD. Furthermore, some newly discovered potential pharmacological targets and newly studied antidepressants have attracted widespread attention, some reagents have even been approved for clinical treatment and some novel therapeutic methods such as phototherapy and acupuncture have been discovered to have effective improvement for the depressive symptoms. In this work, we comprehensively summarize the latest research on the pathogenesis and diagnosis of MDD, preventive approaches and therapeutic medicines, as well as the related clinical trials.', '2026-07-08 09:17:15');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2750745925', 'philosophy', 'Regulation of heat shock transcription factors and their roles in physiology and disease', 'Regulation of heat shock transcription factors and their roles in physiology and disease', '2017', 2017, 924, 924, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnrm.2017.73/MediaObjects/41580_2018_Article_BFnrm201773_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5794010', 'pmc', 'review', 'Nature Reviews Molecular Cell Biology', '["Rocío Gómez‐Pastor","Eileen T. Burchfiel","Dennis J. Thiele"]', 'philosophy', NULL, '2026-07-08 09:17:15');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2214297505', 'philosophy', 'Feed Conversion, Survival and Development, and Composition of Four Insect Species on Diets Composed of Food By-Products', 'A large part of the environmental impact of animal production systems is due to the production of feed. Insects are suggested to efficiently convert feed to body mass and might therefore form a more…', '2015', 2015, 922, 922, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0144601.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6772071', 'pmc', 'article', 'PLoS ONE', '["D.G.A.B. Oonincx","Sarah van Broekhoven","A. van Huis","Joop J. A. van Loon"]', 'philosophy', 'A large part of the environmental impact of animal production systems is due to the production of feed. Insects are suggested to efficiently convert feed to body mass and might therefore form a more sustainable food and/or feed source. Four diets were composed from by-products of food manufacturing and formulated such as to vary in protein and fat content. These were offered to newly hatched Argentinean cockroaches, black soldier flies, yellow mealworms, and house crickets. The first two species are potentially interesting as a feed ingredient, while the latter two are considered edible for humans. Feed conversion efficiency, survival, development time, as well as chemical composition (nitrogen, phosphorus, and fatty acids), were determined. The Argentinean cockroaches and the black soldier flies converted feed more efficiently than yellow mealworms, and house crickets. The first two were also more efficient than conventional production animals. On three of the four diets yellow mealworms and house crickets had a feed conversion efficiency similar to pigs. Furthermore, on the most suitable diet, they converted their feed as efficiently as poultry, when corrected for edible portion. All four species had a higher nitrogen-efficiency than conventional production animals, when corrected for edible portion. Offering carrots to yellow mealworms increased dry matter- and nitrogen-efficiency and decreased development time. Diet affected survival in all species but black soldier flies, and development time was strongly influenced in all four species. The chemical composition of Argentinean cockroaches was highly variable between diets, for black soldier flies it remained similar. The investigated species can be considered efficient production animals when suitable diets are provided. Hence, they could form a sustainable alternative to conventional production animals as a source of feed or food.', '2026-07-08 09:17:23');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4200561001', 'philosophy', 'On the mechanism of tissue-specific mRNA delivery by selective organ targeting nanoparticles', ', and serum protein interactions of SORT nanoparticles. Additionally, we provide evidence for an endogenous targeting mechanism whereby organ targeting occurs via 1) desorption of poly(ethylene…', '2021', 2021, 919, 919, 'https://cdn.ncbi.nlm.nih.gov/pmc/blobs/e758/8719871/a0b5daaeff2b/pnas.2109256118fig01.gif', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8719871', 'pmc', 'article', 'Proceedings of the National Academy of Sciences', '["Sean A. Dilliard","Qiang Cheng","Daniel J. Siegwart"]', 'philosophy', ', and serum protein interactions of SORT nanoparticles. Additionally, we provide evidence for an endogenous targeting mechanism whereby organ targeting occurs via 1) desorption of poly(ethylene glycol) lipids from the LNP surface, 2) binding of distinct proteins to the nanoparticle surface because of recognition of exposed SORT molecules, and 3) subsequent interactions between surface-bound proteins and cognate receptors highly expressed in specific tissues. These findings establish a crucial link between the molecular composition of SORT nanoparticles and their unique and precise organ-targeting properties and suggest that the recruitment of specific proteins to a nanoparticle''s surface can enable drug delivery beyond the liver.', '2026-07-08 09:17:42');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2012451954', 'philosophy', 'Getting up to speed with transcription elongation by RNA polymerase II', 'Getting up to speed with transcription elongation by RNA polymerase II', '2015', 2015, 900, 900, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnrm3953/MediaObjects/41580_2015_Article_BFnrm3953_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4782187', 'pmc', 'review', 'Nature Reviews Molecular Cell Biology', '["Iris H. Jonkers","John T. Lis"]', 'philosophy', NULL, '2026-07-08 09:18:15');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2940585064', 'philosophy', 'Speech synthesis from neural decoding of spoken sentences', 'Speech synthesis from neural decoding of spoken sentences', '2019', 2019, 900, 900, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-019-1119-1/MediaObjects/41586_2019_1119_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/9714519', 'pmc', 'article', 'Nature', '["Gopala K. Anumanchipalli","Josh Chartier","Edward F. Chang"]', 'philosophy', NULL, '2026-07-08 09:18:16');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2591673470', 'philosophy', 'Five factors that guide attention in visual search', 'Five factors that guide attention in visual search', '2017', 2017, 900, 900, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41562-017-0058/MediaObjects/41562_2017_Article_BFs415620170058_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/9879335', 'pmc', 'article', 'Nature Human Behaviour', '["Jeremy M. Wolfe","Todd S. Horowitz"]', 'philosophy', NULL, '2026-07-08 09:18:16');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3121705696', 'philosophy', 'Generalized Synthetic Control Method: Causal Inference with Interactive Fixed Effects Models', 'Difference-in-differences (DID) is commonly used for causal inference in time-series cross-sectional data. It requires the assumption that the average outcomes of treated and control units would have…', '2017', 2017, 905, 905, 'https://static.cambridge.org/binary/version/id/urn:cambridge.org:id:binary:20190924101451535-0998:S1047198716000024:S1047198716000024_fig1g.gif?pub-status=live', 'https://doi.org/10.1017/pan.2016.2', 'repository', 'article', 'Political Analysis', '["Yiqing Xu"]', 'philosophy', 'Difference-in-differences (DID) is commonly used for causal inference in time-series cross-sectional data. It requires the assumption that the average outcomes of treated and control units would have followed parallel paths in the absence of treatment. In this paper, we propose a method that not only relaxes this often-violated assumption, but also unifies the synthetic control method (Abadie, Diamond, and Hainmueller 2010) with linear fixed effects models under a simple framework, of which DID is a special case. It imputes counterfactuals for each treated unit using control group information based on a linear interactive fixed effects model that incorporates unit-specific intercepts interacted with time-varying coefficients. This method has several advantages. First, it allows the treatment to be correlated with unobserved unit and time heterogeneities under reasonable modeling assumptions. Second, it generalizes the synthetic control method to the case of multiple treated units and variable treatment periods, and improves efficiency and interpretability. Third, with a built-in cross-validation procedure, it avoids specification searches and thus is easy to implement. An empirical example of Election Day Registration and voter turnout in the United States is provided.', '2026-07-08 09:18:16');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4210796776', 'philosophy', 'Oxidative Stress in Human Pathology and Aging: Molecular Mechanisms and Perspectives', 'Reactive oxygen and nitrogen species (RONS) are generated through various endogenous and exogenous processes; however, they are neutralized by enzymatic and non-enzymatic antioxidants. An imbalance…', '2022', 2022, 885, 885, 'https://pub.mdpi-res.com/cells/cells-11-00552/article_deploy/html/images/cells-11-00552-g001.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8833991', 'pmc', 'review', 'Cells', '["Younis Ahmad Hajam","Raksha Rani","Shahid Yousuf Ganie","Tariq Ahmad Sheikh","Darakhshan Javaid","Syed Sanober Qadri","Sreepoorna Pramodh","Ahmad Alsulimani","Mustfa Alkhanani","Steve Harakeh","Arif Hussain","Shafiul Haque","Mohd Salim Reshi"]', 'philosophy', 'Reactive oxygen and nitrogen species (RONS) are generated through various endogenous and exogenous processes; however, they are neutralized by enzymatic and non-enzymatic antioxidants. An imbalance between the generation and neutralization of oxidants results in the progression to oxidative stress (OS), which in turn gives rise to various diseases, disorders and aging. The characteristics of aging include the progressive loss of function in tissues and organs. The theory of aging explains that age-related functional losses are due to accumulation of reactive oxygen species (ROS), their subsequent damages and tissue deformities. Moreover, the diseases and disorders caused by OS include cardiovascular diseases [CVDs], chronic obstructive pulmonary disease, chronic kidney disease, neurodegenerative diseases and cancer. OS, induced by ROS, is neutralized by different enzymatic and non-enzymatic antioxidants and prevents cells, tissues and organs from damage. However, prolonged OS decreases the content of antioxidant status of cells by reducing the activities of reductants and antioxidative enzymes and gives rise to different pathological conditions. Therefore, the aim of the present review is to discuss the mechanism of ROS-induced OS signaling and their age-associated complications mediated through their toxic manifestations in order to devise effective preventive and curative natural therapeutic remedies.', '2026-07-08 09:18:45');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2614819371', 'philosophy', 'Production of subject-verb agreement, tense, mood, and negation in Italian agrammatic aphasia.', 'Frontiers Events is a rapidly growing calendar management system dedicated to the scheduling of academic events. This includes announcements and invitations, participant listings and search…', '2015', 2015, 874, 874, 'https://files-journal-api.frontiersin.org/v1/containers(''events'')/files(''150418/figures/1/jpeg'')/versions(1)/get.thumbnail(width=166,height=166)', 'https://doi.org/10.3389/conf.fpsyg.2015.65.00011', 'repository', 'article', 'Frontiers in Psychology', '["Fyndanis Valantis","Carlo Semenza","Capasso Rita","Gandolfi Marialuisa","De Pellegrin Serena","Arcara Giorgio","Burgio Francesca","Maculan Anna","Smania Nicola","Miceli Gabriele"]', 'philosophy', 'Frontiers Events is a rapidly growing calendar management system dedicated to the scheduling of academic events. This includes announcements and invitations, participant listings and search functionality, abstract handling and publication, related events and post-event exchanges. Whether an organizer or participant, make your event a Frontiers Event!', '2026-07-08 09:19:13');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2152359509', 'philosophy', 'Multi-sided platforms', 'Multi-sided platforms', '2015', 2015, 872, 872, 'https://ars.els-cdn.com/content/image/1-s2.0-S0167718715000363-gr1.jpg', 'https://doi.org/10.1016/j.ijindorg.2015.03.003', 'repository', 'article', 'International Journal of Industrial Organization', '["Andrei Hagiu","Julian Wright"]', 'philosophy', NULL, '2026-07-08 09:19:15');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2898962279', 'mathematics', 'Present and future Köppen-Geiger climate classification maps at 1-km resolution', 'We present new global maps of the Köppen-Geiger climate classification at an unprecedented 1-km resolution for the present-day (1980-2016) and for projected future conditions (2071-2100) under…', '2018', 2018, 6545, 6545, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fsdata.2018.214/MediaObjects/41597_2018_Article_BFsdata2018214_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6207062', 'pmc', 'article', 'Scientific Data', '["Hylke E. Beck","Niklaus E. Zimmermann","Tim R. McVicar","Noemi Vergopolan","Alexis Berg","Eric F. Wood"]', 'mathematics', 'We present new global maps of the Köppen-Geiger climate classification at an unprecedented 1-km resolution for the present-day (1980-2016) and for projected future conditions (2071-2100) under climate change. The present-day map is derived from an ensemble of four high-resolution, topographically-corrected climatic maps. The future map is derived from an ensemble of 32 climate model projections (scenario RCP8.5), by superimposing the projected climate change anomaly on the baseline high-resolution climatic maps. For both time periods we calculate confidence levels from the ensemble spread, providing valuable indications of the reliability of the classifications. The new maps exhibit a higher classification accuracy and substantially more detail than previous maps, particularly in regions with sharp spatial or elevation gradients. We anticipate the new maps will be useful for numerous applications, including species and vegetation distribution modeling. The new maps including the associated confidence maps are freely available via www.gloh2o.org/koppen.', '2026-07-08 09:20:45');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2153860431', 'mathematics', 'LD Score regression distinguishes confounding from polygenicity in genome-wide association studies', 'LD Score regression distinguishes confounding from polygenicity in genome-wide association studies', '2015', 2015, 6286, 6286, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fng.3211/MediaObjects/41588_2015_Article_BFng3211_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4495769', 'pmc', 'article', 'Nature Genetics', '["Brendan Bulik‐Sullivan","Po‐Ru Loh","Hilary K. Finucane","Stephan Ripke","Jian Yang","Nick Patterson","Mark J. Daly","Alkes L. Price","Benjamin M. Neale"]', 'mathematics', NULL, '2026-07-08 09:20:46');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2997280954', 'mathematics', 'Normalization and variance stabilization of single-cell RNA-seq data using regularized negative binomial regression', 'Single-cell RNA-seq (scRNA-seq) data exhibits significant cell-to-cell variation due to technical factors, including the number of molecules detected in each cell, which can confound biological…', '2019', 2019, 4978, 4978, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs13059-019-1874-1/MediaObjects/13059_2019_1874_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6927181', 'pmc', 'article', 'Genome biology', '["Christoph Hafemeister","Rahul Satija"]', 'mathematics', 'Single-cell RNA-seq (scRNA-seq) data exhibits significant cell-to-cell variation due to technical factors, including the number of molecules detected in each cell, which can confound biological heterogeneity with technical effects. To address this, we present a modeling framework for the normalization and variance stabilization of molecular count data from scRNA-seq experiments. We propose that the Pearson residuals from "regularized negative binomial regression," where cellular sequencing depth is utilized as a covariate in a generalized linear model, successfully remove the influence of technical characteristics from downstream analyses while preserving biological heterogeneity. Importantly, we show that an unconstrained negative binomial model may overfit scRNA-seq data, and overcome this by pooling information across genes with similar abundances to obtain stable parameter estimates. Our procedure omits the need for heuristic steps including pseudocount addition or log-transformation and improves common downstream analytical tasks such as variable gene selection, dimensional reduction, and differential expression. Our approach can be applied to any UMI-based scRNA-seq dataset and is freely available as part of the R package sctransform, with a direct interface to our single-cell toolkit Seurat.', '2026-07-08 09:21:28');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4394785938', 'mathematics', 'Interactive Tree of Life (iTOL) v6: recent updates to the phylogenetic tree display and annotation tool', 'The Interactive Tree Of Life (https://itol.embl.de) is an online tool for the management, display, annotation and manipulation of phylogenetic and other trees. It is freely available and open to…', '2024', 2024, 3934, 3934, 'https://cdn.ncbi.nlm.nih.gov/pmc/blobs/fa01/11223838/67f7e3bfb813/gkae268fig1.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/11223838', 'pmc', 'article', 'Nucleic Acids Research', '["Ivica Letunić","Peer Bork"]', 'mathematics', 'The Interactive Tree Of Life (https://itol.embl.de) is an online tool for the management, display, annotation and manipulation of phylogenetic and other trees. It is freely available and open to everyone. iTOL version 6 introduces a modernized and completely rewritten user interface, together with numerous new features. A new dataset type has been introduced (colored/labeled ranges), greatly upgrading the functionality of the previous simple colored range annotation function. Additional annotation options have been implemented for several existing dataset types. Dataset template files now support simple assignment of annotations to multiple tree nodes through substring matching, including full regular expression support. Node metadata handling has been greatly extended with novel display and exporting options, and it can now be edited interactively or bulk updated through annotation files. Tree labels can be displayed using multiple simultaneous font styles, with precise positioning, sizing and styling of each individual label part. Various bulk label editing functions have been implemented, simplifying large scale changes of all tree node labels. iTOL''s automatic taxonomy assignment functions now support trees based on the Genome Taxonomy Database (GTDB), in addition to the NCBI taxonomy. The functionality of the optional user account pages has been expanded, simplifying the management, navigation and sharing of projects and trees. iTOL currently handles more than one and a half million trees from >130 000 individual user accounts.', '2026-07-08 09:22:26');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2769542288', 'mathematics', 'Microbiome Datasets Are Compositional: And This Is Not Optional', 'Datasets collected by high-throughput sequencing (HTS) of 16S rRNA gene amplimers, metagenomes or metatranscriptomes are commonplace and being used to study human disease states, ecological…', '2017', 2017, 3086, 3086, 'https://www.frontiersin.org/files/Articles/294209/fmicb-08-02224-HTML/image_m/fmicb-08-02224-g001.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5695134', 'pmc', 'review', 'Frontiers in Microbiology', '["Gregory B. Gloor","Jean M. Macklaim","Vera Pawlowsky‐Glahn","Juan José Egozcue"]', 'mathematics', 'Datasets collected by high-throughput sequencing (HTS) of 16S rRNA gene amplimers, metagenomes or metatranscriptomes are commonplace and being used to study human disease states, ecological differences between sites, and the built environment. There is increasing awareness that microbiome datasets generated by HTS are compositional because they have an arbitrary total imposed by the instrument. However, many investigators are either unaware of this or assume specific properties of the compositional data. The purpose of this review is to alert investigators to the dangers inherent in ignoring the compositional nature of the data, and point out that HTS datasets derived from microbiome studies can and should be treated as compositions at all stages of analysis. We briefly introduce compositional data, illustrate the pathologies that occur when compositional data are analyzed inappropriately, and finally give guidance and point to resources and examples for the analysis of microbiome datasets using compositional data analysis.', '2026-07-08 09:24:07');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2613409207', 'mathematics', 'Singularity: Scientific containers for mobility of compute', 'Here we present Singularity, software developed to bring containers and reproducibility to scientific computing. Using Singularity containers, developers can work in reproducible environments of…', '2017', 2017, 2686, 2686, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0177459.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5426675', 'pmc', 'article', 'PLoS ONE', '["Gregory M. Kurtzer","Vanessa Sochat","Michael W. Bauer"]', 'mathematics', 'Here we present Singularity, software developed to bring containers and reproducibility to scientific computing. Using Singularity containers, developers can work in reproducible environments of their choosing and design, and these complete environments can easily be copied and executed on other platforms. Singularity is an open source initiative that harnesses the expertise of system and software engineers and researchers alike, and integrates seamlessly into common workflows for both of these groups. As its primary use case, Singularity brings mobility of computing to both users and HPC centers, providing a secure means to capture and distribute software and compute environments. This ability to create and deploy reproducible environments across these centers, a previously unmet need, makes Singularity a game changing development for computational science.', '2026-07-08 09:25:25');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1981244178', 'mathematics', 'cocor: A Comprehensive Solution for the Statistical Comparison of Correlations', 'A valid comparison of the magnitude of two correlations requires researchers to directly contrast the correlations using an appropriate statistical test. In many popular statistics packages, however,…', '2015', 2015, 2049, 2049, 'https://journals.plos.org/plosone/article/figure/image?size=large&id=10.1371/journal.pone.0121945.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4383486', 'pmc', 'article', 'PLoS ONE', '["Birk Diedenhofen","Jochen Musch"]', 'mathematics', 'A valid comparison of the magnitude of two correlations requires researchers to directly contrast the correlations using an appropriate statistical test. In many popular statistics packages, however, tests for the significance of the difference between correlations are missing. To close this gap, we introduce cocor, a free software package for the R programming language. The cocor package covers a broad range of tests including the comparisons of independent and dependent correlations with either overlapping or nonoverlapping variables. The package also includes an implementation of Zou''s confidence interval for all of these comparisons. The platform independent cocor package enhances the R statistical computing environment and is available for scripting. Two different graphical user interfaces-a plugin for RKWard and a web interface-make cocor a convenient and user-friendly tool.', '2026-07-08 09:28:38');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2215315565', 'mathematics', 'Experimental realization of two-dimensional boron sheets', 'Experimental realization of two-dimensional boron sheets', '2016', 2016, 1874, 1874, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnchem.2491/MediaObjects/41557_2016_Article_BFnchem2491_Fig1_HTML.jpg', 'http://arxiv.org/abs/1512.05029', 'arxiv', 'article', 'Nature Chemistry', '["Baojie Feng","Jin Zhang","Qing Zhong","Wenbin Li","Shuai Li","Hui Li","Peng Cheng","Sheng Meng","Lan Chen","Kehui Wu"]', 'mathematics', NULL, '2026-07-08 09:30:03');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3120392574', 'mathematics', 'Perineuronal nets stabilize the grid cell network', 'Grid cells are part of a widespread network which supports navigation and spatial memory. Stable grid patterns appear late in development, in concert with extracellular matrix aggregates termed…', '2021', 2021, 1870, 1870, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41467-020-20241-w/MediaObjects/41467_2020_20241_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7801665', 'pmc', 'article', 'Nature Communications', '["Ane Charlotte Christensen","Kristian Kinden Lensjø","Mikkel Elle Lepperød","Svenn-Arne Dragly","Halvard Sutterud","Jan Sigurd Blackstad","Marianne Fyhn","Torkel Hafting"]', 'mathematics', 'Grid cells are part of a widespread network which supports navigation and spatial memory. Stable grid patterns appear late in development, in concert with extracellular matrix aggregates termed perineuronal nets (PNNs) that condense around inhibitory neurons. It has been suggested that PNNs stabilize synaptic connections and long-term memories, but their role in the grid cell network remains elusive. We show that removal of PNNs leads to lower inhibitory spiking activity, and reduces grid cells'' ability to create stable representations of a novel environment. Furthermore, in animals with disrupted PNNs, exposure to a novel arena corrupted the spatiotemporal relationships within grid cell modules, and the stored representations of a familiar arena. Finally, we show that PNN removal in entorhinal cortex distorted spatial representations in downstream hippocampal neurons. Together this work suggests that PNNs provide a key stabilizing element for the grid cell network.', '2026-07-08 09:30:04');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3118048495', 'mathematics', 'CheckV assesses the quality and completeness of metagenome-assembled viral genomes', 'Millions of new viral sequences have been identified from metagenomes, but the quality and completeness of these sequences vary considerably. Here we present CheckV, an automated pipeline for…', '2020', 2020, 1795, 1795, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41587-020-00774-7/MediaObjects/41587_2020_774_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8116208', 'pmc', 'article', 'Nature Biotechnology', '["Stephen Nayfach","Antônio Pedro Camargo","Frederik Schulz","Emiley A. Eloe‐Fadrosh","Simon Roux","Nikos C. Kyrpides"]', 'mathematics', 'Millions of new viral sequences have been identified from metagenomes, but the quality and completeness of these sequences vary considerably. Here we present CheckV, an automated pipeline for identifying closed viral genomes, estimating the completeness of genome fragments and removing flanking host regions from integrated proviruses. CheckV estimates completeness by comparing sequences with a large database of complete viral genomes, including 76,262 identified from a systematic search of publicly available metagenomes, metatranscriptomes and metaviromes. After validation on mock datasets and comparison to existing methods, we applied CheckV to large and diverse collections of metagenome-assembled viral sequences, including IMG/VR and the Global Ocean Virome. This revealed 44,652 high-quality viral genomes (that is, >90% complete), although the vast majority of sequences were small fragments, which highlights the challenge of assembling viral genomes from short-read metagenomes. Additionally, we found that removal of host contamination substantially improved the accurate identification of auxiliary metabolic genes and interpretation of viral-encoded functions.', '2026-07-08 09:30:53');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2111999709', 'mathematics', 'Ranking treatments in frequentist network meta-analysis works without resampling methods', 'BACKGROUND: Network meta-analysis is used to compare three or more treatments for the same condition. Within a Bayesian framework, for each treatment the probability of being best, or, more general,…', '2015', 2015, 1737, 1737, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs12874-021-01397-5/MediaObjects/12874_2021_1397_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4521472', 'pmc', 'article', 'BMC Medical Research Methodology', '["Gerta Rücker","Guido Schwarzer"]', 'mathematics', 'BACKGROUND: Network meta-analysis is used to compare three or more treatments for the same condition. Within a Bayesian framework, for each treatment the probability of being best, or, more general, the probability that it has a certain rank can be derived from the posterior distributions of all treatments. The treatments can then be ranked by the surface under the cumulative ranking curve (SUCRA). For comparing treatments in a network meta-analysis, we propose a frequentist analogue to SUCRA which we call P-score that works without resampling. METHODS: P-scores are based solely on the point estimates and standard errors of the frequentist network meta-analysis estimates under normality assumption and can easily be calculated as means of one-sided p-values. They measure the mean extent of certainty that a treatment is better than the competing treatments. RESULTS: Using case studies of network meta-analysis in diabetes and depression, we demonstrate that the numerical values of SUCRA and P-Score are nearly identical. CONCLUSIONS: Ranking treatments in frequentist network meta-analysis works without resampling. Like the SUCRA values, P-scores induce a ranking of all treatments that mostly follows that of the point estimates, but takes precision into account. However, neither SUCRA nor P-score offer a major advantage compared to looking at credible or confidence intervals.', '2026-07-08 09:31:19');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2462161029', 'mathematics', 'Guidelines for Accurate and Transparent Health Estimates Reporting: the GATHER statement', 'Measurements of health indicators are rarely available for every population and period of interest, and available data may not be comparable. The Guidelines for Accurate and Transparent Health…', '2016', 2016, 1647, 1647, 'https://journals.plos.org/plosmedicine/article/figure/image?id=10.1371/journal.pmed.1002056.t001&size=inline', 'http://dx.plos.org/10.1371/journal.pmed.1002056', 'repository', 'review', 'The Lancet', '["Gretchen A Stevens","Leontine Alkema","Robert E. Black","J. Ties Boerma","Gary S. Collins","Majid Ezzati","John Grove","Daniel Hogan","Margaret C. Hogan","Richard Horton","Joy E Lawn","Ana Marušić","Colin Mathers","Christopher J L Murray","Igor Rudan","Joshua A. Salomon","Paul J. Simpson","Theo Vos","Vivian Welch"]', 'mathematics', 'Measurements of health indicators are rarely available for every population and period of interest, and available data may not be comparable. The Guidelines for Accurate and Transparent Health Estimates Reporting (GATHER) define best reporting practices for studies that calculate health estimates for multiple populations (in time or space) using multiple information sources. Health estimates that fall within the scope of GATHER include all quantitative population-level estimates (including global, regional, national, or subnational estimates) of health indicators, including indicators of health status, incidence and prevalence of diseases, injuries, and disability and functioning; and indicators of health determinants, including health behaviours and health exposures. GATHER comprises a checklist of 18 items that are essential for best reporting practice. A more detailed explanation and elaboration document, describing the interpretation and rationale of each reporting item along with examples of good reporting, is available on the GATHER website.', '2026-07-08 09:32:22');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2988396470', 'mathematics', 'OrthoFinder: phylogenetic orthology inference for comparative genomics', 'Here, we present a major advance of the OrthoFinder method. This extends OrthoFinder''s high accuracy orthogroup inference to provide phylogenetic inference of orthologs, rooted gene trees, gene…', '2019', 2019, 8011, 8011, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs13059-019-1832-y/MediaObjects/13059_2019_1832_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6857279', 'pmc', 'article', 'Genome biology', '["David Emms","Steven Kelly"]', 'mathematics', 'Here, we present a major advance of the OrthoFinder method. This extends OrthoFinder''s high accuracy orthogroup inference to provide phylogenetic inference of orthologs, rooted gene trees, gene duplication events, the rooted species tree, and comparative genomics statistics. Each output is benchmarked on appropriate real or simulated datasets, and where comparable methods exist, OrthoFinder is equivalent to or outperforms these methods. Furthermore, OrthoFinder is the most accurate ortholog inference method on the Quest for Orthologs benchmark test. Finally, OrthoFinder''s comprehensive phylogenetic analysis is achieved with equivalent speed and scalability to the fastest, score-based heuristic methods. OrthoFinder is available at https://github.com/davidemms/OrthoFinder.', '2026-07-08 09:37:52');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2842089854', 'mathematics', 'CasADi: a software framework for nonlinear optimization and optimal control', 'CasADi: a software framework for nonlinear optimization and optimal control', '2018', 2018, 3734, 3734, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1007%2Fs12532-018-0139-4/MediaObjects/12532_2018_139_Fig1_HTML.png', 'https://doi.org/10.5281/zenodo.20716805', 'repository', 'article', 'Mathematical Programming Computation', '["Joel A.E. Andersson","Joris Gillis","Greg Horn","James B. Rawlings","Moritz Diehl"]', 'mathematics', NULL, '2026-07-08 09:40:32');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2511515754', 'mathematics', 'A reference panel of 64,976 haplotypes for genotype imputation', 'A reference panel of 64,976 haplotypes for genotype imputation', '2016', 2016, 3282, 3282, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fng.3643/MediaObjects/41588_2016_Article_BFng3643_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5388176', 'pmc', 'article', 'Nature Genetics', '["Richard Durbin","Klaudia Walter","Yang Luo","Shane McCarthy","Nicole Soranzo","Jeffrey C. Barrett","Eleftheria Zeggini","Arthur Gilly","Carl A. Anderson","Sayantan Das","Sayantan Das","Christian Fuchsberger","Hyun Min Kang","Sai Chen","Sai Chen","Michael Boehnke","Gonçalo Abecasis","Warren Kretzschmar","Sayantan Das","Mark I McCarthy","Hyun Min Kang","Sai Chen","Andrew R Wood","Michael Boehnke","Timothy Frayling","Anubha Mahajan","Warren W. Kretzschmar","Petr Danecek","Kevin Sharp","Olivier Delaneau","Andrew R. Wood","Marcus A. Tuke","Timothy M. Frayling","Alexander Teumer","Matthias Nauck","Alexander Teumer","Petr Danecek","Kevin Sharp","Veikko Salomaa","Andrea Angius","Fabio Busonero","Francesco Cucca","Carlo Sidore","Josine L. Min","Nicholas J. Timpson","George Davey Smith","Laura J. Corbin","Seppo Koskinen","Veikko Salomaa","Scott Vrieze","Scott Vrieze","Cristen J. Willer","He Zhang","Jan H. Veldink","Wouter van Rheenen","Leonard H. van den Berg","Annelot M. Dekker","Tabitha A. Harrison","Charles Kooperberg","Ulrike Peters","Ulrike Peters","Michele T. Pato","Carlos N. Pato","Cornelia M. van Duijn","Matthew G. Sampson","Christopher E. Gillies","Nicola Pirastu","Ilaria Gandin","Massimiliano Cocca","Paolo Gasparini","Massimo Mezzavilla","Massimo Mezzavilla","Paolo Gasparini","Daniela Toniolo","Michela Traglia","Cinzia Sala","Dorrett Boomsma","Kari Branham","Gerome Breen","Gerome Breen","Chad M. Brummett","Ross M. Fraser","James F. Wilson","Harry Campbell","Andrew T. Chan","Andrew T. Chan","Cristen J. Willer","Matthias Kretzler","Sai Chen","Cristen J. Willer","Matthias Kretzler","Sai Chen","Emily Y. Chew","Francis S. Collins","George Dedoussis","Aliki‐Eleni Farmaki","Marcus Dörr","Matthias Nauck","Uwe Völker","Marcus Dörr"]', 'mathematics', NULL, '2026-07-08 09:41:26');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2784327149', 'mathematics', 'TerraClimate, a high-resolution global dataset of monthly climate and climatic water balance from 1958–2015', 'We present TerraClimate, a dataset of high-spatial resolution (1/24°, ~4-km) monthly climate and climatic water balance for global terrestrial surfaces from 1958-2015. TerraClimate uses climatically…', '2018', 2018, 3226, 3226, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fsdata.2017.191/MediaObjects/41597_2018_Article_BFsdata2017191_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5759372', 'pmc', 'article', 'Scientific Data', '["John T. Abatzoglou","Solomon Z. Dobrowski","Sean A. Parks","Katherine C. Hegewisch"]', 'mathematics', 'We present TerraClimate, a dataset of high-spatial resolution (1/24°, ~4-km) monthly climate and climatic water balance for global terrestrial surfaces from 1958-2015. TerraClimate uses climatically aided interpolation, combining high-spatial resolution climatological normals from the WorldClim dataset, with coarser resolution time varying (i.e., monthly) data from other sources to produce a monthly dataset of precipitation, maximum and minimum temperature, wind speed, vapor pressure, and solar radiation. TerraClimate additionally produces monthly surface water balance datasets using a water balance model that incorporates reference evapotranspiration, precipitation, temperature, and interpolated plant extractable soil water capacity. These data provide important inputs for ecological and hydrological studies at global scales that require high spatial resolution and time varying climate and climatic water balance data. We validated spatiotemporal aspects of TerraClimate using annual temperature, precipitation, and calculated reference evapotranspiration from station data, as well as annual runoff from streamflow gauges. TerraClimate datasets showed noted improvement in overall mean absolute error and increased spatial realism relative to coarser resolution gridded datasets.', '2026-07-08 09:41:44');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1844405070', 'mathematics', 'Partitioning heritability by functional annotation using genome-wide association summary statistics', 'Partitioning heritability by functional annotation using genome-wide association summary statistics', '2015', 2015, 3066, 3066, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fng.3404/MediaObjects/41588_2015_Article_BFng3404_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4626285', 'pmc', 'article', 'Nature Genetics', '["Hilary K. Finucane","Brendan Bulik‐Sullivan","Alexander Gusev","Gosia Trynka","Yakir Reshef","Po‐Ru Loh","Verneri Anttila","Han Xu","Chongzhi Zang","Kyle Kai-How Farh","Stephan Ripke","Felix R. Day","Shaun Purcell","Eli A. Stahl","Sara Lindström","John R. B. Perry","Yukinori Okada","Soumya Raychaudhuri","Mark J. Daly","Nick Patterson","Benjamin M. Neale","Alkes L. Price"]', 'mathematics', NULL, '2026-07-08 09:41:59');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1982518595', 'mathematics', 'Elevation-dependent warming in mountain regions of the world', 'Elevation-dependent warming in mountain regions of the world', '2015', 2015, 2915, 2915, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnclimate2563/MediaObjects/41558_2015_Article_BFnclimate2563_Fig1_HTML.jpg', 'https://doi.org/10.1038/nclimate2563', 'repository', 'article', 'Nature Climate Change', '["N. C. Pepin","Raymond S. Bradley","Henry F. Díaz","Michel Baraër","E. B. Caceres","Hayley J. Fowler","Nathan Forsythe","Gregory B. Greenwood","M. Z. Hashmi","Xiaodong Liu","James R. Miller","Liang Ning","A. Ohmura","Elisa Palazzi","Imtiaz Rangwala","Imtiaz Rangwala","Wolfgang Schöner","Igor Severskiy","Maria Shahgedanova","Maxwell Wang","S. N. Williamson"]', 'mathematics', NULL, '2026-07-08 09:42:25');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1819467863', 'mathematics', 'Confirmatory factor analysis with ordinal data: Comparing robust maximum likelihood and diagonally weighted least squares', 'Confirmatory factor analysis with ordinal data: Comparing robust maximum likelihood and diagonally weighted least squares', '2015', 2015, 2857, 2857, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.3758%2Fs13428-021-01547-z/MediaObjects/13428_2021_1547_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/26174714', 'repository', 'article', 'Behavior Research Methods', '["Cheng-Hsien Li"]', 'mathematics', NULL, '2026-07-08 09:42:26');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2801361050', 'mathematics', 'ASTRAL-III: polynomial time species tree reconstruction from partially resolved gene trees', 'BACKGROUND: Evolutionary histories can be discordant across the genome, and such discordances need to be considered in reconstructing the species phylogeny. ASTRAL is one of the leading methods for…', '2018', 2018, 2748, 2748, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1186%2Fs12864-020-6607-z/MediaObjects/12864_2020_6607_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5998893', 'pmc', 'article', 'BMC Bioinformatics', '["Chao Zhang","Maryam Rabiee","Erfan Sayyari","Siavash Mirarab"]', 'mathematics', 'BACKGROUND: Evolutionary histories can be discordant across the genome, and such discordances need to be considered in reconstructing the species phylogeny. ASTRAL is one of the leading methods for inferring species trees from gene trees while accounting for gene tree discordance. ASTRAL uses dynamic programming to search for the tree that shares the maximum number of quartet topologies with input gene trees, restricting itself to a predefined set of bipartitions. RESULTS: We introduce ASTRAL-III, which substantially improves the running time of ASTRAL-II and guarantees polynomial running time as a function of both the number of species (n) and the number of genes (k). ASTRAL-III limits the bipartition constraint set (X) to grow at most linearly with n and k. Moreover, it handles polytomies more efficiently than ASTRAL-II, exploits similarities between gene trees better, and uses several techniques to avoid searching parts of the search space that are mathematically guaranteed not to include the optimal tree. The asymptotic running time of ASTRAL-III in the presence of polytomies is [Formula: see text] where D=O(nk) is the sum of degrees of all unique nodes in input trees. The running time improvements enable us to test whether contracting low support branches in gene trees improves the accuracy by reducing noise. In extensive simulations, we show that removing branches with very low support (e.g., below 10%) improves accuracy while overly aggressive filtering is harmful. We observe on a biological avian phylogenomic dataset of 14K genes that contracting low support branches greatly improve results. CONCLUSIONS: ASTRAL-III is a faster version of the ASTRAL method for phylogenetic reconstruction and can scale up to 10,000 species. With ASTRAL-III, low support branches can be removed, resulting in improved accuracy.', '2026-07-08 09:42:56');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2781491230', 'mathematics', 'Non-Hermitian physics and PT symmetry', 'Non-Hermitian physics and PT symmetry', '2018', 2018, 2707, 2707, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnphys4323/MediaObjects/41567_2018_Article_BFnphys4323_Fig1_HTML.jpg', 'https://doi.org/10.1038/nphys4323', 'repository', 'article', 'Nature Physics', '["Ramy El‐Ganainy","Konstantinos G. Makris","Mercedeh Khajavikhan","Ziad H. Musslimani","Stefan Rotter","Demetrios N. Christodoulides"]', 'mathematics', NULL, '2026-07-08 09:43:12');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2794521141', 'mathematics', 'Batch effects in single-cell RNA-sequencing data are corrected by matching mutual nearest neighbors', 'Batch effects in single-cell RNA-sequencing data are corrected by matching mutual nearest neighbors', '2018', 2018, 2737, 2737, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnbt.4091/MediaObjects/41587_2018_Article_BFnbt4091_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6152897', 'pmc', 'article', 'Nature Biotechnology', '["Laleh Haghverdi","Aaron T. L. Lun","Michael D. Morgan","John C. Marioni"]', 'mathematics', NULL, '2026-07-08 09:43:12');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2338318698', 'mathematics', 'Learning from imbalanced data: open challenges and future directions', 'Despite more than two decades of continuous development learning from imbalanced data is still a focus of intense research. Starting as a problem of skewed distributions of binary tasks, this topic…', '2016', 2016, 2427, 2427, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1007%2Fs10462-024-10759-6/MediaObjects/10462_2024_10759_Fig1_HTML.png', 'https://doi.org/10.1007/s13748-016-0094-0', 'repository', 'article', 'Progress in Artificial Intelligence', '["Bartosz Krawczyk"]', 'mathematics', 'Despite more than two decades of continuous development learning from imbalanced data is still a focus of intense research. Starting as a problem of skewed distributions of binary tasks, this topic evolved way beyond this conception. With the expansion of machine learning and data mining, combined with the arrival of big data era, we have gained a deeper insight into the nature of imbalanced learning, while at the same time facing new emerging challenges. Data-level and algorithm-level methods are constantly being improved and hybrid approaches gain increasing popularity. Recent trends focus on analyzing not only the disproportion between classes, but also other difficulties embedded in the nature of data. New real-life problems motivate researchers to focus on computationally efficient, adaptive and real-time methods. This paper aims at discussing open issues and challenges that need to be addressed to further develop the field of imbalanced learning. Seven vital areas of research in this topic are identified, covering the full spectrum of learning from imbalanced data: classification, regression, clustering, data streams, big data analytics and applications, e.g., in social media and computer vision. This paper provides a discussion and suggestions concerning lines of future research for each of them.', '2026-07-08 09:44:20');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3110151578', 'mathematics', 'Parameterizing neural power spectra into periodic and aperiodic components', 'Parameterizing neural power spectra into periodic and aperiodic components', '2020', 2020, 2385, 2385, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41593-020-00744-x/MediaObjects/41593_2020_744_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/8106550', 'pmc', 'article', 'Nature Neuroscience', '["Thomas Donoghue","Matar Haller","Erik Peterson","Paroma Varma","Priyadarshini Sebastian","Richard Gao","Torben Noto","Antonio H. Lara","Joni D. Wallis","Robert T. Knight","Avgusta Y. Shestyuk","Bradley Voytek"]', 'mathematics', NULL, '2026-07-08 09:44:23');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W4288039037', 'mathematics', 'Scientific Machine Learning Through Physics–Informed Neural Networks: Where we are and What’s Next', 'Abstract Physics-Informed Neural Networks (PINN) are neural networks (NNs) that encode model equations, like Partial Differential Equations (PDE), as a component of the neural network itself. PINNs…', '2022', 2022, 2355, 2355, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1007%2Fs10915-022-01939-z/MediaObjects/10915_2022_1939_Fig1_HTML.png', 'https://doi.org/10.1007/s10915-022-01939-z', 'repository', 'article', 'Journal of Scientific Computing', '["Salvatore Cuomo","Vincenzo Schiano Di Cola","Fabio Giampaolo","Gianluigi Rozza","Maziar Raissi","Francesco Piccialli"]', 'mathematics', 'Abstract Physics-Informed Neural Networks (PINN) are neural networks (NNs) that encode model equations, like Partial Differential Equations (PDE), as a component of the neural network itself. PINNs are nowadays used to solve PDEs, fractional equations, integral-differential equations, and stochastic PDEs. This novel methodology has arisen as a multi-task learning framework in which a NN must fit observed data while reducing a PDE residual. This article provides a comprehensive review of the literature on PINNs: while the primary goal of the study was to characterize these networks and their related advantages and disadvantages. The review also attempts to incorporate publications on a broader range of collocation-based physics informed neural networks, which stars form the vanilla PINN, as well as many other variants, such as physics-constrained neural networks (PCNN), variational hp-VPINN, and conservative PINN (CPINN). The study indicates that most research has focused on customizing the PINN through different activation functions, gradient optimization techniques, neural network structures, and loss function structures. Despite the wide range of applications for which PINNs have been used, by demonstrating their ability to be more feasible in some contexts than classical numerical techniques like Finite Element Method (FEM), advancements are still possible, most notably theoretical issues that remain unresolved.', '2026-07-08 09:44:30');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2805837749', 'mathematics', 'Efficient generation of mouse models of human diseases via ABE- and BE-mediated base editing', 'A recently developed adenine base editor (ABE) efficiently converts A to G and is potentially useful for clinical applications. However, its precision and efficiency in vivo remains to be addressed.…', '2018', 2018, 2102, 2102, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41467-018-04768-7/MediaObjects/41467_2018_4768_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6002399', 'pmc', 'article', 'Nature Communications', '["Zhen Liu","Zongyang Lu","Guang Yang","Shisheng Huang","Guanglei Li","Songjie Feng","Yajing Liu","Jianan Li","Wenxia Yu","Yu Zhang","Jia Chen","Qiang Sun","Xingxu Huang"]', 'mathematics', 'A recently developed adenine base editor (ABE) efficiently converts A to G and is potentially useful for clinical applications. However, its precision and efficiency in vivo remains to be addressed. Here we achieve A-to-G conversion in vivo at frequencies up to 100% by microinjection of ABE mRNA together with sgRNAs. We then generate mouse models harboring clinically relevant mutations at Ar and Hoxd13, which recapitulates respective clinical defects. Furthermore, we achieve both C-to-T and A-to-G base editing by using a combination of ABE and SaBE3, thus creating mouse model harboring multiple mutations. We also demonstrate the specificity of ABE by deep sequencing and whole-genome sequencing (WGS). Taken together, ABE is highly efficient and precise in vivo, making it feasible to model and potentially cure relevant genetic diseases.', '2026-07-08 09:46:07');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2515930553', 'mathematics', 'An integrated design and fabrication strategy for entirely soft, autonomous robots', 'An integrated design and fabrication strategy for entirely soft, autonomous robots', '2016', 2016, 2111, 2111, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature19100/MediaObjects/41586_2016_Article_BFnature19100_Fig1_HTML.jpg', 'https://pubmed.ncbi.nlm.nih.gov/27558065', 'repository', 'article', 'Nature', '["Michael Wehner","Ryan L. Truby","Daniel J. Fitzgerald","Bobak Mosadegh","George M. Whitesides","Jennifer A. Lewis","Robert J. Wood"]', 'mathematics', NULL, '2026-07-08 09:46:08');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2077766806', 'mathematics', 'Climate variation explains a third of global crop yield variability', 'Many studies have examined the role of mean climate change in agriculture, but an understanding of the influence of inter-annual climate variations on crop yields in different regions remains…', '2015', 2015, 1980, 1980, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fncomms6989/MediaObjects/41467_2015_Article_BFncomms6989_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4354156', 'pmc', 'article', 'Nature Communications', '["D. K. Ray","James Gerber","Graham K. MacDonald","Paul West"]', 'mathematics', 'Many studies have examined the role of mean climate change in agriculture, but an understanding of the influence of inter-annual climate variations on crop yields in different regions remains elusive. We use detailed crop statistics time series for ~13,500 political units to examine how recent climate variability led to variations in maize, rice, wheat and soybean crop yields worldwide. While some areas show no significant influence of climate variability, in substantial areas of the global breadbaskets, >60% of the yield variability can be explained by climate variability. Globally, climate variability accounts for roughly a third (~32-39%) of the observed yield variability. Our study uniquely illustrates spatial patterns in the relationship between climate variability and crop yield variability, highlighting where variations in temperature, precipitation or their interaction explain yield variability. We discuss key drivers for the observed variations to target further research and policy interventions geared towards buffering future crop production from climate variability.', '2026-07-08 09:46:48');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2951103577', 'mathematics', 'The brain imaging data structure, a format for organizing and describing outputs of neuroimaging experiments', 'The development of magnetic resonance imaging (MRI) techniques has defined modern neuroimaging. Since its inception, tens of thousands of studies using techniques such as functional MRI and diffusion…', '2016', 2016, 1920, 1920, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fsdata.2016.44/MediaObjects/41597_2016_Article_BFsdata201644_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4978148', 'pmc', 'article', 'Scientific Data', '["Krzysztof J. Gorgolewski","Tibor Auer","Vince D. Calhoun","R. Cameron Craddock","Samir Das","Eugene Duff","Guillaume Flandin","Satrajit Ghosh","Tristan Glatard","Yaroslav O. Halchenko","Daniel A. Handwerker","Michael Hanke","David B. Keator","Xiangrui Li","Zachary Michael","Camille Maumet","B. Nolan Nichols","Thomas E. Nichols","John Pellman","Jean‐Baptiste Poline","Ariel Rokem","Gunnar Schaefer","Vanessa Sochat","William Triplett","Jessica A. Turner","Gaël Varoquaux","Russell A. Poldrack"]', 'mathematics', 'The development of magnetic resonance imaging (MRI) techniques has defined modern neuroimaging. Since its inception, tens of thousands of studies using techniques such as functional MRI and diffusion weighted imaging have allowed for the non-invasive study of the brain. Despite the fact that MRI is routinely used to obtain data for neuroscience research, there has been no widely adopted standard for organizing and describing the data collected in an imaging experiment. This renders sharing and reusing data (within or between labs) difficult if not impossible and unnecessarily complicates the application of automatic pipelines and quality assurance protocols. To solve this problem, we have developed the Brain Imaging Data Structure (BIDS), a standard for organizing and describing MRI datasets. The BIDS standard uses file formats compatible with existing software, unifies the majority of practices already common in the field, and captures the metadata necessary for most common data processing operations.', '2026-07-08 09:47:23');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2950372712', 'mathematics', 'PAGA: graph abstraction reconciles clustering with trajectory inference through a topology preserving map of single cells', 'Single-cell RNA-seq quantifies biological heterogeneity across both discrete cell types and continuous cell transitions. Partition-based graph abstraction (PAGA) provides an interpretable graph-like…', '2019', 2019, 1827, 1827, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1186%2Fs13059-019-1663-x/MediaObjects/13059_2019_1663_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6425583', 'pmc', 'article', 'Genome biology', '["F. Alexander Wolf","Fiona Hamey","Mireya Plass","Jordi Solana","Joakim S. Dahlin","Berthold Göttgens","Nikolaus Rajewsky","Lukas M. Simon","Fabian J. Theis"]', 'mathematics', 'Single-cell RNA-seq quantifies biological heterogeneity across both discrete cell types and continuous cell transitions. Partition-based graph abstraction (PAGA) provides an interpretable graph-like map of the arising data manifold, based on estimating connectivity of manifold partitions ( https://github.com/theislab/paga ). PAGA maps preserve the global topology of data, allow analyzing data at different resolutions, and result in much higher computational efficiency of the typical exploratory data analysis workflow. We demonstrate the method by inferring structure-rich cell maps with consistent topology across four hematopoietic datasets, adult planaria and the zebrafish embryo and benchmark computational performance on one million neurons.', '2026-07-08 09:48:19');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1591018827', 'mathematics', 'A Data–Driven Approximation of the Koopman Operator: Extending Dynamic Mode Decomposition', 'A Data–Driven Approximation of the Koopman Operator: Extending Dynamic Mode Decomposition', '2015', 2015, 1813, 1813, 'https://media.springernature.com/m312/springer-static/image/art%3A10.1007%2Fs00332-015-9258-5/MediaObjects/332_2015_9258_Fig1_HTML.gif', 'http://arxiv.org/abs/1408.4408', 'arxiv', 'article', 'Journal of Nonlinear Science', '["Matthew O. Williams","Ioannis G. Kevrekidis","Clarence W. Rowley"]', 'mathematics', NULL, '2026-07-08 09:48:21');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W1966775465', 'mathematics', 'Efficient Bayesian mixed-model analysis increases association power in large cohorts', 'Efficient Bayesian mixed-model analysis increases association power in large cohorts', '2015', 2015, 1791, 1791, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fng.3190/MediaObjects/41588_2015_Article_BFng3190_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4342297', 'pmc', 'article', 'Nature Genetics', '["Po‐Ru Loh","George Tucker","Brendan Bulik‐Sullivan","Bjarni J. Vilhjálmsson","Hilary K. Finucane","Rany M. Salem","Daniel I. Chasman","Paul M. Ridker","Benjamin M. Neale","Bonnie Berger","Nick Patterson","Alkes L. Price"]', 'mathematics', NULL, '2026-07-08 09:48:42');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3040739689', 'mathematics', 'The FLUXNET2015 dataset and the ONEFlux processing pipeline for eddy covariance data', ', water, and energy exchange between the biosphere and the atmosphere, and other meteorological and biological measurements, from 212 sites around the globe (over 1500 site-years, up to and including…', '2020', 2020, 1768, 1768, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41597-020-0534-3/MediaObjects/41597_2020_534_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/7347557', 'pmc', 'article', 'Scientific Data', '["Gilberto Pastorello","Carlo Trotta","Eleonora Canfora","Housen Chu","Danielle Christianson","You-Wei Cheah","C. Poindexter","Jiquan Chen","Abdelrahman Elbashandy","Marty Humphrey","Peter Isaac","Diego Polidori","Markus Reichstein","Alessio Ribeca","Catharine van Ingen","Nicolas Vuichard","Leiming Zhang","B. D. Amiro","Christof Ammann","M. Altaf Arain","Jonas Ardö","Timothy J. Arkebauer","Stefan K. Arndt","Nicola Arriga","Marc Aubinet","Mika Aurela","Dennis Baldocchi","Alan Barr","Eric Beamesderfer","Luca Belelli Marchesini","Onil Bergeron","Jason Beringer","Christian Bernhofer","Daniel Berveiller","D. P. Billesbach","Thomas Andrew Black","Peter D. Blanken","Gil Bohrer","Julia Boike","Paul V. Bolstad","Damien Bonal","Jean-Marc Bonnefond","D. R. Bowling","Rosvel Bracho","Jason Brodeur","Christian Brümmer","Nina Buchmann","Benoît Burban","Sean P. Burns","Pauline Buysse","Peter Cale","M. Cavagna","Pierre Cellier","Shiping Chen","Isaac Chini","Torben R. Christensen","James Cleverly","Alessio Collalti","Claudia Consalvo","Bruce D. Cook","David Cook","Carole Coursolle","Edoardo Cremonese","Peter S. Curtis","Ettore D’Andrea","Humberto da Rocha","Xiaoqin Dai","K. J. Davis","Bruno De Cinti","A. de Grandcourt","Anne De Ligne","Raimundo Cosme de Oliveira","Nicolas Delpierre","Ankur R. Desai","Carlos Marcelo Di Bella","Paul Di Tommasi","A. J. Dolman","Francisco Domingo","Gang Dong","Sabina Dore","Pierpaolo Duce","Éric Dufrêne","Allison L. Dunn","Jiří Dušek","Derek Eamus","Uwe Eichelmann","Hatim Abdalla M. ElKhidir","Werner Eugster","Cäcilia Ewenz","B. E. Ewers","Daniela Famulari","Silvano Fares","Iris Feigenwinter","Andrew Feitz","Rasmus Fensholt","Gianluca Filippa","M. L. Fischer","J. M. Frank","Marta Galvagno","Mana Gharun"]', 'mathematics', ', water, and energy exchange between the biosphere and the atmosphere, and other meteorological and biological measurements, from 212 sites around the globe (over 1500 site-years, up to and including year 2014). These sites, independently managed and operated, voluntarily contributed their data to create global datasets. Data were quality controlled and processed using uniform methods, to improve consistency and intercomparability across sites. The dataset is already being used in a number of applications, including ecophysiology studies, remote sensing studies, and development of ecosystem and Earth system models. FLUXNET2015 includes derived-data products, such as gap-filled time series, ecosystem respiration and photosynthetic uptake estimates, estimation of uncertainties, and metadata about the measurements, presented for the first time in this paper. In addition, 206 of these sites are for the first time distributed under a Creative Commons (CC-BY 4.0) license. This paper details this enhanced dataset and the processing methods, now made available as open-source codes, making the dataset more accessible, transparent, and reproducible.', '2026-07-08 09:49:00');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2765802355', 'mathematics', 'Flexible mechanical metamaterials', 'Flexible mechanical metamaterials', '2017', 2017, 1755, 1755, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnatrevmats.2017.66/MediaObjects/41578_2017_Article_BFnatrevmats201766_Fig1_HTML.jpg', 'https://doi.org/10.1038/natrevmats.2017.66', 'repository', 'review', 'Nature Reviews Materials', '["Katia Bertoldi","Vincenzo Vitelli","Johan Christensen","Martin van Hecke"]', 'mathematics', NULL, '2026-07-08 09:49:00');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2809286029', 'mathematics', 'Triggers of tree mortality under drought', 'Triggers of tree mortality under drought', '2018', 2018, 1768, 1768, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-018-0240-x/MediaObjects/41586_2018_240_Fig1_HTML.jpg', 'https://hal.science/hal-01840984', 'repository', 'article', 'Nature', '["Brendan Choat","Timothy J. Brodribb","Craig R. Brodersen","Remko A. Duursma","Rosana López","Belinda E. Medlyn"]', 'mathematics', NULL, '2026-07-08 09:49:02');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2791681873', 'mathematics', 'Meta-analysis and the science of research synthesis', 'Meta-analysis and the science of research synthesis', '2018', 2018, 1713, 1713, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature25753/MediaObjects/41586_2018_Article_BFnature25753_Fig1_HTML.jpg', 'https://pubmed.ncbi.nlm.nih.gov/29517004', 'repository', 'review', 'Nature', '["Jessica Gurevitch","Julia Koricheva","Shinichi Nakagawa","Gavin Stewart"]', 'mathematics', NULL, '2026-07-08 09:49:27');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2620721366', 'mathematics', 'Differential analysis of RNA-seq incorporating quantification uncertainty', 'Differential analysis of RNA-seq incorporating quantification uncertainty', '2017', 2017, 1723, 1723, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnmeth.4324/MediaObjects/41592_2017_Article_BFnmeth4324_Fig1_HTML.jpg', 'https://pubmed.ncbi.nlm.nih.gov/28581496', 'repository', 'article', 'Nature Methods', '["Harold Pimentel","Nicolas Bray","Suzette Puente","Páll Melsted","Lior Pachter"]', 'mathematics', NULL, '2026-07-08 09:49:35');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3099011804', 'mathematics', 'Mobility network models of COVID-19 explain inequities and inform reopening', 'Mobility network models of COVID-19 explain inequities and inform reopening', '2020', 2020, 1638, 1638, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-020-2923-3/MediaObjects/41586_2020_2923_Fig1_HTML.png', 'https://pubmed.ncbi.nlm.nih.gov/33171481', 'repository', 'article', 'Nature', '["Serina Chang","Emma Pierson","Pang Wei Koh","Jaline Gerardin","Beth Redbird","David B. Grusky","Jure Leskovec"]', 'mathematics', NULL, '2026-07-08 09:50:36');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2261951110', 'mathematics', 'A Weyl Fermion semimetal with surface Fermi arcs in the transition metal monopnictide TaAs class', 'Weyl fermions are massless chiral fermions that play an important role in quantum field theory but have never been observed as fundamental particles. A Weyl semimetal is an unusual crystal that hosts…', '2015', 2015, 1590, 1590, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fncomms8373/MediaObjects/41467_2015_Article_BFncomms8373_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4490374', 'pmc', 'article', 'Nature Communications', '["Shin-Ming Huang","Su‐Yang Xu","Ilya Belopolski","Chi‐Cheng Lee","Guoqing Chang","Baokai Wang","Nasser Alidoust","Guang Bian","Madhab Neupane","Chenglong Zhang","Shuang Jia","Arun Bansil","Hsin Lin","M. Zahid Hasan"]', 'mathematics', 'Weyl fermions are massless chiral fermions that play an important role in quantum field theory but have never been observed as fundamental particles. A Weyl semimetal is an unusual crystal that hosts Weyl fermions as quasiparticle excitations and features Fermi arcs on its surface. Such a semimetal not only provides a condensed matter realization of the anomalies in quantum field theories but also demonstrates the topological classification beyond the gapped topological insulators. Here, we identify a topological Weyl semimetal state in the transition metal monopnictide materials class. Our first-principles calculations on TaAs reveal its bulk Weyl fermion cones and surface Fermi arcs. Our results show that in the TaAs-type materials the Weyl semimetal state does not depend on fine-tuning of chemical composition or magnetic order, which opens the door for the experimental realization of Weyl semimetals and Fermi arc surface states in real materials.', '2026-07-08 09:51:19');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3148042916', 'mathematics', 'Martini 3: a general purpose force field for coarse-grained molecular dynamics', 'Martini 3: a general purpose force field for coarse-grained molecular dynamics', '2021', 2021, 1578, 1578, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41592-021-01098-3/MediaObjects/41592_2021_1098_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/12554258', 'pmc', 'article', 'Nature Methods', '["Paulo C. T. Souza","Riccardo Alessandri","Jonathan Barnoud","Sebastian Thallmair","Ignacio Faustino","Fabian Grünewald","Ilias Patmanidis","Haleh Abdizadeh","Bart M. H. Bruininks","Tsjerk A. Wassenaar","P. Kroon","Josef Melcr","Vincent Nieto","Valentina Corradi","Hanif M. Khan","Jan Domański","Matti Javanainen","Hector Martinez‐Seara","Nathalie Reuter","Robert B. Best","Ilpo Vattulainen","Luca Monticelli","Xavier Périole","D. Peter Tieleman","Alex H. de Vries","‪Siewert J. Marrink"]', 'mathematics', NULL, '2026-07-08 09:51:20');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2791355014', 'mathematics', 'Mordred: a molecular descriptor calculator', 'Molecular descriptors are widely employed to present molecular characteristics in cheminformatics. Various molecular-descriptor-calculation software programs have been developed. However, users of…', '2018', 2018, 1549, 1549, 'https://media.springernature.com/w215h120/springer-static/image/art%3A10.1038%2Fs41598-023-32347-4/MediaObjects/41598_2023_32347_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5801138', 'pmc', 'article', 'Journal of Cheminformatics', '["Hirotomo Moriwaki","Yu‐Shi Tian","Norihito Kawashita","Tatsuya Takagi"]', 'mathematics', 'Molecular descriptors are widely employed to present molecular characteristics in cheminformatics. Various molecular-descriptor-calculation software programs have been developed. However, users of those programs must contend with several issues, including software bugs, insufficient update frequencies, and software licensing constraints. To address these issues, we propose Mordred, a developed descriptor-calculation software application that can calculate more than 1800 two- and three-dimensional descriptors. It is freely available via GitHub. Mordred can be easily installed and used in the command line interface, as a web application, or as a high-flexibility Python package on all major platforms (Windows, Linux, and macOS). Performance benchmark results show that Mordred is at least twice as fast as the well-known PaDEL-Descriptor and it can calculate descriptors for large molecules, which cannot be accomplished by other software. Owing to its good performance, convenience, number of descriptors, and a lax licensing constraint, Mordred is a promising choice of molecular descriptor calculation software that can be utilized for cheminformatics studies, such as those on quantitative structure-property relationships.', '2026-07-08 09:51:55');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2139019018', 'mathematics', 'International Geomagnetic Reference Field: the 12th generation', 'The 12th generation of the International Geomagnetic Reference Field (IGRF) was adopted in December 2014 by the Working Group V-MOD appointed by the International Association of Geomagnetism and…', '2015', 2015, 1552, 1552, 'https://media.springernature.com/lw685/springer-static/image/art%3A10.1186%2Fs40623-015-0228-9/MediaObjects/40623_2015_228_Fig1_HTML.gif', 'https://insu.hal.science/insu-01412375', 'repository', 'article', 'Earth Planets and Space', '["Erwan Thébault","Christopher C. Finlay","Ciarán Beggan","Patrick Alken","Julien Aubert","Olivier Barrois","F. Bertrand","Tatiana Bondar","Axel Boness","L. Brocco","Elisabeth Canet","Aude Chambodut","Arnaud Chulliat","Pierdavide Coïsson","François Civet","Aimin Du","Alexandre Fournier","Isabelle Fratter","Nicolas Gillet","Brian Hamilton","Mohamed Hamoudi","Gauthier Hulot","Thomas Jäger","Monika Korte","Weijia Kuang","Xavier Lalanne","B. Langlais","Jean-Michel Léger","Vincent Lesur","F. J. Lowes","Susan Macmillan","Mioara Mandéa","Chandrasekharan Manoj","S. Maus","Nils Olsen","V. G. Petrov","Victoria Ridley","M. Rother","Terence J. Sabaka","Diana Saturnino","Reyko Schachtschneider","Olivier Sirol","Andrew Tangborn","Alan Thomson","Lars Tøffner‐Clausen","P. Vigneron","I. Wardinski","T. I. Zvereva"]', 'mathematics', 'The 12th generation of the International Geomagnetic Reference Field (IGRF) was adopted in December 2014 by the Working Group V-MOD appointed by the International Association of Geomagnetism and Aeronomy (IAGA). It updates the previous IGRF generation with a definitive main field model for epoch 2010.0, a main field model for epoch 2015.0, and a linear annual predictive secular variation model for 2015.0-2020.0. Here, we present the equations defining the IGRF model, provide the spherical harmonic coefficients, and provide maps of the magnetic declination, inclination, and total intensity for epoch 2015.0 and their predicted rates of change for 2015.0-2020.0. We also update the magnetic pole positions and discuss briefly the latest changes and possible future trends of the Earth’s magnetic field.', '2026-07-08 09:51:55');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2811374795', 'mathematics', 'Variable generalization performance of a deep learning model to detect pneumonia in chest radiographs: A cross-sectional study', 'BACKGROUND: There is interest in using convolutional neural networks (CNNs) to analyze medical imaging to provide computer-aided diagnosis (CAD). Recent work has suggested that image classification…', '2018', 2018, 1523, 1523, 'https://journals.plos.org/plosmedicine/article/figure/image?size=large&id=10.1371/journal.pmed.1002683.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6219764', 'pmc', 'article', 'PLoS Medicine', '["John R. Zech","Marcus A. Badgeley","Manway Liu","Anthony Costa","J. Titano","Eric K. Oermann"]', 'mathematics', 'BACKGROUND: There is interest in using convolutional neural networks (CNNs) to analyze medical imaging to provide computer-aided diagnosis (CAD). Recent work has suggested that image classification CNNs may not generalize to new data as well as previously believed. We assessed how well CNNs generalized across three hospital systems for a simulated pneumonia screening task. METHODS AND FINDINGS: A cross-sectional design with multiple model training cohorts was used to evaluate model generalizability to external sites using split-sample validation. A total of 158,323 chest radiographs were drawn from three institutions: National Institutes of Health Clinical Center (NIH; 112,120 from 30,805 patients), Mount Sinai Hospital (MSH; 42,396 from 12,904 patients), and Indiana University Network for Patient Care (IU; 3,807 from 3,683 patients). These patient populations had an age mean (SD) of 46.9 years (16.6), 63.2 years (16.5), and 49.6 years (17) with a female percentage of 43.5%, 44.8%, and 57.3%, respectively. We assessed individual models using the area under the receiver operating characteristic curve (AUC) for radiographic findings consistent with pneumonia and compared performance on different test sets with DeLong''s test. The prevalence of pneumonia was high enough at MSH (34.2%) relative to NIH and IU (1.2% and 1.0%) that merely sorting by hospital system achieved an AUC of 0.861 (95% CI 0.855-0.866) on the joint MSH-NIH dataset. Models trained on data from either NIH or MSH had equivalent performance on IU (P values 0.580 and 0.273, respectively) and inferior performance on data from each other relative to an internal test set (i.e., new data from within the hospital system used for training data; P values both <0.001). The highest internal performance was achieved by combining training and test data from MSH and NIH (AUC 0.931, 95% CI 0.927-0.936), but this model demonstrated significantly lower external performance at IU (AUC 0.815, 95% CI 0.745-0.885, P = 0.001). To test the effect of pooling data from sites with disparate pneumonia prevalence, we used stratified subsampling to generate MSH-NIH cohorts that only differed in disease prevalence between training data sites. When both training data sites had the same pneumonia prevalence, the model performed consistently on external IU data (P = 0.88). When a 10-fold difference in pneumonia rate was introduced between sites, internal test performance improved compared to the balanced model (10× MSH risk P < 0.001; 10× NIH P = 0.002), but this outperformance failed to generalize to IU (MSH 10× P < 0.001; NIH 10× P = 0.027). CNNs were able to directly detect hospital system of a radiograph for 99.95% NIH (22,050/22,062) and 99.98% MSH (8,386/8,388) radiographs. The primary limitation of our approach and the available public data is that we cannot fully assess what other factors might be contributing to hospital system-specific biases. CONCLUSION: Pneumonia-screening CNNs achieved better internal than external performance in 3 out of 5 natural comparisons. When models were trained on pooled data from sites with different pneumonia prevalence, they performed better on new pooled data from these sites but not on external data. CNNs robustly identified hospital system and department within a hospital, which can have large differences in disease burden and may confound predictions.', '2026-07-08 09:52:18');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2070923004', 'mathematics', 'Metabolic pathways promoting cancer cell survival and growth', 'Metabolic pathways promoting cancer cell survival and growth', '2015', 2015, 1507, 1507, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fncb3124/MediaObjects/41556_2015_Article_BFncb3124_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4939711', 'pmc', 'review', 'Nature Cell Biology', '["Lindsey K. Boroughs","Ralph J. DeBerardinis"]', 'mathematics', NULL, '2026-07-08 09:52:56');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2527189750', 'mathematics', 'Quantum-chemical insights from deep tensor neural networks', 'Abstract Learning from data has led to paradigm shifts in a multitude of disciplines, including web, text and image search, speech recognition, as well as bioinformatics. Can machine learning enable…', '2017', 2017, 1496, 1496, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fncomms13890/MediaObjects/41467_2017_Article_BFncomms13890_Fig1_HTML.jpg', 'https://www.ncbi.nlm.nih.gov/pmc/articles/5228054', 'pmc', 'article', 'Nature Communications', '["Kristof T. Schütt","Farhad Arbabzadah","Stefan Chmiela","K. Müller","Alexandre Tkatchenko"]', 'mathematics', 'Abstract Learning from data has led to paradigm shifts in a multitude of disciplines, including web, text and image search, speech recognition, as well as bioinformatics. Can machine learning enable similar breakthroughs in understanding quantum many-body systems? Here we develop an efficient deep learning approach that enables spatially and chemically resolved insights into quantum-mechanical observables of molecular systems. We unify concepts from many-body Hamiltonians with purpose-designed deep tensor neural networks, which leads to size-extensive and uniformly accurate (1 kcal mol −1 ) predictions in compositional and configurational chemical space for molecules of intermediate size. As an example of chemical relevance, the model reveals a classification of aromatic rings with respect to their stability. Further applications of our model for predicting atomic energies and local chemical potentials in molecules, reliable isomer energies, and molecules with peculiar electronic structure demonstrate the potential of machine learning for revealing insights into complex quantum-chemical systems.', '2026-07-08 09:52:56');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2964722401', 'mathematics', 'A national experiment reveals where a growth mindset improves achievement', 'A global priority for the behavioural sciences is to develop cost-effective, scalable interventions that could improve the academic outcomes of adolescents at a population level, but no such…', '2019', 2019, 1467, 1467, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fs41586-019-1466-y/MediaObjects/41586_2019_1466_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6786290', 'pmc', 'article', 'Nature', '["David S. Yeager","Paul Hanselman","Gregory M. Walton","Jared S. Murray","Robert Crosnoe","Chandra Muller","Elizabeth Tipton","Barbara Schneider","Chris S. Hulleman","Cintia Hinojosa","David Paunesku","Carissa Romero","Kate Flint","Alice Roberts","Jill Trott","Ronaldo Iachan","Jenny Buontempo","Sophia Yang Hooper","Carlos M. Carvalho","P. Richard Hahn","Maithreyi Gopalan","Pratik Mhatre","Ronald F. Ferguson","Angela Duckworth","Carol S. Dweck"]', 'mathematics', 'A global priority for the behavioural sciences is to develop cost-effective, scalable interventions that could improve the academic outcomes of adolescents at a population level, but no such interventions have so far been evaluated in a population-generalizable sample. Here we show that a short (less than one hour), online growth mindset intervention—which teaches that intellectual abilities can be developed—improved grades among lower-achieving students and increased overall enrolment to advanced mathematics courses in a nationally representative sample of students in secondary education in the United States. Notably, the study identified school contexts that sustained the effects of the growth mindset intervention: the intervention changed grades when peer norms aligned with the messages of the intervention. Confidence in the conclusions of this study comes from independent data collection and processing, pre-registration of analyses, and corroboration of results by a blinded Bayesian analysis. A US national experiment showed that a short, online, self-administered growth mindset intervention can increase adolescents’ grades and advanced course-taking, and identified the types of school that were poised to benefit the most.', '2026-07-08 09:53:23');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2180555938', 'mathematics', 'On-surface synthesis of graphene nanoribbons with zigzag edge topology', 'On-surface synthesis of graphene nanoribbons with zigzag edge topology', '2016', 2016, 1466, 1466, 'https://media.springernature.com/lw1200/springer-static/image/art%3A10.1038%2Fnature17151/MediaObjects/41586_2016_BFnature17151_Fig1_HTML.jpg', 'http://arxiv.org/abs/1511.05037', 'arxiv', 'article', 'Nature', '["Pascal Ruffieux","Shiyong Wang","Bo Yang","Carlos Sánchez‐Sánchez","Jia Liu","Thomas Dienel","Leopold Talirz","Prashant P. Shinde","Carlo A. Pignedoli","Daniele Passerone","Tim Dumslaff","Xinliang Feng","Kläus Müllen","Román Fasel"]', 'mathematics', NULL, '2026-07-08 09:53:26');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2921495327', 'mathematics', 'Principles of confounder selection', 'Selecting an appropriate set of confounders for which to control is critical for reliable causal inference. Recent theoretical and methodological developments have helped clarify a number of…', '2019', 2019, 1477, 1477, 'https://media.springernature.com/m685/springer-static/image/art%3A10.1007%2Fs10654-019-00494-6/MediaObjects/10654_2019_494_Fig1_HTML.png', 'https://www.ncbi.nlm.nih.gov/pmc/articles/6447501', 'pmc', 'article', 'European Journal of Epidemiology', '["Tyler J. VanderWeele"]', 'mathematics', 'Selecting an appropriate set of confounders for which to control is critical for reliable causal inference. Recent theoretical and methodological developments have helped clarify a number of principles of confounder selection. When complete knowledge of a causal diagram relating all covariates to each other is available, graphical rules can be used to make decisions about covariate control. Unfortunately, such complete knowledge is often unavailable. This paper puts forward a practical approach to confounder selection decisions when the somewhat less stringent assumption is made that knowledge is available for each covariate whether it is a cause of the exposure, and whether it is a cause of the outcome. Based on recent theoretically justified developments in the causal inference literature, the following proposal is made for covariate control decisions: control for each covariate that is a cause of the exposure, or of the outcome, or of both; exclude from this set any variable known to be an instrumental variable; and include as a covariate any proxy for an unmeasured variable that is a common cause of both the exposure and the outcome. Various principles of confounder selection are then further related to statistical covariate selection methods.', '2026-07-08 09:53:27');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W3048951226', 'mathematics', 'SHCal20 Southern Hemisphere Calibration, 0–55,000 Years cal BP', 'ABSTRACT Early researchers of radiocarbon levels in Southern Hemisphere tree rings identified a variable North-South hemispheric offset, necessitating construction of a separate radiocarbon…', '2020', 2020, 1455, 1455, 'https://static.cambridge.org/binary/version/id/urn:cambridge.org:id:binary:20200922090001038-0892:S0033822220000594:S0033822220000594_fig1a.png', 'https://doi.org/10.1017/rdc.2020.59', 'repository', 'article', 'Radiocarbon', '["Alan Hogg","Timothy Heaton","Quan Hua","Jonathan Palmer","Chris Turney","John Southon","Alex Bayliss","Paul G. Blackwell","Gretel Boswijk","Christopher Bronk Ramsey","Charlotte Pearson","Fiona Petchey","Paula Reimer","Ron Reimer","Lukas Wacker"]', 'mathematics', 'ABSTRACT Early researchers of radiocarbon levels in Southern Hemisphere tree rings identified a variable North-South hemispheric offset, necessitating construction of a separate radiocarbon calibration curve for the South. We present here SHCal20, a revised calibration curve from 0–55,000 cal BP, based upon SHCal13 and fortified by the addition of 14 new tree-ring data sets in the 2140–0, 3520–3453, 3608–3590 and 13,140–11,375 cal BP time intervals. We detail the statistical approaches used for curve construction and present recommendations for the use of the Northern Hemisphere curve (IntCal20), the Southern Hemisphere curve (SHCal20) and suggest where application of an equal mixture of the curves might be more appropriate. Using our Bayesian spline with errors-in-variables methodology, and based upon a comparison of Southern Hemisphere tree-ring data compared with contemporaneous Northern Hemisphere data, we estimate the mean Southern Hemisphere offset to be 36 ± 27 14 C yrs older.', '2026-07-08 09:53:30');
INSERT INTO enriched_papers (openalex_id, topic_slug, title, tldr, published_at, publication_year, citation_count, score, hero_image_url, oa_url, oa_source, paper_type, journal, authors_json, match_label, abstract, enriched_at) VALUES ('W2164005910', 'mathematics', 'The Extent and Consequences of P-Hacking in Science', 'A focus on novel, confirmatory, and statistically significant results leads to substantial bias in the scientific literature. One type of bias, known as "p-hacking," occurs when researchers collect…', '2015', 2015, 1422, 1422, 'https://journals.plos.org/plosbiology/article/figure/image?size=large&id=10.1371/journal.pbio.1002106.g001', 'https://www.ncbi.nlm.nih.gov/pmc/articles/4359000', 'pmc', 'article', 'PLoS Biology', '["Megan L. Head","Luke Holman","Robert Lanfear","Andrew T. Kahn","Michael D. Jennions"]', 'mathematics', 'A focus on novel, confirmatory, and statistically significant results leads to substantial bias in the scientific literature. One type of bias, known as "p-hacking," occurs when researchers collect or select data or statistical analyses until nonsignificant results become significant. Here, we use text-mining to demonstrate that p-hacking is widespread throughout science. We then illustrate how one can test for p-hacking when performing a meta-analysis and show that, while p-hacking is probably common, its effect seems to be weak relative to the real effect sizes being measured. This result suggests that p-hacking probably does not drastically alter scientific consensuses drawn from meta-analyses.', '2026-07-08 09:53:48');
